const SuttaQuotesData = [
   
                { text: `“Công đức người bố thí, \nLuôn luôn được tăng trưởng,\nTrừ được tâm hận thù.\nKhông chất chứa, chế ngự,\nKẻ chí thiện từ bỏ.\nMọi ác hạnh bất thiện,\nDiệt trừ tham, sân, si.\nTâm giải thoát thanh tịnh.”`, ref: "Trường Bộ 16 – Kinh Đại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },
                { text: `"Hãy tự mình là ngọn đèn cho chính mình, hãy tự mình nương tựa chính mình, chớ nương tựa một gì khác."`, ref: "Trường Bộ 16 – Kinh Đại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },
			{ text: `"Này các Tỷ-kheo, nếu có người hủy báng Ta, hủy báng Pháp hay hủy báng Tăng, các ngươi chớ có vì vậy sanh lòng công phẫn, tức tối, tâm sanh phiền muộn. Này các Tỷ-kheo, nếu có người hủy báng Ta, hủy báng Pháp hay hủy báng Tăng, và nếu các ngươi sanh lòng công phẫn, tức tối, tâm sanh phiền muộn, thời như vậy sẽ có hại cho các ngươi. Nếu các ngươi công phẫn và phiền muộn, thời các ngươi có thể biết được lời nói của những kẻ ấy là đúng hay sai lạc chăng?"`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Này các Tỷ-kheo, nếu có người tán thán Ta, tán thán Pháp, hay tán thán Tăng, thời các ngươi không nên hoan hỷ, vui mừng, tâm không nên thích thú. Này các Tỷ-kheo, nếu có người tán thán ta, tán thán Pháp hay tán thán Tăng, mà nếu các ngươi hoan hỷ, vui mừng và thích thú thời sẽ có hại cho các ngươi. Này các Tỷ-kheo, nếu có người tán thán Ta... thời các ngươi hãy công nhận những gì đúng sự thật là đúng sự thật."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Sa-môn Gotama từ bỏ sát sanh, tránh xa sát sanh, bỏ trượng, bỏ kiếm, biết tàm quý, có lòng từ, sống thương xót đến hạnh phúc của tất cả chúng sanh và loài hữu tình. Sa-môn Gotama từ bỏ lấy của không cho, tránh xa sự lấy của không cho, chỉ lấy những vật đã cho, chỉ mong những vật đã cho, tự sống thanh tịnh không có trộm cướp. Này các Tỷ-kheo, đó là lời tán thán Như Lai của kẻ phàm phu."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Sa-môn Gotama từ bỏ nói láo, tránh xa nói láo, nói những lời chân thật, y chỉ nơi sự thật, chắc chắn, đáng tin cậy, không lừa gạt, không phản lại lời hứa đối với đời. Sa-môn Gotama từ bỏ nói hai lưỡi, tránh xa nói hai lưỡi; nghe điều gì ở chỗ này, không đi nói đến chỗ kia để sanh chia rẽ ở những người nầy; nghe điều gì ở chỗ kia, không đi nói với những người này để sanh chia rẽ ở những người kia."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Như vậy Sa-môn Gotama sống hòa hợp những kẻ ly gián, tăng trưởng những kẻ đã hòa hợp, hoan hỷ trong hòa hợp, nói những lời đưa đến hòa hợp. Này các Tỷ-kheo, Sa-môn Gotama từ bỏ lời nói độc ác, tránh xa lời nói độc ác, những lời nói không lỗi lầm, đẹp tai, dễ thương, thông cảm đến tâm, tao nhã, đẹp lòng nhiều người, vui lòng nhiều người, Sa-môn Gotama nói những lời như vậy."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Này các Tỷ-kheo, Sa-môn Gotama từ bỏ lời nói phù phiếm, tránh xa lời nói phù phiếm, nói đúng thời, nói những lời chân thật, nói những lời có ý nghĩa, nói những lời về Chánh pháp, nói những lời về Luật, nói những lời đáng được gìn giữ, những lời hợp thời, thuận lý, có mạch lạc hệ thống, có ích lợi. Này các Tỷ-kheo, đó là những lời tán thán Như Lai của kẻ phàm phu."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Này các Tỷ-kheo, thật chỉ thuộc các vấn đề không quan trọng, nhỏ nhặt, chỉ thuộc giới luật mà kẻ phàm phu tán thán Như Lai. [...] Lại có những pháp khác, sâu kín, khó thấu, khó chứng, tịch tịnh, mỹ diệu, vượt ngoài tầm của luận lý suông, tế nhị chỉ những người trí mới nhận hiểu. Những pháp ấy Như Lai đã tự chứng tri, giác ngộ và tuyên thuyết."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Này các Tỷ-kheo, Như Lai tuệ tri như thế này: 'Những sở kiến ấy, chấp trước như vậy, chấp thủ như vậy, sẽ đưa đến những cõi thú như vậy, sẽ tác thành những định mạng như vậy'. Như Lai biết như vậy, Ngài lại biết hơn thế nữa, và Ngài không chấp sở tri ấy. Nhờ không chấp trước sở tri ấy, nội tâm chứng được tịch tịnh."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Ngài như thật biết sự tập khởi, sự diệt trừ của các thọ, vị ngọt, những nguy hiểm và sự xuất ly của chúng. Nhờ biết vậy, này các Tỷ-kheo, Như Lai được giải thoát hoàn toàn, không có chấp thủ. Những chấp pháp ấy, này các Tỷ-kheo, là những pháp sâu kín, khó thấy, khó chứng... và chính những pháp ấy, những ai như thật chân chánh tán thán Như Lai mới nói đến."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Vị hữu tình đầu tiên sanh qua nghĩ rằng: 'Ta là Phạm thiên, Ðại Phạm thiên, Toàn năng... Tổ phụ các chúng sanh đã và sẽ sanh. Những loài hữu tình ấy do chính ta sanh ra. Tại sao vậy? Vì chính do ta khởi niệm: Mong sao các loài hữu tình khác cũng đến tại chỗ này'. Các loài hữu tình đến sau cũng nghĩ như thế này: 'Vị ấy là Phạm thiên... Chúng ta do vị Phạm thiên này hóa sanh'."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Này các Tỷ-kheo, ở đời có Sa-môn hay Bà-la-môn, là nhà suy luận, là nhà thẩm sát. Do sự chia chẻ của suy luận, và sự tùy thuận theo thẩm sát, vị này tuyên bố như thế này: 'Bản ngã và thế giới là thường trú, bất sanh, vững chắc như đảnh núi, như trụ đá, còn những loại hữu tình kia thời lưu chuyển luân hồi, chết đi sanh lại, tuy vậy chúng vẫn thường còn'."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Khi hỏi đến vấn đề này hay vấn đề khác, vị ấy dùng lời ngụy biện trườn uốn như con lươn: 'Tôi không nói là như vậy. Tôi không nói là như kia. Tôi không nói là khác như thế. Tôi không nói là không phải như thế. Tôi không nói là không không phải như thế'. Này các Tỷ-kheo, đó là trường hợp thứ nhất... một số Sa-môn, Bà-la-môn chủ trương Ngụy biện luận."`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `Vị ấy nói: 'Bản ngã và thế giới do vô nhân sanh. Tại sao vậy? Vì rằng tôi trước kia không có, nay tôi có. Từ nơi trạng thái không có, tôi trở thành loài hữu tình'. Này các Tỷ-kheo, đó là trường hợp thứ nhất... một số Sa-môn, Bà-la-môn chủ trương Vô nhân luận, chấp bản ngã và thế giới do vô nhân sanh.`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `Chủ trương ấy là kinh nghiệm cá nhân, là sự không biết, không thấy, sự cảm thọ của những Sa-môn, Bà-la-môn, là sự kích thích, dao động, xuyên tạc của những vị bị tham ái chi phối. [...] Chủ trương ấy phát khởi do sự xúc chạm (của các căn). Những vị này không có thể cảm thọ những chủ trương trên, nếu không có cảm xúc.`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `Tất cả những vị này có những cảm thọ (những chủ trương trên) do sự xúc chạm qua sáu xúc xứ. Do duyên với những cảm thọ mà tham ái phát khởi; do duyên tham ái, thủ phát khởi; do duyên thủ, hữu phát khởi; do duyên hữu, sanh phát khởi, do duyên sanh, già, chết, sầu, bi, khổ, ưu, não phát khởi.`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `Này các Tỷ-kheo, cũng ví như người đánh cá lành nghề hay người học đánh cá vung lưới trên mặt hồ nước nhỏ có mắt sít sao. Người ấy nghĩ: 'Những con cá lớn ở trong hồ nước nhỏ này, tất cả chúng đều bị bao phủ trong tấm lưới này, dầu chúng có nhảy vọt lên, chúng vẫn bị hạn cuộc bao phủ ở nơi đây'.`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `Cũng như vậy này các Tỷ-kheo, những Sa-môn, Bà-la-môn nào, luận bàn về quá khứ tối sơ, hay luận bàn về tương lai... đề xướng nhiều sở kiến sai khác, tất cả những vị này đều bị bao phủ trong lưới của sáu mươi hai luận chấp này; dầu có nhảy vọt lên, những vị này vẫn bị hạn cuộc bao phủ ở nơi đây.`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `Này các Tỷ-kheo, thân của Như Lai còn tồn tại, nhưng cái khiến đưa đến đời sống khác đã bị chấm dứt. [...] Như nhánh có một chùm xoài bị chặt đứt, tất cả trái xoài dính với nhánh ấy đều bị chung một số phận với nhánh kia. Cũng như vậy này các Tỷ-kheo, thân của Như Lai còn tồn tại, nhưng cái khiến đưa đến một đời sống khác đã bị chặt đứt.`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `Khi thân của vị này còn tồn tại thời chư Thiên và loài Người có thể thấy thân ấy. Khi thân hoại mạng chung thời chư Thiên và loài Người không thể thấy được. Này các Tỷ-kheo, thân của Như Lai còn tồn tại, nhưng cái khiến đưa đến một đời sống khác đã bị chặt đứt. Khi thân của vị này còn tồn tại thời chư Thiên và loài Người có thể thấy thân ấy.`, ref: "Trường Bộ 1 – Kinh Phạm Võng ", url: "https://loicuaducphat.org/dn/dn1.html#content" },

{ text: `"Như vậy Tỷ-kheo ấy sống hòa hợp những kẻ ly gián, khuyến khích những kẻ hòa hợp, thích thú hòa hợp, hoan hỷ hòa hợp, nói những lời đưa đến hòa hợp. Vị ấy từ bỏ nói lời thô ác, tránh xa lời thô ác, nói những lời nhu hòa, êm tai, khả ái, đi vào lòng người, tao nhã, đẹp lòng nhiều người. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Vị ấy từ bỏ nói láo, tránh xa nói láo, nói những lời chân thật, y chỉ trên sự thật, chắc chắn, đáng tin cậy, không lường gạt, không phản lại lời hứa đối với đời.  Như vậy là giới hạnh của vị ấy trong giới luật."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo từ bỏ nói hai lưỡi, tránh xa nói hai lưỡi, nghe điều gì ở chỗ này, không đến chỗ kia nói để sanh chia rẽ ở những người này; nghe điều gì ở chỗ kia, không đi nói với những người này để sanh chia rẽ ở những người kia."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Cũng vậy, này Ðại vương, Tỷ-kheo ấy nhờ đầy đủ giới luật, nên không thấy sợ hãi từ một chỗ nào về phương diện hộ trì giới luật. Vị ấy nhờ đầy đủ giới luật cao quý này, nên hưởng lạc thọ, nội tâm không vẩn đục. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Này Ðại vương, khi mắt thấy sắc, Tỷ-kheo không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, khiến nhãn căn không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên, Tỷ-kheo tự chế ngự nguyên nhân ấy, hộ trì nhãn căn, thực hành sự hộ trì nhãn căn. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Những nguyên nhân gì khiến ý căn không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên, Tỷ-kheo chế ngự nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn. Vị ấy, nhờ sự hộ trì cao quý các căn ấy, nên hưởng lạc thọ nội tâm, không vẩn đục. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `Ajàtasattu, con bà Videhi, vua nước Magadha nhìn khắp chúng Tỷ-kheo đang yên lặng an tịnh như một hồ nước trong, cảm hứng nói rằng: "Mong hoàng tử Udàyibhadda cũng được sự trầm lặng như sự trầm lặng của các vị Tỷ-kheo này vậy".`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Ðại vương, cũng như con chim bay đến chỗ nào cũng mang theo hai cánh; cũng vậy, Ðại vương, vị Tỷ-kheo bằng lòng với tấm y để che thân, với đồ ăn khất thực để nuôi bụng, đi tại chỗ nào cũng mang theo. Như vậy, này Ðại vương, là Tỷ-kheo biết đủ. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Vị ấy từ bỏ tham ái ở đời, sống với tâm thoát ly tham ái, gột rửa tâm hết tham ái. Từ bỏ sân hận, vị ấy sống với tâm không sân hận, lòng từ mẫn thương xót tất cả chúng hữu tình, gột rửa tâm hết sân hận. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Từ bỏ hôn trầm, thụy miên, vị ấy sống thoát ly hôn trầm và thụy miên; với tâm tưởng hướng về ánh sáng, chánh niệm tỉnh giác, gột rửa tâm hết hôn trầm, thụy miên. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Từ bỏ trạo cử hối tiếc, vị ấy sống không trạo cử, nội tâm trầm lặng, gột rửa tâm hết trạo cử, hối tiếc. Từ bỏ nghi ngờ, vị ấy sống thoát khỏi nghi ngờ, không phân vân lưỡng lự, gột rửa tâm hết nghi ngờ. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Này Ðại vương, cũng như không mắc nợ, như không bệnh tật, như được khỏi tù tội, như được tự do, như đất lành yên ổn, này Ðại vương, Tỷ-kheo quán năm triền cái khi diệt trừ chúng. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Khi quán tự thân đã xả ly năm triền cái ấy, hân hoan sanh; do hân hoan nên hỷ sanh; do tâm hoan hỷ, thân được khinh an; do thân khinh an, lạc thọ sanh; do lạc thọ, tâm được định tĩnh. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo ly dục, ly ác pháp, chứng và trú thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm, với tứ. Tỷ-kheo thấm nhuần, tẩm ướt, làm cho sung mãn, tràn đầy thân mình với hỷ lạc do ly dục sanh, không một chỗ nào trên toàn thân không được hỷ lạc do ly dục sanh ấy thấm nhuần. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo thấm nhuần, tẩm ướt, làm cho sung mãn tràn đầy thân mình với hỷ lạc do định sanh, không một chỗ nào trên toàn thân, không được hỷ lạc do định sanh ấy thấm nhuần. Này Ðại vương, đó là quả thiết thực hiện tại của hạnh Sa-môn, còn vi diệu thù thắng hơn những quả thiết thực hiện tại của hạnh Sa-môn trước. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo ly hỷ trú xả, chánh niệm tỉnh giác, thân cảm sự lạc thọ mà các bậc Thánh gọi là 'Xả niệm lạc trú', chứng và an trú thiền thứ ba. Tỷ-kheo thấm nhuần... thân mình với lạc thọ không có hỷ ấy, không một chỗ nào trên toàn thân, không được lạc thọ không có hỷ ấy thấm nhuần. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo, xả lạc, xả khổ, diệt hỷ ưu đã cảm thọ trước, chứng và trú vào thiền thứ tư, không khổ, không lạc, xả niệm thanh tịnh. Tỷ-kheo ấy thấm nhuần toàn thân mình với tâm thuần tịnh trong sáng, không một chỗ nào trên toàn thân không được tâm thuần tịnh trong sáng ấy thấm nhuần. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Với tâm định tĩnh, thuần tịnh, không cấu nhiễm, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình thản như vậy, Tỷ-kheo dẫn tâm, hướng tâm đến thiên nhĩ thông. Tỷ-kheo với thiên nhĩ thanh tịnh siêu nhân có thể nghe hai loại tiếng, chư Thiên và Người, xa và gần. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Với tâm định tĩnh, thuần tịnh, không cấu nhiễm, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình thản như vậy, Tỷ-kheo dẫn tâm, hướng tâm đến trí huệ về sanh tử của chúng sanh. Vị ấy với thiên nhãn thuần tịnh, siêu nhân, thấy sự sống và chết của chúng sanh. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Vị ấy biết như thật 'đây là khổ', biết như thật 'đây là nguyên nhân của khổ', biết như thật 'đây là khổ diệt', biết như thật 'đây là con đường đưa đến khổ diệt', biết như thật 'đây là những lậu hoặc'... Nhờ hiểu biết như vậy, nhờ nhận thức như vậy, tâm của vị ấy thoát khỏi dục lậu, thoát khỏi hữu lậu, thoát khỏi vô minh lậu. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Ðối với tự thân đã giải thoát, vị ấy biết: Sanh đã tận, phạm hạnh đã thành, việc cần làm đã làm; sau đời hiện tại, không có đời sống nào khác nữa. Này Ðại vương, đó là quả thiết thực, hiện tại của hạnh Sa-môn, còn vi diệu thù thắng hơn những quả thiết thực hiện tại của hạnh Sa-môn trước. "`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Thật khả ái thay, đêm rằm sáng trăng! Nay chúng ta nên đến chiêm bái vị Sa-môn hay Bà-la-môn nào, nhờ sự chiêm bái này tâm chúng ta được tịnh tín?" Jìvaka thưa: "Thế Tôn Gotama có tiếng đồn tốt đẹp: 'Ðây là Thế Tôn, bậc A-la-hán... Phật, Thế Tôn'. Ðại vương hãy đến chiêm bái Thế Tôn này. Rất có thể, nhờ chiêm bái, tâm Ðại vương được tịnh tín."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Bạch Thế Tôn, con muốn hỏi Thế Tôn một vấn đề này... Chúng hưởng được kết quả thiết thực hiện tại từ công nghiệp chức nghiệp của chúng... Chúng giúp cho tự thân, vợ con, cha mẹ, bạn bè được sống an lạc, hạnh phúc. Chúng dâng các vật cúng dường cho Sa-môn, Bà-la-môn... Bạch Thế Tôn, Ngài có thể chỉ cho rõ ràng kết quả thiết thực, hiện tại của hạnh Sa-môn chăng?"`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo từ bỏ nói láo, tránh xa nói láo, nói những lời chân thật, y chỉ trên sự thật, chắc chắn, đáng tin cậy, không lường gạt, không phản lại lời hứa đối với đời. Vị ấy từ bỏ nói hai lưỡi, sống hòa hợp những kẻ ly gián, khuyến khích những kẻ hòa hợp. Như vậy là giới hạnh của vị ấy."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Trong khi một số Sa-môn, Bà-la-môn... vẫn sống nói những câu chuyện vô ích tầm thường như câu chuyện nói về vua chúa, câu chuyện về ăn trộm, câu chuyện về đại thần, câu chuyện về binh lính, câu chuyện về hãi hùng, câu chuyện về chiến tranh, câu chuyện về đồ ăn, đồ uống, và các câu chuyện vô ích khác." Còn Sa-môn Gotama từ bỏ nói những lời tầm thường vô ích như trên.`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Trong khi một số Sa-môn, Bà-la-môn... vẫn sống dùng các đồ trang sức và mỹ phẩm như thoa dầu, đấm bóp, tắm, gương kem đánh mặt, vòng hoa và phấn son, vòng tay, tóc giả trên đầu, gậy cầm tay... Còn vị ấy thì không dùng các loại trang sức và mỹ phẩm như trên."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Vị ấy tránh xa các tà mạng như: hỏi gương soi, hỏi phù đồng thiếu nữ, hỏi thiên thần để biết họa phước, thờ mặt trời, thờ đại địa, phun ra lửa, cầu Siri thần tài, dùng bùa chú để giúp người được may mắn, hay khiến người bị rủi ro. Như vậy là giới hạnh của vị ấy trong giới luật."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Vị ấy tránh xa các tà mạng như: dùng các ảo thuật để được yên ổn, lễ rửa miệng, lễ tắm, lễ hy sinh, làm cho mửa, làm cho xổ, bài tiết các nhơ bẩn... chữa bệnh cho mắt, làm thầy thuốc, mổ xẻ chữa bệnh cho con nít, cho thuốc uống bằng các loại rễ cây, ngăn ngừa công hiệu của thuốc."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Khi mắt thấy sắc, Tỷ-kheo không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, khiến nhãn căn không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên, Tỷ-kheo tự chế ngự nguyên nhân ấy, hộ trì nhãn căn... Vị ấy nhờ sự hộ trì cao quý các căn ấy, nên hưởng lạc thọ nội tâm, không vẩn đục."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo khi đi tới, đi lui, biết rõ mình đang đi tới, đi lui; khi nhìn tới, nhìn lui, biết rõ mình đang nhìn tới, nhìn lui; khi co tay, duỗi tay, biết rõ mình đang co tay, duỗi tay... Như vậy, Tỷ-kheo sống chánh niệm tỉnh giác, thực hành sự chánh niệm tỉnh giác."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo ly dục, ly ác pháp, chứng và trú thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm, với tứ. Tỷ-kheo thấm nhuần, tẩm ướt, làm cho sung mãn, tràn đầy thân mình với hỷ lạc do ly dục sanh, không một chỗ nào trên toàn thân không được hỷ lạc ấy thấm nhuần."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo, xả lạc, xả khổ, diệt hỷ ưu đã cảm thọ trước, chứng và trú vào thiền thứ tư, không khổ, không lạc, xả niệm thanh tịnh. Tỷ-kheo ấy thấm nhuần toàn thân mình với tâm thuần tịnh trong sáng, không một chỗ nào trên toàn thân không được tâm thuần tịnh trong sáng ấy thấm nhuần."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Tỷ-kheo, thể hiện nhiều loại thần thông như: một thân biến thành nhiều thân, nhiều thân biến thành một thân; hiện hình biến hình, đi ngang qua vách, qua tường, qua núi, như đi ngang qua hư không; độn thổ trồi lên, ngang qua đất liền như ở trong nước; đi trên nước không chìm như đi trên đất liền... có thể tự thân bay đến cõi Phạm thiên."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `"Nhờ hiểu biết như vậy, nhận thức như vậy, tâm của vị ấy thoát khỏi dục lậu, thoát khỏi hữu lậu, thoát khỏi vô minh lậu. Ðối với tự thân đã giải thoát, vị ấy biết: Sanh đã tận, phạm hạnh đã thành, việc cần làm đã làm; sau đời hiện tại, không có đời sống nào khác nữa. Này Ðại vương, đó là quả thiết thực hiện tại của hạnh Sa-môn."`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },

{ text: `Ví như một tòa lầu có thượng đài, giữa ngã tư đường, một người có mắt đứng trên ấy, sẽ thấy những người đi vào nhà, đi từ nhà ra, đi qua lại trên đường... Cũng vậy, Tỷ-kheo thấy sự sống và chết của chúng sanh.`, ref: "Trường Bộ 2 – Kinh Sa-môn Quả ", url: "https://loicuaducphat.org/dn/dn2.html#content" },
{ text: `"Những tiếng đồn tốt đẹp sau đây được truyền đi về Sa-môn Gotama: 'Ngài là bậc Thế Tôn, A-la-hán, Chánh Ðẳng Giác, Minh Hạnh Túc, Thiện Thệ, Thế Gian Giải, Vô Thượng Sĩ, Ðiều Ngự Trượng Phu, Thiên Nhân Sư, Phật, Thế Tôn.' Ngài thuyết pháp, sơ thiện, trung thiện, hậu thiện, nghĩa văn đầy đủ, trình bày phạm hạnh hoàn toàn đầy đủ, thanh tịnh.`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `"Theo truyền thống của chúng ta về ba mươi hai tướng của vị đại nhân, những ai có ba mươi hai tướng ấy sẽ chọn trong hai con đường, không có đường nào khác. Nếu là tại gia, sẽ thành vị Chuyển luân Thánh vương... Nếu vị này xuất gia... sẽ chứng quả A-la-hán, Chánh Ðẳng Giác, quét sạch mê lầm ở đời. "`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `"Này Ambattha, cũng như con chim cáy, con chim cáy con có thể tự hát thỏa thích trong tổ của nó.  Này Ambattha, Kapilavatthu thuộc dòng họ Thích ca. Thật không xứng để cho Ambattha phải phật lòng vì một vấn đề nhỏ mọn này. "`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `Bài kệ này do Phạm thiên SanamaKumàra thuyết:\n'Ðối với chúng sanh tin tưởng ở giai cấp,\nSát-đế-lỵ chiếm địa vị tối thắng ở nhân gian.\nNhững vị nào giới hạnh và trí tuệ đầy đủ,\nvị này chiếm địa vị tối thắng giữa Người và chư Thiên.'`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `"Những ai còn chấp trước lý thuyết thọ sanh, còn chấp trước lý thuyết giai cấp, còn chấp trước lý thuyết kiêu mạn, hoặc còn chấp trước cưới hỏi rước dâu, những người ấy còn rất xa sự thành tựu vô thượng trí đức. "`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `"Không chấp trước lý thuyết thọ sanh, không chấp trước lý thuyết giai cấp, không chấp trước lý thuyết kiêu mạn, không chấp trước cưới hỏi, đưa dâu, người ấy tức chứng ngộ vô thượng trí đức. Không có sự thành tựu trí đức nào khác siêu việt hơn, cao thượng hơn sự thành tựu trí đức này. "`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `Thật vi diệu thay, Tôn giả Gotama! Thật vi diệu thay, Tôn giả Gotama! Như người dựng đứng lại những gì bị quăng ngã xuống, phơi bày ra những gì bị che kín, chỉ đường cho người bị lạc hướng, đem đèn sáng vào trong bóng tối để những ai có mắt có thể thấy sắc. Cũng vậy, chánh pháp đã được Tôn giả Gotama dùng nhiều phương tiện trình bày, giải thích.`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `Thế Tôn liền thứ lớp giảng pháp cho Bà-la-môn Pokkharasàdi, thuyết về bố thí, thuyết về trì giới, thuyết về các cõi trời, trình bày sự nguy hiểm, sự hạ liệt, sự nhiễm ô của dục lạc và sự lợi ích của xuất ly. Khi Thế Tôn biết tâm của Bà-la-môn Pokkharasàdi đã sẵn sàng, đã nhu thuận, không còn chướng ngại, được phấn khởi, được tín thành, liền thuyết pháp mà chư Phật đã chứng ngộ, tức là khổ, tập, diệt, đạo. Cũng như tấm vải thuần bạch, được gột rửa các vết đen, sẽ rất dễ thấm màu nhuộm, cũng vậy, chính chỗ ngồi này, pháp nhãn xa trần ly cấu khởi lên trong tâm Bà-la-môn Pokkharasàdi: "Phàm pháp gì được tập khởi lên đều bị tiêu diệt".`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `Như vậy, này Ambattha, ngươi và thầy ngươi không phải là một ẩn sĩ, không sống đời sống của nhà ẩn sĩ. Này Ambattha, nếu có gì nghi ngờ, có gì phân vân về Ta, hãy hỏi Ta và Ta sẽ trả lời.`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },

{ text: `Ambattha, ngươi nghĩ thế nào? Ngươi có được nghe những vị Bà-la-môn, trưởng lão, tôn túc, những vị giáo sư và tổ sư nói đến không? Thuở xưa những vị ẩn sĩ, giữa các Bà-la-môn, những tác giả của chú thuật, những nhà tụng tán các chú thuật đã hát, đã nói lên, đã sưu tầm những Thánh cú mà nay những Bà-la-môn, cũng hát lên, nói lên, đọc lên giống như các vị trước đã làm. Những vị ẩn sĩ ấy tên là Atthaka, Vàmaka,..., Kassapa, Bhagu. Những vị ấy có khéo tắm, khéo chải chuốt, tóc và râu khéo sửa soạn, trang điểm với vòng hoa và ngọc, mặc toàn đồ trắng, tận hưởng và tham đắm năm món dục lạc, như người và thầy của ngươi hiện nay không?`, ref: "Trường Bộ 3 – Kinh Ambattha ", url: "https://loicuaducphat.org/dn/dn3.html#content" },
{ text: `Này Bà-la-môn, trí tuệ được giới hạnh làm cho thanh tịnh, giới hạnh được trí tuệ làm cho thanh tịnh. Chỗ nào có giới hạnh, chỗ ấy có trí tuệ; chỗ nào có trí tuệ, chỗ ấy có giới hạnh. Người có giới hạnh nhất định có trí tuệ; người có trí tuệ nhất định có giới hạnh. Giới hạnh và trí tuệ được xem là tối thắng ở trên đời.`, ref: "Trường Bộ 5 – Kinh Kūṭadanta", url: "https://loicuaducphat.org/dn/dn5.html#content" },


{ text: `Này Kassapa, nếu Tỷ-kheo sống tu tập từ bi tâm, không hận thù, không ác hại, và với sự diệt tận các lậu hoặc, tự giác chứng và an trú ngay hiện tại, tâm giải thoát, tuệ giải thoát vô lậu, này Kassapa, Tỷ-kheo ấy được gọi là Sa-môn, được gọi là Bà-la-môn.`, ref: "Trường Bộ 8 – Đại Kinh Sử Tử Hống", url: "https://loicuaducphat.org/dn/dn8.html#content" },

{ text: `Ta đến các vị ấy và nói: “Này các Hiền giả, những điểm bất đồng ý, hãy để chúng yên như vậy. Những điểm đồng ý, các vị có trí hãy hỏi nhau, tìm hiểu và đàm luận với nhau, giáo sư với giáo sư, hay chúng đệ tử với chúng đệ tử: “Những pháp bất thiện hay được xem là bất thiện, những pháp lỗi lầm hay được xem là lỗi lầm, những pháp không nên tuân hành hay được xem là không nên tuân hành, những pháp không xứng bậc Thánh hay được xem là không xứng đáng bậc Thánh, những pháp ô nhiễm hay được xem là ô nhiễm.`, ref: "Trường Bộ 8 – Đại Kinh Sử Tử Hống", url: "https://loicuaducphat.org/dn/dn8.html#content" },

{ text: `Này Kassapa, và sự tình này xảy ra. Khi các vị có trí hỏi nhau, tìm hiểu và đàm luận với nhau, các vị này nói: “Những pháp thiện hay được xem là thiện, những pháp không lỗi lầm hay được xem là không lỗi lầm, những pháp nên tuân hành hay được xem là nên tuân hành, những pháp xứng bậc Thánh hay được xem là xứng bậc Thánh, những pháp thanh tịnh hay được xem là thanh tịnh, Sa-môn Gotama đã hoàn toàn thành tựu những pháp này, còn những vị tôn giả, sư trưởng các giáo phái kia chỉ thành tựu một phần”.`, ref: "Trường Bộ 8 – Đại Kinh Sử Tử Hống", url: "https://loicuaducphat.org/dn/dn8.html#content" },


{ text: `Du sĩ ngoại đạo Poṭṭhapāda thấy Thế Tôn từ xa đến, liền khuyến cáo chúng của mình: “Các Tôn giả hãy nhỏ tiếng, các Tôn giả hãy đừng làm ồn. Nay Sa-môn Gotama đang đến, Ngài ưa mến sự trầm lặng, vị Ðại đức này tán thán sự trầm lặng. Nếu biết chúng này yên tịnh, Ngài có thể ghé đến đây”. Nghe nói vậy, các du sĩ ngoại đạo liền im lặng.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },

{ text: `Cũng vậy, này Poṭṭhapāda, Tỷ-kheo ấy nhờ đầy đủ giới luật nên không thấy sợ hãi từ một chỗ nào về phương diện hộ trì giới luật. Vị ấy nhờ đầy đủ giới luật cao quý này, nên hưởng lạc thọ nội tâm không lỗi lầm. Như vậy, này Poṭṭhapāda, Tỷ-kheo đầy đủ giới luật.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },

{ text: `Này Poṭṭhapāda, khi Tỷ-kheo ở đây tự mình khởi tưởng, vị này tiếp tục đi từ tưởng này đến tưởng khác cho đến tưởng tột đỉnh. Và vị này, khi đứng lại tưởng tột đỉnh có thể nghĩ: “Tâm còn suy tưởng, có hại cho ta, tâm không suy tưởng mới tốt cho ta. Nếu ta cứ tiếp tục suy tưởng khi những tưởng này của ta diệt đi, các thô tưởng khác lại khởi lên. Vậy ta hãy đừng có suy tưởng”. Và vị này không có suy tưởng. Do không có suy tưởng, các tưởng kia diệt tận và các thô tưởng khác cũng không khởi lên. Vị ấy cảm thọ sự diệt tận. Như vậy này Poṭṭhapāda là sự chứng đạt trí tuệ diệt trừ dần dần các tăng thượng tưởng.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },

{ text: `"- Bạch Thế Tôn, tưởng khởi trước, trí khởi sau; hay trí khởi trước tưởng khởi sau; hay tưởng và trí cùng khởi một lần không trước không sau?" - Này Poṭṭhapāda, tưởng khởi trước trí mới khởi sau, do tưởng sanh, trí mới sanh. Vị ấy tuệ tri: “Do duyên tưởng, trí sanh ra nơi ta”. Này Poṭṭhapāda, với lời dạy này cần phải hiểu tưởng sanh trước trí sanh sau, tưởng sanh trí mới sanh.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },

{ text: `- Thật vi diệu thay, bạch Thế Tôn! Thật vi diệu thay, bạch Thế Tôn! Như người dựng lại những gì bị quăng ngã xuống, phơi bày những gì bị che kín, chỉ đường cho những người lạc hướng, đem đèn sáng vào trong bóng tối để những ai có mắt có thể thấy sắc. Cũng vậy chánh pháp đã được Thế Tôn dùng nhiều phương tiện trình bày, giải thích. Bạch Thế Tôn, con xin quy y Thế Tôn, quy y Pháp và quy y chúng Tỷ-kheo. Mong Thế Tôn nhận con làm đệ tử, từ nay trở đi cho đến mạng chung, con trọn đời quy ngưỡng.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },

{ text: `Này Poṭṭhapāda, Khi nhiễm pháp được diệt trừ, tịnh pháp được tăng trưởng, ngay hiện tại tự mình giác ngộ, với thắng trí, chứng đạt và an trú trí tuệ sung mãn, quảng đại, thời hân hoan sanh, hoan hỷ, khinh an, chánh niệm, tỉnh giác và lạc trú sanh.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },

{ text: `Này Poṭṭhapāda, những pháp gì được Ta tuyên thuyết trình bày một cách dứt khoát? “Ðây là khổ”, này Poṭṭhapāda, đó là pháp được Ta tuyên thuyết trình bày một cách dứt khoát. “Ðây là khổ tập”, này Poṭṭhapāda, đó là pháp được Ta tuyên thuyết trình bày một cách dứt khoát. “Ðây là khổ diệt”, này Poṭṭhapāda, đó là pháp được Ta tuyên thuyết trình bày một cách dứt khoát. “Ðây là con đường đưa đến khổ diệt”, này Poṭṭhapāda, đó là pháp được Ta tuyên thuyết, trình bày một cách dứt khoát.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },

{ text: `Này Poṭṭhapāda, những pháp thuộc về đích giải thoát, thuộc về Pháp, thuộc căn bản phạm hạnh, đưa đến yểm ly, đến ly tham, đến tịch diệt, đến tịch tịnh, đến thắng trí, đến giác ngộ, đến Niết-bàn. Vì vậy những pháp ấy được Ta tuyên thuyết trình bày một cách dứt khoát.`, ref: "Trường Bộ 9 – Kinh Poṭṭhapāda", url: "https://loicuaducphat.org/dn/dn9.html#content" },

{ text: `Này Kevaddha, thế nào là giáo hóa thần thông? Ở đời có Tỷ-kheo giáo hóa như sau: “Hãy suy tư như thế này, chớ có suy tư như thế kia; hãy tác ý như thế này, chớ có tác ý như thế kia; hãy trừ bỏ điều này, hãy chứng đạt và an trú điều kia”. Này Kevaddha, như vậy gọi là giáo hóa thần thông.`, ref: "Trường Bộ 10 – Kinh Kevaddha", url: "https://loicuaducphat.org/dn/dn10.html#content" },

{ text: `“Thức là không thể thấy, vô biên,\nbiến thông hết thảy xứ.\nỞ đây, địa đại, thủy đại,\nhỏa đại, phong đại không có chân đứng.\nỞ đây, cũng vậy dài, ngắn,\ntế, thô, tịnh và bất tịnh.\nỞ đây danh và sắc tiêu diệt hoàn toàn.\nKhi thức diệt, ở đây mọi thứ đều diệt tận”.`, ref: "Trường Bộ 10 – Kinh Kevaddha", url: "https://loicuaducphat.org/dn/dn10.html#content" },


{ text: `- Này Vāsaṭṭha, những Bà-la-môn tinh thông ba tập Vedà không biết, không thấy con đường đưa đến cộng trú với Phạm thiên mà thuyết dạy: “Ðây là trực đạo, đây là chánh đạo hướng đến, dẫn đến cộng trú với Phạm thiên cho những ai thực hành theo”, thật không thể có sự kiện ấy. Này Vāsaṭṭha, ví như một chuỗi người mù ôm lưng nhau, người trước không thấy, người giữa cũng không thấy, người cuối cùng cũng không thấy. Như vậy, này Vāsaṭṭha lời nói của những Bà-la-môn tinh thông ba tập Vedà, người đầu không thấy, giữa cũng không thấy, người cuối cùng cũng không thấy, giống như lời nói mù quáng. Lời nói của những Bà-la-môn tinh thông ba tập Vedà như vậy là lời nói đáng chê cười, là lời nói suông, là lời nói không tưởng, là lời nói trống rỗng.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Người gia trưởng hay con vị gia trưởng, hay một người sinh ở giai cấp (hạ tiện) nào nghe pháp ấy. Sau khi nghe pháp, người ấy sanh lòng tín ngưỡng Như Lai. Khi có lòng tin ngưỡng ấy, vị này suy nghĩ: “Ðời sống tại gia đầy những triền phược, con đường đầy những bụi đời. Ðời sống xuất gia phóng khoáng như hư không. Thật rất khó cho một người sống tại gia có thể sống theo phạm hạnh hoàn toàn đầy đủ, hoàn toàn thanh tịnh, trắng bạch như vỏ ốc. Vậy ta nên cạo bỏ râu tóc, đắp áo cà sa, xuất gia, từ bỏ gia đình”.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Này Vāseṭṭha, năm pháp khiến dục lạc tăng thịnh ấy, các Bà-la-môn tinh thông ba tập Vedā chấp trước, mê đắm, bị trói buộc, không thấy nguy hiểm của chúng, không nhận thức sự không thoát ly của chúng, đã tận hưởng năm pháp ấy. Này Vāseṭṭha, những Bà-la-môn tinh thông ba tập Vedā, loại bỏ những pháp tác thành người Bà-la-môn, tuân theo những pháp không tác thành người Bà-la-môn, chấp trước, mê đắm, bị trói buộc, không thấy nguy hiểm của chúng, không nhận thức sự không thoát ly của chúng, tận hưởng chúng, bị trói buộc bởi sự trói buộc của dục lạc, sau khi thân hoại mạng chung sẽ cộng trú với Phạm thiên, thật không có sự kiện ấy.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Này Vàsettha, như một người muốn xây tại ngã tư đường một cái thang để leo lên lầu. Có người hỏi: "Này bạn, Ông muốn xây một cái thang để leo lên lầu, vậy Ông có biết lầu ấy là về hướng Ðông, hay về hướng Tây, hay về hướng Bắc, hay về hướng Nam? Nhà lầu ấy cao hay thấp, hay trung bình?". Ðược hỏi vậy, vị ấy trả lời không biết. Có người hỏi: "Này bạn, như vậy có phải Ông xây một cái thang để leo lên một cái lầu mà Ông không biết, không thấy?". Hỏi vậy, vị ấy trả lời phải. Này Vàsettha, ngươi nghĩ thế nào? Sự kiện là như vậy, thời có phải lời nói người kia không chánh xác, hợp lý?`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Này Vàsettha, như sông Aciravati này, đầy tràn cho đến bờ khiến con quạ có thể uống được. Có người đến, có sự việc bên bờ bên kia, tìm đến bờ bên kia, hướng đến bờ bên kia và muốn lội qua bờ bên kia. Người đứng bờ bên này kêu bờ bên kia và nói: "Bờ bên kia, hãy lại đây! Bờ bên kia, hãy lại đây". Này Vàsettha, Ngươi nghĩ thế nào? Có phải vì người kia kêu gọi bờ bên kia, vì cầu khẩn, vì hy vọng, vì tán thán mà bờ bên kia của sông Aciravati đến bờ bên này không? "- Tôn giả Gotama, không thể vậy."`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Cũng vậy, này Vàsettha, có năm triền cái được gọi là chướng ngại, cũng được gọi là triền cái, cũng được gọi là màn che, cũng được gọi là triền phược trong giới luật của bậc Thánh. Thế nào là năm? Dục cái, sân cái, hôn trầm thụy miên cái, trạo hối cái, nghi cái. Này Vàsettha, năm triền cái này được gọi là chướng ngại, cũng được gọi là triền cái, cũng được gọi là màn che, cũng được gọi là triền phược. Này Vàsettha, các Bà-la-môn tinh thông ba tập Vedà, bị chướng ngại, bị triền phược, bị che đậy, bị trói buộc bởi năm triền cái này, Này Vàsettha, thật vậy, những Bà-la-môn tinh thông ba tập Vedà, loại bỏ những pháp tác thành người Bà-la-môn, tuân theo những pháp không tác thành người Bà-la-môn, bị chướng ngại, bị triền phược, bị che đậy, bị trói buộc bởi năm triền cái, sau khi thân hoại mạng chung, sẽ cộng trú với Phạm thiên - Thật không thể có sự kiện ấy.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Này Vàsettha, như sông Acivarati này, đầy tràn cho đến bờ khiến con quạ có thể uống được. Có người đến, có sự việc bên bờ bên kia, tìm đến bờ bên kia, hướng đến bờ bên kia và muốn lội qua bờ bên kia. Người này ở bên bờ này trùm đầu và nằm ngủ. Này Vàsettha, nhà Ngươi nghĩ thế nào? Người ấy có thể từ bên này của sông Aciravati đến bờ bên kia không? "- Tôn giả Gotama, không có thể được."`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `"Tỷ-kheo có tự tại, Phạm Thiên có tự tại. Giữa Tỷ-kheo có tự tại với Phạm thiên có tự tại, có thể có một sự cộng hành, cộng trú không? - Tôn giả Gotama, có thể có được. - Lành thay, Vàsettha. Này Vàsettha, Tỷ-kheo sau khi thân hoại mạng chung sẽ cộng trú với Phạm thiên. Sự kiện ấy thật có thể có."`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Này Vàsettha, như người lực sĩ thổi tù và khiến tiếng được nghe khắp bốn phương, không có gì khó khăn, cũng vậy này Vàsettha, đối với mọi hình thức của sự sống, không có ai là vị ấy bỏ qua hay bỏ sót mà không biến mãn với tâm giải thoát, câu hữu với từ. Này Vàsettha, đó là con đường đưa đến cộng trú với Phạm thiên.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Lại nữa, này Vàsettha, vị Tỷ-kheo an trú,  biến mãn một phương với tâm câu hữu với từ... với tâm câu hữu với bi... với tâm câu hữu với hỷ... biến mãn một phương với tâm câu hữu với xả, cũng vậy phương thứ hai, cũng vậy phương thứ ba, cũng vậy phương thứ tư. Như vậy, cùng khắp thế giới, trên, dưới, bề ngang hết thảy phương xứ, cùng khắp vô biên giới, vị ấy an trú biến mãn với tâm câu hữu với xả, quảng đại, vô biên, không hận, không sân.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Khi đã xuất gia như vậy, vị ấy sống chế ngự với sự chế ngự của giới bổn Pàtimokkha, đầy đủ oai nghi chánh hạnh, thấy nguy hiểm trong những lỗi nhỏ nhặt, thọ lãnh và tu học trong giới pháp, thân nghiệp, ngữ nghiệp, thanh tịnh. Mạng sống trong sạch, giới hạnh đầy đủ, thủ hộ các căn, chánh niệm, tỉnh giác và biết tri túc.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Này Vàsettha, đối với người ấy đã sinh trưởng Manasàkata, còn có thể nghi ngờ và có khó khăn hỏi đến con đường đưa đến Manasàkata nhưng đối với Như Lai thì không có nghi ngờ hay khó khăn gì khi hỏi đến Phạm thiên giới hay con đường đưa đến Phạm thiên giới! Này Vàsettha, Ta biết đến Phạm thiên, Phạm thiên giới và con đường đưa đến Phạm thiên giới.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `Này Vàsettha, ở đời các Bà-la-môn dầu có tinh thông ba tập Vedà, khi các vị này ngồi với sự tự tín, thật sự đang chìm trong bùn lầy, và khi đang chìm trong bùn lầy, phải sống trong thất vọng, lầm tưởng rằng đã đến cảnh giới an lạc hơn. Do vậy đối với những Bà-la-môn tinh thông Vedà sự tinh thông ấy được gọi là bãi sa mạc không có nước, sự tinh thông ấy cũng được gọi là rừng rậm không có đường lối, sự tinh thông ấy cũng được gọi là sự bất hạnh.`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },

{ text: `"Phạm thiên có dục ái hay không dục ái? - Tôn giả Gotama, không có dục ái. - Có hận tâm hay không hận tâm? - Tôn giả Gotama, không có hận tâm. - Có sân tâm hay không sân tâm? - Tôn giả Gotama, không có sân tâm. - Có nhiễm tâm hay không có nhiễm tâm? - Tôn giả Gotama, không có nhiễm tâm. - Có tự tại hay không có tự tại? - Tôn giả Gotama, có tự tại." "Các Bà-la-môn tinh thông ba tập Vedà có dục ái hay không dục ái? - Tôn giả Gotama, có dục ái. - Có hận tâm hay không hận tâm? - Tôn giả Gotama, có hận tâm. - Có sân tâm hay không có sân tâm? - Tôn giả Gotama, có sân tâm. - Có nhiễm tâm hay không có nhiễm tâm? - Tôn giả Gotama, có nhiễm tâm. - Có tự tại hay không có tự tại? - Tôn giả Gotama, không có tự tại." "Này Vàsettha, Ngươi nói rằng các Bà-la-môn tinh thông ba tập Vedà là có tham ái, Phạm thiên không có tham ái. Giữa các Bà-la-môn tinh thông ba tập Vedà là có tham ái với Phạm thiên không có tham ái, có thể có một sự cộng hành, cộng trú không? - Tôn giả Gotama, không thể có được."`, ref: "Trường Bộ 13 – Kinh Tam Minh", url: "https://loicuaducphat.org/dn/dn13.html#content" },
{ text: `Này các Tỷ-kheo, hoàng tử Vipassì trên đường đi đến vườn ngự uyển, thấy một người già nua, lưng còng như nóc nhà, chống gậy, vừa đi vừa run rẩy, khổ não, không còn đâu là tuổi trẻ. Thấy vậy hoàng tử hỏi người đánh xe: “Này khanh, người đó là ai vậy? Sao thân người đó không giống các người khác?”: “Tâu Hoàng tử, người đó là một người được gọi là già vậy”. “Này khanh, sao người ấy được gọi là một người già?”: “Tâu Hoàng tử, người ấy gọi là già vì nay người ấy sống không bao lâu nữa”. “Này khanh, vậy rồi Ta có bị già không, một người chưa qua tuổi già?”: “Tâu Hoàng tử, Hoàng tử và cả con nữa, chúng ta tất cả sẽ bị già nua, dầu chúng ta chưa qua tuổi già!”: “Này khanh, thôi nay thăm vườn ngự uyển như vậy là vừa rồi. Hãy cho đánh xe trở về cung”. “Thưa vâng, Hoàng tử”. Này các Tỷ-kheo, hoàng tử Vipassì về trong cung, đau khổ, sầu muộn và suy nghĩ. “Sỉ nhục thay, cái gọi là sanh. Và ai sanh ra cũng phải già yếu như vậy!”.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, rồi Bồ-tát Vipassì suy nghĩ như sau: “Thức này xoay trở lui lại, từ nơi danh sắc, không vượt khỏi danh sắc. Chỉ như thế này, con người được sanh ra hay trở thành già, hay bị chết, hay từ biệt cõi này, hay sanh lại ở cõi khác, nghĩa là do duyên danh sắc, thức sanh; do duyên thức, danh sắc sanh; do duyên danh sắc, lục nhập sanh; do duyên lục nhập, xúc sanh; do duyên xúc, thọ sanh; do duyên thọ, ái sanh; do duyên ái, thủ sanh; do duyên thủ, hữu sanh; do duyên hữu, sanh sanh; do duyên sanh, lão, tử, sầu bi, khổ ưu não sanh. Như vậy là sự tập khởi của toàn bộ khổ uẩn này”.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, rồi Bồ-tát Vipassì suy nghĩ: “Ôi, Ta đã chứng được con đường đưa đến Bồ-đề, nhờ pháp tu quán. Nghĩa là, do danh sắc diệt, thức diệt; do thức diệt, danh sắc diệt; do danh sắc diệt, lục nhập diệt; do lục nhập diệt, xúc diệt; do xúc diệt, thọ diệt, do thọ diệt, ái diệt; do ái diệt, thủ diệt; do thủ diệt, hữu diệt; do hữu diệt, sanh diệt; do sanh diệt, già, chết, ưu, bi, khổ, sầu, não diệt. Như vậy, toàn bộ khổ uẩn diệt”.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, hoàng tử Vipassì trên đường đi đến ngự uyển thấy một vị xuất gia, đầu trọc, đắp áo cà sa. Thấy vậy, hoàng tử hỏi người đánh xe: “Này khanh, người này đã làm gì, mà đầu người ấy lại khác đầu của những người khác, và áo của người ấy cũng khác áo của những người khác?”: “Tâu Hoàng tử, người ấy được gọi là người xuất gia!”: “Này khanh, sao người ấy được gọi là người xuất gia?”: “Tâu Hoàng tử, xuất gia nghĩa là khéo tu phạm hạnh, khéo tu tịnh hạnh, khéo hành thiện nghiệp, khéo hành công đức nghiệp, khéo giữ không hại chúng sanh, khéo có lòng từ đối với chúng sanh!”: “Này khanh, hãy đánh xe đến gần vị xuất gia”. “Thưa vâng, Hoàng tử”.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, rồi hoàng tử Vipassì hỏi vị xuất gia: “Thưa Hiền giả, Ngài đã làm gì, mà đầu của Ngài không giống những người khác, và áo của Ngài không giống các người khác?”: “Thưa Hoàng tử, tôi là một người xuất gia!”: “Thưa Hiền giả, thế nào gọi là người xuất gia?”: “Thưa Hoàng tử, tôi là người được gọi là xuất gia, vì tôi khéo tu phạm hạnh, khéo tu tịnh hạnh, khéo hành thiện nghiệp, khéo hành công đức nghiệp, khéo giữ không hại chúng sanh, khéo có lòng từ đối với chúng sanh”. “Thưa Hiền giả, lành thay hạnh xuất gia của Ngài, lành thay khéo tu phạm hạnh, khéo tu tịnh hạnh, khéo hành thiện nghiệp, khéo hành công đức nghiệp, khéo giữ không hại chúng sanh, khéo có lòng từ đối với chúng sanh”.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, trong khi yên lặng tịnh cư, Bồ-tát Vipassì suy nghĩ: “Sao Ta lại sống bị bao vây bởi đồ chúng này. Tốt hơn là Ta sống một mình, lánh xa đồ chúng này!”`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, rồi Bồ-tát Vipassì, sau một thời gian sống quán sự sanh diệt trong năm uẩn: “Ðây là sắc, đây là sắc tập khởi, đây là sắc diệt. Ðây là thọ, đây là thọ tập khởi, đây là thọ diệt. Ðây là tưởng, đây là tưởng tập khởi, đây là tưởng diệt. Ðây là hành, đây là hành tập khởi, đây là hành diệt! Ðây là thức, đây là thức tập khởi, đây là thức diệt”. Và đối với Ngài, sau khi sống quán pháp sanh diệt trong năm thủ uẩn, chẳng bao lâu các lậu hoặc được tiêu trừ và Ngài được giải thoát.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, Thế Tôn Vipassì, bậc A-la-hán, Chánh Ðẳng Giác suy nghĩ: “Pháp này do Ta chứng được, thật là sâu kín, khó thấy, khó chứng, tịch tịnh, cao thượng, siêu lý luận, vi diệu, chỉ người trí mới hiểu thấu. Còn quần chúng này thì ưa ái dục, khoái ái dục, ham thích ái dục. Ðối với quần chúng ưa ái dục, khoái ái dục, ham thích ái dục, thật khó mà thấy được định lý “Y tánh duyên khởi pháp” (idapaccayatā paṭicca samuppāda); thật khó mà thấy được định lý tất cả hành là tịch tịnh, tất cả sanh y được trừ bỏ, ái được đoạn tận, ly dục, ái diệt, Niết-bàn. Nếu nay Ta thuyết pháp mà các người khác không hiểu Ta, thời như vậy thật khổ não cho Ta!”`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, Thế Tôn Vipassì, bậc A-la-hán, Chánh Ðẳng Giác nhìn đời với Phật nhãn, thấy có hạng chúng sanh nhiễm ít bụi đời, nhiễm nhiều bụi đời, có hạng lợi căn độn căn, có hạng tánh thuận tánh nghịch, có hạng dễ dạy khó dạy, và một số ít thấy sự nguy hiểm phải tái sanh thế giới khác và sự nguy hiểm của những hành động lỗi lầm. Như trong hồ sen xanh, sen hồng hay sen trắng, có một số hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước, lớn lên dưới nước, không vượt lên khỏi mặt nước, được nuôi dưỡng dưới nước; có một số hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước lớn lên dưới nước, sống vươn lên tới mặt nước, có một số hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước lớn lên dưới nước vươn lên khỏi mặt nước, không bị nước làm đẫm ướt.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },

{ text: `Này các Tỷ-kheo, Thế Tôn Vipassì, bậc A-la-hán, Chánh Ðẳng Giác, giữa chúng Tỷ-kheo, tụng đọc giới bổn này:\n\n“Chư Phật dạy Niết-bàn là đệ nhất.\n“Nhẫn nhục, khổ hạnh, kham nhẫn, là đệ nhất.\n“Người xuất gia hại người xuất gia khác.\n“Hại người khác như vậy không xứng gọi là Sa-môn.\n\n“Mọi điều ác không làm, hướng tâm các thiện nghiệp.\n“Giữ tâm trí thanh tịnh, chính lời chư Phật dạy.\n\n“Không chỉ trích, không đánh đập, giữ mình trong giới bổn.\n“Ăn uống có tiết độ, ngủ nghỉ riêng một mình.\n“Hướng tâm đến cao khiết, chính lời chư Phật dạy”.`, ref: "Trường Bộ 14 – Kinh Ðại bổn", url: "https://loicuaducphat.org/dn/dn14.html#content" },
{ text: `Này Ānanda khi nào dân Vajjì, không ban hành những luật lệ không được ban hành, không hủy bỏ những luật lệ đã được ban hành, sống đúng với truyền thống của dân Vajjì như đã ban hành thuở xưa thời, này Ānanda, dân Vajjì sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, khi nào dân Vajjì tôn sùng, kính trọng, đảnh lễ, cúng dường các bậc trưởng lão Vajjì và nghe theo lời dạy của những vị này, thời dân Vajjì sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo tụ họp trong niệm đoàn kết, giải tán trong niệm đoàn kết, và làm việc Tăng sự trong niệm đoàn kết, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ban hành những luật lệ không được ban hành, không hủy bỏ những luật lệ đã được ban hành, sống đúng với những học giới được ban hành, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo tôn sùng, kính trọng, đảnh lễ, cúng dường các bậc Tỷ-kheo thượng tọa những vị này là những vị giàu kinh nghiệm, niên cao lạp trưởng, bậc cha của chúng Tăng, bậc thầy của chúng Tăng và nghe theo lời dạy của những vị này, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không bị chi phối bởi tham ái, tham ái này tác thành một đời sống khác, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo thích sống những chỗ nhàn tịnh, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo tự thân an trú chánh niệm, khiến các bạn đồng tu thiện chí chưa đến muốn đến ở, và các bạn đồng tu thiện chí đã đến ở, được sống an lạc, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ưa thích làm thế sự, không hoan hỷ làm thế sự, không đam mê làm thế sự, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ưa thích phiếm luận, không hoan hỷ phiếm luận, không đam mê phiếm luận, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ưa thích ngủ nghỉ, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ưa thích quần tụ, không hoan hỷ quần tụ, không đam mê quần tụ, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không có ác dục vọng, không bị chi phối bởi ác dục vọng, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không bạn bè ác dục vọng, không thân tín ác dục vọng, không cộng hành với ác dục vọng, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các, Tỷ-kheo khi nào các vị Tỷ-kheo đối với các vị đồng tu phạm hạnh, tại chỗ đông người và vắng người, gìn giữ thân nghiệp từ hòa, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào các vị Tỷ-kheo đối với các vị đồng tu phạm hạnh, tại chỗ đông người và vắng người gìn giữ khẩu nghiệp từ hòa, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào các vị Tỷ-kheo đối với các vị đồng tu phạm hạnh, tại chỗ đông người và vắng người, gìn giữ ý nghiệp từ hòa, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào các vị Tỷ-kheo phân phối không thiên vị, chung thọ hưởng với các bạn giới đức đồng tu, mọi lợi dưỡng chơn chánh, hợp pháp, cho đến những vật thọ lãnh trong bình bát khất thực, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào các vị Tỷ-kheo sống với các bạn đồng tu, tại chỗ đông người và vắng người, trong sự thọ trì những giới luật đúng với Sa-môn hạnh, những giới luật không bị gẫy vụn, không bị sứt mẻ, không bị tỳ vết, không bị uế trược, những giới luật đưa đến giải thoát, được người có trí tán thán, không bị ô nhiễm bởi mục đích sai lạc, những giới luật hướng đến định tâm, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi nào các vị Tỷ-kheo sống với các bạn đồng tu, tại chỗ đông người và vắng người, trong sự thọ trì những tri kiến đúng với Sa-môn hạnh, những thánh tri kiến đưa đến giải thoát, hướng đến sự diệt tận khổ đau cho những ai thực hành theo, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được cường thịnh, không bị suy giảm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Ðây là Giới, đây là Ðịnh, đây là Tuệ, Ðịnh cùng tu với Giới sẽ đưa đến quả vị lớn, lợi ích lớn. Tuệ cùng tu với Ðịnh sẽ đưa đến quả vị lớn, lợi ích lớn. Tâm cùng tu với Tuệ sẽ đưa đến giải thoát hoàn toàn các món lậu hoặc, tức là dục lậu, hữu lậu (tri kiến lậu), vô minh lậu.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Ở đây, này các Gia chủ, người phạm giới, sống trái giới luật sẽ bị tiêu hao tiền của rất nhiều vì sống phóng dật. Ðó là điều nguy hiểm thứ nhất cho những ai phạm giới, sống trái giới luật.\nLại nữa, này các Gia chủ, người phạm giới, sống trái giới luật bị tiếng dữ đồn xa. Ðó là điều nguy hiểm thứ hai cho những ai phạm giới, sống trái giới luật.\nLại nữa, này các Gia chủ, người phạm giới, sống trái giới luật khi vào hội chúng nào, hoặc Sát Ðế Lỵ, hoặc Bà-la-môn, hoặc gia chủ, hoặc Sa-môn, người ấy đi vào với tâm thần sợ hãi, bối rối. Ðó là điều nguy hiểm thứ ba cho những ai phạm giới, sống trái giới luật.\nLại nữa, này các Gia chủ, người phạm giới, sống trái giới luật sẽ chết với tâm hồn rối loạn. Ðó là điều nguy hiểm thứ tư cho những ai phạm giới, sống trái giới luật.\nLại nữa, này các Gia chủ, người phạm giới, sống trái giới luật sau khi thân hoại mạng chung, sẽ bị sanh vào khổ cảnh, ác thú, đọa xứ, địa ngục. Ðó là điều nguy hiểm thứ năm cho những ai phạm giới, sống trái giới luật.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Ở đây, này các Gia chủ, người giữ giới, sống theo giới luật sẽ có tiền của dồi dào rất nhiều vì sống không phóng dật. Ðó là sự lợi ích thứ nhất cho những ai giữ giới, sống theo giới luật.\nLại nữa, này các Gia chủ, người giữ giới, sống theo giới luật được tiếng tốt đồn xa. Ðó là sự lợi ích thứ hai cho những ai giữ giới, sống theo giới luật.\nLại nữa, này các Gia chủ, người giữ giới, sống theo giới luật khi đi vào hội chúng nào, hoặc Sát Ðế Lỵ, hoặc Bà-la-môn, hoặc gia chủ, hoặc Sa-môn, người ấy đi vào với tâm thần không sợ hãi, không bối rối. Ðó là sự lợi ích thứ ba cho những ai giữ giới, sống theo giới luật.\nLại nữa, này các Gia chủ, người giữ giới, sống theo giới luật sẽ chết với tâm hồn không rối loạn. Ðó là sự lợi ích thứ tư cho những ai giữ giới, sống theo giới luật.\nLại nữa, này các Gia chủ, người giữ giới, sống theo giới luật sau khi thân hoại mạng chung, sẽ được sanh vào thiện thú, thiên giới. Ðó là sự lợi ích thứ năm cho những ai giữ giới, sống theo giới luật.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Tại chỗ nào người sáng suốt lấy làm chỗ trú xứ.\nHãy nuôi dưỡng người giữ giới và người phạm hạnh.\nVà san sẽ công đức với Chư Thiên trú tại chỗ ấy.\nÐược tôn kính, chúng sẽ tôn kính lại.\nÐược trọng vọng, chúng sẽ trọng vọng lại.\nChúng sẽ mến thương người ấy như người mẹ thương mến con.\nVà những ai được thiên thần thân mến luôn luôn được thấy may mắn.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Thế Tôn thấy những người kia, người đang đi tìm thuyền, người đang đi tìm phao, người đang đi cột bè để qua bờ bên kia. Thế Tôn hiểu được ý nghĩa của cảnh này, lúc ấy bèn ứng khẩu lời cảm khái:\n“Những ai làm cầu vượt biển trùng dương,\nbỏ lại đất sũng đầm ao, trong khi người phàm phu đang cột bè.\nNhững người ấy thật là những vị trí tuệ được giải thoát”`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, chính vì không giác ngộ, không thông hiểu Bốn Thánh đế mà chúng ta phải lưu chuyển luân hồi lâu năm, Ta và các Ngươi. Bốn Thánh đế ấy là gì?\nNày các Tỷ-kheo, chính vì không giác ngộ, không thông hiểu Khổ Thánh đế,; không giác ngộ, không thông hiểu Khổ Tập Thánh đế,...Khổ Diệt Thánh đế,...Khổ Diệt Ðạo Thánh đế mà chúng ta phải lưu chuyển luân hồi lâu năm, Ta và các Ngươi.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo khi Khổ Thánh đế này được giác ngộ, được thông hiểu; khi Khổ Tập Thánh đế này được giác ngộ, được thông hiểu; khi Khổ Diệt Thánh đế này được giác ngộ, được thông hiểu; khi Khổ Diệt Ðạo Thánh đế này được giác ngộ, được thông hiểu, thời hữu ái được diệt trừ, sự dắt dẫn đến một đời sống được đoạn tuyệt, nay không còn hậu hữu nữa.\nThế Tôn thuyết như vậy. Thiện Thệ lại nói thêm:\n- Chính vì không thấy như thật Bốn Thánh đế nên có sự luân chuyển lâu ngày trong nhiều đời. Khi những sự thực này được nhận thức, nguyên nhân của một đời sống khác được trừ diệt, khi khổ căn được đoạn trừ, sẽ không còn một đời sống khác nữa.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, vì vậy ta sẽ giảng Pháp kính (Gương chánh pháp) để Thánh đệ tử, sau khi chứng đạt pháp nghĩa này, nếu muốn, sẽ tự tuyên bố về mình như sau: “Ðối với ta, sẽ không còn địa ngục, sẽ không còn tái sanh cõi bàng sanh, ngạ quỷ, đọa xứ, ác thú. Ta đã chứng quả Dự lưu, nhứt định không đọa ác đạo, sẽ đạt Chánh giác”.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, vị Thánh đệ tử có chánh tín đối với đức Phật: “Thế Tôn là bậc A-la-hán, Chánh Ðẳng Giác, Minh hạnh Túc, Thiện Thệ, Thế Gian Giải, Vô Thượng Sĩ, Ðiều Ngự Trượng Phu, Thiên Nhân Sư, Phật, Thế Tôn”. Vị ấy có chánh tín đối với chánh pháp: “Chánh pháp được Thế Tôn khéo giảng dạy, thiết thực, vượt ngoài thời gian chi phối, đến để mà thấy, có khả năng giải thoát, được kẻ trí tự mình thâm hiểu”.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Vị ấy có chánh tín đối với chúng Tăng: “Chúng Tăng đệ tử Thế Tôn chân chánh tu hành, chúng Tăng đệ tử Thế Tôn chân trực tu hành, chúng Tăng đệ tử Thế Tôn chân trí tu hành, chúng Tăng đệ tử Thế Tôn chân tịnh tu hành, tức là bốn đôi tám vị. Chúng Tăng đệ tử Thế Tôn đáng được nghênh đón, đáng được cúng dường, đáng được chiêm ngưỡng, đáng được chấp tay, là phước điền vô thượng ở trên đời.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Vị ấy có chánh tín đối với giới hạnh được bậc Thánh mến chuộng, được viên mãn không mảy mún, được vẹn toàn không sứt mẻ, không tỳ vết, không ô nhiễm, những giới hạnh đưa đến giải thoát, được người trí tán thán, không bị ảnh hưởng bởi đời sau, hướng dẫn đến thiền định”.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, các Ngươi phải sống an trú chánh niệm, tỉnh giác. Ðó là lời dạy của Ta cho các Ngươi.\nNày các Tỷ-kheo, thế nào là Tỷ-kheo an trú chánh niệm? Này các Tỷ-kheo, Tỷ-kheo đối với thân, quán thân, tinh tấn, tỉnh giác, chánh niệm nhiếp phục mọi tham ái, ưu bi ở trên đời, đối với các cảm thọ … đối với tâm … đối với các pháp, quán pháp, tinh tấn, tỉnh giác, chánh niệm, nhiếp phục mọi tham ái, ưu bi ở trên đời. Này các Tỷ-kheo, như vậy gọi là chánh niệm.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo thế nào là Tỷ-kheo tỉnh giác? Này các Tỷ-kheo, ở đây Tỷ Kheo tỉnh giác khi đi tới, đi lui, tỉnh giác khi ngó tới, ngó lui; tỉnh giác khi co tay, duỗi tay, tỉnh giác khi mang áo sanghati (tăng-già-lê) mang bát, mang y, tỉnh giác khi ăn, khi uống, khi nhai, khi nếm, tỉnh giác khi đại tiện, tiểu tiện; tỉnh giác khi đi; khi đứng, khi ngồi, khi nằm, khi thức, khi nói, khi im lặng. Này các Tỷ-kheo, như vậy Tỷ-kheo sống tỉnh giác. Này các Tỷ-kheo, Tỷ-kheo phải sống an trú chánh niệm, tỉnh giác. Ðó là lời dạy của Ta cho các Ngươi.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Trong khi Thế Tôn an cư trong mùa mưa, một cơn bệnh trầm trọng khởi lên, rất đau đớn, gần như muốn chết. Nhưng Thế Tôn giữ tâm chánh niệm, tỉnh giác, chịu đựng cơn đau ấy, không một chút ta thán. Thế Tôn tự nghĩ: “Thật không hợp lẽ nếu Ta diệt độ mà không có một lời với các đệ tử hầu cận Ta, không từ biệt chúng Tỷ-kheo. Vậy Ta hãy lấy sức tinh tấn, nhiếp phục cơn bệnh này, duy trì mạng căn và tiếp tục sống”. Và Thế Tôn với sức tinh tấn, nhiếp phục bệnh ấy duy trì mạng căn.\nRồi Thế Tôn lành bệnh. Sau khi lành bệnh không bao lâu, đức Phật rời khỏi tịnh xá và ngồi trên ghế đã soạn sẵn, trong bóng mát của ngôi tịnh xá.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Bạch Thế Tôn, con được thấy Thế Tôn khỏe mạnh. Bạch Thế Tôn, con được thấy Thế Tôn kham nhẫn, bạch Thế Tôn, thấy Thế Tôn bệnh hoạn, thân con cảm thấy yếu ớt như lau sậy, mắt con mờ mịt không thấy rõ phương hướng, dầu cho, bạch Thế Tôn, con được một chút an ủi rằng, Thế Tôn sẽ không diệt độ, nếu Ngài chưa có lời di giáo lại cho chúng Tỷ-kheo.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, chúng Tỷ-kheo còn mong mỏi gì nữa ở Ta! Này Ānanda, Ta đã giảng Chánh pháp, không có phân biệt trong ngoài (mật giáo và không phải mật giáo), vì này Ānanda, đối với các Pháp, Như Lai không bao giờ là vị Ðạo sư còn nắm tay (còn giữ lại một ít mật giáo chưa giảng dạy). Này Ānanda, những ai nghĩ rằng: “Như Lai là vị cầm đầu chúng Tỷ-kheo”; hay “chúng Tỷ-kheo chịu sự giáo huấn của Như Lai” thời này Ānanda, người ấy sẽ có lời di giáo cho chúng Tỷ-kheo. Này Ānanda, Như Lai không nghĩ rằng: “Ta là vị cầm đầu chúng Tỷ-kheo; hay “chúng Tỷ-kheo chịu sự giáo huấn của Ta” thời này Ānanda, làm sao Như Lai lại có lời di giáo cho chúng Tỷ-kheo? Này Ānanda, Ta nay đã già, đã thành bậc trưởng thượng, đã đến tuổi lâm chung, đã đến tám mươi tuổi. Này Ānanda, như cỗ xe đã già mòn, sở dĩ còn chạy được là nhờ dây thắng chằng chịt, cũng vậy thân Như Lai được duy trì sự sống giống như chính nhờ chống đỡ dây chằng. Này Ānanda, chỉ trong khi Như Lai không tác ý đến tất cả tướng, với sự diệt trừ một số cảm thọ, chứng và an trú vô tướng tâm định, chính khi ấy thân Như Lai được thoải mái.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Vậy nên, này Ānanda, hãy tự mình là ngọn đèn cho chính mình, hãy tự mình nương tựa chính mình, chớ nương tựa một gì khác. Dùng Chánh pháp làm ngọn đèn, dùng Chánh pháp làm chỗ nương tựa, chớ nương tựa một gì khác.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, ở đời, vị Tỷ-kheo, đối với thân quán thân, tinh tấn, tỉnh giác, chánh niệm, nhiếp phục mọi tham ái, ưu bi trên đời; đối với các cảm thọ … đối với tâm … đối với các pháp, quán pháp, tinh tấn, tỉnh giác, chánh niệm, nhiếp phục mọi tham ái, ưu bi trên đời. Này Ānanda, như vậy vị Tỷ-kheo tự mình là ngọn đèn cho chính mình, tự mình nương tựa chính mình, không nương tựa một gì khác, dùng Chánh pháp làm ngọn đèn, dùng Chánh pháp làm chỗ nương tựa, không nương tựa một gì khác.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, những ai sau khi Ta diệt độ, tự mình là ngọn đèn cho chính mình, tự mình nương tựa chính mình, không nương tựa một gì khác, dùng Chánh pháp làm ngọn đèn, dùng Chánh pháp làm chỗ nương tựa, không nương tựa vào một pháp gì khác, những vị ấy, này Ānanda, là những vị tối thượng trong hàng Tỷ-kheo của Ta, nếu những vị ấy tha thiết học hỏi.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ác ma, Ta sẽ không diệt độ khi nào những Tỷ-kheo của Ta,...những Tỷ-kheo ni,...những nam cư sĩ,...những nữ cư sĩ của ta chưa trở thành những vị đệ tử chân chánh, sáng suốt, có kỷ luật, sẵn sàng, đa văn, duy trì Chánh pháp, thành tựu Chánh pháp và tùy pháp, sống chân chánh, sống theo Chánh pháp, sau khi học hỏi giáo lý, chưa có thể tuyên bố, diễn giảng, trình bày, xác định, khai minh, phân tích, và giải thích rõ ràng Chánh pháp, khi có tà đạo khởi lên chưa có thể chất vấn và hàng phục một cách khéo léo, chưa có thể truyền bá Chánh pháp thần diệu”.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Và tại điện thờ Capala, Thế Tôn chánh niệm, tỉnh giác, từ bỏ thọ, hành (không duy trì mạng sống lâu hơn nữa). Khi Thế Tôn từ bỏ, không duy trì mạng sống thêm nữa, thời đại địa chấn động, ghê rợn, tóc lông dựng ngược, sấm trời vang dậy. Thế Tôn nhận hiểu ý nghĩa của sự kiện ấy, liền thốt câu kệ cảm khái như sau:\nMạng sống có hạn hay vô hạn,\nTu sĩ từ bỏ, không kéo dài.\nNội tâm chuyên nhất trú thiền định.\nNhư tháo áo giáp đang mang mặc.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, có tám nhân, có tám duyên khiến đại địa chấn động. Thế nào là tám? Này Ānanda, đại địa này thiết lập trên nước, nước ở trên gió và gió ở tại hư không. Này Ānanda, đến thời đại phong khởi lên, gió lớn khi thổi làm nổi sóng nước, và khi nước nổi sóng thì quả đất rung động. Ðó là nhân thứ nhất, duyên thứ nhất, đại địa chấn động.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ác ma, Ta không diệt độ khi nào phạm hạnh mà Ta giảng dạy chưa được thành tựu, thịnh đạt, phổ biến, quảng bá, biến mãn, nghĩa là được khéo giảng dạy cho loài Người.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, phải chăng ngay từ ban đầu Ta đã từng tuyên bố rằng mọi vật ưu ái, thân hình đều phải bị thay đổi, trở về hư không, biến dịch? Này Ānanda, làm sao có thể được như vầy: Những gì sanh khởi, tồn tại, hữu vi, chịu sự biến hoại mà lại mong khỏi có sự biến diệt? Thật không có sự trạng ấy. Này Ānanda, những gì Như Lai đã từ bỏ, dứt khoát, xả ly, phóng xả, khước từ, chính là thọ, hành. Như Lai đã nói và nói một cách dứt khoát: “Không lâu, Như Lai sẽ diệt độ. Sau ba tháng bắt đầu hôm nay, Như Lai sẽ diệt độ”. Nói rằng Như Lai vì muốn sống mà phản lại lời tuyên bố trên thời thật không có sự trạng ấy.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, nay những pháp do Ta chứng ngộ và giảng dạy cho các Ngươi, các Ngươi phải khéo học hỏi, thực chứng tu tập và truyền rộng để phạm hạnh được trường tồn, vĩnh cửu, vì hạnh phúc cho chúng sanh, vì an lạc cho chúng sanh, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho loài Trời và loài Người.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là các pháp do Ta chứng ngộ và giảng dạy, các Ngươi phải khéo học hỏi, thực chứng, tu tập và truyền rộng để cho phạm hạnh được trường tồn, vĩnh cửu, vì hạnh phúc cho chúng sanh, vì an lạc cho chúng sanh, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho loài Trời và loài Người? Chính là Bốn Niệm xứ, Bốn Chánh cần, Bốn Thần túc, Năm Căn, Năm Lực, Bảy Bồ-đề phần, Tám Thánh đạo phần. Này các Tỷ-kheo, chính những pháp này do Ta chứng ngộ và giảng dạy, mà các Ngươi phải khéo học hỏi, thực chứng, tu tập và truyền rộng để phạm hạnh được trường tồn, vĩnh cửu, vì hạnh phúc cho chúng sanh, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho loài Trời và loài Người.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, đây là lời Ta nhắn nhủ các Ngươi. Các hành là vô thường. Hãy tinh tấn lên để tự giải thoát, không lâu Như Lai sẽ diệt độ. Sau ba tháng bắt đầu từ hôm nay, Như Lai sẽ diệt độ.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Ta đã già, dư mạng chẳng còn bao,\nTừ biệt các Ngươi, Ta đi một mình.\nTự mình làm sở y cho chính mình,\nHãy tinh tấn, chánh niệm, giữ giới luật,\nNhiếp thúc ý chí, bảo hộ tự tâm.\nAi tinh tấn trong pháp và luật này\nSẽ diệt sanh tử, chấm dứt khổ đau.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt bốn Pháp mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử. Thế nào là bốn? Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt Thánh Giới mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử. Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt Thánh Ðịnh mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử. Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt Thánh Tuệ mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử. Này các Tỷ-kheo, chính vì không giác ngộ, không chứng đạt Thánh giải thoát mà Ta và các Ngươi lâu đời phải trôi lăn trong biển sanh tử.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, khi Thánh Giới được giác ngộ, được chứng đạt; khi Thánh Ðịnh được giác ngộ, được chứng đạt; khi Thánh Tuệ được giác ngộ, được chứng đạt; khi Thánh Giải thoát được giác ngộ, được chứng đạt, thời tham ái một đời sống tương lai được trừ diệt, những gì đưa đến một đời sống mới được dứt sạch, nay không còn một đời sống nào nữa.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Giới, Ðịnh, Tuệ và Giải thoát vô thượng\nGotama danh xưng đã chứng ngộ.\nÐấng Giác Ngộ giảng pháp chúng Tỷ-kheo.\nÐạo Sư diệt khổ, pháp nhãn, tịnh lạc.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, có thể có vị Tỷ-kheo nói: “Tại trú xứ kia có nhiều Tỷ-kheo Thượng tọa ở, những vị này là bậc đa văn, gìn giữ truyền thống, trì pháp, trì luật, trì pháp yếu. Tôi tự thân nghe từ miệng những vị Thượng tọa ấy, tự thân lãnh thọ, như vậy là Pháp, như vậy là Luật, như vậy là lời dạy của vị Ðạo Sư”. Này các Tỷ-kheo, các Ngươi không nên tán thán, không nên hủy báng lời nói của Tỷ-kheo ấy. Không tán thán, không hủy báng, mỗi mỗi chữ, mỗi mỗi câu, phải được học hỏi kỹ lưỡng và đem so sánh với Kinh, đem đối chiếu với Luật. Khi đem so sánh với Kinh, đối chiếu với Luật, và nếu chúng không phù hợp với Kinh, không tương ứng với Luật, thời các Ngươi có thể kết luận: “Chắc chắn những lời này không phải là lời Thế Tôn và Tỷ-kheo ấy đã thọ giáo sai lầm”. Và, này các Tỷ-kheo, các Ngươi hãy từ bỏ chúng. Khi đem so sánh với Kinh, đem đối chiếu với Luật, nếu chúng phù hợp với Kinh, tương ứng với Luật, thời các Ngươi có thể kết luận: “Chắc chắn những lời ấy phải là lời dạy của Thế Tôn và Tỷ-kheo ấy đã thọ giáo chơn chánh”. Này các Tỷ-kheo, như vậy là Ðại giáo pháp thứ ba, các Ngươi hãy thọ trì.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Tôi nghe: Sau khi dùng cơm tại nhà thợ sắt Cunda.\nCơn bệnh khốc liệt bỗng khởi lên, gần như chết đến nơi.\nSau khi cùng món ăn loại mộc nhĩ.\nKịch bệnh khởi lên nơi bậc Ðạo Sư.\nÐiều phục bệnh hoạn, Thế Tôn dạy rằng:\n“Ta đi đến thành Kusināra”.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Tôn giả Ānanda tự nghĩ: “Thật kỳ diệu thay, thật hy hữu thay thần túc và uy lực của Như Lai. Con sông nhỏ đang chảy nông cạn, khuấy động và vẩn đục này, khi ta đến, liền trở thành trong trẻo, sáng lặng và không vẩn đục”.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Bạch Thế Tôn, thật là kỳ diệu, bạch Thế Tôn, thật là hy hữu, trạng thái trầm tĩnh của một vị xuất gia!`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Pukkusa, người ấy liền tự nghĩ: “Thật là kỳ diệu, thật là hy hữu sự trầm lặng của vị xuất gia, khi thức tỉnh, dầu có mưa tầm tã ào ào, điện quang chói lòa, sấm sét vang động, có hai anh em nông phu và bốn con bò đực bị sét đánh chết mà không thấy gì, không nghe gì hết”. Sau khi nói lên lòng tin tưởng ở nơi Ta, người ấy đảnh lễ Ta, thân phía hữu hướng về phía Ta và từ biệt.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Bạch Thế Tôn, sự tin tưởng của con đối với ngài Alāra Kālāma, nay con đem rải rắc trước luồng gió lớn, nay con đem thả trôi vào dòng nước cuốn. Kỳ diệu thay, bạch Thế Tôn! Hy hữu thay bạch Thế Tôn! Bạch Thế Tôn, như người dựng đứng lại những gì bị quăng ngã xuống, phơi bày ra những gì bị che kín, chỉ đường cho người bị lạc hướng, đem đèn sáng vào trong bóng tối để những ai có mắt có thể thấy sắc. Cũng vậy, Chánh pháp đã được Thế Tôn dùng nhiều phương tiện trình bày. Bạch Thế Tôn, con xin quy y Thế Tôn, quy y Pháp và quy y Tỷ-kheo Tăng. Mong Thế Tôn nhận con làm đệ tử, từ nay trở đi cho đến mạng chung, con trọn đời quy ngưỡng.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Ðức Phật tự đi đến\nCon sông Kakutthà.\nCon sông chảy trong sáng.\nMát lạnh và thanh tịnh.\nVị Ðạo Sư mỏi mệt\nÐi dần xuống mé sông.\nNhư Lai đấng Vô Thượng\nNgự trị ở trên đời\nTắm xong, uống nước xong,\nLội qua bên kia sông.\nBậc Ðạo Sư đi trước,\nGiữa Tăng chúng Tỷ-kheo,\nVừa đi vừa diễn giảng.\nChánh pháp thật vi diệu.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Hiền giả Cunda, tôi tự thân nghe, tự thân lãnh thọ lời nói này của Thế Tôn: “Có hai sự cúng dường ăn uống đồng một quả báo, đồng một dị thục quả, quả báo lớn hơn, lợi ích hơn các sự cúng dường ăn uống khác? Thế nào là hai? Một là bữa ăn trước khi Như Lai chứng vô thượng Chánh Ðẳng Chánh Giác, hai là bữa ăn trước khi Như Lai diệt độ Niết-bàn giới, không còn di hưởng sanh tử. Hai bữa ăn này đồng một quả báo, đồng một dị thục quả, quả báo lớn hơn, lợi ích hơn các sự cúng dường ăn uống khác. Nhờ hành động này, đại đức Cunda sẽ được hưởng tuổi thọ; nhờ hành động này, đại đức Cunda sẽ được hưởng sắc đẹp; nhờ hành động này, đại đức Cunda sẽ được hưởng an lạc; nhờ hành động này, đại đức Cunda sẽ được hưởng danh tiếng; nhờ hành động này, đại đức Cunda sẽ được hưởng cõi trời, nhờ hành động này, đại đức Cunda sẽ được hưởng uy quyền”.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },
{ text: `Này Ānanda, nếu có Tỷ-kheo, Tỷ-kheo ni, cư sĩ nam hay cư sĩ nữ nào thành tựu Chánh pháp và Tùy pháp, sống chơn chánh trong Chánh pháp, hành trì đúng Chánh pháp, thời người ấy kính trọng, tôn sùng, đảnh lễ, cúng dường Như Lai với sự cúng dường tối thượng. Do vậy, này Ānanda, hãy thành tựu Chánh pháp và Tùy pháp, sống chơn chánh trong Chánh pháp và hành trì đúng Chánh pháp. Này Ānanda, các Người phải học tập như vậy.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Subhadda, trong pháp luật nào không có Bát Thánh đạo, thời ở đây không có đệ nhất Sa-môn, ở đây cũng không có đệ nhị Sa-môn, cũng không có đệ tam Sa-môn, cũng không có đệ tứ Sa-môn. Này Subhadda trong pháp luật nào có Bát Thánh đạo, thời ở đây có đệ nhất Sa-môn, cũng có đệ nhị Sa-môn, cũng có đệ tam Sa-môn, ở đấy cũng có đệ tứ Sa-môn. Này Subhadda, chính trong pháp luật này có Bát Thánh Ðạo, thời này Subhadda, ở đây có đệ nhất Sa-môn, ở đây cũng có đệ nhị Sa-môn, cũng có đệ tam Sa-môn, cũng có đệ tứ Sa-môn. Những hệ thống ngoại đạo khác đều không có những Sa-môn. Này Subhadda, nếu những vị Tỷ-kheo này sống chơn chánh, thời đời này không vắng những vị A-la-hán.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Subhadda, năm hai mươi chín,\nTa xuất gia hướng tìm chân thiện đạo.\nTrải năm mươi năm với thêm một năm\nTừ khi xuất gia, này Subhadda,\nTa là du sĩ tu Trí, tu Ðức.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này Ānanda, nếu trong các ngươi có người nghĩ rằng: “Lời nói của bậc Ðạo sư không còn nữa. Chúng ta không có Ðạo sư (giáo chủ)”. Này Ānanda, chớ có những tư tưởng như vậy. Này Ānanda, Pháp và Luật, Ta đã giảng dạy và trình bày, sau khi Ta diệt độ, chính Pháp và Luật ấy sẽ là Ðạo Sư của các Ngươi.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ-kheo, nay Ta khuyên dạy các ngươi: “Các pháp hữu vi là vô thường, hãy tinh tấn, chớ có phóng dật”.\nÐó là lời cuối cùng Như Lai.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Các hành là vô thường,\nCó sanh phải có diệt\nÐã sanh, chúng phải diệt,\nNhiếp chúng là an lạc.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Không phải thở ra vào\nChính tâm trú chánh định\nKhông tham ái tịch tịnh\nTu sĩ hướng diệt độ\nChính tâm tịnh bất động\nNhẫn chịu mọi cảm thọ\nNhư đèn sáng bị tắt\nTâm giải thoát hoàn toàn.`, ref: "Trường Bộ 16 – Kinh Ðại Bát Niết Bàn", url: "https://loicuaducphat.org/dn/dn16.html#content" },

{ text: `Này các Tỷ kheo, đây là con đường độc nhất, đưa đến thanh tịnh cho chúng sanh, vượt khỏi sầu bi, diệt trừ khổ ưu, thành tựu chánh lý, chứng ngộ Niết bàn. Ðó là Bốn niệm xứ.\nThế nào là bốn? Này các Tỷ kheo, ở đây vị Tỷ kheo sống quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, để chế ngự tham ưu ở đời; sống quán thọ trên các thọ, nhiệt tâm, tỉnh giác, chánh niệm, để chế ngự tham ưu ở đời; sống quán tâm trên tâm, nhiệt tâm, tỉnh giác, chánh niệm, để chế ngự tham ưu ở đời; sống quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, để chế ngự tham ưu ở đời.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, ở đây Tỷ kheo đi đến khu rừng, đi đến gốc cây, hay đi đến ngôi nhà trống, và ngồi kiết già, lưng thẳng và an trú chánh niệm trước mặt. Tỉnh giác, vị ấy thở vô; tỉnh giác, vị ấy thở ra. Thở vô dài, vị ấy tuệ tri: “Tôi thở vô dài”; hay thở ra dài, vị ấy tuệ tri: “Tôi thở ra dài”; hay thở vô ngắn, vị ấy tuệ tri: “Tôi thở vô ngắn”; hay thở ra ngắn, vị ấy tuệ tri: “Tôi thở ra ngắn”; Cảm giác toàn thân, tôi sẽ thở vô”, vị ấy tập; “Cảm giác toàn thân, tôi sẽ thở ra”, vị ấy tập; “An tịnh thân hành, tôi sẽ thở vô”, vị ấy tập; “An tịnh thân hành, tôi sẽ thở ra”, vị ấy tập.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Như vậy, vị ấy sống quán thân trên nội thân; hay sống quán thân trên ngoại thân; hay sống quán thân trên cả nội thân, ngoại thân. Hay vị ấy sống quán tánh sanh khởi trên thân; hay sống quán tánh diệt tận trên thân; hay sống quán tánh sanh diệt trên thân. “Có thân đây”, vị ấy an trú chánh niệm như vậy với hy vọng hướng đến chánh trí, chánh niệm. Và vị ấy sống không nương tựa, không chấp trước một vật gì trên đời. Này các Tỷ kheo, như vậy Tỷ kheo sống quán thân trên thân.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Lại nữa, này các Tỷ kheo, Tỷ kheo, khi bước tới, bước lui, biết rõ việc mình đang làm. Khi ngó tới, ngó lui, biết rõ việc mình đang làm. Khi co tay khi duỗi tay biết rõ việc mình đang làm. Khi mang áo Sanghàti (Tăng-già-lê), mang bát, mang y, biết rõ việc mình đang làm. Khi ăn, uống, nhai, nếm, biết rõ việc mình đang làm. Khi đi đại tiện, tiểu tiện, biết rõ việc mình đang làm. Khi đi, đứng, ngồi, nằm, biết rõ việc mình đang làm.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, cũng như một bao đồ, hai đầu trống đựng đầy các loại hột như gạo, lúa, đậu xanh, đậu lớn, mè, gạo đã xay rồi. Một người có mắt, đổ các hột ấy ra và quan sát: “Ðây là hột gạo, đây là hột lúa, đây là đậu xanh, đây là đậu đỏ, đây là mè, đây là hột lúa đã xay rồi.” Cũng vậy, này các Tỷ kheo, một Tỷ kheo quán sát thân này dưới từ bàn chân trở lên, trên cho đến đảnh tóc, bao bọc bởi da và chứa đầy những vật bất tịnh sai biệt: “Trong thân này, đây là tóc, lông, móng, răng, da, thịt, gân, xương, tủy, thận, tim, gan, hoành cách mô, lá lách, phổi, ruột, màng ruột, bụng, phân, mật, đàm, mủ, máu, mồ hôi, mỡ, nước mắt, mỡ da, nước miếng, niêm dịch, nước ở khớp xương, nước tiểu.”`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, ở nơi đây Tỷ kheo khi cảm giác lạc thọ, biết rằng: “Tôi cảm giác lạc thọ”; khi cảm giác khổ thọ, biết rằng: “Tôi cảm giác khổ thọ”; khi cảm giác bất khổ bất lạc thọ, biết rằng: “Tôi cảm giác bất khổ bất lạc thọ”. Hay khi cảm giác lạc thọ thuộc vật chất biết rằng: “Tôi cảm giác lạc thọ thuộc vật chất”. Hay khi cảm giác lạc thọ không thuộc vật chất, biết rằng: “Tôi cảm giác lạc thọ không thuộc vật chất”. Hay khi cảm giác khổ thọ thuộc vật chất, biết rằng: “Tôi cảm giác khổ thọ thuộc vật chất”. Hay khi cảm giác khổ thọ không thuộc vật chất, biết rằng: “Tôi cảm giác khổ thọ không thuộc vật chất”. Hay khi cảm giác bất khổ bất lạc thọ thuộc vật chất, biết rằng: “Tôi cảm giác bất khổ bất lạc thọ thuộc vật chất”. Hay khi cảm giác bất khổ bất lạc thọ không thuộc vật chất, biết rằng: “Tôi cảm giác bất khổ bất lạc thọ không thuộc vật chất”.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, ở đây vị Tỷ kheo: “Với tâm có tham, biết rằng tâm có tham”; hay “Với tâm không tham, biết rằng tâm không tham”; hay “Với tâm có sân, biết rằng tâm có sân”; hay “Với tâm không sân, biết rằng tâm không sân”; hay “Với tâm có si, biết rằng tâm có si”; hay “Với tâm không si, biết rằng tâm không si”; hay “Với tâm có định, biết rằng tâm có định”; hay “Với tâm không định, biết rằng tâm không định”; hay “Với tâm giải thoát, biết rằng tâm có giải thoát”; hay “Với tâm không giải thoát, biết rằng tâm không giải thoát”.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, ở đây Tỷ kheo, nội tâm có tham dục, tuệ tri: “Nội tâm tôi có tham dục”; hay nội tâm không có tham dục, tuệ tri rằng: “Nội tâm tôi không có tham dục”. Và với tham dục chưa sanh nay sanh khởi, vị ấy tuệ tri như vậy. Và với tham dục đã sanh nay được đoạn diệt, vị ấy tuệ tri như vậy. Và với tham dục đã được đoạn diệt, tương lai không sanh khởi nữa, vị ấy tuệ tri như vậy.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Hay nội tâm có sân hận, tuệ tri rằng: “Nội tâm tôi có sân hận”; hay nội tâm không có sân hận, tuệ tri rằng: “Nội tâm tôi không có sân hận.” Và với sân hận chưa sanh nay sanh khởi, vị ấy tuệ tri như vậy. Và với sân hận đã sanh nay được đoạn diệt, vị ấy tuệ tri như vậy. Và với sân hận đã được đoạn diệt, tương lai không sanh khởi nữa, vị ấy tuệ tri như vậy.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Hay nội tâm có hôn trầm thụy miên, tuệ tri rằng: “Nội tâm tôi có hôn trầm thụy miên”; hay nội tâm không có hôn trầm thụy miên, tuệ tri rằng: “Nội tâm tôi không có hôn trầm thụy miên”. Và với hôn trầm thụy miên chưa sanh nay sanh khởi, vị ấy tuệ tri như vậy. Và với hôn trầm thụy miên đã sanh nay được đoạn diệt, vị ấy tuệ tri như vậy. Và với hôn trầm thụy miên đã được đoạn diệt, tương lai không sanh khởi nữa, vị ấy tuệ tri như vậy.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, Tỷ kheo suy tư: “Ðây là sắc, đây là sắc sanh, đây là sắc diệt. Ðây là thọ, đây là thọ sanh, đây là thọ diệt. Ðây là tưởng, đây là tưởng sanh, đây là tưởng diệt. Ðây là hành, đây là hành sanh, đây là hành diệt. Ðây là thức, đây là thức sanh, đây là thức diệt”. Như vậy vị ấy sống quán pháp trên các nội pháp; hay sống quán pháp trên các ngoại pháp; hay sống quán pháp trên các nội pháp, ngoại pháp; hay sống quán tánh sanh khởi trên các pháp; hay sống quán tánh diệt tận trên các pháp; hay sống quán tánh sanh diệt trên các pháp. “Có những pháp ở đây”, vị ấy sống an trú chánh niệm như vậy, với hy vọng hướng đến chánh trí, chánh niệm. Và vị ấy sống không nương tựa, không chấp trước một vật gì ở trên đời. Này các Tỷ kheo, như vậy Tỷ kheo sống quán pháp trên các pháp đối với Năm Thủ uẩn.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Và này các Tỷ kheo, thế nào Khổ Thánh đế? Sanh là khổ, già là khổ, chết là khổ, sầu, bi. Khổ, ưu, não là khổ, cầu không được là khổ, tóm lại Năm Thủ uẩn là khổ.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, sự tham ái này khi sanh khởi thì sanh khởi ở đâu, khi an trú thì an trú ở đâu? Ở đời, sắc gì thân ái, sắc gì khả ái? Ở đời con mắt là sắc thân ái, là sắc khả ái. Sự tham ái này khi sanh khởi thì sanh khởi ở đấy, khi an trú thì an trú ở đấy. Ở đời cái tai … ở đời mũi … ở đời lưỡi … ở đời thân … ở đời ý là sắc thân ái, là sắc khả ái. Sự tham ái này khi sanh khởi thì sanh khởi ở đấy, khi an trú thì an trú ở đấy.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Khổ diệt đạo Thánh đế. Ðó là bát chi Thánh đạo, tức là Chánh tri kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Chánh tri kiến? Này các Tỷ kheo, tri kiến về Khổ, tri kiến về Khổ tập, tri kiến về Khổ diệt, tri kiến về Khổ diệt đạo. Này các Tỷ kheo, như vậy gọi là Chánh tri kiến.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Chánh tư duy? Tư duy về ly dục, tư duy về vô sân, tư duy về bất hại. Này các tỷ kheo, như vậy gọi là Chánh tư duy.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo thế nào là Chánh ngữ? Tự chế không nói láo, tự chế không nói hai lưỡi, tự chế không ác khẩu, tự chế không nói lời phù phiếm. Này các Tỷ kheo, như vậy gọi là Chánh ngữ.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Chánh nghiệp? Tự chế không sát sanh, tự chế không trộm cướp, tự chế không tà dâm. Này các Tỷ kheo, như vậy gọi là Chánh nghiệp.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Chánh mạng? Này các Tỷ kheo, ở đây vị Thánh đệ tử từ bỏ tà mạng, sinh sống bằng chánh mạng. Này các Tỷ kheo, như vậy gọi là Chánh mạng.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, và thế nào là Chánh tinh tấn? Này các Tỷ kheo, ở đây Tỷ kheo, đối với các ác, bất thiện pháp chưa sanh, khởi lên ý muốn không cho sanh khởi; vị này nỗ lực, tinh tấn, quyết tâm, trì chí. Ðối với các ác, bất thiện pháp đã sanh, khởi lên ý muốn trừ diệt, vị này nỗ lực, tinh tấn, quyết tâm, trì chí. Ðối với các thiện pháp chưa sanh, khởi lên ý muốn khiến cho sanh khởi; vị này nỗ lực, tinh tấn, quyết tâm, trì chí. Ðối với các thiện pháp đã sanh, khởi lên ý muốn khiến cho an trú, không cho băng hoại, khiến cho tăng trưởng, phát triển, viên mãn. Vị này nỗ lực, tinh tấn, quyết tâm, trì chí. Này các Tỷ kheo, như vậy gọi là Chánh tinh tấn.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Chánh niệm? Này các Tỷ kheo, ở đây vị Tỷ kheo sống quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, để chế ngự tham ưu ở đời; trên các cảm thọ … trên các tâm … quán pháp trên các pháp, tinh cần tỉnh giác, chánh niệm để chế ngự tham ưu ở đời. Này các Tỷ kheo, như vậy gọi là Chánh niệm.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },

{ text: `Này các Tỷ kheo, thế nào là Chánh định? Này các Tỷ kheo, ở đây Tỷ kheo ly dục, ly ác bất thiện pháp, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm, với tứ. Tỷ kheo ấy diệt tầm, diệt tứ, chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm, không tứ, nội tĩnh nhất tâm. Tỷ kheo ấy ly hỷ trú xả, chánh niệm tỉnh giác, thân cảm sự lạc thọ mà các bậc Thánh gọi là xả niệm lạc trú, chứng và trú Thiền thứ ba. Tỷ kheo ấy xả lạc, xả khổ, diệt hỷ ưu đã cảm thọ trước, chứng và trú Thiền thứ tư, không khổ, không lạc, xả niệm thanh tịnh. Này các Tỷ kheo, như vậy gọi là Chánh định.`, ref: "Trường Bộ 22 – Kinh Ðại Niệm xứ", url: "https://loicuaducphat.org/dn/dn22.html#content" },
{ text: `Này Bhaggava, Ta biết về khởi nguyên thế giới, Ta còn biết hơn thế nữa. Và khi Ta biết như vậy, Ta không có chấp trước. Vì không chấp trước, Ta tự thân thấu hiểu được sự an tịnh ấy. Chính nhờ chứng ngộ sự an tịnh này mà Như Lai không rơi vào lầm lỗi.`, ref: "Trường Bộ 24 – Kinh Ba-lê", url: "https://loicuaducphat.org/dn/dn24.html#content" },

{ text: `Nhưng này Bhaggava, Ta không có nói như vậy: “Khi một ai đạt đến thanh tịnh, giải thoát, khi ấy vị ấy biết mọi vật là bất tịnh.” Này Bhaggava, Ta nói như sau: “Khi một ai đạt đến thanh tịnh, giải thoát, khi ấy vị ấy biết mọi vật là thanh tịnh.”`, ref: "Trường Bộ 24 – Kinh Ba-lê", url: "https://loicuaducphat.org/dn/dn24.html#content" },

{ text: `- Này Bhaggava, thật khó cho Ngươi khi Ngươi theo các kiến giải sai khác, kham nhẫn các sự việc sai khác, theo dõi những mục tiêu sai khác, đeo đuổi những mục đích sai khác, được huấn luyện theo các phương pháp sai khác để có thể đạt được thanh tịnh, giải thoát. Này Bhaggava, hãy đặt nặng lòng tin ở nơi Ta, hãy khéo gìn giữ lòng tin tưởng ấy.`, ref: "Trường Bộ 24 – Kinh Ba-lê", url: "https://loicuaducphat.org/dn/dn24.html#content" },

{ text: `Bạch Thế Tôn, nếu thật khó cho con, khi con theo các kiến giải sai khác, kham nhẫn các sự việc sai khác, theo dõi những mục tiêu sai khác, đeo đuổi những mục đích sai khác, được huấn luyện theo các phương pháp sai khác, để có thể đạt được thanh tịnh giải thoát, thời Bạch Thế Tôn, ít nhất con cũng đặt nặng lòng tin vào Thế Tôn, và con sẽ khéo gìn giữ lòng tin tưởng ấy.`, ref: "Trường Bộ 24 – Kinh Ba-lê", url: "https://loicuaducphat.org/dn/dn24.html#content" },
{ text: `Thật sự khác thay, khi các Tôn giả ngoại đạo, các du sĩ này hội họp lại, quy tụ lại, ồn ào, cao giọng lớn tiếng, họ sống bàn cãi về những phiếm luận vô ích như câu chuyện về vua chúa … câu chuyện về sự hiện hữu và sự không hiện hữu. Thật sai khác thay, Thế Tôn an trú các nhàn tịnh xứ, núi rừng tịch mịch, xa vắng, ít tiếng động, có gió đồng thổi, lánh xa mắt người đời, thích hợp cho sự tịnh tu.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Vị ấy lựa một chỗ thanh vắng, tịch mịch, như ngôi rừng, gốc cây, trên khe núi, trong hang đá, bãi tha ma, lùm cây, ngoài trời, hay đống rơm. Sau khi ăn xong đi khất thực về, vị ấy ngồi kiết già, lưng thẳng và an trú chánh niệm trước mặt. Vị ấy từ bỏ tham ái ở đời, an trú với tâm thoát ly tham ái, gột sạch tâm hết tham ái. Từ bỏ sân tâm, an trú với tâm thoát ly sân tâm, khởi lòng thương tưởng mọi loài chúng sanh, gột sạch tâm hết sân hận. Từ bỏ hôn trầm thụy miên, an trú với tâm thoát ly hôn trầm thụy miên, tưởng niệm đến ánh sáng, chánh niệm, tỉnh giác, gột sạch tâm hết hôn trầm thụy miên. Từ bỏ trạo hối, an trú tâm thoát ly trạo hối, nội tâm an tịnh, gột sạch tâm hết trạo hối. Từ bỏ nghi hoặc, an trú với tâm thoát ly nghi ngờ, không còn nghi hoặc, gột sạch tâm không còn nghi ngờ đối với các thiện pháp.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Này Nigrodha, Ngươi nghĩ thế nào? Ngươi có bao giờ nghe các vị du sĩ niên cao, trưởng thượng, bậc Tổ sư truyền thống nói như sau: “Các vị A la hán, Chánh Ðẳng Giác trong thời quá khứ, các vị Thế Tôn này khi nào hội họp lại, quy tụ lại, ồn ào, cao giọng, lớn tiếng, chung sống bàn cãi về những phiếm luận vô ích, như câu chuyện về vua chúa, câu chuyện về ăn trộm … câu chuyện về hiện hữu và không hiện hữu, như Ngươi và Sư trưởng của Ngươi hiện nay đang làm? Hay là những bậc Thế Tôn ấy an trú các nhàn tịnh xứ, núi rừng tịch mịch, xa vắng, ít tiếng, ít động, có gió đồng thổi, lánh xa mắt của người đời, thích hợp cho sự tĩnh tu, như hiện Ta đang sống chăng?`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Này Nigrodha, Ngươi là bậc có trí và niên trưởng, có bao giờ Ngươi suy nghĩ như sau: “Ðức Phật, bậc Giác Ngộ, thuyết giảng giáo pháp đưa đến giác ngộ; Thế Tôn là vị đã điều phục, thuyết giảng giáo pháp đưa đến sự điều phục; Thế Tôn bậc An Chỉ, thuyết giảng giáo pháp đưa đến An Chỉ; Thế Tôn là bậc đến bờ bên kia, thuyết giảng giáo pháp đưa đến bờ bên kia; Thế Tôn bậc Tịnh Lạc, thuyết giảng giáo pháp đưa đến sự tịnh lạc.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Và này Nigrodha, có những pháp bất thiện không được từ bỏ, làm cho cấu uế, đưa đến tái sanh, đem lại đau khổ, đưa lại quả khổ, đem lại già, bệnh, chết trong tương lai. Những pháp ấy, Ta thuyết giảng để diệt trừ chúng. Nếu các Ngươi thực hành đúng theo lời giảng dạy, thời các pháp cấu uế của ngươi được trừ diệt, các pháp thanh tịnh được tăng trưởng, và các ngươi sẽ tự chứng biết, chứng ngộ, đạt đến an trú ngay trong hiện tại, trí tuệ cụ túc, viên mãn.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Này Nigrodha, Ngươi có thể nghĩ rằng: “Sa môn Gotama nói vậy là muốn có đệ tử.” Này Nigrodha, Ngươi chớ có hiểu như vậy. Bổn sư Ngươi là ai, hãy giữ nguyên vị Bổn sư ấy cho Ngươi. Này Nigrodha, Ngươi có thể nghĩ rằng: “Sa môn Gotama nói vậy là muốn chúng tôi từ bỏ kinh tụng của chúng tôi”. Này Nigrodha, Ngươi chớ có hiểu như vậy. Kinh tụng của Ngươi là gì, hãy giữ nguyên kinh tụng ấy cho Ngươi. Này Nigrodha, Ngươi có thể nghĩ rằng: “Sa môn Gotama nói như vậy là muốn chúng tôi từ bỏ nghề sống của chúng tôi.” Này Nigrodha, chớ có hiểu như vậy. Nghề sống của Ngươi là gì, hãy giữ nguyên nghề sống ấy cho Ngươi.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Này Nigrodha, Ta nói vậy không phải vì muốn có đệ tử; Ta nói vậy không phải vì mu khiến các Ngươi từ bỏ kinh tụng, Ta nói vậy không phải vì muốn khiến các Ngươi từ bỏ nghề sống; Ta nói vậy không phải vì muốn xác tín cho các Ngươi đối với các pháp bất thiện mà truyền thống Tổ sư đã xem là bất thiện; Ta nói vậy không phải vì muốn cho các Ngươi từ bỏ những thiện pháp mà truyền thống Tổ sư đã xem là thiện pháp. Và này Nigrodha, có những pháp bất thiện không được từ bỏ, làm cho cấu uế, đưa đến tái sanh, đem lại đau khổ, đưa lại quả khổ, đem lại già, bệnh, chết trong tương lai. Những pháp ấy, Ta thuyết giảng để diệt trừ chúng. Nếu các Ngươi thực hành đúng theo lời giảng dạy, thời các pháp cấu uế của ngươi được trừ diệt, các pháp thanh tịnh được tăng trưởng, và các ngươi sẽ tự chứng biết, chứng ngộ, đạt đến an trú ngay trong hiện tại, trí tuệ cụ túc, viên mãn.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `- Này Nigrodha, ở đây một vị khổ hạnh siêng tu khổ hạnh. Nhờ tu khổ hạnh này, vị ấy hoan hỷ tâm tư thỏa mãn. Này Nigrodha, vị khổ hạnh do siêng tu khổ hạnh, phát sanh hoan hỷ, tâm tư thỏa mãn. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.\nLại nữa, này Nigrodha, vị khổ hạnh tu hành khổ hạnh, do khổ hạnh này, vị này khen mình chê người. Này Nigrodha, vị khổ hạnh tu hành khổ hạnh nào, do khổ hạnh ấy khen mình chê người. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.\nLại nữa, này Nigrodha, vị khổ hạnh tu hành khổ hạnh, do khổ hạnh này trở thành mê say, nhiễm trước, phóng dật. Này Nigrodha, vị tu hành khổ hạnh nào, do khổ hạnh ấy mê say, nhiễm trước, phóng dật. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa, này Nigrodha, vị khổ hạnh tu hành khổ hạnh. Do khổ hạnh này, được thọ lãnh cúng dường, cung kính, danh vọng. Do được cúng dường, cung kính, danh vọng, trở thành hoan hỷ, tâm tư thỏa mãn. Này Nigrodha, vị khổ hạnh tu hành khổ hạnh nào; do khổ hạnh ấy được thọ lãnh cúng dường, cung kính, danh vọng, trở thành hoan hỷ, tâm tư thỏa mãn. Này Nigrodha, như vậy đó là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa, này Nigrodha, người khổ hạnh tu hành khổ hạnh. Do khổ hạnh này, được cúng dường, cung kính, danh vọng. Do được cúng dường, cung kính, danh vọng, nên khen mình chê người. Này Nigrodha, người khổ hạnh tu hành khổ hạnh nào, do khổ hạnh ấy được cúng dường, cung kính, danh vọng. Do được cúng dường, cung kính, danh vọng. Do được cúng dường, cung kính, danh vọng này, nên khen mình chê người. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa, này Nigrodha, người khổ hạnh tu hành khổ hạnh. Do khổ hạnh này, được cúng dường, cung kính, danh vọng. Do được cúng dường, cung kính, danh vọng, trở thành mê say, chấp trước, phóng dật. Này Nigrodha, người khổ hạnh tu hành khổ hạnh nào, do khổ hạnh ấy được cúng dường, cung kính, danh vọng. Do được cúng dường, cung kính, danh vọng này, trở thành mê say, chấp trước, phóng dật. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa, này Nigrodha, người khổ hạnh tu hành khổ hạnh, phân biệt các thức ăn: “Món này thích hợp với ta, món này không thích hợp với ta.” Ðối với các thức ăn không thích hợp thì cố ý từ bỏ. Ðối với các thức ăn thích hợp thì nắm giữ, tham đắm, chấp trước, không thấy các sự nguy hiểm, không phân biệt chúng là không giải thoát, thọ hưởng chúng … Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa, này Nigrodha, người khổ hạnh tu hành khổ hạnh, nhân vì mong mỏi được cúng dường cung kính danh vọng, nghĩ rằng: “Các vua chúa sẽ cung kính ta, cũng vậy các vị đại thần, các vị Sát đế lỵ, các vị Bà la môn, các vị Gia chủ, các vị Giáo chủ các giáo phái”. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa, này Nigrodha, người khổ hạnh chống báng một Sa môn hay Bà la môn khác như sau: “Người này sống ăn uống đủ mọi thứ. Như hạt giống từ rễ sanh, hạt giống từ nhánh cây sanh, hạt giống từ đốt sanh, hạt giống từ chiết cây sanh và thứ năm là hạt giống từ hạt giống sanh, nhai nghiền chúng tất cả với tầm sét không bánh xe được gọi là xương quai hàm và người ta gọi vị ấy là một vị Sa môn. Này Nigrodha, như vậy, là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa này Nigrodha, người khổ hạnh thấy một Sa môn hay Bà la môn được các gia đình cung kính, kính trọng, lễ bái, cúng dường. Thấy vậy vị ấy nghĩ rằng: “Các gia đình cung kính, kính trọng, lễ bái, cúng dường người sống ăn uống đủ mọi thứ. Các gia đình ấy không cung kính, kính trọng, lễ bái, cúng dường ta, một người tu khổ hạnh. Do vậy sanh tật đố, ganh ghét đối với các gia đình. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa, này Nigrodha, người khổ hạnh trở thành người ngồi giữa công chúng. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh. Lại nữa, này Nigrodha, người khổ hạnh, khi đi giữa các gia đình (để khất thực) không cho người ta thấy mình: “Như vậy là khổ hạnh của ta, như vậy là khổ hạnh của ta.”. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.\nLại nữa, này Nigrodha, người khổ hạnh làm bộ có vẻ bí mật. Khi được hỏi: “Có chấp nhận việc này không?”, tuy không chấp nhận nhưng trả lời: “Có chấp nhận”; tuy chấp nhận, nhưng trả lời: “Không chấp nhận.” Như vậy, vị này cố tình nói láo. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Lại nữa, này Nigrodha, người khổ hạnh hay tức giận và ôm lòng oán thù. Này Nigrodha, vì người khổ hạnh hay tức giận và ôm lòng oán thù. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.\nLại nữa, này Nigrodha, người khổ hạnh thường hay giả dối lừa đảo, tật đố và hà tiện, giảo hoạt và ngụy trá, cứng cỏi và quá mạn, có ác ý và bị ác ý chi phối, có tà kiến và tư tưởng cực đoan, chấp trước kinh nghiệm tự thân, cứng đầu và khó giải thoát. Này Nigrodha, vì một người khổ hạnh chấp trước kinh nghiệm tự thân, cứng đầu và khó giải thoát. Này Nigrodha, như vậy là cấu uế cho người khổ hạnh.`, ref: "Trường Bộ 25 – Kinh Ưu-đàm-bà-la Sư tử hống", url: "https://loicuaducphat.org/dn/dn25.html#content" },

{ text: `Này các Tỷ kheo, thế nào là một Tỷ kheo sống tự mình là ngọn đèn cho chính mình, tự mình nương tựa mình, không nương tựa một ai khác, lấy Chánh pháp làm ngọn đèn, nương tựa Chánh pháp, không nương tựa một gì khác? Này các Tỷ kheo, ở đây vị Tỷ kheo sống quán thân trên tự thân, nhiệt tâm, tinh cần, chánh niệm, tỉnh giác, để diệt trừ tham ưu ở đời, trên các cảm thọ … trên các tâm … quán pháp trên các pháp, nhiệt tâm, tinh cần, chánh niệm, tỉnh giác, để có thể diệt trừ tham ưu ở đời. Như vậy này các Tỷ kheo, vị Tỷ kheo sống tự mình là ngọn đèn cho chính mình, tự mình nương tựa mình, không nương tựa một ai khác, lấy Chánh pháp làm ngọn đèn, nương tựa Chánh pháp, không nương tựa một gì khác.`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },

{ text: `Này các Tỷ kheo, hãy đi lại trong giới hạn được phép của mình, trong giới hạn Tổ phụ các Ngươi truyền lại. Này các Tỷ kheo, nếu các Ngươi đi lại trong giới hạn được phép của mình, trong giới hạn Tổ phụ các Ngươi truyền lại thời tuổi thọ sẽ được tăng thịnh, sắc đẹp sẽ được tăng thịnh, an lạc sẽ được tăng thịnh, tài sản sẽ được tăng thịnh, thế lực sẽ được tăng thịnh.`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },

{ text: `Này các Tỷ kheo, như thế nào vị Tỷ kheo tuổi thọ được tăng thịnh? Này các Tỷ kheo, ở đây, vị Tỷ kheo tu tập thần túc, đầy đủ Dục thiền định tinh cần hành; tu tập thần túc, đầy đủ Tinh tấn thiền định tinh cần hành; tu tập thần túc đầy đủ Tâm định tinh cần hành; tu tập thần túc đầy đủ Tư duy thiền định tinh cần hành. Vị này tu tập bốn pháp thần túc này một cách tinh cần, nếu muốn sống kéo dài một kiếp hay năm còn lại của một kiếp. Này các Tỷ kheo, như vậy Ta nói vị Tỷ kheo tuổi thọ được tăng thịnh.`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },

{ text: `Này các Tỷ kheo, thế nào là vị Tỷ kheo sắc đẹp được tăng thịnh? Này các Tỷ kheo, ở đây, vị Tỷ kheo sống giữ giới luật, chế ngự với sự chế ngự của giới bổn Pātimokkha, đầy đủ oai nghi chánh hạnh, thấy nguy hiểm trong những lỗi nhỏ nhặt, thọ lãnh và tu học trong giới pháp. Này các Tỷ kheo, như vậy vị Tỷ kheo sắc đẹp được tăng thịnh.`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },

{ text: `Này các Tỷ kheo, thế nào là vị Tỷ kheo an lạc được tăng thịnh? Này các Tỷ kheo, ở đây, vị Tỷ kheo ly dục, ly ác pháp, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh với tầm, với tứ; diệt tầm, diệt tứ, chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm, không tứ … chứng và trú Thiền thứ ba … chứng và trú Thiền thứ tư. Này các Tỷ kheo, như vậy vị Tỷ kheo an lạc được tăng thịnh.`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },

{ text: `Này các Tỷ kheo, thế nào là vị Tỷ kheo tài sản được tăng thịnh? Này các Tỷ kheo, ở đây, vị Tỷ kheo an trú, biến mãn một phương với tâm câu hữu với từ, cũng vậy phương thứ hai, cũng vậy phương thứ ba, cũng vậy phương thứ tư. Như vậy cùng khắp thế giới, trên, dưới, bề ngang, hết thảy phương xứ, cùng khắp vô biên giới, vị ấy an trú biến mãn với tâm câu hữu với từ, quảng đại vô biên, không hận, không sân, với tâm câu hữu với bi … với tâm câu hữu với hỷ … Vị ấy an trú biến mãn với tâm câu hữu với xả, quảng đại vô biên, không hận, không sân. Này các Tỷ kheo, như vậy vị Tỷ kheo, tài sản được tăng thịnh.`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },

{ text: `Này các Tỷ kheo, như thế nào là vị Tỷ kheo thế lực được tăng thịnh? Này các tỷ kheo, ở đây vị Tỷ kheo, với sự diệt tận các lậu hoặc, tự mình biết và chứng, đạt đến an trú ngay trong hiện tại tâm giải thoát, tuệ giải thoát không còn các lậu hoặc. Này các Tỷ kheo, như vậy là vị Tỷ kheo thế lực được tăng thịnh.\nNày các Tỷ kheo, ta quán sát và thấy không có một uy lực nào khác khó nhiếp phục hơn uy lực của Ma vương. Này các Tỷ kheo, chính nhờ chấp nhận và thực hành những thiện pháp ấy mà công đức này được tăng thịnh!`, ref: "Trường Bộ 26 – Kinh Chuyển luân Thánh vương Sư tử hống", url: "https://loicuaducphat.org/dn/dn26.html#content" },

{ text: `Ðối với họ, than đỏ được dập tắt, khói được tiêu tan, cối và chầy rơi ngả nghiêng, buổi chiều lo ăn buổi ăn chiều, buổi sáng lo buổi ăn sáng; họ đi vào làng, vào thị xã, vào kinh đô để khất thực. Khi xin được đồ ăn rồi, họ lại vào các chòi lá trong khu rừng để tu thiền. Này Vāsaṭṭha, họ “Jhāyanti”, tu thiền, tức là họ suy tư Jhàyakà. Jhàyakà là danh từ thứ hai được khởi lên.`, ref: "Trường Bộ 27 – Kinh Khởi thế nhân bổn", url: "https://loicuaducphat.org/dn/dn27.html#content" },

{ text: `Các vị ấy loại bỏ các ác, bất thiện pháp, tức là Bràhmanà (Bà-la-môn), và chữ Bràhmanà là danh từ đầu tiên được khởi lên. Những vị này lập lên những chòi bằng lá tại các khu rừng và tu thiền trong những nhà chòi bằng lá ấy. Ðối với họ, than đỏ được dập tắt, khói được tiêu tan, cối và chầy rơi ngả nghiêng, buổi chiều lo buổi ăn chiều, buổi sáng lo buổi ăn sáng; họ đi vào làng, vào thị xã, vào kinh đô để khất thực. Khi họ xin được đồ ăn rồi, họ lại vào các chòi lá trong các khu rừng để tu thiền.`, ref: "Trường Bộ 27 – Kinh Khởi thế nhân bổn", url: "https://loicuaducphat.org/dn/dn27.html#content" },
{ text: `Bạch Thế Tôn, lại nữa, điểm này thật là vô thượng: Thế Tôn thuyết pháp về các thiện pháp. Ở đây những thiện pháp là Bốn Niệm xứ, Bốn Chánh cần, Bốn Như ý túc, Năm Căn, Năm Lực, Bảy Giác chi, Thánh đạo tám ngành. Bạch Thế Tôn, ở đây vị Tỷ kheo tận diệt các lậu hoặc, có thể tự mình chứng tri và chứng ngộ, đạt đến và an trú ngay trong hiện tại, Tâm giải thoát và Tuệ giải thoát vô lậu này. Bạch Thế Tôn, thật là vô thượng đối với các thiện pháp. Tất cả điểm này, Thế Tôn đã biết và ngoài sự hiểu biết của Ngài, không có gì còn lại để hiểu biết hơn nữa. Không có một ai, một Sa môn hay một Bà-la-môn nào khác có thể chứng biết hơn Thế Tôn về vấn đề các thiện pháp.`, ref: "Trường Bộ 28 – Kinh Tự hoan hỷ", url: "https://loicuaducphat.org/dn/dn28.html#content" },

{ text: `Lại nữa, bạch Thế Tôn, điểm này thật là vô thượng: Thế Tôn thuyết pháp về vấn đề chánh hạnh trong ngôn ngữ. Bạch Thế Tôn, ở đây, một người không những không nói những lời liên hệ đến nói láo, mà cũng phải, trong khi tìm cách thắng cuộc, không dùng lời vu khống, lời ác khẩu và lời ly gián; trái lại, người ấy nói lời từ hòa, sáng suốt, đáng được giữ gìn, và nói đúng thời. Bạch Thế Tôn, như vậy là tối thượng về chánh hạnh trong ngôn ngữ.`, ref: "Trường Bộ 28 – Kinh Tự hoan hỷ", url: "https://loicuaducphat.org/dn/dn28.html#content" },

{ text: `Lại nữa, bạch Thế Tôn, điểm này thật là vô thượng: Thế Tôn thuyết pháp về vấn đề giới hạnh của con người. Bạch Thế Tôn, ở đây, có người chân thật, thành tín, không dối trá, không lừa gạt, không gợi ý, không chiêm tướng, không lấy lợi câu lợi; hộ trì các căn, ăn uống tiết độ, hành động ôn hòa, luôn luôn cảnh giác, không chán nản, tinh cần, trầm tư, chánh niệm, ngôn từ lanh lợi, hành vi gan dạ, chịu đựng, biết điều, không tham dục, tỉnh giác, cẩn trọng. Bạch Thế Tôn, như vậy là tối thượng về vấn đề giới hạnh của con người.`, ref: "Trường Bộ 28 – Kinh Tự hoan hỷ", url: "https://loicuaducphat.org/dn/dn28.html#content" },

{ text: `Bạch Thế Tôn, những gì có thể đạt được bởi một thiện nam tử có lòng tin, có tinh tấn, có kiên trì bởi sự kiên trì của con người, bởi sự tinh tấn của con người, bởi sự tiến bộ của con người, bởi sự nhẫn nhục của con người, đều được Thế Tôn chứng đạt. Bạch Thế Tôn, Thế Tôn không có đam mê các dục lạc, dục lạc này là đê tiện, hèn hạ, thuộc phàm phu, không xứng bậc Thánh, không có lợi ích. Thế Tôn cũng không đam mê tu hành khổ hạnh, khổ hạnh này là khổ, không xứng bậc Thánh, không có lợi ích. Thế Tôn có thể đạt được nếu Ngài muốn, một cách dễ dàng, một cách đầy đủ, sự hạnh phúc ngay trong hiện tại, do bốn Thiền định đem lại.`, ref: "Trường Bộ 28 – Kinh Tự hoan hỷ", url: "https://loicuaducphat.org/dn/dn28.html#content" },
{ text: `Do vậy, này Cunda, những pháp do Ta tự chứng tri và tuyên bố cho các Ngươi, tất cả các Ngươi hãy hội họp lại và tụng đọc lại, chớ có cãi lộn nhau, nhưng hãy so sánh các nghĩa với nhau, các câu với nhau để cho phạm hạnh này được tồn tại lâu dài, được an trú lâu dài, vì hạnh phúc cho muôn loài, vì an lạc cho muôn loài, vì lòng thương tưởng cho đời, vì lợi ích, vì an lạc cho chư Thiên và cho loài Người. Những pháp ấy là Bốn Niệm xứ, Bốn Chánh cần, Bốn Như ý túc, Năm Căn, Năm Lực, Bảy Giác chi, Tám Thánh đạo.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, các Ngươi hãy hội họp với nhau trong tinh thần hòa đồng và tương kính, không có tranh luận nhau. Có vị đồng phạm hạnh nói pháp giữa Tăng chúng. Nếu các Ngươi nghĩ rằng “Vị Ðại đức này nắm nghĩa sai lạc hay hành văn sai lạc”, các Ngươi không nên tán thán, không nên bác bỏ, các Ngươi phải giải thích cho vị ấy một cách cẩn thận cả nghĩa lẫn hành văn.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, các Ngươi hãy hội họp với nhau trong tinh thần hòa đồng và tương kính, không có tranh luận nhau. Này Cunda, có vị đồng phạm hạnh khác nói pháp giữa Tăng chúng. Nếu các Ngươi nghĩ rằng: “Vị Ðại đức ấy nắm nghĩa sai lạc nhưng hành văn đúng đắn”, các Ngươi không nên tán thán, không nên bác bỏ. Không thán thán, không bác bỏ, các ngươi nên nói với vị ấy: “Này Hiền giả, giữa những cách hành văn này, nghĩa này hay nghĩa kia, nghĩa nào thích hợp hơn?” Nếu vị ấy trả lời: “Này Hiền giả, giữa những cách hành văn này, nghĩa này thích hợp hơn nghĩa kia”, các Ngươi không nên bác bỏ, không phỉ báng, các Ngươi phải giải thích một cách cẩn thận ý nghĩa đúng đắn cho vị ấy.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda Ta không thuyết giảng chỉ để ngăn chận các lậu hoặc ngay trong hiện tại. Này Cunda, Ta không thuyết pháp, chỉ để diệt trừ các lậu hoặc trong tương lai mà thôi. Này Cunda, Ta thuyết pháp vừa để ngăn chận các lậu hoặc ngay trong hiện tại mà cũng để diệt trừ các lậu hoặc trong tương lai nữa.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Do vậy, này Cunda, tấm y mà Ta cho phép các Ngươi mặc, như vậy vừa đủ cho các Ngươi ngăn chận lạnh, ngăn chận nóng, ngăn chận sự xúc chạm của các loài ruồi muỗi, của gió, mặt trời và các loài rắn, và các che dấu sự hổ thẹn.\nCác món ăn khất thực mà Ta cho phép các Ngươi dùng, như vậy vừa đủ để nuôi dưỡng thân thể, giúp thân thể sống còn, tránh khỏi nguy hại và giúp đời sống phạm hạnh với hy vọng: “Như vậy ta diệt trừ các cảm thọ cũ và không cho khởi lên các cảm thọ mới. Nhờ vậy đời sống của ta mới khỏi bị lầm lỗi và ta sống an lạc.”`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Nhà cửa nào mà Ta cho phép các ngươi an trú, như vậy vừa đủ cho các Ngươi ngăn chận lạnh, ngăn chận nóng, ngăn chận sự xúc chạm của ruồi muỗi, gió, mặt trời và các loài rắn, chỉ với mục đích tránh thoát sự nguy hiểm của thời tiết, và an hưởng đời sống tịnh cư.\nCác dược phẩm và thuốc trị bịnh mà Ta cho phép các Ngươi dùng, như vậy vừa đủ để ngăn chận các cảm thọ đau ốm khởi lên và để gìn giữ sức khỏe.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, ở đây có người ngu si, sau khi sát sanh, tự mình sung sướng hoan hỷ, đó là hỷ lạc thứ nhất. Lại nữa, này Cunda, ở đây có người sau khi lấy của không cho, tự mình sung sướng, hoan hỷ, đó là hỷ lạc thứ hai. Lại nữa, này Cunda, ở đây có người sau khi nói láo, tự mình sung sướng, hoan hỷ, đó là hỷ lạc thứ ba. Lại nữa này Cunda, ở đây có người say đắm, đam mê sống vây quanh với năm món dục lạc, đó là hỷ lạc thứ tư. Này Cunda, bốn loại hỷ lạc này là thấp kém, hạ liệt, thuộc phàm phu, không xứng Thánh hạnh, không có lợi ích, không hướng đến yểm ly, vô tham, tịch diệt, an tịnh, thắng trí, giác ngộ và Niết-bàn. Này Cunda, sự kiện này có thể xảy ra. Các du sĩ ngoại đạo có thể nói: “Các vị Sa-môn Thích tử đang sống đam mê bốn loại hỷ lạc này”. Họ cần phải được trả lời: “Nói như vậy là không phải; các ông nói như vậy là không đúng đắn. Nói như vậy là các ông xuyên tạc, không đúng sự thật, không thực có”.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, có bốn loại hỷ lạc này. Thế nào là bốn? Này Cunda, ở đây vị Tỷ-kheo, ly dục, ly ác pháp, chứng và an trú Sơ thiền, một trạng thái hỷ lạc do ly dục sanh, với tầm, với tứ. Ðó là hỷ lạc thứ nhất. Lại nữa này Cunda, vị Tỷ-kheo diệt tầm và tứ, chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm không tứ, nội tĩnh nhất tâm. Ðó là hỷ lạc thứ hai. Lại nữa này Cunda, vị Tỷ-kheo ly hỷ trú xả … chứng và trú Thiền thứ ba … Ðó là hỷ lạc thứ ba. Lại nữa này Cunda, vị Tỷ-kheo xả lạc, xả khổ … chứng và trú Thiền thứ tư … Ðó là hỷ lạc thứ tư. Này Cunda, bốn loại hỷ lạc nhất định đưa đến yểm ly, vô tham, tịch diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn. Này Cunda, sự kiện này có thể xảy ra. Các du sĩ ngoại đạo có thể nói: “Các vị Sa-môn Thích tử đang sống đam mê bốn loại hỷ lạc này”. Họ cần phải được trả lời: “Nói như vậy là phải; các ông nói như vậy là nói đúng đắn. Nói như vậy là các ông không xuyên tạc, đúng sự thật, và thực có”.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, sự kiện này có thể xảy ra. Các du sĩ ngoại đạo có thể nói: “Các Sa-môn Thích tử sống không giữ vững lập trường”. Này Cunda, các vị du sĩ ngoại đạo nói vậy cần phải được trả lời như sau: “Này Hiền giả, Thế Tôn, vị đã biết, đã thấy, là bậc A-la-hán, Chánh Ðẳng Giác đã thuyết, đã trình bày những pháp cho các đệ tử cho đến trọn đời. Này Hiền giả, giống như cột trụ bằng đá hay bằng sắt, chân cột được khéo chôn sâu vào đất, không lắc qua lại, không có rung động. Cũng vậy này Hiền giả, Thế Tôn, vị đã biết, đã thấy là bậc A-la-hán, Chánh Ðẳng Giác đã thuyết, đã trình bày những pháp cho các đệ tử cho đến trọn đời. Này Hiền giả, giống như cột trụ bằng đá hay bằng sắt, chân cột được khéo chôn sâu vào đất, không lắc qua lại, không có rung động. Cũng vậy này Hiền giả, Thế Tôn, vị đã biết, đã thấy là bậc A-la-hán, Chánh Ðẳng Giác đã thuyết, đã trình bày những pháp cho các đệ tử cho đến trọn đời.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Hiền giả, vị Tỷ-kheo là bậc A-la-hán, đã diệt trừ các lậu hoặc, phạm hạnh đã thành, các việc phải làm đã làm, đã đặt gánh nặng xuống, mục tiêu đã đạt, hữu kiết sử đã diệt trừ, chánh trí giải thoát, không thể làm chín việc sau đây: Này Hiền giả, vị Tỷ-kheo đã diệt trừ các lậu hoặc, không thể cố ý tước đoạt sanh mạng của loài hữu tình; vị Tỷ-kheo đã diệt trừ các lậu hoặc không thể lấy của không cho, tức là ăn trộm; vị Tỷ kheo đã diệt trừ các lậu hoặc không thể hành dâm; vị Tỷ-kheo đã diệt trừ các lậu hoặc, không thể biết mà nói láo; vị Tỷ-kheo đã diệt trừ các lậu hoặc không thể cất chứa tiền của để hưởng thọ dục lạc, như khi còn tại gia; vị Tỷ-kheo đã diệt tận các lậu hoặc không thể đi con đường hành tham; vị Tỷ-kheo đã diệt tận các lậu hoặc không thể đi con đường hành sân; vị Tỷ-kheo đã diệt tận các lậu hoặc, không thể đi con đường hành si; vị Tỷ-kheo đã diệt tận các lậu hoặc, không thể đi con đường hành theo sợ hãi. Này Hiền giả, một vị Tỷ-kheo, là bậc A-la-hán, Chánh Ðẳng Giác, đã diệt tận các lậu hoặc, phạm hạnh đã thành, các việc phải làm đã làm, đã đặt gánh nặng xuống, mục tiêu đã đạt, hữu kiết sử đã diệt trừ, chánh trí giải thoát, không thể làm chín việc như vậy”.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, sự kiện này có thể xảy ra. Các du sĩ ngoại đạo có thể nói như sau: “Ðối với quá khứ, Sa-môn Gotama có tri kiến siêu việt. Nhưng đối với tương lai, Sa-môn Gotama không có tri kiến siêu việt; như sự việc xảy ra như thế nào và vì sao lại xảy ra như vậy?” Như vậy, các vị du sĩ ngoại đạo này chủ trương rằng tri kiến về vấn đề này có thể được trình bày nêu rõ bởi tri kiến một vấn đề khác, như những kẻ ngu si, không thông minh khác. Này Cunda, về vấn đề quá khứ, Như Lai có thể nhớ đến đời sống quá khứ. Ngài muốn như thế nào, Ngài có thể nhớ xa được như vậy. Về vấn đề vị lai, Như Lai có trí do tuệ sanh: “Ðây là đời sống cuối cùng, nay không còn đời sống nào khác nữa”.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, nếu những gì thuộc quá khứ, vị lai, hay hiện tại là hư vọng, không thật, không lợi ích, Như Lai không trả lời. Này Cunda, nếu những gì thuộc quá khứ, vị lai, hay hiện tại là chơn chánh, như thật, nhưng không lợi ích, Như Lai cũng không trả lời. Này Cunda, nếu những gì thuộc quá khứ, vị lai, hay hiện tại là chơn chánh, như thật, có lợi ích, Như Lai biết thời trả lời câu hỏi ấy. Như vậy, này Cunda, đối với các pháp quá khứ, vị lai, hiện tại, Như Lai là vị nói phải thời nói chơn chánh, nói như thật, nói có lợi ích, nói đúng Pháp, nói đúng Luật. Do vậy mới gọi là Như Lai.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, trong thế giới này với chư Thiên, Ma vương, Phạm thiên, với chúng Sa-môn và Bà-la-môn, với chư Thiên và loài Người, những gì được thấy, được nghe, được cảm giác, được phân biệt, được đạt đến, được tìm cầu, được suy đạt với ý, tất cả đều được Như Lai biết rõ. Do vậy mới gọi là Như Lai. Này Cunda, trong thời gian giữa đêm Như Lai chứng ngộ Vô thượng Chánh Ðẳng Giác và đêm Như Lai nhập Vô dư y Niết-bàn giới, trong thời gian ấy, những gì Như Lai nói trong khi thuyết giảng, nói chuyện hay trình bày, tất cả là như vậy, chớ không gì khác. Do vậy mới gọi là Như Lai. Này Cunda, Như Lai nói gì thời làm vậy, làm gì thời nói vậy. Nói gì thời làm vậy, làm gì thời nói vậy nên được gọi là Như Lai. Ðối với thế giới với chư Thiên, Ma vương, Phạm thiên, với chúng Sa-môn và Bà-la-môn, với chư Thiên và loài Người, Như Lai là bậc Toàn Thắng, không ai có thể thắng nổi, bậc Toàn kiến, bậc Tự Tại.`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, sự kiện này có thể xảy ra. Các du sĩ ngoại đạo có thể nói: “Này Hiền giả, vì sao Sa môn Gotama lại không nói?” Này Cunda, được nói vậy, Ngươi phải trả lời các du sĩ ngoại đạo như sau: “Này Hiền giả, vì không liên hệ đến lợi ích, không liên hệ đến Pháp, không liên hệ đến căn bản phạm hạnh, không hướng đến yểm ly, vô tham, đoạn diệt, an tịnh, thắng trí, giác ngộ và Niết bàn. Do vậy Thế Tôn không trả lời.”`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },

{ text: `Này Cunda, sự kiện này có thể xảy ra. Các du sĩ ngoại đạo có thể nói: “Này Hiền giả, Sa môn Gotama nói điều gì?” Này Cunda, được nói vậy, Ngươi phải trả lời các du sĩ ngoại đạo như sau: “Ðây là Khổ, này Hiền giả, đó là điều Thế Tôn nói. Ðây là Khổ tập, này Hiền giả, đó là điều Thế Tôn nói. Ðây là Khổ diệt, này Hiền giả, đó là điều Thế Tôn nói. Ðây là con đường đưa đến Khổ diệt, này Hiền giả, đó là điều Thế Tôn nói.”\nNày Cunda, sự kiện này có thể xảy ra. Các du sĩ ngoại đạo có thể nói: “Này Hiền giả, vì sao Thế Tôn lại nói vậy?” Này Cunda, được nói như vậy, Ngươi phải trả lời cho các du sĩ ngoại đạo như sau: “Này Hiền giả, vì liên hệ đến lợi ích, liên hệ đến Pháp, liên hệ đến căn bản phạm hạnh, vì nhất định hướng đến yểm ly, vô tham, đoạn diệt, an tịnh, thắng trí, giác ngộ và Niết bàn. Do vậy, Thế Tôn mới nói.”`, ref: "Trường Bộ 29 – Kinh Thanh Tịnh", url: "https://loicuaducphat.org/dn/dn29.html#content" },
{ text: `Này Gia chủ tử, quen thói lười biếng có sáu nguy hiểm: “quá lạnh”, không làm việc; “quá nóng”, không làm việc; “quá trễ” không làm việc; “quá sớm”, không làm việc; “tôi đói quá”, không làm việc; “tôi quá no”, không làm việc. Trong khi những công việc phải làm lại không làm. Tài sản chưa có không xây dựng lên, tài sản có rồi bị tiêu thất. Này Gia chủ tử, quen thói lười biếng có sáu nguy hiểm như vậy. Thế Tôn thuyết giảng như vậy.`, ref: "Trường Bộ 31 – Kinh Giáo Thọ Thi-ca-la-việt", url: "https://loicuaducphat.org/dn/dn31.html#content" },

{ text: `Này các Hiền giả, Như Lai thanh tịnh thiện hành về thân. Như Lai không có ác về thân mà Như Lai phải gìn giữ: “Chớ để người khác biết việc này về Ta”. Này các Hiền giả, Như Lai thanh tịnh thiện hành về miệng. Như Lai không có ác hạnh về miệng mà Như Lai phải gìn giữ: “Chớ để người khác biết việc này về Ta”. Này các Hiền giả, Như Lai thanh tịnh thiện hành về ý. Như Lai không có ác hạnh về ý mà Như Lai phải gìn giữ: “Chớ để người khác biết việc này về Ta”.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Bốn chánh cần: Ở đây, này các Hiền giả vị Tỷ-kheo, với mục đích khiến cho các ác, bất thiện pháp từ trước chưa sanh không cho sanh khởi, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm. Với mục đích khiến cho các ác bất thiện pháp đã sanh ra được trừ diệt, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm. Với mục đích khiến cho các thiện pháp từ trước chưa sanh nay cho sanh khởi, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm. Với mục đích khiến cho các thiện pháp đã được sanh có thể duy trì, không có mù mờ, được tăng cường, được quảng đại, được tu tập, được viên mãn, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, thế nào là sự tu tập thiền định, nhờ tu tập, nhờ hành trì nhiều lần đưa đến lạc trú ngay trong hiện tại? Ở đây, này các Hiền giả, có vị Tỷ-kheo ly dục, ly ác pháp, và trú thiền thứ nhất … thiền thứ hai … thiền thứ ba … chứng và trú thiền thứ tư. Này các Hiền giả, như vậy là sự tu tập thiền định, nhờ tu tập, nhờ hành trì nhiều lần đưa đến lạc trú ngay trong hiện tại.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, thế nào là sự tu tập thiền định, nhờ tu tập, nhờ hành trì nhiều lần đưa đến chứng đắc tri kiến? Này các Hiền giả, ở đây, vị Tỷ-kheo, tác ý quang minh tưởng, an trú tưởng ban ngày, ban ngày thế nào ban đêm như vậy, ban đêm thế nào ban ngày như vậy. Và như vậy với tâm mở rộng không có đóng kín, tạo ra một tâm có hào quang. Này các Hiền giả, như vậy là tu tập thiền định, nhờ tu tập, nhờ hành trì nhiều lần, đưa đến chứng đắc tri kiến.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, thế nào là sự tu tập thiền định, nhờ tu tập, nhờ hành trì nhiều lần, hướng đến chánh niệm, tỉnh giác? Này các Hiền giả, ở đây, vị Tỷ-kheo biết được thọ khởi, biết được thọ trú, biết được thọ diệt, biết được tưởng khởi, biết được tưởng trú, biết được tưởng diệt, biết được tầm khởi, biết được tầm trú, biết được tầm diệt. Này các Hiền giả, như vậy là sự tu tập thiền định, nhờ tu tập, nhờ hành trì nhiều lần, đưa đến chánh niệm tỉnh giác.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, thế nào là sự tu tập thiền định, nhờ tu tập, nhờ hành trì nhiều lần, đưa đến sự diệt tận các lậu hoặc? Này các Hiền giả, ở đây vị Tỷ-kheo an trú, quán tánh sanh diệt trên Năm Thủ uẩn- Ðây là sắc, đây là sắc tập, đây là sắc diệt. Ðây là thọ … Ðây là tưởng … Ðây là hành … Ðây là thức, đây là thức tập, đây là thức diệt. Này các Tỷ-kheo, như vậy là sự tu tập thiền định, nhờ tu tập, nhờ hành trì nhiều lần, đưa đến sự diệt tận các lậu hoặc.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ-kheo tự bằng lòng với bất cứ phòng xá nào, tán thán sự bằng lòng với bất cứ phòng xá nào, không cố gắng tìm cầu phòng xá một cách không xứng đáng, không có áo não nếu không được trú xứ. Nhưng khi được phòng xá, vị này không nhiễm trước, không say mê, không có phạm tội. Vị này dùng các phòng xá, thấy các nguy hiểm và biết rõ sự giải thoát. Vì tự bằng lòng với bất cứ phòng xá nào, vị này không khen mình chê người. Ở đây, vị này khéo léo, tinh cần, tỉnh giác, chánh niệm. Này các Hiền giả, vị Tỷ-kheo ấy được gọi là một vị đã trung thành với Thánh chủng, theo truyền thống quá khứ.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ-kheo ưa thích đoạn trừ, hoan hỷ đoạn trừ, ưa thích tu tập, hoan hỷ tu tập. Nhờ ưa thích đoạn trừ, hoan hỷ đoạn trừ, ưa thích tu tập, hoan hỷ tu tập nên không khen mình chê người. Ở đây, vị Tỷ-kheo này khéo léo, tinh cần, tỉnh giác, chánh niệm. Này các Hiền giả, vị ấy được gọi là một vị đã trung thành với Thánh chủng, theo truyền thống quá khứ.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, thế nào là đoạn trừ tinh cần? Này các Hiền giả, ở đây, vị Tỷ-kheo không chấp nhận dục tầm đã khởi lên, từ bỏ, đoạn trừ, tiêu diệt, không cho hiện hữu; không chấp nhận sân tầm đã khởi lên … không chấp nhận hại tầm đã khởi lên, từ bỏ, đoạn trừ, tiêu diệt, không cho hiện hữu. Này các Hiền giả, như vậy gọi là đoạn trừ tinh cần.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Vị ấy thành tựu giới đức được các bậc Thánh ái mộ, không bị hư hoại, không bị tỳ vết, được thực hành liên tục, không bị khiếm khuyết khiến con người tự tại, được bậc Thánh tán thán, không bị nhiễm ô, hướng đến thiền định.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, do nhân y phục, vị Tỷ-kheo khởi lên lòng tham ái. Này các Hiền giả, do nhân đồ ăn khất thực, vị Tỷ-kheo khởi lên lòng tham ái. Này các Hiền giả, do nhân phòng xá, vị Tỷ-kheo khởi lên lòng tham ái. Này các Hiền giả, do nhân hữu và phi hữu, vị Tỷ-kheo khởi lên lòng tham ái.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, một vị Lậu tận Tỷ kheo không thể cố sát hại đời sống loài hữu tình. Một vị Lậu tận Tỷ kheo không thể cố ý lấy của không cho gọi là trộm cắp. Một vị Lậu tận Tỷ kheo không thể cố ý hành dâm. Một vị Lậu tận Tỷ kheo không thể cố ý tự mình biết mà nói láo. Một vị Lậu tận Tỷ kheo không thể tiêu dùng các vật chứa cất vào các thú vui dục lạc như khi còn là cư sĩ.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, năm pháp nội tâm một vị Tỷ kheo cần phải có nếu muốn chỉ trích một vị khác: “Tôi nói đúng thời, không phải phi thời. Tôi nói đúng sự thật, không sai sự thật. Tôi nói một cách từ tốn, không nói lời ác khẩu. Tôi nói lời có lợi ích, không nói lời không có lợi ích. Tôi nói lời có lòng từ, không phải lời sân hận”. Này các Hiền giả, như vậy là năm pháp nội tâm một vị Tỷ kheo cần phải có, nếu muốn chỉ trích một vị khác.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, ở đây vị Tỷ kheo có lòng tin, tin tưởng sự giác ngộ của Như Lai. Vị ấy thiểu bệnh, thiểu não, sự tiêu hóa được điều hòa, không lạnh quá, không nóng quá, trung bình hợp với sự tinh tấn. Vị ấy không lường đảo, dối gạt, nêu rõ tự mình như chơn đối với bậc Ðạo Sư, đối với các vị sáng suốt hay đối với các vị đồng phạm hạnh. Vị ấy sống siêng năng, tinh tấn, từ bỏ các ác pháp, thành tựu các thiện pháp, cương quyết, kiên trì nỗ lực, không tránh né đối với các thiện pháp. Vị ấy có trí tuệ, thành tựu trí tuệ hướng đến sự sanh diệt của các pháp, thành tựu Thánh quyết trạch, đưa đến sự đoạn diệt chơn chánh các khổ đau.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo, khi những giới luật của vị này không bị phá hoại, không vi phạm, được kiên trì tuân hành, không có tỳ vết, làm con người được giải thoát, được người trí tán thán, không uế tạp, hướng đến thiền định, vị Tỷ kheo ấy giữ giới hạnh Sa môn như vậy, sống trước mặt hay sau lưng với các vị đồng phạm hạnh như vậy là một pháp hòa kính, tạo ra từ ái, tạo ra cung kính, đưa đến đoàn kết, không tranh luận, hòa hợp, đồng tâm, ý hợp.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo, đối với các đồ vật được cúng dường một cách hợp pháp cho đến đồ vật nhận trong bình bát, đều đem chia đồng đều giữa các vị Tỷ kheo có giới hạnh, như vậy là một pháp hòa kính, tạo ra từ ái, tạo ra cung kính, đưa đến đoàn kết, không tranh luận, hòa hợp, đồng tâm, ý hợp.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa khi vị Tỷ kheo thành tựu từ ý nghiệp trước mặt hay sau lưng, đối với các vị đồng phạm hạnh, như vậy là một pháp hòa kính, tạo ra từ ái, tạo ra cung kính, đưa đến đoàn kết, không tranh luận, hòa hợp, đồng tâm, ý hợp.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, ở đây có việc vị Tỷ kheo phải làm. Vị này nghĩ: “Có công việc ta sẽ phải làm. Nếu ta làm việc, thời thân ta sẽ mệt mỏi. Vậy ta nên nằm xuống”. Vị ấy nằm xuống, không có tinh tấn để đạt được điều chưa đạt được, để thành tựu điều chưa thành tựu, để chứng ngộ điều chưa chứng ngộ được, như vậy là giải đãi sự thứ nhất.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo bị đau bệnh nhẹ. Vị này nghĩ: “Nay ta bị đau bệnh nhẹ, cần phải nằm nghỉ. Vậy ta nên nằm xuống”. Vị ấy nằm xuống, không có tinh tấn để đạt được điều chưa đạt được, để thành tựu điều chưa thành tựu, để chứng ngộ điều chưa chứng ngộ được, như vậy là giải đãi sự thứ bảy.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo mới đau bệnh dậy, mới khỏi bệnh không bao lâu. Vị ấy nghĩ: “Ta mới đau bệnh dậy, mới khỏi bệnh không bao lâu. Thân này của ta yếu đuối, không làm được việc gì, vậy ta hãy nằm xuống”. Vị ấy nằm xuống, không có tinh tấn để đạt được điều chưa đạt được, để thành tựu điều chưa thành tựu được, để chứng ngộ điều chưa chứng ngộ được. Như vậy là giải đãi sự thứ tám.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo bị đau bệnh nhẹ. Vị ấy nghĩ: “Ta nay bị đau bệnh nhẹ, sự kiện này có thể xảy ra, bệnh này có thể trầm trọng hơn. Vậy ta hãy cố gắng tinh tấn để đạt được điều gì chưa đạt được, thành tựu điều gì chưa thành tựu được, chứng ngộ điều gì chưa chứng ngộ được”. Và vị ấy tinh tấn để đạt được điều gì chưa đạt được, thành tựu điều gì chưa thành tựu được, và chứng ngộ điều gì chưa chứng ngộ được. Ðó là tinh tấn sự thứ bảy.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo nghe nhiều, gìn giữ những gì đã nghe, chất chứa những gì đã nghe, Những pháp ấy, sơ thiện, trung thiện, hậu thiện, nghĩa lý văn cú cụ túc, đề cao đời sống phạm hạnh, hoàn toàn đầy đủ thanh tịnh những pháp ấy, vị đã nghe nhiều, đã nắm giữ, đã ghi nhớ nhờ tụng đọc nhiều lần, chuyên ý quán sát, khéo thành tựu nhờ chánh kiến.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo là thiện hữu, thiện bạn lữ, là thiện bạn đảng, là hộ trì nhân. Này các Hiền giả, vị Tỷ kheo nào là thiện hữu, là thiện bạn lữ, là thiện bạn đảng. Pháp như vậy là hộ trì nhân.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa vị Tỷ kheo thiện ngôn, đầy đủ sự nhu hòa và khiêm nhường, nhẫn nại và nhận sự chỉ trích một cách cung kính. Này các Hiền giả, vị Tỷ kheo nào thiện ngôn … nhận sự chỉ trích một cách cung kính. Pháp như vậy là hộ trì nhân.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, khi nào có những trách nhiệm cần phải làm đối với các vị đồng phạm hạnh niên lạp cao hơn, vị ấy khéo léo, không có biếng nhác, suy tư một cách đầy đủ các phương tiện, vừa đủ để làm, vừa đủ để tổ chức. Này các Hiền giả, một vị Tỷ kheo nào, đối với các vị đồng phạm hạnh … vừa đủ để tổ chức. Pháp như vậy là hộ trì nhân.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa có vị Tỷ kheo ưa Pháp, ái luyến nói Pháp, tự mình vô cùng hoan hỷ đối với Thắng pháp, Thắng luật. Này các Hiền giả, vị Tỷ kheo nào ưa Pháp … vô cùng hoan hỷ đối với Thắng pháp, Thắng luật. Pháp như vậy là hộ trì nhân.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo tự mình bằng lòng với các vật dụng nhận được như y phục, ẩm thực, sàng tọa, bệnh dược. Này các Hiền giả, vị Tỷ kheo nào tự bằng lòng … Pháp như vậy là hộ trì nhân.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa vị Tỷ kheo sống tinh tấn siêng năng đoạn trừ các ác pháp, thành tựu các thiện pháp, cương quyết, kiên trì tinh tấn, nhẫn trì không phế bỏ các thiện pháp. Này các Hiền giả, một vị Tỷ kheo nào sống tinh tấn siêng năng … nhẫn trì không phế bỏ các thiện pháp. Pháp như vậy là hộ trì nhân.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo chánh niệm, đầy đủ tối thượng niệm và tỉnh giác, nhớ đến và ghi nhớ những điều nói và làm từ lâu. Này các Hiền giả, vị Tỷ kheo nào có chánh niệm, ghi nhớ những điều đã nói và làm từ lâu. Pháp như vậy là hộ trì nhân.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Này các Hiền giả, lại nữa, vị Tỷ kheo có huệ trí, đầy đủ sanh diệt trí, hướng đến sự quyết trạch các bậc Thánh, chơn chánh diệt trừ mọi đau khổ. Này các Hiền giả, vị Tỷ kheo nào có huệ trí … chơn chánh diệt trừ mọi đau khổ. Pháp như vậy là hộ trì nhân.`, ref: "Trường Bộ 33 – Kinh Phúng Tụng", url: "https://loicuaducphat.org/dn/dn33.html#content" },

{ text: `Tám Suy Nghĩ của bậc Đại Nhân: Pháp này cho người thiểu dục, pháp này không phải cho người đa dục; pháp này cho người tri túc, pháp này không phải cho người không tri túc; pháp này cho người an tịnh độc cư, pháp này không phải cho người ưa tụ hội; pháp này cho người siêng năng tinh tấn, pháp này không phải cho người giải đãi; pháp này cho người có niệm hiền tiền, pháp này không phải cho người thất niệm; pháp này là cho người có định tâm, pháp này không phải cho người không có định tâm; pháp này cho người có trí tuệ, pháp này không phải cho người có ác tuệ; pháp này cho người không ưa thích lý luận, pháp này không phải cho người ưa thích lý luận. Như vậy là tám pháp cần được sanh khởi.`, ref: "Trường Bộ 34 – Kinh Thập Thượng", url: "https://loicuaducphat.org/dn/dn34.html#content" },

        
             { text: `Này các Tỷ-kheo, Như Lai là bậc A-la-hán, Chánh Ðẳng Giác, thắng tri địa đại là địa đại. Vì thắng tri địa đại là địa đại, Như Lai không nghĩ đến địa đại, không nghĩ đến (tự ngã) đối chiếu với địa đại, không nghĩ đến (tự ngã) như là địa đại, không nghĩ: “Ðịa đại là của ta” - không dục hỷ địa đại. Vì sao vậy? Vì Như Lai biết rằng: “Dục hỷ là căn bản của đau khổ, từ hữu, sanh khởi lên, và già và chết đến với loài sinh vật”. Do vậy, này các Tỷ-kheo, Ta nói vì Như Lai, với sự diệt trừ hoàn toàn các ái, sự ly tham, sự đoạn diệt, sự xả ly, sự từ bỏ hoàn toàn các ái, đã chơn chánh giác ngộ vô thượng chánh đẳng chánh giác.`, ref: "Trung Bộ 1 – Kinh Pháp Môn Căn Bản", url: "https://loicuaducphat.org/mn/mn1.html#content" },
			 { text: `“Này các Tỷ-kheo, có những lậu hoặc phải do tri kiến được đoạn trừ, có những lậu hoặc phải do phòng hộ được đoạn trừ, có những lậu hoặc phải do thọ dụng được đoạn trừ, có những lậu hoặc phải do kham nhẫn được đoạn trừ, có những lậu hoặc phải do tránh né được đoạn trừ, có những lậu hoặc phải do trừ diệt được đoạn trừ, có những lậu hoặc phải do tu tập được đoạn trừ.”`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `“Với người không như lý tác ý, một trong sáu tà kiến này khởi lên: ‘Ta có tự ngã’, tà kiến này khởi lên với người ấy như thật, như chơn; ‘Ta không có tự ngã’, tà kiến này khởi lên với người ấy như thật như chơn; ‘Do tự mình, ta tưởng tri ta có tự ngã’...”\n“Này các Tỷ-kheo, như vậy gọi là tà kiến, kiến trù lâm, kiến hoang vu, kiến hý luận, kiến tranh chấp, kiến kiết phược. Này các Tỷ-kheo, trói buộc bởi kiến kiết sử, kẻ phàm phu ít nghe không được giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói kẻ ấy không thoát khỏi khổ đau.”`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `“Này các Tỷ-kheo, và vị Thánh đệ tử nghe nhiều, được thấy các bậc Thánh, thuần thục pháp các bậc Thánh, tu tập pháp các bậc Thánh; được thấy các bậc Chơn nhơn, thuần thục pháp các bậc Chơn nhơn, tu tập pháp các bậc Chơn nhơn, tuệ tri các pháp cần phải tác ý, tuệ tri các pháp không cần phải tác ý.”\n“Vị ấy như lý tác ý: ‘Ðây là khổ’, như lý tác ý: ‘Ðây là khổ tập’, như lý tác ý: ‘Ðây là khổ diệt’, như lý tác ý: ‘Ðây là con đường đưa đến khổ diệt’. Nhờ vị ấy tác ý như vậy, ba kiết sử được trừ diệt: thân kiến, nghi, giới cấm thủ.”`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `“Này các Tỷ-kheo, thế nào là các lậu hoặc phải do phòng hộ được đoạn trừ? Ở đây, có Tỷ-kheo như lý giác sát, sống phòng hộ với sự phòng hộ mắt. Này các Tỷ-kheo, nếu Tỷ-kheo ấy sống không phòng hộ với sự phòng hộ mắt, các lậu hoặc tàn hại và nhiệt não ấy có thể khởi lên. Nếu sống phòng hộ mắt, các lậu hoặc tàn hại và nhiệt não ấy không còn nữa. Này các Tỷ-kheo, các pháp ấy được gọi là các lậu hoặc phải do phòng hộ được đoạn trừ.`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `Vị ấy như lý giác sát, thọ dụng món ăn khất thực không phải để vui đùa, không phải để đam mê, không phải để trang sức, không phải để tự làm đẹp mình, mà chỉ để thân này được sống lâu và được bảo dưỡng, để thân này khỏi bị thương hại, để hỗ trợ phạm hạnh, nghĩ rằng: “Như vậy, ta diệt trừ các cảm thọ cũ và không cho khởi lên các cảm thọ mới, và ta sẽ không có lỗi lầm, sống được an ổn”.`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `Này các Tỷ-kheo, ở đây, vị Tỷ-kheo như lý giác sát, kham nhẫn lạnh, nóng, đói, khát, sự xúc chạm của ruồi, muỗi, gió, sức nóng mặt trời, các loài bò sát; kham nhẫn những cách nói mạ lị phỉ báng. Vị ấy có tánh kham nhẫn các cảm thọ về thân, những cảm thọ thống khổ, khốc liệt, đau nhói, nhức nhối, không sung sướng, không thích thú, chết điếng người. Này các Tỷ-kheo, nếu vị ấy không kham nhẫn như vậy, các lậu hoặc tàn hại và nhiệt não có thể khởi lên. Nếu vị ấy kham nhẫn như vậy, các lậu hoặc tàn hại và nhiệt não ấy không còn nữa. Này các Tỷ-kheo, các pháp ấy được gọi là các lậu hoặc phải do kham nhẫn được đoạn trừ.`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `Vị ấy như lý giác sát, thọ dụng sàng tọa, chỉ để ngăn ngừa lạnh, ngăn ngừa nóng, ngăn ngừa sự xúc chạm của ruồi, muỗi, gió, sức nóng mặt trời, các loại bò sát, chỉ để giải trừ nguy hiểm của thời tiết, chỉ với mục đích sống độc cư an tịnh.\nVị ấy như lý giác sát thọ dụng dược phẩm trị bệnh, chỉ để ngăn chận các cảm giác khổ thống đã sanh, để được ly khổ hoàn toàn.\nNày các Tỷ-kheo, nếu vị ấy không thọ dụng như vậy, các lậu hoặc tàn hại và nhiệt não có thể khởi lên. Nếu vị ấy thọ dụng như vậy, các lậu hoặc tàn hại và nhiệt não ấy không còn nữa. Này các Tỷ-kheo, các pháp ấy được gọi là các lậu hoặc phải do thọ dụng được đoạn trừ.`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `Này các Tỷ-kheo, ở đây, Tỷ-kheo như lý giác sát tránh né voi dữ, tránh né ngựa dữ, tránh né bò dữ, tránh né chó dữ, rắn, khúc cây, gai góc, hố sâu, vực núi, ao nước nhớp, vũng nước. Có những chỗ ngồi không xứng đáng ngồi, những trú xứ không nên lai vãng, những bạn bè ác độc mà nếu giao du thì bị các vị đồng phạm hạnh có trí nghi ngờ, khinh thường; vị ấy như lý giác sát tránh né chỗ ngồi không xứng đáng ấy, trú xứ không nên lai vãng ấy và các bạn độc ác ấy.`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },

{ text: `Này các Tỷ-kheo, ở đây, Tỷ-kheo như lý giác sát không có chấp nhận dục niệm đã khởi lên, từ bỏ, trừ diệt, diệt tận, không cho tồn tại (dục niệm ấy); không có chấp nhận sân niệm đã khởi lên, từ bỏ, trừ diệt, diệt tận, không cho tồn tại (sân niệm ấy); không có chấp nhận hại niệm đã khởi lên, từ bỏ, trừ diệt, diệt tận, không cho tồn tại (hại niệm ấy); không chấp nhận các ác bất thiện pháp luôn luôn khởi lên, từ bỏ, trừ diệt, diệt tận, không cho tồn tại (các ác bất thiện pháp ấy)`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },
{ text: `“Này các Tỷ-kheo, đối với Tỷ-kheo những lậu hoặc nào phải do tri kiến được đoạn trừ đã được tri kiến đoạn trừ, những lậu hoặc nào phải do phòng hộ được đoạn trừ đã được phòng hộ đoạn trừ... Tỷ-kheo ấy được gọi là đã sống phòng hộ với sự phòng hộ tất cả lậu hoặc, đã đoạn diệt khát ái, đã thoát ly kiết sử, đã chánh quán kiêu mạn, đã diệt tận khổ đau.”`, ref: "Trung Bộ 2 – Kinh Tất Cả Lậu Hoặc", url: "https://loicuaducphat.org/mn/mn2.html#content" },
{ text: `Này các Tỷ-kheo, hãy là người thừa tự Pháp của Ta, đừng là những người thừa tự tài vật. Ta có lòng thương tưởng các Ngươi và Ta nghĩ: “Làm sao những đệ tử của Ta là những người thừa tự Pháp của Ta, không phải là những người thừa tự tài vật?”. Và này các Tỷ-kheo, nếu các Ngươi là những người thừa tự tài vật của Ta, không phải là những người thừa tự Pháp, thì không những các Ngươi trở thành những người mà người ta nói: “Cả thầy và trò đều là những người thừa tự tài vật, không phải là những người thừa tự Pháp”, mà cả Ta cũng trở thành người mà người ta nói: “Cả thầy và trò đều là những người thừa tự tài vật, không phải là những người thừa tự Pháp”.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },

{ text: `Này các Tỷ-kheo, dầu cho Tỷ-kheo này, sau khi ăn loại đồ ăn ấy, trừ bỏ đói lả và kiệt sức, và trải qua đêm ngày hôm ấy như vậy, nhưng đối với Ta, Tỷ-kheo đầu tiên đáng được kính nể hơn, và đáng được tán thán hơn. Vì sao vậy? Vì như vậy sẽ đưa đến cho Tỷ-kheo ấy, trong một thời gian lâu ngày, ít dục, biết đủ, khổ hạnh, dễ nuôi dưỡng, tinh cần, tinh tấn. Do vậy, này các Tỷ-kheo, hãy là người thừa tự Pháp của Ta, đừng là người thừa tự tài vật.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },

{ text: `Này chư Hiền, ở đây vị Ðạo Sư sống viễn ly mà các đệ tử không tùy học viễn ly. Những pháp nào vị Ðạo Sư dạy nên từ bỏ, những pháp ấy họ không từ bỏ, và họ sống trong sự đầy đủ, lười biếng, dẫn đầu về đọa lạc, bỏ rơi gánh nặng sống viễn ly.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },

{ text: `Này chư Hiền, các Thượng Tọa Tỷ-kheo có ba trường hợp đáng bị quở trách. Vị Ðạo Sư sống viễn ly, các đệ tử không tùy học viễn ly. Ðó là trường hợp thứ nhất, các Thượng Tọa Tỷ-kheo đáng bị quở trách. Và những pháp nào vị Ðạo Sư dạy nên từ bỏ, những pháp ấy họ không từ bỏ. Ðó là trường hợp thứ hai, các Thượng Tọa Tỷ-kheo đáng bị quở trách. Và họ sống đầy đủ, lười biếng, dẫn đầu về đọa lạc, bỏ rơi gánh nặng sống viễn ly. Ðó là trường hợp thứ ba, các Thượng Tọa Tỷ-kheo đáng bị quở trách. Này chư Hiền, các Thượng tọa Tỷ-kheo do ba trường hợp này đáng bị quở trách.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },

{ text: `Này chư Hiền, các Thượng tọa Tỷ-kheo có ba trường hợp đáng được tán thán. Vị Ðạo Sư sống viễn ly, các đệ tử tùy học viễn ly. Ðó là trường hợp thứ nhất, các Thượng Tọa Tỷ-kheo đáng được tán thán. Và những pháp nào vị Ðạo Sư dạy nên từ bỏ, những pháp ấy họ từ bỏ. Ðó là trường hợp thứ hai, các Thượng tọa Tỷ-kheo đáng được tán thán. Và họ không sống trong sự đầy đủ, không lười biếng, họ bỏ rơi gánh nặng về đọa lạc và dẫn đầu về sống viễn ly. Ðó là trường hợp thứ ba, các Thượng Tọa Tỷ-kheo đáng được tán thán. Này chư Hiền, các Thượng tọa Tỷ-kheo do ba trường hợp này, đáng được tán thán.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },

{ text: `Ở đây, này chư Hiền, tham là ác pháp, và sân cũng là ác pháp, có một con đường Trung đạo diệt trừ tham và diệt trừ sân, khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn. Và này chư Hiền con đường Trung đạo ấy là gì- (con đường) khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn? Ðó là con đường Thánh tám ngành, tức là: Chánh tri kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định. Này chư Hiền, đó là con đường Trung đạo, khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },

{ text: `Ở đây, này chư Hiền, phẫn nộ là ác pháp và hiềm hận cũng là ác pháp, giả dối là ác pháp và não hại cũng là ác pháp, tật đố là ác pháp và xan lẫn cũng là ác pháp, man trá là ác pháp và phản bội cũng là ác pháp, ngoan cố là ác pháp và bồng bột nông nổi cũng là ác pháp, mạn là ác pháp và tăng thượng mạn cũng là ác pháp, kiêu là ác pháp và phóng dật cũng là ác pháp. Có một con đường Trung đạo diệt trừ kiêu và diệt trừ phóng dật, khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn. Ðó là con đường Thánh tám ngành, tức là: Chánh tri kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },

{ text: `Và này chư Hiền, con đường Trung đạo ấy là gì- (con đường) khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn? Ðó là con đường Thánh tám ngành, tức là: Chánh tri kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định. Này chư Hiền, đó là con đường Trung đạo khiến (tịnh) nhãn sanh, khiến (chân) trí sanh, hướng đến tịch tịnh, thắng trí, giác ngộ, Niết-bàn.`, ref: "Trung Bộ 3 – Kinh Thừa Tự Pháp", url: "https://loicuaducphat.org/mn/mn3.html#content" },
{ text: `Này Bà-la-môn, rồi Ta suy nghĩ: “Những Sa-môn hay Bà-la-môn nào, thân nghiệp không thanh tịnh, sống tại các trú xứ xa vắng, trong rừng núi hoang vu, do nguyên nhân nhiễm trước, thân nghiệp không thanh tịnh, những Tôn giả Sa-môn hay Bà-la-môn ấy chắc chắn làm cho sợ hãi, khiếp đảm, bất thiện khởi lên. Ta không có thân nghiệp không thanh tịnh, sống tại các trú xứ xa vắng, trong rừng núi hoang vu. Thân nghiệp Ta thanh tịnh. Ta là một trong những bậc Thánh, với thân nghiệp thanh tịnh, sống tại các trú xứ xa vắng, trong rừng núi hoang vu”. Này Bà-la-môn, Ta tự quán sát thân nghiệp hoàn toàn thanh tịnh này, tự cảm thấy lòng tự tin được xác chứng hơn, khi sống trong rừng núi.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },

{ text: `Này Bà-la-môn, tùy thuộc vấn đề này, Ta suy nghĩ như sau: “Những Sa-môn hay Bà-la-môn nào dao động, tâm không an tịnh, sống tại các trú xứ xa vắng, trong rừng núi hoang vu, do nguyên nhân nhiễm trước bị dao động, tâm không an tịnh, những Tôn giả Sa-môn hay Bà-la-môn ấy chắc chắn làm cho sợ hãi, khiếp đảm, bất thiện khởi lên. Ta không có dao động, tâm không phải không an tịnh, sống tại các trú xứ xa vắng, trong rừng núi hoang vu. Ta không có dao động, tâm được an tịnh. Ta là một trong những bậc Thánh không có dao động, tâm được an tịnh, sống tại các trú xứ xa vắng, trong rừng núi hoang vu”. Này Bà-la-môn, Ta tự quán sát tâm Ta được an tịnh như vậy, tự cảm thấy lòng tự tin được xác chứng hơn, khi sống trong rừng núi.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },

{ text: `Này Bà-la-môn, tùy thuộc vấn đề này, Ta suy nghĩ như sau: “Những Sa-môn hay Bà-la-môn nào biếng nhác, kém tinh tấn, sống tại các trú xứ xa vắng, trong rừng núi hoang vu, do nguyên nhân nhiễm trước biếng nhác, kém tinh tấn, những Tôn giả Sa-môn hay Bà-la-môn ấy chắc chắn làm cho sợ hãi, khiếp đảm, bất thiện khởi lên. Ta không có biếng nhác, kém tinh tấn, sống tại các trú xứ xa vắng, trong rừng núi hoang vu. Ta siêng năng, tinh tấn. Ta là một trong những bậc Thánh siêng năng, tinh tấn, sống tại các trú xứ xa vắng, trong rừng núi hoang vu”. Này Bà-la-môn, Ta tự quán sát Ta siêng năng, tinh tấn như vậy, tự cảm thấy lòng tự tin được xác chứng hơn, khi sống trong rừng núi.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },

{ text: `Này Bà-la-môn, tùy thuộc vấn đề này, Ta suy nghĩ như sau: “Những Sa-môn hay Bà-la-môn nào thất niệm, không tỉnh giác, sống tại các trú xứ xa vắng, trong rừng núi hoang vu, do nguyên nhân nhiễm trước thất niệm, không tỉnh giác, những Tôn giả Sa-môn hay Bà-la-môn ấy chắc chắn làm cho sợ hãi, khiếp đảm, bất thiện khởi lên. Ta không có thất niệm, không phải không tỉnh giác, sống tại các trú xứ xa vắng, trong rừng núi hoang vu. Ta an trú niệm. Ta là một trong những bậc Thánh an trú niệm, sống tại các trú xứ xa vắng, trong rừng núi hoang vu”. Này Bà-la-môn, Ta tự quán sát Ta an trú niệm như vậy, tự cảm thấy lòng tự tin được xác chứng hơn, khi sống trong rừng núi.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },

{ text: `Này Bà-la-môn, tùy thuộc vấn đề này, Ta suy nghĩ như sau: “Những Sa-môn hay Bà-la-môn nào không định tĩnh, tâm bị tán loạn, sống tại các trú xứ xa vắng, trong rừng núi hoang vu, do nguyên nhân nhiễm trước không định tĩnh, tâm bị tán loạn, những Tôn giả Sa-môn hay Bà-la-môn ấy chắc chắn làm cho sợ hãi, khiếp đảm, bất thiện khởi lên. Ta được định tĩnh, tâm không bị tán loạn sống tại các trú xứ xa vắng, trong rừng núi hoang vu. Ta thành tựu định tâm. Ta là một trong những bậc Thánh thành tựu định tâm, sống tại các trú xứ xa vắng, trong rừng núi hoang vu”. Này Bà-la-môn, Ta tự quán sát Ta thành tựu định tâm như vậy, từ cảm thấy lòng tự tin được xác chứng hơn, khi sống trong rừng núi.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },

{ text: `Này Bà-la-môn, có một số Sa-môn, Bà-la-môn nghĩ rằng ngày giống như đêm, nghĩ rằng đêm giống như ngày. Như vậy, Ta nói rằng những Sa-môn, Bà-la-môn ấy sống trong si ám. Này Bà-la-môn, Ta nghĩ rằng đêm là đêm, nghĩ rằng ngày là ngày. Này Bà-la-môn, ai nói một cách chơn chánh sẽ nói như sau: “Vị hữu tình nào không có si ám, sinh ra ở đời vì hạnh phúc cho muôn loài, vì an lạc cho muôn loài, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho loài Trời và loài Người. Vị ấy khi nói một cách chân chánh về Ta sẽ nói như sau: “Là vị hữu tình không có si ám, sinh ra ở đời vì hạnh phúc cho muôn loài, vì an lạc cho muôn loài, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho loài Trời và loài Người”.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },

{ text: `Này Bà-la-môn, Ta tinh cần, tinh tấn, không lười biếng. Ta an trú chánh niệm, không có loạn, thân được khinh an, không có dao động, tâm được định tĩnh, chuyên nhất.\nNày Bà-la-môn, Ta ly dục, ly các ác pháp, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm với tứ.\nDiệt tầm, diệt tứ, Ta chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm, không tứ, nội tĩnh nhất tâm.\nLy hỷ trú xả, chánh niệm tỉnh giác, thân cảm sự lạc thọ mà các bậc Thánh gọi là xả niệm lạc trú, Ta chứng và an trú Thiền thứ ba.\nXả lạc và xả khổ, diệt hỷ ưu đã cảm thọ trước, Ta chứng và an trú Thiền thứ tư, không khổ không lạc, xả niệm thanh tịnh.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },

{ text: `Này Bà-la-môn trong đêm canh ba, Ta chứng được minh thứ ba, vô minh diệt, minh sanh; bóng tối diệt, ánh sáng sanh, trong khi Ta sống không phóng dật, nhiệt tâm, tinh cần.\nNhờ biết như vậy, nhờ thấy như vậy, tâm của Ta thoát khỏi dục lậu, thoát khỏi hữu lậu, thoát khỏi vô minh lậu. Ðối với tự thân đã giải thoát như vậy, khởi lên trí hiểu biết: Ta đã giải thoát. Ta đã thắng tri: “Sanh đã tận, phạm hạnh đã thành, việc cần làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },

{ text: `Này Bà-la-môn, Ông có thể có tư tưởng như sau: “Nay Sa-môn Gotama chưa diệt trừ tham, chưa diệt trừ sân, chưa diệt trừ si, nên sống tại các trú xứ xa vắng, trong rừng núi hoang vu”. Này Bà-la-môn, chớ có hiểu như vậy. Do Ta quán sát hai mục đích mà Ta sống tại các trú xứ xa vắng, trong rừng núi hoang vu. Tự thấy sự hiện tại lạc trú và vì lòng thương tưởng chúng sanh trong tương lai.`, ref: "Trung Bộ 4 – Kinh Sợ Hãi Khiếp Đảm", url: "https://loicuaducphat.org/mn/mn4.html#content" },	
{ text: `Ở đây, Hiền giả, hạng người có cấu uế nhưng không như thật tuệ tri: “Nội thân ta có cấu uế”. Với người này, có thể chờ đợi như sau: “Người này sẽ không khởi lên ước muốn, sẽ không cố gắng, sẽ không tinh tấn để diệt trừ cấu uế ấy. Người này sẽ từ trần, trong khi còn có tham, còn có sân, còn có si, trong khi còn cấu uế, trong khi tâm còn ô nhiễm”. Này Hiền giả, giống như một cái bát bằng đồng, mang từ chợ về hay mang từ nhà thợ rèn về, phủ đầy bụi bặm, và người chủ cái bát ấy không dùng đến, không lau chùi và quăng cái bát ấy vào chỗ đầy bụi bặm. Này Hiền giả, như vậy cái bát ấy, sau một thời gian càng ô nhiễm hơn, càng đầy bụi bặm hơn.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Này Hiền giả, như vậy hạng người có cấu uế nhưng không như thật tuệ tri: “Nội thân ta có cấu uế”. Với người này, có thể chờ đợi như sau: “Người này sẽ không khởi lên ước muốn, sẽ không cố gắng, sẽ không tinh tấn để diệt trừ cấu uế ấy. Người này sẽ từ trần, trong khi còn có tham, còn có sân, còn có si, trong khi còn cấu uế, trong khi tâm còn nhiễm”.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Ở đây, này Hiền giả, hạng người có cấu uế, và như thật tuệ tri: “Nội thân ta có cấu uế”. Với người này, có thể chờ đợi như sau: “Người này sẽ khởi lên ước muốn, sẽ cố gắng, sẽ tinh tấn để diệt trừ cấu uế ấy. Người này sẽ từ trần, trong khi không còn tham, không còn sân, không còn si, trong khi không còn cấu uế, trong khi tâm không còn ô nhiễm”. Này Hiền giả, giống như cái bát bằng đồng, mang từ chợ về hay mang từ nhà thợ rèn về, phủ đầy bụi bặm, và người chủ cái bát ấy dùng đến, lau chùi và không quăng cái bát ấy vào chỗ đầy bụi bặm. Này Hiền giả, như vậy cái bát ấy, sau một thời gian được thanh tịnh hơn, được sạch sẽ hơn.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Này Hiền giả, như vậy hạng người có cấu uế và như thật tuệ tri: “Nội thân ta có cấu uế”. Với hạng người này, có thể chờ đợi như sau: “Người này sẽ khởi lên ước muốn, sẽ cố gắng, sẽ tinh tấn, để diệt trừ cấu uế ấy. Người này sẽ từ trần, trong khi không còn tham, không còn sân, không còn si, trong khi không còn cấu uế, trong khi tâm không còn ô nhiễm”.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Ở đây, này Hiền giả, hạng người không có cấu uế nhưng không như thật tuệ tri: “Nội thân ta không có cấu uế”. Với người này, có thể chờ đợi như sau: “Người này sẽ tư niệm tịnh tướng. Do tư niệm tịnh tướng, tham sẽ làm ô nhiễm tâm của người này. Người này sẽ từ trần, trong khi còn có tham, còn có sân, còn có si, trong khi còn cấu uế, trong khi tâm còn ô nhiễm”. Này Hiền giả, giống như một cái bát bằng đồng, mang từ chợ về hay mang từ nhà thợ rèn về, thanh tịnh và sạch sẽ. Và người chủ cái bát ấy không dùng đến, không lau chùi và quăng cái bát ấy vào chỗ đầy bụi bặm. Này Hiền giả, như vậy cái bát ấy, sau một thời gian, càng ô nhiễm hơn, càng bụi bặm hơn.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `- Này Hiền giả, như vậy hạng người không có cấu uế nhưng không như thật tuệ tri: “Nội thân ta không có cấu uế”. Với người này có thể chờ đợi sau: “Người này sẽ tư niệm tịnh tướng. Do tư niệm tịnh tướng, tham sẽ làm ô nhiễm tâm của người này. Người này sẽ từ trần trong khi còn có tham, còn có sân, còn có si, trong khi còn cấu uế, trong khi tâm còn ô nhiễm”.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Ở đây, này Hiền giả, hạng người không có cấu uế và như thật tuệ tri: “Nội thân ta không có cấu uế”. Với người này có thể chờ đợi như sau: “Người này sẽ không tư niệm tịnh tướng. Do không tư niệm tịnh tướng, tham sẽ không làm ô nhiễm tâm của người này. Người này sẽ từ trần, trong khi không có tham, không có sân, không có si, trong khi không còn cấu uế, trong khi tâm không còn ô nhiễm”. Này Hiền giả, giống như một cái bát bằng đồng, mang từ chợ về hay mang từ nhà thợ rèn về, thanh tịnh và sạch sẽ và người chủ cái bát ấy dùng đến, lau chùi và không quăng cái bát ấy vào chỗ đầy bụi bặm. Này Hiền giả, như vậy cái bát ấy, sau một thời gian, càng được thanh tịnh hơn, càng được sạch sẽ hơn.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `- Này Hiền giả, như vậy hạng người không có cấu uế, và như thật tuệ tri: “Nội thân ta không có cấu uế”. Với người này có thể chờ đợi như sau: “Người này sẽ không tư niệm tịnh tướng. Do không tư niệm tịnh tướng, tham sẽ không làm ô nhiễm tâm người này. Người này sẽ từ trần, không có tham, không có sân, không có si, không còn cấu uế, tâm không còn ô nhiễm”.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `- Này Hiền giả, cấu uế gọi là cấu uế, danh từ gì là đồng nghĩa cái gọi là cấu uế?\n- Này Hiền giả, các ác bất thiện pháp, cảnh giới của dục là đồng nghĩa cái gọi là cấu uế.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Này Hiền giả, sự tình này xảy ra, ở đây, một Tỷ-kheo có thể khởi lên ý muốn như sau: “Nếu ta có phạm giới tội, mong rằng các Tỷ-kheo chớ có biết về ta rằng là đã phạm giới tội”. Này Hiền giả, sự tình này có thể xảy ra: các Tỷ-kheo có thể biết được các Tỷ-kheo ấy đã phạm giới tội. Tỷ-kheo này nghĩ rằng: “Các Tỷ-kheo đã biết được ta đã phạm giới tội”. Do đó, vị này trở thành phẫn nộ và bất mãn. Phẫn nộ và bất mãn, cả hai thuộc về cấu uế.`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },

{ text: `Những kẻ Thiện nam tử, do lòng tin, xuất gia, từ bỏ gia đình, sống không gia đình; những vị nào không gian ngụy, không xảo trá, không khi cuống, không trạo cử, không kiêu mạn, không dao động, không lắm lời, không tạp thoại, hộ trì các căn, tiết độ trong ăn uống, chú tâm cảnh giác, tha thiết với hạnh Sa-môn, nhiệt thành tôn trọng Phật pháp, không sống trong sung túc, không biếng nhác, bỏ rơi gánh nặng về đọa lạc, dẫn đầu về viễn ly, tinh cần, tinh tấn, nỗ lực, chú tâm cảnh giác, định tâm, nhất tâm, có trí tuệ, không đần độn. Những vị này sau khi nghe pháp môn này của Tôn giả Sāriputta, hình như đang uống, hình như đang nếm với lời nói và tâm ý. Thật lành thay, một vị Tôn giả đồng phạm hạnh đã khiến cho vượt khỏi bất thiện và an trú vào chánh thiện!`, ref: "Trung Bộ 5 – Kinh Không Uế Nhiễm", url: "https://loicuaducphat.org/mn/mn5.html#content" },
{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo có ước nguyện: “Mong rằng ta được các đồng phạm hạnh thương mến, yêu quý, cung kính và tôn trọng!”, Tỷ-kheo ấy phải thành tựu viên mãn giới luật, kiên trì, nội tâm tịch tĩnh, không gián đoạn Thiền định, thành tựu quán hạnh, thích sống tại các trú xứ không tịch.`, ref: "Trung Bộ 6 – Kinh Ước Nguyện", url: "https://loicuaducphat.org/mn/mn6.html#content" },

{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo có ước nguyện: “Mong rằng những bà con huyết thống với ta, khi họ chết và mệnh chung, nghĩ (đến ta) với tâm hoan hỷ (và nhờ vậy) được quả báo lớn, lợi ích lớn!”, Tỷ-kheo ấy phải thành tựu viên mãn giới luật … (như trên) … trú xứ không tịch.`, ref: "Trung Bộ 6 – Kinh Ước Nguyện", url: "https://loicuaducphat.org/mn/mn6.html#content" },

{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo có ước nguyện: “Mong rằng ta nhiếp phục lạc và bất lạc, chớ không phải bất lạc nhiếp phục ta. Mong rằng ta sống luôn luôn nhiếp phục bất lạc được khởi lên!”, Tỷ-kheo ấy phải thành tựu viên mãn giới luật … (như trên) … trú xứ không tịch.\nNày các Tỷ-kheo, nếu Tỷ-kheo có ước nguyện: “Mong rằng ta nhiếp phục khiếp đảm và sợ hãi, chớ không phải khiếp đảm và sợ hãi nhiếp phục ta! Mong rằng ta sống luôn luôn nhiếp phục khiếp đảm và sợ hãi được khởi lên!”, Tỷ-kheo ấy phải thành tựu viên mãn giới luật … (như trên) … trú xứ không tịch.`, ref: "Trung Bộ 6 – Kinh Ước Nguyện", url: "https://loicuaducphat.org/mn/mn6.html#content" },

{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo có ước nguyện: “Mong rằng, tùy theo ý muốn, không có khó khăn, không có mệt nhọc, không có phí sức, ta chứng được bốn Thiền, thuộc tăng thượng tâm, hiện tại lạc trú!”, Tỷ-kheo ấy phải thành tựu viên mãn giới luật … (như trên) … trú xứ không tịch.\nNày các Tỷ-kheo, nếu Tỷ-kheo có ước nguyện: “Mong rằng ta trừ diệt ba kiết sử, chứng quả Dự lưu, không còn bị đọa lạc, chắc chắn hướng đến Chánh giác!”, Tỷ-kheo ấy phải thành tựu viên mãn giới luật … (như trên) … trú xứ không tịch.`, ref: "Trung Bộ 6 – Kinh Ước Nguyện", url: "https://loicuaducphat.org/mn/mn6.html#content" },
{ text: `Này các Tỷ-kheo, như một tấm vải cấu uế, nhiễm bụi, một người thợ nhuộm nhúng tấm vải ấy vào thuốc nhuộm này hay thuốc nhuộm khác- hoặc xanh, hoặc vàng, hoặc đỏ, hoặc tía- vải ấy sẽ được màu nhuộm không tốt đẹp, sẽ được màu nhuộm không sạch sẽ. Vì sao vậy? Này các Tỷ-kheo, vì tấm vải không được trong sạch. Cũng vậy, này các Tỷ-kheo, cõi ác chờ đợi một tâm cấu uế. Này các Tỷ-kheo, như một tấm vải thanh tịnh, trong sạch, một người thợ nhuộm nhúng tấm vải ấy vào thuốc nhuộm này hay thuốc nhuộm khác- hoặc xanh, hoặc vàng, hoặc đỏ, hoặc tía, vải ấy sẽ được màu nhuộm tốt đẹp, sẽ được màu nhuộm sạch sẽ. Vì sao vậy? Này các Tỷ-kheo, vì tấm vải được trong sạch. Cũng vậy, này các Tỷ-kheo, cõi thiện chờ đợi một tâm không cấu uế.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là những cấu uế của tâm? Tham dục, tà tham là cấu uế của tâm, sân là cấu uế của tâm, phẫn là cấu uế của tâm, hận là cấu uế của tâm, hư ngụy, não hại, tật đố, xan tham, man trá, khi cuống, ngoan cố, cấp tháo, quá mạn, kiêu, phóng dật là cấu uế của tâm.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo nào nghĩ rằng: “Tham dục, tà tham là cấu uế của tâm” và sau khi biết vậy, vị ấy đoạn trừ tham dục, tà tham cấu uế của tâm; nghĩ rằng: “Sân là cấu uế của tâm”, và sau khi biết vậy, vị ấy đoạn trừ sân, cấu uế của tâm; phẫn … hận … hư ngụy … não hại, tật đố, xan tham, man trá, khi cuống … ngoan cố … cấp tháo … mạn … quá mạn … kiêu; nghĩ rằng: “Phóng dật là cấu uế của tâm” thì sau khi biết vậy, vị ấy đoạn trừ phóng dật, cấu uế của tâm.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Vị ấy tự nghĩ: “Ta thành tựu lòng tin tuyệt đối đối với Pháp”, và chứng được nghĩa tín thọ, chứng được pháp tín thọ, chứng được hân hoan liên hệ đến pháp; từ hân hoan, hỷ sanh; từ hỷ, thân được khinh an; thân khinh an, cảm giác được lạc thọ; với lạc thọ, tâm được Thiền định.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Vị ấy tự nghĩ: “Ðến giai đoạn này, đối với Ta, có sự từ bỏ, có sự diệt trừ, có sự giải thoát, có sự đoạn trừ, có sự xả ly”, và chứng được nghĩa tín thọ, chứng được pháp tín thọ, chứng được hân hoan liên hệ đến pháp; từ hân hoan, hỷ sanh; từ hỷ, thân khinh an; thân khinh an, cảm giác được lạc thọ; với lạc thọ, tâm được Thiền định.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Này các Tỷ-kheo, như một tấm vải cấu uế, nhiễm bụi, nếu bỏ trong nước sạch, trở thành thanh tịnh sạch sẽ, như bỏ vào lò lửa trở thành thanh tịnh sạch sẽ. Cũng vậy, này các Tỷ-kheo, một Tỷ-kheo, giới như vậy, pháp như vậy, tuệ như vậy- nếu có ăn đồ khất thực với gạo thơm, hạt đen được vất đi, với các món canh, với các món ăn khác, cũng không vì vậy trở thành một chướng ngại cho vị ấy.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Vị ấy an trú, biến mãn một phương với tâm câu hữu với từ, cũng vậy phương thứ hai, cũng vậy phương thứ ba, cũng vậy phương thứ tư. Như vậy, cùng khắp thế giới, trên dưới bề ngang, hết thảy phương xứ, cùng khắp vô biên giới, vị ấy an trú biến mãn với tâm câu hữu với từ, quảng đại, vô biên, không hận, không sân.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Vị ấy biết: “Có cái này, có cái hạ liệt, có cái cao thượng, có sự giải thoát vượt qua các tưởng”.\nDo vị ấy biết như vậy, thấy như vậy, tâm được giải thoát khỏi dục lậu, tâm được giải thoát khỏi hữu lậu, tâm được giải thoát khỏi vô minh lậu. Ðối với tự thân đã giải thoát, trí khởi lên: “Ta đã giải thoát, sanh đã tận, phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”. Này các Tỷ-kheo, Tỷ-kheo ấy được gọi là Tỷ-kheo đã được tắm rửa với sự tắm rửa nội tâm.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Trong sông Bàhukà\nTại Adhikakkà,\nTại cả sông Gayà\nKẻ ngu dầu thường tắm,\nÁc nghiệp không rửa sạch.\nSông Sundarikà\nCó thể làm được gì?\nPayàga làm gì?\nCả sông Bàhukà?\nKhông thể rửa nghiệp đen\nCủa kẻ ác gây tội.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Ðối kẻ sống thanh tịnh,\nNgày nào cũng ngày tốt,\nVới kẻ sống thanh tịnh,\nNgày nào cũng ngày lành.`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `Các tịnh nghiệp thanh tịnh,\nLuôn thành tựu thiện hạnh.\nNày vị Bà-la-môn,\nChỉ nên tắm ở đây,\nKhiến mọi loài chúng sanh,\nÐược sống trong an ổn.\nNếu không nói dối trá,\nNếu không hại chúng sanh,\nKhông lấy của không cho,\nCó lòng tín, không tham,\nÐi Gayà làm gì,\nGayà một giếng nước?`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },

{ text: `\Thật vi diệu thay, Tôn giả Gotama! Thật vi diệu thay, Tôn giả Gotama! Tôn giả Gotama, như người dựng đứng lại những gì bị quăng ngã xuống, phơi bày ra những gì bị che kín, chỉ đường cho kẻ bị lạc hướng, đem đèn sáng vào trong bóng tối, để những ai có mắt có thể thấy sắc. Cũng vậy Chánh pháp đã được Tôn giả Gotama dùng nhiều phương tiện trình bày. Nay con quy y Tôn giả Gotama, quy y Pháp và quy y Tăng. Mong con được xuất gia với Tôn giả Gotama! Mong con được thọ đại giới!`, ref: "Trung Bộ 7 – Kinh Ví Dụ Tấm Vải", url: "https://loicuaducphat.org/mn/mn7.html#content" },
{ text: `Này Cunda, giống như một con đường không bằng phẳng, có một con đường bằng phẳng khác đối trị. Này Cunda, giống như một bến nước không bằng phẳng, có một bến nước bằng phẳng khác đối trị. Cũng vậy này Cunda: Đối với con người làm hại, có sự không làm hại đối trị. Ðối với con người sát sanh, có từ bỏ sát sanh đối trị. Ðối với con người lấy của không cho, có từ bỏ lấy của không cho đối trị …, Ðối với con người nhiễm thế tục, cố chấp tư kiến, tánh khó hành xả, có không nhiễm thế tục, không cố chấp tư kiến, tánh dễ hành xả đối trị.`, ref: "Trung Bộ 8 – Kinh Ðoạn Giảm", url: "https://loicuaducphat.org/mn/mn8.html#content" },

{ text: `Này Cunda, ví như các bất thiện pháp, tất cả đều hướng hạ, còn các thiện pháp, tất cả đều hướng thượng. Cũng vậy, này Cunda: Con người không làm hại, hướng thượng đối với người làm hại, con người từ bỏ sát sanh, hướng thượng đối với người sát sanh. Con người từ bỏ lấy của không cho, hướng thượng đối với người lấy của không cho. Con người không nhiễm thế tục, không cố chấp tư kiến, tánh dễ hành xả, hướng thượng đối với người nhiễm thế tục, cố chấp tư kiến, tánh khó hành xả.`, ref: "Trung Bộ 8 – Kinh Ðoạn Giảm", url: "https://loicuaducphat.org/mn/mn8.html#content" },

{ text: `Này Cunda, con người tự mình bị rơi vào bùn lầy có thể kéo lên một người bị rơi vào bùn lầy, sự tình ấy không thể xảy ra. Này Cunda, con người tự mình không rơi vào bùn lầy, có thể kéo lên một người bị rơi vào bùn lầy, sự tình ấy có thể xảy ra. Này Cunda, con người tự mình không được nhiếp phục, không được huấn luyện, không được hoàn toàn giải thoát, tự mình có thể nhiếp phục, huấn luyện và hoàn toàn giải thoát người khác, sự tình ấy không thể xảy ra. Một người được nhiếp phục, được huấn luyện, được hoàn toàn giải thoát, tự mình có thể nhiếp phục, huấn luyện, hoàn toàn giải thoát người khác, sự tình ấy có thể xảy ra.`, ref: "Trung Bộ 8 – Kinh Ðoạn Giảm", url: "https://loicuaducphat.org/mn/mn8.html#content" },

{ text: `Này Cunda, những gì bậc Ðạo Sư phải làm, vì hạnh phúc, vì lòng thương tưởng đệ tử, những việc ấy Ta đã làm, vì lòng thương tưởng cho các Người. Này Cunda, đây là những gốc cây, đây là những ngôi nhà trống. Này Cunda, hãy Thiền định, chớ có phóng dật, chớ có hối tiếc về sau. Ðó là lời giáo huấn của Ta cho các Người.`, ref: "Trung Bộ 8 – Kinh Ðoạn Giảm", url: "https://loicuaducphat.org/mn/mn8.html#content" },
{ text: `Chư Hiền, thế nào là bất thiện, thế nào là căn bổn bất thiện, thế nào là thiện, thế nào là căn bổn thiện? Chư Hiền, sát sanh là bất thiện, lấy của không cho là bất thiện, tà hạnh trong các dục là bất thiện, nói láo là bất thiện, nói hai lưỡi là bất thiện, ác khẩu là bất thiện, nói phù phiếm là bất thiện, tham dục là bất thiện, sân là bất thiện, tà kiến là bất thiện. Chư Hiền, như vậy gọi là bất thiện.\nVà chư Hiền, thế nào là căn bổn bất thiện? Tham là căn bổn bất thiện, sân là căn bổn bất thiện, si là căn bổn bất thiện. Chư Hiền, như vậy gọi là căn bổn bất thiện.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },

{ text: `Và này chư Hiền, thế nào là thiện? Từ bỏ sát sanh là thiện, từ bỏ lấy của không cho là thiện, từ bỏ tà hạnh trong các dục là thiện, từ bỏ nói láo là thiện, từ bỏ nói hai lưỡi là thiện, từ bỏ ác khẩu là thiện, từ bỏ nói phù phiếm là thiện, không tham dục là thiện, không sân là thiện, chánh tri kiến là thiện. Chư Hiền, như vậy gọi là thiện.\nChư Hiền, thế nào là căn bổn thiện? Không tham là căn bổn thiện, không sân là căn bổn thiện, không si là căn bổn thiện. Chư Hiền, như vậy gọi là căn bổn thiện.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },

{ text: `Chư Hiền, khi nào Thánh đệ tử tuệ tri bất thiện,..tuệ tri thiện,... tuệ tri căn bổn thiện, khi ấy, vị ấy đoạn trừ tất cả tham tùy miên, tẩy sạch sân tùy miên, nhổ tận gốc kiến mạn tùy miên “Tôi là”, đoạn trừ vô minh, khiến minh khởi lên, diệt tận khổ đau ngay trong hiện tại. Chư Hiền, như vậy Thánh đệ tử có chánh tri kiến, có tri kiến chánh trực, có lòng tin Pháp tuyệt đối và thành tựu diệu pháp này.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },

{ text: `Chư Hiền, thế nào là thức ăn, thế nào là tập khởi của thức ăn, thế nào là đoạn diệt của thức ăn, thế nào là con đường đưa đến đoạn diệt của thức ăn? Chư Hiền, có bốn loại thức ăn này, khiến các loài chúng sanh đã sanh được an trú hay các loài hữu tình sẽ sanh được hỗ trợ cho sanh. Thế nào là bốn? Ðoàn thực, loại thô hay loại tế, xúc thực là thứ hai, tư niệm thực là thứ ba, thức thực là thứ tư. Từ tập khởi của ái có tập khởi của thức ăn, từ đoạn diệt của ái có đoạn diệt của thức ăn. Thánh Ðạo Tám Ngành này là con đường đưa đến đoạn diệt của thức ăn, tức là: Chánh Tri kiến, Chánh Tư duy, Chánh Ngữ, Chánh Nghiệp, Chánh Mạng, Chánh Tinh tấn, Chánh Niệm, Chánh Ðịnh.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },

{ text: `Chư Hiền, khi nào Thánh đệ tử tuệ tri Khổ, tuệ tri Tập khởi của khổ, tuệ tri Ðoạn diệt của khổ, tuệ tri Con Ðường đưa đến đoạn diệt của khổ, chư Hiền, khi ấy Thánh đệ tử có chánh tri kiến, có tri kiến chánh trực, có lòng tin Pháp tuyệt đối và thành tựu diệu pháp này.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },

{ text: `Chư Hiền, thế nào là Khổ? Sanh là khổ, già là khổ, bệnh là khổ, chết là khổ, sầu bi khổ ưu não là khổ, cầu không được là khổ, tóm lại năm thủ uẩn là khổ. Chư Hiền, như vậy gọi là Khổ. Chư Hiền, thế nào là Tập khởi của khổ? Chính là ái đưa đến tái sanh, cùng khởi hỷ dục và tham hướng đến tái sanh, cùng khởi hỷ dục và tham, tìm cầu hỷ lạc chỗ này chỗ kia, tức là dục ái, hữu ái, phi hữu ái. Chư Hiền, như vậy gọi là Tập khởi của khổ.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },

{ text: `Chư Hiền, thế nào là Ðoạn diệt của khổ? Ðó là sự đoạn diệt, ly tham, không có dư tàn, sự quăng bỏ, sự từ bỏ, sự giải thoát, sự vô chấp khát ái ấy. Chư Hiền, thế nào là Con Ðường đưa đến đoạn diệt của khổ? Chính là Thánh Ðạo Tám Ngành đưa đến khổ diệt, tức là: Chánh Tri kiến, Chánh Tư duy, Chánh Ngữ, Chánh Nghiệp, Chánh Mạng, Chánh Tinh tấn, Chánh Niệm, Chánh Ðịnh.`, ref: "Trung Bộ 9 – Kinh Chánh Tri Kiến", url: "https://loicuaducphat.org/mn/mn9.html#content" },
{ text: `Này các Tỷ-kheo, không cần gì nửa tháng, một vị nào tu tập Bốn Niệm xứ này trong bảy ngày, vị ấy có thể chứng một trong hai quả sau đây: Một là chứng Chánh trí ngay trong hiện tại, hai là nếu còn hữu dư y, thì chứng quả Bất hoàn. Này các Tỷ-kheo, đây là con đường độc nhất đưa đến thanh tịnh cho chúng sanh, vượt khỏi sầu não, diệt trừ khổ ưu, thành tựu Chánh trí, chứng ngộ Niết-bàn. Ðó là Bốn Niệm xứ.`, ref: "Trung Bộ 10 – Kinh Niệm Xứ", url: "https://loicuaducphat.org/mn/mn10.html#content" },
{ text: `Này Sāriputta, như thế này là sự yểm ly của Ta. Này Sāriputta, tỉnh giác, Ta đi tới; tỉnh giác Ta đi lui, Ta an trú lòng từ cho đến trong một giọt nước với tâm tư: “Mong rằng Ta không làm hại một chúng sanh nhỏ nào trong những ác đạo của họ!” Này Sāriputta, như vậy là sự yểm ly của Ta.`, ref: "Trung Bộ 12 – Ðại Kinh Sư Tử Hống", url: "https://loicuaducphat.org/mn/mn12.html#content" },

{ text: `Này Sāriputta, rồi Ta trong những đêm đông lạnh lẽo, giữa những ngày mồng tám, khi có tuyết rơi, trong những đêm như vậy, Ta sống giữa trời, và ban ngày sống trong khu rừng rậm rạp. Ta sống trong những ngày cuối tháng hè, ban ngày thì sống giữa trời, còn ban đêm trong khu rừng rậm rạp. Rồi này Sāriputta, những bài kệ kỳ diệu từ trước chưa từng được nghe sau đây được khởi lên:\n\nNay bị thiêu đốt, bị buốt lạnh,\nCô độc sống trong rừng kinh hoàng,\nTrần truồng, Ta ngồi không lửa ấm,\nẨn sĩ, trong lý tưởng đăm chiêu.`, ref: "Trung Bộ 12 – Ðại Kinh Sư Tử Hống", url: "https://loicuaducphat.org/mn/mn12.html#content" },

{ text: `Này Sāriputta, những ai nói một cách chân chánh sẽ nói như sau: “Một vị hữu tình không bị si chi phối, đã sanh ra ở đời vì lợi ích, vì hạnh phúc cho chúng sanh, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư Thiên và loài Người”. Vị ấy sẽ nói về Ta một cách chân chánh như sau: “Một vị hữu tình không bị si chi phối, đã sanh ra ở đời vì lợi ích, vì hạnh phúc cho chúng sanh, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư Thiên và loài Người”.`, ref: "Trung Bộ 12 – Ðại Kinh Sư Tử Hống", url: "https://loicuaducphat.org/mn/mn12.html#content" },	
		{ text: `Lại nữa, này các Tỷ-kheo, do dục làm nhân, do dục làm duyên, do dục làm nguyên nhân, do chính dục làm nhân, vua tranh đoạt với vua, Sát-đế-lị tranh đoạt với Sát-đế-lị, Bà-la-môn tranh đoạt với Bà-la-môn, gia chủ tranh đoạt với gia chủ, mẹ tranh đoạt với con, con tranh đoạt với mẹ, cha tranh đoạt với con, con tranh đoạt với cha, anh em tranh đoạt với anh em, anh tranh đoạt với chị, chị tranh đoạt với anh, bạn bè tranh đoạt với bạn bè. Khi họ đã dấn mình vào tranh chấp, tranh luận, tranh đoạt; họ công phá nhau bằng tay; họ công phá nhau bằng đá; họ công phá nhau bằng gậy; họ công phá nhau bằng kiếm. Ở đây họ đi đến tử vong, đi đến sự đau khổ gần như tử vong. Này các Tỷ-kheo, như vậy là sự nguy hiểm các dục, thiết thực hiện tại, thuộc khổ uẩn, lấy dục làm nhân, lấy dục làm duyên, là nguồn gốc của dục, là nguyên nhân của dục.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, do dục làm nhân, do dục làm duyên, do dục làm nguyên nhân, do chính dục làm nhân, họ cầm mâu và thuẫn, họ đeo cung và tên, họ dàn trận hai mặt, và tên được nhắm bắn nhau, đao được quăng ném nhau, kiếm được vung chém nhau. Họ bắn đâm nhau bằng tên, họ quăng đâm nhau bằng đao, họ chặt đầu nhau bằng kiếm. Ở đây họ đi đến tử vong, đi đến sự đau khổ gần như tử vong. Này các Tỷ-kheo, như vậy là sự nguy hiểm các dục, thiết thực hiện tại, thuộc khổ uẩn, lấy dục làm nhân, lấy dục làm duyên, là nguồn gốc của dục, là nguyên nhân của dục.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, do dục làm nhân, do dục làm duyên, do dục làm nguyên nhân, do chính dục làm nhân, họ cầm mâu và thuẫn, họ đeo cung và tên, họ công phá thành quách mới trét vôi hồ và tên được nhắm bắn nhau, đao được quăng ném nhau, kiếm được vung chém nhau. Ở đây, họ bắn đâm nhau bằng tên, họ quăng đâm nhau bằng đao, họ đổ nước phân sôi, họ đè bẹp nhau bằng đá, họ chặt đầu nhau bằng kiếm. Ở đây họ đi đến tử vong, đi đến sự đau khổ gần như tử vong. Này các Tỷ-kheo, như vậy là sự nguy hiểm các dục, thiết thực hiện tại, thuộc khổ uẩn, lấy dục làm nhân, lấy dục làm duyên, là nguồn gốc của dục, là nguyên nhân của dục.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, do dục làm nhân, do dục làm duyên, do dục làm nguyên nhân, do chính dục làm nhân, họ sống làm các ác hạnh về thân, làm các ác hạnh về lời nói, làm các ác hạnh về ý. Do họ sống làm các ác hạnh về thân, làm các ác hạnh về lời nói, làm các ác hạnh về ý, khi thân hoại mạng chung, họ sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Này các Tỷ-kheo, như vậy là sự nguy hiểm các dục, đưa đến đau khổ tương lai, là khổ uẩn, do dục làm nhân, do dục làm duyên, do dục làm nhân duyên, do chính dục làm nhân.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `- Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp. Lại nữa, này các Tỷ-kheo, người ta thấy cô gái ấy, thi thể bị quăng vào nghĩa địa, một ngày hay hai ngày hay ba ngày, thi thể ấy trương phồng lên, xanh đen lại, nát thối ra. Này các Tỷ-kheo, các Người nghĩ thế nào? Có phải sự mỹ diệu sắc đẹp xưa kia của cô gái đã biến mất và sự nguy hiểm đã hiện ra?\n- Bạch Thế Tôn, sự thật là vậy.\n- Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `- Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp. Lại nữa, này các Tỷ-kheo, người ta thấy cô gái ấy, thi thể bị quăng vào nghĩa địa, chỉ có toàn xương trắng màu vỏ ốc … chỉ còn một đống xương lâu hơn một năm … chỉ còn các xương thối trở thành bột. Này các Tỷ-kheo, các Người nghĩ thế nào? Có phải sự mỹ diệu về sắc đẹp xưa kia của cô gái nay đã biến mất, và sự nguy hiểm hiện ra?\n- Bạch Thế Tôn, sự thật là vậy.\n- Này các Tỷ-kheo, như vậy là sự nguy hiểm các sắc pháp.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là sự nguy hiểm các cảm thọ? Này các Tỷ-kheo, các cảm thọ là vô thường, khổ, biến hoại, như vậy là sự nguy hiểm các cảm thọ. Và này các Tỷ-kheo, thế nào là sự xuất ly các cảm thọ? Này các Tỷ-kheo, sự điều phục dục tham đối với các cảm thọ, sự đoạn trừ dục tham, như vậy gọi là sự xuất ly các cảm thọ.`, ref: "Trung Bộ 13 – Ðại Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn13.html#content" },
{ text: `Này Mahānāma, thuở xưa, khi Ta còn là Bồ-tát, chưa chứng được Bồ-đề, chưa thành Chánh Ðẳng Chánh Giác, Ta khéo thấy với như thật chánh trí tuệ: “Các dục vui ít, khổ nhiều, não nhiều, sự nguy hiểm ở đây lại nhiều hơn”, dầu Ta có thấy với như thật chánh trí tuệ như vậy, nhưng Ta chưa chứng được hỷ lạc do ly dục, ly ác bất thiện pháp sanh hay một pháp nào khác cao thượng hơn. Và như vậy Ta biết rằng, Ta chưa khỏi bị các dục chi phối. Và này Mahānāma, khi nào Ta khéo thấy với như thật chánh trí tuệ: “Các dục, vui ít, khổ nhiều, não nhiều, sự nguy hiểm ở đây lại nhiều hơn”, và Ta chứng được hỷ lạc do ly dục, ly ác bất thiện pháp sanh hay một pháp nào khác cao thượng hơn, như vậy Ta khỏi bị các dục chi phối.`, ref: "Trung Bộ 14 – Tiểu Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn14.html#content" },

{ text: `Và này Mahānāma, thế nào là vị ngọt các dục? Này Mahānāma, có năm pháp tăng trưởng các dục này: Các sắc pháp do mắt nhận thức, khả ái, khả lạc, khả ý, khả hỷ, tương ưng với dục, hấp dẫn; các tiếng do tai nhận thức…; các hương do mũi nhận thức…; các vị do lưỡi nhận thức…; các xúc do thân nhận thức, khả ái, khả lạc, khả ý, khả hỷ, tương ưng với dục, hấp dẫn. Này Mahānāma, có năm pháp tăng trưởng các dục như vậy. Này Mahānāma, y cứ vào năm pháp tăng trưởng các dục này, có lạc và hỷ khởi lên, như vậy là vị ngọt các dục.`, ref: "Trung Bộ 14 – Tiểu Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn14.html#content" },

{ text: `“Chư Hiền Nigaṇṭha, Ta có thể không di động thân thể, không nói lên một lời, sống cảm giác thuần túy lạc thọ luôn trong một ngày một đêm. Chư Hiền Nigaṇṭha, Ta có thể không di động thân thể, không nói lên một lời, sống cảm giác thuần túy lạc thọ luôn trong hai ngày hai đêm, luôn trong ba ngày ba đêm, luôn trong bốn ngày bốn đêm, luôn trong năm ngày năm đêm, luôn trong sáu ngày sáu đêm, luôn trong bảy ngày bảy đêm. Chư Hiền Nigaṇṭha, các Ngươi nghĩ thế nào? Sự kiện là như vậy, ai sống hạnh phúc hơn, vua Magadha Seniya Bimbisāra hay Ta?`, ref: "Trung Bộ 14 – Tiểu Kinh Khổ Uẩn", url: "https://loicuaducphat.org/mn/mn14.html#content" },
{ text: `Chư Hiền, nếu Tỷ-kheo thỉnh nguyện: “Mong rằng chư Tôn giả nói với tôi, mong rằng tôi được chư Tôn giả nói!” Nhưng nếu vị ấy là một người khó nói, đầy đủ những tánh khiến người ấy trở thành khó nói, khó kham nhẫn, không cung kính đón nhận khi được giảng dạy thì các vị đồng phạm hạnh nghĩ rằng, Tỷ-kheo ấy không đáng nói đến, nghĩ rằng Tỷ-kheo ấy không đáng được giáo huấn, nghĩ rằng không nên đặt lòng tin vào người ấy.`, ref: "Trung Bộ 15 – Kinh Tư Lượng", url: "https://loicuaducphat.org/mn/mn15.html#content" },

{ text: `Chư Hiền, ở đây, Tỷ-kheo cần phải quán sát tự ngã với tự ngã như sau:\n“Không biết ta có ác dục, có bị ác dục chi phối không?” Chư Hiền, nếu Tỷ-kheo quán sát và biết rằng: “Ta có ác dục và bị ác dục chi phối”, thì chư Hiền, Tỷ-kheo ấy cần phải tinh tấn đoạn trừ các ác, bất thiện pháp ấy. Chư Hiền, nếu Tỷ-kheo quán sát và biết rằng: “Ta không có ác dục, không bị ác dục chi phối”, thì chư Hiền, Tỷ-kheo ấy phải sống với tâm niệm hoan hỷ, ngày đêm tu học các thiện pháp.`, ref: "Trung Bộ 15 – Kinh Tư Lượng", url: "https://loicuaducphat.org/mn/mn15.html#content" },

{ text: `Chư Hiền, nếu trong khi quán sát, Tỷ-kheo thấy rõ rằng tất cả các ác, bất thiện pháp chưa được đoạn trừ trong nội tâm, thì chư Hiền, Tỷ-kheo ấy cần phải tinh tấn đoạn trừ các ác, bất thiện pháp ấy. Chư Hiền, nếu Tỷ-kheo trong khi quán sát thấy rõ rằng tất cả các ác, bất thiện pháp đã được đoạn trừ trong nội tâm, thì chư Hiền, Tỷ-kheo ấy phải sống với tâm niệm hoan hỷ, ngày đêm tu học thiện pháp.`, ref: "Trung Bộ 15 – Kinh Tư Lượng", url: "https://loicuaducphat.org/mn/mn15.html#content" },

{ text: `Chư Hiền, ví như một phụ nữ hay một đàn ông trẻ tuổi, trong tuổi thanh xuân, tánh ưa trang điểm, tự quán sát mặt mày của mình trong một tấm kính sạch sẽ và trong suốt, hay trong một bát nước trong sáng. Nếu người ấy thấy bụi bặm hay cấu uế trên mặt mình, thì người ấy tinh tấn đoạn trừ bụi bặm hay cấu uế ấy. Nếu người ấy không thấy bụi bặm hay cấu uế trên mặt mình, thì người ấy sẽ hoan hỷ nghĩ rằng: “Thật sự ta được điều tốt đẹp; thật sự ta được thanh tịnh”. Cũng vậy chư Hiền, nếu trong khi quán sát, Tỷ-kheo thấy rõ rằng tất cả các ác, bất thiện pháp chưa đoạn trừ ở nội tâm, thì chư Hiền, Tỷ-kheo ấy cần phải tinh tấn đoạn trừ các ác, bất thiện pháp ấy. Chư Hiền, nếu Tỷ-kheo trong khi quán sát thấy rõ rằng các ác, bất thiện pháp đã đoạn trừ ở nội tâm, thì chư Hiền, Tỷ-kheo ấy phải sống với tâm niệm hoan hỷ, ngày đêm tu học thiện pháp.`, ref: "Trung Bộ 15 – Kinh Tư Lượng", url: "https://loicuaducphat.org/mn/mn15.html#content" },
{ text: `Chư Tỷ-kheo, Tỷ-kheo nào chưa diệt trừ năm tâm hoang vu, chưa đoạn tận năm tâm triền phược, vị ấy có thể lớn mạnh, trưởng thành, hưng thịnh trong Pháp và Luật này, sự kiện này không xảy ra.`, ref: "Trung Bộ 16 – Kinh Tâm Hoang Vu", url: "https://loicuaducphat.org/mn/mn16.html#content" },

{ text: `Thế nào là năm tâm hoang vu chưa được đoạn trừ? Chư Tỷ-kheo, ở đây, Tỷ-kheo nghi ngờ bậc Ðạo Sư, do dự, không quyết đoán, không có tịnh tín. Chư Tỷ-kheo, Tỷ-kheo nào nghi ngờ bậc Ðạo Sư, do dự, không quyết đoán, không có tịnh tín, thời tâm vị này không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn. Nếu tâm của ai không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn, như vậy là tâm hoang vu thứ nhất chưa được diệt trừ.`, ref: "Trung Bộ 16 – Kinh Tâm Hoang Vu", url: "https://loicuaducphat.org/mn/mn16.html#content" },

{ text: `Và lại nữa, chư Tỷ-kheo, Tỷ-kheo phẫn nộ đối với các đồng phạm hạnh, không có hoan hỷ, tâm tư chống đối, cứng rắn. Chư Tỷ-kheo, Tỷ-kheo nào phẫn nộ đối với các vị đồng phạm hạnh, không có hoan hỷ, tâm tư chống đối, cứng rắn, thời tâm của vị này không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn. Nếu tâm của ai không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn, như vậy là tâm hoang vu thứ năm chưa được diệt trừ.`, ref: "Trung Bộ 16 – Kinh Tâm Hoang Vu", url: "https://loicuaducphat.org/mn/mn16.html#content" },

{ text: `Thế nào là năm tâm triền phược chưa được đoạn tận? Chư Tỷ-kheo, ở đây, Tỷ-kheo, đối với những dục, không phải không tham ái, không phải không dục cầu, không phải không ái luyến, không phải không khao khát, không phải không nhiệt tình, không phải không khát ái. Chư Tỷ-kheo, vị Tỷ-kheo nào đối với những dục, không phải không tham ái … không phải không khát ái, tâm của vị ấy không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn. Nếu tâm của ai không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn, như vậy là tâm triền phược thứ nhất chưa được đoạn tận.`, ref: "Trung Bộ 16 – Kinh Tâm Hoang Vu", url: "https://loicuaducphat.org/mn/mn16.html#content" },

{ text: `Và lại nữa, chư Tỷ-kheo, Tỷ-kheo nào ăn cho đến thỏa thê, cho đến bụng chứa đầy, sống thiên nặng về khoái lạc về sàng tọa, khoái lạc về ngủ nghỉ, khoái lạc về thụy miên, tâm của vị ấy không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn. Nếu tâm của ai không hướng về nỗ lực, chuyên cần, kiên trì, tinh tấn, như vậy là tâm triền phược thứ tư chưa được đoạn tận.`, ref: "Trung Bộ 16 – Kinh Tâm Hoang Vu", url: "https://loicuaducphat.org/mn/mn16.html#content" },

{ text: `Vị ấy tu tập như ý túc câu hữu với dục Thiền định, tinh cần hành; tu tập như ý túc câu hữu với tinh tấn Thiền định, tinh cần hành; tu tập như ý túc câu hữu với tâm Thiền định, tinh cần hành; tu tập như ý túc câu hữu với tư duy Thiền định, tinh cần hành; với nỗ lực là thứ năm. Chư Tỷ-kheo, Tỷ-kheo nào đầy đủ mười lăm pháp kể cả nỗ lực, thời có đủ khả năng để phá vỡ, có đủ khả năng để chánh giác, có đủ khả năng để đạt thành vô thượng an ổn khỏi các ách phược.`, ref: "Trung Bộ 16 – Kinh Tâm Hoang Vu", url: "https://loicuaducphat.org/mn/mn16.html#content" },

{ text: `Chư Tỷ-kheo, như có khoảng tám, mười hay mười hai cái trứng của con gà mái, những trứng này được con gà mái khéo ấp, ngồi lên trên, khéo ấp nóng, khéo ấp dưỡng, thời dầu cho con gà mái không khởi lên sự mong ước: “Mong rằng những con gà con của ta, sau khi đâm thủng vỏ trứng với móng chân nhọn của chúng, hay với mỏ của chúng, có thể thoát ra một cách yên ổn”, những con gà con ấy, sau khi đâm thủng vỏ trứng với móng chân nhọn của chúng hay với mỏ của chúng, có khả năng thoát ra một cách yên ổn. Chư Tỷ-kheo, cũng vậy, Tỷ-kheo đầy đủ mười lăm pháp, kể cả nỗ lực, thời có đủ khả năng để phá vỡ, có đủ khả năng để chánh giác, có đủ khả năng để đạt thành vô thượng an ổn khỏi các ách phược.`, ref: "Trung Bộ 16 – Kinh Tâm Hoang Vu", url: "https://loicuaducphat.org/mn/mn16.html#content" },
{ text: `“Này Hiền giả, theo lời dạy của Ta, trong thế giới với chư Thiên, Māra và Phạm thiên, với các chúng Sa-môn, Bà-la-môn, chư Thiên và loài Người, không có tranh luận một ai ở đời; các tưởng sẽ không ám ảnh vị Bà-la-môn sống không bị dục triền phược, không có nghi ngờ do dự, với mọi hối quá đoạn diệt, không có tham ái đối với hữu và phi hữu. Này Hiền giả, như vậy là quan điểm của Ta, như vậy là lời Ta giảng dạy”.`, ref: "Trung Bộ 18 – Kinh Mật Hoàn", url: "https://loicuaducphat.org/mn/mn18.html#content" },

{ text: `Này Tỷ-kheo, do bất cứ nhân duyên gì, một số hý luận vọng tưởng ám ảnh một người. Nếu ở đây không có gì đáng tùy hỷ, đáng đón mừng, đáng chấp thủ, thời như vậy là sự đoạn tận tham tùy miên, sự đoạn tận sân tùy miên, sự đoạn tận kiến tùy miên, sự đoạn tận nghi tùy miên, sự đoạn tận mạn tùy miên, sự đoạn tận hữu tham tùy miên, sự đoạn tận vô minh tùy miên, sự đoạn tận chấp trượng, chấp kiếm, đấu tranh, tránh tranh, luận tranh, kháng tranh, ly gián ngữ, vọng ngữ. Chính ở đây, những ác, bất thiện pháp này đều được tiêu diệt, không còn dư tàn.`, ref: "Trung Bộ 18 – Kinh Mật Hoàn", url: "https://loicuaducphat.org/mn/mn18.html#content" },

{ text: `Chư Hiền, do nhân con mắt và các sắc pháp, nhãn thức khởi lên. Sự gặp gỡ của ba pháp này là xúc. Do duyên xúc nên có cảm thọ. Những gì có cảm thọ thời có tưởng, những gì có tưởng thời có suy tầm, những gì có suy tầm thì có hý luận. Do hý luận ấy làm nhân, một số hý luận vọng tưởng ám ảnh một người, đối với các sắc pháp do con mắt nhận thức, quá khứ, tương lai và hiện tại.`, ref: "Trung Bộ 18 – Kinh Mật Hoàn", url: "https://loicuaducphat.org/mn/mn18.html#content" },

{ text: `Chư Hiền, do nhân lỗ tai và các tiếng, nhĩ thức khởi lên, do nhân lỗ mũi và các hương, tỷ thức khởi lên, do nhân lưỡi và các vị, thiệt thức khởi lên, do nhân thân và xúc, thân thức khởi lên; do nhân ý và các pháp, ý thức khởi lên. Sự gặp gỡ của ba pháp này là xúc. Do duyên xúc nên có các cảm thọ. Những gì có cảm thọ thời có tưởng. Những gì có tưởng thời có suy tầm. Những gì có suy tầm thời có hý luận. Do hý luận ấy làm nhân, một số hý luận vọng tưởng ám ảnh một người, đối với các pháp do ý thức nhận thức, quá khứ, tương lai và hiện tại.`, ref: "Trung Bộ 18 – Kinh Mật Hoàn", url: "https://loicuaducphat.org/mn/mn18.html#content" },

{ text: `Chư Hiền, sự kiện này xảy ra: khi nào có mắt, khi nào có sắc pháp, khi nào có nhãn thức, thời sự thi thiết của xúc được hiển lộ. Sự kiện này xảy ra: khi nào có sự thi thiết của xúc thời sự thi thiết của thọ được hiển lộ. Sự kiện này xảy ra: khi nào có thi thiết của thọ thời sự thi thiết của tưởng được hiển lộ. Sự kiện này xảy ra: khi nào có sự thi thiết của tưởng, thời sự thi thiết của suy tầm được hiển lộ. Sự kiện này xảy ra: khi nào có sự thi thiết của suy tầm thời sự thi thiết của sự ám ảnh một số hý luận vọng tưởng được hiển lộ.`, ref: "Trung Bộ 18 – Kinh Mật Hoàn", url: "https://loicuaducphat.org/mn/mn18.html#content" },
{ text: `Chư Tỷ-kheo, trước khi Ta giác ngộ, khi chưa thành Chánh Giác và còn là Bồ-tát, Ta suy nghĩ như sau: “Ta sống suy tư và chia hai suy tầm”. Chư Tỷ-kheo, phàm có dục tầm nào, sân tầm nào, hại tầm nào, Ta phân thành phần thứ nhất; phàm có ly dục tầm nào, vô sân tầm nào, vô hại tầm nào, Ta phân thành phần thứ hai.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, rồi Ta sống không phóng dật, nhiệt tâm, tinh cần. Khi dục tầm khởi lên, Ta tuệ tri: “Dục tầm này khởi lên nơi Ta, và dục tầm này đưa đến tự hại, đưa đến hại người, đưa đến hại cả hai, diệt trí tuệ, dự phần vào phiền não, không đưa đến Niết-bàn”. Chư Tỷ-kheo, khi Ta suy tư: “Dục tầm này đưa đến tự hại”, dục tầm được biến mất, Chư Tỷ-kheo, khi Ta suy tư: “Dục tầm đưa đến hại người”, dục tầm được biến mất. Chư Tỷ-kheo, khi Ta suy tư: “Dục tầm đưa đến hại cả hai”, dục tầm được biến mất. Chư Tỷ-kheo, khi Ta suy tư: “Dục tầm diệt trí tuệ, dự phần vào phiền não, không đưa đến Niết-bàn”, dục tầm được biến mất. Chư Tỷ-kheo, như vậy Ta tiếp tục trừ bỏ, xả ly và đoạn tận dục tầm.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, Tỷ-kheo suy tư, quán sát nhiều vấn đề gì, thời tâm sanh khuynh hướng đối với vấn đề ấy. Chư Tỷ-kheo, nếu Tỷ-kheo suy tư, quán sát nhiều về dục tầm, vị ấy từ bỏ ly dục tầm. Khi tâm đã nặng về dục tầm, thời tâm vị ấy có khuynh hướng về dục tầm. Chư Tỷ-kheo, nếu Tỷ-kheo suy tư quán sát nhiều về sân tầm … (như trên) … về hại tầm, vị ấy từ bỏ vô hại tầm. Khi tâm đã đặt nặng về hại tầm thời tâm vị ấy có khuynh hướng về hại tầm.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, ví như vào cuối tháng mùa mưa, về mùa thu, khi lúa đã trổ hạt, một người mục đồng chăn giữ bò, cầm roi đánh các con bò bên này, đánh bên kia, chế ngự chúng, ngăn chận chúng. Vì sao vậy? Chư Tỷ-kheo, vì người mục đồng thấy do nhân duyên này, đưa đến sự chết, sự tù tội, sự đánh đập hay sự trách móc. Chư Tỷ-kheo, cũng vậy, Ta đã thấy sự nguy hại, sự hạ liệt, sự uế nhiễm của các pháp bất thiện, và thấy sự viễn ly, sự lợi ích, sự thanh tịnh của các thiện pháp.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, trong khi Ta sống không phóng dật, nhiệt tâm, tinh cần như vậy, khi ly dục tầm khởi lên, Ta tuệ tri như vầy: “Ly dục tầm này khởi lên nơi Ta và ly dục tầm này không đưa đến tự hại, không đưa đến hại người, không đưa đến hại cả hai, tăng trưởng trí tuệ, không dự phần vào phiền não, đưa đến Niết-bàn”. Chư Tỷ-kheo, nếu ban đêm Ta suy tư, quán sát (về ly dục tầm) không phải từ nhân duyên ấy Ta thấy sợ hãi. Chư Tỷ-kheo, nếu ban ngày Ta suy tư, quán sát (về ly dục tầm), không phải từ nhân duyên ấy Ta thấy sợ hãi. Chư Tỷ-kheo, nếu ban đêm, ban ngày, Ta suy tư, quán sát (về ly dục tầm), không phải từ nhân duyên ấy Ta thấy sợ hãi. Và Ta suy tư, quán sát quá lâu, thân Ta có thể mệt mỏi; khi thân mệt mỏi thì tâm bị dao động; khi tâm bị dao động thì tâm rất khó được định tĩnh. Chư Tỷ-kheo, rồi tự nội thân Ta trấn an tâm, trấn tịnh tâm, khiến được nhất tâm, khiến thành định tĩnh. Vì sao vậy? Vì để tâm Ta khỏi dao động.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, ví như vào cuối tháng hè, khi tất cả lúa gạo đã cất vào kho thóc, một người mục đồng chăn giữ các con bò. Khi người mục đồng ở dưới gốc cây hay ở ngoài trời, người ấy có thể nghĩ đến có việc cần phải làm, và người ấy nghĩ: “Ðây là những con bò”. Chư Tỷ-kheo, cũng vậy ở đây, có việc cần phải làm, và Ta nghĩ: “Ðây là những pháp”.\nChư Tỷ-kheo, Ta phát tâm dõng mãnh, tinh tấn, không có tiêu cực, niệm không tán loạn được an trú, thân được khinh an, không có cuồng nhiệt, tâm được định tĩnh nhất tâm.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, Ta ly dục, ly ác, bất thiện pháp, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, có tầm, có tứ. Diệt tầm và tứ, Ta chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm không tứ, nội tĩnh nhất tâm. Ly hỷ trú xả, chánh niệm tỉnh giác, thân cảm sự lạc thọ mà các bậc Thánh gọi là xả niệm lạc trú, Ta chứng và an trú Thiền thứ ba. Xả lạc xả khổ, diệt hỷ ưu đã cảm thọ trước, Ta chứng và trú Thiền thứ tư, không khổ, không lạc, xả niệm thanh tịnh.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, giống như trong khu rừng rậm rạp có một hồ nước lớn thâm sâu, và một đoàn nai lớn sống gần một bên. Có một người đến, không muốn chúng được lợi ích, không muốn chúng được hạnh phúc, không muốn chúng được an ổn khỏi các ách nạn. Nếu có con đường nào được yên ổn, được an toàn, đưa đến hoan hỷ, người ấy sẽ chận đóng con đường này lại, sẽ mở con đường nguy hiểm, sẽ đặt con mồi đực, sẽ đặt con mồi cái. Chư Tỷ-kheo, như vậy, sau một thời gian đoàn nai lớn ấy gặp ách nạn và hao mòn dần. Chư Tỷ-kheo, có một người đến, muốn đoàn nai ấy được lợi ích, muốn chúng được hạnh phúc, muốn chúng được an ổn khỏi các ách nạn. Nếu có con đường nào được yên ổn, được an toàn, người ấy sẽ mở con đường này, sẽ đóng con đường nguy hiểm lại, sẽ đem con mồi đực đi, sẽ hủy bỏ con mồi cái. Chư Tỷ-kheo, như vậy đoàn nai lớn ấy sau một thời gian sẽ được tăng trưởng, hưng thịnh, thành mãn.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, hồ nước lớn, thâm sâu chỉ cho các dục. Chư Tỷ-kheo, đoàn nai lớn chỉ cho các loài hữu tình. Chư Tỷ-kheo, con người không muốn chúng được lợi ích, không muốn chúng được hạnh phúc, không muốn chúng được an ổn khỏi các ách nạn chỉ cho ác ma. Chư Tỷ-kheo, con đường nguy hiểm chỉ cho con đường tà đạo có tám ngành, tức là tà tri kiến, tà tư duy, tà ngữ, tà nghiệp, tà mạng, tà tinh tấn, tà niệm, tà định. Chư Tỷ-kheo, con mồi đực chỉ cho hỷ và tham. Chư Tỷ-kheo, con mồi cái chỉ cho vô minh. Chư Tỷ-kheo, còn người muốn chúng được lợi ích, muốn chúng được hạnh phúc, muốn chúng được an ổn khỏi các ách nạn chỉ cho Như Lai, bậc A-la-hán, Chánh Ðẳng Giác. Con đường yên ổn, an toàn, đưa đến hoan hỷ chỉ cho con đường Thánh đạo Tám ngành, tức là Chánh tri kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },

{ text: `Chư Tỷ-kheo, như vậy Ta mở con đường yên ổn, an toàn, đưa đến hoan hỷ, Ta đóng con đường nguy hiểm, Ta mang đi con mồi đực, Ta hủy bỏ con mồi cái. Chư Tỷ-kheo, những gì vị Ðạo Sư cần phải làm cho các đệ tử vì lòng thương tưởng họ, những điều ấy Ta đã làm, vì lòng thương tưởng các Người. Chư Tỷ-kheo, đây là các gốc cây, đây là các chỗ trống. Hãy Thiền định, chớ có phóng dật, chớ có hối tiếc về sau. Ðó là lời giáo huấn của Ta.`, ref: "Trung Bộ 19 – Kinh Song Tầm", url: "https://loicuaducphat.org/mn/mn19.html#content" },
 { text: `Chư Tỷ-kheo, ví như một người thợ mộc thiện xảo hay đệ tử một người thợ mộc, dùng một cái nêm nhỏ đánh bật ra, đánh tung ra, đánh văng ra một cái nêm khác; chư Tỷ-kheo, cũng vậy, khi một Tỷ-kheo y cứ một tướng nào, tác ý một tướng nào, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si sanh khởi, thời này chư Tỷ-kheo, Tỷ-kheo ấy cần phải tác ý một tướng khác liên hệ đến thiện, không phải tướng kia. Nhờ tác ý một tướng khác liên hệ đến thiện, khác với tướng kia, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được trừ diệt, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Chư Tỷ-kheo, nếu Tỷ-kheo ấy khi tác ý một tướng khác với tướng kia, liên hệ đến thiện, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si vẫn khởi lên, thời này chư Tỷ-kheo, Tỷ-kheo ấy cần phải quán sát các nguy hiểm của những tầm ấy: “Ðây là những tầm bất thiện, đây là những tầm có tội, đây là những tầm có khổ báo”. Nhờ quán sát các nguy hiểm của những tầm ấy, các bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được trừ diệt, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Chư Tỷ-kheo, ví như một người đàn bà hay người đàn ông trẻ tuổi, trong tuổi thanh xuân, tánh ưa trang sức nếu một xác rắn, hay xác chó, hay xác người được quàng vào cổ, người ấy phải lo âu, xấu hổ, ghê tởm. Chư Tỷ-kheo, cũng vậy, nếu Tỷ-kheo ấy quán sát các nguy hiểm của những tầm ấy: “Ðây là những tầm bất thiện, đây là những tầm có tội, đây là những tầm có khổ báo”. Nhờ quán sát các nguy hiểm của những tầm ấy, các bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được trừ diệt, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Chư Tỷ-kheo, nếu Tỷ-kheo ấy trong khi quán sát các nguy hiểm của những tầm ấy, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si vẫn khởi lên, thời này chư Tỷ-kheo, Tỷ-kheo ấy cần phải không ức niệm, không tác ý những tầm ấy. Nhờ không ức niệm, không tác ý các tầm ấy, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được trừ diệt, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh. Chư Tỷ-kheo, ví như một người có mắt, không muốn thấy các sắc pháp nằm trong tầm mắt của mình, người ấy nhắm mắt lại hay ngó qua một bên. Chư Tỷ-kheo, cũng vậy, nếu Tỷ-kheo ấy, trong khi không ức niệm, không tác ý … được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },

{ text: `Chư Tỷ-kheo, nếu Tỷ-kheo, trong khi y cứ tướng nào, tác ý tướng nào, các ác bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si sanh khởi. Tỷ-kheo ấy tác ý một tướng khác, liên hệ đến thiện, khác với tướng kia, các ác, bất thiện tầm liên hệ đến dục, liên hệ đến sân, liên hệ đến si được diệt trừ, đi đến diệt vong. Chính nhờ diệt trừ chúng, nội tâm được an trú, an tịnh, nhất tâm, định tĩnh.`, ref: "Trung Bộ 20 – Kinh An Trú Tầm", url: "https://loicuaducphat.org/mn/mn20.html#content" },
{ text: `Này Phagguna, Ông phải học tập như sau: “Mong rằng tâm của ta sẽ không bị biến nhiễm! Mong rằng ta sẽ không nói những lời ác ngữ! Mong rằng ta sẽ sống với lòng lân mẫn, với tâm từ bi, không ôm lòng sân hận!” Này Phagguna, Ông phải học tập như vậy.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },

{ text: `Này các Tỷ-kheo, Ta theo hạnh nhất tọa thực. Chư Tỷ-kheo, sống theo hạnh nhất tọa thực, Ta cảm thấy không bệnh tật, không ốm đau, nhẹ nhàng, khang kiện và sảng khoái. Chư Tỷ-kheo, các Ngươi hãy sống theo hạnh nhất tọa thực. Chư Tỷ-kheo, các Ngươi theo hạnh nhất tọa thực thời các Ngươi sẽ cảm thấy không bệnh tật, không ốm đau, nhẹ nhàng, khang kiện và sảng khoái.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },

{ text: `Này các Tỷ-kheo, một thời các Tỷ-kheo của Ta có tâm rất thuần thục hoan hỷ. Chư Tỷ-kheo, Ta không cần phải giảng dạy gì cho các Tỷ-kheo ấy; chư Tỷ-kheo, Ta chỉ cần khơi dậy ức niệm nơi các Tỷ-kheo ấy. Chư Tỷ-kheo, ví như trên đất bằng, tại chỗ ngã tư, có một chiếc xe đang đậu, thắng với ngựa hay, có roi ngựa đặt ngang sẵn sàng. Có người mã thuật sư thiện xảo, người đánh xe điều ngự các con ngựa đáng được điều ngự, leo lên xe ấy, tay trái nắm lấy dây cương, tay mặt cầm lấy roi ngựa, có thể đánh xe ngựa ấy đi tới đi lui, tại chỗ nào và như thế nào, theo ý mình muốn. Cũng vậy chư Tỷ-kheo, Ta không cần phải giảng dạy gì cho các Tỷ-kheo ấy; chư Tỷ-kheo, Ta chỉ cần khơi dậy ức niệm nơi các Tỷ-kheo ấy.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },

{ text: `Do vậy, này các Tỷ-kheo, hãy từ bỏ bất thiện, hãy nỗ lực đối với các thiện pháp, như vậy các Ngươi mới thành tựu sự trưởng thành, hưng thịnh, lớn mạnh trong Pháp và Luật này. Chư Tỷ-kheo, cũng như gần một thôn làng hay thị trấn nhỏ, có ngôi rừng cây tala lớn, ngôi rừng bị các cây leo y lan bao phủ. Có một người đến khu rừng này, muốn lợi ích cho ngôi rừng, muốn hạnh phúc, muốn an ổn khỏi các ách phược cho ngôi rừng. Người ấy chặt đứt các nhành cây cong thiếu hẳn sinh lực, vất chúng ra khỏi ngôi rừng, dọn dẹp trong rừng sạch sẽ. Người ấy săn sóc kỹ lưỡng các nhánh cây tala thẳng thắn, khéo mọc. Chư Tỷ-kheo, sau một thời gian, ngôi rừng như vậy được trưởng thành, hưng thịnh, lớn mạnh. Cũng vậy, này các Tỷ-kheo, các Ngươi hãy từ bỏ bất thiện, hãy nỗ lực đối với các thiện pháp, như vậy các Ngươi mới thành tựu sự trưởng thành, hưng thịnh, lớn mạnh trong Pháp và Luật này.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },

{ text: `Cũng vậy chư Tỷ-kheo, ở đây, Tỷ-kheo hết sức hiền lành, hết sức nhu thuận, hết sức ôn hòa trong khi chưa bị những lời nói bất khả ý, xúc phạm. Và chư Tỷ-kheo, chỉ khi nào Tỷ-kheo bị những lời nói bất khả ý, xúc phạm mà vị ấy vẫn hết sức hiền lành, hết sức nhu thuận, hết sức ôn hòa, khi ấy vị ấy mới được xem là hiền lành, mới được xem là nhu thuận, mới được xem là ôn hòa. Chư Tỷ-kheo, Ta không gọi một Tỷ-kheo là dễ nói, khi vị ấy dễ nói về các vật dụng như y áo, món ăn, sàng tọa, dược phẩm trị bệnh, khi vị ấy thành tựu được tánh dễ nói. Vì sao vậy? Chư Tỷ-kheo, Tỷ-kheo ấy khi không được các vật dụng như y áo, thức ăn, sàng tọa, dược phẩm trị bệnh, không còn là dễ nói, không còn thành tựu tánh dễ nói. Chư Tỷ-kheo, Tỷ-kheo nào tôn trọng Pháp, cung kính Pháp, sùng kính Pháp trở thành dễ nói, thành tựu tánh dễ nói, vị ấy Ta mới gọi là dễ nói. Do vậy, này các Tỷ-kheo, hãy suy nghĩ: “Chỉ vì tôn trọng Pháp, cung kính Pháp, sùng kính Pháp chúng ta sẽ trở thành dễ nói, thành tựu tánh dễ nói”. Chư Tỷ-kheo, các Ngươi phải học tập như vậy.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },

{ text: `Chư Tỷ-kheo, có năm loại ngôn ngữ mà các Ngươi có thể dùng khi nói với các người khác: đúng thời hay phi thời, chơn thực hay không chơn thực, nhu nhuyến hay thô bạo, có lợi ích hay không lợi ích, với từ tâm hay với sân tâm. Chư Tỷ-kheo, khi nói với các người khác, các Ngươi có thể nói đúng thời hay phi thời. Chư Tỷ-kheo, khi nói với các người khác, các Ngươi có thể nói lời chơn thực hay nói lời không chơn thực. Chư Tỷ-kheo, khi nói với các người khác, các Ngươi có thể nói lời nhu nhuyến hay nói lời thô bạo. Chư Tỷ-kheo, khi nói với các người khác, các Ngươi có thể nói lời lợi ích hay nói lời không lợi ích. Chư Tỷ-kheo, khi nói với các người khác, các Ngươi có thể nói với từ tâm hay với sân tâm.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },

{ text: `Chư Tỷ-kheo, ở tại đây, các Ngươi cần phải học tập như sau: “Chúng ta sẽ giữ tâm của chúng ta không biến nhiễm, chúng ta sẽ không thốt ra những lời ác ngữ, chúng ta sẽ sống với lòng lân mẫn, với tâm từ bi, với nội tâm không sân hận. Chúng ta sẽ sống bao phủ người này với tâm câu hữu với từ. Và với người này là đối tượng, ta sống biến mãn cùng khắp thế giới với tâm câu hữu với từ, quảng địa vô biên, không hận, không sân”. Chư Tỷ-kheo, như vậy các Ngươi cần phải học tập.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },

{ text: `Chư Tỷ-kheo, như những kẻ đạo tặc hạ liệt, dùng cưa hai lưỡi mà cưa tay, cưa chân; dầu vậy, nếu một ai ở đây khởi ý nhiễm loạn, người ấy do vậy không phải là người thực hành giáo pháp của Ta. Ở đây, chư Tỷ-kheo các Ông phải học tập như sau: “Chúng ta sẽ giữ tâm của chúng ta không biến nhiễm; chúng ta sẽ không thốt ra những lời ác ngữ; chúng ta sẽ sống với lòng lân mẫn, với tâm từ bi, với nội tâm không sân hận. Chúng ta sẽ sống bao phủ người này với tâm câu hữu với từ. Và với người này là đối tượng, ta sống biến mãn cùng khắp thế giới với tâm câu hữu với từ, quảng đại, vô biên, không hận, không sân”. Chư Tỷ-kheo, các Ông cần phải học tập như vậy.`, ref: "Trung Bộ 21 – Kinh Ví Dụ Cái Cưa", url: "https://loicuaducphat.org/mn/mn21.html#content" },
{ text: `Thật sự, này các Tỷ-kheo, sự kiện này không xảy ra, người ta có thể thọ dụng các dục ngoài các dục, ngoài các dục tưởng, ngoài các dục tầm.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Chư Tỷ-kheo, ở đây có một số người ngu si học pháp, như Kinh, Ứng tụng, Giải thuyết, Kệ tụng, Cảm hứng ngữ, Như thị ngữ, Bổn sanh, Vị tằng hữu pháp, Phương quảng. Sau khi học các pháp này, họ không quán sát ý nghĩa những pháp ấy với trí tuệ. Những pháp ấy, vì ý nghĩa không được trí tuệ quán sát, nên không trở thành rõ ràng. Họ học các pháp chỉ vì lợi ích, muốn chỉ trích người khác, chỉ vì lợi ích, muốn khoái khẩu biện luận, và họ không đạt được mục tiêu mà sự học pháp hướng đến. Những pháp ấy vì nắm giữ sai lạc nên đưa họ đến bất hạnh, đau khổ lâu dài. Vì sao vậy? Này các Tỷ-kheo, vì nắm giữ sai lạc các pháp.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Chư Tỷ-kheo, ví như một người ưa muốn rắn nước, tìm cầu rắn nước, đi khắp chỗ để tìm rắn nước. Người đó thấy một con rắn nước lớn, và người đó bắt con rắn ấy ở lưng hay ở đuôi. Con rắn ấy có thể quay lại cắn người đó nơi tay, nơi cánh tay hay ở một phần nào khác của cơ thể, và người đó có thể do nhân này mà bị chết hay bị đau khổ gần như chết. Vì sao vậy? Chư Tỷ-kheo, vì nắm bắt con rắn một cách sai lạc. Cũng vậy này các Tỷ-kheo, ở đây, một số người ngu si học pháp. họ học các pháp chỉ vì lợi ích, muốn chỉ trích người khác, chỉ vì lợi ích, muốn khoái khẩu biện luận, và họ không đạt được mục tiêu mà sự học pháp hướng đến. Những pháp ấy vì nắm giữ sai lạc nên đưa họ đến bất hạnh, đau khổ lâu dài.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Cũng vậy, chư Tỷ-kheo, ở đây, một số Thiện nam tử học pháp … chư Tỷ-kheo, vì khéo nắm giữ các pháp vậy. Do vậy, này các Tỷ-kheo, hãy hiểu rõ ý nghĩa lời Ta thuyết giảng và thọ trì như vậy. Nếu có ai không hiểu rõ ý nghĩa lời Ta thuyết giảng thì ở nơi đây, các Ông hãy hỏi Ta hay hỏi những bậc Tỷ-kheo trí thức.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Chư Tỷ-kheo, Ta sẽ giảng pháp cho các Ông, ví như chiếc bè để vượt qua, không phải để nắm giữ lấy. Ở đây, chư Tỷ-kheo, người đó sau khi vượt qua bờ bên kia, có thể suy nghĩ: “Chiếc bè này lợi ích nhiều cho ta. Nhờ chiếc bè này, ta tinh tấn dùng tay chân đã vượt qua bờ bên kia một cách an toàn. Nay ta hãy kéo chiếc bè này lên trên bờ đất khô, hay nhận chìm xuống nước, và đi đến chỗ nào ta muốn”. Chư Tỷ-kheo, làm như vậy, người đó làm đúng sở dụng chiếc bè ấy. Cũng vậy, này chư Tỷ-kheo, Ta thuyết pháp như chiếc bè để vượt qua, không phải để nắm giữ lấy. Chư Tỷ-kheo, các Ông cần hiểu ví dụ cái bè. Chánh pháp còn phải bỏ đi, huống nữa là phi pháp.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Và này chư Tỷ-kheo, có vị Ða văn Thánh đệ tử đi đến yết kiến các bậc Thánh, thuần thục các pháp bậc Thánh, tu tập pháp các bậc Thánh, đi đến yết kiến các bậc Chơn nhơn, thuần thục pháp các bậc Chơn nhơn, tu tập pháp các bậc Chơn nhơn, xem sắc pháp: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”, xem cảm thọ: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”, xem tưởng: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”, xem các hành: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”, xem cái gì được thấy, được nghe, được cảm xúc, được ý thức, được đạt tới, được tìm cầu, được ý suy tư: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”, và bất cứ kiến xứ nào đều nói rằng: “Ðây là thế giới, đây là tự ngã, sau khi chết tôi sẽ thường còn, thường hằng, thường trú, không biến chuyển, tôi sẽ trú như thế này cho đến mãi mãi”, xem như vậy là: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”. Vị này do quán sát như vậy, đối với sự vật chẳng thật có nên không có lo âu, phiền muộn.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Này Tỷ-kheo, ở đây, có người nghĩ như sau: “Cái gì chắc chắn đã là của tôi, nay chắc chắn không còn là của tôi. Cái gì chắc chắn có thể là của tôi, chắc chắn tôi không được cái ấy”. Người đó sầu muộn, than vãn, khóc lóc, đấm ngực, đi đến bất tỉnh. Này Tỷ-kheo, như vậy, có cái không thực có ở ngoài, có thể gây lo âu, phiền muộn.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Này các Tỷ-kheo, các Ông có thể nắm giữ một vật sở hữu gì, và vật sở hữu được nắm giữ ấy sẽ thường còn, thường hằng, thường trú, không chuyển biến, có thể trú như thế này mãi mãi không? Chư Tỷ-kheo, các Ông có thể thấy một vật sở hữu nào được nắm giữ và vật sở hữu được nắm giữ ấy sẽ thường còn, thường hằng, thường trú, không chuyển biến, có thể trú như thế này mãi mãi không?\n- Bạch Thế Tôn, không.\n- Lành thay, này các Tỷ-kheo. Này các Tỷ-kheo, Ta cũng không thấy... có thể trú như thế này mãi mãi.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Chư Tỷ-kheo, Ta nói như vậy, thuyết như vậy, một số Sa-môn, Bà-la-môn xuyên tạc Ta một cách phi chơn, hồ đồ, hư vọng, không thực: “Sa-môn Gotama chủ trương chủ nghĩa hư vô, đề cao đoạn diệt, hủy diệt, sự tiêu diệt các hữu tình”. Nhưng này các Tỷ-kheo, Ta không là như vậy, Ta không nói như vậy. Chư Tỷ-kheo, xưa cũng như nay, Ta chỉ nói lên sự khổ và sự diệt khổ. Chư Tỷ-kheo, nếu ở đây những người khác nhiếc mắng, phỉ báng, làm cho Như Lai tức giận, thì này các Tỷ-kheo, ở đây, Như Lai không có sân hận, không có bất mãn, tâm không phẫn nộ. Chư Tỷ-kheo, nếu ở đây, những người khác cung kính, tôn trọng, lễ bái, cúng dường Như Lai, thì này các Tỷ-kheo, ở đây Như Lai không có hoan hỷ, sung sướng, Tâm không thích thú. Chư Tỷ-kheo, nếu những người khác cung kính, tôn trọng, lễ bái, cúng dường Như Lai, thì này các Tỷ-kheo, ở đây Như Lai suy nghĩ: “Ðây là điều xưa kia đã từng biết rõ: ở đây là trách nhiệm Ta phải làm”.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Này các Tỷ-kheo, nếu có những người khác nhiếc mắng, phỉ báng, làm cho các Ông tức giận, ở đây các Ông chớ có sân hận, bất mãn, tâm chớ khởi phẫn nộ. Do vậy, này các Tỷ-kheo, nếu có những người khác cung kính, tôn trọng, lễ bái cúng dường các Ông, thì ở đây, các Ông chớ có hoan hỷ, sung sướng, tâm sanh thích thú. Do vậy, này các Tỷ-kheo, nếu có những người khác cung kính, tôn trọng, lễ bái cúng dường các Ông, thì ở đây, các Ông hãy suy nghĩ: “Ðây là điều xưa kia đã từng biết rõ, đây là những trách nhiệm ta phải làm”.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Này các Tỷ-kheo, cái gì không phải của các Ông, các Ông hãy từ bỏ. Các Ông từ bỏ, sẽ đưa lại hạnh phúc, an lạc lâu dài cho các Ông. Chư Tỷ-kheo, cái gì không phải của các Ông? Chư Tỷ-kheo, sắc không phải của các Ông, hãy từ bỏ sắc. Các Ông từ bỏ sắc sẽ đưa lại hạnh phúc, an lạc lâu dài cho các Ông. Chư Tỷ-kheo, thọ không phải của các Ông, hãy từ bỏ thọ. Các Ông từ bỏ thọ sẽ đưa lại hạnh phúc, an lạc lâu dài cho các Ông. Chư Tỷ-kheo, tưởng không phải của các Ông, hãy từ bỏ tưởng. Các Ông từ bỏ tưởng sẽ đem lại hạnh phúc, an lạc lâu dài cho các Ông. Chư Tỷ-kheo, các hành không phải của các Ông, hãy từ bỏ các hành. Các Ông từ bỏ các hành sẽ đem lại hạnh phúc, an lạc lâu dài cho các Ông. Chư Tỷ-kheo, thức không phải của các Ông, hãy từ bỏ thức. Các Ông từ bỏ thức sẽ đem lại hạnh phúc, an lạc lâu dài cho các Ông.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Chư Tỷ-kheo, các Ông nghĩ thế nào? Trong rừng Jetavana này, nếu có người thâu lượm cỏ, cây, nhành, lá rồi đốt hay làm với chúng tùy theo ý muốn, các Ông có nghĩ chăng? Người ấy thâu lượm chúng ta, đốt chúng ta hay làm với chúng ta tùy theo ý muốn?\n- Bạch Thế Tôn, không. Vì sao vậy? Bạch Thế Tôn, vì nó không phải tự ngã hay không phải sở thuộc của ngã.\n- Cũng vậy, này các Tỷ-kheo, cái gì không phải của các Ông, các Ông hãy từ bỏ. Các Ông từ bỏ sẽ đưa lại hạnh phúc, an lạc lâu dài cho các Ông. Chư Tỷ-kheo, và cái gì không phải của các Ông? Chư Tỷ-kheo, sắc không phải của các Ông, hãy từ bỏ sắc. Các Ông từ bỏ sắc sẽ đưa lại hạnh phúc, an lạc lâu dài cho các Ông. Thọ … tưởng … hành … thức không phải của các Ông, hãy từ bỏ thức. Các Ông từ bỏ thức sẽ đem lại hạnh phúc, an lạc lâu dài cho các Ông.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Chư Tỷ-kheo, pháp được Ta khéo giảng, làm cho tỏ lộ, làm cho khai thông, làm cho khai thị, được loại trừ các vải quấn cũ. Chư Tỷ-kheo, vì pháp được Ta khéo giảng, làm tỏ lộ, làm cho khai thông, làm cho khai thị, được loại trừ các vải quấn cũ, nên những vị Tỷ-kheo, là bậc A-la-hán, các lậu hoặc đã tận, tu hành thành mãn, việc nên làm đã làm, gánh nặng đã đặt xuống, lý tưởng đã thành đạt, hữu kiết sử đã đoạn trừ, được giải thoát nhờ chánh trí, vòng luân chuyển (sanh tử) của những vị này không thể chỉ bày.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },

{ text: `Chư Tỷ-kheo, pháp được Ta khéo giảng, làm cho tỏ lộ, làm cho khai thông, làm cho khai thị, được loại trừ các vải quấn cũ. Chư Tỷ-kheo, vì pháp được Ta khéo giảng, làm cho tỏ lộ, làm cho khai thông, làm cho khai thị, được loại trừ các vải quấn cũ, nên những vị nào chỉ đủ lòng tin nơi Ta, chỉ đủ lòng thương mến đối với Ta, thì tất cả những vị ấy được hướng về chư Thiên.`, ref: "Trung Bộ 22 – Kinh Ví Dụ Con Rắn", url: "https://loicuaducphat.org/mn/mn22.html#content" },
{ text: `Này các Tỷ-kheo, lành thay khi Thiện nam tử các Người, vì lòng tin xuất gia, từ bỏ gia đình, sống không gia đình, cùng nhau hội họp để luận bàn đạo pháp. Này các Tỷ-kheo, khi các Người hội họp với nhau, có hai việc cần phải làm: luận bàn đạo pháp hay giữ sự im lặng của bậc Thánh.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, có hai loại tầm cầu này: Thánh cầu và phi Thánh cầu. Chư Tỷ-kheo, và thế nào là phi Thánh cầu? Ở đây, này các Tỷ-kheo, có người tự mình bị sanh lại tầm cầu cái bị sanh, tự mình bị già lại tìm cầu cái bị già, tự mình bị bệnh … tự mình bị chết … tự mình bị sầu … tự mình bị ô nhiễm lại tầm cầu cái bị ô nhiễm. Này các Tỷ-kheo, cái gì theo các Người gọi là bị sanh? Này các Tỷ-kheo, vợ con là bị sanh; đầy tớ nam, đầy tớ nữ là bị sanh; dê và cừu là bị sanh; gà và heo là bị sanh; voi, bò, ngựa đực, ngựa cái là bị sanh; vàng và bạc là bị sanh. Này các Tỷ-kheo, những chấp thủ ấy bị sanh, và người ấy lại nắm giữ, tham đắm, mê say chúng, tự mình bị sanh lại tầm cầu cái bị sanh.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Và này các Tỷ-kheo, cái gì theo các Người gọi là bị sầu? Này các Tỷ-kheo, vợ con là bị sầu; đầy tớ nam, đầy tớ nữ là bị sầu; dê và cừu là bị sầu, gà và heo là bị sầu; voi, bò, ngựa đực, ngựa cái là bị sầu. Này các Tỷ-kheo, những chấp thủ ấy là bị sầu, và người ấy lại nắm giữ, tham đắm, mê say chúng, tự mình bị sầu lại tìm cầu cái bị sầu.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Thánh cầu? Ở đây, này các Tỷ-kheo, có người tự mình bị sanh, sau khi biết rõ sự nguy hại của bị sanh, tìm cầu cái vô sanh, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị già, sau khi biết rõ sự nguy hại của bị già, tìm cầu cái không già, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị bệnh … cái không bệnh … tự mình bị chết … cái bất tử … tự mình bị sầu … cái không sầu … tự mình bị ô nhiễm, sau khi biết rõ sự nguy hại của ô nhiễm, tìm cầu cái không ô nhiễm, vô thượng an ổn khỏi các khổ ách, Niết-bàn. Này các Tỷ-kheo, như vậy, gọi là Thánh cầu.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, Ta cũng vậy, trước khi Giác Ngộ, khi chưa chứng Chánh Ðẳng Giác, khi còn là Bồ-tát, tự mình bị sanh lại tìm cầu cái bị sanh, tự mình bị già, lại tìm cầu cái bị già, tự mình bị bệnh … tự mình bị chết … tự mình bị sầu” … tự mình bị ô nhiễm lại tìm cầu cái bị ô nhiễm. Này các Tỷ-kheo, rồi Ta suy nghĩ như sau: “Tại sao Ta, tự mình bị sanh lại tìm cầu cái bị sanh, tự mình bị già … (như trên) … tự mình bi ô nhiễm lại tìm cầu cái bị ô nhiễm? Vậy Ta, tự mình bị sanh, sau khi biết rõ sự nguy hại của bị sanh, hãy tìm cầu cái không sanh, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị già … cái không già … tự mình bị bệnh … cái không bệnh … tự mình bị chết … cái bất tử … tự mình bị sầu … cái không sầu … tự mình bi ô nhiễm, sau khi biết rõ sự nguy hại của cái bị nhiễm, hãy tìm cầu cái không ô nhiễm, vô thượng an ổn khỏi các khổ ách, Niết-bàn.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Rồi này các Tỷ-kheo, sau một thời gian, khi Ta còn trẻ, niên thiếu, tóc đen nhánh, đầy đủ huyết khí của tuổi thanh xuân, trong thời vàng son cuộc đời, mặc dầu cha mẹ không bằng lòng, nước mắt đầy mặt, than khóc, Ta cạo bỏ râu tóc, đắp áo cà-sa, xuất gia, từ bỏ gia đình, sống không gia đình.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, Alāra Kālāma là Ðạo Sư của Ta, lại đặt Ta, đệ tử của vị ấy ngang hàng với mình, và tôn sùng Ta với sự tôn sùng tối thượng. Này các Tỷ-kheo, rồi Ta tự suy nghĩ: “Pháp này không hướng đến yểm ly, không hướng đến ly tham, không hướng đến đoạn diệt, không hướng đến an tịnh, không hướng đến thượng trí, không hướng đến giác ngộ, không hướng đến Niết-bàn, mà chỉ đưa đến sự chứng đạt Vô sở hữu xứ”. Như vậy này các Tỷ-kheo, Ta không tôn kính pháp này, và từ bỏ pháp ấy, Ta bỏ đi.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, Ta, kẻ đi tìm cái gì chí thiện, tìm cầu vô thượng tối thắng an tịnh đạo lộ, tuần tự du hành tại nước Magadha và đến tại tụ lạc Uruvela. Tại đây, Ta thấy một địa điểm khả ái, một khóm rừng thoải mái, có con sông trong sáng chảy gần, với một chỗ lội qua dễ dàng khả ái, và xung quanh có làng mạc bao bọc dễ dàng đi khất thực. Này các Tỷ-kheo, rồi Ta tự nghĩ: “Thật là một địa điểm khả ái, một khóm rừng thoải mái, có con sông trong sáng chảy gần, với một chỗ lội qua dễ dàng khả ái, và xung quanh có làng mạc bao bọc dễ dàng đi khất thực. Thật là một chỗ vừa đủ cho một Thiện nam tử tha thiết tinh cần có thể tinh tấn”. Và này các Tỷ-kheo, Ta ngồi xuống tại chỗ ấy và nghĩ: “Thật là vừa đủ để tinh tấn”.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, rồi Ta suy nghĩ như sau: “Pháp này do Ta chứng được, thật là sâu kín, khó thấy, khó chứng, tịch tịnh, cao thượng, siêu lý luận, vi diệu, chỉ người trí mới hiểu thấu. Còn quần chúng này thì ưa ái dục, khoái ái dục, ham thích ái dục. Ðối với quần chúng ưa ái dục, khoái ái dục, ham thích ái dục, thật khó mà thấy được định lý Idapaccàyata Paticcasamuppada (Y Tánh Duyên Khởi Pháp); sự kiện này thật khó thấy; tức là sự tịnh chỉ tất cả hành, sự trừ bỏ tất cả sanh y, ái diệt, ly tham, đoạn diệt, Niết-bàn.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Sao Ta nói Chánh pháp,\nÐược chứng ngộ khó khăn?\nNhững ai còn tham sân,\nKhó chứng ngộ pháp này.\n\nÐi ngược dòng, thâm diệu,\nKhó thấy, thật tế nhị,\nKẻ ái nhiễm vô minh,\nKhông thấy được pháp này.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Xưa tại Magadha,\nHiện ra pháp bất tịnh,\nPháp do tâm cấu uế,\nDo suy tư tác thành.\nHãy mỡ tung mở rộng,\nCánh cửa bất tử này.\nHãy để họ nghe Pháp,\nBậc Thanh tịnh Chứng Ngộ.\n\nNhư đứng trên tảng đá,\nTrên đỉnh núi tột cao\nCó người đứng nhìn xuống,\nÐám chúng sanh quây quần.\nCũng vậy, ôi Thiện Thệ,\nBậc Biến Nhãn cùng khắp,\nLeo lên ngôi lâu đài,\nXây dựng bằng Chánh pháp\nBậc Thoát Ly sầu muộn,\nNhìn xuống đám quần sanh,\nBị sầu khổ áp bức,\nBị sanh già chi phối,\n\nÐứng lên vị Anh Hùng,\nBậc Chiến Thắng chiến trường.\nVị trưởng đoàn lữ khách,\nBậc Thoát Ly nợ nần.\nHãy đi khắp thế giới,\nBậc Thế Tôn Chánh Giác!\nHãy thuyết vi diệu pháp,\nNgười nghe sẽ thâm hiểu!`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, sau khi biết được lời Phạm thiên yêu cầu, vì lòng từ bi đối với chúng sanh, với Phật nhãn, Ta nhìn quanh thế giới. Này các Tỷ-kheo, với Phật nhãn, Ta thấy có hạng chúng sanh ít nhiễm bụi đời, nhiều nhiễm bụi đời, có hạng lợi căn, độn căn, có hạng thiện tánh, ác tánh, có hạng dễ dạy, khó dạy, và một số ít thấy sự nguy hiểm phải tái sanh thế giới khác và sự nguy hiểm làm những hành động lỗi lầm. Như trong hồ sen xanh, hồ sen hồng hay hồ sen trắng có một số hoa sen xanh, sen hồng, hay sen trắng sanh ra dưới nước, lớn lên dưới nước, không vượt lên khỏi mặt nước, được nuôi dưỡng dưới nước. Có một hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước, lớn lên dưới nước, sống vươn lên tới mặt nước. Có một số hoa sen xanh, sen hồng hay sen trắng sanh ra dưới nước, lớn lên dưới nước, vươn lên khỏi mặt nước, không bị nước đẫm ướt.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Cửa bất tử rộng mở,\nCho những ai chịu nghe.\nHãy từ bỏ tín tâm,\nKhông chính xác của mình.\nTự nghĩ đến phiền toái,\nTa đã không muốn giảng,\nTối thượng vi diệu pháp,\nGiữa chúng sanh loài Người.\n(Ôi Phạm thiên)`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, rồi Ta tự suy nghĩ: “Ta sẽ thuyết pháp cho ai đầu tiên, ai sẽ mau hiểu Chánh pháp này?” Này các Tỷ-kheo, rồi Ta tự nghĩ: “Nay có Alāra Kālāma là bậc trí thức, đa văn, sáng suốt, đã từ lâu sống ít nhiễm bụi đời. Ta hãy thuyết pháp đầu tiên cho Alāra Kālāma, vị này sẽ mau hiểu Chánh pháp này”. Này các Tỷ-kheo, rồi chư Thiên đến Ta và nói như sau: “Bạch Thế Tôn, Alāra Kālāma đã mệnh chung bảy ngày rồi”. Rồi tri kiến khởi lên nơi Ta: “Alāra Kālāma đã mệnh chung bảy ngày rồi”. Này các Tỷ-kheo, Ta nghĩ: “Thật là một thiệt hại lớn cho Alāra Kālāma: Nếu nghe pháp này, Alāra Kālāma sẽ mau thâm hiểu”.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `- Này các Tỷ-kheo, Như Lai là bậc A-la-hán, Chánh Ðẳng Giác. Hãy lóng tai, Pháp bất tử đã chứng được, Ta giảng dạy, Ta thuyết pháp. Sống đúng theo lời khuyến giáo, các Ông không bao lâu, sau khi tự tri, tư chứng, tự đạt được ngay trong hiện tại mục đích vô thượng của phạm hạnh mà các Thiện nam tử xuất gia, từ bỏ gia đình, sống không gia đình, các Ông sẽ an trú”.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, có năm dục trưởng dưỡng. Thế nào là năm? Các sắc do mắt nhận thức, sắc này khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn. Các tiếng do tai nhận thức … (như trên) … các hương do mũi nhận thức … các vị do lưỡi nhận thức … các xúc do thân cảm xúc là khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn. Này các Tỷ-kheo, như vậy, là năm dục trưởng dưỡng.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, những Sa-môn hay Bà-la-môn nào bị trói buộc, bị tham đắm, bị mê say bởi năm dục trưởng dưỡng này, không thấy sự nguy hại của chúng, không biết rõ sự xuất ly khỏi chúng, mà thọ dụng chúng, những vị ấy cần phải được hiểu là: “Các Người đã rơi vào bất hạnh, đã rơi vào tai họa, đã bị Ác ma sử dụng như ý muốn”. Này các Tỷ-kheo, như một con nai sống trong rừng bị sập bẫy nằm xuống, con nai ấy cần phải được hiểu là: “Nó đã rơi vào bất hạnh, đã rơi vào tai họa, đã bị thợ săn sử dụng như ý muốn. Khi người thợ săn đến, con nai không thể bỏ đi như ý muốn. Này các Tỷ-kheo, cũng vậy, những vị Sa-môn hay Bà-la-môn nào bị trói buộc … (như trên) … đã bị Ác ma sử dụng như ý muốn.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Này các Tỷ-kheo, những Sa-môn hay Bà-la-môn nào không bị trói buộc, không bị tham đắm, không bị mê say bởi năm dục trưởng dưỡng này, thấy sự nguy hại của chúng, biết rõ sự xuất ly khỏi chúng, và thọ dụng chúng, những vị ấy cần phải được hiểu là: “Các Người không rơi vào bất hạnh, không rơi vào tai họa, không bị Ác ma sử dụng như ý muốn”. Này các Tỷ-kheo, như một con nai sống trong rừng, không bị sập bẫy phải nằm xuống, con nai ấy cần phải được hiểu là: “Nó không rơi vào bất hạnh, nó không rơi vào tai họa, nó không bị người thợ săn sử dụng như ý muốn”. Khi người thợ săn đến, con nai có thể bỏ đi như ý muốn. Này các Tỷ-kheo, cũng vậy, những Sa-môn hay Bà-la-môn nào không bị trói buộc … không bị Ác ma sử dụng như ý muốn.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Chư Tỷ-kheo, ví như con nai sống trong rừng, đi qua đi lại trong rừng, an tâm nó đi, an tâm nó đứng, an tâm nó ngồi, an tâm nó nằm. Tại sao vậy? Này các Tỷ-kheo, vì nó vượt khỏi tầm tay của người thợ săn. Cũng vậy, này các Tỷ-kheo, một Tỷ-kheo ly dục, ly ác bất thiện pháp chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc, do ly dục sanh, có tầm có tứ. Này các Tỷ-kheo, Tỷ-kheo ấy được gọi là: một vị đã làm Ác Ma mù mắt, đã diệt trừ mọi vết tích, đã vượt khỏi tầm mắt Ác ma.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },

{ text: `Sau khi thấy bằng trí tuệ, các lậu hoặc được đoạn trừ. Này các Tỷ-kheo, Tỷ-kheo ấy được gọi là một vị đã làm Ác ma mù mắt, đã diệt trừ mọi vết tích, đã vượt khỏi tầm mắt Ác ma. Vị ấy đã vượt khỏi mọi triền phược ở đời. An tâm vị ấy đi, an tâm vị ấy đứng, an tâm vị ấy ngồi, an tâm vị ấy nằm. Vì sao vậy? Này các Tỷ-kheo, vì vị ấy vượt khỏi tầm tay của Ác ma.`, ref: "Trung Bộ 26 – Kinh Thánh Cầu", url: "https://loicuaducphat.org/mn/mn26.html#content" },
{ text: `Chư Hiền, nếu những người khác xử sự với Tỷ-kheo không có hoàn hảo, không có tốt đẹp, không có khả ái, hoặc dùng tay xúc chạm, hoặc dùng đá xúc chạm, hoặc dùng gậy xúc chạm, hoặc dùng gươm xúc chạm, vị ấy tuệ tri như sau: “Sự thể của thân này là như vậy, nên tay có thể xúc chạm, đá có thể xúc chạm, gậy có thể xúc chạm, gươm có thể xúc chạm. Thế Tôn đã dạy như sau trong ví dụ cái cưa: “Chư Tỷ-kheo, nếu có kẻ trộm cướp hạ tiện lấy cái cưa hai lưỡi cắt từng phần tay và chân. Nếu ai ở đây sanh ý phẫn nộ, người ấy không làm đúng lời Ta dạy”. Ta sẽ tinh cần, tinh tấn, không giải đãi. Niệm được an trú không có loạn niệm, thân thể được khinh an, không dao động, tâm được định tĩnh nhất tâm. Nay mặc cho tay xúc chạm thân này, mặc cho đá xúc chạm thân này, mặc cho gậy xúc chạm thân này, mặc cho gươm xúc chạm thân này, lời dạy chư Phật cần phải được thực hành.`, ref: "Trung Bộ 28 – Ðại Kinh Dụ Dấu Chân Voi", url: "https://loicuaducphat.org/mn/mn28.html#content" },

{ text: `Chư Hiền, nếu có những người khác mắng nhiếc, chỉ trích, chọc tức, nhiễu não Tỷ-kheo, vị ấy biết rõ như sau: “Khổ thọ khởi lên nơi tôi này thuộc tai xúc chạm; thọ này do nhân duyên, không phải không do nhân duyên. Do nhân duyên gì? Do nhân duyên xúc vậy”. Vị ấy thấy xúc là vô thường; vị ấy thấy thọ là vô thường; vị ấy thấy tưởng là vô thường; vị ấy thấy hành là vô thường; vị ấy thấy thức là vô thường; tâm của vị này hoan hỷ, thích thú, tịnh chỉ, quyết định, tùy thuộc giới đối tượng.`, ref: "Trung Bộ 28 – Ðại Kinh Dụ Dấu Chân Voi", url: "https://loicuaducphat.org/mn/mn28.html#content" },

{ text: `Thế Tôn đã nói như sau: “Ai thấy được lý duyên khởi, người ấy thấy được pháp; ai thấy được pháp, người ấy thấy được lý duyên khởi”. Những pháp này do duyên khởi lên chính là năm thủ uẩn. Sự tham dục, chấp trước, tham đắm, mê say trong năm thủ uẩn này tức là khổ tập; sự nhiếp phục tham dục, sự từ bỏ tham dục tức là sự khổ diệt”. Cho đến mức độ này, Chư Hiền, Tỷ-kheo đã làm rất nhiều.`, ref: "Trung Bộ 28 – Ðại Kinh Dụ Dấu Chân Voi", url: "https://loicuaducphat.org/mn/mn28.html#content" },


{ text: `Ở đây, này các Tỷ-kheo, có Thiện nam tử do lòng tin xuất gia, từ bỏ gia đình, sống không gia đình: “Ta bị chìm đắm trong sanh, già, chết, sầu, bi, khổ, ưu, não, bị chìm đắm trong đau khổ, bị chi phối bởi đau khổ. Rất có thể, toàn bộ khổ uẩn này có thể chấm dứt được”. Vị ấy xuất gia như vậy, được lợi dưỡng, tôn kính, danh vọng. Do lợi dưỡng, tôn kính, danh vọng này, vị ấy hoan hỷ, mãn nguyện. Do lợi dưỡng, tôn kính, danh vọng này, vị ấy khen mình, chê người: “Ta được lợi dưỡng như vậy, được danh vọng như vậy. Còn các Tỷ-kheo khác ít được biết đến, ít có uy quyền”. Vị ấy, vì lợi dưỡng, tôn kính, danh vọng này, trở thành mê say, tham đắm, phóng dật. Do sống phóng dật, vị ấy bị đau khổ.`, ref: "Trung Bộ 29 – Ðại kinh Thí dụ Lõi cây", url: "https://loicuaducphat.org/mn/mn29.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, phạm hạnh này không phải vì lợi ích, lợi dưỡng, danh vọng, không phải vì lợi ích thành tựu giới đức, không phải vì lợi ích thành tựu thiền định, không phải vì lợi ích tri kiến. Và này các Tỷ-kheo, tâm giải thoát bất động chính là mục đích của phạm hạnh này, là lõi cây, là mục tiêu cuối cùng của phạm hạnh.`, ref: "Trung Bộ 29 – Ðại kinh Thí dụ Lõi cây", url: "https://loicuaducphat.org/mn/mn29.html#content" },


{ text: `Cũng vậy, này Bà-la-môn, ở đây, có người do lòng tin xuất gia, từ bỏ gia đình, sống không gia đình: “Ta bị chìm đắm trong sanh, già, chết, sầu, bi, khổ, ưu, não, bị chìm đắm trong đau khổ, bị chi phối bởi đau khổ, Rất có thể toàn bộ khổ uẩn này có thể chấm dứt”. Vị ấy xuất gia như vậy, được lợi dưỡng, tôn kính, danh vọng. Do lợi dưỡng, tôn kính, danh vọng này, vị ấy hoan hỷ, tự mãn. Do lợi dưỡng, tôn kính, danh vọng này, vị ấy khen mình, chê người: “Ta được lợi dưỡng như vậy, được danh vọng như vậy, còn các Tỷ-kheo khác ít được biết đến, ít có uy quyền”. Và vị ấy không phát khởi lòng ao ước và không cố gắng tinh tấn để chứng được các pháp khác cao thượng hơn, thù thắng hơn những lợi dưỡng, tôn kính, danh vọng. Vị ấy trở thành biếng nhác và thụ động. Này Bà-la-môn, ví như một người muốn được lõi cây, tìm cầu lõi cây. Trong khi đi tìm lõi cây, trước một cây lớn, đứng thẳng, có lõi cây, người ấy bỏ qua lõi cây, bỏ qua giác cây, bỏ qua vỏ trong, bỏ qua vỏ ngoài, chặt cành lá, lấy chúng mang đi, tưởng rằng đó là lõi cây. Và người ấy sẽ không đạt được mục đích mà lõi cây có thể thành tựu. Này Bà-la-môn, Ta nói rằng người này giống như ví dụ ấy.`, ref: "Trung Bộ 30 – Tiểu kinh Thí dụ Lõi cây", url: "https://loicuaducphat.org/mn/mn30.html#content" },
{ text: `Bạch Thế Tôn, ở đây chúng con nghĩ như sau: “Thật lợi ích thay cho ta, thật khéo lợi ích thay cho ta, khi ta được sống với các vị đồng phạm hạnh như vậy”. Bạch Thế Tôn, do vậy, đối với các vị đồng phạm hạnh này, con khởi lên từ thân nghiệp, trước mặt và sau lưng, con khởi lên từ khẩu nghiệp, trước mặt và sau lưng, con khởi lên từ ý nghiệp, trước mặt và sau lưng. Bạch Thế Tôn, do vậy, chúng con nghĩ như sau: “Ta hãy từ bỏ tâm của ta và sống thuận theo tâm của những Tôn giả này”. Bạch Thế Tôn, con từ bỏ tâm của con và sống thuận theo tâm của những Tôn giả ấy. Bạch Thế Tôn, chúng con tuy khác thân nhưng giống như đồng một tâm. Bạch Thế Tôn, như vậy chúng con sống hòa hợp, hoan hỷ với nhau, như nước với sữa, sống nhìn nhau với cặp mắt thiện cảm.`, ref: "Trung Bộ 31 – Tiểu Kinh Rừng Sừng Bò", url: "https://loicuaducphat.org/mn/mn31.html#content" },

{ text: `Này Dīgha, nếu gia đình nào, ba Thiện nam tử này xuất gia, từ bỏ gia đình, sống không gia đình, nghĩ đến ba Thiện nam tử này với tâm niệm hoan hỷ, thì gia đình ấy sẽ được an lạc, hạnh phúc lâu dài. Này Dīgha, nếu bà con quyến thuộc của gia đình mà ba Thiện nam tử này xuất gia, từ bỏ gia đình, sống không gia đình, nghĩ đến ba Thiện nam tử này với tâm niệm hoan hỷ, thì bà con quyến thuộc của gia đình ấy sẽ được an lạc, hạnh phúc lâu dài. Này Dīgha, hãy xem ba Thiện nam tử này sống như thế nào? - Vì hạnh phúc cho chúng sanh, vì an lạc cho chúng sanh, vì lòng thương tưởng cho đời, vì hạnh phúc, vì an lạc cho chư Thiên và loài Người.`, ref: "Trung Bộ 31 – Tiểu Kinh Rừng Sừng Bò", url: "https://loicuaducphat.org/mn/mn31.html#content" },
{ text: `Tôn giả Ānanda hãy đến đây, thiện lai, Tôn giả Ānanda, vị thị giả Thế Tôn, vị hầu cận Thế Tôn. Này Hiền giả Ānanda, khả ái thay khu rừng Gosinga! Ðêm rằm sáng trăng, cây Ta-la trổ hoa cùng khắp, hương trời như được tỏa rộng khắp nơi. Này Hiền giả Ānanda, hạng Tỷ-kheo nào có thể làm chói sáng khu rừng Gosinga?\nỞ đây, này Hiền giả Sāriputta, Tỷ-kheo nghe nhiều, gìn giữ điều đã nghe, tích tụ điều đã nghe. Những pháp sơ thiện, trung thiện, hậu thiện, văn nghĩa cụ túc, nói lên phạm hạnh hoàn toàn thanh tịnh, những pháp ấy được vị ấy nghe nhiều và gìn giữ kỹ, được lập lại lớn tiếng, được ý tư duy, được tri kiến khéo quán sát; vị ấy thuyết pháp cho bốn hội chúng với văn cú viên dung, lưu loát, với mục đích đoạn trừ mọi tùy miên. Này Hiền giả Sāriputta, hạng Tỷ-kheo này có thể làm sáng chói khu rừng Gosinga.`, ref: "Trung Bộ 32 – Ðại Kinh Rừng Sừng Bò", url: "https://loicuaducphat.org/mn/mn32.html#content" },

{ text: `Ở đây, này Hiền giả Sāriputta, Tỷ-kheo ưa thích đời sống tịnh cư, vui thú đời sống tịnh cư, nội tâm tu pháp, tịnh chỉ, không gián đoạn thiền định, thành tựu quán hạnh, luôn luôn lui tới các chỗ không tịch. Này Hiền giả Sāriputta, hạng Tỷ-kheo này có thể làm sáng chói khu rừng Gosinga.`, ref: "Trung Bộ 32 – Ðại Kinh Rừng Sừng Bò", url: "https://loicuaducphat.org/mn/mn32.html#content" },

{ text: `Ở đây, này Hiền giả Sāriputta, Tỷ-kheo, tự mình sống ở rừng núi và tán thán đời sống ở rừng núi, tự mình sống khất thực, và tán thán đời sống khất thực, tự mình mặc y phấn tảo và tán thán hạnh mặc y phấn tảo, tự mình sống với ba y và tán thán hạnh ba y, tự mình sống thiểu dục và tán thán hạnh thiểu dục, tự mình sống biết đủ và tán thán hạnh biết đủ, tự mình sống độc cư và tán thán hạnh sống độc cư, tự mình sống không nhiễm thế tục và tán thán hạnh không nhiễm thế tục, tự mình tinh cần, tinh tấn và tán thán hạn tinh cần, tinh tấn, tự mình thành tựu giới hạnh và tán thán sự thành tựu giới hạnh, tự mình thành tựu Thiền định và tán thán sự thành tựu thiền định, tự mình thành tựu trí tuệ và tán thán sự thành tựu trí tuệ, tự mình thành tựu giải thoát và tán thán sự thành tựu giải thoát, tự mình thành tựu giải thoát tri kiến và tán thán sự thành tựu giải thoát tri kiến. Này Hiền giả Sāriputta, hạng Tỷ-kheo như vậy có thể làm sáng chói khu rừng Gosinga.`, ref: "Trung Bộ 32 – Ðại Kinh Rừng Sừng Bò", url: "https://loicuaducphat.org/mn/mn32.html#content" },

{ text: `Ở đây, này Hiền giả Moggallāna, Tỷ-kheo điều phục được tâm, không phải Tỷ-kheo không điều phục được tâm. An trú quả nào vị ấy muốn an trú vào buổi sáng, vị ấy an trú quả ấy vào buổi sáng; an trú quả nào vị ấy muốn an trú vào buổi trưa, vị ấy an trú quả ấy buổi trưa; an trú quả nào vị ấy muốn an trú vào buổi chiều, vị ấy an trú quả ấy vào buổi chiều. Này Hiền giả Moggallāna, hạng Tỷ-kheo như vậy có thể làm sáng chói khu rừng Gosinga.`, ref: "Trung Bộ 32 – Ðại Kinh Rừng Sừng Bò", url: "https://loicuaducphat.org/mn/mn32.html#content" },

{ text: `Này Sāriputta, các Ông hãy nghe Ta nói hạng Tỷ-kheo nào có thể làm sáng chói khu rừng Gosinga. Ở đây, này Sāriputta, Tỷ-kheo, sau buổi ăn, sau khi đi khất thực về, ngồi kiết-già, lưng thẳng, đặt niệm trước mặt, và nghĩ rằng: “Ta sẽ không bỏ ngồi kiết-già này cho đến khi tâm của ta được khéo giải thoát các lậu hoặc, không có chấp thủ”. Này Sāriputta, hạng Tỷ-kheo như vậy có thể làm sáng chói khu rừng Gosinga.`, ref: "Trung Bộ 32 – Ðại Kinh Rừng Sừng Bò", url: "https://loicuaducphat.org/mn/mn32.html#content" },
{ text: `Này các Tỷ-kheo, thế nào là công việc đáng phải làm hơn nữa? “Thân hành chúng ta phải được thanh tịnh, minh chánh, cởi mở, không có tỳ vết, che giấu. Nhưng chúng ta không vì thân hành thanh tịnh ấy, khen mình, chê người”. Như vậy, này các Tỷ-kheo, các Ông cần phải tu tập. Này các Tỷ-kheo, các Ông có thể khởi lên ý kiến: “Chúng ta đã thành tựu tàm quý, thân hành chúng ta thanh tịnh, đến mức độ này, như vậy là vừa đủ; đến mức độ này, như vậy đã làm xong. Chúng ta đã đạt được mục đích Sa-môn hạnh. Chúng ta không có gì phải làm hơn nữa”. Và cho đến mức độ ấy, các Ông có thể tự thỏa mãn. Này các Tỷ-kheo, Ta khuyến cáo các Ông. Này các Tỷ-kheo, Ta tuyên bố cho các ông: Khi các Ông hướng đến mục đích Sa-môn hạnh, chớ có từ bỏ mục đích này, khi đang còn công việc đáng phải làm hơn nữa.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là các công việc đáng phải làm hơn nữa? “Chúng ta phải hộ trì các căn. Khi mắt thấy sắc, không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì khiến con mắt không được chế ngự, khiến tham ái, ưu bi, các ác, bất thiện pháp khởi lên, chúng ta sẽ tự chế ngự nguyên nhân ấy, hộ trì con mắt, thực hành sự hộ trì con mắt. Khi tai nghe tiếng … mũi ngửi hương … lưỡi nếm vị … thân cảm xúc … ý nhận thức các pháp, không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì khiến ý căn không được chế ngự, khiến tham ái, ưu, bi, các ác, bất thiện pháp khởi lên, chúng ta sẽ tự chế ngự nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn”.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là các công việc đáng phải làm hơn nữa? “Chúng ta phải biết tiết độ trong ăn uống, với chánh tư duy, chúng ta thọ thực, không phải để vui đùa, không phải để đam mê, không phải để trang sức, không phải để tự làm đẹp mình, mà chỉ để thân này được sống lâu và được bảo dưỡng, để (thân này) khỏi bị thương hại, để hỗ trợ phạm hạnh, nghĩ rằng: “Như vậy chúng ta diệt trừ các cảm thọ cũ và không cho khởi lên cảm thọ mới, và chúng ta sẽ không có lỗi lầm, sống được an ổn”. Như vậy, này các Tỷ-kheo, các Ông cần phải tu tập.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là các công việc đáng phải làm hơn nữa? “Chúng ta phải chú tâm cảnh giác. Ban ngày đi kinh hành (hay) trong lúc ngồi, chúng ta phải tẩy sạch tâm tư khỏi các pháp chướng ngại. Ban đêm canh một đi kinh hành (hay) trong lúc ngồi, chúng ta phải tẩy sạch tâm tư khỏi các pháp chướng ngại. Ban đêm canh giữa, chúng ta phải nằm dáng nằm con sư tử, nghiêng bên hông tay phải, một chân đặt trên chân kia, chánh niệm tỉnh giác, tâm nghĩ đến lúc thức dậy lại. Ban đêm canh đầu thức dậy, đi kinh hành (hay) trong lúc ngồi, chúng ta phải tẩy sạch tâm tư khỏi các pháp chướng ngại”. Như vậy, này các Tỷ-kheo, các Ông cần phải tu tập.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Nhờ hiểu biết như vậy, nhận thức như vậy, tâm của vị ấy thoát khỏi dục lậu, thoát khỏi hữu lậu, thoát khỏi vô minh lậu. Ðối với tự thân đã giải thoát như vậy, khởi lên sự hiểu biết: “Ta đã giải thoát”. Vị ấy tuệ tri: “Sanh đã tận, phạm hạnh đã thành, những việc cần làm đã làm xong, sau đời hiện tại không có đời sống nào khác nữa”.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Này các Tỷ-kheo, như thế nào, Tỷ-kheo là Sa-môn? Vị này đã làm cho dừng lại các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh, già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo là Sa-môn.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo đã tắm sạch sẽ? Vị này đã tắm gội sạch sẽ các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo đã tắm sạch sẽ.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo đã biết và hiểu rõ? Vị này đã biết và hiểu rõ các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo đã biết và hiểu rõ.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo có học? Vị này đã tiêu diệt các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo có học.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo được gọi là bậc Thánh? Vị này đã làm cho xa lìa các ác pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo được gọi là bậc Thánh.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo được gọi là bậc A-la-hán? Vị này đã làm cho xa lìa các ác, các pháp bất thiện, những pháp này ô nhiễm, đưa đến tái sanh, đáng sợ hãi, đem lại khổ quả, đưa đến sanh già, chết trong tương lai. Như vậy, này các Tỷ-kheo, Tỷ-kheo là bậc A-la-hán.`, ref: "Trung Bộ 39 – Ðại Kinh Xóm Ngựa", url: "https://loicuaducphat.org/mn/mn39.html#content" },
{ text: `Này các Tỷ-kheo, các Ông đã chấp nhận rằng, trong khi các Ông sống cạnh tranh, luận tranh, đấu tranh, đả thương nhau bằng binh khí miệng lưỡi, trong khi ấy, không có an trú từ thân hành đối với các vị đồng phạm hạnh cả trước mặt lẫn sau lưng, không có an trú từ khẩu hành đối với các vị đồng phạm hạnh cả trước mặt lẫn sau lưng, không có an trú từ ý hành đối với các vị đồng phạm hạnh cả trước mặt lẫn sau lưng. Như vậy, này các kẻ mê mờ kia, do biết gì, do thấy gì, các Ông sống cạnh tranh, luận tranh, đấu tranh, đả thương nhau với những binh khí miệng lưỡi; và các Ông không tự thông cảm nhau, không chấp nhận thông cảm, không tự hòa giải nhau, không chấp nhận hòa giải. Như vậy, này các kẻ mê mờ kia, các Ông sẽ phải chịu bất hạnh, đau khổ trong một thời gian dài.`, ref: "Trung Bộ 48 – Kinh Kosambiya", url: "https://loicuaducphat.org/mn/mn48.html#content" },

{ text: `- Này các Tỷ-kheo, có sáu pháp này cần phải ghi nhớ, tạo thành tương ái, tạo thành tương kính, đưa đến hòa đồng, đưa đến vô tranh luận, hòa hợp, nhất trí. Thế nào là sáu? Ở đây, này các Tỷ-kheo, Tỷ-kheo an trú từ thân hành, an trú từ khẩu hành, an trú từ ý hành đối với các vị đồng phạm hạnh cả trước mặt lẫn sau lưng. Pháp này cần phải ghi nhớ, tạo thành tương ái, tạo thành tương kính, đưa đến hòa đồng, đưa đến không tranh luận, hòa hợp, nhất trí.`, ref: "Trung Bộ 48 – Kinh Kosambiya", url: "https://loicuaducphat.org/mn/mn48.html#content" },

{ text: `Này các Tỷ-kheo, đối với các tài vật nhận được đúng pháp, hợp pháp, cho đến những tài vật thâu nhận chỉ trong bình bát, Tỷ-kheo không phải là người không san sẻ, các tài vật nhận được như vậy, phải là người san sẻ dùng chung với các vị đồng phạm hạnh có giới đức. Pháp này cần phải ghi nhớ, tạo thành tương ái, tạo thành tương kính, đưa đến hòa đồng, đưa đến không tranh luận, hòa hợp, nhất trí.`, ref: "Trung Bộ 48 – Kinh Kosambiya", url: "https://loicuaducphat.org/mn/mn48.html#content" },

{ text: `Này các Tỷ-kheo, đối với các giới luật không có vi phạm, không có tỳ vết, không có vẩn đục, không có uế tạp, giải thoát, được người trí tán thán, không bị chấp trước, đưa đến thiền định, Tỷ-kheo sống thành tựu trong các giới luật ấy với các vị đồng phạm hạnh cả trước mặt lẫn sau lưng. Pháp này cần phải ghi nhớ, tạo thành tương ái, tạo thành tương kính, đưa đến hòa đồng, đưa đến không tranh luận, hòa hợp, nhất trí.`, ref: "Trung Bộ 48 – Kinh Kosambiya", url: "https://loicuaducphat.org/mn/mn48.html#content" },

{ text: `Này các Tỷ-kheo, đối với các tri kiến thuộc về bậc Thánh có khả năng hướng thượng, khiến người thực hành chân chánh diệt tận khổ đau, Tỷ-kheo, sống thành tựu tri kiến như vậy, cùng với các đồng phạm hạnh cả trước mặt lẫn sau lưng. Pháp này cần phải ghi nhớ, tạo thành tương ái, tạo thành tương kính, đưa đến hòa đồng, đưa đến không tranh luận, hòa hợp, nhất trí.`, ref: "Trung Bộ 48 – Kinh Kosambiya", url: "https://loicuaducphat.org/mn/mn48.html#content" },
{ text: `Này Kandaraka, trong chúng Tỷ-kheo này, có những Tỷ-kheo là bậc hữu học, giới luật kiên trì, giới hạnh kiên trì, sáng suốt, hạnh nghiệp sáng suốt, sống với tâm khéo an trú Bốn Niệm xứ. Thế nào là bốn? Ở đây này Kandaraka, Tỷ-kheo sống quán thân trên thân, nhiệt tâm tỉnh giác, chánh niệm, để nhiếp phục tham ưu trên đời; sống quán thọ trên các cảm thọ, nhiệt tâm tỉnh giác, chánh niệm, để nhiếp phục tham ưu trên đời; sống quán tâm trên tâm, nhiệt tâm, tỉnh giác, chánh niệm để nhiếp phục tham ưu trên đời; sống quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, để nhiếp phục tham ưu trên đời.`, ref: "Trung Bộ 51 – Kinh Kandaraka", url: "https://loicuaducphat.org/mn/mn51.html#content" },

{ text: `Thật vi diệu thay, bạch Thế Tôn! Thật hy hữu thay, bạch Thế Tôn! Bốn Niệm xứ này đã được Thế Tôn khéo trình bày, để chúng sanh được thanh tịnh, để sầu bi được vượt qua, để khổ ưu được diệt trừ, để chánh lý được thành đạt, để Niết-bàn được chứng ngộ. Bạch Thế Tôn, chúng con là hàng tại gia, mặc đồ trắng, thỉnh thoảng chúng con sống khéo an trú tâm vào Bốn Niệm xứ này. Ở đây, Bạch Thế Tôn, chúng con sống quán thân trên thân, quán thọ trên các cảm thọ...quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, để nhiếp phục tham ưu trên đời.`, ref: "Trung Bộ 51 – Kinh Kandaraka", url: "https://loicuaducphat.org/mn/mn51.html#content" },

{ text: `Thật vi diệu thay, bạch Thế Tôn! Thật hy hữu thay, bạch Thế Tôn! Bạch Thế Tôn, Thế Tôn hiểu được hạnh phúc và sự bất hạnh của chúng sanh trong khi loài người sống trong sự rối ren như vậy, trong sự cặn bã như vậy, trong sự xảo quyệt như vậy. Bạch Thế Tôn, rối ren thay như loài người. Bạch Thế Tôn, cởi mở thay như loài thú vật. Bạch Thế Tôn, con có thể nhiếp phục con voi, một cách khiến con voi ấy mỗi khi đi hay đến Campā, liền trình bày mọi sự gian dối, giả dối, xảo trá, xảo quyệt. Nhưng bạch Thế Tôn, những người đầy tớ của chúng con, những người phục dịch, những người làm công, thân hành họ làm một cách, khẩu hành họ làm một cách khác, ý hành họ làm một cách khác nữa.`, ref: "Trung Bộ 51 – Kinh Kandaraka", url: "https://loicuaducphat.org/mn/mn51.html#content" },
{ text: `Và này Mahānāma, thế nào là vị Thánh đệ tử thành tựu giới hạnh? Ở đây, này Mahānāma, vị Thánh đệ tử có giới hạnh, sống chế ngự với sự chế ngự của giới bổn Pātimokkha, đầy đủ oai nghi chánh hạnh, thấy nguy hiểm trong những lỗi nhỏ nhặt, thọ lãnh và tu học các học pháp. Này Mahānāma, như vậy là vị Thánh đệ tử thành tựu giới hạnh.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Và này Mahānāma, thế nào là vị Thánh đệ tử hộ trì các căn? Ở đây, này Mahānāma, vị Thánh đệ tử, khi mắt thấy sắc, không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì vì nhãn căn không được chế ngự, khiến tham ưu, các ác, bất thiện pháp khởi lên, vị ấy tự chế ngự nguyên nhân ấy, hộ trì nhãn căn, thực hành sự hộ trì nhãn căn. Khi tai nghe tiếng … mũi ngửi hương … lưỡi nếm vị … thân cảm xúc … ý nhận thức các pháp, vị ấy không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì vì ý căn không được chế ngự, khiến tham ưu, các ác, bất thiện pháp khởi lên, vị ấy chế ngự nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn. Này Mahānāma, như vậy là vị Thánh đệ tử hộ trì các căn.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Và này Mahānāma, thế nào là vị Thánh đệ tử biết tiết độ trong ăn uống? Ở đây, này Mahānāma, vị Thánh đệ tử chơn chánh giác sát, thọ dụng món ăn, không phải để vui đùa, không phải để đam mê, không phải để trang sức, không phải để tự làm đẹp mình, chỉ để thân này được duy trì, được bảo dưỡng, khỏi bị gia hại, để chấp trì Phạm hạnh, nghĩ rằng: “Như vậy ta diệt trừ các cảm thọ cũ và không cho khởi lên các cảm thọ mới; và ta sẽ không phạm lỗi lầm, sống được an ổn”. Này Mahānāma, như vậy là vị Thánh đệ tử biết tiết độ trong sự ăn uống.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Và này Mahānāma, thế nào là vị Thánh đệ tử chú tâm cảnh giác? Ở đây, này Mahānāma, vị Thánh đệ tử ban ngày trong khi đi kinh hành và trong khi đang ngồi, gột sạch tâm trí khỏi các chướng ngại pháp, ban đêm trong canh một, trong khi đi kinh hành và trong khi đang ngồi, gột sạch tâm trí khỏi các chướng ngại pháp, ban đêm trong canh giữa, vị này nằm xuống phía hông bên phải, như dáng nằm con sư tử, chân gác trên chân với nhau, chánh niệm tỉnh giác, hướng niệm đến lúc ngồi dậy lại. Ban đêm trong canh cuối, khi đã thức dậy, trong khi đi kinh hành và trong khi đang ngồi, gột sạch tâm trí khỏi các chướng ngại pháp. Này Mahānāma, như vậy là vị Thánh đệ tử chú tâm cảnh giác.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Ở đây, này Mahānāma, vị Thánh đệ tử có lòng tin, có lòng tin ở sự giác ngộ của Như Lai: Ngài là Thế Tôn, bậc A-la-hán, Chánh Ðẳng Giác, Minh Hạnh Túc, Thiện Thệ, Thế Gian Giải, Vô Thượng Sĩ, Ðiều Ngự Trượng Phu, Thiên Nhân Sư, Phật, Thế Tôn.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Ở đây, này Mahānāma, vị Thánh đệ tử có lòng tàm, tự xấu hổ vì thân ác hạnh, khẩu ác hạnh, ý ác hạnh, tự xấu hổ vì thành tựu ác, bất thiện pháp. Vị này có lòng quý, tự sợ hãi vì thân ác hạnh, khẩu ác hạnh, ý ác hạnh, tự sợ hãi vì thành tựu ác, bất thiện pháp.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Ở đây, này Mahānāma, vị Thánh đệ tử là vị đa văn, nhớ nghĩ những điều đã nghe, tích tụ những điều đã nghe. Những pháp nào, sơ thiện, trung thiện, hậu thiện, có nghĩa, có văn, nói lên phạm hạnh hoàn toàn đầy đủ thanh tịnh, những pháp như vậy, vị ấy nghe nhiều, thọ trì, đọc tụng bằng lời, được ý suy tư, được chánh kiến thể nhập.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },

{ text: `Ở đây, này Mahānāma, vị Thánh đệ tử sống tinh cần tinh tấn, trừ bỏ các pháp bất thiện, thành tựu các thiện pháp, nỗ lực, kiên trì, không từ bỏ gánh nặng đối với các thiện pháp. Vị ấy có niệm, thành tựu niệm tuệ tối thắng, nhớ lại, nhớ lại nhiều lần những gì đã làm từ lâu, đã nói từ lâu. Vị ấy có trí tuệ, thành tựu trí tuệ về sanh diệt, thành tựu Thánh thể nhập đưa đến chơn chánh đoạn tận khổ đau. Này Mahānāma, như vậy vị Thánh đệ tử thành tựu diệu pháp.`, ref: "Trung Bộ 53 – Kinh Hữu học", url: "https://loicuaducphat.org/mn/mn53.html#content" },
{ text: `Vị ấy xuất gia như vậy, hành trì các học giới và hạnh sống của các Tỷ-kheo, từ bỏ sát sanh, tránh xa sát sanh, bỏ trượng, bỏ kiếm, biết xấu hổ, sợ hãi, có lòng từ, sống thương xót đến hạnh phúc tất cả chúng sanh và loài hữu tình. Vị ấy từ bỏ lấy của không cho, tránh xa lấy của không cho, chỉ mong những vật đã cho, tự sống thanh tịnh, không có trộm cướp. Vị ấy từ bỏ đời sống không Phạm hạnh, sống theo Phạm hạnh, sống đời sống viễn ly, tránh xa dâm dục hạ liệt.`, ref: "Trung Bộ 60 – Kinh Không Gì Chuyển Hướng", url: "https://loicuaducphat.org/mn/mn60.html#content" },
{ text: `Rồi Thế Tôn, sau khi để một ít nước còn lại trong chậu nước (rửa chân), bảo Tôn giả Rāhula\n- Này Rāhula, Ông có thấy một ít nước còn lại này trong chậu nước không?\n- Thưa vâng, bạch Thế Tôn.\n- Cũng ít vậy, này Rāhula, là Sa-môn hạnh của những người nào biết mà nói láo, không có tàm quý.`, ref: "Trung Bộ 61 – Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn61.html#content" },

{ text: `Rồi Thế Tôn, sau khi đổ đi chút ít nước (rửa chân) còn lại ấy rồi bảo Rāhula\n- Này Rāhula, Ông có thấy chút ít nước còn lại ấy bị đổ đi không?\n- Thưa vâng, bạch Thế Tôn.\n- Cũng đổ đi vậy, này Rāhula, là Sa-môn hạnh của những người nào biết mà nói láo, không có tàm quý.`, ref: "Trung Bộ 61 – Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn61.html#content" },

{ text: `Này Rāhula, Ông nghĩ thế nào? Mục đích của cái gương là gì?\n- Bạch Thế Tôn, mục đích là để phản tỉnh.\n- Cũng vậy, này Rāhula, sau khi phản tỉnh nhiều lần, hãy hành thân nghiệp. Sau khi phản tỉnh nhiều lần, hãy hành khẩu nghiệp. Sau khi phản tỉnh nhiều lần, hãy hành ý nghiệp.`, ref: "Trung Bộ 61 – Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn61.html#content" },

{ text: `Này Rāhula, khi Ông muốn làm một thân nghiệp gì, hãy phản tỉnh thân nghiệp ấy như sau: “Thân nghiệp này của ta có thể đưa đến tự hại, có thể đưa đến hại người, có thể đưa đến hại cả hai; thời thân nghiệp này là bất thiện, đưa đến đau khổ, đem đến quả báo đau khổ”. Này Rāhula, nếu trong khi phản tỉnh, Ông biết: “Thân nghiệp này, ta muốn làm. Thân nghiệp này của ta có thể đưa đến tự hại, có thể đưa đến hại người, có thể đưa đến hại cả hai; thời thân nghiệp này là bất thiện, đưa đến đau khổ, đem đến quả báo đau khổ”. Một thân nghiệp như vậy, này Rāhula, Ông nhất định chớ có làm. Này Rāhula, nếu sau khi phản tỉnh, ông biết: “Thân nghiệp này ta muốn làm. Thân nghiệp này của ta không có thể đưa đến tự hại, không có thể đưa đến hại người, không có thể đưa đến hại cả hai; thời thân nghiệp này là thiện, đưa đến an lạc, đem đến quả báo an lạc”. Một thân nghiệp như vậy, này Rāhula, Ông nên làm.`, ref: "Trung Bộ 61 – Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn61.html#content" },
{ text: `Này Rāhula, hãy tu tập sự tu tập niệm hơi thở vô, hơi thở ra. Này Rāhula, tu tập niệm hơi thở vô hơi thở ra, làm cho sung mãn, được quả lớn, được lợi ích lớn.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },

{ text: `Này Rāhula, hãy tu tập sự tu tập như đất. Này Rāhula, do tu tập sự tu tập như đất, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại. Này Rāhula, ví như trên đất người ta quăng đồ tịnh, quăng đồ không tịnh, quăng phân uế, quăng nước tiểu, nhổ nước miếng, quăng mủ và quăng máu; tuy vậy đất không lo âu, không dao động, hay không nhàm chán; cũng vậy, này Rāhula, hãy tu tập như đất. Này Rāhula, do tu tập sự tu tập như đất, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },

{ text: `Này Rāhula, hãy tu tập sự tu tập như nước. Này Rāhula, do tu tập sự tu tập như nước, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại. Này Rāhula, ví như trong nước người ta rửa đồ tịnh, rửa đồ không tịnh, rửa sạch phân uế, rửa sạch nước tiểu, rửa sạch nước miếng, rửa sạch mủ, rửa sạch máu; tuy vậy nước không lo âu, không dao động, không nhàm chán; cũng vậy, này Rāhula, hãy tu tập sự tụ tập như nước, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },

{ text: `Này Rāhula, hãy tu tập sự tu tập như lửa. Này Rāhula, do tu tập sự tu tập như lửa, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại. Này Rāhula, ví như lửa đốt các đồ tịnh, đốt các đồ không tịnh, đốt phân uế, đốt nước tiểu, đốt nước miếng, đốt mủ, đốt máu; tuy vậy lửa không lo âu, không dao động, không nhàm chán; cũng vậy, này Rāhula, hãy tu tập sự tu tập như lửa, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },

{ text: `Này Rāhula, hãy tu tập sự tu tập như gió. Này Rāhula, do tu tập sự tu tập như gió, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại. Này Rāhula, như gió thổi các đồ tịnh, thổi các đồ không tịnh, thổi phân uế, thổi nước tiểu, thổi nước miếng, thổi mủ, thổi máu, tuy vậy gió không lo âu, không dao động, không nhàm chán; cũng vậy, này Rāhula, hãy tu tập sự tu tập như gió, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },

{ text: `Này Rāhula, hãy tu tập sự tu tập như hư không. Này Rāhula, do tu tập sự tu tập như hư không, các xúc khả ái, không khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại. Này Rāhula, ví như hư không không bị trú tại một chỗ nào; cũng vậy, này Rāhula, hãy tu tập sự tu tập như hư không. Này Rāhula, do tu tập sự tu tập như hư không, các xúc khả ái không, khả ái được khởi lên, không có nắm giữ tâm, không có tồn tại.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },

{ text: `Này Rāhula, hãy tu tập sự tu tập về lòng từ. Này Rāhula, do tu tập sự tu tập về lòng từ, cái gì thuộc sân tâm sẽ được trừ diệt. Này Rāhula, hãy tu tập sự tu tập về lòng bi. Này Rāhula, do tu tập sự tu tập về lòng bi, cái gì thuộc hại tâm sẽ được trừ diệt. Này Rāhula, hãy tu tập sự tu tập về hỷ. Này Rāhula, do tu tập sự tu tập về hỷ, cái gì thuộc bất lạc sẽ được trừ diệt. Này Rāhula, hãy tu tập sự tu tập về xả. Này Rāhula, do tu tập sự tu tập về xả, cái gì thuộc hận tâm sẽ được trừ diệt.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },

{ text: `Này Rāhula, hãy tu tập sự tu tập về bất tịnh. Này Rāhula, do tu tập sự tu tập về bất tịnh, cái gì thuộc tham ái được trừ diệt. Này Rāhula, hãy tu tập sự tu tập về vô thường. Này Rāhula, do tu tập sự tu tập về vô thường, cái gì thuộc ngã mạn được trừ diệt.`, ref: "Trung Bộ 62 – Đại Kinh Giáo Giới Rahula", url: "https://loicuaducphat.org/mn/mn62.html#content" },
{ text: `Và này Ānanda, thế nào là con đường, thế nào là lộ trình đưa đến sự đoạn trừ năm hạ phần kiết sử? Ở đây, này Ānanda, Tỷ-kheo do viễn ly các sanh y (Upadhiviveka), do đoạn trừ các bất thiện pháp, do làm cho an tịnh thân thô ác hành một cách toàn diện, ly dục, ly bất thiện pháp, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, có tầm, có tứ.`, ref: "Trung Bộ 64 – Ðại Kinh Màlunkyà", url: "https://loicuaducphat.org/mn/mn64.html#content" },

{ text: `Vị ấy chánh quán mọi sắc pháp, thọ pháp, tưởng pháp, hành pháp, thức pháp là vô thường, khổ, như bệnh, như cục bướu, như mũi tên, như điều bất hạnh, như bệnh chướng, như kẻ địch, như phá hoại, là không, là vô ngã. Vị này giải thoát tâm khỏi các pháp ấy. Sau khi giải thoát tâm khỏi các pháp ấy, vị ấy tập trung tâm vào bất tử giới (Amatadhatu) và nghĩ rằng: “Ðây là tịch tịnh, đây là vi diệu, tức là sự an chỉ tất cả hành, sự xả ly tất cả sanh y, sự ái diệt, vô tham, đoạn diệt, Niết-bàn”. Nếu an trú vững chắc ở đây, vị này đạt đến sự đoạn tận các lậu hoặc. Nếu vị ấy không đạt đến sự đoạn tận các lậu hoặc, thời do sự tham pháp, hỷ pháp của mình, thời do sự đoạn tận năm hạ phần kiết sử, vị ấy được hóa sanh, nhập Niết-bàn ở đấy, không phải trở lui đời này nữa.`, ref: "Trung Bộ 64 – Ðại Kinh Màlunkyà", url: "https://loicuaducphat.org/mn/mn64.html#content" },
{ text: `Này các Tỷ-kheo, Ta ăn chỉ ngồi một lần. Này các Tỷ-kheo, do Ta ăn chỉ ngồi một lần, Ta cảm thấy ít bệnh, ít não, nhẹ nhàng, có sức và lạc trú. Này các Tỷ-kheo, hãy ăn chỉ ngồi một lần. Này các Tỷ-kheo, hãy ăn chỉ ngồi một lần, và các Ông sẽ cảm thấy ít bệnh, ít não, nhẹ nhàng, có sức và lạc trú.`, ref: "Trung Bộ 65 – Kinh Bhaddali", url: "https://loicuaducphat.org/mn/mn65.html#content" },

{ text: `Này Bhaddali, thật sự một lỗi lầm đã chiếm đoạt Ông, thật là ngu ngốc, thật là si mê, thật là bất thiện. Trong khi chúng Tỷ-kheo chấp hành học giới đã được Ta chế định, Ông đã tuyên bố sự bất lực của Ông. Này Bhaddali, nếu Ông sau khi thấy một lỗi lầm là một lỗi lầm, và như pháp phát lộ, chúng ta sẽ chấp nhận cho Ông. Vì rằng, này Bhaddali, như vậy là sự lớn mạnh trong giới luật của bậc Thánh, nghĩa là bất cứ ai, sau khi thấy một lỗi lầm là một lỗi lầm, phải như pháp phát lộ và phòng hộ trong tương lai.`, ref: "Trung Bộ 65 – Kinh Bhaddali", url: "https://loicuaducphat.org/mn/mn65.html#content" },

{ text: `Ở đây, này Bhaddali, có Tỷ-kheo thực hành trọn vẹn học giới trong giáo pháp bậc Ðạo Sư. Vị ấy suy nghĩ như sau: “Ta hãy sống tại một trú xứ xa vắng, khu rừng, gốc cây, sườn núi, chỗ hoang dã, hang núi, nghĩa địa, tùng lâm, ngoài trời, đống rơm. Và ta có thể chứng được thượng nhân pháp, tri kiến thù thắng xứng đáng bậc Thánh”. Vị ấy sống tại một trú xứ xa vắng, khu rừng, gốc cây, sườn núi, chỗ hoang dã, hang núi, nghĩa địa, tùng lâm, ngoài trời, đống rơm. Khi vị ấy sống viễn ly như vậy, bậc Ðạo Sư không quở trách, các vị đồng Phạm hạnh có trí sau khi quán sát không quở trách, chư Thiên không quở trách, tự mình không quở trách mình. Vị này không bị bậc Ðạo Sư quở trách, không bị các đồng Phạm hạnh sau khi quán sát quở trách, không bị chư Thiên quở trách, không bị mình quở trách mình, nên chứng được thượng nhân pháp, tri kiến thù thắng xứng đáng bậc Thánh.`, ref: "Trung Bộ 65 – Kinh Bhaddali", url: "https://loicuaducphat.org/mn/mn65.html#content" },
{ text: `Rồi Tôn giả Udāyi, trong khi độc cư Thiền tịnh, sự suy tư sau đây đã khởi lên trong tâm trí Tôn giả: “Thế Tôn thật sự là vị đã đoạn trừ nhiều khổ pháp cho chúng ta. Thế Tôn thật sự là vị đã mang lại nhiều lạc pháp cho chúng ta. Thế Tôn thật sự là vị đã đoạn trừ nhiều bất thiện pháp cho chúng ta. Thế Tôn thật sự là vị đã mang lại nhiều thiện pháp cho chúng ta”.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Bạch Thế Tôn, thuở trước chúng con thường ăn buổi chiều, buổi sáng, ban ngày và phi thời. Bạch Thế Tôn, thời ấy, Thế Tôn gọi các Tỷ-kheo và bảo: “Này các Tỷ-kheo, hãy từ bỏ ăn ban ngày phi thời”. Bạch Thế Tôn, do vậy con cảm thấy thất vọng, con cảm thấy sầu muộn, nghĩ rằng: “Những món ăn thượng vị loại cứng và loại mềm, các tín chủ cúng dường cho chúng ta ban ngày và phi thời. Nay Thế Tôn dạy chúng ta phải đoạn trừ, bậc Thiện Thệ dạy chúng ta phải từ bỏ”. Bạch Thế Tôn, giữa chúng con, những ai nhìn Thế Tôn với lòng ái mộ, với lòng tôn kính và với lòng tàm quý, liền từ bỏ ăn ban ngày phi thời.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Này Udāyi, ở đây có một số người ngu si; khi Ta nói: “Hãy từ bỏ việc này”, liền nói như sau: “Có sá gì sự việc tiểu tiết, nhỏ mọn này. Sa-môn này đặt quá nặng về cấm đoán đoạn giảm”. Họ không chịu từ bỏ và gây lên bất mãn chống Ta và chống những Tỷ-kheo muốn thực hành học giới. Sự việc ấy, này Udāyi, đối với họ, trở thành một trói buộc mạnh mẽ, một trói buộc vững chắc, một trói buộc kiên cường, một trói buộc không mục nát, một khúc gỗ to lớn.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Ví như, này Udāyi, một người nghèo khổ thấy một Tỷ-kheo trong tịnh xá, tay chân lau rửa sạch sẽ, sau khi ăn buổi cơm ngon lành, đang ngồi trong bóng mát, hướng về tăng thượng tâm. Người ấy suy nghĩ: “An lạc thay, Sa-môn hạnh! Vô bệnh thay, Sa-môn hạnh! Vậy sau khi cạo bỏ râu tóc, đắp áo cà-sa, ta hãy xuất gia, từ bỏ gia đình, sống không gia đình”. Nhưng người ấy không có thể từ bỏ cái chòi ở hư nát, mở toang cho quạ, không đẹp mắt chút nào, không có thể từ bỏ cái giường nằm hư nát, không đẹp mắt chút nào, không có thể từ bỏ các loại gạo lúa cất chứa trong một cái chum không đẹp mắt chút nào, không có thể từ bỏ bà vợ không đẹp mắt chút nào, để có thể sau khi cạo bỏ râu tóc, đắp áo cà-sa, xuất gia, từ bỏ gia đình, sống không gia đình.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Này Udāyi, một gia chủ hay con người gia chủ, giàu có, tài sản lớn, tiền của lớn, vô số vàng bạc, vô số gạo thóc, vô số ruộng nương, vô số đất đai, vô số thê thiếp, vô số đầy tớ nam, vô số nữ tỳ. Vị này thấy một Tỷ-kheo trong một tinh xá, tay chân lau rửa sạch sẽ, sau khi ăn bữa cơm ngon lành, đang ngồi trong bóng mát, hướng về tăng thượng tâm. Vị này suy nghĩ: “An lạc thay, Sa-môn hạnh! Vô bệnh thay, Sa-môn hạnh! Vậy sau khi cạo bỏ râu tóc, đắp áo cà-sa, ta hãy xuất gia, từ bỏ gia đình, sống không gia đình”.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Ở đây, này Udāyi, có người sống, hướng đến sự đoạn trừ sanh y, sự từ bỏ sanh y. Nhưng trong khi vị này sống hướng đến sự đoạn trừ sanh y, sự từ bỏ sanh y, những tư niệm, tư duy liên hệ đến sanh y hiện hành khởi lên. Vị này chấp nhận chúng, không đoạn trừ chúng, không từ bỏ chúng, không chấm dứt chúng, không tiêu diệt chúng. Này Udāyi, Ta nói: “Người này bị trói buộc, không phải không bị trói buộc”. Vì sao vậy? Này Udāyi, sự sai biệt về căn tánh trong người này đã được Ta biết rõ.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Ở đây, này Udāyi, có người sống, hướng đến sự đoạn trừ sanh y, sự từ bỏ sanh y. Nhưng trong khi vị này sống hướng đến sự đoạn trừ sanh y, sự từ bỏ sanh y, các tư niệm điên đảo, các tư niệm, tư duy liên hệ đến sanh y, tùy lúc tùy thời hiện hành khởi lên. Này Udāyi, niệm khởi lên chậm chạp và vị này đoạn trừ niệm ấy một cách mau chóng, từ bỏ, chấm dứt, tiêu diệt (niệm ấy). Này Udāyi, ví như một người nhỏ hai hay ba giọt nước vào một ấm nước đun sôi cả ngày. Này Udāyi giọt nước rơi một cách chậm chạp như bị tiêu diệt, tiêu mất một cách mau chóng. Này Udāyi, Ta nói: “Người này cũng bị trói buộc, không phải không bị trói buộc”. Vì sao vậy? Này Udāyi, sự sai biệt về căn tánh trong người này đã được Ta biết rõ.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Nhưng ở đây, này Udāyi, có người nghĩ rằng: “Sanh y là nguồn gốc của đau khổ”, sau khi biết như vậy, vị ấy thành vô sanh y, giải thoát với sự đoạn diệt sanh y. Này Udāyi, Ta nói: “Người này không bị trói buộc, không phải bị trói buộc”. Vì sao vậy? Này Udāyi, sự sai biệt về căn tánh trong người này đã được Ta biết rõ.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Này Udāyi, có năm dục trưởng dưỡng này. Thế nào là năm? Sắc do mắt nhận thức, khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn. Tiếng do tai nhận thức, … hương do mũi nhận thức, … vị do lưỡi nhận thức, … xúc do thân cảm xúc, khả ái, khả hỷ, khả lạc, khả ý, kích thích lòng dục, hấp dẫn. Những pháp này, này Udāyi, là năm dục trưởng dưỡng. Này Udāyi, phàm có lạc gì, hỷ gì khởi lên, do duyên năm dục trưởng dưỡng này, lạc hỷ ấy được gọi là dục lạc, ô uế lạc, phàm phu lạc, phi Thánh lạc, không nên thực hiện, không nên tu tập, không nên làm cho sung mãn. Ta nói rằng lạc ấy đáng phải sợ hãi.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },

{ text: `Ở đây, này Udāyi, Tỷ-kheo ly dục, ly bất thiện pháp, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, có tầm, có tứ. Diệt tầm và tứ,...diệt hỷ ưu đã cảm thọ trước, chứng và trú Thiền thứ tư, không khổ, không lạc, xả niệm, thanh tịnh. Như vậy được gọi là yếm ly lạc, độc trú lạc, tịch tịnh lạc, chánh giác lạc, cần phải thực hiện, cần phải tu tập, cần làm cho sung mãn. Ta nói rằng lạc ấy không đáng sợ hãi.`, ref: "Trung Bộ 66 – Kinh Ví Dụ Con Chim Cáy", url: "https://loicuaducphat.org/mn/mn66.html#content" },
{ text: `Lành thay, lành thay, các Anuruddha, thật xứng đáng cho các Ông, những Thiện gia nam tử, vì lòng tin xuất gia, từ bỏ gia đình, sống không gia đình, các Ông có hoan hỷ trong Phạm hạnh. Này các Anuruddha, trong khi các Ông với tuổi trẻ tốt đẹp, trong tuổi thanh xuân, với tóc đen nhánh, có thể hưởng thụ các dục lạc, thời các Ông, này các Anuruddha, với tuổi trẻ tốt đẹp, trong tuổi thanh xuân, với tóc đen nhánh, lại xuất gia, từ bỏ gia đình, sống không gia đình. Này các Anuruddha, các Ông không vì mệnh lệnh của vua mà xuất gia, từ bỏ gia đình, sống không gia đình. Các Ông không vì mệnh lệnh của kẻ ăn trộm mà xuất gia, từ bỏ gia đình, sống không gia đình. Các Ông không vì nợ nần, không vì sợ hãi, không vì mất nghề sinh sống mà xuất gia, từ bỏ gia đình, sống không gia đình. Nhưng với tư tưởng như sau: “Ta bị sanh, già, chết, sầu, bi, khổ, não áp bức, bị khổ áp bức, bị khổ chi phối. Tuy vậy, ta mong có thể thấy được sự chấm dứt toàn bộ khổ uẩn này.”`, ref: "Trung Bộ 68 – Kinh Nalakapāna", url: "https://loicuaducphat.org/mn/mn68.html#content" },

{ text: `Và xuất gia như vậy, này các Anuruddha, người Thiện gia nam tử cần phải làm gì? Này các Anuruddha, ly dục, ly bất thiện pháp. Nếu không chứng được hỷ lạc hay một trạng thái khác an tịnh hơn, thời dục tham xâm chiếm tâm và an trú, sân xâm chiếm tâm và an trú, hôn trầm thụy miên … trạo cử, hối quá … nghi hoặc … bất lạc … giải đãi xâm chiếm tâm và an trú. Này các Anuruddha, khi chưa ly dục, chưa ly bất thiện pháp, vị ấy không chứng được hỷ lạc hay một trạng thái khác an tịnh hơn. Này các Anuruddha, ly dục, ly bất thiện pháp, vị ấy chứng được hỷ lạc hay một trạng thái khác an tịnh hơn, thời dục tham không xâm chiếm tâm và an trú, sân không xâm chiếm tâm và an trú, hôn trầm thụy miên … trạo cử hối quá … nghi hoặc … bất lạc … giải đãi không xâm chiếm tâm và an trú. Này các Anuruddha, ly dục, ly bất thiện pháp, vị ấy chứng được hỷ lạc hay một trạng thái khác an tịnh hơn.`, ref: "Trung Bộ 68 – Kinh Nalakapāna", url: "https://loicuaducphat.org/mn/mn68.html#content" },
{ text: `Này các Tỷ-kheo, Ta không nói rằng trí tuệ được hoàn thành lập tức. Nhưng này các Tỷ-kheo, trí tuệ được hoàn thành nhờ học từ từ, hành từ từ, thực tập từ từ.`, ref: "Trung Bộ 70 – Kinh Kīṭāgiri", url: "https://loicuaducphat.org/mn/mn70.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là trí tuệ được hoàn thành nhờ học từ từ, hành từ từ, thực tập từ từ? Ở đây, này các Tỷ-kheo, một vị có lòng tin đi đến gần; sau khi đến gần, vị ấy tỏ sự kính lễ; sau khi tỏ sự kính lễ, vị ấy lóng tai; sau khi lóng tai, vị ấy nghe pháp; sau khi nghe pháp, vị ấy thọ trì pháp; sau khi thọ trì, vị ấy suy tư ý nghĩa các pháp được thọ trì; sau khi suy tư ý nghĩa, các pháp được chấp thuận; sau khi các pháp được chấp thuận, ước muốn sanh khởi; sau khi ước muốn sanh khởi, vị ấy nỗ lực; sau khi nỗ lực, vị ấy cân nhắc; sau khi cân nhắc, vị ấy tinh cần. Do tinh cần, vị ấy tự thân chứng được sự thật tối thượng, và với trí tuệ thể nhập sự thật ấy, vị ấy thấy.`, ref: "Trung Bộ 70 – Kinh Kīṭāgiri", url: "https://loicuaducphat.org/mn/mn70.html#content" },

{ text: `Này các Tỷ-kheo, cho đến một bậc Ðạo sư sống quá trọng vọng tài vật, là vị thừa tự tài vật, và sống liên hệ với tài vật, thời sự mua may bán đắt này không xảy ra: “Chúng tôi sẽ làm việc này như vậy, và như vậy chúng tôi sẽ không làm việc này như vậy”, huống nữa là Như Lai, này các Tỷ-kheo, là vị sống hoàn toàn không liên hệ với các tài vật.`, ref: "Trung Bộ 70 – Kinh Kīṭāgiri", url: "https://loicuaducphat.org/mn/mn70.html#content" },

{ text: `Này các Tỷ-kheo, đến với một đệ tử, có lòng tin giáo pháp bậc Ðạo sư và sống thể nhập giáo pháp ấy, thời giáo pháp bậc Ðạo sư được hưng thịnh, được nhiều sinh lực. Này các Tỷ-kheo, đối với đệ tử có lòng tin giáo pháp bậc Ðạo Sư và sống thể nhập giáo pháp ấy, thời tùy pháp này được khởi lên: “Dầu chỉ còn da, gân và xương, dầu thịt và máu trên thân bị khô héo, mong rằng sẽ có tinh tấn lực để chứng đắc những gì chưa chứng đắc, nhờ trượng phu nhẫn nại, nhờ trượng phu tinh tấn, nhờ trượng phu cần dõng”. Này các Tỷ-kheo, đối với một đệ tử có lòng tin giáo pháp bậc Ðạo sư và sống thể nhập giáo pháp ấy, vị ấy sẽ chứng được một trong hai quả như sau: Chánh trí ngay trong hiện tại, và nếu có dư y, chứng quả Bất hoàn.`, ref: "Trung Bộ 70 – Kinh Kīṭāgiri", url: "https://loicuaducphat.org/mn/mn70.html#content" },
{ text: `Nhưng này Aggivessana, thân này có sắc, do bốn đại thành, do cha mẹ sanh, nhờ cơm cháo nuôi dưỡng, vô thường, biến hoại, phân toái, đoạn tuyệt, hoại diệt, cần phải được quán sát là vô thường, khổ, như bệnh, như cục bướu, như mũi tên, như điều bất hạnh, như bệnh chướng, như kẻ địch, như phá hoại, là không, là vô ngã. Khi vị ấy quán sát thân này là vô thường, khổ, như bệnh, như cục bướu, như mũi tên, như điều bất hạnh, như bệnh chướng, như kẻ địch, như phá hoại, là không, là vô ngã, thời thân, thân dục, thân ái, thân phục tòng được đoạn diệt.`, ref: "Trung Bộ 74 – Kinh Trường Trảo", url: "https://loicuaducphat.org/mn/mn74.html#content" },

{ text: `Này Aggivessana, lạc thọ là vô thường, hữu vi, do duyên sanh, bị đoạn diệt, bị hủy hoại, bị suy tàn, bị tiêu diệt. Này Aggivessana, khổ thọ là vô thường, hữu vi, do duyên sanh, bị đoạn diệt, bị hủy hại, bị suy tàn, bị tiêu diệt. Này Aggivessana, bất khổ bất lạc thọ là vô thường, hữu vi, do duyên sanh, bị đoạn diệt, bị hủy hoại, bị suy tàn, bị tiêu diệt.`, ref: "Trung Bộ 74 – Kinh Trường Trảo", url: "https://loicuaducphat.org/mn/mn74.html#content" },
{ text: `Ông nghĩ thế nào, ? Ở đây, này Magandiya, có người trước kia đam mê các sắc pháp do mắt nhận thức, các sắc pháp này là khả ái, khả hỷ, khả lạc, khả ý, liên hệ đến dục, hấp dẫn. Người ấy sau một thời gian, sau khi như chơn biết được sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các sắc pháp, sau khi đoạn tận sắc ái, sau khi trừ diệt nhiệt não đối với sắc pháp, người này trú với khát ái được đoạn trừ, với nội tâm an tịnh.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Rồi Ta sau một thời gian, sau khi như chơn biết được sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các dục vọng, sau khi đoạn tận dục ái, sau khi trừ diệt nhiệt não của các dục, Ta trú với khát ái được đoạn trừ, với nội tâm an tịnh. Rồi Ta thấy các chúng sanh khác, chưa xả ly tham ái đối với các dục đang bị các dục ái nhai nghiến, đang bị dục nhiệt não thiêu đốt, đang chạy theo các dục. Ta không ước vọng được như họ; ở đây, Ta không ham thích. Vì sao vậy? Vì rằng, này Magandiya, có hỷ lạc này, ly dục, ly bất thiện pháp, sau khi chứng đạt Thiên lạc, được an trú, hoan hỷ trong hỷ lạc ấy. Ta không ao ước cái gì thấp kém; ở đây, Ta không ham thích.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Cũng vậy, này Magandiya, sự xúc chạm với các dục trong thời quá khứ cũng là đau khổ, rất là nồng cháy, rất là nhiệt não, và sự xúc chạm với các dục trong thời vị lai cũng là đau khổ, rất là nồng cháy, rất là nhiệt não, và sự xúc chạm với các dục trong thời hiện lại cũng là đau khổ, rất là nồng cháy, rất là nhiệt não. Và này Magandiya, những chúng sanh này chưa đoạn trừ tham ái đối với các dục, đang bị các dục ái nhai nghiến, đang bị dục nhiệt não thiêu đốt, với các căn bị hư hoại, do sự xúc chạm đau khổ với các dục, lại có phản tưởng là được lạc thọ.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Ví như, này Magandiya, một người bị bệnh cùi thân (đầy) lở lói, thân bị hư thối nứt chảy, bị các loài trùng đục khoét, đang cào rách miệng các vết thương với móng tay, hơ đốt thân mình trên hố than hừng. Này Magandiya, người bị bệnh cùi với thân (đầy) lở lói, thân bị hư thối nứt chảy, bị các loài trùng đục khoét, càng cào rách miệng các vết thương với các móng tay, càng hơ đốt thân mình trên hố than hừng chừng nào thời miệng các vết thương ấy lại càng thêm bất tịnh, càng thêm hôi thối và càng thêm thối nát, và người ấy chỉ có cảm giác dễ chịu, thỏa thích do nhân duyên gãi ngứa miệng các vết thương; cũng vậy, này Magandiya, các chúng sanh, chưa đoạn trừ tham ái đối với các dục, đang bị các dục ái nhai nghiến, đang bị dục nhiệt não thiêu đốt, chạy theo các dục. Này Magandiya các chúng sanh, chưa đoạn trừ tham ái đối với các dục, đang bị các dục ái nhai nghiến, đang bị dục nhiệt não thiêu đốt, càng chạy theo dục chừng nào, thời dục ái các chúng sanh ấy càng tăng trưởng, càng bị dục nhiệt não thiêu đốt, và họ chỉ có cảm giác dễ chịu, thỏa thích do duyên năm dục trưởng dưỡng.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Này Magandiya, Ông nghĩ thế nào? Ông có thấy hay nghe một vị vua hay vị đại thần của vua hưởng thụ một cách đầy đủ, một cách sung mãn năm dục trưởng dưỡng, dục ái chưa được đoạn tận, dục nhiệt não chưa được trừ diệt, đã trú, đang trú hay sẽ trú với khát ái được đoạn trừ, với nội tâm an tịnh không?\n- Thưa không, Tôn giả Gotama.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `- Lành thay, này Magandiya! Này Magandiya, Ta cũng không thấy, cũng không nghe một vị vua hay vị đại thần của vua hưởng thụ một cách đầy đủ, một cách sung mãn năm dục trưởng dưỡng, dục ái chưa được đoạn tận, dục nhiệt não chưa được trừ diệt, đã trú, đang trú hay sẽ trú với khát ái được đoạn trừ, với nội tâm an tịnh. Nhưng này Magandiya, những vị Sa-môn hay Bà-la-môn nào đã sống, đang sống hay sẽ sống với khát ái được đoạn trừ, với nội tâm an tịnh, tất cả những vị này, sau khi như chơn biết sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các dục ấy, với dục ái được đoạn tận, với dục nhiệt não được trừ diệt, đã trú, đang trú hay sẽ trú với khát ái được đoạn trừ, với nội tâm được an tịnh.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Không bệnh, lợi tối thắng,\nNiết-bàn, lạc tối thắng,\nBát chánh là độc đạo,\nAn ổn và bất tử.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Cũng vậy, này Magandiya, nếu Ta thuyết pháp cho Ông: “Ðây là không bệnh, đây là Niết-bàn”, Ông có thể biết không bệnh, Ông có thể thấy Niết-bàn. Và với mắt được khởi lên cho Ông, lòng tham dục đối với năm thủ uẩn được đoạn trừ; và Ông có thể nghĩ như sau: “Thật sự trong một thời gian dài, ta bị tâm này lường gạt, lừa dối, phỉnh gạt, chấp thủ sắc, ta đã chấp thủ, chấp thủ thọ, ta đã chấp thủ, chấp thủ tưởng, ta đã chấp thủ, chấp thủ các hành, ta đã chấp thủ, chấp thủ thức, ta đã chấp thủ. Do duyên chấp thủ ấy nơi ta, nên có hữu; do duyên hữu, có sanh; do duyên sanh, có già chết, sầu, bi, khổ, ưu, não khởi lên. Như vậy là sự tập khởi của toàn bộ Khổ uẩn”.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },

{ text: `Vậy này Magandiya, hãy thân cận các vị chân nhân. Này Magandiya, do Ông thân cận các vị chân nhân, thời này Magandiya, Ông sẽ được nghe diệu pháp. Này Magandiya, do Ông được nghe diệu pháp, thời này Magandiya, Ông sẽ sống đúng với Chánh pháp và tùy pháp. Này Magandiya, do Ông sống đúng với Chánh pháp và tùy pháp, thời này Magandiya, Ông sẽ tự mình biết, tự mình thấy: “Ðây là những bệnh chướng, những cục bướu, những mũi tên. Ở đây, những bệnh chướng, những cục bướu, những mũi tên được trừ diệt, không có dư tàn. Do chấp thủ được diệt ở ta, nên hữu diệt; do hữu diệt, sanh diệt; do sanh diệt, già, chết, sầu, bi, khổ, ưu, não được diệt trừ. Như vậy là sự đoạn diệt của toàn bộ khổ uẩn này”.`, ref: "Trung Bộ 75 – Kinh Māgandiya", url: "https://loicuaducphat.org/mn/mn75.html#content" },
{ text: `Vị ấy sống biết đủ, bằng lòng với tấm y để che thân với đồ ăn khất thực để nuôi sống, đi tại chỗ nào cũng mang theo y và bình bát. Như con chim bay đến chỗ nào cũng mang theo hai cánh, cũng vậy, Tỷ-kheo bằng lòng với tấm y để che thân, với đồ ăn khất thực để nuôi bụng, đi tại chỗ nào cũng mang theo. Vị ấy thành tựu Thánh giới uẩn này, nội tâm hưởng lạc thọ không khuyết phạm.`, ref: "Trung Bộ 76 – Kinh Sandaka", url: "https://loicuaducphat.org/mn/mn76.html#content" },
{ text: `Các Tôn giả hãy nhỏ tiếng! Các Tôn giả hãy lặng tiếng! Nay đệ tử của Sa-môn Gotama, Sa-môn Ānanda đang đến. Khi nào các đệ tử của Sa-môn Gotama trú ở Kosambi, thời Sa-môn Ānanda này là một vị trong những vị ấy. Các Tôn giả ấy ưa mến trầm lặng, tu tập trong trầm lặng, tán thán trầm lặng, nếu biết chúng này trầm lặng, có thể ghé tại đây.\nRồi các du sĩ ấy đều im lặng.`, ref: "Trung Bộ 76 – Kinh Sandaka", url: "https://loicuaducphat.org/mn/mn76.html#content" },
{ text: `Bạch Thế Tôn, Thế Tôn ăn ít và tán thán hạnh ăn ít. Bạch Thế Tôn, Thế Tôn ăn ít và tán thán hạnh ăn ít. Chính pháp này, bạch Thế Tôn, là pháp thứ nhất, con thấy nơi Thế Tôn. Do pháp này các đệ tử cung kính, tôn trọng, kính lễ, cúng dường Thế Tôn, và sau khi cung kính, tôn trọng, sống nương tựa vào Thế Tôn.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },

{ text: `Lại nữa, bạch Thế Tôn, Thế Tôn biết đủ với bất cứ loại y nào và tán thán hạnh biết đủ với bất cứ loại y nào. Bạch Thế Tôn, Thế Tôn biết đủ với bất cứ loại y nào và tán thán hạnh biết đủ với bất cứ loại y nào. Chính pháp này, bạch Thế Tôn là pháp thứ hai con thấy nơi Thế Tôn. Do pháp này, các đệ tử cung kính, tôn trọng, kính lễ, cúng dường Thế Tôn, và sau khi cung kính, tôn trọng, sống nương tựa vào Thế Tôn.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },

{ text: `Lại nữa, bạch Thế Tôn, Thế Tôn biết đủ với bất cứ món ăn khất thực nào và tán thán hạnh biết đủ với bất cứ món ăn khất thực nào. Bạch Thế Tôn, Thế Tôn biết đủ với bất cứ món ăn khất thực nào và tán thán hạnh biết đủ với bất cứ món ăn khất thực nào. Chính pháp này, bạch Thế Tôn, là pháp thứ ba, con thấy nơi Thế Tôn. Do pháp này, các đệ tử cung kính, tôn trọng, kính lễ, cúng dường Thế Tôn, và sau khi cung kính, tôn trọng, sống nương tựa vào Thế Tôn.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },

{ text: `Lại nữa, bạch Thế Tôn, Thế Tôn biết đủ với bất cứ sàng tọa nào và tán thán hạnh biết đủ với bất cứ sàng tọa nào. Bạch Thế Tôn, Thế Tôn biết đủ với bất cứ sàng tọa nào và tán thán hạnh biết đủ với bất cứ sàng tọa nào. Chính pháp này, bạch Thế Tôn, là pháp thứ tư, con thấy nơi Thế Tôn. Do pháp này, các đệ tử cung kính, tôn trọng, kính lễ, cúng dường Thế Tôn, và sau khi cung kính, tôn trọng, sống nương tựa vào Thế Tôn.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },

{ text: `Lại nữa, bạch Thế Tôn, Thế Tôn sống viễn ly và tán thán hạnh sống viễn ly. Bạch Thế Tôn, Thế Tôn sống viễn ly và tán thán hạnh sống viễn ly. Chính pháp này bạch Thế Tôn, là pháp thứ năm, con thấy nơi Thế Tôn. Do pháp này, các đệ tử cung kính, tôn trọng, kính lễ, cúng dường Thế Tôn, và sau khi cung kính, tôn trọng, sống nương tựa vào Thế Tôn.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },

{ text: `Lại nữa, này Udāyi, những đệ tử của Ta bị đắm chìm trong đau khổ, bị đau khổ chi phối, đến Ta và hỏi về khổ Thánh đế. Ðược hỏi về Khổ Thánh đế, Ta trả lời cho họ. Ta làm cho tâm của họ thỏa mãn với câu trả lời của Ta. Họ hỏi Ta về Khổ tập, Khổ diệt, Khổ diệt đạo Thánh đế, Ta trả lời cho họ. Ta làm cho tâm của họ thỏa mãn với câu trả lời của Ta. Ðây là pháp thứ tư, này Udāyi, mà các đệ tử của Ta cung kính, tôn trọng, kính lễ, cúng dường Ta và sau khi cung kính, tôn trọng, sống nương tựa vào Ta.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },

{ text: `Lại nữa, này Udāyi, Ta thuyết giảng con đường tu hành cho các đệ tử. Và các đệ tử của Ta y cứ theo đường tu hành này, tu tập Bốn Niệm xứ. Ở đây, này Udāyi, vị Tỷ-kheo sống quán thân trên thân, nhiệt tâm tỉnh giác, chánh niệm để nhiếp phục tham ưu trên đời, quán thọ trên các cảm thọ … quán tâm trên các tâm … quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm để nhiếp phục tham ưu trên đời. Và ở đây, các đệ tử của Ta phần đông an trú, sau khi chứng ngộ nhờ thắng trí và chứng đắc cứu cánh viên mãn.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },

{ text: `Lại nữa, này Udāyi, Ta thuyết giảng con đường tu hành cho các đệ tử. Và các đệ tử của Ta y cứ con đường tu hành này, tu tập Bốn Chánh cần. Ở đây, này Udāyi, vị Tỷ-kheo với mục đích khiến cho các ác, bất thiện pháp từ trước chưa sanh không cho sanh khởi, khởi lên ý muốn cố gắng, tinh tấn, sách tâm, trì tâm; với mục đích khiến cho các ác, bất thiện pháp đã sanh ra được trừ diệt, khởi lên ý muốn cố gắng, tinh tấn, sách tâm, trì tâm; với mục đích khiến cho các thiện pháp từ trước chưa sanh nay cho sanh khởi, khởi lên ý muốn cố gắng, tinh tấn, sách tâm, trì tâm; với mục đích khiến cho các thiện pháp đã được sanh có thể duy trì, không có mù mờ, được tăng trưởng, được quảng đại, được tu tập, được viên mãn, khởi lên ý muốn cố gắng, tinh tấn, sách tâm, trì tâm … Và ở đây, các đệ tử của Ta phần đông an trú, sau khi chứng ngộ nhờ thắng trí và chứng đắc cứu cánh viên mãn.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },

{ text: `Này Udāyi, chính đệ tử của Ta thán phục tri kiến vi diệu và nghĩ rằng: “Khi nói: “Ta biết”, nghĩa là Sa-môn Gotama có biết: Khi nói: “Ta thấy”, nghĩa là Sa-môn Gotama có thấy. Sa-môn Gotama thuyết pháp với thắng trí, không phải không với thắng trí. Sa-môn thuyết pháp với nhân duyên, không phải không có nhân duyên. Sa-môn Gotama thuyết pháp có thần thông lực, không phải không có thần thông lực”. Ðây là pháp thứ hai, này Udāyi, các đệ tử của Ta cung kính, tôn trọng, kính lễ, cúng dường Ta và sau khi cung kính, tôn trọng, sống nương tựa vào Ta.`, ref: "Trung Bộ 77 – Ðại kinh Sakaludāyin", url: "https://loicuaducphat.org/mn/mn77.html#content" },
{ text: `Và này Thợ mộc, những bất thiện tư duy này sanh khởi như thế nào? Sự sanh khởi của chúng cũng được nói đến. Cần phải trả lời là từ tưởng sanh khởi. Thế nào là tưởng? Tưởng có nhiều loại, đa chủng, sai biệt: dục tưởng, sân tưởng, hại tưởng, từ đấy những bất thiện tư duy sanh khởi.`, ref: "Trung Bộ 78 – Ðại kinh Samanamandikà", url: "https://loicuaducphat.org/mn/mn78.html#content" },

{ text: `Và này Thợ mộc, những bất thiện tư duy này từ đâu được trừ diệt, không có dư tàn? Sự trừ diệt của chúng cũng được nói đến. Ở đây, này Thợ mộc, vị Tỷ-kheo ly dục, ly bất thiện pháp chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm, với tứ. Ở đây, những bất thiện tư duy được trừ diệt, không có dư tàn.`, ref: "Trung Bộ 78 – Ðại kinh Samanamandikà", url: "https://loicuaducphat.org/mn/mn78.html#content" },

{ text: `Và sự thực hành như thế nào, này Thợ mộc, là sự thực hành đưa đến diệt trừ các bất thiện tư duy? Ở đây, vị Tỷ-kheo khởi lên ý muốn nỗ lực, tinh tấn, quyết tâm, sách tấn tâm khiến cho các ác, bất thiện pháp chưa sanh không được sanh khởi … khiến cho các ác, bất thiện pháp đã sanh được trừ diệt; khiến cho các thiện pháp chưa sanh nay được sanh khởi; khởi lên ý muốn nỗ lực, tinh tấn, quyết tâm, sách tấn tâm; khiến cho các thiện pháp đã sanh có thể duy trì, không có mơ hồ, được tăng trưởng, được quảng đại, được tu tập, được viên mãn. Sự thực hành như vậy là sự thực hành đưa đến diệt trừ các bất thiện tư duy.`, ref: "Trung Bộ 78 – Ðại kinh Samanamandikà", url: "https://loicuaducphat.org/mn/mn78.html#content" },

{ text: `Này Thợ mộc, thế nào là thiện tư duy? Ly dục tư duy, vô sân tư duy, bất hại tư duy; những pháp này, này Thợ mộc, được gọi là thiện tư duy.`, ref: "Trung Bộ 78 – Ðại kinh Samanamandikà", url: "https://loicuaducphat.org/mn/mn78.html#content" },
{ text: `- Bạch Thế Tôn, như con được hiểu lời Thế Tôn thuyết pháp, thời sống tại gia đình thật không dễ gì thực hành Phạm hạnh, hoàn toàn viên mãn, hoàn toàn trong sạch, trắng bạch như vỏ ốc. Con muốn, bạch Thế Tôn, cạo bỏ râu tóc, đắp áo cà-sa, xuất gia, từ bỏ gia đình, sống không gia đình. Bạch Thế Tôn, mong Thế Tôn cho con xuất gia dưới sự chỉ dẫn của Thế Tôn, cho con thọ đại giới.\n- Nhưng này Raṭṭḥapāla, Ông có được cha mẹ bằng lòng cho Ông xuất gia chưa?\n- Bạch Thế Tôn, con chưa được cha mẹ bằng lòng cho con xuất gia.\n- Này Raṭṭḥapāla, Như Lai không có cho ai xuất gia nếu không được cha mẹ người ấy bằng lòng.\n- Như vậy, bạch Thế Tôn, con sẽ làm những gì cần thiết để cha mẹ bằng lòng cho con được xuất gia, từ bỏ gia đình, sống không gia đình.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Rồi thiện nam tử Raṭṭḥapāla không được cha mẹ cho xuất gia, liền ngay tại chỗ ấy nằm xuống trên đất trần và nói:\n- Ta sẽ chết ở đây, hay được xuất gia.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Rồi các thân hữu của thiện nam tử Raṭṭḥapāla đi đến cha mẹ thiện nam tử Raṭṭḥapāla, sau khi đến liền thưa:\n- Thưa Mẹ và Cha, thiện nam tử Raṭṭḥapāla đang nằm xuống trên đất trần kia và nói: “Ở đây, ta sẽ chết, hay được xuất gia”. Nếu Cha Mẹ không bằng lòng cho thiện nam tử Raṭṭḥapāla xuất gia, từ bỏ gia đình, sống không gia đình, thời Raṭṭḥapāla sẽ chết ở tại chỗ ấy. Còn nếu Cha Mẹ bằng lòng cho thiện nam tử Raṭṭḥapāla xuất gia, từ bỏ gia đình, sống không gia đình, thời Cha Mẹ có thể thấy Raṭṭḥapāla sau khi xuất gia. Nếu thiện nam tử Raṭṭḥapāla không cảm thấy hoan hỷ trong khi xuất gia, từ bỏ gia đình, sống không gia đình, thời Raṭṭḥapāla không còn con đường nào đi khác hơn. Raṭṭḥapāla sẽ trở lại ở đây. Hãy bằng lòng cho phép thiện nam tử Raṭṭḥapāla xuất gia, từ bỏ gia đình, sống không gia đình.\n- Này các con thân mến, chúng ta bằng lòng cho phép thiện nam tử Raṭṭḥapāla xuất gia, từ bỏ gia đình, sống không gia đình, nhưng sau khi xuất gia, cần phải về thăm cha mẹ.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Rồi Tôn giả Raṭṭḥapāla vào buổi sáng đắp y, cầm bát đi đến ngồi nhà của người cha mình, sau khi đến ngồi xuống trên chỗ đã soạn sẵn. Rồi người cha của Tôn giả Raṭṭḥapāla cho trình bày ra đống vàng nén và tiền vàng và nói với Tôn giả Raṭṭḥapāla\n- Này con thân yêu Raṭṭḥapāla, đây là tiền tài của mẹ, kia là tiền tài của cha, kia là tiền tài của tổ tiên. Này con thân yêu Raṭṭḥapāla, con có thể thụ hưởng tài vật và làm các phước đức. Này con thân yêu Raṭṭḥapāla, hãy từ bỏ tu học, hoàn tục thụ hưởng các tài vật và làm các phước đức.\n- Thưa gia chủ, nếu gia chủ làm theo lời nói của tôi, sau khi chồng chất đống vàng nén và tiền vàng này vào trong các xe, sau khi cho chở và hạ xuống giữa sông Hằng, hãy đổ đống vàng này vào giữa dòng sông. Vì sao vậy? Này gia chủ, vì do nhân duyên này, mà sầu, bi, khổ, ưu, não sẽ khởi lên cho gia chủ.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Rồi những người vợ cũ của Tôn giả Raṭṭḥapāla ôm mỗi chân (Tôn giả) và nói:\n- Thưa phu quân, vì thiên nữ nào mà phu quân sống phạm hạnh?\n- Các bà chị, không phải vì thiên nữ nào mà chúng tôi sống phạm hạnh.\n- Phu quân Raṭṭḥapāla đối với chúng ta gọi chúng ta là bà chị.\nNói lên như vậy, (các người vợ cũ) liền ngã xuống đất, bất tỉnh.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Hãy nhìn hình bóng trang sức này,\nMột nhóm vết thương được tích tụ,\nBệnh nhiều, tham tưởng cũng khá nhiều,\nNhưng không gì kiên cố, thường trú.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Hãy nhìn dung mạo trang sức này,\nVới các châu báu, với vòng tai,\nMột bộ xương được da bao phủ,\nÐược y phục làm cho sáng chói.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Chân được sơn với son với sáp,\nMặt được thoa với phấn, với bột,\nVừa đủ làm mê hoặc kẻ ngu,\nNhưng vô phương kẻ cầu bờ giác.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Tóc được uốn bảy vòng, bảy lớp,\nMắt được xoa với thuốc, với son,\nVừa đủ làm mê hoặc kẻ ngu,\nNhưng vô phương kẻ cầu bờ giác.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Như hộp thuốc trang hoàng mới mẻ,\nLà uế thân được điểm thời trang,\nVừa đủ làm mê hoặc kẻ ngu,\nNhưng vô phương kẻ cầu bờ giác.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Người thợ săn đặt bày lưới sập,\nLoài nai khôn chẳng chạm bén chân,\nĂn lúa xong, chúng ta lên đường,\nMặc cho kẻ bắt nai than khóc.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `“Thế giới là vô thường, đi đến hủy diệt”, thưa Ðại vương, đó là thuyết giáo Chánh pháp thứ nhất, do Thế Tôn, bậc Tri Giả, Kiến Giả, bậc A-la-hán, Chánh Ðẳng Giác, thuyết giảng. Do tôi biết, tôi thấy và tôi nghe thuyết giáo ấy, mà tôi xuất gia, từ bỏ gia đình, sống không gia đình.\n“Thế giới là vô hộ, vô chủ”, thưa Ðại vương, đó là thuyết giáo Chánh pháp thứ hai, do Thế Tôn, bậc Tri Giả. Kiến Giả, bậc A-la-hán, Chánh Ðẳng Giác thuyết giảng. Do tôi biết, tôi thấy và tôi nghe thuyết giáo ấy, mà tôi xuất gia, từ bỏ gia đình, sống không gia đình.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `“Thế giới là vô sở hữu, ra đi cần phải từ bỏ tất cả”, thưa Ðại vương đó là thuyết giáo Chánh pháp thứ ba, do Thế Tôn, bậc Tri Giả, Kiến Giả, bậc A-la-hán, Chánh Ðẳng Giác thuyết giảng. Do tôi biết, tôi thấy, tôi nghe thuyết giáo ấy, mà tôi xuất gia, từ bỏ gia đình, sống không gia đình.\n“Thế giới là thiếu thốn, khao khát, nô lệ cho tham ái”, thưa Ðại vương, đó là thuyết giáo Chánh pháp thứ tư, do Thế Tôn, bậc Tri Giả, Kiến Giả, bậc A-la-hán, Chánh Ðẳng Giác thuyết giảng. Do tôi biết, tôi thấy, tôi nghe thuyết giáo ấy, mà tôi xuất gia, từ bỏ gia đình, sống không gia đình.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `- Thưa Ðại vương, Ðại vương nghĩ thế nào? Ðại vương có thể nói chăng, với các thân hữu quen biết, bà con huyết thống của Ðại vương: “Mong rằng Tôn giả thân hữu quen biết, bà con huyết thống làm vơi nhẹ sự đau khổ của tôi! Mong tất cả hãy san sẻ cảm thọ này, để tôi có thể có một cảm thọ nhẹ nhàng hơn”; hay là Ðại vương chỉ có thể thọ lãnh cảm thọ ấy một mình?\n- Thưa Tôn giả Raṭṭḥapāla, tôi không có thể nói với các thân hữu quen biết, bà con huyết thống của tôi: “Mong rằng các Tôn giả thân hữu quen biết, bà con huyết thống làm vơi nhẹ sự đau khổ của tôi. Mong tất cả hãy san sẻ cảm thọ này để có thể có một cảm thọ nhẹ nhàng hơn”; và tôi chỉ có thể thọ lãnh cảm thọ ấy một mình”.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `- Thưa Ðại vương, Ðại vương nghĩ thế nào? Dầu cho nay Ðại vương sống thụ hưởng mãn túc, cụ túc năm món dục trưởng dưỡng, Ðại vương có thể nói được như sau: “Chính như vậy, tôi thọ hưởng mãn túc, cụ túc năm món dục trưởng dưỡng này”; hay là người khác sẽ thọ hưởng tài sản này, còn Ðại vương sẽ phải đi theo nghiệp của mình?\n- Thưa Tôn giả Raṭṭḥapāla, dầu cho nay tôi sống thụ hưởng mãn túc, cụ túc năm món dục trưởng dưỡng. Tôi không có thể nói được như sau: “Chính như vậy tôi thọ hưởng mãn túc, cụ túc năm món dục trưởng này”. Chính người khác sẽ thọ hưởng tài sản này, còn tôi phải đi theo nghiệp của tôi.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Ta thấy người giàu sang ở đời,\nCó của vì si không bố thí.\nVì tham, họ tích tụ tài vật,\nVà chạy theo dục vọng càng nhiều.\nDùng bạo lực, chinh phục quả đất,\nVua trị vì cho đến hải biên,\nKhông thỏa mãn bờ biển bên này,\nVà chạy theo bờ biển bên kia.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Vua cùng rất nhiều loại người khác,\nÁi chưa ly, mạng chung đã đến,\nBị thiếu thốn, không bỏ thân họ,\nKhông thỏa mãn lòng dục ở đời.\nQuyến thuộc tán loạn, khóc người ấy:\n“Than ôi, người ấy không bất tử! ”.\nMạng thân người ấy vải bao phủ,\nHọ đốt lửa làm lễ hỏa thiêu.\nBị thọc với cây, người ấy cháy,\nÐộc mảnh vải, bỏ tiền của lại.\nỞ đây, quyến thuộc cùng thân hữu,\nKhông nơi nương tựa cho kẻ chết.\nKẻ thừa tự, nhận mang tài sản,\nRiêng con người, theo nghiệp phải đi,\nTiền của đâu có theo người chết,\nCả vợ con, tài sản, quốc độ.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Tài sản không mua được trường thọ,\nPhú quý không tránh được già suy,\nKẻ trí nói đời này thật ngắn,\nThật vô thường, biến đổi luôn luôn.\nKẻ giàu, kẻ nghèo đều cảm xúc,\nNgười ngu, kẻ trí đồng cảm thọ,\nKẻ ngu bị ngu đánh nằm ngã,\nBậc trí cảm xúc, không run sợ.\nDo vậy, trí tuệ thắng tài vật,\nNhờ trí, ở đây được viên thành.\nKhông thành mãn trong hữu, phi hữu,\nKẻ ngu tạo tác các ác nghiệp.\nNhập thai thác sanh thế giới khác,\nNgười ấy luân hồi, tiếp tục sanh,\nKẻ thiểu trí chắc hẳn phải là\nNhập thai và sanh thế giới khác.\nNhư kẻ trộm bị bắt khi trộm,\nÁc tánh hại mình do tự nghiệp,\nChúng sanh cũng vậy chết đời khác,\nÁc tánh hại mình, do tự lực.`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },

{ text: `Dục vọng nhiều loại, ngọt, khả ái,\nNhiễu loạn tâm dưới nhiều hình thức,\nThấy hoạn nạn trong dục trưởng dưỡng,\nNên tôi xuất gia, tâu Ðại vương!\nNhư quả từ đây, người bị rụng,\nCả già lẫn trẻ, khi thân hoại,\nDo thấy chính vậy, tôi xuất gia,\nHạnh Sa-môn phải là tối thắng,\nThưa Ðại vương!`, ref: "Trung Bộ 82 – Kinh Raṭṭḥapāla", url: "https://loicuaducphat.org/mn/mn82.html#content" },
{ text: `Ai trước phóng dật, sau không phóng dật,\nSáng chói đời này, như trăng thoát mây,\nAi làm ác nghiệp, nhờ thiện chặn lại,\nSáng chói đời này, như trăng thoát mây.`, ref: "Trung Bộ 86 – Kinh Aṅgulimāla", url: "https://loicuaducphat.org/mn/mn86.html#content" },

{ text: `Thời thời nghe pháp, y pháp hành trì.\nMột kẻ như vậy, không có hại ta,\nCũng không làm hại một người nào khác.\nVị ấy sẽ chứng tối thượng tịch tịnh.`, ref: "Trung Bộ 86 – Kinh Aṅgulimāla", url: "https://loicuaducphat.org/mn/mn86.html#content" },

{ text: `Hộ trì mọi người, kẻ mạnh người yếu,\nNhư người dẫn nước, hướng dẫn nước chảy,\nNhư kẻ làm tên uốn cong thân tên,\nNhư người thợ mộc uốn nắn cây gỗ.\nKẻ trí tự mình, tự điều phục mình,\nCó kẻ được điều bởi gậy, roi, móc,\nRiêng Ta được điều không gậy, không kiếm.\n(Bởi bậc như vậy).`, ref: "Trung Bộ 86 – Kinh Aṅgulimāla", url: "https://loicuaducphat.org/mn/mn86.html#content" },

{ text: `Kẻ ngu vô trí, đam mê phóng dật,\nCòn người có trí, giữ không phóng dật,\nNhư giữ tài sản, tối thượng, tối quý,\nChớ mê phóng dật, chớ mê dục lạc.`, ref: "Trung Bộ 86 – Kinh Aṅgulimāla", url: "https://loicuaducphat.org/mn/mn86.html#content" },

{ text: `Giữ không phóng dật, luôn luôn Thiền định,\nChứng đắc đại lạc, quảng đại vô lượng,\nThiện lai, ta đến, không đi lạc hướng,\nKhông ai khuyên ta theo tư tưởng ác.\nGiữa các chân lý được khéo giảng dạy,\nChân lý ta theo, chân lý tối thượng,\nThiện lai ta đến, không đi lạc hướng,\nKhông ai khuyên ta theo tư tưởng ác,\nBa minh ta chứng, Phật lý viên thành.`, ref: "Trung Bộ 86 – Kinh Aṅgulimāla", url: "https://loicuaducphat.org/mn/mn86.html#content" },
{ text: `- Này Gia chủ, có phải các căn của Ông đổi khác?\n- Bạch Thế Tôn, sao các căn của con có thể không đổi khác được? Bạch Thế Tôn, đứa con một khả ái, đáng thương của con đã mệnh chung. Sau khi nó chết, con không còn muốn làm việc, con không còn muốn ăn uống, con luôn luôn đi đến nghĩa địa và than khóc: “Con ở đâu, đứa con một của ta? Con ở đâu, đứa con một của ta?”\n- Sự thật là như vậy, này Gia chủ, vì rằng, này Gia chủ, sầu, bi, khổ, ưu, não do ái sanh ra, hiện hữu từ nơi ái.`, ref: "Trung Bộ 87 – Kinh Ái Sanh", url: "https://loicuaducphat.org/mn/mn87.html#content" },
{ text: `Này Bà-la-môn, đây là một pháp môn, do pháp môn này cần phải được hiểu là sầu, bi, khổ, não do ái sanh ra, hiện hữu từ nơi ái. Này Bà-la-môn, thuở xưa, ở tại Sāvatthi này, người mẹ của một người đàn ông mệnh chung. Từ khi bà ta mệnh chung, người đàn ông này phát điên cuồng, tâm tư hỗn loạn, đi từ đường này qua đường khác, đi từ ngã tư đường này qua ngã tư đường khác và nói: “Người có thấy mẹ tôi đâu không? Người có thấy mẹ tôi đâu không?”`, ref: "Trung Bộ 87 – Kinh Ái Sanh", url: "https://loicuaducphat.org/mn/mn87.html#content" },

{ text: `Này Bà-la-môn, đây là một pháp môn, do pháp môn này cần phải được hiểu là sầu, bi, khổ, ưu, não do ái sanh ra, hiện hữu từ nơi ái. Này Bà-la-môn, thuở xưa chính tại thành Sāvatthi này, một người đàn bà đi về thăm gia đình bà con. Những người bà con ấy của người đàn bà muốn dùng sức mạnh bắt người đàn bà ấy phải xa chồng và muốn gả cho một người đàn ông khác. Người đàn bà ấy không chịu. Rồi người đàn bà ấy nói với chồng mình: “Này Hiền phu, những người bà con này muốn dùng sức mạnh bắt tôi phải xa anh và muốn gả cho một người đàn ông khác. Nhưng tôi không muốn như vậy”. Rồi người ấy chặt người đàn bà ấy làm hai, rồi tự vận, nghĩ rằng: “Hai chúng ta sẽ gặp nhau trong đời sau”. Này Bà-la-môn, do pháp môn này cần phải được hiểu rằng sầu, bi, khổ, ưu, não do ái sanh ra, hiện hữu từ nơi ái.`, ref: "Trung Bộ 87 – Kinh Ái Sanh", url: "https://loicuaducphat.org/mn/mn87.html#content" },
{ text: `Rồi trong khi tản bộ thưởng ngoạn, vua Pasenadi nước Kosala thấy những gốc cây khả ái, đẹp mắt, lặng tiếng, ít ồn, vắng người, thoáng gió, xa lánh mọi tụ hội đông đảo, thích hợp với trầm tư mặc tưởng. Thấy vậy, vua liền nghĩ đến Thế Tôn: “Những gốc cây khả ái, đẹp mắt, lặng tiếng, ít ồn, vắng người, thoáng gió, xa lánh mọi tụ hội đông đảo, thích hợp với trầm tư mặc tưởng này, chính tại đây, chúng ta đảnh lễ Thế Tôn, bậc A-la-hán, Chánh Ðẳng Giác”.`, ref: "Trung Bộ 89 – Kinh Pháp Trang Nghiêm", url: "https://loicuaducphat.org/mn/mn89.html#content" },

{ text: `Ở đây, Bạch Thế Tôn, con thấy các Tỷ-kheo sống hành trì Phạm hạnh viên mãn, thanh tịnh cho đến trọn đời, cho đến hơi thở cuối cùng. Bạch Thế Tôn, con không thấy ngoài đây ra có một Phạm hạnh nào khác viên mãn, thanh tịnh như vậy. Bạch Thế Tôn, đây là pháp truyền thống của con đối với Thế Tôn. “Thế Tôn là bậc Chánh Ðẳng Giác. Pháp được Thế Tôn khéo giảng, chư Tăng đệ tử của Thế Tôn khéo tu tập, hành trì”.`, ref: "Trung Bộ 89 – Kinh Pháp Trang Nghiêm", url: "https://loicuaducphat.org/mn/mn89.html#content" },

{ text: `Lại nữa bạch Thế Tôn, vua chúa cãi lộn với vua chúa, Sát-đế-lị cãi lộn với Sát-đế-lị, Bà-la-môn cãi lộn với Bà-la-môn, gia chủ cãi lộn với gia chủ, mẹ cãi lộn với con, con cãi lộn với mẹ, cha cãi lộn với con, con cãi lộn với cha, anh em cãi lộn với anh em, anh em cãi lộn với chị em, chị em cãi lộn với anh em, bạn bè cãi lộn với bạn bè. Còn ở đây, bạch Thế Tôn, con thấy các Tỷ-kheo sống với nhau thuận hòa, thân hữu, không cãi lộn nhau, hòa hợp như nước với sữa, nhìn nhau với cặp mắt ái kính. Bạch Thế Tôn, con không thấy ngoài đây ra, có một Phạm hạnh nào khác viên mãn, thanh tịnh như vậy. Bạch Thế Tôn, đây là pháp truyền thống của con đối với Thế Tôn: “Thế Tôn là bậc Chánh Ðẳng Giác, Pháp được Thế Tôn khéo giảng, đệ tử chúng Tăng của Thế Tôn khéo tu tập, hành trì”.`, ref: "Trung Bộ 89 – Kinh Pháp Trang Nghiêm", url: "https://loicuaducphat.org/mn/mn89.html#content" },

{ text: `Còn ở đây, bạch Thế Tôn, con thấy các Tỷ-kheo hân hoan, phấn khởi, hỷ lạc, các căn thoải mái, không dao động, bình tĩnh, sống dựa vào sự hỷ cúng của người khác, với tâm tư như con thú rừng. Bạch Thế Tôn, con suy nghĩ như sau: “Thật sự các bậc Tôn giả này ý thức được một sự tối thắng thù diệu nào trong giáo lý Thế Tôn, một sự thành đạt tuần tự nên các bậc Tôn giả này hân hoan, phấn khởi, hỷ lạc, các căn thoải mái, không dao động, bình tĩnh, sống dựa vào sự hỷ cúng của người khác, với tâm tư như con thú rừng. Bạch Thế Tôn, đây là pháp truyền thống của con đối với Thế Tôn: “Thế Tôn là bậc Chánh Ðẳng Giác, Pháp được Thế Tôn khéo giảng, đệ tử chúng Tăng của Thế Tôn khéo tu tập hành trì”.`, ref: "Trung Bộ 89 – Kinh Pháp Trang Nghiêm", url: "https://loicuaducphat.org/mn/mn89.html#content" },

{ text: `Ở đây, bạch Thế Tôn, con thấy các Tỷ-kheo, trong khi Thế Tôn thuyết pháp cho đồ chúng hàng trăm người, trong khi ấy không có một tiếng nhảy mũi hay tiếng ho khởi lên. Bạch Thế Tôn, thuở xưa, trong khi Thế Tôn thuyết pháp cho đồ chúng hàng trăm người, có người đệ tử Thế Tôn ho lên. Một đồng Phạm hạnh khẽ đập vào đầu gối và nói: “Tôn giả hãy im lặng, Tôn giả chớ có làm ồn. Thế Tôn, bậc Ðạo Sư của chúng ta đang thuyết pháp”. Bạch Thế Tôn, con khởi lên ý nghĩ như sau: “Thật vi diệu thay! Thật hy hữu thay! Thính chúng này thật khéo được huấn luyện, không gậy, không kiếm. Bạch Thế Tôn, con không thấy ngoài đồ chúng này có một đồ chúng nào khác được khéo huấn luyện như đồ chúng này.”`, ref: "Trung Bộ 89 – Kinh Pháp Trang Nghiêm", url: "https://loicuaducphat.org/mn/mn89.html#content" },
{ text: `- Này Dhananjani, Ông nghĩ thế nào? Ở đây, có người vì vợ con làm các điều phi pháp, làm các điều bất chánh. Do nhân duyên làm các điều phi pháp, làm các điều bất chánh, các địa ngục quân kéo người ấy đến địa ngục. Người ấy làm được gì khi nói: “Tôi vì vợ con đã làm các điều phi pháp, đã làm điều bất chánh. Chớ có để các địa ngục quân kéo tôi đến địa ngục”? Hay vợ con người ấy có làm được gì khi nói: “Chồng, cha tôi vì chúng tôi đã làm các điều phi pháp, đã làm các điều bất chánh. Chớ có để các địa ngục quân kéo chồng, cha tôi đến địa ngục”?\n- Thưa không được, Tôn giả Sāriputta. Các địa ngục quân vẫn quăng người ấy xuống địa ngục, dầu người ấy có khóc than.`, ref: "Trung Bộ 97 – Kinh Dhànanjàni", url: "https://loicuaducphat.org/mn/mn97.html#content" },
{ text: `Này các Tỷ-kheo, các dục là vô thường, trống rỗng, giả dối, thuộc ngu si tánh. Này các Tỷ-kheo, đây là lời chào xáo của kẻ ngu xây dựng trên giả dối. Các dục hiện tại, và các dục tương lai, các dục tưởng hiện tại và các dục tưởng tương lai, cả hai đều thuộc lãnh vực của ma, là cảnh giới của ma, là chỗ dinh dưỡng của ma, là chỗ ăn uống của ma.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `Ở đây, các ác bất thiện ý này dẫn đến tham dục, sân hận, khích động, và chính những pháp ấy tác thành chướng ngại ở đây cho Thánh đệ tử học tập. Ở đây, này các Tỷ-kheo, vị Thánh đệ tử suy nghĩ như sau: “Các dục hiện tại, và các dục tương lai, các dục tưởng hiện tại và các dục tưởng tương lai, cả hai đều thuộc lãnh vực của ma, là cảnh giới của ma, là chỗ dinh dưỡng của ma, là chỗ ăn uống của ma. Vậy ta hãy an trú với tâm quảng đại, đại hành, sau khi chiến thắng thế giới, sau khi xác định vị trí của ý. Khi ta an trú với tâm quảng đại, đại hành chiến thắng thế giới, xác định vị trí của ý, các ác bất thiện ý: tham dục, sân hận, khích động sẽ không khởi lên; với các pháp ấy được đoạn trừ, tâm của ta không trở thành hạn hẹp, trái lại thành vô lượng, khéo tu tập”.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `Lại nữa này các Tỷ-kheo, vị Thánh đệ tử suy nghĩ như sau: “Những dục hiện tại và những dục tương lai, những dục tưởng hiện tại, và những dục tưởng tương lai, phàm bất cứ sắc pháp gì, là bốn đại chủng và sắc do bốn đại tạo thành”. Trong khi vị ấy hành trì như vậy, an trú nhiều lần như vậy, tâm trở thành an tịnh trong giới xứ (của nó). Với tâm an tịnh, vị ấy thành tựu Bất động ngay trong hiện tại hay thiên nặng về trí tuệ. Sau khi thân hoại mạng chung, sự tình này xảy ra, thức diễn tiến ấy có thể tùy theo đây đạt đến Bất động.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `Lại nữa này các Tỷ-kheo, vị Thánh đệ tử suy nghĩ như sau: “Những dục hiện tại và những dục tương lai, những dục tưởng hiện tại và những dục tưởng tương lai, những sắc pháp hiện tại và những sắc pháp tương lai, những sắc tưởng hiện tại và những sắc tưởng tương lai, cả hai đều vô thường. Cái gì vô thường thời không đáng để được hoan hỷ, không đáng để được hoan nghênh, không đáng để được chấp trước”. Trong khi vị ấy hành trì như vậy, an trú nhiều lần như vậy, tâm trí trở thành an tịnh trong giới xứ (của nó). Với tâm an tịnh, vị ấy thành tựu Bất động ngay trong hiện tại hay thiên nặng về trí tuệ. Sau khi thân hoại mạng chung, sự tình này xảy ra, thức diễn tiến ấy có thể tùy theo đây đạt đến Bất động.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `Ở đây, này Ānanda, một Tỷ-kheo hành trì như vậy và suy nghĩ: “Nếu trước không có như vậy thời có thể không là của ta. Nếu nay không có như vậy, thời có thể sẽ không là của ta. Ta đoạn trừ những gì hiện có và những gì đã có”. Và như vậy vị ấy được xả. Vị ấy hoan hỷ trong xả ấy, hoan nghênh, chấp trước xả ấy. Do vị ấy hoan hỷ trong xả ấy, hoan nghênh, chấp trước xả ấy, thức lệ thuộc xả ấy và thủ trước xả ấy. Có thủ trước, này Ānanda, vị Tỷ-kheo không chứng cứu cánh Niết-bàn.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },

{ text: `Những gì, này Ānanda, vị Ðạo sư cần phải làm, vì lòng từ mẫn mưu tìm hạnh phúc cho các đệ tử, những điều ấy đã được Ta làm, vì lòng từ mẫn của Ta đối với Ông. Này Ānanda, đây là những gốc cây, đây là những khoảng trống. Hãy tu Thiền, này Ānanda, chớ có phóng dật, chớ có hối hận về sau. Ðây là lời dạy của Ta cho Ông.`, ref: "Trung Bộ 106 – Kinh Bất Động Lợi Ích", url: "https://loicuaducphat.org/mn/mn106.html#content" },
{ text: `Có thể trình bày, này Bà-la-môn, trong Pháp và Luật này, có một tuần tự học tập, có một tuần tự công trình, có một tuần tự đạo lộ. Ví như, này Bà-la-môn, một người huấn luyện ngựa thiện xảo, sau khi được một con ngựa hiền thiện, trước tiên luyện tập cho nó quen mang dây cương, rồi tập luyện cho nó quen các hạnh khác; cũng vậy, này Bà-la-môn, Như Lai khi được một người đáng được điều phục, trước tiên huấn luyện người ấy như sau: “Hãy đến Tỷ-kheo, hãy giữ giới hạnh, hãy sống chế ngự với sự chế ngự của giới bổn, đầy đủ oai nghi chánh hạnh, thấy sự nguy hiểm trong những lỗi nhỏ nhặt, thọ trì và học tập các học giới”.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Này Bà-la-môn, khi vị Tỷ-kheo giữ giới hạnh, chế ngự với sự chế ngự của giới bổn, đầy đủ oai nghi chánh hạnh, thấy sự nguy hiểm trong những lỗi nhỏ nhặt, thọ trì và học tập các học giới, Như Lai mới huấn luyện vị ấy thêm như sau: “Hãy đến Tỷ-kheo, hãy hộ trì các căn, khi mắt thấy sắc chớ có nắm giữ tướng chung, chớ có nắm giữ tướng riêng. Những nguyên nhân gì, vì nhãn căn không được chế ngự khiến tham ái, ưu bi, các ác bất thiện pháp khởi lên, vị Tỷ-kheo tự chế ngự nguyên nhân ấy, hộ trì con mắt, thực hành sự hộ trì con mắt. Khi tai nghe tiếng … mũi ngửi hương … lưỡi nếm vị. Thân cảm xúc … ý nhận thức các pháp, vị ấy không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, vì ý căn không được chế ngự, khiến tham ái, ưu bi, các pháp ác bất thiện khởi lên, Tỷ-kheo chế ngự nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn”.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Này Bà-la-môn, sau khi Tỷ-kheo hộ trì các căn rồi, Như Lai mới huấn luyện vị ấy thêm như sau: “Hãy đến Tỷ-kheo, hãy tiết độ trong ăn uống, chơn chánh giác sát thọ dụng món ăn, không phải để vui đùa, không phải để đam mê, không phải để trang sức, không phải để tự làm đẹp mình, chỉ để thân này được duy trì, được bảo dưỡng, khỏi bị gia hại, để chấp trì Phạm hạnh, nghĩ rằng: “Như vậy ta diệt trừ các cảm thọ cũ và không cho khởi lên các cảm thọ mới; và ta sẽ không phạm lỗi lầm, sống được an ổn”.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Này Bà-la-môn, sau khi Tỷ-kheo tiết độ trong ăn uống rồi, Như Lai mới huấn luyện vị ấy thêm như sau: “Hãy đến Tỷ-kheo, hãy chú tâm cảnh giác! Ban ngày trong khi đi kinh hành và trong khi đang ngồi, gột sạch tâm trí khỏi các chướng ngại pháp; ban đêm trong canh đầu, trong khi đi kinh hành và trong khi đang ngồi, gột sạch tâm trí khỏi các chướng ngại pháp; ban đêm trong canh giữa, hãy nằm xuống phía hông bên phải, như dáng nằm con sư tử, chân gác trên chân với nhau, chánh niệm tỉnh giác, hướng niệm đến lúc ngồi dậy lại. Ban đêm trong canh cuối, khi đã thức dậy, trong khi đi kinh hành và trong khi đang ngồi, gột sạch tâm trí khỏi các chướng ngại pháp”.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Này, Bà-la-môn, sau khi vị Tỷ-kheo chú tâm tỉnh giác, Như Lai mới huấn luyện vị ấy thêm nữa như sau: “Hãy đến Tỷ-kheo, hãy thành tựu chánh niệm tỉnh giác, khi đi tới khi đi lui đều tỉnh giác; khi nhìn thẳng, khi nhìn quanh đều tỉnh giác; khi co tay, khi duỗi tay đều tỉnh giác; khi mang y kép, bình bát, thượng y đều tỉnh giác; khi ăn, uống, nhai, nuốt, đều tỉnh giác; khi đi đại tiện, tiểu tiện đều tỉnh giác; khi đi, đứng, ngồi, nằm, thức, nói, yên lặng đều tỉnh giác”.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Này Bà-la-môn, sau khi chánh niệm tỉnh giác rồi, Như Lai mới huấn luyện vị ấy thêm như sau: “Hãy đến Tỷ-kheo, hãy lựa một chỗ thanh vắng, tịch mịch như rừng, gốc cây, khe núi, hang đá, bãi tha ma, lùm cây, ngoài trời, đống rơm”.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Vị ấy lựa một chỗ thanh vắng, tịch mịch, như rừng, gốc cây, khe núi, hang đá, bãi tha ma, lùm cây, ngoài trời, đống rơm. Sau khi đi khất thực về và ăn xong, vị ấy ngồi kiết-già, lưng thẳng tại chỗ nói trên và an trú chánh niệm trước mặt. Vị ấy từ bỏ tham ái ở đời, sống với tâm thoát ly tham ái, gột rửa tâm hết tham ái. Từ bỏ sân hận, vị ấy sống với tâm không sân hận, lòng từ mẫn thương xót tất cả chúng hữu tình, gột rửa tâm hết sân hận. Từ bỏ hôn trầm thụy miên, vị ấy sống thoát ly hôn trầm thụy miên, với tâm tưởng hướng về ánh sáng, chánh niệm tỉnh giác, gột rửa tâm hết hôn trầm thụy miên; từ bỏ trạo cử hối tiếc, vị ấy sống không trạo cử, nội tâm trầm lặng, gột rửa tâm hết trạo cử hối tiếc; từ bỏ nghi ngờ, vị ấy sống thoát khỏi nghi ngờ, không phân vân lưỡng lự, gột rửa tâm hết nghi ngờ đối với các thiện pháp.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Khi đoạn trừ năm triền cái ấy, những pháp làm ô nhiễm tâm, làm trí tuệ yếu ớt, vị ấy ly dục, ly bất thiện pháp chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm với tứ. Vị ấy diệt tầm và tứ, chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm không tứ, nội tĩnh nhất tâm. Vị ấy ly hỷ trú xả, chánh niệm tỉnh giác, thân cảm sự lạc thọ mà các bậc Thánh gọi là xả niệm lạc trú, chứng và trú Thiền thứ ba. Xả lạc, xả khổ, diệt hỷ ưu đã cảm thọ trước, chứng và trú Thiền thứ tư, không khổ, không lạc, xả niệm thanh tịnh.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Này Bà-la-môn, do nhân gì, do duyên gì, trong khi có mặt Rājagaha, trong khi có mặt con đường đưa đến Rājagaha, trong khi có mặt Ông là người chỉ đường, dầu cho Ông có khuyến giáo như vậy, giảng dạy như vậy, một người lấy con đường sai lạc, đi về hướng Tây, còn một người có thể đi đến Rājagaha một cách an toàn?\n- Thưa Tôn giả Gotama, ở đây, con làm gì được? Con chỉ là người chỉ đường, thưa Tôn giả Gotama.\n- Cũng vậy, này Bà-la-môn, trong khi có mặt Niết-bàn, trong khi có mặt con đường đi đến Niết-bàn, và trong khi có mặt Ta là bậc chỉ đường. Nhưng các đệ tử của Ta, được Ta khuyến giáo như vậy, giảng dạy như vậy, một số chứng được cứu cánh đích Niết-bàn, một số không chứng được. Ở đây, này Bà-la-môn, Ta làm gì được? Như Lai chỉ là người chỉ đường.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Thưa Tôn giả Gotama, đối với những người không phải vì lòng tin, chỉ vì sinh kế, xuất gia, từ bỏ gia đình, sống không gia đình, những người xảo trá, lường gạt, hư ngụy, mất thăng bằng, cao mạn, dao động, nói phô tạp nhạp, không hộ trì các căn, ăn uống không tiết độ, không chú tâm cảnh giác, thờ ơ với Sa-môn hạnh, không tôn kính học tập, sống quá đầy đủ, uể oải, đi đầu trong thối thất, từ bỏ gánh nặng viễn ly, biếng nhác, tinh cần thấp kém, thất niệm, không tỉnh giác, không định tâm, tâm tán loạn, liệt tuệ, câm ngọng; Tôn giả Gotama không thể sống với những người như vậy.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Thưa Tôn giả Gotama, với những Thiện gia nam tử vì lòng tin xuất gia, từ bỏ gia đình, sống không gia đình, không xảo trá, không lường gạt, không hư ngụy, không mất thăng bằng, không cao mạn, không dao động, không nói phô tạp nhạp, hộ trì các căn, ăn uống có tiết độ, chú tâm tỉnh giác, không thờ ơ với Sa-môn hạnh, tôn kính học tập, sống không quá đầy đủ, không uể oải, từ bỏ thối thất, đi đầu trong viễn ly, tinh cần, tinh tấn, chánh niệm, an trú, tỉnh giác, định tĩnh, nhứt tâm, có trí tuệ, không câm ngọng; Tôn giả Gotama sống hòa hợp với những vị ấy.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Thưa Tôn giả Gotama, Ví như trong các loại căn hương, hắc chiên đàn hương được gọi là tối thượng; trong các loại lõi cây hương, xích chiên đàn hương được gọi là tối thượng; trong các loại hoa hương, vũ quý hương (jasmine) được gọi là tối thượng. Cũng vậy là lời khuyến giáo của Tôn giả Gotama được xem là cao nhất trong những lời khuyến giáo hiện nay.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },

{ text: `Thật vi diệu thay, thưa Tôn giả Gotama! Thật vi diệu thay, thưa Tôn giả Gotama! Như người dựng đứng lại những gì bị quăng ngã xuống, phơi bày những gì bị che kín, chỉ đường cho những người bị lạc hướng, đem đèn sáng vào trong bóng tối để những ai có mắt có thể thấy sắc; cũng vậy, Chánh pháp đã được Tôn giả Gotama dùng nhiều phương tiện trình bày giải thích. Con xin quy y Tôn giả Gotama, quy y Pháp và chúng Tỷ-kheo Tăng. Mong Tôn giả Gotama nhận con làm đệ tử, từ nay cho đến mạng chung, con trọn đời quy ngưỡng.`, ref: "Trung Bộ 107 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn107.html#content" },
{ text: `Này Bà-la-môn, Thế Tôn, bậc Tri Giả, Kiến Giả, bậc A-la-hán, Chánh Ðẳng Giác đã thi thiết học pháp, đã tuyên bố giới bổn Pātimokkha cho các Tỷ-kheo. Trong những ngày Bố-tát Uposatha chúng tôi cận trú ở chung một thôn điền, tất cả chúng tôi hội họp với nhau tại một chỗ; sau khi tụ họp, chúng tôi hỏi những gì đã xảy ra cho mỗi một người. Nếu trong khi hỏi nhau như vậy, có Tỷ-kheo phạm tội, phạm giới, chúng tôi bảo vị ấy làm đúng Pháp, đúng lời dạy. Thật vậy, không phải các Tôn giả xử sự chúng tôi, chính pháp xử sự chúng tôi.`, ref: "Trung Bộ 108 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn108.html#content" },

{ text: `Này Bà-la-môn, giữa chúng tôi, vị nào có đầy đủ các pháp này, chúng tôi nay cung kính, tôn trọng, lễ bái, cúng dường vị ấy; sau khi cung kính, tôn trọng, chúng tôi an trú, nương tựa vị ấy. Ở đây, này Bà-la-môn, Tỷ-kheo có giới hạnh, sống chế ngự với sự chế ngự của giới bổn Pātimokkha, đầy đủ oai nghi chánh hạnh, thấy sự nguy hiểm trong những lỗi nhỏ nhặt, sau khi thọ trì, học tập trong các học pháp. Vị ấy là bậc đa văn, thọ trì những điều đã nghe, cất chứa những điều đã nghe; những pháp nào sơ thiện, trung thiện, hậu thiện, với nghĩa, với văn, nói lên Phạm hạnh hoàn toàn đầy đủ thanh tịnh, những pháp ấy đều được nghe nhiều, được thọ trì, được lời nói làm cho quen thuộc, được ý tư niệm, được chánh kiến khéo ngộ nhập. Vị ấy biết đủ đối với các vật thực dụng như y, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh. Vị ấy là người tùy theo ý muốn, không có khó khăn, không có mệt nhọc, chứng được bốn Thiền, thuộc tăng thượng tâm hiện tại lạc trú. Vị ấy với sự đoạn diệt các lậu hoặc, sau khi với thượng trí đã chứng ngộ, vị ấy chứng đạt và an trú ngay trong hiện tại vô lậu tâm giải thoát, tuệ giải thoát.`, ref: "Trung Bộ 108 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn108.html#content" },

{ text: `Thật vậy, thưa Tôn giả Ānanda, Veluvana là một chỗ khả ái, ít tiếng động, ít tiếng ồn, được che khỏi gió, xa lánh dân cư đông đúc, thích hợp Thiền tịnh, xứng đáng với những người tu Thiền và tánh thiên về Thiền định như quý vị Tôn giả. Và chư vị Tôn giả là những vị tu Thiền và tánh thiên về Thiền định. Thưa Tôn giả Ānanda, một thời Tôn giả Gotama ở tại Vesālī, Ðại Lâm, ở Kutagarasala. Rồi, thưa Tôn giả Ānanda, tôi đi đến Tôn giả Gotama. Ở đấy, Tôn giả Gotama dùng nhiều phương tiện nói về Thiền định luận. Tôn giả Gotama thật là vị tu Thiền và tánh thiên về Thiền định.`, ref: "Trung Bộ 108 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn108.html#content" },

{ text: `Này Bà-la-môn, loại Thiền định nào Thế Tôn không tán thán? Ở đây, này Bà-la-môn, một số vị sống với tâm thấm nhuần dục tham, bị dục tham chi phối, và không như thật biết sự giải thoát khỏi dục tham đã được khởi lên. Vị ấy lấy dục tham làm đối tượng tối hậu, Thiền tu, Thiền tư, Thiền định, Thiền nhập. Vị ấy sống với tâm thấm nhuần sân hận, bị sân hận chi phối, và không như thật biết sự giải thoát khỏi sân hận đã được khởi lên. Vị ấy lấy sân hận làm đối tượng tối hậu, Thiền tu, Thiền tư, Thiền định, Thiền nhập. Này Bà-la-môn, Thế Tôn không tán thán loại Thiền định như vậy.`, ref: "Trung Bộ 108 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn108.html#content" },

{ text: `Này Bà-la-môn, loại Thiền định nào Thế Tôn không tán thán? Vị ấy sống với tâm thấm nhuần hôn trầm thụy miên, bị hôn trầm thụy miên chi phối, và không như thật biết sự giải thoát khỏi hôn trầm thụy miên đã được khởi lên. Vị ấy lấy hôn trầm thụy miên làm đối tượng tối hậu, Thiền tu, Thiền tư, Thiền định, Thiền nhập. Vị ấy sống với tâm thấm nhuần trạo hối, bị trạo hối chi phối và không như thật biết sự giải thoát khỏi trạo hối đã được khởi lên. Vị ấy lấy trạo hối làm đối tượng tối hậu, Thiền tu, Thiền tư, Thiền định, Thiền nhập. Vị ấy sống với tâm thấm nhuần nghi hoặc, bị nghi hoặc chi phối và không như thật biết sự giải thoát khỏi nghi hoặc đã được khởi lên. Vị ấy lấy nghi hoặc làm đối tượng tối hậu, Thiền tu, Thiền tư, Thiền định, Thiền nhập. Này Bà-la-môn, Thế Tôn không tán thán loại Thiền định như vậy.`, ref: "Trung Bộ 108 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn108.html#content" },

{ text: `Và này Bà-la-môn, loại Thiền định nào Thế Tôn ấy tán thán? Ở đây, này Bà-la-môn, Tỷ-kheo ly dục, ly bất thiện pháp chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, với tầm với tứ. Vị ấy diệt tầm và tứ, chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm không tứ, nội tĩnh nhất tâm. Vị ấy ly hỷ trú xả, chánh niệm tỉnh giác, thân cảm sự lạc thọ mà các bậc Thánh gọi là xả niệm lạc trú, chứng và trú Thiền thứ ba. Xả lạc, xả khổ, diệt hỷ ưu đã cảm thọ trước, chứng và trú Thiền thứ tư, không khổ, không lạc, xả niệm thanh tịnh. Này Bà-la-môn, loại Thiền như vậy, Thế Tôn ấy tán thán.`, ref: "Trung Bộ 108 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn108.html#content" },

{ text: `Này Bà-la-môn, Thế Tôn là bậc làm cho khởi dậy con đường trước đây chưa từng được hiện khởi, làm cho biết con đường trước đây chưa từng được biết, nói lên con đường trước đây chưa từng được nói; là bậc hiểu đạo, biết đạo và thiện xảo về đạo. Và nay các đệ tử Ngài là những vị sống hành đạo và tùy hành đạo, và sẽ thành tựu những pháp ấy về sau.`, ref: "Trung Bộ 108 – Kinh Ganaka Moggallāna", url: "https://loicuaducphat.org/mn/mn108.html#content" },
{ text: `Do vậy, này các Tỷ-kheo, phàm có sắc gì, quá khứ, vị lai hay hiện tại, nội hay ngoại … tất cả loại sắc, cần phải như thật quán: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”. Phàm có thọ gì, phàm có tưởng gì, phàm có hành gì, phàm có thức gì quá khứ, vị lai hay hiện tại, nội hay ngoại. Tất cả loại thức, cần phải như thật quán: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”.`, ref: "Trung Bộ 109 – Ðại kinh Mãn nguyệt", url: "https://loicuaducphat.org/mn/mn109.html#content" },
{ text: `Và này các Tỷ-kheo, như thế nào là người bất chánh có tà kiến như người bất chánh? Ở đây, này các Tỷ-kheo, người bất chánh có tà kiến như sau: “Không có bố thí, không có lễ hy sinh, không có tế tự, không có quả dị thục các nghiệp thiện ác, không có đời này, không có đời khác, không có cha, không có mẹ, không có loại hóa sanh. Ở đời, không có những vị Sa-môn, những vị Bà-la-môn chánh hướng, chánh hạnh đã tự mình chứng đạt với thượng trí đời này và đời khác, và truyền dạy lại”. Như vậy, này các Tỷ-kheo, là người bất chánh có tà kiến như người bất chánh.`, ref: "Trung Bộ 110 – Tiểu kinh Mãn nguyệt", url: "https://loicuaducphat.org/mn/mn110.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là người bất chánh bố thí như người bất chánh? Ở đây, này các Tỷ-kheo, người bất chánh bố thí một cách vô lễ, bố thí không phải tự tay, bố thí không có suy tư kỹ lưỡng, bố thí những vật không cần dùng, bố thí không nghĩ đến tương lai. Như vậy, này các Tỷ-kheo, là người bất chánh bố thí như người bất chánh.`, ref: "Trung Bộ 110 – Tiểu kinh Mãn nguyệt", url: "https://loicuaducphat.org/mn/mn110.html#content" },

{ text: `Và này, các Tỷ-kheo, như thế nào là người chơn chánh suy tư như người chơn chánh? Ở đây, này các Tỷ-kheo, người chơn chánh không suy nghĩ tự làm hại mình, không suy nghĩ làm hại người khác, không suy nghĩ làm hại cả hai. Như vậy, này các Tỷ-kheo, là người chơn chánh suy tư như người chơn chánh.`, ref: "Trung Bộ 110 – Tiểu kinh Mãn nguyệt", url: "https://loicuaducphat.org/mn/mn110.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là người chơn chánh có chánh kiến như bậc chơn chánh? Ở đây, này các Tỷ-kheo, người chơn chánh có chánh kiến như sau: “Có bố thí, có lễ hy sinh, có tế tự, có quả dị thục các nghiệp thiện ác, có đời này, có đời khác, có cha, có mẹ, có loại hóa sanh. Ở đời có những vị Sa-môn, những vị Bà-la-môn chánh hướng, chánh hạnh, đã tự mình chứng đạt với thượng trí đời này và đời khác, và truyền dạy lại. Như vậy, này các Tỷ-kheo, là người chơn chánh có chánh kiến như người chơn chánh.`, ref: "Trung Bộ 110 – Tiểu kinh Mãn nguyệt", url: "https://loicuaducphat.org/mn/mn110.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là người chơn chánh bố thí như người chơn chánh? Ở đây, này các Tỷ-kheo, người chơn chánh bố thí một cách lễ độ, bố thí với tự tay, bố thí có suy tư kỹ lưỡng, bố thí những vật cần dùng, bố thí có nghĩ đến tương lai. Như vậy, này các Tỷ-kheo, là người chơn chánh bố thí như người chơn chánh.`, ref: "Trung Bộ 110 – Tiểu kinh Mãn nguyệt", url: "https://loicuaducphat.org/mn/mn110.html#content" },
{ text: `Này các Tỷ-kheo, nếu nói một cách chơn chánh về Sāriputta, một người có thể nói như sau: “Sāriputta được tự tại, được cứu cánh trong Thánh giới, được tự tại, được cứu cánh trong Thánh định, được tự tại, được cứu cánh trong Thánh tuệ, được tự tại, được cứu cánh trong Thánh giải thoát”.`, ref: "Trung Bộ 111 – Kinh Bất Đoạn", url: "https://loicuaducphat.org/mn/mn111.html#content" },

{ text: `Này các Tỷ-kheo, nếu nói một cách chơn chánh về Sāriputta, một người có thể nói như sau: “Sāriputta là con chánh tông của Thế Tôn, sanh ra từ miệng, sanh ra từ Pháp, do Pháp hóa thành, thừa tự Chánh pháp, không thừa tự vật chất”.`, ref: "Trung Bộ 111 – Kinh Bất Đoạn", url: "https://loicuaducphat.org/mn/mn111.html#content" }, 
{ text: `Này các Tỷ-kheo, với Tỷ-kheo, các lậu hoặc đã đoạn tận, tu hành thành mãn, những việc phải làm đã làm, đã đặt gánh nặng xuống, đã thành đạt mục đích, đã đoạn trừ hữu kiết sử, và đã được giải thoát nhờ chánh trí, câu trả lời tùy pháp (anudhamma) của vị ấy phải như sau: “Này chư Hiền, tôi không cảm thấy luyến ái, không chống đối, độc lập, không trói buộc, giải thoát, không hệ lụy, an trú với tâm không có hạn chế, đối với những vật được thấy … được nghe … được cảm giác … được nhận thức. Chư Hiền, vì rằng tôi biết như vậy, thấy như vậy, đối với bốn hình thức tuyên bố này, tôi có thể nói tâm tôi được giải thoát khỏi các lậu hoặc, không có chấp thủ”.`, ref: "Trung Bộ 112 – Kinh Sáu Thanh Tịnh", url: "https://loicuaducphat.org/mn/mn112.html#content" },
{ text: `Này các Tỷ-kheo, người Chân nhân suy nghĩ như sau: “Không phải vì thuộc về một gia đình quý phái mà các tham pháp đi đến đoạn trừ, hay các sân pháp đi đến đoạn trừ, hay các si pháp đi đến đoạn trừ. Nếu một người xuất gia không phải từ một gia đình quý phái và người ấy hành trì đúng pháp và thuận pháp, hành trì chơn chánh, hành trì thuận pháp, thời ở đây, người ấy được kính trọng, ở đây, người ấy được tán thán”. Người ấy, sau khi lấy đạo lộ làm chính yếu, không khen mình chê người vì tự mình thuộc vào gia đình quý phái. Như vậy, này các Tỷ-kheo, là Chân nhân pháp.`, ref: "Trung Bộ 113 – Kinh Chân Nhân", url: "https://loicuaducphat.org/mn/mn113.html#content" },

{ text: `Này các Tỷ-kheo, người Chân Nhân suy nghĩ như sau: “Không phải vì mình được nhiều người biết đến mà các tham pháp đi đến đoạn trừ, hay sân pháp đi đến đoạn trừ, hay các si pháp đi đến đoạn trừ. Nếu một người xuất gia không được nhiều người biết, không có danh xưng, và người ấy hành trì đúng pháp và thuận pháp, hành trì chơn chánh, hành trì thuận pháp, thời ở đây, người ấy được kính trọng, ở đây, người ấy được tán thán”. Người ấy, sau khi lấy đạo lộ làm chính yếu, không khen mình chê người vì tự mình được nhiều người biết và có danh xưng. Như vậy, này các Tỷ-kheo, là Chân nhân pháp.`, ref: "Trung Bộ 113 – Kinh Chân Nhân", url: "https://loicuaducphat.org/mn/mn113.html#content" },

{ text: `Này các Tỷ-kheo, người Chân nhân suy nghĩ như sau: “Không phải vì tự mình là bậc trì luật mà các tham pháp đi đến đoạn trừ hay các sân pháp đi đến đoạn trừ hay các si pháp đi đến đoạn trừ. Nếu có người không phải là bậc trì luật, những người này hành trì đúng pháp và thuận pháp, hành trì chơn chánh, hành trì thuận pháp, thời ở đây, người ấy được kính trọng, ở đây, người ấy được tán thán”. Người ấy sau khi lấy đạo lộ làm chánh yếu, không khen mình chê người vì tự mình là bậc trì luật. Như vậy, này các Tỷ-kheo, là Chân nhân pháp.`, ref: "Trung Bộ 113 – Kinh Chân Nhân", url: "https://loicuaducphat.org/mn/mn113.html#content" },

{ text: `Và người Chân nhân, này các Tỷ-kheo, suy nghĩ như sau: “Không phải do tự mình là bậc thuyết pháp mà các tham pháp đi đến đoạn trừ, hay các sân pháp đi đến đoạn trừ, hay các si pháp đi đến đoạn trừ. Nếu một người không phải là người thuyết pháp, nhưng hành trì đúng pháp, và thuận pháp, hành trì chơn chánh, hành trì thuận pháp, thời ở đây người ấy được kính trọng, ở đây, người ấy được tán thán”. Người ấy, sau khi lấy đạo lộ làm chánh yếu, không khen mình chê người vì tự mình là bậc thuyết pháp. Như vậy, này các Tỷ-kheo, là Chân nhân pháp.`, ref: "Trung Bộ 113 – Kinh Chân Nhân", url: "https://loicuaducphat.org/mn/mn113.html#content" },

{ text: `Và người Chân nhân, này các Tỷ-kheo, suy nghĩ như sau: “Không phải vì tự mình theo hạnh sống ở rừng núi mà các tham pháp đi đến đoạn trừ, hay các sân pháp đi đến đoạn trừ, hay các si pháp đi đến đoạn trừ. Nếu một người không theo hạnh sống ở rừng núi, nhưng hành trì đúng pháp và thuận pháp, hành trì chơn chánh, hành trì thuận pháp, thời ở đây, người ấy được kính trọng, ở đây, người ấy được tán thán”. Người ấy, sau khi lấy đạo lộ làm chánh yếu, không khen mình chê người, vì tự mình theo hạnh sống ở rừng núi. Như vậy, này các Tỷ-kheo, là Chân nhân pháp.`, ref: "Trung Bộ 113 – Kinh Chân Nhân", url: "https://loicuaducphat.org/mn/mn113.html#content" },
{ text: `Và này các Tỷ-kheo, thế nào là tà kiến? Không có bố thí, không có cúng dường, không có tế tự, không có quả báo các nghiệp thiện ác, không có đời này, không có đời khác, không có mẹ, không có cha, không có các loại hóa sanh; ở đời không có các vị Sa-môn, Bà-la-môn, chánh hướng, chánh hạnh, sau khi với thượng trí tự mình chứng đạt lại tuyên bố lên. Như vậy, này các Tỷ-kheo, là tà kiến.`, ref: "Trung Bộ 117 – Ðại Kinh Bốn Mươi", url: "https://loicuaducphat.org/mn/mn117.html#content" },

{ text: `Tà niệm, này các Tỷ-kheo, do chánh niệm làm cho tiêu diệt. Và những ác bất thiện pháp được tà niệm duyên khởi, các pháp ấy được tiêu diệt trong người có chánh niệm. Và những thiện pháp được chánh niệm duyên khởi, các pháp ấy được tu tập và trở thành viên mãn.`, ref: "Trung Bộ 117 – Ðại Kinh Bốn Mươi", url: "https://loicuaducphat.org/mn/mn117.html#content" },
{ text: `Trong khi vị ấy sống không phóng dật, nhiệt tâm, tinh cần, các niệm và tư duy thuộc về thế tục được đoạn trừ. Nhờ đoạn trừ các pháp ấy, nội tâm được an trú, an tọa, chuyên nhất, định tĩnh. Như vậy, này các Tỷ-kheo, Tỷ-kheo tu tập thân hành niệm.`, ref: "Trung Bộ 119 – Kinh Thân Hành Niệm", url: "https://loicuaducphat.org/mn/mn119.html#content" },

{ text: `Này các Tỷ-kheo, đối với vị nào tu tập, làm cho sung mãn thân hành niệm, các thiện pháp của vị ấy đi vào nội tâm đều thuộc về minh phần. Ví như, này các Tỷ-kheo, biển lớn của ai được thấm nhuần bởi tâm, thời các con sông của vị ấy đi vào trong biển, đều thuộc về biển lớn; cũng vậy, này các Tỷ-kheo, đối với vị nào tu tập làm cho sung mãn thân hành niệm, các thiện pháp của vị ấy đi vào nội tâm đều thuộc về minh phần.`, ref: "Trung Bộ 119 – Kinh Thân Hành Niệm", url: "https://loicuaducphat.org/mn/mn119.html#content" },
{ text: `Này Ānanda, một Tỷ-kheo không chói sáng nếu thích thú trong hội chúng của mình, nếu hân hoan trong hội chúng của mình, nếu hoan hỷ trong hội chúng của mình, nếu thích thú trong hội chúng của người, nếu hân hoan trong hội chúng của người, nếu hoan hỷ trong hội chúng của người. Này Ānanda, nếu Tỷ-kheo nào thích thú trong hội chúng của mình,... hoan hỷ trong hội chúng của người, có thể là một vị chứng đắc tùy theo ý muốn, chứng đắc không khó khăn, chứng đắc không mệt nhọc, viễn ly lạc, độc cư lạc, an tịnh lạc, chánh giác lạc; sự kiện như vậy không xảy ra. Nhưng này Ānanda, Tỷ-kheo nào sống một mình, xa lánh tụ hội, thời vị ấy có hy vọng chứng đắc tùy theo ý muốn, chứng đắc không khó khăn, chứng đắc không mệt nhọc, viễn ly lạc, độc cư lạc, an tịnh lạc, chánh giác lạc; sự kiện như vậy có thể xảy ra.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },

{ text: `Này Ānanda, Ta không quán thấy một sắc pháp nào trong ấy có hoan hỷ, trong ấy có hoan lạc, chịu sự biến dịch, chịu sự đổi khác mà không khởi lên sầu, bi, khổ, ưu, não.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },

{ text: `Nhưng sự (an) trú này, này Ānanda, đã được Như Lai hoàn toàn giác ngộ, tức là sau khi không tác ý với tất cả tướng, chứng đắc và (an) trú nội không. Và nếu này Ānanda, trong khi Như Lai an trú trong an trú này, nếu có những Tỷ-kheo, Tỷ-kheo ni, nam cư sĩ, nữ cư sĩ, quốc vương, đại thần, ngoại đạo, ngoại đạo đệ tử đến yết kiến, trong khi ấy, này Ānanda, Như Lai với tâm hướng đến viễn ly, thiên về viễn ly, nặng nề viễn ly, sống độc cư, hoan hỷ trong ly dục, làm cho đoạn tận tất cả các pháp dựa trên các lậu hoặc an trú, nói lên tại chỗ ấy những lời thuần túy liên hệ đến khích lệ.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },

{ text: `Này Ānanda, vị ấy suy nghĩ: “Ðối với những suy tầm hạ liệt, đê tiện, phàm phu, không thuộc bậc Thánh, không liên hệ đến mục đích, không đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn, như là dục tầm, sân tầm, hại tầm, ta sẽ không suy nghĩ các loại suy tầm ấy”. Ở đây, vị ấy ý thức rõ ràng như vậy.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },

{ text: `Này Ānanda, đối với những suy tầm này, thuộc bậc Thánh, có khả năng cầu tiến, hướng dẫn đến sự đoạn trừ hoàn toàn đau khổ, như là ly dục tầm, vô sân tầm, bất hại tầm, vị ấy nghĩ: “Ta sẽ suy tư các loại suy tầm này”. Ở đây, vị ấy ý thức rõ ràng như vậy.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },

{ text: `Và như thế nào, này Ānanda, là các đệ tử đối xử với bậc Ðạo sư với tâm thân hữu, không với tâm thù nghịch? Ở đây, này Ānanda, vị Ðạo sư với lòng từ mẫn thuyết pháp cho các đệ tử, tìm cầu hạnh phúc cho họ, vì lòng từ mẫn nói rằng: “Ðây là hạnh phúc cho các Ông, đây là an lạc cho các Ông”. Các đệ tử của vị ấy chịu nghe theo, chịu lóng tai, không chú tâm vào hướng khác, và không ngược lại đi xa lời dạy của bậc Ðạo sư. Như vậy, này Ānanda, là các đệ tử đối xử với bậc Ðạo sư, với tâm thân hữu, không phải với tâm thù nghịch. Do vậy, này Ānanda, hãy đối xử với Ta với tâm thân hữu, chớ với tâm thù nghịch và như vậy sẽ là hạnh phúc, là an lạc lâu dài cho các Ông.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },

{ text: `Ta không sách tấn các Ông như người thợ gốm đối với các đồ gốm chưa nung, chưa được nung chín. Ta sẽ nói hết lời khiển trách này đến lời khiển trách khác, hết lời thúc giục này đến lời thúc giục khác. Cái gì là lõi cây, cái ấy sẽ đứng vững tồn tại.`, ref: "Trung Bộ 122 – Kinh Đại Không", url: "https://loicuaducphat.org/mn/mn122.html#content" },
{ text: `Ở đây, này Ānanda, các cảm thọ khởi lên nơi Thế Tôn được biết đến; được biết đến, chúng an trú; được biết đến, chúng đi đến biến hoại; các tưởng được biết đến; các tầm khởi lên được biết đến; được biết đến, chúng an trú; được biết đến, chúng đi đến biến hoại. Này Ānanda, hãy thọ trì việc này là một hy hữu, một vị tằng hữu của Như Lai.`, ref: "Trung Bộ 123 – Kinh Hy hữu vị tằng hữu pháp", url: "https://loicuaducphat.org/mn/mn123.html#content" },
{ text: `Này Aggivessana, nào có lợi ích gì? Vương tử Jayasenna sống giữa các dục, thọ hưởng các dục, bị tư tưởng dục nhai nghiến, bị nhiệt não dục thiêu đốt, tha thiết truy cầu dục, lại có thể biết, có thể thấy, hay có thể chứng quả vị chỉ có ly dục mới biết được, chỉ có ly dục mới thấy được. Chỉ có ly dục mới đạt được, hay chỉ có ly dục mới chứng được; sự kiện như vậy không xảy ra.`, ref: "Trung Bộ 125 – Kinh Ðiều Ngự Địa", url: "https://loicuaducphat.org/mn/mn125.html#content" },

{ text: `Tỷ-kheo kham nhẫn lạnh, nóng, đói, khát, sự xúc chạm của muỗi, ruồi, gió, mặt trời và các loài bò sát, các ác ngữ, các lời nói chửi mắng, vị ấy sống quen kham nhẫn với những cảm thọ về thân, thống khổ, đau nhói, đau đớn, kịch liệt, bất khoái, không thích ý, đau đớn đến chết, được gột sạch về uế nhiễm tham, sân, si. Vị ấy xứng đáng được cúng dường, cung kính, tôn trọng, chấp tay, là vô thượng phước điền trên đời.`, ref: "Trung Bộ 125 – Kinh Ðiều Ngự Địa", url: "https://loicuaducphat.org/mn/mn125.html#content" },
{ text: `- Này các Anuruddha, các Ông có sống hòa hợp, hoan hỷ với nhau, không có cãi nhau. Như nước với sữa, sống nhìn nhau với cặp mắt thiện cảm không?\n- Bạch Thế Tôn, thật sự chúng con sống hòa hợp, hoan hỷ với nhau, không có cãi nhau, như nước với sữa, sống nhìn nhau với cặp mắt thiện cảm.`, ref: "Trung Bộ 128 – Kinh Tùy Phiền Não", url: "https://loicuaducphat.org/mn/mn128.html#content" },

{ text: `Bạch Thế Tôn, ở đây chúng con nghĩ như sau: “Thật lợi ích thay cho ta! Thật khéo lợi ích thay cho ta, khi ta được sống với các vị đồng Phạm hạnh như vậy!” Bạch Thế Tôn, do vậy đối với các vị đồng Phạm hạnh này, con khởi lên từ thân nghiệp, trước mặt và sau lưng; con khởi lên từ khẩu nghiệp, trước mặt và sau lưng, con khởi lên từ ý nghiệp, trước mặt và sau lưng. Bạch Thế Tôn, do vậy chúng con nghĩ như sau: “Ta hãy từ bỏ tâm của ta và sống thuận theo tâm của những Tôn giả này”. Và bạch Thế Tôn, con từ bỏ tâm của con và sống thuận theo tâm của những Tôn giả ấy. Bạch Thế Tôn, chúng con tuy khác thân nhưng giống như đồng một tâm. Bạch Thế Tôn, như vậy chúng con sống hòa hợp, hoan hỷ với nhau, như nước với sữa, sống nhìn nhau với cặp mắt thiện cảm.`, ref: "Trung Bộ 128 – Kinh Tùy Phiền Não", url: "https://loicuaducphat.org/mn/mn128.html#content" },
{ text: `Rồi này các Tỷ-kheo, vua Yāma nói với người ấy: “Này người kia, nếu vì phóng dật nên Ngươi không làm điều thiện về thân, khẩu, ý; chắc chắn chúng sẽ làm cho Ngươi, này Người kia, tùy theo sự phóng dật ấy của Ngươi. Vì rằng đây là một ác nghiệp của Ngươi, không phải do mẹ làm, không phải do cha làm, không phải do anh làm, không phải do chị làm, không phải do bạn và thân hữu làm, không phải do bà con huyết thống làm, không phải do Sa-môn, Bà-la-môn làm, không phải do chư Thiên làm. Ác nghiệp ấy chính do Ngươi làm, chính Người phải cảm thọ quả báo việc làm ấy”.`, ref: "Trung Bộ 130 – Kinh Thiên Sứ", url: "https://loicuaducphat.org/mn/mn130.html#content" },

{ text: `Dầu Thiên sứ báo động,\nThanh niên vẫn phóng dật,\nHọ ưu buồn lâu dài,\nSanh làm người hạ liệt.\nỞ đây bậc Chân nhân,\nÐược Thiên sứ báo động,\nKhông bao giờ phóng dật,\nTrong diệu pháp bậc Thánh.\nThấy sợ trong chấp thủ,\nTrong hiện hữu sanh tử.\nÐược giải thoát chấp thủ,\nSanh tử được đoạn trừ,\nÐược yên ổn an lạc,\nNgay hiện tại tịch tịnh,\nMọi oán hận sợ hãi,\nCác vị ấy vượt qua,\nMọi đau đớn sầu khổ,\nThảy đều được siêu thoát.`, ref: "Trung Bộ 130 – Kinh Thiên Sứ", url: "https://loicuaducphat.org/mn/mn130.html#content" },
{ text: `Quá khứ không truy tìm\nTương lai không ước vọng.\nQuá khứ đã đoạn tận,\nTương lai lại chưa đến,\nChỉ có pháp hiện tại\nTuệ quán chính ở đây.\nKhông động, không rung chuyển\nBiết vậy, nên tu tập,\nHôm nay nhiệt tâm làm,\nAi biết chết ngày mai?\nKhông ai điều đình được,\nVới đại quân thần chết,\nTrú như vậy nhiệt tâm,\nÐêm ngày không mệt mỏi,\nXứng gọi Nhất dạ Hiền,\nBậc an tịnh, trầm lặng.`, ref: "Trung Bộ 131 – Kinh Nhất Dạ Hiền Giả", url: "https://loicuaducphat.org/mn/mn131.html#content" },
{ text: `Này Thanh niên, các loài hữu tình là chủ nhân của nghiệp, là thừa tự của nghiệp. Nghiệp là thai tạng, nghiệp là quyến thuộc, nghiệp là điểm tựa, nghiệp phân chia các loài hữu tình; nghĩa là có liệt, có ưu.`, ref: "Trung Bộ 135 – Tiểu Kinh Nghiệp Phân Biệt", url: "https://loicuaducphat.org/mn/mn135.html#content" },
{ text: `Và những sanh y vô trí thức trước của nó đã được đầy đủ, đã được thành tựu. Chúng được đoạn tận, chặt tận gốc rễ, làm cho như thân cây tala, không thể hiện hữu nữa trong tương lai, không có khả năng sanh khởi nữa. Do vậy, một Tỷ-kheo thành tựu như vậy là thành tựu với tối thắng huệ thí thắng xứ này. Vì rằng, này Tỷ-kheo, như vậy là tối thắng Thánh huệ thí, tức là sự xả ly tất cả sanh y.`, ref: "Trung Bộ 140 – Kinh Giới Phân Biệt", url: "https://loicuaducphat.org/mn/mn140.html#content" },

{ text: `Và tham ái vô trí thức trước của nó, thuộc tham dục, tham nhiễm; pháp ấy được đoạn tận, chặt tận gốc rễ, làm cho như thân cây tala, không thể hiện hữu nữa trong tương lai, không có khả năng sanh khởi nữa. Và sự phẫn nộ vô trí thức trước của nó, thuộc sân hận, thuộc tội quá; pháp ấy được đoạn tận, cắt tận gốc rễ, làm cho như thân cây tala, không thể hiện hữu nữa trong tương lai, không có khả năng sanh khởi nữa. Và vô minh vô trí thức trước của nó, thuộc si mê, thuộc tội quá; pháp ấy được đoạn tận, cắt tận gốc rễ, làm cho như thân cây tala, không thể hiện hữu trong tương lai, không có khả năng sanh khởi nữa. Do vậy, Tỷ-kheo thành tựu như vậy là thành tựu tối thắng tịch tịnh thắng xứ. Này Tỷ-kheo, như vậy là tối thắng Thánh tịch tịnh, tức là sự tịch tịnh tham sân si.`, ref: "Trung Bộ 140 – Kinh Giới Phân Biệt", url: "https://loicuaducphat.org/mn/mn140.html#content" },

{ text: `Này Tỷ-kheo, “Tôi là”, như vậy là vọng tưởng. “Tôi là cái này”, như vậy là vọng tưởng. “Tôi sẽ là”, như vậy là vọng tưởng. “Tôi sẽ không là”, như vậy là vọng tưởng. “Tôi sẽ có sắc”, như vậy là vọng tưởng. “Tôi sẽ không có sắc”, như vậy là vọng tưởng. “Tôi sẽ có tưởng”, như vậy là vọng tưởng. “Tôi sẽ không có tưởng”, như vậy là vọng tưởng. “Tôi sẽ không có tưởng, không không có tưởng”, như vậy là vọng tưởng. Vọng tưởng, này Tỷ-kheo, là bệnh, vọng tưởng là cục bướu, vọng tưởng là mũi tên. Này Tỷ-kheo, khi vượt khỏi mọi vọng tưởng, vị ẩn sĩ được gọi là tịch tịnh. Nhưng này Tỷ-kheo, vị ẩn sĩ tịch tịnh không sanh, không già, không có dao động, không có hy cầu. Vì không có cái gì do đó có thể sanh, này Tỷ-kheo, không sanh làm sao già được? Không già, làm sao chết được? Không chết làm sao dao động được? Không dao động, làm sao hy cầu?`, ref: "Trung Bộ 140 – Kinh Giới Phân Biệt", url: "https://loicuaducphat.org/mn/mn140.html#content" },
{ text: `Và này Ānanda, thế nào là loại cúng dường được thanh tịnh bởi người cho và cũng bởi người nhận? Ở đây, này Ānanda, người cho giữ giới, theo thiện pháp; và người nhận cũng giữ giới, theo thiện pháp. Như vậy, này Ānanda, là sự cúng dường được thanh tịnh bởi người cho và cũng bởi người nhận.`, ref: "Trung Bộ 142 – Kinh Phân Biệt Cúng Dường", url: "https://loicuaducphat.org/mn/mn142.html#content" },

{ text: `Ai đầy đủ giới luật,\nBố thí cho thiện giới;\nVật thí được đúng pháp,\nVới tâm khéo hoan hỷ,\nVới lòng tin vững vàng,\nVào quả lớn của nghiệp,\nTa nói bố thí ấy,\nChắc chắn có quả lớn.`, ref: "Trung Bộ 142 – Kinh Phân Biệt Cúng Dường", url: "https://loicuaducphat.org/mn/mn142.html#content" },

{ text: `Ai xuất ly tham ái,\nBố thí không tham ái,\nVật thí được đúng pháp.\nVới tâm khéo hoan hỷ,\nVới lòng tin vững vàng,\nVào quả lớn của nghiệp,\nTa nói bố thí ấy,\nLà bố thí tối thượng.`, ref: "Trung Bộ 142 – Kinh Phân Biệt Cúng Dường", url: "https://loicuaducphat.org/mn/mn142.html#content" },
{ text: `-Này Puñña, người nước Sunaparanta là hung bạo. Này Puñña, người nước Sunaparanta là thô ác. Này Puñña, nếu người nước Sunaparanta mắng nhiếc Ông, nhục mạ Ông, thời này Puñña, tại đấy Ông sẽ như thế nào?\n-Bạch Thế Tôn, nếu người nước Sunaparanta mắng nhiếc con, nhục mạ con, thời tại đấy, con sẽ nghĩ như sau: “Thật là hiền thiện, người nước Sunaparanta này! Thật là chí thiện, người nước Sunaparanta này! Vì rằng họ không lấy tay đánh đập ta”. Bạch Thế Tôn, tại đấy con sẽ nghĩ như vậy. Bạch Thiện Thệ, tại đấy con sẽ nghĩ như vậy.`, ref: "Trung Bộ 145 – Kinh Giáo Giới Phú-Lâu-Na", url: "https://loicuaducphat.org/mn/mn145.html#content" },
{ text: `Này Sāriputta, nếu Tỷ-kheo sau khi tư duy biết rằng: “Trên con đường ta đã đi vào làng để khất thực, tại trú xứ ta đã đi khất thực và trên con đường từ làng ta đi khất thực trở về, đối với các sắc do mắt nhận thức, có khởi lên nơi ta dục, tham, sân, si hay hận tâm”, thời này Sāriputta, Tỷ-kheo ấy phải tinh tấn đoạn tận các ác bất thiện pháp ấy. Nhưng này Sāriputta, nếu Tỷ-kheo trong khi suy tư được biết như sau: “Trên con đường ta đã đi … ta đi khất thực trở về, đối với các sắc do mắt nhận thức, không có khởi lên nơi dục, tham, sân, si hay hận tâm”, thời này Sāriputta, Tỷ-kheo ấy phải an trú với hỷ và hân hoan ngày đêm tu học trong các thiện pháp.`, ref: "Trung Bộ 151 – Kinh Khất Thực Thanh Tịnh", url: "https://loicuaducphat.org/mn/mn151.html#content" },

{ text: `Lại nữa, này Sāriputta, Tỷ-kheo cần phải suy tư như sau: “Ta đã đoạn tận năm dục trưởng dưỡng chưa? Này Sāriputta, nếu Tỷ-kheo, trong khi suy tư được biết như sau: “Ta chưa đoạn tận năm dục trưởng dưỡng”, thời này Sāriputta, Tỷ-kheo ấy phải tinh tấn đoạn tận năm dục trưởng dưỡng. Nhưng nếu, này Sāriputta, Tỷ-kheo trong khi suy tư được biết như sau: “Ta đã đoạn tận năm dục trưởng dưỡng”, thời này Sāriputta, Tỷ-kheo ấy phải an trú với hỷ và hân hoan ngày đêm tu học trong các thiện pháp.`, ref: "Trung Bộ 151 – Kinh Khất Thực Thanh Tịnh", url: "https://loicuaducphat.org/mn/mn151.html#content" },

{ text: `Lại nữa, này Sāriputta, Tỷ-kheo cần phải suy tư như sau: “Ta đã đoạn tận năm triền cái chưa?” Nếu, này Sāriputta, trong khi suy tư, Tỷ-kheo được biết như sau: “Ta chưa đoạn tận năm triền cái”, thời này Sāriputta, Tỷ-kheo ấy phải tinh tấn đoạn tận năm triền cái. Nhưng nếu, này Sāriputta, Tỷ-kheo trong khi suy tư được biết như sau: “Ta đã đoạn tận năm triền cái ”, thời này Sāriputta, Tỷ-kheo ấy phải an trú với hỷ và hân hoan ngày đêm tu học trong các thiện pháp.`, ref: "Trung Bộ 151 – Kinh Khất Thực Thanh Tịnh", url: "https://loicuaducphat.org/mn/mn151.html#content" },

{ text: `Lại nữa, này Sāriputta, Tỷ-kheo cần phải suy tư như sau: “Ta đã tu tập bốn niệm xứ chưa?” Này Sāriputta, nếu trong khi suy tư, Tỷ-kheo được biết: “Ta chưa tu tập bốn niệm xứ”, thời này Sāriputta, vị Tỷ-kheo cần phải tinh tấn tu tập bốn niệm xứ. Nhưng nếu, này Sāriputta, trong khi suy tư, Tỷ-kheo được biết như sau: “Ta đã tu tập bốn niệm xứ ”, thời này Sāriputta, Tỷ-kheo ấy cần phải an trú với hỷ và hân hoan ngày đêm tu học trong các thiện pháp.`, ref: "Trung Bộ 151 – Kinh Khất Thực Thanh Tịnh", url: "https://loicuaducphat.org/mn/mn151.html#content" },

{ text: `Lại nữa, này Sāriputta, Tỷ-kheo cần phải suy tư: “Ta đã tu tập Chỉ và Quán chưa? ” Nếu Tỷ-kheo, này Sāriputta, trong khi suy tư được biết như sau: “Ta chưa tu tập Chỉ và Quán ”, thời này Sāriputta, Tỷ-kheo ấy cần phải tinh tấn tu tập Chỉ và Quán. Nhưng nếu, này các Tỷ-kheo, Tỷ-kheo trong khi suy tư được biết như sau: “Ta đã tu tập Chỉ và Quán ”, thời này Sāriputta, Tỷ-kheo ấy cần phải an trú với hỷ và hân hoan ngày đêm tu học trong các thiện pháp.`, ref: "Trung Bộ 151 – Kinh Khất Thực Thanh Tịnh", url: "https://loicuaducphat.org/mn/mn151.html#content" },
{ text: `Như vậy, này Ānanda, Ta đã giảng vô thượng căn tu tập trong giới luật bậc Thánh, đã giảng đạo lộ của bậc hữu học, đã giảng bậc Thánh, các căn được tu tập. Này Ānanda, những gì một bậc Ðạo sư phải làm, vì lòng từ mẫn, mưu cầu hạnh phúc cho các đệ tử, những điều ấy Ta đã làm cho các Ông. Này Ānanda, đây là những gốc cây, đây là những chỗ trống. Này Ānanda, hãy Thiền tư, chớ có phóng dật, chớ có hối hận về sau. Ðây là những lời giáo giới của Ta cho các Ông.`, ref: "Trung Bộ 152 – Kinh Căn Tu Tập", url: "https://loicuaducphat.org/mn/mn152.html#content" },

   
               { text: `- Thưa Tôn giả, làm sao Ngài vượt khỏi bộc lưu?\n- Này Hiền giả, không đứng lại, không bước tới, Ta vượt khỏi bộc lưu.\n- Thưa Tôn giả, làm sao không đứng lại, không bước tới, Ngài vượt khỏi bộc lưu?\n- Này Hiền giả, khi Ta đứng lại, thời Ta chìm xuống. Này Hiền giả, khi Ta bước tới, thời Ta trôi giạt; do vậy, này Hiền giả, không đứng lại, không bước tới, Ta vượt khỏi bộc lưu.\n(Vị Thiên):\nTừ lâu, tôi mới thấy\nBà-la-môn tịch tịnh.\nKhông đứng, không bước tới,\nVượt chấp trước ở đời.`, ref: "Tương Ưng Bộ 1.1", url: "https://loicuaducphat.org/sn/sn1.1.html#content" },

{ text: `- Thưa Tôn giả, Ngài có biết giải thoát, thoát ly, viễn ly cho các chúng sanh không?\n- Này Hiền giả, Ta có biết giải thoát, thoát ly, viễn ly cho các chúng sanh.\n- Thưa Tôn giả, như thế nào Ngài biết giải thoát, thoát ly, viễn ly cho các chúng sanh?\nHỷ, tái sanh đoạn tận,\nTưởng, thức được trừ diệt,\nCác thọ diệt, tịch tịnh,\nNhư vậy này Hiền giả,\nTa biết sự giải thoát,\nThoát ly và viễn ly,\nCho các loại chúng sanh.`, ref: "Tương Ưng Bộ 1.2", url: "https://loicuaducphat.org/sn/sn1.2.html#content" },

{ text: `… Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nMạng sống bị dắt dẫn,\nTuổi thọ chẳng là bao,\nBị dẫn đến già nua,\nKhông có nơi dừng bước.\nAi đem tâm quán tưởng,\nSợ hãi tử vong này,\nHãy làm các công đức,\nÐưa đến chơn an lạc.\n\n(Thế Tôn):\nMạng sống bị dắt dẫn,\nTuổi thọ chẳng là bao,\nBị dẫn đến già nua,\nKhông có nơi dừng bước.\nAi đem tâm quán tưởng,\nSợ hãi tử vong này,\nHãy bỏ mọi thế lợi,\nTâm hướng cầu tịch tịnh.`, ref: "Tương Ưng Bộ 1.3", url: "https://loicuaducphat.org/sn/sn1.3.html#content" },

{ text: `… Nhân duyên ở (Sāvatthi ), đứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nThời gian lặng trôi qua,\nÐêm ngày luôn di động,\nTuổi tác buổi thanh xuân,\nTiếp tục bỏ chúng ta.\nNhững ai chịu quán sát,\nSợ hãi tử vong này,\nHãy làm các công đức,\nÐưa đến chơn an lạc.\n\n(Thế Tôn):\nThời gian lặng trôi qua,\nÐêm ngày luôn di động,\nTuổi tác buổi thanh xuân,\nTiếp tục bỏ chúng ta.\nNhững ai chịu quán sát,\nSợ hãi tử vong này,\nHãy bỏ mọi thế lợi,\nTâm hướng cầu tịch tịnh.`, ref: "Tương Ưng Bộ 1.4", url: "https://loicuaducphat.org/sn/sn1.4.html#content" },

{ text: `… Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nPhải cắt đoạn bao nhiêu,\nPhải từ bỏ bao nhiêu,\nTu tập thêm bao nhiêu,\nVượt qua bao trói buộc,\nÐể được có danh xưng,\nTỷ-kheo vượt bộc lưu?\n\n(Thế Tôn):\nPhải cắt đoạn đến năm,\nPhải từ bỏ đến năm,\nTu tập thêm năm pháp (lực),\nVượt qua năm trói buộc,\nÐể được có danh xưng,\nTỷ-kheo “vượt bộc lưu”.`, ref: "Tương Ưng Bộ 1.5", url: "https://loicuaducphat.org/sn/sn1.5.html#content" },

{ text: `… Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nCó bao pháp mê ngủ,\nKhi pháp khác tỉnh giác?\nCó bao pháp tỉnh giác,\nKhi pháp khác mê ngủ?\nCó bao nhiêu việc làm\nÐưa ta đến trần cấu?\nCó bao nhiêu việc làm\nKhiến ta được thanh tịnh?\n\n(Thế Tôn):\nCó năm pháp mê ngủ,\nKhi pháp khác tỉnh giác,\nCó năm pháp tỉnh giác,\nKhi pháp khác mê ngủ.\nChính có năm việc làm\nÐưa ta đến trần cấu,\nChính có năm việc làm]\nKhiến ta được thanh tịnh.`, ref: "Tương Ưng Bộ 1.6", url: "https://loicuaducphat.org/sn/sn1.6.html#content" },

{ text: `Những ai đối các pháp,\nQuá đắm say mê loạn,\nBị hướng dẫn lầm lạc,\nVòng quanh các dị giáo,\nHọ mê ngủ triền miên,\nHọ không có tỉnh giác,\nNay thật đã đến thời,\nHọ cần phải thức tỉnh.\n\n(Thế Tôn):\nNhững ai đối các pháp,\nKhông đắm say mê loạn,\nKhông bị dẫn lầm lạc,\nVòng quanh các dị giáo,\nHọ chứng Chánh đẳng giác.\nHọ liễu tri viên mãn,\nTrên đường không thăng bằng,\nHọ bước thật thăng bằng.`, ref: "Tương Ưng Bộ 1.8", url: "https://loicuaducphat.org/sn/sn1.8.html#content" },

{ text: `… Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nÐối vị ưa kiêu mạn,\nỞ đây không điều phục,\nKhông trí tuệ sáng suốt,\nKhông định tĩnh nhiếp tâm,\nÐộc thân trú rừng núi,\nSống với tâm phóng dật,\nVị ấy không vượt khỏi,\nSự chi phối ma lực.\n\n(Thế Tôn):\n\nTừ bỏ mọi kiêu mạn,\nTâm tư khéo nhiếp định,\nVới tâm khéo tư sát,\nGiải thoát mọi phiền trược,\nÐộc thân trú rừng núi (giới),\nVới tâm không phóng dật,\nVị ấy vượt thoát khỏi,\nSự chi phối ma lực.`, ref: "Tương Ưng Bộ 1.9", url: "https://loicuaducphat.org/sn/sn1.9.html#content" },

{ text: `… Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nThường sống trong rừng núi,\nBậc Thánh sống Phạm hạnh,\nMột ngày ăn một buổi,\nSao sắc họ thù diệu?\n\n(Thế Tôn):\nKhông than việc đã qua,\nKhông mong việc sắp tới,\nSống ngay với hiện tại,\nDo vậy, sắc thù diệu.\n\nDo mong việc sắp tới,\nDo than việc đã qua,\nNên kẻ ngu héo mòn,\nNhư lau xanh rời cành.`, ref: "Tương Ưng Bộ 1.10", url: "https://loicuaducphat.org/sn/sn1.10.html#content" },

{ text: `Kẻ ngu, sao không biết,\nVị Ứng cúng đã nói:\n“Mọi hành là vô thường,\nTự tánh phải sanh diệt,\nSau khi sanh, chúng diệt,\nNhiếp chúng là an lạc.”`, ref: "Tương Ưng Bộ 1.11", url: "https://loicuaducphat.org/sn/sn1.11.html#content" },

{ text: `… Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nCha đối con vui thích,\nChủ với bò vui thích,\nNgười sanh y, vui thích,\nKhông sanh y, không vui.\n\n(Thế Tôn):\nCha đối con sầu muộn,\nChủ với bò sầu muộn,\nNgười sanh y, sầu muộn,\nKhông sanh y, không sầu.`, ref: "Tương Ưng Bộ 1.12", url: "https://loicuaducphat.org/sn/sn1.12.html#content" },

{ text: `… Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nThương ai bằng thương con,\nCủa nào bằng bò nhà,\nSáng nào bằng mặt trời,\nNước nào hơn biển cả.\n\n(Thế Tôn):\nThương ai bằng thương mình,\nCủa nào bằng lúa gạo,\nSáng nào bằng trí tuệ,\nNước nào hơn mưa rào.`, ref: "Tương Ưng Bộ 1.13", url: "https://loicuaducphat.org/sn/sn1.13.html#content" },

{ text: `(Thế Tôn):\nGiữa các loài hai chân,\nChánh giác là tối thắng.\nGiữa các loài bốn chân,\nThuần chủng là tối thắng.\nTrong các hàng thê thiếp,\nNhu thuận là tối thắng.\nTrong các hàng con trai,\nTrung thành là tối thắng.`, ref: "Tương Ưng Bộ 1.14", url: "https://loicuaducphat.org/sn/sn1.14.html#content" },

{ text: `Nay là thời giữa trưa,\nLoài chim nghỉ yên lặng,\nVang động tiếng rừng sâu,\nTa run, ta khiếp sợ.\n\n(Thế Tôn):\nNay là thời giữa trưa,\nLoài chim nghỉ yên lặng,\nVang động tiếng rừng sâu,\nTa vui, Ta thích thú.`, ref: "Tương Ưng Bộ 1.15", url: "https://loicuaducphat.org/sn/sn1.15.html#content" },

{ text: `Ngủ gục, nhác, ngáp dài,\nKhông vui, ăn quá độ,\nỞ đây, đối chúng sanh,\nThánh đạo không hiển lộ.\nNgủ gục, nhác, ngáp dài,\nKhông vui, ăn quá độ,\nVới tinh tấn, đoạn chúng,\nThánh đạo được thanh tịnh.`, ref: "Tương Ưng Bộ 1.16", url: "https://loicuaducphat.org/sn/sn1.16.html#content" },

{ text: `Khó làm, khó kham nhẫn,\nThiếu trí, hành Sa-môn,\nChỗ kẻ ngu thối đọa,\nChỗ ấy đầy chướng ngại.\nBao ngày hành Sa-môn\nNếu tâm không chế ngự,\nMỗi bước, phải sa đọa,\nNô lệ cho suy tư,\nNhư rùa rút chân cẳng,\nTrong mai rùa của mình.\nVị Tỷ-kheo cũng vậy,\nThâu nhiếp mọi suy tư,\nKhông tham dính vật gì,\nKhông làm hại người nào,\nHoàn toàn thật tịch tịnh,\nKhông chỉ trích một ai.`, ref: "Tương Ưng Bộ 1.17", url: "https://loicuaducphat.org/sn/sn1.17.html#content" },

{ text: `Người được tàm chế ngự,\nTìm được ai ở đời?\nAi biết ngăn chỉ trích,\nNhư ngựa hiền bóng roi.\nNgười được tàm chế ngự,\nSống thường thường chánh niệm,\nVị ấy đạt kết quả,\nKhổ đau được đoạn tận,\nBước những bước thăng bằng,\nTrên đường không thăng bằng.`, ref: "Tương Ưng Bộ 1.18", url: "https://loicuaducphat.org/sn/sn1.18.html#content" },

{ text: `Ngài không có am tranh,\nNgài không có tổ ấm,\nNgài không có dây giăng,\nNgài thoát khỏi hệ phược.\n\n(Thế Tôn):\nTa không có am tranh,\nTa không có tổ ấm,\nTa không có dây giăng,\nTa thoát khỏi hệ phược.\n\n(Vị Thiên):\nCon nói am là gì?\nNói tổ ấm là gì?\nNói dây giăng là gì?\nNói hệ phược là gì?\n\n(Thế Tôn):\nÔng nói am là mẹ,\nNói tổ ấm là vợ,\nNói dây giăng là con,\nNói hệ phược là ái.\n\n(Vị Thiên):\nLành thay, Ngài không am!\nLành thay, không tổ ấm!\nLành thay, không dây giăng!\nLành thay, Ngài thoát phược!`, ref: "Tương Ưng Bộ 1.19", url: "https://loicuaducphat.org/sn/sn1.19.html#content" },

{ text: `- Này Hiền giả, ta không bỏ hiện tại và chạy theo những gì bị thời gian chi phối. Và này Hiền giả, chính ta bỏ những gì bị thời gian chi phối để chạy theo hiện tại. Này Hiền giả, Thế Tôn đã nói, các dục bị thời gian chi phối, nhiều khổ đau, nhiều phiền não (Upàyàsà); nguy hiểm ở đấy càng nhiều hơn. Còn pháp này thuộc về hiện tại, không bị thời gian chi phối, đến để mà thấy, có khả năng hướng thượng, chỉ người trí mới tự mình giác hiểu.`, ref: "Tương Ưng Bộ 1.20", url: "https://loicuaducphat.org/sn/sn1.20.html#content" },

{ text: `(Thế Tôn):\nBằng, thắng hay thua Ta,\nNghĩ vậy đấu tranh khởi;\nCả ba không dao động,\nBằng, thắng không khởi lên.\n\nHãy từ bỏ tính toán,\nKhông chạy theo hư tưởng,\nTừ bỏ mọi tham ái,\nÐối danh sắc ở đời,\nVị ấy đoạn triền phược,\nKhông lo âu, không ái.\nChư Thiên và loài Người,\nÐời này hay đời sau,\nỞ cảnh giới chư Thiên,\nHay tại mọi trú xứ,\nTìm cầu nhưng không gặp,\nVết tích của vị ấy.\n\nKhắp thế giới chớ làm,\nÐiều ác thân, miệng, ý,\nTừ bỏ mọi ái dục,\nChánh niệm, tâm tỉnh giác,\nKhông khổ hạnh ép xác,\nVô bổ, không lợi ích.`, ref: "Tương Ưng Bộ 1.20", url: "https://loicuaducphat.org/sn/sn1.20.html#content" },

{ text: `… (Nhân duyên ở Sāvatthi). Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nNhư kiếm đã chạm da,\nNhư lửa cháy trên đầu,\nTỷ-kheo hãy chánh niệm,\nXuất gia bỏ ái dục.\n\n(Thế Tôn):\nNhư kiếm đã chạm da,\nNhư lửa cháy trên đầu,\nTỷ-kheo hãy chánh niệm,\nXuất gia bỏ thân kiến.`, ref: "Tương Ưng Bộ 1.21", url: "https://loicuaducphat.org/sn/sn1.21.html#content" },

{ text: `Nội triền và ngoại triền,\nChúng sanh bị triền phược,\nCon hỏi Gotama,\nAi thoát khỏi triền này?\n\n(Thế Tôn):\nNgười trú giới có trí,\nTu tập tâm và tuệ,\nNhiệt tâm và thận trọng,\nTỷ-kheo ấy thoát triền.\nVới ai, đã từ bỏ\nTham, sân và vô minh,\nBậc Lậu tận, Ứng cúng,\nVị ấy thoát triền phược.\nChỗ nào danh và sắc,\nÐược đoạn tận, vô dư,\nÐoạn chướng ngại, sắc tưởng,\nChỗ ấy triền phược đoạn.`, ref: "Tương Ưng Bộ 1.23", url: "https://loicuaducphat.org/sn/sn1.23.html#content" },

{ text: `Chỗ nào ý chế ngự,\nChỗ ấy đau khổ tận.\nÝ chế ngự hoàn toàn,\nThoát đau khổ hoàn toàn.\n\n(Thế Tôn):\nKhông nên chế ngự ý,\nHoàn toàn về mọi mặt,\nChớ có chế ngự ý,\nNếu tự chủ đạt được.\nChỗ nào ác pháp khởi,\nChỗ ấy chế ngự ý.`, ref: "Tương Ưng Bộ 1.24", url: "https://loicuaducphat.org/sn/sn1.24.html#content" },

{ text: `Vị Tỷ-kheo La-hán,\nÐã làm điều phải làm,\nCác lậu được đoạn tận,\nThân này, thân tối hậu.\nVị ấy có thể nói:\n“Chính tôi vừa nói lên”\nVị ấy có thể nói:\n“Họ nói là của tôi”?\n\n(Thế Tôn):\nVị Tỷ-kheo La-hán,\nÐã làm điều phải làm,\nCác lậu được đoạn tận,\nThân này, thân tối hậu.\nVị ấy có thể nói:\n“Chính tôi vừa nói lên”,\nVị ấy có thể nói:\n“Họ nói là của tôi”.\nVị ấy khéo biết rõ,\nDanh xưng ở thế gian,\nVì chỉ là danh xưng,\nVị ấy cũng danh xưng.`, ref: "Tương Ưng Bộ 1.25", url: "https://loicuaducphat.org/sn/sn1.25.html#content" },

{ text: `(Vị Thiên):\nVị Tỷ-kheo La-hán,\nÐã làm điều phải làm,\nCác lậu được đoạn tận,\nThân này, thân tối hậu.\nCó phải Tỷ-kheo ấy,\nÐi gần đến kiêu mạn,\nKhi vị ấy có nói:\n“Chính tôi vừa nói lên”.\nKhi vị ấy có nói:\n“Họ nói là của tôi”?\n\n(Thế Tôn):\nAi đoạn tận kiêu mạn,\nKhông còn những buộc ràng,\nMọi hệ phược kiêu mạn,\nÐược hoàn toàn đoạn tận.\nVị có trí sáng suốt,\nVượt khỏi mọi hư tưởng,\nVị ấy có thể nói:\n“Chính tôi vừa nói lên”,\nVị ấy có thể nói:\n“Họ nói là của tôi”.\nVị ấy khéo biết rõ,\nDanh xưng ở thế gian,\nVì chỉ là danh xưng,\nVị ấy cũng danh xưng.`, ref: "Tương Ưng Bộ 1.25", url: "https://loicuaducphat.org/sn/sn1.25.html#content" },

{ text: `Vật gì chiếu sáng đời,\nDo chúng, đời chói sáng?\nCon đến hỏi Thế Tôn,\nMuốn biết lời giải đáp.\n\n(Thế Tôn):\nBốn vật chiếu sáng đời,\nThứ năm, đây không có.\nNgày, mặt trời sáng chói,\nÐêm, mặt trăng tỏ rạng,\nLửa cháy đỏ đêm ngày,\nChói sáng khắp mọi nơi.\nChánh giác sáng tối thắng,\nSáng này, sáng vô thượng.`, ref: "Tương Ưng Bộ 1.26", url: "https://loicuaducphat.org/sn/sn1.26.html#content" },

{ text: `Chỗ nào nước chảy ngược?\nChỗ nào nước xoáy dừng?\nChỗ nào danh và sắc,\nÐược đoạn diệt, không dư?\nChỗ nào nước và đất,\nLửa, gió không vững trú,\nDo vậy nước chảy ngược,\nChỗ ấy nước xoáy dừng,\nChỗ ấy danh và sắc,\nÐược đoạn diệt, không dư.`, ref: "Tương Ưng Bộ 1.27", url: "https://loicuaducphat.org/sn/sn1.27.html#content" },

{ text: `Sát-đế-lỵ giàu lớn,\nTài sản, quốc độ lớn,\nLuôn luôn ganh tị nhau,\nHưởng dục không biết ngán,\nGiữa người sống dao động,\nTrôi theo dòng tái sanh.\nAi bỏ tật và ái,\nKhông dao động giữa đời.\n\n(Thế Tôn):\nVị xuất gia bỏ nhà,\nBỏ con, gia súc, thân,\nBỏ tham và bỏ sân,\nVà từ bỏ vô minh,\nBậc Lậu tận, La-hán,\nKhông dao động giữa đời.`, ref: "Tương Ưng Bộ 1.28", url: "https://loicuaducphat.org/sn/sn1.28.html#content" },

{ text: `Bốn bánh xe, chín cửa,\nÐầy uế, hệ lụy tham,\nChìm đắm trong bùn nhơ,\nÔi, thưa bậc Ðại Hùng,\nSanh thú người như vậy,\nTương lai sẽ thế nào?\n\n(Thế Tôn):\nCắt hỷ và buộc ràng,\nDục tham và tà ác,\nÁi căn được đoạn tận,\nSanh thú sẽ như vậy.`, ref: "Tương Ưng Bộ 1.29", url: "https://loicuaducphat.org/sn/sn1.29.html#content" },

{ text: `Chân như chân sơn dương,\nVừa thon lại vừa mạnh,\nĂn uống có chừng mực,\nKhông tham lam, say đắm,\nNhư sư tử, voi rừng,\nÐộc hành, không dục vọng.\nSau khi đến, con hỏi,\nLàm sao thoát khổ đau?\n\n(Thế Tôn):\nCó năm dục ở đời,\nÝ căn là thứ sáu,\nỞ đây, từ ước muốn,\nNhư vậy thoát khổ đau.`, ref: "Tương Ưng Bộ 1.30", url: "https://loicuaducphat.org/sn/sn1.30.html#content" },

{ text: `Hãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nÐược tốt hơn, không xấu.\n\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nKhông sầu, giữa sầu muộn.\n\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nChúng sanh sanh thiện thú.\n\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nChúng sanh thường hưởng lạc.\n\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nGiải thoát mọi khổ đau.`, ref: "Tương Ưng Bộ 1.31", url: "https://loicuaducphat.org/sn/sn1.31.html#content" },

{ text: `Ðứng một bên, một vị Thiên nói lên bài kệ này trước mặt Thế Tôn:\nVì xan tham, phóng dật,\nNhư vậy không bố thí,\nAi ước mong công đức,\nCó trí nên bố thí.\n\nRồi một vị Thiên khác nói lên bài kệ này trước mặt Thế Tôn:\nÐiều kẻ xan tham sợ,\nNên không dám bố thí,\nSợ ấy đến với họ,\nChính vì không bố thí.\nÐiều kẻ xan tham sợ,\nChính là đói và khát,\nKẻ ngu phải cảm thọ,\nÐời này và đời sau.\nVậy hãy chế xan tham,\nBố thí, nhiếp cấu uế,\nChúng sanh vững an trú,\nCông đức trong đời sau.`, ref: "Tương Ưng Bộ 1.32", url: "https://loicuaducphat.org/sn/sn1.32.html#content" },

{ text: `Rồi một vị Thiên khác nói lên bài kệ này trước mặt Thế Tôn:\nKhó thay sự đem cho,\nKhó thay làm hạnh ấy.\nKẻ ác khó tùy thuận,\nKhó thay pháp bậc lành.\nDo vậy kẻ hiền, ác,\nSanh thú phải sai khác,\nKẻ ác sanh địa ngục,\nNgười lành lên cõi trời.\n\nSở hành vẫn chơn chánh,\nDầu phải sống vụn vặt,\nDầu phải nuôi vợ con,\nVới đồ ăn lượm lặt,\nNhưng vẫn bố thí được,\nTừ vật chứa ít ỏi,\nTừ ngàn người bố thí,\nTừ trăm ngàn vật cho,\nTrị giá không ngang bằng,\nKẻ bố thí như vậy.`, ref: "Tương Ưng Bộ 1.32", url: "https://loicuaducphat.org/sn/sn1.32.html#content" },

{ text: `Rồi một vị Thiên khác nói lên bài kệ này với Thế Tôn:\nVì sao họ bố thí,\nRộng lớn nhiều như vậy,\nTrị giá không ngang bằng,\nKẻ nghèo, chơn bố thí?\nSao ngàn người bố thí,\nTừ trăm ngàn vật cho,\nTrị giá không ngang bằng,\nKẻ bố thí như vậy?\n\nRồi Thế Tôn nói lên bài kệ này với vị Thiên ấy:\nCó những người bố thí,\nMột cách bất bình thường,\nSau khi chém và giết,\nMới làm vơi nỗi sầu.\nSự bố thí như vậy,\nÐầy nước mắt đánh đập,\nTrị giá không ngang bằng,\nKẻ nghèo, chơn bố thí.\nTừ ngàn người bố thí,\nTừ trăm ngàn vật cho,\nTrị giá không ngang bằng,\nKẻ bố thí như vậy.`, ref: "Tương Ưng Bộ 1.32", url: "https://loicuaducphat.org/sn/sn1.32.html#content" },

{ text: `Ðứng một bên, một vị Thiên nói lên lời cảm hứng này trước mặt Thế Tôn:\nLành thay sự bố thí!\nKính thưa bậc Tôn giả.\nVì xan tham, phóng dật,\nNhư vậy không bố thí,\nAi ước mong công đức,\nCó trí nên bố thí.`, ref: "Tương Ưng Bộ 1.33", url: "https://loicuaducphat.org/sn/sn1.33.html#content" },

{ text: `Rồi một vị Thiên khác nói lên lời cảm hứng này trước mặt Thế Tôn:\nLành thay sự bố thí,\nKính thưa bậc Tôn giả!\nNhưng thật tốt lành thay,\nBố thí trong thiếu thốn!\nLành thay sự bố thí,\nPhát xuất từ lòng tin!\nLành thay sự bố thí,\nVới tài sản hợp pháp!\nAi là người bố thí,\nVới tàn sản hợp pháp,\nDo nỗ lực tinh tấn,\nNhờ vậy thâu hoạch được;\nVị ấy vượt dòng suối,\nThần chết Dạ-ma giới,\nSau khi chết được sanh,\nChỗ trú xứ chư Thiên.`, ref: "Tương Ưng Bộ 1.33", url: "https://loicuaducphat.org/sn/sn1.33.html#content" },

{ text: `Rồi một vị Thiên khác nói lên lời cảm hứng này trước mặt Thế Tôn:\nLành thay sự bố thí,\nKính thưa bậc Tôn giả!\nNhưng thật tốt lành thay,\nBố thí trong thiếu thốn!\nLành thay sự bố thí,\nPhát xuất từ lòng tin!\nLành thay sự bố thí,\nVới tài sản hợp pháp!\nLành thay sự bố thí,\nCó suy tư sáng suốt!\nBố thí có suy tư,\nBậc Thiện Thệ tán thán.\nBố thí cho những vị,\nÐáng kính trọng ở đời,\nBố thí những vị ấy,\nÐược hưởng quả phước lớn,\nNhư hạt giống tốt đẹp,\nGieo vào ruộng tốt lành.`, ref: "Tương Ưng Bộ 1.33", url: "https://loicuaducphat.org/sn/sn1.33.html#content" },

{ text: `Bố thí với lòng tin,\nÐược tán thán nhiều mặt,\nCó pháp hơn bố thí,\nPháp ấy là Pháp cú.\nTừ xưa, từ xa xưa,\nNgười lành, người chơn thiện,\nVới trí tuệ sáng suốt,\nÐạt đến cảnh Niết-bàn.`, ref: "Tương Ưng Bộ 1.33", url: "https://loicuaducphat.org/sn/sn1.33.html#content" },

{ text: `Ðứng một bên, một vị Thiên nói lên bài kệ này trước mặt Thế Tôn:\nGiữa loài Người chúng ta,\nCó các dục vô thường.\nAi hưởng chúng ở đời,\nBị chúng trói, chúng buộc.\nPhóng dật đối với chúng,\nKhó thoát ly với chúng,\nNgười nào khó thoát ly,\nBị thần chết chinh phục.\nHọa từ dục vọng sanh,\nKhổ từ dục vọng khởi,\nDục vọng được nhiếp phục,\nNhờ vậy họa nhiếp phục,\nTai họa được nhiếp phục,\nNhờ vậy khổ nhiếp phục.\nVật sai biệt ở đời,\nChúng không phải các dục,\nChính tư niệm tham ái,\nLà dục vọng con người.\nVật sai biệt tồn tại,\nNhư vậy ở trên đời,\nDo vậy bậc Hiền trí,\nÐiều phục các dục vọng.\nHãy từ bỏ phẫn nộ,\nHãy nhiếp phục kiêu mạn,\nHãy vượt qua tất cả,\nMọi kiết sử trói buộc.\nChớ có quá chấp trước,\nÐối với danh sắc ấy,\nKhổ không thể đến được,\nVới ai không có gì.\nHãy từ bỏ tính toán,\nKhông chạy theo hư tưởng,\nCắt đứt mọi tham ái,\nVới danh sắc ở đời.\nVị ấy đoạn phiền trược,\nKhông lo âu, không ái;\nChư Thiên và loài Người,\nÐời này hay đời sau,\nỞ cảnh giới chư Thiên,\nHay tại mọi trú xứ,\nTìm cầu nhưng không gặp,\nVết tích của vị ấy,\nHọ tìm nhưng không thấy,\nVị giải thoát như vậy.`, ref: "Tương Ưng Bộ 1.34", url: "https://loicuaducphat.org/sn/sn1.34.html#content" },

{ text: `Ðứng một bên, một vị Thiên nói lên bài kệ này trước mặt Thế Tôn:\nTín là người thứ hai,\nLà bạn của loài Người,\nNếu không trú bất tín,\nÐược danh dự, xưng tán,\nSau khi bỏ thân này,\nÐược sanh lên Thiên giới.\nHãy từ bỏ phẫn nộ,\nHãy nhiếp phục kiêu mạn,\nHãy vượt qua tất cả\nMọi kiết sử trói buộc.\nChớ có quá chấp trước,\nÐối với danh sắc ấy.\nTham không thể đến được,\nVới ai không có gì.\nKẻ ngu không trí tuệ,\nMới đam mê, phóng dật,\nKẻ trí không phóng dật,\nNhư giữ tài vật quý.\nChớ đam mê, phóng dật,\nChớ đắm say ái dục,\nThiền tư, không phóng dật,\nÐạt được tối thắng lạc.`, ref: "Tương Ưng Bộ 1.36", url: "https://loicuaducphat.org/sn/sn1.36.html#content" },

{ text: `Rồi các vị Thiên khác cũng đọc lên một bài kệ trước Thế Tôn:\nTại đây chúng Tỷ-kheo,\nThiền định, tâm chánh trực,\nNhư chủ xe nắm cương,\nBậc hiền hộ các căn.\n\nLại một vị Thiên khác cũng đọc lên một bài kệ trước Thế Tôn:\nNhư khóa gãy, chốt tháo,\nTrụ bị đào, tham đoạn,\nSống thanh tịnh, vô cấu,\nCó mắt, voi khéo điều.\n\nLại một vị Thiên khác cũng đọc lên một bài kệ trước mặt Thế Tôn:\nNhững ai quy y Phật,\nSẽ không đọa ác thú,\nSau khi bỏ thân Người,\nSẽ sanh làm chư Thiên.`, ref: "Tương Ưng Bộ 1.37", url: "https://loicuaducphat.org/sn/sn1.37.html#content" },

{ text: `Rồi một vị Thiên khác nói lên lời cảm hứng này trước mặt Thế Tôn:\n\nCác vị Bà-la-môn,\nTinh thông năm Vệ-đà,\nDầu tu tập khổ hạnh,\nCho đến hàng trăm năm,\nTâm họ không có thể,\nChơn chánh được giải thoát.\nTự tánh quá hạ liệt,\nKhông đến bờ bên kia,\nBị khát ái chi phối,\nBị giới cấm trói buộc,\nDầu tu tập khổ hạnh,\nCho đến hàng trăm năm,\nTâm họ không có thể,\nChơn chánh được giải thoát.\nTự tánh quá hạ liệt,\nKhông đến bờ bên kia.\nỞ đời không nhiếp phục,\nKiêu mạn cùng các dục,\nTâm không được an tịnh,\nKhông tu tập Thiền định.\nỞ trong rừng cô độc,\nNhưng tâm tư phóng dật,\nVị ấy khó vượt khỏi,\nSự chinh phục tử thần.\nNhiếp phục được kiêu mạn,\nKhéo tu tập Thiền định,\nTâm tư khéo an tịnh,\nGiải thoát được viên mãn,\nỞ trong rừng cô độc,\nTâm tư không phóng dật,\nVị ấy khéo vượt khỏi,\nSự chinh phục tử thần.`, ref: "Tương Ưng Bộ 1.38", url: "https://loicuaducphat.org/sn/sn1.38.html#content" },

{ text: `Lúc bấy giờ, chân Thế Tôn bị miếng đá bể đâm phải. Cảm thọ Thế Tôn mãnh liệt. Thân cảm thọ khổ đau, nhói đau, nhức nhối, khốc liệt, không khoái tâm, không thích thú. Nhưng Thế Tôn chánh niệm tỉnh giác, nhẫn chịu, không phiền não. Rồi Thế Tôn cho trải áo Sanghàti xếp tư lại, nằm xuống phía hông bên phải như dáng điệu con sư tử, chân đặt trên chân, chánh niệm tỉnh giác.\n\nÐứng một bên, một vị Thiên đọc lên lời cảm hứng này trước mặt Thế Tôn:\n- Sa-môn Gotama thật là bậc Long tượng. Và với tư cách Long tượng, Ngài nhẫn chịu thân thọ khởi lên, đau khổ, nhói đau, nhức nhối, khốc liệt, không khoái tâm, không thích thú, Ngài chánh niệm tỉnh giác, nhẫn chịu, không phiền não.`, ref: "Tương Ưng Bộ 1.38", url: "https://loicuaducphat.org/sn/sn1.38.html#content" },

{ text: `Ðứng một bên, vị Thiên ấy nói lên bài kệ này trước mặt Thế Tôn:\nTrong ngôi nhà thiêu cháy,\nVật dụng đem ra ngoài,\nVật ấy có lợi ích,\nKhông phải vật bị thiêu.\nCũng vậy trong đời này,\nBị già chết thiêu cháy,\nHãy đem ra, bằng thí,\nVật thí, khéo đem ra.\nCó thí, có lạc quả,\nKhông thí, không như vậy.\nKẻ trộm, vua cướp đoạt,\nLửa thiêu đốt hủy hoại,\nKhi giờ cuối cùng đến,\nBỏ thân, bỏ sở hữu.\nKẻ trí, hiểu biết vậy,\nThọ dụng và bố thí,\nThí xong, thọ dụng xong,\nTheo lực hành động ấy,\nKhông bị ai chỉ trích,\nVị ấy được sanh Thiên.`, ref: "Tương Ưng Bộ 1.41", url: "https://loicuaducphat.org/sn/sn1.41.html#content" },

{ text: `Cho gì là cho lực?\nCho gì là cho sắc?\nCho gì là cho lạc?\nCho gì là cho mắt?\nCho gì cho tất cả?\nXin đáp điều con hỏi?\n\n(Thế Tôn):\nCho ăn là cho lực,\nCho mặc là cho sắc,\nCho xe là cho lạc,\nCho đèn là cho mắt.\nAi cho chỗ trú xứ,\nVị ấy cho tất cả,\nAi giảng dạy Chánh pháp,\nVị ấy cho bất tử.`, ref: "Tương Ưng Bộ 1.42", url: "https://loicuaducphat.org/sn/sn1.42.html#content" },

{ text: `Trời, Người, cả hai loài,\nÐều ưa thích ăn uống,\nVị Dạ-xoa tên gì,\nLại không thích ăn uống?\n\n(Thế Tôn):\nAi cho với lòng tin,\nVới tâm tư thanh tịnh,\nÐược phần món ăn ấy,\nÐời này và đời sau.\nVậy hãy ngừa xan tham,\nBố thí, nhiếp cấu uế,\nHữu tình vững an trú,\nCông đức trong đời sau.`, ref: "Tương Ưng Bộ 1.43", url: "https://loicuaducphat.org/sn/sn1.43.html#content" },

{ text: `Những ai ngày lẫn đêm,\nCông đức luôn tăng trưởng,\nTrú pháp, cụ túc giới,\nKẻ nào sanh thiên giới?\nAi trồng vườn, trồng rừng,\nAi dựng xây cầu cống,\nÐào giếng, cho nước uống,\nNhững ai cho nhà cửa,\nNhững vị ấy ngày đêm,\nCông đức luôn tăng trưởng,\nTrú pháp, cụ túc giới,\nNhững vị ấy sanh Thiên.`, ref: "Tương Ưng Bộ 1.47", url: "https://loicuaducphat.org/sn/sn1.47.html#content" },

{ text: `(Thế Tôn):\nỞ đời kẻ xan tham,\nKeo kiết hay khước từ,\nTạo nên những chướng ngại,\nNgăn kẻ khác bố thí,\nBị tái sanh địa ngục,\nBàng sanh, Dạ-ma giới.\nNếu được sanh làm người,\nSanh gia đình nghèo khó,\nY, thực, dục, hỷ lạc,\nHọ được rất khó khăn.\nÐiều kẻ ngu ước vọng,\nHọ không thâu hoạch được,\nQuả hiện tại là vậy,\nÐời sau sanh ác thú.`, ref: "Tương Ưng Bộ 1.49", url: "https://loicuaducphat.org/sn/sn1.49.html#content" },

{ text: `(Thế Tôn):\nỞ đây được thân người,\nTừ tốn không xan tham,\nTin Phật và Chánh pháp,\nCùng tôn trọng chúng Tăng,\nHọ chói sáng chư Thiên,\nTại đấy họ tái sanh.\nNếu họ sanh làm người,\nHọ sanh nhà phú gia,\nY, thực, dục, hỷ lạc,\nHọ được không khó khăn,\nNhư các Tự tại thiên,\nHân hoan được thọ hưởng,\nGiữa vật dụng tài sản,\nÐược người khác quy tụ,\nQuả hiện tại là vậy,\nÐời sau sanh Thiên giới.`, ref: "Tương Ưng Bộ 1.49", url: "https://loicuaducphat.org/sn/sn1.49.html#content" },

{ text: `- Vật gì tốt đến già?\nVật gì tốt kiên trú?\nVật gì vật báu người?\nVật gì cướp khó đoạt?\n- Giới là tốt đến già,\nTín là tốt kiên trú,\nTuệ, vật báu loài Người,\nCông đức, cướp khó đoạt .`, ref: "Tương Ưng Bộ 1.51", url: "https://loicuaducphat.org/sn/sn1.51.html#content" },

{ text: `- Vật gì tốt không già?\nVật gì tốt trường cửu?\nVật gì vật báu người?\nVật gì cướp không đoạt?\n- Giới là tốt không già,\nTín là tốt trường cửu,\nTuệ, vật báu loài Người,\nCông đức, cướp không đoạt.`, ref: "Tương Ưng Bộ 1.52", url: "https://loicuaducphat.org/sn/sn1.52.html#content" },

{ text: `- Ai bạn kẻ đi đường?\nAi bạn người ở nhà?\nAi bạn khi cần thiết?\nAi bạn cho đời sau?\nBạn đường, bạn đi đường,\n- Bạn ở nhà là mẹ,\nBạn bè khi cần thiết,\nMới là bạn thường xuyên,\nCông đức tự mình làm,\nLà bạn cho đời sau.`, ref: "Tương Ưng Bộ 1.53", url: "https://loicuaducphat.org/sn/sn1.53.html#content" },

{ text: `- Cái gì sanh thành người?\nCái gì luôn dong ruổi?\nCái gì chịu luân hồi?\nCái gì người sợ hãi?\n- Ái dục sanh thành người,\nChính tâm luôn dong ruỗi,\nChúng sanh chịu luân hồi,\nÐau khổ, người sợ hãi.`, ref: "Tương Ưng Bộ 1.55", url: "https://loicuaducphat.org/sn/sn1.55.html#content" },

{ text: `- Cái gì sanh thành người?\nCái gì luôn dong ruỗi?\nCái gì chịu luân hồi?\nVì đâu, không giải thoát?\n- Ái dục sanh thành người,\nChính tâm luôn dong ruỗi,\nChúng sanh chịu luân hồi,\nVì khổ, không giải thoát.`, ref: "Tương Ưng Bộ 1.56", url: "https://loicuaducphat.org/sn/sn1.56.html#content" },

{ text: `- Cái gì sanh thành người?\nCái gì luôn dong ruỗi?\nCái gì chịu luân hồi?\nCái gì người nương tựa?\n- Ái dục sanh thành người,\nChính tâm luôn dong ruỗi,\nChúng sanh chịu luân hồi,\nChính nghiệp, người nương tựa.`, ref: "Tương Ưng Bộ 1.57", url: "https://loicuaducphat.org/sn/sn1.57.html#content" },
{ text: `- Cái gì gọi phi đạo?\nCái gì diệt ngày đêm?\nCái gì uế Phạm hạnh?\nCái gì tắm không nước?\n- Tham dục gọi phi đạo,\nTuổi tác diệt ngày đêm,\nNữ nhân uế Phạm hạnh,\nKhiến loài Người hệ lụy,\nKhổ hạnh và Phạm hạnh,\nLà tắm không cần nước.`, ref: "Tương Ưng Bộ 1.58", url: "https://loicuaducphat.org/sn/sn1.58.html#content" },

{ text: `- Cái gì làm người bạn?\nCái gì giáo hóa người?\nCái gì người ái lạc?\nGiải thoát mọi khổ đau?\n- Tín thành làm bạn người,\nTrí tuệ giáo hóa người,\nNgười ái lạc Niết-bàn,\nGiải thoát mọi khổ đau.`, ref: "Tương Ưng Bộ 1.59", url: "https://loicuaducphat.org/sn/sn1.59.html#content" },

{ text: `- Vật gì thắng tất cả?\nVật gì không số hơn?\nVà có một pháp nào,\nMọi vật đều tùy thuộc?\n\n- Danh vượt thắng tất cả,\nDanh không số nào hơn,\nChính danh là một pháp,\nMọi vật đều tùy thuộc.`, ref: "Tương Ưng Bộ 1.61", url: "https://loicuaducphat.org/sn/sn1.61.html#content" },

{ text: `- Vật gì dắt dẫn đời?\nVật gì tự não hại?\nVà có một pháp nào,\nMọi vật đều tùy thuộc?\n- Chính tâm dắt dẫn đời,\nChính tâm tự não hại,\nChính tâm là một pháp,\nMọi vật đều tùy thuộc.`, ref: "Tương Ưng Bộ 1.62", url: "https://loicuaducphat.org/sn/sn1.62.html#content" },

{ text: `- Vật gì trói buộc đời?\nVật gì dẫn hành đời?\nDo đoạn trừ pháp gì,\nMới được gọi Niết-bàn?\n- Chính hỷ trói buộc đời,\nTầm cầu dẫn hành đời,\nDo đoạn trừ khát ái,\nMới được gọi Niết-bàn.`, ref: "Tương Ưng Bộ 1.64", url: "https://loicuaducphat.org/sn/sn1.64.html#content" },

{ text: `- Vật gì triền phược đời?\nVật gì dẫn hành đời?\nDo đoạn trừ pháp gì,\nMọi triền phược đoạn diệt?\n- Chính hỷ triền phược đời,\nTầm cầu dẫn hành đời,\nDo đoạn trừ khát ái,\nMọi triền phược đoạn diệt.`, ref: "Tương Ưng Bộ 1.65", url: "https://loicuaducphat.org/sn/sn1.65.html#content" },

{ text: `- Vật gì áp đảo đời?\nVật gì bao phủ đời?\nTên gì bắn trúng đời?\nBởi gì thường huân tập?\n- Sự chết áp đảo đời,\nGià nua bao phủ đời,\nTên ái bắn trúng đời,\nBởi dục, thường huân tập.`, ref: "Tương Ưng Bộ 1.66", url: "https://loicuaducphat.org/sn/sn1.66.html#content" },

{ text: `- Vật gì treo cột đời?\nVật gì bao phủ đời?\nVật gì đóng kín đời?\nTrên gì đời an trú?\n- Khát ái treo cột đời,\nGià nua bao phủ đời,\nSự chết đóng kín đời,\nTrên khổ, đời an trú.`, ref: "Tương Ưng Bộ 1.67", url: "https://loicuaducphat.org/sn/sn1.67.html#content" },

{ text: `- Vật gì đóng kín đời?\nTrên gì đời an trú?\nVật gì treo cột đời?\nVật gì bao phủ đời?\n- Sự chết đóng kín đời,\nTrên khổ, đời an trú,\nKhát ái treo cột đời,\nGià nua bao phủ đời.`, ref: "Tương Ưng Bộ 1.68", url: "https://loicuaducphat.org/sn/sn1.68.html#content" },

{ text: `- Vật gì trói buộc đời?\nÐiều phục gì được thoát?\nVật gì được đoạn trừ,\nKhiến mọi phược đoạn tận?\n- Ước muốn trói buộc đời,\nÐiều phục dục được thoát,\nƯớc muốn được đoạn trừ,\nMọi triền phược đoạn tận.`, ref: "Tương Ưng Bộ 1.69", url: "https://loicuaducphat.org/sn/sn1.69.html#content" },

{ text: `Sát vật gì được lạc?\nSát vật gì không sầu?\nCó một pháp loại gì,\nNgài tán đồng sát hại,\nTôn giả Gotama?\n\n(Thế Tôn):\nSát phẫn nộ được lạc,\nSát phẫn nộ không sầu,\nPhẫn nộ với độc căn,\nVới vị ngọt tối thượng,\nPháp ấy, bậc Thánh Hiền,\nTán đồng sự sát hại.\nSát pháp ấy không sầu,\nNày Hiền giả Thiên nhân.`, ref: "Tương Ưng Bộ 1.71", url: "https://loicuaducphat.org/sn/sn1.71.html#content" },

{ text: `- Tài sản gì ở đời,\nÐối người là tối thượng?\nSự gì khéo tu trì,\nÐưa đến chơn an lạc?\nVật gì ngọt tối thượng,\nTrong tất cả vị ngọt?\nSống cuộc sống thế nào,\nÐược gọi sống tối thượng?\n- Lòng tin ở đời này,\nLà tài sản tối thượng.\nChánh pháp khéo tu trì,\nÐưa đến chơn an lạc.\nSự thật ngọt tối thượng,\nTrong tất cả vị ngọt.\nSống cuộc sống trí tuệ,\nÐược gọi sống tối thượng.`, ref: "Tương Ưng Bộ 1.73", url: "https://loicuaducphat.org/sn/sn1.73.html#content" },

{ text: `Vật gì được mọc lên,\nLà mọc lên tối thượng?\nVật gì được rơi xuống,\nLà rơi xuống tối thượng?\nVật gì thường bộ hành?\nVật gì thuyết tối thượng?\n\n(Thế Tôn):\nHuệ minh được mọc lên,\nLà mọc lên tối thượng.\nVô minh được rơi xuống,\nLà rơi xuống tối thượng.\nTăng-già thường bộ hành,\nÐức Phật thuyết tối thượng.`, ref: "Tương Ưng Bộ 1.74", url: "https://loicuaducphat.org/sn/sn1.74.html#content" },

{ text: `Vì sao ở đời này,\nRất nhiều người sợ hãi,\nDầu con đường đề cập,\nDưới hình thức sai biệt?\nCon hỏi Gotama,\nBậc trí tuệ sáng suốt,\nPhải an trú chỗ nào,\nKhỏi sợ hãi đời sau?\n\n(Thế Tôn):\nHãy chánh trú lời, ý,\nThân nghiệp chớ làm ác.\nNếu an trú trong nhà,\nVới tài sản dồi dào,\nHãy tín tâm, nhu hòa,\nChia tài sản, hòa nhã.\nAn trú bốn pháp này,\nKhông sợ hãi đời sau.`, ref: "Tương Ưng Bộ 1.75", url: "https://loicuaducphat.org/sn/sn1.75.html#content" },

{ text: `- Ai già, ai không già?\nThế nào gọi phi đạo?\nVật gì chướng ngại pháp?\nVật gì đêm ngày diệt?\nVật gì uế Phạm hạnh?\nVật gì tắm không nước?\nÐời bao nhiêu lỗ trống,\nTrên ấy, tâm không trú?\nCon đến hỏi Thế Tôn,\nMong biết câu trả lời!\n- Sắc hữu tình bị già,\nDanh tánh lại không già,\nTham dục gọi phi đạo,\nTham ái, chướng ngại pháp.\nTuổi tác đêm, ngày diệt,\nNữ nhân uế Phạm hạnh,\nÐắm trước trong uế này,\nLà toàn thể chúng sanh.\nKhổ hạnh và Phạm hạnh,\nLà tắm không cần nước,\nSáu lỗ trống ở đời,\nTrên ấy, tâm không trú,\nBiếng nhác và phóng dật,\nUể oải, không tự chế,\nThụy miên và hôn trầm,\nCả sáu lỗ trống này,\nCần ly khai tất cả.`, ref: "Tương Ưng Bộ 1.76", url: "https://loicuaducphat.org/sn/sn1.76.html#content" },

{ text: `- Vật gì chủ ở đời?\nHàng hóa gì tối thượng?\nVật gì làm rỉ sét,\nLưỡi kiếm ở trên đời?\nVật gì ở đời này,\nTác thành cõi địa ngục?\nAi đem đi, bị chận?\nAi đem đi, được ưa?\nAi thường xuyên đi lại,\nÐược kẻ trí hoan hỷ?\n- Thế lực chủ ở đời,\nNữ nhân, vật tối thượng.\nPhẫn nộ làm rỉ sét,\nLưỡi kiếm ở trên đời.\nKẻ trộm ở đời này,\nTác thành cõi địa ngục.\nTrộm đem đi, bị chận,\nSa-môn đem, được ưa,\nSa-môn thường đi lại,\nÐược kẻ trí hoan hỷ.`, ref: "Tương Ưng Bộ 1.77", url: "https://loicuaducphat.org/sn/sn1.77.html#content" },

{ text: `- Nghĩ lợi, không cho ai,\nCon người từ bỏ gì?\nThiện gì nên thốt ra?\nÁc gì nên ngăn chận?\n- Con người không cho mình,\nKhông nên từ bỏ mình,\nLời thiện, nên thốt ra,\nLời ác, nên ngăn chận.`, ref: "Tương Ưng Bộ 1.78", url: "https://loicuaducphat.org/sn/sn1.78.html#content" },

{ text: `- Cái gì cột lương thực?\nCái gì hút tài sản?\nCái gì lôi cuốn người?\nỞ đời, khó bỏ gì?\nCái gì buộc phàm nhân,\nNhư chim bị bẫy sập?\n- Lòng tin cột lương thực,\nThần tài hút tài sản.\nLòng muốn lôi cuốn người,\nỞ đời, muốn khó bỏ.\nHam muốn buộc phàm nhân,\nNhư chim bị bẫy sập.`, ref: "Tương Ưng Bộ 1.79", url: "https://loicuaducphat.org/sn/sn1.79.html#content" },

{ text: `- Vật gì chiếu sáng đời?\nVật gì thức tỉnh đời?\nAi cộng nghiệp với người?\nCử chỉ chúng là gì?\nAi nuôi kẻ nhác, siêng,\nNhư mẹ nuôi con cái?\nHữu tình gì trì mạng,\nY cứ vào địa đại?\n- Trí tuệ chiếu sáng đời,\nChánh niệm thức tỉnh đời,\nBò cộng nghiệp với người,\nÐường cày là con đường.\nMưa nuôi kẻ nhác, siêng,\nNhư mẹ nuôi con cái.\nMưa trì mạng chúng sanh,\nY cứ vào địa đại.`, ref: "Tương Ưng Bộ 1.80", url: "https://loicuaducphat.org/sn/sn1.80.html#content" },

{ text: `- Ai không tranh luận đời?\nAi sống không hoại diệt?\nAi rõ ham muốn đời?\nAi thường xuyên tự tại?\nAi an trú như vậy,\nCha, mẹ, anh đảnh lễ?\nAi dầu có hạ sanh,\nÐược Sát-lỵ tôn kính?\n- Sa-môn không tranh đời,\nSa-môn sống không diệt,\nSa-môn rõ dục vọng,\nSa-môn thường tự tại,\nSa-môn trú như vậy,\nCha, mẹ, anh kính lễ.\nSa-môn dầu hạ sanh,\nÐược Sát-lỵ tôn kính.`, ref: "Tương Ưng Bộ 1.81", url: "https://loicuaducphat.org/sn/sn1.81.html#content" },

{ text: `Ðứng một bên, Thiên tử Kassapa bạch Thế Tôn: - Thế Tôn đề cao Tỷ-kheo và sự giáo giới vị Tỷ kheo cho chúng con.\n\n- Vậy này Kassapa, hãy nói lên ở đây về vấn đề ấy.\n\n(Kassapa):\nHãy học điều khéo nói,\nTrong hạnh nghiệp Sa-môn,\nVắng lặng, ngồi một mình,\nVới tâm tư an tịnh.`, ref: "Tương Ưng Bộ 2.1", url: "https://loicuaducphat.org/sn/sn2.1.html#content" },
{ text: `Ðứng một bên, Thiên tử Kassapa nói lên bài kệ này trước Thế Tôn:\n\nVới tâm tư giải thoát,\nVị Tỷ-kheo tu thiền,\nVà với lòng ước vọng,\nÐạt được tâm sở nguyện.\nSau khi biết cuộc đời,\nHưng thịnh và phế tàn,\nTâm thuần, không nương tựa,\nHưởng lợi quả như chơn.`, ref: "Tương Ưng Bộ 2.2", url: "https://loicuaducphat.org/sn/sn2.2.html#content" },

{ text: `Ðứng một bên, Thiên tử Màgadha nói lên với Thế Tôn bài kệ:\nVật gì chiếu sáng đời,\nDo chúng, đời chói sáng?\nCon đến hỏi Thế Tôn,\nMuốn nghe lời giải đáp.\n\n(Thế Tôn)\nBốn vật chiếu sáng đời,\nThứ năm đây không có,\nNgày, mặt trời sáng chói,\nÐêm, mặt trăng tỏ rạng,\nLửa cháy đỏ đêm ngày,\nChói sáng khắp mọi nơi,\nChánh giác sáng tối thắng,\nSáng này sáng vô thượng .`, ref: "Tương Ưng Bộ 2.4", url: "https://loicuaducphat.org/sn/sn2.4.html#content" },

{ text: `Thiên tử Dàmali nói lên bài kệ này trước Thế Tôn:\nỞ đây, Bà-la-môn,\nTinh cần, không biếng nhác,\nÐoạn trừ các dục vọng,\nNhờ vậy không tái sanh .\n\nThế Tôn bèn trả lời:\nÔi này Dàmali,\nVới vị Bà-la-môn,\nKhông còn gì phải làm,\nViệc phải làm đã làm,\nChính là Bà-la-môn.\nChúng sanh đủ tay chân,\nKhông tìm được chân đứng,\nTrôi giạt và chìm nổi,\nTrong biển rộng, sông dài.\nTìm được chỗ chân đứng,\nKhô ráo vị ấy đứng,\nÐã đến bờ bên kia,\nVị ấy không trôi giạt.\nVậy này Dàmali,\nVí dụ ấy là vậy.\nCũng vậy Bà-la-môn,\nÐoạn trừ các lậu hoặc,\nSáng suốt và kín đáo,\nTinh tấn tu Thiền định.\nVị ấy đã đạt được,\nTận cùng đường sanh tử,\nÐã đến bờ bên kia,\nNên không còn trôi giạt.`, ref: "Tương Ưng Bộ 2.5", url: "https://loicuaducphat.org/sn/sn2.5.html#content" },

{ text: `Ðứng một bên, Thiên tử Kàmada bạch Thế Tôn:\nKhó làm, bạch Thế Tôn,\nThế Tôn, thật khó làm.\n\n(Thế Tôn)\nTuy vậy, Kàmada,\nHọ làm việc khó làm,\nChính các vị hữu học,\nKiên trì tu giới định,\nÐã chọn đời xuất gia,\nBiết đủ, đem an lạc.\n\nBiết đủ, bạch Thế Tôn,\nBiết đủ, thật khó được.\n\n(Thế Tôn)\nTuy vậy, Kàmada,\nHọ được điều khó được.\nNhững vị lòng ưa thích,\nTâm tư được điều tịnh,\nCả ngày và cả đêm,\nÝ an lạc tu tập.\n\nKhó tịnh, bạch Thế Tôn,\nTâm ấy, thật khó tịnh.\n\n(Thế Tôn)\nTuy vậy, Kàmada,\nHọ tịnh tâm khó tịnh.\nNhững vị lòng ưa thích,\nCác căn được tịch tịnh,\nCắt đứt lưỡi tử thần,\nBậc Hiền Thánh đi tới.\n\nKhó đi, bạch Thế Tôn,\nCon đường thật lồi lõm.\n\n(Thế Tôn)\nTuy vậy, Kàmada,\nBậc Hiền Thánh vẫn đi.\nTrên con đường khó đi,\nVà có nhiều lồi lõm,\nKẻ phàm phu vấp ngã,\nTrên đường mất thăng bằng.\nCon đường đối bậc Thánh,\nLà con đường thăng bằng,\nBậc Thánh bước thăng bằng,\nTrên đường mất thăng bằng.`, ref: "Tương Ưng Bộ 2.6", url: "https://loicuaducphat.org/sn/sn2.6.html#content" },

{ text: `Ðứng một bên, Thiên tử Pancàlacanda nói lên bài kệ này trước Thế Tôn:\nDầu giữa những chướng ngại,\nBậc Ðại trí Chánh giác,\nVẫn tìm được lối thoát,\nVượt qua mọi chướng ngại.\nBậc trí hiểu Thiền định,\nBiết từ bỏ, tối thắng,\nBậc Mâu-ni, ẩn sĩ\n\nThế Tôn lên tiếng:\nPancàlacanda,\nDầu giữa những chướng ngại,\nHọ tìm được lối thoát,\nHọ tìm được Chánh pháp\nÐưa đến quả Niết-bàn.\nNhững vị đạt chánh niệm,\nKiên trì không dao động,\nHọ là bậc chơn chánh,\nTâm điều phục, định tĩnh.`, ref: "Tương Ưng Bộ 2.7", url: "https://loicuaducphat.org/sn/sn2.7.html#content" },

{ text: `Ðứng một bên, Thiên tử Tàyana nói lên bài kệ này trước Thế Tôn:\n\nÔi này Bà-la-môn,\nTinh tấn, cắt dòng nước,\nÐoạn trừ và tiêu diệt,\nMọi tham đắm dục vọng.\nẨn sĩ không đoạn dục,\nKhông chứng được nhứt tâm.\nNếu làm việc phải làm,\nCần kiên trì, tinh tấn.\nXuất gia, nếu biếng nhác,\nCàng tung vãi bụi trần.\nKhông làm, hơn làm dở,\nLàm dở sau khổ đau.\nÐã làm nên làm tốt,\nLàm tốt không khổ đau.\nNhư nắm vụng lá cỏ,\nCó thể bị đứt tay.\nSa-môn hạnh vụng tu,\nKéo đến cõi địa ngục.\nMọi sở hành biếng nhác,\nMọi hạnh tu ô nhiễm,\nÁc hạnh trong Phạm hạnh,\nKhông đưa đến quả lớn.`, ref: "Tương Ưng Bộ 2.8", url: "https://loicuaducphat.org/sn/sn2.8.html#content" },

{ text: `Ðứng một bên, Thiên tử Candimasa nói lên bài kệ này trước mặt Thế Tôn:\n\nHọ sẽ đi an toàn,\nNhư thú, vùng không muỗi,\nSau khi chứng Thiền định,\nNhất tâm, niệm tỉnh giác,\nHọ sẽ đi bờ kia,\nNhư cá, phá rách lưới,\nSau khi chứng Thiền định,\nTự chế, vượt lỗi lầm .`, ref: "Tương Ưng Bộ 2.11", url: "https://loicuaducphat.org/sn/sn2.11.html#content" },

{ text: `Ðứng một bên, Thiên tử Veṇḍu nói lên bài kệ này trước mặt Thế Tôn:\nHạnh phúc thay những người,\nSau khi hầu Thiện Thệ,\nTuân phụng lời Ngài dạy,\nTu học không phóng dật!\n\nThế Tôn nói:\nNhững ai Thiền tu học.\nTrong pháp cú Ta dạy,\nTinh cần, không phóng dật,\nÐúng thời họ sẽ đi,\nThoát khỏi tay tử thần.`, ref: "Tương Ưng Bộ 2.12", url: "https://loicuaducphat.org/sn/sn2.12.html#content" },

{ text: `Ðứng một bên, Thiên tử Diighalatthi nói lên bài kệ này trước mặt Thế Tôn:\n\nVới tâm tư giải thoát,\nVị Tỷ-kheo tu Thiền,\nVà với lòng ước vọng,\nÐạt được tâm sở nguyện,\nSau khi biết cuộc đời,\nSanh khởi rồi đoạn diệt,\nTâm thuần không chấp trước,\nHưởng lợi quả như chơn.`, ref: "Tương Ưng Bộ 2.13", url: "https://loicuaducphat.org/sn/sn2.13.html#content" },

{ text: `Ðứng một bên, Thiên tử Nandana nói bài kệ với Thế Tôn:\nCon hỏi Gotama,\nBậc Ðại Giác toàn trí,\nCon hỏi đấng Thế Tôn,\nVới tri kiến vạn năng.\nNgười nào gọi trì giới?\nNgười nào gọi trí tuệ?\nNgười nào vượt sầu khổ?\nNgười nào chư Thiên lạy?\n\n(Thế Tôn):\nAi hộ trì giới luật,\nTrí tuệ, tâm tu trì,\nChú tâm, vui Thiền định,\nTâm tư trú chánh niệm,\nTất cả mọi sầu khổ,\nÐược trừ diệt, đoạn tận,\nCác lậu hoặc tận trừ,\nSống với thân tối hậu,\nVị ấy gọi trì giới,\nVị ấy gọi trí tuệ,\nVị ấy vượt sầu khổ,\nVị ấy chư Thiên lạy.`, ref: "Tương Ưng Bộ 2.14", url: "https://loicuaducphat.org/sn/sn2.14.html#content" },

{ text: `Ðứng một bên, Thiên tử Candana nói lên bài kệ với Thế Tôn:\nLàm sao vượt bộc lưu,\nNgày đêm vững, kiên trì,\nKhông trú, không bám víu,\nAi không chìm vực sâu?\n\n(Thế Tôn):\nVị luôn luôn trì giới,\nTrí tuệ, khéo định tĩnh,\nChí siêng năng dõng mãnh,\nVượt bộc lưu khó vượt.\nVị đoạn, ly dục tưởng,\nVượt khỏi sắc triền phược,\nÐoạn tận hỷ, hữu ái,\nKhông chìm xuống vực sâu.`, ref: "Tương Ưng Bộ 2.15", url: "https://loicuaducphat.org/sn/sn2.15.html#content" },
{ text: `Ðứng một bên, Thiên tử Sudatta nói lên bài kệ này trước mặt Thế Tôn:\nNhư kiếm đã chạm da,\nNhư lửa cháy trên đầu,\nTỷ-kheo hãy chánh niệm,\nXuất gia, bỏ ái dục.\n\n(Thế Tôn):\nNhư kiếm đã chạm da,\nNhư lửa cháy trên đầu,\nTỷ-kheo hãy chánh niệm,\nXuất gia, bỏ thân kiến.`, ref: "Tương Ưng Bộ 2.16", url: "https://loicuaducphat.org/sn/sn2.16.html#content" },

{ text: `Ðứng một bên, Thiên tử Subrahmà nói lên bài kệ với Thế Tôn:\nTâm này thường sợ hãi,\nÝ này thường dao động,\nÐiều mong ước không khởi,\nÐiều không mong lại khởi,\nNếu có, không sợ hãi,\nHãy nói điều con hỏi.\n\n(Thế Tôn):\nKhông ngoài hạnh giác chi,\nKhông ngoài hộ trì căn,\nKhông ngoài bỏ tất cả,\nTa thấy các pháp ấy,\nÐưa đến sự an toàn,\nCho tất cả chúng sanh.`, ref: "Tương Ưng Bộ 2.17", url: "https://loicuaducphat.org/sn/sn2.17.html#content" },

{ text: `Làm sao, này Tỷ-kheo,\nNgài không có sầu muộn,\nTuy vậy, Ngài cũng không\nCó được sự hoan hỷ?\nLàm sao nay Ngài lại,\nNgồi cô độc một mình,\nKhông có được hoan hỷ,\nCũng không bị dao động?\n\nThật sự, này Dạ-xoa,\nTa không có sầu muộn,\nTuy vậy ở nơi Ta,\nHoan hỷ không khởi lên,\nDầu nay Ta có ngồi,\nRiêng một mình cô độc,\nTa không có hoan hỷ,\nCũng không bị dao động.\n\nLàm sao, này Tỷ-kheo,\nNgài không có sầu muộn,\nLàm sao ở nơi Ngài,\nHoan hỷ không khởi lên?\nLàm sao nay Ngài lại,\nNgồi cô độc một mình,\nKhông có được hoan hỷ,\nCũng không bị dao động?\n\nHoan hỷ chỉ có đến,\nVới người tâm sầu muộn,\nSầu muộn chỉ có đến,\nVới người tâm hoan hỷ.\nDo vậy, vị Tỷ-kheo,\nKhông hoan hỷ, sầu muộn.\nVậy nên, này Hiền giả,\nÔng phải biết như vậy.\n\nÐã lâu, con mới thấy,\nBà-la-môn tịch tịnh,\nVị Tỷ-kheo không sầu,\nCũng không có hoan hỷ,\nÐã an toàn vượt khỏi,\nChỗ người đời đắm say.`, ref: "Tương Ưng Bộ 2.18", url: "https://loicuaducphat.org/sn/sn2.18.html#content" },

{ text: `Ðứng một bên, Thiên tử Uttara nói lên bài kệ này trước mặt Thế Tôn:\nMạng sống bị dắt dẫn,\nTuổi thọ chẳng là bao,\nBị dẫn đến già nua,\nKhông có nơi dừng bước.\nAi đem tâm quán tưởng,\nSợ hãi tử vong này,\nHãy làm các công đức,\nÐưa đến chơn an lạc.\n\nMạng sống bị dắt dẫn,\nTuổi thọ chẳng là bao,\nBị dẫn đến già nua,\nKhông có nơi dừng bước.\nAi đem tâm quán tưởng,\nSợ hãi tử vong này,\nHãy bỏ mọi thế lợi,\nTâm hướng cầu tịch tịnh.`, ref: "Tương Ưng Bộ 2.19", url: "https://loicuaducphat.org/sn/sn2.19.html#content" },

{ text: `Ðứng một bên, Thiên tử Siva nói lên bài kệ này trước mặt Thế Tôn:\n\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nChỉ tốt hơn, không xấu.\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nÐược tuệ, không gì khác.\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nKhông sầu giữa sầu muộn.\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nChói sáng giữa quyến thuộc.\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền,\nChúng sanh sanh thiện thú.\nHãy thân với người lành,\nHãy gần gũi người thiện,\nBiết diệu pháp người hiền\nChúng sanh thường hưởng lạc.`, ref: "Tương Ưng Bộ 2.21", url: "https://loicuaducphat.org/sn/sn2.21.html#content" },

{ text: `Ðứng một bên, Thiên tử Khemā nói lên bài kệ này trước mặt Thế Tôn:\n\nKẻ ngu không trí tuệ,\nLấy ngã làm kẻ thù,\nTự làm các ác nghiệp,\nÐưa đến quả đắng cay.\nNghiệp nào không khéo làm,\nLàm xong bị nung nấu,\nVới mặt đầy nước mắt,\nKhóc lóc chịu quả báo.\nVà nghiệp nào khéo làm,\nLàm xong, không nung nấu,\nTâm vui, ý thoải mái,\nVị ấy hưởng quả báo.\nBiết điều lợi cho mình,\nLàm trước điều phải làm,\nKhông tâm trạng đánh xe,\nKẻ trí lòng tinh tấn.\nNhư người chủ đánh xe,\nRời đại đạo thăng bằng,\nLeo lên đường lồi lõm,\nƯu tư nạn gãy trục.\nCũng vậy bỏ Chánh pháp,\nNgười ngu theo phi pháp,\nRơi vào miệng tử thần,\nƯu tư như gãy trục.`, ref: "Tương Ưng Bộ 2.22", url: "https://loicuaducphat.org/sn/sn2.22.html#content" },

{ text: `(Thế Tôn)\nAi cho với lòng tin,\nVới tâm tư thanh tịnh,\nÐược phần món ăn ấy,\nÐời này và đời sau.\nVậy hãy ngăn xan tham,\nBố thí, nhiếp cấu uế,\nChúng sanh vẫn hưởng thọ,\nCông đức trong đời sau.`, ref: "Tương Ưng Bộ 2.23", url: "https://loicuaducphat.org/sn/sn2.23.html#content" },

{ text: `Một thời một số đông Tỷ-kheo trú ở Kosala, trên sườn núi Himavanta (Tuyết sơn), tại một cốc nhỏ trong rừng. Họ tự cao, tự mãn, dao động, lắm mồm lắm miệng, ăn nói huyên thuyên, thất niệm, không tỉnh giác, không định tĩnh, tâm tư tán loạn, các căn không chế ngự.\n\nRồi Thiên tử Jantu, vào đêm Bố-tát, ngày rằm, đi đến các Tỷ-kheo ấy, sau khi đến nói lên bài kệ với các Tỷ-kheo ấy:\n\nCác Tỷ-kheo thuở xưa,\nSống thật chơn an lạc,\nHọ thật là đệ tử,\nBậc Ðại Giác Cù-đàm.\nKhông ham tìm món ăn,\nKhông ham tìm chỗ trú,\nBiết đời là vô thường,\nHọ chấm dứt khổ đau.\nNay tự làm ác hạnh,\nNhư thôn trưởng trong làng.\nHọ ăn, ăn ngả gục,\nThèm khát vật nhà người.\nCon vái chào chúng Tăng,\nÐảnh lễ một vài vị\nKẻ khác, sống vất vưởng,\nKhông chỉ đạo, hướng dẫn.\nHọ giống như thân thể\nKẻ chết bị quăng bỏ.\nNhững ai sống phóng dật,\nVì họ con nói lên,\nNhững ai không phóng dật,\nChân thành, con đảnh lễ .`, ref: "Tương Ưng Bộ 2.25", url: "https://loicuaducphat.org/sn/sn2.25.html#content" },

{ text: `Thời gian lặng trôi qua,\nÐêm ngày luôn di động,\nTuổi tác buổi thanh xuân,\nTiếp tục bỏ chúng ta.\nNhững ai chịu quán sát,\nSợ hãi tử vong này,\nHãy làm các công đức,\nÐược hưởng cảnh an lạc.\n\n(Thế Tôn):\nThời gian lặng trôi qua,\nÐêm ngày luôn di động,\nTuổi tác buổi thanh xuân,\nTiếp tục bỏ chúng ta.\nNhững ai chịu quán sát,\nSợ hãi tử vong này,\nHãy bỏ mọi thế lợi,\nÐược hưởng chơn tịch tịnh.`, ref: "Tương Ưng Bộ 2.27", url: "https://loicuaducphat.org/sn/sn2.27.html#content" },

{ text: `Bốn bánh xe chín cửa,\nÐầy uế, hệ lụy tham,\nChìm đắm trong bùn nhơ,\nÔi! Thưa bậc Ðại Hùng,\nSanh thú Ngài như vậy,\nTương lai sẽ thế nào?\n\n(Thế Tôn):\n\nCắt hỷ và buộc ràng,\nDục tham và tà ác,\nÁi căn được đoạn tận,\nSanh thú sẽ như vậy.`, ref: "Tương Ưng Bộ 2.28", url: "https://loicuaducphat.org/sn/sn2.28.html#content" },

{ text: `Rồi Thế Tôn biết được chính là Ác ma, liền nói lên bài kệ cho Ác ma:\n\nPhàm những sắc pháp gì,\nÐời này hay đời sau,\nVới màu sắc thù diệu,\nChói sáng giữa hư không,\nTất cả những sắc ấy,\nÐược Ma vương tán thán,\nChúng chỉ là bẫy mồi,\nQuăng ra để diệt cá.`, ref: "Tương Ưng Bộ 2.30", url: "https://loicuaducphat.org/sn/sn2.30.html#content" },

{ text: `Tham, sân, si ba pháp,\nLà ác tâm cho người,\nChúng di hại tự ngã,\nChúng tác thành tự ngã,\nNhư vỏ và lõi cây,\nTự tác thành trái cây.`, ref: "Tương Ưng Bộ 3.2", url: "https://loicuaducphat.org/sn/sn3.2.html#content" },

{ text: `Ngồi một bên, vua Pasenadi nước Kosala bạch Thế Tôn:\n- Bạch Thế Tôn, có cái gì sanh mà không già và không chết không?\n- Thưa Ðại vương, không có cái gì sanh mà không già và không chết.\nThưa Ðại vương, dầu cho những vị Sát-đế-lỵ là những bậc đại phú, phú hào, có tiền của lớn, có tài sản lớn, có nhiều vàng và bạc, có nhiều tài sản vật dụng, có nhiều tiền của, ngũ cốc. Các vị ấy có sanh cũng không thoát khỏi già và chết.`, ref: "Tương Ưng Bộ 3.3", url: "https://loicuaducphat.org/sn/sn3.3.html#content" },

{ text: `Thưa Ðại vương, cho đến các vị Tỷ-kheo, những bậc A-la-hán, đã đoạn tận các lậu hoặc, Phạm hạnh đã thành, những việc nên làm đã làm, đã đặt gánh nặng xuống, đã đạt được mục đích tối hậu, đã đoạn được hữu kiết sử, đã được giải thoát nhờ chánh trí, cho đến thân này của các vị ấy cũng phải bị hủy hoại, cũng phải bị từ bỏ.\n\nXe vua dầu mỹ diệu,\nRồi cũng phải hư hoại,\nThân thể này cũng vậy,\nRồi cũng phải già yếu.\nChỉ thiện pháp không già,\nBậc thiện nhân nói vậy.`, ref: "Tương Ưng Bộ 3.3", url: "https://loicuaducphat.org/sn/sn3.3.html#content" },
{ text: `“Những ai thân làm ác, miệng nói ác, ý nghĩ ác, những người ấy không bảo vệ tự ngã. Dầu cho họ được tượng binh bảo vệ, hay được mã binh bảo vệ, hay được xa binh bảo vệ, hay được bộ binh bảo vệ; đối với những người ấy, tự ngã không được bảo vệ. Vì cớ sao? Vì sự bảo vệ như vậy là bảo vệ ở ngoài, không phải sự bảo vệ bên trong. Cho nên đối với những người ấy, tự ngã không được bảo vệ.\n\nVà những ai thân làm thiện, miệng nói thiện, ý nghĩ thiện, những người ấy bảo vệ tự ngã. Dầu cho họ không được tượng binh bảo vệ, hay không được mã binh bảo vệ, hay không được xa binh bảo vệ, hay không được bộ binh bảo vệ; đối với những người ấy, tự ngã được bảo vệ. Vì cớ sao? Vì sự bảo vệ như vậy là sự bảo vệ bên trong, không phải sự bảo vệ ở ngoài. Cho nên đối với những người ấy, tự ngã được bảo vệ.”\n\nLành thay bảo vệ thân!\nLành thay bảo vệ lời!\nLành thay bảo vệ ý!\nLành thay tổng bảo vệ!\nKẻ liêm sỉ bảo vệ,\nTổng quát và cùng khắp,\nVị ấy có tên gọi,\nLà vị được bảo vệ.`, ref: "Tương Ưng Bộ 3.5", url: "https://loicuaducphat.org/sn/sn3.5.html#content" },

{ text: `Thật sự là vậy, thưa Ðại vương. Ít thay là những người trong đời này, sau khi được tài sản phong phú, dồi dào, lại có thể không bị lôi cuốn, không bị chìm đắm, không bị say mê trong các dục và không có những hành vi không tốt đẹp đối với người khác. Trái lại, thật là nhiều thay những người trong đời này, sau khi được tài sản phong phú, dồi dào, có thể bị lôi cuốn, bị chìm đắm, bị say mê trong các dục và có những hành vi không tốt đẹp đối với các người khác.\n\nLoài người bị đắm say,\nTrong tài sản, trong dục,\nHọ tham lam, điên dại,\nTrong các dục ở đời,\nKhông ý thức rõ ràng,\nÐã quá độ say mê,\nChẳng khác gì con nai,\nKhông thấy đặt bẫy sập,\nVề sau họ khổ đau,\nChịu quả báo ác nghiệp.`, ref: "Tương Ưng Bộ 3.6", url: "https://loicuaducphat.org/sn/sn3.6.html#content" },

{ text: `- Thưa Ðại vương, các vị Sát-đế-lỵ đại phú, các vị Bà-la-môn đại phú, các vị gia chủ đại phú, phú hào có tiền của lớn, có tài sản lớn, có nhiều vàng và bạc, có nhiều tài sản vật dụng, có nhiều tiền của, ngũ cốc; vì nhân các dục, vì duyên các dục, vì nhân duyên các dục, đã dụng ý nói lên lời vọng ngôn. Do vậy họ sẽ gánh chịu bất lợi, đau khổ trong một thời gian dài.\n\nLoài Người bị đắm say,\nTrong tài sản, trong dục,\nHọ tham lam, điên dại,\nTrong các dục ở đời.\nKhông ý thức rõ ràng,\nÐã quá độ say mê,\nChẳng khác gì con cá,\nKhông thấy đặt bẫy sập.\nVề sau họ khổ đau,\nChịu quả báo ác nghiệp.`, ref: "Tương Ưng Bộ 3.7", url: "https://loicuaducphat.org/sn/sn3.7.html#content" },

{ text: `Rồi Thế Tôn, sau khi biết rõ ý nghĩa này, trong lúc ấy liền nói lên bài kệ này:\n\nTâm ta đi cùng khắp,\nTất cả mọi phương trời,\nCũng không tìm thấy được,\nAi thân hơn tự ngã.\nTự ngã đối mọi người,\nQuá thân ái như vậy.\nVậy ai yêu tự ngã,\nChớ hại tự ngã người.`, ref: "Tương Ưng Bộ 3.8", url: "https://loicuaducphat.org/sn/sn3.8.html#content" },

{ text: `Ngồi xuống một bên, các Tỷ-kheo ấy bạch Thế Tôn:\n- Ở đây, bạch Thế Tôn, vua Pasenadi nước Kosala bắt trói một số đông người. Một số người bị trói bằng dây, một số người bị trói bằng dây chuyền, một số người bị trói bằng kềm kẹp.\n\nRồi Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy nói lên bài kệ:\nBậc có trí nói rằng\nTrói vậy không vững chắc,\nTrói bằng sắt, dây gai,\nKềm kẹp bằng gỗ mộc;\nÐam mê các dục lạc,\nVới châu báu, trang sức,\nVà tâm tư tưởng vọng,\nHướng về con, về vợ.\nBậc có trí nói rằng\nTrói vậy thật vững chắc.\nDầu trói buộc trì xuống,\nTế nhị và khó thoát,\nCác vị chơn xuất gia,\nCắt đứt chúng làm đôi,\nKhông ước vọng mong cầu,\nTừ bỏ mọi dục lạc.`, ref: "Tương Ưng Bộ 3.10", url: "https://loicuaducphat.org/sn/sn3.10.html#content" },

{ text: `Thưa Ðại vương, chính phải cộng trú mới biết được giới đức của một người, và phải trong một thời gian dài không thể khác được, phải có tác ý, không phải không có tác ý, phải có trí tuệ, không phải với ác tuệ.\nThưa Ðại vương, chính trong thời gian bất hạnh mới biết được sự trung kiên của một người, phải trong một thời gian dài không thể không khác được, phải có tác ý, không phải không tác ý, phải có trí tuệ, không phải với ác tuệ.\nThưa Ðại vương, chính phải đàm đạo mới biết được trí tuệ của một người, và phải trong một thời gian dài không thể khác được, phải có tác ý, không phải không tác ý, phải có trí tuệ, không phải với ác tuệ.`, ref: "Tương Ưng Bộ 3.11", url: "https://loicuaducphat.org/sn/sn3.11.html#content" },

{ text: `Không phải do sắc tướng,\nBiết rõ được con người,\nKhông phải nhìn thoáng qua,\nÐặt được lòng tin cậy.\nDưới bộ áo đạo đức,\nVới hình tướng tự chế,\nNhững kẻ sống buông thả,\nSống phây phây đời này.\nNhư bông tai bằng đất,\nGiả dạng bông tai thật,\nNhư nửa tiền bằng đồng,\nÐược sơn phết lớp vàng.\nMột số sống che đậy,\nẨn kín dưới bề ngoài,\nNội thân thật bất tịnh,\nMặt ngoài giả mỹ diệu.`, ref: "Tương Ưng Bộ 3.11", url: "https://loicuaducphat.org/sn/sn3.11.html#content" },

{ text: `- Thưa Ðại vương, tùy theo cùng độ ưa thích mà Ta nói rằng dục ấy là tối thượng trong năm dục công đức. Và thưa Ðại vương, các sắc ấy, các tiếng ấy … các hương ấy … các vị ấy … đối với một số người được ưa thích, các sắc ấy đối với một số người không được ưa thích. Thưa Ðại vương, nếu một ai ưa thích đối với các sắc pháp, tâm viên ý mãn, không có muốn các sắc pháp nào khác hơn, các sắc pháp nào tốt đẹp hơn các sắc pháp ấy, thời đối với vị này, các sắc pháp ấy là tối thượng, đối với vị này, các sắc pháp ấy là vô thượng.`, ref: "Tương Ưng Bộ 3.12", url: "https://loicuaducphat.org/sn/sn3.12.html#content" },

{ text: `Rồi Thế Tôn, sau khi hiểu rõ ý nghĩa này ngay trong lúc ấy nói lên bài kệ:\n\nVì nghĩ đến tư lợi,\nNên mới cướp hại người,\nKhi người khác cướp hại,\nBị hại, lại hại người.\nNgười ngu nghĩ như vậy,\nKhi ác chưa chín muồi,\nKhi ác đã chín muồi,\nNgười ngu chịu khổ đau.\nSát người, bị người sát,\nThắng người, bị người thắng,\nMắng người, người mắng lại,\nNão người, người não lại,\nDo nghiệp được diễn tiến,\nBị hại, lại hại người.`, ref: "Tương Ưng Bộ 3.14", url: "https://loicuaducphat.org/sn/sn3.14.html#content" },

{ text: `- Bạch Thế Tôn, có một pháp nào có thể đưa đến chứng đắc và tồn tại cả hai hạnh phúc: hạnh phúc đời này và hạnh phúc đời sau?\n- Bất phóng dật, thưa Ðại vương, là một pháp có thể đưa đến chứng đắc và tồn tại cả hai hạnh phúc: hạnh phúc đời này và hạnh phúc đời sau. Thưa Ðại vương, cũng như con voi, trong tất cả loài hữu tình có chân, tóm thâu tất cả đặc tướng của chân trong bàn chân của nó; và bàn chân của voi được xem là đệ nhất về phương diện to lớn trong tất cả loại chân. Cũng vậy, thưa Ðại vương, bất phóng dật là một pháp có thể đưa đến chứng đắc và tồn tại cả hai hạnh phúc: hạnh phúc đời này và hạnh phúc đời sau.`, ref: "Tương Ưng Bộ 3.17", url: "https://loicuaducphat.org/sn/sn3.17.html#content" },

{ text: `Ai ước nguyện tuổi thọ,\nKhông bệnh, có diệu sắc,\nÐược sanh lên Thiên giới,\nSanh các nhà quý tộc,\nPhải liên tục tăng thượng,\nTinh tấn, không dừng nghĩ.\nNgười hiền triết tán thán,\nHạnh lành không phóng dật,\nÐối với những người lành,\nLàm các hạnh công đức,\nNgười hiền không phóng dật,\nÐược cả hai lợi ích,\nLợi ích trong đời này,\nLợi ích cả đời sau.\nKẻ anh hùng được gọi,\nLà bậc chơn hiền trí,\nNếu biết nắm chụp lấy,\nHạnh phúc cho chính mình.`, ref: "Tương Ưng Bộ 3.17", url: "https://loicuaducphat.org/sn/sn3.17.html#content" },

{ text: `Này Ānanda, chính vì Ta y cứ, làm bạn với thiện, nên các chúng sanh bị sanh được giải thoát khỏi sanh; các chúng sanh bị già được giải thoát khỏi già; các chúng sanh bị bệnh được giải thoát khỏi bệnh; các chúng sanh bị chết được giải thoát khỏi chết; các chúng sanh bị sầu, bi, khổ, ưu, não được giải thoát khỏi sầu, bi, khổ ưu, não. Và chính theo pháp môn này, này Ānanda, Ông cần phải hiểu như thế nào toàn phần đời sống Phạm hạnh này là thuộc về thiện hữu, thiện bạn lữ, thiện giao du.”`, ref: "Tương Ưng Bộ 3.18", url: "https://loicuaducphat.org/sn/sn3.18.html#content" },

{ text: `Thưa Ðại vương, nếu Ðại vương an trú không phóng dật, y cứ không phóng dật, thời tự ngã được che chở, hộ trì, nội cung được che chở, hộ trì, kho tàng được che chở, hộ trì.\n\nNgười ước mong tài sản,\nPhải liên tục tăng thượng,\nNgười hiền trí tán thán,\nHạnh lành không phóng dật.\nÐối với những người lành,\nLàm các hạnh công đức.\nNgười hiền không phóng dật,\nÐược cả hai lợi ích,\nLợi ích trong đời này,\nLợi ích cả đời sau.\nKẻ anh hùng được gọi\nLà bậc chơn hiền trí,\nNếu biết nắm chụp lấy\nHạnh phúc cho chính mình.`, ref: "Tương Ưng Bộ 3.18", url: "https://loicuaducphat.org/sn/sn3.18.html#content" },

{ text: `Lúa, tài sản, vàng bạc,\nHay mọi vật sở hữu,\nNô tỳ và lao công,\nCác mạng sống tùy thuộc,\nVị ấy phải ra đi,\nKhông đem theo được ai,\nTất cả phải bỏ lại,\nKhi ra đi một mình.\nChỉ có các hành động,\nVề thân, miệng và ý.\nMới thật thuộc vị ấy,\nMang theo khi ra đi,\nNghiệp ấy theo vị ấy,\nNhư bóng không rời hình.\nDo vậy hãy làm lành,\nTích lũy cho đời sau,\nCông đức cho đời sau,\nLàm hậu cứ cho người.`, ref: "Tương Ưng Bộ 3.20", url: "https://loicuaducphat.org/sn/sn3.20.html#content" },

{ text: `- Như vậy là phải, thưa Ðại vương. Như vậy là phải, thưa Ðại vương. Tất cả chúng sanh đều phải chết, đều kết thúc trong sự chết, đều không vượt qua sự chết. Ví như, thưa Ðại vương, tất cả đồ gốm do người thợ gốm làm ra, chưa nung chín hay đã nung chín, tất cả đồ gốm ấy đều phải bể, đều kết thúc trong sự bể, đều không vượt qua sự bể. Cũng vậy, thưa Ðại vương, tất cả chúng sanh đều phải chết, đều kết thúc trong sự chết, đều không vượt qua sự chết.\n\nMọi chúng sanh sẽ chết,\nMạng sống, chết kết thúc,\nTùy nghiệp, họ sẽ đi,\nNhận lãnh quả thiện ác,\nÁc nghiệp, đọa địa ngục,\nThiện nghiệp, lên Thiên giới.\nDo vậy hãy làm lành,\nTích lũy cho đời sau,\nCông đức cho đời sau,\nLàm hậu cứ cho người.`, ref: "Tương Ưng Bộ 3.22", url: "https://loicuaducphat.org/sn/sn3.22.html#content" },

{ text: `- Thưa Ðại vương, có ba pháp ở đời, khi khởi lên đưa lại bất lợi, đau khổ, bất an trú. Thế nào là ba? Thưa Ðại vương, tham là pháp ở đời, khi khởi lên đưa lại bất lợi, đau khổ, bất an trú. Thưa Ðại vương, sân là pháp ở đời, khi khởi lên đưa lại bất lợi, đau khổ, bất an trú. Thưa Ðại vương, si là pháp ở đời, khi khởi lên đưa lại bất lợi, đau khổ, bất an trú. Thưa Ðại vương, ba pháp này ở đời, khi khởi lên đem lại bất lợi, đau khổ, bất an trú.\n\nTham, sân, si ba pháp,\nLà ác tâm cho người,\nChúng di hại tự ngã,\nChúng tác thành tự ngã,\nNhư vỏ và lõi cây,\nTự tác thành trái cây.`, ref: "Tương Ưng Bộ 3.23", url: "https://loicuaducphat.org/sn/sn3.23.html#content" },

{ text: `Như núi đá rộng lớn,\nDựng đứng lên hư không,\nTiến tới tràn xung quanh,\nÁp đè cả bốn phía.\nCũng vậy, già và chết\nDi chuyển đến hữu tình,\nGiai cấp Sát-đế-lỵ,\nBà-la-môn, Phệ-xá,\nThủ-đà, Chiên-đà-la\nKẻ đổ rác, đổ phân,\nKhông một ai thoát khỏi,\nTất cả bị chinh phục.\nỞ đây không tượng binh,\nKhông xa binh, bộ binh,\nKhông trận chiến chú thuật,\nKhông trận chiến tài sản\nCó thể giúp chiến thắng,\nChống với già, với chết.\nDo vậy người hiền trí,\nThấy rõ phần tự lợi,\nNgười trí đặt tin tưởng,\nVào Phật, Pháp và Tăng.\nAi với thân, khẩu, ý,\nHành trì đúng Chánh pháp,\nÐời này được tán thán,\nÐời sau, hưởng phước trời.`, ref: "Tương Ưng Bộ 3.25", url: "https://loicuaducphat.org/sn/sn3.25.html#content" },

{ text: `(Thế Tôn):\nTa đã được giải thoát,\nKhỏi bẫy sập của ma,\nThoát khỏi dây dục lạc,\nCả Thiên giới, Nhân giới.\nTa đã được giải thoát,\nKhỏi triền phược của ma,\nNày kẻ Tử ma kia,\nÔng đã bị bại trận.`, ref: "Tương Ưng Bộ 4.4", url: "https://loicuaducphat.org/sn/sn4.4.html#content" },

{ text: `- Này các Tỷ-kheo, Ta đã được giải thoát khỏi tất cả bẫy sập ở Thiên giới và Nhân giới. Này các Tỷ-kheo, các Ông cũng được giải thoát khỏi tất cả bẫy sập ở Thiên giới và Nhân giới. Này các Tỷ-kheo, hãy du hành vì hạnh phúc cho quần chúng, vì an lạc cho quần chúng, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư Thiên và loài Người. Chớ có đi hai người một chỗ. Này các Tỷ-kheo, hãy thuyết pháp sơ thiện, trung thiện, hậu thiện, có nghĩa, có văn. Hãy tuyên thuyết Phạm hạnh hoàn toàn viên mãn thanh tịnh. Có các chúng sanh sanh ra ít nhiễm bụi đời, nếu không được nghe pháp sẽ đi đến hoại diệt. Họ sẽ trở thành những vị thâm hiểu Chánh pháp. Này các Tỷ-kheo, Ta sẽ đi đến Uruvelà, thị trấn Senà để thuyết pháp.`, ref: "Tương Ưng Bộ 4.5", url: "https://loicuaducphat.org/sn/sn4.5.html#content" },

{ text: `Rồi Thế Tôn biết: “Ðây là Ác ma”, liền nói lên bài kệ này với Ác ma:\n\nQuý thay bậc Mâu-ni,\nSống trong nhà không tịch,\nBiết chế ngự tự ngã,\nTại đấy vị ấy trú.\nSống từ bỏ tất cả,\nVới hạnh tu tương xứng,\nNhiều loại thú bộ hành,\nNhiều sự vật khủng khiếp,\nNhiều ruồi muỗi độc xà,\nKhông mảy may rung động\nSợi lông bậc Mâu-ni\nSống trong nhà không tịch.\nDầu trời nứt, đất động,\nDầu muôn loài khủng bố,\nDầu bị giáo, đao, tên,\nQuẳng ném vào ngực Ngài,\nChư Phật không tạo nên,\nNhững căn cứ sanh y .`, ref: "Tương Ưng Bộ 4.6", url: "https://loicuaducphat.org/sn/sn4.6.html#content" },

{ text: `Rồi Ác ma đi đến Thế Tôn; sau khi đến, nói lên bài kệ với Thế Tôn:\nSao Ngài còn nằm ngủ,\nSao Ngài vẫn nằm ngủ,\nSao Ngài ngủ như vậy,\nNhư kẻ chết nằm co?\nNghĩ rằng nhà trống không,\nNên Ngài ngủ như vậy,\nSao Ngài ngủ như vậy,\nKhi mặt trời đã mọc?\n\n(Thế Tôn):\nKhi không còn tham ái,\nVới lưới triền, nọc độc,\nNgười vậy được giải thoát,\nKhông bị dẫn nơi nào.\nÁc ma! Bậc Giác Ngộ\nMọi sanh y diệt tận,\nVị ấy nếu có ngủ,\nCác Ông làm được gì?`, ref: "Tương Ưng Bộ 4.7", url: "https://loicuaducphat.org/sn/sn4.7.html#content" },

{ text: `Rồi Ác ma đi đến Thế Tôn; sau khi đến, nói lên bài kệ này trước mặt Thế Tôn:\nCha sung sướng vì con,\nNgười chăn sướng vì bò,\nNgười sướng vì sanh y,\nKhông sanh y, không sướng.\n\n(Thế Tôn):\nCha sầu vì con cái,\nNgười chăn sầu vì bò,\nNgười sầu vì sanh y,\nKhông sanh y, không sầu.`, ref: "Tương Ưng Bộ 4.8", url: "https://loicuaducphat.org/sn/sn4.8.html#content" },

{ text: `- Này các Tỷ-kheo, ngắn ngủi thay là tuổi thọ loài Người ở đời này, rồi phải đi trong tương lai! Hãy làm điều lành. Hãy sống Phạm hạnh. Không có gì sanh ra lại không bị tử vong. Này các Tỷ-kheo, người sống lâu chỉ có một trăm năm, hoặc ít hơn, hoặc nhiều hơn.\n\nLoài Người thọ mạng ngắn,\nNgười lành phải âu lo,\nNhư cháy đầu, hãy sống,\nTử vong rồi phải đến.\n\nNgày đêm có trôi qua,\nThọ mạng có chấm dứt,\nMạng người phải khô cạn,\nNhư suối nhỏ đầu non.`, ref: "Tương Ưng Bộ 4.9", url: "https://loicuaducphat.org/sn/sn4.9.html#content" },

{ text: `Rồi Ác ma đi đến Thế Tôn; sau khi đến, nói lên bài kệ này với Thế Tôn:\nSao Ngài uể oải nằm,\nHay tìm thơ, tìm vận,\nPhải chăng việc sai biệt,\nKhông chờ đợi Ngài làm,\nPhải một mình cô độc,\nTrên ghế giường nằm, ngồi,\nVới gương mặt ngái ngủ,\nSao Ngài ngủ như vậy?\n\n(Thế Tôn):\nTa không uể oải nằm,\nKhông tìm thơ, tìm vận,\nMục đích Ta đã đạt,\nÐâu có sầu muộn gì!\nTa nằm ngồi một mình,\nTrên ghế giường vắng lặng,\nYên tĩnh Ta nằm nghỉ,\nTâm từ, thương chúng sanh.\nNhững kẻ, ngực bị đâm,\nHổn hển tim dồn dập,\nVẫn tìm được giấc ngủ,\nDầu bị thương tích nặng.\nSao Ta lại không ngủ,\nKhi không bị thương tích,\nKhi thức không âu lo,\nKhi ngủ chẳng sợ hãi,\nNgày đêm không khởi lên,\nPhiền não bận lòng Ta?\nTa không thấy tai hại,\nMột chỗ nào trên đời,\nDo vậy, Ta nằm nghỉ,\nTâm từ, thương chúng sanh.`, ref: "Tương Ưng Bộ 4.13", url: "https://loicuaducphat.org/sn/sn4.13.html#content" },

{ text: `Rồi Ác ma suy nghĩ: “Sa-môn Gotama này, xung quanh có đại chúng cư sĩ đoanh vây, đang thuyết pháp. Vậy ta hãy đi đến Sa-môn Gotama và làm mờ mắt đại chúng này.” Rồi Ác ma đi đến Thế Tôn; sau khi đến, nói lên bài kệ với Thế Tôn:\n\nThật không chút thích hợp,\nÐể Ngài giảng dạy người,\nGiữa người thuận, kẻ nghịch,\nChớ hành nghề đứng giữa.\n\n(Thế Tôn):\nVới lòng từ, thương tưởng,\nBậc Giác Ngộ dạy người,\nGiữa người thuận, kẻ nghịch,\nNhư Lai chơn giải thoát.`, ref: "Tương Ưng Bộ 4.14", url: "https://loicuaducphat.org/sn/sn4.14.html#content" },

{ text: `Rồi Ác ma đi đến Thế Tôn; sau khi đến, nói lên bài kệ với Thế Tôn:\nMọi hành tung của ý\nLà bẫy sập trên không,\nChính với bẫy sập ấy,\nTa trói buộc lấy Ngài,\nNày vị Sa-môn kia,\nNgài chưa thoát khỏi ta.\n\n(Thế Tôn):\nSắc, thanh, vị, hương, xúc,\nLàm tâm ý ưa thích,\nTa không ưa muốn chúng,\nTa vượt thoát ngoài chúng,\nNày kẻ Tử ma kia,\nÔng đã bị bại trận.`, ref: "Tương Ưng Bộ 4.15", url: "https://loicuaducphat.org/sn/sn4.15.html#content" },

{ text: `Và Thế Tôn biết được: “Ðây là Ác ma”, liền nói lên bài kệ cho Ác ma:\nSắc, thọ, tưởng, hành, thức,\nCái ấy không phải tôi,\nCái ấy không của tôi,\nNhư vậy đây ly tham,\nLy tham vậy, tâm an,\nMọi kiết sử siêu thoát,\nDầu tìm mọi xứ sở,\nMa quân không gặp được.`, ref: "Tương Ưng Bộ 4.16", url: "https://loicuaducphat.org/sn/sn4.16.html#content" },

{ text: `Rồi Thế Tôn biết được: “Ðây là Ác ma”, liền nói bài kệ cho Ác ma:\nSắc, thanh, vị và hương,\nCùng toàn bộ xúc, pháp,\nLà thế vật rùng rợn,\nLàm mê loạn ở đời.\nÐệ tử bậc Chánh Giác,\nChánh niệm, vượt khỏi chúng,\nVượt thế lực Ác ma,\nNhư mặt trời sáng chói.`, ref: "Tương Ưng Bộ 4.17", url: "https://loicuaducphat.org/sn/sn4.17.html#content" },

{ text: `Một thời Thế Tôn ở Kosala, dưới chân núi Tuyết Sơn, tại một am thất nhỏ trong rừng. Trong khi Thế Tôn Thiền tịnh độc cư, tư tưởng sau đây được khởi lên: “Có thể chăng cai trị mà không giết hại, không để người giết hại; không chinh phục, không khiến người chinh phục; không sầu muộn, không khiến người sầu muộn một cách đúng pháp?”.\n\n(Thế Tôn):\nDầu cho cả ngọn núi,\nTrở thành toàn vàng ròng,\nCho đến hóa gấp đôi,\nCũng không thỏa mãn được,\nTham vọng của một người.\nBiết vậy để hành trì,\nAi thấy rõ đau khổ,\nVà nguyên nhân đau khổ,\nLàm sao người như vậy,\nCó khuynh hướng ái dục?\nSau khi biết sanh y\nLà ràng buộc ở đời,\nNgười biết vậy nên học,\nGiải trừ mọi buộc ràng.`, ref: "Tương Ưng Bộ 4.20", url: "https://loicuaducphat.org/sn/sn4.20.html#content" },

{ text: `Rồi Ác ma biến hình thành một Bà-la-môn, với búi tóc lớn, mặc áo bằng da con linh dương, già yếu, lưng còm như xà nhà, hơi thở hổn hển, tay cầm gậy bằng gỗ udumbara, đi đến các Tỷ-kheo ấy; sau khi đến, nói với các Tỷ-kheo:\n- Chư Ðại đức xuất gia quá trẻ, niên thiếu, tóc còn đen nhánh, trong tuổi thanh xuân, trong thời trẻ thơ của tuổi đời, không thọ hưởng các dục. Chư Ðại đức hãy thọ hưởng các ái dục của con người, chớ có bỏ hiện tại và chạy theo những gì bị thời gian chi phối.\n\n- Này Bà-la-môn, chúng tôi không bỏ hiện tại và chạy theo những gì bị thời gian chi phối. Và này Bà-la-môn, chúng tôi bỏ những gì bị thời gian chi phối và chạy theo hiện tại. Này Bà-la-môn, Thế Tôn đã nói các dục bị thời gian chi phối, nhiều khổ đau, nhiều phiền não, tai họa ở đấy càng nhiều hơn. Còn pháp này thuộc về hiện tại, không bị thời gian chi phối, đến để mà thấy, có khả năng hướng thượng, và chỉ người trí mới tự mình giác hiểu.`, ref: "Tương Ưng Bộ 4.21", url: "https://loicuaducphat.org/sn/sn4.21.html#content" },

{ text: `Rồi Thế Tôn biết được ý nghĩa này, ngay khi ấy nói lên bài kệ:\nAi thấy rõ khổ đau,\nVà nguyên nhân đau khổ,\nLàm sao người như vậy,\nCó khuynh hướng các dục?\nSau khi biết sanh y\nLà ràng buộc ở đời,\nNgười biết vậy nên học,\nGiải trừ mọi buộc ràng.`, ref: "Tương Ưng Bộ 4.21", url: "https://loicuaducphat.org/sn/sn4.21.html#content" },

{ text: `Rồi Tôn giả Samiddhi, sau khi biết: “Ðây là Ác ma” liền nói lên bài kệ với Ác ma:\nTa với lòng tín ngưỡng,\nBỏ gia đình, xuất gia,\nNiệm tuệ ta tăng trưởng,\nTâm tư ta Thiền định.\nDầu Ông tạo sắc gì,\nKhông làm ta sợ hãi.`, ref: "Tương Ưng Bộ 4.22", url: "https://loicuaducphat.org/sn/sn4.22.html#content" },

{ text: `(Thế Tôn):\nVị Anh hùng kiên chí,\nThường Thiền lạc, Thiền tư,\nNgày đêm đầy nhiệt tình,\nNhưng sự sống, không tham,\nChiến thắng quân thần chết,\nTái sanh không đi đến,\nChinh phục ái, ái căn.`, ref: "Tương Ưng Bộ 4.23", url: "https://loicuaducphat.org/sn/sn4.23.html#content" },

{ text: `Rồi Ác ma đi đến Thế Tôn, sau khi đến, nói lên bài kệ với Thế Tôn:\nVới tâm tư sầu muộn,\nNgài Thiền tư trong rừng,\nVì tài sản hao mòn,\nHay vì thèm tài sản?\nCó thể tại xóm làng,\nNgài đã gây tội phạm.\nSao Ngài không làm thân\nVới bà con xóm giềng?\nSao Ngài không có thể\nLàm bạn với một ai?\n\n(Thế Tôn):\nMọi sầu căn nhổ sạch,\nKhông tội phạm, Ta Thiền,\nKhông sầu muộn, Ta Thiền.\nMọi hữu ái, đoạn tận,\nVô lậu, Ta Thiền định,\nNày Bà con phóng dật!`, ref: "Tương Ưng Bộ 4.24", url: "https://loicuaducphat.org/sn/sn4.24.html#content" },

{ text: `(Thế Tôn):\nVới mục đích đạt thành,\nVới thân tâm an tịnh,\nTa chiến thắng quân binh.\nHình sắc lạc, khả ái.\nTa độc tọa Thiền tư,\nChứng ngộ chơn an lạc,\nDo vậy, giữa chúng sanh,\nTa không bạn một ai.\nLàm bạn với một ai,\nÐối với Ta không cần.`, ref: "Tương Ưng Bộ 4.25", url: "https://loicuaducphat.org/sn/sn4.25.html#content" },

{ text: `Rồi nữ ma Bất lạc nói lên bài kệ với Thế Tôn:\nLàm sao vị Tỷ-kheo,\nSống giữa nhiều chướng ngại,\nÐã vượt năm bộc lưu,\nLại gắng vượt thứ sáu?\nLàm sao Thiền tư được,\nGiữa rất nhiều dục tưởng,\nÐược giữ ngoài vị ấy,\nKhông bắt vị ấy được?\n\n(Thế Tôn):\nVới thân được khinh an,\nVới tâm khéo giải thoát,\nKhông còn các sở hành,\nChánh niệm, không tham trước,\nBiết rõ được Chánh pháp,\nKhông tầm, tu Thiền định.\nKhông phẫn nộ, vọng niệm,\nKhông thụy miên, giải đãi,\nNhư vậy vị Tỷ-kheo,\nSống giữa nhiều chướng ngại,\nÐã vượt năm bộc lưu,\nLại gắng vượt thứ sáu,\nNhư vậy tu Thiền tư,\nGiữa rất nhiều dục tưởng,\nÐược giữ ngoài vị ấy,\nKhông bắt vị ấy được.`, ref: "Tương Ưng Bộ 4.25", url: "https://loicuaducphat.org/sn/sn4.25.html#content" },

{ text: `Tỷ-kheo-ni Alavikà biết được: “Ðấy là Ác ma”, liền nói lên bài kệ:\n\nỞ đời có xuất ly,\nNhờ trí tuệ, ta chứng.\nNày Bà con phóng dật,\nBiết sao được pháp ấy?\nÁi dục như kiếm thương,\nÐài chém đầu các uẩn.\nÐiều Ông gọi dục lạc,\nTa gọi là bất lạc.`, ref: "Tương Ưng Bộ 5.1", url: "https://loicuaducphat.org/sn/sn5.1.html#content" },

{ text: `Tỷ-kheo-ni Somà biết được: “Ðây là Ác ma”, liền nói lên bài kệ với Ác ma:\n\nNữ tánh chướng ngại gì,\nKhi tâm khéo Thiền định,\nKhi trí tuệ triển khai,\nChánh quán pháp vi diệu?\nAi tự mình tìm hỏi:\n“Ta, nữ nhân, nam nhân,\nHay ta là ai khác?”\nXứng nói chuyện Ác ma,\nÁc ma thật cân xứng.`, ref: "Tương Ưng Bộ 5.2", url: "https://loicuaducphat.org/sn/sn5.2.html#content" },

{ text: `Tỷ-kheo-ni Vijayà suy nghĩ: “Ðây là Ác ma”, liền nói lên bài kệ với Ác ma:\n\nSắc, tiếng, vị, hương, xúc,\nLàm cho ý đam mê,\nTa nhường lại Ác ma,\nTa đâu có cần chúng.\nVới thân bất tịnh này,\nDễ hư hoại mong manh,\nTa bực phiền, tủi hổ,\nDục ái được đoạn tận.\nHọ sanh hưởng sắc giới,\nChúng vọng vô sắc giới,\nThiền chứng an tịnh ấy,\nMọi nơi, mê ám diệt.`, ref: "Tương Ưng Bộ 5.4", url: "https://loicuaducphat.org/sn/sn5.4.html#content" },

{ text: `(Càlà):\nSanh ra rồi phải chết,\nÐã sanh thấy khổ đau,\nKiết sử trói gia hại,\nDo vậy không thích sanh.\nÐức Phật thuyết giảng pháp,\nKhiến vượt khỏi tái sanh,\nÐoạn trừ mọi khổ não,\nGiúp ta trú chân thật.\nChúng sanh hướng sắc giới,\nHọ vọng vô sắc giới,\nNếu không biết đoạn diệt,\nHọ đi đến tái sanh.`, ref: "Tương Ưng Bộ 5.6", url: "https://loicuaducphat.org/sn/sn5.6.html#content" },

{ text: `Rồi Ác ma đi đến Tỷ-kheo-ni Sisupacàlà; sau khi đến, nói với Tỷ-kheo-ni Sisupacàlà:\nVì ai Nàng trọc đầu,\nHiện tướng nữ Sa-môn?\nNàng không thích tà giáo,\nVậy nàng tu cho ai,\nNày kẻ Ngu muội kia?\n\n(Sisupacàlà):\nNhững kẻ tin tà kiến,\nThuộc ngoại đạo tà giáo.\nTa không thích pháp họ,\nTa không giỏi pháp họ!\nCó dòng họ Thích-ca.\nÐản sanh Phật vô tỷ,\nNgài chinh phục tất cả,\nNgài đại phá chúng ma,\nTại mọi chỗ, mọi nơi,\nKhông ai chiến thắng Ngài.\nNgài giải thoát hoàn toàn,\nKhông bị gì triền phược.\nBậc Pháp nhãn thấy khắp;\nTất cả nghiệp đoạn diệt,\nGiải thoát, diệt sanh y.\nThế Tôn, Ðạo Sư ta,\nTa thích giáo pháp Ngài.`, ref: "Tương Ưng Bộ 5.8", url: "https://loicuaducphat.org/sn/sn5.8.html#content" },

{ text: `Do ai, hữu tình này,\nÐược sanh, được tạo tác?\nNgười tạo hữu tình này,\nHiện nay ở tại đâu?\nTừ đâu hữu tình sanh?\nÐi đâu hữu tình diệt?\n\nRồi Tỷ-kheo-ni Vajirà biết được: “Ðây là Ác ma”, liền trả lời Ác ma với bài kệ:\n\nSao Ông lại nói hoài,\nÐến hai chữ chúng sanh?\nPhải chăng, này Ác ma,\nÔng rơi vào tà kiến?\nÐây quy tụ các hành,\nChúng sanh được hình thành,\nNhư bộ phận quy tụ,\nTên xe được nói lên.\nCũng vậy, uẩn quy tụ,\nThông tục gọi chúng sanh.\nChỉ có khổ được sanh,\nKhổ tồn tại, khổ diệt,\nNgoài khổ, không gì sanh,\nNgoài khổ không gì diệt.`, ref: "Tương Ưng Bộ 5.10", url: "https://loicuaducphat.org/sn/sn5.10.html#content" },

{ text: `Ðứng một bên, Phạm thiên Sahampati nói lên bài kệ này trước mặt Thế Tôn:\n\nHãy ở chỗ núi non,\nXa vắng các xóm làng,\nHãy sống đời giải thoát,\nTừ bỏ các kiết sử!\nNếu tại đấy không đạt\nÐiều Ông ưa, Ông thích,\nHãy sống giữa chúng Tăng,\nHộ trì, giữ chánh niệm,\nVà bộ hành khất thực,\nNhà này đến nhà khác,\nCác căn được hộ trì,\nThận trọng, giữ chánh niệm.\nHãy ở chỗ núi non,\nXa vắng các xóm làng,\nThoát ly mọi sợ hãi,\nVô úy, sống giải thoát.\nNhững chỗ có rắn độc,\nCó đêm chớp, sấm vang,\nTrong đêm đen tối mịt,\nVị Tỷ-kheo lặng ngồi,\nKhông run, không hoảng sợ,\nLông tóc không dựng ngược.`, ref: "Tương Ưng Bộ 6.13", url: "https://loicuaducphat.org/sn/sn6.13.html#content" },

{ text: `- Cũng vậy, này Bà-la-môn, nếu Ông phỉ báng chúng tôi là người không phỉ báng; nhiếc mắng chúng tôi là người không nhiếc mắng; gây lộn với chúng tôi là người không gây lộn; chúng tôi không thâu nhận sự việc ấy từ Ông, thời này Bà-la-môn, sự việc ấy về lại Ông. Này Bà-la-môn, sự việc ấy chỉ về lại Ông. Này Bà-la-môn, ai phỉ báng lại khi bị phỉ báng, nhiếc mắng lại khi bị nhiếc mắng, gây lộn lại khi bị gây lộn, thời như vậy, này Bà-la-môn, người ấy được xem là đã hưởng thọ, đã san sẻ với Ông. Còn chúng tôi không cùng hưởng thọ sự việc ấy với Ông, không cùng san sẻ sự việc ấy với Ông, thời này Bà-la-môn, sự việc ấy về lại Ông! Này Bà-la-môn, sự việc ấy về lại Ông!`, ref: "Tương Ưng Bộ 7.2", url: "https://loicuaducphat.org/sn/sn7.2.html#content" },

{ text: `(Thế Tôn):\nVới vị không phẫn nộ,\nPhẫn nộ từ đâu đến?\nSống chế ngự, chánh mạng,\nGiải thoát, nhờ chánh trí.\nVị ấy sống như vậy,\nÐời sống được tịch tịnh.\nNhững ai bị phỉ báng,\nTrở lại phỉ báng người,\nKẻ ấy làm ác mình,\nLại làm ác cho người.\nNhững ai bị phỉ báng,\nKhông phỉ báng chống lại,\nNgười ấy đủ thắng trận,\nThắng cho mình, cho người.\nVị ấy tìm lợi ích,\nCho cả mình và người.\nVà kẻ đã phỉ báng,\nTự hiểu, lắng nguôi dần.\nBậc Y sư cả hai,\nChữa mình, chữa cho người,\nQuần chúng nghĩ là ngu,\nVì không hiểu Chánh pháp.`, ref: "Tương Ưng Bộ 7.2", url: "https://loicuaducphat.org/sn/sn7.2.html#content" },

{ text: `Nội triền và ngoại triền,\nChúng sanh bị triền phược,\nCon hỏi Gotama,\nAi thoát triền phược này?\n\n(Thế Tôn)\nNgười có trí, trú giới,\nTu tập tâm và tuệ,\nNhiệt tâm và thận trọng,\nTỷ-kheo ấy thoát triền.\nVới ai đã từ bỏ,\nTham sân và vô minh,\nBậc Ứng cúng lậu tận,\nVị ấy thoát triền phược.\nChỗ nào danh và sắc\nÐược đoạn tận vô dư,\nÐoạn chướng ngại sắc tưởng,\nChỗ ấy triền phược đoạn.`, ref: "Tương Ưng Bộ 7.6", url: "https://loicuaducphat.org/sn/sn7.6.html#content" },

{ text: `Rồi Bà-la-môn Sundarika Bharadvāja đi đến Thế Tôn; sau khi đến, nói với Thế Tôn: - Thọ sanh Tôn giả là gì?\n\n(Thế Tôn):\nChớ hỏi về thọ sanh,\nHãy hỏi về sở hành.\nTùy theo mọi thứ củi,\nNgọn lửa được sanh khởi.\nDầu thuộc nhà hạ tiện,\nBậc ẩn sĩ tinh cần,\nÐược xem như thượng sanh,\nBiết tàm quý, trừ ác.\nÐiều thuận bởi chân lý,\nThuần thục trong hành trì,\nThông đạt các Thánh kinh,\nPhạm hạnh được viên thành.\nTế vật đã đem lại,\nHãy cầu khẩn vị ấy,\nLễ tế làm đúng thời,\nVị ấy xứng cúng dường.`, ref: "Tương Ưng Bộ 7.9", url: "https://loicuaducphat.org/sn/sn7.9.html#content" },

{ text: `Rồi Bà-la-môn Kasi Bharadvāja nói lên bài kệ với Thế Tôn:\nÔng nói là nông phu,\nTa không thấy Ông cày,\nNgười nông phu được hỏi,\nHãy lên tiếng trả lời,\nSao chúng tôi biết được,\nÔng thật sự có cày?\n\n(Thế Tôn):\nLòng tin là hạt giống,\nKhổ hạnh là mưa móc,\nTrí tuệ đối với Ta,\nLà cày và ách mang,\nTàm quý là cán cày,\nÝ căn là dây cột,\nChánh niệm đối với Ta,\nLà lưỡi cày, gậy đâm.\nThân hành được hộ trì,\nKhẩu hành được hộ trì\nÐối với các món ăn,\nBụng Ta dùng vừa phải,\nTa nhổ lên tà vạy,\nVới chơn lý sự thật,\nHoan hỷ trong Niết-bàn\nLà giải thoát của Ta.\nTinh tấn đối với Ta,\nLà khả năng mang ách,\nÐưa Ta tiến dần đến,\nAn ổn khỏi ách nạn,\nÐi đến, không trở lui,\nChỗ Ta đi, không sầu.\nNhư vậy, cày ruộng này,\nÐưa đến quả bất tử,\nSau khi cày cày này,\nMọi đau khổ được thoát.`, ref: "Tương Ưng Bộ 7.11", url: "https://loicuaducphat.org/sn/sn7.11.html#content" },

{ text: `(Thế Tôn):\nNhiều lần và nhiều lần,\nChúng gieo vãi hạt giống.\nNhiều lần và nhiều lần,\nTrời mưa đi, mưa lại.\nNhiều lần và nhiều lần,\nNgười nông phu cày ruộng.\nNhiều lần và nhiều lần,\nLúa gạo đến quốc độ.\nNhiều lần và nhiều lần,\nHành khất lại xin ăn.\nNhiều lần và nhiều lần,\nThí chủ lại bố thí.\nNhiều lần và nhiều lần,\nThí chủ sau khi cho.\nNhiều lần và nhiều lần,\nÐược đi đến thiên giới.\nNhiều lần và nhiều lần,\nNgười làm sữa vắt sữa,\nNhiều lần và nhiều lần,\nBò con tìm bò mẹ.\nNhiều lần và nhiều lần,\nMệt sức và lao khổ.\nNhiều lần và nhiều lần,\nKẻ ngu nhập bào thai.\nNhiều lần và nhiều lần,\nLại sanh rồi lại chết.\nNhiều lần và nhiều lần,\nHọ mang đến nghĩa địa.\nHọ được đường giải thoát,\nKhông đưa đến tái sanh.\nBậc đại trí, đại tuệ,\nKhông sanh đi, sanh lại.`, ref: "Tương Ưng Bộ 7.12", url: "https://loicuaducphat.org/sn/sn7.12.html#content" },

{ text: `Ngồi xuống một bên, Bà-la-môn Devadhītā nói lên bài kệ với Thế Tôn:\nChỗ nào người thí chủ,\nXứng đáng nên bố thí?\nChỗ nào sự bố thí,\nÐưa đến quả báo lớn?\nCúng dường phải thế nào?\nCung kính phải thế nào?\n\n(Thế Tôn):\nAi biết được đời trước,\nThấy Thiên giới, ác thú,\nÐoạn diệt được tái sanh,\nThắng trí, bậc Mâu-ni.\nNên bố thí vị ấy,\nBố thí được quả lớn.\nCúng dường phải như vậy,\nCung kính phải như vậy.`, ref: "Tương Ưng Bộ 7.13", url: "https://loicuaducphat.org/sn/sn7.13.html#content" },

{ text: `Rồi Bà-la-môn Mànatthada sau khi ngồi trên ghế của mình, nói lên bài kệ với Thế Tôn:\nÐối ai không nên kiêu?\nÐối ai nên kính trọng?\nÐối ai nên tôn kính?\nCúng dường ai, tốt lành?\n\n(Thế Tôn):\nVới mẹ và với cha,\nVới anh nhiều tuổi hơn,\nVới thầy là thứ tư,\nKhông nên sanh kiêu mạn,\nNên kính trọng vị ấy,\nNên tôn kính vị ấy,\nCúng dường họ, tốt lành.\nCác bậc A-la-hán,\nThanh lương, lậu hoặc đoạn,\nViệc nên làm đã làm,\nHãy nhiếp phục kiêu mạn,\nBậc Vô thượng tôn ấy,\nÔng thật nên đảnh lễ.`, ref: "Tương Ưng Bộ 7.15", url: "https://loicuaducphat.org/sn/sn7.15.html#content" },

{ text: `Nay Ông làm việc gì,\nTrong rừng cây sa-la,\nKhiến Ông sống một mình,\nVui gì Ông tìm được,\nTỷ-kheo Gotama?\n\n(Thế Tôn):\nTa không phải làm gì,\nTrong khu rừng sa-la.\nVới Ta, rễ đã cắt,\nCả khu rừng rậm rạp,\nNhư vậy Ta được thoát,\nMọi rừng rú chông gai.\nTâm Ta không bị đâm,\nMột mình sống an lạc,\nÐoạn trừ mọi bất mãn,\nSống thích thú hoan hỷ.`, ref: "Tương Ưng Bộ 7.17", url: "https://loicuaducphat.org/sn/sn7.17.html#content" },

{ text: `Trong khu rừng thâm u,\nNhiều dễ sợ khủng khiếp,\nRừng trống không, hoang vắng,\nNgài vào sâu một mình,\nThân bất động, kiên trì,\nÐẹp đẽ và uy nghi.\nNày Tỷ-kheo, Ngài thiền\nVới tâm tư định tĩnh.\nỞ đây không ca hát,\nỞ đây không nói năng,\nCô độc trong rừng sâu,\nBậc Thánh nhơn an trú,\nNhư vậy đối với con,\nThật kỳ diệu hy hữu.\nKhi Ngài sống một mình,\nHoan hỷ trong rừng vắng,\nCon nghĩ, Ngài ước nguyện,\nÐồng sanh làm thân hữu,\nVới bậc Thế giới chủ,\nTại vô thượng Tam thiên.\nVậy sao bậc Tôn giả,\nKhông bỏ rừng hoang vắng,\nTu khổ hạnh ở đây,\nÐể đạt Phạm thiên quả?\n\n(Thế Tôn):\nPhàm có ước vọng gì,\nHay những ái lạc gì,\nNhững gì kẻ phàm phu,\nThường chấp trước các giới,\nCác tham ái khởi lên,\nTừ gốc rễ vô minh,\nTất cả Ta đoạn tận,\nTrừ cả gốc lẫn rễ.\nNay Ta không ước nguyện,\nKhông tham ái, chấp trước,\nÐối với tất cả pháp,\nTa thấy đều thanh tịnh.\nÐạt được Chánh Ðẳng Giác,\nVà mục đích tối thượng,\nTa tu tập Thiền định,\nVắng lặng, không sợ hãi.`, ref: "Tương Ưng Bộ 7.18", url: "https://loicuaducphat.org/sn/sn7.18.html#content" },

{ text: `Ngồi xuống một bên, Bà-la-môn Màtaposaka nói với Thế Tôn:\n- Thưa Tôn giả Gotama, tôi tìm món ăn thiết thực theo thường pháp. Sau khi tìm món ăn thiết thực theo thường pháp, tôi nuôi dưỡng mẹ cha. Thưa Tôn giả Gotama, tôi làm như vậy; tôi có làm đúng trách nhiệm không?\n\n- Này Bà-la-môn, Ông làm như vậy là làm đúng trách nhiệm. Này Bà-la-môn, ai tìm đồ ăn thiết thực theo thường pháp; sau khi tìm đồ ăn thiết thực theo thường pháp, lại nuôi dưỡng mẹ cha thì người ấy được nhiều công đức.\n\nNgười nào theo thường pháp,\nNuôi dưỡng mẹ và cha,\nChính do công hạnh này,\nÐối với cha, với mẹ,\nNhờ vậy, bậc Hiền Thánh,\nTrong đời này tán thán,\nSau khi chết, được sanh,\nHưởng an lạc, chư Thiên.`, ref: "Tương Ưng Bộ 7.19", url: "https://loicuaducphat.org/sn/sn7.19.html#content" },

{ text: `Ngồi một bên Bà-la-môn Bhikkhaka bạch Thế Tôn:\n- Thưa Tôn giả Gotama, con là người khất thực và Tôn giả cũng là người khất thực. Vậy có sự sai khác gì giữa chúng ta?\n\n(Thế Tôn):\nKhông phải ai xin ăn,\nCũng gọi là khất sĩ.\nNếu chấp trì độc pháp,\nKhông còn gọi Tỷ-kheo.\nAi sống ở đời này,\nTừ bỏ các phước báo,\nÐoạn trừ mọi ác pháp,\nHành trì theo Phạm hạnh,\nSống đời sống chánh trí,\nVị ấy xứng “Tỷ-kheo”.`, ref: "Tương Ưng Bộ 7.20", url: "https://loicuaducphat.org/sn/sn7.20.html#content" },

{ text: `(Thế Tôn):\nChánh pháp là ao hồ,\nGiới là bến nước tắm,\nKhông cấu uế, trong sạch,\nÐược thiện nhơn tán thán,\nLà chỗ bậc có trí,\nThường tắm, trừ uế tạp,\nKhi tay chân trong sạch,\nHọ qua bờ bên kia.`, ref: "Tương Ưng Bộ 7.21", url: "https://loicuaducphat.org/sn/sn7.21.html#content" },

{ text: `Rồi Tôn giả Vangìsa sau khi tự mình đoạn trừ bất mãn và làm cho thỏa mãn khởi lên, liền ngay trong lúc ấy, nói lên những bài kệ này:\n\nVới ta đã xuất gia,\nBỏ nhà, sống không nhà,\nTâm tư nay chạy loạn,\nKhởi lên từ đen tối.\nCon nhà bậc thượng lưu,\nThiện xảo trong cung pháp,\nNgàn người bắn tứ phía,\nVẫn không bỏ chạy loạn.\nNếu phụ nữ có đến,\nDầu nhiều hơn, đông hơn,\nSẽ không não loạn ta,\nVì ta trú Chánh pháp,\nChính ta từng được nghe,\nPhật, dòng họ mặt trời,\nThuyết giảng Niết-bàn đạo,\nỞ đây ta ưa thích.\nNếu ta trú như vậy,\nÁc ma, Ông có đến,\nSở hành ta là vậy,\nÔng đâu thấy đường ta,`, ref: "Tương Ưng Bộ 8.1", url: "https://loicuaducphat.org/sn/sn8.1.html#content" },

{ text: `Rồi Tôn giả Vangìsa sau khi tự mình đoạn trừ bất mãn và làm thỏa mãn khởi lên, liền ngay trong lúc ấy nói lên bài kệ này:\n\nTa bỏ lạc, bất lạc,\nMọi tâm tư gia sự,\nKhông tạo một chỗ nào,\nThành cơ sở tham dục.\nAi thoát khỏi rừng tham,\nThoát ly mọi tham dục,\nLy tham không đắm trước,\nXứng danh chơn Tỷ-kheo.\nPhàm địa giới, không giới,\nCả sắc giới trong đời,\nMọi vật đều biến hoại,\nMọi sự đều vô thường.\nAi hiểu biết như vậy,\nSở hành sẽ chân chính.\nChúng sanh thường chấp trước,\nÐối với các sanh y,\nÐối vật họ thấy, nghe\nHọ ngửi, nếm, xúc chạm.\nỞ đây, ai đoạn dục,\nTâm tư không nhiễm ô,\nKhông mắc dính chỗ này,\nVị ấy danh Mâu-ni.\nÐối với sáu mươi pháp,\nThuộc vọng tưởng phi pháp,\nPhàm phu thường chấp trước,\nChấp thủ và tham đắm.\nTỷ-kheo không phiền não,\nKhông nói lời ác ngữ,\nSáng suốt, tâm thường định,\nKhông dối trá, thận trọng,\nThoát ly mọi tham ái.\nVị Mâu-ni chứng đạt,\nCảnh Niết-bàn tịch tịnh,\nChờ đón thời mệnh chung,\nVới tâm tư vắng lặng,\nThanh thoát nhập Niết-bàn.`, ref: "Tương Ưng Bộ 8.2", url: "https://loicuaducphat.org/sn/sn8.2.html#content" },

{ text: `Ðệ tử Gotama,\nHãy từ bỏ kiêu mạn,\nVà cũng tự bỏ luôn,\nCon đường đến kiêu mạn.\nNếu hoàn toàn đắm say,\nTrong con đường kiêu mạn,\nSẽ tự mình hối trách,\nTrong thời gian lâu dài.\nNhững ai khinh khi người,\nVới khinh khi kiêu mạn,\nÐi con đường kiêu mạn,\nSẽ đọa lạc địa ngục.\nNhững người ấy sầu khổ,\nTrong thời gian lâu dài,\nDo kiêu mạn dắt dẫn,\nPhải sanh vào địa ngục.\nTỷ-kheo không bao giờ\nPhải sầu muộn buồn thảm,\nThắng lợi trên chánh đạo,\nSở hành được chân chánh,\nVị ấy được thọ hưởng,\nDanh dự và an lạc,\nChơn thực được danh xưng,\nLà bậc hưởng Pháp lạc.\nDo vậy ở đời này,\nKhông thô lậu, tinh tấn\nÐoạn trừ mọi triền cái,\nSống thanh tịnh trong sạch,\nVà đoạn tận kiêu mạn,\nHoàn toàn, không dư thừa,\nChấm dứt mọi phiền não,\nVới trí tuệ quang minh,\nNgài được xem là bậc\nSống tịch tịnh an lạc.`, ref: "Tương Ưng Bộ 8.3", url: "https://loicuaducphat.org/sn/sn8.3.html#content" },

{ text: `Rồi Tôn giả Vangìsa nói lên bài kệ với Tôn giả Ānanda:\nDục ái đốt cháy tôi,\nTâm tôi bị thiêu cháy.\nThật là điều tốt lành,\nÐệ tử Gotama,\nVì lòng từ thương tưởng,\nNói pháp tiêu lửa hừng.\n\n(Ānanda):\nChính vì điên đảo tưởng,\nTâm Ông bị thiêu đốt,\nHãy từ bỏ tịnh tướng,\nHệ lụy đến tham dục,\nNhìn các hành vô thường,\nKhổ đau, không phải ngã,\nDập tắt đại tham dục,\nChớ để bị cháy dài;\nHãy tu tâm bất tịnh,\nNhất tâm, khéo định tĩnh,\nTu tập thân niệm trú,\nHành nhiều hạnh yểm ly;\nHãy tập hạnh vô tướng,\nÐoạn diệt mạn tùy miên,\nNhờ quán sâu kiêu mạn,\nHạnh Ông được an tịnh.`, ref: "Tương Ưng Bộ 8.4", url: "https://loicuaducphat.org/sn/sn8.4.html#content" },

{ text: `Rồi Tôn giả Vangìsa trước mặt Thế Tôn, nói lên những bài kệ tán thán thích đáng:\n\nAi nói lên lời gì,\nLời ấy không khổ mình,\nLại không làm hại người,\nLời ấy là thiện thuyết.\nAi nói lời ái ngữ,\nLời nói khiến hoan hỷ,\nLời nói không ác độc,\nLời ấy là ái ngữ.\nCác lời nói chơn thật,\nLà lời nói bất tử,\nNhư vậy là thường pháp,\nTừ thuở thật ngàn xưa.\nBậc Thiện Nhân được xem,\nAn trú trên chơn thực,\nTrên nghĩa và trên pháp,\nLời đồn là như vậy.\nLời đức Phật nói lên,\nÐạt an ổn Niết-bàn,\nChấm dứt mọi khổ đau,\nThật lời nói tối thượng.`, ref: "Tương Ưng Bộ 8.5", url: "https://loicuaducphat.org/sn/sn8.5.html#content" },

{ text: `Rồi một vị Thiên trú ở khu rừng ấy, thương xót Tỷ-kheo ấy, muốn hạnh phúc, muốn cảnh giác, liền đi đến Tỷ-kheo ấy. Sau khi đến, vị Thiên ấy nói lên những bài kệ với vị Tỷ-kheo này:\n\nÔng ước muốn viễn ly,\nÐã sống trong rừng núi,\nNay tâm Ông vọng động,\nDong duổi theo ngoại giới.\nÔng đối mặt với Ông,\nHãy chế ngự lòng dục,\nNhờ vậy, Ông hạnh phúc,\nThoát ly được tham ái.\nHãy từ bỏ bất mãn,\nSống an trú chánh niệm,\nÔng thành người hiền thiện,\nÐược chúng tôi tán thán.\nTrừ bụi trần địa ngục,\nThật rất khó vượt qua,\nÔng chớ vận chuyển theo,\nCác bụi trần dục vọng,\nNhư chim, thân dính bụi,\nRung thân khiến bụi rơi.\nCũng vậy vị Tỷ-kheo,\nTinh cần, trú chánh niệm,\nVùng vẫy khiến rơi rớt,\nNhững bụi đời dính thân.\n\nTỷ-kheo ấy được vị Thiên cảnh giác, tâm hết sức xúc động.`, ref: "Tương Ưng Bộ 9.1", url: "https://loicuaducphat.org/sn/sn9.1.html#content" },

{ text: `Tỷ-kheo, hãy thức dậy,\nSao Ông hãy còn nằm?\nÔng được lợi ích gì,\nTrong giấc ngủ của ông?\nKẻ bịnh, kẻ trúng tên,\nBị đánh sao ngủ được?\nVì lòng tin, xuất gia,\nBỏ nhà, sống không nhà,\nTín ấy cần phát triển,\nChớ để ngủ chinh phục.\n\n(Vị Tỷ-kheo):\nCác dục là vô thường,\nChỉ kẻ ngu say đắm,\nÐã giải thoát triền phược,\nKhông còn bị ái trước.\nHạnh xuất gia như vậy,\nSao để dục nhiệt não?\nÐã nhiếp phục dục ái,\nVượt thoát lưới vô minh,\nVới chánh trí thanh tịnh,\nHạnh xuất gia như vậy,\nSao để dục nhiệt não?\nVới minh phá vô minh,\nÐoạn diệt các lậu hoặc,\nKhông sầu, không ưu não,\nHạnh xuất gia như vậy,\nSao để dục nhiệt não?\nTinh tấn và nhiệt tâm,\nThường dõng mãnh cầu tiến,\nHướng vọng đến Niết-bàn,\nHạnh xuất gia như vậy,\nSao để dục nhiệt não?`, ref: "Tương Ưng Bộ 9.2", url: "https://loicuaducphat.org/sn/sn9.2.html#content" },

{ text: `Các Tỷ-kheo ấy an cư mùa mưa xong, sau ba tháng, bắt đầu đi du hành. Một vị Thiên trú ở khu rừng ấy, không thấy các Tỷ-kheo ấy, liền than van, ưu buồn, ngay lúc ấy nói lên bài kệ này:\n\nHôm nay tâm của ta,\nCảm thấy không vui vẻ,\nKhi thấy nhiều chỗ ngồi,\nTrống không, không có người.\nNhững bậc Ða văn ấy,\nThuyết pháp thật mỹ diệu.\nÐệ tử Gotama,\nHiện nay đang ở đâu?\n\nKhi nghe nói vậy, một vị Thiên khác nói lên những bài kệ cho vị Thiên ấy:\n\nHọ đi Magadha,\nHọ đi Kosala,\nVà một số vị ấy,\nÐi đến đất Vajjà.\nNhư nai thoát bẫy sập,\nChạy nhảy khắp bốn phương.\nTỷ-kheo không nhà cửa,\nSống giải thoát như vậy.`, ref: "Tương Ưng Bộ 9.4", url: "https://loicuaducphat.org/sn/sn9.4.html#content" },

{ text: `Lúc bấy giờ, Tôn giả Ānanda sống quá bận rộn bởi nhiều liên hệ với cư sĩ. Rồi một vị Thiên trú ở khu rừng ấy thương xót Tôn giả Ānanda, muốn hạnh phúc, muốn cảnh giác, liền đi đến Tôn giả Ānanda. Sau khi đến, vị ấy nói lên những bài kệ với Tôn giả Ānanda:\n\nÔng đã quyết lựa chọn,\nÐời sống dưới gốc cây,\nTâm Ông quyết nhập một\nVới mục đích Niết-bàn.\nCù-đàm, hãy Thiền tư,\nVà sống, chớ phóng dật,\nÐối với Ông, ích gì,\nTạp thoại, vô vị ấy?`, ref: "Tương Ưng Bộ 9.5", url: "https://loicuaducphat.org/sn/sn9.5.html#content" },

{ text: `Sau khi đến, vị ấy nói lên những bài kệ với Tôn giả Nàgadatta:\n\nNày Nàgadatta,\nHãy vào làng đúng thời,\nVà khi từ làng về,\nHãy về cho thật sớm.\nÔng sống quá liên hệ,\nVới các hàng cư sĩ,\nBị vấn vương quá nhiều,\nNhững cảm thọ khổ lạc.\nTa sợ kẻ bạt mạng,\nNàgadatta này,\nLại bị trói, bị buộc,\nTrong gia đình thế sự.\nChớ để mình rơi vào,\nCường lực của tử thần,\nLàm sao tránh né được,\nKhỏi Ác ma chi phối!\n\nTôn giả Nàgadatta được vị Thiên ấy cảnh giác, tâm hết sức xúc động.`, ref: "Tương Ưng Bộ 9.7", url: "https://loicuaducphat.org/sn/sn9.7.html#content" },

{ text: `Trên bờ sông, cửa chợ,\nTại trạm nghỉ, lộ trình,\nDân chúng thường tập hợp,\nTranh luận liền khởi lên.\nGiữa ta và giữa Ông,\nCó gì là sai khác?\n\n(Vị Tỷ-kheo):\nNhiều tiếng qua tiếng lại,\nBậc khổ hạnh kham nhẫn,\nChớ cảm thấy bực phiền,\nChớ phát sinh nhiễm trước.\nAi bị tiếng rối loạn,\nNhư nai trong rừng rú,\nÐược gọi là khinh tâm,\nKhó tu hành thành tựu.`, ref: "Tương Ưng Bộ 9.8", url: "https://loicuaducphat.org/sn/sn9.8.html#content" },

{ text: `Tỷ-kheo ấy được nghe tiếng nhạc khí, tiếng cồng v.v … đánh lên, tiếng ồn ào khởi lên, liền than thở, nói lên ngay lúc ấy những bài kệ này:\n\nChúng ta sống một mình,\nTrong khu rừng cô độc,\nNhư khúc gỗ lột vỏ,\nLăn lóc trong rừng sâu,\nTrong đêm tối hân hoan,\nNhư hiện tại đêm nay,\nAi sống đời bất hạnh,\nNhư chúng ta hiện sống?\n\nRồi một vị Thiên trú ở khu rừng ấy, có lòng thương xót Tỷ-kheo ấy, muốn hạnh phúc, muốn cảnh giác liền đi đến Tỷ-kheo ấy. Sau khi đến, vị ấy nói lên những bài kệ:\n\nÔng sống chỉ một mình,\nTrong khu rừng cô độc,\nNhư khúc gỗ lột vỏ,\nLăn lóc trong rừng sâu.\nRất nhiều người thèm muốn,\nÐời sống như ông vậy,\nNhư kẻ đọa địa ngục,\nThèm muốn sanh thiên giới.\n\nRồi Tỷ-kheo ấy được vị Thiên ấy cảnh giác, tâm hết sức xúc động.`, ref: "Tương Ưng Bộ 9.9", url: "https://loicuaducphat.org/sn/sn9.9.html#content" },

{ text: `Sau khi đến, vị Thiên ấy nói lên những bài kệ cho Tỷ-kheo:\n\nÔng tác ý bất chánh,\nNên say đắm tư duy.\nHãy từ bỏ bất chánh,\nHãy tư duy chơn chánh,\nNương tựa Phật, Pháp, Tăng,\nGiữ giới, không thối chuyển,\nÔng chắc chắn chứng đạt,\nHân hoan và hỷ lạc.\nVới hân hoan sung mãn,\nÔng chấm dứt khổ đau.\n\nRồi Tỷ-kheo ấy, được vị Thiên ấy cảnh giác, tâm hết sức xúc động.`, ref: "Tương Ưng Bộ 9.11", url: "https://loicuaducphat.org/sn/sn9.11.html#content" },

{ text: `Nay chính giờ giữa trưa,\nChim chóc đậu im lặng,\nRừng lớn vang tiếng động,\nKhiến ta run, hoảng sợ.\n\n(Vị Tỷ-kheo):\nNay chính giờ giữa trưa,\nChim chóc đậu im lặng,\nRừng lớn vang tiếng động,\nHoan hỷ đến với ta.`, ref: "Tương Ưng Bộ 9.12", url: "https://loicuaducphat.org/sn/sn9.12.html#content" },

{ text: `Xưa sống thật an lạc,\nChúng đệ tử Cù-đàm,\nKhông tham tìm món ăn,\nKhông tham tìm chỗ trú,\nBiết đời là vô thường,\nHọ chấm dứt khổ đau.\nNay tự làm ác hạnh,\nNhư thôn trưởng trong làng,\nHọ ăn, ăn ngã gục,\nThèm khát vật nhà người.\nCon vái chào chúng Tăng,\nÐảnh lễ một vài vị,\nVất vưởng, không hướng dẫn.\nHọ sống như ngạ quỉ.\nNhững ai sống phóng dật,\nVì họ, con nói lên,\nNhững ai không phóng dật,\nChân thành con đảnh lễ.`, ref: "Tương Ưng Bộ 9.13", url: "https://loicuaducphat.org/sn/sn9.13.html#content" },

{ text: `Chư Phật, Ngài dạy rằng,\nSắc không phải sinh mạng,\nVậy sao sinh mạng này,\nLại có trong thân này?\nTừ đâu xương thịt đến,\nTrong thân thể hiện tại?\nLàm sao sinh mạng này,\nGá dính trong thai tạng?\n\n(Thế Tôn):\n“Trước tiên giọt chất tụ,\nXuất hiện một nụ nhỏ,\nThịt mềm được sanh ra,\nRồi rắn đặc thành khối,\nTừ đó, các chi sanh,\nLông, tóc, móng xuất hiện.\nNhững gì người mẹ ăn,\nÐồ ăn, đồ uống nào,\nCon người trong bụng mẹ,\nỞ đấy, lấy nuôi dưỡng”.`, ref: "Tương Ưng Bộ 10.1", url: "https://loicuaducphat.org/sn/sn10.1.html#content" },

{ text: `Thật không tốt lành gì,\nMột Sa-môn như Ngài,\nÐã đoạn mọi triền phược,\nÐã sống chơn giải thoát,\nLại tiếp tục giảng dạy,\nNhững kẻ khác tu học.\n\n(Thế Tôn):\nNày Dạ-xoa Sakka,\nDầu vì lý do gì,\nLoài Người sống chung nhau,\nKhông một lý do nào,\nXứng đáng bậc trí tuệ,\nVới lòng từ lân mẫn,\nNếu với tâm tín thành,\nGiảng dạy những người khác,\nDo vậy không hệ lụy,\nVì lòng từ lân mẫn.`, ref: "Tương Ưng Bộ 10.2", url: "https://loicuaducphat.org/sn/sn10.2.html#content" },

{ text: `(Dạ-xoa):\nTham dục và sân hận,\nDo nhân gì sanh khởi?\nBất mãn và thỏa mãn,\nSợ hãi từ đâu sanh?\nTừ đâu được khởi lên,\nCác tư tưởng, tư duy,\nNhư quạ được bầy trẻ,\nThả bay rồi kéo lại?\n\n(Thế Tôn):\nTham dục và sân hận,\nDo nhân này sanh khởi,\nBất mãn và thỏa mãn,\nSợ hãi từ đây sanh.\nTừ đây được khởi lên,\nCác tư tưởng, tư duy,\nNhư quạ được bầy trẻ,\nThả bay rồi kéo lại.\nChính do tham ái sanh,\nChính do tự ngã sanh.\nNhư cây nigroda (cây bàng),\nDo từ thân cây sanh.\nPhàm phu bám ác dục,\nNhư cây leo khắp rừng.\nNhững ai hiểu biết được,\nDo nhân ấy sanh khởi,\nHọ diệt trừ nhân ấy.\nHãy nghe, này Dạ-xoa,\nHọ vượt bộc lưu này,\nBộc lưu thật khó vượt,\nTừ trước chưa vượt qua,\nKhông còn phải tái sanh.`, ref: "Tương Ưng Bộ 10.3", url: "https://loicuaducphat.org/sn/sn10.3.html#content" },

{ text: `(Thế Tôn):\nLành thay, thường chánh niệm,\nNhờ niệm, lạc tăng trưởng,\nCó niệm, mai đẹp hơn,\nHận thù được giải thoát.\nVới ai trọn ngày đêm,\nTâm ý lạc, bất hại,\nTừ tâm mọi hữu tình,\nVị ấy không thù hận.`, ref: "Tương Ưng Bộ 10.4", url: "https://loicuaducphat.org/sn/sn10.4.html#content" },

{ text: `- Bạch Thế Tôn, Thế Tôn ngủ có an lạc chăng?\n\n(Thế Tôn):\nBà-la-môn tịch tịnh,\nLuôn luôn sống an lạc,\nKhông đèo bồng dục vọng,\nThanh lương, không sanh y,\nMọi ái trước đoạn diệt,\nTâm khổ não điều phục,\nTịch tịnh, sống an lạc,\nTâm tư đạt hòa bình.`, ref: "Tương Ưng Bộ 10.8", url: "https://loicuaducphat.org/sn/sn10.8.html#content" },

{ text: `(Dạ-xoa):\nCái gì đối người đời,\nLà tài sản tối thượng?\nCái gì khéo hành trì,\nÐem lại chơn an lạc?\nCái gì giữa các vị,\nLà vị ngọt tối thượng?\nPhải sống như thế nào,\nÐược gọi sống tối thượng?\n\n(Thế Tôn):\nLòng tin đối người đời,\nLà tài sản tối thượng.\nChánh pháp khéo hành trì,\nÐem lại chơn an lạc.\nChân lý giữa các vị,\nLà vị ngọt tối thượng.\nPhải sống với trí tuệ,\nÐược gọi sống tối thượng.`, ref: "Tương Ưng Bộ 10.12", url: "https://loicuaducphat.org/sn/sn10.12.html#content" },

{ text: `(Dạ-xoa):\nLàm sao vượt bộc lưu?\nLàm sao vượt biển lớn?\nLàm sao thoát khổ não?\nLàm sao được thanh tịnh?\n\n(Thế Tôn):\nVới tín, vượt bộc lưu.\nKhông phóng dật, vượt biển.\nTinh tấn, thoát khổ não.\nVới Trí, được thanh tịnh.`, ref: "Tương Ưng Bộ 10.12", url: "https://loicuaducphat.org/sn/sn10.12.html#content" },

{ text: `(Dạ-xoa):\nLàm sao được trí tuệ?\nLàm sao được tài sản?\nLàm sao đạt danh xưng?\nLàm sao kết bạn hữu?\nÐời này qua đời khác,\nLàm sao không sầu khổ?\n\n(Thế Tôn):\nAi tin tưởng Chánh pháp\nCủa bậc A-la-hán,\nPháp ấy khiến đạt được,\nNiết-bàn (chơn an lạc),\nKhéo học, không phóng dật,\nMinh nhãn khéo phân biệt,\nNhờ hành trì như vậy,\nVị ấy được trí tuệ.\nLàm gì khéo thích hợp,\nGánh vác các trách nhiệm,\nPhấn chấn, thích hoạt động,\nNhư vậy được tài sản,\nChơn thật đạt danh xưng,\nBố thí kết bạn hữu,\nÐời này qua đời khác,\nNhư vậy không sầu khổ.\nTín nam gia chủ nào,\nTìm cầu bốn pháp này,\nChơn thực và chế ngự,\nKiên trì và xả thí,\nVị ấy sau khi chết,\nKhông còn phải sầu khổ.\nÐời này qua đời khác,\nSau chết, không sầu khổ.\nTa muốn Ông đến hỏi,\nSa-môn, Bà-la-môn,\nCó những pháp nào khác,\nTốt hơn bốn pháp này:\nChơn thực và chế ngự,\nXả thí và kham nhẫn.`, ref: "Tương Ưng Bộ 10.12", url: "https://loicuaducphat.org/sn/sn10.12.html#content" },

{ text: `Này các Tỷ-kheo, Thiên chủ Sakka ấy, sống nhờ quả công đức của mình, trị vì và cai trị chư Thiên ở Tam thập tam thiên, sẽ là người tán thán nỗ lực và tinh tấn. Ở đây, này các Tỷ-kheo, các Ông làm cho sáng chói, vị ấy khi các Ông xuất gia trong pháp luật khéo thuyết như vậy, nỗ lực, tinh cần hay tinh tấn để đạt được những gì chưa đạt, để chứng được những gì chưa chứng, để ngộ được những gì chưa ngộ.`, ref: "Tương Ưng Bộ 11.1", url: "https://loicuaducphat.org/sn/sn11.1.html#content" },

{ text: `Này các vị Tỷ-kheo,\nTrong rừng hay gốc cây,\nHay tại căn nhà trống,\nHãy niệm bậc Chánh Giác.\nCác Ông có sợ hãi,\nSợ hãi sẽ tiêu diệt.\nNếu không tư niệm Phật,\nTối thượng chủ ở đời,\nVà cũng là Ngưu vương,\nTrong thế giới loài Người,\nVậy hãy tư niệm Pháp,\nHướng thượng, khéo tuyên thuyết.\nNếu không tư niệm Pháp,\nHướng thượng, khéo tuyên thuyết,\nVậy hãy tư niệm Tăng,\nLà phước điền vô thượng.\nVậy này các Tỷ-kheo,\nNhư vậy tư niệm Phật,\nTư niệm Pháp và Tăng,\nSợ hãi hay hoảng hốt,\nHay lông tóc dựng ngược,\nKhông bao giờ khởi lên`, ref: "Tương Ưng Bộ 11.3", url: "https://loicuaducphat.org/sn/sn11.3.html#content" },

{ text: `Trong tư lợi tối thượng,\nKhông gì hơn kham nhẫn.\nNgười đầy đủ sức mạnh,\nChịu nhẫn người yếu kém,\nNhẫn ấy gọi tối thượng,\nThường nhẫn kẻ yếu hèn.\nSức mạnh của kẻ ngu,\nÐược xem là sức mạnh,\nThời sức mạnh kẻ mạnh,\nLại được gọi yếu hèn.\nNgười mạnh hộ trì pháp,\nKhông nói lời phản ứng,\nBị mắng nhiếc, mắng lại,\nÁc hại nặng nề hơn.\nBị mắng, không mắng lại,\nÐược chiến thắng hai lần.\nSống lợi ích cả hai,\nLợi mình và lợi người,\nBiết kẻ khác tức giận,\nGiữ niệm, tâm an tịnh,\nLà y sĩ cả hai,\nChữa mình và chữa người,\nQuần chúng nghĩ là ngu,\nVì không giỏi Chánh pháp.`, ref: "Tương Ưng Bộ 11.4", url: "https://loicuaducphat.org/sn/sn11.4.html#content" },

{ text: `(Sakka):\nMọi người phải tinh tấn,\nCho đến đích thành tựu.\nKhi mục đích thành tựu,\nThời chiếu diệu chói sáng,\nKhông gì tốt đẹp hơn,\nSo sánh với kham nhẫn.`, ref: "Tương Ưng Bộ 11.8", url: "https://loicuaducphat.org/sn/sn11.8.html#content" },

{ text: `(Sakka):\nMùi hương các ẩn sĩ,\nÐã lâu ngày tu hành,\nXuất phát từ thân họ,\nHãy được gió mang đi,\nNhư vòng hoa nhiều loại,\nÐược trang sức trên đầu.\nChư Tôn giả, chúng tôi,\nƯớc mong được hương ấy,\nKhông gì ở nơi đây,\nLàm chư Thiên ghê tởm.`, ref: "Tương Ưng Bộ 11.9", url: "https://loicuaducphat.org/sn/sn11.9.html#content" },

{ text: `- Này các Tỷ-kheo, thuở xưa, khi Thiên chủ Sakka còn làm người, vị này chấp trì và thật hành bảy cấm giới túc. Nhờ chấp trì bảy cấm giới túc này, Sakka được địa vị Sakka. Bảy cấm giới túc là gì?\n\n“Cho đến trọn đời, tôi hiếu dưỡng cha mẹ. Cho đến trọn đời, tôi kính trọng gia trưởng. Cho đến trọn đời, tôi nói lời nhu hòa. Cho đến trọn đời, tôi không nói lời hai lưỡi. Cho đến trọn đời, với tâm ly cấu uế và xan tham, tôi sống trong gia đình với tâm bố thí, với tay sạch sẽ, hoan hỷ thí xả, nhiệt tình đáp ứng các yêu cầu, sung sướng phân phối vật bố thí. Cho đến trọn đời, tôi nói lời chân thực. Cho đến trọn đời, tôi không phẫn nộ, nếu tôi có phẫn nộ, tôi sẽ mau chóng dẹp trừ phẫn nộ ấy”.\n\nAi hiếu dưỡng cha mẹ,\nKính trọng bậc gia trưởng,\nNói những lời nhu hòa,\nTừ bỏ lời hai lưỡi,\nChế ngự lòng xan tham,\nLà con người chân thực,\nNhiếp phục được phẫn nộ,\nVới con người như vậy,\nChư Thiên tam thập tam,\nGọi là bậc Chơn nhơn.`, ref: "Tương Ưng Bộ 11.11", url: "https://loicuaducphat.org/sn/sn11.11.html#content" },

{ text: `- Thuở xưa, này các Tỷ-kheo, một người ở tại thành Vương Xá này; người ấy nghèo khó, bần cùng, khốn khổ. Người ấy chấp trì lòng tin trong Pháp và Luật do Như Lai tuyên thuyết, chấp trì giới, chấp trì văn, chấp trì thí, chấp trì tuệ. Người ấy do chấp trì lòng tin trong Pháp và Luật do Như Lai tuyên thuyết, chấp trì giới, chấp trì văn, chấp trì thí, chấp trì tuệ. Sau khi thân hoại mạng chung, vị ấy được sanh thiện thú, Thiên giới, đời này và cọng trú với chư Thiên Tam thập tam thiên. Vị ấy chói sáng hơn chư Thiên khác về dung sắc và danh tiếng.`, ref: "Tương Ưng Bộ 11.14", url: "https://loicuaducphat.org/sn/sn11.14.html#content" },

{ text: `Ai tín thành Như Lai,\nBất động, khéo an trú,\nAi giữ giới thuần thiện,\nÐược bậc Thánh tán thán.\nAi tín thành chúng Tăng,\nChơn trực và chánh kiến,\nÐược gọi: “Không phải nghèo”,\nÐời sống không hư vọng.\nDo vậy người có trí,\nPhải kiên trì Phật giáo,\nTín thành và trì giới,\nTrí kiến đúng Chánh pháp.`, ref: "Tương Ưng Bộ 11.14", url: "https://loicuaducphat.org/sn/sn11.14.html#content" },

{ text: `(Thế Tôn):\nCác cảnh vườn mỹ diệu,\nCác khu rừng mỹ diệu,\nCác ao sen khéo xây,\nÐược loài Người khả ái.\nThật sự chỉ đáng giá,\nThật là ít, nhỏ nhoi.\nTại làng hay tại rừng,\nChỗ đất thấp hay cao,\nChỗ nào La-hán trú,\nĐất ấy thật khả ái.`, ref: "Tương Ưng Bộ 11.15", url: "https://loicuaducphat.org/sn/sn11.15.html#content" },

{ text: `Loài Người lễ tế đàn,\nChúng sanh mong công đức.\nAi làm các công đức,\nÐưa đến sự tái sanh,\nChỗ nào sự bố thí,\nÐược quả báo thật lớn?\n\n(Thế Tôn):\nAi thành tựu bốn đạo,\nAi chứng đắc bốn quả,\nTăng chúng ấy chơn trực,\nGiới, định, tuệ đầy đủ.\nLoài Người lễ tế đàn,\nChúng sanh mong công đức.\nAi làm các công đức,\nÐưa đến sự tái sanh,\nBố thí cho chúng Tăng,\nÐược quả báo thật lớn.`, ref: "Tương Ưng Bộ 11.16", url: "https://loicuaducphat.org/sn/sn11.16.html#content" },

{ text: `Rồi Thiên chủ Sakka nói lên bài kệ này trước mặt Thế Tôn:\nÐứng lên bậc Anh hùng,\nBậc chiến thắng chiến trường,\nÐã đặt gánh nặng xuống,\nKhông mắc nợ một ai,\nBộ hành khắp thế giới,\nTâm Ngài khéo giải thoát,\nChẳng khác gì mặt trăng,\nTrong đêm rằm chói sáng.\n\nPhạm thiên Sahampati: - Này Thiên chủ, kính lễ Như Lai không phải như vậy. Và này Thiên chủ, kính lễ Như Lai phải như thế này:\n\nÐứng lên, bậc Anh hùng,\nBậc chiến thắng chiến trường,\nLãnh đạo đoàn lữ hành,\nKhông mắc nợ một ai,\nBộ hành khắp thế giới,\nThế Tôn hãy thuyết pháp,\nCó những người sẽ hiểu.`, ref: "Tương Ưng Bộ 11.17", url: "https://loicuaducphat.org/sn/sn11.17.html#content" },

{ text: `(Sakka):\nNhưng ta chỉ đảnh lễ,\nBậc thành tựu giới, luật,\nLâu ngày tu Thiền định,\nChơn chánh hành xuất gia,\nThành đạt và chứng được\nCứu cánh chơn Phạm hạnh.\nNgoài ra các gia chủ,\nLàm công đức, giữ giới,\nNuôi dưỡng vợ đúng pháp,\nCác cư sĩ như vậy,\nTa cũng sẽ đảnh lễ,\nHỡi này Mātali.`, ref: "Tương Ưng Bộ 11.18", url: "https://loicuaducphat.org/sn/sn11.18.html#content" },

{ text: `(Sakka):\nBậc Chánh Ðẳng Chánh Giác,\nÐời này với chư Thiên,\nBậc Ðạo Sư tối thượng,\nVị ấy ta đảnh lễ,\nHỡi này Mātali.\nNhững vị đã đoạn trừ,\nTham, sân và vô minh,\nBậc lậu tận, La-hán,\nVị ấy ta đảnh lễ.\nBậc điều phục tham sân,\nVượt khỏi màn vô minh,\nHoan hỷ đoạn tái sanh,\nCác bậc thuộc hữu học,\nKhông phóng dật, tu học,\nVị ấy ta đảnh lễ,\nHỡi này Mātali.`, ref: "Tương Ưng Bộ 11.19", url: "https://loicuaducphat.org/sn/sn11.19.html#content" },

{ text: `(Sakka):\nÐối với xuất gia ấy,\nÐiều khiến ta ưa thích,\nKhi họ từ làng về,\nHọ đi không tham vọng,\nVựa lúa, không cất chứa,\nKhông ghè, không nồi niêu,\nNhững gì họ tìm kiếm,\nCó người khác sẵn sàng.\nDo vậy, họ nuôi sống,\nTheo cung cách tốt đẹp.\nHọ là bậc Hiền trí,\nKhuyên nhủ lời tốt đẹp.\nHay họ giữ im lặng,\nTrong tư thế trầm tĩnh.\nChư thiên chiến Tu-la,\nLoài Người cũng gây chiến.\nHỡi này Mātali!\nKhông chiến giữa gây chiến,\nTrầm tĩnh giữa đao gậy,\nKhông chấp giữa chấp trước.\nVậy ta kính lễ họ,\nHỡi này Mātali!`, ref: "Tương Ưng Bộ 11.20", url: "https://loicuaducphat.org/sn/sn11.20.html#content" },

{ text: `Sát vật gì, được lạc?\nSát vật gì, không sầu?\nCó một loại pháp gì,\nNgài tán đồng sát hại,\nTôn giả Gotama?\n\n(Thế Tôn):\nSát phẫn nộ được lạc,\nSát phẫn nộ không sầu.\nPhẫn nộ với độc căn,\nVới vị ngọt tối thượng,\nPháp ấy, bậc Hiền thánh\nTán đồng sự sát hại.\nSát pháp ấy, không sầu,\nHỡi này Vāsava!`, ref: "Tương Ưng Bộ 11.21", url: "https://loicuaducphat.org/sn/sn11.21.html#content" },

{ text: `Tâm ta không dễ dàng,\nÐể cho bị thất trận,\nKhông dễ bị lôi kéo,\nTrong xoáy nước dục tình.\nNgười biết đã từ lâu,\nTa không còn phẫn nộ,\nPhẫn nộ không chân đứng\nMột chỗ nào trong ta.\nTa không nói ác ngữ,\nVì phẫn nộ giận hờn,\nVà không có khen tặng,\nNhững đức tánh của ta.\nThấy được lợi ích mình,\nTa tự thân chế ngự.`, ref: "Tương Ưng Bộ 11.22", url: "https://loicuaducphat.org/sn/sn11.22.html#content" },

{ text: `Chớ để lòng phẫn nộ,\nNhiếp phục, chi phối người!\nChớ để lòng sân hận,\nÐối trị với sân hận!\nKhông phẫn nộ, vô hại,\nBậc Thánh thường an trú.\nPhẫn nộ quăng người ác,\nNhư đá rơi vực thẳm.`, ref: "Tương Ưng Bộ 11.25", url: "https://loicuaducphat.org/sn/sn11.25.html#content" },

{ text: `- Này các Tỷ-kheo, thế nào là lý Duyên khởi? Này các Tỷ-kheo, vô minh duyên hành; hành duyên thức; thức duyên sanh sắc; danh sắc duyên sáu xứ; sáu xứ duyên xúc; xúc duyên thọ; thọ duyên ái; ái duyên thủ; thủ duyên hữu; hữu duyên sanh; sanh duyên già, chết, sầu, bi, khổ, ưu, não được khởi lên. Như vậy toàn bộ khổ uẩn này tập khởi. Này các Tỷ-kheo, như vậy gọi là tập khởi.`, ref: "Tương Ưng Bộ 12.1", url: "https://loicuaducphat.org/sn/sn12.1.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là sanh? Cái gì thuộc chúng sanh này hay chúng sanh khác, thuộc bộ loại chúng sanh này hay thuộc bộ loại chúng sanh khác bị sanh, xuất sanh, giáng sanh, đản sanh, sự xuất hiện các uẩn, sự thành tựu các xứ. Này các Tỷ-kheo, đây gọi là sanh.`, ref: "Tương Ưng Bộ 12.2", url: "https://loicuaducphat.org/sn/sn12.2.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là vô minh? Này các Tỷ-kheo, không rõ biết Khổ, không rõ biết Khổ tập, không rõ biết Khổ diệt, không rõ biết Con đường đưa đến Khổ diệt. Này các Tỷ-kheo, đây gọi là vô minh.`, ref: "Tương Ưng Bộ 12.2", url: "https://loicuaducphat.org/sn/sn12.2.html#content" },

{ text: `Như vậy này các Tỷ-kheo, vô minh duyên hành; hành duyên thức; thức duyên danh sắc; danh sắc duyên sáu xứ; sáu xứ duyên xúc; xúc duyên thọ; thọ duyên ái; ái duyên thủ; thủ duyên hữu; hữu duyên sanh; sanh duyên già, chết, sầu, bi, khổ, ưu, não được khởi lên. Như vậy là toàn bộ khổ uẩn này tập khởi. Nhưng do sự ly tham, đoạn diệt vô minh một cách hoàn toàn, nên hành diệt. Do hành diệt nên thức diệt. Do thức diệt nên danh sắc diệt. Do danh sắc diệt nên sáu xứ diệt. Do sáu xứ diệt nên xúc diệt. Do xúc diệt nên thọ diệt. Do thọ diệt nên ái diệt. Do ái diệt nên thủ diệt. Do thủ diệt nên hữu diệt. Do hữu diệt nên sanh diệt. Do sanh diệt nên già, chết, sầu, bi, khổ, ưu, não đều diệt. Như vậy là toàn bộ khổ uẩn này đoạn diệt.`, ref: "Tương Ưng Bộ 12.2", url: "https://loicuaducphat.org/sn/sn12.2.html#content" },

{ text: `- Này các Tỷ-kheo, Thế Tôn Vipassì bậc A-la-hán, Chánh Ðẳng Giác, trước khi Ngài giác ngộ, chưa chứng Chánh Ðẳng Giác, còn là Bồ-tát, đã khởi lên tư tưởng sau đây: “Thật sự thế giới này đang lâm nguy, bị sanh, bị già, bị chết, đoạn diệt và tái sanh; và từ nơi đau khổ này, không biết xuất ly, thoát khỏi già và chết; từ nơi đau khổ này, không biết khi nào biết đến xuất ly, thoát khỏi già và chết”.`, ref: "Tương Ưng Bộ 12.4", url: "https://loicuaducphat.org/sn/sn12.4.html#content" },

{ text: `- Này các Tỷ-kheo, có bốn loại đồ ăn này khiến cho các loại sanh vật hay các loại chúng sanh được tồn tại hay khiến cho các loại sắp sanh thành được thọ sanh. Thế nào là bốn? Một là đoàn thực hoặc thô hoặc tế, hai là xúc thực, ba là tư niệm thực, bốn là thức thực. Này các Tỷ-kheo, bốn loại đồ ăn này khiến cho các loại sanh vật hay khiến cho các loại chúng sanh được tồn tại hay khiến cho các loại sắp sanh thành được thọ sanh.\n\nVà này các Tỷ-kheo, bốn loại đồ ăn này do cái gì làm nhân, do cái gì tập khởi, do cái gì tác sanh, do cái gì làm cho hiện hữu? Bốn loại đồ ăn này do ái làm nhân, do ái tập khởi, do ái tác sanh, do ái làm hiện hữu.`, ref: "Tương Ưng Bộ 12.11", url: "https://loicuaducphat.org/sn/sn12.11.html#content" },

{ text: `Và này các Tỷ-kheo, những Sa-môn hay là Bà-la-môn nào biết rõ già, chết, biết rõ già, chết tập khởi, biết rõ già, chết đoạn diệt, biết rõ con đường đưa đến già, chết đoạn diệt … biết rõ sanh … hữu … thủ … ái … thọ … xúc … sáu xứ … danh sắc … thức … biết rõ các hành, biết rõ các hành tập khởi, biết rõ các hành đoạn diệt, biết rõ con đường đưa đến các hành đoạn diệt; các Sa-môn hay Bà-la-môn ấy được chấp nhận là Sa-môn giữa các Sa-môn, hay là Bà-la-môn giữa các Bà-la-môn. Và những bậc Tôn giả ấy, ngay trong đời sống hiện tại có thể với thắng trí tự mình giác ngộ, chứng đạt và an trú mục đích Sa-môn và mục đích Bà-la-môn hạnh.`, ref: "Tương Ưng Bộ 12.13", url: "https://loicuaducphat.org/sn/sn12.13.html#content" },

{ text: `“Chánh kiến, chánh kiến”, bạch Thế Tôn được nói đến như vậy. Bạch Thế Tôn, cho đến như thế nào là chánh kiến?\n- Này Kaccāyana, thế giới này phần lớn y chỉ vào hai cực đoan này: có và không có.\nNày Kaccāyana, ai với chánh trí tuệ thấy như chơn thế giới tập khởi, vị ấy không chấp nhận thế giới là không có. Này Kaccāyana, ai với chánh trí tuệ thấy như chơn thế giới đoạn diệt, vị ấy không chấp nhận thế giới là có.`, ref: "Tương Ưng Bộ 12.15", url: "https://loicuaducphat.org/sn/sn12.15.html#content" },

{ text: `Này Kaccāyana, chấp thủ phương tiện và bị thiên kiến trói buộc, phần lớn thế giới này là vậy. Và ai với tâm không trú trước, không chấp thủ phương tiện ấy, không chấp thủ thiên chấp tùy miên ấy, không có chấp trước, không trú trước, vị ấy không có nghĩ: “Ðây là tự ngã của tôi”. Khi khổ sanh thời xem là sanh, khi khổ diệt thời xem là diệt; vị ấy không có nghi ngờ, không có phân vân, không duyên vào ai khác, trí ở đây là của vị ấy. Cho đến như vậy, này Kaccāyana, là chánh tri kiến.`, ref: "Tương Ưng Bộ 12.15", url: "https://loicuaducphat.org/sn/sn12.15.html#content" },

{ text: `“Tất cả là có”, này Kaccāyana, là một cực đoan. “Tất cả là không có” là cực đoan thứ hai. Xa lìa hai cực đoan ấy, này Kaccāyana, Như Lai thuyết pháp theo trung đạo. Vô minh duyên hành; hành duyên thức … (như trên) … Như vậy là toàn bộ khổ uẩn này tập khởi. Nhưng do ly tham, đoạn diệt vô minh một cách hoàn toàn, nên các hành diệt. Do các hành diệt nên thức diệt … (như trên) … Như vậy là toàn bộ khổ uẩn này đoạn diệt.`, ref: "Tương Ưng Bộ 12.15", url: "https://loicuaducphat.org/sn/sn12.15.html#content" },

{ text: `Nếu Tỷ-kheo thuyết pháp về yếm ly, ly tham, đoạn diệt vô minh, như vậy là đủ để được gọi là Tỷ-kheo thuyết pháp.\nNếu Tỷ-kheo thực hành về yếm ly, ly tham, đoạn diệt vô minh, như vậy là đủ để được gọi là Tỷ-kheo thực hành các pháp và tùy pháp.\nNếu Tỷ-kheo giải thoát, không còn chấp thủ mọi yếm ly, ly tham, đoạn diệt vô minh, như vậy là đủ để được gọi là Tỷ-kheo đã đạt được Niết-bàn ngay trong đời sống hiện tại.`, ref: "Tương Ưng Bộ 12.16", url: "https://loicuaducphat.org/sn/sn12.16.html#content" },

{ text: `- Này các Tỷ-kheo, bị vô minh che đậy và bị tham ái hệ phược, thân này của người ngu được sanh khởi. Vô minh ấy, người ngu không đoạn tận. Tham ái ấy, người ngu không tận trừ. Vì sao? Này các Tỷ-kheo, người ngu sống Phạm hạnh không phải vì chơn chánh đoạn trừ khổ đau. Do vậy người ngu, khi thân hoại mạng chung, đi đến một thân khác. Do đi đến một thân khác, người ấy không giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng: “Người ấy không thoát khỏi đau khổ”.`, ref: "Tương Ưng Bộ 12.19", url: "https://loicuaducphat.org/sn/sn12.19.html#content" },

{ text: `Và này các Tỷ-kheo, bị vô minh che đậy, bị tham ái hệ phược, thân người Hiền trí được sanh khởi. Vô minh ấy, người Hiền trí đoạn tận. Tham ái ấy, người Hiền trí tận trừ. Vì sao? Này các Tỷ-kheo, người Hiền trí sống Phạm hạnh, vì chơn chánh đoạn trừ khổ đau. Do vậy, người Hiền trí, khi thân hoại mạng chung, không đi đến một thân khác. Do không đi đến một thân khác, vị ấy giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng: “Vị ấy thoát khỏi đau khổ”.`, ref: "Tương Ưng Bộ 12.19", url: "https://loicuaducphat.org/sn/sn12.19.html#content" },

{ text: `- Và này các Tỷ-kheo, thế nào là lý duyên khởi? Do duyên sanh, này các Tỷ-kheo, già, chết khởi lên. Dầu các Như Lai có xuất hiện hay không xuất hiện, an trú là giới tánh ấy, pháp trú tánh ấy, pháp quyết định tánh ấy, y duyên tánh ấy. Như Lai hoàn toàn chứng ngộ, hoàn toàn chứng đạt định lý ấy. Sau khi hoàn toàn chứng ngộ, hoàn toàn chứng đạt, Như Lai tuyên bố, tuyên thuyết, tường thuyết, khai hiển, khai thị, phân biệt, minh hiển, minh thị.`, ref: "Tương Ưng Bộ 12.20", url: "https://loicuaducphat.org/sn/sn12.20.html#content" },

{ text: `Do duyên sanh, này các Tỷ-kheo, nên có già, chết. Do duyên hữu, này các Tỷ-kheo, nên có sanh. Do duyên thủ, này các Tỷ-kheo, nên có hữu. Do duyên ái, này các Tỷ-kheo, nên có thủ. Do duyên thọ, này các Tỷ-kheo, nên có ái. Do duyên xúc, này các Tỷ-kheo, nên có thọ. Do duyên sáu xứ, này các Tỷ-kheo, nên có xúc. Do duyên danh sắc, này các Tỷ-kheo, nên có sáu xứ. Do duyên thức, này các Tỷ-kheo, nên có danh sắc. Do duyên các hành, này các Tỷ-kheo, nên có thức. Do duyên vô minh, này các Tỷ-kheo, nên có hành. Dầu cho Như Lai có xuất hiện hay không xuất hiện, an trú là giới tánh ấy, pháp trú tánh ấy, pháp quyết định tánh ấy, y duyên tánh ấy. Như Lai hoàn toàn chứng ngộ, hoàn toàn chứng đạt tánh ấy. Sau khi hoàn toàn chứng ngộ, hoàn toàn chứng đạt, Như Lai tuyên bố, tuyên thuyết, tường thuyết, khai hiển, khai thị, phân biệt, minh hiển, minh thị.`, ref: "Tương Ưng Bộ 12.20", url: "https://loicuaducphat.org/sn/sn12.20.html#content" },

{ text: `Do vì, này các Tỷ-kheo, vị Thánh đệ tử khéo thấy như chơn với chánh trí tuệ lý duyên khởi này và các pháp duyên sanh này, nên chắc chắn vị ấy không chạy theo quá khứ (với những câu hỏi): “Ta có mặt trong quá khứ? Ta không có mặt không quá khứ? Ta là gì trong quá khứ? Ta có mặt như thế nào trong quá khứ? Hay trước ta đã là gì, và nay trong quá khứ ta là gì?”`, ref: "Tương Ưng Bộ 12.20", url: "https://loicuaducphat.org/sn/sn12.20.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, với Pháp được Ta khéo thuyết, hiển thị, khai thị, hiển lộ, các buộc ràng được cắt đoạn, thật là đủ cho Thiện nam tử do lòng tin xuất gia có thể bắt đầu tinh tấn (hành trì và nguyện). Như vậy, này các Tỷ-kheo, với Pháp được Ta khéo thuyết, hiển thị, hiển lộ các buộc ràng được cắt đoạn. Chắc chắn dầu chỉ còn lại da, gân và xương trên thân, dầu thịt, máu trở thành khô cạn, mong rằng tinh tấn lực, sẽ được kiên trì để chứng đắc những gì chưa chứng đắc, nhờ trượng phu lực, nhờ trượng phu tinh tấn, nhờ trượng phu cần dõng.`, ref: "Tương Ưng Bộ 12.22", url: "https://loicuaducphat.org/sn/sn12.22.html#content" },

{ text: `Khổ thay, này các Tỷ-kheo, là người sống biếng nhác, dính đầy các pháp ác, bất thiện và mục đích lớn bị suy giảm! An lạc thay, này các Tỷ-kheo, là người sống tinh cần, tinh tấn, viễn ly các ác, bất thiện pháp, và mục đích lớn được viên mãn!`, ref: "Tương Ưng Bộ 12.22", url: "https://loicuaducphat.org/sn/sn12.22.html#content" },

{ text: `Này các Tỷ-kheo, không phải với cái hạ liệt có thể đạt được cái cao thượng. Này các Tỷ-kheo, phải với cái cao thượng mới đạt được cái cao thượng. Ðáng được tán thán, này các Tỷ-kheo, là Phạm hạnh này với sự có mặt của bậc Ðạo Sư. Do vậy, này các Tỷ-kheo, hãy tinh tấn lên để chứng đạt những gì chưa chứng đạt, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ.`, ref: "Tương Ưng Bộ 12.22", url: "https://loicuaducphat.org/sn/sn12.22.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, với Pháp được Ta khéo thuyết, hiển thị, khai thị, hiển lộ, các buộc ràng được cắt đoạn, thật là đủ cho Thiện nam tử do lòng tin xuất gia có thể bắt đầu tinh tấn (hành trì và nguyện). Như vậy, này các Tỷ-kheo, với Pháp được Ta khéo thuyết, hiển thị, hiển lộ các buộc ràng được cắt đoạn. Chắc chắn dầu chỉ còn lại da, gân và xương trên thân, dầu thịt, máu trở thành khô cạn, mong rằng tinh tấn lực, sẽ được kiên trì để chứng đắc những gì chưa chứng đắc, nhờ trượng phu lực, nhờ trượng phu tinh tấn, nhờ trượng phu cần dõng.`, ref: "Tương Ưng Bộ 12.22", url: "https://loicuaducphat.org/sn/sn12.22.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, các Ông cần phải học tập. Này các Tỷ-kheo, thấy được tự lợi là vừa đủ để tinh tấn không phóng dật. Hay này các Tỷ-kheo, khi thấy lợi tha là vừa đủ để tinh tấn, không phóng dật. Hay này các Tỷ-kheo, thấy lợi cả hai, là vừa đủ để tinh tấn, không phóng dật. Có vậy, sự xuất gia này của chúng ta sẽ không phải trống không, có kết quả, có thành tích. Và những vật dụng chúng ta thọ dụng như y phục, đồ ăn khất thực, sàng tọa, thuốc trị bệnh, dầu cho những thứ này là khiêm tốn, đối với chúng ta sẽ có quả lớn, có lợi ích lớn.`, ref: "Tương Ưng Bộ 12.22", url: "https://loicuaducphat.org/sn/sn12.22.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào đối với người biết, đối với người thấy, các lậu hoặc được đoạn diệt? Ðây là sắc, đây là sắc tập khởi, đây là sắc đoạn diệt. Ðây là thọ … Ðây là tưởng … Ðây là hành … Ðây là thức, đây là thức tập khởi, đây là thức đoạn diệt. Như vậy, này các Tỷ-kheo, đối với người biết, như vậy đối với người thấy, các lậu hoặc được đoạn diệt.\n\nNày các Tỷ-kheo, trong đoạn diệt ấy, trí về đoạn diệt, Ta nói rằng trí ấy có duyên, không phải không có duyên. Và này các Tỷ-kheo, duyên của trí về đoạn diệt là gì? Giải thoát là câu trả lời. Này các Tỷ-kheo, Ta nói rằng giải thoát có duyên, không phải không có duyên. Và này các Tỷ-kheo, duyên của giải thoát là gì? Ly tham là câu trả lời.`, ref: "Tương Ưng Bộ 12.23", url: "https://loicuaducphat.org/sn/sn12.23.html#content" },

{ text: `Và này các Tỷ-kheo, duyên của tri kiến như chân là gì? Ðịnh là câu trả lời. Này các Tỷ-kheo, Ta nói rằng định có duyên, không phải không có duyên. Và này các Tỷ-kheo, duyên của định là gì? Lạc là câu trả lời.`, ref: "Tương Ưng Bộ 12.23", url: "https://loicuaducphat.org/sn/sn12.23.html#content" },

{ text: `Và này các Tỷ-kheo, duyên của hân hoan là gì? Lòng tin là câu trả lời. Này các Tỷ-kheo, Ta nói rằng lòng tin có duyên, không phải không có duyên. Và này các Tỷ-kheo, duyên của lòng tin là gì? Khổ là câu trả lời. Này các Tỷ-kheo, Ta nói rằng khổ có duyên, không phải không có duyên.`, ref: "Tương Ưng Bộ 12.23", url: "https://loicuaducphat.org/sn/sn12.23.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trên đỉnh núi trời mưa nặng hột và nước chảy theo triền thấp, tràn đầy hang núi, khe núi, thung lũng. Khi các hang núi, khe núi, thung lũng được tràn đầy, thời ao nhỏ được tràn đầy; ao nhỏ được tràn đầy thời ao lớn được tràn đầy; ao lớn tràn đầy thời sông nhỏ được tràn đầy; sông nhỏ được tràn đầy thời sông lớn được tràn đầy; sông lớn được tràn đầy thời biển lớn, đại dương được tràn đầy.\n\nCũng vậy, này các Tỷ-kheo, vô minh duyên hành; hành duyên thức; thức duyên danh sắc; danh sắc duyên sáu xứ; sáu xứ duyên xúc; xúc duyên thọ; thọ duyên ái; ái duyên thủ; thủ duyên hữu; hữu duyên sanh; sanh duyên khổ; khổ duyên tín; tín duyên hân hoan; hân hoan duyên hỷ; hỷ duyên khinh an; khinh an duyên lạc; lạc duyên định; định duyên tri kiến như chân; tri kiến như chân duyên yếm ly; yếm ly duyên ly tham; ly tham duyên giải thoát; giải thoát duyên trí về đoạn diệt.`, ref: "Tương Ưng Bộ 12.23", url: "https://loicuaducphat.org/sn/sn12.23.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là hành? Có ba hành này, này các Tỷ-kheo: thân hành, khẩu hành, ý hành. Ba hành này, này các Tỷ-kheo, được gọi là hành.`, ref: "Tương Ưng Bộ 12.28", url: "https://loicuaducphat.org/sn/sn12.28.html#content" },

{ text: `- Này các Tỷ-kheo, cái chúng ta tư niệm, tư lường, có thầm ý, cái ấy trở thành sở duyên cho thức an trú. Khi nào sở duyên có mặt thời thức có an trú. Do thức ấy an trú, tăng trưởng, nên trong tương lai, tái hữu sanh khởi. Do sanh khởi tái hữu có mặt trong tương lai, nên già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.38", url: "https://loicuaducphat.org/sn/sn12.38.html#content" },

{ text: `Này các Tỷ-kheo, nếu không có tư niệm, không có tư lường nhưng nếu có thầm ý, cái ấy trở thành sở duyên cho thức an trú. Khi nào sở duyên có mặt thời thức có an trú. Do thức ấy an trú, tăng trưởng, nên trong tương lai, tái hữu sanh khởi. Do sanh khởi tái hữu có mặt trong tương lai, nên già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.38", url: "https://loicuaducphat.org/sn/sn12.38.html#content" },

{ text: `Này các Tỷ-kheo, nếu chúng ta không có tư niệm, không có tư lường, không có thầm ý, thời không có sở duyên cho thức an trú. Khi nào sở duyên không có mặt thời thức không an trú. Do thức ấy không an trú và không tăng trưởng, nên trong tương lai tái hữu không sanh khởi. Do sanh khởi tái hữu không có mặt trong tương lai, nên sanh, già chết, sầu, bi, ưu, não được đoạn diệt. Như vậy là sự đoạn diệt của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.38", url: "https://loicuaducphat.org/sn/sn12.38.html#content" },

{ text: `- Này các Tỷ-kheo, cái gì chúng ta tư niệm, chúng ta tư lường, chúng ta có thầm ý, cái ấy trở thành (sở duyên) cho thức an trú. Do sở duyên có mặt nên thức có an trú. Do thức ấy an trú và tăng trưởng nên có sự hạ sanh danh sắc.\n\nDo duyên danh sắc nên có sáu xứ. Do duyên sáu xứ nên có xúc. Do duyên xúc nên có thọ… ái… thủ… hữu… sanh, già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.39", url: "https://loicuaducphat.org/sn/sn12.39.html#content" },

{ text: `Này các Tỷ-kheo, nếu chúng ta không tư niệm, không tư lường nhưng có thầm ý, thời cái ấy trở thành sở duyên cho thức an trú. Do sở duyên có mặt nên thức có an trú. Do thức ấy an trú và tăng trưởng nên có sự hạ sanh danh sắc. Do duyên danh sắc nên có sáu xứ… như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.39", url: "https://loicuaducphat.org/sn/sn12.39.html#content" },

{ text: `Này các Tỷ-kheo, nếu chúng ta không tư niệm, không tư lường, không có thầm ý, thời không có sở duyên cho thức an trú. Do sở duyên không có mặt nên thức không an trú. Do thức ấy không an trú và không tăng trưởng nên danh sắc không hạ sanh. Do danh sắc diệt nên sáu xứ diệt… như vậy là sự đoạn diệt của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 12.39", url: "https://loicuaducphat.org/sn/sn12.39.html#content" },

{ text: `- Ở đây, này các Tỷ-kheo, vị Tỷ-kheo đang tư lường, tư lường như sau: “Sự đau khổ nhiều loại và đa dạng này khởi lên trên đời như già và chết; sự đau khổ này lấy gì làm nhân, lấy gì tập khởi, lấy gì tác sanh, lấy gì làm hiện hữu? Do cái gì có mặt, già chết hiện hữu? Do cái gì không có mặt, già chết không hiện hữu?”\n\nTư lường như vậy, vị ấy biết như sau: “Sự đau khổ nhiều loại và đa dạng này khởi lên trên đời như già và chết, sự đau khổ này lấy sanh làm nhân, lấy sanh làm tập khởi, lấy sanh làm tác sanh, lấy sanh làm hiện hữu. Do sanh có mặt, già chết hiện hữu. Do sanh không có mặt, già chết không hiện hữu”.`, ref: "Tương Ưng Bộ 12.51", url: "https://loicuaducphat.org/sn/sn12.51.html#content" },

{ text: `Này các Tỷ-kheo, khi nào vị Tỷ-kheo đoạn tận vô minh, minh được sanh khởi. Vị ấy do vô minh đoạn tận, minh sanh khởi, không có dự tính, không có dụng ý, vị ấy không chấp thủ một sự gì ở đời. Không chấp thủ, vị ấy không sợ hãi. Không sợ hãi, vị ấy hoàn toàn tịch tịnh. Vị ấy biết rõ: “Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 12.51", url: "https://loicuaducphat.org/sn/sn12.51.html#content" },

{ text: `Nếu vị ấy cảm giác lạc thọ, vị ấy biết lạc thọ ấy vô thường, vị ấy biết không nên tham đắm, vị ấy biết không nên hoan hỷ. Nếu vị ấy cảm giác khổ thọ, vị ấy biết khổ thọ vô thường, vị ấy biết không nên tham đắm, vị ấy biết không nên hoan hỷ. Nếu vị ấy cảm giác bất khổ bất lạc thọ, vị ấy biết thọ ấy vô thường, vị ấy biết không nên tham đắm, vị ấy biết không nên hoan hỷ. Nếu vị ấy cảm giác lạc thọ, thọ ấy được cảm giác với niệm thoát ly. Nếu vị ấy cảm giác khổ thọ, thọ ấy được cảm giác với niệm thoát ly. Nếu vị ấy cảm giác bất khổ bất lạc thọ, thọ ấy được cảm giác với niệm thoát ly .`, ref: "Tương Ưng Bộ 12.51", url: "https://loicuaducphat.org/sn/sn12.51.html#content" },

{ text: `Này các Tỷ-kheo, ví như một người từ trong lò nung của người thợ gốm lấy ra một cái ghè nóng và đặt trên một khoảng đất bằng phẳng để sức nóng ở đấy được nguội dần, và các miếng sành vụn được gạt bỏ một bên. Cũng vậy, này các Tỷ-kheo, khi cảm giác một cảm thọ tận cùng của thân, vị ấy biết: “Ta cảm giác một cảm thọ tận cùng của thân”. Khi vị ấy cảm giác một cảm thọ tận cùng của sinh mạng, vị ấy biết: “Ta cảm giác một cảm thọ tận cùng của sinh mạng”. Vị ấy biết: “Sau khi thân hoại mạng chung, ở đây tất cả những cảm thọ không làm cho có hỷ lạc, sẽ trở thành vắng lặng, cái thân được bỏ qua một bên”.`, ref: "Tương Ưng Bộ 12.51", url: "https://loicuaducphat.org/sn/sn12.51.html#content" },

{ text: `Này các Tỷ-kheo, ví như một đống lửa lớn làm bằng mười xe củi, hay hai mươi xe củi, hay ba mươi xe củi, hay bốn mươi xe củi đang cháy đỏ. Tại đây có người thỉnh thoảng ném cỏ khô vào, và ném củi khô vào. Này các Tỷ-kheo, như vậy đống lửa lớn ấy được nuôi dưỡng, được tiếp tế, có thể cháy đỏ trong một thời gian dài. Cũng vậy, này các Tỷ-kheo, ai sống thấy vị ngọt trong các pháp được chấp thủ, ái được tăng trưởng. Do duyên ái nên thủ có mặt. Do duyên thủ nên hữu có mặt. Do duyên hữu nên sanh có mặt. Do duyên sanh nên già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là toàn bộ khổ uẩn này tập khởi.`, ref: "Tương Ưng Bộ 12.52", url: "https://loicuaducphat.org/sn/sn12.52.html#content" },

{ text: `Ví như, này các Tỷ-kheo, do duyên dầu và duyên tim, ngọn đèn dầu được cháy đỏ. Tại đây có người thỉnh thoảng rót dầu thêm và khơi tim lên. Này các Tỷ-kheo, ngọn đèn dầu ấy được nuôi dưỡng như vậy, được tiếp tế như vậy, có thể cháy đỏ trong một thời gian dài. Cũng vậy, này các Tỷ-kheo, ai sống thấy vị ngọt trong các pháp kiết sử, ái được tăng trưởng. Do duyên ái nên thủ có mặt. Do duyên thủ nên hữu có mặt. Do duyên hữu nên sanh có mặt. Do duyên sanh nên già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là toàn bộ khổ uẩn này tập khởi.`, ref: "Tương Ưng Bộ 12.53", url: "https://loicuaducphat.org/sn/sn12.53.html#content" },

{ text: `Ví như, này các Tỷ-kheo, do duyên dầu và do duyên tim, ngọn đèn dầu được cháy đỏ. Tại đấy không có người thỉnh thoảng rót thêm dầu vào và không khơi tim lên. Như vậy, này các Tỷ-kheo, ngọn đèn ấy do nhiên liệu được tiếp tế trước tiêu diệt và do nhiên liệu khác không được đem thêm, không được nuôi dưỡng, sẽ bị tắt. Cũng vậy, này các Tỷ-kheo, ai sống thấy sự nguy hiểm trong các pháp kiết sử, ái được đoạn diệt. Do ái diệt nên thủ diệt. Do thủ diệt nên hữu diệt. Do hữu diệt nên sanh diệt. Do sanh diệt nên già chết, sầu, bi, khổ, ưu, não được đoạn diệt. Như vậy là toàn bộ khổ uẩn này đoạn diệt.`, ref: "Tương Ưng Bộ 12.53", url: "https://loicuaducphat.org/sn/sn12.53.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một cây lớn, các rễ của cây ấy đâm sâu xuống dưới và đâm ngang, tất cả rễ ấy đều đem lên nhựa sống cho cây ấy. Này các Tỷ-kheo, cây lớn ấy được nuôi dưỡng như vậy, được tiếp tế như vậy, có thể đứng vững trong một thời gian dài. Cũng vậy, này các Tỷ-kheo, ai sống thấy vị ngọt trong các pháp được chấp thủ, ái được tăng trưởng. Do duyên ái, thủ sanh khởi. Do duyên thủ nên hữu sanh khởi. Do duyên hữu nên sanh sanh khởi. Do duyên sanh nên già chết, sầu, bi, khổ, ưu, não sanh khởi. Như vậy là toàn bộ khổ uẩn này tập khởi.`, ref: "Tương Ưng Bộ 12.55", url: "https://loicuaducphat.org/sn/sn12.55.html#content" },

{ text: `Này các Tỷ-kheo, ví như một cây lớn, có một người đến, cầm cái cuốc và cái giỏ. Người ấy chặt đứt rễ của cây ấy. Sau khi đào cái mương, người ấy nhổ các rễ lớn cho đến các rễ con, các rễ phụ. Rồi người ấy chặt cây ấy thành từng khúc. Sau khi chặt cây thành từng khúc, người ấy bửa, sau khi bửa, người ấy chẻ thành từng miếng nhỏ. Sau khi chẻ thành từng miếng nhỏ, người ấy phơi giữa gió và nắng. Sau khi người ấy phơi giữa gió và nắng, người ấy lấy lửa đốt. Sau khi lấy lửa đốt, người ấy vun thành đống tro. Sau khi vun thành đống tro, người ấy sàng tro ấy giữa gió lớn hay đổ tro ấy vào dòng nước mạnh cho nước cuốn đi. Như vậy, này các Tỷ-kheo, cây lớn ấy, rễ bị cắt đứt, làm thành như thân cây ta-la, làm cho không thể tái sanh, trong tương lai không thể sống lại được. Cũng vậy, này các Tỷ-kheo, ai sống thấy được sự nguy hiểm trong các pháp chấp thủ,  ái được đoạn diệt. Do ái diệt nên thủ diệt. Do thủ diệt nên hữu diệt. Do hữu diệt nên sanh diệt. Do sanh diệt, nên già chết, sầu, bi, khổ, ưu, não đều diệt. Như vậy là toàn bộ khổ uẩn này đoạn diệt.`, ref: "Tương Ưng Bộ 12.55", url: "https://loicuaducphat.org/sn/sn12.55.html#content" },

{ text: `- Này các Tỷ-kheo, kẻ vô văn phàm phu có thể nhàm chán, viễn ly, giải thoát thân do bốn đại tạo thành này. Vì cớ sao? Này các Tỷ-kheo, vì họ thấy được cái thân do bốn đại tạo thành này được tăng, được giảm, được thủ, được xả. Do vậy, ở đây kẻ vô văn phàm phu có thể nhàm chán, viễn ly, giải thoát. Và này các Tỷ-kheo, cái gọi là tâm, là ý, là thức, ở đây, kẻ vô văn phàm phu không đủ để có thể nhàm chán, không đủ để có thể viễn ly, không đủ để có thể giải thoát. Vì sao? Ðã lâu ngày, này các Tỷ-kheo, kẻ vô văn phàm phu đắm trước, xem là của tôi, chấp thủ: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”. Do vậy, ở đây, kẻ vô văn phàm phu không đủ để có thể nhàm chán, không đủ để có thể viễn ly, không đủ để có thể giải thoát.`, ref: "Tương Ưng Bộ 12.61", url: "https://loicuaducphat.org/sn/sn12.61.html#content" },

{ text: `Này các Tỷ-kheo, thật tốt hơn cho kẻ vô văn phàm phu đi đến với thân do bốn đại tạo thành này xem như là tự ngã, hơn là đối với tâm. Vì sao? Này các Tỷ-kheo, thân do bốn đại tạo thành này được thấy đứng vững một năm, đứng vững hai năm, đứng vững ba năm, đứng vững bốn năm, đứng vững năm năm, đứng vững mười năm, đứng vững hai mươi năm, đứng vững ba mươi năm, đứng vững bốn mươi năm, đứng vững năm mươi năm, đứng vững một trăm năm, đứng vững nhiều hơn nữa. Còn cái gọi là tâm này, là ý này, là thức này, này các Tỷ-kheo, cả đêm và ngày, khởi lên là khác, diệt đi là khác.`, ref: "Tương Ưng Bộ 12.61", url: "https://loicuaducphat.org/sn/sn12.61.html#content" },

{ text: `Do đoạn diệt, ly tham vô minh một cách hoàn toàn nên hành diệt. Do hành diệt nên thức diệt… (như trên)… Như vậy là toàn bộ khổ uẩn này đoạn diệt. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử, nhàm chán đối với sắc, nhàm chán đối với thọ, nhàm chán đối với tưởng, nhàm chán đối với các hành, nhàm chán đối với thức. Do nhàm chán nên viễn ly; do viễn ly nên giải thoát. Trong sự giải thoát, trí khởi lên biết được: “Ta giải thoát”, vị ấy biết rõ: “Sanh đã tận, Phạm hạnh đã thành, những gì nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 12.61", url: "https://loicuaducphat.org/sn/sn12.61.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Ða văn Thánh đệ tử khéo chơn chánh tư duy lý duyên khởi: “Do cái này có mặt, cái kia có mặt. Do cái này sanh, cái kia sanh. Do cái này không có mặt, cái kia không có mặt. Do cái này diệt, cái kia diệt”.\n\nNày các Tỷ-kheo, do duyên xúc đưa đến cảm giác lạc thọ, nên lạc thọ sanh khởi. Do duyên xúc đưa đến cảm giác lạc thọ ấy diệt, nên lạc thọ được khởi lên do duyên xúc đưa đến cảm giác lạc thọ ấy diệt, lạc thọ ấy được chấm dứt. Này các Tỷ-kheo do duyên xúc đưa đến cảm giác khổ thọ, … (như trên)… Này các Tỷ-kheo, do duyên xúc đưa đến cảm giác bất khổ bất lạc thọ,… (như trên)…, bất khổ bất lạc thọ ấy chấm dứt.\n\nVí như, này các Tỷ-kheo, do hai khúc cây cọ xát hòa hợp nên sức nóng được sanh, lửa được khởi lên. Do hai khúc cây ấy xa lìa tách biệt, nên sức nóng ấy đoạn diệt, sức nóng ấy chấm dứt. Cũng vậy, này các Tỷ-kheo, do duyên xúc đưa đến cảm giác lạc thọ nên lạc thọ sanh khởi … (như trên)… Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử nhàm chán đối với xúc, nhàm chán đối với thọ, nhàm chán đối với tưởng, nhàm chán đối với thức. Do nhàm chán nên viễn ly; do viễn ly nên giải thoát. Trong sự giải thoát trí khởi lên, biết rằng: “Ta đã giải thoát”, vị ấy biết rõ: “Sanh đã tận, Phạm hạnh đã thành, những gì nên làm đã làm, không còn trở lại trạng thái này nữa”.`, ref: "Tương Ưng Bộ 12.62", url: "https://loicuaducphat.org/sn/sn12.62.html#content" },

{ text: `Này các Tỷ-kheo, nếu đối với đoàn thực, có tham, có hỷ, có ái, thời có thức được an trú, tăng trưởng. Chỗ nào thức được an trú, tăng trưởng, chỗ ấy có danh sắc sanh. Chỗ nào có danh sắc sanh, chỗ ấy có các hành tăng trưởng. Chỗ nào có các hành tăng trưởng, chỗ ấy hữu được tái sanh trong tương lai. Chỗ nào hữu được tái sanh trong tương lai, chỗ ấy có sanh, già chết trong tương lai. Chỗ nào có sanh, già chết trong tương lai, Ta nói chỗ ấy có sầu, có khổ, có não.`, ref: "Tương Ưng Bộ 12.64", url: "https://loicuaducphat.org/sn/sn12.64.html#content" },

{ text: `Này các Tỷ-kheo, nếu đối với đoàn thực không có tham, không có hỷ, không có ái, thời không có thức an trú, tăng trưởng. Chỗ nào không có thức an trú, tăng trưởng, chỗ ấy không có danh sắc sanh. Chỗ nào không có danh sắc sanh, chỗ ấy không có các hành tăng trưởng. Chỗ nào không có các hành tăng trưởng, chỗ ấy không có hữu tái sanh trong tương lai. Chỗ nào không có hữu tái sanh trong tương lai, chỗ ấy không có sanh, già, chết trong tương lai. Chỗ nào không có sanh, già, chết trong tương lai, Ta nói rằng chỗ ấy không có sầu, không có khổ, không có não.`, ref: "Tương Ưng Bộ 12.64", url: "https://loicuaducphat.org/sn/sn12.64.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một ngôi nhà có mái hay một dãy hành lang có mái, có cửa sổ phía Bắc, phía Nam, hay phía Ðông. Khi mặt trời mọc lên, ánh sáng ngang qua cửa sổ chiếu vào, thời chiếu vào chỗ nào? - Bạch Thế Tôn, chiếu vào tường phía Tây. - Này các Tỷ-kheo, nếu không có tường phía Tây, thời chiếu vào chỗ nào? - Bạch Thế Tôn, chiếu trên đất. - Này các Tỷ-kheo, nếu không có đất, thời chiếu vào chỗ nào? - Bạch Thế Tôn, chiếu trên nước. - Này các Tỷ-kheo, nếu không có nước, thời chiếu vào chỗ nào? - Bạch Thế Tôn, không có chiếu ở đâu cả.\n\n- Cũng vậy, này các Tỷ-kheo, nếu đối với thức thực, không có tham, không có hỷ, không có ái, thời không có thức an trú. Chỗ nào không có thức an trú, chỗ ấy không có danh sắc sanh. Chỗ nào không có danh sắc sanh, chỗ ấy không có các hành tăng trưởng. Chỗ nào không có các hành tăng trưởng, chỗ ấy không có hữu tái sanh trong tương lai. Chỗ nào không có hữu tái sanh trong tương lai, chỗ ấy không có sanh, già chết trong tương lai. Chỗ nào không có sanh, già chết trong tương lai, Ta nói rằng chỗ ấy không có sầu, không có khổ, không có não.`, ref: "Tương Ưng Bộ 12.64", url: "https://loicuaducphat.org/sn/sn12.64.html#content" },

{ text: `- Ở đây, này các Tỷ-kheo, Tỷ-kheo trong khi nắm giữ nội xúc, nắm giữ nội xúc như sau: “Sự đau khổ đa loại, đa dạng này khởi lên ở đời với già chết; sự đau khổ này lấy cái gì làm nhân, hay lấy cái gì làm tập khởi, lấy cái gì làm tác sanh, lấy cái gì làm hiện hữu? Cái gì có mặt, già chết hiện hữu? Cái gì không có mặt, già chết không hiện hữu?”. Vị ấy nắm giữ nội xúc, biết như sau: “Sự đau khổ đa loại, đa dạng này khởi lên ở đời với già chết. Sự đau khổ này lấy sanh y làm nhân, lấy sanh y làm tập khởi, lấy sanh y làm tác sanh, lấy sanh y làm hiện hữu. Do sanh y có mặt, già chết hiện hữu. Do sanh y không có mặt, già chết không hiện hữu”. Vị ấy biết già chết. Vị ấy biết già chết tập khởi. Vị ấy biết già chết đoạn diệt. Vị ấy biết con đường thích ứng đưa đến già chết đoạn diệt. Và nhờ thực hành như vậy, vị ấy trở thành một vị tùy pháp hành. Này các Tỷ-kheo, đây gọi là Tỷ-kheo đã thực hành để diệt tận khổ đau, để đoạn diệt già chết một cách hoàn toàn.`, ref: "Tương Ưng Bộ 12.66", url: "https://loicuaducphat.org/sn/sn12.66.html#content" },

{ text: `Vị ấy lại nắm giữ thêm nội xúc và nắm giữ như sau: “Sanh y này lấy gì làm nhân, lấy gì làm tập khởi, lấy gì làm tác sanh, lấy gì làm hiện hữu? Cái gì có mặt, sanh y hiện hữu? Cái gì không có mặt, sanh y không hiện hữu?”. Vị ấy nắm giữ nội xúc, biết được như sau: “Sanh y lấy ái làm nhân, lấy ái làm tập khởi, lấy ái làm tác sanh, lấy ái làm hiện hữu. Do ái có mặt, sanh y hiện hữu. Do ái không có mặt, sanh y không hiện hữu”. Vị ấy biết sanh y, biết sanh y tập khởi, biết sanh y đoạn diệt, và biết con đường thích ứng đưa đến sanh y đoạn diệt. Do thực hành như vậy, vị ấy được gọi là tùy pháp hành. Này các Tỷ-kheo, đây gọi là Tỷ-kheo đã chơn chánh thực hành để tận diệt đau khổ và đoạn diệt sanh y một cách hoàn toàn.`, ref: "Tương Ưng Bộ 12.66", url: "https://loicuaducphat.org/sn/sn12.66.html#content" },

{ text: `Vị ấy lại nắm giữ thêm nội xúc và nắm giữ như sau: “Nhưng ái này, khởi lên tại chỗ nào được khởi lên, an trú tại chỗ nào được an trú?”. Vị ấy nắm giữ nội xúc, biết được như sau: “Tất cả những gì ở đời khả ái, hấp dẫn, khởi lên; tại chỗ ấy, ái được sanh khởi; tại chỗ ấy, ái được an trú. Và cái gì ở đời khả ái, hấp dẫn? Con mắt ở đời là khả ái, hấp dẫn khởi lên; tại chỗ ấy, ái được sanh khởi; tại chỗ ấy ái được an trú”. … Lỗ tai ở đời là khả ái, hấp dẫn… … Lỗ mũi ở đời là khả ái, hấp dẫn… … Lưỡi ở đời là khả ái, hấp dẫn… … Thân ở đời là khả ái, hấp dẫn… … Ý ở đời là khả ái, hấp dẫn khởi lên; tại chỗ ấy, ái được sanh khởi; tại chỗ ấy, ái được an trú.`, ref: "Tương Ưng Bộ 12.66", url: "https://loicuaducphat.org/sn/sn12.66.html#content" },

{ text: `Này các Tỷ-kheo, những ai trong quá khứ… những ai trong tương lai… những ai trong thời hiện tại là Sa-môn hay Bà-la-môn, thấy những gì ở đời khả ái, hấp dẫn là thường còn, thấy là lạc, thấy là vô bệnh, thấy là an ổn, thấy là tự ngã, những người ấy làm ái tăng trưởng. Những ai làm ái tăng trưởng, những người ấy làm sanh y tăng trưởng. Những ai làm sanh y tăng trưởng, những người ấy làm đau khổ tăng trưởng. Những ai làm đau khổ tăng trưởng, những người ấy không thể giải thoát sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng họ không thể giải thoát khỏi đau khổ.`, ref: "Tương Ưng Bộ 12.66", url: "https://loicuaducphat.org/sn/sn12.66.html#content" },

{ text: `Này các Tỷ-kheo, những ai trong quá khứ… những ai trong tương lai… những ai trong thời hiện tại là Sa-môn hay Bà-la-môn, thấy những gì khả ái, hấp dẫn ở đời là vô thường, thấy là khổ, thấy là vô ngã, thấy là bệnh, thấy là đáng sợ hãi, họ từ bỏ ái. Những ai từ bỏ ái, những người ấy từ bỏ sanh y. Những ai từ bỏ sanh y, những người ấy từ bỏ đau khổ. Những ai từ bỏ đau khổ, những người ấy được giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng họ được giải thoát khỏi đau khổ.`, ref: "Tương Ưng Bộ 12.66", url: "https://loicuaducphat.org/sn/sn12.66.html#content" },

{ text: `- Này các Tỷ-kheo, khi nào biển lớn dâng lên thời các sông lớn dâng lên; khi nào các sông lớn dâng lên thời các sông nhỏ dâng lên; khi nào các sông nhỏ dâng lên thời các hồ lớn dâng lên; khi nào các hồ lớn dâng lên thời các hồ nhỏ dâng lên. Cũng vậy, này các Tỷ-kheo, khi nào vô minh dâng lên thời các hành dâng lên; khi nào các hành dâng lên thời thức dâng lên; khi nào thức dâng lên thời danh sắc dâng lên; khi nào danh sắc dâng lên thời sáu xứ dâng lên; khi nào sáu xứ dâng lên thời xúc dâng lên; khi nào xúc dâng lên thời thọ dâng lên; khi nào thọ dâng lên thời ái dâng lên; khi nào ái dâng lên thời thủ dâng lên; khi nào thủ dâng lên thời hữu dâng lên; khi nào hữu dâng lên thời sanh dâng lên; khi nào sanh dâng lên thời già chết dâng lên.`, ref: "Tương Ưng Bộ 12.69", url: "https://loicuaducphat.org/sn/sn12.69.html#content" },

{ text: `Này các Tỷ-kheo, biển lớn không dâng lên thời sông lớn không dâng lên; sông lớn không dâng lên thời sông nhỏ không dâng lên; sông nhỏ không dâng lên thời hồ lớn không dâng lên; hồ lớn không dâng lên thời hồ nhỏ không dâng lên. Cũng vậy, này các Tỷ-kheo, vô minh không dâng lên thời các hành không dâng lên; các hành không dâng lên thời thức không dâng lên; thức không dâng lên thời danh sắc không dâng lên; danh sắc không dâng lên thời sáu xứ không dâng lên; sáu xứ không dâng lên thời xúc không dâng lên; xúc không dâng lên thời thọ không dâng lên; thọ không dâng lên thời ái không dâng lên; ái không dâng lên thời thủ không dâng lên; thủ không dâng lên thời hữu không dâng lên; hữu không dâng lên thời sanh không dâng lên; sanh không dâng lên thời già chết không dâng lên.`, ref: "Tương Ưng Bộ 12.69", url: "https://loicuaducphat.org/sn/sn12.69.html#content" },

{ text: `Này các Tỷ-kheo, đối với ai không như thật biết và thấy các hành, người ấy cần phải tìm đến bậc Ðạo Sư để có như thật trí đối với các hành. Ðối với ai không như thật biết và thấy các hành tập khởi, người ấy cần phải tìm đến bậc Ðạo Sư để có như thật trí đối với các hành tập khởi. Ðối với ai không như thật biết và thấy các hành đoạn diệt, người ấy cần phải tìm đến bậc Ðạo Sư để có như thật trí đối với các hành đoạn diệt. Ðối với ai không như thật biết và thấy con đường đưa đến hành đoạn diệt, người ấy cần phải tìm đến bậc Ðạo Sư để có như thật trí đối với con đường đưa đến các hành đoạn diệt.`, ref: "Tương Ưng Bộ 12.82", url: "https://loicuaducphat.org/sn/sn12.82.html#content" },

{ text: `Rồi Thế Tôn lấy lên một ít bụi trên đầu móng tay rồi gọi các Tỷ-kheo: - Các Ông nghĩ thế nào, này các Tỷ-kheo, cái gì nhiều hơn, một ít bụi này Ta lấy lên trên đầu ngón tay, hay là quả đất lớn này?\n\n- Chính cái này, bạch Thế Tôn, là nhiều hơn, tức là quả đất lớn này. Ít hơn là một ít bụi được Thế Tôn lấy lên trên đầu ngón tay; không phải một trăm lần, không phải một ngàn lần, không phải một trăm ngàn lần có thể sánh bằng, khi so sánh quả đất lớn với một ít bụi được Thế Tôn lấy lên trên đầu ngón tay.\n\n- Cũng vậy, này các Tỷ-kheo, đối với vị Thánh đệ tử đã chứng được kiến cụ túc, đối với người đã chứng được minh kiến, cái này là nhiều hơn, tức là khổ đã được đoạn tận, đã được diệt tận; ít hơn là khổ còn lại, không phải một trăm lần, không phải một ngàn lần, không phải một trăm ngàn lần, có thể sánh bằng khi so sánh với khổ uẩn trước đã được đoạn tận, đã được diệt tận, tức là bảy lần nhiều hơn. Như vậy lợi ích lớn thay, này các Tỷ-kheo, như vậy lợi ích lớn thay là chứng đắc pháp nhãn.`, ref: "Tương Ưng Bộ 13.1", url: "https://loicuaducphat.org/sn/sn13.1.html#content" },

{ text: `- Này các Tỷ-kheo, tùy thuộc theo giới, các chúng sanh cùng hòa hợp, cùng đi với nhau. Chúng sanh liệt ý chí cùng hòa hợp, cùng đi với chúng sanh liệt ý chí. Chúng sanh thiện ý chí cùng hòa hợp, cùng đi với chúng sanh thiện ý chí.`, ref: "Tương Ưng Bộ 14.14", url: "https://loicuaducphat.org/sn/sn14.14.html#content" },

{ text: `Này các Tỷ-kheo, tùy thuộc theo giới thời quá khứ, các chúng sanh đã cùng hòa hợp, đã cùng đi với nhau. Chúng sanh liệt ý chí đã cùng hòa hợp, cùng đi với chúng sanh liệt ý chí. Chúng sanh thiện ý chí đã cùng hòa hợp, cùng đi với chúng sanh thiện ý chí.`, ref: "Tương Ưng Bộ 14.15", url: "https://loicuaducphat.org/sn/sn14.15.html#content" },

{ text: `Này các Tỷ-kheo, tùy thuộc theo giới thời vị lai, các chúng sanh sẽ cùng hòa hợp, sẽ cùng đi với nhau. Chúng sanh liệt ý chí sẽ cùng hòa hợp, cùng đi với chúng sanh liệt ý chí. Chúng sanh thiện ý chí sẽ cùng hòa hợp, cùng đi với chúng sanh thiện ý chí.`, ref: "Tương Ưng Bộ 14.15", url: "https://loicuaducphat.org/sn/sn14.15.html#content" },

{ text: `Ví như, này các Tỷ-kheo, sữa cùng hòa hợp, cùng đi với sữa; dầu cùng hòa hợp, cùng đi với dầu; thục tô cùng hòa hợp, cùng đi với thục tô; mật ong cùng hòa hợp, cùng đi với mật ong; mật mía cùng hòa hợp, cùng đi với mật mía. Cũng vậy, này các Tỷ-kheo, tùy thuộc theo giới, các chúng sanh cùng hòa hợp, cùng đi với nhau. Chúng sanh thiện ý chí cùng hòa hợp, cùng đi với chúng sanh thiện ý chí.`, ref: "Tương Ưng Bộ 14.16", url: "https://loicuaducphat.org/sn/sn14.16.html#content" },

{ text: `Liên lạc, dục tình sanh,\nLiên lạc, không được đoạn,\nNhư leo tấm ván nhỏ,\nBị chìm giữa sóng lớn,\nCũng vậy, đến kẻ nhác,\nKẻ sống thiện cũng chìm.\n\nDo vậy, hãy tránh xa\nKẻ nhác, không tinh tấn,\nHãy cộng trú bậc Hiền,\nBậc Thánh sống viễn ly,\nThường siêng năng tinh tấn,\nTinh cần tu Thiền tịnh.`, ref: "Tương Ưng Bộ 14.16", url: "https://loicuaducphat.org/sn/sn14.16.html#content" },
{ text: `- Này các Tỷ-kheo, tùy thuộc theo giới, các chúng sanh cùng hòa hợp, cùng đi với nhau. Kẻ bất tín cùng hòa hợp, cùng đi với kẻ bất tín. Kẻ không biết thẹn cùng hòa hợp, cùng đi với kẻ không biết thẹn. Kẻ không biết sợ cùng hòa hợp, cùng đi với kẻ không biết sợ. Kẻ ít nghe cùng hòa hợp, cùng đi với kẻ ít nghe. Kẻ biếng nhác cùng hòa hợp, cùng đi với kẻ biếng nhác. Kẻ thất niệm cùng hòa hợp, cùng đi với kẻ thất niệm. Kẻ ác tuệ cùng hòa hợp, cùng đi với kẻ ác tuệ.`, ref: "Tương Ưng Bộ 14.17", url: "https://loicuaducphat.org/sn/sn14.17.html#content" },

{ text: `- Này các Tỷ-kheo, tùy thuộc theo giới, các chúng sanh cùng hòa hợp, cùng đi với nhau. Kẻ tín cùng hòa hợp, cùng đi với kẻ tín. Kẻ biết thẹn cùng hòa hợp, cùng đi với kẻ biết thẹn. Kẻ biết sợ cùng hòa hợp, cùng đi với kẻ biết sợ. Kẻ nghe nhiều cùng hòa hợp, cùng đi với kẻ nghe nhiều. Kẻ tinh cần cùng hòa hợp, cùng đi với kẻ tinh cần. Kẻ trì niệm cùng hòa hợp, cùng đi với kẻ trì niệm. Kẻ trí tuệ cùng hòa hợp, cùng đi với kẻ trí tuệ.`, ref: "Tương Ưng Bộ 14.17", url: "https://loicuaducphat.org/sn/sn14.17.html#content" },
{ text: `Này các Tỷ-kheo, cho đến khi nào các chúng sanh đối với bốn giới này chưa như thật thắng tri như vậy vị ngọt là vị ngọt, như vậy nguy hiểm là nguy hiểm, như vậy xuất ly là xuất ly; thời này các Tỷ-kheo, các chúng sanh này không sống với tâm viễn ly, không tương quan, không liên hệ, với những chướng ngại được từ bỏ đối với Thiên giới, Ma giới, Phạm thiên giới, cùng các chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người.\n\nVà này các Tỷ-kheo, cho đến khi nào các chúng sanh đối với bốn giới này đã như thật thắng tri như vậy vị ngọt là vị ngọt, như vậy nguy hiểm là nguy hiểm, như vậy xuất ly là xuất ly; thời này các Tỷ-kheo, các chúng sanh này sống với tâm viễn ly, không tương quan, không liên hệ với những chướng ngại được từ bỏ đối với Thiên giới, Ma giới, Phạm thiên giới, cùng các chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người.`, ref: "Tương Ưng Bộ 14.33", url: "https://loicuaducphat.org/sn/sn14.33.html#content" },

{ text: `- Này các Tỷ-kheo, nếu địa giới thuần khổ, đầy những khổ, chìm đắm trong khổ, không chìm đắm trong lạc; thời các chúng sanh có thể không tham đắm địa giới. Và vì rằng, này các Tỷ-kheo, địa giới là lạc, đầy những lạc, chìm đắm trong lạc, không chìm đắm trong khổ, do vậy chúng sanh tham đắm địa giới.\n\nNày các Tỷ-kheo, nếu địa giới thuần lạc, đầy những lạc, chìm đắm trong lạc, không chìm đắm trong khổ; thời các chúng sanh có thể không nhàm chán địa giới. Và vì rằng, này các Tỷ-kheo, địa giới là khổ, đầy những khổ, chìm đắm trong khổ, không chìm đắm trong lạc; do vậy các chúng sanh nhàm chán địa giới.`, ref: "Tương Ưng Bộ 14.34", url: "https://loicuaducphat.org/sn/sn14.34.html#content" },

{ text: `- Này các Tỷ-kheo, ai hoan hỷ địa giới, người ấy hoan hỷ khổ. Ai hoan hỷ khổ, Ta nói rằng người ấy không giải thoát khỏi khổ. Này các Tỷ-kheo, ai hoan hỷ thủy giới… Này các Tỷ-kheo, ai hoan hỷ hỏa giới… Này các Tỷ-kheo, ai hoan hỷ phong giới, người ấy hoan hỷ khổ. Ai hoan hỷ khổ, Ta nói rằng người ấy không giải thoát khỏi khổ.`, ref: "Tương Ưng Bộ 14.35", url: "https://loicuaducphat.org/sn/sn14.35.html#content" },

{ text: `Này các Tỷ-kheo, ai không hoan hỷ địa giới, người ấy không hoan hỷ khổ. Ai không hoan hỷ khổ, Ta nói rằng người ấy giải thoát khỏi khổ. Này các Tỷ-kheo, ai không hoan hỷ thủy giới… Này các Tỷ-kheo, ai không hoan hỷ hỏa giới… Này các Tỷ-kheo, ai không hoan hỷ phong giới, người ấy không hoan hỷ khổ. Ai không hoan hỷ khổ, Ta nói rằng người ấy giải thoát khỏi khổ.`, ref: "Tương Ưng Bộ 14.35", url: "https://loicuaducphat.org/sn/sn14.35.html#content" },

{ text: `Này các Tỷ-kheo, sự sanh khởi, sự an trú, sự tái sanh, sự tái hiện hữu của địa giới là sự sanh khởi của khổ, sự an trú của tham, sự tái hiện hữu của già chết. Này các Tỷ-kheo… của thủy giới… Này các Tỷ-kheo… của hỏa giới… Này các Tỷ-kheo, sự sanh khởi, sự an trú, sự tái sanh, sự tái hiện hữu của phong giới là sự sanh khởi của khổ, sự an trú của tham, sự tái hiện hữu của già chết.\n\nNày các Tỷ-kheo, sự đoạn diệt, tịnh chỉ, tiêu diệt của địa giới là sự đoạn diệt của khổ, sự tịnh chỉ của tham, sự tiêu diệt của già chết. Này các Tỷ-kheo… của thủy giới… Này các Tỷ-kheo… của hỏa giới… Này các Tỷ-kheo, sự đoạn diệt, tịnh chỉ, tiêu diệt của phong giới là sự đoạn diệt của khổ, sự tịnh chỉ của tham, sự tiêu diệt của già chết.`, ref: "Tương Ưng Bộ 14.36", url: "https://loicuaducphat.org/sn/sn14.36.html#content" },

{ text: `- Vô thỉ là luân hồi này, này các Tỷ-kheo, khởi điểm không thể nêu rõ đối với lưu chuyển luân hồi của các chúng sanh bị vô minh che đậy, bị tham ái trói buộc. Ví như, này các Tỷ-kheo, có người chặt các cành cỏ, khúc cây, nhành cây, nhành lá, trong cõi Diêm-phù-đề này, chất chúng thành một đống, làm chúng thành những que đặt theo hình các ô vuông, cầm từng que đặt xuống và nói: “Ðây là mẹ tôi, đây là mẹ của mẹ tôi”. Và không thể cùng tận, này các Tỷ-kheo, là các bà mẹ, mẹ của người ấy. Nhưng nhành cỏ, khúc cây, nhành cây, nhành lá trong cõi Diêm-phù-đề này có thể đi đến đoạn tận, đoạn diệt.\n\nVì sao? Vô thỉ là luân hồi, này các Tỷ-kheo, khởi điểm không thể nêu rõ đối với lưu chuyển luân hồi của các chúng sanh bị vô minh che đậy, bị tham ái trói buộc. Cũng vậy, đã lâu ngày, này các Tỷ-kheo, các Ông chịu đựng khổ, chịu đựng thống khổ, chịu đựng tai họa, và các mộ phần ngày một lớn lên. Cho đến như vậy, này các Tỷ-kheo, là vừa đủ để các Ông nhàm chán, là vừa đủ để các Ông từ bỏ, là vừa đủ để các Ông giải thoát đối với tất cả các hành.`, ref: "Tương Ưng Bộ 15.1", url: "https://loicuaducphat.org/sn/sn15.1.html#content" },

{ text: `- Vô thỉ là luân hồi này, này các Tỷ-kheo, khởi điểm không thể nêu rõ đối với sự lưu chuyển luân hồi của các chúng sanh bị vô minh che đậy, bị tham ái trói buộc. Các Ông nghĩ thế nào, này các Tỷ-kheo, cái gì là nhiều hơn? Dòng nước mắt tuôn chảy do các Ông than van, khóc lóc, phải hội ngộ với những gì không ưa, phải biệt ly với những gì mình thích, khi các Ông phải lưu chuyển luân hồi trong thời gian dài này hay là nước trong bốn biển lớn?\n\n- Bạch Thế Tôn, theo như lời Thế Tôn thuyết pháp, chúng con hiểu rằng, cái này, bạch Thế Tôn, là nhiều hơn, tức là dòng nước mắt tuôn chảy do chúng con than van, khóc lóc, phải hội ngộ với những gì không ưa, phải biệt ly với những gì mình thích, khi phải lưu chuyển luân hồi trong thời gian dài này chớ không phải nước trong bốn biển lớn.\n\n- Lành thay, lành thay, này các Tỷ-kheo! Lành thay, này các Tỷ-kheo, các Ông đã hiểu như vậy Pháp do Ta dạy!`, ref: "Tương Ưng Bộ 15.3", url: "https://loicuaducphat.org/sn/sn15.3.html#content" },

{ text: `Cái này là nhiều hơn, này các Tỷ-kheo, tức là dòng nước mắt tuôn chảy do các Ông than van, khóc lóc, phải hội ngộ với những gì không ưa, phải biệt ly với những gì mình thích, khi các Ông phải lưu chuyển luân hồi trong thời gian dài này chớ không phải nước trong bốn biển lớn. Trong một thời gian dài, này các Tỷ-kheo, các Ông chịu đựng mẹ chết. … các Ông chịu đựng con chết.. … các Ông chịu đựng con gái chết … … các Ông chịu đựng tai họa về bà con … … các Ông chịu đựng tai họa về tiền của … Trong một thời gian dài, này các Tỷ-kheo, các Ông chịu đựng tai họa của bệnh tật. Cái này là nhiều hơn, là dòng nước mắt tuôn chảy do các Ông than van, khóc lóc, phải hội ngộ với những gì mình không ưa, phải biệt ly với những gì mình thích, khi các Ông phải chịu đựng tai họa của bệnh tật chớ không phải nước trong bốn biển. Vì sao? Vô thỉ là luân hồi này, này các Tỷ-kheo … bị tham ái trói buộc. Cho đến như vậy, này các Tỷ-kheo, là vừa đủ để các Ông nhàm chán, là vừa đủ để các Ông từ bỏ, là vừa đủ để các Ông giải thoát đối với tất cả các hành.`, ref: "Tương Ưng Bộ 15.3", url: "https://loicuaducphat.org/sn/sn15.3.html#content" },

{ text: `- Có bao nhiêu kiếp, bạch Thế Tôn đã đi qua, đã vượt qua?\n- Rất nhiều, này Bà-la-môn, là những kiếp đã đi qua, đã vượt qua. Thật không dễ gì để có thể đếm chúng được, là một vài kiếp, một vài trăm kiếp, một vài ngàn kiếp, một vài trăm ngàn kiếp.\n- Tôn giả Gotama có thể cho một ví dụ được không?\n- Có thể được, này Bà-la-môn. Ví như, này Bà-la-môn, sông Hằng này từ chỗ nguồn bắt đầu đến chỗ nó chảy nhập vào biển. Số cát nằm ở giữa chặng ấy, thật không dễ gì để có thể đếm chúng được là một số hột cát, là số trăm hột cát, là số ngàn hột cát, là số trăm ngàn hột cát. Nhiều hơn vậy, này Bà-la-môn, là những kiếp đã đi qua, đã vượt qua. Thật không dễ gì có thể đếm chúng được, là một số kiếp, một trăm kiếp, là một ngàn kiếp, là một số trăm ngàn kiếp.\n\nVí sao? Vô thỉ là luân hồi này, này Bà-la-môn, khởi điểm không thể nêu rõ đối với sự lưu chuyển luân hồi của các chúng sanh bị vô minh che đậy, bị tham ái trói buộc. Cũng vậy, đã lâu ngày, này Bà-la-môn, các Ông chịu đựng khổ, chịu đựng thống khổ, chịu đựng tai họa, và các mộ phần ngày một lớn lên. Cho đến như vậy, này Bà-la-môn, là vừa đủ để nhàm chán, là vừa đủ để từ bỏ, là vừa đủ để giải thoát đối với tất cả các hành.`, ref: "Tương Ưng Bộ 15.8", url: "https://loicuaducphat.org/sn/sn15.8.html#content" },

{ text: `- Vô thỉ là luân hồi này, này các Tỷ-kheo. Khởi điểm không thể nêu rõ đối với sự lưu chuyển luân hồi của các chúng sanh bị vô minh che đậy, bị tham ái trói buộc. Ví như, này các Tỷ-kheo, một cây gậy được ném lên trên hư không, khi thì rơi trên đầu gốc, khi thì rơi chặng giữa, khi thì rơi đầu ngọn. Cũng vậy, này các Tỷ-kheo, các chúng sanh bị vô minh che đậy, bị tham ái trói buộc, lưu chuyển luân hồi, khi thì từ thế giới này đi thế giới khác, khi thì từ thế giới khác đến thế giới này. Vì sao? Vô thỉ là luân hồi, này các Tỷ-kheo … là vừa đủ để được giải thoát.`, ref: "Tương Ưng Bộ 15.9", url: "https://loicuaducphat.org/sn/sn15.9.html#content" },

{ text: `- Vô thỉ là luân hồi này, này các Tỷ-kheo … Các xương của một người, này các Tỷ-kheo, lưu chuyển luân hồi có thể lớn như một đồi xương, một chồng xương, một đống xương, như núi Vepulla này, nếu có người thâu lượm xương lại, gìn giữ chúng, không làm chúng hủy hoại. Vì sao? Vô thỉ là luân hồi này, này các Tỷ-kheo … là vừa đủ để giải thoát đối với tất cả các hành.`, ref: "Tương Ưng Bộ 15.10", url: "https://loicuaducphat.org/sn/sn15.10.html#content" },

{ text: `Chồng chất như xương người,\nChỉ sống có một kiếp,\nChất đống bằng hòn núi,\nBậc Ðạo Sư nói vậy.\n\nÐống xương ấy được nói,\nLớn như Vepulla,\nPhía Bắc núi Linh Thứu,\nNúi thành Magadha.\n\nNgười thấy bốn sự thật,\nVới chân chánh trí tuệ,\nKhổ và khổ tập khởi,\nSẽ vượt qua đau khổ,\nCon đường Thánh tám ngành,\nDẫn đến khổ tịnh chỉ.\n\nNgười ấy phải luân chuyển,\nTối đa là bảy lần.\nLà vị đoạn tận khổ,\nÐoạn diệt mọi kiết sử.`, ref: "Tương Ưng Bộ 15.10", url: "https://loicuaducphat.org/sn/sn15.10.html#content" },

{ text: `- Vô thỉ là luân hồi này, này các Tỷ-kheo. Khởi điểm không thể nêu rõ đối với sự lưu chuyển luân hồi của các chúng sanh bị vô minh che đậy, bị tham ái trói buộc. Này các Tỷ-kheo, khi các Ông thấy sự khốn cùng, bất hạnh, các Ông phải đi đến kết luận: “Chúng ta chịu đựng như vậy trong thời gian dài này”. Vì sao? Vô thỉ là luân hồi này, này các Tỷ-kheo … là vừa đủ để giải thoát đối với tất cả các hành.`, ref: "Tương Ưng Bộ 15.11", url: "https://loicuaducphat.org/sn/sn15.11.html#content" },

{ text: `- Vô thỉ là luân hồi này, này các Tỷ-kheo. Khởi điểm không thể nêu rõ, đối với sự lưu chuyển luân hồi của các chúng sanh bị vô minh che đậy, bị tham ái trói buộc. Các Ông nghĩ thế nào, này các Tỷ-kheo, cái nào là nhiều hơn, dòng máu tuôn chảy do đầu bị thương tích khi các Ông lưu chuyển luân hồi trong thời gian dài này, hay là nước trong bốn biển lớn? Cái này là nhiều hơn, này các Tỷ-kheo, tức là dòng máu tuôn chảy do đầu bị thương tích khi các Ông lưu chuyển luân hồi trong thời gian dài này, không phải là nước trong bốn biển lớn. Này các Tỷ-kheo, dòng máu tuôn chảy do đầu các Ông bị thương tích khi các Ông là bò, sanh ra làm bò trong thời gian dài … sanh ra làm cừu trong thời gian dài … … khi các Ông là dê, sanh ra làm dê … … khi các Ông là nai, sanh ra làm nai … … khi các Ông là gia cầm, sanh ra làm gia cầm … … khi các Ông là heo, sanh ra làm heo … Này các Tỷ-kheo, dòng máu tuôn chảy do đầu bị thương tích khi các Ông làm đạo tặc, làm kẻ trộm làng, bị bắt trong thời gian dài … Này các Tỷ-kheo, dòng máu tuôn chảy do đầu bị thương tích khi các Ông làm đạo tặc, tư thông vợ người, bị bắt trong thời gian dài chớ không phải là nước trong bốn biển lớn.`, ref: "Tương Ưng Bộ 15.13", url: "https://loicuaducphat.org/sn/sn15.13.html#content" },

{ text: `- Tri túc, này các Tỷ-kheo, là Kassapa này, với bất cứ loại y nào, và tán thán hạnh tri túc với bất cứ loại y nào; … … tán thán hạnh tri túc với bất cứ đồ ăn khất thực nào; … … tán thán hạnh tri túc với bất cứ loại sàng tọa nào; … … tán thán hạnh tri túc với bất cứ loại thuốc men trị bệnh nào; và không vì duyên với thuốc men trị bệnh, làm điều bất chánh, bất xứng. Nếu không được thuốc men trị bệnh, vị này không có dao động. Và nếu được thuốc men trị bệnh, vị này dùng thuốc men trị bệnh ấy, không tham lam, không say đắm, không phạm tội, thấy nguy hại, quán xuất ly với trí tuệ.`, ref: "Tương Ưng Bộ 16.1", url: "https://loicuaducphat.org/sn/sn16.1.html#content" },

{ text: `Do vậy, này các Tỷ-kheo, hãy học tập như sau: “Chúng tôi sẽ tri túc với bất cứ loại y nào, và chúng tôi sẽ là người tán thán hạnh tri túc với bất cứ loại y nào. Và không vì y, chúng tôi sẽ làm điều bất chánh, bất xứng. Nếu không được y, chúng tôi sẽ không dao động. Và nếu được y, chúng tôi sẽ dùng y ấy, không tham lam, không say đắm, không phạm tội, thấy sự nguy hại, quán xuất ly với trí tuệ. Chúng tôi sẽ tri túc với bất cứ loại đồ ăn khất thực nào … với bất cứ loại sàng tọa nào … với bất cứ loại thuốc men trị bệnh nào, và chúng tôi sẽ là người tán thán sự tri túc với bất cứ loại thuốc men trị bệnh nào. Và không vì thuốc men trị bệnh, chúng tôi sẽ làm điều bất chánh, bất xứng. Nếu không được thuốc men trị bệnh, chúng tôi sẽ không dao động. Và nếu được thuốc men trị bệnh, chúng tôi sẽ dùng thuốc men trị bệnh ấy, không tham lam, không say đắm, không phạm tội, thấy nguy hại, quán xuất ly với trí tuệ. Như vậy, này các Tỷ-kheo, các ông cần phải học tập”.`, ref: "Tương Ưng Bộ 16.1", url: "https://loicuaducphat.org/sn/sn16.1.html#content" },

{ text: `Và này Hiền giả, thế nào là có nhiệt tâm? Ở đây, này Hiền giả, vị Tỷ-kheo suy nghĩ: “Các ác bất thiện pháp không khởi lên nơi ta. Nếu chúng khởi lên, có thể đưa đến bất lợi”, vị ấy khởi nhiệt tâm. “Các ác bất thiện pháp khởi lên nơi ta. Nếu chúng không bị đoạn diệt, có thể đưa đến bất lợi”, vị ấy khởi nhiệt tâm. “Các thiện pháp không khởi lên nơi ta. Nếu chúng không khởi lên, có thể đưa đến bất lợi”, vị ấy khởi nhiệt tâm. “Các thiện pháp khởi lên nơi ta. Nếu chúng bị đoạn diệt, có thể đưa đến bất lợi”, vị ấy khởi nhiệt tâm. “Các thiện pháp khởi lên nơi ta. Nếu chúng bị đoạn diệt, có thể đưa đến bất lợi”, vị ấy khởi lên nhiệt tâm. Như vậy, này Hiền giả, là có nhiệt tâm.`, ref: "Tương Ưng Bộ 16.2", url: "https://loicuaducphat.org/sn/sn16.2.html#content" },

{ text: `Và này Hiền giả, như thế nào là có biết sợ? Ở đây, này Hiền giả, vị Tỷ-kheo suy nghĩ: “Các ác bất thiện pháp không khởi lên nơi ta. Nếu chúng khởi lên, có thể đưa đến bất lợi”, vị ấy có biết sợ. “Các ác bất thiện pháp khởi lên nơi ta. Nếu chúng không bị đoạn diệt, có thể đưa đến bất lợi”, vị ấy có biết sợ. “Các thiện pháp không khởi lên nơi ta. Nếu chúng không khởi lên, có thể đưa đến bất lợi”, vị ấy có biết sợ. “Các thiện pháp khởi lên nơi ta. Nếu chúng bị đoạn diệt, có thể đưa đến bất lợi”, vị ấy có biết sợ. Như vậy, này Hiền giả, là có biết sợ. Như vậy, này Hiền giả, là có nhiệt tâm, có biết sợ, có thể có giác ngộ, có thể có Niết-bàn, có thể đưa đến chứng đạt vô thượng an ổn khỏi các khổ ách.`, ref: "Tương Ưng Bộ 16.2", url: "https://loicuaducphat.org/sn/sn16.2.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một người nhìn một cái giếng cũ, hay sườn núi dốc, hay thác nước, thân phải dè dặt, tâm phải dè dặt. Cũng vậy, này các Tỷ-kheo, hãy giống như mặt trăng khi đi đến các gia đình, thân phải dè dặt, tâm phải dè dặt, luôn luôn là người mới giữa các gia đình, không có đường đột xông xáo.`, ref: "Tương Ưng Bộ 16.3", url: "https://loicuaducphat.org/sn/sn16.3.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, bàn tay này giữa hư không, không bị dính vào, không bị nắm lấy, không bị trói buộc. Cũng vậy, này các Tỷ-kheo, là vị Tỷ-kheo đi đến các gia đình, tâm không bị dính vào, không bị nắm lấy, không bị trói buộc, nghĩ rằng: “Những ai muốn được lợi, hãy được lợi! Những ai muốn công đức, hãy làm các công đức!”.`, ref: "Tương Ưng Bộ 16.3", url: "https://loicuaducphat.org/sn/sn16.3.html#content" },

{ text: `- Và này các Tỷ-kheo, Tỷ-kheo nào với tâm như thế này thuyết pháp cho các người khác: “Pháp được Thế Tôn khéo giảng, pháp ấy liên hệ đến hiện tại, có hiệu quả tức thời, đến để mà thấy, có khả năng hướng thượng, được người có trí tự mình giác hiểu. Ôi, mong họ được nghe pháp ta giảng. Và sau khi nghe pháp, mong họ được hiểu rõ pháp. Và sau khi hiểu rõ pháp, mong họ như vậy thực hành; duyên pháp thiện pháp tánh thuyết pháp cho các người khác. Duyên lòng từ bi, duyên lòng từ mẫn, khởi lòng lân mẫn thuyết pháp cho các người khác”, này các Tỷ-kheo, Tỷ-kheo như vậy là Tỷ-kheo thanh tịnh thuyết pháp.`, ref: "Tương Ưng Bộ 16.3", url: "https://loicuaducphat.org/sn/sn16.3.html#content" },
{ text: `Và này các Tỷ-kheo, Tỷ-kheo nào với tâm như thế này đi đến các gia đình (nghĩ rằng): “Ðối với các gia đình người khác, làm sao có thể mong: ‘Mong họ hãy cho ta, chớ có không cho. Mong họ cho ta nhiều, chớ có cho ít. Mong họ cho ta đồ tốt, chớ có cho đồ xấu. Mong họ cho ta mau, chớ có cho chậm. Mong họ kính trọng ta, chớ có không kính trọng’?”.\n\nNày các Tỷ-kheo, nếu Tỷ-kheo với tâm như vậy, khi đi đến các gia đình không được cho, Tỷ-kheo không vì vậy mà bị bực phiền, không do nhân duyên ấy mà cảm thọ khổ ưu. Họ cho ít, không cho nhiều… họ cho đồ xấu, không cho đồ tốt, cho chậm, không cho mau… cho bất kính, không phải kính trọng, Tỷ-kheo không vì vậy mà bị bực phiền, không do nhân duyên ấy mà cảm thọ khổ ưu.`, ref: "Tương Ưng Bộ 16.4", url: "https://loicuaducphat.org/sn/sn16.4.html#content" },

{ text: `- Lành thay, lành thay, Kassapa! Thật vì hạnh phúc cho quần sanh, này Kassapa, ông đã thực hành như vậy, vì an lạc cho quần sanh, vì lòng từ mẫn với đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư Thiên và loài Người. Do vậy, này Kassapa, hãy mang vải gai thô, phấn tảo đáng được quăng bỏ. Hãy sống khất thực và trú ở trong rừng!`, ref: "Tương Ưng Bộ 16.5", url: "https://loicuaducphat.org/sn/sn16.5.html#content" },

{ text: `- Thật sự, này các Tỷ-kheo, các ông đã phạm tội, ngu đần như vậy, si mê như vậy, bất thiện như vậy! Vì rằng các ông đã xuất gia trong Pháp và Luật khéo nói này, các ông đã nói với nhau: “Hãy đến, này Tỷ-kheo, ai sẽ là người nói nhiều hơn? Ai sẽ là người nói tốt đẹp hơn? Ai sẽ là người nói dài hơn?”. Và vì rằng, này các Tỷ-kheo, các ông đã thấy tội lỗi là tội lỗi, như pháp sám hối, Ta chấp nhận tội lỗi ấy cho các ông!\n\nNày các Tỷ-kheo, như vậy luật của bậc Thánh được tăng trưởng, khi nào có người sau khi thấy tội lỗi là tội lỗi, như pháp sám hối để ngăn ngừa trong tương lai!`, ref: "Tương Ưng Bộ 16.6", url: "https://loicuaducphat.org/sn/sn16.6.html#content" },

{ text: `Ví như mặt trăng, này Kassapa, trong thời kỳ tối trời, dầu là đêm hay là ngày, hình sắc tổn giảm dần, hình tròn tổn giảm dần, ánh sáng tổn giảm dần, quỹ đạo nó đi tổn giảm dần. Cũng vậy, này Kassapa, với ai không có lòng tin đối với thiện pháp, không có biết thẹn… không có biết sợ… không có tinh tấn… không có trí tuệ đối với thiện pháp; với người ấy, dầu là đêm hay ngày, chờ đợi là sự tổn giảm đối với thiện pháp, không phải là sự tăng trưởng.`, ref: "Tương Ưng Bộ 16.7", url: "https://loicuaducphat.org/sn/sn16.7.html#content" },

{ text: `Ví như mặt trăng, này Kassapa, trong thời kỳ sáng trời, dầu là đêm hay ngày, hình sắc tăng trưởng dần, hình tròn tăng trưởng dần, ánh sáng tăng trưởng dần, quỹ đạo nó đi tăng trưởng dần. Cũng vậy, này Kassapa, ai có lòng tin đối với thiện pháp, có biết thẹn… có biết sợ… có tinh tấn… có trí tuệ là sự tăng trưởng đối với thiện pháp; với người ấy, dầu là đêm hay ngày, chờ đợi là sự tăng trưởng đối với thiện pháp, không phải là sự tổn giảm.`, ref: "Tương Ưng Bộ 16.7", url: "https://loicuaducphat.org/sn/sn16.7.html#content" },

{ text: `- Này Kassapa, thuở xưa các Trưởng lão Tỷ-kheo là những vị ở rừng như vậy và tán thán ở rừng, là những vị đi khất thực và tán thán hạnh khất thực, là những vị mang y phấn tảo và tán thán hạnh mang y phấn tảo, là những vị mang ba y và tán thán hạnh mang ba y, là những vị sống thiểu dục và tán thán hạnh thiểu dục, là những vị sống tri túc và tán thán hạnh tri túc, là những vị sống viễn ly và tán thán hạnh viễn ly, là những vị sống không giao thiệp và tán thán hạnh không giao thiệp, là những vị sống tinh cần và tán thán hạnh tinh cần.`, ref: "Tương Ưng Bộ 16.8", url: "https://loicuaducphat.org/sn/sn16.8.html#content" },

{ text: `Ở đây, vị Tỷ-kheo nào sống ở rừng và tán thán hạnh ở rừng, đi khất thực và tán thán hạnh khất thực, mang y phấn tảo và tán thán hạnh mang y phấn tảo, mang ba y và tán thán hạnh mang ba y, sống thiểu dục và tán thán hạnh thiểu dục, sống tri túc và tán thánh hạnh tri túc, sống viễn ly và tán thán hạnh sống viễn ly, sống không giao thiệp và tán thán hạnh không giao thiệp, sống tinh cần và tán thán hạnh tinh cần; vị Tỷ-kheo ấy được các vị Trưởng lão Tỷ-kheo mời ngồi và nói: “Hãy đến, này Tỷ-kheo, Tỷ-kheo này tên gì? Thật là hiền thiện, vị Tỷ-kheo này! Thật là muốn học, vị Tỷ-kheo này! Hãy đến Tỷ-kheo, hãy ngồi chỗ ngồi này!”`, ref: "Tương Ưng Bộ 16.8", url: "https://loicuaducphat.org/sn/sn16.8.html#content" },

{ text: `Ở đây, này Kassapa, các tân Tỷ-kheo suy nghĩ như sau: “Tỷ-kheo nào sống ở rừng và tán thán hạnh sống ở rừng, đi khất thực… mang y phấn tảo… mang ba y… thiểu dục… tri túc… sống viễn ly… sống không giao thiệp… tinh cần và tán thán hạnh tinh cần; Tỷ-kheo ấy được các Trưởng lão Tỷ-kheo mời ngồi và nói: “Hãy đến, này Tỷ-kheo, Tỷ-kheo này tên gì? Thật là hiền thiện, Tỷ-kheo này! Thật là muốn học, Tỷ-kheo này! Hãy đến Tỷ-kheo, hãy ngồi chỗ ngồi này”. Các vị ấy thực hành đúng như vậy và như vậy các vị ấy được hạnh phúc, được an lạc trong một thời gian dài.`, ref: "Tương Ưng Bộ 16.8", url: "https://loicuaducphat.org/sn/sn16.8.html#content" },

{ text: `Này Kassapa, ai nói một cách chơn chánh như sau: “Người sống Phạm hạnh phải chịu đựng những hiểm nạn của Phạm hạnh. Người sống Phạm hạnh phải bị bức não bởi những áp bức của Phạm hạnh”. Nói như vậy, này Kassapa, là nói một cách chơn chánh. Người sống Phạm hạnh phải chịu đựng những hiểm nạn của Phạm hạnh. Người sống Phạm hạnh phải bị bức não bởi những áp bức của Phạm hạnh.`, ref: "Tương Ưng Bộ 16.8", url: "https://loicuaducphat.org/sn/sn16.8.html#content" },

{ text: `Ví như, này Kassapa, chiếc thuyền bị chìm vì chở quá nặng. Không phải vì vậy, này Kassapa, diệu pháp bị biến mất. Này Kassapa, có năm thối pháp khiến cho diệu pháp bị hỗn loạn và biến mất. Thế nào là năm? Ở đây, này Kassapa, các Tỷ-kheo, Tỷ-kheo-ni, nam cư sĩ, nữ cư sĩ sống không tôn kính, không tùy thuận bậc Ðạo Sư, sống không tôn kính, không tùy thuận Chánh pháp, sống không tôn kính, không tùy thuận chúng Tăng, sống không tôn kính, không tùy thuận học giới, sống không tôn kính, không tùy thuận đối với Thiền định. Này Kassapa, chính những thối pháp này đưa đến sự hỗn loạn, sự biến mất của diệu pháp.`, ref: "Tương Ưng Bộ 16.13", url: "https://loicuaducphat.org/sn/sn16.13.html#content" },

{ text: `Này Kassapa, chính những thối pháp này đưa đến sự hỗn loạn, sự biến mất của diệu pháp. Và có năm pháp, này Kassapa, đưa đến sự an trú, bền vững, không biến mất của diệu pháp. Thế nào là năm? Ở đây, này Kassapa, các Tỷ-kheo, Tỷ-kheo-ni, nam cư sĩ, nữ cư sĩ sống kính trọng, tùy thuận bậc Ðạo Sư, sống kính trọng, tùy thuận Chánh pháp, sống kính trọng, tùy thuận chúng Tăng, sống kính trọng, tùy thuận học giới, sống kính trọng tùy thuận Thiền định. Chính năm pháp này, này Kassapa, đưa đến sự an trú, bền vững, không biến mất của diệu pháp.`, ref: "Tương Ưng Bộ 16.13", url: "https://loicuaducphat.org/sn/sn16.13.html#content" },

{ text: `- Khổ lụy, này các Tỷ-kheo, là các lợi đắc, cung kính, danh vọng; thật là đắng cay, ác độc, là chướng ngại pháp để chứng đạt vô thượng an ổn, khỏi các khổ ách. Do vậy, này các Tỷ-kheo, cần phải học tập như sau: “Ðối với lợi đắc, cung kính, danh vọng đã đến, chúng ta sẽ từ bỏ chúng. Ðối với lợi đắc, cung kính, danh vọng chưa đến, chúng ta không để chúng xâm chiếm tâm và an trú”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 17.1", url: "https://loicuaducphat.org/sn/sn17.1.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một người câu cá quăng một lưỡi câu ngắn có mồi thịt vào trong một hồ nước sâu, và một con cá có mắt thấy mồi thịt nuốt lưỡi câu ấy. Như vậy, này các Tỷ-kheo, con cá đã nuốt lưỡi câu ấy bị rơi vào bất hạnh, bị rơi vào tai họa, bị người câu cá muốn làm gì thì làm. Người câu cá, này các Tỷ-kheo, chỉ cho ma, lưỡi câu, này các Tỷ-kheo, chỉ cho lợi đắc, cung kính, danh vọng. Tỷ-kheo nào, này các Tỷ-kheo, thọ hưởng, ái luyến lợi đắc, cung kính, danh vọng đã đến, Tỷ-kheo ấy, này các Tỷ-kheo, được gọi là Tỷ-kheo đã nuốt lưỡi câu của ác ma, bị rơi vào bất hạnh, bị rơi vào tai họa, bị ác ma muốn làm gì thì làm.`, ref: "Tương Ưng Bộ 17.2", url: "https://loicuaducphat.org/sn/sn17.2.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một con dê cái lông dài, đi vào một khóm cây gai gốc; chỗ này, chỗ kia, nó bị mắc dính vào; chỗ này, chỗ kia, nó bị mắc vướng vào; chỗ này, chỗ kia, nó bị trói buộc vào; chỗ này, chỗ kia, nó bị rơi vào bất hạnh, tai họa. Cũng như vậy, này các Tỷ-kheo, ở đây, có Tỷ-kheo bị lợi đắc, cung kính, danh vọng chi phối, tâm bị xâm chiếm, vào buổi sáng đắp y, cầm y bát, đi vào làng hay thị trấn để khất thực. Chỗ này, chỗ kia, vị ấy bị mắc dính vào; chỗ này, chỗ kia, vị ấy bị mắc vướng vào; chỗ này, chỗ kia, vị ấy bị trói cột vào; chỗ này, chỗ kia, vị ấy bị rơi vào bất hạnh, tai họa.`, ref: "Tương Ưng Bộ 17.4", url: "https://loicuaducphat.org/sn/sn17.4.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một con trùng phẩn, ăn phân, đầy những phân, tràn ngập những phân, và trước mặt có một đống phân lớn. Nó khinh miệt các con trùng phẩn khác và nói: “Ta ăn phân, đầy những phân, tràn ngập những phân, và trước mặt ta, có đống phân lớn này”.\n\nCũng vậy, này các Tỷ-kheo, ở đây, có Tỷ-kheo bị lợi đắc, cung kính, danh vọng chi phối, tâm bị xâm chiếm, vào buổi sáng đắp y, cầm y bát, vào làng hay thị trấn để khất thực. Vị ấy tại đây đã ăn uống no đủ, lại được mời vào ngày mai, và bình bát của vị ấy được tràn đầy.\n\nVị ấy đi đến ngôi vườn (tịnh xá) và giữa chúng Tỷ-kheo khoe khoang như sau: “Ta ăn uống no đủ, lại được mời vào ngày mai, và bình bát này của ta tràn đầy. Ta nhận được các vật dụng như y áo, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh. Nhưng các Tỷ-kheo khác công đức ít, ảnh hưởng ít, không nhận được các vật dụng như y áo, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh”.\n\nVị ấy bị lợi đắc, cung kính, danh vọng chi phối, tâm bị xâm chiếm, khinh miệt các Tỷ-kheo chánh hạnh khác. Này các Tỷ-kheo, như vậy sẽ đem lại bất hạnh, đau khổ lâu dài cho kẻ ngu si ấy.`, ref: "Tương Ưng Bộ 17.5", url: "https://loicuaducphat.org/sn/sn17.5.html#content" },

{ text: `- Khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Như thế nào, này các Tỷ-kheo, sét đánh (được ví như) một người hữu học với tâm nhiệt thành, khi bị các lợi đắc, cung kính, danh vọng chạm đến? Này các Tỷ-kheo, sét đánh chỉ cho lợi đắc, cung kính, danh vọng chạm đến. Như vậy, khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 17.6", url: "https://loicuaducphat.org/sn/sn17.6.html#content" },

{ text: `- Khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Như thế nào, này các Tỷ-kheo, bị mũi tên độc bắn trúng (được ví như) một người hữu học với tâm trí nhiệt thành, khi bị các lợi đắc, cung kính, danh vọng chạm đến. Mũi tên, này các Tỷ-kheo, chỉ cho các lợi đắc, cung kính, danh vọng … Như vậy, khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 17.7", url: "https://loicuaducphat.org/sn/sn17.7.html#content" },

{ text: `- Khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Ở đây, này các Tỷ-kheo, Ta thấy có người bị sự cung kính chi phối, tâm bị xâm chiếm, sau khi thân hoại mạng chung, phải sanh vào khổ xứ, ác thú, đọa xứ, địa ngục. Ở đây, này các Tỷ-kheo, Ta thấy có người bị sự không cung kính chi phối, tâm bị xâm chiếm, sau khi thân hoại mạng chung, phải sanh vào khổ xứ, ác thú, đọa xứ, địa ngục. Nhưng ở đây, này các Tỷ-kheo, Ta thấy có người bị cả hai cung kính và không cung kính chi phối, tâm bị xâm chiếm, sau khi thân hoại mạng chung, phải sanh vào khổ xứ, ác thú, đọa xứ, địa ngục. Như vậy, khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 17.10", url: "https://loicuaducphat.org/sn/sn17.10.html#content" },

{ text: `Ai khi được cung kính, Khi không được cung kính, Trong cả hai trường hợp, Tâm định, không lay chuyển; Sống hạnh không phóng dật, Tâm thường nhập Thiền tư, Với tâm tưởng tế nhị, Chánh quán các sở kiến, Không còn lạc chấp thủ, Ðược gọi bậc Chơn nhơn.`, ref: "Tương Ưng Bộ 17.10", url: "https://loicuaducphat.org/sn/sn17.10.html#content" },

{ text: `- Khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Ở đây, này các Tỷ-kheo, với tâm của Ta, Ta biết có người có tâm như sau: “Dầu cho vì một bình bát bạc đựng đầy phấn vàng, vị này cũng không có cố ý nói láo”. Trong một thời gian khác, Ta lại thấy người ấy bị lợi đắc, cung kính, danh vọng chi phối, tâm bị xâm chiếm, đã cố ý nói láo. Như vậy, khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 17.12", url: "https://loicuaducphat.org/sn/sn17.12.html#content" },

{ text: `- Này các Tỷ-kheo, những Sa-môn hay Bà-la-môn nào như thật biết vị ngọt, sự nguy hiểm, sự xuất ly của lợi đắc, cung kính, danh vọng; các vị Sa-môn hay Bà-la-môn ấy đối với Ta, đuợc chấp nhận là vị Sa-môn giữa các Sa-môn, hay là Bà-la-môn giữa các Bà-la-môn. Và những bậc Tôn giả ấy, ngay trong đời sống hiện tại, có thể tự mình chứng ngộ với thượng trí, chứng đạt và an trú mục đích Sa-môn hạnh và mục đích Bà-la-môn hạnh.`, ref: "Tương Ưng Bộ 17.25", url: "https://loicuaducphat.org/sn/sn17.25.html#content" },

{ text: `- Khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Lợi đắc, cung kính, danh vọng, này các Tỷ-kheo, cắt đứt da ngoài. Sau khi cắt đứt da ngoài, chúng cắt đứt da trong. Sau khi cắt đứt da trong, chúng cắt đứt thịt. Sau khi cắt đứt thịt, chúng cắt đứt dây gân. Sau khi cắt đứt dây gân, chúng cắt đứt xương. Sau khi cắt đứt xương, chúng chạm tới tủy và đứng lại. Như vậy, khổ lụy, này các Tỷ-kheo, là lợi đắc, cung kính, danh vọng … Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 17.28", url: "https://loicuaducphat.org/sn/sn17.28.html#content" },

{ text: `- Này Rāhula, Ông nghĩ thế nào? Mắt là thường hay vô thường? - Là vô thường, bạch Thế Tôn. - Cái gì vô thường là khổ hay lạc? - Là khổ, bạch Thế Tôn. - Cái gì vô thường, khổ, chịu sự biến hoại, có hợp lý chăng nếu xem cái ấy: “Cái này là của tôi, cái này là tôi, cái này tự ngã của tôi”? - Thưa không, bạch Thế Tôn. - Cái gì vô thường là khổ hay lạc? - Là khổ, bạch Thế Tôn. - Cái gì vô thường, khổ, chịu sự biến hoại, có hợp lý chăng, khi xem cái ấy: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”? - Thưa không, bạch Thế Tôn. - Thấy vậy, này Rāhula, bậc Thánh đệ tử nghe nhiều, nhàm chán mắt, nhàm chán tai, nhàm chán mũi, nhàm chán lưỡi, nhàm chán thân, nhàm chán ý. Do nhàm chán, vị ấy ly tham. Do ly tham, vị ấy giải thoát. Trong sự giải thoát, trí khởi lên: “Ta đã giải thoát”. Vị ấy biết: “Sanh đã tận, Phạm hạnh đã thành; những gì nên làm đã làm; không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 18.1", url: "https://loicuaducphat.org/sn/sn18.1.html#content" },

{ text: `- Bạch Thế Tôn, do biết thế nào, do thấy thế nào, trong thân có thức này và trong tất cả tướng ở ngoài, không có ngã kiến, ngã sở kiến, ngã mạn tùy miên?\n\n- Này Rāhula, phàm sắc nào quá khứ, vị lai, hiện tại, hoặc nội hay ngoại, hoặc thô hay tế, hoặc liệt hay thắng, hoặc xa hay gần, vị ấy thấy như thật tất cả các sắc với chánh trí tuệ là: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”. Phàm thọ nào … Phàm tưởng nào … Phàm hành nào … Phàm thức nào quá khứ, vị lai, hiện tại, hoặc nội hay ngoại, hoặc thô hay tế, hoặc liệt hay thắng, hoặc xa hay gần, vị ấy thấy như thật tất cả các thức với chánh trí tuệ là: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”.\n\nNày Rāhula, do biết như vậy, do thấy như vậy, trong thân có thức này với tất cả tướng ở ngoài, không có ngã kiến, không có ngã sở kiến, không có ngã mạn tùy miên.`, ref: "Tương Ưng Bộ 18.21", url: "https://loicuaducphat.org/sn/sn18.21.html#content" },

{ text: `- Bạch Thế Tôn, do biết như thế nào, thấy như thế nào, trong thân thể có thức này và trong tất cả tướng ở ngoài, tâm đã viễn ly được ngã kiến, ngã sở kiến, ngã mạn, siêu việt mọi ngã mạn, tịch tịnh, giải thoát?\n\n- Này Rāhula, phàm sắc gì quá khứ, vị lai, hiện tại, phàm thọ gì … phàm tưởng gì … phàm hành gì … phàm thức gì quá khứ, vị lai, hiện tại, hoặc nội hay ngoại, hoặc thô hay tế, hoặc liệt hay thắng, hoặc xa hay gần; vị ấy thấy như thật tất cả các thức với chánh trí tuệ là: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”. Do thấy như thật với chánh trí tuệ như vậy, vị ấy được giải thoát, không có chấp thủ.\n\nNày Rāhula, do biết như vậy, thấy như vậy, trong thân thể có thức này và trong tất cả tướng ở ngoài, tâm đã viễn ly ngã kiến, ngã sở kiến, ngã mạn, vượt khỏi các ngã mạn, được tịch tịnh, giải thoát.`, ref: "Tương Ưng Bộ 18.22", url: "https://loicuaducphat.org/sn/sn18.22.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, một ngôi nhà có nóc nhọn cao, phàm có những cây kèo xa nào, tất cả chúng đều đi đến góc nhọn, đều quy tựa vào góc nhọn, đều châu đầu vào góc nhọn, tất cả chúng đều đâm đầu vào một gốc. Cũng vậy, này các Tỷ-kheo, phàm có những bất thiện pháp nào, tất cả chúng đều lấy vô minh làm cội rễ, đều lấy vô minh làm điểm tựa, đều châu đầu vào vô minh, tất cả chúng đều đâm đầu vào một gốc. Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Chúng ta hãy sống không phóng dật”.`, ref: "Tương Ưng Bộ 20.1", url: "https://loicuaducphat.org/sn/sn20.1.html#content" },

{ text: `- Này các Tỷ-kheo, các Ông nghĩ thế nào? Cái gì nhiều hơn, chút đất này Ta lấy trên đầu móng tay, hay quả đất lớn này? - Cái này, bạch Thế Tôn, là nhiều hơn, tức là quả đất lớn này và ít hơn là chút đất mà Thế Tôn lấy trên đầu móng tay. Không thể đi đến ước tính, không thể đi đến so sánh, không thể đi đến một vi phần, khi so sánh quả đất lớn với chút đất mà Thế Tôn lấy trên đầu móng tay.\n\n- Cũng vậy, này các Tỷ-kheo, rất ít là chúng sanh được tái sanh làm người! Còn rất nhiều là những chúng sanh phải tái sanh ra ngoài loài Người! Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Chúng tôi sẽ sống không phóng dật”.`, ref: "Tương Ưng Bộ 20.2", url: "https://loicuaducphat.org/sn/sn20.2.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, những gia đình nào có nhiều phụ nữ và ít đàn ông, thời những gia đình ấy rất dễ bị các đạo tặc, trộm ghè não hại. - Cũng vậy, này các Tỷ-kheo, Tỷ-kheo nào không tu tập từ tâm giải thoát, không làm cho sung mãn, thời vị ấy dễ bị phi nhân não hại. - Ví như, này các Tỷ-kheo, những gia đình nào có ít phụ nữ và nhiều đàn ông, thời gia đình ấy khó bị các đạo tặc, trộm ghè não hại. Cũng vậy, này các Tỷ-kheo, Tỷ-kheo nào tu tập từ tâm giải thoát, làm cho sung mãn, thời vị ấy rất khó bị phi nhân não hại. Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Chúng tôi sẽ tu tập từ tâm giải thoát, làm cho sung mãn, làm thành cỗ xe, làm thành căn cứ địa, an trú, tích lũy và khéo thực hiện”. Như vậy, này các Tỷ-kheo các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 20.3", url: "https://loicuaducphat.org/sn/sn20.3.html#content" },

{ text: `- Này các Tỷ-kheo, ai vào buổi sáng bố thí một trăm cái nồi, ai buổi trưa bố thí một trăm cái nồi, hay ai buổi chiều bố thí một trăm cái nồi, và ai buổi sáng chỉ trong thời gian bóp vú sữa con bò một lần (trong nháy mắt), tu tập từ tâm giải thoát, hay ai buổi trưa chỉ trong thời gian bóp vú sữa con bò một lần (trong nháy mắt), tu tập từ tâm giải thoát, hay ai buổi chiều chỉ trong thời gian bóp vú sữa con bò một lần (trong nháy mắt), tu tập từ tâm giải thoát, sự việc này đối với sự việc trước, quả có lớn hơn. Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Chúng tôi sẽ tu tập từ tâm giải thoát, làm cho sung mãn, làm thành cỗ xe, làm thành căn cứ địa, an trú, tích lũy và khéo thực hiện”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 20.4", url: "https://loicuaducphat.org/sn/sn20.4.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, những Tỷ-kheo sẽ thành trong tương lai. Những bài kinh nào do Như Lai thuyết, thâm sâu, nghĩa lý thâm diệu, xuất thế gian, liên hệ đến không, họ sẽ không nghe khi các kinh ấy được thuyết giảng; họ sẽ không lóng tai; họ sẽ không an trú chánh tri tâm, và họ sẽ không nghĩ rằng các pháp ấy cần phải học thuộc lòng, cần phải thấu đáo. Còn những bài kinh nào do các thi sĩ làm, những bài thơ với những danh từ hoa mỹ, với những câu văn hoa mỹ, thuộc ngoại điển, do các đệ tử thuyết giảng, họ sẽ nghe khi các kinh ấy được thuyết giảng; họ sẽ lóng tai; họ sẽ an trú chánh tri tâm và họ sẽ nghĩ rằng, các pháp ấy cần phải học thuộc lòng, cần phải học thấu đáo. Như vậy, này các Tỷ-kheo, các kinh do Như Lai thuyết, thâm sâu, nghĩa lý thâm diệu, xuất thế gian, liên hệ đến không sẽ đi đến tiêu diệt. Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Những bài kinh nào do Như Lai thuyết giảng, thâm sâu, nghĩa lý thâm diệu, xuất thế gian, liên hệ đến không, chúng tôi sẽ nghe khi các kinh ấy được thuyết giảng; chúng tôi sẽ lóng tai; chúng tôi sẽ an trú chánh tri tâm. Và chúng tôi sẽ nghĩ rằng, các pháp ấy cần phải học thuộc lòng, cần phải học thấu đáo”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 20.7", url: "https://loicuaducphat.org/sn/sn20.7.html#content" },

{ text: `Sống trên các gối rơm, này các Tỷ-kheo, là nếp sống hiện nay của các Tỷ-kheo, không phóng dật, nhiệt tâm trong các nỗ lực. Ác ma không có cơ hội, không có đối tượng để xâm lăng. Trong tương lai, này các Tỷ-kheo, các Tỷ-kheo sẽ trở thành nhu nhược, tay chân mềm mỏng. Họ nằm trên những đồ nằm mềm mại. Họ ngủ cho đến mặt trời mọc trên những gối bông. Ác ma sẽ nắm được cơ hội, sẽ nắm được đối tượng (để xâm lăng). Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Chúng tôi sẽ sống trên những gối rơm, không phóng dật, nhiệt tâm trong nỗ lực”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 20.8", url: "https://loicuaducphat.org/sn/sn20.8.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, ở đây các Trưởng lão Tỷ-kheo vào buổi sáng đắp y, cầm y bát, đi vào làng hay thị trấn để khất thực. Tại đấy họ thuyết pháp. Các gia chủ hoan hỷ làm bổn phận của mình với các vị ấy. Các Tỷ-kheo ấy thọ dụng các lợi đắc, không tham trước, không say đắm, không phạm tội, thấy những nguy hiểm, hiểu sự xuất ly với trí tuệ. Nhờ vậy, các Tỷ-kheo ấy được dung sắc và sức mạnh, và không vì nhân duyên ấy họ đi đến chết hay đi đến đau khổ gần như chết. Nhưng này các Tỷ-kheo, được huấn luyện theo các Trưởng lão Tỷ-kheo, các tân Tỷ-kheo vào buổi sáng đắp y, cầm y bát đi vào làng hay thị trấn để khất thực. Tại đấy, các vị thuyết pháp. Các gia chủ hoan hỷ làm bổn phận của mình. Các Tỷ-kheo ấy thọ dụng các lợi đắc, tham trước, say đắm, phạm tội, không thấy sự nguy hiểm, không hiểu sự xuất ly với trí tuệ. Do vậy, các vị Tỷ-kheo ấy không được dung sắc và sức mạnh, và vì nhân duyên ấy họ đi đến chết hay đi đến đau khổ gần như chết. Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Chúng tôi sẽ thọ dụng các lợi đắc, không tham đắm, không say mê, không phạm tội, thấy những nguy hiểm, hiểu rõ sự xuất ly với trí tuệ”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 20.9", url: "https://loicuaducphat.org/sn/sn20.9.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, ở đây, một số Tỷ-kheo vào buổi sáng đắp y, cầm y bát, đi vào làng hay thị trấn để khất thực, thân không phòng hộ, lời nói không phòng hộ, tâm không phòng hộ, niệm không an trú, các căn không chế ngự. Ở đấy, các vị ấy thấy các phụ nữ mặc không đứng đắn, hay mặc không kín đáo. Sau khi các vị ấy thấy các phụ nữ mặc không đứng đắn, hay mặc không kín đáo, tham dục não hại tâm. Các vị ấy bị tham dục não hại tâm, đi đến chết hay đi đến đau khổ gần như chết. Ðây là sự chết, này các Tỷ-kheo, trong giới luật của bậc Thánh, tức là sự từ bỏ học giới và hoàn tục. Ðây là đau khổ gần như chết, này các Tỷ-kheo, tức là sự vi phạm một uế tội, một tội phạm còn có thể tuyên bố xuất gỡ được. Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Phòng hộ thân, phòng hộ lời nói, phòng hộ tâm, an trú chánh niệm, chế ngự các căn, chúng tôi sẽ đi vào làng hay thị trấn để khất thực”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 20.10", url: "https://loicuaducphat.org/sn/sn20.10.html#content" },

{ text: `- Các Ông có nghe chăng, này các Tỷ-kheo, trong ban đêm lúc gần sáng, có con giả-can già tru lớn tiếng? - Thưa không, bạch Thế Tôn. - Rất có thể, này các Tỷ-kheo, trong con giả-can già ấy, có nhiều biết ơn, có nhiều cảm tạ, hơn là ở đây trong một người tự xưng là Thích tử về biết ơn và về cảm tạ! Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Chúng tôi sẽ biết ơn, cảm tạ. Dầu cho có chút ít gì làm giữa chúng tôi, chúng tôi cũng không để cho mất đi”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 20.12", url: "https://loicuaducphat.org/sn/sn20.12.html#content" },

{ text: `- Này Thera, thế nào là độc trú được làm viên mãn với các chi tiết? Ở đây, này Thera, cái gì đã qua được đoạn tận; cái gì sắp đến được từ bỏ; đối với những tự ngã, lợi đắc hiện tại, dục tham được khéo nhiếp phục. Như vậy, này Thera, là độc trú được làm viên mãn với các chi tiết. Thế Tôn thuyết giảng như vậy, Thiện Thệ nói như vậy xong, bậc Ðạo Sư lại nói thêm:\n\nAi chiến thắng tất cả,\nAi hiểu biết tất cả,\nAi là bậc Thiện trí,\nMọi pháp không ô nhiễm.\nAi từ bỏ tất cả,\nÁi tận được giải thoát,\nTa nói chính người ấy,\nThật là vị độc trú.`, ref: "Tương Ưng Bộ 21.10", url: "https://loicuaducphat.org/sn/sn21.10.html#content" },

{ text: `- Thật sự là vậy, này Gia chủ. Thật sự là vậy, này Gia chủ. Thân của Gia chủ, này Gia chủ, là bệnh hoạn, ốm đau, bị nhiễm ô che đậy. Ai mang cái thân này, này Gia chủ, lại tự cho là không bệnh, dầu chỉ trong một giây phút; người ấy phải là người ngu! Do vậy, này Gia chủ, Gia chủ cần phải học tập như sau: “Dầu cho thân tôi có bệnh, tâm sẽ không bị bệnh”. Như vậy, này Gia chủ, Gia chủ cần phải học tập.`, ref: "Tương Ưng Bộ 22.1", url: "https://loicuaducphat.org/sn/sn22.1.html#content" },

{ text: `- Sắc giới, này Gia chủ, là nhà của thức. Thức bị lòng tham sắc giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Thọ giới, này Gia chủ, là nhà của thức. Thức bị lòng tham thọ giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Tưởng giới, này Gia chủ, là nhà của thức. Thức bị lòng tham tưởng giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Hành giới, này Gia chủ, là nhà của thức. Thức bị lòng tham hành giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Thức giới, này Gia chủ, là nhà của thức. Thức bị lòng tham thức giới trói buộc, này Gia chủ, được gọi là du hành có gia đình. Như vậy, này Gia chủ, là du hành có gia đình.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `Và này Gia chủ, thế nào là du hành không gia đình? Ðối với sắc giới, này Gia chủ, cái gọi là dục, là tham, là hỷ, là khát ái, những gì thuộc chấp thủ, tâm trú trước, thiên chấp tùy miên; Như Lai đoạn tận chúng, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không tái sanh, không thể sanh khởi trong tương lai. Do vậy, Như Lai được gọi là du hành không gia đình. Ðối với thọ giới, này Gia chủ … Ðối với tưởng giới, này Gia chủ … Ðối với hành giới, này Gia chủ … Ðối với thức giới, này Gia chủ, cái gọi là dục, là tham, là hỷ, là khát ái, những gì thuộc chấp thủ, tâm trú trước, thiên chấp tùy miên; Như Lai đoạn tận chúng, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không tái sanh, không thể sanh khởi trong tương lai. Do vậy, Như Lai được gọi là du hành không gia đình.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `Như thế nào là du hành không trú xứ? Sự trói buộc bởi an trú chấp trước vào sắc tướng, này Gia chủ, đối với Như Lai đã được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không tái sanh, không thể sanh khởi trong tương lai. Do vậy, Như Lai được gọi là du hành không trú xứ. Sự trói buộc bởi an trú chấp trước vào thanh tướng … vào hương tướng … vào vị tướng … vào xúc tướng … vào pháp tướng, này Gia chủ, đối với Như Lai đã được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không tái sanh, không thể sanh khởi trong tương lai. Do vậy, Như Lai được gọi là du hành không trú xứ. Như vậy, này Gia chủ, là du hành không trú xứ.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `Như thế nào, này Gia chủ, là tác thành hệ lụy trong làng? Ở đây, này Gia chủ, có người sống thân mật với gia chủ, cùng vui, cùng buồn. Giữa những người sung sướng, vị ấy sung sướng. Giữa những người buồn khổ, vị ấy buồn khổ. Khi có công việc phải làm khởi lên, tự liên hệ mình vào các công việc ấy. Như vậy, này Gia chủ, là tác thành hệ lụy trong làng.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `Và như thế nào, này Gia chủ, là không tác thành hệ lụy trong làng? Ở đây, này Gia chủ, vị Tỷ-kheo không sống quá thân mật với gia chủ, không cùng vui, không cùng buồn, không vui sướng giữa những người sung sướng, không buồn khổ giữa những người buồn khổ. Khi có công việc phải làm khởi lên, không tự mình liên hệ vào các công việc ấy. Như vậy, này Gia chủ, là không tác thành hệ lụy trong làng.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `Như thế nào, này Gia chủ, là hy vọng hão huyền? Ở đây, này Gia chủ, có người suy nghĩ như sau: “Mong rằng có sắc như vậy trong tương lai! Mong rằng có thọ như vậy trong tương lai! Mong rằng có tưởng như vậy trong tương lai! Mong rằng có các hành như vậy trong tương lai! Mong rằng có thức như vậy trong tương lai!” Như vậy, này Gia chủ, là hư vọng hão huyền.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `“Bậc Thánh bỏ gia đình,\nDu hành không trú xứ,\nÐối với dân trong làng,\nKhông tác thành hệ lụy.\nTuyệt không các dục vọng.\nKhông ước vọng hão huyền,\nChấm dứt mọi tranh luận,\nBất cứ với một ai”.`, ref: "Tương Ưng Bộ 22.3", url: "https://loicuaducphat.org/sn/sn22.3.html#content" },

{ text: `- Này các Tỷ-kheo, hãy tu tập Thiền định. Vị Tỷ-kheo có Thiền định, này các Tỷ-kheo, hiểu biết một cách như thật. Hiểu biết gì một cách như thật? Sắc tập khởi và đoạn diệt; thọ tập khởi và đoạn diệt; tưởng tập khởi và đoạn diệt; các hành tập khởi và đoạn diệt; thức tập khởi và đoạn diệt.`, ref: "Tương Ưng Bộ 22.5", url: "https://loicuaducphat.org/sn/sn22.5.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là sắc tập khởi? Thế nào là thọ tập khởi? Thế nào là tưởng tập khởi? Thế nào là các hành tập khởi? Thế nào là thức tập khởi? Ở đây, này các Tỷ-kheo, Tỷ-kheo hoan hỷ, hoan nghênh, đắm trước rồi an trú. Hoan hỷ, hoan nghênh, đắm trước và an trú gì? Hoan hỷ, hoan nghênh, đắm trước rồi an trú sắc. Do vị ấy hoan hỷ, hoan nghênh, đắm trước rồi an trú sắc, hỷ đối với sắc khởi lên. Do hỷ đối với sắc, thủ đối với sắc khởi lên. Do duyên thủ đối với sắc, hữu khởi lên. Do duyên hữu, sanh khởi lên. Do duyên sanh, già chết, sầu, bi, khổ, ưu, não khởi lên. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.\n\nHoan hỷ, hoan nghênh, đắm trước rồi an trú thọ … rồi an trú tưởng … rồi an trú các hành … rồi an trú thức. Do vị ấy hoan hỷ, hoan nghênh, đắm trước rồi an trú thức, hỷ khởi lên. Do hỷ đối với thức, thủ đối với thức khởi lên. Do duyên thủ đối với thức, hữu khởi lên. Do duyên hữu, sanh khởi lên. Do duyên sanh, già chết, sầu, bi, khổ, ưu, não khởi lên. Như vậy là sự tập khởi của toàn bộ khổ uẩn này. Này các Tỷ-kheo, đây là sắc tập khởi, đây là thọ tập khởi, đây là tưởng tập khởi, đây là hành tập khởi, đây là thức tập khởi.`, ref: "Tương Ưng Bộ 22.5", url: "https://loicuaducphat.org/sn/sn22.5.html#content" },
{ text: `- Này các Tỷ-kheo, thế nào là chấp thủ và ưu não? Ở đây, này các Tỷ-kheo, kẻ vô văn phàm phu không thấy rõ các bậc Thánh, không thuần thục pháp các bậc Thánh, không tu tập pháp các bậc Thánh, không thấy rõ các bậc Chân nhân, không thuần thục pháp các bậc Chân nhân, không tu tập pháp các bậc Chân nhân, người ấy quán sắc như là tự ngã, hay tự ngã như là có sắc, hay sắc ở trong tự ngã, hay tự ngã ở trong sắc. Ðối với vị ấy, sắc ấy biến hoại và đổi khác. Ðối với vị ấy, khi sắc ấy biến hoại và đổi khác, thức tùy chuyển theo sự biến hoại của sắc. Các pháp ưu não sanh khởi do thức tùy chuyển theo sự biến hoại của sắc sau khi xâm nhập tâm và an trú. Do tâm bị xâm chiếm nên khủng bố, chướng ngại, khát vọng được sanh khởi và ưu não.`, ref: "Tương Ưng Bộ 22.7", url: "https://loicuaducphat.org/sn/sn22.7.html#content" },

{ text: `Này các Tỷ-kheo, như thế nào là không chấp thủ và không ưu não? Ở đây, này các Tỷ-kheo, vị Ða văn Thánh đệ tử quán sắc: “Ðây không phải của tôi, đây không phải là tôi, đây không phải là tự ngã của tôi”. Sắc ấy của vị này biến hoại, đổi khác. Vị này, khi sắc biến hoại, đổi khác, không khởi lên sầu, bi, khổ, ưu, não. … quán thọ: “Ðây không phải của tôi.”. … quán tưởng: “Ðây không phải của tôi.”. … quán các hành: “Ðây không phải của tôi.”. … quán thức: “Ðây không phải của tôi, đây không phải là tôi, đây không phải tự ngã của tôi”. Thức ấy của vị này biến hoại, đổi khác. Vị này, khi thức ấy biến hoại, đổi khác, không khởi lên sầu, bi, khổ, ưu, não. Như vậy, này các Tỷ-kheo, là không chấp thủ, không ưu não.`, ref: "Tương Ưng Bộ 22.8", url: "https://loicuaducphat.org/sn/sn22.8.html#content" },

{ text: `- Này các Tỷ-kheo, sắc là vô thường, trong quá khứ, trong vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử đối với sắc quá khứ không tiếc nuối, đối với sắc vị lai không hoan hỷ, đối với sắc hiện tại hướng đến yếm ly, ly tham, đoạn diệt. Này các Tỷ-kheo, thọ là vô thường … Này các Tỷ-kheo, tưởng là vô thường … Này các Tỷ-kheo, các hành là vô thường, trong quá khứ, trong vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử đối với các hành quá khứ không tiếc nuối, đối với các hành vị lai không hoan hỷ, đối với các hành hiện tại hướng đến yếm ly, ly tham, đoạn diệt. Này các Tỷ-kheo, thức là vô thường trong quá khứ, trong vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử đối với thức quá khứ không tiếc nuối, đối với thức vị lai không hoan hỷ, đối với thức hiện tại hướng đến yếm ly, ly tham, đoạn diệt.`, ref: "Tương Ưng Bộ 22.9", url: "https://loicuaducphat.org/sn/sn22.9.html#content" },

{ text: `- Sắc, này các Tỷ-kheo, là khổ, quá khứ, vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử, đối với sắc quá khứ không tiếc nuối, đối với sắc vị lai không hoan hỷ, đối với sắc hiện tại hướng đến yếm ly, ly tham đoạn diệt. Thọ, này các Tỷ-kheo, là khổ … Tưởng, này các Tỷ-kheo, là khổ … Các hành, này các Tỷ-kheo, là khổ … Thức, này các Tỷ-kheo, là khổ, quá khứ, vị lai, còn nói gì đến hiện tại. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử đối với thức quá khứ không tiếc nuối, đối với thức vị lai không hoan hỷ, đối với thức hiện tại hướng đến yếm ly, ly tham, đoạn diệt.`, ref: "Tương Ưng Bộ 22.10", url: "https://loicuaducphat.org/sn/sn22.10.html#content" },

{ text: `- Sắc, này các Tỷ-kheo, là vô thường; cái gì vô thường là khổ; cái gì khổ là vô ngã; cái gì vô ngã, cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Thọ, này các Tỷ-kheo, là vô thường; cái gì vô thường là khổ; cái gì khổ là vô ngã; cái gì vô ngã cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Tưởng, này các Tỷ-kheo, là vô thường … Các hành, này các Tỷ-kheo, là vô thường … Thức, này các Tỷ-kheo, là vô thường; cái gì vô thường là khổ; cái gì khổ là vô ngã; cái gì vô ngã cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử yếm ly đối với sắc … ” … không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.15", url: "https://loicuaducphat.org/sn/sn22.15.html#content" },

{ text: `- Sắc, này các Tỷ-kheo, là khổ. Cái gì khổ là vô ngã; cái gì vô ngã cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Thọ, này các Tỷ-kheo, là khổ … Tưởng, này các Tỷ-kheo, là khổ … Các hành, này các Tỷ-kheo, là khổ … Thức, này các Tỷ-kheo, là khổ. Cái gì khổ là vô ngã; cái gì vô ngã cần phải như thật quán với chánh trí tuệ: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Thấy vậy, này các Tỷ-kheo, vị Ða văn Thánh đệ tử yếm ly đối với sắc … ” … không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.16", url: "https://loicuaducphat.org/sn/sn22.16.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là gánh nặng? Năm thủ uẩn là câu trả lời. Thế nào là năm? Sắc thủ uẩn, thọ thủ uẩn, tưởng thủ uẩn, hành thủ uẩn, thức thủ uẩn. Này các Tỷ-kheo, đây gọi là gánh nặng. Và này các Tỷ-kheo, thế nào là kẻ mang gánh nặng? Người là câu trả lời. Vị Tôn giả này có tên như thế này, dòng họ như thế này. Này các Tỷ-kheo, đây gọi là kẻ mang gánh nặng! Và này các Tỷ-kheo, thế nào là mang gánh nặng lên? Chính là tham ái này đưa đến tái sanh, câu hữu với hỷ và tham, đi tìm hỷ lạc chỗ này, chỗ kia. Tức là dục ái, hữu ái, phi hữu ái. Này các Tỷ-kheo, đây gọi là mang gánh nặng lên. Này các Tỷ-kheo, thế nào là đặt gánh nặng xuống? Ðây là sự ly tham, đoạn diệt ái ấy một cách hoàn toàn, sự từ bỏ, sự xả ly, sự giải thoát, sự không chấp thủ. Này các Tỷ-kheo, đây gọi là đặt gánh nặng xuống.`, ref: "Tương Ưng Bộ 22.22", url: "https://loicuaducphat.org/sn/sn22.22.html#content" },

{ text: `Năm uẩn là gánh nặng,\nKẻ gánh nặng là người;\nMang lấy gánh nặng lên,\nChính là khổ ở đời.\nCòn đặt gánh nặng xuống,\nTức là lạc, không khổ,\nÐặt gánh nặng xuống xong,\nKhông mang thêm gánh khác.\nNếu nhổ khát ái lên,\nTận cùng đến gốc rễ,\nKhông còn đói và khát,\nÐược giải thoát tịnh lạc!`, ref: "Tương Ưng Bộ 22.22", url: "https://loicuaducphat.org/sn/sn22.22.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là các pháp cần phải liễu tri? Sắc, này các Tỷ-kheo, là pháp cần phải liễu tri, thọ là pháp cần phải liễu tri, tưởng là pháp cần phải liễu tri, các hành là pháp cần phải liễu tri, thức là pháp cần phải liễu tri. Những pháp này, này các Tỷ-kheo, là những pháp cần phải liễu tri. Và này các Tỷ-kheo, thế nào là liễu tri? Này các Tỷ-kheo, sự đoạn tận tham, sự đoạn tận sân, sự đoạn tận si, này các Tỷ-kheo, được gọi là liễu tri.`, ref: "Tương Ưng Bộ 22.23", url: "https://loicuaducphat.org/sn/sn22.23.html#content" },

{ text: `- Này các Tỷ-kheo, trước khi Ta giác ngộ, chưa chứng Chánh Ðẳng Giác, còn là Bồ-tát, Ta suy nghĩ như sau: “Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của sắc? Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của thọ? Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của tưởng? Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của các hành? Cái gì là vị ngọt, cái gì là sự nguy hiểm, cái gì là sự xuất ly của thức?” Rồi này các Tỷ-kheo, Ta suy nghĩ như sau: “Do duyên sắc, lạc hỷ sanh; cái ấy gọi là vị ngọt của sắc. Sự vô thường, đau khổ, chịu sự biến hoại của sắc; cái ấy gọi là sự nguy hiểm của sắc. Sự nhiếp phục dục và tham đối với sắc, sự đoạn tận dục và tham; cái ấy là xuất ly của sắc”.`, ref: "Tương Ưng Bộ 22.26", url: "https://loicuaducphat.org/sn/sn22.26.html#content" },

{ text: `- Này các Tỷ-kheo, nếu không có vị ngọt của sắc, thời các loài hữu tình không có tham đắm đối với sắc. Và vì rằng, này các Tỷ-kheo, có vị ngọt của sắc cho nên các loài hữu tình có tham đắm đối với sắc. - Này Tỷ-kheo, nếu không có sự nguy hiểm của sắc, thời các loài hữu tình không có yếm ly đối với sắc. Và vì rằng, này các Tỷ-kheo, có sự nguy hiểm của sắc cho nên các loài hữu tình có yếm ly đối với sắc. Và này các Tỷ-kheo, khi nào các loài hữu tình đối với năm thủ uẩn này, như thật thắng tri vị ngọt là vị ngọt, nguy hiểm là nguy hiểm, xuất ly là xuất ly, thời các loài hữu tình ấy, này các Tỷ-kheo, với thế giới chư Thiên, Ma, Phạm thiên, với quần chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người, có thể sống xuất ly, thoát sự liên hệ, giải thoát, với tâm tự tại.`, ref: "Tương Ưng Bộ 22.28", url: "https://loicuaducphat.org/sn/sn22.28.html#content" },

{ text: `- Này các Tỷ-kheo, cái gọi là sắc sanh, trú, khởi, hiện hữu; cái ấy là khổ sanh, bệnh tật trú, già chết hiện hữu. Này các Tỷ-kheo, cái gọi là thọ sanh, trú, khởi, hiện hữu … tưởng sanh, trú, khởi, hiện hữu … các hành sanh, trú, khởi, hiện, hữu … Này các Tỷ-kheo, cái gọi là thức sanh, trú, khởi, hiện hữu; cái ấy gọi là khổ sanh, bệnh tật trú, già chết hiện hữu. Này các Tỷ-kheo, cái gọi là sắc đoạn diệt, an chỉ, biến mất; cái ấy gọi là khổ đoạn diệt, bệnh tật an chỉ, già chết biến mất. Này các Tỷ-kheo, cái gọi là thọ đoạn diệt … tưởng đoạn diệt … các hành đoạn diệt … Này các Tỷ-kheo, cái gọi là thức đoạn diệt, an chỉ, biến mất; cái ấy là khổ đoạn diệt, bệnh tật an chỉ, già chết biến mất.`, ref: "Tương Ưng Bộ 22.30", url: "https://loicuaducphat.org/sn/sn22.30.html#content" },

{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết về đau khổ và cội gốc của đau khổ. Hãy lắng nghe … Này các Tỷ-kheo, thế nào là đau khổ? Sắc, này các Tỷ-kheo, là đau khổ; thọ là đau khổ; tưởng là đau khổ; các hành là đau khổ; thức là đau khổ. Ðây, này các Tỷ-kheo, gọi là đau khổ. Này các Tỷ-kheo, thế nào là cội gốc của đau khổ? Chính là khát ái này hướng tới tái sanh, câu hữu với hỷ và tham, tìm cầu hỷ lạc chỗ này, chỗ kia; tức là dục ái, hữu ái, phi hữu ái.`, ref: "Tương Ưng Bộ 22.31", url: "https://loicuaducphat.org/sn/sn22.31.html#content" },

{ text: `- Này các Tỷ-kheo, cái gì không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông. Này các Tỷ-kheo, cái gì không phải của các Ông? Sắc, này các Tỷ-kheo, không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông. Thọ, này các Tỷ-kheo, không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông. Tưởng, này các Tỷ-kheo … Các hành, này các Tỷ-kheo … Thức, này các Tỷ-kheo, không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông.`, ref: "Tương Ưng Bộ 22.33", url: "https://loicuaducphat.org/sn/sn22.33.html#content" },

{ text: `Ví như, này các Tỷ-kheo, có người mang lại cỏ, củi, cành cây, lá của Jetavana này, và đốt chúng hay tùy theo duyên sử dụng chúng. Các Ông có nghĩ rằng: “Người ấy mang chúng tôi, hay đốt, hay tùy theo duyên sử dụng chúng tôi”? - Thưa không, bạch Thế Tôn. Vì sao như vậy? Vì cái ấy không phải chúng con. Bạch Thế Tôn, cái ấy không phải thuộc tự ngã của chúng con. - Cũng vậy, này các Tỷ-kheo, sắc không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông. Thọ không phải của các Ông … Tưởng không phải của các Ông. Các hành không phải của các Ông … Thức không phải của các Ông, hãy từ bỏ nó. Từ bỏ nó sẽ đưa lại hạnh phúc, an lạc cho các Ông.`, ref: "Tương Ưng Bộ 22.33", url: "https://loicuaducphat.org/sn/sn22.33.html#content" },

{ text: `- Ðối với vị Tỷ-kheo thực hành pháp và tùy pháp, tùy pháp này có mặt: Ðối với sắc, vị ấy sống nhiều yếm ly; đối với thọ, vị ấy sống nhiều yếm ly; đối với tưởng, vị ấy sống nhiều yếm ly; đối với các hành, vị ấy sống nhiều yếm ly; đối với thức, vị ấy sống nhiều yếm ly. Ai sống nhiều yếm ly đối với sắc … đối với thọ … đối với tưởng … đối với các hành … ai sống nhiều yếm ly đối với thức, vị ấy liễu tri sắc … liễu tri thọ … liễu tri tưởng … liễu tri các hành … liễu tri thức. Do liễu tri sắc … thọ … tưởng … các hành … do liễu tri thức, vị ấy được giải thoát khỏi sắc, giải thoát khỏi thọ, giải thoát khỏi tưởng, giải thoát khỏi các hành, giải thoát khỏi thức, giải thoát khỏi sanh, già chết, sầu, bi, khổ, ưu, não. Ta nói vị ấy giải thoát khỏi đau khổ.`, ref: "Tương Ưng Bộ 22.39", url: "https://loicuaducphat.org/sn/sn22.39.html#content" },

{ text: `- Hãy sống tự mình làm hòn đảo cho chính mình, này các Tỷ-kheo, hãy nương tựa nơi chính mình, không nương tựa một ai khác. Hãy lấy pháp làm hòn đảo, hãy lấy pháp làm chỗ nương tựa, không nương tựa một ai khác. Với những ai sống tự mình làm hòn đảo cho chính mình, này các Tỷ-kheo, nương tựa nơi chính mình, không nương tựa một ai khác. Lấy pháp làm hòn đảo, lấy pháp làm chỗ nương tựa, không nương tựa một ai khác, hãy như lý quán sát: “Sầu, bi, khổ, ưu, não do nguồn gốc gì sanh? Do cái gì làm cho hiện hữu?”`, ref: "Tương Ưng Bộ 22.43", url: "https://loicuaducphat.org/sn/sn22.43.html#content" },

{ text: `Này các Tỷ-kheo, biết sắc là vô thường … Này các Tỷ-kheo, biết thọ là vô thường … Này các Tỷ-kheo, biết tưởng là vô thường … Này các Tỷ-kheo, biết các hành là vô thường … Này các Tỷ-kheo, biết thức là vô thường, biến hoại, ly tham, đoạn diệt; vị ấy thấy tất cả thức xưa và nay là vô thường, khổ, chịu sự biến hoại. Do thấy như thật với chánh trí tuệ như vậy, các sầu, bi, khổ, ưu, não được đoạn tận. Do chúng được đoạn tận, vị ấy không bị ưu, não. Do không bị ưu, não, vị ấy sống an lạc. Do sống an lạc, vị Tỷ-kheo được gọi là vị đã lắng dịu mọi tướng phần, nhất hướng Niết-bàn.`, ref: "Tương Ưng Bộ 22.43", url: "https://loicuaducphat.org/sn/sn22.43.html#content" },
{ text: `- Sắc, này các Tỷ-kheo, là vô thường. Cái gì vô thường là khổ. Cái gì khổ là vô ngã. Cái gì vô ngã, cần phải như thật quán với chánh trí tuệ là: “Cái này không phải của tôi; cái này không phải là tôi; cái này không phải tự ngã của tôi”. Do như thật quán với chánh trí tuệ như vậy, tâm ly tham, được giải thoát, không có chấp thủ các lậu hoặc.`, ref: "Tương Ưng Bộ 22.45", url: "https://loicuaducphat.org/sn/sn22.45.html#content" },

{ text: `Này các Tỷ-kheo, nếu vị Tỷ-kheo đối với sắc giới có tâm ly tham, giải thoát, không có chấp thủ các lậu hoặc, đối với thọ giới … đối với tưởng giới … đối với hành giới … đối với thức giới, có tâm ly tham, giải thoát, không có chấp thủ các lậu hoặc. Do giải thoát, vị ấy an trú. Do an trú, vị ấy tri túc. Do tri túc, vị ấy không ưu não. Do không ưu não, vị ấy tự mình tịch tịnh. Vị ấy biết: ” Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.45", url: "https://loicuaducphat.org/sn/sn22.45.html#content" },
{ text: `- Sắc, này các Tỷ-kheo, đang bốc cháy; thọ đang bốc cháy; tưởng đang bốc cháy; hành đang bốc cháy; thức đang bốc cháy! Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với sắc … đối với thọ … đối với tưởng … đối với các hành … nhàm chán đối với thức. Do nhàm chán nên ly tham; do ly tham nên giải thoát. Trong sự giải thoát, trí khởi lên: “Ta đã được giải thoát”. Vị ấy biết: “Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.61", url: "https://loicuaducphat.org/sn/sn22.61.html#content" },

{ text: `Này Tỷ-kheo, ai suy tưởng sắc, người ấy bị Ma trói buộc. Ai không suy tưởng, người ấy được giải thoát khỏi Ác ma. Ai suy tưởng thọ … tưởng … các hành … Ai suy tưởng thức, người ấy bị Ma trói buộc. Ai không suy tưởng, người ấy được giải thoát khỏi Ác ma. Này Tỷ-kheo, lời nói vắn tắt này của Ta cần phải hiểu ý nghĩa một cách rộng rãi như vậy.`, ref: "Tương Ưng Bộ 22.64", url: "https://loicuaducphat.org/sn/sn22.64.html#content" },

{ text: `- Này Rādha, phàm có sắc gì quá khứ, vị lai, hiện tại, thuộc nội hay ngoại, thô hay tế, liệt hay thắng, xa hay gần; tất cả sắc cần được thấy như thật với chánh trí tuệ là: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”. Phàm có thọ … Phàm có tưởng … Phàm có các hành … Phàm có thức gì quá khứ, vị lai, hiện tại, thuộc nội hay ngoại, thô hay tế, liệt hay thắng, xa hay gần; tất cả thức cần được thấy như thật với chánh trí tuệ là: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”. Này Rādha, do biết vậy, do thấy vậy, đối với thân có thức này, và đối với tất cả tướng ở ngoài, không có tư tưởng: “Ngã kiến, ngã sở kiến, ngã mạn tùy miên”.`, ref: "Tương Ưng Bộ 22.71", url: "https://loicuaducphat.org/sn/sn22.71.html#content" },

{ text: `- Này các Tỷ-kheo, những Sa-môn hay Bà-la-môn nào có nhớ đến các đời sống ở các kiếp trước, tất cả họ đều nhớ đến năm thủ uẩn hay nhớ đến một trong những uẩn này. Thế nào là năm? Này các Tỷ-kheo, có người nhớ rằng: “Trong quá khứ, thân ta như thế này”. Nhớ như vậy, vị ấy nhớ đến sắc. Hay có người nhớ rằng: “Trong quá khứ, ta có cảm thọ như thế này”. Nhớ như vậy, vị ấy nhớ đến thọ. Hay có người nhớ rằng: “Trong quá khứ ta có tưởng … có các hành … có thức như thế này”. Nhớ như vậy, vị ấy nhớ đến thức.`, ref: "Tương Ưng Bộ 22.79", url: "https://loicuaducphat.org/sn/sn22.79.html#content" },

{ text: `Này các Tỷ-kheo, thế nào gọi là sắc? Bị thay đổi, này các Tỷ-kheo, nên gọi là sắc. Bị thay đổi bởi cái gì? Bị thay đổi bởi lạnh, bị thay đổi bởi nóng, bị thay đổi bởi đói, bị thay đổi bởi khát, bị thay đổi bởi sự xúc chạm của ruồi, muỗi, gió, sức nóng và rắn. Bị thay đổi, này các Tỷ-kheo, nên gọi là sắc. Này các Tỷ-kheo, thế nào gọi là thọ? Ðược cảm thọ, này các Tỷ-kheo, nên gọi là thọ. Cảm thọ gì? Cảm thọ lạc, cảm thọ khổ, cảm thọ phi khổ phi lạc. Ðược cảm thọ, này các Tỷ-kheo, nên gọi là thọ. Này các Tỷ-kheo, thế nào gọi là tưởng? Nhận rõ, này các Tỷ-kheo, nên gọi là tưởng. Nhận rõ gì? Nhận rõ màu xanh, nhận rõ màu vàng, nhận rõ màu đỏ, nhận rõ màu trắng. Nhận rõ, này các Tỷ-kheo, nên gọi là tưởng.`, ref: "Tương Ưng Bộ 22.79", url: "https://loicuaducphat.org/sn/sn22.79.html#content" },

{ text: `Này các Tỷ-kheo, thế nào gọi là hành? Làm cho hiện hành (pháp) hữu vi nên gọi là hành. Làm cho hiện hành (pháp) hữu vi gì? Làm cho hiện hành sắc với sắc tánh, làm cho hiện hành thọ với thọ tánh, làm cho hiện hành tưởng với tưởng tánh, làm cho hiện hành các hành với hành tánh, làm cho hiện hành thức với thức tánh. Làm cho hiện hành (pháp) hữu vi, này các Tỷ-kheo, nên gọi là các hành. Và này các Tỷ-kheo, thế nào gọi là thức? Rõ biết, này các Tỷ-kheo, nên gọi là thức. Rõ biết gì? Rõ biết chua, rõ biết đắng, rõ biết cay, rõ biết ngọt, rõ biết chất kiềm … rõ biết không phải chất kiềm, rõ biết mặn, rõ biết không mặn. Rõ biết, này các Tỷ-kheo, nên gọi là thức.`, ref: "Tương Ưng Bộ 22.79", url: "https://loicuaducphat.org/sn/sn22.79.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Ða văn Thánh đệ tử suy nghĩ như sau: “Nay ta bị sắc chinh phục. Trong thời quá khứ, ta cũng bị sắc chinh phục, như ta bị sắc hiện tại chinh phục. Nếu ta hoan hỷ đối với sắc vị lai, thời trong vị lai, ta sẽ bị sắc chinh phục, như nay ta bị sắc hiện tại chinh phục”. Do suy nghĩ như vậy, vị ấy không có luyến tiếc đối với sắc quá khứ, không có hoan hỷ đối với sắc vị lai, và thực hành sự yếm ly, ly tham, đoạn diệt đối với sắc hiện tại.`, ref: "Tương Ưng Bộ 22.79", url: "https://loicuaducphat.org/sn/sn22.79.html#content" },

{ text: `- Này các Tỷ-kheo, đây là nghề sinh sống hèn hạ nhất, tức là nghề khất thực. Ðây là một lời nguyền rủa trong đời, này các Tỷ-kheo, khi nói: “Ông, kẻ khất thực với bát trên bàn tay, Ông đi chỗ này, chỗ kia và đấy là nghề sinh sống”. Này các Tỷ-kheo, điều mà các thiện gia nam tử chấp nhận là những vị sống vì lý tưởng mục đích, duyên với lý tưởng mục đích; không phải vì ma cưỡng ép, không phải vì trộm cướp cưỡng ép, không phải vì thiếu nợ, không phải vì sợ hãi, không phải vì không có nguồn sinh sống, mà với ý nghĩ: “Ta bị chìm đắm trong sanh, già chết, sầu, bi, khổ, ưu, não; bị chìm đắm trong đau khổ, bị đoanh vây bởi đau khổ. Rất có thể, sự chấm dứt toàn bộ khổ uẩn này được tìm ra”.`, ref: "Tương Ưng Bộ 22.80", url: "https://loicuaducphat.org/sn/sn22.80.html#content" },

{ text: `Và như vậy, này các Tỷ-kheo, là thiện gia nam tử xuất gia. Vị ấy có tham dục đối với các dục vọng, tham ái cuồng nhiệt, tâm tư sân hận, tư niệm ô nhiễm, thất niệm, không tỉnh giác, không định tĩnh, tâm tán loạn, các căn không chế ngự. Ví như, này các Tỷ-kheo, một que củi từ chỗ hỏa táng, cả hai đầu đều cháy, ở giữa lại dính phân, không được dùng làm củi trong làng, không được dùng làm củi trong rừng. Dùng ví dụ ấy, Ta tả cho các Ông con người ấy, đã mất cả nhà và tài sản, lại không làm viên mãn mục đích của Sa-môn hạnh.`, ref: "Tương Ưng Bộ 22.80", url: "https://loicuaducphat.org/sn/sn22.80.html#content" },

{ text: `Này các Tỷ-kheo, có ba bất thiện tầm này: dục tầm, sân tầm, hại tầm. Và này các Tỷ-kheo, ba bất thiện tầm này được đoạn diệt không có dư tàn, đối với vị nào tâm đã khéo an trú vào bốn Niệm xứ hay tu tập vô tướng Thiền định. Này các Tỷ-kheo, hãy khéo tu tập vô tướng Thiền định. Này các Tỷ-kheo, vô tướng Thiền định được tu tập, làm cho tăng thịnh, đưa đến quả lớn, lợi ích lớn.`, ref: "Tương Ưng Bộ 22.80", url: "https://loicuaducphat.org/sn/sn22.80.html#content" },

{ text: `Này các Tỷ-kheo, có hai kiến này: hữu kiến, phi hữu kiến. Ở đây, này các Tỷ-kheo, vị Ða văn Thánh đệ tử suy nghĩ như sau: “Có cái gì ở trong đời, ta chấp trước mà không có phạm tội?” Và vị ấy biết: “Không có cái gì ở trong đời ta chấp trước mà không có phạm tội”. Nếu ta chấp thủ sự chấp thủ sắc … thọ … tưởng … các hành … Nếu ta chấp thủ sự chấp thủ thức, do duyên chấp thủ, hữu trở thành của ta. Do duyên hữu, có sanh. Do sanh, có già chết, sầu, bi, khổ, ưu, não. Như vậy là sự tập khởi của toàn bộ khổ uẩn này.`, ref: "Tương Ưng Bộ 22.80", url: "https://loicuaducphat.org/sn/sn22.80.html#content" },

{ text: `Này các Tỷ-kheo, biết như thế nào, thấy như thế nào, các lậu hoặc được đoạn tận lập tức? Ở đây, này các Tỷ-kheo, kẻ vô văn phàm phu không thấy rõ các bậc Thánh, không thuần thục pháp các bậc Thánh, không tu tập pháp các bậc Thánh, không thấy rõ các bậc Chân nhân, không thuần thục pháp các bậc Chân nhân, không tu tập pháp các bậc Chân nhân, quán sắc như là tự ngã, sự quán như vầy là hành. Hành ấy lấy gì làm nhân, lấy gì làm tập khởi, lấy gì sanh, lấy gì làm hiện hữu? Ðối với kẻ vô văn phàm phu, này các Tỷ-kheo, cảm xúc bởi thọ sanh ra do xúc chạm với vô minh, khát ái sanh. Từ khát ái ấy, hành ấy sanh. Như vậy, này các Tỷ-kheo, hành ấy là vô thường, hữu vi, do duyên sanh. Khát ái ấy là vô thường, hữu vi, do duyên sanh. Thọ ấy … xúc ấy là vô thường, hữu vi, do duyên sanh. Vô minh ấy là vô thường, hữu vi, do duyên sanh. Do biết vậy, do thấy vậy, các lậu hoặc được đoạn tận lập tức.`, ref: "Tương Ưng Bộ 22.81", url: "https://loicuaducphat.org/sn/sn22.81.html#content" },

{ text: `Ðối với kẻ vô văn phàm phu, này các Tỷ-kheo, do cảm xúc bởi thọ sanh ra do xúc chạm với vô minh, khát ái sanh. Do khát ái ấy, hành ấy sanh. Như vậy, này các Tỷ-kheo, hành ấy là vô thường, hữu vi, do duyên sanh. Khát ái ấy là vô thường, hữu vi, do duyên sanh. Thọ ấy là vô thường, hữu vi, do duyên sanh. Xúc ấy là vô thường, hữu vi, do duyên sanh. Vô minh ấy là vô thường, hữu vi, do duyên sanh. Này các Tỷ-kheo, do biết như vậy, thấy như vậy, các lậu hoặc được đoạn tận lập tức.`, ref: "Tương Ưng Bộ 22.81", url: "https://loicuaducphat.org/sn/sn22.81.html#content" },

{ text: `Con đường chia làm hai, này Tissa, là ví cho trạng thái nghi hoặc. Con đường tay trái, này Tissa, là ví cho con đường tà đạo tám ngành, tức là tà tri kiến … tà định. Con đường tay mặt, này Tissa, là ví cho con đường Thánh đạo Tám ngành, tức là chánh tri kiến … chánh định. Khu rừng rậm, này Tissa, là ví cho vô minh. Các đầm nước thấp, này Tissa, là ví cho các dục. Vực nước sâu, này Tissa, là ví cho phẫn nộ, ưu não. Khoảnh đất bằng phẳng khả ái, này Tissa, là ví cho Niết-bàn.`, ref: "Tương Ưng Bộ 22.84", url: "https://loicuaducphat.org/sn/sn22.84.html#content" },

{ text: `- Này các Tỷ-kheo, Ta không tranh luận với đời, chỉ có đời tranh luận với Ta. Này các Tỷ-kheo, người nói Pháp không tranh luận bất cứ với một ai ở đời. Này các Tỷ-kheo, cái gì người có trí ở đời chấp nhận là “không”, Ta cũng nói là “không”. Này các Tỷ-kheo, cái gì người có trí ở đời chấp nhận là “có”, Ta cũng nói là “có”. Và này các Tỷ-kheo, cái gì người có trí ở đời chấp nhận là “không”, Ta cũng nói là “không”? Này các Tỷ-kheo, người có trí ở đời không chấp nhận sắc … thọ … tưởng … các hành … thức là thường còn, thường hằng, thường trú, không chịu sự biến hoại, thời Ta cũng nói là “không”. Và này các Tỷ-kheo, cái gì người có trí ở đời chấp nhận là “có”, Ta cũng nói là “có”? Này các Tỷ-kheo, người có trí ở đời chấp nhận sắc … thọ … tưởng … các hành … thức là vô thường, không thường hằng, không thường trú, chịu sự biến hoại, thời Ta cũng nói là “có” (vậy). Ví như, này các Tỷ-kheo, bông sen xanh, hay bông sen hồng, hay bông sen trắng sanh ra trong nước, lớn lên trong nước, vươn lên khỏi nước, và đứng thẳng không bị nước nhiễm ướt. Cũng vậy, này các Tỷ-kheo, Như Lai sanh ra ở trong đời, lớn lên trong đời, vươn lên khỏi đời, và sống không bị đời ô nhiễm.`, ref: "Tương Ưng Bộ 22.94", url: "https://loicuaducphat.org/sn/sn22.94.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, sông Hằng này chảy mang theo đống bọt nước lớn. Có người có mắt nhìn đống bọt nước ấy, chuyên chú, như lý quán sát. Do nhìn chuyên chú, như lý quán sát nó, đống bọt nước ấy hiện rõ ra là trống không, hiện rõ ra là rỗng không, hiện rõ ra là không có lõi cứng. Làm sao, này các Tỷ-kheo, lại có lõi cứng trong đống bọt nước được? Cũng vậy, này các Tỷ-kheo, phàm có sắc gì thuộc quá khứ, vị lai, hiện tại, hoặc nội hay ngoại, hoặc thô hay tế, hoặc liệt hay thắng, hoặc xa hay gần; vị Tỷ-kheo thấy sắc, chuyên chú, như lý quán sát sắc. Do vị Tỷ-kheo nhìn chuyên chú, như lý quán sát sắc, sắc ấy hiện rõ ra là trống không, hiện rõ ra là rỗng không, hiện rõ ra là không có lõi cứng. Làm sao, này các Tỷ-kheo, lại có lõi cứng trong sắc được?`, ref: "Tương Ưng Bộ 22.95", url: "https://loicuaducphat.org/sn/sn22.95.html#content" },

{ text: `Sắc ví với đống bọt,\nThọ ví bong bóng nước,\nTưởng ví ráng mặt trời,\nHành ví với cây chuối,\nThức ví với ảo thuật,\nÐấng bà con mặt trời,\nÐã thuyết giảng như vậy.\n\nNếu như vậy chuyên chú,\nNhư lý chơn quán sát,\nNhư lý nhìn các pháp,\nHiện rõ tánh trống không.\n\nBắt đầu với thân này,\nBậc Ðại Tuệ thuyết giảng,\nÐoạn tận cả ba pháp,\nThấy sắc bị quăng bỏ.\n\nThân bị quăng, vô tri,\nKhông thọ, sức nóng, thức,\nBị quăng đi, nó nằm,\nLàm đồ ăn kẻ khác.\n\nCái thân liên tục này,\nẢo sư, kẻ ngu nói,\nÐược gọi kẻ sát nhân,\nKhông tìm thấy lõi cây.\n\nHãy quán uẩn như vậy,\nVị Tỷ-kheo tinh cần,\nSuốt cả đêm lẫn ngày,\nTỉnh giác, chánh tư niệm.\n\nHãy bỏ mọi kiết sử,\nLàm chỗ mình nương tựa,\nSống như lửa cháy đầu,\nCầu chứng cảnh bất động.`, ref: "Tương Ưng Bộ 22.95", url: "https://loicuaducphat.org/sn/sn22.95.html#content" },

{ text: `- Không có một sắc nào, này Tỷ-kheo, sắc ấy là thường còn, thường hằng, thường trú, không chịu sự biến hoại, vĩnh viễn thường hằng, vĩnh trú. Không có một thọ … một tưởng … các hành … một thức nào, thức ấy là thường còn, thường hằng, thường trú, không chịu sự biến hoại, vĩnh viễn thường hằng, vĩnh trú.`, ref: "Tương Ưng Bộ 22.98", url: "https://loicuaducphat.org/sn/sn22.98.html#content" },

{ text: `- Vô thuỷ, này các Tỷ-kheo, là sự luân hồi này. Ðiểm bắt đầu không thể nêu rõ đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển, luân hồi. Có thể có một thời, này các Tỷ kheo, biển lớn đi đến khô cạn, hoàn toàn đi đến khô kiệt, không có hiện hữu. Nhưng này các Tỷ kheo, Ta không có tuyên bố rằng, có sự chấm dứt khổ đau đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển, luân hồi. Có thể có một thời, này các Tỷ-kheo, Sineru (Tu-di), Vua các núi, đi đến băng hoại, hoại diệt, không có hiện hữu. Nhưng này các Tỷ-kheo, Ta không có tuyên bố rằng, có sự chấm dứt khổ đau đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển, luân hồi! Có thể có một thời, này các Tỷ-kheo, đại địa đi đến băng hoại, hoại diệt, không có hiện hữu. Nhưng này các Tỷ-kheo, Ta không có tuyên bố rằng, có sự chấm dứt khổ đau đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển luân hồi!`, ref: "Tương Ưng Bộ 22.99", url: "https://loicuaducphat.org/sn/sn22.99.html#content" },

{ text: `- Vô thuỷ, này các Tỷ-kheo, là sự luân hồi này. Ðiểm bắt đầu không thể nêu rõ đối với chúng sanh bị vô minh che đậy, bị khát ái trói buộc, phải lưu chuyển, luân hồi. Ví như, này các Tỷ-kheo, có con chó bị dây thằng trói chặt vào một cây cột trụ vững chắc. Nếu nó có đi, nó chỉ đi tới cây cột hay cột trụ ấy. Nếu nó đứng, nó chỉ đứng gần cây cột hay cột trụ ấy. Nếu nó ngồi, nó chỉ ngồi gần cây cột hay cột trụ ấy. Nếu nó nằm, nó chỉ nằm gần cây cột hay cột trụ ấy. Cũng vậy, này các Tỷ-kheo, kẻ vô văn phàm phu quán sắc: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”, quán thọ … quán tưởng … quán các hành … quán thức: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”. Nếu người ấy có đi, người ấy chỉ đi tới năm thủ uẩn này. Nếu người ấy đứng, người ấy chỉ đứng gần năm thủ uẩn này. Nếu người ấy ngồi, người ấy chỉ ngồi gần năm thủ uẩn này. Nếu người ấy nằm, người ấy chỉ nằm gần năm thủ uẩn này. Do vậy, này các Tỷ-kheo, cần phải luôn luôn quán sát tâm của mình như sau: “Trong một thời gian dài, tâm này bị tham, sân, si nhiễm ô. Do tâm nhiễm ô, này các Tỷ-kheo, chúng sanh bị nhiễm ô. Do tâm thanh tịnh, chúng sanh được thanh tịnh”.`, ref: "Tương Ưng Bộ 22.100", url: "https://loicuaducphat.org/sn/sn22.100.html#content" },

{ text: `Này các Tỷ-kheo, các Ông có thấy một bức họa gọi là danh họa không? - Thưa có, bạch Thế Tôn. - Này các Tỷ-kheo, bức danh họa ấy do tâm tư họa mà thành. Do vậy, này các Tỷ-kheo, tâm còn đa dạng hơn cả danh họa ấy. Do vậy, này các Tỷ-kheo, cần phải luôn luôn quán sát tâm của mình như sau: “Trong một thời gian dài, tâm này bị tham, sân, si làm nhiễm ô. Do tâm nhiễm ô, này các Tỷ-kheo, chúng sanh bị nhiễm ô. Do tâm thanh tịnh, chúng sanh được thanh tịnh”.`, ref: "Tương Ưng Bộ 22.100", url: "https://loicuaducphat.org/sn/sn22.100.html#content" },

{ text: `Này các Tỷ-kheo, Ta không quán thấy một bộ loại nào khác lại đa dạng như tâm. Như các hữu tình thuộc loại bàng sanh; các hữu tình thuộc loại bàng sanh ấy, này các Tỷ-kheo, do tâm tư duy (mà thành). Do vậy, này các Tỷ-kheo, tâm ấy lại đa dạng hơn các hữu tình thuộc loại bàng sanh ấy. Do vậy, này các Tỷ-kheo, cần phải luôn luôn quán sát tâm của mình như sau: “Trong một thời gian dài, tâm này bị tham, sân, si làm nhiễm ô. Do tâm nhiễm ô, này các Tỷ-kheo, chúng sanh bị nhiễm ô. Do tâm thanh tịnh, chúng sanh được thanh tịnh”.`, ref: "Tương Ưng Bộ 22.100", url: "https://loicuaducphat.org/sn/sn22.100.html#content" },

{ text: `Này các Tỷ-kheo, như có Tỷ-kheo sống không chí tâm trong sự tu tập, khởi lên ước muốn như sau: “Mong rằng tâm của ta được giải thoát khỏi các lậu hoặc, không có chấp thủ!” Tuy vậy, tâm của vị ấy cũng không giải thoát khỏi các lậu hoặc, có chấp thủ. Vì sao? Phải nói rằng vì vị ấy không có tu tập. Không có tu tập cái gì? Không có tu tập Bốn niệm xứ. Không có tu tập Bốn chánh cần. Không có tu tập Bốn như ý túc. Không có tu tập Năm căn. Không có tu tập Năm lực. Không có tu tập Bảy giác chi. Không có tu tập Thánh đạo Tám ngành.`, ref: "Tương Ưng Bộ 22.101", url: "https://loicuaducphat.org/sn/sn22.101.html#content" },

{ text: `Ví như, này các Tỷ-kheo, có tám, mười hay mười hai trứng gà, không được con gà mái ấp nằm đúng cách, không được ấp nóng đúng cách, không được ấp dưỡng đúng cách. Dầu cho con gà mái ấy khởi lên ý muốn: “Mong rằng những con gà con của ta, với chân, móng và đỉnh đầu, hay với miệng và mỏ, sau khi làm bể vỏ trứng, được xuất sanh một cách an toàn”; tuy vậy các con gà con ấy không có thể, với chân, móng, đỉnh đầu hay với miệng và mỏ, sau khi làm bể vỏ trứng, được xuất sanh một cách an toàn. Vì sao? Này các Tỷ-kheo, tám, mười hay mười hai trứng gà ấy không được con gà mái ấp nằm một cách đúng đắn, ấp nóng một cách đúng đắn, ấp dưỡng một cách đúng đắn. Cũng vậy, này các Tỷ-kheo, Tỷ-kheo không chí tâm trong sự tu tập. Dầu cho vị ấy có khởi lên ý muốn: “Mong rằng tâm ta được giải thoát khỏi các lậu hoặc, không có chấp thủ”; tuy vậy, tâm vị ấy cũng không giải thoát khỏi các lậu hoặc, có chấp thủ. Vì sao? Phải nói rằng, vì vị ấy không có tu tập. Không có tu tập cái gì? Không có tu tập Bốn niệm xứ … Không có tu tập con đường Thánh đạo Tám ngành.`, ref: "Tương Ưng Bộ 22.101", url: "https://loicuaducphat.org/sn/sn22.101.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một người thợ đá hay đệ tử người thợ đá, khi nhìn vào cán búa thấy dấu các ngón tay và dấu các ngón tay cái. Vị ấy không có thể biết được như sau: “Hôm nay, từng ấy cán búa của ta bị hao mòn; hôm nay từng ấy, các ngày khác từng ấy”. Nhưng vị ấy biết được cán búa bị hao mòn trên sự hao mòn của cán búa. Cũng vậy, này các Tỷ-kheo, vị Tỷ-kheo chí tâm trong sự tu tập không có biết như sau: “Hôm nay, từng ấy lậu hoặc của ta được hao mòn, hôm qua từng ấy, các ngày khác từng ấy”. Nhưng vị ấy biết được các lậu hoặc được hao mòn trên sự hao mòn các lậu hoặc. Ví như, này các Tỷ-kheo, một chiếc thuyền đi biển có đầy đủ cột buồm và dây buồm, bị mắc cạn sáu tháng do thiếu nước trong mùa khô; các cột buồm và dây buồm bị gió và mặt trời làm hư hỏng, rồi bị nước mưa đổ xuống trong mùa mưa, chúng trở thành yếu và hư nát. Cũng vậy, này các Tỷ-kheo, Tỷ-kheo sống chí tâm trong sự tu tập, các kiết sử rất dễ bị yếu dần và hư nát.`, ref: "Tương Ưng Bộ 22.101", url: "https://loicuaducphat.org/sn/sn22.101.html#content" },

{ text: `- Do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận, tất cả sắc tham được đoạn tận, tất cả hữu tham được đoạn tận, tất cả vô minh được đoạn tận, tất cả ngã mạn được tận trừ. Ví như, này các Tỷ-kheo, một người làm ruộng, vào mùa thu, dùng một cái cày lớn cắt đứt tất cả rễ mọc trong khi cày. Cũng vậy, này các Tỷ-kheo, do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận, tất cả sắc tham được đoạn tận, tất cả hữu tham được đoạn tận, tất cả vô minh được đoạn tận, tất cả ngã mạn được tận trừ. Ví như, này các Tỷ-kheo, một người cắt cỏ cắt đứt cây cỏ, nắm lấy đầu ngọn đập lên, đập xuống, đập tả, đập hữu, rồi quăng một bên. Cũng vậy, này các Tỷ-kheo, do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận … tất cả ngã mạn được tận trừ. Ví như, này các Tỷ-kheo, khi một chùm xoài bị cắt đứt từ cành, thời các trái xoài cùng dính vào cành đều bị đứt theo. Cũng vậy, này các Tỷ-kheo, do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận … tất cả ngã mạn được tận trừ.`, ref: "Tương Ưng Bộ 22.102", url: "https://loicuaducphat.org/sn/sn22.102.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trong mùa thu, khi trời mở rộng và gột sạch mây, mặt trời mọc lên trên bầu trời, đuổi sạch tất cả u ám khỏi hư không, bừng sáng, chói sáng và rực sáng. Cũng vậy, này các Tỷ-kheo, do tu tập, làm cho sung mãn vô thường tưởng, tất cả dục tham được đoạn tận, tất cả sắc tham được đoạn tận, tất cả hữu tham được đoạn tận, tất cả vô minh được đoạn tận, tất cả ngã mạn được tận trừ. Tu tập vô thường tưởng như thế nào, này các Tỷ-kheo, làm cho sung mãn như thế nào mà tất cả dục tham được đoạn tận … tất cả ngã mạn được tận trừ? Ðây là sắc; đây là sắc tập khởi; đây là sắc đoạn diệt; đây là thọ … đây là tưởng … đây là các hành … đây là thức; đây là thức tập khởi; đây là thức đoạn diệt. Vô thường tưởng được tu tập như vậy, này các Tỷ-kheo, được làm cho sung mãn như vậy, tất cả dục tham được đoạn tận, tất cả sắc tham được đoạn tận; tất cả hữu tham được đoạn tận; tất cả vô minh được đoạn tận; tất cả ngã mạn được tận trừ.`, ref: "Tương Ưng Bộ 22.102", url: "https://loicuaducphat.org/sn/sn22.102.html#content" },

{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết cho các Ông về Khổ, Khổ tập khởi, Khổ đoạn diệt, Con đường đưa đến khổ đoạn diệt. Hãy lắng nghe. Và này các Tỷ-kheo, thế nào là Khổ? Phải trả lời là năm thủ uẩn. Thế nào là năm? Tức là sắc thủ uẩn … thức thủ uẩn. Ðây gọi là Khổ, này các Tỷ-kheo. Và này các Tỷ-kheo, thế nào là Khổ tập khởi? Chính là khát ái này, đưa đến tái sanh … phi hữu ái. Này các Tỷ-kheo, đây gọi là Khổ tập khởi. Và này các Tỷ-kheo, thế nào là Khổ đoạn diệt? Chính là sự ly tham, đoạn diệt không dư tàn khát ái ấy, sự xả ly, sự từ bỏ, sự giải thoát, sự thoát ly chấp trước. Này các Tỷ-kheo, đây gọi là Khổ đoạn diệt. Và này các Tỷ-kheo, thế nào là Con đường đưa đến khổ đoạn diệt? Chính là con đường Thánh đạo Tám ngành, tức là chánh tri kiến … chánh định. Này các Tỷ-kheo, đây gọi là Con đường đưa đến khổ đoạn diệt.`, ref: "Tương Ưng Bộ 22.104", url: "https://loicuaducphat.org/sn/sn22.104.html#content" },

{ text: `“Minh, minh”, bạch Thế Tôn, như vậy được nói đến. Bạch Thế Tôn, như thế nào là minh? Cho đến như thế nào, một người là minh? - Ở đây, này Tỷ-kheo, bậc Ða văn Thánh đệ tử biết rõ sắc, biết rõ sắc tập khởi, biết rõ sắc đoạn diệt, biết rõ con đường đưa đến sắc đoạn diệt. … biết rõ thọ … biết rõ tưởng … biết rõ các hành … biết rõ con đường đưa đến thức đoạn diệt. Này Tỷ-kheo, đây gọi là minh. Và cho đến như vậy, một người là minh.`, ref: "Tương Ưng Bộ 22.114", url: "https://loicuaducphat.org/sn/sn22.114.html#content" },

{ text: `- Ở đây, này các Tỷ-kheo, kẻ vô văn phàm phu không thấy rõ các bậc Thánh … không tu tập pháp các bậc Chân nhân, quán sắc như là tự ngã, hay tự ngã như là có sắc, hay sắc ở trong tự ngã, hay tự ngã ở trong sắc. Người như vậy, này các Tỷ-kheo, được gọi là kẻ vô văn phàm phu, bị trói buộc bởi các trói buộc của sắc, bị trói buộc bởi các trói buộc nội ngoại, kẻ không thấy bờ bên này, kẻ không thấy bờ bên kia, khi sanh bị trói buộc, khi chết bị trói buộc, khi đi từ đời này qua đời khác bị trói buộc.`, ref: "Tương Ưng Bộ 22.117", url: "https://loicuaducphat.org/sn/sn22.117.html#content" },

{ text: `- Các Ông nghĩ thế nào, này các Tỷ-kheo, các Ông có quán sắc: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”? - Thưa có, bạch Thế Tôn. - Lành thay! Này các Tỷ-kheo, các Ông cần phải như thật quán sắc với chánh trí tuệ: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”.`, ref: "Tương Ưng Bộ 22.119", url: "https://loicuaducphat.org/sn/sn22.119.html#content" },

{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết cho các Ông về các pháp bị trói buộc và sự trói buộc. Hãy lắng nghe. Và này các Tỷ-kheo, thế nào là các pháp bị trói buộc? Thế nào là sự trói buộc? Sắc, này các Tỷ-kheo, là pháp bị trói buộc. Dục và tham đối với sắc là sự trói buộc của sắc. … Thọ … Tưởng … Các hành … Thức, này các Tỷ-kheo, là pháp bị trói buộc. Dục và tham đối với thức là sự trói buộc của thức. Này các Tỷ-kheo, các pháp này, này các Tỷ-kheo, được gọi là các pháp bị trói buộc. Ðây là sự trói buộc.`, ref: "Tương Ưng Bộ 22.120", url: "https://loicuaducphat.org/sn/sn22.120.html#content" },
{ text: `- Thưa Hiền giả Sāriputta, những pháp gì Tỷ-kheo giữ giới cần phải như lý tác ý? - Này Hiền giả Kotthika, Tỷ-kheo giữ giới cần phải như lý tác ý năm thủ uẩn là vô thường, khổ, bệnh hoạn, ung nhọt, mũi tên, bất hạnh, ốm đau, người lạ, hủy hoại, rỗng không, vô ngã. Thế nào là năm? Tức là sắc thủ uẩn, thọ thủ uẩn, tưởng thủ uẩn, hành thủ uẩn, thức thủ uẩn. Này Hiền giả Kotthika, vị Tỷ-kheo giữ giới cần phải như lý tác ý năm thủ uẩn là vô thường, khổ, bệnh hoạn, ung nhọt, mũi tên, bất hạnh, ốm đau, người lạ, hủy hoại, rỗng không, vô ngã.`, ref: "Tương Ưng Bộ 22.122", url: "https://loicuaducphat.org/sn/sn22.122.html#content" },

{ text: `“Vô minh, vô minh”, bạch Thế Tôn, được nói đến như vậy. Bạch Thế Tôn, thế nào là vô minh? Và cho đến như thế nào được gọi là vô minh? - Ở đây, này Tỷ-kheo, kẻ vô văn phàm phu, không như thật biết rõ: “Sắc chịu sự tập khởi” là sắc chịu sự tập khởi, không như thật biết rõ: “Sắc chịu sự đoạn diệt” là sắc chịu sự đoạn diệt, không như thật biết rõ: “Sắc chịu sự tập khởi và đoạn diệt” là sắc chịu sự tập khởi và đoạn diệt. Như vậy, này Tỷ-kheo, gọi là vô minh. Cho đến như vậy được gọi là vô minh.`, ref: "Tương Ưng Bộ 22.126", url: "https://loicuaducphat.org/sn/sn22.126.html#content" },

{ text: `- Sắc là than đỏ, này các Tỷ-kheo! Thọ là than đỏ! Tưởng là than đỏ! Các hành là than đỏ! Thức là than đỏ! Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với sắc, nhàm chán đối với thọ, nhàm chán đối với tưởng, nhàm chán đối với các hành, nhàm chán đối với thức. Do nhàm chán nên ly tham, do ly tham nên giải thoát. Trong sự giải thoát, trí khởi lên: “Ta đã được giải thoát”. Vị ấy biết rõ: “Sanh đã tận, Phạm hạnh đã thành, các việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 22.136", url: "https://loicuaducphat.org/sn/sn22.136.html#content" },

{ text: `- Cái gì vô thường, này các Tỷ-kheo, ở đây các Ông cần phải đoạn trừ lòng dục. Này các Tỷ-kheo, cái gì là vô thường? Này các Tỷ-kheo, sắc là vô thường. … Thọ … Tưởng … Các hành … Thức là vô thường, ở đây, các Ông cần phải đoạn trừ lòng dục. Cái gì vô thường, này các Tỷ-kheo, ở đây các Ông cần phải đoạn trừ lòng dục.`, ref: "Tương Ưng Bộ 22.137", url: "https://loicuaducphat.org/sn/sn22.137.html#content" },

{ text: `- Ðối với vị thiện nam tử vì lòng tin xuất gia, này các Tỷ-kheo, đây là thuận pháp: Hãy sống nhàm chán nhiều đối với sắc… đối với thọ… đối với tưởng… đối với các hành, hãy sống nhàm chán nhiều đối với thức. Ai sống nhàm chán nhiều đối với sắc… đối với thọ… đối với tưởng… đối với các hành, ai sống nhàm chán nhiều đối với thức thời sẽ biến tri sắc… thọ… tưởng… các hành, biến tri thức. Vị nào biến tri sắc, biến tri thọ, biến tri tưởng, biến tri các hành, biến tri thức, thời được giải thoát khỏi sắc, được giải thoát khỏi thọ, được giải thoát khỏi tưởng, được giải thoát khỏi các hành, được giải thoát khỏi thức, được giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói vị ấy được giải thoát khỏi đau khổ.`, ref: "Tương Ưng Bộ 22.146", url: "https://loicuaducphat.org/sn/sn22.146.html#content" },

{ text: `- Bạch Thế Tôn, chánh quán với mục đích gì? - Chánh quán, này Rādha, với mục đích nhàm chán. - Bạch Thế Tôn, nhàm chán với mục đích gì? - Nhàm chán, này Rādha, với mục đích ly tham. - Bạch Thế Tôn, ly tham với mục đích gì? - Ly tham, này Rādha, với mục đích được giải thoát. - Bạch Thế Tôn, giải thoát với mục đích gì? - Giải thoát, này Rādha, với mục đích Niết-bàn. - Bạch Thế Tôn, Niết-bàn với mục đích gì? - Này Rādha, Ông đi quá xa với câu hỏi này, không thế nắm được giới hạn của câu hỏi. Nhập vào Niết-bàn, này Rādha, là sự thực hành Phạm hạnh; Niết-bàn là mục tiêu cuối cùng; Niết-bàn là cứu cánh.`, ref: "Tương Ưng Bộ 23.1", url: "https://loicuaducphat.org/sn/sn23.1.html#content" },

{ text: `- Nếu có sắc, này Rādha, thời có chết, hay có sát giả, hay có bị chết. Do vậy, này Rādha, Ông hãy thấy sắc là sự chết, hãy thấy là sát giả, hãy thấy là bị chết, hãy thấy là bệnh, hãy thấy là ung nhọt, hãy thấy là mũi tên, hãy thấy là bất hạnh, hãy thấy tự tánh là bất hạnh. Những ai thấy sắc như vậy là thấy chơn chánh.`, ref: "Tương Ưng Bộ 23.1", url: "https://loicuaducphat.org/sn/sn23.1.html#content" },

{ text: `Ví như, này Rādha, các đứa con trai hay các đứa con gái chơi với cái nhà bằng đất. Cho đến khi đối với những nhà bằng đất ấy, lòng tham chưa thoát ly, lòng dục chưa thoát ly, lòng ái chưa thoát ly, lòng khát chưa thoát ly, lòng nhiệt tình chưa thoát ly, lòng khát ái chưa thoát ly, thời chúng còn tham dính vào, thích chơi, chất chứa, và đắm trước những nhà bằng đất ấy. Nhưng khi nào các đứa con trai hay các đứa con gái ấy đối với những nhà bằng đất kia, lòng tham đã thoát ly, lòng dục đã thoát ly, lòng ái đã thoát ly, lòng khát đã thoát ly, lòng nhiệt tình đã thoát ly, lòng khát ái đã thoát ly, thời với tay và với chân, chúng phá tan, phá vỡ, phá sập, không chơi với những căn nhà bằng đất ấy. Cũng vậy, này Rādha, Ông hãy phá tan, phá vỡ, phá sập, không chơi với sắc, chú tâm hướng đến đoạn diệt khát ái đối với sắc. Ðoạn diệt khát ái, này Rādha, là Niết-bàn.`, ref: "Tương Ưng Bộ 23.2", url: "https://loicuaducphat.org/sn/sn23.2.html#content" },

{ text: `“Chúng sanh, chúng sanh”, bạch Thế Tôn, được nói đến như vậy. Cho đến như thế nào, bạch Thế Tôn, được gọi là chúng sanh? - Này Rādha, dục nào, tham nào, hỷ nào, khát ái nào đối với sắc, triền phược ở đấy, triền miên ở đấy, do vậy gọi là chúng sanh … thọ … tưởng … các hành … Dục nào, tham nào, hỷ nào, khát ái nào đối với thức, triền phược ở đấy, triền miên ở đấy, do vậy gọi là chúng sanh.`, ref: "Tương Ưng Bộ 23.2", url: "https://loicuaducphat.org/sn/sn23.2.html#content" },

{ text: `“Ðoạn diệt sợi dây tái sanh. Ðoạn diệt sợi dây tái sanh”, bạch Thế Tôn, được nói đến như vậy. Thế nào là sợi dây tái sanh, bạch Thế Tôn? Thế nào là sự đoạn diệt sợi dây tái sanh? - Này Rādha, phàm dục gì, tham gì, hỷ gì, khát ái gì, phàm những chấp thủ phương tiện, tâm kiên trú, thiên chấp tùy miên gì đối với sắc, như vậy gọi là sợi dây tái sanh. Sự đoạn diệt chúng là sự đoạn diệt sợi dây tái sanh. … đối với thọ … với tưởng … với các hành … Phàm dục gì, tham gì, hỷ gì, khát ái gì, phàm những chấp thủ phương tiện, tâm kiên trú, thiên chấp tùy miên gì đối với thức, đó gọi là sợi dây tái sanh. Sự đoạn diệt chúng là sự đoạn diệt sợi dây tái sanh.`, ref: "Tương Ưng Bộ 23.3", url: "https://loicuaducphat.org/sn/sn23.3.html#content" },

{ text: `- Này Rādha, phàm có dục nào, tham nào, hỷ nào, khát ái nào đối với sắc, hãy từ bỏ chúng. Như vậy, sắc sẽ được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không thể tái sanh, không thể sanh khởi trong tương lai. … đối với thọ … đối với tưởng … đối với các hành … Này Rādha, phàm có dục nào, tham nào, hỷ nào, khát ái nào, đối với thức, hãy từ bỏ chúng. Như vậy, thức sẽ được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, làm cho không thể tái sanh, không thể sanh khởi trong tương lai.`, ref: "Tương Ưng Bộ 23.9", url: "https://loicuaducphat.org/sn/sn23.9.html#content" },

{ text: `- Khi nào vị Thánh đệ tử, này các Tỷ-kheo, đối với sáu xứ này, nghi hoặc được đoạn trừ; đối với khổ, nghi hoặc được đoạn trừ; đối với khổ tập khởi, nghi hoặc được đoạn trừ; đối với khổ đoạn diệt, nghi hoặc được đoạn trừ; đối với con đường đưa đến khổ đoạn diệt, nghi hoặc được đoạn trừ; như vậy, này các Tỷ-kheo gọi là bậc Thánh đệ tử đã chứng được Dự lưu, không còn bị thối đọa, quyết chắc hướng đến giác ngộ.`, ref: "Tương Ưng Bộ 24.1", url: "https://loicuaducphat.org/sn/sn24.1.html#content" },

{ text: `- Này các Tỷ-kheo, sự sanh, sự trú, sự thành, sự xuất hiện của mắt là sự sanh của khổ, sự trú của bệnh hoạn, sự xuất hiện của già chết. Sự sanh, sự trú, sự thành, sự xuất hiện của tai … của mũi … của lưỡi … của thân … của ý là sự sanh của khổ, sự trú của bệnh hoạn, sự xuất hiện của già chết. Sự diệt, sự lắng dịu, sự chấm dứt của sắc là sự diệt của khổ, sự lắng dịu của bệnh hoạn, sự chấm dứt của già chết. Sự diệt, sự lắng dịu, sự chấm dứt của tai … của mũi … của lưỡi … của thân … của ý là sự diệt của khổ, sự lắng dịu của bệnh hoạn, sự chấm dứt của già chết.`, ref: "Tương Ưng Bộ 26.1", url: "https://loicuaducphat.org/sn/sn26.1.html#content" },

{ text: `- Này các Tỷ-kheo, dục tham đối với mắt là tùy phiền não của tâm. Dục tham đối với tai là tùy phiền não của tâm. Dục tham đối với mũi là tùy phiền não của tâm. Dục tham đối với lưỡi là tùy phiền não của tâm. Dục tham đối với thân là tùy phiền não của tâm. Dục tham đối với ý là tùy phiền não của tâm. Này các Tỷ-kheo, khi nào vị Tỷ-kheo đối với sáu xứ này, đoạn tận được tùy phiền não, thời tâm vị ấy hướng về ly dục. Do biến mãn với ly dục, tâm vị ấy được xem là kham nhẫn, chứng tri đối với các pháp cần phải giác ngộ.`, ref: "Tương Ưng Bộ 27.1", url: "https://loicuaducphat.org/sn/sn27.1.html#content" },

{ text: `- Có bốn hạng tu Thiền này, này các Tỷ-kheo. Thế nào là bốn? Ở đây, này các Tỷ-kheo, có người tu Thiền, thiện xảo về Thiền chứng trong Thiền định, nhưng không thiện xảo về chỉ trú trong Thiền định. Ở đây, này các Tỷ-kheo, có người tu Thiền, thiện xảo về chỉ trú trong Thiền định, nhưng không thiện xảo về Thiền chứng trong Thiền định. Ở đây, này các Tỷ-kheo, có người tu Thiền, không thiện xảo về Thiền chứng trong Thiền định, cũng không thiện xảo về chỉ trú trong Thiền định. Ở đây, này các Tỷ-kheo, có người tu Thiền, thiện xảo về Thiền chứng trong Thiền định, và cũng thiện xảo về chỉ trú trong Thiền định. Tại đây, này các Tỷ-kheo, người tu Thiền thiện xảo về Thiền chứng trong Thiền định và cũng thiện xảo về chỉ trú trong Thiền định. Trong bốn vị tu Thiền ấy, vị tu Thiền này là tối tôn, tối thắng, là bậc thượng thủ, tối thượng, tối diệu.`, ref: "Tương Ưng Bộ 34.11", url: "https://loicuaducphat.org/sn/sn34.11.html#content" },

{ text: `- Ai ưa thích các sắc, này các Tỷ-kheo, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói người ấy không thoát khỏi khổ. Ai ưa thích các tiếng … các hương … các vị … các xúc … Ai ưa thích các pháp, người ấy ưa thích khổ. Ai ưa thích khổ, Ta nói người ấy không thoát khỏi khổ. Ai không ưa thích các sắc, này các Tỷ-kheo, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói người ấy thoát khỏi khổ. Ai không ưa thích các tiếng … các hương … các vị … các xúc … Ai không ưa thích các pháp, người ấy không ưa thích khổ. Ai không ưa thích khổ, Ta nói người ấy thoát khỏi khổ.`, ref: "Tương Ưng Bộ 35.20", url: "https://loicuaducphat.org/sn/sn35.20.html#content" },

{ text: `Mắt, này các Tỷ-kheo, bị bốc cháy. Các sắc bị bốc cháy. Nhãn thức bị bốc cháy. Nhãn xúc bị bốc cháy. Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; cảm thọ ấy bị bốc cháy. Bị bốc cháy bởi cái gì? Bị bốc cháy bởi lửa tham, lửa sân, lửa si. Ta nói rằng bị bốc cháy bởi sanh, già, chết, sầu, bi, khổ, ưu, não … Tai … Mũi … Lưỡi bị bốc cháy. Các vị bị bốc cháy. Thiệt thức bị bốc cháy. Thiệt xúc bị bốc cháy. Do duyên thiệt xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; cảm thọ ấy bị bốc cháy. Bị bốc cháy bởi cái gì? Bị bốc cháy bởi lửa tham, lửa sân, lửa si. Ta nói rằng bị bốc cháy bởi sanh, già, chết, sầu, bi, khổ, ưu, não … Thân … Ý bị bốc cháy. Các pháp bị bốc cháy. Ý thức bị bốc cháy. Ý xúc bị bốc cháy. Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy bị bốc cháy. Bị bốc cháy bởi cái gì? Bị bốc cháy bởi lửa tham, lửa sân, lửa si. Ta nói rằng bị bốc cháy bởi sanh, già, chết, sầu, bi, khổ, ưu, não.`, ref: "Tương Ưng Bộ 35.28", url: "https://loicuaducphat.org/sn/sn35.28.html#content" },

{ text: `- Do biết như thế nào, bạch Thế Tôn, do thấy như thế nào, vô minh được đoạn tận, minh được sanh khởi? - Này Tỷ-kheo, do biết, do thấy mắt là vô thường, vô minh được đoạn tận, minh được sanh khởi. Do biết, do thấy các sắc là vô thường, vô minh được đoạn tận, minh được sanh khởi … nhãn thức … nhãn xúc … Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; do biết, do thấy cảm thọ ấy là vô thường, vô minh được đoạn tận, minh được sanh khởi. Tai … Mũi … Lưỡi … Thân … Do biết, do thấy ý là vô thường, vô minh được đoạn tận, minh được sanh khởi … Các pháp … Ý thức … Ý xúc … Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; do biết, do thấy cảm thọ ấy là vô thường, vô minh được đoạn tận, minh được sanh khởi. Do biết như vậy, này các Tỷ-kheo, do thấy như vậy, vô minh được đoạn tận, minh được sanh khởi.`, ref: "Tương Ưng Bộ 35.53", url: "https://loicuaducphat.org/sn/sn35.53.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là pháp đưa đến liễu tri tất cả chấp thủ? Do duyên mắt và các sắc khởi lên nhãn thức. Do ba pháp này hợp lại có xúc. Do duyên xúc có thọ. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với mắt, nhàm chán đối với các sắc, nhàm chán đối với nhãn thức, nhàm chán đối với nhãn xúc, nhàm chán đối với với thọ. Do nhàm chán, vị ấy ly tham. Do ly tham, vị ấy được giải thoát. Nhờ giải thoát, vị ấy biết rõ: “Ta đã liễu tri chấp thủ”. Do duyên tai và các tiếng khởi lên nhĩ thức … Do duyên mũi và các hương … Do duyên lưỡi và các vị … Do duyên thân và các xúc … Do duyên ý và các pháp khởi lên ý thức. Do ba pháp này hợp lại có xúc. Do duyên xúc có thọ. Thấy vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với ý, nhàm chán đối với các pháp, nhàm chán đối với ý thức, nhàm chán đối với ý xúc, nhàm chán đối với thọ. Do nhàm chán, vị ấy ly tham. Do ly tham, vị ấy được giải thoát. Nhờ giải thoát, vị ấy biết rõ: “Ta đã liễu tri chấp thủ”. Như vậy, này các Tỷ-kheo, là pháp đưa đến liễu tri tất cả chấp thủ.`, ref: "Tương Ưng Bộ 35.60", url: "https://loicuaducphat.org/sn/sn35.60.html#content" },

{ text: `Này Migajāla, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ, tán dương và trú với lòng tham luyến pháp ấy; do vị ấy hoan hỷ, tán dương và trú với lòng tham luyến pháp ấy nên hỷ khởi lên. Do hỷ có mặt nên dục tham có mặt. Do dục tham có mặt nên triền phược có mặt. Bị trói buộc bởi hỷ triền phược, này Migajāla, nên Tỷ-kheo được gọi là người sống có người thứ hai. Tỷ-kheo sống như vậy, này Migajāla, dầu cho đến ở các trú xứ xa vắng, các khóm rừng, các khu rừng, ít tiếng động, ít ồn ào, khỏi hơi thở quần chúng, vắng người, thích hợp với tịnh; dầu vậy, vẫn được gọi là sống với người thứ hai. Vì sao? Vì rằng ái, người thứ hai, chưa được đoạn tận cho nên được gọi là sống có người thứ hai.`, ref: "Tương Ưng Bộ 35.63", url: "https://loicuaducphat.org/sn/sn35.63.html#content" },

{ text: `Và này Migajala, có các sắc do mắt nhận thức, khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ, không tán dương và trú với lòng không tham luyến pháp ấy; thời do vị ấy không hoan hỷ, không tán dương và trú với lòng không tham luyến pháp ấy, nên hỷ đoạn diệt; thời do hỷ không có mặt nên dục tham không có mặt. Do dục tham không có mặt nên triền phược không có mặt. Do không bị trói buộc bởi hỷ triền phược, này Migajāla, nên Tỷ-kheo được gọi là người trú một mình.`, ref: "Tương Ưng Bộ 35.63", url: "https://loicuaducphat.org/sn/sn35.63.html#content" },

{ text: `Này Migajāla, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ, không tán dương và trú với tâm không tham luyến pháp ấy; thời do vị ấy không hoan hỷ, không tán dương, trú với tâm không tham luyến pháp ấy nên hỷ đoạn diệt. Do hỷ không có mặt nên dục tham không có mặt. Do dục tham không có mặt nên triền phược không có mặt. Do không bị trói buộc bởi hỷ triền phược, này Migajāla, nên Tỷ-kheo được gọi là người trú một mình. Tỷ-kheo sống như vậy, này Migajāla, dầu có ở giữa làng tràn đầy những Tỷ-kheo, Tỷ-kheo-ni, nam cư sĩ, nữ cư sĩ, vua chúa, đại thần của vua, các ngoại đạo và các đệ tử các ngoại đạo, vị ấy vẫn được gọi là vị sống một mình. Vì sao? Vì rằng ái, người thứ hai, được đoạn tận, do vậy được gọi là sống một mình.`, ref: "Tương Ưng Bộ 35.63", url: "https://loicuaducphat.org/sn/sn35.63.html#content" },

{ text: `- Này Migajāla, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ, tán dương, sống với tâm tham luyến sắc ấy; do vị ấy hoan hỷ, tán dương, sống với tâm tham luyến sắc ấy nên hỷ sanh. Này Migajāla, Ta nói rằng do hỷ tập khởi nên khổ tập khởi … Các tiếng … Các hương … … Các vị … Các xúc … Này Migajāla, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ, tán dương, sống với tâm tham luyến pháp ấy; do vị ấy hoan hỷ, tán dương sống với tâm tham luyến pháp ấy nên hỷ sanh. Này Migajāla, Ta nói rằng do hỷ tập khởi nên khổ tập khởi.`, ref: "Tương Ưng Bộ 35.64", url: "https://loicuaducphat.org/sn/sn35.64.html#content" },

{ text: `Này Migajāla, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ, không tán dương, sống với tâm không tham luyến sắc ấy; do vị ấy không hoan hỷ, không tán dương, sống với tâm không tham luyến, không an trú tham luyến sắc ấy nên hỷ diệt. Này Migajāla, Ta nói rằng do hoan hỷ đoạn diệt nên khổ đoạn diệt … Các tiếng … Các hương … … Các vị … Các xúc … Này Migajāla, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ, không tán dương, sống với tâm không tham luyến pháp ấy; do vị ấy không hoan hỷ, không tán dương, sống với tâm không tham luyến pháp ấy nên hỷ diệt. Này Migajāla, Ta nói rằng do hỷ đoạn diệt nên khổ đoạn diệt.`, ref: "Tương Ưng Bộ 35.64", url: "https://loicuaducphat.org/sn/sn35.64.html#content" },

{ text: `“Thế giới, thế giới”, bạch Thế Tôn, như vậy được nói đến. Cho đến như thế nào, bạch Thế Tôn, là thế giới, hay là danh nghĩa thế giới? - Chỗ nào, này Samiddhi, có mắt, có các sắc, có nhãn thức, có các pháp do mắt nhận thức, tại chỗ ấy có thế giới, hay danh nghĩa thế giới … (như trên) … Chỗ nào có ý, có các pháp, có ý thức, có các pháp do ý nhận thức, tại chỗ ấy có thế giới hay có danh nghĩa thế giới. Và tại chỗ nào, này Samiddhi, không có mắt, không có các sắc, không có nhãn thức, không có các pháp do mắt nhận thức, tại chỗ ấy không có thế giới, hay không có danh nghĩa thế giới … không có ý … tại chỗ ấy, không có thế giới hay không có danh nghĩa thế giới.`, ref: "Tương Ưng Bộ 35.68", url: "https://loicuaducphat.org/sn/sn35.68.html#content" },

{ text: `:“Thiết thực hiện tại, thiết thực hiện tại (Sanditthiko)”, bạch Thế Tôn, như vậy được nói đến. Cho đến như thế nào, bạch Thế Tôn, là thiết thực hiện tại, có kết quả tức thời, đến để mà thấy, có khả năng hướng thượng, được những người có trí tự mình giác hiểu? Ở đấy, này Upavāna, sau khi mắt thấy sắc, Tỷ-kheo cảm thọ sắc, nhưng không cảm thọ tham sắc, và không có nội tham đối với sắc; vị ấy biết rõ: “Tôi không có nội tham đối với sắc”. Cho đến chừng nào, này Upavāna, sau khi mắt thấy sắc, Tỷ-kheo cảm thọ sắc, nhưng không cảm thọ tham sắc, và không có nội tham đối với các sắc; vị ấy biết rõ: “Tôi không có nội tham đối với các sắc”. Như vậy, này Upavāna, là thiết thực hiện tại, có kết quả tức thời, đến để mà thấy, có khả năng hướng thượng, được những người trí tự mình giác hiểu.`, ref: "Tương Ưng Bộ 35.70", url: "https://loicuaducphat.org/sn/sn35.70.html#content" },

{ text: `- Tỷ-kheo nào, này các Tỷ-kheo, không như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm, sự xuất ly của sáu xúc xứ; vị ấy không thành tựu Phạm hạnh, còn đứng xa Pháp và Luật này. - Ông nghĩ thế nào, này Tỷ-kheo? Ông có quán con mắt: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”? - Thưa không, bạch Thế Tôn. - Lành thay, này Tỷ-kheo. Ở đây, này Tỷ-kheo, do Ông như thật thấy con mắt với chánh trí tuệ: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”; như vậy là khéo thấy. Ðây là khổ được đoạn tận … tai … mũi … … lưỡi … thân … Ông nghĩ thế nào, này Tỷ-kheo? Ông có quán ý: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”? - Thưa không, bạch Thế Tôn. - Lành thay, này Tỷ-kheo. Ở đây, này Tỷ-kheo, do Ông như thật thấy ý với chánh trí tuệ: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải tự ngã của tôi”; như vậy là khéo thấy. Ðây là khổ được đoạn tận.`, ref: "Tương Ưng Bộ 35.71", url: "https://loicuaducphat.org/sn/sn35.71.html#content" },

{ text: `- Bạch Thế Tôn, con không hiểu pháp Thế Tôn dạy về mục đích thanh tịnh trì giới. - Này Tỷ-kheo, nếu Ông không hiểu pháp Ta dạy về mục đích thanh tịnh trì giới, thời này Tỷ-kheo, Ông hiểu pháp Ta dạy như thế nào? - Bạch Thế Tôn, con hiểu pháp do Thế Tôn dạy là tham và đoạn tham. - Lành thay, lành thay, này Tỷ-kheo! Lành thay, này Tỷ-kheo! Ông hiểu pháp Ta dạy là tham và đoạn tham. Với mục đích tham và đoạn tham, này Tỷ-kheo, là pháp Ta dạy. Ông nghĩ thế nào, này Tỷ-kheo, mắt là thường hay vô thường? - Là vô thường, bạch Thế Tôn … - Tai … Mũi … Lưỡi … Thân … Ý là thường hay vô thường? - Là vô thường, bạch Thế Tôn. - Cái gì vô thường là khổ hay lạc? - Cái gì vô thường, khổ, chịu sự biến hoại, có hợp lý chăng nếu quán cái ấy là: “Cái này là của tôi, cái này là tôi, cái này là tự ngã của tôi”? - Thưa không, bạch Thế Tôn. - Thấy vậy, này Tỷ-kheo, bậc Ða văn Thánh đệ tử nhàm chán đối với mắt … ” … không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 35.74", url: "https://loicuaducphat.org/sn/sn35.74.html#content" },

{ text: `Ngồi xuống một bên, Tôn giả Rādha bạch Thế Tôn: - Lành thay, bạch Thế Tôn, nếu Thế Tôn vắn tắt thuyết pháp cho con. Sau khi nghe pháp của Thế Tôn con sẽ sống một mình, an tịnh, không phóng dật, nhiệt tâm, tinh cần. - Cái gì vô thường, này Rādha, ở đây Ông cần phải đoạn tận lòng dục. Và này Rādha, cái gì là vô thường? Mắt, này Rādha, là vô thường, ở đây Ông cần phải đoạn tận lòng dục. Các sắc là vô thường … Nhãn thức là vô thường … Nhãn xúc … Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy là vô thường. Ở đây, Ông cần phải đoạn tận lòng dục … Tai … Mũi … … Lưỡi … Thân … Ý là vô thường, ở đây Ông cần phải đoạn tận lòng dục. Các pháp … Ý thức … Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy là vô thường. Ở đây, Ông cần phải đoạn tận lòng dục. Phàm cái gì là vô thường, này Rādha, ở đây, Ông cần phải đoạn tận lòng dục.`, ref: "Tương Ưng Bộ 35.76", url: "https://loicuaducphat.org/sn/sn35.76.html#content" },

{ text: `- Phàm cái gì là khổ, này Rādha, ở đây Ông cần phải đoạn tận lòng dục. Và này Rādha, cái gì là khổ? Mắt, này Rādha, là khổ; ở đây, Ông cần phải đoạn tận lòng dục. Các pháp … Nhãn thức … Nhãn xúc … Do duyên ý xúc, khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy là khổ. Ở đây, Ông cần phải đoạn tận lòng dục. Phàm cái gì là khổ, này Rādha, ở đây, Ông cần phải đoạn tận lòng dục.`, ref: "Tương Ưng Bộ 35.77", url: "https://loicuaducphat.org/sn/sn35.77.html#content" },

{ text: `:“Trống không là thế giới, trống không là thế giới”, bạch Thế Tôn, như vậy được nói đến. Cho đến như thế nào, bạch Thế Tôn, được gọi trống không là thế giới? - Vì rằng, này Ānanda, thế giới là không tự ngã, và không thuộc tự ngã, nên thế giới được gọi là trống không. Và cái gì, này Ānanda, là không tự ngã và không thuộc tự ngã? Mắt, này Ānanda, là không tự ngã và không thuộc tự ngã. Các sắc là không tự ngã, hay không thuộc tự ngã. Nhãn thức là không tự ngã, hay không thuộc tự ngã. Nhãn xúc là không tự ngã, hay không thuộc tự ngã … Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy không có tự ngã hay không thuộc tự ngã. Và vì rằng, này Ānanda, không có tự ngã, hay không thuộc tự ngã nên được gọi trống không là thế giới này.`, ref: "Tương Ưng Bộ 35.84", url: "https://loicuaducphat.org/sn/sn35.84.html#content" },

{ text: `- Bạch Thế Tôn, có một quốc độ tên là Sunāparanta, tại đấy con sẽ ở. - Thô bạo, này Puñña, là người xứ Sunāparanta. Ðộc ác, này Puñña, là người xứ Sunāparanta. Nếu người xứ Sunāparanta, này Puñña, chửi bới, nhiếc mắng Ông, thời này Puñña, ở đây, Ông nghĩ thế nào? - Nếu người xứ Sunāparanta, bạch Thế Tôn, chửi bới, nhiếc mắng con, ở đây, con sẽ nghĩ: “Thật là hiền thiện, người xứ Sunāparanta này! Thật là khéo hiền thiện, người xứ Sunāparanta này! Vì những người này không lấy tay đánh đập ta”. Như vậy, ở đây, bạch Thế Tôn, con sẽ nghĩ như vậy. Như vậy, ở đây, bạch Thiện Thệ, con sẽ nghĩ như vậy. - Lành thay, lành thay, này Puñña! Ðầy đủ với sự an tịnh tự điều này, Ông có thể sống tại quốc độ Sunāparanta. Này Puñña, nay Ông hãy làm những gì Ông nghĩ là hợp thời.`, ref: "Tương Ưng Bộ 35.87", url: "https://loicuaducphat.org/sn/sn35.87.html#content" },

{ text: `- Ái nhiễm, này các Tỷ-kheo, là bệnh tật; ái nhiễm là mụt nhọt; ái nhiễm là mũi tên. Do vậy, này các Tỷ-kheo, Như Lai sống không ái nhiễm, không bị mũi tên làm bị thương. Do vậy, này các Tỷ-kheo, nếu Tỷ-kheo có ước vọng gì, hãy ước sống không ái nhiễm, không bị mũi tên làm bị thương. Chớ có nghĩ đến mắt, chớ có nghĩ đến trong mắt, chớ có nghĩ đến từ mắt, chớ có nghĩ đến: “Mắt là của tôi”. Chớ có nghĩ đến các sắc, chớ có nghĩ đến trong các sắc, chớ có nghĩ đến từ các sắc, chớ có nghĩ đến: “Các sắc là của tôi”. Chớ có nghĩ đến nhãn thức, chớ có nghĩ đến trong nhãn thức, chớ có nghĩ đến từ nhãn thức, chớ có nghĩ đến: “Nhãn thức là của tôi”. Chớ có nghĩ đến nhãn xúc, chớ có nghĩ đến trong nhãn xúc, chớ có nghĩ đến từ nhãn xúc, chớ có nghĩ đến: “Nhãn xúc là của tôi”. Do duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ hay bất khổ bất lạc; chớ có nghĩ đến cảm thọ ấy, chớ có nghĩ đến trong cảm thọ ấy, chớ có nghĩ đến từ cảm thọ ấy, chớ có nghĩ đến: “Cảm thọ ấy là tôi”. Chớ có nghĩ đến tất cả, chớ có nghĩ đến trong tất cả, chớ có nghĩ đến từ tất cả, chớ có nghĩ đến: “Tất cả là của tôi”. Vị ấy do không nghĩ đến nên không chấp thủ một vật gì ở đời. Do không chấp thủ, vị ấy không có dao động. Do không dao động, vị ấy tự mình tịch tịnh một cách hoàn toàn. Vị ấy biết rõ: “Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”.`, ref: "Tương Ưng Bộ 35.89", url: "https://loicuaducphat.org/sn/sn35.89.html#content" },

{ text: `- Có sáu xúc xứ này, này các Tỷ-kheo, không nhiếp phục, không phòng hộ, không bảo vệ, không thâu nhiếp, đem lại đau khổ. Thế nào là sáu? Mắt xúc xứ, này các Tỷ-kheo, không nhiếp phục, không phòng hộ, không bảo vệ, không thâu nhiếp, đem lại đau khổ … Tai … Mũi … … Lưỡi … Thân … Ý xúc xứ, này các Tỷ-kheo, không nhiếp phục, không phòng hộ, không bảo vệ, không thâu nhiếp, đem lại đau khổ. Sáu xúc xứ này, này các Tỷ-kheo, không nhiếp phục, không phòng hộ, không bảo vệ, không thâu nhiếp, đem lại đau khổ.`, ref: "Tương Ưng Bộ 35.92", url: "https://loicuaducphat.org/sn/sn35.92.html#content" },

{ text: `Có sáu xúc này, này các Tỷ-kheo, khéo nhiếp phục, khéo phòng hộ, khéo bảo vệ, khéo thâu nhiếp, đem lại an lạc. Thế nào là sáu? Mắt xúc xứ, này các Tỷ-kheo, khéo nhiếp phục, khéo phòng hộ, khéo bảo vệ, khéo thâu nhiếp, đem lại an lạc … Tai … Mũi … … Lưỡi … Thân … Ý xúc xứ, này các Tỷ-kheo, khéo nhiếp phục, khéo phòng hộ, khéo bảo vệ, khéo thâu nhiếp, đem lại an lạc. Sáu xúc xứ này, này các Tỷ-kheo, khéo nhiếp phục, khéo phòng hộ, khéo bảo vệ, khéo thâu nhiếp, đem lại an lạc.`, ref: "Tương Ưng Bộ 35.92", url: "https://loicuaducphat.org/sn/sn35.92.html#content" },

{ text: `Hỡi các vị Tỷ-kheo,\nChính sáu xúc xứ này,\nChỗ nào không thâu nhiếp,\nChỗ ấy có đau khổ.\nNhững ai học biết được,\nChế ngự, phòng hộ chúng,\nVới lòng tin làm bạn,\nSống thoát ly dục vọng.\n\nThấy sắc pháp khả ái,\nThấy sắc không khả ái,\nHãy nhiếp phục đường tham,\nÐối các sắc khả ái,\nChớ khiến ý nhiễm ô:\n“Ðối sắc, ta không thích”.\n\nSau khi nghe các tiếng,\nKhả ái, không khả ái,\nChớ để tâm say mê,\nVới các tiếng khả ái.\nHãy nhiếp phục lòng sân,\nVới tiếng không khả ái,\nChớ khiến ý nhiễm ô:\n“Ðối tiếng, ta không thích”.\n\nSau khi ngửi các hương,\nThơm dịu, thật khả ái,\nSau khi ngửi các hương,\nBất tịnh, thật đáng ghét;\nHãy nhiếp phục lòng sân,\nÐối các hương đáng ghét,\nCòn đối hương khả ái,\nChớ để dục chi phối.\n\nNếm xong vị ngon ngọt,\nVà nếm vị không ngon,\nChớ có sanh tham luyến,\nKhi hưởng nếm vị ngon,\nChớ nói lời chống đối,\nKhi nếm vị không ngon.\n\nKhi cảm thọ lạc xúc,\nChớ đắm say tham luyến,\nKhi cảm thọ khổ xúc,\nChớ bị xúc động mạnh.\nÐối với cả hai xúc,\nLạc, khổ đều niệm xả,\nKhông thích, không chống đối,\nBất cứ loại xúc nào.\n\nÐối với các người khác,\nMê theo hý luận tưởng,\nHọ mê theo hý luận,\nHọ hành theo hư tưởng;\nHãy đoạn trừ tất cả,\nGia sự do ý tạo,\nHãy nhiếp các hành động,\nHướng đến hạnh viễn ly.\n\nNhư vậy đối sáu xứ,\nKhi ý khéo tu tập,\nNếu có cảm xúc gì,\nTâm không bị dao động.\nTỷ-kheo hãy nhiếp phục,\nCả hai tham sân ấy,\nHãy đến bờ bên kia,\nVượt buộc ràng sanh tử.`, ref: "Tương Ưng Bộ 35.92", url: "https://loicuaducphat.org/sn/sn35.92.html#content" },
{ text: `- Ông nghĩ thế nào, này Màlukyaputta? Các sắc do mắt nhận thức, Ông không thấy, trước đây Ông không thấy, nay Ông không thấy, và Ông không muốn thấy; ở đây đối với chúng, Ông có lòng dục, tham hay khát ái không? - Thưa không, bạch Thế Tôn. - Các tiếng do tai nhận thức … Các hương do mũi nhận thức … Các vị do lưỡi nhận thức … Các xúc do thân nhận thức, Ông không cảm thọ, trước đây Ông không cảm thọ, nay Ông không cảm thọ, và Ông không muốn cảm thọ; ở đây đối với chúng, Ông có lòng dục, tham hay khát ái không? - Thưa không, bạch Thế Tôn.\n\nThấy sắc, niệm mê say,\nTác ý đến ái tướng,\nTâm tham đắm cảm thọ,\nTham luyến sắc an trú.\nVị ấy, thọ tăng trưởng,\nNhiều loại, từ sắc sinh,\nTham dục và hại tâm,\nNão hại tâm vị ấy,\nNhư vậy, khổ tích lũy,\nÐược gọi xa Niết- bàn.\n\nNghe tiếng, niệm mê say,\nTác ý đến ái tướng,\nTâm tham đắm cảm thọ,\nTham luyến tiếng an trú.\nVị ấy, thọ tăng trưởng,\nNhiều loại, từ tiếng sanh,\nTham dục và hại tâm,\nNão hại tâm vị ấy,\nNhư vậy, khổ tích lũy,\nÐựơc gọi xa Niết-bàn.\n\nNếm vị, niệm mê say,\nTác ý đến ái tướng,\nTâm tham đắm cảm thọ,\nTham luyến vị an trú.\nVị ấy, thọ tăng trưởng,\nNhiều loại, từ vị sanh,\nTham dục và hại tâm,\nNão hại tâm vị ấy,\nNhư vậy, khổ tích lũy,\nÐược gọi xa Niết-bàn.`, ref: "Tương Ưng Bộ 35.93", url: "https://loicuaducphat.org/sn/sn35.93.html#content" },

{ text: `Vị ấy không tham sắc,\nThấy sắc, không ái luyến,\nTâm không dính cảm thọ,\nKhông luyến sắc an trú.\nTheo sắc, vị ấy thấy,\nTùy sắc, thọ cảm giác,\nTiêu mòn, không tích lũy,\nNhư vậy, chánh niệm hành,\nNhư vậy, khổ không chứa.\nÐược gọi gần Niết-bàn\n\nVị ấy không tham tiếng,\nNghe tiếng, không ái luyến,\nTâm không dính cảm thọ,\nKhông luyến tiếng an trú.\nTheo tiếng, vị ấy nghe,\nTùy tiếng, thọ cảm giác.\nTiêu mòn, không tích lũy,\nNhư vậy, chánh niệm hành,\nNhư vậy, khổ không chứa,\nÐược gọi gần Niết-bàn.\n\nVị ấy không tham hương,\nNgửi hương, không ái luyến,\nTâm không dính cảm thọ,\nKhông luyến hương an trú.\nTheo hương, vị ấy ngửi,\nTùy hương, thọ cảm giác,\nTiêu mòn, không tích lũy,\nNhư vậy, chánh niệm hành,\nNhư vậy, khổ không chứa.\nÐược gọi gần Niết-bàn.\n\nVị ấy không tham vị,\nNếm vị, không ái luyến,\nTâm không dính cảm thọ,\nKhông luyến vị an trú.\nTheo vị, vị ấy nếm.\nTùy vị, thọ cảm giác,\nTiêu mòn, không tích lũy,\nNhư vậy, chánh niệm hành,\nNhư vậy, khổ không chứa.\nÐược gọi gần Niết-bàn.\n\nVị ấy không tham xúc,\nCảm xúc, không ái luyến,\nTâm không dính cảm thọ,\nKhông luyến xúc an trú,\nTheo xúc, vị ấy cảm,\nTùy xúc, thọ cảm giác,\nTiêu mòn, không tích lũy,\nNhư vậy, chánh niệm hành,\nNhư vậy, khổ không chứa,\nÐược gọi gần Niết-bàn.`, ref: "Tương Ưng Bộ 35.93", url: "https://loicuaducphat.org/sn/sn35.93.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là pháp thối đọa? Ở đây, này các Tỷ-kheo, Tỷ-kheo sau khi mắt thấy sắc, các ác, bất thiện pháp; các ức niệm tư duy liên hệ đến kiết sử được khởi lên. Nếu Tỷ-kheo đón nhận chúng, không từ bỏ, không đoạn trừ, không tiêu diệt, không khiến chúng không thể sanh khởi, thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta làm thối thất các thiện pháp”. Ðây Như Lai gọi là pháp thối đọa, … tai nghe tiếng … mũi ngửi hương … … lưỡi nếm vị … thân cảm xúc … Lại nữa, này các Tỷ-kheo, sau khi ý nhận thức pháp, các ác, bất thiện pháp; các ức niệm tư duy liên hệ đến kiết sử được khởi lên. Nếu Tỷ-kheo đón nhận chúng, không từ bỏ, không đoạn trừ, không tiêu diệt, không khiến chúng không thể sanh khởi, thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta làm thối thất các thiện pháp”. Ðây Như Lai gọi là pháp thối đọa. Như vậy, này các Tỷ-kheo, là pháp thối đọa.`, ref: "Tương Ưng Bộ 35.94", url: "https://loicuaducphat.org/sn/sn35.94.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là pháp bất thối đọa? Ở đây, này các Tỷ-kheo, Tỷ-kheo sau khi mắt thấy sắc, các ác, bất thiện pháp; các ức niệm tư duy liên hệ đến kiết sử được khởi lên. Này các Tỷ-kheo, nếu Tỷ-kheo không có đón nhận chúng, từ bỏ, đoạn trừ, tiêu diệt, khiến chúng không thể sanh khởi, thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta không làm thối thất các thiện pháp”. Ðây Như Lai gọi là pháp bất thối đọa … tai nghe tiếng … mũi ngửi hương … … lưỡi nếm vị … thân cảm xúc … Ở đây, này các Tỷ-kheo, sau khi ý nhận thức pháp, các ác, bất thiện pháp; các ức niệm tư duy liên hệ đến kiết sử được khởi lên. Này các Tỷ-kheo, nếu Tỷ-kheo không có đón nhận chúng, từ bỏ, đoạn trừ, tiêu diệt, khiến chúng không thể sanh khởi, thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta không làm thối thất các thiện pháp”. Ðây Như Lai gọi là pháp bất thối đọa. Như vậy, này các Tỷ-kheo, là pháp bất thối đọa.`, ref: "Tương Ưng Bộ 35.94", url: "https://loicuaducphat.org/sn/sn35.94.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là trú phóng dật? Ai sống không nhiếp hộ nhãn căn, này các Tỷ-kheo, thời tâm người ấy bị nhiễm đối với các sắc do mắt nhận biết. Với người tâm bị nhiễm ô thời không có hân hoan. Do không có hân hoan nên không có hỷ. Do không có hỷ nên không có khinh an. Do không khinh an nên khổ an trú. Với người đau khổ, tâm không có thể định tĩnh. Do tâm không định tĩnh, các pháp không hiển lộ. Do các pháp không hiển lộ, người ấy được gọi là người an trú phóng dật … nhĩ căn … tỷ căn … … thiệt căn … thân căn … Ai sống không nhiếp hộ ý căn, tâm bị nhiễm ô đối với các pháp do ý nhận biết. Với người tâm bị nhiễm ô thời không có hân hoan. Do không hân hoan nên không có hỷ. Do không có hỷ nên không có khinh an. Do không có khinh an nên khổ an trú. Với người đau khổ, tâm không có thể định tĩnh. Do tâm không định tĩnh, các pháp không hiển lộ. Do các pháp không hiển lộ, người ấy được gọi là người an trú phóng dật. Như vậy, này các Tỷ-kheo, là an trú phóng dật.`, ref: "Tương Ưng Bộ 35.95", url: "https://loicuaducphat.org/sn/sn35.95.html#content" },

{ text: `Và như thế nào, này các Tỷ-kheo, là an trú không phóng dật? Ai sống nhiếp hộ nhãn căn, tâm không bị nhiễm ô đối với các sắc do mắt nhận biết. Với người tâm không bị nhiễm ô thời hân hoan sanh. Do có hân hoan nên hỷ sanh. Do có hỷ sanh nên thân được khinh an. Do thân khinh an nên cảm lạc thọ. Với người an lạc, tâm được định tĩnh. Do tâm định tĩnh, các pháp được hiển lộ. Do các pháp được hiển lộ, người ấy được gọi là người trú không phóng dật … nhĩ căn … tỷ căn … … thiệt căn … thân căn … Ai sống nhiếp hộ ý căn, tâm không bị nhiễm ô đối với các pháp do ý nhận biết. Với người tâm không bị nhiễm ô thời hân hoan sanh. Do có hân hoan nên hỷ sanh. Do có hỷ tâm nên thân được khinh an. Do thân khinh an nên cảm lạc thọ. Với người an lạc, tâm được định tĩnh. Do tâm định tĩnh, các pháp được hiển lộ. Do các pháp được hiển lộ, người ấy được gọi là người trú không phóng dật. Như vậy, này các Tỷ-kheo, là trú không phóng dật.`, ref: "Tương Ưng Bộ 35.95", url: "https://loicuaducphat.org/sn/sn35.95.html#content" },

{ text: `Và thế nào, này các Tỷ-kheo, là không nhiếp hộ? Và này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ sắc ấy, tán dương và an trú với tâm tham luyến; thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta đã làm thối thất các thiện pháp”. Như Lai gọi đây là pháp thối đọa … Có những tiếng do tai nhận thức … Có những hương do mũi nhận thức … Có những vị do lưỡi nhận thức … Có những xúc do thân cảm giác … Có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ pháp ấy, tán dương và an trú với tâm tham luyến; thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta đã làm thối thất các thiện pháp”. Và Như Lai gọi đây là thối thất. Như vậy, này các Tỷ-kheo, là không nhiếp hộ.`, ref: "Tương Ưng Bộ 35.96", url: "https://loicuaducphat.org/sn/sn35.96.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là nhiếp hộ? Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo không hoan hỷ sắc ấy, không tán dương và an trú với tâm không tham luyến; thời này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta không làm thối thất các thiện pháp”. Và Như Lai gọi đây là không thối thất … Có những tiếng do tai nhận thức … Có những hương do mũi nhận thức … Có những vị do lưỡi nhận thức … Có những xúc do thân cảm giác … Và này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo không hoan hỷ pháp ấy, không tán dương và an trú với tâm không tham luyến; này các Tỷ-kheo, Tỷ-kheo ấy cần phải hiểu rằng: “Ta không làm thối thất các thiện pháp”. Và Như Lai gọi đây là không thối thất. Như vậy, này các Tỷ-kheo, là có nhiếp hộ.`, ref: "Tương Ưng Bộ 35.96", url: "https://loicuaducphat.org/sn/sn35.96.html#content" },

{ text: `- Này các Tỷ-kheo, hãy tu tập Thiền định. Này các Tỷ-kheo, một Tỷ-kheo được Thiền định, hiểu rõ như thật. Và hiểu rõ như thật cái gì? - Như thật hiểu rõ mắt là vô thường, như thật hiểu rõ các sắc là vô thường, như thật hiểu rõ nhãn thức là vô thường, như thật hiểu rõ nhãn xúc là vô thường. Phàm duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; như thật hiểu rõ cảm thọ ấy là vô thường … tai … mũi … lưỡi … thân … Như thật hiểu rõ ý là vô thường, như thật hiểu rõ các pháp là vô thường, như thật hiểu rõ nhãn thức là vô thường, như thật hiểu rõ nhãn xúc là vô thường. Phàm duyên ý xúc, khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; như thật hiểu rõ cảm thọ ấy là vô thường. Này các Tỷ-kheo, hãy tu tập Thiền định. Này các Tỷ-kheo, vị Tỷ-kheo được Thiền định, hiểu rõ như thật.`, ref: "Tương Ưng Bộ 35.97", url: "https://loicuaducphat.org/sn/sn35.97.html#content" },

{ text: `- Cái gì không phải của các Ông, này các Tỷ-kheo, hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc an lạc cho các Ông. Và này các Tỷ-kheo, cái gì không phải của các Ông? Mắt, này các Tỷ-kheo, không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Các sắc không phải của các Ông. Hãy từ bỏ chúng. Từ bỏ chúng, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Nhãn thức không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Nhãn xúc không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Phàm duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông … Tai … Mũi … … Lưỡi … Thân … Ý không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Các pháp không phải của các Ông. Hãy từ bỏ chúng. Từ bỏ chúng, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Ý thức không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Ý xúc không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông. Phàm duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa lại hạnh phúc, an lạc cho các Ông.`, ref: "Tương Ưng Bộ 35.99", url: "https://loicuaducphat.org/sn/sn35.99.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trong rừng Thắng Lâm này có người mang đi, hay mang đốt, hay làm theo những gì người ấy muốn, tất cả cỏ, củi, nhánh cây hay lá, thời các Ông có nghĩ như sau: “Người ấy mang chúng tôi đi, hay đốt chúng tôi, hay làm gì chúng tôi theo ý người ấy muốn”? - Thưa không, bạch Thế Tôn. - Vì sao? Vì chúng không phải tự ngã hay không thuộc về tự ngã. Cũng vậy, này các Tỷ-kheo, mắt không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa đến hạnh phúc, an lạc cho các Ông. Các sắc không phải của các Ông … Nhãn thức không phải của các Ông … Nhãn xúc không phải của các Ông … Do duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy không phải của các Ông. Hãy từ bỏ nó. Từ bỏ nó, sẽ đưa đến hạnh phúc, an lạc cho các Ông.`, ref: "Tương Ưng Bộ 35.99", url: "https://loicuaducphat.org/sn/sn35.99.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là khổ tập khởi? Do duyên mắt và các sắc khởi lên nhãn thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Ðây là khổ tập khởi. Do duyên tai … Do duyên mũi … Do duyên lưỡi … Do duyên thân … Do duyên ý và các pháp khởi lên ý thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Ðây là khổ tập khởi, này các Tỷ-kheo.`, ref: "Tương Ưng Bộ 35.104", url: "https://loicuaducphat.org/sn/sn35.104.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là khổ đoạn diệt? Do duyên mắt và các sắc khởi lên nhãn thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Do ly tham, đoạn diệt ái ấy một cách hoàn toàn nên thủ diệt. Do thủ diệt nên hữu diệt. Do hữu diệt nên sanh diệt. Do sanh diệt nên già chết, sầu, bi, khổ, ưu, não diệt. Ðây là toàn bộ khổ uẩn này đoạn diệt. Ðây là khổ chấm dứt. Do duyên tai … Do duyên mũi … Do duyên lưỡi … Do duyên thân … Do duyên ý và các pháp khởi lên ý thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Do ly tham, đoạn diệt ái ấy một cách hoàn toàn nên thủ diệt. Do thủ diệt nên hữu diệt. Do hữu diệt nên sanh diệt. Do sanh diệt nên già, chết, sầu, bi, ưu, não diệt. Ðây là toàn bộ khổ uẩn này đoạn diệt. Ðây là khổ chấm dứt.`, ref: "Tương Ưng Bộ 35.104", url: "https://loicuaducphat.org/sn/sn35.104.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là thế giới tập khởi? Do duyên mắt và các sắc khởi lên nhãn thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Do duyên ái nên có thủ. Do duyên thủ nên có hữu. Do duyên hữu nên có sanh. Do duyên sanh nên có già chết, sầu, bi, khổ, ưu, não sanh khởi. Ðây là thế giới tập khởi. Do duyên tai … Do duyên mũi … Do duyên lưỡi … Do duyên thân … Và do duyên ý và các pháp khởi lên ý thức. Do ba pháp này họp lại nên có xúc. Do duyên xúc nên có thọ. Do duyên thọ nên có ái. Do duyên ái nên có thủ. Do duyên thủ nên có hữu. Do duyên hữu nên có sanh. Do duyên sanh nên có già, chết, sầu, bi, khổ, ưu, não sanh khởi. Này các Tỷ-kheo, đây là thế giới tập khởi.`, ref: "Tương Ưng Bộ 35.105", url: "https://loicuaducphat.org/sn/sn35.105.html#content" },

{ text: `- Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu một Tỷ-kheo hoan hỷ sắc ấy, tán dương, tham luyến an trú; thời này các Tỷ-kheo, đây gọi là Tỷ-kheo đã đi đến trú xứ của Ma, đã bị Ma chinh phục. Lưới bẫy của Ma đoanh vây vị ấy. Bị Ma trói buộc, vị ấy bị Ác ma muốn làm gì vị ấy thì làm … Này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ pháp ấy, tán dương, tham luyến an trú; thời này các Tỷ-kheo, đây gọi là Tỷ-kheo đã đi đến trú xứ của Ma, đã bị Ma chinh phục. Lưới bẫy của Ma đoanh vây vị ấy. Bị Ma trói buộc, vị ấy bị Ác ma muốn làm gì vị ấy thì làm.`, ref: "Tương Ưng Bộ 35.112", url: "https://loicuaducphat.org/sn/sn35.112.html#content" },

{ text: `- Này các Tỷ-kheo, trước khi Ta chưa giác ngộ, chưa thành Chánh đẳng Chánh giác, còn là Bồ-tát, Ta khởi lên ý nghĩ như sau: “Năm dục công đức mà tâm Ta trước kia cảm xúc, đã thuộc quá khứ, đã đoạn diệt, đã biến hoại; ở đây, tâm Ta đi đến cuồng nhiệt khi chúng có mặt hiện tại, và trở thành giảm thiểu khi chúng chưa đến, còn ở vị lai”. Rồi, này các Tỷ-kheo, Ta suy nghĩ như sau: “Năm dục công đức mà tâm Ta trước kia cảm xúc, đã thuộc quá khứ, đã đoạn diệt, đã biến hoại. Ở đây, vì lợi ích cho chính Ta, hãy sống không phóng dật, gìn giữ tâm chánh niệm”. Do vậy, này các Tỷ-kheo, đối với năm dục công đức mà tâm các Ông trước đây cảm xúc, đã thuộc quá khứ, đã đoạn diệt, đã biến hoại; ở đây, tâm các Ông đi đến cuồng nhiệt khi chúng có mặt hiện tại, và trở thành giảm thiểu khi chúng chưa đến, còn ở vị lai. Do vậy, này các Tỷ-kheo, đối với năm dục công đức mà tâm các Ông trước đây cảm xúc, đã thuộc quá khứ, đã đoạn diệt, đã biến hoại. Ở đây, vì lợi ích cho chính các Ông, hãy sống không phóng dật, gìn giữ tâm chánh niệm.`, ref: "Tương Ưng Bộ 35.115", url: "https://loicuaducphat.org/sn/sn35.115.html#content" },

{ text: `- Bạch Thế Tôn, do nhân gì, do duyên gì, ở đây một số loài hữu tình ngay trong hiện tại không nhập Niết-bàn? Bạch Thế Tôn, do nhân gì, do duyên gì, ở đây một số loài hữu tình ngay trong hiện tại nhập được Niết-bàn? - Này Thiên chủ, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ sắc ấy, tán dương, tham luyến an trú, y cứ vào đấy, thức khởi lên chấp thủ cái ấy. Vì có chấp thủ, này Thiên chủ, Tỷ-kheo ấy không nhập Niết-bàn. Này Thiên chủ, có những tiếng do tai nhận thức … có những hương do mũi nhận thức … có những vị do lưỡi nhận thức … có những xúc do thân cảm giác … Này Thiên chủ, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo hoan hỷ pháp ấy, tán dương, tham luyến an trú. Do Tỷ-kheo ấy hoan hỷ pháp ấy, tán dương, tham luyến an trú, y cứ vào đấy, thức khởi lên chấp thủ cái ấy. Do có chấp thủ, này Thiên chủ, Tỷ-kheo ấy không nhập Niết-bàn.`, ref: "Tương Ưng Bộ 35.116", url: "https://loicuaducphat.org/sn/sn35.116.html#content" },

{ text: `Và này Thiên chủ, có những sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ sắc ấy, không tán dương, không tham luyến an trú; thời do vị ấy không hoan hỷ sắc ấy, không tán dương, không tham luyến an trú, không y cứ cái ấy, thức khởi lên không chấp thủ cái ấy. Do không chấp thủ, này Thiên chủ, Tỷ-kheo nhập Niết-bàn. Có những tiếng do tai nhận thức … Có những hương do mũi nhận thức … Có những vị do lưỡi nhận thức … Có những xúc do thân cảm giác … Này Thiên chủ, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Nếu Tỷ-kheo không hoan hỷ pháp ấy, không tán dương, không tham luyến an trú; thời do Tỷ-kheo ấy không hoan hỷ pháp ấy, không tán dương, không tham luyến an trú, không y cứ vào cái ấy, thức khởi lên không chấp thủ cái ấy. Không chấp thủ, này Thiên chủ, Tỷ-kheo ấy nhập Niết-bàn. Này Thiên chủ, đây là nhân, đây là duyên, do vậy ở đây một số loài hữu tình ngay trong hiện tại nhập Niết-bàn.`, ref: "Tương Ưng Bộ 35.116", url: "https://loicuaducphat.org/sn/sn35.116.html#content" },

{ text: `Ngồi xuống một bên, Tỷ-kheo ấy nói với Tôn giả Sāriputta: - Tỷ-kheo đồng trú, thưa Tôn giả Sāriputta, đã từ bỏ học pháp và hoàn tục. - Này Hiền giả, như vậy xẩy đến cho vị nào không hộ trì các căn, không tiết độ trong ăn uống, không chú tâm tỉnh giác. Cho đến trọn đời, vị ấy có thể tiếp tục đời sống Phạm hạnh hoàn toàn thanh tịnh, sự việc như vậy không xảy ra. Này Hiền giả, một Tỷ-kheo hộ trì các căn, tiết độ trong ăn uống, chú tâm tỉnh giác. Cho đến trọn đời, vị ấy có thể tiếp tục đời sống Phạm hạnh hoàn toàn thanh tịnh, sự việc như vậy có xảy ra. Do vậy, này Hiền giả, cần phải học tập như sau: “Chúng tôi sẽ hộ trì các căn, tiết độ trong ăn uống, chú tâm tỉnh giác”. Như vậy, này Hiền giả, ông cần phải học tập.`, ref: "Tương Ưng Bộ 35.118", url: "https://loicuaducphat.org/sn/sn35.118.html#content" },

{ text: `Và này Hiền giả, thế nào là hộ trì các căn? Này Hiền giả, khi mắt thấy sắc, Tỷ-kheo không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, vì đó nhãn căn không được chế ngự, khiến tham ái, ưu bi, các ác bất thiện pháp khởi lên, Tỷ-kheo tự chế ngự những nguyên nhân ấy, hộ trì nhãn căn, thực hành sự hộ trì nhãn căn. Khi tai nghe tiếng … khi mũi ngửi hương … khi lưỡi nếm vị … khi thân cảm xúc … khi ý nhận thức các pháp, vị ấy không nắm giữ tướng chung, không nắm giữ tướng riêng. Những nguyên nhân gì, vì đó ý căn không được chế ngự, khiến tham ái, ưu bi, các ác bất thiện pháp khởi lên, Tỷ-kheo tự chế ngự những nguyên nhân ấy, hộ trì ý căn, thực hành sự hộ trì ý căn. Như vậy, này Hiền giả, là sự hộ trì các căn.`, ref: "Tương Ưng Bộ 35.118", url: "https://loicuaducphat.org/sn/sn35.118.html#content" },

{ text: `Này Hiền giả, thế nào là tiết độ trong ăn uống? Ở đây, này Hiền giả, Tỷ-kheo như lý giác sát, thọ dụng các món ăn. Không phải để vui đùa, không phải để đam mê, không phải để trang sức, không phải để tự mình làm đẹp mình mà chỉ để thân này được duy trì và được bảo dưỡng, để thân này khỏi bị thương hại, để hỗ trợ Phạm hạnh, nghĩ rằng: “Như vậy, ta diệt trừ các cảm thọ cũ và không cho khởi lên các cảm thọ mới, và ta sẽ không có lỗi lầm, sống được an ổn”. Như vậy, này Hiền giả, là tiết độ trong ăn uống.`, ref: "Tương Ưng Bộ 35.118", url: "https://loicuaducphat.org/sn/sn35.118.html#content" },

{ text: `Và này Hiền giả, như thế nào là chú tâm tỉnh giác? Ở đây, này Hiền giả, Tỷ-kheo ban ngày trong khi đi kinh hành và ngồi, tâm gột sạch các pháp triền cái. Ban đêm trong canh một, trong khi vị ấy đi kinh hành và ngồi, tâm gột sạch các pháp triền cái. Ban đêm trong canh giữa, vị ấy nằm phía hông bên hữu, trong tư thế con sư tử, chân này đặt trên chân kia, chánh niệm tỉnh giác, tác ý tưởng đến lúc ngồi dậy. Ban đêm trong canh cuối, khi vị ấy đi kinh hành và trong khi ngồi, tâm gột sạch khỏi các pháp triền cái. Như vậy, này Hiền giả, là chú tâm tỉnh giác.`, ref: "Tương Ưng Bộ 35.118", url: "https://loicuaducphat.org/sn/sn35.118.html#content" },
{ text: `- Thưa Bharadvāja, do nhân gì, do duyên gì, những Tỷ-kheo trẻ tuổi này, còn non trẻ, tóc đen nhánh, đầy đủ với tuổi trẻ hiền thiện, trong lúc tuổi còn thanh xuân lại không tham nhiễm dục vọng, thực hành Phạm hạnh hoàn toàn thanh tịnh cho đến trọn đời, và sống toàn thời gian một cách hoàn mãn? - Thưa Ðại vương, Thế Tôn, bậc Tri giả, Kiến giả, bậc A-la-hán, Chánh Ðẳng Giác đã nói như sau: “Hãy đến, này các Tỷ-kheo, đối với những người chỉ là mẹ, hãy an trú tâm người mẹ. Ðối với những người chỉ là chị, hãy an trú tâm người chị. Ðối với người chỉ là con gái, hãy an trú tâm người con gái. Thưa Ðại Vương, đây là nhân, đây là duyên, do vậy các Tỷ-kheo trẻ tuổi này, còn non trẻ, tóc đen nhánh, đầy đủ với tuổi trẻ hiền thiện, trong lúc tuổi còn thanh xuân lại không tham nhiễm dục vọng, thực hành Phạm hạnh hoàn toàn thanh tịnh cho đến trọn đời, và sống toàn thời gian một cách hoàn mãn.`, ref: "Tương Ưng Bộ 35.125", url: "https://loicuaducphat.org/sn/sn35.125.html#content" },

{ text: `- Tham vọng, này Bharadvāja, là tâm. Ðôi khi đối với những người chỉ là mẹ, tham pháp khởi lên. Ðối với những người chỉ là chị, tham pháp khởi lên. Ðối với những người chỉ là con gái, tham pháp khởi lên. Này Bharadvāja, có một nhân khác, có một duyên khác, do vậy các Tỷ-kheo trẻ tuổi này … một cách hoàn mãn? - Thưa Ðại vương, Thế Tôn, bậc Tri giả, Kiến giả, bậc A-la-hán, Chánh Ðẳng Giác đã nói như sau: “Hãy đến, này các Tỷ-kheo, hãy quán sát thân này dưới từ bàn chân trở lên, trên từ đảnh tóc trở xuống, bao bọc bởi da và chứa đầy bất tịnh sai biệt. Trong thân này, đây là tóc, lông, móng, răng, da, thịt, gân, xương, tủy, thận, tim, gan, hoành cách mô, lá lách, phổi, ruột, bao tử, phân, mật, đàm, mủ, máu, mồ hôi, mỡ, nước mắt, mỡ da, nước miếng, nước mủ, nước ở khớp xương, nước tiểu. Thưa Ðại vương, đây là nhân, đây là duyên, do vậy các Tỷ-kheo trẻ tuổi này thực hành Phạm hạnh hoàn toàn thanh tịnh cho đến trọn đời, và sống toàn thời gian một cách hoàn mãn.`, ref: "Tương Ưng Bộ 35.125", url: "https://loicuaducphat.org/sn/sn35.125.html#content" },

{ text: `- Thật vi diệu thay, thưa Tôn giả Bharadvāja! Thật hy hữu thay, thưa Tôn giả Bharadvāja, là lời khéo nói này của Thế Tôn, bậc Tri giả, Kiến giả, bậc A-la-hán, Chánh Ðẳng Giác. Chính nhân này, thưa Tôn giả Bharadvāja, chính duyên này, do vậy các Tỷ-kheo trẻ tuổi này, còn non trẻ, tóc đen nhánh, đầy đủ với tuổi trẻ hiền thiện, trong lúc tuổi còn thanh xuân, lại không tham nhiễm dục vọng, thực hành Phạm hạnh hoàn toàn thanh tịnh cho đến trọn đời, sống toàn thời gian một cách hoàn mãn. Tôi cũng vậy, thưa Tôn giả Bharadvāja, khi nào tôi vào trong nội cung với thân không phòng hộ, với lời nói không phòng hộ, với tâm không phòng hộ, với niệm không an trú, với các căn không chế ngự; thời trong khi ấy, tham pháp chinh phục tôi. Nhưng thưa Tôn giả Bharadvāja, trong khi tôi vào nội cung, với thân được phòng hộ, với lời nói được phòng hộ, với tâm được phòng hộ, với niệm được an trú, với các căn được chế ngự; thời trong khi ấy, tham pháp không chinh phục tôi.`, ref: "Tương Ưng Bộ 35.125", url: "https://loicuaducphat.org/sn/sn35.125.html#content" },

{ text: `Những bậc cổ nhân xưa,\nTối thắng trong giới hạnh,\nCác bậc Bà-la-môn,\nGhi nhớ các cổ luật.\nCác căn được hộ trì,\nÐược khéo léo chế ngự,\nHọ nhiếp phục đoạn tận\nMọi tức giận phẫn nộ.\n\nHọ hân hoan trong pháp,\nHọ hân hoan trong Thiền,\nHọ là Bà-la-môn,\nGhi nhớ các cổ luật.\nCòn kẻ trốn luật này,\nChỉ lắp bắp tụng đọc,\nSay mê trong giai cấp,\nHọ bước đi khập khểnh.\n\nBị phẫn nộ nhiếp phục,\nDùng nhiều loại gậy gộc,\nHọ rơi vào nguy hại,\nGiữa kẻ tham, bậc Thánh,\nRỗng không là giới cấm,\nKhi căn không chế ngự,\nNhư người được tài sản,\nTrong cơn mộng nằm mơ.\n\nKhông ăn, quyết nhịn đói,\nNằm ngủ trên đất trần,\nSáng dậy, tắm sạch tội,\nTụng đọc ba Vệ-đà,\nMặc da thú thô cứng,\nBện tóc, da dính bùn,\nTụng đọc các thần chú,\nGiới cấm thủ, khổ hạnh.\n\nGiả dối và lừa đảo,\nSử dụng các gậy gộc,\nDùng nước để tắm rửa,\nDùng nước để súc miệng,\nÐó là những sắc tướng,\nCác hàng Bà-la-môn,\nHọ làm và thực hiện,\nMong hưởng những lợi nhỏ.\n\nNhất tâm, khéo định tĩnh,\nTrong sáng, không cấu uế,\nNhu thuận mọi chúng sanh,\nCon đường đạt tối thượng.`, ref: "Tương Ưng Bộ 35.130", url: "https://loicuaducphat.org/sn/sn35.130.html#content" },

{ text: `- Tôn giả Kaccāna có nói đến hộ trì các căn. Cho đến như thế nào, thưa Tôn giả Kaccāna, là hộ trì các căn? - Ở đây, này Bà-la-môn, có người sau khi mắt thấy sắc, có tâm hướng đến các sắc khả ái, có tâm ghét bỏ các sắc không khả ái, sống với niệm không an trú, với tâm nhỏ hẹp. Người ấy không như thật biết rõ tâm giải thoát và tuệ giải thoát. Do vậy, các ác bất thiện pháp đã khởi lên, không có đoạn diệt không có dư tàn. … sau khi tai nghe tiếng … sau khi mũi ngửi hương … sau khi lưỡi nếm vị … sau khi thân cảm xúc … … sau khi ý biết các pháp, tâm hướng đến các pháp khả ái, tâm ghét bỏ các pháp không khả ái, sống với niệm không an trú, với tâm nhỏ hẹp. Người ấy không như thật biết rõ tâm giải thoát và tuệ giải thoát. Do vậy, các ác bất thiện pháp đã khởi lên, không có đoạn diệt không có dư tàn. Như vậy, này Bà-la-môn, là các căn không có hộ trì.`, ref: "Tương Ưng Bộ 35.130", url: "https://loicuaducphat.org/sn/sn35.130.html#content" },

{ text: `- Thật là vi diệu, thưa Tôn giả Kaccāna, thật là hy hữu, thưa Tôn giả Kaccāna, cách thức Tôn giả Kaccāna đã định nghĩa các căn không hộ trì. Các căn có hộ trì, các căn có hộ trì, Tôn giả Kaccāna đã nói như vậy; cho đến như thế nào, thưa Tôn giả Kaccāna, là các căn có hộ trì? - Ở đây, này Bà-la-môn, Tỷ-kheo sau khi mắt thấy sắc, tâm không hướng đến các sắc khả ái, tâm không ghét bỏ các sắc không khả ái, sống với niệm an trú, với tâm vô lượng. Vị ấy như thật biết rõ tâm giải thoát và tuệ giải thoát. Do vậy, các ác bất thiện pháp đã khởi lên được đoạn diệt không có dư tàn. … sau khi tai nghe tiếng … sau khi mũi ngửi hương … sau khi lưỡi nếm vị … sau khi thân cảm xúc … … sau khi ý nhận biết các pháp, tâm không hướng đến các pháp khả ái, tâm không ghét bỏ các pháp không khả ái, sống với niệm an trú, với tâm vô lượng. Vị ấy như thật biết rõ tâm giải thoát và tuệ giải thoát. Do vậy, các ác bất thiện pháp đã khởi lên được đoạn diệt không có dư tàn. Như vậy, này Bà-la-môn, là các căn được hộ trì.`, ref: "Tương Ưng Bộ 35.130", url: "https://loicuaducphat.org/sn/sn35.130.html#content" },

{ text: `Này các Tỷ-kheo, có những sắc do mắt nhận thức khả ái và không khả ái. Dầu chúng xúc chạm tâm nhiều lần, chúng không chi phối được tâm và tồn tại. Do tâm không bị chi phối, tinh cần, tinh tấn khởi lên, không có biếng nhác; niệm được an trú, không có thất thoát; thân được khinh an, không có cuồng nhiệt; tâm được định tĩnh, nhất tâm. Này các Tỷ-kheo, thấy được quả không phóng dật này, đối với những Tỷ-kheo ấy. Ta tuyên bố rằng, cần phải cố gắng không phóng dật đối với sáu xúc xứ. Này các Tỷ-kheo, có những tiếng do tai nhận thức … có những hương do mũi nhận thức … có những vị do lưỡi nhận thức … có những xúc do thân nhận thức … Này các Tỷ-kheo, có những pháp do ý nhận thức khả ái và không khả ái. Dầu chúng xúc chạm tâm nhiều lần, chúng không chi phối được tâm và tồn tại. Do tâm không bị chi phối, tinh cần, tinh tấn khởi lên, không có biếng nhác; niệm được an trú, không có thất thoát; thân được khinh an, không cuồng nhiệt; tâm được định tĩnh, nhất tâm. Này các Tỷ-kheo, thấy được quả không phóng dật này, đối với những Tỷ-kheo ấy, Ta tuyên bố rằng, cần phải cố gắng không phóng dật đối với sáu xúc xứ.`, ref: "Tương Ưng Bộ 35.132", url: "https://loicuaducphat.org/sn/sn35.132.html#content" },

{ text: `Này các Tỷ-kheo, Ta đã thấy các địa ngục gọi là sáu xúc xứ địa ngục. Ở đấy, phàm mắt thấy sắc gì, thấy sắc không khả lạc, không phải sắc khả lạc; thấy sắc không khả hỷ, không phải sắc khả hỷ; thấy sắc không khả ý, không phải sắc khả ý. Phàm tai nghe tiếng gì … Phàm mũi ngửi hương gì … Phàm lưỡi nếm vị gì … Phàm thân cảm xúc gì … Phàm ý nhận thức pháp gì, nhận thức pháp không khả lạc, không phải pháp khả lạc; nhận thức không phải khả hỷ, không phải pháp khả hỷ; nhận thức pháp không khả ý, không phải pháp khả ý. Này các Tỷ-kheo, các Ông được lợi đắc. Này các Tỷ-kheo, các Ông được khéo lợi đắc. Các Ông đã nắm được cơ hội để sống Phạm hạnh.`, ref: "Tương Ưng Bộ 35.133", url: "https://loicuaducphat.org/sn/sn35.133.html#content" },

{ text: `Này các Tỷ-kheo, Ta đã thấy các Thiên giới gọi là sáu xúc xứ Thiên giới. Tại đấy, phàm mắt thấy sắc gì, thấy sắc khả lạc, không phải sắc không lạc; thấy sắc khả hỷ, không phải sắc không khả hỷ; thấy sắc khả ý, không phải sắc không khả ý. Phàm tai nghe tiếng gì … Phàm mũi ngửi hương gì … Phàm lưỡi nếm vị gì … Phàm thân cảm xúc gì … Phàm ý nhận thức pháp gì, nhận thức pháp khả lạc, không phải không khả lạc; nhận thức pháp khả hỷ, không phải không khả hỷ; nhận thức pháp khả ý, không phải pháp không khả ý. Này các Tỷ-kheo, các Ông được lợi đắc. Này các Tỷ-kheo, các Ông được khéo lợi đắc. Các Ông đã nắm được cơ hội để sống Phạm hạnh.`, ref: "Tương Ưng Bộ 35.133", url: "https://loicuaducphat.org/sn/sn35.133.html#content" },

{ text: `Này các Tỷ-kheo, chư Thiên và Người đời thích thú sắc, bị sắc kích thích. Khi sắc biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, chư Thiên và Người đời sống đau khổ … thích thú tiếng … thích thú hương … thích thú vị … thích thú xúc … Này các Tỷ-kheo, chư Thiên và Người đời thích thú pháp, bị pháp kích thích. Khi pháp biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, chư Thiên và Người đời sống đau khổ. Này các Tỷ-kheo, Như Lai, bậc A-la-hán, Chánh Ðẳng Giác, sau khi như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và xuất ly của sắc, không có thích thú sắc, không có ưa thích sắc, không bị sắc kích thích. Khi sắc biến hoại, ly tham, đoạn diệt, này các Tỷ-kheo, Như Lai sống an lạc … không thích thú tiếng … không thích thú hương … không thích thú vị … không thích thú xúc … Sau khi như thật biết rõ sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của pháp, Như Lai không thích thú pháp, không ưa thích pháp, không bị pháp kích thích. Khi pháp biến hoại, ly tham, đoạn diệt, Như Lai sống an lạc.`, ref: "Tương Ưng Bộ 35.134", url: "https://loicuaducphat.org/sn/sn35.134.html#content" },

{ text: `Sắc, thanh, hương, vị, xúc,\nVà toàn thể các pháp,\nKhả lạc, hỷ, khả ý,\nNhư vậy, chúng được gọi.\n\nChư Thiên và Người đời,\nXem chúng là khả lạc,\nChỗ nào chúng đoạn diệt,\nThiên, Nhân thấy đau khổ.\n\nBậc Thánh thấy an lạc,\nKhi thân kiến đoạn diệt,\nBậc Thánh xem trái ngược,\nMọi quan điểm của đời.\n\nÐiều người gọi là lạc,\nBậc Thánh gọi là khổ.\nÐiều người gọi là khổ,\nThánh nhân biết là lạc.\n\nThấy pháp khó nhận biết,\nKẻ vô trí mê loạn,\nTối tăm đối vô minh,\nMù lòa đối không thấy.\n\nThiện nhân mắt rộng mở,\nThấy rõ ràng ánh sáng,\nSống gần, biết rõ ràng,\nThuần thục trong pháp lớn.\n\nBị tham sanh chinh phục,\nBị dòng hữu cuốn trôi,\nBị Ác ma chi phối,\nKhông giác ngộ pháp này.\n\nNgoài Thánh không có ai,\nGiác ngộ con đường này,\nCon đường đạt Niết-bàn,\nChánh trí thoát lậu hoặc.`, ref: "Tương Ưng Bộ 35.134", url: "https://loicuaducphat.org/sn/sn35.134.html#content" },

{ text: `- Này các Tỷ-kheo, hãy tu tập Thiền định. Này các Tỷ-kheo, Tỷ-kheo có tâm định tĩnh, sự vật như thật hiển hiện. Và sự vật gì như thật hiển hiện? Mắt vô thường như thật hiển hiện. Các sắc vô thường như thật hiển hiện. Nhãn thức vô thường như thật hiển hiện. Nhãn xúc vô thường như thật hiển hiện. Phàm duyên nhãn xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy vô thường như thật hiển hiện. Tai … Mũi … Lưỡi … Thân … Ý vô thường như thật hiển hiện. Các pháp vô thường như thật hiển hiện. Ý thức vô thường như thật hiển hiện. Ý xúc vô thường như thật hiển hiện. Phàm duyên ý xúc khởi lên cảm thọ gì, lạc, khổ, hay bất khổ bất lạc; cảm thọ ấy vô thường như thật hiển hiện. Này các Tỷ-kheo, hãy tu tập Thiền định. Tỷ-kheo có tâm định tĩnh, sự vật như thật hiển hiện.`, ref: "Tương Ưng Bộ 35.156", url: "https://loicuaducphat.org/sn/sn35.156.html#content" },

{ text: `Này các Tỷ-kheo, có những sắc do mắt nhận thức khả lạc, khả hỷ, khá ý, khả ái, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, đây không gọi là biển trong giới luật của bậc Thánh. Ở đây, thế giới này với Thiên giới, với Ma giới, với Phạm thiên giới, với quần chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người, phần lớn chìm đắm trong ấy, bị rối ren như cuộn chỉ, bị bao trùm như cuộn dây, thành như sợi dây bện bằng cỏ, không thể vượt qua cõi dữ, ác thú, đọa xứ, luân hồi! Này các Tỷ-kheo, có những tiếng do tai nhận thức … có những hương do mũi nhận thức … có những vị do lưỡi nhận thức … có những xúc do thân nhận thức … Này các Tỷ-kheo, có những pháp do ý nhận thức khả lạc, khả hỷ, khả ái, khả ý, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, đây không gọi là biển trong giới luật của bậc Thánh. Ở đây, thế giới này với Thiên giới, với Ma giới, với Phạm thiên giới, với quần chúng Sa-môn, Bà-la-môn, với chư Thiên và loài Người, phần lớn chìm đắm trong ấy, bị rối ren như cuộn chỉ, bị bao trùm như cuộn dây, thành như sợi dây bện bằng cỏ, không thể vượt qua cõi dữ, ác thú, đọa xứ, luân hồi!`, ref: "Tương Ưng Bộ 35.225", url: "https://loicuaducphat.org/sn/sn35.225.html#content" },

{ text: `Như rùa dấu thân phần,\nTrong mai rùa của nó.\nCũng vậy, vị Tỷ-kheo,\nThâu nhóm mọi tâm tư,\nKhông nương tựa một ai,\nKhông hại một người nào,\nHoàn toàn đạt tịch tịnh,\nKhông nói xấu một ai.`, ref: "Tương Ưng Bộ 35.236", url: "https://loicuaducphat.org/sn/sn35.236.html#content" },

{ text: `- Này các Tỷ-kheo, các Ông có thấy khúc gỗ to lớn này đang trôi theo dòng nước sông Hằng không? - Thưa có, bạch Thế Tôn. - Này các Tỷ-kheo, nếu khúc gỗ không đâm vào bờ bên này, không đâm vào bờ bên kia, không chìm giữa dòng, không mắc cạn trên miếng đất nổi, không bị loài Người nhặt lấy, không bị phi nhân nhặt lấy, không bị mắc vào xoáy nước, không bị mục bên trong; như vậy, này các Tỷ-kheo, khúc gỗ ấy sẽ hướng về biển, sẽ xuôi theo biển, sẽ nghiêng nhập vào biển. Vì sao? Vì rằng, này các Tỷ-kheo, dòng sông Hằng hướng về biển, xuôi theo biển, nghiêng trôi về biển. Cũng vậy, này các Tỷ-kheo, nếu các Ông không đâm vào bờ bên này, không đâm vào bờ bên kia, không chìm giữa dòng, không mắc cạn trên miếng đất nổi, không bị loài Người nhặt lấy, không bị phi nhân nhặt lấy, không bị mắc vào xoáy nước, không bị mục bên trong; như vậy, này các Tỷ-kheo, các Ông sẽ hướng về Niết-bàn, sẽ xuôi theo Niết-bàn, sẽ nghiêng nhập vào Niết-bàn. Vì sao? Vì rằng, này các Tỷ-kheo, chánh kiến hướng về Niết-bàn, xuôi theo Niết-bàn, nghiêng nhập vào Niết-bàn.`, ref: "Tương Ưng Bộ 35.237", url: "https://loicuaducphat.org/sn/sn35.237.html#content" },

{ text: `- Bạch Thế Tôn, bờ bên này là gì? Bờ bên kia là gì? Thế nào là chìm giữa dòng? Thế nào là mắc cạn trên miếng đất nổi? Thế nào là bị loài Người nhặt lấy? Thế nào là bị phi nhân nhặt lấy? Thế nào là bị mắc vào xoáy nước? Thế nào là bị mục nát bên trong? - Bờ bên này, này Tỷ-kheo, là đồng nghĩa với sáu nội xứ này. Bờ bên kia, này Tỷ-kheo, là đồng nghĩa với sáu ngoại xứ. Bị chìm giữa dòng, này Tỷ-kheo, là đồng nghĩa với hỷ tham. Bị mắc cạn trên miếng đất nổi, này Tỷ-kheo, là đồng nghĩa với ngã mạn. Và này Tỷ-kheo, thế nào là bị người nhặt lấy? Ở đây, Tỷ-kheo sống quá liên hệ với cư sĩ, chung vui, chung buồn, an lạc khi họ an lạc, đau khổ khi họ bị đau khổ, tự trói buộc mình trong các công việc phải làm được khởi lên của họ. Ðây gọi là Tỷ-kheo bị loài Người nhặt lấy. Và thế nào, này Tỷ-kheo, là bị phi nhân nhặt lấy? Ở đây, Tỷ-kheo sống Phạm hạnh với ước nguyện được sanh cộng trú với một hạng chư Thiên: “Mong rằng với giới luật này, với cấm giới này, với khổ hạnh này, với Phạm hạnh này, ta sẽ trở thành Thiên nhân hay một loài chư Thiên!” Ðây, này Tỷ-kheo, được gọi là bị phi nhân nhặt lấy. Bị mắc vào xoáy nước, này Tỷ-kheo, là đồng nghĩa với năm dục công đức. Và này Tỷ-kheo, thế nào là bị mục nát bên trong? Ở đây, này Tỷ-kheo, có người thọ tà giới, theo ác pháp, bất tịnh, có những hành vi đáng nghi ngờ, có những hành động che đậy, không phải Sa-môn nhưng hiện tướng Sa-môn, không phải Phạm hạnh nhưng hiện tướng Phạm hạnh, nội tâm bị hủ bại, đầy dục vọng, là một đống rác bẩn. Ðây, này Tỷ-kheo, được gọi là bị mục nát bên trong.`, ref: "Tương Ưng Bộ 35.237", url: "https://loicuaducphat.org/sn/sn35.237.html#content" },

{ text: `- Và này chư Hiền, thế nào là nhiễm dục lậu? Ở đây, này chư Hiền, Tỷ-kheo khi mắt thấy sắc, thiên chấp sắc khả ái, ghét bỏ các sắc không khả ái, sống với thân niệm không an trú, với tâm nhỏ hẹp. Vị ấy không như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở đây, các ác bất thiện pháp ấy khởi lên không được trừ diệt không có dư tàn … Khi lưỡi nếm vị … Khi ý biết các pháp, thiên chấp pháp khả ái, ghét bỏ pháp không khả ái, sống với thân niệm không an trú, với tâm nhỏ hẹp. Vị ấy không như thật rõ biết tâm giải thoát, tuệ giải thoát ấy. Chính ở đây, các ác bất thiện pháp ấy khởi lên không được trừ diệt không có dư tàn. Này chư Hiền, đây gọi là Tỷ-kheo bị nhiễm dục lậu đối với các sắc do mắt nhận thức … đối với các vị do lưỡi nhận thức … đối với các pháp do ý nhận thức. Tỷ-kheo sống như vậy, này chư Hiền, nếu Māra có đến vị ấy, ngang qua mắt, Māra nắm được cơ hội, Māra nắm được đối tượng … Nếu Māra có đến vị ấy, ngang qua lưỡi, Māra nắm được cơ hội, Māra nắm được đối tượng … Nếu Māra có đến vị ấy, ngang qua ý, Māra nắm được cơ hội, Māra nắm được đối tượng.`, ref: "Tương Ưng Bộ 35.239", url: "https://loicuaducphat.org/sn/sn35.239.html#content" },

{ text: `Và này chư Hiền, thế nào là không nhiễm dục lậu? Ở đây, này chư Hiền, Tỷ-kheo khi mắt thấy sắc, không thiên chấp sắc khả ái, không ghét bỏ sắc không khả ái, sống an trú thân niệm, với tâm vô lượng. Vị ấy như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở nơi đây, các ác bất thiện pháp khởi lên được đoạn diệt không có dư tàn … Khi lưỡi nếm vị … Khi ý biết các pháp, vị ấy không thiên chấp các pháp khả ái, không ghét bỏ các pháp không khả ái, sống an trú thân niệm, với tâm vô lượng. Vị ấy như thật biết rõ tâm giải thoát, tuệ giải thoát. Chính ở nơi đây, các ác bất thiện pháp khởi lên được đoạn diệt không có dư tàn. Này chư Hiền, đây gọi là vị Tỷ-kheo không bị nhiễm dục lậu đối với các sắc do mắt nhận thức … đối với các vị do lưỡi nhận thức … đối với các pháp do ý nhận thức … Tỷ-kheo sống như vậy, này chư Hiền, nếu Māra có đến vị ấy, ngang qua mắt, Māra không nắm được cơ hội, Māra không nắm được đối tượng … Nếu Māra có đến vị ấy, ngang qua lưỡi, Māra không nắm được cơ hội, Māra không nắm được đối tượng … Nếu Māra có đến vị ấy, ngang qua ý, Māra không nắm được cơ hội, Māra không nắm được đối tượng.`, ref: "Tương Ưng Bộ 35.239", url: "https://loicuaducphat.org/sn/sn35.239.html#content" },

{ text: `Và này các Tỷ-kheo, như thế nào là Tỷ-kheo thấy được các dục? Khi các dục được thấy, thời dục, dục ái, dục mê, dục nhiệt não đối với các dục không có tùy miên. Ví như, này các Tỷ-kheo, có một hố than sâu hơn thân người, đầy vun than hừng, không có ngọn, không có khói. Rồi có người đi đến, muốn sống, không muốn chết, muốn lạc, ghét bỏ khổ. Rồi hai người lực sĩ đến, kẹp người ấy vào trong các cánh tay, và kéo người ấy đến hố than hừng. Người ấy vật vã thân bên này, bên kia. Vì sao? Này các Tỷ-kheo, người ấy được biết rằng: “Ta sẽ rơi vào trong hố than hừng này. Do nhân này, ta sẽ đi đến chết hay đau khổ gần như chết”. Cũng vậy, này các Tỷ-kheo, Tỷ-kheo thấy các dục như hố than hừng và ai thấy được các dục, thời dục, dục ái, dục mê, dục nhiệt não đối với các dục không có tùy miên.`, ref: "Tương Ưng Bộ 35.240", url: "https://loicuaducphat.org/sn/sn35.240.html#content" },

{ text: `Thế nào, này các Tỷ-kheo, là sở hành và sở trú của Tỷ-kheo được giác tri? Vì rằng, do sở hành như vậy, các tham ái, ưu bi, các ác bất thiện pháp không có tồn chỉ. Ví như, này các Tỷ-kheo, một người đi vào một khu rừng đầy những gai góc, trước mặt người ấy là gai, phía Tây … phía Bắc … phía Nam … người ấy là gai, phía dưới người ấy là gai, phía trên người ấy là gai. Chỗ nào người ấy đi tới hay chỗ nào người ấy đi lui, người ấy nghĩ: “Mong sao tôi chớ có bị vướng gai”. Cũng vậy, này các Tỷ-kheo, đối với sự vật gì khả ái, khả lạc, sự vật ấy được gọi là gai trong giới luật của bậc Thánh.`, ref: "Tương Ưng Bộ 35.240", url: "https://loicuaducphat.org/sn/sn35.240.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là không hộ trì? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi mắt thấy sắc, thiên chấp các sắc khả ái, ghét bỏ các sắc không khả ái, sống với thân niệm không an trú, với tâm nhỏ hẹp. Vị ấy không như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở nơi đây, các ác bất thiện pháp ấy khởi lên không được đoạn diệt không có dư tàn. Như vậy, này các Tỷ-kheo, là không hộ trì.`, ref: "Tương Ưng Bộ 35.240", url: "https://loicuaducphat.org/sn/sn35.240.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là được hộ trì? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi mắt thấy sắc, không thiên chấp các sắc khả ái, không ghét bỏ các sắc không khả ái, sống với thân niệm an trú, với tâm vô lượng. Vị ấy như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở nơi đây, các ác bất thiện pháp ấy khởi lên được đoạn diệt không có dư tàn … khi lưỡi nếm vị … khi ý biết pháp, không thiên chấp các pháp khả ái, không ghét bỏ các pháp không khả ái, sống với thân niệm an trú, với tâm vô lượng. Vị ấy như thật rõ biết tâm giải thoát, tuệ giải thoát. Chính ở đây, các ác bất thiện pháp ấy khởi lên được đoạn diệt không có dư tàn. Như vậy, này các Tỷ-kheo, là có hộ trì.`, ref: "Tương Ưng Bộ 35.240", url: "https://loicuaducphat.org/sn/sn35.240.html#content" },

{ text: `Ví như, này Tỷ-kheo, có ngôi thành của vua ở biên giới được xây dựng với pháo đài kiên cố, với tường và tháp canh kiên cố và có đến sáu cửa thành. Tại đấy có người giữ cửa thành, là bậc thông minh, có kinh nghiệm và có trí, ngăn chận những người không quen biết, cho vào những người quen biết. Từ phương Ðông, hai người sứ giả cấp tốc đi đến, và nói với người giữ cửa thành: “Này Bạn, vị chủ thành trì này ở đâu?” Người giữa cửa thành ấy nói: “Thưa các Tôn giả, vị ấy đang ngồi giữa ngã tư đường”. Hai người sứ giả ấy cấp tốc tuyên bố lời như thật ngữ cho vị chủ ngôi thành, rồi tiếp tục đi theo con đường họ đến. Từ phương Tây, lại hai người sứ giả cấp tốc đi đến … từ phương Bắc, lại hai người sứ giả cấp tốc đi đến, và nói với người giữ cửa thành: “Này Bạn, vị chủ thành trì này ở đâu?” Người giữ cửa thành ấy nói: “Thưa các Tôn giả, vị ấy đang ngồi giữa ngã tư đường”. Rồi hai người sứ giả ấy cấp tốc tuyên bố lời như thật ngữ cho vị chủ ngôi thành, rồi tiếp tục theo con đường họ đến.\n\nNày Tỷ-kheo, Ta nói ví dụ để giải thích ý nghĩa, và đây là ý nghĩa: Ngôi thành, này Tỷ-kheo, là đồng nghĩa với thân do bốn đại chủng tạo thành này, do cha mẹ sanh, do cơm cháo nuôi dưỡng, vô thường, tiêu mòn, tiêu hao, hủy hoại, hủy diệt. Sáu cửa, này Tỷ-kheo, là đồng nghĩa với sáu nội xứ. Người giữ cửa, này Tỷ-kheo, là đồng nghĩa với niệm. Hai vị sứ giả cấp tốc, này Tỷ-kheo, là đồng nghĩa với chỉ và quán. Người chủ ngôi thành là đồng nghĩa với thức. Ở giữa tại ngã tư đường là đồng nghĩa với bốn đại chủng: địa giới, thủy giới, hỏa giới và phong giới. Lời như thật ngữ, này Tỷ-kheo, là đồng nghĩa với Niết-bàn. Theo con đường họ đến là đồng nghĩa với con đường Thánh đạo Tám ngành. Như chánh tri kiến … chánh định.`, ref: "Tương Ưng Bộ 35.241", url: "https://loicuaducphat.org/sn/sn35.241.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một vị vua hay đại thần của vua từ trước chưa từng được nghe tiếng đàn tỳ bà, nay được nghe tiếng đàn tỳ bà, vị ấy nói: “Này Bạn, tiếng ấy là tiếng gì, khả ái như vậy, khả lạc như vậy, mê ly như vậy, say đắm như vậy, hấp dẫn như vậy?” Họ nói với vị ấy: “Thưa Tôn giả, đây là đàn tỳ bà, với tiếng khả ái như vậy, mê ly như vậy, khả lạc như vậy, say đắm như vậy, hấp dẫn như vậy”. Vị ấy nói như sau: “Hãy đi và đem đàn tỳ bà ấy về cho ta”. Họ đem đàn tỳ bà về cho vị ấy, và nói như sau: “Thưa Tôn giả, đàn tỳ bà này với tiếng khả ái như vậy, khả lạc như vậy, mê ly như vậy, say đắm như vậy, hấp dẫn như vậy”. Vị ấy bèn nói: “Thôi vừa rồi đối với ta về đàn tỳ bà này. Hãy đem tiếng lại cho ta”. Họ thưa với vị ấy: “Thưa Tôn giả, cái này được gọi là đàn tỳ bà, gồm có nhiều thành phần, gồm có số lớn thành phần. Nhờ nhiều thành phần này nên đàn phát âm. Như duyên cái bầu, duyên cái da, duyên cái cán, duyên cái đầu, duyên cái dây, duyên cái cung, duyên nỗ lực thích nghi của người. Như vậy, thưa Tôn giả, cái này gọi là đàn tỳ bà, gồm có nhiều thành phần, gồm có số lớn thành phần. Nhờ gồm nhiều thành phần này nên đàn phát âm”. Rồi vua ấy đập đàn tỳ bà ấy ra thành 10 mảnh, 100 mảnh; sau khi đập bể đàn tỳ bà ấy ra thành 10 mảnh, 100 mảnh, vị ấy chẻ thành từng miếng nhỏ; sau khi chẻ thành từng miếng nhỏ, vị ấy lấy lửa đốt; sau khi lấy lửa đốt, vị ấy vun lại thành đống tro; sau khi vun lại thành đống tro, vị ấy đem quạt đống tro lớn ấy trước làn gió mạnh, hay để chúng trôi theo dòng nước sông chảy mạnh. Rồi vị ấy nói: “Thật là hạ liệt, cái gọi đàn tỳ bà này, dầu cho tỳ bà là cái gì. Ở đây, đại chúng thường phóng dật, bị hướng dẫn sai lạc”.\n\nCũng vậy, này các Tỷ-kheo, Tỷ-kheo quán sát sắc cho đến sở thú của sắc, quán sát thọ … quán sát tưởng … quán sát các hành … quán sát thức cho đến sở thú của thức. Trong tất cả quán sát này, không có cái gì là “Tôi”, là “Của tôi”, là “Tôi là” cả.`, ref: "Tương Ưng Bộ 35.242", url: "https://loicuaducphat.org/sn/sn35.242.html#content" },

{ text: `Ví như, này các Tỷ-kheo, có người bắt được sáu sinh vật, giới loại khác nhau, chỗ tìm món ăn khác nhau, và cột chúng với một sợi dây vững chắc. Sau khi bắt được con rắn, người ấy cột với sợi dây vững chắc. Sau khi bắt được con cá sấu, người ấy cột một sợi dây vững chắc. Sau khi bắt được con chim, người ấy cột với sợi dây vững chắc … Sau khi bắt được con chó, người ấy cột với một sợi dây vững chắc. Sau khi bắt được con giả can, người ấy cột với một sợi dây vững chắc. Sau khi bắt được con khỉ, người ấy cột với một sợi dây vững chắc. Sau khi cột chúng với những sợi dây vững chắc, người ấy cột một cái gút ở chính giữa và thả chúng đi. Này các Tỷ-kheo, sáu con sinh vật ấy, với giới loại sai khác, với chỗ tìm món ăn sai khác, mỗi con sẽ lôi kéo tùy theo chỗ tìm món ăn và giới loại sai biệt của mình. Con rắn lôi kéo, nghĩ rằng: “Ta sẽ đi vào gò mối”. Con cá sấu lôi kéo, nghĩ rằng: “Ta sẽ đi vào trong nước”. Con chim lôi kéo, nghĩ rằng: “Ta sẽ bay lên trời”.Con chó lôi kéo, nghĩ rằng: ” Ta sẽ đi vào làng”. Con giả can lôi kéo, nghĩ rằng: “Ta sẽ đi vào nghĩa địa”. Con khỉ lôi kéo, nghĩ rằng: “Ta sẽ đi vào rừng”. Này các Tỷ-kheo, khi nào sáu con sinh vật ấy trở thành mệt mỏi, khi ấy, con sinh vật nào mạnh hơn các sinh vật còn lại, được chúng đi theo, chúng tuân theo, chúng phục tùng. Cũng vậy, này các Tỷ-kheo, với Tỷ-kheo thân niệm không tu tập, không làm cho sung mãn, con mắt sẽ lôi cuốn nó đối với các sắc khả ái và ghét bỏ đối với các sắc không khả ái … Ý sẽ lôi cuốn nó đối với các pháp khả ái và ghét bỏ đối với các pháp không khả ái.`, ref: "Tương Ưng Bộ 35.243", url: "https://loicuaducphat.org/sn/sn35.243.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, các Ông cần phải hiểu: “Tôi là”, này các Tỷ-kheo, là một ngã mạn. “Cái này là tôi”, là một ngã mạn. “Tôi sẽ là”, là một ngã mạn. “Tôi sẽ không là”, là một ngã mạn. “Tôi sẽ có sắc”, là một ngã mạn. “Tôi sẽ không có sắc”, là một ngã mạn. “Tôi sẽ có tưởng”, là một ngã mạn. “Tôi sẽ không có tưởng”, là một ngã mạn. “Tôi sẽ không có tưởng và không không có tưởng”, là một ngã mạn. Ngã mạn, này các Tỷ-kheo, là tham. Ngã mạn là mụt nhọt. Ngã mạn là mũi tên. Do vậy, này các Tỷ-kheo, các Ông cần phải học tập: “Tôi sẽ sống với tâm trừ bỏ ngã mạn”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 35.244", url: "https://loicuaducphat.org/sn/sn35.244.html#content" },

{ text: `- Này các Tỷ-kheo, có ba thọ này. Thế nào là ba? Lạc thọ, khổ thọ, bất khổ bất lạc thọ. Ðây, này các Tỷ-kheo, là ba thọ.\n\nVị đệ tử đức Phật,\nÐịnh, tỉnh giác, chánh niệm,\nHiểu rõ ràng các thọ,\nVà xuất ly các thọ.\n\nChỗ này, chúng đoạn diệt,\nCon đường đến đoạn diệt,\nTỷ-kheo đoạn các thọ,\nKhông khát ái, tịch tịnh.`, ref: "Tương Ưng Bộ 36.1", url: "https://loicuaducphat.org/sn/sn36.1.html#content" },

{ text: `- Này các Tỷ-kheo, có ba thọ này. Thế nào là ba? Lạc thọ, khổ thọ, bất khổ bất lạc thọ. Ðây, này các Tỷ-kheo, là ba thọ.\n\nLạc thọ hay khổ thọ,\nCùng bất khổ bất lạc,\nNội thọ và ngoại thọ,\nPhàm có cảm thọ gì.\n\nBiết được: “Ðây là khổ”,\nHư ngụy và biến hoại,\nThấy xúc, xúc biến diệt,\nỞ đây, sống ly tham.`, ref: "Tương Ưng Bộ 36.2", url: "https://loicuaducphat.org/sn/sn36.2.html#content" },

{ text: `- Này các Tỷ-kheo, có ba thọ này. Thế nào là ba? Lạc thọ, khổ thọ, bất khổ bất lạc thọ. Này các Tỷ-kheo, tham tùy miên đối với lạc thọ cần phải đoạn tận. Sân tùy miên đối với khổ thọ cần phải đoạn tận. Vô minh tùy miên đối với bất khổ bất lạc thọ cần phải đoạn tận. Này các Tỷ-kheo, khi nào Tỷ-kheo đoạn tận tham tùy miên đối với lạc thọ, đoạn tận sân tùy miên đối với khổ thọ, đoạn tận vô minh tùy miên đối với bất khổ bất lạc thọ; thời này các Tỷ-kheo, sự từ bỏ tham tùy miên của Tỷ-kheo được gọi là chánh kiến, ái được đoạn tận, kiết sử được hủy hoại. Với minh kiến chơn chánh đối với ngã mạn, vị ấy đoạn tận khổ đau.\n\nNếu cảm giác lạc thọ,\nKhông tuệ tri cảm thọ,\nÐây gọi tham tùy miên,\nKhông thấy rõ xuất ly.\n\nNếu cảm giác khổ thọ,\nKhông tuệ tri cảm thọ,\nÐây gọi sân tùy miên,\nKhông thấy rõ xuất ly.\n\nVới bất khổ bất lạc,\nBậc Ðại trí thuyết giảng,\nNếu hoan hỷ thọ ấy,\nKhông thoát được khổ đau.\n\nVị Tỷ-kheo nhiệt tình,\nTỉnh giác, không cuồng trí,\nÐối với tất cả thọ,\nBậc Hiền trí liễu tri.\n\nVị ấy liễu tri thọ,\nHiện tại không lậu hoặc,\nThân hoại, bậc Pháp trú\nÐại trí vượt ước lường.`, ref: "Tương Ưng Bộ 36.3", url: "https://loicuaducphat.org/sn/sn36.3.html#content" },

{ text: `Kẻ vô văn phàm phu, khi cảm giác khổ thọ về thân, thời sầu muộn, than vãn, khóc lóc, đấm ngực, đi đến bất tỉnh. Này các Tỷ-kheo, đây gọi là kẻ vô văn phàm phu không đứng lên trên vực thẳm, không đạt tới chỗ chân đứng. Còn bậc Ða văn Thánh đệ tử, này các Tỷ-kheo, khi cảm giác khổ thọ về thân, không sầu muộn, không than vãn, không khóc lóc, không đấm ngực, không đi đến bất tỉnh. Này các Tỷ-kheo, đây gọi là bậc Ða văn Thánh đệ tử đã đứng lên trên vực thẳm, đã đạt tới chỗ chân đứng.\n\nAi không chịu đựng nổi,\nCác khổ thọ khởi lên,\nThân đau, hại mạng sống,\nCảm xúc khiến run rẩy.\nAi than vãn, khóc lóc,\nSuy nhược, thiếu kiên cường,\nKhông đứng trên vực sâu,\nKhông đạt chỗ chân đứng.\n\nAi có thể chịu đựng,\nCác khổ thọ khởi lên,\nThân đau, hại mạng sống,\nCảm xúc không run rẩy,\nVị ấy vượt vực sâu,\nÐạt tới chỗ chân đứng.`, ref: "Tương Ưng Bộ 36.4", url: "https://loicuaducphat.org/sn/sn36.4.html#content" },

{ text: `- Này các Tỷ-kheo, có ba cảm thọ này. Thế nào là ba? Lạc thọ, khổ thọ, bất khổ bất lạc thọ. Lạc thọ, này các Tỷ-kheo, cần phải thấy là khổ. Khổ thọ cần phải thấy là mũi tên. Bất khổ bất lạc thọ cần phải thấy là vô thường. Khi nào, này các Tỷ-kheo, Tỷ-kheo thấy được lạc thọ là khổ, thấy được khổ thọ là mũi tên, thấy được bất khổ bất lạc thọ là vô thường; thời này các Tỷ-kheo, đây gọi là Tỷ-kheo có chánh kiến, ái được đoạn tận, kiết sử được hủy hoại. Với minh kiến chơn chánh đối với ngã mạn, vị ấy đoạn tận khổ đau.\n\nAi thấy lạc là khổ,\nThấy khổ là mũi tên,\nVới bất khổ bất lạc,\nThấy thọ là vô thường,\nTỷ-kheo ấy chánh kiến,\nLiễu tri các cảm thọ.\n\nVị ấy liễu tri thọ,\nHiện tại không lậu hoặc,\nMạng chung, bậc Pháp trú,\nÐại trí vượt ước lường.`, ref: "Tương Ưng Bộ 36.5", url: "https://loicuaducphat.org/sn/sn36.5.html#content" },

{ text: `Ví như, này các Tỷ-kheo, có người bị người ta bắn với mũi tên, rồi họ bắn người ấy với mũi tên thứ hai. Như vậy, này các Tỷ-kheo, người ấy cảm giác cảm thọ cả hai mũi tên. Cũng vậy, này các Tỷ-kheo, kẻ vô văn phàm phu khi cảm xúc khổ thọ; thời sầu muộn, than vãn, khóc lóc, đấm ngực, đi đến bất tỉnh. Người ấy cảm giác hai cảm thọ, cảm thọ về thân và cảm thọ về tâm. Cảm xúc bởi khổ thọ ấy, người ấy cảm thấy sân hận. Do cảm thấy sân hận đối với khổ thọ ấy, sân tùy miên đối với khổ thọ được tồn chỉ tùy miên. Cảm xúc bởi khổ thọ, người ấy hoan hỷ dục lạc. Vì sao? Vì rằng, này các Tỷ-kheo, kẻ vô văn phàm phu không tìm thấy một sự xuất ly khổ thọ nào khác, ngoài dục lạc. Do hoan hỷ dục lạc ấy, tham tùy miên đối với lạc thọ tồn tại. Người ấy không như thật rõ biết sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các cảm thọ ấy. Do người ấy không như thật rõ biết sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các cảm thọ ấy, nên vô minh tùy miên đối với bất khổ bất lạc thọ tồn tại. Nếu người ấy cảm thọ cảm giác lạc thọ, người ấy cảm thọ cảm giác như người bị trói buộc. Nếu người ấy cảm thọ cảm giác khổ thọ, người ấy cảm thọ cảm giác như người bị trói buộc. Nếu người ấy cảm thọ cảm giác bất khổ bất lạc thọ, người ấy cảm thọ cảm giác như người bị trói buộc. Này các Tỷ-kheo, đây gọi là kẻ vô văn phàm phu bị trói buộc bởi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng người ấy bị trói buộc bởi đau khổ.`, ref: "Tương Ưng Bộ 36.6", url: "https://loicuaducphat.org/sn/sn36.6.html#content" },

{ text: `Bậc Trí tuệ Ða văn,\nLạc khổ không chi phối,\nGiữa kẻ trí, phàm phu,\nThiện sai biệt rất lớn.\n\nBậc Ða văn, Tầm pháp,\nThấy đời này, đời sau,\nÁi pháp không phá tâm,\nKhông ái, không sân hận.\n\nTùy thuận hay đối nghịch,\nTiêu tán, diệt, không còn,\nVị ấy biết con đường,\nÐường không cấu, không sầu,\nChánh trí, đoạn tái sanh,\nÐến được bờ giác ngộ.`, ref: "Tương Ưng Bộ 36.6", url: "https://loicuaducphat.org/sn/sn36.6.html#content" },

{ text: `Ví như, này các Tỷ-kheo, có người bị người ta bắn một mũi tên. Họ không bắn tiếp người ấy với mũi tên thứ hai. Như vậy, này các Tỷ-kheo, người ấy cảm giác cảm thọ của một mũi tên. Cũng vậy, này các Tỷ-kheo, bậc Ða văn Thánh đệ tử khi cảm xúc khổ thọ; vị ấy không sầu muộn, không than vãn, không khóc lóc, không đấm ngực, không đi đến bất tỉnh. Vị ấy cảm giác chỉ một cảm thọ, cảm thọ về thân, không phải cảm thọ về tâm. Vị ấy không cảm thấy sân hận đối với khổ thọ ấy. Do không cảm thấy sân hận đối với khổ thọ ấy, sân tùy miên đối với khổ thọ không có tồn tại. Cảm xúc bởi khổ thọ, vị ấy không hoan hỷ dục lạc. Vì sao? Vì bậc Ða văn Thánh đệ tử có tuệ tri một sự xuất ly khác đối với khổ thọ, ngoài dục lạc. Vì vị ấy không hoan hỷ dục lạc, tham tùy miên đối với dục lạc không có tồn tại. Vị ấy như thật tuệ tri sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của những cảm thọ ấy. Vì rằng, vị ấy như thật tuệ tri sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các cảm thọ ấy. Vì rằng, vị ấy như thật tuệ tri sự tập khởi, sự đoạn diệt, vị ngọt, sự nguy hiểm và sự xuất ly của các cảm thọ ấy, đối với bất khổ bất lạc thọ, vô minh tùy miên không có tồn tại. Nếu vị ấy cảm thọ lạc thọ, vị ấy cảm thọ lạc thọ như người không bị trói buộc. Nếu vị ấy cảm thọ cảm giác khổ thọ, vị ấy cảm thọ cảm giác như người không bị trói buộc. Nếu vị ấy cảm thọ cảm giác bất khổ bất lạc thọ, vị ấy cảm thọ cảm giác như người không bị trói buộc. Này các Tỷ-kheo, đây gọi là Tỷ-kheo không bị trói buộc bởi sanh, già, chết, sầu, bi, khổ, ưu, ão. Ta nói rằng vị ấy không bị trói buộc bởi đau khổ.`, ref: "Tương Ưng Bộ 36.6", url: "https://loicuaducphat.org/sn/sn36.6.html#content" },

{ text: `Nếu vị ấy cảm thọ cảm giác lạc thọ, vị ấy tuệ tri: “Thọ ấy là vô thường”. Vị ấy tuệ tri: “Ta không chấp trước thọ ấy”. Vị ấy tuệ tri: “Ta không hoan hỷ thọ ấy”. Nếu vị ấy cảm thọ khổ thọ … Nếu vị ấy cảm thọ bất khổ bất lạc thọ, vị ấy tuệ tri: “Thọ ấy là vô thường”. Vị ấy tuệ tri: “Ta không chấp trước thọ ấy”. Vị ấy tuệ tri: “Ta không hoan hỷ thọ ấy”. Nếu vị ấy cảm thọ cảm giác lạc thọ, vị ấy cảm giác thọ ấy như người không bị trói buộc. Nếu vị ấy cảm thọ cảm giác khổ thọ, vị ấy cảm thọ cảm giác thọ ấy như người không bị trói buộc. Nếu vị ấy cảm thọ cảm giác bất khổ bất lạc thọ, vị ấy cảm thọ cảm giác thọ ấy như người không bị trói buộc. Khi vị ấy cảm thọ một cảm thọ cùng tận sức chịu đựng của thân, vị ấy tuệ tri: “Ta đang cảm thọ một cảm thọ cùng tận đến sức chịu đựng của thân”. Khi vị ấy cảm thọ một cảm thọ cùng tận chịu đựng của sinh mạng, vị ấy tuệ tri: “Ta đang cảm thọ một cảm thọ cùng tận đến sức chịu đựng của sinh mạng”. Vị ấy tuệ tri rằng: “Sau khi thân hoại mạng chung, ở đây, một cảm thọ cảm giác không có gì đáng hoan hỷ, sẽ đi đến lắng dịu”.`, ref: "Tương Ưng Bộ 36.7", url: "https://loicuaducphat.org/sn/sn36.7.html#content" },

{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo sống chánh niệm, tỉnh giác, không phóng dật, nhiệt tâm, tinh cần như vậy, khổ thọ khởi lên. Vị ấy tuệ tri như sau: “Khổ thọ này khởi lên nơi ta. Khổ thọ ấy có duyên, không phải không duyên. Do duyên gì? Do duyên chính thân này. Nhưng thân này là vô thường, hữu vi, do duyên sanh. Do duyên thân khởi lên, và duyên này là vô thường, hữu vi, thời khổ thọ được khởi lên, làm sao thường trú được?”. Vị ấy trú, quán vô thường đối với thân và khổ thọ. Vị ấy trú, quán tiêu vong. Vị ấy trú, quán ly tham. Vị ấy trú, quán đoạn diệt. Vị ấy trú, quán từ bỏ. Do vị ấy trú, quán vô thường; do vị ấy trú, quán tiêu vong; do vị ấy trú, quán ly tham; do vị ấy trú, quán đoạn diệt; do vị ấy trú, quán từ bỏ đối với thân và khổ thọ của vị ấy, nên sân tùy miên đối với thân và khổ thọ được đoạn diệt.`, ref: "Tương Ưng Bộ 36.7", url: "https://loicuaducphat.org/sn/sn36.7.html#content" },
{ text: `Có hai cực đoan mà người xuất gia không nên thực hành: Một là say đắm dục lạc đối với các dục vọng hạ liệt, đê tiện, phàm phu, không xứng Thánh hạnh, không liên hệ đến mục đích. Hai là hành hạ tự thân, khổ đau, không xứng bậc Thánh, không liên hệ đến mục đích. Từ bỏ hai cực đoan này là con đường trung đạo, đã được Như Lai giác ngộ, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn.\n\nThế nào là con đường trung đạo ấy, này Thôn trưởng, đã được Như Lai giác ngộ, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn? Ðây là con đường Thánh đạo Tám ngành, tức là chánh tri kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định. Ðây là con đường trung đạo, này Thôn trưởng, được Như Lai giác ngộ, tác thành mắt, tác thành trí, đưa đến an tịnh, thắng trí, giác ngộ, Niết-bàn.`, ref: "Tương Ưng Bộ 42.12", url: "https://loicuaducphat.org/sn/sn42.12.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là vô vi? Này các Tỷ-kheo, sự đoạn tận tham, sự đoạn tận sân, sự đoạn tận si. Này các Tỷ-kheo, đây gọi là vô vi. Và này các Tỷ-kheo, thế nào là con đường đưa đến vô vi? Thân niệm, này các Tỷ-kheo, đây gọi là con đường đưa đến vô vi. Như vậy, này các Tỷ-kheo, Ta thuyết về vô vi, Ta thuyết về con đường đưa đến vô vi. Này các Tỷ-kheo, những gì một bậc Ðạo sư cần phải làm cho những đệ tử, vì hạnh phúc, vì lòng từ mẫn, vì khởi lên lòng từ mẫn đối với họ; tất cả, Ta đã làm đối với các Ông. Này các Tỷ-kheo, đây là những gốc cây, đây là những căn nhà trống, hãy tu tập Thiền định. Chớ có phóng dật. Chớ để hối hận về sau. Ðây là lời giáo giới của Ta cho các Ông.`, ref: "Tương Ưng Bộ 43.1", url: "https://loicuaducphat.org/sn/sn43.1.html#content" },

{ text: `Này các Tỷ-kheo, Ta sẽ giảng cho các Ông về vô vi và về con đường đưa đến vô vi. Hãy lắng nghe. Và này các Tỷ-kheo, thế nào là vô vi? Này các Tỷ-kheo, sự đoạn tận tham, sự đoạn tận sân, sự đoạn tận si. Này các Tỷ-kheo, đây gọi là vô vi. Và này các Tỷ-kheo, thế nào là con đường đưa đến vô vi, chỉ và quán, này các Tỷ-kheo, đây là con đường đưa đến vô vi.`, ref: "Tương Ưng Bộ 43.2", url: "https://loicuaducphat.org/sn/sn43.2.html#content" },

{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết cho các Ông về sự đến bờ bên kia và con đường đưa đến bờ bên kia, hãy lắng nghe. Này các Tỷ-kheo, thế nào là đến bờ bên kia? Này các Tỷ-kheo, sự đoạn tận tham, sự đoạn tận sân, sự đoạn tận si; này các Tỷ-kheo, đây gọi là đến bờ bên kia. Và này các Tỷ-kheo, thế nào là con đường đưa đến bờ bên kia? Thân niệm, này các Tỷ-kheo, là con đường đưa đến bờ bên kia. Như vậy, này các Tỷ-kheo, Ta thuyết về sự đến bờ bên kia, Ta thuyết về con đường đưa đến bờ bên kia. Này các Tỷ-kheo, những gì một bậc Ðạo sư cần phải làm cho những đệ tử, vì hạnh phúc, vì lòng từ mẫn, vì khởi lên lòng từ mẫn đối với họ; tất cả, Ta đã làm đối với các Ông. - Này các Tỷ-kheo, đây là những gốc cây, đây là những căn nhà trống, hãy tu tập Thiền định. Chớ có phóng dật. Chớ để hối hận về sau. Ðây là lời giáo giới của Ta cho các Ông.`, ref: "Tương Ưng Bộ 43.150", url: "https://loicuaducphat.org/sn/sn43.150.html#content" },

{ text: `- Thưa Hiền giả, đối với ai chưa đoạn trừ tham đối với sắc, chưa đoạn trừ dục, chưa đoạn trừ ái, chưa đoạn trừ khát, chưa đoạn trừ nhiệt tâm, chưa đoạn trừ khát ái, thời người ấy có quan điểm: “Như Lai có tồn tại sau khi chết. Hay Như Lai không có tồn tại sau khi chết. Hay Như Lai có tồn tại và không tồn tại sau khi chết. Hay Như Lai không tồn tại và không không tồn tại sau khi chết”. Này Hiền giả, đối với ai đã đoạn trừ tham đối với sắc, đã đoạn trừ dục, đã đoạn trừ ái, đã đoạn trừ khát, đã đoạn trừ nhiệt tâm, đã đoạn trừ khát ái, người ấy sẽ không có quan điểm: “Như Lai có tồn tại sau khi chết. Hay Như Lai không có tồn tại sau khi chết. Hay Như Lai có tồn tại và không tồn tại sau khi chết. Hay Như Lai không tồn tại và không không tồn tại sau khi chết”. Này Hiền giả, đây là nhân, đây là duyên, đây là lý do mà Thế Tôn không trả lời vấn đề ấy.`, ref: "Tương Ưng Bộ 44.5", url: "https://loicuaducphat.org/sn/sn44.5.html#content" },

{ text: `- Thưa Tôn giả Kotthika, Như Lai có tồn tại sau khi chết? … Như Lai không tồn tại và không không tồn tại sau khi chết? … Ðược hỏi vậy, Hiền giả trả lời: “Thế Tôn không trả lời: ‘Như Lai có tồn tại sau khi chết … Như Lai không tồn tại và không không tồn tại sau khi chết” ”. Do nhân gì, thưa Hiền giả, do duyên gì, Thế Tôn không trả lời vấn đề ấy? - Thưa Hiền giả, với ai còn ái lạc sắc, ưa thích sắc, hoan hỷ sắc, không như thật biết, như thật thấy sắc đoạn diệt, thời người ấy có quan điểm: “Như Lai có tồn tại sau khi chết … Như Lai không tồn tại và không không tồn tại sau khi chết”. Thưa Hiền giả, với ai còn ái lạc thọ, ưa thích thọ, hoan hỷ thọ, không như thật biết, như thật thấy thọ đoạn diệt, thời người ấy có các quan điểm: “Như Lai có tồn tại sau khi chết … Như Lai không tồn tại và không không tồn tại sau khi chết” … tưởng … các hành … Thưa Hiền giả, với ai còn ái lạc thức, ưa thích thức, hoan hỷ thức, không như thật biết, như thật thấy thức đoạn diệt, thời người ấy có các quan điểm: “Như Lai có tồn tại sau khi chết … Như Lai không tồn tại và không không tồn tại sau khi chết”. Này Hiền giả, đây là nhân, đây là duyên, đây là lý do mà Thế Tôn không trả lời về vấn đề ấy.`, ref: "Tương Ưng Bộ 44.6", url: "https://loicuaducphat.org/sn/sn44.6.html#content" },

{ text: `Thưa Tôn giả Gotama, con có khởi lên phân vân và nghi ngờ như sau: “Như thế nào, cần phải thấu hiểu pháp của Sa-môn Gotama?” - Này Vaccha, thôi vừa rồi sự phân vân của Ông. Thôi vừa rồi sự nghi ngờ của Ông. Chính do trên điểm Ông phân vân mà nghi ngờ được khởi lên. Ta tuyên bố sự sanh khởi, này Vaccha, đối với những ai có chấp thủ, không phải đối với ai không có chấp thủ. Ví như, này Vaccha, một ngọn lửa cháy đỏ khi nào có nhiên liệu, không phải không có nhiên liệu. Cũng vậy, này Vaccha, Ta tuyên bố về sanh khởi đối với người có chấp thủ (sanh y), không phải với người không có chấp thủ. - Thưa Tôn giả Gotama, trong khi có gió thổi ngọn lửa đi thật xa, thời Tôn giả Gotama tuyên bố cái gì làm nhiên liệu cho ngọn lửa này? - Này Vaccha, trong khi có gió thổi ngọn lửa đi thật xa, thời Ta nói chính gió là nhiên liệu. Trong khi ấy, này Vaccha, chính gió là nhiên liệu (upàdàna). - Thưa Tôn giả Gotama, trong khi một loài hữu tình quăng bỏ thân này để sanh vào một thân khác, thời Tôn giả Gotama tuyên bố cái gì làm nhiên liệu cho thân này? - Này Vaccha, trong khi một loài hữu tình quăng bỏ thân này và sanh vào một thân khác, này Vaccha, Ta tuyên bố rằng trong khi ấy chính ái (tanhà) là nhiên liệu (upàdàna).`, ref: "Tương Ưng Bộ 44.9", url: "https://loicuaducphat.org/sn/sn44.9.html#content" },

{ text: `- Khi nào vô minh dẫn đầu, này các Tỷ-kheo, đưa đến sự thành tựu các pháp bất thiện, thời vô tàm, vô quý nối tiếp theo. Với kẻ bị vô minh chi phối, vô trí, này các Tỷ-kheo, tà kiến sanh. Ðối với kẻ có tà kiến, tà tư duy sanh. Ðối với kẻ có tà tư duy, tà ngữ sanh. Ðối với kẻ có tà ngữ, tà nghiệp sanh. Ðối với kẻ có tà nghiệp, tà mạng sanh. Ðối với kẻ có tà mạng, tà tinh tấn sanh. Ðối với kẻ có tà tinh tấn, tà niệm sanh. Ðối với kẻ có tà niệm, tà định sanh.\n\nKhi nào minh dẫn đầu, này các Tỷ-kheo, đưa đến sự thành tựu các thiện pháp, thời tàm và quý nối tiếp theo. Với kẻ được minh chi phối, có trí, này các Tỷ-kheo, chánh kiến sanh. Ðối với vị chánh kiến, chánh tư duy sanh. Ðối với vị chánh tư duy, chánh ngữ sanh. Ðối với vị chánh ngữ, chánh nghiệp sanh. Ðối với vị chánh nghiệp, chánh mạng sanh. Ðối với vị chánh mạng, chánh tinh tấn sanh. Ðối với vị chánh tinh tấn, chánh niệm sanh. Ðối với vị chánh niệm, chánh định sanh.`, ref: "Tương Ưng Bộ 45.1", url: "https://loicuaducphat.org/sn/sn45.1.html#content" },

{ text: `- Một nửa Phạm hạnh này, bạch Thế Tôn, là thiện bạn hữu, thiện bạn đảng, thiện thân tình. - Chớ có nói vậy, này Ānanda! Chớ có nói vậy, này Ānanda! Toàn bộ Phạm hạnh này, này Ānanda, là thiện bạn hữu, thiện bạn đảng, thiện thân tình. Với Tỷ-kheo thiện bạn hữu, thiện bạn đảng, thiện thân tình, này Ānanda, thời được chờ đợi Thánh đạo Tám ngành được tu tập, Thánh đạo Tám ngành được làm cho viên mãn. Này Ānanda, chính với pháp môn này, các Ông cần phải hiểu thế nào toàn bộ Phạm hạnh này là thiện bạn hữu, thiện bạn đảng, thiện thân tình. Do Ta lấy thiện làm bạn hữu, này Ānanda, nên các chúng sanh bị sanh được giải thoát khỏi sanh; các chúng sanh bị già được giải thoát khỏi già; các chúng sanh bị chết được giải thoát khỏi chết; các chúng sanh bị sầu, bi, khổ, ưu, não được giải thoát khỏi sầu, bi, khổ, ưu, não. Chính với pháp môn này, này Ānanda, các Ông cần phải hiểu thế nào toàn bộ Phạm hạnh này là thiện bạn hữu, thiện bạn đảng, thiện thân tình.`, ref: "Tương Ưng Bộ 45.2", url: "https://loicuaducphat.org/sn/sn45.2.html#content" },

{ text: `Rồi Tôn giả Sāriputta đi đến Thế Tôn; sau khi đến, đảnh lễ Thế Tôn rồi ngồi xuống một bên. Ngồi một bên, Tôn giả Sāriputta bạch Thế Tôn: - Toàn bộ Phạm hạnh này, bạch Thế Tôn, chính là thiện bạn hữu, thiện bạn đãng, thiện thân tình này. - Lành thay, này Sāriputta! Lành thay, này Sāriputta! Chính toàn bộ Phạm hạnh này là thiện bạn hữu, thiện bạn đãng, thiện thân tình này. Này Sāriputta, với Tỷ-kheo thiện bạn hữu, thiện bạn đãng, thiện thân tình, được chờ đợi rằng Thánh đạo Tám ngành sẽ được tu tập, sẽ được làm cho viên mãn.`, ref: "Tương Ưng Bộ 45.3", url: "https://loicuaducphat.org/sn/sn45.3.html#content" },

{ text: `Ai được tín, trí tuệ,\nThường xuyên liên kết lại,\nLấy hổ thẹn làm cán,\nLấy ý làm ách xe.\nNiệm là người đánh xe,\nBiết hộ trì, phòng hộ,\nCỗ xe lấy giới luật\nLàm vật dụng cho xe.\nThiền là trục bánh xe,\nTinh tấn là bánh xe,\nXả là định thường hằng,\nVô dục là nệm xe.\nVô sân và vô hại,\nViễn ly là binh khí,\nNhẫn nhục là áo giáp,\nAn ổn khỏi khổ ách,\nLàm mục đích đạt đến,\nCỗ xe được chuyển vận.\nPháp này tự ngã làm,\nTrở thành thuộc tự ngã.\nLà cỗ xe thù thắng,\nVô thượng, không sánh bằng.\nNgồi trên cỗ xe ấy,\nBậc Trí thoát ly đời,\nChắc chắn, không sai chạy,\nHọ đạt được chiến thắng.`, ref: "Tương Ưng Bộ 45.4", url: "https://loicuaducphat.org/sn/sn45.4.html#content" },

{ text: `“Phạm hạnh, Phạm hạnh”, bạch Thế Tôn, được nói đến như vậy. Bạch Thế Tôn, thế nào là Phạm hạnh? Thế nào là cứu cánh Phạm hạnh? - Này Tỷ-kheo, con đường Thánh đạo Tám ngành này là Phạm hạnh, tức là chánh tri kiến … chánh định. Này Tỷ-kheo, đoạn tận tham, đoạn tận sân, đoạn tận si, đây là cứu cánh Phạm hạnh.`, ref: "Tương Ưng Bộ 45.6", url: "https://loicuaducphat.org/sn/sn45.6.html#content" },

{ text: `“Nhiếp phục tham, nhiếp phục sân, nhiếp phục si”, bạch Thế Tôn, được gọi là như vậy. Ðồng nghĩa với gì, bạch Thế Tôn, là nhiếp phục tham, nhiếp phục sân, nhiếp phục si? - Ðồng nghĩa với Niết-bàn giới là nhiếp phục tham, nhiếp phục sân, nhiếp phục si, cũng được gọi là đoạn tận các lậu hoặc. Khi được nói vậy, Tỷ-kheo ấy bạch Thế Tôn: “Bất tử, bất tử”, bạch Thế Tôn, được gọi là như vậy. Thế nào là bất tử, bạch Thế Tôn? Thế nào là con đường đưa đến bất tử? - Ðoạn tận tham, đoạn tận sân, đoạn tận si, này Tỷ-kheo, được gọi là bất tử. Con đường Thánh đạo Tám ngành này là con đường đưa đến bất tử, tức là chánh tri kiến … chánh định.`, ref: "Tương Ưng Bộ 45.7", url: "https://loicuaducphat.org/sn/sn45.7.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là chánh tri kiến? Này các Tỷ-kheo, chính là trí về khổ, trí về khổ tập, trí về khổ diệt, trí về con đường đưa đến khổ diệt. Này các Tỷ-kheo, đây gọi là chánh tri kiến. Và này các Tỷ-kheo, thế nào là chánh tư duy? Này các Tỷ-kheo, chính là xuất ly tư duy, vô sân tư duy, vô hại tư duy. Này các Tỷ-kheo, đây gọi là chánh tư duy. Và này các Tỷ-kheo, thế nào là chánh ngữ? Này các Tỷ-kheo, chính là từ bỏ nói láo, từ bỏ nói hai lưỡi, từ bỏ nói lời độc ác, từ bỏ nói lời phù phiếm. Này các Tỷ-kheo, đây gọi là chánh ngữ. Và này các Tỷ-kheo, thế nào là chánh nghiệp? Này các Tỷ-kheo, chính là từ bỏ sát sanh, từ bỏ lấy của không cho, từ bỏ phi Phạm hạnh. Này các Tỷ-kheo, đây gọi là chánh nghiệp. Và này các Tỷ-kheo, thế nào là chánh mạng? Ở đây, này các Tỷ-kheo, vị Thánh đệ tử đoạn trừ tà mạng, nuôi sống với chánh mạng. Này các Tỷ-kheo, đây gọi là chánh mạng.`, ref: "Tương Ưng Bộ 45.8", url: "https://loicuaducphat.org/sn/sn45.8.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là chánh tinh tấn? Ở đây, này các Tỷ-kheo, với mục đích khiến cho các ác, bất thiện pháp từ trước chưa sanh không cho sanh khởi, khởi lên ý muốn, cố gắng, tinh tấn, sách tấn, trì tâm; với mục đích khiến cho các ác, bất thiện pháp đã sanh được trừ diệt, khởi lên ý muốn, cố gắng, tinh tấn, sách tấn, trì tâm; với mục đích khiến cho các thiện pháp từ trước chưa sanh nay được sanh khởi, khởi lên ý muốn, cố gắng, tinh tấn, sách tấn, trì tâm; với mục đích khiến cho các thiện pháp đã được sanh có thể duy trì, không có lu mờ, được tăng trưởng, được quảng đại, được tu tập, được viên mãn, khởi lên ý muốn, cố gắng, tinh tấn, sách tấn, trì tâm. Này các Tỷ-kheo, đây gọi là chánh tinh tấn.`, ref: "Tương Ưng Bộ 45.8", url: "https://loicuaducphat.org/sn/sn45.8.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là chánh niệm? Ở đây, này các Tỷ-kheo, Tỷ-kheo sống quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, với mục đích điều phục tham ưu ở đời; Tỷ-kheo sống quán thọ trên các thọ, nhiệt tâm, tỉnh giác, chánh niệm với mục đích điều phục tham ưu ở đời; Tỷ-kheo sống quán tâm trên tâm, nhiệt tâm, tỉnh giác, chánh niệm với mục đích điều phục tham ưu ở đời; Tỷ-kheo sống quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm với mục đích điều phục tham ưu ở đời. Này các Tỷ-kheo, đây gọi là chánh niệm.`, ref: "Tương Ưng Bộ 45.8", url: "https://loicuaducphat.org/sn/sn45.8.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là chánh định? Ở đây, này các Tỷ-kheo, Tỷ-kheo ly dục, ly pháp bất thiện, chứng và trú Thiền thứ nhất, một trạng thái hỷ lạc do ly dục sanh, có tầm, có tứ. Làm cho tịnh chỉ tầm và tứ, chứng và trú Thiền thứ hai, một trạng thái hỷ lạc do định sanh, không tầm, không tứ, nội tĩnh, nhất tâm. Vị ấy ly hỷ trú xả, chánh niệm, tỉnh giác, thân cảm sự lạc thọ mà các bậc Thánh gọi là xả niệm lạc trú, chứng và trú Thiền thứ ba. Xả lạc, xả khổ, diệt hỷ ưu đã cảm thọ trước, chứng và trú Thiền thứ tư, không khổ không lạc, xả niệm thanh tịnh. Này các Tỷ-kheo, đây gọi là chánh định.`, ref: "Tương Ưng Bộ 45.8", url: "https://loicuaducphat.org/sn/sn45.8.html#content" },

{ text: `- Này các Tỷ-kheo, ví như sợi râu của lúa mì hay sợi râu của lúa mạch đặt hướng sai lạc, khi bị tay hay chân đè vào, có thể đâm thủng tay hay chân, hay có thể làm đổ máu; sự tình này không xảy ra. Vì sao? Này các Tỷ-kheo, vì sợi râu bị đặt hướng sai lạc. Cũng vậy, này các Tỷ-kheo, Tỷ-kheo kiến bị đặt hướng sai lạc, con đường tu tập bị đặt hướng sai lạc, có thể đâm thủng vô minh, làm minh sanh khởi, có thể đạt Niết-bàn; sự tình này không xảy ra. Vì sao? Này các Tỷ-kheo, vì kiến bị đặt hướng sai lạc.`, ref: "Tương Ưng Bộ 45.9", url: "https://loicuaducphat.org/sn/sn45.9.html#content" },

{ text: `- Này các Tỷ-kheo, Ta muốn sống Thiền định trong nửa tháng, không có ai đến yết kiến Ta, trừ độc nhất người mang đồ ăn khất thực. - Thưa vâng, bạch Thế Tôn. Các Tỷ-kheo ấy vâng đáp Thế Tôn. Như vậy, không một ai đến yết kiến Thế Tôn, trừ một người người mang đồ ăn khất thực lại. Rồi Thế Tôn sau nửa tháng, từ chỗ Thiền tịnh đứng dậy và gọi các Tỷ-kheo: - Với sự an trú, Ta đã trú khi Ta mới chứng Chánh đẳng Chánh giác, nhưng Ta chỉ trú một phần thôi. Như vậy, Ta rõ biết những gì được cảm thọ do duyên tà kiến, những gì được cảm thọ do duyên chánh kiến … những gì được cảm thọ do duyên tà định, những gì được cảm thọ do duyên chánh định, những gì được cảm thọ do duyên ước muốn (chanda), những gì được cảm thọ do duyên tầm (vitakka), những gì được cảm thọ do duyên tưởng (sannà). Khi ước muốn không tịnh chỉ, thời tầm không tịnh chỉ, tưởng không tịnh chỉ; do duyên như vậy, có được những cảm thọ. Và khi ước muốn được tịnh chỉ, nhưng tầm chưa được tịnh chỉ, tưởng chưa được tịnh chỉ; do duyên như vậy, có được những cảm thọ. Và khi ước muốn được tịnh chỉ, tầm được tịnh chỉ, nhưng tưởng chưa được tịnh chỉ, do duyên như vậy, có được những cảm thọ. Và khi ước muốn được tịnh chỉ, tầm được tịnh chỉ, tưởng được tịnh chỉ, do duyên như vậy, có được những cảm thọ. Ðối với người chưa chứng đạt, cần phải tinh tấn để được chứng đạt. Trong trường hợp đã được chứng đạt; do duyên như vậy, có được những cảm thọ.`, ref: "Tương Ưng Bộ 45.11", url: "https://loicuaducphat.org/sn/sn45.11.html#content" },

{ text: `- Có tám pháp này, này các Tỷ-kheo, thanh tịnh, trong sáng, không cấu uế, ly các phiền não, nếu chưa sanh khởi có thể sanh khởi, nhưng chỉ khi nào Như Lai, bậc A-la-hán, Chánh Ðẳng Giác xuất hiện. Thế nào là tám? Tức là chánh tri kiến … chánh định. Có tám pháp này, này các Tỷ-kheo, thanh tịnh, trong sáng, không có cấu uế, ly các phiền não, nếu chưa sanh khởi có thể sanh khởi, nhưng chỉ khi nào Như Lai, bậc A-la-hán Chánh Ðẳng Giác xuất hiện.`, ref: "Tương Ưng Bộ 45.16", url: "https://loicuaducphat.org/sn/sn45.16.html#content" },

{ text: `- Này các Tỷ-kheo, ví như một cái bình, nếu không có cái giá chống đỡ thời dễ bị nghiêng ngã, nếu có cái giá chống đỡ thời khó nghiêng ngã. Cũng vậy, này các Tỷ-kheo, nếu tâm không có cái giá chống đỡ thời dễ bị nghiêng ngã, nếu có cái giá chống đỡ thời khó nghiêng ngã. Và này các Tỷ-kheo, cái gì là giá chống đỡ cho tâm? Chính là Thánh đạo Tám ngành này, tức là chánh tri kiến … chánh định. Ðây gọi là cái giá chống đỡ tâm. Này các Tỷ-kheo, ví như cái bình không có cái giá chống đỡ thời dễ bị nghiêng ngã, nếu có cái giá chống đỡ thời khó bị nghiêng ngã. Cũng vậy, này các Tỷ-kheo, nếu tâm không có cái giá chống đỡ thời dễ bị nghiêng ngã, nếu có cái giá chống đỡ thời khó bị nghiêng ngã.`, ref: "Tương Ưng Bộ 45.27", url: "https://loicuaducphat.org/sn/sn45.27.html#content" },

{ text: `- Này các Tỷ-kheo, có ba thọ này do xúc sanh, lấy xúc làm căn bản, lấy xúc làm nhân duyên, lấy xúc làm trợ duyên. Thế nào là ba? Lạc thọ, khổ thọ, bất khổ bất lạc thọ. Ví như, này các Tỷ-kheo, hai khúc gỗ cọ xát nhau, đem đến gần nhau, nên sức nóng sanh ra, lửa được hiện hữu. Khi hai khúc gỗ ấy bị phân ly tuyệt duyên, thời sức nóng khởi lên do duyên ấy được đoạn diệt, được tịnh chỉ. Cũng vậy, này các Tỷ-kheo, ba thọ này do xúc sanh, lấy xúc làm căn bản, lấy xúc làm nhân duyên, lấy xúc làm trợ duyên, do duyên xúc tương ứng, các thọ tương ứng, tương ứng, khởi lên. Do sự đoạn diệt của xúc tương ứng, tương ứng các thọ tương ứng, tương ứng được đoạn diệt.`, ref: "Tương Ưng Bộ 36.10", url: "https://loicuaducphat.org/sn/sn36.10.html#content" },

{ text: `Này Tỷ-kheo, Ta nói rằng có ba thọ này: lạc thọ, khổ thọ, bất khổ bất lạc thọ. Ba thọ này được Ta nói đến. Nhưng này Tỷ-kheo, Ta lại nói: “Phàm cái gì được cảm thọ, cái ấy nằm trong đau khổ”. Chính vì liên hệ đến tánh vô thường của các hành mà lời ấy được Ta nói lên: “Phàm cái gì được cảm thọ, cái ấy nằm trong đau khổ”. Chính vì liên hệ đến tánh đoạn tận, tánh tiêu vong, tánh ly tham, tánh đoạn diệt, tánh biến hoại của các hành mà lời ấy được Ta nói lên: “Phàm cái gì được cảm thọ, cái ấy nằm trong đau khổ”.`, ref: "Tương Ưng Bộ 36.11", url: "https://loicuaducphat.org/sn/sn36.11.html#content" },

{ text: `- Ví như ở trên hư không có nhiều loại gió thổi. Có gió từ phương Ðông thổi. Có gió từ phương Tây thổi. Có gió từ phương Bắc thổi. Có gió từ phương Nam thổi. Có gió có bụi thổi. Có gió không bụi thổi. Có gió lạnh thổi. Có gió nóng thổi. Có gió lượng nhỏ thổi, có gió lượng lớn thổi. Cũng vậy, này các Tỷ-kheo, trong cái thân này, có nhiều loại thọ sai biệt khởi lên. Lạc thọ khởi lên. Khổ thọ khởi lên. Bất khổ bất lạc thọ khởi lên.\n\nGiống như giữa hư không,\nGió nhiều loại thổi lên,\nTừ phương Ðông, phương Tây,\nTừ phương Bắc, phương Nam.\n\nGió có bụi, không bụi,\nCó gió lạnh, gió nóng,\nCó gió lớn, gió nhỏ,\nGió nhiều loại, thổi lên.\n\nCũng vậy, trong thân này,\nKhởi lên nhiều cảm thọ,\nLạc thọ và khổ thọ,\nBất khổ bất lạc thọ.\n\nKhi Tỷ-kheo nhiệt tâm,\nTỉnh giác, không sanh y,\nDo vậy, bậc Hiền giả,\nLiễu tri tất cả thọ.\n\nVị ấy liễu tri thọ,\nNgay hiện tại, vô lậu,\nThân hoại, bậc Pháp trú,\nÐại trí, vượt ước lường.`, ref: "Tương Ưng Bộ 36.12", url: "https://loicuaducphat.org/sn/sn36.12.html#content" },

{ text: `- Với mục đích gì, này Hiền giả Sāriputta, Phạm hạnh được sống dưới Sa-môn Gotama? - Này Hiền giả, Phạm hạnh được sống dưới Thế Tôn với mục đích liễu tri khổ. - Có con đường nào, có đạo lộ nào, này Hiền giả, đưa đến liễu tri khổ ấy? - Có con đường, có đạo lộ, này Hiền giả, đưa đến liễu tri khổ ấy. - Con đường ấy là gì, đạo lộ ấy là gì, này Hiền giả, đưa đến liễu tri khổ ấy? - Ðấy là Thánh đạo Tám ngành, này Hiền giả, tức là chánh tri kiến … chánh định. Ðây là con đường, đây là đạo lộ, này Hiền giả, đưa đến liễu tri khổ ấy. - Này Hiền giả, hiền thiện là con đường, hiền thiện là đạo lộ đưa đến liễu tri khổ ấy. Thật là vừa đủ, này Hiền giả, để không phóng dật.`, ref: "Tương Ưng Bộ 38.4", url: "https://loicuaducphat.org/sn/sn38.4.html#content" },

{ text: `- Này Hiền giả Sāriputta, trong Pháp luật này, cái gì là khó làm? - Xuất gia, này Hiền giả, là điều khó làm trong Pháp luật này. - Ðối với người đã xuất gia, này Hiền giả, cái gì là khó làm? - Ðối với người đã xuất gia, này Hiền giả, hoan hỷ là điều khó làm. - Này Hiền giả, đối với người đã hoan hỷ, cái gì là khó làm? - Này Hiền giả, đối với người đã hoan hỷ, điều khó làm là sự thực hành đúng pháp và tùy pháp. - Có lâu không, này Hiền giả, một người đã thực hành đúng pháp và tùy pháp có thể thành vị A-la-hán? - Không lâu, này Hiền giả.`, ref: "Tương Ưng Bộ 38.16", url: "https://loicuaducphat.org/sn/sn38.16.html#content" },

{ text: `- Cũng vậy, bạch chư Thượng tọa, con mắt không phải là trói buộc của các sắc; các sắc không phải là trói buộc của con mắt. Và ở đây, do duyên cả hai khởi lên dục tham gì, dục tham ấy ở đây chính là trói buộc. Cái tai không phải là trói buộc của các tiếng … Mũi không phải là trói buộc của các hương … Lưỡi không phải là trói buộc của các vị … Thân không phải là trói buộc của các xúc … Ý không phải là trói buộc của các pháp. Các pháp cũng không phải là trói buộc của ý. Và ở đây, do duyên cả hai khởi lên dục tham gì, dục tham ấy ở đây chính là trói buộc.`, ref: "Tương Ưng Bộ 41.1", url: "https://loicuaducphat.org/sn/sn41.1.html#content" },

{ text: `Bộ phận được tinh thuần,\nMái trần che mầu trắng,\nChỉ có một bánh xe,\nCỗ xe liên tục chạy.\nHãy xem vị đang đến,\nKhông vi phạm lỗi lầm,\nChặt đứt được dòng nước,\nKhông còn bị trói buộc.\n\n: “Bộ phận được tinh thuần”, bạch Thượng tọa, là đồng nghĩa với các giới luật. “Mái trần che màu trắng”, bạch Thượng tọa, là đồng nghĩa với giải thoát. “Một bánh xe”, bạch Thượng tọa, là đồng nghĩa với niệm. “Liên tục chạy”, bạch Thượng tọa, là đồng nghĩa với đi tới đi lui. “Cỗ xe”, bạch Thượng tọa, là đồng nghĩa với cái thân do bốn đại tạo thành này, do cha mẹ sanh ra, do cơm cháo nuôi dưỡng, vô thường, bị biến hoại, bị tiêu mòn, bị tiêu hủy, bị hủy diệt. Tham, bạch Thượng tọa, là một lỗi lầm. Sân là một lỗi lầm. Si là một lỗi lầm. Ðối với Tỷ-kheo đã đoạn tận các lậu hoặc, chúng được đoạn tận, chặt đứt từ gốc rễ, làm cho như thân cây ta-la, không có thể tái sanh, không có thể sanh khởi trong tương lai. Do vậy, Tỷ-kheo đã đoạn tận các lậu hoặc được gọi là không vi phạm lỗi lầm. “Vị đang đến”, bạch Thượng tọa, là đồng nghĩa với vị A-la-hán. “Dòng nước”, bạch Thượng tọa, là đồng nghĩa với khát ái. Ðối với Tỷ-kheo đã đoạn tận các lậu hoặc, khát ái ấy được đoạn tận, cắt đứt tận gốc rễ, làm cho như thân cây ta-la, không có thể tái sanh, không có thể sanh khởi trong tương lai. Do vậy, Tỷ-kheo đã đoạn tận các lậu hoặc được gọi là chặt đứt được dòng nước.`, ref: "Tương Ưng Bộ 41.5", url: "https://loicuaducphat.org/sn/sn41.5.html#content" },

{ text: `- Ví như, này Thôn trưởng, có người lấy một tảng đá lớn ném xuống một hồ nước sâu. Rồi một quần chúng đông đảo, tụ tập, tụ họp lại, cầu khẩn, tán dương, chấp tay đi cùng khắp và nói rằng: “Hãy đứng lên, tảng đá lớn! Hãy nổi lên, tảng đá lớn! Hãy trôi vào bờ, này tảng đá lớn!” Ông nghĩ thế nào, này Thôn trưởng, tảng đá lớn ấy do nhân cầu khẩn của đại quần chúng ấy, hay do nhân tán dương, hay do nhân chấp tay đi cùng khắp, có thể trồi lên, hay nổi lên, hay trôi dạt vào bờ không? - Thưa không, bạch Thế Tôn. - Cũng vậy, này Thôn trưởng, người nào sát sanh, lấy của không cho, sống theo tà hạnh trong các dục, nói láo, nói hai lưỡi, nói lời độc ác, nói lời phù phiếm, tham lam, sân hận, theo tà kiến. Rồi một quần chúng đông đảo, tụ tập, tụ họp lại, cầu khẩn, tán dương, chấp tay đi cùng khắp và nói rằng: “Mong người này, sau khi thân hoại mạng chung, được sanh lên thiện thú, Thiên giới, cõi đời này!” Nhưng người ấy, sau khi thân hoại mạng chung, phải sanh vào cõi dữ, ác thú, đọa xứ, địa ngục.`, ref: "Tương Ưng Bộ 42.6", url: "https://loicuaducphat.org/sn/sn42.6.html#content" },

{ text: `Này Thôn trưởng, các Sa-môn Thích tử không được phép dùng vàng bạc. Các Sa-môn Thích tử không được giữ vàng bạc. Các Sa-môn Thích tử không được nhận lấy vàng bạc. Các Sa-môn Thích tử đã từ bỏ châu báu và vàng bạc. Họ đã ly khai vàng và bạc. Ðối với ai được dùng vàng bạc, người ấy cũng được phép dùng năm dục trưởng dưỡng. Ðối với ai được phép dùng năm dục trưởng dưỡng, người ấy hoàn toàn thọ trì phi Sa-môn pháp, phi Thích tử pháp. Này Thôn trưởng, Ta nói như sau: Cỏ được đi tìm cầu bởi ai cần đến cỏ. Củi được đi tìm cầu bởi ai cần đến củi. Cỗ xe được đi tìm cầu bởi ai cần đến cỗ xe. Người được đi tìm cầu bởi ai cần đến người. Nhưng này Thôn trưởng, không bất cứ một lý do gì Ta nói rằng vàng, bạc được chấp nhận, được tìm cầu.`, ref: "Tương Ưng Bộ 42.10", url: "https://loicuaducphat.org/sn/sn42.10.html#content" },

{ text: `- Ông nghĩ thế nào, này Thôn trưởng, nếu đứa trẻ Ciravàsii của Ông bị giết, hay bị bắt, hay bị thiệt hại, hay bị chỉ trích, Ông có khởi lên sầu, bi, khổ, ưu, não không? - Bạch Thế Tôn, nếu đứa con trai Ciravàsii của con bị giết, hay bị bắt, hay bị thiệt hại, hay bị chỉ trích, hay sinh mạng bị đổi khác, thời làm sao con không khởi lên sầu, bi, khổ, ưu, não được? - Với pháp môn này, này Thôn trưởng, cần phải hiểu như sau: Phàm có khổ nào khởi lên, tất cả khổ ấy đều lấy dục làm căn bản, lấy dục làm sở nhân. Dục là căn bản của khổ.`, ref: "Tương Ưng Bộ 42.11", url: "https://loicuaducphat.org/sn/sn42.11.html#content" },
{ text: `Ít thay là những người,\nÐạt đến bờ bên kia.\nPhần lớn quần chúng khác,\nChạy qua lại bờ này.\n\nNhững ai theo thuyết giảng,\nChánh pháp khéo tuyên thuyết,\nHọ đến bờ bên kia,\nKhéo vượt cảnh giới Ma.\n\nÐoạn tận các hắc pháp,\nBậc trí tu bạch pháp,\nBỏ nhà, sống không nhà,\nTrong độc cư, khó lạc.\n\nỞ đây, muốn hưởng lạc,\nHãy bỏ mọi dục vọng,\nBậc trí tự thanh lọc,\nTự tâm khỏi phiền não.\n\nNhững ai khéo tu tập,\nChánh tâm trong giác chi,\nTừ bỏ các chấp trước,\nHoan hỷ không chấp thủ,\nLậu hoặc tận, chói sáng,\nÐạt tịch tịnh ở đời.`, ref: "Tương Ưng Bộ 45.34", url: "https://loicuaducphat.org/sn/sn45.34.html#content" },

{ text: `- Này các Tỷ-kheo, như cái đi trước và điềm tướng báo trước mặt trời mọc, tức là rạng đông; cũng vậy, này các Tỷ-kheo, cái đi trước và điềm tướng báo trước sự sanh khởi của Thánh đạo Tám ngành, chính là bạn hữu với thiện. Này các Tỷ-kheo, Tỷ-kheo bạn hữu với thiện, thời chờ đợi rằng Thánh đạo Tám ngành sẽ được tu tập, Thánh đạo Tám ngành sẽ được sung mãn. Và này các Tỷ-kheo, thế nào là Tỷ-kheo bạn hữu với thiện, tu tập Thánh đạo Tám ngành và làm cho sung mãn Thánh đạo Tám ngành? Ở đây, này các Tỷ-kheo, Tỷ-kheo tu tập chánh tri kiến liên hệ đến viễn ly, liên hệ đến ly tham, liên hệ đến đoạn diệt, hướng đến từ bỏ … tu tập chánh định … hướng đến từ bỏ. Như vậy, này các Tỷ-kheo, Tỷ-kheo làm bạn hữu với thiện, tu tập Thánh đạo Tám ngành và làm cho sung mãn Thánh đạo Tám ngành.`, ref: "Tương Ưng Bộ 45.50", url: "https://loicuaducphat.org/sn/sn45.50.html#content" },

{ text: `Và này các Tỷ-kheo, Tỷ-kheo đầy đủ như lý tác ý này, thời chờ đợi rằng Thánh đạo Tám ngành sẽ được tu tập, Thánh đạo Tám ngành sẽ được sung mãn. Và này các Tỷ-kheo, thế nào là Tỷ-kheo đầy đủ như lý tác ý, tu tập Thánh đạo Tám ngành, làm cho sung mãn Thánh đạo Tám ngành? Ở đây, này các Tỷ-kheo, Tỷ-kheo tu tập chánh tri kiến với cứu cánh là nhiếp phục tham, với cứu cánh là nhiếp phục sân, với cứu cánh là nhiếp phục si. Như vậy, này các Tỷ-kheo, Tỷ-kheo đầy đủ như lý tác ý … tu tập chánh định với cứu cánh là nhiếp phục tham, với cứu cánh là nhiếp phục sân, với cứu cánh là nhiếp phục si … Như vậy, này các Tỷ-kheo, Tỷ-kheo đầy đủ như lý tác ý, tu tập Thánh đạo Tám ngành, và làm cho sung mãn Thánh đạo Tám ngành.`, ref: "Tương Ưng Bộ 45.64", url: "https://loicuaducphat.org/sn/sn45.64.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, phàm có những dấu chân của các loại chúng sanh bộ hành nào, tất cả đều hội tập trong chân con voi, vì chân con voi được gọi là tối thượng trong tất cả loại chân, tức là về phần to lớn. Cũng vậy, này các Tỷ-kheo, phàm có những thiện pháp nào, tất cả đều lấy không phóng dật làm căn bản, lấy không phóng dật làm chỗ quy tụ, không phóng dật được gọi là tối thượng trong tất cả thiện pháp. Với Tỷ-kheo không phóng dật, này các Tỷ-kheo, được chờ đợi rằng Thánh đạo Tám ngành được tu tập, Thánh đạo Tám ngành sẽ được sung mãn.`, ref: "Tương Ưng Bộ 45.142", url: "https://loicuaducphat.org/sn/sn45.142.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, có cây thiên về hướng Ðông, hướng về hướng Ðông, xuôi về hướng Ðông, khi bị chặt từ gốc, cây ấy sẽ rơi về hướng nào? - Bạch Thế Tôn, về phía nó thiên về, về phía nó hướng về, về phía nó xuôi về. - Cũng vậy, này các Tỷ-kheo, Tỷ-kheo tu tập Thánh đạo Tám ngành, làm cho sung mãn Thánh đạo Tám ngành, thiên về Niết-bàn, hướng về Niết-bàn, xuôi về Niết-bàn. Ở đây, này các Tỷ-kheo, Tỷ-kheo tu tập chánh tri kiến liên hệ đến viễn ly … tu tập chánh định liên hệ đến viễn ly, liên hệ đến ly tham, liên hệ đến đoạn diệt, hướng đến từ bỏ. Cũng vậy, này các Tỷ-kheo, Tỷ-kheo tu tập Thánh đạo Tám ngành, làm cho sung mãn Thánh đạo Tám ngành, thiên về Niết-bàn, hướng về Niết-bàn, xuôi về Niết-bàn.`, ref: "Tương Ưng Bộ 45.154", url: "https://loicuaducphat.org/sn/sn45.154.html#content" },

{ text: `- Này các Tỷ-kheo, có ba loại tầm cầu. Thế nào là ba? Tầm cầu về dục, tầm cầu về hữu, tầm cầu về Phạm hạnh. Những pháp này, này các Tỷ-kheo, là ba tầm cầu. Chính vì liễu tri ba tầm cầu này mà Thánh đạo Tám ngành được tu tập.`, ref: "Tương Ưng Bộ 45.165", url: "https://loicuaducphat.org/sn/sn45.165.html#content" },

{ text: `- Này các Tỷ-kheo, có ba kiêu mạn. Thế nào là ba? Kiêu mạn: “Tôi hơn”; kiêu mạn: “Tôi bằng”; kiêu mạn: “Tôi thua”. Này các Tỷ-kheo, đó là ba kiêu mạn này. Chính vì mục đích thắng tri, liễu tri, đoạn diệt, đoạn tận ba kiêu mạn này mà Thánh đạo Tám ngành được tu tập. Thế nào là Thánh đạo Tám ngành được tu tập? Ở đây, này các Tỷ-kheo, Tỷ-kheo tu tập chánh tri kiến … tu tập chánh định liên hệ đến viễn ly, liên hệ đến ly tham, liên hệ đến đoạn diệt, hướng đến từ bỏ. Chính vì mục đích thắng tri, liễu tri, đoạn diệt, đoạn tận ba kiêu mạn này mà Thánh đạo Tám ngành này cần phải tu tập.`, ref: "Tương Ưng Bộ 45.168", url: "https://loicuaducphat.org/sn/sn45.168.html#content" },

{ text: `- Y cứ vào vua núi Tuyết sơn, này các Tỷ-kheo, các loài rắn lớn tăng trưởng tự thân, thâu hoạch sức mạnh. Ở đấy, khi chúng tăng trưởng tự thân, thâu hoạch sức mạnh, chúng đi xuống các hồ nhỏ. Sau khi xuống các hồ nhỏ, chúng đi xuống các hồ lớn. Sau khi đi xuống các hồ lớn, chúng đi xuống các sông nhỏ. Sau khi đi xuống các sông nhỏ, chúng đi xuống các sông lớn. Sau khi đi xuống các sông lớn, chúng đi ra biển, ra đại dương. Tại đấy, thân của chúng được to lớn và quảng đại hơn.\n\nCũng vậy, này các Tỷ-kheo, Tỷ-kheo y cứ vào giới, an trú vào giới, tu tập bảy giác chi, làm cho sung mãn bảy giác chi, đạt được sự to lớn, sự quảng đại trong các pháp.`, ref: "Tương Ưng Bộ 46.1", url: "https://loicuaducphat.org/sn/sn46.1.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, cái thân này y cứ món ăn, duyên món ăn được an trú; không có món ăn thì không an trú. Cũng vậy, này các Tỷ-kheo, năm triền cái y cứ món ăn, duyên món ăn được an trú; không có món ăn thì không an trú. Và này các Tỷ-kheo, món ăn nào đối với dục tham chưa sanh được sanh khởi; hay đối với dục tham đã sanh được tăng trưởng, quảng đại? Này các Tỷ-kheo, có tịnh tướng, ở đây, nếu phi như lý tác ý được làm cho sung mãn, thời tịnh tướng này là món ăn khiến cho dục tham chưa sanh được sanh khởi; hay đối với dục tham đã sanh khiến cho tăng trưởng, quảng đại.`, ref: "Tương Ưng Bộ 46.2", url: "https://loicuaducphat.org/sn/sn46.2.html#content" },

{ text: `Và này các Tỷ-kheo, món ăn nào đối với sân chưa sanh làm cho sanh khởi; hay đối với sân đã sanh khiến được tăng trưởng, quảng đại? Này các Tỷ-kheo, có đối ngại tướng. Ở đây, nếu phi như lý tác ý được làm cho sung mãn, thời đối ngại tướng này là món ăn khiến cho sân chưa sanh được sanh khởi; hay đối với sân đã sanh khiến cho tăng trưởng, quảng đại.`, ref: "Tương Ưng Bộ 46.2", url: "https://loicuaducphat.org/sn/sn46.2.html#content" },

{ text: `Này các Tỷ-kheo, món ăn nào đối với hôn trầm thụy miên chưa sanh làm cho sanh khởi; hay đối với hôn trầm thụy miên đã sanh khiến cho tăng trưởng, quảng đại? Này các Tỷ-kheo, có sự không hân hoan, biếng nhác, uể oải, ăn quá no, tâm rụt rè. Ở đây, nếu phi như lý tác ý được làm cho sung mãn, thời chính là món ăn khiến cho hôn trầm thụy miên chưa sanh được sanh khởi; hay đối với hôn trầm thụy miên đã sanh khiến cho tăng trưởng, quảng đại.`, ref: "Tương Ưng Bộ 46.2", url: "https://loicuaducphat.org/sn/sn46.2.html#content" },

{ text: `Và này các Tỷ-kheo, món ăn nào đối với định giác chi chưa sanh khiến cho sanh khởi; hay đối với định giác chi đã sanh được tu tập, làm cho viên mãn? Này các Tỷ-kheo, có tịnh chỉ tướng, bất loạn tướng. Ở đây, nếu như lý tác ý được làm cho viên mãn, thời đây là món ăn khiến cho định giác chi chưa sanh được sanh khởi; hay đối với định giác chi đã sanh khiến cho được tu tập, làm cho viên mãn.`, ref: "Tương Ưng Bộ 46.2", url: "https://loicuaducphat.org/sn/sn46.2.html#content" },

{ text: `- Này các Tỷ-kheo, những Tỷ-kheo nào cụ túc giới, cụ túc định, cụ túc tuệ, cụ túc giải thoát, cụ túc giải thoát tri kiến, Ta nói rằng ai thấy các Tỷ-kheo ấy thì có rất nhiều lợi ích. Ai nghe các Tỷ-kheo ấy, này các Tỷ-kheo, Ta nói rằng có rất nhiều lợi ích. Ai yết kiến các Tỷ-kheo ấy, này các Tỷ-kheo, Ta nói rằng có rất nhiều lợi ích. Ai thân cận các Tỷ-kheo ấy, này các Tỷ-kheo, Ta nói rằng có rất nhiều lợi ích. Ai nhớ nghĩ đến các Tỷ-kheo ấy, này các Tỷ-kheo, Ta nói rằng có rất nhiều lợi ích. Ai tùy thuận các Tỷ-kheo ấy xuất gia, này các Tỷ-kheo, Ta nói rằng có rất nhiều lợi ích. Vì sao? Này các Tỷ-kheo, khi nghe pháp từ các Tỷ-kheo như vậy, vị nào sống viễn ly, được hai sự viễn ly: viễn ly về thân và viễn ly về tâm. Vị sống viễn ly như vậy thì sẽ tùy niệm pháp ấy, tùy tầm pháp ấy.`, ref: "Tương Ưng Bộ 46.3", url: "https://loicuaducphat.org/sn/sn46.3.html#content" },

{ text: `Này các Tỷ-kheo, trong khi Tỷ-kheo sống viễn ly như vậy, tùy niệm, tùy tầm pháp ấy; trong lúc ấy, niệm giác chi bắt đầu phát khởi trong Tỷ-kheo ấy. Trong khi Tỷ-kheo tu tập niệm giác chi; trong khi ấy, nhờ tu tập, niệm giác chi đi đến viên mãn. Vị ấy trú với chánh niệm như vậy, với trí tuệ quyết trạch, tư sát, thành tựu quán sát pháp ấy. Trong khi, này các Tỷ-kheo, Tỷ-kheo sống chánh niệm như vậy, với trí tuệ quyết trạch, tư sát và đi đến quán sát pháp ấy; trong khi ấy, này các Tỷ-kheo, trạch pháp giác chi bắt đầu phát khởi trong Tỷ-kheo ấy. Trong khi Tỷ-kheo tu tập trạch pháp giác chi; trong khi ấy, nhờ tu tập, trạch pháp giác chi đi đến viên mãn. Trong khi vị ấy với trí tuệ quyết trạch, tư sát và thành tựu quán sát pháp ấy, thời tinh tấn, không thụ động bắt đầu phát khởi nơi vị ấy.`, ref: "Tương Ưng Bộ 46.3", url: "https://loicuaducphat.org/sn/sn46.3.html#content" },

{ text: `Trong khi, này các Tỷ-kheo, Tỷ-kheo với ý hoan hỷ, thân được khinh an, tâm được khinh an; trong khi ấy, khinh an giác chi bắt đầu phát khởi trong Tỷ-kheo ấy. Trong khi Tỷ-kheo tu tập khinh an giác chi; trong khi ấy, nhờ tu tập, khinh an giác chi đi đến viên mãn. Với vị có thân khinh an, lạc hiện hữu. Với vị có lạc, tâm được định tĩnh. Trong khi, này các Tỷ-kheo, Tỷ-kheo có thân khinh an, được an lạc, tâm được định tĩnh; trong khi ấy, này các Tỷ-kheo, định giác chi bắt đầu phát khởi trong Tỷ-kheo ấy. Trong khi Tỷ-kheo tu tập định giác chi; trong khi ấy, định giác chi nhờ tu tập, đi đến viên mãn. Vị ấy với tâm định tĩnh như vậy, khéo trú xả nhìn (sự vật). Trong khi, này các Tỷ-kheo, Tỷ-kheo với tâm định tĩnh, khéo trú xả nhìn (sự vật) như vậy; trong khi ấy, này các Tỷ-kheo, xả giác chi bắt đầu phát khởi trong Tỷ-kheo ấy. Trong khi Tỷ-kheo tu tập xả giác chi; trong khi ấy, xả giác chi nhờ tu tập, đi đến viên mãn.`, ref: "Tương Ưng Bộ 46.3", url: "https://loicuaducphat.org/sn/sn46.3.html#content" },
{ text: `Chính cấu uế của vàng, này các Tỷ-kheo, do những cấu uế ấy, vàng bị uế nhiễm, không có nhu nhuyến, không có kham nhậm, không có chói sáng, dễ bị bể vụn, và không chân chánh chịu sử dụng. Cũng vậy, này các Tỷ-kheo, có năm cấu uế này của tâm, chính những cấu uế ấy khiến tâm bị uế nhiễm, không có nhu nhuyến, không có kham nhậm, không có chói sáng, dễ bị bể vụn, không chân chánh được định tĩnh để đoạn diệt các lậu hoặc. Thế nào là năm? Dục tham, này các Tỷ-kheo, là cấu uế của tâm. Do cấu uế ấy, tâm bị uế nhiễm, không có nhu nhuyến, không có kham nhậm, không có chói sáng, dễ bị bể vụn, không chân chánh được định tĩnh để đoạn diệt các lậu hoặc. … (Với sân, hôn trầm thụy miên, trạo hối, nghi) Những pháp này, này các Tỷ-kheo, là năm cấu uế của tâm. Chính do những cấu uế ấy, tâm không có nhu nhuyến, không có kham nhậm, không có chói sáng, dễ bị bể vụn, và không chân chánh được định tĩnh để đoạn diệt các lậu hoặc.`, ref: "Tương Ưng Bộ 46.33", url: "https://loicuaducphat.org/sn/sn46.33.html#content" },

{ text: `Này các Tỷ-kheo, ở đây, có thiện nam tử đoạn trừ các dục vọng, xuất gia, từ bỏ gia đình, sống không gia đình, nhưng bị những dục vọng ấy, hay bị những dục vọng tệ hại hơn làm cho người ấy bị phá hủy, bị hư hại, ngã xuống, nằm rạp xuống. Năm chướng ngại, triền cái này, này các Tỷ-kheo, bao trùm tâm, làm cho yếu ớt trí tuệ. Thế nào là năm? Dục tham, này các Tỷ-kheo, là chướng ngại, triền cái, bao trùm tâm, làm cho yếu ớt trí tuệ. Sân, này các Tỷ-kheo, là chướng ngại, triền cái, bao trùm tâm, làm cho yếu ớt trí tuệ. Hôn trầm thụy miên … Trạo hối … Nghi hoặc, này các Tỷ-kheo, là chướng ngại, triền cái, bao trùm tâm, làm cho yếu ớt trí tuệ. Này các Tỷ-kheo, năm chướng ngại, triền cái này bao trùm tâm và làm cho yếu ớt trí tuệ. Bảy giác chi này, này các Tỷ-kheo, không phải là chướng ngại, triền cái, không bao trùm tâm, được tu tập, được làm cho sung mãn, đưa đến chứng ngộ quả minh và giải thoát. Thế nào là bảy? Niệm giác chi, này các Tỷ-kheo, không phải là chướng ngại, triền cái, không bao trùm tâm, được tu tập, được làm cho sung mãn, đưa đến chứng ngộ quả minh và giải thoát … Xả giác chi, này các Tỷ-kheo, không phải là chướng ngại, triền cái, không bao trùm tâm, được tu tập, được làm cho sung mãn, đưa đến chứng ngộ quả minh và giải thoát. Bảy giác chi này, này các Tỷ-kheo, không phải là chướng ngại, triền cái, không bao trùm tâm, được tu tập, được làm cho sung mãn, đưa đến chứng ngộ quả minh và giải thoát.`, ref: "Tương Ưng Bộ 46.39", url: "https://loicuaducphat.org/sn/sn46.39.html#content" },

{ text: `- Trong khi tâm thụ động, này các Tỷ-kheo, trong khi ấy, không phải thời là tu tập khinh an giác chi, không phải thời là tu tập định giác chi, không phải thời là tu tập xả giác chi. Vì sao? Khi tâm thụ động, này các Tỷ-kheo, thật khó làm tâm phát khởi nhờ những pháp này. Ví như, này các Tỷ-kheo, một người muốn đốt lên một ngọn lửa nhỏ, người ấy ném vào đấy cỏ ướt, phân bò ướt, củi ướt, để ngọn lửa ấy giữa mưa, gió và rắc bụi lên trên; người ấy có thể nhen đỏ ngọn lửa nhỏ ấy không? - Thưa không, bạch Thế Tôn. - Cũng vậy, này các Tỷ-kheo, trong khi tâm thụ động, trong khi ấy, không phải thời là tu tập khinh an giác chi, không phải thời là tu tập định giác chi, không phải thời là tu tập xả giác chi. Vì sao? Vì rằng, khi tâm thụ động, thật khó làm tâm phát khởi nhờ những pháp này.`, ref: "Tương Ưng Bộ 46.60", url: "https://loicuaducphat.org/sn/sn46.60.html#content" },

{ text: `- Và này các Tỷ-kheo, trong khi tâm thụ động, trong khi ấy, phải thời là tu tập trạch pháp giác chi, phải thời là tu tập tinh tấn giác chi, phải thời là tu tập hỷ giác chi. Vì sao? Vì rằng, này các Tỷ-kheo, khi tâm thụ động, thật dễ làm tâm phát khởi nhờ những pháp này. Ví như, này các Tỷ-kheo, một người muốn đốt lên một ngọn lửa nhỏ, người ấy ném vào đấy cỏ khô, phân bò khô, củi khô, dùng miệng thổi, không có rắc bụi lên trên; người ấy có thể nhen đỏ ngọn lửa ấy không? - Thưa có, bạch Thế Tôn. - Cũng vậy, này các Tỷ-kheo, trong khi tâm thụ động, trong khi ấy, phải thời là tu tập trạch pháp giác chi, phải thời là tu tập tinh tấn giác chi, phải thời là tu tập hỷ giác chi. Vì sao? Vì rằng, này các Tỷ-kheo, khi tâm thụ động, thật dễ làm tâm phát khởi nhờ những pháp này.`, ref: "Tương Ưng Bộ 46.61", url: "https://loicuaducphat.org/sn/sn46.61.html#content" },

{ text: `- Và này các Tỷ-kheo, trong khi tâm dao động, trong khi ấy, không phải thời là tu tập trạch pháp giác chi, không phải thời là tu tập tinh tấn giác chi, không phải thời là tu tập hỷ giác chi. Vì sao? Vì rằng, này các Tỷ-kheo, tâm dao động, thật khó được tịnh chỉ do những pháp ấy. Ví như, này các Tỷ-kheo, một người muốn dập tắt một đống lửa lớn. Ở đây, người ấy ném vào cỏ khô, phân bò khô và củi khô, lấy miệng thổi, và không rắc bụi lên trên. Người ấy có thể dập tắt đống lửa lớn ấy không? - Thưa không, bạch Thế Tôn. - Cũng vậy, này các Tỷ-kheo, trong khi tâm dao động, không phải thời là tu tập trạch pháp giác chi, không phải thời là tu tập tinh tấn giác chi, không phải thời là tu tập hỷ giác chi. Vì sao? Vì rằng, tâm dao động, thật không dễ được tịnh chỉ nhờ những pháp ấy.`, ref: "Tương Ưng Bộ 46.62", url: "https://loicuaducphat.org/sn/sn46.62.html#content" },

{ text: `- Và này các Tỷ-kheo, trong khi tâm dao động, trong khi ấy, phải thời là tu tập khinh an giác chi, phải thời là tu tập định giác chi, phải thời là tu tập xả giác chi. Vì sao? Vì rằng, tâm dao động thật dễ được tịnh chỉ nhờ những pháp này. Ví như, này các Tỷ-kheo, có người muốn dập tắt một đống lửa lớn. Ở đây, người ấy ném vào cỏ ướt, ném vào phân bò ướt, ném vào củi ướt, để giữa gió và mưa, và rắc bụi lên trên. Người ấy có thể dập tắt ngọn lửa lớn ấy không? - Thưa có, bạch Thế Tôn. - Cũng vậy, này các Tỷ-kheo, trong khi tâm dao động, trong khi ấy, phải thời là tu tập khinh an giác chi, phải thời là tu tập định giác chi, phải thời là tu tập xả giác chi. Vì sao? Vì rằng, tâm dao động, thật dễ được tịnh chỉ nhờ các pháp này. Nhưng đối với niệm, này các Tỷ-kheo, Ta nói rằng lợi ích trong mọi trường hợp.`, ref: "Tương Ưng Bộ 46.63", url: "https://loicuaducphat.org/sn/sn46.63.html#content" },

{ text: `- Có con đường độc nhất này, này các Tỷ-kheo, khiến cho các loài hữu tình được thanh tịnh, vượt qua được sầu bi, chấm dứt khổ ưu, chứng đạt chánh lý, chứng ngộ Niết-bàn. Tức là bốn niệm xứ. Thế nào là bốn? - Ở đây, này các Tỷ-kheo, Tỷ-kheo trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời … trú, quán thọ trên các cảm thọ, nhiệt tâm, tỉnh giác, chánh niệm … trú, quán tâm trên tâm, nhiệt tâm, tỉnh giác … trú, quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Có con đường độc nhất này, này các Tỷ-kheo, khiến cho các loài hữu tình được thanh tịnh, vượt qua được sầu bi, chấm dứt khổ ưu, chứng đạt chánh lý, chứng ngộ Niết-bàn. Con đường ấy tức là bốn niệm xứ.`, ref: "Tương Ưng Bộ 47.1", url: "https://loicuaducphat.org/sn/sn47.1.html#content" },

{ text: `- Này các Tỷ-kheo, Tỷ-kheo cần phải trú chánh niệm, tỉnh giác. Ðây là lời giáo giới của Ta cho các Ông. Và này các Tỷ-kheo, thế nào là Tỷ-kheo chánh niệm? Ở đây, này các Tỷ-kheo, Tỷ-kheo trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời … quán thọ trên các thọ … quán tâm trên tâm … quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Như vậy, này các Tỷ-kheo, là Tỷ-kheo chánh niệm. Và này các Tỷ-kheo, thế nào là Tỷ-kheo tỉnh giác? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi đi tới, khi đi lui, đều tỉnh giác; khi nhìn tới, khi nhìn lui, đều tỉnh giác; khi co cánh tay, duỗi cánh tay, đều tỉnh giác; khi đắp y Tăng-già-lê, khi mang y bát, đều tỉnh giác; khi ăn uống, nhai nếm, đều tỉnh giác; khi đi tiểu tiện, đại tiện, đều tỉnh giác; khi đi, đứng, ngồi, ngủ, thức, nói, im lặng, đều tỉnh giác. Như vậy, này các Tỷ-kheo, là Tỷ-kheo tỉnh giác. Này các Tỷ-kheo, Tỷ-kheo hãy chánh niệm, tỉnh giác. Ðây là lời giáo giới của Ta cho các Ông.`, ref: "Tương Ưng Bộ 47.2", url: "https://loicuaducphat.org/sn/sn47.2.html#content" },

{ text: `- Vậy này Tỷ-kheo, Ông phải gột sạch hai pháp cơ bản về các thiện pháp. Và thế nào là hai pháp cơ bản về các thiện pháp? Chính là giới khéo thanh tịnh, và tri kiến chánh trực. Này Tỷ-kheo, khi nào Ông được giới khéo thanh tịnh và tri kiến chánh trực, này Tỷ-kheo, Ông hãy y cứ trên giới, an trú trên giới, tu tập bốn niệm xứ theo ba cách. Thế nào là bốn? Ở đây, này Tỷ-kheo, Ông hãy trú, quán thân trên nội thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Hay Ông hãy trú, quán thân trên ngoại thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Hay Ông hãy trú, quán thân trên nội ngoại thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Hay Ông hãy trú, quán thọ trên các nội thọ … Hay Ông hãy trú, quán tâm trên các nội tâm … Hay Ông hãy trú, quán pháp trên các nội pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Hay Ông hãy trú, quán pháp trên các ngoại pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Hay Ông hãy trú, quán pháp trên các nội ngoại pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Này Tỷ-kheo, khi nào Ông y cứ trên giới, an trú trên giới và tu tập bốn niệm xứ theo ba cách như vậy; khi ấy, này Tỷ-kheo, hoặc đêm hay ngày, chờ đợi là tăng trưởng trong các thiện pháp, không phải là tổn giảm.`, ref: "Tương Ưng Bộ 47.3", url: "https://loicuaducphat.org/sn/sn47.3.html#content" },

{ text: `“Hãy đến, này các Tỷ-kheo, hãy trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chuyên chú, với tâm thanh tịnh, định tĩnh, nhất tâm, để có chánh trí như thật đối với thân. Hãy trú, quán thọ trên các thọ, nhiệt tâm, tỉnh giác, chuyên chú, với tâm thanh tịnh, định tĩnh, nhất tâm để có chánh trí như thật đối với các thọ. Hãy trú, quán tâm trên tâm, nhiệt tâm, tỉnh giác, chuyên chú, với tâm thanh tịnh, định tĩnh, nhất tâm, để có chánh trí như thật đối với tâm. Hãy trú, quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chuyên chú, với tâm thanh tịnh, định tĩnh, nhất tâm, để có chánh trí như thật đối với các pháp”. Này các Tỷ-kheo, những Tỷ-kheo nào mới tu, xuất gia chẳng bao lâu, mới đến trong Pháp và Luật này; những vị ấy, này các Tỷ-kheo, cần phải được khích lệ, cần phải được hướng dẫn, cần phải được an trú, tu tập bốn niệm xứ này.`, ref: "Tương Ưng Bộ 47.4", url: "https://loicuaducphat.org/sn/sn47.4.html#content" },

{ text: `- Ðống bất thiện, này các Tỷ-kheo, nếu có ai nói là năm triền cái, người ấy nói một cách chơn chánh. Toàn bộ đống bất thiện này, này các Tỷ-kheo, tức là năm triền cái. Thế nào là năm? Dục tham triền cái, sân triền cái, hôn trầm thụy miên triền cái, trạo hối triền cái, nghi hoặc triền cái. Ðống bất thiện này, này các Tỷ-kheo, nếu có ai nói là năm triền cái, người ấy nói một cách chơn chánh. Toàn bộ đống bất thiện này, này các Tỷ-kheo, tức là năm triền cái. Ðống thiện, này các Tỷ-kheo, nếu có ai nói là bốn niệm xứ, người ấy nói một cách chơn chánh. Toàn bộ đống thiện này, này các Tỷ-kheo, tức là bốn niệm xứ. Thế nào là bốn? Ở đây, này các Tỷ-kheo, Tỷ-kheo trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời … quán thọ trên các thọ … quán tâm trên tâm … quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Ðống thiện này, này các Tỷ-kheo, nếu có ai nói là bốn niệm xứ, người ấy nói một cách chơn chánh. Toàn bộ đống thiện này, này các Tỷ-kheo, tức là bốn niệm xứ.`, ref: "Tương Ưng Bộ 47.5", url: "https://loicuaducphat.org/sn/sn47.5.html#content" },

{ text: `- Thuở xưa, này các Tỷ-kheo, một con chim ưng cái thình lình vồ xuống và chụp lấy một con chim cút. Rồi này các Tỷ-kheo, con chim cút bị con chim ưng cái bắt, than khóc như sau: “- Như thế này, thật bất hạnh cho tôi! Thật thiếu công đức cho tôi! Vì rằng tôi đã đi không phải chỗ hành xứ của mình, đi vào cảnh giới của người khác. Nếu tôi đi trong chỗ hành xứ của tôi, trong cảnh giới của cha mẹ tôi, thời con chim ưng này không thể hơn tôi, nếu phải đánh nhau”. “- Này Chim cút, thế nào là chỗ hành xứ của ngươi, thế nào là cảnh giới của cha mẹ ngươi?” : “Là vạt đất được lưỡi cày xới lên”. Rồi này các Tỷ-kheo, con chim ưng cái không có siết mạnh sức mạnh của mình, không có bóp chặt sức mạnh của mình, thả con chim cút rồi nói: : “Hãy đi, này Chim cút. Sau khi đi tại chỗ ấy, ta sẽ không thả cho ngươi”. Rồi này các Tỷ-kheo, con chim cút đi đến vạt đất được lưỡi cày xới lên, leo lên một hòn đất lớn, đứng trên ấy và nói với con chim ưng: “- Này, hãy đến ta, Chim ưng! Này, hãy đến ta, này Chim ưng!” Rồi này các Tỷ-kheo, con chim ưng cái siết mạnh sức mạnh của mình, bóp chặt sức mạnh của mình, xếp cả hai cánh, thình lình vồ lấy con chim cút. Này các Tỷ-kheo, khi con chim cút biết được: “Con chim ưng này đang vồ mạnh xuống ta”, liền nấp sau hòn đất ấy. Này các Tỷ-kheo, ở đây, con chim ưng bị bể ngực. Cũng vậy, này các Tỷ-kheo, đối với ai đi tới chỗ không phải hành xứ của mình, đi đến cảnh giới của người khác. Do vậy, này các Tỷ-kheo, chớ có đi đến chỗ không phải hành xứ của mình, chỗ cảnh giới của người khác. Này các Tỷ-kheo, đi đến chỗ không phải hành xứ của mình, đi đến cảnh giới của người khác, thời Ác ma nắm được cơ hội, Ác ma nắm được đối tượng.`, ref: "Tương Ưng Bộ 47.6", url: "https://loicuaducphat.org/sn/sn47.6.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, đối với ai đi tới chỗ không phải hành xứ của mình, đi đến cảnh giới của người khác. Do vậy, này các Tỷ-kheo, chớ có đi đến chỗ không phải hành xứ của mình, chỗ cảnh giới của người khác. Này các Tỷ-kheo, đi đến chỗ không phải hành xứ của mình, đi đến cảnh giới của người khác, thời Ác ma nắm được cơ hội, Ác ma nắm được đối tượng. Này các Tỷ-kheo, chỗ nào không phải hành xứ của Tỷ-kheo? Chỗ nào là cảnh giới của người khác? Chính là năm dục công đức. Thế nào là năm? Có các sắc do mắt nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Có các tiếng do tai nhận thức … Có các hương do mũi nhận thức … Có các vị do lưỡi nhận thức … Có các xúc do thân nhận thức khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, đây là chỗ không phải hành xứ của Tỷ-kheo, chỗ cảnh giới của người khác. Này các Tỷ-kheo, hãy đi đến chỗ hành xứ của mình, chỗ cảnh giới của cha mẹ mình. Này các Tỷ-kheo, đi đến chỗ hành xứ của mình, đến cảnh giới của cha mẹ mình, thời Ác ma không nắm được cơ hội, không nắm được đối tượng. Và này các Tỷ-kheo, chỗ nào là chỗ hành xứ của Tỷ-kheo? Chỗ nào là cảnh giới của cha mẹ? Chính là bốn niệm xứ. Thế nào là bốn? Ở đây, này các Tỷ-kheo, Tỷ-kheo trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời; trú, quán thọ trên các thọ…; trú, quán tâm trên tâm…; trú, quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Này các Tỷ-kheo, đây là chỗ hành xứ của mình, chỗ cảnh giới của cha mẹ mình.`, ref: "Tương Ưng Bộ 47.6", url: "https://loicuaducphat.org/sn/sn47.6.html#content" },

{ text: `- Này các Tỷ-kheo, tại núi chúa Tuyết sơn có khoảnh đất gồ ghề, không thăng bằng, chỗ ấy không có các loài vượn, loài người qua lại. Này các Tỷ-kheo, tại núi chúa Tuyết sơn có những khoảng đất ghồ ghề, không bằng phẳng, chỗ ấy chỉ có loài vượn qua lại, không có loài người. Tại núi chúa Tuyết sơn, có những khoảnh đất bằng phẳng, khả ái. Tại chỗ ấy có các loài vượn và loài người qua lại. Tại đấy, này các Tỷ-kheo, những người thợ săn đặt các bẫy nhựa trên những con đường có vượn qua lại để bắt các con vượn. Ở đây, này các Tỷ-kheo, những con vượn nào tánh không ngu si, không tham ăn, thấy bẫy nhựa ấy liền tránh xa. Còn con vượn nào ngu si, tham ăn, thấy bẫy nhựa ấy, thò tay nắm lấy và bị dính vào đấy. “Ta sẽ gỡ bàn tay ra”, nó thò bàn tay thứ hai nắm lấy và bị dính ở đấy. “Ta sẽ gỡ hai tay ra”, nó giơ chân nắm lấy và bị dính ở đấy. “Ta sẽ gỡ hai bàn tay và bàn chân ra”, nó giơ bàn chân thứ hai nắm lấy và bị dính ở đấy. “Ta sẽ gỡ cả hai tay và hai chân”, nó dùng miệng ngậm lấy và bị mắc dính ở đấy. Như vậy, này các Tỷ-kheo, con vượn bị bắt năm chỗ, liền rên la nằm xuống, rơi vào bất hạnh, rơi vào khổ não, bị người thợ săn muốn làm gì thì làm. Này các Tỷ-kheo, người thợ săn đâm chết nó, nướng nó trên đống than củi, và ra đi, theo sở thích của mình. Cũng vậy, này các Tỷ-kheo, là người đi đến chỗ không phải hành xứ của mình, chỗ cảnh giới của người khác. Này các Tỷ-kheo, đi đến chỗ không phải hành xứ của mình, chỗ cảnh giới của người khác, Ác ma nắm được cơ hội, Ác ma nắm được đối tượng.`, ref: "Tương Ưng Bộ 47.7", url: "https://loicuaducphat.org/sn/sn47.7.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, ở đây, có Tỷ-kheo ngu si, không thông minh, không khéo léo, trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Dầu vị ấy trú, quán thân trên thân, nhưng tâm không định tĩnh, các phiền não không được đoạn tận; vị ấy không học được tướng ấy. Dầu vị ấy trú, quán thọ trên các thọ ... quán tâm trên tâm ... Vị ấy trú, quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Dầu vị ấy trú, quán pháp trên các pháp, nhưng tâm không định tĩnh, các phiền não không được đoạn tận; vị ấy không học được tướng ấy. Này các Tỷ-kheo, Tỷ-kheo ngu si, không thông minh, không khéo léo ấy, không được lạc trú ngay trong hiện tại, không được tỉnh giác. Vì sao? Vì rằng, này các Tỷ-kheo, Tỷ-kheo ngu si, không thông minh, không khéo léo ấy, không học được tướng tâm của mình.`, ref: "Tương Ưng Bộ 47.8", url: "https://loicuaducphat.org/sn/sn47.8.html#content" },

{ text: `- Này Ānanda, có phải trước đây Ta đã từng tuyên bố với Ông rằng mọi pháp khả ái, khả ý đều có tánh chất khác biệt, có tánh chất ly tán, có tánh chất đổi khác? Làm sao, này Ānanda, ở đây, lời ước nguyền này có thể thành tựu được: “Mong rằng cái gì được sanh, được thành, là pháp hữu vi, là pháp bị diệt hoại, lại có thể không bị diệt hoại!”? Sự kiện như vậy không xảy ra. Ví như, này Ānanda, từ một cây lớn mọc thẳng, có lõi cây, một cành cây lớn bị gãy đổ. Cũng vậy, này Ānanda, từ nơi chúng Tỷ-kheo đứng thẳng, có lõi cây, Sāriputta bị mệnh chung. Làm sao, này Ānanda, ở đây, lời ước nguyền này có thể thành tựu được: “Mong sao cái gì được sanh, được thành, là pháp hữu vi, là pháp bị diệt hoại, lại có thể không bị diệt hoại!”? Sự kiện như vậy không xảy ra. Do vậy, này Ānanda, hãy tự mình là ngọn đèn cho chính mình, hãy tự mình nương tựa chính mình, chớ nương tựa một gì khác. Dùng Chánh pháp làm ngọn đèn, dùng Chánh pháp làm chỗ nương tựa, chớ nương tựa một điều gì khác.`, ref: "Tương Ưng Bộ 47.13", url: "https://loicuaducphat.org/sn/sn47.13.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào trong khi hộ trì cho mình, là hộ trì người khác? Chính do sự thực hành, do sự tu tập, do sự làm cho sung mãn. Như vậy, này các Tỷ-kheo, trong khi hộ trì cho mình, là hộ trì người khác. Và này các Tỷ-kheo, thế nào trong khi hộ trì người khác, là hộ trì cho mình? Chính do sự kham nhẫn, do sự vô hại, do lòng từ, do lòng ai mẫn. Như vậy, này các Tỷ-kheo, trong khi hộ trì người khác, là hộ trì cho mình. Này các Tỷ-kheo, “Tôi sẽ hộ trì cho mình”, tức là niệm xứ cần phải thực hành. Này các Tỷ-kheo, “Tôi sẽ hộ trì người khác”, tức là niệm xứ cần phải thực hành. Trong khi hộ trì cho mình, này các Tỷ-kheo, là hộ trì người khác. Trong khi hộ trì người khác, là hộ trì cho mình.`, ref: "Tương Ưng Bộ 47.19", url: "https://loicuaducphat.org/sn/sn47.19.html#content" },

{ text: `- Ví như một số đông quần chúng, này các Tỷ-kheo, tụ họp lại và nói: “Cô gái hoa hậu của quốc độ. Cô gái hoa hậu của quốc độ!”. Và người con gái hoa hậu quốc độ ấy với tất cả sự quyến rủ của mình, múa cho họ xem, với tất cả sự quyến rủ của mình, hát cho họ nghe. Và một số quần chúng còn đông hơn tụ họp lại và nói: “Cô gái hoa hậu của quốc độ múa và hát”. Rồi một người đến, muốn sống, không muốn chết, muốn lạc, ghét khổ, họ nói với người ấy như sau: “Này Ông, hãy xem đây. Ðây là cái bát đầy dầu. Ông hãy mang bát dầu ấy và đi vòng quanh đám quần chúng lớn và người con gái hoa hậu của quốc độ. Và một người với cây kiếm giơ cao sẽ đi theo sau lưng Ông. Tại chỗ nào làm đổ một ít dầu, tại chỗ ấy, đầu Ông bị rơi xuống”. Các Ông nghĩ thế nào, này các Tỷ-kheo, người ấy có thể không tác ý đến bát dầu, phóng tâm hướng ngoại không? - Ví dụ này, này các Tỷ-kheo, Ta nói ra để nêu rõ ý nghĩa. Và đây là ý nghĩa của nó. Này các Tỷ-kheo, cái bát đầy dầu là đồng nghĩa với thân hành niệm. Do vậy, này các Tỷ-kheo, các Ông cần phải học tập như sau: “Chúng ta sẽ tu tập thân hành niệm, làm cho sung mãn, làm cho như thành cỗ xe, làm cho như thành đất nền, làm cho tiếp tục an trú, làm cho tích tập, làm cho khéo có hiệu năng”. Như vậy, này các Tỷ-kheo, các Ông cần phải học tập.`, ref: "Tương Ưng Bộ 47.20", url: "https://loicuaducphat.org/sn/sn47.20.html#content" },

{ text: `“Quán thân trên thân này”, này các Tỷ-kheo, đối với các pháp từ trước Ta chưa từng được nghe, nhãn sanh, trí sanh, minh sanh, quang sanh. Quán thân trên thân cần phải tu tập này … Quán thân trên thân đã được tu tập này, này các Tỷ-kheo, đối với các pháp từ trước Ta chưa từng được nghe, nhãn sanh, trí sanh, minh sanh, quang sanh. “Quán thọ trên các cảm thọ này” … “Quán tâm trên tâm này” … “Quán pháp trên các pháp này”, này các Tỷ-kheo, đối với các pháp từ trước Ta chưa từng được nghe, nhãn sanh, trí sanh, minh sanh, quang sanh. Quán pháp trên pháp cần phải tu tập này … Quán pháp trên pháp đã được tu tập này, này các Tỷ-kheo, đối với các pháp từ trước Ta chưa từng được nghe, nhãn sanh, trí sanh, minh sanh, quang sanh.`, ref: "Tương Ưng Bộ 47.31", url: "https://loicuaducphat.org/sn/sn47.31.html#content" },

{ text: `- Này các Tỷ-kheo, Tỷ-kheo hãy trú chánh niệm, tỉnh giác. Ðây là lời giáo giới của Ta cho các Ông. Và này các Tỷ-kheo, thế nào là Tỷ-kheo chánh niệm? Ở đây, này các Tỷ-kheo, Tỷ-kheo trú, quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời … Như vậy, này các Tỷ-kheo, là Tỷ-kheo chánh niệm. Và này các Tỷ-kheo, như thế nào là Tỷ-kheo tỉnh giác? Ở đây, này các Tỷ-kheo, Tỷ-kheo biết rõ ràng các cảm thọ khởi lên, biết rõ ràng các cảm thọ an trú, biết rõ ràng các cảm thọ đi đến tiêu mất; biết rõ ràng các tưởng khởi lên, biết rõ ràng các tưởng an trú, biết rõ ràng các tưởng đi đến tiêu mất. Như vậy, này các Tỷ-kheo, là Tỷ-kheo tỉnh giác. Này các Tỷ-kheo, Tỷ-kheo hãy trú chánh niệm, tỉnh giác. Ðây là lời giáo giới của Ta cho các Ông.`, ref: "Tương Ưng Bộ 47.35", url: "https://loicuaducphat.org/sn/sn47.35.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, hãy sống hộ trì với sự hộ trì của Giới bổn, đầy đủ uy nghi chánh hạnh, thấy sự nguy hiểm trong những lỗi nhỏ nhặt, chấp nhận và thực hành các học giới. Này Tỷ-kheo, sau khi sống, hộ trì với sự hộ trì của Giới bổn, đầy đủ uy nghi chánh hạnh, thấy sự nguy hiểm trong những lỗi nhỏ nhặt, chấp nhận và thực hành các học giới rồi, này Tỷ-kheo, y cứ trên giới, an trú trên giới, hãy tu tập bốn niệm xứ. Thế nào là bốn? Ở đây, này Tỷ-kheo, Tỷ-kheo hãy trú, quán thân trên thân … Hãy trú, quán thọ trên các cảm thọ … Hãy trú, quán tâm trên tâm … Hãy trú, quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Khi nào, này Tỷ-kheo, Ông y cứ trên giới, an trú trên giới, tu tập bốn niệm xứ; khi ấy, này Tỷ-kheo, hoặc là đêm hay ngày, hãy chờ đợi ở nơi Ông sự tăng trưởng trong các thiện pháp, không phải sự tổn giảm.`, ref: "Tương Ưng Bộ 47.48", url: "https://loicuaducphat.org/sn/sn47.48.html#content" },

{ text: `- Nhưng thưa Tôn giả Gotama, cái gì làm chỗ quy tựa cho ý? - Này Bà-la-môn, niệm là chỗ quy tựa cho ý. - Nhưng thưa Tôn giả Gotama, cái gì làm chỗ quy tựa cho niệm? - Này Bà-la-môn, giải thoát là chỗ quy tựa cho niệm. - Nhưng thưa Tôn giả Gotama, cái gì làm chỗ quy tựa cho giải thoát? - Này Bà-la-môn, Niết-bàn là chỗ quy tựa cho giải thoát. - Nhưng thưa Tôn giả Gotama, cái gì là chỗ quy tựa cho Niết-bàn? - Này Bà-la-môn, câu hỏi đi quá xa không thể nắm được chỗ tận cùng của câu hỏi. Này Bà-la-môn, Phạm hạnh được sống để thể nhập Niết-bàn, Phạm hạnh lấy Niết-bàn làm mục đích, lấy Niết-bàn làm cứu cánh.`, ref: "Tương Ưng Bộ 48.42", url: "https://loicuaducphat.org/sn/sn48.42.html#content" },

{ text: `Và này Sāriputta, thế nào là sự tối thượng tôn kính mà Tỷ-kheo đã đoạn tận các lậu hoặc bày tỏ sự tối thượng tôn kính đối với Như Lai hay đối với lời giảng dạy của Như Lai? - Ở đây, bạch Thế Tôn, Tỷ-kheo đã đoạn tận các lậu hoặc sống tôn trọng, cung kính bậc Ðạo Sư; sống tôn trọng, cung kính Pháp; sống tôn trọng, cung kính chúng Tăng; sống tôn trọng, cung kính học giới; sống tôn trọng, cung kính Thiền định. Ðây là sự tối thượng tôn kính, bạch Thế Tôn, mà Tỷ-kheo đã đoạn tận các lậu hoặc; bày tỏ sự tối thượng tôn kính đối với Như Lai, hay lời giảng dạy của Như Lai. - Lành thay, lành thay, này Sāriputta! Cái này là tối thượng tôn kính mà Tỷ-kheo đã đoạn tận các lậu hoặc bày tỏ sự tối thượng tôn kính đối với Như Lai, hay đối với lời giảng dạy của Như Lai.`, ref: "Tương Ưng Bộ 48.58", url: "https://loicuaducphat.org/sn/sn48.58.html#content" },

{ text: `Có người tu tập tập như ý túc câu hữu với tâm định tinh cần hành, với ý nghĩ: “Như vậy, tâm của ta sẽ không quá thụ động và cũng không quá hăng say, sẽ không co rút phía trong, sẽ không phân tán phía ngoài, an trú với tưởng trước sau đồng đẳng. Trước thế nào, thời sau như vậy; sau thế nào, thời trước như vậy. Dưới thế nào, thời trên như vậy; trên thế nào, thời dưới như vậy. Ban ngày thế nào, thời ban đêm như vậy; ban đêm thế nào, thời ban ngày như vậy”. Như vậy, với tâm rộng mở, không với tâm gò bó, với tâm chói sáng, vị ấy tu tập tâm.`, ref: "Tương Ưng Bộ 51.11", url: "https://loicuaducphat.org/sn/sn51.11.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là dục quá thụ động? Dục nào, này các Tỷ-kheo, đi đôi với biếng nhác, tương ưng với biếng nhác, này các Tỷ-kheo, đây gọi là dục quá thụ động. Này các Tỷ-kheo, thế nào là dục quá hăng say? Dục nào, này các Tỷ-kheo, đi đôi với trạo cử, tương ưng với dao động, này các Tỷ-kheo, đây gọi là dục quá hăng say. Này các Tỷ-kheo, thế nào là dục bị co rút phía trong? Lòng dục nào, này các Tỷ-kheo, đi đôi với hôn trầm thụy miên, tương ưng với hôn trầm thụy miên, này các Tỷ-kheo, đây gọi là dục bị co rút phía trong. Này các Tỷ-kheo, thế nào là dục bị phân tán phía ngoài? Lòng dục nào, này các Tỷ-kheo, hướng về phía ngoài, duyên năm dục công đức, bị phân tán, bị phân ly, này các Tỷ-kheo, đây gọi là dục bị phân tán phía ngoài.`, ref: "Tương Ưng Bộ 51.20", url: "https://loicuaducphat.org/sn/sn51.20.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là Tỷ-kheo trú với tưởng trước sau đồng đẳng, trước thế nào, thời sau như vậy; sau thế nào, thời trước như vậy? Ở đây, này các Tỷ-kheo, tưởng trước sau của Tỷ-kheo được khéo nắm lấy, khéo tác ý, khéo thọ trì, khéo thể nhập với trí tuệ. Như vậy, này các Tỷ-kheo, trú với tưởng trước sau đồng đẳng, trước thế nào, thời sau như vậy; sau thế nào, thời trước như vậy.`, ref: "Tương Ưng Bộ 51.20", url: "https://loicuaducphat.org/sn/sn51.20.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là Tỷ-kheo trú dưới thế nào, thời trên như vậy; trên thế nào thời dưới như vậy? Ở đây, này các Tỷ-kheo, Tỷ-kheo quán thân này, từ bàn chân trở lên, từ đầu tóc trở xuống, bao bọc bởi da, đều đầy những vật bất tịnh; thân này có tóc, lông, móng, răng, da, thịt, dây gân, xương, tủy, thận, tim, gan, hoành cách mô, lá lách, phổi, ruột, màng ruột, bao tử, phân, mật, đàm, mủ, máu, mồ hôi, mỡ, nước mắt, mỡ da, nước miếng, nước mũi, nước ở khớp xương, nước tiểu. Như vậy, này các Tỷ-kheo, Tỷ-kheo trú dưới thế nào, thời trên như vậy; trên thế nào, thời dưới như vậy.`, ref: "Tương Ưng Bộ 51.20", url: "https://loicuaducphat.org/sn/sn51.20.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là Tỷ-kheo với tâm rộng mở, với tâm không gò bó, với tâm chói sáng, vị ấy tu tập tâm? Ở đây, này các Tỷ-kheo, quang tưởng (alokasannà) của Tỷ-kheo, được khéo nắm lấy, tưởng ban ngày được khéo an trú. Như vậy, này các Tỷ-kheo, là Tỷ-kheo với tâm rộng mở, với tâm không gò bó, với tâm chói sáng, vị ấy tu tập tâm.`, ref: "Tương Ưng Bộ 51.20", url: "https://loicuaducphat.org/sn/sn51.20.html#content" },

{ text: `- Cũng vậy, này chư Hiền, Tỷ-kheo tu tập bốn niệm xứ, làm cho sung mãn bốn niệm xứ. Dầu cho vua chúa, hay đại thần, hay thân hữu, hay bạn bè, hay bà con huyết thống có thể đến dâng các tài vật và mời: “Hãy đến, này Người tốt kia, sao để các áo vàng này hành hạ Ông? Sao lại đi biểu diễn với đầu trọc và bình bát? Hãy hoàn tục, thọ hưởng các tài vật và làm các phước đức!”; Tỷ-kheo ấy, thưa chư Hiền, được tu tập bốn niệm xứ, được làm cho sung mãn bốn niệm xứ, có thể từ bỏ giới trở lui hoàn tục; sự kiện như vậy không xảy ra. Vì sao? Vì này chư Hiền, tâm người ấy đã lâu ngày thiên về viễn ly, hướng về viễn ly, xuôi về viễn ly, lại trở lại hoàn tục, sự kiện như vậy không xảy ra.`, ref: "Tương Ưng Bộ 52.8", url: "https://loicuaducphat.org/sn/sn52.8.html#content" },

{ text: `Một thời, Tôn giả Anuruddha trú ở Sāvatthi, tại rừng Andha, bị bệnh, khổ đau, bị trọng bệnh. Rồi nhiều Tỷ-kheo đi đến Tôn giả Anuruddha và nói với Tôn giả Anuruddha: - Tôn giả Anuruddha an trú với sự an trú gì, khiến cho khổ thọ về thân khởi lên, lại không có ảnh hưởng gì đến tâm? - Thưa chư Hiền, do tôi trú với tâm khéo an trú trên bốn niệm xứ, nên các khổ thọ về thân khởi lên không có ảnh hưởng gì đến tâm. Thế nào là bốn? Ở đây, thưa chư Hiền, tôi trú, quán thân trên thân … quán thọ trên các cảm thọ … quán tâm trên tâm … quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Thưa chư Hiền, do tôi trú với tâm khéo an trú trên bốn niệm xứ, nên các khổ thọ về thân khởi lên không có ảnh hưởng đến tâm.`, ref: "Tương Ưng Bộ 52.10", url: "https://loicuaducphat.org/sn/sn52.10.html#content" },

{ text: `- Có một pháp, này các Tỷ-kheo, được tu tập, được làm cho sung mãn thời có quả lớn, có lợi ích lớn. Thế nào là một pháp? Niệm hơi thở vô, hơi thở ra. Và này các Tỷ-kheo, niệm hơi thở vô, hơi thở ra, tu tập như thế nào, làm cho sung mãn như thế nào thời có quả lớn, có lợi ích lớn? Ở đây, này các Tỷ-kheo, Tỷ-kheo đi đến rừng, hay đi đến gốc cây, hay đi đến chỗ nhà trống, ngồi kiết-già, lưng thẳng, đặt niệm trước mặt; vị ấy chánh niệm thở vô, chánh niệm thở ra. Thở vô dài, vị ấy rõ biết: “Tôi thở vô dài”. Thở ra dài, vị ấy rõ biết: “Tôi thở ra dài”. Thở vô ngắn, vị ấy rõ biết: “Tôi thở vô ngắn”. Thở ra ngắn, vị ấy rõ biết: “Tôi thở ra ngắn”. “Cảm giác toàn thân, tôi sẽ thở vô”, vị ấy tập. “Cảm giác toàn thân, tôi sẽ thở ra”, vị ấy tập. “An tịnh thân hành, tôi sẽ thở vô”, vị ấy tập. “An tịnh thân hành, tôi sẽ thở ra”, vị ấy tập... Tu tập như vậy, này các Tỷ-kheo, làm cho sung mãn như vậy, niệm hơi thở vô, hơi thở ra thời có quả lớn, có lợi ích lớn.`, ref: "Tương Ưng Bộ 54.1", url: "https://loicuaducphat.org/sn/sn54.1.html#content" },

{ text: `- Này các Tỷ-kheo, các Ông có thấy Tỷ-kheo ấy, thân có rung động hay có dao động không? - Bạch Thế Tôn, chúng con thấy vị Tôn giả ấy ngồi giữa Tăng chúng hay ngồi một mình, độc cư; chúng con không thấy vị Tôn giả ấy thân bị rung động hay dao động. - Ðối với một vị có Thiền định như vậy, này các Tỷ-kheo, nhờ tu tập, nhờ làm cho sung mãn, nên thân vị ấy không rung động hay dao động, nên tâm vị ấy không rung động hay dao động. Ðối với vị Tỷ-kheo ấy, được định như vậy, không có khó khăn, không có gian nan, không có mệt nhọc. Và này các Tỷ-kheo, vị ấy tu tập, làm cho sung mãn định nào mà thân không rung động, không dao động, hay tâm không rung động, không dao động? Này các Tỷ-kheo, do vị ấy tu tập, làm cho sung mãn định niệm hơi thở vô, hơi thở ra, nên thân không rung động, không dao động, hoặc tâm không rung động hay không dao động.`, ref: "Tương Ưng Bộ 54.7", url: "https://loicuaducphat.org/sn/sn54.7.html#content" },

{ text: `- Này các Tỷ-kheo, định niệm hơi thở vô, hơi thở ra này được tu tập, được làm cho sung mãn là tịch tịnh, thù diệu, thuần nhất, lạc trú, làm cho các ác, bất thiện pháp đã sanh biến mất, tịnh chỉ lập tức. Ví như, này các Tỷ-kheo, trong cuối mùa hạ, bụi nhớp bay lên và một đám mưa lớn trái mùa lập tức làm chúng biến mất, tịnh chỉ. Cũng vậy, này các Tỷ-kheo, định niệm hơi thở vô, hơi thở ra được tu tập, được làm cho sung mãn là tịch tịnh, thù diệu, thuần nhất, lạc trú, làm cho các ác, bất thiện pháp đã sanh biến mất, tịnh chỉ lập tức. Và này các Tỷ-kheo, định niệm hơi thở vô, hơi thở ra, được tu tập như thế nào, được làm cho sung mãn như thế nào là tịch tịnh, thù diệu, thuần nhất, lạc trú, làm cho các ác, bất thiện pháp đã sanh được biến mất và tịnh chỉ lập tức? Ở đây, này các Tỷ-kheo, Tỷ-kheo đi đến khu rừng, hay đi đến gốc cây, hay đi đến căn nhà trống, ngồi kiết-già … “Quán từ bỏ, tôi sẽ thở vô”, vị ấy tập. “Quán từ bỏ, tôi sẽ thở ra”, vị ấy tập. Này các Tỷ-kheo, định niệm hơi thở vô, hơi thở ra tu tập như vậy, làm cho sung mãn như vậy là tịch tịnh, thù diệu, thuần nhất, lạc trú, và các ác, bất thiện pháp đã sanh được biến mất và tịnh chỉ lập tức.`, ref: "Tương Ưng Bộ 54.9", url: "https://loicuaducphat.org/sn/sn54.9.html#content" },

{ text: `Lúc nào, này Ānanda, Tỷ-kheo thở vô dài, vị ấy rõ biết: “Tôi thở vô dài”. Hay khi Tỷ-kheo thở ra dài, vị ấy rõ biết: “Tôi thở ra dài”. Hay khi Tỷ-kheo thở vô ngắn, vị ấy rõ biết: “Tôi thở vô ngắn”. Hay khi Tỷ-kheo thở ra ngắn, vị ấy rõ biết: “Tôi thở ra ngắn”. “Cảm giác toàn thân, tôi sẽ thở vô”, vị ấy tập. “Cảm giác toàn thân, tôi sẽ thở ra”, vị ấy tập. “An tịnh thân hành, tôi sẽ thở vô”, vị ấy tập. “An tịnh thân hành, tôi sẽ thở ra”, vị ấy tập. Này Ānanda, sống quán thân trên thân, Tỷ-kheo trú như vậy, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Vì sao? Này Ānanda, Ta tuyên bố rằng, tùy thuộc về thân, tức là hơi thở vô, hơi thở ra. Do vậy, này Ānanda, quán thân trên thân, Tỷ-kheo trú như vậy, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời.`, ref: "Tương Ưng Bộ 54.10", url: "https://loicuaducphat.org/sn/sn54.10.html#content" },

{ text: `Trong khi, này Ānanda, Tỷ-kheo: “Cảm giác hỷ thọ, tôi sẽ thở vô”, vị ấy tập. “Cảm giác hỷ thọ, tôi sẽ thở ra”, vị ấy tập. “Cảm giác lạc thọ, tôi sẽ thở vô”, vị ấy tập. “Cảm giác lạc thọ, tôi sẽ thở ra”, vị ấy tập. “Cảm giác tâm hành, tôi sẽ thở vô”, vị ấy tập. “Cảm giác tâm hành, tôi sẽ thở ra”, vị ấy tập. “An tịnh tâm hành, tôi sẽ thở vô”, vị ấy tập. “An tịnh tâm hành, tôi sẽ thở ra”, vị ấy tập. Trong khi quán thọ trên các cảm thọ, Tỷ-kheo trú như vậy, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời. Vì sao? Này Ānanda, Ta tuyên bố rằng, tùy thuộc về thọ, tức là hơi thở vô, hơi thở ra, được khéo tác ý. Do vậy, này Ānanda, quán thọ trên các cảm thọ, Tỷ-kheo trú như vậy, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời.`, ref: "Tương Ưng Bộ 54.10", url: "https://loicuaducphat.org/sn/sn54.10.html#content" },

{ text: `Trong khi, này Ānanda, Tỷ-kheo: “Cảm giác về tâm, tôi sẽ thở vô”, vị ấy tập. “Cảm giác về tâm, tôi sẽ thở ra”, vị ấy tập. “Với tâm hân hoan, tôi sẽ thở vô”, vị ấy tập. “Với tâm hân hoan, tôi sẽ thở ra”, vị ấy tập. “Với tâm định tĩnh, tôi sẽ thở vô”, vị ấy tập. “Với tâm định tĩnh, tôi sẽ thở ra”, vị ấy tập. “Với tâm giải thoát, tôi sẽ thở vô”, vị ấy tập. “Với tâm giải thoát, tôi sẽ thở ra”, vị ấy tập. Trong khi quán tâm trên tâm, Tỷ-kheo trú như vậy, nhiệt tâm, tỉnh giác, nhiếp phục tham ưu ở đời. Vì sao? Này Ānanda, Ta tuyên bố rằng sự tu tập chánh niệm hơi thở vô, hơi thở ra không phải cho người thất niệm và không tỉnh giác. Do vậy, này Ānanda, quán tâm trên tâm, Tỷ-kheo trong khi ấy, trú nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời.`, ref: "Tương Ưng Bộ 54.10", url: "https://loicuaducphat.org/sn/sn54.10.html#content" },

{ text: `Trong khi Tỷ-kheo, này Ānanda, “Quán vô thường, tôi sẽ thở vô”, vị ấy tập. “Quán vô thường, tôi sẽ thở ra”, vị ấy tập. “Quán ly tham, tôi sẽ thở vô”, vị ấy tập. “Quán ly tham, tôi sẽ thở ra”, vị ấy tập. “Quán đoạn diệt, tôi sẽ thở vô”, vị ấy tập. “Quán đoạn diệt, tôi sẽ thở ra”, vị ấy tập. “Quán từ bỏ, tôi sẽ thở vô”, vị ấy tập. “Quán từ bỏ, tôi sẽ thở ra”, vị ấy tập. Trong khi quán pháp trên các pháp, này Ānanda, Tỷ-kheo trú như vậy, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời, đoạn tận các tham ưu; sau khi thấy với trí tuệ, vị ấy khéo trú xả. Do vậy, này Ānanda, quán pháp trên các pháp, Tỷ-kheo trú như vậy, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời.`, ref: "Tương Ưng Bộ 54.10", url: "https://loicuaducphat.org/sn/sn54.10.html#content" },

{ text: `- Này các Tỷ-kheo, nếu các du sĩ ngoại đạo đến hỏi các Ông: “Với sự an trú nào, này chư Hiền, Sa-môn Gotama an trú nhiều trong mùa mưa?” Ðược hỏi vậy, này các Tỷ-kheo, các Ông hãy trả lời cho cho các du sĩ ngoại đạo ấy như sau: “Với định niệm hơi thở vô, hơi thở ra, này chư Hiền, Thế Tôn an trú nhiều trong các mùa mưa”. Ở đây, này các Tỷ-kheo, chánh niệm Ta thở vô, chánh niệm Ta thở ra. Hay thở vô dài, Ta rõ biết: “Ta thở vô dài”. Hay thở ra dài, Ta rõ biết: “Ta thở ra dài”. Hay thở vô ngắn, Ta rõ biết: “Ta thở vô ngắn”. Hay thở ra ngắn, Ta rõ biết: “Ta thở ra ngắn” … “Quán từ bỏ, Ta thở vô”, Ta rõ biết như vậy. “Quán từ bỏ, Ta thở ra”, Ta rõ biết như vậy. Này các Tỷ-kheo, ai muốn nói một cách chơn chánh, đây là Thánh trú, đây là Phạm trú, đây là Như Lai trú; người ấy nói một cách chơn chánh, phải nói định niệm hơi thở vô, hơi thở ra là Thánh trú, là Phạm trú, là Như Lai trú.`, ref: "Tương Ưng Bộ 54.11", url: "https://loicuaducphat.org/sn/sn54.11.html#content" },

{ text: `Này các Tỷ-kheo, những Tỷ-kheo nào là bậc hữu học, tâm chưa thành tựu, đang sống cần cầu vô thượng an ổn khỏi các khổ ách; những vị ấy tu tập, làm cho sung mãn định niệm hơi thở vô, hơi thở ra, sẽ đưa đến đoạn tận các lậu hoặc. Và này các Tỷ-kheo, những Tỷ-kheo nào là bậc A-la-hán, đoạn tận các lậu hoặc, tu hành thành mãn, những việc nên làm đã làm, đã đặt gánh nặng xuống, đã thành đạt lý tưởng, đã tận trừ hữu kiết sử, chánh trí, giải thoát; những vị ấy tu tập, làm cho sung mãn định niệm hơi thở vô, hơi thở ra, ngay trong hiện tại, đưa đến lạc trú, chánh niệm tỉnh giác. Này các Tỷ-kheo, ai muốn nói một cách chơn chánh, đây là Thánh trú, đây là Phạm trú, đây là Như Lai trú; người ấy nói một cách chơn chánh, phải nói định niệm hơi thở vô, hơi thở ra là Thánh trú, là Phạm trú, là Như Lai trú.`, ref: "Tương Ưng Bộ 54.11", url: "https://loicuaducphat.org/sn/sn54.11.html#content" },

{ text: `- Này Ānanda, có một pháp được tu tập, được làm cho sung mãn, làm cho viên mãn bốn pháp. Bốn pháp được tu tập, được làm cho sung mãn, làm cho viên mãn bảy pháp. Bảy pháp được tu tập, được làm cho sung mãn, làm cho viên mãn hai pháp. - Một pháp ấy là gì, bạch Thế Tôn, được tu tập, được làm cho sung mãn, làm cho viên mãn bốn pháp? Bốn pháp được tu tập, được làm cho sung mãn, làm cho viên mãn bảy pháp? Bảy pháp được tu tập được làm cho sung mãn, làm cho viên mãn hai pháp? - Này Ānanda, định niệm hơi thở vô, hơi thở ra được tu tập, được làm cho sung mãn, làm cho viên mãn bốn niệm xứ. Bốn niệm xứ được tu tập, được làm cho sung mãn, làm cho viên mãn bảy giác chi. Bảy giác chi được tu tập, được làm cho sung mãn, làm cho viên mãn minh và giải thoát.`, ref: "Tương Ưng Bộ 54.13", url: "https://loicuaducphat.org/sn/sn54.13.html#content" },

{ text: `Tu tập như thế nào, này Ānanda, làm cho sung mãn như thế nào, bốn niệm xứ làm cho viên mãn bảy giác chi? Trong khi, này Ānanda, Tỷ-kheo trú, quán thân trên thân, niệm được an trú; khi ấy, này Ānanda, Tỷ-kheo có niệm, không phải thất niệm. Trong khi, này Ānanda, Tỷ-kheo an trú niệm, không phải thất niệm, thời niệm giác chi, đối với Tỷ-kheo ấy được thành tựu. Trong khi, này Ānanda, Tỷ-kheo tu tập niệm giác chi, niệm giác chi được Tỷ-kheo tu tập đi đến viên mãn. Vị ấy trú chánh niệm như vậy, với trí tuệ quyết trạch, tư sát, thành tựu quán pháp ấy.`, ref: "Tương Ưng Bộ 54.13", url: "https://loicuaducphat.org/sn/sn54.13.html#content" },

{ text: `Ở đây, này các Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Ta muốn sống, không muốn chết, muốn lạc, ghét khổ. Nếu có ai đến đoạt mạng sống của ta, một người muốn sống, không muốn chết, muốn lạc, ghét khổ, như vậy là một việc không khả ái, không khả ý đối với ta. Nhưng nếu ta đoạt mạng sống một người muốn sống, không muốn chết, muốn lạc, ghét khổ, như vậy là một việc không khả ái, không khả ý đối với người ấy. Một pháp này không khả ái, không khả ý cho ta, thời pháp ấy cũng không khả ái, không khả ý cho người khác. Và một pháp này không khả ái, không khả ý cho ta, thời sao ta lại đem cột pháp ấy cho người khác?” Do suy tư như vậy, vị ấy từ bỏ sát sanh, khuyến khích người khác từ bỏ sát sanh, nói lời tán thán từ bỏ sát sanh. Như vậy, về thân hành, vị ấy được hoàn toàn thanh tịnh.`, ref: "Tương Ưng Bộ 55.7", url: "https://loicuaducphat.org/sn/sn55.7.html#content" },

{ text: `Lại nữa, này các Gia chủ, vị Thánh đệ tử suy tư như sau: “Nếu có ai lấy của không cho của ta, gọi là ăn trộm, như vậy là một việc không khả ái, không khả ý cho ta. Nhưng nếu ta lấy của không cho của người khác, gọi là ăn trộm, như vậy là một việc không khả ái, không khả ý cho người ấy. Một pháp này không khả ái, không khả ý cho ta, thời pháp ấy cũng không khả ái, không khả ý cho người khác. Và một pháp này không khả ái, không khả ý cho ta, thời sao lại đem cột pháp ấy cho người khác?” Do suy tư như vậy, vị ấy từ bỏ lấy của không cho, khuyến khích người khác từ bỏ lấy của không cho, nói lời tán thán từ bỏ lấy của không cho. Như vậy, về thân hành, vị ấy được hoàn toàn thanh tịnh.`, ref: "Tương Ưng Bộ 55.7", url: "https://loicuaducphat.org/sn/sn55.7.html#content" },

{ text: `Lại nữa, này các Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Nếu ai có tà hạnh với vợ của ta, như vậy là một việc không khả ái, không khả ý cho ta. Nhưng nếu ta có tà hạnh với vợ của người khác, như vậy là một việc không khả ái, không khả ý cho người ấy. Một pháp này không khả ái, không khả ý cho ta, thời pháp này không khả ái, không khả ý cho người khác. Và một pháp này không khả ái, không khả ý cho ta, thời sao ta lại đem cột pháp ấy cho người khác?” Do suy tư như vậy, vị ấy tự mình từ bỏ tà hạnh trong các dục, khuyến khích người khác từ bỏ tà hạnh trong các dục, nói lời tán thán từ bỏ tà hạnh trong các dục. Như vậy, về thân hành, vị ấy được hoàn toàn thanh tịnh.`, ref: "Tương Ưng Bộ 55.7", url: "https://loicuaducphat.org/sn/sn55.7.html#content" },

{ text: `Lại nữa, này các Gia chủ, vị Thánh đệ tử suy nghĩ như sau: “Nếu có ai làm tổn hại lợi ích ta với lời nói láo, như vậy là một việc không khả ái, không khả ý cho ta. Nhưng nếu ta cũng làm tổn hại lợi ích người khác với lời nói láo, như vậy là một việc không khả ái, không khả ý cho người ấy. Một pháp này không khả ái, không khả ý cho ta, thời pháp này không khả ái, không khả ý cho người khác. Và một pháp này không khả ái, không khả ý cho ta, thời sao ta lại đem cột pháp ấy cho người khác?” Do suy tư như vậy, vị ấy tự mình từ bỏ nói láo, khuyến khích người khác từ bỏ nói láo, nói lời tán thán từ bỏ nói láo. Như vậy, về khẩu hành, vị ấy được hoàn toàn thanh tịnh.`, ref: "Tương Ưng Bộ 55.7", url: "https://loicuaducphat.org/sn/sn55.7.html#content" },

{ text: `Lại nữa, này các Gia chủ, vị Thánh đệ tử suy tư như sau: “Nếu có ai chia rẽ bạn bè ta bằng lời nói hai lưỡi, như vậy là một việc không khả ái, không khả ý cho ta. Nhưng nếu ta chia rẽ bạn bè người khác bằng lời nói hai lưỡi, như vậy là một việc không khả ái, không khả ý cho người ấy. Một pháp này không khả ái, không khả ý cho ta, thời pháp này không khả ái, không khả ý cho người khác. Và một pháp này không khả ái, không khả ý cho ta, thời sao ta lại đem cột pháp ấy cho người khác?” Do suy tư như vậy, vị ấy tự mình từ bỏ nói hai lưỡi, khuyến khích người khác từ bỏ nói lời hai lưỡi, nói lời tán thán từ bỏ nói lời hai lưỡi. Như vậy, về khẩu hành, vị ấy được hoàn toàn thanh tịnh.`, ref: "Tương Ưng Bộ 55.7", url: "https://loicuaducphat.org/sn/sn55.7.html#content" },

{ text: `Lại nữa, này các Gia chủ, vị Thánh đệ tử suy tư như sau: “Nếu có ai đối xử với ta bằng thô ác ngữ, như vậy là một việc không khả ái, không khả ý cho ta. Nhưng nếu ta cũng đối xử với người khác bằng thô ác ngữ, như vậy là một việc không khả ái, không khả ý cho người ấy. Một pháp này không khả ái, không khả ý cho ta, thời pháp này không khả ái, không khả ý cho người khác. Và một pháp này không khả ái, không khả ý cho ta, thời sao ta lại đem cột pháp ấy cho người khác?” Do suy tư như vậy, vị ấy tự mình từ bỏ thô ác ngữ, khuyến khích người khác từ bỏ thô ác ngữ, nói lời tán thán từ bỏ thô ác ngữ. Như vậy, về khẩu hành, vị ấy được hoàn toàn thanh tịnh.`, ref: "Tương Ưng Bộ 55.7", url: "https://loicuaducphat.org/sn/sn55.7.html#content" },

{ text: `Lại nữa, này các Gia chủ, vị Thánh đệ tử suy tư như sau: “Nếu có ai đối xử với ta với lời tạp ngữ, với lời phù phiếm, như vậy là một việc không khả ái, không khả ý cho ta. Nhưng nếu ta cũng đối xử với người khác với lời tạp ngữ, với lời phù phiếm, như vậy là một việc không khả ái, không khả ý cho người ấy. Một pháp này không khả ái, không khả ý cho ta, thời pháp này không khả ái, không khả ý cho người khác. Và một pháp này không khả ái, không khả ý cho ta, thời sao ta lại đem cột pháp ấy cho người khác?” Do suy tư như vậy, vị ấy tự mình từ bỏ lời nói phù phiếm, khuyến khích người khác từ bỏ nói lời phù phiếm, tán thán từ bỏ nói lời phù phiếm. Như vậy, về khẩu hành, vị ấy được hoàn toàn thanh tịnh.`, ref: "Tương Ưng Bộ 55.7", url: "https://loicuaducphat.org/sn/sn55.7.html#content" },
{ text: `- Tất cả những ai, này các Tỷ-kheo, các Ông có lòng từ mẫn, và những người mà các Ông nghĩ cần phải nghe theo, những ai là bạn bè, hay thân hữu, hay bà con, hay cùng một huyết thống; tất cả những vị ấy, này các Tỷ-kheo, cần phải được khuyến khích, phải được áp đặt, phải được an trú trong bốn Dự lưu phần. Thế nào là bốn? Họ cần phải được khuyến khích, phải được áp đặt, phải được an trú vào tịnh tín bất động đối với đức Phật: “Ðây là bậc Ứng Cúng, … Phật, Thế Tôn” … đối với Pháp … đối với Tăng … đối với các giới được các bậc Thánh ái kính … đưa đến Thiền định. Những ai mà các Ông có lòng từ mẫn, này các Tỷ-kheo, những ai mà các Ông nghĩ là cần phải nghe theo, các bạn bè, hay thân hữu, hay bà con, hay cùng một huyết thống; các người ấy cần phải được khuyến khích, cần phải được áp đặt, cần phải được an trú trong bốn Dự lưu phần này.`, ref: "Tương Ưng Bộ 55.16", url: "https://loicuaducphat.org/sn/sn55.16.html#content" },

{ text: `- Chớ có sợ, này Mahānāma! Chớ có sợ, này Mahānāma! Không ác sẽ là cái chết của Ông! Không ác là cái chết của ông! Này Mahānāma, với ai đã lâu ngày tâm tu tập trọn vẹn về tín, tâm tu tập trọn vẹn về giới, tâm tu tập trọn vẹn về sở văn, tâm tu tập trọn vẹn về thí xả, tâm tu tập trọn vẹn về trí tuệ; với người ấy, dầu thân có sắc này, do bốn đại hợp thành, do cha mẹ sanh, do cơm cháo nuôi dưỡng, có bị vô thường phá hoại, phấn toái, đoạn tuyệt, hoại diệt; dầu cho thân này ở đây bị quạ ăn, chim kên ăn, chim ưng ăn, chó ăn, hay giả-can ăn, hay các loại chúng sanh sai khác ăn; nhưng nếu tâm của vị ấy được lâu ngày tu tập trọn vẹn về tín, tu tập trọn vẹn về giới, tu tập trọn vẹn về sở văn, tu tập trọn vẹn về thí xả, tu tập trọn vẹn về trí tuệ, thời tâm của vị ấy thượng thặng, đi đến thù thắng.`, ref: "Tương Ưng Bộ 55.21", url: "https://loicuaducphat.org/sn/sn55.21.html#content" },

{ text: `Ví như, này Mahānāma, một người nhận chìm một ghè sữa bơ, hay một ghè dầu vào trong một hồ nước sâu và đập bể ghè ấy. Ở đây, các mảnh ghè hay mảnh vụn chìm xuống nước; nhưng sữa, bơ hay dầu thời nổi lên, trồi lên trên. Cũng vậy, này Mahānāma, với ai đã lâu ngày, tâm được tu tập trọn vẹn về tín, tâm được tu tập trọn vẹn về giới, tâm được tu tập trọn vẹn về sở văn, tâm được tu tập trọn vẹn về thí xả, tâm được tu tập trọn vẹn về trí tuệ; với người ấy, thân có sắc này, do bốn đại hợp thành, do cha mẹ sanh, do cơm cháo nuôi dưỡng, có bị vô thường phá hoại, phấn toái, đoạn tuyệt, đoạn diệt; dầu cho thân này ở đây bị quạ ăn, chim kên ăn, chim ưng ăn, chó ăn, giả-can ăn hay các sanh loại sai khác ăn; nhưng nếu tâm của vị ấy được lâu ngày tu tập trọn vẹn về tín, tu tập trọn vẹn về giới, tu tập trọn vẹn về sở văn, tu tập trọn vẹn về thí xả, tu tập trọn vẹn về trí tuệ; thời tâm của vị ấy thượng thặng, đi đến thù thắng.`, ref: "Tương Ưng Bộ 55.21", url: "https://loicuaducphat.org/sn/sn55.21.html#content" },

{ text: `Này Mahānāma, đã lâu ngày tâm Ông được tu tập trọn vẹn về tín, được tu tập trọn vẹn về giới, được tu tập trọn vẹn về sở văn, được tu tập trọn vẹn về thí xả, được tu tập trọn vẹn về trí tuệ. Chớ có sợ, này Mahānāma, chớ có sợ, này Mahānāma, không ác sẽ là cái chết của Ông! Không ác là cái chết của Ông! Ví như, này Mahānāma, một cây thiên về phía Ðông, hướng về phía Ðông, xuôi về phía Ðông, nếu bị chặt đứt từ gốc rễ, nó sẽ ngả về phía nào? - Bạch Thế Tôn, về phía nào nó thiên, về phía nào nó hướng, về phía nào nó xuôi. - Cũng vậy, này Mahānāma, do thành tựu bốn pháp này, vị Thánh đệ tử thiên về Niết-bàn, hướng về Niết-bàn, xuôi về Niết-bàn.`, ref: "Tương Ưng Bộ 55.21", url: "https://loicuaducphat.org/sn/sn55.21.html#content" },

{ text: `Ai tin tưởng Như Lai,\nBất động khéo an lập.\nAi có giới thiện lành,\nÐược bậc Thánh ái kính.\nAi tin tưởng chúng Tăng,\nSở kiến được chánh trực,\nNgười ấy gọi “Không nghèo”,\nÐời sống không uổng phí.\nDo vậy, bậc Hiền minh\nCần tu tập tín giới,\nThấy rõ được Chánh pháp,\nKhông quên lời Phật dạy.`, ref: "Tương Ưng Bộ 55.26", url: "https://loicuaducphat.org/sn/sn55.26.html#content" },

{ text: `- Này các Tỷ-kheo, có bốn phước đức sung mãn, thiện sung mãn, món ăn cho lạc này. Thế nào là bốn? Ở đây, này các Tỷ-kheo, vị Thánh đệ tử thành tựu lòng tịnh tín bất động đối với Phật: “Ðây là bậc Ứng Cúng … Phật, Thế Tôn”. Ðây là phước đức sung mãn, thiện sung mãn, món ăn cho lạc thứ nhất. Lại nữa, này các Tỷ-kheo, vị Thánh đệ tử thành tựu lòng tịnh tín bất động đối với Pháp: “Pháp được Thế Tôn khéo thuyết … chỉ người có trí tự mình giác hiểu”. Ðây là phước đức sung mãn, thiện sung mãn, món ăn cho lạc thứ hai. Lại nữa, này các Tỷ-kheo, vị Thánh đệ tử thành tựu lòng tịnh tín bất động đối với chúng Tăng: “Diệu hạnh là chúng đệ tử của Thế Tôn … là phước điền vô thượng ở đời”. Ðây là phước đức sung mãn, thiện sung mãn, món ăn cho lạc thứ ba. Lại nữa, này các Tỷ-kheo, vị Thánh đệ tử thành tựu các giới được các bậc Thánh ái kính … đưa đến Thiền định. Ðây là phước đức sung mãn, thiện sung mãn, món ăn cho lạc thứ tư. Những pháp này, này các Tỷ-kheo, là bốn phước đức sung mãn, thiện sung mãn, món ăn cho lạc.`, ref: "Tương Ưng Bộ 55.31", url: "https://loicuaducphat.org/sn/sn55.31.html#content" },

{ text: `- Lại nữa, này các Tỷ-kheo, vị Thánh đệ tử trú ở gia đình, với tâm thoát khỏi cấu uế của xan tham, bố thí dễ dàng, bàn tay rộng mở, thích thú từ bỏ, đáp ứng điều yêu cầu, thích thú chia xẻ vật bố thí. Ðây là phước đức sung mãn, thiện sung mãn, món ăn cho lạc thứ tư. Những pháp này, này các Tỷ-kheo, là bốn phước đức sung mãn, thiện sung mãn, món ăn cho lạc.`, ref: "Tương Ưng Bộ 55.32", url: "https://loicuaducphat.org/sn/sn55.32.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, khi trên đầu núi có cơn mưa to lớn, nước mưa ấy chảy theo hướng xuôi của nó, tràn đầy các hang núi, khe núi; sau khi tràn đầy các hang núi, khe núi, nó tràn đầy hồ nhỏ; sau khi tràn đầy hồ nhỏ, nó tràn đầy hồ lớn; sau khi tràn đầy hồ lớn, nó tràn đầy sông nhỏ; sau khi tràn đầy sông nhỏ, nó tràn đây sông lớn; sau khi tràn đầy sông lớn, nó tràn đầy biển, đại dương. Cũng vậy, này các Tỷ-kheo, đối với vị Thánh đệ tử, lòng tịnh tín bất động đối với đức Phật, lòng tịnh tín bất động đối với Pháp, lòng tịnh tín bất động đối với chúng Tăng, và các giới được các bậc Thánh ái kính; những pháp này trôi chảy đến bờ bên kia, đưa đến đoạn diệt các lậu hoặc.`, ref: "Tương Ưng Bộ 55.38", url: "https://loicuaducphat.org/sn/sn55.38.html#content" },

{ text: `Ở đây, này Nandiyà, vị Thánh đệ tử thành tựu lòng tịnh tín bất động đối với đức Phật: “Ðây là bậc Ứng Cúng, … Phật, Thế Tôn”. Vị này không thỏa mãn với lòng tịnh tín bất động ấy, cố gắng hơn nữa, ban ngày sống viễn ly, ban đêm sống Thiền tịnh. Do vị ấy sống không phóng dật, nên hân hoan khởi. Do vị ấy hân hoan, nên hỷ sanh. Do ý có hỷ, nên thân khinh an. Do thân khinh an, nên vị ấy cảm thọ lạc. Do tâm được lạc, nên vị ấy định tĩnh. Do tâm định tĩnh, các pháp được hiện ra. Do các pháp được hiện ra, vị ấy được gọi là trú không phóng dật. Lại nữa, này Nandiyà, vị Thánh đệ tử đối với Pháp … đối với chúng Tăng … vị ấy thành tựu các giới được các bậc Thánh ái kính … đưa đến Thiền định. Vị ấy không thỏa mãn với các giới được các bậc Thánh ái kính, cố gắng tinh tấn hơn nữa, ban ngày sống viễn ly, ban đêm sống Thiền tịnh. Do vị ấy sống không phóng dật như vậy, hân hoan sanh. Vị ấy có hân hoan, nên hỷ sanh. Do ý có hỷ, nên thân kinh an. Do thân khinh an, nên vị ấy cảm thọ lạc. Do tâm được lạc, nên vị ấy định tĩnh. Do tâm định tĩnh, các pháp được hiện ra. Do các pháp được hiện ra, vị ấy được gọi là trú không phóng dật. Như vậy, này Nandiyà, là vị Thánh đệ tử trú không phóng dật.`, ref: "Tương Ưng Bộ 55.40", url: "https://loicuaducphat.org/sn/sn55.40.html#content" },

{ text: `Là đại dương, đại hải,\nNước mênh mông rộng lớn,\nÐầy rẫy những hãi hùng,\nChứa vô lượng trân châu,\nPhục vụ trăm ngàn người,\nCác con sông lớn, nhỏ,\nChúng tuôn chảy ồ ạt,\nChúng đổ về bể khơi.\nCũng vậy là những người,\nThí đồ ăn, uống, vải,\nBố thí giường, chỗ ngồi,\nMền, nệm, các đồ nằm,\nVô lượng nguồn phước đức,\nTừ kẻ trí tuôn chảy,\nNhư sông hồ đầy nước,\nChảy tuôn ra bể cả.`, ref: "Tương Ưng Bộ 55.41", url: "https://loicuaducphat.org/sn/sn55.41.html#content" },

{ text: `Ai ước muốn phước đức,\nVững trú trên điều thiện,\nTu tập theo con đường,\nÐưa đến đạt bất tử,\nChứng được lõi của pháp,\nThích thú đoạn lậu hoặc,\nVị ấy không run sợ,\nKhi nghĩ đến thần chết.`, ref: "Tương Ưng Bộ 55.43", url: "https://loicuaducphat.org/sn/sn55.43.html#content" },

{ text: `Một cư sĩ có trí bị bệnh, đau đớn, bị trọng bệnh, này Mahānāma, phải được một cư sĩ có trí giáo giới với bốn pháp an ủi này. Cần phải nói như vậy. Nếu vị ấy nói: “Tôi còn có lòng thương nhớ cha mẹ”, thời nên nói với vị ấy như sau: “Thưa Tôn giả, Tôn giả thế nào cũng phải chết. Dầu Tôn giả có lòng thương nhớ cha mẹ, Tôn giả cũng sẽ chết. Dầu Tôn giả không có lòng thương nhớ cha mẹ, Tôn giả cũng sẽ chết. Vậy tốt hơn là Tôn giả hãy từ bỏ lòng thương nhớ đối với cha mẹ của Tôn giả”. Nếu vị ấy nói: “Tôi có lòng thương nhớ vợ con”, thời vị ấy cần phải được nói như sau: “Tôn giả thế nào cũng chết. Dầu Tôn giả có lòng thương nhớ vợ con, Tôn giả cũng sẽ chết. Dầu Tôn giả không có lòng thương nhớ vợ con, Tôn giả cũng sẽ chết. Vậy tốt hơn là Tôn giả hãy từ bỏ lòng thương nhớ đối với vợ con của Tôn giả”.`, ref: "Tương Ưng Bộ 55.54", url: "https://loicuaducphat.org/sn/sn55.54.html#content" },

{ text: `- Những thiện nam tử nào trong thời quá khứ, này các Tỷ-kheo, đã chơn chánh xuất gia, từ bỏ gia đình, sống không gia đình; tất cả những vị ấy đã làm như vậy để như thật chứng ngộ bốn Thánh đế. Những thiện nam tử nào trong thời vị lai, này các Tỷ-kheo, sẽ chơn chánh xuất gia, từ bỏ gia đình, sống không gia đình; tất cả những vị ấy sẽ làm như vậy để như thật chứng ngộ bốn Thánh đế. Những thiện nam tử nào trong thời hiện tại, này các Tỷ-kheo, chơn chánh xuất gia, từ bỏ gia đình, sống không gia đình; tất cả những vị ấy làm như vậy để như thật chứng ngộ bốn Thánh đế. Thế nào là bốn? Thánh đế về Khổ, Thánh đế về Khổ tập, Thánh đế về Khổ diệt, Thánh đế về Con Ðường đưa đến Khổ diệt. Những thiện nam tử nào trong thời quá khứ, này các Tỷ-kheo, đã chơn chánh xuất gia, từ bỏ gia đình, sống không gia đình … sẽ chơn chánh xuất gia … tất cả những vị ấy làm như vậy để như thật chứng ngộ bốn Thánh đế này. Do vậy, này các Tỷ-kheo, một cố gắng cần phải làm để rõ biết: “Ðây là Khổ” … Một sự cố gắng cần phải làm để rõ biết: “Ðây là Con Ðường đưa đến Khổ diệt”.`, ref: "Tương Ưng Bộ 56.3", url: "https://loicuaducphat.org/sn/sn56.3.html#content" },

{ text: `- Này các Tỷ-kheo, chớ có suy tầm các tầm ác, bất thiện, như dục tầm, sân tầm, hại tầm. Vì sao? Các tầm ấy, này các Tỷ-kheo, không liên hệ đến mục đích, chúng không phải căn bản cho Phạm hạnh, chúng không đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn. Khi các Ông suy tầm, này các Tỷ-kheo, các Ông hãy suy tầm: “Ðây là khổ” … hãy suy tầm: “Ðây là Khổ tập” … hãy suy tầm: “Ðây là Khổ diệt” … hãy suy tầm: “Ðây là Con Ðường đưa đến Khổ diệt”. Vì sao? Các suy tầm ấy, này các Tỷ-kheo, liên hệ đến mục đích, chúng là căn bản cho Phạm hạnh, chúng đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn. Do vậy, này các Tỷ-kheo, một cố gắng cần phải làm để rõ biết: “Ðây là Khổ” … Một cố gắng cần phải làm để rõ biết: “Ðây là Con Ðường đưa đến Khổ diệt”.`, ref: "Tương Ưng Bộ 56.7", url: "https://loicuaducphat.org/sn/sn56.7.html#content" },

{ text: `- Này các Tỷ-kheo, chớ có nói lời tranh luận nhau: “Ông không biết Pháp và Luật này. Tôi biết Pháp và Luật này. Sao Ông có thể biết Pháp và Luật này? Ông theo tà hạnh. Tôi theo chánh hạnh. Ðiều đáng nói trước, Ông lại nói sau. Ðiều đáng nói sau, Ông lại nói trước. Lời nói tôi tương ưng. Lời nói Ông không tương ưng. Ðiều Ông quan niệm, trình bày đã bị đảo lộn. Quan điểm của Ông đã bị thách đố. Hãy đi giải tỏa quan điểm của Ông. Hãy tự thoát khỏi bế tắc nếu Ông có thể làm được”. Vì sao? Những câu chuyện ấy, này các Tỷ-kheo, không liên hệ đến mục đích, không phải căn bản cho Phạm hạnh, không đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn. Và này các Tỷ-kheo, nếu có nói, thời hãy nói: “Ðây là Khổ” … hãy nói: “Ðây là Con Ðường đưa đến Khổ diệt”. Vì sao? Các lời nói ấy, này các Tỷ-kheo, liên hệ đến mục đích, chúng là căn bản cho Phạm hạnh, chúng đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn. Do vậy, này các Tỷ-kheo, một cố gắng cần phải làm để rõ biết: “Ðây là Khổ” … Một cố gắng cần phải làm để rõ biết: “Ðây là Con Ðường đưa đến Khổ diệt”.`, ref: "Tương Ưng Bộ 56.9", url: "https://loicuaducphat.org/sn/sn56.9.html#content" },

{ text: `- Này các Tỷ-kheo, chớ có nói những câu chuyện của loài súc sanh, như câu chuyện về vua chúa, câu chuyện về ăn trộm, câu chuyện về đại thần, câu chuyện về binh lính, câu chuyện về hãi hùng, câu chuyện về chiến tranh, câu chuyện về đồ ăn, câu chuyện về đồ uống, câu chuyện về vải mặc, câu chuyện về giường nằm, câu chuyện về vòng hoa, câu chuyện về hương liệu, câu chuyện về bà con, câu chuyện về xe cộ, câu chuyện về làng xóm, câu chuyện về thị tứ, câu chuyện về thành phố, câu chuyện về quốc độ, câu chuyện về đàn bà, câu chuyện về đàn ông, câu chuyện về vị anh hùng, câu chuyện bên lề đường, câu chuyện tại chỗ lấy nước, câu chuyện người đã chết, các câu chuyện tạp thoại, các câu chuyện biến trạng của thế giới, câu chuyện về biến trạng của đại dương, câu chuyện về sự hiện hữu và sự không hiện hữu. Vì sao? Những câu chuyện này, này các Tỷ-kheo, không đưa đến mục đích, không phải căn bản cho Phạm hạnh, không đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn.`, ref: "Tương Ưng Bộ 56.10", url: "https://loicuaducphat.org/sn/sn56.10.html#content" },

{ text: `Bốn pháp này, này các Tỷ-kheo, là như thật, không ly như thật, không khác như thật. Thế nào là bốn? Ðây là Khổ, này các Tỷ-kheo, đây là như thật, không ly như thật, không khác như thật. Ðây là Khổ tập, này các Tỷ-kheo, đây là như thật, không ly như thật, không khác như thật. Ðây là Khổ diệt, này các Tỷ-kheo, đây là như thật, không ly như thật, không khác như thật. Ðây là Con Ðường đưa đến Khổ diệt, này các Tỷ-kheo, đây là như thật, không ly như thật, không khác như thật. Bốn pháp này, này các Tỷ-kheo, là như thật, không ly như thật, không khác như thật. Do vậy, này các Tỷ-kheo, một sự cố gắng cần phải làm để rõ biết: “Ðây là Khổ” … một cố gắng cần phải làm để rõ biết: “Ðây là Con Ðường đưa đến Khổ diệt”.`, ref: "Tương Ưng Bộ 56.20", url: "https://loicuaducphat.org/sn/sn56.20.html#content" },

{ text: `- Này các Tỷ-kheo, do không giác ngộ, do không thông đạt bốn Thánh đế mà Ta và các Ông lâu ngày phải dong ruổi, lưu chuyển như thế này. Thế nào là bốn? Do không giác ngộ, do không thông đạt Thánh đế về Khổ, này các Tỷ-kheo, nên Ta và các Ông lâu ngày phải dong ruổi, lưu chuyển như thế này … Thánh đế về Khổ tập … Thánh đế về Khổ diệt … Do không giác ngộ, do không thông đạt Thánh đế về Con Ðường đưa đến Khổ diệt, này các Tỷ-kheo, nên Ta và các Ông lâu ngày phải dong ruổi, lưu chuyển như thế này. Nhưng nay, này các Tỷ-kheo, Thánh đế về Khổ này đã được giác ngộ, đã được thông đạt Thánh đế về Khổ tập đã được giác ngộ, đã được thông đạt Thánh đế về Khổ diệt đã được giác ngộ, đã được thông đạt Thánh đế về Con Ðường đưa đến Khổ diệt đã được giác ngộ, đã được thông đạt. Ðược chặt đứt là hữu ái, được đoạn tận là những gì đưa đến tái sanh. Nay không còn tái sanh nữa. Thế Tôn thuyết giảng như vậy … bậc Ðạo Sư lại nói thêm:\n\nDo không như thật thấy,\nBốn sự thật bậc Thánh,\nPhải lâu ngày luân chuyển,\nTrải qua nhiều đời sống.\nKhi chúng được thấy rõ,\nMầm tái sanh nhổ sạch,\nGốc khổ được đoạn tận,\nNay không còn tái sanh.`, ref: "Tương Ưng Bộ 56.21", url: "https://loicuaducphat.org/sn/sn56.21.html#content" },

{ text: `Những ai không rõ biết,\nKhổ và Khổ tập khởi,\nKhông rõ như thế nào,\nKhổ đoạn tận không dư,\nKhông biết Con Ðường ấy\nÐưa đến chỉ tịnh Khổ.\nNhững vị ấy không có\nTâm và tuệ giải thoát,\nHọ không thể chấm dứt,\nPhải đi đến sanh già.\nNhững vị nào rõ biết,\nKhổ và Khổ tập khởi,\nVà rõ như thế nào,\nKhổ đoạn tận không dư,\nRõ biết Con Ðường ấy\nÐưa đến chỉ tịnh khổ.\nTâm giải thoát thành tựu,\nVà các tuệ giải thoát,\nHọ có thể chấm dứt,\nKhông đi đến sanh già.`, ref: "Tương Ưng Bộ 56.22", url: "https://loicuaducphat.org/sn/sn56.22.html#content" },

{ text: `- Các Ông nghĩ thế nào, này các Tỷ-kheo, cái gì là nhiều hơn, một số ít lá Simsapà mà Ta nắm lấy trong tay, hay lá trong rừng Simsapà? - Thật là quá ít, bạch Thế Tôn, một ít lá Simsapà mà Thế Tôn nắm lấy trong tay, và thật là quá nhiều lá trong rừng Simsapà. - Cũng vậy, này các Tỷ-kheo, thật là quá nhiều, những gì Ta đã thắng tri mà không nói cho các Ông! Thật là quá ít những gì mà Ta đã nói ra! Nhưng tại sao, này các Tỷ-kheo, Ta lại không nói ra những điều ấy? Vì rằng, này các Tỷ-kheo, những điều ấy không liên hệ đến mục đích, không phải là căn bản cho Phạm hạnh, không đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn. Do vậy, Ta không nói lên những điều ấy. Và này các Tỷ-kheo, điều gì mà Ta nói? “Ðây là Khổ”, này các Tỷ-kheo, là điều Ta nói. “Ðây là Khổ tập”, là điều Ta nói. “Ðây là Khổ diệt”, là điều Ta nói. “Ðây là Con Ðường đưa đến Khổ diệt”, là điều Ta nói. Nhưng tại sao, này các Tỷ-kheo, Ta lại nói ra những điều ấy? Vì rằng, này các Tỷ-kheo, những điều ấy liên hệ đến mục đích, là căn bản cho Phạm hạnh, đưa đến yếm ly, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn. Do vậy, Ta nói lên những điều ấy.`, ref: "Tương Ưng Bộ 56.31", url: "https://loicuaducphat.org/sn/sn56.31.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, một cây gậy được quăng lên hư không, khi thì rơi xuống đầu gốc, khi thì rơi xuống chặng giữa, khi thì rơi xuống đầu ngọn. Cũng vậy, này các Tỷ-kheo, các chúng sanh bị vô minh che lấp, bị khát ái trói buộc, dong ruổi, luân chuyển, khi thì đi từ thế giới này đến thế giới kia, khi thì đi từ thế giới kia đến thế giới này. Vì sao? Vì rằng không thấy bốn Thánh đế. Này các Tỷ-kheo, bốn Thánh đế ấy là gì? Thánh đế về Khổ … Thánh đế về Con Ðường đưa đến Khổ diệt.`, ref: "Tương Ưng Bộ 56.33", url: "https://loicuaducphat.org/sn/sn56.33.html#content" },

{ text: `- Này các Tỷ-kheo, khi khăn đầu hay đầu bị lửa cháy, thời phải làm gì? - Bạch Thế Tôn, khi khăn đầu hay đầu bị bị lửa cháy, để dập tắt khăn đầu hay đầu bị lửa cháy cần phải có ước muốn tăng thượng, tinh tấn, cố gắng, nỗ lực, không có thối thất, chánh niệm và tỉnh giác. - Bỏ qua đầu và khăn bị cháy, này các Tỷ-kheo, không có tác ý để như thật chứng ngộ bốn Thánh đế, chưa được chứng ngộ, cần phải có ước muốn tăng thượng, tinh tấn, cố gắng, nỗ lực, không thối thất, chánh niệm và tỉnh giác. Thế nào là bốn? Thánh đế về Khổ … Thánh đế về Con Ðường đưa đến Khổ diệt. Do vậy, này các Tỷ-kheo, một cố gắng cần phải làm để rõ biết: “Ðây là Khổ” … một cố gắng cần phải làm để rõ biết: “Ðây là Con Ðường đưa đến Khổ diệt”.`, ref: "Tương Ưng Bộ 56.34", url: "https://loicuaducphat.org/sn/sn56.34.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, một người tuổi thọ đến một trăm năm, mạng sống đến một trăm năm. Có người đến nói với người ấy: “Này Ông, vào buổi sáng, Ông sẽ bị đâm một trăm cây thương. Vào buổi trưa, Ông sẽ bị đâm một trăm cây thương. Vào buổi chiều, Ông sẽ bị đâm một trăm cây thương. Này Ông, như vậy mỗi ngày Ông bị đâm ba trăm cây thương, với tuổi thọ đến một trăm năm, với mạng sống đến một trăm năm. Sau một trăm năm, Ông sẽ được giác ngộ bốn Thánh đế trước kia chưa được giác ngộ”. Này các Tỷ-kheo, một thiện nam tử hiểu biết nghĩa lý có thể chấp nhận chăng? Vì sao? Vô thỉ, này các Tỷ-kheo, là sự luân chuyển, khởi điểm không thể nêu rõ, đối với (những đau khổ) do bị thương đâm, do bị kiếm chém, do bị búa chặt. Dầu vậy đi chăng nữa, này các Tỷ-kheo, Ta cũng không tuyên bố rằng nhờ khổ và ưu mà bốn Thánh đế được chứng ngộ. Nhưng này các Tỷ-kheo, Ta tuyên bố rằng nhờ lạc và hỷ mà bốn Thánh đế được chứng ngộ. Thế nào là bốn? Thánh đế về Khổ … Thánh đế về Con Ðường đưa đến Khổ diệt.`, ref: "Tương Ưng Bộ 56.35", url: "https://loicuaducphat.org/sn/sn56.35.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, một người quăng một khúc gỗ có một lỗ hổng vào biển lớn. Tại đấy có con rùa mù, sau mỗi trăm năm nổi lên một lần. Các Ông nghĩ thế nào, này các Tỷ-kheo, con rùa mù ấy sau mỗi trăm năm nổi lên một lần, có thể chui cổ vào khúc gỗ có một lỗ hổng hay không? - Năm khi mười họa may ra có thể được, bạch Thế Tôn, sau một thời gian dài. - Ta tuyên bố rằng còn mau hơn, này các Tỷ-kheo, là con rùa mù ấy, sau mỗi trăm năm nổi lên một lần, có thể chui cổ vào khúc gỗ có một lỗ hổng ấy; còn hơn kẻ ngu, khi một lần đã rơi vào đọa xứ để được làm người trở lại. Vì sao? Vì rằng ở đấy không có pháp hành, chánh hành, thiện nghiệp, phước nghiệp. Ở đấy, này các Tỷ-kheo, chỉ có ăn thịt lẫn nhau, và chỉ có người yếu bị ăn thịt. Vì sao? Vì không thấy được bốn Thánh đế. Thế nào là bốn? Thánh đế về Khổ … Thánh đế về Con Ðường đưa đến Khổ diệt. Do vậy, này các Tỷ-kheo, một cố gắng cần phải làm để rõ biết: “Ðây là Khổ” … một cố gắng cần phải làm để rõ biết: “Ðây là Con Ðường đưa đến Khổ diệt”.`, ref: "Tương Ưng Bộ 56.47", url: "https://loicuaducphat.org/sn/sn56.47.html#content" },

{ text: `- Ví như, này các Tỷ-kheo, quả đất lớn này chỉ toàn một bãi nước và một người đến ném xuống đấy một khúc cây có một lỗ hổng. Rồi gió phương Ðông thổi nó trôi về phương Tây; gió phương Tây thổi nó trôi về phương Ðông; gió phương Bắc thổi nó trôi về phương Nam; gió phương Nam thổi nó trôi về phương Bắc. Tại đấy, một con rùa mù cứ mỗi trăm năm nổi lên một lần. Các Ông nghĩ thế nào, này các Tỷ-kheo, con rùa mù ấy sau mỗi trăm năm nổi lên một lần, có thể chui cổ vào trong khúc cây có một lỗ hổng không? - Thật khó được vậy, bạch Thế Tôn, con rùa mù ấy, sau mỗi trăm năm nổi lên một lần, có thể chui cổ vào trong khúc cây có một lỗ hổng ấy! - Thật khó được vậy, này các Tỷ-kheo, là được làm người! Thật khó được vậy, này các Tỷ-kheo, là Như Lai xuất hiện ở đời, bậc A-la-hán, Chánh Ðẳng Giác! Thật khó được vậy, này các Tỷ-kheo, là Pháp và Luật này do Như Lai thuyết giảng chiếu sáng trên đời. Nhưng nay, này các Tỷ-kheo, các Ông đã được làm người, và Như Lai xuất hiện ở đời, bậc A-la-hán, Chánh đẳng Chánh giác. Và Pháp và Luật được Như Lai thuyết giảng chói sáng ở đời. Do vậy, này các Tỷ-kheo, một cố gắng cần phải làm để rõ biết: “Ðây là Khổ” … một cố gắng cần phải làm để rõ biết: “Ðây là Con Ðường đưa đến Khổ diệt”.`, ref: "Tương Ưng Bộ 56.48", url: "https://loicuaducphat.org/sn/sn56.48.html#content" },

{ text: `Rồi Thế Tôn lấy lên một ít đất trên đầu móng tay và bảo các Tỷ-kheo: - Các Ông nghĩ thế nào, này các Tỷ-kheo, cái nào là nhiều hơn, một ít đất Ta lấy trên đầu móng tay, hay quả đất lớn này? - Cái này là nhiều hơn, bạch Thế Tôn, tức là quả đất. Và ít hơn là một ít đất mà Thế Tôn lấy trên đầu móng tay, không thể ước tính được, không thể so sánh được, không thể thành một phần nhỏ được, nếu đem so sánh quả đất lớn với một ít đất mà Thế Tôn lấy trên đầu móng tay. - Cũng vậy, này các Tỷ-kheo, ít hơn là các chúng sanh sau khi chết từ thân người, được tái sanh làm người lại. Và nhiều hơn là các chúng sanh sau khi chết từ thân người, phải tái sanh trong địa ngục. Vì sao? Này các Tỷ-kheo, vì không thấy bốn Thánh đế. Thế nào là bốn? Thánh đế về Khổ … Thánh đế về Con Ðường đưa đến Khổ diệt. Do vậy, này các Tỷ-kheo, một cố gắng cần phải làm để rõ biết: “Ðây là Khổ” … một cố gắng cần phải làm để rõ biết: “Ðây là Con Ðường đưa đến Khổ diệt”.`, ref: "Tương Ưng Bộ 56.102", url: "https://loicuaducphat.org/sn/sn56.102.html#content" },

   
                { text: `Ta không thấy một sắc nào khác, này các Tỷ-kheo, xâm chiếm và ngự trị tâm người đàn ông như sắc người đàn bà. Này các Tỷ-kheo, sắc người đàn bà xâm chiếm và ngự trị tâm người đàn ông.`, ref: "Tăng Chi Bộ 1.1", url: "https://loicuaducphat.org/an/an1.1.html#content" },

{ text: `Ta không thấy một sắc nào khác, này các Tỷ-kheo, xâm chiếm và ngự trị tâm người đàn bà như sắc người đàn ông. Này các Tỷ-kheo, sắc người đàn ông xâm chiếm và ngự trị tâm người đàn bà.`, ref: "Tăng Chi Bộ 1.6", url: "https://loicuaducphat.org/an/an1.6.html#content" },

{ text: `Ta không thấy một tiếng nào khác, này các Tỷ-kheo, xâm chiếm và ngự trị tâm người đàn ông, như tiếng người đàn bà. Này các Tỷ-kheo, tiếng người đàn bà xâm chiếm và ngự trị tâm người đàn ông.`, ref: "Tăng Chi Bộ 1.2", url: "https://loicuaducphat.org/an/an1.2.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, dẫn đến dục tham chưa sanh được sanh khởi, hay dục tham đã sanh được tăng trưởng quảng đại, này các Tỷ-kheo, như tịnh tướng. Tịnh tướng, này các Tỷ-kheo, nếu không như lý tác ý, đưa đến dục tham chưa sanh được sanh khởi, hay dục tham đã sanh được tăng trưởng quảng đại.`, ref: "Tăng Chi Bộ 1.11", url: "https://loicuaducphat.org/an/an1.11.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, đưa đến hôn trầm thụy miên chưa sanh được sanh khởi, hay hôn trầm thụy miên đã sanh được tăng trưởng quảng đại, này các Tỷ-kheo, như không hân hoan, biếng nhác, chán nản, ăn quá no, tâm thụ động. Với người có tâm thụ động, này các Tỷ-kheo, hôn trầm thụy miên chưa sanh được sanh khởi, hay hôn trầm thụy miên đã sanh được tăng trưởng quảng đại.`, ref: "Tăng Chi Bộ 1.13", url: "https://loicuaducphat.org/an/an1.13.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, đưa đến dục tham chưa sanh không sanh khởi, hay dục tham đã sanh được đoạn tận, này các Tỷ-kheo, như bất tịnh tướng. Bất tịnh tướng, này các Tỷ-kheo, nếu như lý tác ý, thời dục tham chưa sanh không sanh khởi, hay dục tham đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.16", url: "https://loicuaducphat.org/an/an1.16.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, đưa đến sân chưa sanh không sanh khởi, hay sân đã sanh được đoạn tận, này các Tỷ-kheo, như từ tâm giải thoát. Từ tâm giải thoát, này các Tỷ-kheo, nếu như lý tác ý, thời sân chưa sanh không sanh khởi, hay sân đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.17", url: "https://loicuaducphat.org/an/an1.17.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, đưa đến hôn trầm thụy miên chưa sanh không sanh khởi, hay hôn trầm thụy miên đã sanh được đoạn tận, này các Tỷ kheo, như tinh cần giới, tinh tấn giới, dõng mãnh giới. Người tinh cần tinh tấn, này các Tỷ kheo, hôn trầm thụy miên chưa sanh không sanh khởi, hay hôn trầm thụy miên đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.18", url: "https://loicuaducphat.org/an/an1.18.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ kheo, lại khó sử dụng, này các Tỷ kheo, như tâm không được tu tập. Tâm không được tu tập, này các Tỷ kheo, khó sử dụng.`, ref: "Tăng Chi Bộ 1.21", url: "https://loicuaducphat.org/an/an1.21.html#content" },


{ text: `Ta không thấy một pháp nào khác, này các Tỷ kheo, lại dễ sử dụng, này các Tỷ kheo, như tâm được tu tập. Tâm được tu tập, này các Tỷ kheo, dễ sử dụng.`, ref: "Tăng Chi Bộ 1.22", url: "https://loicuaducphat.org/an/an1.22.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ kheo, lại đưa đến bất lợi lớn, này các Tỷ kheo, như tâm không được tu tập. Tâm không được tu tập, này các Tỷ kheo, đưa đến bất lợi lớn.`, ref: "Tăng Chi Bộ 1.23", url: "https://loicuaducphat.org/an/an1.23.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ kheo, lại đưa đến lợi ích lớn, này các Tỷ kheo, như tâm được tu tập. Tâm được tu tập, này các Tỷ kheo, đưa đến lợi ích lớn.`, ref: "Tăng Chi Bộ 1.24", url: "https://loicuaducphat.org/an/an1.34.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, với tâm của Ta biết tâm một người là uế nhiễm, Ta rõ biết: “Nếu trong thời gian này, người này mệnh chung, người ấy bị rơi vào địa ngục như vậy tương xứng”. Vì cớ sao? Này các Tỷ-kheo, vì rằng tâm người ấy uế nhiễm. Cũng do tâm uế nhiễm làm nhân như vậy, này các Tỷ-kheo, một số loài hữu tình ở đời, sau khi thân hoại mạng chung, sanh vào cõi dữ, ác thú, đọa xứ, địa ngục.`, ref: "Tăng Chi Bộ 1.43", url: "https://loicuaducphat.org/an/an1.43.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, với tâm của Ta biết tâm một người là thanh tịnh, Ta biết rõ: “Nếu trong thời gian này, người này mệnh chung, người ấy được sanh lên Thiên giới như vậy tương xứng”. Vì cớ sao? Này các Tỷ-kheo, vì rằng tâm người ấy thanh tịnh. Cũng do tâm thanh tịnh làm nhân như vậy, này các Tỷ-kheo, một số loài hữu tình ở đời này, sau khi thân hoại mạng chung, sanh vào cõi thiện, cõi Trời, cõi đời này.`, ref: "Tăng Chi Bộ 1.44", url: "https://loicuaducphat.org/an/an1.44.html#content" },

{ text: `Tâm này, này các Tỷ-kheo, là sáng chói, nhưng bị ô nhiễm bởi các cấu uế từ ngoài vào.`, ref: "Tăng Chi Bộ 1.49", url: "https://loicuaducphat.org/an/an1.49.html#content" },

{ text: `Nếu chỉ trong khoảnh khắc búng móng tay, này các Tỷ-kheo, vị Tỷ-kheo phát từ tâm; Vị ấy, này các Tỷ-kheo, được gọi là: vị Tỷ-kheo trú Thiền tịnh không có trống không, làm theo lời dạy bậc Ðạo Sư, là người làm theo giáo giới, ăn đồ ăn khất thực của xứ không có uổng phí. Còn nói gì những người làm cho sung mãn từ tâm ấy.`, ref: "Tăng Chi Bộ 1.53", url: "https://loicuaducphat.org/an/an1.53.html#content" },

{ text: `Phàm những pháp nào, này các Tỷ-kheo, là bất thiện, thuộc thành phần bất thiện, đứng về phía bất thiện, tất cả các pháp ấy đều được ý đi trước. Ý khởi trước các pháp ấy. Các pháp bất thiện theo sau.`, ref: "Tăng Chi Bộ 1.56", url: "https://loicuaducphat.org/an/an1.56.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận, này các Tỷ-kheo, như phóng dật. Với người phóng dật, này các Tỷ-kheo, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.58", url: "https://loicuaducphat.org/an/an1.58.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận, này các Tỷ-kheo, như biếng nhác. Với người biếng nhác, này các Tỷ-kheo, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.60", url: "https://loicuaducphat.org/an/an1.60.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận, này các Tỷ-kheo, như tinh tấn tinh cần. Với người tinh cần tinh tấn, này các Tỷ-kheo, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.61", url: "https://loicuaducphat.org/an/an1.61.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận, này các Tỷ-kheo, như ít dục. Với người có ít dục, này các Tỷ-kheo, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.63", url: "https://loicuaducphat.org/an/an1.63.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận, này các Tỷ-kheo, như là không biết vừa đủ. Với người không biết vừa đủ, này các Tỷ-kheo, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.64", url: "https://loicuaducphat.org/an/an1.64.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận, này các Tỷ-kheo, như biết vừa đủ. Với người biết vừa đủ, này các Tỷ-kheo, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.65", url: "https://loicuaducphat.org/an/an1.65.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận, này các Tỷ-kheo, như như lý tác ý. Với người như lý tác ý, này các Tỷ-kheo, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.67", url: "https://loicuaducphat.org/an/an1.67.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận, này các Tỷ-kheo, như tỉnh giác. Với người tỉnh giác, này các Tỷ-kheo, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.69", url: "https://loicuaducphat.org/an/an1.69.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận, này các Tỷ-kheo, như làm bạn với ác. Với người làm bạn với ác, này các Tỷ-kheo, các pháp bất thiện chưa sanh được sanh khởi, và các pháp thiện đã sanh bị đoạn tận.`, ref: "Tăng Chi Bộ 1.70", url: "https://loicuaducphat.org/an/an1.70.html#content" },

{ text: `Ta không thấy một pháp nào khác, này các Tỷ-kheo, do pháp ấy, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận, này các Tỷ-kheo, như làm bạn với thiện. Với người làm bạn với thiện, này các Tỷ-kheo, các pháp thiện chưa sanh được sanh khởi, và các pháp bất thiện đã sanh được đoạn tận.`, ref: "Tăng Chi Bộ 1.71", url: "https://loicuaducphat.org/an/an1.71.html#content" },

{ text: `Ít có giá trị, này các Tỷ-kheo, là những mất mát này, như mất mát tài sản. Cái này là khốn cùng giữa các mất mát, này các Tỷ-kheo, tức là mất mát trí tuệ.`, ref: "Tăng Chi Bộ 1.78", url: "https://loicuaducphat.org/an/an1.78.html#content" },

{ text: `Ít có giá trị, này các Tỷ-kheo, là những mất mát này, như mất mát danh tiếng. Cái này là khốn cùng giữa các mất mát, này các Tỷ-kheo, tức là mất mát trí tuệ.`, ref: "Tăng Chi Bộ 1.80", url: "https://loicuaducphat.org/an/an1.80.html#content" },

{ text: `Ít có giá trị, này các Tỷ-kheo, là những tăng trưởng này, như tăng trưởng danh tiếng. Cái này là tối thượng giữa các tăng trưởng, này các Tỷ-kheo, tức là tăng trưởng trí tuệ. Do vậy, này các Tỷ-kheo, các Thầy cần phải học tập như sau: “Chúng ta sẽ làm tăng trưởng sự tăng trưởng trí tuệ”. Như vậy, này các Tỷ-kheo, các Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 1.81", url: "https://loicuaducphat.org/an/an1.81.html#content" },

{ text: `Những Tỷ-kheo nào, này các Tỷ-kheo, nêu rõ pháp là pháp, nêu rõ phi pháp là phi pháp, các Tỷ-kheo ấy, này các Tỷ-kheo, sở hành như vậy, đem lại hạnh phúc cho đa số, an lạc cho đa số, lợi ích cho đa số, đem lại hạnh phúc an lạc cho chư Thiên và loài Người. Và hơn nữa, này các Tỷ-kheo, các Tỷ-kheo ấy tạo phước đức và an trú diệu pháp này.`, ref: "Tăng Chi Bộ 1.140", url: "https://loicuaducphat.org/an/an1.140.html#content" },

{ text: `Một người, này các Tỷ-kheo, khi xuất hiện ở đời, sự xuất hiện đem lại hạnh phúc cho đa số, an lạc cho đa số, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư Thiên và loài Người. Một người ấy là ai? Chính là Thế Tôn, bậc A-la-hán, Chánh Ðẳng Giác. Chính một người này, này các Tỷ-kheo, khi xuất hiện ở đời, sự xuất hiện đem lại hạnh phúc cho đa số, an lạc cho đa số, vì lòng thương tưởng cho đời, vì lợi ích, vì hạnh phúc, vì an lạc cho chư Thiên và loài Người.”`, ref: "Tăng Chi Bộ 1.170", url: "https://loicuaducphat.org/an/an1.170.html#content" },

{ text: `Sự xuất hiện của một người, này các Tỷ-kheo, khó gặp được ở đời. Của người nào? Của Như Lai, bậc A-la-hán, Chánh Ðẳng Giác. Sự xuất hiện của một người này, này các Tỷ-kheo, khó gặp được ở đời.`, ref: "Tăng Chi Bộ 1.171", url: "https://loicuaducphat.org/an/an1.171-174.html#content" },

{ text: `Sự kiện này không xảy ra, này các Tỷ-kheo, không có được: Một người thành tựu chánh kiến có thể chấp nhận các hành là thường còn. Sự kiện này không xảy ra. Và sự kiện này có xảy ra, này các Tỷ-kheo, kẻ phàm phu có thể chấp nhận các hành là thường còn. Sự kiện này có xảy ra.`, ref: "Tăng Chi Bộ 1.268", url: "https://loicuaducphat.org/an/an1.268.html#content" },

{ text: `Sự kiện này không xảy ra, này các Tỷ-kheo, không có được: là quả dị thục của thân làm ác có thể là khả lạc, khả hỷ, khả ý. Sự kiện này không xảy ra. Sự kiện này có xảy ra, này các Tỷ-kheo, là quả dị thục của thân làm ác là không khả lạc, không khả hỷ, không khả ý. Sự kiện này có xảy ra.`, ref: "Tăng Chi Bộ 1.284", url: "https://loicuaducphat.org/an/an1.284-286.html#content" },

{ text: `Ðối với người có chánh kiến, này các Tỷ-kheo, phàm mọi thân hành hoàn toàn được thực hiện, được chấp nhận theo chánh kiến, phàm mọi khẩu hành… phàm mọi ý hành hoàn toàn được thực hiện, được chấp nhận theo chánh kiến, phàm có tư tâm sở nào, phàm có quyết định nào, phàm có ước nguyện nào, và phàm có các hành nào, tất cả pháp ấy đưa đến khả lạc, khả hỷ, khả ý, đưa đến hạnh phúc, an lạc.`, ref: "Tăng Chi Bộ 1.315", url: "https://loicuaducphat.org/an/an1.315.html#content" },
{ text: `Ở đây, này các Tỷ-kheo, có người suy xét như sau: “Quả dị thục của thân làm ác trong đời sau là ác và khổ, Quả dị thục của miệng nói ác trong đời sau là ác và khổ, Quả dị thục của ý nghĩ ác trong đời sau là ác và khổ. Nếu thân ta làm ác, nói lời ác, nghĩ việc ác. Sao ta lại không có thể, sau khi thân hoại mạng chung, phải sanh vào cõi dữ, ác thú, đọa xứ, địa ngục”. Người ấy sợ hãi tội có kết quả trong đời sau, từ bỏ thân làm ác, tu tập thân làm thiện, từ bỏ miệng nói ác, tu tập miệng nói thiện, từ bỏ ý nghĩ ác, tu tập ý nghĩ thiện, và cư xử tự ngã hoàn toàn thanh tịnh.`, ref: "Tăng Chi Bộ 2.1", url: "https://loicuaducphat.org/an/an2.1.html#content" },

{ text: `Này các Tỷ-kheo, cần phải học tập như sau: “Chúng ta phải sợ hãi đối với tội có kết quả hiện tại. Chúng ta phải sợ hãi đối với tội có kết quả trong đời sau. Chúng ta phải tránh xa các tội. Chúng ta phải thấy rõ sự nguy hiểm của các tội”. Như vậy, này các Tỷ-kheo, các ngươi cần phải học tập. Ðối với ai tránh xa các tội, này các Tỷ-kheo, đối với ai thấy rõ sự nguy hiểm của các tội, thời được chờ đợi rằng người ấy sẽ được giải thoát tất cả tội.`, ref: "Tăng Chi Bộ 2.1", url: "https://loicuaducphat.org/an/an2.1.html#content" },

{ text: `Này các Tỷ-kheo, nếu các Thầy không có thối chuyển, cố gắng như sau: “Ta sẵn sàng, dầu chỉ còn da, gân và xương, dầu thịt và máu trên thân bị khô héo, mong rằng sẽ có tinh tấn kiên trì để chứng đắc những gì chưa chứng đắc, nhờ sức mạnh của người, nhờ tinh tấn của người, nhờ cần dõng của người”. Thời không bao lâu, này các Tỷ-kheo, các Thầy sẽ đạt được mục đích mà các Thiện nam tử chơn chánh xuất gia, từ bỏ gia đình, sống không gia đình: Ðó chính là vô thượng cứu cánh Phạm hạnh, ngay trong hiện tại, các Thầy với thắng trí, tự mình chứng ngộ, chứng đạt và an trú.`, ref: "Tăng Chi Bộ 2.5", url: "https://loicuaducphat.org/an/an2.5.html#content" },

{ text: `Này các Tỷ-kheo, ai sống thấy vị ngọt trong các pháp có thể khởi lên kiết sử, này các Tỷ-kheo, tham không đoạn tận, sân không đoạn tận, si không đoạn tận. Do tham không đoạn tận, sân không đoạn tận, si không đoạn tận, nên không giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng người ấy không giải thoát khỏi khổ đau.`, ref: "Tăng Chi Bộ 2.6", url: "https://loicuaducphat.org/an/an2.6.html#content" },

{ text: `Này các Tỷ-kheo, ai sống thấy nhàm chán trong các pháp có thể khởi lên kiết sử, này các Tỷ-kheo, tham được đoạn tận, sân được đoạn tận, si được đoạn tận. Do tham được đoạn tận, sân được đoạn tận, si được đoạn tận, nên được giải thoát khỏi sanh, già, chết, sầu, bi, khổ, ưu, não. Ta nói rằng người ấy giải thoát khỏi khổ đau.`, ref: "Tăng Chi Bộ 2.6", url: "https://loicuaducphat.org/an/an2.6.html#content" },

{ text: `Hai pháp trắng này, này các Tỷ-kheo, che chở cho thế giới. Thế nào là hai? Tàm và quý. (Xấu hổ và sợ hãi tội lỗi) Nếu hai pháp trắng này, không che chở cho thế giới, thời không thể chỉ được đây là mẹ hay là em, chị của mẹ, hay đây là vợ của anh hay em của mẹ, hay đây là vợ của Thầy hay đây là vợ của các vị tôn trưởng. Và thế giới sẽ đi đến hỗn loạn như giữa các loài dê, loài gà vịt, loài heo, loài chó, loài dã can.`, ref: "Tăng Chi Bộ 2.9", url: "https://loicuaducphat.org/an/an2.9.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là sức mạnh tư sát? Ở đây, này các Tỷ-kheo, có người tư sát như sau: “Với thân làm ác, quả dị thục là ác ngay hiện tại và trong đời sau. Với miệng nói ác, quả dị thục là ác ngay trong hiện tại và trong đời sau. Với ý nghĩ ác, quả dị thục là ác ngay trong hiện tại và trong đời sau”. Vị ấy, tư sát như vậy, từ bỏ thân làm ác, tu tập thân làm thiện, từ bỏ miệng nói ác, tu tập miệng nói thiện, từ bỏ ý nghĩ ác, tu tập ý nghĩ thiện, tư sát sự thật thanh tịnh. Này các Tỷ-kheo, đây gọi là sức mạnh tư sát.`, ref: "Tăng Chi Bộ 2.11", url: "https://loicuaducphat.org/an/an2.11.html#content" },

{ text: `Và thế nào, này các Tỷ-kheo, là sức mạnh tu tập? Ở đây, này các Tỷ-kheo, sức mạnh tu tập tức là sức mạnh của người hữu học.\nNhư vậy, này các tỳ kheo, do sức mạnh tu học, vị ấy từ bỏ tham, từ bỏ sân, từ bỏ si. Sau khi từ bỏ tham, từ bỏ sân, từ bỏ si, vị ấy không làm các điều bất thiện, không phục vụ các điều ác. Này các Tỷ-kheo, đây gọi là sức mạnh tu tập.`, ref: "Tăng Chi Bộ 2.11", url: "https://loicuaducphat.org/an/an2.11.html#content" },

{ text: `Trong bất cứ tranh tụng nào, này các Tỷ-kheo, Tỷ-kheo phạm tội và Tỷ-kheo buộc tội, không tự mình khéo quán sát lấy mình, thời tranh tụng ấy được chờ đợi là sẽ đưa đến kéo dài, gay gắt, ác liệt, và các Tỷ-kheo sẽ sống không được an lạc. Và trong bất cứ cuộc tranh tụng nào, này các Tỷ-kheo, Tỷ-kheo phạm tội và Tỷ-kheo buộc tội, có tự mình khéo quán sát lấy mình, thời tranh tụng ấy, này các Tỷ-kheo, được chờ đợi là không đưa đến kéo dài, gay gắt, ác liệt, và các Tỷ-kheo sẽ sống được an lạc.`, ref: "Tăng Chi Bộ 2.15", url: "https://loicuaducphat.org/an/an2.15.html#content" },

{ text: `Này Ananda, Ta đã tuyên bố một cách dứt khoát rằng, thân làm ác, miệng nói ác, ý nghĩ ác là điều không nên làm. Nếu làm những điều không nên làm ấy, thời có những nguy hại như sau được chờ đợi: Tự mình chê trách mình; sau khi được biết, kẻ trí chê trách, tiếng ác đồn xa, bị mê ám khi mạng chung; sau khi thân hoại mạng chung, bị sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Vì thế, này Ananda, Ta đã tuyên bố một cách dứt khoát rằng, thân làm ác, miệng nói ác, ý nghĩ ác là điều không nên làm. Nếu làm những điều không nên làm ấy, thời có những nguy hại như vậy được chờ đợi.`, ref: "Tăng Chi Bộ 2.18", url: "https://loicuaducphat.org/an/an2.18.html#content" },

{ text: `Này Ananda, Ta dã tuyên bố một cách dứt khoát rằng, thân làm thiện, miệng nói thiện, ý nghĩ thiện là điều nên làm. Nếu làm những điều nên làm ấy, thời có những lợi ích như sau được chờ đợi: Tự mình không chê trách mình; sau khi được biết, kẻ trí tán thán, tiếng lành đồn xa, không bị mê ám khi mạng chung; sau khi thân hoại mạng chung, được sanh vào cõi Thiện, cõi Trời, cõi đời này. Vì thế, này Ananda, Ta đã tuyên bố một cách dứt khoát rằng, thân làm thiện, miệng nói thiện, ý nghĩ thiện là điều nên làm. Nếu làm những điều nên làm ấy, thời có những lợi ích như vậy được chờ đợi.`, ref: "Tăng Chi Bộ 2.18", url: "https://loicuaducphat.org/an/an2.18.html#content" },

{ text: `Này các Tỷ-kheo, hãy từ bỏ bất thiện, này các Tỷ-kheo, từ bỏ bất thiện có thể làm được. Nếu từ bỏ bất thiện không thể làm được thời ta đã không nói như sau: “Này các Tỷ-kheo, hãy từ bỏ bất thiện”. Vì rằng, này các Tỷ-kheo, từ bỏ bất thiện có thể làm được, do vậy Ta mới nói rằng: “Này các Tỷ-kheo, hãy từ bỏ bất thiện”. Và nếu, này các Tỷ-kheo, từ bỏ bất thiện đưa đến bất hạnh, đau khổ, thời ta không nói như sau: “Này các Tỷ-kheo, hãy từ bỏ bất thiện”. Và này các Tỷ-kheo, vì từ bỏ bất thiện đưa đến hạnh phúc, an lạc, nên Ta đã nói như sau: “Này các Tỷ-kheo, hãy từ bỏ bất thiện”.`, ref: "Tăng Chi Bộ 2.19", url: "https://loicuaducphat.org/an/an2.19.html#content" },

{ text: `Hai pháp này, này các Tỷ-kheo, đưa đến sự hỗn loạn (mê mờ) và biến mất của diệu pháp. Thế nào là hai? Văn cú bị đảo ngược và ý nghĩa bị hiểu lầm. Nếu văn cú bị đảo ngược thời ý nghĩa bị hiểu lầm. Những pháp này, này các Tỷ-kheo, là hai pháp đưa đến hỗn loạn và biến mất của diệu pháp.`, ref: "Tăng Chi Bộ 2.20", url: "https://loicuaducphat.org/an/an2.20.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là địa vị bậc không phải Chân nhân? Người không phải Chân nhân, này các Tỷ-kheo, không biết ơn, không nhớ ơn. Ðối với những người độc ác, đây là đặc tánh của họ được biết đến, này các Tỷ-kheo, tức là không biết ơn, không nhớ ơn. Ðây hoàn toàn là địa vị kẻ không Chân nhân, này các Tỷ-kheo, tức là không biết ơn, không nhớ ơn. Còn bậc Chân nhân, này các Tỷ-kheo, là biết ơn, là nhớ ơn. Ðối với những thiện nhân, đây là đặc tánh của họ được biết đến, này các Tỷ-kheo, tức là biết ơn, nhớ ơn. Ðây hoàn toàn là địa vị bậc Chân nhân, này các Tỷ-kheo, tức là biết ơn, nhớ ơn.`, ref: "Tăng Chi Bộ 2.32", url: "https://loicuaducphat.org/an/an2.32.html#content" },

{ text: `Có hai hạng người, này các Tỷ-kheo, ta nói không thể trả ơn được. Thế nào là hai? Mẹ và Cha. Nếu một bên vai cõng mẹ, này các Tỷ-kheo, nếu một bên vai cõng cha, làm vậy suốt trăm năm, cho đến trăm tuổi; nếu đấm bóp, thoa xức, tắm rửa, xoa gội, và dầu tại đấy, mẹ cha có vãi tiểu tiện đại tiện, như vậy, này các Tỷ-kheo, cũng chưa làm đủ hay trả ơn đủ mẹ và cha. Hơn nữa, này các Tỷ-kheo, nếu có an trí cha mẹ vào quốc độ với tối thượng uy lực, trên quả đất lớn với bảy báu này, như vậy, này các Tỷ-kheo, cũng chưa làm đủ hay trả ơn đủ mẹ và cha. Vì cớ sao? Vì rằng, này các Tỷ-kheo, cha mẹ đã làm nhiều cho con cái, nuôi nấng, nuôi dưỡng chúng lớn, giới thiệu chúng vào đời này.`, ref: "Tăng Chi Bộ 2.33", url: "https://loicuaducphat.org/an/an2.33.html#content" },

{ text: `Này các Tỷ-kheo, ai đối với cha mẹ không có lòng tin, khuyến khích, hướng dẫn an trú các vị ấy vào lòng tin; đối với mẹ cha theo ác giới, khuyến khích, hướng dẫn, an trú các vị ấy vào thiện giới; đối với mẹ cha xan tham, khuyến khích, hướng dẫn, an trú các vị ấy vào bố thí; đối với mẹ cha theo ác trí tuệ, khuyến khích, hướng dẫn, an trú các vị ấy vào trí tuệ. Cho đến như vậy, này các Tỷ-kheo, là làm đủ và trả ơn đủ mẹ và cha.`, ref: "Tăng Chi Bộ 2.33", url: "https://loicuaducphat.org/an/an2.33.html#content" },

{ text: `- Có bao nhiêu người, bạch Thế Tôn, đáng được cúng dường ở đời? Và chỗ nào cần phải bố thí cúng dường.\n- Có hai hạng người, này gia chủ, đáng được cúng dường ở đời: Hữu học và vô học. Ðối với hai hạng người này đáng được cúng dường ở đời, này gia chủ, ở đây cần phải bố thí cúng dường.\nThế Tôn thuyết như vậy, Thiện Thệ nói như vậy xong, bậc Ðạo sư lại nói thêm:\n\nHữu học và vô học\nCả hai ở trong đời\nÐều đáng được cúng dường\nÐối với người dâng lễ\nHọ giữ thân chánh trực\nCả lời nói ý nghĩ\nPhước điền người dâng cúng\nÐây thí có quả lớn.`, ref: "Tăng Chi Bộ 2.35", url: "https://loicuaducphat.org/an/an2.35.html#content" },

{ text: `Này Sàriputta, cần phải học tập như sau: “Chúng tôi sẽ có các căn an tịnh, các ý an tịnh”. Này Sàriputta, cần phải học tập như vậy. Với những ai có các căn an tịnh, này Sàriputta, với những ai có các ý an tịnh, thời thân nghiệp cũng sẽ được an tịnh, khẩu nghiệp được an tịnh, ý nghiệp được an tịnh. “Chúng ta sẽ đem tặng cho các vị đồng Phạm hạnh một quà tặng an tịnh”. Như vậy, này Sàriputta, các Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 2.36", url: "https://loicuaducphat.org/an/an2.36.html#content" },

{ text: `- Do nhân gì, thưa Tôn giả Kaccàna, do duyên gì các người Sát-đế-lỵ tranh chấp với các người Sát-đế-lỵ, các người Bà-la-môn tranh chấp với các người Bà-la-môn, các người gia chủ tranh chấp với các người gia chủ?\n- Do nhân thiên chấp, bị trói buộc, bị đắm say, bị xâm chiếm, bị đắm trước bởi các dục tham, này Bà-la-môn, nên các quý tộc tranh chấp với các quý tộc, các người Bà-la-môn tranh chấp với các người Bà La môn, các người gia chủ tranh chấp với các người gia chủ.`, ref: "Tăng Chi Bộ 2.37", url: "https://loicuaducphat.org/an/an2.37.html#content" },

{ text: `- Do nhân gì, thưa Tôn giả Kaccàna, do duyên gì các Sa-môn tranh chấp với các Sa-môn?\n- Do nhân thiên chấp, bị trói buộc, bị đắm say, bị xâm chiếm, bị đắm trước bởi các kiến chấp, này Bà-la-môn, nên các Sa-môn tranh chấp với các Sa-môn.`, ref: "Tăng Chi Bộ 2.37", url: "https://loicuaducphat.org/an/an2.37.html#content" },

{ text: `Vị trưởng lão, này Bà-la-môn, 80 tuổi hay 90 tuổi, hay 100 tuổi đời, nếu vị ấy thọ hưởng các dục vọng, sống giữa các dục vọng, bị đốt cháy bởi lửa nhiệt não của dục vọng, bị nhai nghiến bởi các tầm tư dục vọng, cố gắng tìm cầu các dục vọng; người như vậy được gọi là kẻ ngu, không phải là bậc trưởng lão. Dầu cho này Bà-la-môn, một người còn trẻ, một thanh niên trẻ trung với tóc đen nhánh, đầy đủ tuổi trẻ hiền thiện trong thời sơ khởi của tuổi đời, mà người ấy không hưởng thọ các dục vọng, không sống giữa các dục vọng, không bị đốt cháy bởi lửa nhiệt não của dục vọng, không bị nhai nghiến bởi các tầm tư dục vọng, không có cố gắng tìm cầu các dục vọng; người như vậy được gọi là bậc có trí, bậc trưởng lão.`, ref: "Tăng Chi Bộ 2.38", url: "https://loicuaducphat.org/an/an2.38.html#content" },

{ text: `Này các Tỷ-kheo, khi các ác Tỷ-kheo cường mạnh, trong khi ấy, các thuần tịnh Tỷ-kheo yếu đuối. Trong khi ấy, này các Tỷ-kheo, các Tỷ-kheo thuần tịnh giữ thái độ im lặng, hoặc ẩn mình giữa chúng Tỷ-kheo, hoặc đi đến các quốc độ biên địa. Và như vậy, này các Tỷ-kheo, là bất hạnh cho đa số, là không an lạc cho đa số, là không lợi ích cho đa số, là bất hạnh, đau khổ cho chư Thiên và loài Người.`, ref: "Tăng Chi Bộ 2.39", url: "https://loicuaducphat.org/an/an2.39.html#content" },

{ text: `Những Tỷ-kheo nào, này các Tỷ-kheo, chặn đứng cả văn và nghĩa, bằng cách nắm giữ sai lạc các kinh điển và những văn tự thích ứng, thì những Tỷ-kheo ấy, này các Tỷ-kheo, chịu trách nhiệm về bất hạnh cho đa số, không an lạc cho đa số, không lợi ích cho đa số, bất hạnh, đau khổ cho chư Thiên và loài Người. Ngoài ra, các Tỷ-kheo ấy, này các Tỷ-kheo, chất chứa nhiều vô phước làm cho diệu pháp biến mất.`, ref: "Tăng Chi Bộ 2.41", url: "https://loicuaducphat.org/an/an2.41.html#content" },

{ text: `Những Tỷ-kheo nào, này các Tỷ-kheo, tùy thuận cả văn và nghĩa, bằng cách nắm giữ đúng đắn các kinh điển và những văn tự thích ứng, thì những Tỷ-kheo ấy, này các Tỷ-kheo, chịu trách nhiệm về hạnh phúc cho đa số, an lạc cho đa số, lợi ích cho đa số, hạnh phúc, và an lạc cho chư Thiên và loài Người. Ngoài ra, các Tỷ-kheo ấy, này các Tỷ-kheo, chất chứa nhiều phước đức, làm cho diệu pháp an trú.`, ref: "Tăng Chi Bộ 2.41", url: "https://loicuaducphat.org/an/an2.41.html#content" },

{ text: `Có hai loại hội chúng này, này các Tỷ-kheo. Thế nào là hai? Hội chúng nông nổi và hội chúng thâm sâu. Này các Tỷ-kheo, thế nào là hội chúng nông nổi? Ở đây, này các Tỷ-kheo, tại hội chúng nào có các Tỷ-kheo tháo động, kiêu căng, lắm mồm lắm miệng, lắm lời, thất niệm, không tỉnh giác, không định tĩnh, tâm tán loạn, các căn thả lỏng. Này các Tỷ-kheo, đây gọi là hội chúng nông nổi. Này các Tỷ-kheo, thế nào là hội chúng thâm sâu? Ở đây, này các Tỷ-kheo, tại hội chúng nào có các Tỷ-kheo, không tháo động, không kiêu căng, không dao động, không lắm mồm lắm miệng, không lắm lời, không thất niệm, tỉnh giác, có định tĩnh, có nhất tâm, có các căn được bảo vệ. Này các Tỷ-kheo, đây gọi là hội chúng thâm sâu.`, ref: "Tăng Chi Bộ 2.42", url: "https://loicuaducphat.org/an/an2.42.html#content" },

{ text: `Có hai loại hội chúng này, này các Tỷ-kheo. Thế nào là hai? Hội chúng bất hòa và hội chúng hòa hợp. Và này các Tỷ-kheo, thế nào là hội chúng bất hòa? Ở đây, này các Tỷ-kheo, tại hội chúng nào, các Tỷ-kheo sống cạnh tranh, luận tranh, đấu tranh, đả thương nhau bằng binh khí miệng lưỡi, này các Tỷ-kheo, đây gọi là hội chúng bất hòa. Và này các Tỷ-kheo, thế nào là hội chúng hòa hợp? Ở đây, này các Tỷ-kheo, tại hội chúng nào, các Tỷ-kheo hòa hợp, hòa kính, không có đấu tranh, hòa hợp như sữa với nước, sống nhìn nhau với cặp mắt từ ái, này các Tỷ-kheo, đây gọi là hội chúng hòa hợp.`, ref: "Tăng Chi Bộ 2.43", url: "https://loicuaducphat.org/an/an2.43.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, tại hội chúng nào, các trưởng lão Tỷ-kheo sống trong sự đầy đủ, lười biếng, dẫn đầu về đọa lạc, bỏ rơi gánh nặng sống viễn ly, không có gia sức tinh tấn để đạt đến những gì chưa đạt, để chứng được những gì chưa chứng, để ngộ được những gì chưa ngộ. Còn lớp hậu nhân, tùy thuận hậu kiến của họ, sống trong sự đầy đủ, biếng nhác, dẫn đầu về đọa lạc, bỏ rơi gánh nặng sống viễn ly, không có gia sức tinh tấn để đạt được những gì chưa đạt, để chứng được những gì chưa chứng, để ngộ được những gì chưa ngộ. Này các Tỷ-kheo, đây gọi là hội chúng không thù thắng.`, ref: "Tăng Chi Bộ 2.44", url: "https://loicuaducphat.org/an/an2.44.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, tại hội chúng nào, các trưởng lão Tỷ-kheo không sống trong sự đầy đủ, không lười biếng, từ bỏ gánh nặng đọa lạc, dẫn đầu trong đời sống viễn ly, có gia sức tinh tấn để đạt đến những gì chưa đạt, để chứng được những gì chưa chứng, để ngộ được những gì chưa ngộ. Còn lớp hậu nhân, tùy thuận hậu kiến của họ, không sống trong sự đầy đủ, không biếng nhác, từ bỏ gánh nặng đọa lạc, dẫn đầu trong đời sống viễn ly, có gia sức tinh tấn để đạt được những gì chưa đạt, để chứng được những gì chưa chứng, để ngộ được những gì chưa ngộ. Này các Tỷ-kheo, đây gọi là hội chúng thù thắng.`, ref: "Tăng Chi Bộ 2.44", url: "https://loicuaducphat.org/an/an2.44.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, tại hội chúng nào, các Tỷ-kheo đối với các kinh điển do Như Lai tuyên thuyết, thâm sâu, ý nghĩa sâu kín, siêu thế, liên hệ đến không, khi các kinh điển ấy được thuyết giảng, họ không khéo nghe, không lóng tai, không an trú tâm để hiểu biết chúng, không nghĩ rằng các pháp ấy cần phải lãnh thọ, cần phải học thuộc lòng. Nhưng đối với các kinh điển thi văn do thi sĩ làm ra, với các nguyên âm hoa mỹ, với các phụ âm hoa mỹ, các kinh thuộc ngoại giáo, được các đệ tử ngoại giáo nói lên, khi các kinh điển ấy được thuyết giảng, họ khéo nghe, họ lóng tai, họ an trú tâm để hiểu biết chúng, họ nghĩ rằng các pháp ấy cần phải lãnh thọ, cần phải học thuộc lòng. Này các Tỷ-kheo, đây gọi là hội chúng được huấn luyện trong khoa trương, không được huấn luyện trong chất vấn.`, ref: "Tăng Chi Bộ 2.45", url: "https://loicuaducphat.org/an/an2.45.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, tại hội chúng nào, các Tỷ-kheo đối với các kinh điển do Như Lai tuyên thuyết, thâm sâu, ý nghĩa sâu kín, siêu thế, liên hệ đến không, khi các kinh điển ấy được thuyết giảng, họ khéo nghe, lóng tai, họ an trú tâm để hiểu biết chúng, họ nghĩ rằng các pháp ấy cần phải lãnh thọ, cần phải học thuộc lòng. Và sau khi học thuộc lòng các pháp ấy, họ hỏi đi hỏi lại cùng nhau, họ mở rộng ra để thảo luận với những câu hỏi như sau : “Cái này là gì? Thế nào là ý nghĩa của cái này?” Họ mở rộng những gì được che kín, họ phơi bày những gì không được phơi bày, họ giải nghi về các điểm nghi vấn trong Chánh pháp. Này các Tỷ-kheo, đây gọi là hội chúng được huấn luyện trong chất vấn, không được huấn luyện trong khoa trương.`, ref: "Tăng Chi Bộ 2.45", url: "https://loicuaducphat.org/an/an2.45.html#content" },
{ text: `Có hai loại lạc này, này các Tỷ-kheo. Thế nào là hai? Lạc tại gia và lạc xuất gia. Những pháp này, này các Tỷ-kheo, là hai lạc. Tối thắng trong hai lạc này, này các Tỷ-kheo, tức là lạc xuất gia.`, ref: "Tăng Chi Bộ 2.64", url: "https://loicuaducphat.org/an/an2.64.html#content" },

{ text: `Có hai loại lạc này, này các Tỷ-kheo. Thế nào là hai? Dục lạc và viễn ly lạc. Những pháp này, này các Tỷ-kheo, là hai lạc. Tối thắng trong hai lạc này, này các Tỷ-kheo, tức là viễn ly lạc.`, ref: "Tăng Chi Bộ 2.65", url: "https://loicuaducphat.org/an/an2.65.html#content" },
{ text: `Này các Tỷ-kheo, thế nào là hạng người có hy vọng? Ở đây, này các Tỷ-kheo, một Tỷ-kheo giữ tánh tình hiền thiện. Vị ấy nghe: “Tỷ-kheo có tên như vậy, đã đoạn tận các lậu hoặc ngay trong hiện tại, tự mình với thắng trí, chứng ngộ, chứng đạt và an trú vô lậu tâm giải thoát, tuệ giải thoát”. Người ấy suy nghĩ như sau: “Ðến khi nào, do đoạn tận các lậu hoặc ngay trong hiện tại, tự mình với thắng trí, ta sẽ chứng đạt, chứng ngộ và an trú vô lậu tâm giải thoát, tuệ giải thoát?” Người như vậy, này các Tỷ-kheo, được gọi là người có hy vọng.`, ref: "Tăng Chi Bộ 3.13", url: "https://loicuaducphat.org/an/an3.13.html#content" },

{ text: `Có ba pháp này, này các Tỷ-kheo, đưa đến hại mình, đưa đến hại người, đưa đến hại cả hai. Thế nào là ba? Thân làm ác, miệng nói ác, ý nghĩ ác. Ba pháp này, này các Tỷ-kheo, đưa đến hại mình, đưa đến hại người, đưa đến hại cả hai.`, ref: "Tăng Chi Bộ 3.17", url: "https://loicuaducphat.org/an/an3.17.html#content" },

{ text: `Có ba pháp này, này các Tỷ-kheo, không đưa đến hại mình, không đưa đến hại người, không đưa đến hại cả hai. Thế nào là ba? Thân làm thiện, miệng nói thiện, ý nghĩ thiện. Có ba pháp này, này các Tỷ-kheo, không đưa đến hại mình, không đưa đến hại người, không đưa đến hại cả hai.`, ref: "Tăng Chi Bộ 3.17", url: "https://loicuaducphat.org/an/an3.17.html#content" },

{ text: `Này các Tỷ-kheo, thành tựu ba pháp, Tỷ kheo thâu nhận được thiện pháp chưa được thâu nhận, tăng trưởng thiện pháp đã được thâu nhận. Thế nào là ba? Ở đây, này các Tỷ-kheo, Tỷ kheo vào buổi sáng có nhiệt tâm chăm chú vào định tướng, vào buổi trưa có nhiệt tâm chăm chú vào định tướng, vào buổi chiều có nhiệt tâm chăm chú vào định tướng. Thành tựu với ba pháp này, này các Tỷ-kheo, một Tỷ-kheo thâu nhận được thiện pháp chưa được thâu nhận, và tăng trưởng thiện pháp đã được thâu nhận.`, ref: "Tăng Chi Bộ 3.19", url: "https://loicuaducphat.org/an/an3.19.html#content" },

{ text: `Và như thế nào, này các Tỷ-kheo, là Tỷ-kheo khéo phấn đấu? Ở đây, này các Tỷ-kheo, Tỷ-kheo sống tinh cần tinh tấn, đoạn tận các pháp bất thiện, làm cho sanh khởi các pháp thiện, dõng mãnh, kiên trì, tinh tấn, không có từ bỏ gánh nặng đối với các thiện pháp. Như vậy, này các Tỷ-kheo, là Tỷ-kheo khéo phấn đấu.`, ref: "Tăng Chi Bộ 3.20", url: "https://loicuaducphat.org/an/an3.20.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Tỷ-kheo xây dựng được căn bản? Ở đây, này các Tỷ-kheo, Tỷ-kheo đối với các Tỷ-kheo nghe nhiều, thông hiểu các tập Agàma (A-hàm), bậc trì Pháp, trì Luật, trì Toát yếu, thường thường đến yết kiến, phỏng vấn, đặt các câu hỏi: “Thưa Tôn giả, cái này là thế nào? Pháp này ý nghĩa gì? “Các Tôn giả ấy mở rộng những gì chưa được mở rộng, phơi bày những gì chưa được phơi bày, và đối với những đoạn sai khác còn có những chỗ nghi ngờ, các vị ấy giải thích các sự nghi ngờ. Như vậy, này các Tỷ-kheo, là Tỷ-kheo xây dựng được căn bản.`, ref: "Tăng Chi Bộ 3.20", url: "https://loicuaducphat.org/an/an3.20.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người chất chứa các thân hành có não hại, chất chứa các khẩu hành có não hại, chất chứa các ý hành có não hại. Sau khi chất chứa thân hành có não hại, chất chứa khẩu hành có não hại, chất chứa ý hành có não hại, người ấy sanh trong thế giới có não hại. Vì phải sanh trong thế giới có não hại, người ấy cảm giác các cảm xúc có não hại. Người ấy, vì cảm giác các cảm xúc có não hại, nên cảm giác các cảm thọ có não hại, nhất hướng đau khổ, như các chúng sanh ở trong địa ngục.`, ref: "Tăng Chi Bộ 3.24", url: "https://loicuaducphat.org/an/an3.24.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là hạng người với tâm ví dụ như vết thương? Ở đây, này các Tỷ-kheo, có người phẫn nộ, nhiều hiềm hận, dầu có bị nói chút ít, cũng tức tối phẫn nộ, sân hận, sừng sộ, biểu lộ sự phẫn nộ, sân hận và bực tức. Ví như một vết thương đang làm mủ, nếu bị cây gậy hay một miếng sành đánh phải, liền chảy mủ nhiều hơn. Cũng vậy, này các Tỷ-kheo, ở đây có người phẫn nộ và bực tức. Này các Tỷ kheo, đây gọi là hạng người được ví dụ với vết thương đang làm mủ.`, ref: "Tăng Chi Bộ 3.25", url: "https://loicuaducphat.org/an/an3.25.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người thấp kém về giới, định, tuệ. Hạng người như vậy, này các Tỷ-kheo, không nên gần gũi, không nên sống chung, không nên hầu hạ cúng dường, trừ khi vì lòng thương tưởng, vì lòng từ mẫn.`, ref: "Tăng Chi Bộ 3.26", url: "https://loicuaducphat.org/an/an3.26.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người đồng đẳng với mình về giới, định, tuệ. Hạng người như vậy, này các Tỷ-kheo, nên gần gũi, nên sống chung, nên hầu hạ cúng dường. Vì cớ sao? Với ý nghĩ: “(Cả hai) thiện xảo về giới, câu chuyện của chúng ta sẽ thuộc về giới, được diễn tiến (lợi ích) cho cả hai chúng ta, và sẽ làm cho hai chúng ta được an lạc. (Cả hai) là thiện xảo về định ...... (Cả hai) là thiện xảo về tuệ, câu chuyện của chúng ta sẽ thuộc về tuệ, được diễn tiến (lợi ích) cho cả hai, và chúng sẽ làm cho hai chúng ta an lạc”. Cho nên, người như vậy nên gần gũi, nên sống chung, nên hầu hạ cúng dường.`, ref: "Tăng Chi Bộ 3.26", url: "https://loicuaducphat.org/an/an3.26.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người thù thắng về giới, định và tuệ. Hạng người ấy, này các Tỷ-kheo, sau khi cung kính, tôn trọng, cần phải gần gũi, cần phải sống chung, cần phải hầu hạ cúng dường. Vì cớ sao? Với ý nghĩ: “Như vậy, nếu giới chưa đầy đủ, ta sẽ làm đầy đủ, hay nếu giới được đầy đủ, ta sẽ hỗ trợ thêm cho chỗ này chỗ kia với trí tuệ. Hay nếu định chưa đầy đủ, ta sẽ làm cho đầy đủ, hay nếu định được đầy đủ, ta sẽ hỗ trợ thêm cho chỗ này chỗ kia với trí tuệ. Hay nếu tuệ chưa đầy đủ, ta sẽ làm đầy đủ, hay nếu tuệ được đầy đủ, ta sẽ hỗ trợ thêm cho chỗ này chỗ kia với trí tuệ”. Cho nên, với hạng người này, sau khi cung kính tôn trọng, nên gần gũi, nên sống chung, nên hầu hạ cúng dường.`, ref: "Tăng Chi Bộ 3.26", url: "https://loicuaducphat.org/an/an3.26.html#content" },

{ text: `Người gần kẻ hạ liệt,\nRồi cũng bị hạ liệt;\nThân cận người đồng đẳng,\nÐược khỏi bị thối đọa;\nAi gần bậc thù thắng,\nMau chóng được thăng tiến;\nDo vậy hãy sống chung,\nBậc ưu thắng hơn mình.`, ref: "Tăng Chi Bộ 3.26", url: "https://loicuaducphat.org/an/an3.26.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người giữ giới, tánh tình hiền thiện. Người như vậy, này các Tỷ-kheo, cần phải gần gũi, cần phải sống chung, cần phải hầu hạ cúng dường. Vì cớ sao? Vì rằng, dầu không thuận theo chút nào tri kiến của người như vậy, nhưng tiếng tốt được đồn xa về người ấy là có bạn lành, là có bằng hữu lành, là tôn sùng kẻ lành. Cho nên, hạng người như vậy, cần phải gần gũi, cần phải sống chung, cần phải hầu hạ cúng dường.`, ref: "Tăng Chi Bộ 3.27", url: "https://loicuaducphat.org/an/an3.27.html#content" },


{ text: `Và này các Tỷ-kheo, thế nào là hạng người nói như phân? Ở đây, này các Tỷ-kheo, có hạng người khi đi vào hội trường, hay đi vào hội chúng, hay khi đi đến giữa các người bà con, hay khi đi đến giữa các người đồng một tổ hợp, hay đi đến giữa cung vua, hay bị dẫn như là người làm chứng, được nói: “Ngươi biết gì, hãy nói lên”. Người ấy không biết, nói rằng: “Tôi có biết”; có biết, nói rằng: “Tôi không biết”; không thấy, nói rằng: “Tôi có thấy”; có thấy, nói rằng: “Tôi không thấy”. Do vì mình hay vì người, hay vì một vài lợi vật nhỏ, mà đã cố ý nói láo. Người như vậy, này các Tỷ-kheo, được gọi là người nói như phân.`, ref: "Tăng Chi Bộ 3.27", url: "https://loicuaducphat.org/an/an3.27.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là hạng người nói như hoa? Ở đây, này các Tỷ-kheo, có người khi đi vào hội trường, hay khi đi vào hội chúng, hay khi đi đến giữa các người bà con, hay khi đi đến giữa các người đồng một tổ hợp, hay đi đến cung vua, hay bị dẫn như là người làm chứng, được nói: “Ngươi biết gì, hãy nói lên”. Người ấy không biết, nói rằng: “Tôi không biết”; có biết, nói rằng: “Tôi có biết”; không thấy, nói rằng: “Tôi không thấy”; có thấy, nói rằng: “Tôi có thấy”. Không vì mình hay vì người, hay vì một vài lợi vật nhỏ mà đã cố ý nói láo. Người như vậy, này các Tỷ-kheo, được gọi là người nói như hoa.`, ref: "Tăng Chi Bộ 3.27", url: "https://loicuaducphat.org/an/an3.27.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là hạng người nói như mật? Ở đây, này các Tỷ-kheo, có người đoạn tận ác ngữ, từ bỏ lời nói ác ngữ. Lời nói của người ấy không hại, tai ưa nghe, khả ái, đi thẳng đến tâm, lễ độ, được nhiều người ưa thích, được nhiều người thích ý, người ấy nói những lời như vậy. Này các Tỷ-kheo, đây gọi là hạng người nói như mật.`, ref: "Tăng Chi Bộ 3.27", url: "https://loicuaducphat.org/an/an3.27.html#content" },



{ text: `Và này các Tỷ-kheo, thế nào là người với trí tuệ lộn ngược? Ở đây, này các Tỷ-kheo, có hạng người đi đến khu vườn (tinh xá) thường thường nghe pháp từ các Tỷ-kheo, các vị Tỷ-kheo thuyết pháp cho người ấy, sơ thiện, trung thiện, hậu thiện, có nghĩa, có văn, trình bày Phạm hạnh hoàn toàn viên mãn thanh tịnh. Người ấy, tại chỗ ngồi ấy, đối với bài thuyết giảng ấy, không có tác ý đến đoạn đầu, không có tác ý đến đoạn giữa, không có tác ý đến đoạn cuối. Cũng vậy, khi người ấy từ chỗ ngồi ấy đứng lên, đối với bài thuyết giảng ấy, người ấy không có tác ý đến đoạn đầu, không có tác ý đến đoạn giữa, không có tác ý đến đoạn cuối. Ví như này các Tỷ-kheo, một cái ghè bị lộn ngược, nước chứa trong ấy tuôn chảy, không có dừng lại. Cũng vậy, này các Tỷ-kheo, ở đây, có hạng người đi đến khu vườn ... không có tác ý đoạn cuối. Cũng vậy, khi người ấy từ chỗ ngồi ấy đứng lên ... không có tác ý đoạn cuối. Này các Tỷ-kheo, đây gọi là hạng người với trí tuệ lộn ngược.`, ref: "Tăng Chi Bộ 3.30", url: "https://loicuaducphat.org/an/an3.30.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là hạng người có trí tuệ rộng lớn? Ở đây, này các Tỷ-kheo, có hạng người đi đến khu vườn (tinh xá) thường thường nghe pháp từ các Tỷ-kheo, các vị Tỷ-kheo thuyết pháp cho người ấy, sơ thiện, trung thiện, hậu thiện, có nghĩa, có văn, trình bày Phạm hạnh hoàn toàn viên mãn thanh tịnh. Người ấy, tại chỗ ngồi ấy, đối với bài thuyết giảng ấy, có tác ý đến đoạn đầu, có tác ý đến đoạn giữa, có tác ý đến đoạn cuối. Cũng vậy, khi người ấy từ chỗ ngồi ấy đứng lên, đối với bài thuyết giảng ấy, người ấy có tác ý đến đoạn đầu, có tác ý đến đoạn giữa, có tác ý đến đoạn cuối. Ví như này các Tỷ-kheo, một cái ghè bị lộn ngược, nước chứa trong ấy tuôn chảy, có dừng lại. Cũng vậy, này các Tỷ-kheo, ở đây, có hạng người đi đến khu vườn ... có tác ý đoạn cuối.  Cũng vậy, khi vị ấy, từ chỗ ngồi ấy đứng lên, đối với bài thuyết giảng ấy, có tác ý đến đoạn đầu ... có tác ý đến đoạn cuối. Này các Tỷ-kheo, đây gọi là hạng người có trí tuệ rộng lớn.`, ref: "Tăng Chi Bộ 3.30", url: "https://loicuaducphat.org/an/an3.30.html#content" },

{ text: `Bậc trí tuệ rộng lớn\nÐược gọi tốt hơn cả\nHọ thường thường đi đến\nÐến gần các Tỷ-kheo\nÐoạn đầu của bài giảng\nÐoạn giữa và đoạn cuối\nNgồi trên chỗ mình ngồi\nNắm giữ được lời văn\nThọ trì điều được nghe\nSuy tư điều tối thắng\nVới ý không dao động\nLà hạng người như vậy\nThực hành pháp, tùy pháp\nCó thể đoạn khổ đau.`, ref: "Tăng Chi Bộ 3.30", url: "https://loicuaducphat.org/an/an3.30.html#content" },

{ text: `Những gia đình nào, này các Tỷ-kheo, trong ấy, các con cái kính lễ mẹ cha ở trong nhà, những gia đình ấy được chấp nhận ngang bằng với Phạm Thiên. Những gia đình nào, này các Tỷ-kheo, trong ấy, các con cái kính lễ mẹ cha ở trong nhà, những gia đình ấy được chấp nhận như các Ðạo sư thời xưa. Những gia đình nào, này các Tỷ-kheo, trong ấy, các con cái kính lễ mẹ cha ở trong nhà, những gia đình ấy được chấp nhận là đáng được cúng dường.`, ref: "Tăng Chi Bộ 3.31", url: "https://loicuaducphat.org/an/an3.31.html#content" },

{ text: `Phạm Thiên, này các Tỷ-kheo, là đồng nghĩa với cha mẹ. Các Ðạo sư thời xưa, này các Tỷ-kheo, là đồng nghĩa với cha mẹ. Ðáng được cúng dường, này các Tỷ-kheo, là đồng nghĩa với cha mẹ. Vì cớ sao? Giúp đỡ rất nhiều, này các Tỷ-kheo, là cha mẹ đối với con cái, nuôi chúng lớn, dưỡng dục chúng, giới thiệu chúng vào đời.`, ref: "Tăng Chi Bộ 3.31", url: "https://loicuaducphat.org/an/an3.31.html#content" },

{ text: `Ở đây, này Ananda, vị Tỷ-kheo suy nghĩ như sau: “Ðây là an tịnh, đây là thù diệu, tức là chỉ tức tất cả hành, từ bỏ tất cả sanh y, đoạn tận tham, ly tham, đoạn diệt, Niết-bàn”. Như vậy, này Ananda, rất có thể Tỷ-kheo được định như vậy, trong cái thân có thức này, không có ngã kiến, ngã sở kiến, ngã mạn tuỳ miên; đối với tất cả tướng ở ngoài, không có ngã kiến, ngã sở kiến, ngã mạn tuỳ miên; và do chứng đạt và an trú tâm giải thoát, tuệ giải thoát, không có ngã kiến, ngã sở kiến, ngã mạn tuỳ miên; vị ấy có thể chứng đạt và an trú tâm giải thoát, tuệ giải thoát.`, ref: "Tăng Chi Bộ 3.32", url: "https://loicuaducphat.org/an/an3.32.html#content" },
{ text: `Ngồi xuống một bên, Hatthaka người Alavì bạch Thế Tôn: - Bạch Thế Tôn, Thế Tôn sống có an lạc không?\n- Phải, này Hoàng Tử, ta sống được an lạc. Và những ai cảm thấy an lạc ở đời, Ta là một trong số những người ấy.\n- Bạch Thế Tôn, lạnh là đêm mùa đông, thời gian giữa những ngày tám là thời gian tuyết rơi, cứng rắn là đất do trâu bò dẫm đạp, mỏng manh là nệm làm bằng lá, lưa thưa là những lá của cây, lạnh là tấm vải cà sa, và lạnh là làn gió thổi.\nRồi Thế Tôn nói như sau: - Dẫu vậy, này Hoàng Tử, Ta sống được an lạc. Và những ai cảm thấy an lạc ở đời, Ta là một trong số những người ấy.`, ref: "Tăng Chi Bộ 3.35", url: "https://loicuaducphat.org/an/an3.35.html#content" },

{ text: `- Hoàng Tử nghĩ thế nào, này Hoàng tử, với người gia chủ hay người con của người gia chủ ấy, khởi lên những nhiệt não về thân hay về tâm, do tham ái sanh. Bị nung đốt bởi những nhiệt não do tham ái sanh, người ấy có cảm thấy đau khổ không?\n- Thưa có, bạch Thế Tôn.\n- Người gia chủ hay con của người gia chủ ấy, này Hoàng Tử, bị nung đốt bởi những nhiệt não do tham ái sanh, cảm thấy đau khổ. Tham ái ấy, Như Lai đã đoạn tận, cắt đứt từ gốc rễ, làm cho như thân cây tala, làm cho không thể hiện hữu, làm cho không thể sanh khởi trong tương lai. Do vậy ta cảm thấy an lạc.`, ref: "Tăng Chi Bộ 3.35", url: "https://loicuaducphat.org/an/an3.35.html#content" },

{ text: `Luôn luôn được an lạc,\nVi phạm chí tịch tịnh\nKhông bị dục uế nhiễm\nTrong mát, không sanh y,\nMọi tham trước dứt đoạn,\nNhiếp phục tâm sầu khổ,\nAn tịnh, cảm thọ lạc\nVới tâm đạt an tịnh.`, ref: "Tăng Chi Bộ 3.35", url: "https://loicuaducphat.org/an/an3.35.html#content" },
{ text: `Với Ta, này các Tỷ-kheo, được đầy đủ với sự giàu sang như vậy, được cứu cánh nuôi dưỡng tế nhị như vậy, ta suy nghĩ rằng: “Kẻ vô văn phàm phu tự mình bị già, không vượt qua khỏi già, khi thấy người khác bị già, lại bực phiền, hổ thẹn, ghê tởm, quên rằng mình cũng như vậy. Ta cũng bị già, không vượt qua khỏi già, sau khi thấy người khác già, ta có thể bực phiền, hổ thẹn, ghê tởm sao? Như vậy, thật không xứng đáng cho ta”. Sau khi quan sát về ta như vậy, này các Tỷ-kheo, sự kiêu mạn của tuổi trẻ trong tuổi trẻ được đoạn trừ hoàn toàn.`, ref: "Tăng Chi Bộ 3.39", url: "https://loicuaducphat.org/an/an3.39.html#content" },

{ text: `Với Ta, này các Tỷ-kheo, được đầy đủ với sự giàu sang như vậy, được cứu cánh nuôi dưỡng tế nhị như vậy, ta suy nghĩ rằng: “Kẻ vô văn phàm phu tự mình bị bệnh, không vượt khỏi bệnh, thấy người khác bị bệnh, lại bực phiền, hổ thẹn, ghê tởm, quên rằng mình cũng như vậy. Ta cũng bị bệnh, không vượt qua khỏi bệnh, sau khi thấy người khác bị bệnh, ta có thể bực phiền, hổ thẹn, ghê tởm sao? Như vậy, thật không xứng đáng cho ta”. Sau khi quan sát về ta như vậy, này các Tỷ-kheo, sự kiêu mạn của không bệnh trong không bệnh được đoạn trừ hoàn toàn.`, ref: "Tăng Chi Bộ 3.39", url: "https://loicuaducphat.org/an/an3.39.html#content" },

{ text: `Với Ta, này các Tỷ-kheo, được đầy đủ với sự giàu sang như vậy, được cứu cánh nuôi dưỡng tế nhị như vậy, ta suy nghĩ rằng: “Kẻ vô văn phàm phu tự mình bị chết, không vượt khỏi chết, thấy người khác bị chết, lại bực phiền, hổ thẹn, ghê tởm, quên rằng mình cũng như vậy. Ta cũng bị chết, không vượt qua khỏi chết, sau khi thấy người khác chết, ta có thể bực phiền, hổ thẹn, ghê tởm sao? Như vậy, thật không xứng đáng cho ta”. Sau khi quan sát về ta như vậy, này các Tỷ-kheo, sự kiêu mạn của sự sống trong sự sống được đoạn trừ hoàn toàn.`, ref: "Tăng Chi Bộ 3.39", url: "https://loicuaducphat.org/an/an3.39.html#content" },
{ text: `Có ba kiêu mạn này, này các Tỷ-kheo, Thế nào là ba? Kiêu mạn của tuổi trẻ, Kiêu mạn của không bệnh, Kiêu mạn của sự sống.`, ref: "Tăng Chi Bộ 3.39", url: "https://loicuaducphat.org/an/an3.39.html#content" },

{ text: `Say sưa trong Kiêu mạn của tuổi trẻ, này các Tỷ-kheo, kẻ vô văn phàm phu làm các ác hành về thân, làm các ác hành về lời nói, làm các ác hành về ý. Do làm các ác hành về thân, làm các ác hành về lời nói, làm các ác hành về ý, sau khi thân hoại mạng chung, bị sanh vào cõi dữ, ác thú, đọa xứ, địa ngục.`, ref: "Tăng Chi Bộ 3.39", url: "https://loicuaducphat.org/an/an3.39.html#content" },

{ text: `Say sưa trong Kiêu mạn của sự sống, này các Tỷ-kheo, kẻ vô văn phàm phu làm các ác hành về thân, làm các ác hành về lời nói, làm các ác hành về ý. Do làm các ác hành về thân, làm các ác hành về lời nói, làm các ác hành về ý, sau khi thân hoại mạng chung, bị sanh vào cõi dữ, ác thú, đọa xứ, địa ngục.`, ref: "Tăng Chi Bộ 3.39", url: "https://loicuaducphat.org/an/an3.39.html#content" },

{ text: `Say sưa trong Kiêu mạn của tuổi trẻ, này các Tỷ-kheo, vị Tỷ-kheo từ bỏ học pháp, trở lui lại đời sống thế tục. Say sưa trong kiêu mạn của không bệnh, này các Tỷ-kheo, vị Tỷ-kheo từ bỏ học pháp, trở lui lại đời sống thế tục. Say sưa trong kiêu mạn của đời sống, này các Tỷ-kheo, vị Tỷ-kheo từ bỏ học pháp, trở lui lại đời sống thế tục.`, ref: "Tăng Chi Bộ 3.39", url: "https://loicuaducphat.org/an/an3.39.html#content" },
{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo đi đến ngôi rừng, hay đi đến gốc cây, hay đi đến ngôi nhà trống, quan sát như sau: “Không phải vì y áo, ta xuất gia từ bỏ gia đình, sống không gia đình. Không phải vì món ăn khất thực, không phải vì sàng tọa, không phải vì nhân có mặt hay không có mặt ở đây mà ta xuất gia từ bỏ gia đình, sống không gia đình, (nhưng với ý nghĩ như sau): “Nay ta bị rơi vào sanh, già, chết, sầu, bi, khổ, ưu, não, rơi vào khổ, bị khổ chi phối. Có thể do làm như vậy, sự đoạn tận tất cả khổ uẩn này được hiện khởi lên (cho ta). Và ta đã xuất gia từ bỏ gia đình, sống không gia đình, sau khi đã đoạn tận tất cả các dục vọng như vậy, lại còn đeo đuổi các dục vọng như kia hay còn ác tệ hơn. Như vậy, thật không xứng đáng cho ta”.`, ref: "Tăng Chi Bộ 3.40", url: "https://loicuaducphat.org/an/an3.40.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo quan sát như sau: “Thắng tấn là tinh tấn của ta, không có thụ động; an trú là niệm của ta, không có thất niệm; khinh an là thân của ta, không có dao động; định tĩnh là tâm của ta, được nhất tâm”. Vị ấy làm cho tăng thượng tự ngã, từ bỏ bất thiện, tu tập thiện, từ bỏ có tội, tu tập không tội, gìn giữ cho tự ngã được thanh tịnh. Này các Tỷ-kheo, đây gọi là tự ngã tăng thượng.`, ref: "Tăng Chi Bộ 3.40", url: "https://loicuaducphat.org/an/an3.40.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo đi đến ngôi rừng hay đi đến gốc cây, hay đi đến ngôi nhà trống, rồi thẩm sát như sau: “Không phải vì y áo, ta xuất gia từ bỏ gia đình, sống không gia đình. Không phải vì món ăn khất thực, không phải vì sàng tọa, không phải vì nhân có mặt hay không có mặt ở đây mà ta xuất gia từ bỏ gia đình, sống không gia đình, (nhưng với ý nghĩ như sau): “Nay ta bị rơi vào sanh, già, chết, sầu, bi, khổ, ưu, não, rơi vào khổ, bị khổ chi phối. Có thể làm như vậy, đoạn tận của tất cả khổ uẩn này được hiện khởi lên cho ta. Và ta đã xuất gia như vậy, lại có thể suy nghĩ về dục tầm hay có thể suy nghĩ về sân tầm, hay có thể suy nghĩ về hại tầm. Như vậy, thật không xứng đáng cho ta”.`, ref: "Tăng Chi Bộ 3.40", url: "https://loicuaducphat.org/an/an3.40.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo quan sát như sau: “Có các chư Thiên có thần thông, có thiên nhãn, có tha tâm thông. Các vị này có thể thấy từ xa, tuy ở gần nhưng không thấy họ được, và họ có thể biết tâm ta với tâm của họ. Các vị ấy có thể biết về ta như sau: “Hãy xem thiện nam tử này, tuy vì lòng tin xuất gia, từ bỏ gia đình, sống không gia đình, nhưng sống xen lẫn với các pháp ác, bất thiện.”`, ref: "Tăng Chi Bộ 3.40", url: "https://loicuaducphat.org/an/an3.40.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo quan sát như sau: “Pháp được Thế Tôn khéo thuyết, thiết thực hiện tại, có kết quả ngay tức thời, đến để mà thấy, có khả năng hướng thượng, được người có trí tự mình giác hiểu. Nay ta có những người đồng Phạm hạnh, họ sống biết và thấy. Ta đã được xuất gia trong pháp và Luật khéo giảng như vậy, không lẽ ta lại có thể sống biếng nhác phóng dật. Như vậy, thật không xứng đáng cho ta”.`, ref: "Tăng Chi Bộ 3.40", url: "https://loicuaducphat.org/an/an3.40.html#content" },
{ text: `Do sự có mặt của ba pháp, này các Tỷ-kheo, một thiện nam tử có lòng tin tạo ra nhiều phước. Thế nào là ba? Do sự có mặt của lòng tin, này các Tỷ-kheo, một thiện nam tử có lòng tin tạo ra nhiều phước. Do sự có mặt của vật bố thí, này các Tỷ-kheo, một thiện nam tử có lòng tin tạo ra nhiều phước. Do sự có mặt của các vị xứng đáng được cúng dường, này các Tỷ-kheo, một thiện nam tử có lòng tin tạo ra nhiều phước.`, ref: "Tăng Chi Bộ 3.41", url: "https://loicuaducphat.org/an/an3.41.html#content" },
 { text: `Do ba sự kiện, này các Tỷ-kheo, một người được biết là có lòng tin. Thế nào là ba? Ưa thấy người có giới hạnh, ưa nghe diệu pháp, với tâm ly cấu uế của xan tham, sống trong nhà, bố thí rộng rãi với bàn tay sạch sẽ, ưa thích từ bỏ, sẵn sàng để được yêu cầu, thích phân phát vật bố thí. Do ba sự kiện này, này các Tỷ-kheo, một người được biết là có lòng tin.`, ref: "Tăng Chi Bộ 3.42", url: "https://loicuaducphat.org/an/an3.42.html#content" },

{ text: `Ba pháp này, này các Tỷ-kheo, được người Hiền trí tuyên bố, được bậc Chân nhân tuyên bố. Thế nào là ba? Bố thí, này các Tỷ-kheo, được người Hiền trí tuyên bố, được bậc Chân nhân tuyên bố. Xuất gia, này các Tỷ-kheo, được người Hiền trí tuyên bố, được bậc Chân nhân tuyên bố. Hầu hạ cha mẹ, này các Tỷ-kheo, được người Hiền trí tuyên bố, được bậc Chân nhân tuyên bố. Ba pháp này, này các Tỷ-kheo, được người Hiền trí tuyên bố, được bậc Chân nhân tuyên bố.`, ref: "Tăng Chi Bộ 3.45", url: "https://loicuaducphat.org/an/an3.45.html#content" },

{ text: `Gần làng hay thị trấn nào, này các Tỷ-kheo, các bậc xuất gia có giới hạnh trú ở, tại chỗ ấy, các người nhờ ba sự kiện được gặt nhiều công đức. Thế nào là ba? Bởi thân, bởi lời nói, bởi ý.`, ref: "Tăng Chi Bộ 3.46", url: "https://loicuaducphat.org/an/an3.46.html#content" },

{ text: `Khi nào Tỷ-kheo, này các Tỷ-kheo, đối với các pháp ác, bất thiện chưa sanh, nhiệt tình làm mạnh đừng để cho sanh, đối với các pháp thiện chưa sanh, nhiệt tình làm mạnh để cho sanh khởi. Ðể chịu đựng các thân thọ đã sanh, khổ đau, nhói đau, da diết đau, gay gắt đau, không thích thú, không thích ý, đoạt mạng sống, nhiệt tình làm mạnh. Tỷ-kheo ấy, này các Tỷ-kheo, được gọi là vị có nhiệt tình, thận trọng, chánh niệm để chơn chánh đoạn tận khổ đau.`, ref: "Tăng Chi Bộ 3.49", url: "https://loicuaducphat.org/an/an3.49.html#content" },

{ text: `Thật vậy, này các Bà-la-môn, thế giới này đã bị già, bệnh, chết dắt dẫn. Thế giới đã bị già, bệnh, chết dắt dẫn như vậy, này các Bà-la-môn, thời chế ngự thân, chế ngự lời nói, chế ngự ý trong đời này, đối với kẻ đã đi đến cõi chết, phải là chỗ nương tựa, là hang trú ẩn, là hòn cù lao (hay ngọn đèn), là chỗ quy y và là đích xứ đi đến.`, ref: "Tăng Chi Bộ 3.51", url: "https://loicuaducphat.org/an/an3.51.html#content" },

{ text: `Ðời sống bị dắt dẫn\nMạng sống chẳng là bao\nBị già kéo dẫn đi\nKhông có nơi nương tựa\nHãy luôn luôn quán tưởng\nSợ hãi tử vong này\nHãy làm các công đức\nÐưa đến chơn an lạc.\nỞ đây chế ngự thân,\nChế ngự lời và ý,\nKẻ ấy dầu có chết,\nCũng được hưởng an lạc,\nVì khi còn đang sống\nÐã làm các công đức.`, ref: "Tăng Chi Bộ 3.51", url: "https://loicuaducphat.org/an/an3.51.html#content" },


{ text: `Bị tham ái làm say đắm, này Bà-la-môn, bị chinh phục, tâm bị xâm chiếm, nên suy nghĩ điều hại mình, suy nghĩ điều hại người, suy nghĩ điều hại cả hai, cảm thọ tâm khổ tâm ưu. Tham ái được đoạn trừ, thời không nghĩ đến tự hại, không nghĩ đến hại người, không nghĩ đến hại cả hai, không cảm thọ tâm khổ tâm ưu. Như vậy, này Bà-la-môn, pháp là thiết thực hiện tại, không có thời gian, đến để mà thấy, có khả năng hướng thượng, được người trí tự mình giác hiểu.`, ref: "Tăng Chi Bộ 3.53", url: "https://loicuaducphat.org/an/an3.53.html#content" },

{ text: `Bị sân làm uế nhiễm, này Bà-la-môn, bị chinh phục, tâm bị xâm chiếm, nên suy nghĩ điều hại mình, suy nghĩ điều hại người, suy nghĩ điều hại cả hai, cảm thọ tâm khổ tâm ưu. Sân được đoạn trừ, thời không nghĩ đến tự hại, không nghĩ đến hại người, không nghĩ đến hại cả hai, không cảm thọ tâm khổ tâm ưu. Như vậy, này Bà-la-môn, pháp là thiết thực hiện tại, không có thời gian, đến để mà thấy, có khả năng hướng thượng, được người trí tự mình giác hiểu.`, ref: "Tăng Chi Bộ 3.53", url: "https://loicuaducphat.org/an/an3.53.html#content" },

{ text: `Thật vi diệu thay, Tôn giả Gotama! Thật vi diệu thay, Tôn giả Gotama! Như người dựng đứng những gì bị quăng ngã xuống, hay trình bày cái gì bị che kín, hay chỉ đường cho người bị lạc hướng, hay cầm đèn sáng vào bóng tối để những ai có mắt có thể thấy sắc. Cũng vậy, Chánh pháp đã được Tôn giả Gotama dùng nhiều phương tiện thuyết giảng. Con nay xin quy y Tôn giả Gotama, quy y Pháp, quy y Tăng. Mong Tôn giả Gotama nhận con làm đệ tử cư sĩ, từ nay cho đến mạng chung, con trọn đời quy ngưỡng.`, ref: "Tăng Chi Bộ 3.53", url: "https://loicuaducphat.org/an/an3.53.html#content" },

{ text: `Ngày nay, này Bà-la-môn, loài người bị tham ái phi pháp làm cho say đắm, và bị ác tham chinh phục, bị tà kiến chi phối. Vì bị tham ái phi pháp làm cho say đắm, vì bị ác tham chinh phục, vì bị tà kiến chi phối, chúng cầm gươm sắc bén sát hại lẫn nhau. Do vậy, nhiều người mạng chung. Ðây là nhân, này Bà-la-môn, đây là duyên, ngày nay loài người bị tiêu diệt, bị giảm thiểu trông rõ như thế, các làng trở thành không phải làng, các thị trấn trở thành không phải thị trấn, các thành phố trở thành không phải thành phố, các quốc độ trở thành không quốc độ.`, ref: "Tăng Chi Bộ 3.56", url: "https://loicuaducphat.org/an/an3.56.html#content" },

{ text: `Giới hạnh không dao động\nKhôn khéo và thiền tịnh,\nVới tâm được chinh phục,\nNhứt tâm, khéo định tĩnh,\nBậc trí đoạn mê ám,\nBa minh, diệt tử thần,\nVị ấy được tôn xưng,\nÐại hạnh cho Trời Người,\nBậc “Ðoạn tận tất cả”,\nÐầy đủ cả ba minh.`, ref: "Tăng Chi Bộ 3.58", url: "https://loicuaducphat.org/an/an3.58.html#content" },

{ text: `Ai đầy đủ giới hạnh\nTinh cần và định tĩnh\nVới tầm được chinh phục\nNhứt tâm khéo định tĩnh\nAi biết được đời trước\nThấy Thiên giới đọa xứ\nVị ấy là đạo sĩ\nÐoạn sanh, đạt thắng trí\nVị Bà-la-môn nào,\nChứng được ba minh này,\nTa gọi là ba minh\nKhông như thường được gọi.`, ref: "Tăng Chi Bộ 3.59", url: "https://loicuaducphat.org/an/an3.59.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Khổ Thánh đế?\nSanh là khổ, già là khổ, bệnh là khổ, chết là khổ, sầu bi, khổ, ưu, não là khổ. Ðiều mong cầu không được là khổ. Tóm lại, năm thủ uẩn là khổ. Này các Tỷ-kheo, đây là Khổ Thánh đế.`, ref: "Tăng Chi Bộ 3.61", url: "https://loicuaducphat.org/an/an3.61.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Thánh đế về Khổ tập?\nVô minh duyên hành, hành duyên thức, thức duyên sắc, danh sắc duyên sáu xứ, sáu xứ duyên xúc, xúc duyên thọ, thọ duyên ái, ái duyên thủ, thủ duyên hữu, hữu duyên sanh, sanh duyên già, chết, sầu, bi, khổ, ưu não. Như vầy là sự tập khởi của toàn bộ khổ uẩn này. Này các Tỷ-kheo, đây gọi là Thánh đế về Khổ tập.`, ref: "Tăng Chi Bộ 3.61", url: "https://loicuaducphat.org/an/an3.61.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Thánh đế về Khổ diệt?\nDo vô minh diệt không có tàn dư, nên các hành diệt. Do hành diệt, nên thức diệt. Do thức diệt nên danh sắc diệt. Do danh sắc diệt nên sáu xứ diệt. Do sáu xứ diệt nên xúc diệt. Do xúc diệt nên thọ diệt. Do thọ diệt nên ái diệt. Do ái diệt nên thủ diệt. Do thủ diệt nên hữu diệt. Do hữu diệt nên sanh diệt. Do sanh diệt nên già, chết, sầu, bi, khổ, ưu não đều diệt. Như vậy là sự đoạn diệt toàn bộ của khổ uẩn này. Này các Tỷ-kheo, Ðây gọi là Thánh đế về Khổ diệt.`, ref: "Tăng Chi Bộ 3.61", url: "https://loicuaducphat.org/an/an3.61.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Thánh đế về con đường đưa đến Khổ diệt?\nÐây là Thánh đạo Tám ngành, tức là chánh tri kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định. Này các Tỷ-kheo, đây gọi là Thánh đế về con đường đưa đến Khổ diệt.`, ref: "Tăng Chi Bộ 3.61", url: "https://loicuaducphat.org/an/an3.61.html#content" },

{ text: `Ở đây, này Bà-la-môn, Ta sống gần một làng hay một thị trấn. Buổi sáng, Ta đắp y, cầm y bát, đi vào làng ấy hay vào thị trấn ấy để khất thực. Sau khi ăn xong, trên con đường đi khất thực trở về, Ta đi đến góc cuối của ngôi rừng. Ở tại đấy, Ta lượm cỏ hay lá chất thành một đống, rồi ta ngồi kiết già, lưng thẳng, để niệm trước mặt, ly dục, ly pháp bất thiện, Ta chứng đạt và an trú sơ Thiền, một trạng thái hỷ lạc do ly dục sanh, có tầm có tứ.`, ref: "Tăng Chi Bộ 3.63", url: "https://loicuaducphat.org/an/an3.63.html#content" },

{ text: `Này các Kàlàmà, chớ có tin vì nghe báo cáo, chớ có tin vì nghe truyền thuyết; chớ có tin vì theo truyền thống; chớ có tin vì được kinh điển truyền tụng; chớ có tin vì lý luận suy diễn; chớ có tin vì diễn giải tương tự; chớ có tin vì đánh giá hời hợt những dữ kiện; chớ có tin vì phù hợp với định kiến; chớ có tin vì phát xuất từ nơi có uy quyền, chớ có tin vì vị Sa-môn là bậc đạo sư của mình.\nNhưng này các Kàlàmà, khi nào tự mình biết rõ như sau: “Các pháp này là bất thiện; Các pháp này là đáng chê; Các pháp này bị các người có trí chỉ trích; Các pháp này nếu thực hiện và chấp nhận đưa đến bất hạnh khổ đau”, thời này Kàlàmà, hãy từ bỏ chúng!`, ref: "Tăng Chi Bộ 3.65", url: "https://loicuaducphat.org/an/an3.65.html#content" },

{ text: `Vị ấy rõ biết như sau: “Trước ta có tham, tham ấy là bất thiện. Nay ta không có nữa. Như vầy là thiện. Trước ta có sân, sân ấy là bất thiện. Nay ta không có nữa. Như vầy là thiện. Trước ta có si, si ấy là bất thiện. Nay ta không có nữa. Như vậy là thiện”. Như vậy, ngay trong đời sống hiện tại, vị ấy được giải thoát khỏi hy cầu, được tịch tịnh, được thanh lương, cảm thấy an lạc, tự mình an trú trong Phạm thể.`, ref: "Tăng Chi Bộ 3.66", url: "https://loicuaducphat.org/an/an3.66.html#content" },

{ text: `Cái gì là tham, này các Tỷ-kheo, cái ấy bất thiện. Ai với lòng tham có làm gì về thân, về lời, về ý, cái ấy bất thiện. Với ai có lòng tham, bị lòng tham chinh phục, tâm không được tự chủ, vu cáo làm người khác đau khổ, bằng cách sát hại, trói buộc, tịch thu tài sản, mắng nhiếc hay tẩn xuất, dựa trên: “Ta là sức mạnh, ta có sức mạnh.” Cái ấy là bất thiện. Như vậy, rất nhiều ác bất thiện pháp này sanh từ tham, duyên khởi từ tham, tập khởi từ tham, khởi lên nơi người ấy.`, ref: "Tăng Chi Bộ 3.69", url: "https://loicuaducphat.org/an/an3.69.html#content" },

{ text: `- Cái gì là sân, này các Tỷ-kheo, cái ấy bất thiện. Ai với lòng sân có làm gì về thân, về lời, về ý, cái ấy bất thiện. Với ai có lòng sân, bị lòng sân chinh phục, tâm không được tự chủ, vu cáo làm người khác đau khổ, bằng cách sát hại, trói buộc, tịch thu tài sản, mắng nhiếc hay tẩn xuất, dựa trên: “Ta là sức mạnh, ta có sức mạnh.” Cái ấy là bất thiện. Như vậy, rất nhiều ác bất thiện pháp này sanh từ sân, duyên khởi từ sân, tập khởi từ sân, khởi lên nơi người ấy.`, ref: "Tăng Chi Bộ 3.69", url: "https://loicuaducphat.org/an/an3.69.html#content" },

{ text: `Như vậy, này Ananda, nghiệp là thửa ruộng, thức là hột giống, ái là sự nhuận ướt. Chúng sanh bị vô minh che lấp, bị ái trói buộc, nên thức được an lập trong giới thấp kém. Như vậy, trong tương lai có sự tái sanh sanh khởi. Như vậy, này Ananda, hữu có mặt.`, ref: "Tăng Chi Bộ 3.76", url: "https://loicuaducphat.org/an/an3.76.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, hãy học tập như sau: “Sắc bén sẽ là ước muốn chúng ta để thọ trì tăng thượng giới học. Sắc bén sẽ là ước muốn chúng ta để thọ trì tăng thượng định học. Sắc bén sẽ là ước muốn chúng ta để thọ trì tăng thượng tuệ học”. Như vậy, này các Tỷ-kheo, các Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 3.81", url: "https://loicuaducphat.org/an/an3.81.html#content" },

{ text: `Người tinh tấn, nghị lực\nKiên trì và Thiền tu\nSống hộ trì các căn\nHãy hành ba tăng thượng\nTrước thế nào, sau vậy\nSau thế nào, trước vậy\nDưới thế nào, trên vậy\nTrên thế nào, dưới vậy\nNgày thế nào, đêm vậy\nÐêm thế nào, ngày vậy.\nHãy nhiếp phục mọi phương\nVới vô lượng tâm định\nÐây gọi hữu đạo học\nLà thuần tịnh hạnh đức\nÐây gọi là Chánh giác\nBậc trí đạt tối hậu\nVới thức được đoạn diệt\nÁi diệt, được giải thoát\nNhư đèn sáng tịch diệt\nTâm vị ấy giải thoát.`, ref: "Tăng Chi Bộ 3.90", url: "https://loicuaducphat.org/an/an3.90.html#content" },

{ text: `Ví như, này các Tỷ-kheo, vào mùa thu, khi bầu trời quang đãng, không có mây và mặt trời mọc lên giữa bầu trời, phá sạch hắc ám khắp cả hư không, và chói sáng, bừng sáng, rực sáng; cũng vậy, này các Tỷ-kheo, với vị Thánh đệ tử; pháp nhãn ly trần ly cấu khởi lên; và do tri kiến này khởi lên, này các Tỷ-kheo, ba kiết sử được đoạn tận, thân kiến, nghi, giới cấm thủ. Lại nữa, vị ấy được thoát khỏi hai pháp tham và sân. Vị ấy ly dục, ly pháp bất thiện, chứng đạt và an trú sơ Thiền, một trạng thái hỷ lạc do ly dục sanh, có tầm có tứ. Trong thời gian ấy, này các Tỷ-kheo, vị Thánh đệ tử nếu có mạng chung, sẽ không có kiết sử nào, do kiết sử ấy, vị Thánh đệ tử phải đi đến thế giới này nữa.`, ref: "Tăng Chi Bộ 3.94", url: "https://loicuaducphat.org/an/an3.94.html#content" },

{ text: `Lúc nào, này các Tỷ-kheo, các Tỷ-kheo sống hòa hợp, hoan hỷ, không có luận tranh, như nước và sữa lẫn lộn, nhìn nhau với cặp mắt ái kính, lúc ấy, này các Tỷ-kheo, các Tỷ-kheo tạo được công đức, lúc ấy, này các Tỷ-kheo, các Tỷ-kheo sống phạm trú. Nghĩa là, với ai hân hoan với tâm giải thoát liên hệ với hỷ, thời hỷ sanh; với ai có hỷ, thân được khinh an; với thân khinh an, cảm giác được lạc thọ; với ai cảm giác lạc thọ, tâm được định tĩnh.`, ref: "Tăng Chi Bộ 3.95", url: "https://loicuaducphat.org/an/an3.95.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Tỷ-kheo đầy đủ sắc đẹp?\nỞ đây, này các Tỷ-kheo, Tỷ-kheo giữ gìn giới luật, sống hộ trì với sự hộ trì của giới bổn, đầy đủ uy nghi chánh hạnh, thấy sợ hãi trong những lỗi nhỏ nhặt, chấp nhận và học tập trong các học pháp. Như vậy, này các Tỷ-kheo, là Tỷ-kheo đầy đủ sắc đẹp.`, ref: "Tăng Chi Bộ 3.96", url: "https://loicuaducphat.org/an/an3.96.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là Tỷ-kheo đầy đủ sức mạnh?\nỞ đây, này các Tỷ-kheo, Tỷ-kheo sống tinh cần tinh cấn, đoạn tận các pháp bất thiện, thành tựu đầy đủ các pháp thiện, nỗ lực kiên trì, dõng mãnh, không từ bỏ trách nhiệm đối với các pháp thiện. Như vậy, này các Tỷ-kheo, là Tỷ-kheo đầy đủ sức mạnh.`, ref: "Tăng Chi Bộ 3.96", url: "https://loicuaducphat.org/an/an3.96.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, nếu Tỷ-kheo trưởng lão này nói lên ở giữa chúng Tăng. Các Tỷ kheo ấy nói như sau: “Chư Tôn giả hãy im lặng, Tỷ-kheo trưởng lão đang nói pháp và luật, và lời nói của vị ấy trở thành châu báu cần phải cất giữ, như một người cất giữ tấm vải kàsi trong một hộp có hương thơm.” Do vậy, này các Tỷ-kheo, hãy học tập như sau: “Chúng ta sẽ được như ví dụ tấm vải kàsi, không giống như ví dụ tấm vải bằng vỏ cây”. Như vậy, này các Tỷ-kheo, các Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 3.99", url: "https://loicuaducphat.org/an/an3.99.html#content" },

{ text: `Ðịnh như vậy không có an tịnh, không có thù thắng, không được khinh an, không đạt đến nhất tâm, nhưng là một trạng thái chế ngự thường xuyên dằn ép. Nhưng đến một thời, này các Tỷ-kheo, tâm của vị ấy được nội trú, lắng đứng lại, được nhất tâm, được định tĩnh. Ðịnh ấy được an tịnh, được thù diệu, được khinh an, đạt đến nhất tâm, không phải một trạng thái chế ngự thường xuyên dằn ép, tùy thuộc vào pháp gì tâm người ấy hướng đến để thắng tri, để chứng ngộ; vị ấy có khả năng, có năng lực đạt đến pháp ấy, dầu thuộc loại xứ nào.`, ref: "Tăng Chi Bộ 3.101", url: "https://loicuaducphat.org/an/an3.101.html#content" },

{ text: `Này các Tỷ-kheo, trước khi Ta giác ngộ, chưa chánh đẳng giác, còn là Bồ-tát, ta suy nghĩ như sau: “Cái gì là vị ngọt ở đời? Cái gì là nguy hại, cái gì là xuất ly?”. Rồi này các Tỷ-kheo, về vấn đề ấy, tư tưởng sau đây khởi lên nơi ta: “Do duyên với đời, khởi lên lạc hỷ gì, đây là vị ngọt ở đời. Cái gì ở đời là vô thường, khổ, chịu sự biến hoại, đấy là nguy hại ở đời. Ðiều phục dục tham ở đời, đoạn tận tham dục, đấy là xuất ly ở đời”.`, ref: "Tăng Chi Bộ 3.104", url: "https://loicuaducphat.org/an/an3.104.html#content" },

{ text: `Này các Tỷ-kheo, ta đã đi tìm cầu vị ngọt ở đời. Vị ngọt ở đời là gì, Ta đã tìm được. Cho đến như thế nào, vị ngọt có mặt ở đời, với trí tuệ ta khéo thấy vị ấy ngọt. Này các Tỷ-kheo, ta đã tìm cầu nguy hại ở đời. Nguy hại ở đời là gì, Ta đã tìm được. Cho đến như thế nào, nguy hại có mặt ở đời, với trí tuệ ta, ta khéo thấy nguy hại ấy, này các Tỷ-kheo ta đã tìm cầu xuất ly ở đời. Xuất ly ở đời là gì, Ta đã tìm được. Cho đến như thế nào, xuất ly có mặt ở đời, với trí tuệ ta, ta khéo thấy xuất ly ấy.`, ref: "Tăng Chi Bộ 3.104", url: "https://loicuaducphat.org/an/an3.104.html#content" },

{ text: `Này các Tỷ-kheo, cho đến khi nào ta như thật giác tri vị ngọt ở đời là vị ngọt, nguy hại là nguy hại, xuất ly là xuất ly, cho đến khi ấy, này các Tỷ-kheo, ta mới xác nhận Ta đã giác liễu vô thượng Chánh đẳng Chánh giác, cùng với thế giới gồm có Thiên giới, Ma giới, Phạm thiên giới, cùng với quần chúng Sa-môn, Bà-la-môn, chư Thiên và loài Người. Và tri kiến khởi lên nơi ta: “Bất động là tâm giải thoát của ta. Ðây là đời sống cuối cùng. Nay không còn tái sanh nữa”.`, ref: "Tăng Chi Bộ 3.104", url: "https://loicuaducphat.org/an/an3.104.html#content" },

{ text: `Này các Tỷ-kheo, nếu không có vị ngọt ở đời, thời các loài hữu tình không có tham nhiễm đối với đời. Vì rằng, này các Tỷ-kheo, có vị ngọt ở đời, nên các loài hữu tình có tham nhiễm ở đời. Này các Tỷ-kheo, nếu không có nguy hại ở đời, thời các loài hữu tình không có nhàm chán đối với đời. Vì rằng, này các Tỷ-kheo, có nguy hại ở đời, nên các loài hữu tình có nhàm chán đối với đời. Này các Tỷ-kheo, nếu không có xuất ly ra khỏi đời, thời các loài hữu tình không có xuất ly đối với đời. Vì rằng, này các Tỷ-kheo, có xuất ly đối với đời, nên các loài hữu tình có xuất ly ra khỏi đời.`, ref: "Tăng Chi Bộ 3.105", url: "https://loicuaducphat.org/an/an3.105.html#content" },

{ text: `Này các Tỷ-kheo, đây được xem là khóc than trong giới luật bậc Thánh, tức là ca vịnh. Này các Tỷ-kheo, đây được xem là điên loạn trong giới luật bậc Thánh, tức là múa nhảy. Này các Tỷ-kheo, đây được xem là trẻ con trong giới luật bậc Thánh, tức là cười quá đáng để lộ cả răng. Do luật này, này các Tỷ-kheo, hãy phá cây cầu đi đến hát. Hãy phá cây cầu đi đến múa nhảy. Thật là vừa đủ nếu các Thầy được hoan hỷ đúng pháp, mỉm cười để tỏ là các Thầy được hoan hỷ.`, ref: "Tăng Chi Bộ 3.107", url: "https://loicuaducphat.org/an/an3.107.html#content" },

{ text: `Này các Tỷ-kheo, hưởng thọ ba sự ở đời, không bao giờ thỏa mãn. Thế nào là ba? Hưởng thọ ngủ nghỉ, này các Tỷ-kheo, không bao giờ thỏa mãn. Hưởng thọ rượu men rượu nấu, này các Tỷ-kheo, không bao giờ thỏa mãn. Hưởng thọ sự dâm dục giao hợp, này các Tỷ kheo, không bao giờ thỏa mãn.`, ref: "Tăng Chi Bộ 3.108", url: "https://loicuaducphat.org/an/an3.108.html#content" },

{ text: `Này gia chủ, ví như ngôi nhà nóc nhọn vụng lợp, thời nóc nhọn không được phòng hộ, rui kèo không được phòng hộ, vách tường không được phòng hộ; nóc nhọn bị đầy ứ, rỉ nước, các rui kèo bị đầy ứ rỉ nước, các vách tường bị đầy ứ, rỉ nước, nóc nhọn bị hủ bại, rui kèo bị hủ bại, vách tường bị hủ bại. Cũng vậy, này gia chủ, khi tâm không được phòng hộ, thời thân nghiệp cũng không được phòng hộ, khẩu nghiệp ... ý nghiệp ...  thời thân nghiệp đầy ứ tham dục và rỉ chảy; khẩu nghiệp đầy ứ tham dục và rỉ chảy; ý nghiệp đầy ứ tham dục và rỉ chảy; Với ai thân nghiệp đầy ứ tham dục và rỉ chảy, khẩu nghiệp đầy ứ tham dục và rỉ chảy, ý nghiệp đầy ứ tham dục và rỉ chảy, thời thân nghiệp bị hủ bại, khẩu nghiệp ... ý nghiệp bị hủ bại. Với ai thân nghiệp bị hủ bại, khẩu nghiệp ... ý nghiệp bị hủ bại, thời sự chết không được hiền thiện, mạng chung không được hiền thiện.`, ref: "Tăng Chi Bộ 3.109", url: "https://loicuaducphat.org/an/an3.109.html#content" },

{ text: `Này các Tỷ-kheo, ba hạng người này rơi vào đọa xứ, rơi vào địa ngục, trừ phi họ đoạn bỏ pháp này. Thế nào là ba? Ai sống không Phạm hạnh, tự xưng là có sống Phạm hạnh; đối với người sống Phạm hạnh thanh tịnh, hành Phạm hạnh thật thanh tịnh, ai công kích là không Phạm hạnh một cách không căn cứ; ai chủ trương như sau: “Không có lỗi lầm trong các dục vọng” và rơi vào say đắm trong các dục vọng; những hạng người này, này các Tỷ-kheo, là ba hạng người rơi vào trong đọa xứ, rơi vào địa ngục, trừ phi họ đoạn bỏ pháp này.`, ref: "Tăng Chi Bộ 3.113", url: "https://loicuaducphat.org/an/an3.113.html#content" },

{ text: `Sự xuất hiện của ba hạng người này, này các Tỷ-kheo, khó tìm được ở đời. Thế nào là ba? Này các Tỷ-kheo, sự xuất hiện của Như Lai, bậc A-la-hán, Chánh Ðẳng Chánh Giác, khó tìm được ở đời. Người có thể thuyết pháp và luật do Như Lai tuyên thuyết, khó tìm được ở đời. Người tri ân, người biết ơn, khó tìm được ở đời.`, ref: "Tăng Chi Bộ 3.114", url: "https://loicuaducphat.org/an/an3.114.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người không tháo động, không kiêu căng, không dao động, không lắm mồm lắm miệng, không lắm lời, trú niệm, tỉnh giác, định tĩnh, nhất tâm, các căn được bảo vệ. Này các Tỷ-kheo, đây gọi là hạng người khó ước lượng.`, ref: "Tăng Chi Bộ 3.115", url: "https://loicuaducphat.org/an/an3.115.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có người tháo động, kiêu căng, dao động, lắm mồm lắm miệng, lắm lời, thất niệm không tỉnh giác, không định tĩnh, tâm tán loạn, các căn thả lỏng. Này các Tỷ-kheo, đây gọi là hạng người dễ ước lượng.`, ref: "Tăng Chi Bộ 3.115", url: "https://loicuaducphat.org/an/an3.115.html#content" },
{ text: `Tại phương hướng nào, này các Tỷ-kheo, các Tỷ-kheo sống cạnh tranh, luận tranh, đấu tranh, đả thương nhau với binh khí miệng lưỡi, thật không thoải mái cho ta, này các Tỷ-kheo, khi nghĩ đến phương hướng ấy, còn nói gì đến chỗ ấy. Ở đây, Ta đi đến kết luận như sau: “Thật vậy, các Tỷ-kheo ấy đã từ bỏ ba pháp và đã làm quá nhiều ba pháp”.nBa pháp họ đã từ bỏ là gì? Viễn ly tầm, vô sân tầm, bất hại tầm. Ba pháp này họ đã từ bỏ. Ba pháp gì họ đã làm quá nhiều? Dục tầm, sân tầm, hại tầm. Ba pháp này họ đã làm quá nhiều.`, ref: "Tăng Chi Bộ 3.124", url: "https://loicuaducphat.org/an/an3.124.html#content" },

{ text: `Tại phương hướng nào, này các Tỷ-kheo, các Tỷ-kheo sống hòa hợp, hoan hỷ, không đấu tranh nhau, như sữa và nước lẫn lộn, nhìn nhau với cặp mắt ái kính, này các Tỷ-kheo, đi đến phương hướng ấy thật thoải mái cho ta, còn nói gì nghĩ đến phương hướng ấy. Ở đây, Ta đi đến kết luận như sau: “Thật vậy, các Tỷ-kheo ấy đã từ bỏ ba pháp này và đã làm quá nhiều ba pháp này”.Ba pháp họ đã từ bỏ là gì? Dục tầm, sân tầm, hại tầm. Ba pháp này họ đã từ bỏ.Ba pháp gì họ đã làm quá nhiều? Viễn ly tầm, vô sân tầm, bất hại tầm.`, ref: "Tăng Chi Bộ 3.124", url: "https://loicuaducphat.org/an/an3.124.html#content" },

{ text: `Này các Tỷ-kheo, ở đây, sau khi đắp y vào buổi sáng, Ta cầm lấy y bát, đi vào Ba-la-nại để khất thực. Này các Tỷ-kheo, trong khi đi khất thực tại Goyogapilakkha, Ta thấy một Tỷ-kheo hưởng thọ hương vị trống không, không có Thiền định, hưởng thọ hương vị hướng ngoại của vật dục, thất niệm, không tỉnh giác, không định tĩnh, với tâm tán loạn, với các căn phóng túng. Thấy vậy, Ta liền nói với vị Tỷ-kheo ấy: “Này Tỷ-kheo, này Tỷ-kheo! Thầy chớ có làm cho tự ngã trở thành thối nát. Này Tỷ-kheo, ai làm cho tự ngã thối nát đầy ứ, thoát ra toàn mùi hôi thối, rồi mong rằng: “Các loài ruồi lằng sẽ không bu đậu, sẽ không có chiếm cứ, sự kiện như vậy không xảy ra”. Này các Tỷ-kheo, Tỷ-kheo ấy được ta giáo giới với lời giáo giới này, cảm thấy xúc động mạnh.`, ref: "Tăng Chi Bộ 3.128", url: "https://loicuaducphat.org/an/an3.128.html#content" },

{ text: `Tham cầu, này các Tỷ-kheo, là thối nát; sân là mùi hôi thối, các suy tầm ác bất thiện là ruồi lằng. Này các Tỷ-kheo, ai làm cho các tự ngã thối nát, đầy ứ, thoát ra mùi hôi thối, rồi mong rằng: “Các loài ruồi lằng sẽ không bu đậu, sẽ không chiếm cứ”, sự kiện như vậy không xảy ra.`, ref: "Tăng Chi Bộ 3.128", url: "https://loicuaducphat.org/an/an3.128.html#content" },

{ text: `Tai mắt không giữ gìn\nCác căn không phòng hộ\nRuồi lằng sẽ bu đậu\nCác tư duy tham ái\nTỷ-kheo làm thối nát\nÐầy ứ những mùi hôi\nXa thay là Niết-bàn!\nChịu phần về bất hạnh\nTại làng hay trong rừng\nTự ngã không an tịnh\nKẻ ngu và không trí\nÐi đứng đầy ruồi lằng\nAi đầy đủ giới luật\nThích tịch tịnh trí tuệ\nSống an tịnh hạnh phúc\nMọi ruồi lằng diệt trừ`, ref: "Tăng Chi Bộ 3.128", url: "https://loicuaducphat.org/an/an3.128.html#content" },

{ text: `Này các Tỷ-kheo, ba pháp này chói sáng, được hiển lộ, không có che giấu. Vành tròn của mặt trăng, này các Tỷ-kheo, chói sáng, được hiển lộ, không có che giấu. Vành tròn của mặt trời, này các Tỷ-kheo, chói sáng, được hiển lộ, không có che giấu. Pháp và Luật được Thế Tôn tuyên thuyết, này các Tỷ-kheo, chói sáng, được hiển lộ, không có che giấu. Ba pháp này chói sáng, được hiển lộ, không có che giấu.`, ref: "Tăng Chi Bộ 3.131", url: "https://loicuaducphat.org/an/an3.131.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có người dầu bị nói một cách kịch liệt, dầu có bị nói một cách ác độc, dầu có bị nói một cách thô lỗ, tuy vậy vẫn dễ dàng hòa hợp, thân thiện, và hoan hỷ. Này các Tỷ-kheo, ví như chữ viết trên nước được mau chóng biến mất, không có tồn tại lâu dài. Cũng vậy, này các Tỷ-kheo, có người dầu bị nói một cách kịch liệt, dầu có bị nói một cách ác độc, dầu có bị nói một cách thô lỗ, tuy vậy vẫn dễ dàng hòa hợp, thân thiện, và hoan hỷ. Này các Tỷ-kheo, đây được gọi là hạng người như chữ được viết trên nước.`, ref: "Tăng Chi Bộ 3.132", url: "https://loicuaducphat.org/an/an3.132.html#content" },

{ text: `Các loại hữu tình nào, này các Tỷ-kheo, vào buổi sáng, thân làm việc thiện, nói lời nói thiện, ý nghĩ điều thiện, các loài hữu tình ấy, này các Tỷ-kheo, có một buổi sáng tốt đẹp. Các loại hữu tình nào, này các Tỷ-kheo, vào buổi trưa, thân làm việc thiện, nói lời nói thiện, ý nghĩ điều thiện, các loài hữu tình ấy, này các Tỷ-kheo, có một buổi trưa tốt đẹp. Các loại hữu tình nào, này các Tỷ-kheo, vào buổi chiều, thân làm việc thiện, nói lời nói thiện, ý nghĩ điều thiện, các loài hữu tình ấy, này các Tỷ-kheo, có một buổi chiều tốt đẹp.`, ref: "Tăng Chi Bộ 3.155", url: "https://loicuaducphat.org/an/an3.155.html#content" },

{ text: `Giới, Thiền định, Trí tuệ\nVới giải thoát vô thượng\nGotama danh xưng\nGiác ngộ những pháp này\nÐức Phật thắng tri chúng\nThuyết pháp cho Tỷ-kheo\nÐạo sư đoạn tận khổ\nBậc Tuệ nhãn tịch tịnh.`, ref: "Tăng Chi Bộ 4.1", url: "https://loicuaducphat.org/an/an4.1.html#content" },
{ text: `Những ai sống ở đời\nKhông chế ngự các dục\nKhông từ bỏ ly tham\nThọ hưởng các dục vọng\nHọ đi đến sanh già\nÐến rồi lại đến nữa\nBị khát ái trói buộc\nHọ đi thuận dòng đời\nDo vậy bậc có trí\nỞ đời, trú chánh niệm\nKhông thọ hưởng các dục\nKhông hành trì điều ác\nDầu chịu sự khổ đau\nTừ bỏ các dục vọng\nHọ được gọi hạng người\nÐi ngược lại dòng đời.`, ref: "Tăng Chi Bộ 4.5", url: "https://loicuaducphat.org/an/an4.5.html#content" },

{ text: `Những ai quyết đoạn tận\nNăm phiền não kiết sử\nBậc hữu học viên mãn\nKhông còn bị thối thất\nÐạt được tâm điều phục\nCác căn được định tĩnh\nVị ấy được gọi là\nNgười đã tự đứng lại\nÐối các pháp thắng liệt\nVị ấy được giác tri\nÐã được quét, quạt sạch\nCác pháp được chấm dứt\nVị ấy bậc trí giả\nPhạm hạnh được thành tựu\nÐược tên gọi danh xưng\nBậc đã đi đến nơi\nChỗ tận cùng thế giới\nBậc đã đến bờ kia.`, ref: "Tăng Chi Bộ 4.5", url: "https://loicuaducphat.org/an/an4.5.html#content" },


{ text: `Người có ái làm bạn\nSẽ luân chuyển dài dài\nKhi hiện hữu chỗ này\nKhi hiện hữu chỗ khác\nNgười ấy không dừng được\nSự luận chuyển tái sanh\nRõ biết nguy hại này\nChính ái sanh đau khổ\nTỷ-kheo từ bỏ ái\nKhông nắm giữ chấp thủ\nAn trú, không thất niệm\nVị ấy sống xuất gia.`, ref: "Tăng Chi Bộ 4.9", url: "https://loicuaducphat.org/an/an4.9.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người như thật quán tri sự tập khởi, sự chấm dứt, vị ngọt, sự nguy hại, sự xuất ly của các dục. Do như thật quán tri sự tập khởi, sự chấm dứt, vị ngọt, sự nguy hại, sự xuất ly của các dục, nên dục tham, dục hỷ, dục luyến, dục đam mê, dục khát, dục não, dục chấp thủ, dục ái trong các dục không xâm chiếm và tồn tại. Này các Tỷ-kheo, đây gọi là ly dục ách.`, ref: "Tăng Chi Bộ 4.10", url: "https://loicuaducphat.org/an/an4.10.html#content" },

{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo khi đang đi ... khi đang đứng ... khi đang ngồi ... khi đang nằm, thức khởi lên dục tầm, hay sân tầm, hay hại tầm mà nếu Tỷ-kheo chấp nhận, không có từ bỏ, không có tẩy sạch, không có chấm dứt, không có đi đến không hiện hữu; này các Tỷ-kheo, nếu Tỷ-kheo khi đang nằm, thức có sở hành như vậy, vị ấy được gọi là người không có nhiệt tình, không có xấu hổ, liên tục thường hằng biếng nhác, tinh tấn hạ liệt.`, ref: "Tăng Chi Bộ 4.11", url: "https://loicuaducphat.org/an/an4.11.html#content" },

{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo khi đang đi ... khi đang đứng ... khi đang ngồi ... khi đang nằm, thức khởi lên dục tầm, hay sân tầm, hay hại tầm mà nếu Tỷ-kheo không chấp nhận, từ bỏ, tẩy sạch, chấm dứt, đi đến không hiện hữu; này các Tỷ-kheo, nếu Tỷ-kheo khi đang nằm, thức có sở hành như vậy, vị ấy được gọi là người có nhiệt tình, có xấu hổ, liên tục thường hằng tinh cần, tinh tấn, siêng năng.`, ref: "Tăng Chi Bộ 4.11", url: "https://loicuaducphat.org/an/an4.11.html#content" },

{ text: `Nếu khi đi khi đứng\nKhi ngồi hay khi nằm\nKhởi lên ác tầm tư\nLiên hệ đến gia đình\nThực hành theo ác đạo\nMờ ám bởi si mê\nVị Tỷ-kheo như vậy\nKhông chứng Vô thượng giác\nAi khi đi khi đứng\nKhi ngồi hay khi nằm\nÐiều phục được tâm tư\nYêu thích tầm chỉ tịnh\nVị Tỷ-kheo như vậy\nChứng được Vô thượng giác`, ref: "Tăng Chi Bộ 4.11", url: "https://loicuaducphat.org/an/an4.11.html#content" },

{ text: `Nếu Tỷ-kheo trong khi đi ... trong khi đứng ... nếu Tỷ-kheo trong khi ngồi ... nếu Tỷ-kheo trong khi nằm thức, tham, sân, si được từ bỏ ... hôn trầm thụy miên, trạo hối, nghi được đoạn tận , tinh cần, tinh tấn, không có thụ động, niệm được an trú không có thất niệm, thân được khinh an, không có cuồng nhiệt, tâm được định tĩnh nhất tâm. Này các Tỷ-kheo, nếu các Tỷ-kheo khi đang thức có sở hành như vậy; vị ấy được gọi là người có nhiệt tâm, có xấu hổ, liên tục thường hằng tinh cần tinh tấn, siêng năng.`, ref: "Tăng Chi Bộ 4.12", url: "https://loicuaducphat.org/an/an4.12.html#content" },

{ text: `Ði đứng biết tự chế\nNgồi nằm biết tự chế\nTỷ-kheo biết tự chế\nKhi co tay, duỗi tay\nPhía trên, ngang cùng khắp\nXa cho đến cùng tột\nBất cứ sanh thú nào\nỞ tại thế giới này\nKhéo quán sát sanh diệt\nCủa tất cả pháp uẩn\nTâm chỉ tịnh chánh hạnh\nThường xuyên chuyên học tập\nLiên tục, hằng siêng năng\nTỷ-kheo được gọi vậy.`, ref: "Tăng Chi Bộ 4.12", url: "https://loicuaducphat.org/an/an4.12.html#content" },

{ text: `- Một thời, này các Tỷ-kheo, Ta trú ở Uruvelà trên bờ sông Neranjarà, dưới cây bàng ajapàla, khi mới thành Chánh giác. Trong khi Ta Thiền tịnh độc cư, này các Tỷ-kheo, tư tưởng sau đây được khởi lên: “Thật là khó khăn, sống không cung kính, không vâng lời, vậy Ta hãy cung kính, đảnh lễ và sống y chỉ vào một vị Sa-môn hay Bà-la-môn”. Rồi này các Tỷ-kheo, Ta suy nghĩ: “Với mục đích làm cho giới uẩn ...định uẩn ... tuệ uẩn ... giải thoát uẩn chưa được đầy đủ, Ta hãy cung kính, đảnh lễ và sống y chỉ vào một vị Sa-môn hay Bà-la-môn nào khác. Nhưng Ta không thấy một chỗ nào trong thế giới chư Thiên, Ác ma và Phạm thiên, giữa quần chúng Sa-môn và Bà-la-môn, chư Thiên hay loài Người, không có một vị Sa-môn hay Bà-la-môn nào khác với giới đầy đủ hơn Ta, mà Ta có thể cung kính, đảnh lễ, sống y chỉ. Rồi này các Tỷ-kheo, Ta suy nghĩ như sau: “Với pháp này mà Ta đã chơn chánh giác ngộ, Ta hãy cung kính đảnh lễ và sống y chỉ pháp ấy”. Và Ta sống cung kính, tôn trọng và y chỉ pháp ấy và Ta đã tự Chánh Ðẳng Giác. Và này các Tỷ-kheo, vì rằng chúng Tăng thành tựu sự cao cả nên Ta tôn trọng đặc biệt chúng Tăng.`, ref: "Tăng Chi Bộ 4.21", url: "https://loicuaducphat.org/an/an4.21.html#content" },

{ text: `Nếu trưởng lão, này các Tỷ-kheo, là 80 tuổi, hay 90 tuổi, hay 100 tuổi đời, và nếu vị ấy nói phi thời, nói phi chân, nói phi nghĩa, nói phi pháp, nói phi luật, nói những lời không đáng giữ gìn, lời nói không hợp thời cơ, không hợp lý, không có giới hạn, không có liên hệ đến mục đích, thời vị ấy chỉ được gọi là vị trưởng lão ngu. Nếu là một vị tuổi trẻ, này các Tỷ kheo, một thanh niên còn non trẻ, tóc đen nhánh, trong tuổi hiền thiện của đời, còn trong tuổi thanh xuân, vị ấy nói lời đúng thời, nói lời chân thực, nói lời có nghĩa, nói lời đúng pháp, nói lời đúng luật, nói những lời đáng giữ gìn, lời nói hợp thời cơ, hợp lý, có giới hạn, liên hệ đến mục đích, thời vị ấy chỉ được gọi là vị trưởng lão hiền trí.`, ref: "Tăng Chi Bộ 4.22", url: "https://loicuaducphat.org/an/an4.22.html#content" },

{ text: `Này các Tỷ-kheo, có bốn pháp tác thành trưởng lão này. Thế nào là bốn? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo có giới, sống chế ngự với sự chế ngự của giới bổn Pàtimokkha, đầy đủ uy nghi chánh hạnh, thấy sợ hãi trong các lỗi nhỏ nhặt, chấp nhận và học tập trong các học pháp. Là vị nghe nhiều, thọ trì điều đã nghe, tích tụ điều đã nghe, những pháp sơ thiện, trung thiện, hậu thiện, có nghĩa có văn, đề cao Phạm hạnh hoàn toàn viên mãn thanh tịnh, các pháp như vậy, vị ấy nghe nhiều, thọ trì đọc tụng bằng lời, quán sát với ý, thể nhập với chánh kiến, đối với bốn thiền thuộc tăng thượng tâm, hiện tại lạc trú, có được không khó khăn, có được không mệt nhọc, có được không phí sức; do đoạn diệt các lậu hoặc, ngay trong hiện tại, tự mình với thắng trí, chứng ngộ, chứng đạt và an trú vô lậu tâm giải thoát, tuệ giải thoát. Này các Tỷ-kheo, bốn pháp này tác thành vị trưởng lão.`, ref: "Tăng Chi Bộ 4.22", url: "https://loicuaducphat.org/an/an4.22.html#content" },

{ text: `Ai với tâm cống cao\nNói nhiều lời phù phiếm\nVới tư duy không định\nNhư thú không ưa pháp\nXa địa vị trưởng lão\nÁc kiến, không kính trọng\nVà ai đủ giới hạnh\nNghe nhiều trí biện tài\nSống chế ngự bậc trí\nÐối với tất cả pháp\nVị ấy với trí tuệ\nQuán thấy chơn ý nghĩa\nÐạt cứu cánh các pháp\nKhông hoang vu, biện tài\nÐoạn tận sanh và chết\nViên mãn hành Phạm hạnh\nVị ấy Ta gọi tên\nTrưởng lão không lậu hoặc\nDo đoạn trừ lậu hoặc\nÐược gọi là trưởng lão.`, ref: "Tăng Chi Bộ 4.22", url: "https://loicuaducphat.org/an/an4.22.html#content" },

{ text: `Cái gì, này các Tỷ-kheo, trong toàn thế giới với Thiên giới, Ma giới, Phạm thiên giới, cùng với quần chúng Sa-môn, Bà-la-môn, chư Thiên và loài Người, được thấy, được nghe, được cảm giác, được thức tri, được đạt đến, được tầm cầu, được ý tư sát, tất cả đều được Như Lai chánh đẳng giác. Do vậy, được gọi là Như Lai. Từ đêm, này các Tỷ-kheo, Như Lai được chánh đẳng giác, đến đêm Như Lai nhập Niết-bàn, trong thời gian ấy, điều gì Như Lai nói, nói lên, tuyên bố, tất cả là như vậy, không có khác được. Do vậy, được gọi là Như Lai. Này các Tỷ-kheo, Như Lai nói gì thì làm vậy, làm gì thì nói vậy. Vì rằng nói gì thì làm vậy, làm gì thì nói vậy, nên được gọi là Như Lai.`, ref: "Tăng Chi Bộ 4.23", url: "https://loicuaducphat.org/an/an4.23.html#content" },

{ text: `Này các Tỷ-kheo, cái gì trong toàn thế giới với Thiên giới, Ma giới, Phạm thiên giới, cùng với quần chúng Sa-môn, Bà-la-môn, chư Thiên và loài Người, được thấy ... được ý tư sát, tất cả Ta đều biết. Này các Tỷ-kheo, cái gì trong toàn thế giới này ... được thấy, được ý tư sát, Ta đã được biết rõ như sau: “Tất cả đều được Như Lai biết đến. Như Lai không có dựng đứng lên”. Này các Tỷ-kheo, nếu Ta nói rằng: “Ta biết tất cả, cái gì trong toàn thế giới ... được thấy, được ý tư sát”. Như vậy, là có nói láo trong ta. Nếu Ta nói như sau: “Ta cả hai biết và không biết”. Như vậy, là có nói láo trong ta. Nếu Ta nói như sau: “Ta không biết và cũng không phải biết”. Như vậy là có nói láo trong Ta. Như vậy có lỗi trong Ta.`, ref: "Tăng Chi Bộ 4.24", url: "https://loicuaducphat.org/an/an4.24.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, Như Lai là vị đã thấy những gì cần thấy, nhưng không có tưởng tượng điều đã được thấy, không có tưởng tượng những cái gì không được thấy, không có tưởng tượng những gì cần phải thấy, không có tưởng tượng đối với người thấy. Ðã nghe những gì cần nghe, nhưng không có tưởng tượng điều đã được nghe, không có tưởng tượng những cái gì không được nghe, không có tưởng tượng những gì cần phải nghe, không có tưởng tượng đối với người nghe. Ðã cảm giác những gì cần cảm giác, nhưng không có tưởng tượng điều đã được cảm giác, không có tưởng tượng những cái gì không được cảm giác, không có tưởng tượng những gì cần phải cảm giác, không có tưởng tượng đối với người cảm giác. Ðã thức tri những gì cần thức tri, nhưng không có tưởng tượng điều đã được thức tri, không có tưởng tượng những cái gì không được thức tri, không có tưởng tượng những cái gì cần phải thức tri, không có tưởng tượng đối với người thức tri. Như vậy, này các Tỷ-kheo, Như Lai đối với các pháp được thấy, được nghe, được cảm giác, được thức tri, đều đã biết rõ, nên vị ấy là như vậy. Lại nữa, hơn người như vậy, không có ai khác tối thượng hơn và thù thắng hơn, Ta tuyên bố như vậy.`, ref: "Tăng Chi Bộ 4.24", url: "https://loicuaducphat.org/an/an4.24.html#content" },

{ text: `Phạm hạnh được sống, này các Tỷ-kheo, không vì mục đích lừa dối quần chúng, không vì mục đính mơn trớn quần chúng, không vì mục đích được lợi ích về lợi dưỡng, cung kính, danh vọng, không vì mục đích được lợi ích thoát khỏi lời phê bình bàn tán, không với ý nghĩ: “Mong quần chúng biết Ta như vậy”. Và này các Tỷ-kheo, Phạm hạnh này được sống với mục đích được chế ngự, với mục đích đoạn tận, với mục đích ly tham, với mục đích đoạn diệt.`, ref: "Tăng Chi Bộ 4.25", url: "https://loicuaducphat.org/an/an4.25.html#content" },

{ text: `Với mục đích chế ngự,\nVới mục đích đoạn tận,\nLà đời sống Phạm hạnh,\nTránh xa lời nói suông,\nThế Tôn đã tuyên bố,\nÐi đến nhập Niết-bàn,\nCon đường này được đi,\nBởi đại nhân, đại sĩ,\nAi dấn bước thực hành,\nÐúng như lời Phật dạy,\nSẽ chấm dứt khổ đau,\nLàm theo Ðạo Sư dạy.`, ref: "Tăng Chi Bộ 4.25", url: "https://loicuaducphat.org/an/an4.25.html#content" },

{ text: `Những vị Tỷ-kheo nào, này các Tỷ-kheo, lừa dối cứng đầu, lắm mồm lắm miệng, hoang dâm, hỗn hào, không có định tĩnh, những Tỷ-kheo ấy không phải là Tỷ-kheo của Ta. Những Tỷ-kheo ấy đã rơi khỏi Pháp Luật này. Và họ không đi đến tăng trưởng, tăng thịnh, tăng rộng trong Pháp Luật này. Và này các Tỷ-kheo, các Tỷ-kheo nào không lừa dối, không lắm mồm lắm miệng, có trí, không cứng đầu, khéo định tĩnh, những Tỷ-kheo ấy phải là Tỷ-kheo của Ta. Và những Tỷ-kheo ấy không rơi khỏi Pháp Luật này, và họ đi đến tăng trưởng, tăng thịnh, tăng rộng trong Pháp Luật này.`, ref: "Tăng Chi Bộ 4.26", url: "https://loicuaducphat.org/an/an4.26.html#content" },

{ text: `Kẻ lừa dối cứng đầu,\nKẻ lắm mồm, hoang dâm,\nKẻ hỗn hào, không định,\nKhông tăng trưởng các pháp,\nÐược bậc Chánh Ðẳng Giác,\nTuyên bố và thuyết giảng,\nKhông lừa, không lắm mồm,\nCó trí, không cứng đầu,\nVới tâm khéo định tĩnh,\nChúng tăng trưởng các pháp,\nÐược bậc Chánh Ðẳng Giác,\nTuyên bố và thuyết giảng.`, ref: "Tăng Chi Bộ 4.26", url: "https://loicuaducphat.org/an/an4.26.html#content" },

{ text: `Biết đủ với sự vật,\nKhông quan trọng, dễ được,\nLại không có phạm tội,\nTâm không bị phiền nhiễu,\nVề vấn đề trú xứ,\nY áo và ăn uống,\nTâm không bị lo lắng,\nVề phương hướng phải đi,\nCác pháp được tuyên bố,\nThuận lợi Sa-môn hạnh,\nChúng được có đầy đủ.\nVới vị biết vừa đủ,\nVới vị không phóng dật,\nTinh cần trong học tập.`, ref: "Tăng Chi Bộ 4.27", url: "https://loicuaducphat.org/an/an4.27.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo biết đủ với bất cứ loại y nào, và nói lời tán thán sự biết đủ với bất cứ loại y nào, không vì nhân y phục rơi vào sự tầm cầu bất chính, không thích hợp. Nếu không được y, không có lo âu tiếc nuối; nếu được y không có tham lam, mê say, tham đắm; thấy sự nguy hiểm và với trí tuệ thấy được sự xuất ly, vị ấy hưởng thọ y, không vì biết đủ với bất cứ loại y nào, không có khen mình chê người. Ai ở đây, khôn khéo (thiện xảo), không có thụ động, tỉnh giác, chánh niệm, này các Tỷ-kheo, đấy gọi là Tỷ-kheo đứng ở trên Thánh truyền thống, kỳ cựu, được nhận biết là tối sơ.`, ref: "Tăng Chi Bộ 4.28", url: "https://loicuaducphat.org/an/an4.28.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo biết đủ với bất cứ loại đồ ăn khất thực nào, và nói lời tán thán sự biết đủ với bất cứ loại đồ ăn khất thực nào, không vì nhân khất thực rơi vào sự tầm cầu bất chính, không thích hợp. Nếu không được đồ ăn khất thực, không có lo âu tiếc nuối; nếu được đồ ăn khất thực, không có tham lam, mê say, tham đắm; thấy sự nguy hiểm và với trí tuệ thấy được sự xuất ly, vị ấy hưởng thọ đồ ăn khất thực, không vì biết đủ với bất cứ loại đồ ăn khất thực nào, không có khen mình, chê người. Ai ở đây khôn khéo (thiện xảo), không có thụ động, tỉnh giác, chánh niệm, này các Tỷ-kheo, đây gọi là Tỷ-kheo đứng ở trên Thánh truyền thống, kỳ cựu, được nhận biết là tối sơ.`, ref: "Tăng Chi Bộ 4.28", url: "https://loicuaducphat.org/an/an4.28.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo ưa thích tu tập, vui thích tu tập, ưa thích đoạn tận, vui thích đoạn tận, nhưng không vì ưa thích tu tập, vui thích tu tập, ưa thích đoạn tận, vui thích đoạn tận mà khen mình chê người. Ai ở đây khôn khéo, không có thụ động, tỉnh giác, chánh niệm, này các Tỷ-kheo, đây gọi là Tỷ-kheo đứng trên Thánh truyền thống, kỳ cựu, được nhận biết là tối sơ.`, ref: "Tăng Chi Bộ 4.28", url: "https://loicuaducphat.org/an/an4.28.html#content" },

{ text: `Hãy sống không có tham,\nVới tâm không có sân,\nChánh niệm và nhất tâm,\nNội tâm khéo định tĩnh.`, ref: "Tăng Chi Bộ 4.29", url: "https://loicuaducphat.org/an/an4.29.html#content" },

{ text: `Có bốn bánh xe này, này các Tỷ-kheo, thành tựu với chúng, bốn bánh xe được vận chuyển giữa chư Thiên và loài Người thành tựu với chúng, chư Thiên và loài nguời không bao lâu đạt đến sự lớn mạnh, tăng thịnh trong các tài sản. Thế nào là bốn? Trú xứ thích hợp, thân cận các bậc Chân nhân, tự nguyện chân chánh, phước đã làm từ trước.`, ref: "Tăng Chi Bộ 4.31", url: "https://loicuaducphat.org/an/an4.31.html#content" },

{ text: `Dầu cho các loại hữu tình nào, này các Tỷ-kheo, không chân hay hai chân, bốn chân hay nhiều chân, có sắc hay không sắc, có tưởng hay không tưởng, hay phi tưởng phi phi tưởng, Thế Tôn, bậc A-la-hán, Chánh Ðẳng Giác được xem là tối thượng. Những ai đặt lòng tin vào đức Phật, họ đặt lòng tin vào tối thượng. Với những ai đặt lòng tin vào tối thượng, họ được quả dị thục tối thượng.`, ref: "Tăng Chi Bộ 4.34", url: "https://loicuaducphat.org/an/an4.34.html#content" },

{ text: `Này các Tỷ-kheo, dầu cho loại pháp hữu vi nào, Thánh đạo tám ngành được xem là tối thượng, những ai đặt lòng tin vào Thánh đạo Tám ngành, họ đặt lòng tin vào tối thượng. Với những ai đặt lòng tin vào tối thượng, họ được quả dị thục tối thượng.`, ref: "Tăng Chi Bộ 4.34", url: "https://loicuaducphat.org/an/an4.34.html#content" },

{ text: `Dầu cho loại pháp nào, này các Tỷ-kheo, hữu vi hay vô vi, ly tham được xem là tối thượng trong tất cả pháp, tức là sự nhiếp phục kiêu mạn, sự nhiếp phục khát ái, sự nhổ lên tham ái, sự chặt đứt tái sanh, sự đoạn diệt tham ái, sự ly tham đoạn diệt, Niết-bàn. Những ai đặt lòng tin vào pháp ly tham, này các Tỷ-kheo, họ đặt lòng tin vào tối thượng. Với những ai đặt lòng tin vào tối thượng, họ được quả dị thục tối thượng.`, ref: "Tăng Chi Bộ 4.34", url: "https://loicuaducphat.org/an/an4.34.html#content" },

{ text: `Dầu cho loại chúng Tăng hay hội chúng nào, này các Tỷ-kheo, chúng Tăng đệ tử của Như Lai được xem là tối thượng trong tất cả hội chúng ấy. Tức là bốn đôi tám vị, chúng Tăng đệ tử của Thế Tôn đáng được cung kính, đáng được tôn trọng, đáng được cúng dường, đáng được chắp tay, là vô thượng phước điền ở đời. Những ai đặt lòng tin vào chúng Tăng, này các Tỷ-kheo, họ đặt lòng tin vào tối thượng. Với những ai đặt lòng tin vào tối thượng, họ được quả dị thục tối thượng. Này các Tỷ-kheo, đây là bốn lòng tin tối thượng.`, ref: "Tăng Chi Bộ 4.34", url: "https://loicuaducphat.org/an/an4.34.html#content" },

{ text: `Tin tưởng vào tối thượng,\nBiết được pháp tối thượng,\nTin tưởng Phật tối thượng,\nÐáng tôn trọng vô thượng,\nTin tưởng Pháp tối thượng,\nLy tham, an tịnh, lạc,\nTin tưởng Tăng tối thượng,\nLà ruộng phước vô thượng,\nBố thí bậc tối thượng,\nPhước tối thượng tăng trưởng,\nTối thượng về thọ mạng,\nDung sắc và danh văn,\nTối thượng về an lạc,\nTối thượng về sức mạnh,\nBậc trí thí tối thượng,\nPháp tối thượng chánh định,\nChư Thiên hay loài người,\nÐạt được hỷ tối thượng.`, ref: "Tăng Chi Bộ 4.34", url: "https://loicuaducphat.org/an/an4.34.html#content" },

{ text: `Này Bà-la-môn, Ta đã thực hành, hướng đến hạnh phúc cho nhiều người, hướng đến an lạc cho nhiều người, đã an lập nhiều người trên Thánh lý, tức là hiền thiện pháp tánh, thiện pháp tánh. Ta là vị, với tầm tư nào Ta nghĩ cần phải tầm tư, Ta tầm tư tầm tư ấy. Với tầm tư nào Ta nghĩ không cần phải tầm tư, Ta không tầm tư tầm tư ấy. Với tư duy nào Ta nghĩ cần phải tư duy, Ta tư duy tư duy ấy, Với tư duy nào Ta nghĩ không cần phải tư duy, Ta không tư duy tư duy ấy. Này Bà-la-môn, Ta đạt được tâm tự tại trong các đường hướng tầm tư. Này Bà-la-môn đối với bốn Thiền, thuộc tăng thượng tâm, hiện tại lạc trú, Ta có được không khó khăn, Ta có được không mệt nhọc, Ta có được không phí sức. Này Bà-la-môn, do đoạn diệt các lậu hoặc, ngay trong hiện tại, với thắng trí, Ta chứng ngộ, chứng đạt và an trú vô lậu tâm giải thoát, tuệ giải thoát.`, ref: "Tăng Chi Bộ 4.35", url: "https://loicuaducphat.org/an/an4.35.html#content" },

{ text: `Ai trong mọi chúng sanh,\nHiểu rõ được giải thoát,\nKhỏi cạm bẫy thần chết,\nVì hạnh phúc nhân thiên,\nTuyên bố về chánh lý,\nTuyên bố về Chánh pháp.\nQuần chúng thấy nghe vậy,\nLiền hoan hỷ tịnh tín,\nThiện xảo đạo, phi đạo,\nViệc nên làm đã làm,\nVô lậu bậc Giác ngộ,\nVới thân này thân cuối,\nNgài được gọi tôn xưng,\nBậc Ðại tuệ, Ðại nhân.`, ref: "Tăng Chi Bộ 4.35", url: "https://loicuaducphat.org/an/an4.35.html#content" },

{ text: `Ví như, này Bà-la-môn, bông sen xanh, hay bông sen hồng, hay bông sen trắng, sanh ra trong nước, lớn lên trong nước, vươn lên khỏi nước, và đứng thẳng không bị nước thấm ướt. Cũng vậy, này Bà-la-môn sanh ta trong đời, lớn lên trong đời, Ta sống chinh phục đời, không bị đời thấm ướt. Này Bà-la-môn, Ta là Phật, hãy như vậy thọ trì.`, ref: "Tăng Chi Bộ 4.36", url: "https://loicuaducphat.org/an/an4.36.html#content" },

{ text: `Tỷ-kheo an trú giới,\nSống chế ngự các căn,\nBiết tiết độ ăn uống,\nVà chú tâm cảnh giác,\nSống an trú như vậy,\nNgày đêm không mệt mỏi\nTu tập các thiện pháp,\nÐạt an ổn ách nạn,\nƯa thích không phóng dật,\nThấy sợ hãi phóng dật,\nKhông có thể thối đọa,\nTỷ-kheo gần Niết-bàn.`, ref: "Tăng Chi Bộ 4.37", url: "https://loicuaducphat.org/an/an4.37.html#content" },

{ text: `Này các Tỷ-kheo, có bốn định tu tập này. Thế nào là bốn? Có định tu tập, này các Tỷ-kheo, do tu tập, do làm cho sung mãn, đưa đến hiện tại lạc trú. Có định tu tập, này các Tỷ-kheo, do tu tập, do làm cho sung mãn, đưa đến chứng được tri kiến. Có định tu tập, này các Tỷ-kheo, do tu tập, do làm cho sung mãn, đưa đến chánh niệm tỉnh giác. Có định tu tập, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến đoạn tận các lậu hoặc.`, ref: "Tăng Chi Bộ 4.41", url: "https://loicuaducphat.org/an/an4.41.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là định tu tập, do tu tập, do làm cho sung mãn, đưa đến chánh niệm tỉnh giác? Ở đây, này các Tỷ-kheo, với vị Tỷ-kheo, thọ khởi lên được rõ biết, thọ an trú được rõ biết, thọ chấm dứt được rõ biết; tưởng khởi lên được rõ biết, tưởng an trú được rõ biết, tưởng chấm dứt được rõ biết; tầm khởi lên được rõ biết, tầm an trú được rõ biết, tầm chấm dứt được rõ biết. Này các Tỷ-kheo, đây gọi là định tu tập, do tu tập, do làm cho sung mãn, đưa đến chánh niệm tỉnh giác.`, ref: "Tăng Chi Bộ 4.41", url: "https://loicuaducphat.org/an/an4.41.html#content" },

{ text: `Bốn hạng người này, này các Tỷ-kheo, có mặt, hiện hữu ở đời. Thế nào là bốn? Kính trọng phẫn nộ, không kính trọng diệu pháp; kính trọng gièm pha, không kính trọng diệu pháp; kính trọng lợi dưỡng, không kính trọng diệu pháp; kính trọng cung kính, không kính trọng diệu pháp.`, ref: "Tăng Chi Bộ 4.43", url: "https://loicuaducphat.org/an/an4.43.html#content" },

{ text: `Bốn hạng người này, này các Tỷ-kheo, có mặt, hiện hữu ở đời. Thế nào là bốn? Kính trọng diệu pháp, không kính trọng phẫn nộ; kính trọng diệu pháp, không kính trọng gièm pha; kính trọng diệu pháp, không kính trọng lợi dưỡng; kính trọng diệu pháp, không kính trọng cung kính.`, ref: "Tăng Chi Bộ 4.43", url: "https://loicuaducphat.org/an/an4.43.html#content" },

{ text: `Các Tỷ-kheo kính trọng,\nPhẫn nộ và gièm pha,\nKính trọng các lợi dưỡng,\nKính trọng sự cung kính,\nVị ấy không lớn mạnh,\nTrong pháp đức Phật thuyết,\nAi hiện sống, đã sống,\nKính trọng Chánh diệu pháp,\nCác vị ấy lớn mạnh\nTrong pháp đức Phật thuyết.`, ref: "Tăng Chi Bộ 4.43", url: "https://loicuaducphat.org/an/an4.43.html#content" },

{ text: `Này Hiền giả, Ta tuyên bố rằng: “Tại chỗ nào không bị sanh, không bị già, không bị chết, không có từ bỏ (đời này), không có sanh khởi (đời khác), không có thể đi đến để thấy, để biết, để đạt đến chỗ tận cùng của thế giới”. Nhưng này Hiền giả, trong cái thân dài độ mấy tấc này, với những tưởng, những tư duy của nó, Ta tuyên bố về thế giới, về thế giới tập khởi, về thế giới đoạn diệt, về con đường đưa đến thế giới đoạn diệt.`, ref: "Tăng Chi Bộ 4.45", url: "https://loicuaducphat.org/an/an4.45.html#content" },

{ text: `Với đi, không bao giờ,\nÐạt tận cùng thế giới.\nNếu không, không đạt được,\nChỗ tận cùng thế giới,\nThời không có giải thoát,\nRa khỏi ngoài khổ đau.\nDo vậy, bậc có trí,\nHiểu biết rõ thế giới,\nÐi tận cùng thế giới,\nVới Phạm hạnh thành tựu,\nBậc đạt được an tịnh,\nBiết tận cùng thế giới,\nKhông mong cầu đời này,\nKhông mong cầu đời sau.`, ref: "Tăng Chi Bộ 4.45", url: "https://loicuaducphat.org/an/an4.45.html#content" },

{ text: `Này các Tỷ-kheo, có bốn sự việc này, rất xa, rất xa với nhau. Thế nào là bốn? Trời và đất, này các Tỷ-kheo, là sự việc thứ nhất rất xa, rất xa với nhau. Bờ biển bên này, này các Tỷ-kheo với bờ biển bên kia, là sự việc thứ hai rất xa, rất xa với nhau. Từ chỗ mặt trời mọc lên, này các Tỷ-kheo, đến chỗ mặt trời lặn xuống, là sự việc thứ ba rất xa, rất xa với nhau. Pháp của hạng người bất thiện, này các Tỷ-kheo, với pháp của hạng người thiện, là sự việc thứ tư rất xa, rất xa với nhau.`, ref: "Tăng Chi Bộ 4.47", url: "https://loicuaducphat.org/an/an4.47.html#content" },

{ text: `Nếu vị ấy không nói,\nChúng không biết vị ấy,\nNhư vậy bậc Hiền trí,\nLẫn lộn với kẻ ngu,\nNếu vị ấy nói lên,\nChúng biết đến vị ấy,\nKhi vị ấy thuyết giảng,\nCon đường đến bất tử,\nVậy hãy thuyết giảng lên,\nChói sáng chơn diệu pháp,\nHãy dâng cao ngọn cờ,\nNgọn cờ các ẩn sĩ,\nKhéo nói là ngọn cờ,\nCủa các bậc ẩn sĩ,\nVà pháp là ngọn cờ,\nCủa những bậc ẩn sĩ.`, ref: "Tăng Chi Bộ 4.48", url: "https://loicuaducphat.org/an/an4.48.html#content" },

{ text: `Này các Tỷ-kheo, có bốn tưởng điên đảo, tâm điên đảo, kiến điên đảo này. Thế nào là bốn? Trong vô thường, nghĩ là thường, này các Tỷ-kheo, đó là tưởng điên đảo, tâm điên đảo, kiến điên đảo. Trong khổ nghĩ là không khổ, này các Tỷ-kheo, đó là tưởng điên đảo, tâm điên đảo, kiến điên đảo. Trong vô ngã, nghĩ là ngã, này các Tỷ-kheo, đó là tưởng điên đảo, tâm điên đảo, kiến điên đảo. Trong không thanh tịnh, nghĩ là thanh tịnh, này các Tỷ-kheo, đó là tưởng điên đảo, tâm điên đảo, kiến điên đảo.`, ref: "Tăng Chi Bộ 4.49", url: "https://loicuaducphat.org/an/an4.49.html#content" },

{ text: `Có Sa-môn, Phạm chí,\nBị tham sân trói buộc,\nBị vô minh bao phủ,\nLoài người ưa sắc đẹp,\nUống rượu men rượu nấu,\nHưởng thụ pháp dâm dục,\nMê hoặc, họ chấp nhận,\nNhận lấy vàng và bạc,\nCác Sa-môn, Phạm chí,\nSinh sống theo tà mạng.\nPhật, bà con mặt trời\nNói đến uế nhiễm ấy,\nBị ô nhiễm bởi chúng,\nCác Sa-môn, Phạm chí,\nKhông cháy sang, chói sáng,\nÁnh sáng bụi ô nhiễm,\nBao phủ bởi tối tăm,\nNô lệ bởi ái dục,\nBị ái kéo, dắt dẫn,\nHọ làm đầy dẫy thêm,\nBãi tha ma ghê tởm,\nChúng lại phải tái sanh.`, ref: "Tăng Chi Bộ 4.50", url: "https://loicuaducphat.org/an/an4.50.html#content" },

{ text: `Biển lớn không hạn lượng,\nHồ lớn nhiều sợ hãi,\nLà kho tàng cất giữ,\nVô số lượng châu báu,\nCũng là chỗ trú ẩn,\nVô số các loại cá,\nLà chỗ các sóng lớn,\nQuy tụ chảy ra biển,\nCũng vậy người bố thí,\nÐồ ăn và đồ uống,\nVải mặc và giường nằm,\nChỗ ngồi và thảm nệm,\nBậc Hiền thí như vậy,\nPhước đức ùa chảy đến,\nNhư sông dẫn dòng nước,\nÙa chảy vào bể cả.`, ref: "Tăng Chi Bộ 4.51", url: "https://loicuaducphat.org/an/an4.51.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo trong khi hưởng thọ y của ai... hưởng thọ đồ ăn khất thực của ai... hưởng thọ trú xứ của ai... hưởng thọ dược phẩm trị bệnh của ai, nếu vị ấy đạt đến và an trú vô lượng tâm định, như vậy là nguồn sanh phước vô lượng cho người bố thí, là nguồn sanh thiện đem lại an lạc, thuộc Thiên giới, là quả lạc dị thục, dẫn đến cõi Trời, đưa đến khả lạc, khả hỷ, khả ý, hạnh phúc, an lạc.`, ref: "Tăng Chi Bộ 4.51", url: "https://loicuaducphat.org/an/an4.51.html#content" },

{ text: `Này các Tỷ-kheo, vị Thánh đệ tử thành tựu bốn nguồn sanh phước, nguồn sanh thiện này, thời không dễ gì để nắm lấy một số lượng phước thiện, và nói rằng: “Có chừng ấy nguồn sanh phước, nguồn sanh thiện, đem lại an lạc, thuộc thiên giới, là quả lạc dị thục đem đến cõi trời, đưa đến khả lạc, khả hỷ, khả ý, hạnh phúc, an lạc”; vì rằng cả khối phước thiện lớn được xem là vô số vô lượng.`, ref: "Tăng Chi Bộ 4.51", url: "https://loicuaducphat.org/an/an4.51.html#content" },

{ text: `Ai tin tưởng Như Lai,\nBất động, khéo an trú,\nAi tin giới, hiền thiện,\nBậc Thánh khen, mến chuộng.\nAi tịnh tín chúng Tăng,\nVới cái nhìn chánh trực,\nNgười ấy được họ gọi,\nKhông phải là người nghèo.\nÐời sống người như vậy,\nKhông phải đời trống rỗng,\nDo vậy tín và giới,\nTịnh tín và thắng pháp,\nBậc trí chú tâm niệm,\nLời dạy của chư Phật.`, ref: "Tăng Chi Bộ 4.52", url: "https://loicuaducphat.org/an/an4.52.html#content" },

{ text: `Các Thánh nữ đệ tử khi bố thí đồ ăn, này Suppavàsà, bố thí bốn sự cho những người nhận. Thế nào là bốn? Cho thọ mạng, cho dung sắc, cho an lạc, cho sức mạnh. Sau khi cho thọ mạng, người cho được chia phần thọ mạng, thuộc cõi Trời hay cõi Người. Sau khi cho dung sắc, người cho được chia phần dung sắc, thuộc cõi Trời hay cõi Người. Sau khi cho an lạc, người cho được chia phần an lạc, hoặc thuộc cõi Trời, hoặc thuộc cõi Người. Sau khi cho sức mạnh, người cho được chia phần sức mạnh, thuộc cõi Trời, hay cõi Người. Này Suppavàsà, khi Thánh nữ đệ tử bố thí đồ ăn, bố thí bốn sự này cho những người nhận.`, ref: "Tăng Chi Bộ 4.57", url: "https://loicuaducphat.org/an/an4.57.html#content" },
{ text: `Những ai khéo chế ngự,\nSống bố thí người khác,\nAi tùy thời nhiệt thành,\nBố thí đồ ăn uống,\nÐem lại cho các vị,\nBốn sự kiện như sau,\nCho thọ mạng, dung sắc,\nCho an lạc, sức mạnh,\nVị bố thí thọ mạng,\nVị bố thí dung sắc,\nNgười bố thí an lạc,\nNgười bố thí sức mạnh,\nThọ mạng dài, danh xưng,\nDầu sanh tại chỗ nào.`, ref: "Tăng Chi Bộ 4.59", url: "https://loicuaducphat.org/an/an4.59.html#content" },

{ text: `Này Gia chủ, Thánh đệ tử ấy, sau khi biết được dục tham là uế nhiễm của tâm, từ bỏ dục tham, uế nhiễm của tâm; sau khi biết được sân hận là uế nhiễm của tâm, từ bỏ sân hận, uế nhiễm của tâm; sau khi biết được hôn trầm thụy miên là uế nhiễm của tâm, từ bỏ hôn trầm thụy miên, uế nhiễm của tâm; sau khi biết được trạo hối là uế nhiễm của tâm, từ bỏ trạo hối, uế nhiễm của tâm; sau khi biết được nghi là uế nhiễm của tâm, từ bỏ nghi, uế nhiễm của tâm; này Gia chủ, đây gọi là vị Thánh đệ tử có đại trí tuệ, có trí tuệ rộng lớn, bước vào giới vức minh kiến, đầy đủ trí tuệ. Ðây gọi là đầy đủ trí tuệ.`, ref: "Tăng Chi Bộ 4.61", url: "https://loicuaducphat.org/an/an4.61.html#content" },

{ text: `Những gia đình nào, này các Tỷ-kheo, các cha mẹ được các con đảnh lễ cúng dường ở trong nhà, những gia đình ấy được xem là giống như Phạm thiên. Những gia đình nào, này các Tỷ-kheo, các cha mẹ được các con đảnh lễ cúng dường ở trong nhà, những gia đình ấy được xem là giống như bậc Ðạo sư thời xưa. Những gia đình nào, này các Tỷ-kheo, các cha mẹ được các con đảnh lễ cúng dường ở trong nhà, những gia đình ấy, này các Tỷ-kheo, được xem là giống như chư Thiên thời trước. Những gia đình nào, này các Tỷ-kheo, các cha mẹ được các con đảnh lễ cúng dường ở trong nhà, những gia đình ấy được xem là đáng được cúng dường.`, ref: "Tăng Chi Bộ 4.62", url: "https://loicuaducphat.org/an/an4.62.html#content" },

{ text: `Phạm Thiên, này các Tỷ-kheo, là đồng nghĩa với mẹ cha; các bậc Ðạo sư thời xưa, này các Tỷ-kheo, là đồng nghĩa với mẹ cha; chư Thiên thuở xưa, này các Tỷ-kheo, là đồng nghĩa với mẹ cha; đáng được cung kính cúng dường, này các Tỷ-kheo, là đồng nghĩa với mẹ cha. Vì cớ sao? Này các Tỷ-kheo, vì mẹ cha giúp đỡ rất nhiều cho các con, nuôi dưỡng chúng lớn và giới thiệu chúng vào đời này.`, ref: "Tăng Chi Bộ 4.62", url: "https://loicuaducphat.org/an/an4.62.html#content" },

{ text: `Tham ái vật đẹp đẽ,\nThích thú sắc khả ái,\nBị cột bởi vô minh,\nCác hữu tình hạ liệt,\nCàng tăng trưởng trói buộc.\nCho đến kẻ có trí,\nLàm các việc bất thiện,\nSanh từ tham, sân, si,\nKhiến phiền muộn, khó chịu,\nLàm đau khổ sanh khởi,\nKẻ vô minh bao vây,\nKẻ mù không có mắt,\nTự tánh họ là vậy,\nHọ không thể nghĩ rằng,\nTa có thể như vậy.`, ref: "Tăng Chi Bộ 4.66", url: "https://loicuaducphat.org/an/an4.66.html#content" },

{ text: `Ðem đến hại mình, này các Tỷ-kheo, khi lợi dưỡng, cung kính, danh vọng khởi lên cho Devadatta; đem đến bất hạnh cho người, này các Tỷ-kheo, khi lợi dưỡng, cung kính, danh vọng khởi lên cho Devadatta! Ví như, này các Tỷ-kheo, một cây chuối khi sanh ra trái, đem đến hại mình; khi sanh ra trái, đem đến bất hạnh cho người khi sanh ra trái. Cũng vậy, này các Tỷ-kheo, đem đến hại mình khi lợi dưỡng, cung kính, danh vọng khởi lên cho Devadatta, đem đến bất hạnh cho người khi lợi dưỡng, cung kính, danh vọng khởi lên cho Devadatta. Ví như, này các Tỷ-kheo, cây tre đem đến hại mình khi sanh ra trái, đem đến bất hạnh cho người khi sanh ra trái. Cũng vậy, này các Tỷ-kheo, đem đến hại mình khi lợi dưỡng, cung kính, danh vọng khởi lên cho Devadatta.`, ref: "Tăng Chi Bộ 4.68", url: "https://loicuaducphat.org/an/an4.68.html#content" },


{ text: `Ở đây, này các Tỷ-kheo, bậc Chân nhân là người dầu có được hỏi, không nói lên lời không tán thán người khác; còn nói gì nếu không được hỏi! Nhưng nếu được hỏi, và phải trả lời, dè dặt và ngập ngừng, vị ấy không nói lên lời tán thán người khác. Cần phải được hiểu, này các Tỷ-kheo, vị này là bậc Chân nhân. Lại nữa, này các Tỷ-kheo, bậc Chân nhân là người dầu không được hỏi, cũng nói lên lời tán thán người khác; còn nói gì nếu được hỏi. Nếu được hỏi và phải trả lời, không dè dặt, không ngập ngừng, vị ấy nói lời tán thán người khác, đầy đủ và toàn bộ. Cần phải được hiểu, này các Tỷ-kheo, vị này là bậc Chân nhân.`, ref: "Tăng Chi Bộ 4.73", url: "https://loicuaducphat.org/an/an4.73.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, bậc Chân nhân là Người, nếu không được hỏi, vẫn nói lên lời không tán thán về mình; còn nói gì nếu được hỏi! Nếu được hỏi và phải trả lời, không dè dặt, không ngập ngừng, vị ấy nói lên lời không tán thán về mình, đầy đủ và toàn bộ. Cần phải được hiểu, này các Tỷ-kheo, vị này là bậc Chân nhân. Lại nữa, này các Tỷ-kheo, bậc Chân nhân dầu có được hỏi cũng không nói lên lời tán thán về mình; còn nói gì nếu không được hỏi! Nếu được hỏi và phải trả lời, dè dặt và ngập ngừng, vị ấy nói lên lời tán thán về mình, không đầy đủ; không toàn bộ. Cần phải được hiểu, này các Tỷ-kheo, vị này là bậc Chân nhân.`, ref: "Tăng Chi Bộ 4.73", url: "https://loicuaducphat.org/an/an4.73.html#content" },

{ text: `Ví như, này các Tỷ-kheo, người vợ trẻ, trong đêm hay ngày, được đưa về nhà chồng, nàng cảm thấy hết sức xấu hổ, sợ hãi trước mặt mẹ chồng, cha chồng, trước mặt chồng, cho đến trước mặt các người phục vụ, làm công. Sau một thời gian, do chung sống, do thân mật, nàng có thể nói với mẹ chồng, với cha chồng, với chồng: “Hãy đi đi, các người có biết được gì!”. Cũng vậy, này các Tỷ-kheo, ở đây có Tỷ-kheo, trong đêm hay ngày được xuất gia, từ bỏ gia đình sống không gia đình, cảm thấy hết sức xấu hổ, sợ hãi trước mặt các Tỷ-kheo, Tỷ-kheo-ni, nam cư sĩ, nữ cư sĩ, cho đến trước những người làm vườn và những Sa-di. Sau một thời gian, do chung sống, do thân mật, vị ấy có thể nói với sư A-xà-lê, với sư Giáo thọ: “Hãy đi đi, các người có thể biết được gì!”.`, ref: "Tăng Chi Bộ 4.74", url: "https://loicuaducphat.org/an/an4.74.html#content" },

{ text: `Có bốn điều này không thể nghĩ đến được, này các Tỷ-kheo, nếu nghĩ đến, thời người suy nghĩ có thể đi đến cuồng loạn và thống khổ. Thế nào là bốn? Phật giới của các đức Phật, này các Tỷ-kheo, không thể nghĩ đến được, nếu nghĩ đến, thời người suy nghĩ có thể đi đến cuồng loạn và thống khổ. Thiền giới của người ngồi Thiền, này các Tỷ-kheo, không thể nghĩ được, nếu nghĩ... thống khổ. Quả dị thục của nghiệp, này các Tỷ-kheo, không thể nghĩ đến được, nếu nghĩ đến... thống khổ. Tâm tư thế giới, này các Tỷ-kheo, không thể nghĩ đến được, nếu nghĩ đến thời có thể đi đến cuồng loạn và thống khổ.`, ref: "Tăng Chi Bộ 4.77", url: "https://loicuaducphat.org/an/an4.77.html#content" },
{ text: `Ví như, này các Tỷ-kheo, khi khăn bị cháy hay đầu bị cháy, và để dập tắt khăn và đầu, cần phải thực hiện tăng thượng ý muốn, tinh tấn, cố gắng, nỗ lực, tâm không thối chuyển, chánh niệm, tỉnh giác. Cũng vậy, này các Tỷ-kheo, người ấy, để chứng đắc các thiện pháp ấy, cần phải thực hiện tăng thượng ý muốn, tinh tấn, cố gắng, nỗ lực, tâm không thối chuyển, chánh niệm, tỉnh giác. Sau một thời gian, vị ấy thành người có được nội tâm chỉ và tăng thượng tuệ pháp quán. Tại đấy, này các Tỷ-kheo, hạng người này có được nội tâm chỉ, có được tăng thượng tuệ pháp quán, người ấy, này các Tỷ-kheo, sau khi an trú trong các thiện pháp ấy, cần phải chú tâm tu tập hơn nữa để đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 4.93", url: "https://loicuaducphat.org/an/an4.93.html#content" },

{ text: `Tại đấy, này các Tỷ-kheo, hạng người này không chứng được nội tâm chỉ, không chứng được tăng thượng tuệ pháp quán. Người này, này các Tỷ-kheo, sau khi đi đến hạng người chứng nội tâm chỉ, chứng được tăng thượng tuệ pháp quán, người này cần phải nói như sau: “Thưa Hiền giả, tâm cần phải an lập thế nào? Tâm cần phải an trú thế nào? Tâm cần phải nhứt tâm thế nào? Tâm cần phải định tĩnh thế nào? Các hành cần phải thấy thế nào? Các hành cần phải biết thế nào? Các hành cần phải quán thế nào?” Người ấy trả lời cho vị này: “Như đã được thấy, như đã được biết, như vậy, này Hiền giả, tâm cần phải an lập; như vậy, tâm cần phải an trú. Như vậy, tâm cần phải nhứt tâm; như vậy, tâm cần phải định tĩnh; như vậy, các hành cần phải thấy; như vậy, các hành cần phải biết; như vậy, các hành cần phải quán”. Vị ấy, sau một thời gian chứng được nội tâm chỉ, chứng được tăng thượng tuệ pháp quán. Vị này, này các Tỷ-kheo, sau khi an trú trong các thiện pháp, cần phải tu tập chú tâm vào sự đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 4.94", url: "https://loicuaducphat.org/an/an4.94.html#content" },

{ text: `Trong bốn trường hợp, này các Tỷ-kheo, cần phải không phóng dật. Thế nào là bốn? Hãy từ bỏ thân làm ác, này các Tỷ-kheo, hãy tu tập thân làm lành, và ở đây chớ có phóng dật. Hãy từ bỏ lời nói ác, này các Tỷ-kheo, hãy tu tập lời nói lành, và ở đây chớ có phóng dật. Hãy từ bỏ ý nghĩ ác, này các Tỷ-kheo, hãy tu tập ý nghĩ lành, và ở đây chớ có phóng dật. Hãy từ bỏ tà kiến, này các Tỷ-kheo, hãy tu tập chánh kiến, và ở đây chớ có phóng dật.`, ref: "Tăng Chi Bộ 4.116", url: "https://loicuaducphat.org/an/an4.116.html#content" },

{ text: `Khi nào, này các Tỷ-kheo, Tỷ-kheo đối với các pháp khiến cho tham đắm, tâm không tham đắm, tự ngã được ly tham; đối với các pháp khiến cho sân hận, tâm không sân hận, tự ngã được ly sân; đối với các pháp khiến cho si mê, tâm không si mê, tự ngã được ly si; đối với các pháp khiến cho say đắm, tâm không say đắm, tự ngã được ly đắm say; thời vị ấy không có sợ hãi, không có dao động, không có hốt hoảng, không rơi vào hoảng sợ, không có đi do nhân các Sa-môn có nói gì.`, ref: "Tăng Chi Bộ 4.117", url: "https://loicuaducphat.org/an/an4.117.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người suy xét: “Nếu thân ta làm ác, lời nói ta ác, ý nghĩa ta ác, thời tự ngã có thể trách ta về phương diện giới: “Sao lại làm nghiệp ấy?”. Người ấy do sợ hãi tự trách, đoạn tận thân làm ác, tu tập thân làm lành, đoạn tận lời nói ác, tu tập lời nói lành, đoạn tận ý nghĩ ác, tu tập ý nghĩ lành; sống tự ngã trong sạch. Này các Tỷ-kheo, đây gọi là sợ hãi tự trách.`, ref: "Tăng Chi Bộ 4.121", url: "https://loicuaducphat.org/an/an4.121.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người suy xét: “Nếu thân ta làm ác, lời nói ta ác, ý nghĩ ta ác, thời các người khác có thể trách ta về phương diện giới: “Sao lại làm nghiệp ấy?”. Người ấy do sợ hãi người khác trách, đoạn tận thân làm ác, tu tập thân làm lành, đoạn tận lời nói ác, tu tập lời nói lành, đoạn tận ý nghĩ ác, tu tập ý nghĩ lành; sống tự ngã trong sạch. Này các Tỷ-kheo, đây gọi là sợ hãi người khác trách.`, ref: "Tăng Chi Bộ 4.121", url: "https://loicuaducphat.org/an/an4.121.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người suy nghĩ như sau: “Với ai thân làm ác, có ác dị thục trong tương lai, với ai lời nói ác ... với ai ý nghĩ ác, có ác dị thục trong tương lai. Làm thế nào cho ta sau khi thân hoại mạng chung, không có sanh tại cõi dữ, ác thú, đọa xứ, địa ngục?”. Người ấy vì sợ hãi ác thú, đoạn tận thân làm ác, tu tập thân làm lành; đoạn tận lời nói ác, tu tập lời nói lành; đoạn tận ý nghĩ ác, tu tập ý nghĩ lành; sống với tự ngã trong sạch. Này các Tỷ-kheo, đây gọi là sợ hãi ác thú.`, ref: "Tăng Chi Bộ 4.121", url: "https://loicuaducphat.org/an/an4.121.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có thiện nam tử vì lòng tin xuất gia, từ bỏ gia đình, sống không gia đình. Vị ấy suy nghĩ như sau: “Ta bị sanh, già, chết, sầu, bi, khổ, ưu, não áp bức, bị khổ áp bức, bị khổ chi phối. Tuy vậy, ta mong có thể thấy được sự chấm dứt toàn bộ khổ uẩn này”. Khi được xuất gia như vậy, vị này buổi sáng đắp y, cầm y bát, đi vào làng hay thị trấn để khất thực, không phòng hộ thân, không phòng hộ lời, không phòng hộ tâm, niệm không an trú, các căn không chế ngự. Vị này thấy ở đây những phụ nữ mặc y phục không đoan chánh hay đắp y phục không đoan chánh. Khi thấy những phụ nữ mặc y phục không đoan chánh hay đắp y phục không đoan chánh, ái dục phá hoại tâm của vị ấy. Vị này, tâm bị ái dục phá hoại, từ bỏ học tập, trở về hoàn tục. Này các Tỷ-kheo, đây gọi là vị Tỷ-kheo bị sợ hãi bởi sự sợ hãi về cá dữ, từ bỏ học tập, trở về hoàn tục. Này các Tỷ-kheo, sợ hãi về cá dữ là đồng nghĩa với phụ nữ. Này các Tỷ-kheo, đây gọi là sợ hãi về cá dữ.`, ref: "Tăng Chi Bộ 4.122", url: "https://loicuaducphat.org/an/an4.122.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có hạng người ly dục, ly ác pháp, chứng đạt và an trú Thiền thứ nhất. Ở đây, về các pháp thuộc sắc, thuộc thọ, thuộc tưởng, thuộc hành, thuộc thức, vị ấy tùy quán là vô thường, là khổ, là bệnh, là ung nhọt, là mũi tên, là bất hạnh, là bệnh hoạn, là hướng ngoại, là hoại diệt, là trống không, là vô ngã. Vị ấy, sau khi thân hoại mạng chung được sanh cộng trú với chư Thiên ở Tịnh cư Thiên. Sự sanh khởi này, này các Tỷ-kheo, không có chung cùng với các hàng phàm phu.`, ref: "Tăng Chi Bộ 4.124", url: "https://loicuaducphat.org/an/an4.124.html#content" },

{ text: `Này các Tỷ-kheo, quần chúng ưa thích chấp giữ, thích thú chấp giữ, hoan hỷ chấp giữ, khi pháp không chấp giữ được Như Lai thuyết giảng, họ khéo nghe, lắng tai, chánh trí an trú tâm. Này các Tỷ-kheo, khi Như Lai, bậc A-la-hán, Chánh Ðẳng Giác xuất hiện, đây là sự vi diệu chưa từng có thứ nhất xuất hiện.`, ref: "Tăng Chi Bộ 4.128", url: "https://loicuaducphat.org/an/an4.128.html#content" },

{ text: `Này các Tỷ-kheo, quần chúng ưa thích kiêu mạn, thích thú kiêu mạn, hoan hỷ kiêu mạn, khi pháp không kiêu mạn được Như Lai thuyết giảng, họ khéo nghe, lắng tai, chánh trí an trú tâm. Này các Tỷ-kheo, khi Như Lai, bậc A-la-hán, Chánh Ðẳng Giác xuất hiện, đây là sự vi diệu chưa từng có thứ hai xuất hiện.`, ref: "Tăng Chi Bộ 4.128", url: "https://loicuaducphat.org/an/an4.128.html#content" },

{ text: `Này các Tỷ-kheo, quần chúng ưa thích không an tịnh, thích thú không an tịnh, hoan hỷ không an tịnh, khi pháp an tịnh được Như Lai thuyết giảng, họ khéo nghe, lắng tai, chánh trí an trú tâm. Này các Tỷ-kheo, khi Như Lai, bậc A-la-hán, Chánh Ðẳng Giác xuất hiện, đây là sự vi diệu chưa từng có thứ ba xuất hiện.`, ref: "Tăng Chi Bộ 4.128", url: "https://loicuaducphat.org/an/an4.128.html#content" },

{ text: `Này các Tỷ-kheo, quần chúng đi đến vô minh, trở thành mù quáng, bị trói buộc che đậy, khi Như Lai thuyết pháp nhiếp phục vô minh, họ khéo nghe, lắng tai, chánh trí an trú tâm. Này các Tỷ-kheo, khi Như Lai, bậc A-la-hán, Chánh Ðẳng Giác xuất hiện, đây là sự vi diệu chưa từng có thứ tư xuất hiện.`, ref: "Tăng Chi Bộ 4.128", url: "https://loicuaducphat.org/an/an4.128.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là thân viễn ly, tâm không viễn ly? Ở đây, này các Tỷ-kheo, các hạng người sống tại các núi non, khóm rừng, các trú xứ xa vắng; vị ấy nghĩ đến dục tầm, nghĩ đến sân tầm, nghĩ đến hại tầm. Như vậy, này các Tỷ-kheo, là hạng người thân viễn ly, nhưng tâm không viễn ly.`, ref: "Tăng Chi Bộ 4.138", url: "https://loicuaducphat.org/an/an4.138.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là thân không viễn ly, nhưng tâm viễn ly? Ở đây, này các Tỷ-kheo, các hạng người không sống tại các núi non, khóm rừng, các trú xứ xa vắng; vị ấy tại đó nghĩ đến tầm xuất ly, nghĩ đến tầm vô sân, nghĩ đến tầm bất hại. Như vậy, này các Tỷ-kheo, là hạng người thân không viễn ly, nhưng tâm viễn ly.`, ref: "Tăng Chi Bộ 4.138", url: "https://loicuaducphat.org/an/an4.138.html#content" },

{ text: `Này các Tỷ-kheo, có bốn loại ánh sáng. Thế nào là bốn? Ánh sáng mặt trăng, ánh sáng mặt trời, ánh sáng ngọn lửa, ánh sáng trí tuệ. Này các Tỷ-kheo, có bốn loại ánh sáng này. Và này các Tỷ-kheo, loại tối thượng trong bốn loại ánh sáng là ánh sáng trí tuệ.`, ref: "Tăng Chi Bộ 4.142", url: "https://loicuaducphat.org/an/an4.142.html#content" },

{ text: `Có bốn thời gian này, này các Tỷ-kheo, nếu khéo tu tập, nếu khéo vận chuyển, tuần tự đưa đến sự đoạn diệt các lậu hoặc. Thế nào là bốn? Nghe pháp đúng thời, đàm luận về pháp đúng thời, chỉ đúng thời, quán đúng thời. Bốn thời gian này, này các Tỷ-kheo, nếu khéo tu tập, khéo vận chuyển, tuần tự đưa đến sự đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 4.147", url: "https://loicuaducphat.org/an/an4.147.html#content" },

{ text: `Này các Tỷ-kheo, có hai loại bệnh này. Thế nào là hai? Bệnh về thân và bệnh về tâm. Này các Tỷ-kheo, Ta thấy có chúng sanh tự nhận mình là không thân bệnh được một năm, tự nhận mình là không thân bệnh được hai năm, được ba ... được bốn ... được năm ... được mười ... được hai mươi ... được ba mươi ... được bốn mươi ... tự nhận mình là không thân bệnh được năm mươi năm, tự nhận mình là không thân bệnh được một trăm năm. Các chúng sanh ấy, này các Tỷ-kheo, rất khó tìm được ở đời là những chúng sanh tự nhận mình là không tâm bệnh dầu chỉ trong một khoảnh khắc, trừ những vị đã đoạn trừ các lậu hoặc.`, ref: "Tăng Chi Bộ 4.157", url: "https://loicuaducphat.org/an/an4.157.html#content" },

{ text: `Này các Tỷ-kheo, có bốn loại bệnh này cho người xuất gia. Thế nào là bốn? Ở đây, này các Tỷ-kheo, người có dục lớn, bực bội tức tối, không tự bằng lòng với các đồ vật như y, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh. Người ấy vì nhiều dục lớn, bực bội tức tối, không tự bằng lòng với các vật dụng như y, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh, khởi lên thèm khát, ác dục, muốn được các điều không được tán thán, muốn được các lợi dưỡng, cung kính, danh vọng. Vị ấy nỗ lực, cố gắng, tinh tấn để được các điều không được tán thán, muốn được các lợi dưỡng, cung kính, danh vọng. Vị ấy sau khi tính toán, đi đến các gia đình; sau khi tính toán, ngồi xuống; sau khi tính toán, thuyết pháp; sau khi tính toán, ngưng nín tiểu tiện, đại tiện. Như vậy, này các Tỷ-kheo, là bốn chứng bệnh của người xuất gia.`, ref: "Tăng Chi Bộ 4.157", url: "https://loicuaducphat.org/an/an4.157.html#content" },

{ text: `Thưa các Hiền giả, Tỷ-kheo hay Tỷ-kheo-ni nào thấy trên tự thân có bốn pháp này, cần phải đi đến kết luận rằng: “Tôi thối đọa khỏi các thiện pháp “. Ðây được Thế Tôn gọi là thối đọa. Thế nào là bốn? Tham ái tăng thịnh, sân tăng thịnh, si tăng thịnh, đối với các vấn đề có mặt, không có mặt, không có tuệ nhãn soi thấu. Thưa các Hiền giả, Tỷ-kheo hay Tỷ-kheo-ni nào thấy trên tự thân có bốn pháp này, cần phải đi đến kết luận rằng: “Tôi thối đọa khỏi các thiện pháp “. Ðây được Thế Tôn gọi là thối đọa.`, ref: "Tăng Chi Bộ 4.158", url: "https://loicuaducphat.org/an/an4.158.html#content" },
{ text: `Này các Tỷ-kheo, các Trưởng lão Tỷ-kheo là những vị sống đầy đủ, lười biếng, dẫn đầu về đọa lạc, bỏ rơi gánh nặng sống viễn ly, không cố gắng tinh tấn để đạt được những gì chưa đạt được, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ. Và những thế hệ sau tiếp nối theo tà kiến của họ. Thế hệ ấy cũng sống đầy đủ, lười biếng, dẫn đầu về đọa lạc, bỏ rơi gánh nặng sống viễn ly, không cố gắng tinh tấn để đạt được những gì chưa đạt được, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ. Này các Tỷ-kheo, đây là pháp thứ tư đưa đến Diệu pháp hỗn loạn và biến mất.`, ref: "Tăng Chi Bộ 4.160", url: "https://loicuaducphat.org/an/an4.160.html#content" },

{ text: `Này các Tỷ-kheo, có bốn đạo hành này. Thế nào là bốn? Ðạo hành khổ, thắng trí chậm; Ðạo hành khổ, thắng trí nhanh; Ðạo hành lạc, thắng trí chậm; Ðạo hành lạc, thắng trí nhanh. Này các Tỷ-kheo, cố bốn đạo hành này.`, ref: "Tăng Chi Bộ 4.161", url: "https://loicuaducphat.org/an/an4.161.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là đạo hành khổ, thắng trí chậm? Ở đây, có người bản tánh tham dục rất cường thịnh, luôn luôn cảm thọ khổ ưu do tham dục sanh; bản tánh sân rất cường thịnh, luôn luôn cảm thọ khổ ưu do sân hận sanh; bản tánh si rất cường thịnh, luôn luôn cảm thọ khổ ưu do si sanh. Với người ấy, năm căn này hiện ra rất mềm yếu, tín căn, tấn căn, niệm căn, định căn, tuệ căn. Do năm căn này mềm yếu, người ấy đạt được Vô gián định một cách chậm chạp để đoạn diệt các lậu hoặc. Này các Tỷ-kheo, đây gọi là đạo hành khổ, thắng trí chậm.`, ref: "Tăng Chi Bộ 4.162", url: "https://loicuaducphat.org/an/an4.162.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là đạo hành không kham nhẫn? Ở đây, này các Tỷ-kheo, có hạng người chưởi mắng lại kẻ đã chưởi mắng, sân hận lại với kẻ đã sân hận, gây lộn lại với kẻ đã gây lộn. Này các Tỷ-kheo, đây gọi là đạo hành không kham nhẫn.`, ref: "Tăng Chi Bộ 4.164", url: "https://loicuaducphat.org/an/an4.164.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là đạo hành kham nhẫn? Ở đây, này các Tỷ-kheo, có hạng người không nhiếc mắng lại kẻ đã nhiếc mắng, không sân hận lại kẻ đã sân hận, không gây lộn lại với kẻ đã gây lộn. Này các Tỷ-kheo, đây gọi là đạo hành kham nhẫn.`, ref: "Tăng Chi Bộ 4.164", url: "https://loicuaducphat.org/an/an4.164.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là đạo hành nhiếp phục? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi mắt thấy sắc, không nắm giữ tướng chung, không nắm giữ tướng riêng. Phàm do nhân duyên gì với nhãn căn này không được chế ngự, khiến cho tham ái, ưu bi, các ác bất thiện khởi lên, vị ấy chế ngự nguyên nhân ấy, hộ trì nhãn căn, sống với sự chế ngự nhãn căn. Khi tai nghe tiếng ... khi mũi ngửi hương ... khi lưỡi nếm vị ... khi thân cảm xúc ... khi ý biết pháp, không nắm giữ tướng chung, không nắm giữ tướng riêng. Phàm do nhân duyên gì ý căn này không được chế ngự, khiến cho tham ái, ưu bi, các ác bất thiện khởi lên, vị ấy chế ngự nguyên nhân ấy, thọ trì ý căn, sống với sự chế ngự ý căn. Này các Tỷ-kheo, đây gọi là đạo hành nhiếp phục.`, ref: "Tăng Chi Bộ 4.164", url: "https://loicuaducphat.org/an/an4.164.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào gọi là đạo hành an tịnh? Ở đây, này các Tỷ-kheo, Tỷ-kheo không có chấp nhận dục tầm khởi lên, từ bỏ, tẩy sạch, làm cho an tịnh, chấm dứt, khiến đi đến không sanh hữu, không có chấp nhận sân tầm khởi lên ... không có chấp nhận hại tầm khởi lên ... không có chấp nhận các pháp ác bất thiện tầm khởi lên, từ bỏ, tẩy sạch, làm cho an tịnh, chấm dứt, khiến đi đến không sanh hữu. Này các Tỷ-kheo, đây gọi là đạo hành an tịnh.`, ref: "Tăng Chi Bộ 4.164", url: "https://loicuaducphat.org/an/an4.164.html#content" },

{ text: `Ở đây, này chư Hiền, Tỷ-kheo tu tập quán, có chỉ đi trước; do vị ấy tu tập quán có chỉ đi trước, con đường được sanh khởi. Vị ấy thực hành con đường ấy, tu tập, làm cho sung mãn. Do vị ấy thực hành con đường ấy, tu tập, làm cho sung mãn, các kiết sử được đoạn tận, các tùy miên được chấm dứt.`, ref: "Tăng Chi Bộ 4.170", url: "https://loicuaducphat.org/an/an4.170.html#content" },

{ text: `Ở đây, này chư Hiền, vị Tỷ-kheo tu tập chỉ, có quán đi trước. Do vị ấy tu tập chỉ có quán đi trước, con đường được sanh khởi. Vị ấy thực hành con đường ấy, tu tập, làm cho sung mãn. Do vị ấy thực hành con đường ấy, tu tập, làm cho sung mãn, các kiết sử được đoạn tận, các tùy miên được chấm dứt.`, ref: "Tăng Chi Bộ 4.170", url: "https://loicuaducphat.org/an/an4.170.html#content" },

{ text: `Ở đây, này chư Hiền, Tỷ-kheo tu tập cả hai chỉ quán gắn liền với nhau. Do vị ấy tu tập cả hai chỉ quán gắn liền với nhau, con đường được sanh khởi. Vị ấy thực hành con đường ấy, tu tập, làm cho sung mãn. Do vị ấy thực hành con đường ấy, tu tập, làm cho sung mãn, các kiết sử được đoạn tận, các tùy miên được chấm dứt.`, ref: "Tăng Chi Bộ 4.170", url: "https://loicuaducphat.org/an/an4.170.html#content" },

{ text: `Ở đây, này chư Hiền, Tỷ-kheo với các dao động đối với các pháp được hoàn toàn dứt sạch. Này các Hiền giả, đây là thời khi tâm của vị ấy an trú, an tọa, nhất tâm, định tĩnh. Với vị ấy, con đường sanh khởi. Vị ấy thực hành con đường ấy, tu tập, làm cho sung mãn. Do vị ấy thực hành con đường ấy, tu tập, làm cho sung mãn, các kiết sử được đoạn tận, các tùy miên được chấm dứt.`, ref: "Tăng Chi Bộ 4.170", url: "https://loicuaducphat.org/an/an4.170.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo có lòng tin, nếu chơn chánh mong cầu, hãy mong cầu như sau: “Mong ta sẽ được như Sàriputta, Moggallàna”. Này các Tỷ-kheo, họ là cán cân, là đồ để đo lường các đệ tử Tỷ-kheo của ta, tức là Sàriputta, Moggallàna.`, ref: "Tăng Chi Bộ 4.176", url: "https://loicuaducphat.org/an/an4.176.html#content" },

{ text: `Này Ràhula, phàm có nội địa giới gì, phàm có ngoại địa giới gì, đều là địa giới này... phàm có nội thủy giới gì, phàm có ngoại thủy giới gì, đều là thủy giới này...., phàm có nội hỏa giới gì, phàm có ngoại hỏa giới gì, đều là hỏa giới này...., phàm có nội phong giới gì, phàm có ngoại phong giới gì, đều là phong giới này. Cần phải như thật thấy phong giới ấy với chánh trí tuệ rằng: “Cái này không phải của tôi, cái này không phải là tôi, cái này không phải là tự ngã của tôi”. Do thấy như thật (phong giới) này với chánh trí tuệ, vị ấy nhàm chán phong giới. Với trí tuệ, vị ấy tẩy sạch tâm.`, ref: "Tăng Chi Bộ 4.177", url: "https://loicuaducphat.org/an/an4.177.html#content" },

{ text: `Khi nào, này Ràhula, Tỷ-kheo đối với bốn giới này, không có tùy quán là tự ngã hay thuộc ngã sở, này Ràhula, vị này được gọi là Tỷ-kheo đã cắt dứt ái, đã giải tỏa các kiết sử, đã chơn chánh minh quán kiêu mạn, đã chấm dứt khổ đau.`, ref: "Tăng Chi Bộ 4.177", url: "https://loicuaducphat.org/an/an4.177.html#content" },

{ text: `Ở đây, này Hiền giả Ananda, chúng sanh không có như thật quán tri: “Các tưởng này dự phần vào thối đọa”, không có như thật quán tri: “Các tưởng này dự phần vào an trú”, không có như thật quán tri: “Các tưởng này dự phần vào thù thắng”, không có như thật quán tri: “Các tưởng này dự phần vào thể nhập”. Này Hiền giả Ananda, đây là nhân, đây là duyên, do vậy ở đây có hạng chúng sanh ngay trong hiện tại, không chứng nhập Niết-bàn.`, ref: "Tăng Chi Bộ 4.179", url: "https://loicuaducphat.org/an/an4.179.html#content" },

{ text: `Này Bà-la-môn, phàm nói lên điều thấy gì, các pháp bất thiện tăng trưởng, các pháp thiện tổn giảm, Ta nói rằng điều thấy như vậy không nên nói ra. Và này Bà-la-môn, phàm nói lên điều thấy gì, các pháp bất thiện tổn giảm, các pháp thiện tăng trưởng, Ta nói rằng điều thấy như vậy nên nói ra. Này Bà-la-môn, phàm nói ra điều nghe gì ... phàm nói ra điều cảm giác gì ... phàm nói ra điều thức tri gì ... các pháp bất thiện tăng trưởng, các pháp thiện tổn giảm, Ta nói rằng điều thức tri như vậy không nên nói ra. Và này Bà-la-môn, phàm nói ra điều thức tri gì, các pháp bất thiện tổn giảm, các pháp thiện tăng trưởng, Ta nói rằng điều thức tri như vậy nên nói ra.`, ref: "Tăng Chi Bộ 4.183", url: "https://loicuaducphat.org/an/an4.183.html#content" },

{ text: `Ở đây, này Bà-la-môn, có người không ly tham đối với các dục, không ly ham muốn, không ly luyến ái, không ly khát ái, không ly nhiệt não, không ly tham ái. Rồi một chứng bệnh trầm trọng khởi lên cho người ấy. Người ấy bị cảm thọ chứng bệnh trầm trọng ấy, suy nghĩ như sau: “Thật sự các dục khả ái sẽ bỏ ta”, hay “Ta sẽ từ bỏ các dục khả ái”. Người ấy sầu muộn, than vãn, khóc lóc, đập ngực, rơi vào bất tỉnh. Này Bà-la-môn, đây là người bản tánh bị chết, sợ hãi, rơi vào run sợ khi nghĩ đến chết.`, ref: "Tăng Chi Bộ 4.184", url: "https://loicuaducphat.org/an/an4.184.html#content" },

{ text: `Lại nữa, này Bà-la-môn, ở đây có người không ly tham đối với thân ... Rồi một chứng bệnh trầm trọng khởi lên cho người ấy. Người ấy bị cảm thọ bởi chứng bệnh trầm trọng ấy, suy nghĩ như sau: “Thật sự thân khả ái sẽ bỏ ta”, hay “Ta sẽ từ bỏ thân khả ái”. Người ấy sầu muộn, than vãn, khóc lóc, đập ngực, rơi vào bất tỉnh. Này Bà-la-môn, đây là người bản tánh bị chết, sợ hãi, rơi vào run sợ khi nghĩ đến chết.`, ref: "Tăng Chi Bộ 4.184", url: "https://loicuaducphat.org/an/an4.184.html#content" },

{ text: `Lại nữa, này Bà-la-môn, ở đây có hạng người không làm điều lành, không làm điều thiện, không che chở kẻ sợ hãi, làm điều ác, làm điều hung bạo, làm điều phạm pháp. Rồi một chứng bệnh trầm trọng khởi lên cho người ấy. Người ấy bị cảm thọ bởi chứng bệnh trầm trọng ấy, suy nghĩ như sau: “Thật sự ta không làm điều lành, không làm điều thiện, không che chở kẻ sợ hãi, làm điều ác, làm điều hung bạo, làm điều phạm pháp”. Tại sanh thú nào mà những người không làm điều lành, không làm điều thiện, không che chở kẻ sợ hãi, làm điều ác, làm điều hung bạo, làm điều phạm pháp, đi đến sau khi chết, ta đi đến sanh thú ấy. Người ấy sầu muộn, than vãn, khóc lóc, đập ngực, rơi vào bất tỉnh. Này Bà-la-môn, đây là người bản tánh bị chết, sợ hãi, rơi vào run sợ khi nghĩ đến chết`, ref: "Tăng Chi Bộ 4.184", url: "https://loicuaducphat.org/an/an4.184.html#content" },

{ text: `Ở đây, này các du sĩ, Bà-la-môn nói như sau: “Tất cả loài hữu tình không đáng bị sát hại”. Người Bà-la-môn nói như vậy là nói sự thật, không nói láo. Do vậy, vị ấy không nghĩ đến “Sa-môn”, không nghĩ đến “Bà-la-môn”, không nghĩ đến: “Ta hơn (các người khác)”, không nghĩ đến: “Ta bằng (các người khác)”, không nghĩ đến: “Ta là hạ liệt”. Lại nữa do thắng tri sự thật hàm chứa ở đấy, người ấy thực hành lòng thương tưởng, lòng từ mẫn đối với các loài hữu tình.`, ref: "Tăng Chi Bộ 4.185", url: "https://loicuaducphat.org/an/an4.185.html#content" },

{ text: `Lại nữa, này các du sĩ, Bà-la-môn nói như sau: “Mọi dục là vô thường, khổ, chịu sự biến hoại”. Người Bà-la-môn nói như vậy là nói sự thật, không nói láo. Do vậy, vị ấy không nghĩ đến “Sa-môn”, không nghĩ đến “Bà-la-môn”, không nghĩ đến: “Ta hơn (các người khác)”, không nghĩ đến: “Ta bằng (các người khác)”, không nghĩ đến: “Ta là hạ liệt”. Lại nữa do thắng tri sự thật hàm chứa ở đấy, (trong lời nói ấy), người ấy thực hành nhàm chán, ly tham, đoạn diệt đối với các dục.`, ref: "Tăng Chi Bộ 4.185", url: "https://loicuaducphat.org/an/an4.185.html#content" },

{ text: `Lại nữa, này các du sĩ, Bà-la-môn nói như sau: “Tất cả các sanh hữu là vô thường, khổ, chịu sự biến hoại”. Người Bà-la-môn nói như vậy là nói sự thật, không nói láo. Do vậy, vị ấy không nghĩ đến “Sa-môn”, không nghĩ đến “Bà-la-môn”, không nghĩ đến: “Ta hơn (các người khác)”, không nghĩ đến: “Ta bằng (các người khác)”, không nghĩ đến: “Ta là hạ liệt”. Lại nữa do thắng tri sự thật hàm chứa ở đấy, người ấy thực hiện nhàm chán, ly tham, đoạn diệt đối với các sanh hữu.`, ref: "Tăng Chi Bộ 4.185", url: "https://loicuaducphat.org/an/an4.185.html#content" },

{ text: `Lại nữa, này các du sĩ, người Bà-la-môn nói như sau: “Ta không là bất cứ ai, bất cứ thuộc ai, bất cứ là gì. Trong ấy, không có cái gì được gọi là của ta, bất cứ ở đâu, bất cứ là gì”. Người Bà-la-môn nói như vậy là nói sự thật, không nói láo. Do vậy, vị ấy không nghĩ đến “Sa-môn”, không nghĩ đến “Bà-la-môn”, không nghĩ đến: “Ta hơn (các người khác)”, không nghĩ đến: “Ta bằng (các người khác)”, không nghĩ đến: “Ta là hạ liệt”. Lại nữa do thắng tri sự thật hàm chứa ở đấy, (trong lời nói ấy) người ấy thực hành con đường không có sự vật gì.`, ref: "Tăng Chi Bộ 4.185", url: "https://loicuaducphat.org/an/an4.185.html#content" },

{ text: `Ở đây, này Tỷ-kheo, Bậc Hiền trí, Ðại tuệ, không có nghĩ tự làm hại mình, không có nghĩ tự làm hại người, không có nghĩ tự mình làm hại cả hai, có suy nghĩ điều gì thời suy nghĩ lợi mình, lợi người, lợi cả hai, lợi toàn thể thế giới. Như vậy, này Tỷ-kheo, là Bậc Hiền trí, Ðại tuệ.`, ref: "Tăng Chi Bộ 4.186", url: "https://loicuaducphat.org/an/an4.186.html#content" },

{ text: `Này Tỳ-kheo, chính bởi Tâm mà thế giới bị dẫn dắt; chính bởi Tâm mà thế giới bị lôi kéo; và thế giới đi theo sự làm chủ của Tâm khi nó đã khởi lên.`, ref: "Tăng Chi Bộ 4.186", url: "https://loicuaducphat.org/an/an4.186.html#content" },

{ text: `Ở đây, này Mallikà, có hạng nữ nhân phẫn nộ, não hại nhiều, tuy bị ít nói, liền nổi nóng, nổi giận, nổi sân, sừng sộ, gây hấn, biểu lộ phẫn nộ, sân hận, bất mãn. Người này không bố thí cho Sa-môn, Bà-la-môn món ăn vật uống, vải mặc, xe cộ, vòng hoa, hương, phấn sáp, giường nằm, trú xứ, đèn đuốc; tánh tình keo kiệt; thấy người khác được lợi dưỡng, cung kính, tôn trọng, tôn kính, đảnh lễ, cúng dường, thì ganh tỵ, tức tối, trói buộc bởi ganh tỵ. Người ấy, sau khi từ bỏ đời này, trở lui lại trạng thái này, tại đấy, tại đấy, tái sanh hạ liệt, dung sắc xấu, sắc đẹp xấu, hình dáng hạ liệt, nghèo khổ, tài sản ít, sở hữu ít, ảnh hưởng uy tín ít.`, ref: "Tăng Chi Bộ 4.197", url: "https://loicuaducphat.org/an/an4.197.html#content" },

{ text: `Ở đây, này Mallikà, có hạng nữ nhân không phẫn nộ, não hại không nhiều, tuy bị nói nhiều, không có nổi nóng, không có nổi giận, không nổi sân, không sừng sộ, không gây hấn, không biểu lộ phẫn nộ, không sân hận, không bất mãn. Người này bố thí cho Sa-môn, Bà-la-môn món ăn vật uống, vải mặc, xe cộ, vòng hoa, hương, phấn sáp, giường nằm, trú xứ, đèn đuốc; tánh tình không keo kiệt; thấy người khác được lợi dưỡng, cung kính, tôn trọng, tôn kính, đảnh lễ, cúng dường, không ganh tỵ, tức tối, trói buộc bởi ganh tỵ. Người ấy, sau khi từ bỏ đời này, trở lui lại trạng thái này, tại đấy, tái sanh dung sắc đẹp, sắc đẹp tốt, tịnh tín, thành tựu với dung sắc thù thắng, giàu sang, tài sản lớn, sở hữu lớn, uy tín ảnh hưởng lớn.`, ref: "Tăng Chi Bộ 4.197", url: "https://loicuaducphat.org/an/an4.197.html#content" },

{ text: `Ái, này các Tỷ-kheo, là lưới triền khiến cho lưu chuyển luân hồi được rộng ra, bám dính vào; chính do ái ấy, thế giới này bị hoại vong, trói buộc, rối loạn như một cuộn chỉ, rối ren như một ổ kén, quyện lại như cỏ mujia và lau sậy babbaja, không thể nào ra khỏi khổ xứ, ác thú, đọa xứ, sanh tử.`, ref: "Tăng Chi Bộ 4.199", url: "https://loicuaducphat.org/an/an4.199.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có người tự mình đầy đủ lòng tin, còn khích lệ người khác có đầy đủ lòng tin; tự mình có xấu hổ và khích lệ người khác có xấu hổ; tự mình có sợ tội lỗi và khích lệ người khác có sợ tội lỗi; tự mình nghe nhiều và khích lệ người khác nghe nhiều; tự mình siêng năng tinh cần và khích lệ người khác siêng năng tinh cần; tự mình chánh niệm và khích lệ người khác chánh niệm; tự mình có trí tuệ và khích lệ người khác có trí tuệ. Người này, này các Tỷ-kheo, được gọi là gọi là bậc Chân nhân còn hơn cả bậc Chân nhân.`, ref: "Tăng Chi Bộ 4.202", url: "https://loicuaducphat.org/an/an4.202.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có người tự mình từ bỏ sát sanh, còn khích lệ người khác từ bỏ sát sanh; tự mình từ bỏ lấy của không cho và khích lệ người khác từ bỏ lấy của không cho; tự mình từ bỏ tà hạnh trong các dục và khích lệ người khác từ bỏ tà hạnh trong các dục; tự mình từ bỏ nói láo và khích lệ người khác từ bỏ nói láo; tự mình từ bỏ nói hai lưỡi và khích lệ người khác từ bỏ nói hai lưỡi; tự mình từ bỏ nói lời thô ác và khích lệ người khác từ bỏ nói lời thô ác; tự mình từ bỏ nói lời phù phiếm và khích lệ người khác từ bỏ nói lời phù phiếm. Này các Tỷ-kheo, đây gọi là gọi là bậc Chân nhân còn hơn cả bậc Chân nhân.`, ref: "Tăng Chi Bộ 4.203", url: "https://loicuaducphat.org/an/an4.203.html#content" },

{ text: `Thành tựu với bốn pháp này, này các Tỷ-kheo, như vậy tương xứng bị rơi vào địa ngục. Thế nào là bốn? Thành tựu với thân làm ác, với lời nói ác, với ý nghĩ ác, với không biết ơn, không biết trả ơn. Thành tựu với bốn pháp này, này các Tỷ-kheo, như vậy tương xứng bị rơi vào địa ngục.\nThành tựu với bốn pháp này, này các Tỷ-kheo, như vậy tương xứng được sanh lên cõi Trời. Thế nào là bốn? Thành tựu với thân làm thiện, với lời nói thiện, với ý nghĩ thiện, biết ơn, biết trả ơn. Thành tựu với bốn pháp này, này các Tỷ-kheo, như vậy tương xứng được sanh lên cõi Trời.`, ref: "Tăng Chi Bộ 4.213", url: "https://loicuaducphat.org/an/an4.213.html#content" },

{ text: `Ở đây, này Ananda, kẻ ác Tỷ-kheo, do theo ác giới, theo ác pháp không trong sạch, sở hành đáng nghi ngờ, có hành động che giấu, không phải Sa-môn nhưng tự xưng là Sa-môn, không hành Phạm hạnh nhưng tự xưng là hành Phạm hạnh, nội tâm mục nát, đầy ứ dục vọng, một đống rác dơ bẩn. Vị ấy nghĩ như sau: “Nếu các Tỷ-kheo sẽ biết Ta là ác giới, theo ác pháp, không thanh tịnh ... một đống rác dơ bẩn; nếu họ hòa hợp, họ sẽ làm hại ta; nếu họ chia rẽ, họ sẽ không làm hại được ta”. Này Ananda, do thấy lợi ích thứ nhất này, ác Tỷ-kheo thích thú với phá hòa hợp Tăng.`, ref: "Tăng Chi Bộ 4.243", url: "https://loicuaducphat.org/an/an4.243.html#content" },

{ text: `Lại nữa, này Ananda, ác Tỷ-kheo có tà mạng, nuôi sống mình với tà mạng. Vị ấy suy nghĩ như sau: “Nếu các Tỷ-kheo sẽ biết Ta có tà mạng, nuôi sống mình với tà mạng; nếu họ hòa hợp, họ sẽ làm hại ta; nếu họ chia rẽ, họ sẽ không làm hại được ta”. Này Ananda, do thấy lợi ích thứ ba này, ác Tỷ-kheo thích thú với phá hòa hợp Tăng.`, ref: "Tăng Chi Bộ 4.243", url: "https://loicuaducphat.org/an/an4.243.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, các học pháp thắng hạnh được Ta đặt cho các đệ tử, để những ai ít lòng tin phát khởi lòng tin. Vì rằng, này các Tỷ-kheo, các học pháp thắng hạnh được Ta chế đặt cho các đệ tử, để những ai ít lòng tin phát khởi lòng tin, để những ai có lòng tin, được tăng trưởng lòng tin. Do vậy, một đệ tử sau khi chấp nhận và học tập trong các học pháp, đối với học pháp ấy là người sở hành không bị bể vụn, sở hành không cắt xén, sở hành không bị vết nhơ, sở hành không bị chấm đen. Như vậy, này các Tỷ-kheo, là lợi ích của học tập.`, ref: "Tăng Chi Bộ 4.245", url: "https://loicuaducphat.org/an/an4.245.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, các học pháp sở hành Phạm hạnh được Ta đặt cho các đệ tử, để chơn chánh đoạn diệt đau khổ một cách hoàn toàn. Vì rằng, này các Tỷ-kheo, các học pháp sở hành Phạm hạnh được Ta chế đặt cho các đệ tử, để chơn chánh đoạn diệt đau khổ một cách hoàn toàn. Do vậy, một đệ tử sau khi chấp nhận và học tập trong các học pháp, đối với học pháp ấy là người sở hành không bị bể vụn, sở hành không cắt xén, sở hành không bị vết nhơ, sở hành không bị chấm đen. Như vậy, này các Tỷ-kheo, là lợi ích của học tập.`, ref: "Tăng Chi Bộ 4.245", url: "https://loicuaducphat.org/an/an4.245.html#content" },

{ text: `Này các Tỷ-kheo, có bốn pháp phi Thánh cầu này. Thế nào là bốn? Ở đây, này các Tỷ-kheo, có người tự mình bị già, tầm cầu cái bị già; tự mình bị bệnh, tầm cầu cái bị bệnh; tự mình bị chết, tầm cầu cái bị chết; tự mình bị uế nhiễm, tầm cầu cái bị uế nhiễm. Này các Tỷ-kheo, có bốn pháp phi Thánh cầu này.`, ref: "Tăng Chi Bộ 4.255", url: "https://loicuaducphat.org/an/an4.255.html#content" },

{ text: `Này các Tỷ-kheo, có bốn pháp Thánh cầu này. Thế nào là bốn? Ở đây, này các Tỷ-kheo, có người tự mình bị già, sau khi biết sự nguy hại của bị già, tầm cầu cái không bị già, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị bệnh, sau khi biết sự nguy hại của bị bệnh, tầm cầu cái không bệnh, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình bị chết, sau khi biết sự nguy hại của bị chết, tầm cầu cái không chết, vô thượng an ổn khỏi các khổ ách, Niết-bàn; tự mình uế nhiễm, sau khi biết sự nguy hại của uế nhiễm, tầm cầu cái không bị uế nhiễm, vô thượng an ổn khỏi các khổ ách, Niết-bàn. Này các Tỷ-kheo, có bốn pháp Thánh cầu này.`, ref: "Tăng Chi Bộ 4.255", url: "https://loicuaducphat.org/an/an4.255.html#content" },

{ text: `Phàm những gia đình nào, này các Tỷ-kheo, đạt đến sự lớn mạnh trong các tài sản, được tồn tại lâu dài; tất cả đều do bốn sự kiện ấy hay là một trong những sự kiện này. Thế nào là bốn? Tìm những gì đã mất; sửa lại cái gì đã già yếu; ăn và uống không quá độ; đặt nữ nhân, nam nhân có giới trong địa vị tối thắng. Phàm những gia đình nào, này các Tỷ-kheo, đạt đến sự lớn mạnh trong các tài sản, được tồn tại lâu dài; tất cả đều do bốn sự kiện ấy hay là một trong những sự kiện này.`, ref: "Tăng Chi Bộ 4.258", url: "https://loicuaducphat.org/an/an4.258.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống đau khổ, với tổn não, với ưu não, với nhiệt não, sau khi thân hoại mạng chung, được chờ đợi là ác thú. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo không có lòng tin, không có lòng hổ thẹn, không có lòng sợ hãi, biếng nhác, ác tuệ. Thành tựu với năm pháp này, này các Tỷ-kheo, ngay trong hiện tại sống đau khổ, với tổn não, với ưu não, với nhiệt não; sau khi thân hoại mạng chung, được chờ đợi là ác thú.`, ref: "Tăng Chi Bộ 5.3", url: "https://loicuaducphat.org/an/an5.3.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống an lạc, không có tổn não, không ưu não, không có nhiệt não; sau khi thân hoại mạng chung, được chờ đợi là cõi lành. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo có lòng tin, có lòng hổ thẹn, có lòng sợ hãi, tinh cần tinh tấn, có trí tuệ. Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống an lạc, không có tổn não, không có ưu não, không có nhiệt não; sau khi thân hoại mạng chung, được chờ đợi là cõi lành.`, ref: "Tăng Chi Bộ 5.3", url: "https://loicuaducphat.org/an/an5.3.html#content" },
{ text: `Không có sự bước vào bất thiện, này các Tỷ-kheo, cho đến khi nào có lòng hổ thẹn... lòng sợ hãi... tinh tấn... trí tuệ an trú vào các thiện pháp. Khi nào lòng hổ thẹn... lòng sợ hãi... tinh tấn... trí tuệ biến mất, này các Tỷ-kheo, không xấu hổ... không sợ hãi... biếng nhác... ác tuệ khởi lên và tồn tại, thời có sự bước vào bất thiện.`, ref: "Tăng Chi Bộ 5.6", url: "https://loicuaducphat.org/an/an5.6.html#content" },


{ text: `Này các Tỷ-kheo, cho đến khi nào vị Tỷ-kheo chưa gây được lòng tin đối với các thiện pháp, chưa gây được lòng hổ thẹn đối với các bất thiện pháp, chưa gây được lòng sợ hãi đối với các bất thiện pháp, chưa gây được tinh tấn đối với các thiện pháp; chưa gây được trí tuệ đối với các thiện pháp, cho đến khi ấy, này các Tỷ-kheo, Ta cần phải phòng hộ Tỷ-kheo ấy. Khi nào, này các Tỷ-kheo, Tỷ-kheo gây được lòng tin đối với các thiện pháp, gây được lòng hổ thẹn đối với các bất thiện pháp, gây được lòng sợ hãi đối với các bất thiện pháp, gây được lòng tinh tấn đối với các thiện pháp; gây được trí tuệ đối với các thiện pháp, thời khi ấy, này các Tỷ-kheo, Ta không còn săn sóc Tỷ-kheo ấy, nghĩ rằng: “Nay Tỷ-kheo ấy đã biết tự bảo vệ mình, không còn phóng dật nữa”.`, ref: "Tăng Chi Bộ 5.7", url: "https://loicuaducphat.org/an/an5.7.html#content" },

{ text: `Phần lớn, này các Tỷ-kheo, các loại hữu tình tìm được lạc thú trong các dục. Với thiện nam tử, này các Tỷ-kheo, đã bỏ một bên lưỡi liềm và đòn gánh, xuất gia, từ bỏ gia đình, sống không gia đình, vị ấy vừa đủ để được gọi: “Vị thiện nam tử vì lòng tin xuất gia”. Vì cớ sao?\nCác dục, này các Tỷ-kheo, được tìm thấy với tuổi trẻ, các dục này hay các dục khác. Và này các Tỷ-kheo, các dục hạ liệt, các dục trung đẳng, và các dục tối thắng, tất cả dục đều được chấp nhận là các dục.`, ref: "Tăng Chi Bộ 5.7", url: "https://loicuaducphat.org/an/an5.7.html#content" },

{ text: `Tỷ-kheo, này các Tỷ-kheo, không cung kính, không thận trọng, không sống tương hòa với các vị đồng Phạm hạnh, sẽ làm cho viên mãn thắng hạnh pháp, sự kiện này không xảy ra. Sau khi không làm cho viên mãn thắng hạnh pháp, vị ấy sẽ làm cho viên mãn hữu học pháp, sự kiện này không xảy ra. Không làm cho viên mãn hữu học pháp, vị ấy sẽ làm cho viên mãn các giới luật, sự kiện này không xảy ra. Sau khi không làm cho viên mãn các giới luật, vị ấy sẽ làm cho viên mãn chánh tri kiến, sự kiện này không xảy ra. Sau khi không làm cho viên mãn chánh tri kiến, vị ấy sẽ làm cho viên mãn chánh định, sự kiện này không xảy ra.`, ref: "Tăng Chi Bộ 5.21", url: "https://loicuaducphat.org/an/an5.21.html#content" },

{ text: `Tỷ-kheo, này các Tỷ-kheo, có cung kính, có thận trọng, sống tương hòa với các vị đồng Phạm hạnh sẽ làm cho viên mãn thắng hạnh pháp, sự kiện này có xảy ra. Sau khi làm cho viên mãn thắng hạnh pháp, vị ấy sẽ làm cho viên mãn hữu học pháp, sự kiện này có xảy ra. Sau khi làm cho viên mãn hữu học pháp, vị ấy sẽ làm cho viên mãn các giới luật, sự kiện này có xảy ra. Sau khi làm cho viên mãn các giới luật, vị ấy sẽ làm cho viên mãn chánh tri kiến, sự kiện này có xảy ra. Sau khi làm cho viên mãn chánh tri kiến, vị ấy sẽ làm cho viên mãn chánh định, sự kiện này có xảy ra.`, ref: "Tăng Chi Bộ 5.21", url: "https://loicuaducphat.org/an/an5.21.html#content" },

{ text: `Này các Tỷ-kheo, có năm uế nhiễm này của tâm, do các uế nhiễm ấy, tâm bị uế nhiễm, không nhu nhuyến, không dễ sử dụng, không sáng chói, bị bể vụn, không chơn chánh định tĩnh để đoạn diệt các lậu hoặc. Thế nào là năm? Tham dục, sân, hôn trầm thụy miên, trạo hối, nghi. Có năm uế nhiễm này của tâm, này các Tỷ-kheo, do năm uế nhiễm ấy, tâm bị uế nhiễm không được nhu nhuyến, không dễ sử dụng, không sáng chói, bị bể vụn, không chơn chánh, định tĩnh để đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 5.23", url: "https://loicuaducphat.org/an/an5.23.html#content" },

{ text: `Và khi nào, này các Tỷ-kheo, tâm được giải thoát khỏi năm uế nhiễm này: tham dục, sân, hôn trầm thụy miên, trạo hối, nghi. Khi ấy tâm ấy được nhu nhuyến, dễ sử dụng, sáng chói, không bể vụn, chơn chánh định tĩnh để đoạn diệt các lậu hoặc. Tùy thuộc theo pháp gì cần phải được giác ngộ với thắng trí, tâm vị ấy hướng đến để được giác ngộ với thắng trí. Tại đây, tại đấy vị ấy có khả năng, có năng lực đạt đến pháp ấy, dầu thuộc loại xứ nào.`, ref: "Tăng Chi Bộ 5.23", url: "https://loicuaducphat.org/an/an5.23.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một cây, với cành và lá bị phá hoại, thời đọt cây ấy không đi đến viên mãn, vỏ cây không đi đến viên mãn, giác cây không đi đến viên mãn, lõi cây không đi đến viên mãn. Cũng vậy, này các Tỷ-kheo, với người ác giới, với người phá giới, chánh định do vậy bị phá hoại. Khi chánh định không có mặt, với người chánh định bị phá hoại, như thật tri kiến nhân do vậy bị phá hoại. Khi như thật tri kiến không có mặt, với người như thật tri kiến bị phá hoại, nhàm chán, ly tham do vậy bị phá hoại. Khi nhàm chán, ly tham không có mặt, với người nhàm chán ly tham bị phá hoại, giải thoát tri kiến do vậy bị phá hoại.`, ref: "Tăng Chi Bộ 5.24", url: "https://loicuaducphat.org/an/an5.24.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một cây, với cành và lá được đầy đủ, thời đọt cây ấy đi đến viên mãn, vỏ cây đi đến viên mãn, giác cây đi đến viên mãn, lõi cây đi đến viên mãn. Cũng vậy, này các Tỷ-kheo, với người có giới, với người giữ gìn giới, chánh định nhân vậy được đầy đủ. Do chánh định có mặt, với người chánh định được thành tựu, như thật tri kiến do vậy được thành tựu. Do như thật tri kiến có mặt, với người như thật tri kiến được thành tựu, nhàm chán, ly tham do vậy được thành tựu. Do nhàm chán, ly tham có mặt, với người nhàm chán, ly tham được thành tựu, giải thoát tri kiến do vậy được thành tựu.`, ref: "Tăng Chi Bộ 5.24", url: "https://loicuaducphat.org/an/an5.24.html#content" },

{ text: `Này các Tỷ-kheo, thông minh, thường niệm, hãy tu tập vô lượng định. Với ai thông minh, thường niệm, tu tập vô lượng định, tự mỗi người ấy khởi lên năm trí. Thế nào là năm? Ðịnh này hiện tại lạc và tương lai có quả dị thục lạc, trong mỗi người, trí (như vậy) khởi lên. Ðịnh này thuộc bậc Thánh, không thuộc vật chất, trong mỗi người, trí (như vậy) khởi lên. Ðịnh này không do người ác thực hiện, trong mỗi người, trí (như vậy) khởi lên. Ðịnh này an tịnh, thù diệu, đem đến khinh an, đạt được nhất tâm, không phải là sự chế ngự gò ép thường xuyên, trong mỗi người, trí (như vậy) khởi lên: “An tịnh, ta nhập định này. An tịnh, ta xuất khỏi định này”, trong mỗi người trí (như vậy) khởi lên.`, ref: "Tăng Chi Bộ 5.27", url: "https://loicuaducphat.org/an/an5.27.html#content" },

{ text: `Này các Tỷ-kheo, có năm lợi ích này của kinh hành. Thế nào là năm? Kham nhẫn được đường trường; kham nhẫn được tinh cần; ít bệnh tật; đưa đến tiêu hóa tốt đẹp các đồ được ăn, được uống, được nhai, được nếm; định chứng được trong khi kinh hành được tồn tại lâu dài. Những pháp này, này các Tỷ-kheo là năm lợi ích của kinh hành.`, ref: "Tăng Chi Bộ 5.29", url: "https://loicuaducphat.org/an/an5.29.html#content" },


{ text: `- Này Nàgita, những ai đã đến, và làm ồn ào như những hàng cá với đống cá lớn?\n- Các người ấy, bạch Thế Tôn, là các Ba-la-môn gia chủ ở Icchànangalam, đang đứng ở ngoài cổng vào, đem theo rất nhiều đồ ăn loại cứng và loại mềm cho Thế Tôn và chúng Tăng.\n- Này Nàgita, Ta không có liên hệ gì với danh vọng và danh vọng không có liên hệ gì với Ta. Này Nàgita, những ai tìm được không có khó khăn, tìm được không có mệt nhọc, tìm được không có phí sức, tìm được an ổn lạc, viễn ly lạc, an tịnh lạc, chánh giác lạc, mà Ta đã tìm được không có khó khăn, tìm được không có mệt nhọc, tìm được không có phí sức. Hãy để họ thọ hưởng lạc như phân ấy, thụy miên lạc, lợi dưỡng, cung kính, danh văn lạc.`, ref: "Tăng Chi Bộ 5.30", url: "https://loicuaducphat.org/an/an5.30.html#content" },

{ text: `Này Nàgita, với những ai nặng nề về ái lạc, này Nàgita, sự biến hoại, đổi khác, sầu bi khổ ưu não khởi lên. Ðấy là kết quả tất nhiên cho người ấy. Những ai chuyên chú tâm về tướng bất tịnh, này Nàgita, thời sự nhàm chán đối với tịnh tướng được an trú. Ðấy là kết quả tất nhiên cho người ấy. Ai sống tùy quán vô thường trong sáu xúc xứ, này Nàgita, thời sự nhàm chán đối với xúc được an trú. Ðấy là kết quả tất nhiên cho người ấy. Ai sống tùy quán sanh diệt đối với năm thủ uẩn, này Nàgita, thời sự nhàm chán đối với chấp thủ được an trú. Ðấy là kết quả tất nhiên cho người ấy.`, ref: "Tăng Chi Bộ 5.30", url: "https://loicuaducphat.org/an/an5.30.html#content" },

{ text: `Người có bố thí, này Sumanà, khi được làm người, vượt qua vị làm người không bố thí trên năm phương diện: Về nhân thọ mạng, về nhân sắc, về nhân lạc, về nhân danh xưng, về nhân tăng thượng. Người có bố thí, này Sumanà, khi được làm người, vượt qua vị làm người không bố thí trên năm phương diện này. Sự việc là như vậy, này Sumanà, là vừa đủ để bố thí, là vừa đủ để làm các công đức. Chúng là những giúp ích, những công đức cho chư Thiên. Chúng là những giúp ích, những công đức cho loài Người. Chúng là những giúp ích, những công đức cho những người xuất gia.`, ref: "Tăng Chi Bộ 5.31", url: "https://loicuaducphat.org/an/an5.31.html#content" },

{ text: `Như mặt trăng không uế,\nÐi giữa hư không giới,\nVới ánh sáng bừng chói,\nGiữa quần sao ở đời.\nCũng vậy, người đủ giới,\nHạng người có lòng tin,\nVới bố thí, bừng chói,\nGiữa xan tham ở đời.\nNhư mây mưa sấm sét,\nVòng hoa chóp trăm đầu,\nTràn đầy cả thung lũng,\nLan tràn cả đất bằng.\nCũng vậy, đầy tri kiến,\nÐệ tử bậc Chánh Giác,\nBậc trí vượt xan tham,\nTrên cả năm phương diện,\nThọ mạng và danh xưng,\nDung sắc và an lạc,\nVới tài sản sung mãn,\nChết hưởng hỷ lạc thiên.`, ref: "Tăng Chi Bộ 5.31", url: "https://loicuaducphat.org/an/an5.31.html#content" },

{ text: `Người bố thí, này Sìha, người thí chủ được quần chúng ái mộ và ưa thích. Này Sìha, người bố thí, người thí chủ được quần chúng ái mộ và ưa thích, đây quả bố thí thiết thực hiện tại. Lại nữa, này Sìha! Bậc thiện, bậc Chân nhân thân cận người bố thí, người thí chủ. Này Sìha, bậc Thiện, bậc Chân nhân, thân cận người bố thí, người thí chủ. Này Sìha, đây là quả bố thí thiết thực hiện tại. Lại nữa, này Sìha! Người bố thí, người thí chủ được đồn tốt đẹp truyền đi. Này Sìha, người bố thí, người thí chủ được tiếng đồn tốt đẹp truyền đi. Này Sìha, đây là quả bố thí thiết thực hiện tại.`, ref: "Tăng Chi Bộ 5.34", url: "https://loicuaducphat.org/an/an5.34.html#content" },

{ text: `Người bố thí, này Sìha, người thí chủ đi đến hội chúng nào, hoặc hội chúng Sát-đế-ly, hoặc hội chúng Bà-la-môn, hoặc hội chúng gia chủ, hoặc hội chúng Sa-môn. Vị ấy đi đến với tự tín, không có do dự hoang mang. Này Sìha, người bố thí, người thí đi đến hội chúng nào, hoặc hội chúng Sát Ðế Lỵ, hoặc hội chúng Bà-la-môn, hoặc hội chúng gia chủ, hoặc hội chúng Sa-môn; vị ấy đi đến với tự tín, không có do dự hoang mang. Này Sìha, đây là quả bố thí thiết thực hiện tại.`, ref: "Tăng Chi Bộ 5.34", url: "https://loicuaducphat.org/an/an5.34.html#content" },

{ text: `Này các Tỷ-kheo, có năm lợi ích này của bố thí. Thế nào là năm? Ðược nhiều người ái mộ, ưa thích; được bậc Thiện nhân, Chân nhân thân cận; tiếng đồn tốt đẹp được truyền đi; không có sai lệch pháp của người gia chủ; khi thân hoại mạng chung được sanh lên cõi lành, Thiên giới. Những pháp này, này các Tỷ-kheo, là lợi ích của bố thí.`, ref: "Tăng Chi Bộ 5.35", url: "https://loicuaducphat.org/an/an5.35.html#content" },
{ text: `Này các Tỷ-kheo, có năm bố thí đúng thời này. Thế nào là năm? Bố thí cho người đến, bố thí cho người đi, bố thí cho người đau bệnh, bố thí trong thời đói, phàm có những hoa quả gì mới gặt hái được, dành chúng đầu tiên để cúng dường các bậc giữ giới. Này các Tỷ-kheo, năm pháp này là năm bố thí đúng thời.`, ref: "Tăng Chi Bộ 5.36", url: "https://loicuaducphat.org/an/an5.36.html#content" },

{ text: `Người bố thí bữa ăn, này các Tỷ-kheo, người thí chủ đem lại cho người thọ lãnh năm điều. Thế nào là năm? Cho thọ mạng, cho dung sắc, cho an lạc, cho sức mạnh, cho biện tài. Cho thọ mạng, vị ấy được chia thọ mạng chư Thiên hay loài Người. Cho dung sắc, vị ấy được chia dung sắc chư Thiên hay loài Người. Cho an lạc, vị ấy được chia an lạc chư Thiên hay loài Người. Cho sức mạnh, vị ấy được chia sức mạnh chư Thiên hay loài Người. Cho biện tài, vị ấy được chia biện tài chư Thiên hay loài Người. Người bố thí bữa ăn, này các Tỷ-kheo, người thí chủ đem lại cho người thọ lãnh năm điều này.`, ref: "Tăng Chi Bộ 5.37", url: "https://loicuaducphat.org/an/an5.37.html#content" },

{ text: `Này các Tỷ-kheo, có năm lợi ích này cho thiện nam tử có lòng tin. Thế nào là năm? Các Thiện nhân, các Chân nhân, trước hết có lòng thương tưởng đến vị có lòng tin, không có như vậy đối với vị không có lòng tin; khi đến thăm, trước hết họ đến thăm vị có lòng tin, không có như vậy đối với vị không có lòng tin; khi chấp nhận, họ chấp nhận (các món ăn) trước hết từ những người có lòng tin, không từ những người không có lòng tin; họ thuyết pháp trước hết cho những người có lòng tin, không cho những người không có lòng tin; người có lòng tin, sau khi thân hoại mạng chung, được sanh lên cõi lành, cõi Trời. Những pháp này, này các Tỷ-kheo, là năm lợi ích cho thiện nam tử có lòng tin.`, ref: "Tăng Chi Bộ 5.38", url: "https://loicuaducphat.org/an/an5.38.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trên khoảnh đất tốt, tại ngã tư đường, có cây bàng to lớn là chỗ nương tựa cho các loài chim chung quanh. Cũng vậy, này các Tỷ-kheo, thiện nam tử có lòng tin là chỗ nương tựa cho quần chúng, cho các Tỷ-kheo, Tỷ-kheo-ni, cho nam cư sĩ và cho nữ cư sĩ.`, ref: "Tăng Chi Bộ 5.38", url: "https://loicuaducphat.org/an/an5.38.html#content" },

{ text: `Như cây bàng to lớn,\nVới cành, lá, trái cây,\nVới thân, rễ, đầy trái,\nLàm chỗ trú loài chim.\nTại trú xứ thoải mái,\nCác con chim làm tổ,\nCần bóng mát, hứng mát,\nCần trái cây, ăn trái.\nCũng vậy, vị trì giới,\nNgười có lòng tịnh tín,\nKhiêm nhường và nhu thuận,\nHiền hòa, lời từ tốn,\nTánh tình thật dịu hiền,\nVị đoạn tham, đoạn sân,\nÐoạn si, không lậu hoặc,\nLà ruộng phước ở đời.\nHọ đến người như vậy,\nHọ thuyết pháp, người ấy\nÐoạn trừ mọi khổ đau,\nVị ấy ở tại đây,\nHiểu biết Chánh pháp ấy,\nViên bản nhập Niết-bàn,\nHoàn toàn không lậu hoặc.`, ref: "Tăng Chi Bộ 5.38", url: "https://loicuaducphat.org/an/an5.38.html#content" },

{ text: `Ai cho vật khả ý,\nNhận được điều khả ý,\nBố thí vật tối thượng,\nSẽ được quả tối thượng.\nNgười có vật thù diệu,\nNhận được điều thù diệu,\nNgười có vật tối thắng,\nNhận được điều tối thắng.\nNgười nào đem bố thí\nVật tối thượng, thù diệu,\nVà các vật tối thượng,\nNgười ấy thọ mạng dài,\nVà được cả danh xưng,\nTại chỗ vị ấy sanh.`, ref: "Tăng Chi Bộ 5.44", url: "https://loicuaducphat.org/an/an5.44.html#content" },

{ text: `Biển lớn không hạn lượng,\nHồ lớn nhiều sợ hãi,\nLà kho tàng cất giữ,\nVô số lượng châu báu,\nCũng là chỗ trú ẩn;\nVô số các loại cá,\nLà chỗ các sông lớn.\nQuy tựu chảy ra biển.\nCũng vậy người bố thí,\nÐồ ăn và đồ uống,\nVải mặc và giường nằm,\nChỗ ngồi và thảm nệm,\nBậc Hiền thí như vậy,\nPhước đức ùa chạy đến,\nNhư sông dẫn dòng nước,\nÙa chảy vào biển cả.`, ref: "Tăng Chi Bộ 5.45", url: "https://loicuaducphat.org/an/an5.45.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Thánh đệ tử sống ở gia đình, tâm không bị cấu uế xan tham chi phối, bố thí rộng rãi, với bàn tay rộng mở, ưa thích từ bỏ, sẵn sàng để được yêu cầu, ưa thích phân phát vật bố thí. Này các Tỷ-kheo, đây gọi là thí tài.`, ref: "Tăng Chi Bộ 5.47", url: "https://loicuaducphat.org/an/an5.47.html#content" },

{ text: `Ai tin tưởng Như Lai,\nBất động, khéo an trí,\nAi gìn giữ thiện giới,\nThánh ái mộ tán thán.\nAi tịnh tín chúng Tăng,\nÐược thấy bậc Chánh trực,\nNgười ấy gọi không nghèo,\nMạng sống không trống không.\nDo vậy, tín và giới,\nTịnh tín thấy Chánh pháp,\nBậc trí tâm chuyên chú,\nNhớ đến lời Phật dạy.`, ref: "Tăng Chi Bộ 5.47", url: "https://loicuaducphat.org/an/an5.47.html#content" },

{ text: `Với kẻ phàm phu không học, này các Tỷ-kheo, phải bị già và già đến...  phải bị bệnh và bệnh đến... phải bị chết và chết đến... phải bị hoại diệt và hoại diệt đến... phải bị tiêu diệt và tiêu diệt đến; khi tiêu diệt đến, kẻ ấy không suy tư: “Không phải chỉ một mình ta phải bị tiêu diệt và tiêu diệt đến, nhưng đối với các loài hữu tình, có đến, có đi, có diệt, có sanh, tất cả loài hữu tình đều phải bị tiêu diệt và tiêu diệt đến. Và nếu phải bị tiêu diệt, và khi tiêu diệt đến, ta lại sầu, bi, than khóc, đập ngực, đi đến bất tỉnh, thời ăn uống không làm ta ưa thích; thân ta trở thành xấu xí; công việc không có xúc tiến, kẻ thù sẽ hoan hỷ, bạn bè sẽ lo buồn”. Kẻ ấy phải bị tiêu diệt, khi tiêu diệt đến, sầu, bi, than khóc, đập ngực, đi đến bất tỉnh. Này các Tỷ-kheo, đây gọi là kẻ phàm phu không học, bị mũi tên sầu muộn tẩm thuốc độc bắn trúng, kẻ ấy tự làm mình ưu não.
`, ref: "Tăng Chi Bộ 5.48", url: "https://loicuaducphat.org/an/an5.48.html#content" },

{ text: `Với lời thật khéo nói,\nVới bố thí chơn chánh,\nVới truyền thống khéo giữ,\nChỗ nào được lợi ích,\nChỗ ấy gắng tinh cần.\nNếu biết lợi không được,\nCả ta và người khác,\nKhông sầu, biết chịu đựng,\nMong vị ấy nghĩ rằng:\nNay ta phải làm gì?\nPhải kiên trì thế nào?`, ref: "Tăng Chi Bộ 5.50", url: "https://loicuaducphat.org/an/an5.50.html#content" },

{ text: `Dục tham, này các Tỷ-kheo, là chướng ngại triền cái bao phủ tâm, làm yếu ớt trí tuệ. Sân, này các Tỷ-kheo, là chướng ngại triền cái bao phủ tâm làm yếu ớt trí tuệ. Hôn trầm thụy miên, này các Tỷ-kheo, là chướng ngại, triền cái bao phủ tâm, làm yếu ớt trí tuệ. Trạo hối, này các Tỷ-kheo, là chướng ngại, triền cái bao phủ tâm, làm yếu ớt trí tuệ. Nghi, này các Tỷ-kheo, là chướng ngại, triền cái bao phủ tâm, làm yếu ớt trí tuệ. Những pháp này, này các Tỷ-kheo, là năm chướng ngại triền cái bao phủ tâm, làm yếu ớt trí tuệ.`, ref: "Tăng Chi Bộ 5.51", url: "https://loicuaducphat.org/an/an5.51.html#content" },


{ text: `Ví như, này các Tỷ-kheo, một con sông chảy, từ núi xuống, chảy thật xa, dòng chảy nhanh cuốn trôi mọi vật. Rồi có người lấy cày mở hai bên bờ sông. Như vậy, này các Tỷ-kheo, dòng sông ấy ở chặng giữa bị trở ngại, tràn rộng, bị chuyển hướng, không còn chảy ra xa, không còn chảy nhanh, không cuốn trôi mọi vật. Cũng vậy, này các Tỷ-kheo, Tỷ-kheo ấy không đoạn tận năm chướng ngại triền cái này bao phủ tâm, làm yếu ớt trí tuệ, không có sức mạnh và trí tuệ yếu kém, sẽ biết được lợi ích của mình, hay sẽ biết lợi ích của người, hay có thể biết lợi ích của cả hai, sẽ chứng ngộ được pháp thượng nhân, trí kiến thù thắng, xứng đáng bậc Thánh; sự kiện này không xảy ra.`, ref: "Tăng Chi Bộ 5.51", url: "https://loicuaducphat.org/an/an5.51.html#content" },


{ text: `Nói đến một đống bất thiện, này các Tỷ-kheo, nói một cách chơn chánh là nói đến năm triền cái. Thật vậy, này các Tỷ-kheo, toàn bộ đống bất thiện tức là năm triền cái. Thế nào là năm? Dục tham triền cái, sân triền cái, hôn trầm thụy miên triền cái, trạo hối triền cái, nghi triền cái. Nói đến một đống bất thiện, này các Tỷ-kheo, nói một cách chơn chánh là nói đến năm triền cái. Thật vậy, này các Tỷ-kheo, toàn bộ đống bất tiện này, này các Tỷ-kheo, tức là năm triền cái.`, ref: "Tăng Chi Bộ 5.52", url: "https://loicuaducphat.org/an/an5.52.html#content" },


{ text: `Này các Tỷ-kheo, nếu có ai nói rằng: “Là bẫy mồi toàn diện của Màra”, thời người ấy đã nói một cách chơn chánh về nữ nhân, thật là “một bẫy mồi hoàn toàn của Màra”.`, ref: "Tăng Chi Bộ 5.55", url: "https://loicuaducphat.org/an/an5.55.html#content" },

{ text: `Hãy nói chuyện với người,\nCó kiếm ở trong tay,\nNói chuyện với ác quỷ,\nHay ngồi thật gần kề.\nCon rắn có nọc độc,\nBị cắn liền mệnh chung,\nNhưng chớ có một mình,\nNói chuyện với nữ nhân.\nThất niệm, họ trói lại,\nVới nhìn, với nụ cười,\nVới xiêm áo hở hang,\nVới lời nói ngọt lịm,\nNgười ấy vẫn không thỏa,\nBất tỉnh bị mệnh chung.\nNăm dục trưởng dưỡng ấy,\nÐược thấy trong nữ sắc\nSắc, thanh, hương, vị, xúc,\nHấp dẫn và đẹp ý.\nBị thác nước dục vọng,\nTràn ngập và cuốn trôi,\nKẻ ngu si vô trí,\nKhông liễu tri các dục.\nLoài người khi mạng chung,\nSanh thú hữu, phi hữu,\nHọ phải bị dẫn đầu,\nTrong nhiều kiếp luân hồi.\nAi liễu tri các dục,\nSở hành không sợ hãi,\nHọ đến bờ bên kia,\nÐạt được lậu hoặc tận.`, ref: "Tăng Chi Bộ 5.55", url: "https://loicuaducphat.org/an/an5.55.html#content" },

{ text: `Này Tỷ-kheo, khi một người sống với các căn không được bảo vệ, với ăn uống không có tiết độ, không có chú tâm cảnh giác, không có quán nhìn các thiện pháp, không có trước đêm và sau đêm chuyên chú tu tập các pháp giác chi. Do vậy, thân Thầy cảm thấy như bị say ngọt, mắt Thầy không thấy rõ phương hướng, pháp không được Thầy nhớ đến. Hôn trầm thụy miên chinh phục tâm Thầy và an trú. Không có hoan hỷ, Thầy sống Phạm hạnh. Thầy có những nghi ngờ đối với Chánh pháp. Do vậy, này Tỷ-kheo, Thầy phải học tập như sau: “Ta sẽ bảo vệ các căn, có tiết độ trong ăn uống, chú tâm cảnh giác, quán nhìn các Thiện pháp, trước đêm và sau đêm ta sẽ sống chuyên chú tu tập các pháp giác chi”.`, ref: "Tăng Chi Bộ 5.56", url: "https://loicuaducphat.org/an/an5.56.html#content" },

{ text: `Này Tỷ-kheo, khi một người sống với các căn được bảo vệ, với ăn uống có tiết độ, có chú tâm cảnh giác, có quán nhìn các thiện pháp, trước đêm và sau đêm sống chuyên chú tu tập các pháp giác chi. Do vậy, thân không cảm thấy như bị say ngọt, các phương hướng được hiện rõ, và pháp được người ấy nhớ rõ. Hôn trầm thụy miên không còn chinh phục tâm của vị ấy. Với tâm hoan hỷ, vị ấy sống Phạm hạnh. Vị ấy không còn nghi ngờ đối với các thiện pháp. Vậy này các Tỷ-kheo, các Thầy cần phải học tập như sau: “Ta sẽ bảo vệ các căn, có tiết độ trong ăn uống, chuyên tâm cảnh giác quán nhìn các thiện pháp, trước đêm và sau đêm, ta sẽ sống chuyên chú tu tập các pháp giác chi”.`, ref: "Tăng Chi Bộ 5.56", url: "https://loicuaducphat.org/an/an5.56.html#content" },


{ text: `Bị bệnh và bị già,\nLại thêm phải bị chết,\nPháp yếu là như vậy,\nHữu tình là như vậy.\nPhàm phu sanh nhàm chán,\nThật không hợp cho Ta,\nNếu Ta cũng nhàm chán,\nÐối với các chúng sanh,\nCùng chung một số phận.\nTrong khi đời sống Ta,\nKhông khác gì đời họ,\nTa được sống như vậy,\nBiết pháp không sanh y,\nKiêu mạn trong không bệnh,\nTrong tuổi trẻ sinh mạng,\nTất cả Ta nhiếp phục\nPhát xuất từ an ổn,\nTa thấy hạnh viễn ly,\nTa phát tâm dõng mãnh,\nThấy được cảnh Niết-bàn.\nNay Ta không có thể,\nHưởng thọ các dục vọng,\nTa sẽ không thối đọa,\nChứng cứu cánh Phạm hạnh.`, ref: "Tăng Chi Bộ 5.57", url: "https://loicuaducphat.org/an/an5.57.html#content" },

{ text: `Có năm tưởng này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, đưa đến cứu cánh bất tử. Thế nào là năm? Tưởng bất tịnh, tưởng chết, tưởng nguy hại, tưởng ghê tởm các món ăn, tưởng không có hân hoan đối với tất cả thế giới. Năm tưởng này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, đưa đến cứu cánh bất tử.`, ref: "Tăng Chi Bộ 5.61", url: "https://loicuaducphat.org/an/an5.61.html#content" },

{ text: `Có năm tưởng này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến quả lớn lợi ích, thể nhập vào bất tử, đưa đến cứu cánh bất tử. Thế nào là năm? Tưởng vô thường, tưởng vô ngã, tưởng chết, tưởng ghê tởm các món ăn, tưởng không có hân hoan đối với tất cả thế giới. Những pháp này là năm tưởng, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, đưa đến cứu cánh bất tử.`, ref: "Tăng Chi Bộ 5.62", url: "https://loicuaducphat.org/an/an5.62.html#content" },

{ text: `Này các Tỷ-kheo, tăng trưởng với năm tăng trưởng, vị Thánh đệ tử tăng trưởng, với Thánh tăng trưởng đem lại kiên cố, đem lại thù thắng cho tự thân. Thế nào là năm? Tăng trưởng với lòng tin, tăng trưởng với giới, tăng trưởng với học hỏi, tăng trưởng với bố thí, tăng trưởng với trí tuệ. Tăng trưởng với năm tăng trưởng này, này các Tỷ-kheo, vị Thánh đệ tử tăng trưởng với Thánh tăng trưởng, đem lại kiên cố, đem lại thù thắng cho tự thân.`, ref: "Tăng Chi Bộ 5.63", url: "https://loicuaducphat.org/an/an5.63.html#content" },

{ text: `Năm pháp này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến đoạn diệt các lậu hoặc. Thế nào là năm? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo trú quán bất tịnh trên thân, với tưởng ghê tởm đối với các món ăn, với tưởng không hoan hỷ đối với tất cả thế giới, quán vô thường đối với tất cả hành, với tưởng về chết, nội tâm khéo an trú. Năm pháp này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đưa đến đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 5.70", url: "https://loicuaducphat.org/an/an5.70.html#content" },


{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo thuyết pháp cho các người khác một cách rộng rãi như đã được nghe, như đã được học thông suốt. Vị ấy dùng trọn cả ngày để trình bày pháp cho các người khác, bỏ phế sống độc cư an tịnh, không nỗ lực chuyên chú vào nội tâm an chỉ. Này Tỷ-kheo, đấy gọi là Tỷ-kheo thuyết trình nhiều, nhưng không sống theo pháp.\nLại nữa, này các Tỷ-kheo, Tỷ-kheo đọc tụng pháp một cách rộng rãi như đã được nghe, như đã được học thuộc lòng. Vị ấy dùng trọn cả ngày để tụng đọc, bỏ phế sống độc cư an tịnh, không nỗ lực chuyên chú vào nội tâm an chỉ. Này Tỷ-kheo, đây gọi là Tỷ-kheo đọc tụng nhiều, nhưng không sống theo pháp.`, ref: "Tăng Chi Bộ 5.73", url: "https://loicuaducphat.org/an/an5.73.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo với tâm tùy tầm tùy tứ, với ý tùy quán pháp như đã được nghe, như đã được học thuộc lòng. Vị ấy dùng trọn cả ngày suy tầm về pháp, bỏ phế sống độc cư an tịnh, không nỗ lực chuyên chú vào nội tâm an chỉ. Này Tỷ-kheo, đây gọi là Tỷ-kheo suy tầm nhiều, nhưng không sống theo pháp.\nỞ đây, này Tỷ-kheo, Tỷ-kheo học thuộc lòng pháp, tức là Khế kinh, Ứng tụng, Ký thuyết, Phúng tụng, Không hỏi tự nói, Như thị thuyết, Bổn sanh, Vị tằng hữu pháp, Trí giải hay Phương quảng. Vị ấy không dùng trọn cả ngày để học thuộc lòng pháp, không phế bỏ sống độc cư an tịnh, nỗ lực chuyên chú vào nội tâm an chỉ. Này Tỷ-kheo, như vậy Tỷ-kheo sống theo pháp.`, ref: "Tăng Chi Bộ 5.73", url: "https://loicuaducphat.org/an/an5.73.html#content" },

{ text: `Này Tỷ-kheo, điều gì bậc Ðạo Sư cần phải làm cho các đệ tử vì hạnh phúc, vì lòng thương tưởng, vì lòng từ khởi lên, các điều ấy, Ta đã làm cho các Thầy. Này Tỷ-kheo, đây là những gốc cây, đây là những căn nhà trống. Này Tỷ-kheo, hãy tu Thiền, chớ có phóng dật, chớ có để về sau sẽ phải hối tiếc. Ðấy là lời giáo giới của Ta cho các Thầy.`, ref: "Tăng Chi Bộ 5.73", url: "https://loicuaducphat.org/an/an5.73.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo quán sát như sau: “Nay ta còn trẻ, niên thiếu, còn thanh niên, tóc đen nhánh, trong buổi thanh xuân, trong sơ kỳ tuổi đời. Nhưng rồi đến thời già sẽ xúc chạm thân này. Khi đã già yếu, và bị già chinh phục, thật không dễ gì để tác ý đến giáo pháp của các đức Phật, thật không dễ gì để sống tại các trú xứ rừng núi cao nguyên xa vắng. Trước khi trạng thái ấy đến với ta, không đáng ưa, không đáng thích, không khả ý, ta hãy hăng hái tinh cần trước khi thời ấy đến, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ. Và nếu thành tựu trạng thái ấy, có bị già, ta sẽ sống được thoải mái”.\nNày các Tỷ-kheo, do quán thấy sợ hãi thứ nhất này về tương lai, như vậy là vừa đủ để Tỷ-kheo sống không phóng dật, nhiệt tâm, tinh cần, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ.`, ref: "Tăng Chi Bộ 5.78", url: "https://loicuaducphat.org/an/an5.78.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo quán sát như sau: “Nay ta ít bệnh, ít não, sự tiêu hóa được điều hòa, không lạnh quá, không nóng quá, trung bình, hợp với tinh tấn, nhưng rồi đến thời bệnh sẽ xúc chạm thân này. Khi đã bị bệnh và bị bệnh chinh phục, thật không dễ gì tác ý đến giáo pháp của các đức Phật, thật không dễ gì để sống tại các trú xứ rừng núi cao nguyên xa vắng. Trước khi trạng thái ấy đến với ta, không đáng ưa, không đáng thích, không khả ý, ta hãy hăng hái tinh cần trước khi thời ấy đến, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ. Và nếu thành tựu trạng thái ấy, dầu có bị bệnh, ta sẽ sống được thoải mái”.\nNày các Tỷ-kheo, do quán thấy sợ hãi thứ hai này về tương lai, như vậy là vừa đủ để vị Tỷ-kheo sống không phóng dật, nhiệt tâm, tinh cần, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ.`, ref: "Tăng Chi Bộ 5.78", url: "https://loicuaducphat.org/an/an5.78.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo quán sát như sau: “Nay không có đói kém, được mùa, đồ ăn khất thực dễ kiếm được, thật dễ dàng để nuôi sống bằng khất thực nỗ lực. Nhưng rồi đến thời có nạn đói, mất mùa, đồ ăn khất thực nỗ lực được, không dễ gì nuôi sống bằng khất thực nỗ lực. Và những người bị nạn đói sẽ dời đến chỗ nào được nhiều đồ ăn; tại đấy, phải sống với quần chúng, phải sống với hỗn tạp. Khi phải sống với quần chúng, phải sống với hỗn tạp, thật không dễ gì để tác ý đến giáo pháp của các đức Phật, thật không dễ gì để sống tại các trú xứ rừng núi cao nguyên xa vắng. Trước khi trạng thái ấy đến với ta, không đáng ưa, không đáng thích, không khả ý, ta hãy hăng hái tinh cần trước khi thời ấy đến, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ. Và nếu thành tựu trạng thái ấy, có bị đói kém, ta sẽ sống được thoải mái”.\nNày các Tỷ-kheo, do quán thấy sợ hãi thứ ba này về tương lai, như vậy là vừa đủ để vị Tỷ-kheo sống không phóng dật, nhiệt tâm, tinh cần, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ.`, ref: "Tăng Chi Bộ 5.78", url: "https://loicuaducphat.org/an/an5.78.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo quán sát như sau: “Nay các loài Người sống với nhau thuận hòa, hoan hỷ với nhau, không cãi lộn nhau, hòa hợp như nước với sữa, sống nhìn nhau với cặp mắt ái kính. Nhưng rồi đến thời có sự sợ hãi về nạn cướp rừng, dân chúng trong nước leo lên xe để đi trốn tại nơi nào có sự sợ hãi, dân chúng di động đến chỗ có sự an ổn. Tại đấy, phải sống với quần chúng, phải sống với hỗn tạp, thật không dễ với quần chúng, sống với hỗn tạp, thật không dễ gì để tác ý đến giáo pháp của các đức Phật, thật không dễ gì để sống tại các trú xứ rừng núi cao nguyên xa vắng.. Trước khi trạng thái ấy đến với ta, không đáng ưa, không đáng thích, không khả ý, ta phải hăng hái tinh cần trước khi thời ấy đến để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ. Và nếu thành tựu trạng thái ấy, có gặp sự sợ hãi, ta sẽ sống được thoải mái”.\nNày các Tỷ-kheo, do quán thấy sợ hãi thứ tư này về tương lai, như vậy là vừa đủ để Tỷ-kheo sống không phóng dật, nhiệt tâm, tinh cần, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ.`, ref: "Tăng Chi Bộ 5.78", url: "https://loicuaducphat.org/an/an5.78.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo quán sát như sau: “ Nay chúng Tăng hòa hợp, cùng nhau hoan hỷ, không tranh luận nhau, sống thoải mái cùng chung một lời dạy... nhưng rồi đến thời chúng Tăng chia rẽ. Khi chúng Tăng chia rẽ, thật không dễ gì để tác ý đến giáo pháp của các đức Phật. Thật không dễ gì để sống tại các trú xứ rừng núi, cao nguyên xa vắng. Trước khi trạng thái ấy đến với ta, không đáng ưa, không đáng thích, không khả ý, ta hãy hăng hái tinh cần trước khi thời ấy đến, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ. Và nếu thành tựu trạng thái ấy, chúng Tăng có chia rẽ, ta sẽ sống được thoải mái”.\nNày các Tỷ-kheo, do quán thấy sợ hãi thứ năm này về tương lai, như vậy là vừa đủ để vị Tỷ-kheo sống không phóng dật, nhiệt tâm, tinh cần, để chứng đạt những gì chưa chứng đạt, chứng đắc những gì chưa chứng đắc, chứng ngộ những gì chưa chứng ngộ.`, ref: "Tăng Chi Bộ 5.78", url: "https://loicuaducphat.org/an/an5.78.html#content" },

{ text: `Này các Tỷ-kheo, các Tỷ-kheo trong tương lai sẽ tham muốn các y tốt đẹp. Do họ tham muốn các y tốt đẹp, họ sẽ từ bỏ các y nhặt nơi đống rác, họ sẽ từ bỏ các khu rừng, các vùng cao nguyên, các trú xứ xa vắng, họ sẽ đi đến các làng, thị trấn, kinh đô vua chúa và sống tại các chỗ ấy. Vì nhân y áo, họ sẽ rơi vào những hành vi tầm cầu không thích hợp. Này các Tỷ-kheo, đây là sợ hãi thứ nhất về tương lai, hiện nay chưa sanh khởi, nhưng sẽ sanh khởi trong tương lai. Các Thầy cần phải hoàn toàn rõ biết chúng. Sau khi hoàn toàn rõ biết, cần phải tinh tấn để đoạn trừ sợ hãi ấy.`, ref: "Tăng Chi Bộ 5.80", url: "https://loicuaducphat.org/an/an5.80.html#content" },

{ text: `Này các Tỷ-kheo, những Tỷ-kheo trong tương lai sẽ tham muốn các đồ ăn khất thực ngon lành. Do họ tham muốn các đồ ăn khất thực ngon lành, họ sẽ từ bỏ nếp sống khất thực, từ bỏ các khu rừng, các vùng cao nguyên, các trú xứ xa vắng. Họ sẽ đi vào các làng, thị trấn, kinh đô của vua và sinh sống tại đấy, tìm cầu các món ăn thượng vị, như với đầu lưỡi. Do nhân đồ ăn khất thực, họ sẽ rơi vào nhiều hành động tầm cầu không thích hợp. Này các Tỷ-kheo, đây là sợ hãi thứ hai về tương lai, hiện nay chưa sanh khởi, nhưng sẽ sanh khởi trong tương lai. Các Thầy cần phải hoàn toàn rõ biết chúng. Sau khi hoàn toàn rõ biết, cần phải tinh tấn để đoạn trừ sợ hãi ấy.`, ref: "Tăng Chi Bộ 5.80", url: "https://loicuaducphat.org/an/an5.80.html#content" },

{ text: `Này các Tỷ-kheo, những Tỷ-kheo trong tương lai sẽ tham muốn sàng tọa tốt đẹp. Do họ tham muốn các sàng tọa tốt đẹp, họ sẽ từ bỏ nếp sống dưới gốc cây, họ sẽ từ bỏ các khu rừng, các vùng cao nguyên, các trú xứ xa vắng. Họ sẽ đi vào các làng, thị trấn, kinh đô của vua và sinh sống tại đấy. Vì nhân sàng tọa, họ sẽ rơi vào nhiều hành động tầm cầu không thích hợp. Này các Tỷ-kheo, đây là sợ hãi thứ ba về tương lai, hiện nay chưa sanh khởi, nhưng sẽ sanh khởi trong tương lai. Các Thầy cần phải hoàn toàn rõ biết chúng. Sau khi hoàn toàn rõ biết, cần phải tinh tấn để đoạn trừ sợ hãi ấy.`, ref: "Tăng Chi Bộ 5.80", url: "https://loicuaducphat.org/an/an5.80.html#content" },

{ text: `Này các Tỷ-kheo, sẽ có những Tỷ-kheo trong tương lai sẽ sống liên hệ với Tỷ-kheo-ni, các chánh học nữ, các Sa-di-ni. Khi sống liên hệ với Tỷ-kheo-ni, chánh học nữ, Sa-di-ni, này các Tỷ-kheo, được chờ đợi là: Họ sẽ không thích thú sống Phạm hạnh, hay họ sẽ rơi vào một trong những tội lỗi ô nhiễm, sẽ từ bỏ học pháp và trở lui lại đời sống thế tục. Này các Tỷ-kheo, đây là sợ hãi thứ tư về tương lai, hiện nay chưa sanh khởi. Các Thầy cần phải hoàn toàn rõ biết chúng. Sau khi hoàn toàn rõ biết, cần phải tinh tấn để đoạn trừ sợ hãi ấy.`, ref: "Tăng Chi Bộ 5.80", url: "https://loicuaducphat.org/an/an5.80.html#content" },

{ text: `Này các Tỷ-kheo, sẽ có những Tỷ-kheo trong tương lai sống liên hệ với các người có hệ lụy đến khu vườn, với các Sa-di. Khi sống liên hệ với các người có hệ lụy đến khu vườn và với các Sa-di, này các Tỷ-kheo, được chờ đợi là họ sẽ sống và tận hưởng các vật liệu cất chứa, và họ sẽ làm các thô tướng đối với đất đai và đối với các sản phẩm trồng trọt. Này các Tỷ-kheo, đây là sợ hãi thứ năm về tương lai, hiện nay chưa sanh khởi, nhưng sẽ sanh khởi trong tương lai. Các Thầy cần phải hoàn toàn rõ biết chúng. Sau khi hoàn toàn rõ biết, các Thầy cần phải tinh tấn để đoạn tận sự sợ hãi ấy.`, ref: "Tăng Chi Bộ 5.80", url: "https://loicuaducphat.org/an/an5.80.html#content" },


{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo Trưởng lão đối với các vị đồng Phạm hạnh không được ái mộ, không được ưa thích, không được tôn trọng, không được làm gương để tu tập. Thế nào là năm? Bị tham ái bởi những gì khả ái, bị hiềm hận bởi những gì đáng hiềm hận, bị si mê bởi những gì đáng si mê, bị phẫn nộ bởi những gì đáng phẫn nộ, bị say đắm bởi những gì đáng say đắm. Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo Trưởng Lão đối với các vị đồng Phạm hạnh không được ái mộ, không được ưa thích, không được tôn trọng, không được làm gương để tu tập.`, ref: "Tăng Chi Bộ 5.81", url: "https://loicuaducphat.org/an/an5.81.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo Trưởng lão đối với các vị đồng Phạm hạnh được ái mộ, được ưa thích, được tôn trọng, được làm gương để tu tập. Thế nào là năm? Không bị tham bởi những gì khả ái, không bị hiềm hận bởi những gì đáng hiềm hận, không bị si mê bởi những gì đáng si mê, không bị phẫn nộ bởi những gì đáng phẫn nộ, không bị say đắm bởi những gì đáng say đắm. Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo Trưởng Lão đối với các vị đồng Phạm hạnh được ái mộ, được ưa thích, được tôn trọng, được làm gương để tu tập.`, ref: "Tăng Chi Bộ 5.81", url: "https://loicuaducphat.org/an/an5.81.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, một Tỷ-kheo Trưởng lão đối với các vị đồng Phạm hạnh không được ái mộ, không được ưa thích, không được tôn trọng, không được làm gương để tu tập. Thế nào là năm? Lừa đảo, siểm nịnh (hư đàm), hiện tướng (gợi ý), gièm pha, lấy lợi cầu lợi. Thành tựu năm pháp này, này các Tỷ-kheo, một Tỷ-kheo Trưởng lão đối với các vị đồng Phạm hạnh không được ái mộ, không được ưa thích, không được tôn trọng, không được làm gương để tu tập.`, ref: "Tăng Chi Bộ 5.83", url: "https://loicuaducphat.org/an/an5.83.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, một Tỷ-kheo Trưởng lão đối với các vị đồng Phạm hạnh được ái mộ, được ưa thích, được tôn trọng, được làm gương để tu tập. Thế nào là năm? Có lòng tin, có hổ thẹn, có biết sợ, tinh cần, tinh tấn và có tuệ. Thành tựu năm pháp này, này các Tỷ-kheo, một Tỷ-kheo Trưởng lão đối với các vị đồng Phạm hạnh được ái mộ, được ưa thích, được tôn trọng, được làm gương để tu tập.`, ref: "Tăng Chi Bộ 5.84", url: "https://loicuaducphat.org/an/an5.84.html#content" },

{ text: `Thành tựu năm pháp, này các Tỷ-kheo, một Tỷ-kheo Trưởng lão đối với các vị đồng Phạm hạnh được ái mộ, được ưa thích, được tôn trọng, được làm gương để tu tập. Thế nào là năm? Có giới, sống được bảo vệ với sự bảo vệ của giới bổn, đầy đủ oai nghi chánh hạnh, thấy sự sợ hãi trong các tội nhỏ nhiệm, chấp nhận và học tập các học pháp, nghe nhiều, thọ trì điều được nghe, tích tập điều được nghe. Các pháp nào sơ thiện, trung thiện, hậu thiện, có nghĩa, có văn, đề cao đời sống Phạm hạnh hoàn toàn đầy đủ thanh tịnh, những pháp ấy, vị ấy đã nghe nhiều, đã nắm giữ, đã ghi nhớ nhờ đọc nhiều lần, chuyên ý quán sát, khéo thành tựu nhờ chánh kiến; thiện ngôn dùng lời thiện ngôn, lời nói tao nhã, ý nghĩa minh bạch, giọng nói không bập bẹ, phều phào, giải thích nghĩa lý minh xác, chứng được không khó khăn, chứng được không mệt nhọc, chứng được không phí sức bốn Thiền, thuộc tăng thượng tâm, đem đến hiện tại lạc trú. Do đoạn tận các lậu hoặc, vị ấy tự mình với thắng trí chứng ngộ, chứng đạt và an trú ngay trong hiện tại vô lậu tâm giải thoát, tuệ giải thoát.\nThành tựu năm pháp này, này các Tỷ-kheo, một Tỷ-kheo Trưởng lão đối với các vị đồng Phạm hạnh được ái mộ, được ưa thích, được tôn trọng, được làm gương để tu tập.`, ref: "Tăng Chi Bộ 5.87", url: "https://loicuaducphat.org/an/an5.87.html#content" },

{ text: `Năm pháp này, này các Tỷ-kheo, khiến Tỷ-kheo hữu học thối chuyển. Thế nào là năm? Ưa công việc, ưa đàm luận, ưa ngủ, ưa có quần chúng, không quán sát tâm như đã được giải thoát. Năm pháp này, này các Tỷ-kheo, khiến Tỷ-kheo hữu học thối chuyển.`, ref: "Tăng Chi Bộ 5.89", url: "https://loicuaducphat.org/an/an5.89.html#content" },

{ text: `Năm pháp này, này các Tỷ-kheo, không khiến Tỷ-kheo hữu học thối chuyển. Thế nào là năm? Không ưa công việc, không ưa đàm luận, không ưa ngủ, không ưa có quần chúng, quán sát tâm như đã được giải thoát. Năm pháp này, này các Tỷ-kheo, không khiến Tỷ-kheo hữu học thối chuyển.`, ref: "Tăng Chi Bộ 5.89", url: "https://loicuaducphat.org/an/an5.89.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo hữu học có nhiều công việc, có nhiều việc phải làm, khéo léo trong công việc phải làm, từ bỏ độc cư Thiền tịnh, không chuyên chú vào nội tâm tịnh chỉ. Ðây là pháp thứ nhất khiến Tỷ-kheo hữu học thối chuyển. Lại nữa, này các Tỷ-kheo, Tỷ-kheo hữu học suốt ngày làm những công việc nhỏ nhặt, từ bỏ độc cư Thiền tịnh, không có chuyên chú vào nội tâm tịnh chỉ. Ðây là pháp thứ hai khiến vị Tỷ-kheo hữu học thối chuyển. Lại nữa, này các Tỷ-kheo, Tỷ-kheo hữu học sống liên hệ nhiều với các vị tại gia và xuất gia, hệ lụy với các sự việc tại gia không thích đáng, từ bỏ độc cư Thiền tịnh, không chuyên chú vào nội tâm tịnh chỉ. Ðây là pháp thứ ba khiến Tỷ-kheo hữu học thối chuyển.`, ref: "Tăng Chi Bộ 5.90", url: "https://loicuaducphat.org/an/an5.90.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, vị Tỷ-kheo hữu học đối với các câu chuyện nghiêm trang, khai tâm, như câu chuyện về ít dục, câu chuyện về tri túc, câu chuyện về viễn ly, câu chuyện về không hội họp, câu chuyện về tinh cần tinh tấn, câu chuyện về giới, câu chuyện về định, câu chuyện về tuệ, câu chuyện về giải thoát, câu chuyện về giải thoát tri kiến. Các câu chuyện ấy có được không khó khăn, có được không mệt nhọc, có được không phí sức, không từ bỏ độc cư Thiền tịnh, chuyên chú vào nội tâm tịnh chỉ. Ðây là pháp thứ năm, này các Tỷ-kheo, không đưa đến thối chuyển cho vị Tỷ-kheo hữu học.`, ref: "Tăng Chi Bộ 5.90", url: "https://loicuaducphat.org/an/an5.90.html#content" },
{ text: `Thành tựu năm pháp, này các Tỷ-kheo, vị Tỷ-kheo thực hành Niệm hơi thở vô hơi thở ra, không bao lâu thể nhập vào bất động. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo muốn không có nhiều, công việc không có nhiều, nuôi sống dễ dàng, khéo tri túc với những nhu yếu ở đời, ăn uống ít, không chuyên lo về bao tử; ít thụy miên, chuyên chú trong giác tỉnh; nghe nhiều, thọ trì nhiều, tích lũy điều đã nghe; các pháp nào sơ thiện, trung thiện, hậu thiện, có nghĩa, có văn, tán thán Phạm hạnh hoàn toàn viên mãn thanh tịnh, các pháp ấy, Tỷ-kheo đã nghe nhiều, đã nắm giữ, đã ghi nhớ nhờ đọc nhiều lần, chuyên ý quán sát, khéo thành tựu nhờ chánh kiến; quán sát tâm như đã được giải thoát. Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo thực hành Niệm hơi thở vô hơi thở ra, không bao lâu thể nhập vào bất động.`, ref: "Tăng Chi Bộ 5.96", url: "https://loicuaducphat.org/an/an5.96.html#content" },

{ text: `Con sư tử, này các Tỷ-kheo, là đồng nghĩa với bậc A-la-hán Chánh Ðẳng Giác. Khi Như Lai thuyết pháp cho hội chúng, tức là rống tiếng rống con sư tử. Này các Tỷ-kheo, nếu Như Lai thuyết pháp cho các vị Tỷ-kheo, Như Lai thuyết pháp hết sức cẩn thận, chu đáo, không phải không cẩn thận, chu đáo. Nếu Như Lai thuyết pháp cho các vị Tỷ-kheo Ni, Như Lai thuyết pháp hết sức cẩn thận, chu đáo, không phải không cẩn thận, chu đáo. Nếu Như Lai thuyết pháp cho các hàng nam cư sĩ, Như Lai thuyết pháp hết sức cẩn thận, chu đáo, không phải không cẩn thận, chu đáo. Nếu Như Lai thuyết pháp cho các hàng nữ cư sĩ, Như Lai thuyết pháp hết sức cẩn thận, chu đáo, không phải không cẩn thận, chu đáo. Nếu Như Lai thuyết pháp cho các hàng phàm phu , cho các người bắt chim hay xin ăn, Như Lai thuyết pháp hết sức cẩn thận, chu đáo, không phải không cẩn thận, chu đáo. Vì cớ sao? Vì Như Lai là bậc tôn trọng Pháp, này các Tỷ-kheo, là bậc tôn kính Pháp.`, ref: "Tăng Chi Bộ 5.99", url: "https://loicuaducphat.org/an/an5.99.html#content" },


{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo có lòng tin, có giới, có nghe nhiều, có tinh cần tinh tấn, có trí tuệ. Cái gì làm cho kẻ không có lòng tin sợ hãi, này các Tỷ-kheo, cái ấy không làm cho người có lòng tin sợ hãi. Do vậy, pháp này là pháp làm cho bậc Hữu học không sợ hãi. Cái gì làm cho kẻ ác giới sợ hãi, này các Tỷ kheo, cái ấy không làm cho người có giới sợ hãi. Do vậy, pháp này là pháp làm cho bậc Hữu học không sợ hãi. Cái gì làm cho kẻ ít nghe sợ hãi, này các Tỷ-kheo, cái ấy không làm cho người nghe nhiều sợ hãi. Do vậy, pháp này là pháp làm cho bậc Hữu học không sợ hãi. Cái gì làm cho kẻ biếng nhác sợ hãi, này các Tỷ-kheo, cái ấy không làm cho kẻ tinh cần tinh tấn sợ hãi. Do vậy, pháp này là pháp làm cho bậc Hữu học không sợ hãi. Cái gì làm cho kẻ ác tuệ sợ hãi, này các Tỷ-kheo, cái ấy không làm cho người có trí tuệ sợ hãi. Do vậy, pháp này là pháp làm cho bậc Hữu học không sợ hãi.`, ref: "Tăng Chi Bộ 5.101", url: "https://loicuaducphat.org/an/an5.101.html#content" },


{ text: `Này các Tỷ-kheo, có năm an ổn trú này, Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo an trú từ thân nghiệp đối với các đồng Phạm hạnh, cả trước mặt và sau lưng; an trú từ khẩu nghiệp đối với các đồng Phạm hạnh, trước mặt và sau lưng; an trú từ ý nghiệp đối với các đồng Phạm hạnh, trước mặt và sau lưng; đối với các giới không bị bể vụn, không bị sứt mẻ, không bị nhiễm ô, không bị uế nhiễm, đem lại giải thoát, được người trí tán thán, không bị chấp thủ, đưa đến Thiền định, vị ấy sống thành tựu các giới như vậy đối với các đồng Phạm hạnh, trước mặt và sau lưng, và đối với tri kiến này, thuộc bậc Thánh đưa đến xuất ly, được người thực hành chân chánh đoạn diệt khổ đau, vị ấy sống thành tựu tri kiến như vậy đối với các đồng Phạm hạnh, trước mặt và sau lưng. Năm pháp này, này các Tỷ-kheo, là năm an ổn trú.`, ref: "Tăng Chi Bộ 5.105", url: "https://loicuaducphat.org/an/an5.105.html#content" },

{ text: `Thành tựu năm pháp, này các Tỷ-kheo, Tỷ-kheo thân cận các gia đình, được các gia đình ái mộ, thích ý, kính trọng, noi gương để tu tập. Thế nào là năm? Vị ấy không thân mật với người không thân tín, không can thiệp vào việc không có thẩm quyền, không ra vào với các phần tử chống đối, không nói riêng một bên tai, không xin quá nhiều. Thành tựu năm pháp, này các Tỷ-kheo, Tỷ-kheo thân cận các gia đình, được các gia đình ái mộ, thích ý, kính trọng, noi gương để tu tập.`, ref: "Tăng Chi Bộ 5.111", url: "https://loicuaducphat.org/an/an5.111.html#content" },

{ text: `Thành tựu năm pháp, này các Tỷ-kheo, Tỷ-kheo không có thể đạt đến và an trú chánh định. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo không kham nhẫn các sắc, không kham nhẫn các tiếng, không kham nhẫn các hương, không kham nhẫn các vị, không kham nhẫn các xúc. Thành tựu năm pháp, này các Tỷ-kheo, Tỷ-kheo không có thể đạt đến và an trú chánh định.`, ref: "Tăng Chi Bộ 5.113", url: "https://loicuaducphat.org/an/an5.113.html#content" },

{ text: `Thành tựu năm pháp, này các Tỷ-kheo, Tỷ-kheo có thể đạt đến và an trú chánh định. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo kham nhẫn các sắc, kham nhẫn các tiếng, kham nhẫn các hương, kham nhẫn các vị, kham nhẫn các xúc. Thành tựu năm pháp, này các Tỷ-kheo, Tỷ-kheo có thể đạt đến và an trú chánh định.`, ref: "Tăng Chi Bộ 5.113", url: "https://loicuaducphat.org/an/an5.113.html#content" },

{ text: `Năm pháp này, này các Tỷ-kheo, gia tăng tuổi thọ. Thế nào là năm? Làm việc thích đáng, biết vừa phải trong việc thích đáng, ăn các đồ ăn tiêu hóa, du hành phải thời, và sống Phạm hạnh. Năm pháp này, này các Tỷ-kheo, gia tăng tuổi thọ.`, ref: "Tăng Chi Bộ 5.125", url: "https://loicuaducphat.org/an/an5.125.html#content" },

{ text: `Thành tựu năm pháp này, vị Tỷ-kheo không đủ điều kiện để sống biệt lập chúng Tăng. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo không tự vừa đủ với y nhận được chỗ này chỗ kia; không tự vừa đủ với đồ ăn khất thực nhận được chỗ này chỗ kia; không tự vừa đủ với sàng tọa nhận được chỗ này chỗ kia; không tự vừa đủ với dược phẩm trị bệnh nhận được chỗ này chỗ kia; và sống với nhiều tư duy về dục. Thành tựu năm pháp này, này các Tỷ-kheo, một Tỷ-kheo không đủ điều kiện để sống biệt lập chúng Tăng.`, ref: "Tăng Chi Bộ 5.127", url: "https://loicuaducphat.org/an/an5.127.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, một Tỷ-kheo đủ điều kiện để sống biệt lập với chúng Tăng. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo tự vừa đủ với y nhận được chỗ này chỗ kia; tự vừa đủ với đồ ăn khất thực nhận được chỗ này chỗ này; tự vừa đủ với sàng tọa nhận được chỗ này chỗ kia; tự vừa đủ với dược phẩm nhận được chỗ này chỗ kia; sống nhiều tư duy về viễn ly. Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo đủ điều kiện để sống biệt lập với chúng Tăng.`, ref: "Tăng Chi Bộ 5.127", url: "https://loicuaducphat.org/an/an5.127.html#content" },

{ text: `Có năm điều khổ này cho Sa-môn. Thế nào là năm? Ở đây, này các Tỷ-kheo không tự vừa đủ với y nhận được chỗ này chỗ kia; không tự vừa đủ với đồ ăn khất thực nhận được chỗ này chỗ kia; không tự vừa đủ với sàng tọa nhận được chỗ này chỗ kia; không tự vừa đủ với dược phẩm trị bệnh nhận được chỗ này chỗ kia; sống không vui thích trong Phạm hạnh. Này các Tỷ-kheo, có năm điều khổ này cho Sa-môn.`, ref: "Tăng Chi Bộ 5.128", url: "https://loicuaducphat.org/an/an5.128.html#content" },

{ text: `Có năm an lạc này, này các Tỷ-kheo, cho Sa-môn. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo tự vừa đủ với y nhận được chỗ này chỗ kia; tự vừa đủ với đồ ăn khất thực nhận được chỗ này chỗ kia; tự vừa đủ với sàng tọa nhận được chỗ này chỗ kia; tự vừa đủ với dược phẩm trị bệnh nhận được chỗ này chỗ kia; sống vui thích trong Phạm hạnh. Này các Tỷ-kheo, có năm an lạc này cho vị Sa-môn.`, ref: "Tăng Chi Bộ 5.128", url: "https://loicuaducphat.org/an/an5.128.html#content" },

{ text: `Này các Tỷ-kheo, có năm điều tổn thất này. Thế nào là năm? Tổn thất bà con, tổn thất tài sản, tổn thất tật bệnh, tổn thất giới, tổn thất tri kiến. Này các Tỷ-kheo, không do nhân tổn thất bà con, hay không do nhân tổn thất tài sản, hay không do nhân tổn thất bệnh hoạn mà các loài hữu tình sau khi thân hoại mạng chung sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Này các Tỷ-kheo, chính do nhân tổn thất giới, hay tổn thất tri kiến mà các loài hữu tình sau khi thân hoại mạng chung sanh vào cõi dữ, ác thú, địa ngục. Này các Tỷ-kheo, có năm tổn thất này.`, ref: "Tăng Chi Bộ 5.130", url: "https://loicuaducphat.org/an/an5.130.html#content" },

{ text: `Này các Licchavì, sự hiện hữu của năm châu báu khó tìm được ở đời. Và thế nào là năm? Sự hiện hữu của Như Lai, bậc A-la-hán, Chánh Ðẳng Giác khó tìm được ở đời. Hạng người có thể thuyết giảng Pháp và Luật do Như Lai tuyên bố khó tìm được ở đời. Người hiểu được lời thuyết giảng về Pháp là Luật do Như Lai tuyên bố khó tìm được ở đời. Người đem thực hành các pháp và tùy pháp được hiểu từ lời thuyết giảng về Pháp và Luật do Như Lai tuyên bố khó tìm được ở đời. Người biết ơn, và nhớ ơn khó tìm được ở đời.`, ref: "Tăng Chi Bộ 5.143", url: "https://loicuaducphat.org/an/an5.143.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo không đáng được làm bạn. Thế nào là năm? Bảo làm việc đồng áng; ưa thích kiện tụng; chống đối các Tỷ-kheo lãnh đạo; sống đời sống không có mục đích, kéo dài đời sống như vậy; không có khả năng thỉnh thoảng trình bày, khích lệ, làm cho phấn khởi, làm cho hoan hỷ với một bài thuyết pháp. Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo không đáng được làm bạn.`, ref: "Tăng Chi Bộ 5.146", url: "https://loicuaducphat.org/an/an5.146.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo đáng được làm một người bạn. Thế nào là năm? Không bảo làm việc đồng áng; không ưa thích kiện tụng; không chống đối các Tỷ-kheo lãnh đạo; không sống đời sống không có mục đích, không kéo dài đời sống như vậy; có khả năng thỉnh thoảng trình bày, khích lệ, làm cho phấn khởi, làm cho hoan hỷ với một bài thuyết pháp. Thành tựu năm pháp này, này các Tỷ-kheo, Tỷ-kheo đáng được làm bạn.`, ref: "Tăng Chi Bộ 5.146", url: "https://loicuaducphat.org/an/an5.146.html#content" },

{ text: `Có năm loại bố thí này, này các Tỷ-kheo, không xứng bậc Chân nhân. Thế nào là năm? Bố thí không cung kính, bố thí không suy nghĩ, bố thí không tự tay mình, bố thí đồ quăng bỏ, bố thí không nghĩ đến tương lai. Các pháp này, này các Tỷ-kheo, là năm loại bố thí không xứng bậc Chân nhân. Năm loại bố thí này, này các Tỷ-kheo, là loại bố thí xứng bậc Chân nhân. Thế nào là năm? Bố thí có cung kính, bố thí có suy nghĩ, bố thí tự tay mình, bố thí đồ không quăng bỏ, bố thí có nghĩ đến tương lai. Các pháp này, này các Tỷ-kheo, là năm loại bố thí xứng bậc Chân nhân.`, ref: "Tăng Chi Bộ 5.147", url: "https://loicuaducphat.org/an/an5.147.html#content" },

{ text: `Này các Tỷ-kheo, có năm loại bố thí này xứng bậc Chân nhân. Thế nào là năm? Bố thí có lòng tin, bố thí có kính trọng, bố thí đúng thời, bố thí với tâm không gượng ép, bố thí không làm thương tổn mình và người. Này các Tỷ-kheo, có năm loại bố thí xứng bậc Chân nhân này.`, ref: "Tăng Chi Bộ 5.148", url: "https://loicuaducphat.org/an/an5.148.html#content" },

{ text: `Này các Tỷ-kheo, sau khi bố thí với lòng tin chỗ nào, chỗ nào, quả dị thục của sự bố thí ấy đem lại kết quả: Người ấy được giàu sang, đại phú, tài sản sung mãn, đẹp trai, dễ ngó, có thành tín và thành tựu dung sắc thù thắng như hoa sen. Và này các Tỷ-kheo, sau khi bố thí có cung kính, chỗ nào, chỗ nào, quả dị thục của sự bố thí ấy đem lại kết quả: Người ấy được giàu sang, đại phú, tài sản sung mãn; và các con trai, các bà vợ, các người nô tỳ, các người đưa tin, các người làm công, những người ấy đều sẵn sàng vâng theo người ấy, họ lóng tai và phục vụ với tâm hiểu biết.`, ref: "Tăng Chi Bộ 5.148", url: "https://loicuaducphat.org/an/an5.148.html#content" },

{ text: `Và này các Tỷ-kheo, sau khi bố thí đúng thời, chỗ nào, chỗ nào, quả dị thục của sự bố thí ấy đem lại kết quả: Người ấy được giàu sang, đại phú, tài sản sung mãn; và các vật dụng đến với người ấy đúng thời và sung túc. Và này các Tỷ-kheo, sau khi bố thí không làm thương tổn mình và người, chỗ nào, chỗ nào, quả dị thục của sự bố thí ấy đem lại kết quả: Người ấy được giàu sang, đại phú, tài sản sung mãn; và không một tai nạn nào từ đâu đến, đến với tài sản của người ấy, hoặc từ lửa, từ nước, từ vua, từ ăn trộm, từ các người thù địch hay từ các người thừa tự.`, ref: "Tăng Chi Bộ 5.148", url: "https://loicuaducphat.org/an/an5.148.html#content" },

{ text: `Này Ananda, thật không dễ gì để thuyết pháp cho các người khác. Ðể thuyết pháp cho các người khác, này Ananda, sau khi nội tâm an trú được năm pháp, mới nên thuyết pháp cho các người khác. Thế nào là năm? “Ta sẽ thuyết pháp tuần tự”, thuyết pháp cho người khác cần phải suy nghĩ như vậy. “Ta sẽ thuyết với mắt nhìn vào pháp môn”, thuyết pháp cho người khác cần phải suy nghĩ như vậy. “Ta sẽ thuyết vì lòng từ mẫn”, thuyết pháp cho người khác cần phải suy nghĩ như vậy. “Ta sẽ thuyết pháp, không phải vì tài vật”, thuyết pháp cho người khác cần phải suy nghĩ như vậy. “Ta sẽ thuyết pháp, không làm thương tổn cho mình và cho người”. Thuyết pháp cho người khác cần phải suy nghĩ như vậy. Này Ananda, thật không dễ gì để thuyết pháp cho các người khác. Ðể thuyết pháp cho các người khác, này Ananda, sau nội tâm an trú được năm pháp, mới nên thuyết pháp cho các người khác.`, ref: "Tăng Chi Bộ 5.159", url: "https://loicuaducphat.org/an/an5.159.html#content" },

{ text: `Năm pháp này khởi lên, này các Tỷ-kheo, thật khó trừ khử. Thế nào là năm? Tham khởi lên, thật khó trừ khử; sân khởi lên, thật khó trừ khử; si khởi lên, thật khó trừ khử; ham nói khởi lên, thật khó trừ khử; tâm lang thang thật khó trừ khử. Năm pháp này đã khởi lên, này các Tỷ-kheo, thật khó trừ khử.`, ref: "Tăng Chi Bộ 5.160", url: "https://loicuaducphat.org/an/an5.160.html#content" },

{ text: `Này các Hiền giả, khi Tỷ-kheo buộc tội muốn buộc tội người khác, hãy an trú nội tâm năm pháp rồi hãy buộc tội. Thế nào là năm? “Tôi sẽ nói đúng thời, không phải phi thời”; “Tôi sẽ nói chơn thật, không phải phi chơn thật”; “Tôi sẽ nói nhu hòa, không phải thô bạo”; “Tôi sẽ nói lời liên hệ đến lợi ích, không phải lời không liên hệ đến lợi ích”; “Tôi sẽ nói với từ tâm, không phải với sân tâm”. Này các Hiền giả, khi vị Tỷ-kheo buộc tội muốn buộc tội người khác, hãy an trú nội tâm năm pháp rồi hãy buộc tội người khác.`, ref: "Tăng Chi Bộ 5.167", url: "https://loicuaducphat.org/an/an5.167.html#content" },

{ text: `Thế Tôn nói với Gia chủ Anàthapindika đang ngồi xuống một bên: - Này Gia chủ, Ông đã cung cấp cho chúng Tỷ-kheo các vật dụng cần thiết như y, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh. Nhưng Ông chớ có bằng lòng với ý nghĩ: “Chúng ta đã cung cấp cho chúng Tỷ-kheo các vật dụng cần thiết như y, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh”. Do vậy, này Gia chủ, Ông cần phải học tập như sau: “Với phương tiện nào chúng ta thỉnh thoảng đạt được và an trú hỷ do viễn ly sanh”. Như vậy, này Gia chủ, Ông cần phải học tập.`, ref: "Tăng Chi Bộ 5.176", url: "https://loicuaducphat.org/an/an5.176.html#content" },

{ text: `Này Sàriputta, trong khi Thánh đệ tử đạt được và an trú hỷ do viễn ly sanh, trong thời gian ấy, năm sự kiện không xảy ra cho người ấy: Khổ và ưu liên hệ đến dục trong thời gian ấy không xảy ra cho người ấy. Lạc và hỷ liên hệ đến dục trong thời gian ấy không xảy ra cho người ấy. Khổ và ưu liên hệ đến bất thiện trong thời gian ấy không xảy ra cho người ấy. Lạc và hỷ liên hệ đến bất thiện trong thời gian ấy không xảy ra cho người ấy. Khổ và ưu liên hệ đến thiện, trong thời gian ấy không xảy ra cho người ấy. Này Sàriputta, trong khi vị Thánh đệ tử đạt đến và an trú hỷ do viễn ly sanh, trong thời gian ấy, năm sự kiện này không xảy ra cho người ấy.`, ref: "Tăng Chi Bộ 5.176", url: "https://loicuaducphat.org/an/an5.176.html#content" },

{ text: `Có năm nghề buôn bán này, này các Tỷ-kheo, một nam cư sĩ không nên làm. Thế nào là năm? Buôn bán đao kiếm, buôn bán người, buôn bán thịt, buôn bán rượu, buôn bán thuốc độc. Có năm nghề buôn bán này, này các Tỷ-kheo, một nam cư sĩ không nên làm.`, ref: "Tăng Chi Bộ 5.177", url: "https://loicuaducphat.org/an/an5.177.html#content" },

{ text: `Ví như này các Tỷ-kheo, từ con bò có sữa, từ sữa có lạc, từ lạc có sanh tô, từ sanh tô có thục tô, từ thục tô có đề hồ. Ðây được gọi là đệ nhất. Cũng vậy, này các Tỷ-kheo, trong năm hạng người sống ở rừng, này các Tỷ-kheo, hạng sống ở rừng vì ít dục, vì biết đủ, vì đoạn giảm, vì viễn ly, vì cầu thiện hành này sống ở rừng. Hạng người này trong năm hạng người ấy là đệ nhất, là tối thắng, là thượng thủ, là tối thượng, là tối diệu.`, ref: "Tăng Chi Bộ 5.181", url: "https://loicuaducphat.org/an/an5.181.html#content" },

{ text: `Ở đây, này Kimbila, khi Như Lai nhập diệt, các Tỷ-kheo, Tỷ-kheo-ni, nam cư sĩ, nữ cư sĩ sống không tôn trọng, không vâng lời bậc Ðạo sư; sống không tôn trọng, không vâng lời Pháp; sống không tôn trọng, không vâng lời chúng Tăng; sống không tôn trọng, không vâng lời học pháp; sống không tôn trọng, không vâng lời lẫn nhau. Do nhân này, do duyên này, này Kimbila, khi Như Lai nhập diệt, diệu pháp không được an trú lâu ngày. Ở đây, này Kimbila, khi Như Lai nhập diệt, các Tỷ-kheo, Tỷ-kheo-ni, nam cư sĩ, nữ cư sĩ sống tôn trọng và vâng lời bậc Ðạo sư; sống tôn trọng và vâng lời Pháp; sống tôn trọng và vâng lời chúng Tăng; sống tôn trọng và vâng lời học pháp; sống tôn trọng và vâng lời lẫn nhau. Ðây là nhân, đây là duyên, này Kimbila, khi Như Lai nhập diệt, diệu pháp được tồn tại lâu dài.`, ref: "Tăng Chi Bộ 5.201", url: "https://loicuaducphat.org/an/an5.201.html#content" },

{ text: `Này các Tỷ-kheo, nghe pháp có năm lợi ích này. Thế nào là năm? Ðược nghe điều chưa nghe, làm cho trong sạch điều được nghe, đoạn trừ nghi, làm cho tri kiến chánh trực, làm cho tâm tịnh tín. Này các Tỷ-kheo, nghe pháp có năm lợi ích này.`, ref: "Tăng Chi Bộ 5.202", url: "https://loicuaducphat.org/an/an5.202.html#content" },

{ text: `Này các Tỷ-kheo, có năm nguy hại này đối với người thất niệm, không tỉnh giác rơi vào giấc ngủ. Thế nào là năm? Ngủ một cách khổ sở; thức dậy một cách khổ sở; thấy ác mộng; chư Thiên không phòng hộ; bất tịnh chảy ra, mộng tinh, di tinh. Này các Tỷ-kheo, có năm nguy hại này đối với người thất niệm, không tỉnh giác rơi vào giấc ngủ. Này các Tỷ-kheo, có năm lợi ích này đối với người trú niệm, tỉnh giác rơi vào giấc ngủ. Thế nào là năm? Ngủ một các ngon lành; thức dậy một cách ngon lành; không thấy ác mộng; chư Thiên phòng hộ; bất tịnh không chảy ra. Này các Tỷ-kheo, có năm lợi ích này đối với người trú niệm, tỉnh giác rơi vào giấc ngủ.`, ref: "Tăng Chi Bộ 5.210", url: "https://loicuaducphat.org/an/an5.210.html#content" },

{ text: `Tỷ-kheo nào, này các Tỷ-kheo, mắng nhiếc, mạ lỵ, các vị tu Phạm hạnh, phỉ báng bậc Thánh, vị ấy được chờ đợi năm sự nguy hại. Thế nào là năm? Phạm tội bị tẩn xuất, chặt đứt con đường hướng thượng; hay phạm một tội nhiễm; hay cảm xúc bệnh hoạn trầm trọng; khi mạng chung tâm bị mê loạn; sau khi thân hoại mạng chung, sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Tỷ-kheo nào, này các Tỷ-kheo, mắng nhiếc, mạ lỵ, các vị tu Phạm hạnh, phỉ báng bậc Thánh, vị ấy được chờ đợi năm sự nguy hại này.`, ref: "Tăng Chi Bộ 5.211", url: "https://loicuaducphat.org/an/an5.211.html#content" },

{ text: `Tỷ-kheo nào, này các Tỷ-kheo, là người gây ra cãi cọ, là người gây ra tranh luận, là người gây ra đấu tranh, là người gây ra các cuộc đấu khẩu, là người gây ra kiện tụng trong Tăng chúng. Vị ấy được chờ đợi năm sự nguy hại. Thế nào là năm? Không chứng điều chưa chứng được; thối thất điều đã chứng được; tiếng ác đồn khắp; khi mạng chung, tâm bị mê loạn; sau khi thân hoại mạng chung, sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Tỷ-kheo nào, này các Tỷ-kheo, là người gây ra cãi cọ, là người gây ra tranh luận, là người gây ra đấu tranh, là người gây ra đấu khẩu, là người gây ra kiện tụng trong Tăng chúng. Vị ấy được chờ đợi năm sự nguy hại này.`, ref: "Tăng Chi Bộ 5.212", url: "https://loicuaducphat.org/an/an5.212.html#content" },

{ text: `Có năm nguy hại này cho người nói nhiều. Thế nào là năm? Nói láo; nói lời hai lưỡi; nói lời độc ác; nói lời phù phiếm; sau khi thân hoại hạng chung, sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Này các Tỷ-kheo, có năm nguy hại này cho người nói nhiều.`, ref: "Tăng Chi Bộ 5.214", url: "https://loicuaducphat.org/an/an5.214.html#content" },

{ text: `Có năm nguy hại này cho người không kham nhẫn. Thế nào là năm? Quần chúng không ái mộ, không ưa thích; nhiều người hận thù; nhiều người tránh né; khi mạng chung, tâm bị mê loạn; sau khi thân hoại mạng chung; sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Này các Tỷ-kheo, có năm nguy hại này cho người không kham nhẫn.`, ref: "Tăng Chi Bộ 5.215", url: "https://loicuaducphat.org/an/an5.215.html#content" },

{ text: `Này các Tỷ-kheo, có năm lợi ích này cho người có kham nhẫn. Thế nào là năm? Quần chúng ái mộ, ưa thích; không có người hận thù; không có nhiều người tránh né; khi mạng chung, tâm không bị mê loạn; sau khi thân hoại mạng chung, được sanh vào thiện thú, Thiên giới, cõi đời này. Này các Tỷ-kheo, có năm lợi ích này cho người có kham nhẫn.`, ref: "Tăng Chi Bộ 5.215", url: "https://loicuaducphat.org/an/an5.215.html#content" },

{ text: `Có năm nguy hại này, này các Tỷ-kheo, cho kẻ không tịnh tín. Thế nào là năm? Những tư tưởng bất tín không được tịnh tín; một số tư tưởng đã tịnh tín có thể đổi khác; không làm theo lời dạy của bậc Ðạo Sư; thế hệ tiếp bắt chước tà kiến; tâm không được tịnh tín. Này các Tỷ-kheo, có năm nguy hại này, cho người không có tịnh tín.`, ref: "Tăng Chi Bộ 5.218", url: "https://loicuaducphat.org/an/an5.218.html#content" },

{ text: `Có năm lợi ích này, này các Tỷ-kheo, cho người có tịnh tín. Thế nào là năm? Những tư tưởng bất tín được tịnh tín; những tư tưởng tịnh tín được tăng trưởng; lời dạy của bậc Ðạo Sư được làm theo; thế hệ tiếp bắt chước theo tri kiến; tâm được tịnh tín. Này các Tỷ-kheo, có năm lợi ích này, cho người có tịnh tín.`, ref: "Tăng Chi Bộ 5.218", url: "https://loicuaducphat.org/an/an5.218.html#content" },

{ text: `Có năm nguy hại này, này các Tỷ-kheo, nếu sống quá lâu tại một chỗ. Thế nào là năm? Ðồ dùng nhiều, cất chứa nhiều đồ dùng; nhiều dược phẩm, cất chứa nhiều dược phẩm; nhiều việc làm, nhiều công việc phải làm, không khéo léo trong những công việc gì phải làm; sống lẫn lộn với gia chủ và xuất gia, tùy thuận trong sự liên hệ với gia chủ; và khi ra đi bỏ trú xứ ấy, ra đi với sự luyến tiếc. Này các Tỷ-kheo, đó là năm nguy hại nếu sống quá lâu tại một chỗ.`, ref: "Tăng Chi Bộ 5.223", url: "https://loicuaducphat.org/an/an5.223.html#content" },

{ text: `Có năm lợi ích này, này các Tỷ-kheo, nếu sống đồng đều tại mỗi chỗ. Thế nào là năm? Ðồ dùng không nhiều, không cất chứa nhiều đồ dùng; dược phẩm không nhiều, không cất chứa nhiều dược phẩm; không có nhiều việc làm, không nhiều công việc phải làm, khéo léo trong những công việc phải làm; không sống lẫn lộn với gia chủ và xuất gia, không tùy thuận trong sự liên hệ với gia chủ; và khi ra đi bỏ trú xứ ấy, ra đi không với sự luyến tiếc. Này các Tỷ-kheo, đó là năm lợi ích nếu sống đồng đều tại một chỗ.`, ref: "Tăng Chi Bộ 5.223", url: "https://loicuaducphat.org/an/an5.223.html#content" },

{ text: `Có năm nguy hại này, này các Tỷ-kheo, nếu sống quá lâu tại một chỗ. Thế nào là năm? Xan tham đối với trú xứ; xan tham đối với gia đình; xan tham đối với đồ vật cúng dường; xan tham đối với công đức; xan tham đối với pháp. Có năm nguy hại này, này các Tỷ-kheo, nếu sống quá lâu tại một chỗ.`, ref: "Tăng Chi Bộ 5.224", url: "https://loicuaducphat.org/an/an5.224.html#content" },

{ text: `Có năm nguy hại này, này các Tỷ-kheo, cho người viếng thăm gia đình. Thế nào là năm? Phạm lỗi không mời mà đến; phạm lỗi ngồi một mình; phạm lỗi ngồi chỗ kín đáo; phạm lỗi thuyết pháp cho nữ nhân hơn năm, sáu chữ; sống với nhiều suy tư về dục. Này các Tỷ-kheo, có năm nguy hại này cho người viếng thăm gia đình.`, ref: "Tăng Chi Bộ 5.225", url: "https://loicuaducphat.org/an/an5.225.html#content" },

{ text: `Có năm nguy hại này, này các Tỷ-kheo, đối với vị Tỷ-kheo sống liên hệ quá nhiều với các gia đình. Thế nào là năm? Luôn luôn thấy nữ nhân; do thấy, nên có liên hệ; do có liên hệ nên có sự thân mật; do có sự thân mật nên có cơ hội (để tư thông); khi tâm đã có tư thông, thời được chờ đợi như sau: Sẽ không có hoan hỷ sống Phạm hạnh; hay sẽ rơi vào trong một tội nhiễm ô; hay từ bỏ học giới; trở lui lại đời sống thế tục. Này các Tỷ-kheo, đây là năm nguy hại đối với vị Tỷ-kheo sống liên hệ quá nhiều với các gia đình.`, ref: "Tăng Chi Bộ 5.226", url: "https://loicuaducphat.org/an/an5.226.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, vị Tỷ-kheo trú tại chỗ trở thành không đáng được làm gương để tu tập. Thế nào là năm? Không đầy đủ về uy nghi, không đầy đủ về trách nhiệm; không nghe nhiều, không thọ trì điều được nghe; không biết sống đoạn giảm, không ưa thích sống Thiền tịnh; lời nói không hiền thiện, không là người nói lời hiền thiện; ác tuệ, đần độn, câm điếc. Thành tựu năm pháp này, này các Tỷ-kheo, vị Tỷ-kheo trú tại chỗ trở thành không đáng được làm gương để tu tập.`, ref: "Tăng Chi Bộ 5.231", url: "https://loicuaducphat.org/an/an5.231.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, vị Tỷ-kheo trú tại chỗ trở thành đáng được làm gương để tu tập. Thế nào là năm? Ðầy đủ về uy nghi, đầy đủ về trách nhiệm; nghe nhiều, thọ trì điều được nghe; biết sống đoạn giảm, ưa thích Thiền tịnh; lời nói hiền thiện, là người nói lời hiền thiện; có trí tuệ, không đần độn, không câm điếc. Thành tựu năm pháp này, này các Tỷ-kheo, vị Tỷ-kheo trú tại chỗ trở thành đáng được làm gương để tu tập.`, ref: "Tăng Chi Bộ 5.231", url: "https://loicuaducphat.org/an/an5.231.html#content" },

{ text: `Thành tựu năm pháp này, này các Tỷ-kheo, vị Tỷ-kheo trú tại chỗ có lòng từ mẫn đối với các gia chủ. Thế nào là năm? Khích lệ tăng thượng giới; khiến chúng sống theo gương pháp; khi đến thăm người bệnh, an trú niệm cho người bệnh như sau: “Các vị hãy an trú niệm vào hướng đến quả A-la-hán”; khi đại chúng Tỷ-kheo đi đến từ nhiều địa phương khác nhau, vị ấy nói với các gia chủ đi đến như sau: “Nay đại chúng Tỷ-kheo đã đến từ nhiều địa phương khác nhau. Các vị hãy làm các phước đức. Nay là thời làm các phước đức”; họ có cúng dường các món ăn gì, hoặc thô hoặc tế, tự mình thọ dụng, không làm cho của tín thí rơi rớt. Thành tựu năm pháp này, này các Tỷ-kheo, vị Tỷ-kheo trú tại chỗ có lòng từ mẫn đối với các gia chủ.`, ref: "Tăng Chi Bộ 5.235", url: "https://loicuaducphat.org/an/an5.235.html#content" },

{ text: `Thành tựu sáu pháp, này các Tỷ-kheo, Tỷ-kheo đáng được cung kính, đáng được tôn trọng, đáng được cúng dường, đáng được chắp tay, là phước điền vô thượng ở đời. Thế nào là sáu? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi mắt thấy sắc, không có ưa thích, không có ghét bỏ, trú xả, chánh niệm tỉnh giác; khi tai nghe tiếng... khi mũi ngửi hương... khi lưỡi nếm vị... khi thân cảm xúc... khi ý biết pháp, không có ưa thích, không có ghét bỏ, trú xả, chánh niệm tỉnh giác. Thành tựu sáu pháp này, này các Tỷ-kheo, Tỷ-kheo đáng được cung kính, đáng được tôn trọng, đáng được cúng dường, đáng được chắp tay, là vô thượng phước điền ở đời.`, ref: "Tăng Chi Bộ 6.1", url: "https://loicuaducphat.org/an/an6.1.html#content" },

{ text: `Này Mahànàma, vị Thánh đệ tử tùy niệm các Giới của mình: “Giới không bị bể vụn, không bị sứt mẻ, không bị vết chấm, không có uế tạp, đưa đến giải thoát, được người trí tán thán, không bị chấp thủ, đưa đến Thiền định”. Này Mahànàma, trong khi Thánh đệ tử tùy niệm Giới, trong khi ấy, tâm không bị tham chi phối, không bị sân chi phối, không bị si chi phối; trong khi ấy, tâm vị ấy được chánh trực nhờ dựa vào Giới. Và này Mahànama, Thánh đệ tử với tâm chánh trực, được nghĩa tín thọ, được pháp tín thọ, được hân hoan liên hệ đến Giới. Người có hân hoan, nên hỷ sanh. Người có hỷ, nên thân được khinh an. Với thân khinh an, vị ấy cảm giác lạc thọ. Người có lạc thọ, tâm được định tĩnh. Này Mahànàma, về vị Thánh đệ tử này, được nói như sau: “Với quần chúng không bình thản, vị ấy sống bình thản. Với quần chúng có não hại, vị ấy sống không não hại. Nhập được pháp lưu, vị ấy tu tập niệm Giới”.`, ref: "Tăng Chi Bộ 6.10", url: "https://loicuaducphat.org/an/an6.10.html#content" },

{ text: `Này Mahànàma, vị Thánh đệ tử tự mình niệm Thí của mình: “Thật là được lợi cho ta! Thật là khéo được lợi cho ta, vì rằng với quần chúng bị cấu uế xan tham chi phối, ta sống trong gia đình, với tâm không bị cấu uế của xan tham chi phối, bố thí rộng rãi với bàn tay sạch sẽ, ưa thích từ bỏ, sẵn sàng để được yêu cầu, ưa thích phân phát vật bố thí”. Này Mahànàma, trong khi vị Thánh đệ tử tùy niệm bố thí, trong khi ấy, tâm không bị tham chi phối, không bị sân chi phối, không bị si chi phối; trong khi ấy, tâm vị ấy được chánh trực nhờ dựa vào Thí. Và này Mahànama, Thánh đệ tử với tâm chánh trực, được nghĩa tín thọ, được pháp tín thọ, được hân hoan liên hệ đến Thí. Người có hân hoan, nên hỷ sanh. Người có hỷ, nên thân được khinh an. Với thân khinh an, vị ấy cảm giác lạc thọ. Người có lạc thọ, tâm được định tĩnh. Này Mahànàma, về vị Thánh đệ tử này, được nói như sau: “Với quần chúng không bình thản, vị ấy sống bình thản. Với quần chúng có não hại, vị ấy sống không não hại. Nhập được pháp lưu, vị ấy tu tập niệm Thí”.`, ref: "Tăng Chi Bộ 6.10", url: "https://loicuaducphat.org/an/an6.10.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo nào nói như sau: “Tôi đã từ bỏ tư tưởng “Tôi là”. Tôi không có tùy quán “Cái này là tôi”, tuy vậy, mũi tên nghi ngờ, do sự xâm chiếm tâm tôi và an trú”. Vị ấy cần được nói như sau: “Chớ có như vậy, Hiền giả chớ có nói như vậy. Chớ có xuyên tạc Thế Tôn. Xuyên tạc Thế Tôn như vậy thật không tốt. Thế Tôn không nói như vậy. Này Hiền giả, sự kiện không phải như vậy. Trường hợp không phải như vậy. Với ai đã từ bỏ tư tưởng “Tôi là”, với ai không có tùy quán “Cái này là tôi”, tuy vậy, mũi tên nghi ngờ, do dự xâm chiếm tâm người ấy và an trú; sự kiện không xảy ra như vậy. Này Hiền giả, cái này có khả năng giải thoát mũi tên nghi hoặc do dự, tức là sự nhổ lên kiêu mạn “Tôi là”.`, ref: "Tăng Chi Bộ 6.13", url: "https://loicuaducphat.org/an/an6.13.html#content" },

{ text: `Ở đây, này các Hiền giả, Tỷ-kheo ưa công việc, thích thú công việc, chuyên tâm ưa thích công việc; ưa nói chuyện, thích thú nói chuyện, chuyên tâm ưa thích nói chuyện; ưa ngủ, thích thú ngủ, chuyên tâm ưa thích ngủ; ưa hội chúng, thích thú hội chúng, chuyên tâm ưa thích hội chúng; ưa liên lạc giao thiệp, thích thú liên lạc giao thiệp, chuyên tâm ưa thích liên lạc giao thiệp; ưa hý luận, thích thú hý luận, chuyên tâm ưa thích hý luận. Như vậy, này các Hiền giả, Tỷ-kheo sống nếp sống như vậy, như vậy, khi lâm chung không được hiền thiện, khi mệnh chung không được hiền thiện. Này các Hiền giả, đây được gọi là Tỷ-kheo ái lạc có thân, không từ bỏ có thân để chân chánh chấm dứt khổ đau.`, ref: "Tăng Chi Bộ 6.14", url: "https://loicuaducphat.org/an/an6.14.html#content" },

{ text: `Ở đây, này các Hiền giả, Tỷ-kheo không ưa công việc, không thích thú công việc, không chuyên tâm ưa thích công việc; không ưa nói chuyện, không thích thú nói chuyện, không chuyên tâm ưa thích nói chuyện; không ưa ngủ, không thích thú ngủ, không chuyên tâm ưa thích ngủ; không ưa hội chúng, không thích thú hội chúng, không chuyên tâm ưa thích hội chúng; không ưa liên lạc giao thiệp, không thích thú liên lạc giao thiệp, không chuyên tâm ưa thích liên lạc giao thiệp; không ưa hý luận, không thích thú hý luận, không chuyên tâm ưa thích hý luận. Như vậy, này các Hiền giả, Tỷ-kheo sống nếp sống như vậy, như vậy, khi lâm chung được hiền thiện, khi mệnh chung được hiền thiện. Này các Hiền giả, đây được gọi là Tỷ-kheo ái lạc Niết-bàn, từ bỏ có thân để chân chánh chấm dứt khổ đau.`, ref: "Tăng Chi Bộ 6.14", url: "https://loicuaducphat.org/an/an6.14.html#content" },

{ text: `Ai chuyên ưa hý luận,\nNhư thích thú hý luận,\nÐi ngược lại Niết-bàn,\nNơi an ổn vô thượng.\nAi từ bỏ hý luận,\nƯa thích không hý luận.\nThuận hướng đến Niết-bàn,\nNơi an ổn vô thượng.`, ref: "Tăng Chi Bộ 6.14", url: "https://loicuaducphat.org/an/an6.14.html#content" },

{ text: `Lành thay, này các Tỷ-kheo, Ta cũng không thấy, cũng không nghe như sau, này các Tỷ-kheo: Một vị Sa-môn hay Bà-la-môn sống chuyên tâm hưởng thọ cho đến thỏa thích lạc về giường nằm, lạc về nằm dài, lạc về ngủ nghỉ, không phòng hộ các căn môn, không tiết độ trong ăn uống, không chú tâm cảnh giác, không quán các thiện pháp, đầu đêm cuối đêm không sống chuyên tâm tu tập các pháp giác chi, do đoạn tận các lậu hoặc, có thể tự mình với thắng trí chứng ngộ, chứng đạt và an trú tâm giải thoát, tuệ giải thoát. Do vậy, này các Tỷ-kheo, các Thầy cần phải học tập như sau: Với căn môn được phòng hộ, ăn uống có tiết độ, chú tâm cảnh giác, quán các thiện pháp, đầu đêm cuối đêm sống chuyên tâm tu tập các pháp giác chi, do đoạn tận các lậu hoặc, có thể tự mình với thắng trí chứng ngộ, chứng đạt và an trú tâm giải thoát, tuệ giải thoát. Như vậy, này các Tỷ-kheo, các Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 6.17", url: "https://loicuaducphat.org/an/an6.17.html#content" },

{ text: `Thật vậy, này các Tỷ-kheo, ai với ác ý nhìn các loài bàng sanh bị giết, đem đi giết hại; vì vậy, người ấy không được cưỡi voi, không được cưỡi ngựa, không được cưỡi xe, không được cưỡi cỗ xe, không được thọ hưởng các tài sản, hay không được sống giữa các tài sản lớn hay tài sản chất đống. Còn nói gì về người với ác ý nhìn các loài Người bị giết, bị đem đi giết hại! Thật vậy, này các Tỷ-kheo, như vậy là bất hạnh, đau khổ lâu dài cho người ấy, sau khi thân hoại mạng chung sanh vào cõi dữ, ác thú, đọa xứ, địa ngục.`, ref: "Tăng Chi Bộ 6.18", url: "https://loicuaducphat.org/an/an6.18.html#content" },

{ text: `Có ba pháp này, bạch Thế Tôn, đưa đến Tỷ-kheo thối đọa. Thế nào là ba? Ưa thích công việc, ưa thích nói chuyện, ưa thích ngủ nghỉ. Ba pháp này, bạch Thế Tôn, đưa đến Tỷ-kheo thối đọa.\n- Này các Tỷ-kheo, thế nào là ba pháp đưa đến thối đọa? Ưa hội chúng, ác ngôn, ác bạn hữu. Ba pháp này, này các Tỷ-kheo đưa đến thối đọa. Này các Tỷ-kheo, những ai trong quá khứ đã thối đọa trong các thiện pháp, tất cả đều vì sáu pháp này, sẽ bị thối đọa trong các thiện pháp. Này các Tỷ-kheo, những ai trong tương lai sẽ bị thối đọa trong các thiện pháp, tất cả đều vì sáu pháp này, sẽ bị thối đọa trong các thiện pháp. Này các Tỷ kheo, những ai trong hiện tại bị thối đọa trong các thiện pháp, tất cả đều vì sáu pháp này, bị thối đọa trong các thiện pháp.`, ref: "Tăng Chi Bộ 6.21", url: "https://loicuaducphat.org/an/an6.21.html#content" },

{ text: `Này các Tỷ-kheo, có sáu pháp không thối đọa này, Ta sẽ thuyết, hãy lắng nghe. Và này các Tỷ-kheo, thế nào là sáu pháp không thối đọa? Không ưa công việc, không ưa nói chuyện, không ưa ngủ nghỉ, không ưa hội chúng, thiện ngôn, thiện bạn hữu. Này các Tỷ-kheo, những ai trong thời quá khứ không bị thối đọa, trong các thiện pháp, tất cả đều nhờ sáu pháp này, không bị thối đọa trong các thiện pháp. Này các Tỷ-kheo, những ai trong thời vị lai sẽ không bị thối đọa trong các thiện pháp, tất cả đều nhờ sáu pháp này, sẽ không bị thối đọa trong các thiện pháp. Này các Tỷ-kheo, những ai trong thời hiện tại không bị thối đọa trong các thiện pháp, tất cả đều nhờ sáu pháp này, không bị thối đọa trong các thiện pháp.`, ref: "Tăng Chi Bộ 6.22", url: "https://loicuaducphat.org/an/an6.22.html#content" },

{ text: `Sợ hãi, này các Tỷ-kheo, là đồng nghĩa với các dục. Khổ, này các Tỷ-kheo, là đồng nghiệp với các dục. Bệnh, này các Tỷ-kheo, là đồng nghĩa với các dục. Cục bướu, này các Tỷ-kheo, là đồng nghĩa với các dục. Tham dính, này các Tỷ-kheo, là đồng nghĩa với các dục. Bùn lầy, này các Tỷ-kheo, là đồng nghĩa với các dục. Và này các Tỷ-kheo, vì sao sợ hãi là đồng nghĩa với các dục? Này các Tỷ-kheo, say đắm bởi tham dục, bị trói buộc bởi các tham ước muốn, ngay trong hiện tại không thoát khỏi sợ hãi, đời sau cũng không thoát khỏi sợ hãi. Do vậy, sợ hãi là đồng nghĩa với các dục.`, ref: "Tăng Chi Bộ 6.23", url: "https://loicuaducphat.org/an/an6.23.html#content" },

{ text: `Sợ hãi và khổ đau,\nBệnh hoạn và cục bướu,\nCả hai tham dính bùn,\nÐược gọi là các dục,\nTại đấy kẻ phàm phu,\nTham đắm và chấp trước,\nThấy sợ trong chấp thủ,\nNguồn gốc của tử sanh,\nKhông chấp thủ, giải thoát,\nÐoạn tận được sanh tử,\nChúng đạt được an ổn,\nÐược hiện tại tịnh lạc,\nVượt sợ hãi oán thù,\nMọi đau khổ vượt qua.`, ref: "Tăng Chi Bộ 6.23", url: "https://loicuaducphat.org/an/an6.23.html#content" },

{ text: `Thành tựu sáu pháp, này các Tỷ-kheo, Tỷ-kheo có thể phá vỡ vua núi Tuyết sơn, còn nói gì vô minh hạ liệt. Thế nào là sáu? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo thiện xảo nhập được Thiền định, thiện xảo trú được Thiền định, thiện xảo xuất khỏi Thiền định, thiện xảo trong sự an lạc Thiền định, thiện xảo trong cảnh giới Thiền định, thiện xảo trong sự dẫn khởi đến Thiền định. Thành tựu sáu pháp này, này các Tỷ-kheo, Tỷ-kheo có thể phá vỡ vua núi Tuyết sơn, còn nói gì vô minh hạ liệt.`, ref: "Tăng Chi Bộ 6.24", url: "https://loicuaducphat.org/an/an6.24.html#content" },
{ text: `Ai được thấy tối thắng,\nVà được nghe vô thượng,\nÐược lợi đắc vô thượng,\nVui học tập vô thượng,\nAn trú trong phục vụ,\nTu tập chuyên tùy niệm,\nLiên hệ đến viễn ly,\nÐạt an ổn, bất tử,\nHoan hỷ, không phóng dật,\nThận trọng, hộ trì giới,\nKhi thời đã chín muồi\nÐau khổ được đoạn tận.`, ref: "Tăng Chi Bộ 6.30", url: "https://loicuaducphat.org/an/an6.30.html#content" },

{ text: `Sáu pháp này, này các Tỷ-kheo, không đưa Tỷ-kheo hữu học đến thối đọa. Thế nào là sáu? Không ưa công việc, không ưa nói chuyện, không ưa ngủ nghỉ, không ưa hội chúng, các căn có phòng hộ, ăn uống có tiết độ. Sáu pháp này, này các Tỷ-kheo, không đưa Tỷ-kheo hữu học đến thối đọa.`, ref: "Tăng Chi Bộ 6.31", url: "https://loicuaducphat.org/an/an6.31.html#content" },

{ text: `Có sáu pháp này, này các Tỷ-kheo, không đưa Tỷ-kheo đến thối đọa. Thế nào là sáu? Kính trọng Ðạo Sư, kính trọng Pháp, kính trọng chúng Tăng, kính trọng học pháp, kính trọng không phóng dật, kính trọng tiếp đón. Sáu pháp này, này các Tỷ-kheo, không đưa Tỷ-kheo đến thối đọa.\nTỷ-kheo kính Ðạo Sư,\nCung kính Pháp và Tăng,\nHọc pháp không phóng dật,\nCung kính nghinh tiếp đón,\nKhông thể bị thối đọa,\nNhất định gần Niết-bàn.`, ref: "Tăng Chi Bộ 6.32", url: "https://loicuaducphat.org/an/an6.32.html#content" },

{ text: `Cung kính bậc Ðạo Sư,\nCung kính lớn Pháp Tăng,\nÐầy đủ tàm và quý\nKính nhường và cung kính,\nKhông thể bị thối đọa,\nNhất định gần Niết-bàn.`, ref: "Tăng Chi Bộ 6.33", url: "https://loicuaducphat.org/an/an6.33.html#content" },

{ text: `Có sáu pháp này thuộc về minh phần. Thế nào là sáu? Tưởng vô thường, tưởng khổ trong vô thường, tưởng vô ngã trong khổ, tưởng đoạn tận, tưởng ly tham, tưởng đoạn diệt. Sáu pháp này, này các Tỷ-kheo, là thuộc về minh phần.`, ref: "Tăng Chi Bộ 6.35", url: "https://loicuaducphat.org/an/an6.35.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, có ba phần thuộc người bố thí và có ba phần thuộc người nhận đồ bố thí. Thế nào là ba phần thuộc về người bố thí? Ở đây, này các Tỷ-kheo, người bố thí, trước khi bố thí, ý được vui lòng; trong khi bố thí, tâm được tịnh tín; sau khi bố thí, cảm thấy hoan hỷ. Ðây là ba phần của người bố thí. Thế nào là ba phần của người nhận bố thí? Ở đây, này các Tỷ-kheo, những người nhận vật bố thí, đã được ly tham hay đang thực hành hạnh ly tham; đã được ly sân hay đang thực hành hạnh ly sân; đã được ly si hay đang thực hành hạnh ly si. Ðây là ba phần của những người nhận vật bố thí. Như vậy là ba phần của người bố thí và ba phần của những người nhận được vật bố thí. Như vậy, này các Tỷ-kheo, là thí vật gồm có sáu phần.`, ref: "Tăng Chi Bộ 6.37", url: "https://loicuaducphat.org/an/an6.37.html#content" },

{ text: `Trước bố thí, ý vui,\nKhi bố thí, tâm tín.\nSau bố thí, hoan hỷ,\nÐây lễ thí đầy đủ.\nLy tham và ly sân,\nLy si, không lậu hoặc,\nVị Phạm hạnh chế ngự\nLà ruộng phước lễ thí.\nNếu tự thanh tịnh mình,\nTự tay mình bố thí,\nTự mình đến đời sau,\nLễ thí vậy, quả lớn.\nLễ thí vậy, bậc trí,\nVới tín, tâm giải thoát,\nKhông hận thù, an lạc,\nBậc Hiền sanh ở đời.`, ref: "Tăng Chi Bộ 6.37", url: "https://loicuaducphat.org/an/an6.37.html#content" },

{ text: `Này chư Hiền, cần phải học tập như sau: “Chúng ta là những người chuyên tâm về Pháp, chúng ta sẽ tán thán các Tỷ-kheo tu Thiền “. Này chư Hiền, chư Hiền cần phải học tập như vậy. Vì cớ sao? Thật vậy, này chư Hiền, các người vi diệu ấy khó tìm được ở đời, những người cảm giác bất tử giới với thân và an trú.\nNày chư Hiền, cần phải học tập như sau: “Chúng ta là những người tu thiền, chúng ta sẽ tán thán các Tỷ-kheo chuyên tâm về Pháp”. Này chư Hiền, chư Hiền cần phải học tập như vậy. Vì cớ sao? Thật vậy, này chư Hiền, các người vi diệu ấy khó tìm được ở đời, những người với trí tuệ thể nhập và thấy con đường thâm sâu hướng dẫn đến đích.`, ref: "Tăng Chi Bộ 6.46", url: "https://loicuaducphat.org/an/an6.46.html#content" },

{ text: `Với căn không phòng hộ, này các Tỷ-kheo, với người khiếm khuyết phòng hộ các căn, giới đi đến hủy hoại; với giới không có, có ai khiếm khuyết về giới, chánh định đi đến hủy hoại. Với chánh định không có, với ai khiếm khuyết chánh định, tri kiến như thật đi đến hủy hoại. Với tri kiến như thật không có, với ai khiếm khuyết tri kiến như thật, nhàm chán, ly tham đi đến hủy hoại. Với nhàm chán, ly tham không có, với ai khiếm khuyết nhàm chán, ly tham, giải thoát tri kiến đi đến hủy hoại. Ví như, này các Tỷ-kheo, một cây, với cành và lá khiếm khuyết, thời các chồi non không đi đến viên mãn, vỏ cây không đi đến viên mãn, giác cây không đi đến viên mãn, lõi cây không đi đến viên mãn. Cũng vậy, này các Tỷ-kheo, với căn không phòng hộ, với người khiếm khuyết phòng hộ các căn... giải thoát tri kiến đi đến hủy hoại.`, ref: "Tăng Chi Bộ 6.50", url: "https://loicuaducphat.org/an/an6.50.html#content" },

{ text: `Với các căn được phòng hộ, này các Tỷ-kheo, với người đầy đủ các căn được phòng hộ, giới đi đến đầy đủ. Với giới có mặt, với người đầy đủ giới, chánh định đi đến đầy đủ. Với chánh định có mặt, với người đầy đủ chánh định, tri kiến như thật đi đến đầy đủ. Với tri kiến như thật có mặt, với người đầy đủ tri kiến như thật, nhàm chán, ly tham đi đến đầy đủ. Với nhàm chán, ly tham có mặt, với người đầy đủ nhàm chán, ly tham, giải thoát tri kiến đi đến đầy đủ. Ví như, này các Tỷ-kheo, một cây với cành và lá đầy đủ, thời chồi non đi đến viên mãn, vỏ cây đi đến viên mãn, giác cây đi đến viên mãn, lõi cây đi đến viên mãn. Cũng vậy, này các Tỷ-kheo, với căn được phòng hộ, với người đầy đủ phòng hộ các căn, giới đi đến đầy đủ... giải thoát tri kiến đi đến đầy đủ.`, ref: "Tăng Chi Bộ 6.50", url: "https://loicuaducphat.org/an/an6.50.html#content" },

{ text: `Nhưng đối với Sa-môn, thưa Tôn giả Gotama, mong muốn cái gì, cận hành cái gì, điểm tựa cái gì, xu hướng cái gì, cứu cánh cái gì? - Ðối với Sa-môn, này Bà-la-môn, nhẫn nhục nhu hòa là mong muốn, trí tuệ là cận hành, giới hạnh là điểm tựa, không có sở hữu là xu hướng, Niết-bàn là cứu cánh.`, ref: "Tăng Chi Bộ 6.52", url: "https://loicuaducphat.org/an/an6.52.html#content" },

{ text: `Không phóng dật, này Bà-la-môn, là một pháp được tu tập, được làm cho sung mãn, bao trùm và an trú hai lợi ích: lợi ích hiện tại và lợi ích trong tương lai. Ví như, này Bà-la-môn, phàm có những dấu chân của các loại bộ hành nào, tất cả dấu chân ấy đều được thâu nhiếp trong dấu chân voi. Dấu chân voi được gọi là tối thắng trong các dấu chân ấy, cũng vậy, này Bà-la-môn, không phóng dật là một pháp được tu tập, được làm cho sung mãn, bao trùm và an trú hai lợi ích: lợi ích hiện tại và lợi ích trong tương lai. Cũng vậy, này Bà-la-môn, không phóng dật là một pháp được tu tập, được làm cho sung mãn, bao trùm và an trú hai lợi ích: lợi ích hiện tại và lợi ích trong tương lai. Ðây là một pháp, này Bà-la-môn, được tu tập, được làm cho sung mãn, bao trùm và an trú hai lợi ích: lợi ích hiện tại và lợi ích trong tương lai.`, ref: "Tăng Chi Bộ 6.53", url: "https://loicuaducphat.org/an/an6.53.html#content" },

{ text: `Này Sona, khi tinh cần tinh tấn quá căng thẳng, thời đưa đến dao động; khi tinh cần tinh tấn quá thụ động, thời đưa đến biếng nhác. Do vậy, này Sona, Thầy phải an trú tinh tấn một cách bình đẳng, thể nhập các căn một cách bình đẳng, rồi tại đấy nắm giữ tướng.`, ref: "Tăng Chi Bộ 6.55", url: "https://loicuaducphat.org/an/an6.55.html#content" },

{ text: `Với ai hướng xuất ly,\nTâm xu hướng viễn ly,\nVới ai hướng vô sân,\nTâm xu hướng thủ diệt,\nVới ai hướng ái diệt,\nTâm xu hướng vô si,\nCó thấy xứ sanh khởi,\nTâm được chánh giải thoát.\nVới vị chánh giải thoát,\nVị Tỷ-kheo tâm tịnh,\nKhông cần làm thêm gì,\nKhông có gì phải làm.\nNhư hòn núi đá tảng,\nGió không thể dao động,\nCũng vậy, toàn thể sắc,\nVị, tiếng, và hương, xúc,\nCho đến tất cả pháp,\nKhả ái, không khả ái,\nKhông có thể dao động,\nMột vị được như vậy,\nTâm kiên trú, giải thoát,\nThấy tánh diệt của chúng.`, ref: "Tăng Chi Bộ 6.55", url: "https://loicuaducphat.org/an/an6.55.html#content" },

{ text: `- Bạch Thế Tôn, trong gia đình con có bố thí. Những Tỷ-kheo là vị sống ở rừng, theo hạnh khất thực, mặc áo lấy vải lượm từ đống rác, bậc A-la-hán, hay thực hành A-la-hán đạo, những Tỷ-kheo như vậy, bạch Thế Tôn, đều được bố thí.\n- Nhưng chắc chắn, này Gia chủ, đây thực là một sự khó khăn cho Ông, một người tại gia thọ dụng các dục, bị con cháu trói buộc, được dùng hương chiên đàn từ Kàsi, được đeo và thoa với vòng hoa, hương, hương liệu, được tiêu dùng vàng và bạc để có thể nói ai là bậc A-la-hán, ai là bậc thực hành A-la-hán đạo. Tỷ-kheo trú tại rừng núi, này Gia chủ, nếu tháo động, kiêu căng dao động, lắm mồm, lắm miệng, lắm lời, thất niệm, không tỉnh giác, không định tĩnh, tâm tán loạn, các căn thả lỏng, thời vị ấy về phương diện này đáng bị chỉ trích. Tuy vậy, này Gia chủ, hãy cúng dường chúng Tăng. Nếu Ông cúng dường chúng Tăng, tâm sẽ được định tín. Nếu Ông có tâm định tín, lúc thân hoại mạng chung, sẽ được sanh lên thiện thú, Thiên giới, cõi đời này.`, ref: "Tăng Chi Bộ 6.59", url: "https://loicuaducphat.org/an/an6.59.html#content" },

{ text: `Ở đây, thưa các Hiền giả, có hạng người, khi còn sống gần vị Bổn sư hay sống gần một vị đồng Phạm hạnh đóng vai trò y chỉ sư, trong khi ấy, là người nhu hòa nhất trong những người nhu hòa, là người khiêm tốn nhất trong những người khiêm tốn, là người an tịnh nhất trong những người an tịnh. Khi người ấy rời khỏi bậc Ðạo Sư, rời khỏi các vị đồng Phạm hạnh đóng vai trò y chỉ sư, vị ấy sống giao thiệp với các Tỷ-kheo, các Tỷ-kheo-ni, với các nam cư sĩ, nữ cư sĩ, với các vua chúa, các đại thần của vua, với các ngoại đạo, các đệ tử ngoại đạo. Do vị ấy sống giao thiệp, phóng túng, thô lỗ, đam mê nói chuyện, tham ái tấn công tâm vị ấy. Vị ấy, với tâm bị tham ái tấn công, liền từ bỏ học pháp và hoàn tục. Ví như, này các Hiền giả, một con bò ăn lúa, bị dây cột lại, hay bị nhốt trong chuồng. Này Hiền giả, nếu có ai nói như sau: “Con bò ăn lúa này sẽ không bao giờ đi xuống ruộng lúa nữa”, nói như vậy, thưa các Hiền Giả, là nói một cách chơn chánh không?\n- Thưa không, thưa Hiền giả, sự kiện này, thưa Hiền giả, có xảy ra: Con bò ăn lúa ấy, sau khi bứt dây, hay phá sập chuồng, có thể xuống ruộng lúa nữa.`, ref: "Tăng Chi Bộ 6.60", url: "https://loicuaducphat.org/an/an6.60.html#content" },

{ text: `Xúc, này các Tỷ-kheo, là cực đoan. Xúc tập khởi là cực đoan thứ hai. Xúc diệt là chặng giữa. Ái là người dệt vải; vì rằng ái dệt nên khiến cho vị ấy phải sanh ở hữu này. Cho đến như vậy, này các Tỷ-kheo, Tỷ-kheo thắng tri được điều có thể thắng tri, liễu tri được điều có thể liễu tri. Do thắng tri được điều có thể thắng tri, liễu tri được điều có thể liễu tri, ngay trong hiện tại, vị ấy có thể chấm dứt khổ đau.\nAi biết hai cực đoan,\nGiữa bậc Trí không nhiễm,\nTa gọi bậc Ðại nhân,\nÐây, vượt người dệt vải.`, ref: "Tăng Chi Bộ 6.61", url: "https://loicuaducphat.org/an/an6.61.html#content" },

{ text: `- Ở đây, này Ananda, với tâm của Ta, Ta rõ biết tâm của một người khác: “Trong người này, có những pháp thiện, có những pháp bất thiện”. Sau một thời gian khác, cũng vậy, với tâm của Ta, Ta rõ biết tâm của người ấy: “Trong người này, các pháp thiện đã biến mất, các pháp bất thiện đang hiện hữu, nhưng còn có cội gốc thiện chưa bị cắt đứt. Và pháp thiện sẽ khởi lên từ cội gốc thiện ấy”. Như vậy người này sẽ không bị thối đọa trong tương lai. Ví như, này Ananda, các hột giống chưa bị bể vụn, chưa bị hư thối, chưa bị gió và sức nóng phá hoại, còn giữ được sức sống bám sâu trong cánh đồng, được gieo trên mảnh đất khéo sửa soạn. Này Ananda, Thầy có thể biết những hột giống này sẽ được lớn lên, được tăng trưởng, được lớn mạnh không?`, ref: "Tăng Chi Bộ 6.62", url: "https://loicuaducphat.org/an/an6.62.html#content" },

{ text: `Này các Tỷ-kheo, có năm dục trưởng dưỡng này: Các sắc do mắt nhận thức, khả lạc, khả ý, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Các tiếng do tai nhận thức... các hương do mũi nhận thức... các vị do lưỡi nhận thức... các xúc do thân nhận thức... khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn. Này các Tỷ-kheo, dầu chúng không phải dục, chúng được gọi là dục trưởng dưỡng trong giới luật của bậc Thánh.`, ref: "Tăng Chi Bộ 6.63", url: "https://loicuaducphat.org/an/an6.63.html#content" },

{ text: `Các tư duy tham ái,\nLà dục của con người,\nCác hoa mỹ ở đời,\nChúng không phải là dục,\nCác tư duy tham ái\nLà dục của con người,\nCác hoa mỹ an trú\nNhư vậy ở trên đời,\nỞ đây những bậc Trí,\nNhiếp phục được lòng dục.`, ref: "Tăng Chi Bộ 6.63", url: "https://loicuaducphat.org/an/an6.63.html#content" },

{ text: `Thật vậy, này các Tỷ-kheo, Tỷ-kheo ấy là thiện thân hữu, thiện bằng hữu, thiện bạn bè, thân cận, hầu hạ, tôn kính thiện thân hữu, chấp nhận chánh kiến của họ, sẽ làm cho viên mãn hành trì pháp, sự kiện này có thể xảy ra. Sau khi viên mãn hành trì pháp, sẽ có thể làm cho viên mãn hữu học pháp, sự kiện này có thể xảy ra. Sau khi làm cho viên mãn hữu học pháp, sẽ làm cho viên mãn các giới luật, sự kiện này có xảy ra. Sau khi làm cho viên mãn các giới luật sẽ từ bỏ dục tham, sắc tham, hay vô sắc tham, sự kiện này có xảy ra.`, ref: "Tăng Chi Bộ 6.67", url: "https://loicuaducphat.org/an/an6.67.html#content" },

{ text: `- Thật vậy, này các Tỷ-kheo, Tỷ-kheo ấy ưa thích hội chúng, vui thích hội chúng, chuyên tâm ưa thích hội chúng, ưa thích đồ chúng, vui thích đồ chúng, chuyên tâm ưa thích đồ chúng, vui thích đồ chúng sẽ hoan hỷ sống một mình, sống viễn ly, sự kiện này không xảy ra. Không hoan hỷ sống một mình, sống viễn ly, vị ấy sẽ nắm giữ tướng của tâm, sự kiện này không xảy ra. Không nắm giữ tướng của tâm, sẽ làm cho viên mãn chánh kiến, sự kiện này không xảy ra. Không làm cho viên mãn chánh kiến, sẽ làm cho viên mãn chánh định, sự kiện này không xảy ra. Không làm cho viên mãn chánh định, sẽ từ bỏ các kiết sử, sự kiện này không xảy ra. Không từ bỏ các kiết sử, sẽ chứng ngộ Niết-bàn, sự kiện này không xảy ra.`, ref: "Tăng Chi Bộ 6.68", url: "https://loicuaducphat.org/an/an6.68.html#content" },

{ text: `Thật vậy, này các Tỷ-kheo, Tỷ-kheo ấy không ưa thích hội chúng, không vui thích hội chúng, không chuyên tâm ưa thích hội chúng, không ưa thích đồ chúng, không vui thích đồ chúng, không chuyên tâm ưa thích đồ chúng, không vui thích đồ chúng, không chuyên tâm ưa thích đồ chúng, sẽ hoan hỷ sống một mình, sống viễn ly, sự kiện này có xảy ra. Hoan hỷ sống một mình, sống viễn ly, vị ấy sẽ nắm giữ tướng của tâm, sự kiện này có xảy ra. Nắm giữ tướng của tâm, sẽ làm cho viên mãn chánh kiến, sự kiện này có xảy ra. Làm cho viên mãn chánh kiến, sẽ làm cho viên mãn chánh định, sự kiện này có xảy ra. Làm cho viên mãn chánh định, sẽ từ bỏ các kiết sử, sự kiện này có xảy ra. Từ bỏ các kiết sử, sẽ chứng ngộ Niết-bàn, sự kiện này có xảy ra.`, ref: "Tăng Chi Bộ 6.68", url: "https://loicuaducphat.org/an/an6.68.html#content" },

{ text: `Không đoạn tận sáu pháp, này các Tỷ-kheo, không có thể đạt được an trú sơ Thiền. Thế nào là sáu? Dục tham, sân, hôn trầm, thụy miên, trạo hối, nghi, không như thật khéo thấy với chánh trí tuệ các nguy hại trong các dục. Không đoạn tận sáu pháp này, này các Tỷ-kheo, không có thể đạt được và an trú sơ thiền.`, ref: "Tăng Chi Bộ 6.73", url: "https://loicuaducphat.org/an/an6.73.html#content" },

{ text: `Không đoạn tận sáu pháp, này các Tỷ-kheo, không có thể đạt được và an trú sơ Thiền. Thế nào là sáu? Dục tầm, sân tầm, hại tầm, dục tưởng, sân tưởng, hại tưởng. Không đoạn tận sáu pháp này, này các Tỷ-kheo, không có thể đạt được và an trú sơ Thiền.`, ref: "Tăng Chi Bộ 6.74", url: "https://loicuaducphat.org/an/an6.74.html#content" },

{ text: `Thành tựu với sáu pháp, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống đau khổ, hiềm hận, có ưu não, có nhiệt não, sau khi thân hoại mạng chung, chờ đợi là ác thú. Thế nào là sáu? Với dục tầm, với sân tầm, với hại tầm, với dục tưởng, với sân tưởng, với hại tưởng. Thành tựu với sáu pháp này, các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống đau khổ, hiềm hận, có ưu não, có nhiệt não, sau khi thân hoại mạng chung, chờ đợi là ác thú.`, ref: "Tăng Chi Bộ 6.75", url: "https://loicuaducphat.org/an/an6.75.html#content" },

{ text: `Thành tựu với sáu pháp này, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống an lạc, không hiềm hận, không ưu não, không nhiệt não, sau khi thân hoại mạng chung, chờ đợi là thiện thú. Với xuất ly tầm, với vô sân tầm, với bất hại tầm, với xuất ly tưởng, với vô sân tưởng, với bất hại tưởng. Thành tựu với sáu pháp này, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống an lạc, không hiềm hận, không ưu não, không nhiệt não, sau khi thân hoại mạng chung, chờ đợi là thiện thú.`, ref: "Tăng Chi Bộ 6.75", url: "https://loicuaducphat.org/an/an6.75.html#content" },

{ text: `Không đoạn tận sáu pháp, này các Tỷ-kheo, không có thể chứng ngộ các pháp thượng nhân tri kiến thù thắng xứng đáng bậc Thánh. Thế nào là sáu? Thất niệm, không tỉnh giác, không phòng hộ các căn, không có thể tiết độ trong ăn uống, ngụy trá, hư đàm. Không đoạn tận sáu pháp này, này các Tỷ-kheo, không có thể chứng ngộ các pháp thượng nhân tri kiến thù thắng xứng đáng bậc Thánh.`, ref: "Tăng Chi Bộ 6.77", url: "https://loicuaducphat.org/an/an6.77.html#content" },

{ text: `Thành tựu sáu pháp, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống với nhiều lạc hỷ, đối với vị ấy nguyên nhân đã được hình thành để đoạn trừ các lậu hoặc. Thế nào là sáu? Ở đây, này các Tỷ-kheo, Tỷ-kheo ưa thích pháp, ưa thích tu tập, ưa thích đoạn trừ, ưa thích viễn ly, ưa thích không có sân hận, ưa thích không có hý luận. Thành tựu sáu pháp này, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống với nhiều lạc hỷ, đối với vị ấy, nguyên nhân đã được hình thành để đoạn trừ các lậu hoặc.`, ref: "Tăng Chi Bộ 6.78", url: "https://loicuaducphat.org/an/an6.78.html#content" },

{ text: `Nếu Tỷ-kheo thành tựu sáu pháp, này các Tỷ-kheo, thời bất luận đêm hay ngày, chờ đợi là sự thối đọa trong các thiện pháp, không có tăng trưởng. Thế nào là sáu? Ở đây, này các Tỷ-kheo, Tỷ-kheo có dục lớn, có hiềm hận, không bằng lòng với bất cứ những vật dụng cần thiết nào như y áo, đồ ăn khất thực, sàng tọa, các dược phẩm trị bệnh, không có lòng tin, ác giới, biếng nhác, thất niệm, ác tuệ.`, ref: "Tăng Chi Bộ 6.84", url: "https://loicuaducphat.org/an/an6.84.html#content" },


{ text: `Thành tựu sáu pháp, này các Tỷ-kheo, Tỷ-kheo có thể chứng ngộ vô thượng thanh lương. Thế nào là sáu? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi nào tâm cần phải hạn chế, khi ấy hạn chế tâm; khi nào tâm cần phải phấn chấn, khi ấy phấn chấn tâm; khi nào tâm cần phải làm cho hoan hỷ, khi ấy làm cho tâm hoan hỷ; khi nào tâm cần phải trú xả, quán sát khi ấy làm tâm trú xả, quán sát; xu hướng về thù thắng; hoan hỷ Niết-bàn.`, ref: "Tăng Chi Bộ 6.85", url: "https://loicuaducphat.org/an/an6.85.html#content" },

{ text: `Thành tựu sáu pháp, này các Tỷ-kheo, dầu có nghe diệu pháp, không có thể bước vào quyết định tánh trong các thiện pháp. Thế nào là sáu? Thành tựu nghiệp chướng, thành tựu phiền não chướng, thành tựu dị thục chướng, không có lòng tin, không có ước muốn, và ác tuệ.`, ref: "Tăng Chi Bộ 6.86", url: "https://loicuaducphat.org/an/an6.86.html#content" },

{ text: `Thành tựu sáu pháp, này các Tỷ-kheo, dầu được nghe diệu pháp, cũng không có thể bước vào quyết định tánh trong các thiện pháp. Thế nào là sáu? Khi Pháp và Luật được Như Lai thuyết giảng, không ưa nghe, không có lóng tai, không có an trú tâm liễu giải, nắm giữ điều không lợi ích, bỏ qua điều lợi ích, không thành tựu tùy thuận nhẫn nhục.`, ref: "Tăng Chi Bộ 6.88", url: "https://loicuaducphat.org/an/an6.88.html#content" },

{ text: `Này các Tỷ-kheo, có sáu trường hợp không thể xảy ra. Thế nào là sáu? Người đầy đủ tri kiến không thể sống không tôn kính, không tùy thuận bậc Đạo Sư; người đầy đủ tri kiến không thể sống không tôn kính, không tùy thuận chánh pháp; người đầy đủ tri kiến không thể sống không tôn kính, không tùy thuận chúng Tăng; người đầy đủ tri kiến không thể sống không tôn kính, không tùy thuận học pháp; người đầy đủ tri kiến không thể rơi trở lại vào những vấn đề không nên trở lại; người đầy đủ tri kiến không thể làm cho sanh khởi hữu thứ tám. Này các Tỷ-kheo, đây là sáu trường hợp không thể xảy ra.`, ref: "Tăng Chi Bộ 6.92", url: "https://loicuaducphat.org/an/an6.92.html#content" },

{ text: `Này các Tỷ-kheo, có sáu trường hợp không thể xảy ra. Thế nào là sáu? Người đầy đủ tri kiến không thể chấp nhận bất cứ hành nào là thường còn; người đầu đủ tri kiến không thể chấp nhận bất cứ hành nào là lạc; người đầy đủ tri kiến không thể chấp nhận bất cứ hành nào là ngã; người đầy đủ tri kiến không thể làm hành động vô gián; người đầy đủ tri kiến không thể làm cho thanh tịnh với những lễ nghi đặc biệt; người đầy đủ tri kiến không thể đi tìm các vị đáng được cúng dường ngoài chư Tăng. Này các Tỷ-kheo, đây là sáu trường hợp không thể xảy ra.`, ref: "Tăng Chi Bộ 6.93", url: "https://loicuaducphat.org/an/an6.93.html#content" },
{ text: `Thật vậy, này các Tỷ-kheo, Tỷ-kheo nào thấy bất cứ hành nào là vô thường, sẽ thành tựu được nhẫn nhục tùy thuận, sự kiện này có xảy ra. Thành tựu nhẫn nhục tùy thuận, sẽ nhập vào chánh tánh quyết định, sự kiện này có xảy ra. Nhập vào chánh tánh quyết định, sẽ chứng ngộ quả Dự lưu, quả Nhất lai, quả Bất lai, hay quả A-la-hán, sự kiện này có xảy ra.`, ref: "Tăng Chi Bộ 6.98", url: "https://loicuaducphat.org/an/an6.98.html#content" },

{ text: `Thấy được sáu lợi ích, này các Tỷ-kheo, thật là vừa đủ để vị Tỷ-kheo làm cho an trú tưởng vô thường, không có hạn chế trong tất cả hành. Thế nào là sáu? Tất cả hành hiện ra với tôi, không có an trú; ý của tôi không ưa thích tất cả thế giới; ý của tôi sẽ xuất khỏi tất cả thế giới; ý của tôi sẽ nghiêng về Niết-bàn; các kiết sử của tôi đi đến đoạn diệt; và tôi sẽ thành tựu tối thượng Sa-môn hạnh. Thấy được sáu lợi ích này, này các Tỷ-kheo, thật là vừa đủ để Tỷ-kheo làm cho an trú tưởng vô thường, không có hạn chế trong tất cả hành.`, ref: "Tăng Chi Bộ 6.102", url: "https://loicuaducphat.org/an/an6.102.html#content" },

{ text: `Thấy được sáu lợi ích này, này các Tỷ-kheo, thật là vừa đủ để Tỷ-kheo làm cho an trú tưởng khổ, không có hạn chế trong tất cả hành. Thế nào là sáu? Trong tất cả hành, tưởng Niết-bàn sẽ được an trú trong tôi, ví như kẻ giết người đang đưa dao lên chém; ý của tôi sẽ xuất khỏi tất cả thế giới; tôi sẽ trở thành một người thấy được tịnh lạc trong Niết-bàn; các tùy miên trong tôi sẽ được nhổ lên; tôi sẽ là người đã làm các việc nên làm; tôi sẽ với từ tâm hầu hạ bậc Ðạo Sư. Thấy được sáu lợi ích này, này các Tỷ-kheo, thật là vừa đủ để Tỷ-kheo làm cho an trú tưởng khổ không có hạn chế trong tất cả hành.`, ref: "Tăng Chi Bộ 5.3", url: "https://loicuaducphat.org/an/an5.3.html#content" },

{ text: `Thấy được sáu lợi ích, này các Tỷ-kheo, thật là vừa đủ để Tỷ-kheo làm cho an trú tưởng vô ngã không có hạn chế trong tất cả hành. Thế nào là sáu? Trong tất cả thế giới, tôi sẽ không dự phần vào trong ấy; cái gì tạo ra cái “tôi” trong tôi sẽ được chận đứng; cái gì tạo ra cái “của tôi” trong tôi sẽ được chận đứng; tôi sẽ thành tựu trí; không cùng chia sẻ với người khác; nguyên nhân và các pháp do nhân sanh được tôi khéo thấy. Thấy được sáu lợi ích này, này các Tỷ-kheo, thật là vừa đủ để Tỷ-kheo làm cho an trú tưởng vô ngã không có hạn chế trong tất cả hành.`, ref: "Tăng Chi Bộ 6.104", url: "https://loicuaducphat.org/an/an6.104.html#content" },

{ text: `Này các Tỷ-kheo, có ba pháp này. Thế nào là ba? Không biết đủ, không tỉnh giác, có nhiều dục. Này các Tỷ-kheo, có ba pháp này. Ðể đoạn tận ba pháp đó, này các Tỷ-kheo, ba pháp này cần phải tu tập. Thế nào là ba? Ðể đoạn tận không biết đủ, biết đủ cần phải tu tập. Ðể đoạn tận không tỉnh giác, tỉnh giác cần phải tu tập. Ðể đoạn tận có nhiều dục, ít dục cần phải tu tập. Ðể đoạn tận ba pháp kia, này các Tỷ-kheo, ba pháp này cần phải tu tập.`, ref: "Tăng Chi Bộ 6.114", url: "https://loicuaducphat.org/an/an6.114.html#content" },

{ text: `Này các Tỷ-kheo, có ba pháp này. Thế nào là ba? Ác ngôn, ác bằng hữu, tâm dao động. Này các Tỷ-kheo, có ba pháp này. Ðể đoạn tận ba pháp đó, này các Tỷ-kheo, ba pháp này cần phải tu tập. Thế nào là ba? Ðể đoạn tận ác ngôn, thiện ngôn cần phải tu tập. Để đoạn tận ác bằng hữu, thiện bằng hữu cần phải tu tập. Ðể đoạn tận tâm dao động, niệm hơi thở vào hơi thở ra cần phải tu tập. Ðể đoạn tận ba pháp kia, này các Tỷ-kheo, ba pháp này cần phải tu tập.`, ref: "Tăng Chi Bộ 6.115", url: "https://loicuaducphat.org/an/an6.115.html#content" },


{ text: `Ðể thắng tri tham, này các Tỷ-kheo, sáu pháp cần phải tu tập. Thế nào là sáu? Tưởng vô thường, tưởng khổ trong vô thường, tưởng vô ngã trong khổ, tưởng đoạn tận, tưởng ly tham, tưởng đoạn diệt. Ðể thắng tri tham, này các Tỷ-kheo, sáu pháp này cần phải tu tập.`, ref: "Tăng Chi Bộ 6.142", url: "https://loicuaducphat.org/an/an6.142.html#content" },

{ text: `Thành tựu bảy pháp, này các Tỷ-kheo, Tỷ-kheo không được các đồng Phạm hạnh ái mộ, không được khả ý, không được kính trọng, không được bắt chước tu tập theo. Thế nào là bảy? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo ưa muốn lợi dưỡng, ưa muốn tôn kính, ưa muốn được tán thán, không xấu hổ, không sợ hãi, ác dục và tà kiến. Thành tựu bảy pháp này, này các Tỷ-kheo, Tỷ-kheo không được các đồng Phạm hạnh ái mộ, không được khả ý, không được kính trọng, không được bắt chước tu tập theo.`, ref: "Tăng Chi Bộ 7.1", url: "https://loicuaducphat.org/an/an7.1.html#content" },

{ text: `Thành tựu bảy pháp, này các Tỷ-kheo, Tỷ-kheo được các đồng Phạm hạnh ái mộ, được khả ý, được kính trọng, được bắt chước tu tập theo. Thế nào là bảy? Ở đây, này các Tỷ-kheo, Tỷ-kheo không ưa muốn lợi dưỡng, không ưa muốn tôn kính, không ưa muốn được tán thán, có xấu hổ, có sợ hãi, ít dục và chánh kiến. Thành tựu bảy pháp này, này các Tỷ-kheo, Tỷ-kheo được các đồng Phạm hạnh ái mộ, được khả ý, được kính trọng, được bắt chước tu tập theo.`, ref: "Tăng Chi Bộ 7.1", url: "https://loicuaducphat.org/an/an7.1.html#content" },

{ text: `Tín lực và tấn lực,\nTàm lực và quý lực,\nNiệm lực và định lực,\nVà tuệ lực thứ bảy;\nTỷ-kheo với lực này,\nSống hiền trí an lạc,\nNhư lý suy tư pháp,\nQuán rõ đích trí tuệ,\nNhư ngọn lửa tàn diệt,\nVới tâm được giải thoát.`, ref: "Tăng Chi Bộ 7.3", url: "https://loicuaducphat.org/an/an7.3.html#content" },


{ text: `Này các Tỷ-kheo, có bảy sức mạnh này. Thế nào là bảy? Tín lực, tấn lực, tàm lực, quý lực, niệm lực, định lực, tuệ lực. Và này các Tỷ-kheo, thế nào là tín lực? Ở đây, này các Tỷ-kheo, Thánh đệ tử có lòng tin, tin tưởng ở sự giác ngộ của Như Lai: “Ðây là Thế Tôn, bậc A-la-hán, Chánh Ðẳng Giác, Minh Hạnh Túc, Thiện Thệ, Thế Gian Giải, Vô Thượng Sĩ, Ðiều Ngự Trượng Phu, Thiên Nhơn Sư, Phật Thế Tôn”. Này các Tỷ-kheo, đây gọi là tín lực.`, ref: "Tăng Chi Bộ 7.4", url: "https://loicuaducphat.org/an/an7.4.html#content" },


{ text: `Các pháp này, này các Tỷ-kheo, là bảy pháp. Tín lực và tấn lực, Tàm lực và quý lực, Niệm lực và định lực, Và tuệ lực thứ bảy; Tỷ-kheo với lực này, Sống hiền trí an lạc, Như lý suy tư pháp, Quán rõ đích trí tuệ, Như ngọn lửa tàn diệt, Với tâm được giải thoát.`, ref: "Tăng Chi Bộ 7.4", url: "https://loicuaducphat.org/an/an7.4.html#content" },


{ text: `Tín tài và giới tài,\nTàm tài và quý tài,\nVăn tài và thí tài,\nVà tuệ, tài thứ bảy;\nAi có những tài này,\nNữ nhân hay nam nhân,\nÐược gọi không nghèo khổ,\nMạng sống không trống rỗng,\nDo vậy tín và giới,\nTịnh tín và thấy pháp,\nBậc trí chuyên chú tâm,\nỨc niệm lời Phật dạy.`, ref: "Tăng Chi Bộ 7.6", url: "https://loicuaducphat.org/an/an7.6.html#content" },

{ text: `Này các Tỷ-kheo, có bảy sự thù diệu này. Thế nào là bảy? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo tha thiết hành trì học pháp và trong tương lai khát vọng hành trì học pháp; tha thiết quán Pháp và trong tương lai khát vọng quán Pháp; tha thiết nhiếp phục lòng dục, và trong tương lai khát vọng nhiếp phục lòng dục; tha thiết Thiền tịnh, và trong tương lai khát vọng Thiền tịnh; tha thiết tinh cần tinh tấn và trong tương lai khát vọng tinh cần tinh tấn; tha thiết niệm tuệ và trong tương lai khát vọng niệm tuệ; tha thiết thể nhập tri kiến và trong tương lai khát vọng thể nhập tri kiến. Này các Tỷ-kheo, đây là bảy căn bản để được tán thán.`, ref: "Tăng Chi Bộ 7.20", url: "https://loicuaducphat.org/an/an7.20.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không bị chi phối bởi tham ái, tham ái này tác thành một đời sống khác, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm. Này các Tỷ-kheo, khi nào chúng Tỷ-kheo thích sống những chỗ nhàn tịnh, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm. Này các Tỷ-kheo, khi nào chúng Tỷ-kheo tự thân an trú chánh niệm, khiến các bạn đồng tu thiện chí chưa đến muốn đến ở. Và các bạn đồng tu thiện chí đã đến ở được sống an lạc, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm.`, ref: "Tăng Chi Bộ 7.23", url: "https://loicuaducphat.org/an/an7.23.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo tụ họp trong niệm đoàn kết, giải tán trong niệm đoàn kết, và làm việc Tăng sự trong niệm đoàn kết, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm. Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ban hành những luật lệ không được ban hành, không hủy bỏ những luật lệ đã được ban hành, sống đúng với những học giới được ban hành, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm. Này các Tỷ-kheo, khi nào chúng Tỷ-kheo tôn sùng, kính trọng, đảnh lễ, cúng dường các bậc Tỷ-kheo Thượng tọa, những vị này là những vị giàu kinh nghiệm, niên cao lạp trưởng, bậc cha của chúng Tăng, bậc Thầy của chúng Tăng và nghe theo những lời dạy của những vị này, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm.`, ref: "Tăng Chi Bộ 7.23", url: "https://loicuaducphat.org/an/an7.23.html#content" },

{ text: `Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ưa thích làm thế sự, không hoan hỷ làm thế sự, không đam mê làm thế sự, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm. Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ưa thích phiếm luận, không hoan hỷ phiếm luận, không đam mê phiếm luận, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm. Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ưa thích ngủ nghỉ, không hoan hỷ ngủ nghỉ, không đam mê ngủ nghỉ, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm. Này các Tỷ-kheo, khi nào chúng Tỷ-kheo không ưa thích quần tụ, không hoan hỷ quần tụ, không đam mê quần tụ, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm.`, ref: "Tăng Chi Bộ 7.24", url: "https://loicuaducphat.org/an/an7.24.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là bảy pháp không bị suy giảm? Này các Tỷ-kheo, khi nào chúng Tỷ-kheo có tín tâm, có tàm, có quý, có nghe nhiều, có tinh tấn, có chánh niệm, có trí tuệ, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm. Này các Tỷ-kheo, khi nào bảy pháp không làm suy giảm này được duy trì giữa các Tỷ-kheo, khi nào các Tỷ-kheo được dạy bảy pháp không làm suy giảm này, thời này các Tỷ-kheo, chúng Tỷ-kheo sẽ được lớn mạnh, không bị suy giảm.`, ref: "Tăng Chi Bộ 7.25", url: "https://loicuaducphat.org/an/an7.25.html#content" },

{ text: `Thành tựu bảy chi phần, này các Tỷ-kheo, một Tỷ-kheo cần phải thân cận như một người bạn. Thế nào là bảy? Cho những gì khó cho, làm những gì khó làm, nhẫn những gì khó nhẫn, nói lên những gì bí mật của mình, che giấu bí mật của người khác, không từ bỏ khi gặp bất hạnh, không có khinh rẻ khi tài sản khánh tận. Thành tựu bảy chi phần này, này các Tỷ-kheo, một Tỷ-kheo cần phải thân cận như một người bạn.`, ref: "Tăng Chi Bộ 7.36", url: "https://loicuaducphat.org/an/an7.36.html#content" },

{ text: `Bạn cho điều khó cho,\nLàm những điều khó làm,\nKham nhẫn những lời nói,\nThật khó lòng kham nhẫn,\nNói lên bí mật mình,\nChe giấu bí mật người,\nBất hạnh, không từ bỏ,\nKhánh tận, không chê khinh,\nTrong những trường hợp trên,\nTìm được người như vậy,\nVới ai cần bạn hữu,\nHãy gần bạn như vậy.`, ref: "Tăng Chi Bộ 7.36", url: "https://loicuaducphat.org/an/an7.36.html#content" },

{ text: `Thành tựu bảy pháp, này các Tỷ-kheo, Tỷ-kheo không bao lâu, với thắng trí tự mình chứng ngộ, chứng đạt và an trú bốn vô ngại giải. Thế nào là bảy? Ở đây, này các Tỷ-kheo, Tỷ-kheo khi nào tâm thụ động, như thật rõ biết: “Ðây là tâm ta thụ động”; khi nào tâm muội lược, như thật rõ biết: “Nội tâm ta muội lược”; khi nào tâm tán loạn, hướng ngoại”. Như thật rõ biết tâm ta tán loạn hướng ngoại. Vị ấy nhận thức được các thọ khởi lên, nhận thức được các thọ an trú, nhận thức được các thọ đi đến tiêu diệt; nhận thức được các tưởng khởi lên, nhận thức được các tưởng an trú, nhận thức được các tưởng tiêu diệt; nhận thức được các tầm khởi lên, nhận thức được các tầm an trú, nhận thức được các tầm tiêu diệt. Ðối với các pháp thích hợp hay không thích hợp, đối với các pháp hạ liệt hay thù thắng, đối với các pháp dự phần đen hay dự phần trắng, vị ấy khéo nắm giữ tướng, khéo tác ý, khéo thọ trì, khéo thể nhập với trí tuệ. Thành tựu bảy pháp này, này các Tỷ-kheo, vị Tỷ-kheo không bao lâu, với thắng trí tự mình chứng ngộ, chứng đạt và an trú bốn vô ngại giải.`, ref: "Tăng Chi Bộ 7.38", url: "https://loicuaducphat.org/an/an7.38.html#content" },

{ text: `- Thành tựu bảy pháp, này các Tỷ-kheo, Tỷ-kheo điều phục tâm và không để mình bị tâm điều phục. Thế nào là bảy? Ở đây, này các Tỷ-kheo, Tỷ-kheo thiện xảo về định, thiện xảo nhập định, thiện xảo an trú định, thiện xảo xuất khỏi định, thiện xảo trong sự thoải mái của định, thiện xảo trong cảnh giới của định, thiện xảo trong dẫn phát đến định. Thành tựu bảy pháp này, này các Tỷ-kheo, Tỷ-kheo điều phục tâm và không để mình bị tâm điều phục.`, ref: "Tăng Chi Bộ 7.40", url: "https://loicuaducphat.org/an/an7.40.html#content" },

{ text: `Này Sàriputta, trong Pháp, và Luật này, không có thể nêu rõ một Tỷ-kheo đáng được tán thán, hoàn toàn do đếm số năm. Bảy sự thù diệu này, này Sàriputta, sau khi với thắng trí, Ta tự chứng ngộ, chứng đạt, an trú, và tuyên thuyết. Thế nào là bảy? Ở đây, này Sàriputta, Tỷ-kheo tha thiết hành trì học pháp và trong tương lai khát vọng hành trì học pháp; tha thiết quán pháp và trong tương lai khát vọng quán pháp; tha thiết nhiếp phục lòng dục; và trong tương lai khát vọng nhiếp phục lòng dục, tha thiết Thiền tịnh, trong tương lai khát vọng Thiền tịnh; tha thiết tinh cần tinh tấn và trong tương lai khát vọng tinh cần tinh tấn; tha thiết niệm tuệ và trong tương lai khát vọng niệm tuệ; tha thiết thể nhập tri kiến và trong tương lai khát vọng thể nhập tri kiến. Này Sàriputta, bảy thù diệu sự này được Ta tự mình với thắng trí chứng ngộ, chứng đạt, an trú và tuyên thuyết.`, ref: "Tăng Chi Bộ 7.42", url: "https://loicuaducphat.org/an/an7.42.html#content" },

{ text: `Này các Tỷ-kheo, có bảy tư lương này của định. Thế nào là bảy? Chánh tri kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm. Nhất tâm, này các Tỷ-kheo, được bảy chi phần này làm tư lương; đây được gọi là Thánh chánh định, này các Tỷ-kheo, với các sở ý, với các tư lương.`, ref: "Tăng Chi Bộ 7.45", url: "https://loicuaducphat.org/an/an7.45.html#content" },

{ text: `Ba lửa này, này Bà-la-môn, được cung kính, được tôn trọng, được cúng dường, phải đem lại chánh lạc. Thế nào là ba? Lửa đáng cung kính, lửa gia chủ, lửa đáng cúng dường. Và này Bà-la-môn, thế nào là lửa đáng cung kính? Ở đây, này Bà-la-môn, những người mẹ, những người cha của người ấy, này Bà-la-môn, đây gọi là lửa đáng cung kính. Vì sao? Vì từ đó lửa đáng cung kính này khiến cho mang lại, khiến cho sanh ra. Do vậy, này Bà-la-môn, lửa đáng cung kính này được cung kính, được tôn trọng, được cúng dường, phải đem lại chánh lạc. Và này Bà-la-môn, thế nào là lửa gia chủ? Ở đây, này Bà-la-môn, những người con, những người vợ, những người phục dịch, những người đưa tin, hoặc những người làm công cho người ấy, này Bà-la-môn, đây gọi là lửa gia chủ. Do vậy lửa gia chủ này được cung kính, được tôn trọng, được cúng dường, phải đem lại chánh lạc. Và này Bà-la-môn, thế nào là lửa đáng được cúng dường? Ở đây, này Bà-la-môn, những Sa-môn, Bà-la-môn nào từ bỏ kiêu mạn, phóng dật, sống kham nhẫn nhu hòa; mỗi người điều phục tự ngã; mỗi người an chỉ tự ngã; mỗi người lắng dịu tự ngã. Này Bà-la-môn, đây gọi là ngọn lửa đáng được cúng dường. Do vậy lửa đáng được cúng dường này được cung kính, được tôn trọng, đáng được cúng dường, phải đem lại chánh lạc. Này Bà-la-môn, ba ngọn lửa này được cung kính, được tôn trọng, đáng được cúng dường, phải đem lại chánh lạc.`, ref: "Tăng Chi Bộ 7.47", url: "https://loicuaducphat.org/an/an7.47.html#content" },

{ text: `Tưởng bất tịnh, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, có quả lớn, có lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh, được nói đến như vậy. Do duyên gì được nói đến như vậy? Này các Tỷ-kheo, khi một Tỷ-kheo sống nhiều với các tưởng bất tịnh, thời tâm thối lui, tâm trở lưng, quay lưng để không đắm vào các dâm dục; do đó tâm vị ấy không căng thẳng, thanh thản, khởi lên nhàm chán. Ví như, này các Tỷ-kheo, lông gà hay là dây gân quăng vào lửa thời thối lui, trở lưng, quay lưng, và không căng thẳng; cũng vậy, này các Tỷ-kheo, khi một Tỷ-kheo sống nhiều với các tưởng bất tịnh, thời tâm thối lui, tâm trở lưng, quay lưng để không đắm vào các dâm dục; do đó tâm vị ấy không căng thẳng, thanh thản, khởi lên nhàm chán. Này các Tỷ-kheo, nếu Tỷ-kheo sống nhiều với các tưởng bất tịnh, nhưng tâm lại chạy theo, đắm vào dâm dục, không khởi lên nhàm chán, thời Tỷ-kheo ấy cần phải hiểu rằng: “Tưởng bất tịnh không được ta tu tập; ở nơi ta không có sự sai khác trước và sau. Ta không đạt được quả tu tập”. Ở đấy, vị ấy tỉnh giác như vậy. Này các Tỷ-kheo, nếu Tỷ-kheo sống nhiều với các tưởng bất tịnh, thời tâm thối lui, tâm trở lưng, quay lưng để không đắm vào các dâm dục; do đó tâm vị ấy không căng thẳng, thanh thản, khởi lên nhàm chán, thời Tỷ-kheo ấy cần phải hiểu rằng: “Tưởng bất tịnh được ta tu tập; ở nơi ta có sự sai khác trước và sau. Ta đạt được quả tu tập”. Ở đấy, vị ấy tỉnh giác như vậy. Tưởng bất tịnh, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, có quả lớn, có lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh, được nói đến như vậy, do duyên này được nói đến như vậy.`, ref: "Tăng Chi Bộ 7.49", url: "https://loicuaducphat.org/an/an7.49.html#content" },

{ text: `Một nữ nhân, này các Tỷ-kheo, tác ý nội nữ căn, nữ hành, nữ y phục, nữ loại, nữ dục, nữ thanh, nữ trang sức, thời nữ nhân ấy tham đắm trong ấy, thích thú tại đấy. Do tham đắm trong ấy, thích thú tại đấy nên tác ý đến nam căn ở ngoài, nam hành, nam y phục, nam loại, nam dục, nam thanh, nam trang sức mà nữ nhân ấy tham đắm trong ấy, thích thú tại đấy. Do tham đắm trong ấy, thích thú tại đấy nên nữ nhân ấy ước muốn có sự hệ lụy ở ngoài. Do duyên với hệ lụy ấy, khởi lên lạc, hỷ nên nữ nhân ấy ước muốn lạc hỷ ấy. Này các Tỷ-kheo, do thích thú trong nữ tánh của mình, các loài hữu tình đi đến hệ lụy với những người đàn ông. Như vậy, này các Tỷ-kheo, nữ nhân không có thoát được nữ tánh của mình.`, ref: "Tăng Chi Bộ 7.51", url: "https://loicuaducphat.org/an/an7.51.html#content" },

{ text: `Một nam nhân, này các Tỷ-kheo, tác ý nội nam căn, nam hành, nam y phục, nam loại, nam dục, nam thanh, nam trang sức mà nữ nhân ấy tham đắm trong ấy, thích thú tại đấy. Do tham đắm trong ấy, thích thú tại đấy nên tác ý đến nữ căn ở ngoài, nữ hành, nữ y phục, nữ loại, nữ dục, nữ thanh, nữ trang sức mà nam nhân ấy tham đắm trong ấy, thích thú tại đấy. Do tham đắm trong ấy, thích thú tại đấy nên nam nhân ấy ước muốn có sự hệ lụy ở ngoài. Do duyên với hệ lụy ấy, khởi lên lạc hỷ nên nam nhân ấy ước muốn lạc hỷ ấy. Này các Tỷ-kheo, do thích thú trong nam tánh của mình, các loài hữu tình đi đến hệ lụy với những người đàn bà. Như vậy, này các Tỷ-kheo, nam nhân không thoát khỏi nam tánh của mình.`, ref: "Tăng Chi Bộ 7.51", url: "https://loicuaducphat.org/an/an7.51.html#content" },

{ text: `Ở đây, này Sàriputta, có hạng người bố thí với tâm mong cầu, bố thí với tâm trói buộc, bố thí với tâm mong cầu được chất chứa, bố thí với ý nghĩ: “Ta sẽ hưởng thọ cái này trong đời sau”. Vị ấy bố thí như vậy, khi thân hoại mạng chung, được sanh cộng trú với chư Thiên ở Bốn thiên vương. Và vị ấy, khi nghiệp được đoạn tận, thần lực ấy, danh tiếng ấy, uy quyền ấy được đoạn tận, vị ấy trở thành “vị trở lui lại”, trở lui trạng thái này.`, ref: "Tăng Chi Bộ 7.52", url: "https://loicuaducphat.org/an/an7.52.html#content" },

{ text: `Này Sàriputta, ở đây, ai bố thí không với tâm cầu mong, bố thí không với tâm trói buộc, bố thí không với mong cầu được chất chứa, bố thí không với ý nghĩ: “Ta sẽ hưởng thọ cái này trong đời sau”, bố thí không với ý nghĩ: “Lành thay, sự bố thí”, bố thí không với ý nghĩ: “Cái này đã được cho trong đời quá khứ, đã được tổ tiên làm trong quá khứ, ta không nên để truyền thống gia đình này bị bỏ quên”, bố thí không với ý nghĩ: “Do ta bố thí vật bố thí này, tâm được tịnh tín, hỷ duyệt khởi lên”. Nhưng vị ấy bố thí với ý nghĩ để trang nghiêm tâm, để trang bị tâm. Do vị ấy bố thí như vậy, sau khi thân hoại mạng chung, được sanh cộng trú với chư Thiên ở Phạm chúng thiên. Và khi vị ấy, nghiệp được đoạn tận, thần lực ấy, danh tiếng ấy, uy quyền ấy được đoạn tận, vị ấy trở thành vị Bất lai, không trở lui trạng thái này.`, ref: "Tăng Chi Bộ 7.52", url: "https://loicuaducphat.org/an/an7.52.html#content" },

{ text: `Này các Tỷ-kheo, có bốn điều Như Lai không phải che đậy, và đối với ba điều, Ngài không có phạm lỗi. Thế nào là bốn điều Như Lai không phải che đậy? Này các Tỷ-kheo, thân hành của Như Lai là thanh tịnh. Như Lai không có thân ác hành, khiến Như Lai phải che đậy: “Ðừng để cho người khác biết việc này của Ta!”. Này các Tỷ-kheo, khẩu hành của Như Lai là thanh tịnh. Như Lai không có khẩu ác hành, khiến Như Lai phải che đậy: “Ðừng để cho người khác biết việc này của Ta!”. Này các Tỷ-kheo, ý hành của Như Lai là thanh tịnh. Như Lai không có ý ác hành, khiến Như Lai phải che đậy: “Ðừng để cho người khác biết việc này của Ta!”. Này các Tỷ-kheo mạng sống của Như Lai là thanh tịnh. Như Lai không có tà mạng, khiến Như Lai phải che đậy: “Ðừng để cho người khác biết việc này của Ta!”.`, ref: "Tăng Chi Bộ 7.58", url: "https://loicuaducphat.org/an/an7.58.html#content" },

{ text: `Này các Tỷ-kheo, thành tựu bảy pháp, Tỷ-kheo không bao lâu diệt tận các lậu hoặc... chứng ngộ, chứng đạt và an trú. Thế nào là bảy? Ở đây, này các Tỷ-kheo, Tỷ-kheo có lòng tin, có giữ giới, có nghe nhiều, sống Thiền tịnh, tinh cần tinh tấn, có chánh niệm, có trí tuệ. Thành tựu bảy pháp này, này các Tỷ-kheo, Tỷ-kheo không bao lâu, do diệt tận các lậu hoặc chứng ngộ, chứng đạt và an trú.`, ref: "Tăng Chi Bộ 7.60", url: "https://loicuaducphat.org/an/an7.60.html#content" },

{ text: `Do vậy, này Moggallàna, hãy học tập như sau: “Ta sẽ không nói lời khiêu khích”. Như vậy, này Moggallàna, Thầy cần phải học tập. Khi nào có lời khiêu khích, này Moggallàna, thời chờ đợi là nhiều lời qua tiếng lại, khi nào có nhiều lời qua tiếng lại, thời có dao động. Với người có dao động, thời không có phòng hộ. Với người không có phòng hộ, tâm rời xa Thiền định. Này Moggallàna, Ta không tán thán tất cả sự liên hệ, nhưng không phải Ta không tán thán tất cả sự liên hệ. Thật vậy, này Moggallàna, Ta không tán thán các vị xuất gia có sự liên hệ, với các gia chủ. Nhưng với các trú xứ ít tiếng ồn, ít tiếng động, thoát khỏi hơi thở của nhiều người, những chỗ ở cô độc xa vắng loài Người, thích hợp cho đời sống Thiền tịnh, Ta tán thán sự liên hệ với những trú xứ như vậy.`, ref: "Tăng Chi Bộ 7.61", url: "https://loicuaducphat.org/an/an7.61.html#content" },

{ text: `Kẻ phẫn nộ xấu xí,\nÐau khổ khi nằm ngủ,\nÐược các điều lợi ích\nLại cảm thấy bất lợi.\nPhẫn nộ, nó đả thương,\nVới thân với lời nói,\nNgười phẫn nộ chinh phục,\nTài sản bị tiêu vong.\nBị phẫn nộ điên loạn,\nDanh dự bị hủy diệt,\nBà con cùng bạn bè,\nLánh xa người phẫn nộ.\nPhẫn nộ sanh bất lợi,\nPhẫn nộ dao động tâm,\nSợ hãi sanh từ trong,\nNgười ấy không rõ biết.\nPhẫn nộ không biết lợi,\nPhẫn nộ không thấy pháp,\nPhẫn nộ chinh phục ai,\nNgười ấy bị mê ám.\nNgười phẫn nộ thích thú\nLàm ác như làm thiện,\nVề sau phẫn nộ dứt,\nBị khổ như lửa đốt,\nNhư ngọn lửa dầu khói,\nÐược thấy thất thểu cháy,\nKhi phẫn nộ lan tràn,\nKhi tuổi trẻ nổi nóng,\nKhông xấu hổ, sợ hãi,\nLời nói không cung kính.\nBị phẫn nộ chinh phục,\nKhông hòn đảo tựa nương.\nViệc làm đem hối hận,\nRất xa với Chánh pháp.\nTa sẽ tuyên bố họ,\nHãy nghe như tuyên bố,\nPhẫn nộ giết cả cha,\nPhẫn nộ giết cả mẹ,\nPhẫn nộ giết Phạm chí,\nPhẫn nộ giết phàm phu.\nChính nhờ mẹ dưỡng dục,\nNgười thấy được đời này,\nNhưng phàm phu phẫn nộ,\nGiết người cho sự sống.\nChúng sanh tự ví dụ,\nThương tự ngã tối thượng,\nPhàm phu giết tự ngã,\nÐiên loạn nhiều hình thức,\nLấy gươm giết tự ngã,\nÐiên loại uống thuốc độc,\nDây tự trói họ chết,\nTrong hang động núi rừng,\nNhững hành động sát sanh,\nKhiến tự ngã phải chết.\nHọ làm nhưng không biết,\nKẻ phẫn nộ hại người,\nVới hình thức phẫn nộ,\nMa bẫy ẩn trong tâm.\nHãy nhiếp phục cắt đứt,\nVới tuệ, tấn, chánh kiến,\nBậc trí tuệ cắt đoạn,\nMỗi mỗi bất thiện pháp\nNhư vậy học tập pháp,\nKhông để tâm nản chí,\nLy sân, không áo não,\nLy tham, tật đố không,\nNhiếp phục, đoạn phẫn nộ,\nVô lậu, nhập Niết-bàn.`, ref: "Tăng Chi Bộ 7.64", url: "https://loicuaducphat.org/an/an7.64.html#content" },

{ text: `- Khi tàm quý không có, này các Tỷ-kheo, với người thiếu tàm quý, chế ngự các căn đi đến hủy diệt. Khi chế ngự các căn không có, với người thiếu chế ngự các căn, giới đi đến hủy diệt. Khi giới không có, với người thiếu giới, chánh định đi đến hủy diệt. Khi chánh định không có, với người không có chánh định, tri kiến như thật đi đến hủy diệt. Khi tri kiến như thật không có, với người thiếu tri kiến như thật, nhàm chán ly tham đi đến hủy diệt. Khi nhàm chán ly tham không có, với người thiếu nhàm chán ly tham, giải thoát tri kiến đi đến hủy diệt. Ví như, này các Tỷ-kheo, một cây không có cành và lá, các mầm non của cây cấy không đi đến thành mãn; vỏ trong, giác cây, lõi cây không đi đến thành mãn. Cũng vậy, này các Tỷ-kheo, khi tàm quý không có, với người không có tàm quý, chế ngự các căn đi đến hủy diệt... giải thoát tri kiến đi đến hủy diệt.`, ref: "Tăng Chi Bộ 7.65", url: "https://loicuaducphat.org/an/an7.65.html#content" },

{ text: `Khi tàm quý có mặt, này các Tỷ-kheo, với người đầy đủ tàm quý, chế ngự các căn đi đến đầy đủ. Khi chế ngự các căn có mặt, với người đầy đủ chế ngự các căn, giới đi đến đầy đủ. Khi giới có mặt, với người đầy đủ giới, chánh định đi đến đầy đủ. Khi chánh định có mặt, với người đầy đủ chánh định, tri kiến như thật đi đến đầy đủ. Khi tri kiến như thật có mặt, với người đầy đủ tri kiến như thật, nhàm chán, ly tham đi đến đầy đủ. Khi nhàm chán, ly tham có mặt, với người đầy đủ nhàm chán, ly tham, giải thoát tri kiến đi đến đầy đủ. Ví như, này các Tỷ-kheo, một cây có cành và lá, các mầm non của cây ấy đi đến thành mãn; vỏ trong, giác cây, lõi cây đi đến thành mãn. Cũng vậy, này các Tỷ-kheo, khi tàm quý có mặt, với người đầy đủ tàm quý ... giải thoát tri kiến đi đến đầy đủ.`, ref: "Tăng Chi Bộ 7.65", url: "https://loicuaducphat.org/an/an7.65.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trong thành trì biên địa của vua có một con đường thông hào, vừa sâu và rộng để bảo vệ những người ở trong thành và để chống cự những người bên ngoài. Cũng vậy, này các Tỷ-kheo, Thánh đệ tử có lòng xấu hổ. Vị ấy xấu hổ vì thân làm ác, vì miệng nói ác, vì ý nghĩ ác. Vị ấy xấu hổ vì bị rơi vào các ác, bất thiện pháp. Lấy xấu hổ làm con đường thông hào, này các Tỷ-kheo, Thánh đệ tử từ bỏ bất thiện, tu tập thiện, từ bỏ có tội, tu tập không tội, gìn giữ tự thân thanh tịnh. Với diệu pháp thứ hai này, vị ấy được thành tựu.`, ref: "Tăng Chi Bộ 7.67", url: "https://loicuaducphat.org/an/an7.67.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trong thành trì biên địa của vua có một con đường đi vòng chung quanh, vừa cao vừa rộng để bảo vệ những người ở trong thành và để chống cự những người bên ngoài. Cũng vậy, này các Tỷ-kheo, Thánh đệ tử có lòng sợ hãi, sợ hãi vì thân làm ác, vì miệng nói ác, vì ý nghĩ ác. Vị ấy sợ hãi vì bị rơi vào các ác, bất thiện pháp. Lấy sợ hãi làm con đường đi vòng xung quanh, này các Tỷ-kheo, Thánh đệ tử từ bỏ bất thiện, tu tập thiện, từ bỏ có tội, tu tập không tội, gìn giữ tự thân thanh tịnh. Với diệu pháp thứ ba này, vị ấy được thành tựu.`, ref: "Tăng Chi Bộ 7.67", url: "https://loicuaducphat.org/an/an7.67.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trong thành trì biên địa của vua có nhiều vũ khí được cất chứa, như cung tên và cây lao để bảo vệ những người ở trong thành và để chống cự những người bên ngoài. Cũng vậy, này các Tỷ-kheo, Thánh đệ tử là người nghe nhiều, thọ trì điều đã được nghe, cất chứa điều đã được nghe. Những pháp nào, sơ thiện, trung thiện, hậu thiện, có nghĩa, có văn, nói lên Phạm hạnh hoàn toàn viên mãn thanh tịnh. Các pháp như vậy được nghe nhiều, được thọ trì, được đọc cho thành thục, được ý khéo tùy quán, được khéo thể nhập với tri kiến. Lấy nghe nhiều làm vũ khí, này các Tỷ-kheo, Thánh đệ tử từ bỏ bất thiện, tu tập thiện, từ bỏ có tội, tu tập không tội, gìn giữ tự thân thanh tịnh. Với diệu pháp thứ tư này, vị ấy được thành tựu.`, ref: "Tăng Chi Bộ 7.67", url: "https://loicuaducphat.org/an/an7.67.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trong thành trì biên địa của vua có nhiều quân đội đồn trú, như những người cưỡi voi, những người cưỡi ngựa, những người cưỡi xe, những người cầm cung, những người cầm cờ, những quan lo chỗ ở, các lính lo vấn đề lương thực, những người con vua dõng mãnh, những bộ đội xung kích, đội voi lớn, các dũng sĩ, các binh sĩ mặc áo giáp, những con của nô tỳ, để bảo vệ những người ở trong thành và để chống cự những người bên ngoài. Cũng vậy, này các Tỷ-kheo, vị Thánh đệ tử sống tinh cần tinh tấn để đoạn tận các pháp bất thiện, để đầy đủ các pháp thiện, nỗ lực, kiên trì, không từ bỏ gánh nặng trong các thiện pháp. Lấy tinh tấn làm quân đội, này các Tỷ-kheo, vị thiện nam tử từ bỏ bất thiện, tu tập thiện, từ bỏ có tội, tu tập không tội, gìn giữ tự thân thanh tịnh. Với diệu pháp thứ năm này, vị ấy được thành tựu.`, ref: "Tăng Chi Bộ 7.67", url: "https://loicuaducphat.org/an/an7.67.html#content" },

{ text: `Ví như, này các Tỷ kheo, trong thành trì biên địa của vua có người giữ cửa thành là người hiền trí, thông minh, có trí, ngăn chặn những người lạ mặt, cho vào những người quen biết để bảo vệ những người ở trong thành và để chống cự những người bên ngoài. Cũng vậy, này các Tỷ-kheo, vị Thánh đệ tử sống có chánh niệm thành tựu tối thắng niệm tuệ, nhớ đến và tùy niệm việc làm đã lâu ngày, lời nói đã lâu ngày. Với niệm làm người giữ cửa thành, này các Tỷ kheo, Thánh đệ tử từ bỏ bất thiện, tu tập thiện pháp từ bỏ có tội, tu tập không tội, gìn giữ tự thân thanh tịnh. Với diệu pháp thứ sáu này, vị ấy được thành tựu.`, ref: "Tăng Chi Bộ 7.67", url: "https://loicuaducphat.org/an/an7.67.html#content" },

{ text: `Ví như, này các Tỷ-kheo, trong thành trì biên địa của vua có bức thành vừa cao vừa rộng, ngoài mặt trét vôi hồ để bảo vệ những người ở trong thành và để chống cự những người bên ngoài. Cũng vậy, này các Tỷ-kheo, Thánh đệ tử là người có trí tuệ, thành tựu trí tuệ về sanh diệt, với sự Thánh thể nhập vào con đường đưa đến đoạn tận khổ đau. Với trí tuệ làm lớp vôi hồ trét bên ngoài, này các Tỷ-kheo, Thánh đệ tử từ bỏ bất thiện, tu tập thiện, từ bỏ có tội, tu tập không tội, gìn giữ tự thân thanh tịnh. Với diệu pháp thứ bảy này, vị ấy được thành tựu.`, ref: "Tăng Chi Bộ 7.67", url: "https://loicuaducphat.org/an/an7.67.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo không chí tâm trong sự tu tập khởi lên ước muốn như sau: “Mong rằng tâm ta được giải thoát khỏi các lậu hoặc, không có chấp thủ!” Tuy vậy, tâm vị ấy cũng không giải thoát khỏi các lậu hoặc, không có chấp thủ. Vì cớ sao? Phải nói rằng vì vị ấy không có tu tập. Không có tu tập cái gì? Không có tu tập Bốn niệm xứ, không có tu tập Bốn chánh cần, không có tu tập Bốn như ý túc, không có tu tập Năm căn, không có tu tập Năm lực, không có tu tập Bảy Bồ-đề phần, không có tu tập Thánh đạo tám ngành.`, ref: "Tăng Chi Bộ 7.71", url: "https://loicuaducphat.org/an/an7.71.html#content" },

{ text: `Ta tuyên bố cho các Thầy, này các Tỷ-kheo, Ta nêu rõ cho các Thầy, này các Tỷ-kheo, với một người ác giới, theo ác pháp, tánh tình bất tịnh, thật là tốt hơn bị một người lực sĩ với các tấm sắt nóng đang cháy đỏ, cháy đỏ rực, cháy đỏ lửa ngọn áp cuốn vào thân. Vì cớ sao? Vì do nguyên nhân ấy, này các Tỷ-kheo, người ấy đi đến chết hay đi đến khổ gần như chết, nhưng không vì nhân duyên ấy, sau khi thân hoại mạng chung, có thể sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Nhưng này các Tỷ-kheo, khi một người ác giới, theo ác pháp, sở hành bất tịnh... tánh tình bất tịnh, hưởng thọ các y áo, do các Sát-đế-lỵ đại phú, các Bà-la-môn đại phú, hay các gia chủ đại phú, vì lòng tin cúng dường; như vậy, này các Tỷ-kheo, khiến cho vị ấy bất hạnh, đau khổ lâu dài, sau khi thân hoại mạng chung, sanh vào cõi dữ, ác thú, đọa xứ, địa ngục.\nDo vậy, này các Tỷ-kheo, các Thầy cần phải học tập như sau: “Chúng ta hưởng thọ các vật dụng như y áo, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh của những ai, đối với những người ấy, sở hành như vậy sẽ có quả lớn, có lợi ích hơn. Và sự xuất gia của chúng ta sẽ không có trống không, có kết quả, có thành tích”. Như vậy, này các Tỷ-kheo, các Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 7.72", url: "https://loicuaducphat.org/an/an7.72.html#content" },

{ text: `Thành tựu bảy pháp, này các Tỷ-kheo, Tỷ-kheo là bậc trì Luật. Thế nào là bảy? Biết vi phạm; biết không vi phạm; biết phạm nhẹ, biết phạm nặng; có giới luật, sống chế ngự với sự chế ngự của giới bổn; đầy đủ uy nghi và chánh hạnh, thấy sợ hãi trong những lỗi nhỏ nhặt, chấp nhận và học tập trong các học pháp; bốn Thiền thuộc tăng thượng tâm, hiện tại lạc trú, có được không khó khăn, có được không mệt nhọc, có được không phí sức; do đoạn trừ các lậu hoặc, tự mình với thắng trí ngay trong hiện tại chứng ngộ, chứng đạt vô lậu tâm giải thoát, tuệ giải thoát. Thành tựu bảy pháp này, này các Tỷ-kheo, Tỷ-kheo là bậc trì Luật.`, ref: "Tăng Chi Bộ 7.75", url: "https://loicuaducphat.org/an/an7.75.html#content" },

{ text: `Này Upàli, những pháp nào Thầy biết: “Những pháp này không được đưa đến nhất hướng nhàm chán, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn”, thời này Upàli, Thầy cần phải nhất hướng thọ trì là: “Ðây không phải Pháp, đây không phải Luật, đây không phải lời dạy Thế Tôn”. Và này Upàli, những pháp nào Thầy biết: “Những pháp này đưa đến nhất hướng, nhàm chán, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn”, thời này Upàli, Thầy cần phải nhất hướng thọ trì là: “Ðây là Pháp, đây là Luật, đây là lời dạy Thế Tôn”.`, ref: "Tăng Chi Bộ 7.83", url: "https://loicuaducphat.org/an/an7.83.html#content" },

{ text: `Với từ tâm giải thoát, này các Tỷ-kheo, được sử dụng, được tu tập, được làm cho sung mãn, được làm như cỗ xe, được làm như căn cứ địa, được tùy trú, được tích tập, được khéo tác thành, thời chờ đợi là có tám lợi ích. Thế nào là tám?\nNgủ được an lạc, dậy được an lạc, không thấy ác mộng, được người ái mộ, được phi nhân ái mộ, được chư Thiên hộ trì, lửa hay thuốc độc hay kiếm không gia hại, nếu không thông đạt thượng vị, đạt được Phạm Thiên giới. Với từ tâm giải thoát, này các Tỷ-kheo, được sử dụng, được tu tập, được làm cho sung mãn, được làm như cỗ xe, được làm như căn cứ địa, được tùy trú, được tích tập, được khéo tác thành, thời chờ đợi là có tám lợi ích này.`, ref: "Tăng Chi Bộ 8.1", url: "https://loicuaducphat.org/an/an8.1.html#content" },

{ text: `Ai tu tập từ tâm\nVô lượng thường ức niệm\nCác kiết sử yếu dần\nThấy được sanh y diệt\nVới tâm không ác độc\nTừ mẫn mọi chúng sanh\nDo vậy, vị ấy thành\nBậc thuần nhất chí thiện\nVới tâm ý từ mẫn\nÐối với mọi chúng sanh\nBậc Thánh khéo thực hiện\nNhiều công đức tốt lành\nSau khi đã chinh phục\nRất đông đảo loài người\nCác ẩn sĩ vua chúa\nTheo nghi lễ tế tự\nLễ tế ngựa tế người\nLễ uống nước thắng trận\nLễ ném cầu may rủi\nLễ rút lui khóa cửa\nKhông được phần mười sáu\nBậc khéo tu từ tâm\nNhư ánh sáng mặt trăng\nÐối với các quần sao\nKhông giết, không bảo giết\nKhông thắng, không bảo thắng\nTừ tâm mọi chúng sanh\nKhông hận thù với ai.`, ref: "Tăng Chi Bộ 8.1", url: "https://loicuaducphat.org/an/an8.1.html#content" },

{ text: `Tám pháp thế gian này, này các Tỷ-kheo, tùy chuyển thế giới. Thế giới tùy chuyển theo tám pháp thế gian này. Thế nào là tám? Lợi dưỡng và không lợi dưỡng, danh vọng và không danh vọng, tán thán và chỉ trích, lạc và khổ. Tám pháp thế gian này, này các Tỷ-kheo, tùy chuyển thế giới. Thế giới tùy chuyển theo tám pháp thế gian này.`, ref: "Tăng Chi Bộ 8.5", url: "https://loicuaducphat.org/an/an8.5.html#content" },

{ text: `Lợi dưỡng, không lợi dưỡng,\nDanh vọng, không danh vọng\nTán thán và chỉ trích\nAn lạc và đau khổ\nNhững pháp này vô thường\nKhông thường hằng biến diệt\nBiết chúng giữ chánh niệm\nBậc trí quán biến diệt\nPháp khả ái, không động\nKhông khả ái, không sân\nCác pháp thuận hay nghịch\nÐược tiêu tan không còn\nSau khi biết con đường\nKhông trần cấu, không sầu\nChơn chánh biết sanh hữu\nÐi đến bờ bên kia.`, ref: "Tăng Chi Bộ 8.5", url: "https://loicuaducphat.org/an/an8.5.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, thành tựu tám pháp này, Tỷ-kheo xứng đáng được cung kính ... là ruộng phương vô thượng ở đời. Thế nào là tám? Ở đây, này các Tỷ-kheo, Tỷ-kheo giữ giới, sống chế ngự với sự chế ngự của giới bổn, đầy đủ uy nghi chánh hạnh, thấy sợ hãi trong các lỗi nhỏ nhặt, chấp nhận và học tập trong các học pháp. Phàm nhận các món đồ ăn gì, thô hay tế, vị ấy ăn một cách cẩn thận, không có oán thán gì, vị ấy có nhàm chán, nhàm chán thân làm ác, miệng nói ác, ý nghĩ ác, nhàm chán sự thành tựu các pháp ác bất thiện. Vị ấy hoan hỷ và dễ dàng sống chung với các Tỷ-kheo khác, và không làm các Tỷ-kheo khác hoảng sợ. Phàm có những gian dối, giả dối, xảo trá, quanh co gì, nêu rõ như thật cho vị Ðạo sư hay các đồng Phạm hạnh có trí cố gắng để nhiếp phục. Trong khi học tập, vị ấy khởi lên ý nghĩ: “Hãy để cho các Tỷ-kheo khác học tập, hay không học tập, còn ta, ta sẽ học tập ở đây “. Khi đi, vị ấy đi con đường thẳng, tại đây, con đường thẳng này tức là Chánh tri kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định. Vị ấy sống tinh cần, nghĩ rằng: “Dầu chỉ có da, gân hay xương còn lại, dầu thịt và máu có khô cạn trong thân, điều mà sự kiên trì của con người, sự tinh tấn của con người, sự nỗ lực có thể đạt được, nếu chưa đạt được thời tinh tấn không có chấm dứt. Thành tựu tám pháp này, này các Tỷ-kheo, Tỷ-kheo đáng được cung kính, đáng được tôn trọng, đáng được cúng dường, đáng được chắp tay, là ruộng phước vô thượng ở đời.`, ref: "Tăng Chi Bộ 8.13", url: "https://loicuaducphat.org/an/an8.13.html#content" },

{ text: `Này các Tỷ-kheo, có tám tâm cấu uế này, thế nào là tám? Này các Tỷ-kheo, không đọc tụng là cấu uế của Thánh điển; này các Tỷ-kheo, không thức dậy là cấu uế của nhà; này các Tỷ-kheo, biếng nhác là cấu uế của dung sắc; này các Tỷ-kheo, phóng dật là cấu uế của phòng hộ; này các Tỷ-kheo, ác hạnh là cấu uế của đàn bà; này các Tỷ-kheo, xan tham là cấu uế của bố thí; các pháp ác, bất thiện, là cấu uế của đời này và đời sau. Nhưng này các Tỷ-kheo, còn có cấu uế lớn hơn các cấu uế. Vô minh là cấu uế lớn nhất. Này các Tỷ-kheo, đây là tám loại cấu uế.`, ref: "Tăng Chi Bộ 8.15", url: "https://loicuaducphat.org/an/an8.15.html#content" },

{ text: `Với tám hình tướng, này các Tỷ-kheo, nữ nhân trói buộc nam nhân. Thế nào là tám? Này các Tỷ-kheo, nữ nhân trói buộc nam nhân với sắc; này các Tỷ-kheo nữ nhân trói buộc nam nhân với tiếng cười; này các Tỷ-kheo, nữ nhân trói buộc nam nhân với lời nói; này các Tỷ-kheo, nữ nhân trói buộc nam nhân với lời ca; này các Tỷ-kheo, nữ nhân trói buộc nam nhân với nước mắt; này các Tỷ-kheo, nữ nhân trói buộc nam nhân với áo quần; này các Tỷ-kheo, nữ nhân trói buộc nam nhân với vật tặng; này các Tỷ-kheo, nữ nhân trói buộc nam nhân với xúc chạm. Với tám hình tướng, này các Tỷ-kheo, nữ nhân trói buộc nam nhân. Các loài hữu tình bị khéo trói buộc bởi các hình tướng ấy, giống như trói buộc bởi bẫy sập.`, ref: "Tăng Chi Bộ 8.17", url: "https://loicuaducphat.org/an/an8.17.html#content" },

{ text: `Này các Tỷ-kheo, có tám sức mạnh này. Thế nào là tám? Này các Tỷ-kheo, sức mạnh của con nít là khóc; sức mạnh của đàn bà là phẫn nộ; sức mạnh của người ăn trộm là vũ khí; sức mạnh của các vua chúa là uy quyền; sức mạnh của kẻ ngu là áp đảo; sức mạnh của bậc Hiền trí là cảm hóa; sức mạnh của vị nghe nhiều là thẩm sát; sức mạnh của Sa-môn, Bà-la-môn là nhẫn nhục. Này các Tỷ-kheo, đây là tám sức mạnh.`, ref: "Tăng Chi Bộ 8.27", url: "https://loicuaducphat.org/an/an8.27.html#content" },

{ text: `Ở đây, bạch Thế Tôn, Tỷ-kheo đã đoạn tận các lậu hoặc khéo thấy như thật với chánh trí tuệ rằng tất cả các hành là vô thường. Vì rằng, bạch Thế Tôn, Tỷ-kheo đã đoạn tận các lậu hoặc, khéo thấy như thật với chánh trí tuệ rằng tất cả các hành là vô thường.\nLại nữa, bạch Thế Tôn, Tỷ-kheo đã đoạn tận các lậu hoặc khéo thấy như thật với chánh trí tuệ rằng các dục ví như hố than hừng. Vì rằng, bạch Thế Tôn, Tỷ-kheo đã đoạn tận các lậu hoặc khéo thấy như thật với chánh trí tuệ rằng các dục ví như hố than hừng.\nLại nữa, bạch Thế Tôn, Tỷ-kheo đã đoạn tận các lậu hoặc, với tâm thuận xuôi về viễn ly, hướng về viễn ly, thiên về viễn ly, trú ở viễn ly, hoan hỷ về xuất ly, đoạn tận hoàn toàn tất cả pháp có thể làm trú xứ cho lậu hoặc.\nLại nữa, bạch Thế Tôn, Tỷ-kheo đã đoạn tận các lậu hoặc, Bốn niệm xứ được tu tập, được khéo tu tập. Bạch Thế Tôn, vì rằng Tỷ-kheo đã đoạn tận các lậu hoặc, Bốn niệm xứ được tu tập, được khéo tu tập.\nBạch Thế Tôn, đây là sức mạnh của Tỷ-kheo đã đoạn tận các lậu hoặc. Do sức mạnh này, Tỷ-kheo đã đoạn tận các lậu hoặc, tự nhận mình đã đoạn diệt các lậu hoặc: “Các lậu hoặc đã được ta đoạn tận”.`, ref: "Tăng Chi Bộ 8.28", url: "https://loicuaducphat.org/an/an8.28.html#content" },

{ text: `Ai được sanh làm người\nKhi diệu pháp được giảng\nLại không nắm được thời\nHọ vượt qua khỏi thời\nNhiều phi thời được nói\nLàm chướng ngại con người\nChỉ năm khi mười họa\nNhư Lai hiện ở đời\nÐược giáp mặt với Ngài\nRất khó được ở đời\nÐược sanh ra làm người\nVà diệu pháp được giảng\nVừa đủ để tinh tấn\nVới ai muốn lợi ích\nSao biết rõ diệu pháp\nLại để thời vượt qua!\nKẻ để thời gian qua\nSầu muộn tại địa ngục\nỞ đây ai bỏ rơi\nQuyết định tánh diệu pháp\nNhư kẻ buôn mất của\nSẽ sầu não lâu ngày\nNgười vô minh bao phủ\nVi phạm đến diệu pháp\nPhải chịu đựng lâu ngày\nLưu chuyển trong sanh tử\nAi được sanh làm người\nTrong thời pháp khéo giảng\nQuá khứ, hiện, vị lai\nLàm theo lời Ðạo sư\nNắm được thời ở đời\nCho vô thượng Phạm hạnh\nAi đã bước con đường\nDo Như Lai thuyết giảng\nNhững ai sống chế ngự\nDo bậc pháp nhãn dạy\nNhư đã được thuyết giảng\nBậc bà con mặt trời\nHãy sống thường chánh niệm\nHộ trì không tham dục\nChặt đứt mọi tùy miên\nKhông chạy theo ma giới\nCác vị ấy ở đời\nÐến được bờ bên kia\nVà họ cũng đạt được\nCác lậu hoặc đoạn tận.`, ref: "Tăng Chi Bộ 8.29", url: "https://loicuaducphat.org/an/an8.29.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là tám tư niệm của bậc Ðại nhân?\nNày các Tỷ-kheo, Pháp này để cho người ít dục, Pháp này không phải để cho người nhiều dục; Này các Tỷ kheo,Pháp này để cho người biết đủ, pháp này không phải để cho người không biết đủ; Này các Tỷ kheo, Pháp này để cho người sống thanh vắng, pháp này không phải để cho người ưa hội chúng; Này các Tỷ kheo, Pháp này để cho người tinh cần tinh tấn, pháp này không phải để cho người biếng nhác; Này các Tỷ kheo,Pháp này để cho người trú niệm, pháp này không phải để cho người thất niệm; Này các Tỷ kheo, Pháp này để cho người Thiền định, pháp này không phải để cho người không Thiền định; Này các Tỷ kheo, Pháp này để cho người có trí tuệ, Pháp này không phải để cho người ác tuệ; Này các Tỷ-kheo, Pháp này để cho người không ưa hý luận, không thích hý luận, Pháp này không phải để cho người ưa hý luận, thích hý luận.`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Này các Tỷ-kheo, “Pháp này để cho người ít dục, Pháp này không để cho người có dục lớn”, như vậy đã được nói đến. Do duyên gì được nói như vậy?\nNày các Tỷ-kheo, ở đây, Tỷ-kheo ít dục không muốn: “Mong người ta biết tôi là ít dục”; biết đủ, không muốn: “Mong người ta biết tôi là biết đủ”; sống viễn ly, không muốn: “Mong người ta biết tôi sống viễn ly”; tinh cần tinh tấn, không muốn: “Mong người ta biết tôi sống tinh cần tinh tấn”; trú niệm, không muốn: “Mong người ta biết tôi trú niệm”; có định, không muốn: “Mong người ta biết tôi có định”; có tuệ, không muốn: “Mong người ta biết tôi là người có tuệ “; không thích hý luận, không muốn: “Mong người ta biết tôi không thích hý luận”. Này các Tỷ-kheo, Pháp này để cho người ít dục, Pháp này không để cho người có dục lớn”, đã được nói đến như vậy. Do duyên này được nói như vậy.`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Này các Tỷ-kheo, “Pháp này để cho người biết đủ, Pháp này không để cho người không biết đủ”, như vậy đã được nói đến. Do duyên gì được nói như vậy?\nỞ đây, này các Tỷ-kheo, Tỷ-kheo biết đủ với bất cứ vật dụng gì như y áo, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh. Này các Tỷ-kheo, “Pháp này để cho người biết đủ, Pháp này không phải để cho người không biết đủ”, đã được nói đến như vậy. Do duyên này được nói như vậy.`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Này các Tỷ-kheo, Pháp này để cho người sống viễn ly, “Pháp này không phải để cho người ưa thích hội chúng”, như vậy đã được nói đến. Do duyên gì được nói như vậy?\nỞ đây, này các Tỷ-kheo, Với Tỷ-kheo sống viễn ly, có nhiều người đến thăm như Tỷ-kheo, Tỷ-kheo-Ni, nam cư sĩ, nữ cư sĩ, vua chúa, đại thần, các ngoại đạo sư, đệ tử của các ngoại đạo sư. Ở đây, Tỷ-kheo với tâm thuận về viễn ly, hướng về viễn ly, nhập vào viễn ly, trú vào viễn ly, thích thú xuất ly, nói lời hoàn toàn liên hệ đến lánh xa. Này các Tỷ-kheo, Pháp này để cho người viễn ly, “Pháp này không phải để cho người không ưa hội chúng”, đã được nói đến như vậy. Do duyên này được nói như vậy.`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Này các Tỷ-kheo, Pháp này để cho người tinh cần tinh tấn, “Pháp này không phải để cho người biếng nhác”, như vậy đã được nói đến. Do duyên gì được nói như vậy?\nỞ đây, này các Tỷ-kheo, Tỷ-kheo sống tinh cần tinh tấn, đoạn tận các pháp bất thiện, thành tựu các Pháp thiện, nỗ lực kiên trì, không từ bỏ gánh nặng đối với các thiện pháp. Này các Tỷ-kheo, Pháp này để cho người tinh cần tinh tấn, “Pháp này không phải để cho người biếng nhác”, đã được nói đến như vậy. Do duyên này được nói như vậy.`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Này các Tỷ-kheo, Pháp này để cho người trú niệm, “Pháp này không phải để cho người thất niệm”, như vậy đã được nói đến. Do duyên gì được nói như vậy?\nỞ đây, này các Tỷ-kheo, Tỷ-kheo đầy đủ niệm, thành tựu niệm tuệ tối thắng, ức nhớ tùy niệm những điều đã làm, nói đã lâu. Này các Tỷ-kheo, “Pháp này để cho người trú niệm, Pháp này không phải để cho người thất niệm”, đã được nói đến như vậy. Do duyên này được nói như vậy.`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Này các Tỷ-kheo, Pháp này để cho người thiền định, “Pháp này không phải để cho người không thiền định”, như vậy đã được nói đến. Do duyên gì được nói như vậy?\nỞ đây, này các Tỷ-kheo, Tỷ-kheo ly dục, ly ác pháp ... chứng đạt và an trú Thiền thứ tư. Này các Tỷ-kheo, Pháp này để cho người thiền định, “Pháp này không phải để cho người không thiền định”, đã được nói đến như vậy. Do duyên này được nói như vậy.`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Này các Tỷ-kheo, Pháp này để cho người có trí tuệ, “Pháp này không phải để cho người không trí tuệ”, như vậy đã được nói đến. Do duyên gì được nói như vậy?\nỞ đây, này các Tỷ-kheo, Tỷ-kheo có trí tuệ, có trí tuệ về sanh diệt, thành tựu Thánh thể nhập (quyết trạch), đưa đến chơn chánh đoạn diệt khổ đau. Này các Tỷ-kheo, “Pháp này để cho người có trí tuệ, Pháp này không phải để cho người không trí tuệ”, đã được nói đến như vậy. Do duyên này được nói như vậy`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Này các Tỷ-kheo, Pháp này để cho người không ưa hý luận, không thích hý luận, “Pháp này không phải để cho người ưa hý luận, thích hý luận”, như vậy đã được nói đến. Do duyên gì được nói như vậy?\nNày các Tỷ-kheo, ở đây, Tỷ-kheo đối với đoạn diệt hý luận, tâm được phấn chấn, tịnh tín, an trú, hướng đến. Này các Tỷ-kheo, Pháp này để cho người không ưa hý luận, không thích hý luận, “Pháp này không phải để cho người ưa hý luận, thích hý luận”, đã được nói đến như vậy. Do duyên này được nói như vậy.`, ref: "Tăng Chi Bộ 8.30", url: "https://loicuaducphat.org/an/an8.30.html#content" },

{ text: `Khi ruộng được đầy đủ\nHột giống gieo đầy đủ\nKhi mưa xuống đầy đủ\nLúa gặt được đầy đủ\nTai họa không có mặt\nTăng trưởng được đầy đủ\nRộng lớn được đầy đủ\nKết quả được đầy đủ\nCũng vậy, sự bố thí\nGiữa những người đủ giới\nVà vật liệu bố thí\nCũng được sắm đầy đủ\nÐưa đến sự đầy đủ\nVì sở hành đầy đủ\nVậy ai muốn đầy đủ\nPhải tự mình đầy đủ\nPhục vụ người đủ tuệ\nNhư vậy thành công đủ\nÐầy đủ trí và đức\nVới tâm được đầy đủ\nLàm nghiệp được đầy đủ\nLợi ích được đầy đủ\nNhư thật biết cuộc đời\nÐạt được kiến đầy đủ\nÐường đầy đủ đi đến\nTiến đến ý đầy đủ\nVất bỏ mọi cấu uế\nÐạt Niết-bàn cụ túc\nGiải thoát mọi khổ đau\nTức đầy đủ vẹn toàn.`, ref: "Tăng Chi Bộ 8.34", url: "https://loicuaducphat.org/an/an8.34.html#content" },

{ text: `Này các Tỷ-kheo, người giữ giới thành công, vì tâm hướng đến thanh tịnh. Này các Tỷ-kheo, người giữ giới thành công, vì tâm hướng đến ly tham.`, ref: "Tăng Chi Bộ 8.35", url: "https://loicuaducphat.org/an/an8.35.html#content" },

{ text: `Này các Tỷ-kheo, có ba căn bản làm phước. Thế nào là ba? Căn bản làm phước do bố thí, căn bản làm phước do giới đức, căn bản làm phước do tu tập. Này các Tỷ-kheo, có ba căn bản phước nghiệp này.`, ref: "Tăng Chi Bộ 8.36", url: "https://loicuaducphat.org/an/an8.36.html#content" },

{ text: `Này các Tỷ-kheo, có tám bố thí này của bậc chân nhân. Thế nào là tám? Cho vật trong sạch; cho vật thù diệu; cho đúng thời; cho vật thích ứng; cho với sự cẩn thận; cho luôn luôn; tâm cho được tịnh tín; sau khi cho được hoan hỷ. Này các Tỷ-kheo, có tám bố thí này của bậc chân nhân:`, ref: "Tăng Chi Bộ 8.37", url: "https://loicuaducphat.org/an/an8.37.html#content" },

{ text: `Trong sạch và thù diệu\nÐúng thời và thích ứng\nÐồ uống và đồ ăn\nLuôn luôn làm bố thí\nTrong các ruộng tốt lành\nSống theo đời Phạm hạnh\nKhông có gì hối tiếc\nBố thí nhiều tài vật\nNhững bố thí như vậy\nÐược bậc trí tán thán\nBậc Trí thí như vậy\nVới tâm tín, giải thoát\nKhông hại, tâm an lạc\nBậc trí sanh ở đời.`, ref: "Tăng Chi Bộ 8.37", url: "https://loicuaducphat.org/an/an8.37.html#content" },

{ text: `Ví như, này các Tỷ-kheo, một cơn mưa lớn làm cho các loại mùa màng đều thành tựu đầy đủ, đem lại lợi ích, hạnh phúc, an lạc cho nhiều người. Cũng vậy, này các Tỷ-kheo, bậc Chân nhân sinh ra trong gia đình nào, đem lại lợi ích, hạnh phúc, an lạc cho nhiều người; đem lại lợi ích, hạnh phúc, an lạc cho cha mẹ; đem lại lợi ích, hạnh phúc, an lạc cho vợ con; đem lại lợi ích, hạnh phúc, an lạc cho người phục vụ, người làm công; đem lại lợi ích, hạnh phúc, an lạc cho bạn bè thân hữu; đem lại lợi ích, hạnh phúc, an lạc cho các hương linh đã mất; đem lại lợi ích, hạnh phúc, an lạc cho vua chúa; đem lại lợi ích, hạnh phúc, an lạc cho chư Thiên; đem lại lợi ích, hạnh phúc, an lạc cho Sa-môn, Bà-la-môn.`, ref: "Tăng Chi Bộ 8.38", url: "https://loicuaducphat.org/an/an8.38.html#content" },

{ text: `Vì lợi ích nhiều người\nBậc trí sống gia đình\nKhông mệt mỏi ngày đêm\nCúng dường thật đúng pháp\nMẹ cha và tổ tiên\nNhớ ngày trước đã làm\nÐối xuất gia, không nhà\nKính lễ bậc Phạm hạnh\nTin vững trú, cúng dường\nBiến pháp, khéo xử sự\nLà người đem lợi ích\nCho vua, cho chư Thiên\nLà người đem lợi ích\nCho bà con, bè bạn\nLà người đem lợi ích\nCho tất cả mọi người\nKhéo an trú diệu pháp\nNhiếp xan tham cấu uế\nHưởng cuộc đời hạnh phúc.`, ref: "Tăng Chi Bộ 8.38", url: "https://loicuaducphat.org/an/an8.38.html#content" },

{ text: `Này các Tỷ-kheo, sát sanh được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của sát sanh là được làm người với tuổi thọ ngắn.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Này các Tỷ-kheo, lấy của không cho được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của lấy của không cho là được làm người với sự tổn hại tài sản.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Này các Tỷ-kheo, tà hạnh trong các dục được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của tà hạnh trong các dục là được làm người với sự oán thù của kẻ địch.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Này các Tỷ-kheo, nói láo được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của nói láo là được làm người bị vu cáo không đúng sự thật.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Này các Tỷ-kheo, nói hai lưỡi được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của nói hai lưỡi là được làm người với bạn bè bị đổ vỡ.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Này các Tỷ-kheo, nói ác khẩu được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của nói ác khẩu là được làm người và được nghe những tiếng không khả ý.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Này các Tỷ-kheo, nói lời phù phiếm được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của nói lời phù phiếm là được làm người và được nghe những lời khó chấp nhận.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Này các Tỷ-kheo, uống men rượu, rượu nấu, được thực hiện, được tu tập, được làm cho sung mãn, đưa đến địa ngục, đưa đến loại bàng sanh, đưa đến cõi ngạ quỷ. Quả dị thục hết sức nhẹ của uống rượu mem, rượu nấu là được làm người với tâm điên loạn.`, ref: "Tăng Chi Bộ 8.40", url: "https://loicuaducphat.org/an/an8.40.html#content" },

{ text: `Chớ giết hại loại sanh\nChớ lấy của không cho\nChớ nói lời nói láo\nChớ uống thứ rượu say\nTừ bỏ phi Phạm hạnh\nTừ bỏ không dâm dục\nKhông ăn vào ban đêm\nTránh không ăn phi thời\nKhông mang các vòng hoa\nKhông dùng các hương liệu\nHãy nằm trên tấm thảm\nTrải dài đất làm giường\nChính hạnh trai giới này\nÐược gọi có tám phần\nDo đức Phật nói lên\nÐưa đến đoạn tận khổ\nMặt trăng và mặt trời\nCả hai thấy lành tốt\nChỗ nào chúng đi tới,\nChúng chói sáng hào quang\nChúng làm mây sáng chói\nGiữa hư không chúng đi\nTrên trời chúng chói sáng\nSáng rực mọi phương hướng\nTrong khoảng không gian ấy\nTài sản được tìm thấy\nTrân châu và ngọc báu\nLưu ly đá cầu may\nVàng cục trong lòng đất\nHay loại Kancana\nCùng loại vàng sáng chói\nÐược gọi Hataka\nTuy vậy chúng giá trị\nChỉ một phần mười sáu\nVới hạnh giữ trai giới\nÐầy đủ cả tám mặt\nKể cả ánh sáng trăng\nVới cả vòm trời sao\nVậy người nữ, người nam\nGiữ gìn theo tịnh giới\nHành Bồ-tát trai giới\nÐầy đủ cả tám mặt\nLàm các thiện công đức\nÐem lại nhiều an lạc\nÐược sanh lên cõi trời\nKhông bị người cười chê.`, ref: "Tăng Chi Bộ 8.42", url: "https://loicuaducphat.org/an/an8.42.html#content" },
{ text: `- Này Gotamì, những pháp nào bà biết: “Những pháp này đưa đến tham dục, không phải ly tham; đưa đến hệ phước, không đưa đến ly hệ phước; đưa đến tích tập, không đưa đến không tích tập; đưa đến dục lớn, không đưa đến ít dục; đưa đến không biết đủ, không đưa đến biết đủ; đưa đến tụ hội, không đưa đến nhàn tịnh; đưa đến biếng nhác, không đưa đến tinh tấn; đưa đến khó nuôi dưỡng, không đưa đến dễ nuôi dưỡng”. Này Gotamì, hãy thọ trì nhứt hướng rằng: “Ðó là không phải Pháp, đó là không phải Luật, đó là không phải lời dạy của bậc Ðạo sư”.`, ref: "Tăng Chi Bộ 8.53", url: "https://loicuaducphat.org/an/an8.53.html#content" },

{ text: `Và này Gotamì, những pháp nào bà biết: “Những pháp đưa đến ly tham, không đưa đến tham dục; đưa đến ly hệ phước, không đưa đến hệ phước; đưa đến không tích tập, không đưa đến tích tập; đưa đến ít dục, không đưa đến dục lớn; đưa đến biết đủ, không đưa đến không biết đủ; đưa đến nhàn tịnh, không đưa đến tụ hội; đưa đến tinh tấn, không đưa đến biếng nhác; đưa đến dễ nuôi dưỡng, không đưa đến khó nuôi dưỡng”. Này Gotamì, hãy thọ trì nhứt hướng rằng: “Ðó là Pháp, đó là Luật, đó là lời dạy của bậc Ðạo sư”.`, ref: "Tăng Chi Bộ 8.53", url: "https://loicuaducphat.org/an/an8.53.html#content" },

{ text: `VI. Phẩm Gotamì`, ref: "Tăng Chi Bộ 8.56", url: "https://loicuaducphat.org/an/an8.56.html#content" },

{ text: `Sợ hãi, này các Tỷ-kheo, là đồng nghĩa với các dục. Ðau khổ, này các Tỷ-kheo, là đồng nghĩa với các dục. Bệnh tật, này các Tỷ-kheo, là đồng nghĩa với các dục. Cục bướu, này các Tỷ-kheo, là đồng nghĩa với các dục. Mũi tên, này các Tỷ-kheo, là đồng nghĩa với các dục. Trói buộc, này các Tỷ-kheo, là đồng nghĩa với các dục. Bùn, này các Tỷ-kheo, là đồng nghĩa với các dục. Thai tạng, này các Tỷ-kheo, là đồng nghĩa với các dục.\nNhư thế nào, này các Tỷ-kheo, sợ hãi là đồng nghĩa với các dục? Vì rằng, những ai bị dục ái nhiễm, những ai bị dục tham trói buộc, không được giải thoát khỏi sợ hãi hiện tại, không được giải thoát khỏi sợ hãi trong tương lai; do vậy, sợ hãi là đồng nghĩa với các dục.`, ref: "Tăng Chi Bộ 8.56", url: "https://loicuaducphat.org/an/an8.56.html#content" },

{ text: `Sợ hãi, khổ và bệnh\nCục bướu và mũi tên\nTrói buộc và bùn lầy\nCả hai cùng thai tạng\nChúng được gọi tình dục\nChỗ phàm phu ái nhiễm\nChìm đắm trong sắc đẹp\nChúng lại vào thai tạng\nKhi Tỷ-kheo nhiệt tình\nKhông thả lỏng tỉnh giác\nVượt đường hiểm nạn này\nCon đường khó vượt qua\nVị ấy nhìn chúng sanh\nÐang sống trong sợ hãi\nVì bị sanh và già\nÁm ảnh và chinh phục.`, ref: "Tăng Chi Bộ 8.56", url: "https://loicuaducphat.org/an/an8.56.html#content" },

{ text: `“Nội tâm ta sẽ an trú, khéo vững trú. Các pháp ác, bất thiện sanh khởi không có xâm chiếm tâm và không có chân đứng”. Như vậy, này Tỷ-kheo, Thầy cần phải học tập. Này Tỷ-kheo, khi nào nội tâm của Thầy được an trú, khéo vững trú, các pháp ác, bất thiện sanh khởi xâm chiếm tâm và có chân đứng, khi ấy, này Tỷ-kheo, Thầy cần phải học tập như sau:\n“Từ tâm giải thoát sẽ được ta tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành căn cứ địa, được làm cho kiên trì, được làm cho tích tập, được khéo tinh cần thực hành”. Như vậy, này Tỷ-kheo, Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 8.63", url: "https://loicuaducphat.org/an/an8.63.html#content" },

{ text: `“Ta sẽ sống quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời”. Như vậy, này Tỷ-kheo, Thầy cần phải học tập. Này Tỷ-kheo, khi nào định này của Thầy được tu tập, được làm cho sung mãn như vậy, khi ấy, này Tỷ-kheo, Thầy cần phải tu tập định này với tầm với tứ; cần phải tu tập không tầm, với tứ; cần phải tu tập không tầm, không tứ; cần phải tu tập có hỷ, cần phải tu tập không hỷ; cần phải tu tập câu hữu với lạc; cần phải tu tập câu hữu với xả. Này Tỷ-kheo, khi nào định này của Thầy được tu tập, được làm cho sung mãn như vậy, khi ấy này Tỷ-kheo, chỗ nào, chỗ nào Thầy đi, chỗ ấy Thầy đi được an ổn; chỗ nào, chỗ nào Thầy sẽ đứng, chỗ ấy Thầy đứng được an ổn; chỗ nào, chỗ nào sẽ Thầy ngồi, chỗ ấy Thầy ngồi được an ổn; chỗ nào, chỗ nào Thầy sẽ nằm, chỗ ấy Thầy sẽ nằm được an ổn.`, ref: "Tăng Chi Bộ 8.63", url: "https://loicuaducphat.org/an/an8.63.html#content" },

{ text: `Này các Tỷ-kheo, có tám phi thánh ngôn này. Thế nào là tám? Không thấy nói thấy, không nghe nói nghe, không nghĩ nói nghĩ, không biết nói biết, thấy nói không thấy, nghe nói không nghe, nghĩ nói không nghĩ, biết nói không biết. Này các Tỷ-kheo, đây là tám phi Thánh ngôn.`, ref: "Tăng Chi Bộ 8.67", url: "https://loicuaducphat.org/an/an8.67.html#content" },

{ text: `Này các Tỷ-kheo, có tám thánh ngôn này. Thế nào là tám? Không thấy nói không thấy, không nghe nói không nghe, không nghĩ nói không nghĩ, không biết nói không biết, thấy nói thấy, nghe nói nghe, nghĩ nói nghĩ, biết nói biết. Này các Tỷ-kheo, đây là tám Thánh ngôn.`, ref: "Tăng Chi Bộ 8.68", url: "https://loicuaducphat.org/an/an8.68.html#content" },

{ text: `Ở đây, này các Hiền giả, có Tỷ-kheo trong khi sống nhàn tịnh, không có tinh tấn, khởi lên ước muốn có lợi dưỡng. Vị ấy hăng hái, phấn chấn, tinh tấn để được lợi dưỡng. Do hăng hái, phấn chấn, tinh tấn để được lợi dưỡng, lợi dưỡng khởi lên. Với lợi dưỡng ấy, vị ấy đắm say, phóng dật, rơi vào tình trạng đắm say, phóng dật. Ðây gọi là Tỷ-kheo sống ham muốn lợi dưỡng, hăng hái, phấn chấn, tinh tấn để được lợi dưỡng; được lợi dưỡng, trở thành đắm say, phóng dật và bỏ rơi diệu pháp.`, ref: "Tăng Chi Bộ 8.77", url: "https://loicuaducphat.org/an/an8.77.html#content" },

{ text: `- Này các Tỷ-kheo, có tám pháp này đưa Tỷ-kheo hữu học đến thối đọa. Thế nào là tám? Ưa thích công việc, ưa thích nói chuyện, ưa thích ngủ nghỉ, ưa thích hội chúng, không phòng hộ các căn, không tiết độ trong ăn uống, ưa thích giao thiệp, ưa thích hý luận. Này các Tỷ-kheo, tám pháp này đưa Tỷ-kheo hữu học đến thối đọa.`, ref: "Tăng Chi Bộ 8.79", url: "https://loicuaducphat.org/an/an8.79.html#content" },

{ text: `Này các Tỷ-kheo, có tám pháp này đưa Tỷ-kheo hữu học đến không thối đọa. Thế nào là tám pháp? Không ưa thích công việc, không ưa thích nói chuyện, không ưa thích ngủ nghỉ, không ưa thích hội chúng, các căn được phòng hộ, tiết độ trong ăn uống, không ưa thích giao thiệp, không ưa thích hý luận. Này các Tỷ-kheo, có tám pháp này đưa Tỷ-kheo hữu học đến không thối đọa.`, ref: "Tăng Chi Bộ 8.79", url: "https://loicuaducphat.org/an/an8.79.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo có việc phải làm, vị ấy nghĩ: “Có việc ta sẽ phải làm. Nhưng nếu ta làm, thời thân sẽ mệt mỏi, vậy ta hãy nằm xuống”. Vị ấy nằm xuống, không cố gắng tinh tấn để đạt được những gì chưa đạt, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ biếng nhác thứ nhất.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, Tỷ-kheo có việc phải làm. Vị ấy suy nghĩ: “Có việc ta đã làm, do ta đã làm, thân bị mệt mỏi, vậy ta hãy nằm xuống”. Vị ấy nằm xuống, không cố gắng tinh tấn để đạt những gì chưa đạt, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ biếng nhác thứ hai.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, Tỷ-kheo đi khất thực trong làng hay trong thị trấn, không nhận được các đồ ăn loại thô hay tế, đầy đủ như ý muốn. Vị ấy suy nghĩ: “Ta đi khất thực trong làng hay trong thị trấn, không nhận được các đồ ăn loại thô hay tế, đầy đủ như ý muốn. Nay thân ta mệt mỏi, không có thể chịu đựng. Vậy ta hãy nằm xuống”. Vị ấy nằm xuống, không cố gắng... chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ biếng nhác thứ năm.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, Tỷ-kheo đi khất thực trong làng hay trong thị trấn, nhận được các đồ ăn loại thô hay tế, đầy đủ như ý muốn. Vị ấy suy nghĩ: “Ta đi khất thực trong làng hay trong thị trấn, nhận được các đồ ăn loại thô hay tế, đầy đủ như ý muốn. Nay thân ta nặng nề, không có thể chịu đựng, nặng nề như loại đậu bị ngâm nước. Vậy ta hãy nằm xuống”. Vị ấy nằm xuống, không cố gắng... chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ biếng nhác thứ sáu.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, Tỷ-kheo bị bệnh nhẹ. Vị ấy suy nghĩ: “Nay bệnh nhẹ này khởi lên nơi ta, có lý do để nằm xuống, vậy ta hãy nằm xuống”. Vị ấy nằm xuống, không cố gắng... chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ biếng nhác thứ bảy.\nLại nữa, này các Tỷ-kheo, Tỷ-kheo đau bệnh mới khỏi, mới khỏi bệnh không bao lâu, vị ấy suy nghĩ: “Ta đau bệnh mới khỏi, mới khỏi bệnh không bao lâu, thân ta do bệnh bị yếu, không có thể chịu đựng, vậy ta hãy nằm xuống”. Vị ấy nằm xuống, không cố gắng... chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ biếng nhác thứ tám.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo có việc phải làm. Vị ấy nghĩ: “Có việc ta sẽ phải làm. Nếu ta làm việc, thời không dễ gì để ta tác ý đến lời dạy của các đức Phật. Vậy trước hết, ta bắt đầu tinh tấn, để đạt được những gì chưa đạt, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ”. Vị ấy bắt đầu tinh tấn để đạt được những gì chưa đạt, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ siêng năng thứ nhất.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo đã làm một công việc. Vị ấy suy nghĩ: “Ta đã làm một công việc. Do ta làm công việc, ta đã không có thể tác ý đến lời dạy của các đức Phật. Vậy trước hết, ta bắt đầu tinh tấn, để đạt được những gì chưa đạt, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ”. Vị ấy bắt đầu tinh tấn để đạt được... chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ siêng năng thứ hai.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo khi đi khất thực trong làng hay trong thị trấn, không nhận được các đồ ăn loại thô và loại tế đầy đủ như ý muốn. Vị ấy suy nghĩ: “Ta đi khất thực trong làng hay trong thị trấn, không nhận được các đồ ăn loại thô hay loại tế đầy đủ như ý muốn, thân ta (do vậy) được nhẹ nhàng, có thể chịu đựng. Vậy ta hãy bắt đầu tinh tấn... để chứng ngộ những gì chưa chứng ngộ”. Vị ấy bắt đầu tinh tấn để đạt được... chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ siêng năng thứ năm.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo khi đi khất thực trong làng hay trong thị trấn, nhận được các đồ ăn loại thô và loại tế đầy đủ như ý muốn. Vị ấy suy nghĩ: “Ta đi khất thực trong làng hay trong thị trấn, nhận được các đồ ăn loại thô hay loại tế đầy đủ như ý muốn. Thân ta có sức mạnh, có thể chịu đựng. Vậy ta hãy bắt đầu tinh tấn... để chứng ngộ những gì chưa chứng ngộ”. Vị ấy bắt đầu tinh tấn ... chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ siêng năng thứ sáu.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, Tỷ-kheo mới khỏi một bệnh nhẹ. Vị ấy suy nghĩ: “Bệnh nhẹ này khởi lên nơi ta. Sự kiện này có xảy ra: bệnh này có thể tăng trưởng nơi ta. Vậy trước hết, ta hãy bắt đầu tinh tấn... chưa chứng ngộ”. Này các Tỷ-kheo, đây là căn cứ siêng năng thứ bảy.\nLại nữa, này các Tỷ-kheo, Tỷ-kheo mới khỏi bệnh, được khỏi bệnh không bao lâu, vị ấy suy nghĩ: “Ta mới khỏi bệnh, được khỏi bệnh không bao lâu. Sự kiện này có xảy ra: bệnh này của ta có thể trở lại. Vậy trước hết, ta hãy bắt đầu tinh tấn để đạt được những gì chưa đạt, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ”. Vị ấy bắt đầu tinh tấn, để đạt được những gì chưa đạt, để chứng đắc những gì chưa chứng đắc, để chứng ngộ những gì chưa chứng ngộ. Này các Tỷ-kheo, đây là căn cứ siêng năng thứ tám.`, ref: "Tăng Chi Bộ 8.80", url: "https://loicuaducphat.org/an/an8.80.html#content" },

{ text: `- Khi chánh niệm tỉnh giác không có, này các Tỷ-kheo, với người không có chánh niệm tỉnh giác, tàm quý đi đến hủy diệt. Khi tàm quý không có, này các Tỷ-kheo, với người thiếu tàm quý, chế ngự các căn đi đến hủy diệt. Khi chế ngự các căn không có, với người thiếu chế ngự các căn, giới đi đến hủy diệt. Khi giới không có, với người thiếu giới, chánh định đi đến hủy diệt. Khi chánh định không có, với người không có chánh định, tri kiến như thật đi đến hủy diệt. Khi tri kiến như thật không có, với người thiếu tri kiến như thật, nhàm chán, ly tham đi đến hủy diệt. Khi nhàm chán, ly tham không có, với người thiếu nhàm chán, ly tham, giải thoát tri kiến đi đến hủy diệt. Ví như, này các Tỷ-kheo, một cây không có cành và lá, các mầm non của cây ấy không đi đến thành mãn, vỏ cây, giác cây, lõi cây không đi đến thành mãn. Cũng vậy, này các Tỷ-kheo, khi chánh niệm tỉnh giác không có, với người không có chánh niệm tỉnh giác tàm quý đi đến hủy diệt... giải thoát tri kiến đi đến hủy diệt.`, ref: "Tăng Chi Bộ 8.81", url: "https://loicuaducphat.org/an/an8.81.html#content" },

{ text: `Khi chánh niệm tỉnh giác có mặt, với người có chánh niệm tỉnh giác, tàm quý đi đến đầy đủ. Khi tàm quý có mặt, này các Tỷ-kheo, với người đầy đủ tàm quý, chế ngự các căn, đi đến đầy đủ. Khi chế ngự các căn có mặt, với người đầy đủ chế ngự các căn, giới đi đến đầy đủ. Khi giới có mặt, với người đầy đủ giới, chánh định đi đến đầy đủ. Khi chánh định có mặt, với người đầy đủ chánh định, tri kiến như thật đi đến đầy đủ. Khi tri kiến như thật có mặt, với người đầy đủ tri kiến như thật, thời nhàm chán, ly tham đi đến đầy đủ. Khi nhàm chán, ly tham có mặt, với người đầy đủ nhàm chán, ly tham, giải thoát tri kiến đi đến đầy đủ. Ví như, này các Tỷ-kheo, một cây có cành và lá, các mầm non và lõi cây đi đến thành mãn, vỏ cây, giác cây và lõi cây đi đến thành mãn. Cũng vậy, này các Tỷ-kheo, khi chánh niệm tỉnh giác có mặt, với người đầy đủ chánh niệm tỉnh giác... giải thoát tri kiến đi đến đầy đủ.`, ref: "Tăng Chi Bộ 8.81", url: "https://loicuaducphat.org/an/an8.81.html#content" },

{ text: `- Này các Tỷ-kheo, nếu các du sĩ ngoại đạo có hỏi như sau: “Thưa Hiền giả, tất cả pháp lấy gì làm căn bản? Tất cả pháp lấy gì làm sanh khởi? Tất cả pháp lấy gì làm tập khởi? Tất cả pháp lấy gì làm chỗ tụ hội? Tất cả pháp lấy gì làm thượng thủ? Tất cả pháp lấy gì làm tăng thượng? Tất cả pháp lấy gì làm tối thượng? Tất cả pháp lấy gì làm lõi cây?” Ðược hỏi vậy, này các Tỷ-kheo, các Thầy trả lời như sau: “Này chư Hiền, các pháp lấy dục làm căn bản. Tất cả pháp lấy tác ý làm sanh khởi. Tất cả pháp lấy xúc làm tập khởi. Tất cả pháp lấy thọ làm chỗ tụ hội. Tất cả pháp lấy định làm thượng thủ. Tất cả pháp lấy niệm làm tăng thượng. Tất cả pháp lấy tuệ làm tối thượng. Tất cả pháp lấy giải thoát làm lõi cây”. Ðược hỏi như vậy, này các Tỷ-kheo, các Thầy hãy trả lời cho các du sĩ ngoại đạo ấy như vậy.`, ref: "Tăng Chi Bộ 8.83", url: "https://loicuaducphat.org/an/an8.83.html#content" },

{ text: `Ở đây, này Nàgita, khi Ta thấy các Tỷ-kheo sau khi ăn cho đến thỏa mãn, cho đến bụng có thể chứa được, rồi sống chú tâm vào lạc nằm xuống, lạc về xúc, lạc về ngủ, khi ấy, này Nàgita, Ta suy nghĩ như sau: “Thật sự, các Tôn giả này tìm được có khó khăn, tìm được có mệt nhọc, tìm được có phí sức an ổn lạc, viễn ly lạc, an tịnh lạc, chánh giác lạc; còn Ta thời chứng được không khó khăn, chứng được không mệt nhọc, chứng được không phí sức an ổn lạc, viễn ly lạc, an tịnh lạc, chánh giác lạc; vì rằng các Tôn giả này, sau khi ăn cho đến thỏa mãn, cho đến bụng có thể chứa được, rồi sống chú tâm vào lạc nằm xuống, lạc về xúc, lạc về ngủ”.`, ref: "Tăng Chi Bộ 8.86", url: "https://loicuaducphat.org/an/an8.86.html#content" },

{ text: `Ở đây, này Nàgita, khi ta thấy Tỷ-kheo trú ở cuối làng, đang ngồi Thiền định. Này Nàgita, rồi Ta suy nghĩ: “Nay người giữ khu vườn sẽ đến quấy rầy, hay một Sa-di sẽ làm vị ấy từ bỏ Thiền định”. Do vậy, này Nàgita, Ta không hoan hỷ Tỷ-kheo ấy trú ở cuối làng.\nỞ đây, này Nàgita, Ta thấy một Tỷ-kheo trú ở rừng đang ngồi ngủ gục ở trong rừng. Này Nàgita, Ta suy nghĩ như sau: “Nay Tôn giả này khi đoạn trừ được buồn ngủ và mỏi mệt, sẽ tác ý đến tưởng về rừng và sống nhất tâm”. Do vậy, này Nàgita, Ta hoan hỷ với Tỷ-kheo ấy sống ở trong rừng.`, ref: "Tăng Chi Bộ 8.86", url: "https://loicuaducphat.org/an/an8.86.html#content" },

{ text: `Ở đây, này Nàgita. Ta thấy Tỷ-kheo sống ở rừng đang ngồi không Thiền định ở trong rừng. Này Nàgita, Ta suy nghĩ như sau: “Nay, vị Tôn giả này sẽ định tĩnh tâm chưa được Thiền định, và sẽ bảo vệ tâm đã được Thiền định”. Do vậy, này Nàgita, Ta hoan hỷ với Tỷ-kheo ấy sống ở trong rừng.\nỞ đây, này Nàgita, Ta thấy Tỷ-kheo ngồi Thiền định ở trong rừng. Này Nàgita, Ta suy nghĩ như sau: “Nay Tôn giả này sẽ giải thoát tâm chưa được giải thoát hay sẽ bảo vệ tâm đã được giải thoát”. Do vậy, này Nàgita, Ta hoan hỷ với Tỷ-kheo sống ở trong rừng.`, ref: "Tăng Chi Bộ 8.86", url: "https://loicuaducphat.org/an/an8.86.html#content" },

{ text: `Lại nữa, này chư Hiền, Tỷ-kheo có giới, sống được bảo vệ với sự bảo vệ của giới bổn Pàtimokkha, đầy đủ uy nghi chánh hạnh, thấy sợ hãi trong các lỗi nhỏ nhặt, chấp nhận và học tập trong các học pháp. Này chư Hiền, đây là sở y thứ hai để tu tập các pháp chánh giác phần.`, ref: "Tăng Chi Bộ 9.1", url: "https://loicuaducphat.org/an/an9.1.html#content" },

{ text: `Lại nữa, này chư Hiền, Tỷ-kheo có định, câu chuyện này có khả năng đoạn giảm hướng thượng đưa đến tâm được rộng mở như luận về ít dục, luận về biết đủ, luận về viễn ly, luận về không tụ hội, luận về tinh tấn tinh cần, luận về giới, luận về định, luận về tuệ, luận về giải thoát, luận về giải thoát tri kiến, những câu chuyện như vậy, có được không khó khăn, có được không mệt nhọc, có được không phí sức. Này chư Hiền, đây là sở y thứ ba để tu tập các pháp chánh giác phần.`, ref: "Tăng Chi Bộ 9.1", url: "https://loicuaducphat.org/an/an9.1.html#content" },

{ text: `Lại nữa, này các Tỷ-kheo, Tỷ-kheo sống tinh cần tinh tấn để đoạn tận các pháp bất thiện, để thành tựu các pháp thiện, nỗ lực, kiên trì, không từ bỏ gánh nặng trong các thiện pháp. Này chư Hiền, đây là sở y thứ tư để tu tập các pháp chánh giác phần.`, ref: "Tăng Chi Bộ 9.1", url: "https://loicuaducphat.org/an/an9.1.html#content" },

{ text: `Này các Tỷ-kheo, với Tỷ-kheo làm bạn với thiện, thân hữu với thiện, giao thiệp với thiện, thời được chờ đợi như sau: sẽ giữ giới, sẽ sống được bảo vệ với sự bảo vệ của giới bổn Pàtimokkha, đầy đủ uy nghi chánh hạnh, thấy sợ hãi trong các lỗi nhỏ nhặt, chấp nhận và học tập trong các học pháp.`, ref: "Tăng Chi Bộ 9.1", url: "https://loicuaducphat.org/an/an9.1.html#content" },

{ text: `Và này các Tỷ-kheo, khi Tỷ-kheo ấy đã trú trong năm pháp này, bốn pháp nữa cần phải tu tập. Cần phải tu tập tưởng bất tịnh để đoạn tận tham ái, cần phải tu tập từ tâm để đoạn tận sân, cần phải tu tập niệm hơi thở vô, hơi thở ra để cắt đứt tầm, cần phải tu tập tưởng vô thường để phá hoại ngã mạn. Này các Tỷ-kheo, với Tỷ-kheo có tưởng vô thường, tưởng vô ngã được an trú; với Tỷ-kheo có tưởng vô ngã, ngã mạn bị phá hoại, ngay trong hiện tại, đạt được Niết-bàn.`, ref: "Tăng Chi Bộ 9.1", url: "https://loicuaducphat.org/an/an9.1.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là tuệ lực? Những pháp nào bất thiện được xem là bất thiện; những pháp nào thiện được xem là thiện; những pháp nào có tội được xem là có tội; những pháp nào vô tội được xem là vô tội, những pháp nào đen được xem là đen; những pháp nào trắng được xem là trắng; những pháp nào không nên thực hiện được xem là không nên thực hiện; những pháp nào nên thực hiện được xem là nên thực hiện; những pháp nào không xứng đáng bậc Thánh được xem là không xứng đáng bậc Thánh; những pháp nào xứng đáng bậc Thánh được xem là xứng đáng bậc Thánh. Những pháp ấy cần phải được khéo quán sát, khéo thẩm sát với trí tuệ. Này các Tỷ-kheo, đây gọi là tuệ lực.`, ref: "Tăng Chi Bộ 9.5", url: "https://loicuaducphat.org/an/an9.5.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là tấn lực? Những pháp nào bất thiện được xem là bất thiện; những pháp nào có tội được xem là có tội; những pháp nào đen được xem là đen; những pháp nào không nên thực hiện được xem là không nên thực hiện; những pháp nào không xứng đáng bậc Thánh được xem là không xứng đáng bậc Thánh. Ðối với các pháp ấy, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm để đoạn tận. Những pháp nào thiện được xem là thiện; những pháp nào vô tội được xem là vô tội, những pháp nào trắng được xem là trắng; những pháp nào nên thực hiện được xem là nên thực hiện; những pháp nào xứng đáng bậc Thánh được xem là xứng đáng bậc Thánh. Ðối với các pháp ấy, khởi lên ý muốn, cố gắng, tinh tấn, sách tâm, trì tâm để chứng được. Này các Tỷ-kheo, đây gọi là tấn lực.`, ref: "Tăng Chi Bộ 9.5", url: "https://loicuaducphat.org/an/an9.5.html#content" },

{ text: `“Này Sutavà, Tỷ-kheo nào là bậc A-la-hán, đã tận các lậu hoặc, đã thành tựu viên mãn, việc nên làm đã làm, đã đặt gánh nặng xuống, mục đích đã đạt được, hữu kiết sử đã đoạn tận, chơn chánh giải thoát; vị ấy không có thể làm năm sự: Tỷ-kheo đã đoạn tận các lậu hoặc không có thể có ý đoạt mạng sống của loài hữu tình; Tỷ-kheo đã đoạn tận các lậu hoặc không có thể lấy của không cho được gọi là ăn trộm; Tỷ-kheo đã đoạn tận các lậu hoặc không có thể hành dâm dục; Tỷ-kheo đã đoạn tận các lậu hoặc không có thể biết mà nói láo; Tỷ-kheo đã đoạn tận các lậu hoặc không có thể hưởng thọ các dục do các đồ cất chứa đem lại, như trước còn làm gia chủ”.`, ref: "Tăng Chi Bộ 9.7", url: "https://loicuaducphat.org/an/an9.7.html#content" },

{ text: `Ví như, bạch Thế Tôn, trên đất, người ta quăng đồ tịnh, quăng đồ bất tịnh, quăng phẩn uế, quăng nước tiểu, nhổ nước miếng, quăng mủ và quăng máu; tuy vậy đất không lo âu, không xấu hổ, hay không nhàm chán. Cũng vậy, bạch Thế Tôn, con an trú với tâm như đất, rộng rãi, rộng lớn, vô lượng, không hận, không sân. Bạch Thế Tôn, với ai không an trú thân niệm, người ấy ở đây, sau khi xâm phạm một vị đồng Phạm hạnh, có thể bỏ đi du hành, không có xin lỗi.`, ref: "Tăng Chi Bộ 9.11", url: "https://loicuaducphat.org/an/an9.11.html#content" },

{ text: `Ví như, bạch Thế Tôn, có người mang một cái bát đầy mỡ, có thủng nhiều lỗ, thủng nhiều đường, bị chảy, bị rỉ. Cũng vậy, bạch Thế Tôn, con mang cái thân này, có thủng nhiều lỗ, có thủng nhiều đường, bị chảy, bị rỉ. Bạch Thế Tôn, với ai không an trú thân niệm, người ấy ở đây, sau khi xâm phạm một vị đồng Phạm hạnh, có thể bỏ đi du hành, không có xin lỗi.`, ref: "Tăng Chi Bộ 9.11", url: "https://loicuaducphat.org/an/an9.11.html#content" },

{ text: `Ung nhọt, này các Tỷ-kheo, là đồng nghĩa với thân này do bốn đại tác thành, do cha mẹ sinh ra, do cơm cháo chất chứa nuôi dưỡng, vô thường, biến hoại, tan nát, hủy hoại, hoại diệt, có chín miệng vết thương, có chín miệng nứt rạn. Từ đấy có cái gì chảy ra, chắc chắn bất tịnh rỉ chảy, chắc chắn hôi thúi rỉ chảy, chắc chắn nhàm chán rỉ chảy; có cái gì nứt chảy, chắc chắn bất tịnh nứt chảy, chắc chắn hôi thúi nứt chảy, chắc chắn nhàm chán nứt chảy. Do vậy, này các Tỷ-kheo, các Thầy hãy nhàm chán thân này.`, ref: "Tăng Chi Bộ 9.15", url: "https://loicuaducphat.org/an/an9.15.html#content" },

{ text: `- Này các Tỷ-kheo, có chín tưởng này được tu tập, được làm cho sung mãn, có quả lớn, có lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh. Thế nào là chín? Tưởng bất tịnh, tưởng chết, tưởng ghê tởm đối với các món ăn, tưởng không ưa thích đối với tất cả thế giới, tưởng vô thường, tưởng khổ trên vô thường, tưởng vô ngã trên khổ, tưởng đoạn tận, tưởng ly tham. Này các Tỷ-kheo, chín tưởng này được tu tập, được làm sung mãn, có quả lớn, có lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh.`, ref: "Tăng Chi Bộ 9.16", url: "https://loicuaducphat.org/an/an9.16.html#content" },

{ text: `Này các Tỷ-kheo, gia đình nào thành tựu chín chi phần, nếu chưa đến thời nên đến, nếu đã đến thời nên ngồi xuống. Thế nào là chín? Họ vui vẻ đứng dậy; họ vui vẻ đảnh lễ; họ vui vẻ mời ngồi; nếu có, họ không giấu đi; có nhiều, họ cho nhiều, có đồ tốt, họ cho đồ tốt; họ cho cẩn thận; họ cho một cách chu đáo; họ ngồi xung quanh để nghe pháp, họ thưởng thức lời nói. Này các Tỷ-kheo, gia đình nào thành tựu chín chi phần này, nếu chưa đến thời nên đến, nếu đã đến thời nên ngồi xuống.`, ref: "Tăng Chi Bộ 9.17", url: "https://loicuaducphat.org/an/an9.17.html#content" },

{ text: `- Này các Tỷ-kheo, gia đình nào thành tựu chín chi phần, nếu chưa đến thời không nên đến, nếu đã đến thời không nên ngồi xuống. Thế nào là chín? Không vui vẻ đứng dậy; không vui vẻ đảnh lễ; không vui vẻ mời ngồi; nếu có, họ giấu đi; có nhiều, họ cho ít, có đồ tốt, họ cho đồ xấu; họ cho không cẩn thận; họ cho không có chu đáo; họ không có ngồi xung quanh để nghe pháp, không thưởng thức lời nói. Này các Tỷ-kheo, gia đình nào thành tựu chín chi phần này, nếu chưa đến thời không nên đến, nếu đã đến thời không nên ngồi xuống.`, ref: "Tăng Chi Bộ 9.17", url: "https://loicuaducphat.org/an/an9.17.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Thánh đệ tử suy nghĩ như sau: “Cho đến trọn đời, các vị A-la-hán đoạn tận sát sanh, từ bỏ sát sanh, bỏ trượng, bỏ kiếm, biết tàm quý, có lòng từ, sống thương xót đến hạnh phúc tất cả chúng sanh và loài hữu tình. Hôm nay, đêm này và ngày này, ta cũng đoạn tận sát sanh, từ bỏ sát sanh, bỏ trượng, bỏ kiếm, biết tàm quý, có lòng từ, sống thương xót đến hạnh phúc tất cả chúng sanh là loài hữu tình. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành ngày trai giới”. Ðây là chi phần thứ nhất được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `“Cho đến trọn đời, các vị A-la-hán đoạn tận lấy của không cho, từ bỏ lấy của không cho, chỉ lấy những vật đã cho, chỉ mong những vật đã cho, tự sống thanh tịnh, không có trộm cướp. Hôm nay, đêm này và ngày này, ta cũng đoạn tận lấy của không cho, từ bỏ lấy của không cho, chỉ lấy những vật đã cho, chỉ mong những vật đã cho, tự sống thanh tịnh, không có trộm cướp. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành trai giới”. Ðây là chi phần thứ hai được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `“Cho đến trọn đời, các vị A-la-hán đoạn tận phi Phạm hạnh, hành Phạm hạnh, sống xa lìa, từ bỏ dâm dục hèn hạ. Hôm nay, đêm này và ngày này, ta cũng đoạn phi Phạm hạnh, hành Phạm hạnh, sống xa lìa, từ bỏ dâm dục hèn hạ. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành ngày trai giới”. Ðây là chi phần thứ ba được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `“Cho đến trọn đời, các vị A-la-hán đoạn tận nói láo, tránh xa nói láo, nói những lời chân thật, y chỉ nơi sự thật, chắc chắn, đáng tin cậy, không lừa gạt, không phản lại lời hứa đối với đời. Hôm nay, đêm này và ngày này, ta cũng đoạn tận nói láo, tránh xa nói láo, nói những lời chân thật, y chỉ nơi sự thật, chắc chắn, đáng tin cậy, không lừa gạt, không phản lại lời hứa đối với đời. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành trai giới”. Ðây là chi phần thứ tư được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `“Cho đến trọn đời, các vị A-la-hán đoạn tận đắm say rượu men, rượu nấu. Hôm nay, đêm này và ngày này ta cũng đoạn tận đắm say rượu men, rượu nấu. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành ngày trai giới”. Ðây là chi phần thứ năm được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `“Cho đến trọn đời, các vị A-la-hán mỗi ngày dùng một bữa, không ăn ban đêm, không ăn phi thời. Hôm nay, đêm này và ngày này, ta cũng dùng mỗi ngày dùng một bữa, không ăn ban đêm, không ăn phi thời. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành ngày trai giới”. Ðây là chi phần thứ sáu được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `“Cho đến trọn đời, các vị A-la-hán từ bỏ xem múa, hát, nhạc, diễn kịch, không trang sức bằng vòng hoa, hương liệu, dầu thoa và các thời trang. Hôm nay, đêm này và ngày này, ta cũng từ bỏ xem múa, hát, nhạc, diễn kịch, không trang sức bằng vòng hoa, hương liệu, dầu thoa và các thời trang. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành ngày trai giới”. Ðây là chi phần thứ bảy được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `“Cho đến trọn đời, các vị A-la-hán đoạn tận giường cao, giường lớn, từ bỏ giường cao, giường lớn, các vị ấy nằm trên giường thấp, trên giường nhỏ, trên thảm cỏ. Hôm nay, đêm này và ngày này, ta cũng đoạn tận giường cao, giường lớn, từ bỏ giường cao, giường lớn, ta nằm trên giường thấp, trên giường nhỏ, trên thảm cỏ. Với chi phần này, ta theo gương vị A-la-hán, sẽ thực hành ngày trai giới”. Ðây là chi phần thứ tám được thành tựu.`, ref: "Tăng Chi Bộ 9.18", url: "https://loicuaducphat.org/an/an9.18.html#content" },

{ text: `- Này Gia chủ, dầu bố thí các món thô hay tế, nếu bố thí không cẩn thận, bố thí không có chú tâm, bố thí không tự tay mình, bố thí những vật quăng đi, bố thí không có nghĩ đến tương lai; chỗ nào, chỗ nào, sự bố thí ấy sanh quả dị thục, thời tâm không thiên về thưởng thức các món ăn thù diệu, tâm không thiên về thưởng thức y áo thù diệu, tâm không thiên về thưởng thức các cỗ xe thù diệu, tâm không thiên về thưởng thức năm dục công đức thù diệu. Và các người con, hay vợ, hay những người phục vụ, hay những người đưa tin, hay những người làm công, họ không có khéo nghe, họ không có lóng tai, họ không có an trú tâm hiểu biết. Vì sao? Này Gia chủ, như vậy là quả dị thục của các nghiệp làm không có cẩn thận.`, ref: "Tăng Chi Bộ 9.20", url: "https://loicuaducphat.org/an/an9.20.html#content" },

{ text: `Này Gia chủ, dầu có bố thí các món thô hay tế, nếu bố thí có cẩn thận, bố thí có chú tâm, bố thí tự tay mình, bố thí những vật không quăng bỏ đi, bố thí có nghĩ đến tương lai; chỗ nào, chỗ nào, sự bố thí ấy sanh quả dị thục, thời tâm thiên về thưởng thức các món ăn thù diệu, tâm thiên về thưởng thức y áo thù diệu, tâm thiên về thưởng thức các cỗ xe thù diệu, tâm thiên về thưởng thức năm dục công đức thù diệu. Và các người con, hay vợ, hay những người phục vụ, hay những người đưa tin, hay những người làm công, họ có khéo nghe, họ có lóng tai, họ có an trú tâm hiểu biết. Vì sao? Này Gia chủ, như vậy là quả dị thục của việc làm có cẩn thận.`, ref: "Tăng Chi Bộ 9.20", url: "https://loicuaducphat.org/an/an9.20.html#content" },
{ text: `- Này các Tỷ-kheo, Ta sẽ thuyết về chín pháp lấy ái làm cội gốc. Hãy nghe và khéo tác ý, Ta sẽ giảng. Và này các Tỷ-kheo, thế nào là chín pháp lấy ái làm cội gốc? Do duyên ái nên cầu tìm; do duyên cầu tìm nên có được; do duyên có được nên có quyết định; do duyên quyết định nên có dục tham; do duyên dục tham nên đắm trước; do duyên đắm trước nên có chấp trước; do duyên chấp trước nên có xan tham; do duyên xan tham nên có thủ hộ, chấp trượng, chấp kiếm, đấu tranh, tránh tranh, kháng tranh, ly gián ngữ, vọng ngữ, rất nhiều các ác, bất thiện pháp khởi lên. Này các Tỷ-kheo, đây là chín pháp lấy ái làm cội gốc.`, ref: "Tăng Chi Bộ 9.23", url: "https://loicuaducphat.org/an/an9.23.html#content" },

{ text: `- Này các Tỷ-kheo, khi nào tâm Tỷ-kheo được khéo tích tập với trí tuệ, thời thật hợp lý cho Tỷ-kheo ấy nói như sau: “Ta rõ biết: “Sanh đã tận, Phạm hạnh đã thành, những việc nên làm đã làm, không còn trở lui trạng thái này nữa”. Và này các Tỷ-kheo, thế nào là tâm Tỷ-kheo được khéo tích tập?\n“Ly tham là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ. “Ly sân là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ. “Ly si là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ. “Tánh không có tham là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ. “Tánh sân là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ. “Tánh không có si là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ. “Tánh không chuyển hướng về dục hữu là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ. “Tánh không chuyển hướng về sắc hữu là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ. “Tánh không chuyển hướng về vô sắc hữu là tâm của ta”, như vậy tâm vị ấy được khéo tích tập với trí tuệ.`, ref: "Tăng Chi Bộ 9.25", url: "https://loicuaducphat.org/an/an9.25.html#content" },

{ text: `- Này các Tỷ-kheo, có chín xung đột sự. Thế nào là chín? “Vị ấy đã làm hại tôi”, xung đột khởi lên. “Vị ấy đang làm hại tôi”, xung đột khởi lên. “Vị ấy sẽ làm hại tôi”, xung đột khởi lên. “Vị ấy đã làm hại người tôi thương, tôi mến”... “Vị ấy đang làm hại người tôi thương, tôi mến”... “Vị ấy sẽ làm hại người tôi thương, tôi mến”, xung đột khởi lên. “Vị ấy đã làm lợi cho người tôi không thương, không mến”... “Vị ấy đang làm lợi...” Vị ấy sẽ làm lợi cho người tôi không thương, không mến”, xung đột khởi lên. Này các Tỷ-kheo, đây là chín xung đột sự.`, ref: "Tăng Chi Bộ 9.29", url: "https://loicuaducphat.org/an/an9.29.html#content" },

{ text: `- Này các Tỷ-kheo, có chín điều phục xung đột sự. Thế nào là chín? “Vị ấy đã làm hại tôi; có ích lợi gì mà nghĩ như vậy”, nhờ vậy xung đột được điều phục. “Vị ấy sẽ làm hại tôi; có ích lợi gì mà nghĩ như vậy”, nhờ vậy xung đột được điều phục. “Vị ấy đã làm hại người tôi thương mến; có ích lợi gì mà nghĩ như vậy”, nhờ vậy xung đột được điều phục. “Vị ấy đã làm hại... vị ấy làm hại người tôi thương tôi mến; có ích lợi gì mà nghĩ như vậy”, nhờ vậy xung đột được điều phục. “Vị ấy đã làm lợi cho người tôi không thương, không mến”... “Vị ấy đang làm lợi... vị ấy sẽ làm lợi cho người tôi không thương, không mến, có lợi ích gì mà nghĩ như vậy”, nhờ vậy xung đột được điều phục Này các Tỷ-kheo, đây là chín xung đột sự được điều phục.`, ref: "Tăng Chi Bộ 9.30", url: "https://loicuaducphat.org/an/an9.30.html#content" },

{ text: `Này Ananda, trước khi Ta giác ngộ, chưa chứng được Chánh Ðẳng Giác, còn là Bồ-tát, Ta suy nghĩ như sau: “Lành thay, sự xuất ly! Lành thay, sống viễn ly”. Nhưng tâm của Ta không có hứng khởi trong sự xuất ly ấy, không có tịnh tín, không có an trú, không có giải thoát, dầu Ta có thấy “Ðây là an tịnh”. Này Ananda, về vấn đề ấy, Ta suy nghĩ như sau: “Do nhân gì, do duyên gì, tâm Ta không hứng khởi trong sự xuất ly ấy, không có tịnh tín, không có an trú, không có giải thoát, dầu Ta có thấy: “Ðây là an tịnh?” Rồi này Ananda, Ta suy nghĩ như sau: “Vì Ta không thấy nguy hiểm trong các dục, vì Ta không làm cho sung mãn sự nguy hiểm ấy, lợi ích của xuất ly chưa được chứng đắc, Ta chưa được thưởng thức lợi ích ấy. Do vậy tâm Ta không hứng khởi trong xuất ly ấy, không tịnh tín, không an trú, không giải thoát”. Này Ananda, về vấn đề ấy, Ta suy nghĩ như sau: “Nếu sau khi thấy nguy hiểm trong các dục, Ta làm cho sung mãn sự nguy hiểm ấy. Sau khi chứng được lợi ích trong sự xuất ly, Ta thưởng thức lợi ích ấy”, thời sự kiện này xảy ra: Tâm của Ta có thể hứng khởi trong xuất ly, tịnh tín, an trú, giải thoát, vì Ta có thấy: “Ðây là an tịnh”.`, ref: "Tăng Chi Bộ 9.41", url: "https://loicuaducphat.org/an/an9.41.html#content" },

{ text: `“Bậc thiện trí tìm được,\nGiải thoát trong triền phược,\nVị giác tỉnh với Thiền,\nBậc giác giả Mâu-ni,\nBậc từ bỏ, không chấp\nBậc anh hùng ẩn sĩ.”`, ref: "Tăng Chi Bộ 9.42", url: "https://loicuaducphat.org/an/an9.42.html#content" },

{ text: `- Này các Tỷ-Kheo, có năm pháp làm suy yếu học tập này. Thế nào là năm? Sát sanh, lấy của không cho, tà hạnh trong các dục, nói láo, đắm say rượu men, rượu nấu. Này các Tỷ-kheo, đây là năm pháp làm suy yếu học tập. Này các Tỷ-kheo, để đoạn tận năm pháp làm suy yếu học tập này, Bốn niệm xứ cần phải tu tập. Thế nào là bốn? Ở đây, này các Tỷ-kheo, Tỷ-kheo trú tùy quán thân trên thân, nhiệt tâm tỉnh giác, chánh niệm, để nhiếp phục tham ưu ở đời. Vị ấy trú tùy quán thọ trên các cảm thọ.... trú tùy quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm để nhiếp phục tham ưu ở đời. Này các Tỷ-kheo, để đoạn tận năm pháp làm suy yếu học tập này, Bốn niệm xứ cần phải tu tập.`, ref: "Tăng Chi Bộ 9.63", url: "https://loicuaducphat.org/an/an9.63.html#content" },

{ text: `- Này các Tỷ-kheo, có năm triền cái này. Thế nào là năm? Dục tham triền cái, sân triền cái, hôn trầm thụy miên triền cái, trạo hối triền cái, nghi triền cái. Này các Tỷ-kheo, có năm triền cái này. Này các Tỷ-kheo, để đoạn tận năm triền cái này, Bốn niệm xứ cần phải tu tập. Thế nào là bốn? Ở đây, này các Tỷ-kheo, Tỷ-kheo trú quán thân trên thân... trú quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm để nhiếp phục tham ưu ở đời. Này các Tỷ-kheo, để đoạn tận năm triền cái, Bốn niệm xứ cần phải tu tập.`, ref: "Tăng Chi Bộ 9.64", url: "https://loicuaducphat.org/an/an9.64.html#content" },

{ text: `- Có năm tâm hoang vu này. Thế nào là năm? Này các Tỷ-kheo, ở đây vị Tỷ-kheo nghi ngờ, do dự, không quyết đoán, không có tịnh tín đối với bậc Ðạo Sư. Này các Tỷ-kheo, Tỷ-kheo nào nghi ngờ, do dự, không quyết đoán, không có tịnh tín đối với bậc Ðạo Sư, Tỷ-kheo ấy không hướng về nỗ lực, hăng hái, kiên trì và tinh tấn. Khi tâm của vị ấy không hướng về nỗ lực, hăng hái, kiên trì và tinh tấn, như vậy gọi là tâm hoang vu thứ nhất. Này các Tỷ-kheo, lại nữa, vị Tỷ-kheo nghi ngờ đối với Pháp.... (như trên...) đối với Tăng... (như trên..) đối với Học pháp... tức giận đối với các vị đồng Phạm hạnh, không hoan hỷ, tâm dao động, trở thành hoang vu. Này các Tỷ-kheo, khi một vị Tỷ-kheo phẫn nộ đối với vị đồng Phạm hạnh, không hoan hỷ, tâm dao động, trở thành hoang vu, Tỷ-kheo ấy không hướng về nỗ lực, hăng hái, kiên trì và tinh thần. Như vậy gọi là tân hoang vu thứ năm. Này các Tỷ-kheo, để đoạn tận năm tâm hoang vu này... Bốn niệm xứ cần phải tu tập.`, ref: "Tăng Chi Bộ 9.71", url: "https://loicuaducphat.org/an/an9.71.html#content" },

{ text: `- Này các Tỷ-kheo có năm hạ phần kiết sử này. Thế nào là năm? Thân kiến, nghi, giới cấm thủ, dục tham, sân. Này các Tỷ-kheo, có năm hạ phần kiết sử này. Này các Tỷ-kheo, để đoạn tận tâm hạ phần kiết sử này, Bốn niệm xứ cần phải tu tập. Thế nào là bốn? ... Bốn niệm xứ này cần phải tu tập.`, ref: "Tăng Chi Bộ 9.67", url: "https://loicuaducphat.org/an/an9.67.html#content" },

{ text: `- Này các Tỷ-kheo, có năm dục trưởng dưỡng này. Thế nào là năm? Các sắc do mắt nhận thức, khả lạc, khả hỷ, khả ý, khả ái, liên hệ đến dục, hấp dẫn, các tiếng do tai nhận thức khả lạc... hấp dẫn. Này các Tỷ-kheo, có năm dục trưởng dưỡng này. Này các Tỷ-kheo, để đoạn tận năm dục trưởng dưỡng này, Bốn niệm xứ này phải tu tập.`, ref: "Tăng Chi Bộ 9.65", url: "https://loicuaducphat.org/an/an9.65.html#content" },

{ text: `- Này các Tỷ-kheo có năm thủ uẩn này. Thế nào là năm? Sắc thủ uẩn, thọ thủ uẩn, tưởng thủ uẩn, hành thủ uẩn, thức thủ uẩn. Này các Tỷ-kheo, có năm thủ uẩn này. Này các Tỷ-kheo, để đoạn tận năm thù uẩn này, Bốn niệm xứ cần phải tu tập. Thế nào là bốn? .... Bốn niệm xứ cần phải tu tập.`, ref: "Tăng Chi Bộ 9.66", url: "https://loicuaducphat.org/an/an9.66.html#content" },

{ text: `- Này các Tỷ-kheo, có năm xan tham này. Thế nào là năm? Xan tham trú xứ, xan tham gia đình, xan tham lợi dưỡng, xan tham dung sắc, xan tham pháp. Này các Tỷ-kheo, để đoạn tận năm xan tham này, Bốn niệm xứ cần phải tu tập. Thế nào là bốn? ... Bốn niệm xứ này cần phải tu tập.`, ref: "Tăng Chi Bộ 9.69", url: "https://loicuaducphat.org/an/an9.69.html#content" },

{ text: `- Này các Tỷ-kheo, có năm triền phược này. Thế nào là năm? Ở đây, này các Tỷ-kheo, Tỷ-kheo tâm không ly tham, không ly dục, không ly ái, không ly khao khát, không ly nhiệt tình, không ly ái nhiễm đối với các dục. Này các Tỷ-kheo, Tỷ-kheo tâm không ly tham, không ly dục, không ly ái, không ly khao khát, không ly nhiệt tình, không ly ái nhiễm đối với các dục, tâm của vị ấy không hướng về nỗ lực, hăng hái, kiên trì và tinh tấn. Tâm của vị nào không hướng về … (như trên) … như vậy là tâm triền phược thứ nhất. Này các Tỷ-kheo, lại nữa, Tỷ-kheo tâm không ly tham đối với thân... không ly tham đối với sắc... ăn quá sức bao tử có thể chịu nổi, hưởng thọ sung sướng về giường nằm, sung sướng về thụy miên... Này các Tỷ-kheo, lại nữa, Tỷ-kheo sống đời sống Phạm hạnh với hy vọng mong được thành một loại chư Thiên, “Với giới này, với luật này, với khổ hạnh này, hay với Phạm hạnh này, ta sẽ trở thành loại chư Thiên này hay loại chư Thiên khác”. Này các Tỷ-kheo, khi Tỷ-kheo sống đời sống Phạm hạnh với hy vọng được thành một loại chư Thiên, “Với giới này, với luật này, với khổ hạnh này hay với Phạm hạnh này, ta sẽ trở thành loại chư Thiên này hay loại chư Thiên khác”, tâm vị này không hướng về nỗ lực, hăng hái, kiên trì và tinh tấn. Tâm vị nào... như vậy là tâm triền phược thứ năm. Này các Tỷ-kheo, đây là năm tâm triền phược, muốn đoạn tận năm tâm triền phược này, Bốn niệm xứ này cần phải tu tập.`, ref: "Tăng Chi Bộ 9.72", url: "https://loicuaducphat.org/an/an9.72.html#content" },

{ text: `Này Ananda, các thiện giới có ý nghĩa không hối tiếc, có lợi ích không hối tiếc, không hối tiếc có ý nghĩa hân hoan, có lợi ích hân hoan. Hân hoan có ý nghĩa hoan hỷ, có lợi ích khinh an. Khinh an có ý nghĩa an lạc, có lợi ích an lạc. An lạc có ý nghĩa định, có lợi ích định. Ðịnh có ý nghĩa như thật tri kiến, có lợi ích như thật tri kiến. Như thật tri kiến có ý nghĩa nhàm chán, ly tham, có lợi ích nhàm chán, ly tham. Nhàm chán ly tham có ý nghĩa giải thoát tri kiến, có lợi ích giải thoát tri kiến. Như vậy, này Ananda, các thiện giới thứ lớp dẫn tới tối thượng. Như vậy, này Ananda, các thiện giới thứ lớp đưa đến tối thượng.`, ref: "Tăng Chi Bộ 10.1", url: "https://loicuaducphat.org/an/an10.1.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, nhàm chán lý tham có ý nghĩa giải thoát tri kiến, có lợi ích giải thoát tri kiến; như thật tri kiến có ý nghĩa nhàm chán, ly tham, có lợi ích nhàm chán, ly tham; định có ý nghĩa như thật tri kiến, có lợi như thật tri kiến; an lạc có ý nghĩa định, có lợi ích định; khinh an có ý nghĩa an lạc, có lợi ích an lạc; hỷ có ý nghĩa khinh an, có lợi ích khinh an; hân hoan có ý nghĩa hỷ, có lợi ích hỷ; không nuối tiếc có ý nghĩa hân hoan, có lợi ích hân hoan, các Thiện giới có ý nghĩa không nuối tiếc, có lợi ích không hối tiếc. Như vậy, này các Tỷ-kheo, các pháp khiến cho các pháp (khác) tăng thịnh; các pháp khiến các pháp khác viên mãn, đưa từ bờ bên này qua bờ bên kia.`, ref: "Tăng Chi Bộ 10.2", url: "https://loicuaducphat.org/an/an10.2.html#content" },

{ text: `Như vậy, này các Tỷ-kheo, Tỷ-kheo thành tựu năm chi phần. Này các Tỷ-kheo, như thế nào là trú xứ thành tựu năm chi phần? Ở đây, này các Tỷ-kheo, trú xứ không quá xa, không quá gần, thuận tiện cho đi và đến, ban ngày không đông đủ, ban đêm không ồn ào, không huyên náo, ít xúc chạm với ruồi, muỗi, gió, sức nóng mặt trời, và các loại rắn rít. Trú tại trú xứ ấy, tìm được không mệt nhọc các vật dụng như y áo, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh. Tại trú xứ ấy, các trưởng lão Tỷ-kheo đến ở là những bậc nghe nhiều, được trao truyền kinh điển, những bậc trì Pháp, trì Luật, trì toát yếu, thường thường đến các vị ấy tìm hiểu, hỏi han: “Thưa Tôn giả, cái này là thế nào? Ý nghĩa cái này là gì? “ Các Tôn giả ấy mở rộng những gì chưa mở rộng, trình bày những gì chưa trình bày, đối với những vấn đề còn khởi lên những nghi vấn, vị ấy giải tỏa các nghi vấn ấy. Này các Tỷ-kheo, trú xứ như vậy thành tựu năm chi phần.`, ref: "Tăng Chi Bộ 10.11", url: "https://loicuaducphat.org/an/an10.11.html#content" },

{ text: `Không dục tham, không sân,\nKhông hôn trầm thụy miên\nKhông trạo cử, không nghi,\nTỷ-kheo hoàn toàn không\nVới vô học giới uẩn,\nVới vô học định uẩn,\nÐầy đủ với giải thoát,\nVới tri kiến như vậy.\nVị Tỷ-kheo như vậy,\nÐầy đủ năm chi phần,\nÐoạn tận năm chi phần,\nTrong Pháp và Luật này,\nÐược gọi vị đầy đủ\nHoàn toàn mọi phương diện.`, ref: "Tăng Chi Bộ 10.12", url: "https://loicuaducphat.org/an/an10.12.html#content" },

{ text: `Ví như, này các Tỷ-kheo, phàm có những dấu chân của các loại chúng sanh bộ hành nào, tất cả đều hội tập trong chân con voi và chân con voi được gọi là tối thượng trong tất cả loại chân, tức là về phần to lớn. cũng vậy, này các Tỷ-kheo, phàm có những thiện pháp nào, tất cả những pháp ấy lấy không phóng dật làm căn bản, lấy không phóng dật làm chỗ quy tụ, không phóng dật được gọi là tối thượng trong tất cả thiện pháp`, ref: "Tăng Chi Bộ 10.15", url: "https://loicuaducphat.org/an/an10.15.html#content" },

{ text: `Này các Tỷ-kheo, cho đến các loài hữu tình không chân, hay hai chân, hay nhiều chân, hay có sắc, hay không sắc, hay có tưởng, hay không tưởng, hay phi tưởng phi phi tưởng. Như Lai được gọi là tối thượng giữa họ, bậc A-la-hán, Chánh Ðẳng Giác. Cũng vậy, này các Tỷ-kheo, phàm có những thiện pháp nào, tất cả những pháp ấy lấy không phóng dật làm căn bản, lấy không phóng dật làm chỗ quy tụ, không phóng dật được gọi là tối thượng trong các pháp ấy.`, ref: "Tăng Chi Bộ 10.15", url: "https://loicuaducphat.org/an/an10.15.html#content" },

{ text: `Và này các Tỷ-kheo, thế nào là ác dục? Ở đây, này các Tỷ-kheo, có người không có lòng tin, lại muốn rằng: “Mong rằng họ biết ta có lòng tin”; có ác giới hạn lại muốn rằng: “Mong rằng họ biết ta là người nghe nhiều”; là người ưa thích hội chúng, lại muốn rằng: “Mong rằng họ biết ta là người sống viễn ly”; là người biếng nhác lại muốn rằng: “Mong rằng họ biết ta là người tinh tấn”; là người thất niệm lại muốn rằng: “Mong rằng họ biết ta là người niệm được an trú”; là người không có định, lại muốn rằng: “Mong rằng họ biết ta là người có định”; là người ác tuệ, lại muốn rằng: “Mong rằng họ biết ta là người có trí tuệ”; là người chưa đoạn tận các lậu hoặc lại muốn: “Mong rằng họ biết ta là người đã đoạn tận các lậu hoặc”. Này các Tỷ-kheo, đây gọi là ác dục.`, ref: "Tăng Chi Bộ 10.23", url: "https://loicuaducphat.org/an/an10.23.html#content" },

{ text: `- Phá hòa hợp tăng, phá hòa hợp tăng, bạch Thế Tôn được nói đến như vậy. Cho đến như thế nào, bạch Thế Tôn, là phá hòa hợp Tăng? - Ở đây, này Upali, các Tỷ-kheo thuyết phi pháp là pháp; thuyết pháp là phi pháp; thuyết phi luật là luật; thuyết luật là phi luật; thuyết điều Như Lai không nói, không thuyết, là điều Như Lai nói, Như Lai thuyết; thuyết điều Như Lai có nói, có thuyết, là điều Như Lai không nói, không thuyết; thuyết điều Như Lai thường không sở hành là điều Như Lai thường sở hành; thuyết điều Như Lai thường sở hành là điều Như Lai không thường sở hành; thuyết điều Như Lai không chế đặt là điều Như Lai chế đặt; thuyết điều Như Lai có chế đặt là điều Như Lai không có chế đặt. Chính do mười sự này, họ phá hoại, họ chia rẽ, họ hành bất động yết-ma, họ tuyên đọc giới bổn Pàtimokkha khác biệt. Cho đến như vậy, này Upàli, là chúng Tăng bị phá hoại.`, ref: "Tăng Chi Bộ 10.35", url: "https://loicuaducphat.org/an/an10.35.html#content" },

{ text: `- Phá hoại Tăng hòa hợp, đem lại kết quả gì?\n- Này Ananda, đem lại tội ác kéo dài đến một kiếp.\n- Bạch Thế Tôn, tội ác gì kéo dài một kiếp?\n- Này Ananda, bị nấu trong địa ngục một kiếp.\nKẻ phá hòa hợp Tăng\nBị rơi vào đọa xứ,\nBị rơi vào địa ngục\nKéo dài đến một kiếp;\nƯa thích sự bất hòa,\nAn trú trên phi pháp,\nAn ổn các khổ ách,\nLại xa lìa, từ bỏ;\nAi phá sự hòa hợp,\nCủa Tăng chúng Tỷ-kheo,\nTrong một kiếp, người ấy,\nBị địa ngục nung nấu.`, ref: "Tăng Chi Bộ 10.38", url: "https://loicuaducphat.org/an/an10.38.html#content" },

{ text: `- Bạch Thế Tôn, với chúng Tăng bị phá, làm cho hòa hợp lại, đem đến kết quả gì?\n- Này Ananda, đem đến Phạm công đức!\n- Bạch Thế Tôn, thế nào là Phạm công đức?\n- Này Ananda, trong một kiếp, được sống hoan hỷ ở Thiên giới.\nSống an lạc là người,\nLàm hòa hợp chúng Tăng;\nSống an lạc là người,\nGiúp chúng Tăng hòa hợp;\nƯa thích sự hòa hợp,\nAn trú trên Chánh pháp.\nAi khiến cho chúng Tăng,\nÐược sống trong hòa hợp,\nTrong một kiếp, người ấy\nSống hoan hỷ Thiên giới.`, ref: "Tăng Chi Bộ 10.40", url: "https://loicuaducphat.org/an/an10.40.html#content" },

{ text: `Năm pháp nào cần phải an trú nội tâm? “Ta nói đúng thời, không phải phi thời; ta nói đúng sự thật, không phải không đúng sự thật; ta nói lời nhu hòa, không phải nói lời thô bạo; ta nói lời liên hệ đến mục đích, không phải lời không liên hệ đến mục đích; ta nói với tâm từ bi, không nói với tâm sân hận”. Năm pháp này cần phải an trú nội tâm. Này các Tỷ-kheo, Tỷ-kheo muốn buộc tội người khác, sau khi quán sát nội tâm về năm pháp này, sau khi an trú nội tâm về năm pháp này, hãy buộc tội người khác.`, ref: "Tăng Chi Bộ 10.44", url: "https://loicuaducphat.org/an/an10.44.html#content" },

{ text: `- Bạch Thế Tôn, do nhân gì, do duyên gì, ác nghiệp được làm, ác nghiệp được tiếp tục làm?\n- Này Mahàli, do nhân tham, do duyên tham, ác nghiệp được làm, ác nghiệp được tiếp tục làm. Này Mahali, do nhân sân, do duyên sân, ác nghiệp được làm, ác nghiệp được tiếp tục làm. Do nhân si, do duyên si, ác nghiệp được làm, ác nghiệp được tiếp tục làm. Này Mahàli, do nhân phi như lý tác ý, do duyên phi như lý tác ý, ác nghiệp được làm, ác nghiệp được tiếp tục làm. Này Mahàli, do nhân tâm tà hướng, do duyên tâm tà hướng, ác nghiệp được làm, ác nghiệp được tiếp tục làm. Này Mahàli, đây là nhân, đây là duyên, ác nghiệp được làm, ác nghiệp được tiếp tục làm.`, ref: "Tăng Chi Bộ 10.47", url: "https://loicuaducphat.org/an/an10.47.html#content" },

{ text: `- Này các Tỷ-kheo, có mười pháp này, vị xuất gia phải luôn luôn quán sát. Thế nào là mười? Người xuất gia phải luôn luôn quán sát: “Ta nay đi đến tình trạng là người không có giai cấp” (mất hết giai cấp). Người xuất gia phải luôn luôn quán sát: “Ðời sống của ta tùy thuộc vào người khác.” Vị xuất gia cần phải luôn luôn quán sát: “Nay cử chỉ uy nghi của ta cần phải thay đổi!” Vị xuất gia cần phải luôn luôn quán sát: “Không biết tự ngã có chỉ trích ta về giới hạnh không?” Vị xuất gia cần luôn luôn quán sát: “Không biết các đồng Phạm hạnh có trí, sau khi tìm hiểu, có chỉ trích ta về giới hạnh không?” Vị xuất gia cần phải luôn luôn quán sát: “Mọi sự vật khả ái, khả ý của ta bị đổi khác, bị biến hoại”. Vị xuất gia cần phải luôn luôn quán sát: “Ta là chủ của nghiệp, là thừa tự của nghiệp, là thai tạng của nghiệp, là bà con của nghiệp, là chỗ quy hướng của nghiệp; phàm nghiệp gì ta sẽ làm, thiện hay ác ta sẽ thừa tự nghiệp ấy”. Vị xuất gia cần phải luôn quán sát: “Ðêm ngày trôi qua bên ta và nay ta đã thành người như thế nào?” Vị xuất gia cần phải luôn luôn quán sát: “Ta có cố gắng hoan hỷ trong ngôi nhà trống không hay không?” Vị xuất gia cần phải luôn luôn quán sát: “Ta có chứng được pháp Thượng nhân, tri kiến thù thắng xứng đáng bậc Thánh không, để đến những ngày cuối cùng, các đồng Phạm hạnh có hỏi, ta sẽ không có xấu hổ?” Này các Tỷ-kheo, mười pháp này, vị xuất gia cần phải luôn luôn quán sát.`, ref: "Tăng Chi Bộ 10.48", url: "https://loicuaducphat.org/an/an10.48.html#content" },

{ text: `- Này các Tỷ-kheo, nay các thầy họp, bàn đến vấn đề gì? Câu chuyện gì giữa các Thầy đã bị gián đoạn?\n- Ở đây, bạch Thế Tôn, chúng con sau buổi ăn, sau khi đi khất thực trở về, chúng con ngồi hội họp trong hội trường, cạnh tranh, luận tranh, đấu tranh, sống đả thương nhau với binh khí miệng lưỡi.\n- Này các Tỷ-kheo, thật là không xứng đáng cho các Thầy, các thiện nam tử, vì lòng tin xuất gia, từ bỏ gia đình, sống không gia đình, lại sống cạnh tranh, luận tranh, đấu tranh, đả thương nhau với binh khí miệng lưỡi. Này các Tỷ-kheo, có mười pháp này, cần phải ghi nhớ tạo thành tương ái, tạo thành tương kính, đưa đến hòa đồng, đưa đến không tranh luận, hòa hợp, nhất trí. Thế nào là mười?`, ref: "Tăng Chi Bộ 10.50", url: "https://loicuaducphat.org/an/an10.50.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, Tỷ-kheo quán sát như vậy, được nhiều lợi ích trong các thiện pháp. “Có phải ta sống nhiều với tham? Có phải ta sống nhiều với không tham? Có phải ta sống nhiều với tâm có sân? Có phải ta sống nhiều vớt tâm không có sân? Có phải ta sống nhiều với hôn trầm thụy miên chi phối, hay ta sống nhiều với hôn trầm thụy miên được từ bỏ? Có phải ta sống nhiều với trạo cử, hay ta sống nhiều với không trạo cử? Có phải ta sống nhiều với nghi ngờ, hay ta sống nhiều vượt qua được nghi ngờ? Có phải ta sống nhiều với phẫn nộ, hay ta sống nhiều không bị phẫn nộ? Có phải ta sống nhiều với tâm bị ô nhiễm, hay ta sống nhiều với tâm không bị ô nhiễm? Có phải ta sống nhiều với thân nhiệt nóng, hay ta sống nhiều với thân không nhiệt nóng? Có phải ta sống nhiều với biếng nhác, hay ta sống nhiều với tinh tấn, tinh cần? Có phải ta sống nhiều với không định tĩnh, hay ta sống nhiều với định tĩnh? “`, ref: "Tăng Chi Bộ 10.51", url: "https://loicuaducphat.org/an/an10.51.html#content" },

{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo quán sát như vậy, biết rằng: “Ta sống nhiều với tâm tham; ta sống nhiều với tâm sân; ta sống nhiều với tâm bị hôn trầm thụy miên chi phối; ta sống nhiều với trạo cử; ta sống nhiều với nghi ngờ; ta sống nhiều với phẫn nộ; ta sống nhiều với tâm bị nhiễm ô; ta sống nhiều với thân nhiệt nóng; ta sống nhiều với biếng nhác; ta sống nhiều với không định tĩnh”, thời Tỷ-kheo ấy cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để đoạn tận các pháp ác bất thiện ấy. Ví như, này các Tỷ-kheo, khi khăn bị cháy, hay khi đầu bị cháy, cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để dập tắt khăn hay đầu bị cháy ấy. Cũng vậy này Tỷ kheo, Tỷ kheo ấy cần phải quyết định, ước muốn, tinh tấn, nỗ lực, dõng mãnh, bất thối, chánh niệm, tỉnh giác để đoạn tận các pháp bất thiện ấy.`, ref: "Tăng Chi Bộ 10.51", url: "https://loicuaducphat.org/an/an10.51.html#content" },

{ text: `Này các Tỷ-kheo, nếu Tỷ-kheo quán sát như vậy biết rằng: “Ta sống nhiều với tâm không tham, ta sống nhiều với tâm không sân, ta sống nhiếu với tâm không hôn trầm thụy miên; ta sống nhiều với tâm không trạo cử; ta sống nhiều với tâm nghi ngờ được vượt qua; ta sống nhiều với tâm không phẫn nộ; ta sống nhiều với tâm không nhiễm ô; ta sống nhiều với thân không nhiệt nóng; ta sống nhiều với tâm tinh tấn, tinh cần; ta sống nhiều với tâm định tĩnh”, thời Tỷ-kheo ấy, sau khi an trú trong các thiện pháp ấy, rồi hơn nữa cần chú tâm đoạn diệt các lậu hoặc.`, ref: "Tăng Chi Bộ 10.51", url: "https://loicuaducphat.org/an/an10.51.html#content" },

{ text: `Ở đây, này các Tỷ-kheo, Tỷ-kheo cố gắng để đạt được lòng tin, giới đức, nghe nhiều, bố thí và biện tài với trí tuệ. Những pháp ấy đối với vị này không đứng một chỗ, không tổn giảm. Này các Tỷ-kheo, Ta gọi như vậy là tăng trưởng trong các thiện pháp, không đứng một chỗ, không tổn giảm. Như vậy, này các Tỷ-kheo, là tăng trưởng trong các thiện pháp, không đứng một chỗ, không tổn giảm.`, ref: "Tăng Chi Bộ 10.53", url: "https://loicuaducphat.org/an/an10.53.html#content" },

{ text: `Này các Tỳ Kheo, Ta nói rằng, đồ ăn khất thực có hai loại: nên sử dụng và không nên sử dụng, như vậy được nói đến. Do duyên gì được nói đến như vậy? Ở đây, nếu biết được đồ ăn khất thực nào: “Ðồ ăn khất thực này được ta sử dụng, các pháp bất thiện tăng trưởng, các pháp thiện tổn giảm”, thời đồ ăn khất thực như vậy không nên sử dụng. Ở đây, nếu biết được đồ ăn khất thực nào: “Ðồ ăn khất thực này được ta sử dụng, các pháp bất thiện tổn giảm, các thiện pháp tăng trưởng”, thời đồ ăn khất thực như vậy nên sử dụng.`, ref: "Tăng Chi Bộ 10.54", url: "https://loicuaducphat.org/an/an10.54.html#content" },

{ text: `Này các Tỷ-kheo, Ta nói rằng, người có hai loại: nên thân cận và không nên thân cận, như vậy được nói đến. Do duyên gì được nói đến như vậy? Ở đây, nếu biết được người nào: “Người này ta thân cận, các pháp bất thiện tăng trưởng, các pháp thiện tổn giảm”, thời người như vậy không nên thân cận. Ở đây, nếu biết được người nào: “Người này ta thân cận, các pháp bất thiện tổn giảm, các pháp thiện tăng trưởng”, thời người như vậy nên thân cận. Này các Tỷ-kheo, Ta nói rằng, người có hai loại: nên thân cận và không nên thân cận, như vậy được nói đến. Do duyên này được nói đến như vậy.`, ref: "Tăng Chi Bộ 10.54", url: "https://loicuaducphat.org/an/an10.54.html#content" },

{ text: `- Này các Tỷ-kheo, có mười tưởng này, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh. Thế nào là mười? Tưởng vô thường, tưởng vô ngã, tưởng chết, tưởng nhàm chán trong các món ăn, tưởng không hoan hỷ đối với tất cả thế giới, tưởng xương, tưởng trùng ăn, tưởng xanh bầm, tưởng nứt nẻ, tưởng trương phồng. Này các Tỷ-kheo, mười tưởng này được tụ tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh.`, ref: "Tăng Chi Bộ 10.57", url: "https://loicuaducphat.org/an/an10.57.html#content" },

{ text: `- Này các Tỷ-kheo, mười tưởng này được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh. Thế nào là mười? Tưởng bất tịnh, tưởng chết, tưởng nhàm chán trong các món ăn, tưởng không hoan hỷ đối với tất cả thế giới, tưởng vô thường, tưởng khổ trên vô thường, tưởng vô ngã trên khổ, tưởng đoạn tận, tưởng ly tham, tưởng đoạn diệt. Này các Tỷ-kheo, mười tưởng này, được tu tập, được làm cho sung mãn, đưa đến quả lớn, lợi ích lớn, thể nhập vào bất tử, lấy bất tử làm cứu cánh.`, ref: "Tăng Chi Bộ 10.56", url: "https://loicuaducphat.org/an/an10.56.html#content" },
{ text: `- Này các Tỷ-kheo, nếu các du sĩ ngoại đạo hỏi như sau: “Này chư Hiền, tất cả pháp lấy gì làm căn bản? Tất cả pháp lấy gì làm sanh khởi? Tất cả pháp lấy gì làm tập khởi? Tất cả pháp lấy gì làm chỗ quy tụ? Tất cả pháp lấy gì làm thượng thủ? Tất cả pháp lấy gì làm tăng thượng? Tất cả pháp lấy gì làm tối thượng? Tất cả pháp lấy gì làm lõi cây? Tất cả pháp lấy gì làm chỗ thể nhập? Tất cả pháp lấy gì làm cứu cánh? “ Ðược hỏi vậy, này các Tỷ-kheo, các Thầy có thể trả lời như sau: “Tất cả pháp lấy dục làm căn bản. Tất cả pháp lấy tác ý làm sanh khởi. Tất cả pháp lấy xúc làm tập khởi. Tất cả pháp lấy thọ làm chỗ quy tụ. Tất cả pháp lấy định làm thượng thủ. Tất cả pháp lấy niệm làm tăng thượng. Tất cả pháp lấy tuệ làm tối thượng. Tất cả pháp lấy giải thoát làm lõi cây. Tất cả pháp lấy bất tử làm chỗ thể nhập. Tất cả pháp lấy Niết-bản làm cứu cánh.”`, ref: "Tăng Chi Bộ 10.58", url: "https://loicuaducphat.org/an/an10.58.html#content" },

{ text: `Này các Tỷ-kheo, các Thầy cần phải học tập như sau: “Tâm chúng ta sẽ được thực hành tích tập như khi xuất gia; các pháp bất thiện được sanh không có chinh phục tâm và không tồn tại; tâm chúng ta sẽ được thực hành tích tập với tưởng vô thường; tâm chúng ta sẽ được thực hành tích tập với tưởng vô ngã; tâm chúng ta sẽ được thực hành tích tập với tưởng bất tịnh; tâm chúng ta sẽ được thực hành tích tập với tưởng nguy hại; sau khi biết được thế giới thăng bằng và không thăng bằng, tâm chúng ta sẽ được thực hành tích tập với tưởng ấy. Sau khi biết được thế giới sanh khởi và đoạn diệt, tâm chúng ta sẽ được thực hành tích tập với tưởng ấy. Sau khi biết được thế giới tập khởi và chấm dứt, tâm chúng ta sẽ được thực hành tích tập với tưởng ấy; tâm chúng ta sẽ được thực hành tích tập với tưởng đoạn tận; tâm chúng ta sẽ được thực hành tích tập với tưởng ly tham, và tâm chúng ta sẽ được thực hành tích tập với tưởng đoạn diệt.” Như vậy, này các Tỷ-kheo, các Thầy cần phải học tập.`, ref: "Tăng Chi Bộ 10.59", url: "https://loicuaducphat.org/an/an10.59.html#content" },

{ text: `- Tôn giả Girimànanda, bạch Thế Tôn, bị bệnh, khổ đau, bị trọng bệnh. Lành thay, nếu Thế Tôn đi đến Tôn giả Girimànanda, vì lòng từ mẫn. - Này Ananda, nếu Thầy đi đến Tỷ-kheo Girimànanda và đọc lên mười tưởng, thời sự kiện này có thể xảy ra: Tỷ-kheo Girimànanda sau khi được nghe mười tưởng, bệnh của vị ấy có thể được thuyên giảm ngay lập tức! Thế nào là mười? Tưởng vô thường, tưởng vô ngã, tưởng bất tịnh, tưởng nguy hại, tưởng đoạn tận, tưởng từ bỏ, tưởng đoạn diệt, tưởng nhàm chán đối với tất cả thế giới, tưởng vô thường trong tất cả hành, tưởng niệm hơi thở vô hơi thở ra.`, ref: "Tăng Chi Bộ 10.60", url: "https://loicuaducphat.org/an/an10.60.html#content" },

{ text: `- Tôn giả Girimànanda, bạch Thế Tôn, bị bệnh, khổ đau, bị trọng bệnh. Lành thay, nếu Thế Tôn đi đến Tôn giả Girimànanda, vì lòng từ mẫn. - Này Ananda, nếu Thầy đi đến Tỷ-kheo Girimànanda và đọc lên mười tưởng, thời sự kiện này có thể xảy ra: Tỷ-kheo Girimànanda sau khi được nghe mười tưởng, bệnh của vị ấy có thể được thuyên giảm ngay lập tức! Thế nào là mười? Tưởng vô thường, tưởng vô ngã, tưởng bất tịnh, tưởng nguy hại, tưởng đoạn tận, tưởng từ bỏ, tưởng đoạn diệt, tưởng nhàm chán đối với tất cả thế giới, tưởng vô thường trong tất cả hành, tưởng niệm hơi thở vô hơi thở ra.`, ref: "Tăng Chi Bộ 10.60", url: "https://loicuaducphat.org/an/an10.60.html#content" },

{ text: `Và này Ananda, thế nào là tưởng vô thường? Ở đây, này Ananda, Tỷ-kheo đi đến ngôi rừng, hay đến gốc cây, hay đi đến ngôi nhà trống, quán sát như sau: “Sắc là vô thường, thọ là vô thường, tưởng là vô thường, hành là vô thường, thức là vô thường.” Như vậy vị ấy trú, tùy quán vô thường, trong năm thú uẩn này. Này Ananda, đây gọi là tưởng vô thường.`, ref: "Tăng Chi Bộ 10.60", url: "https://loicuaducphat.org/an/an10.60.html#content" },

{ text: `Và này Ananda, thế nào là tưởng vô ngã? Ở đây, này Ananda, Tỷ-kheo đi đến khu rừng hay đi đến gốc cây, hay đi đến ngôi nhà trống, quán sát như sau: “Mắt là vô ngã, các sắc là vô ngã; tai là vô ngã, các tiếng là vô ngã; mũi là vô ngã, các hương là vô ngã; lưỡi là vô ngã, các vị là vô ngã; thân là vô ngã, xúc là vô ngã; ý là vô ngã, các pháp là vô ngã.” Này Ananda, đây gọi là tưởng vô ngã.`, ref: "Tăng Chi Bộ 10.60", url: "https://loicuaducphat.org/an/an10.60.html#content" },

{ text: `Và này Ananda, thế nào là tưởng nguy hại? Ở đây, này Ananda, Tỷ-kheo đi đến khu rừng, đi đến gốc cây, hay đi đến ngôi nhà trống, quán sát như sau: “Nhiều khổ là thân này, nhiều sự nguy hại. Như vậy trong thân này, nhiều loại bệnh khởi lên. Ví như bệnh đau mắt, bệnh đau về tai, bệnh đau mũi, bệnh đau lưỡi, bệnh đau thân, bệnh đau đầu, bệnh đau vành tai, bệnh đau miệng, bệnh đau răng, bệnh ho, bệnh suyễn, bệnh sổ mũi, bệnh sốt, bệnh già yếu, bệnh đau yếu, bệnh đau bụng, bất tỉnh, kiết lỵ, bệnh đau bụng quặn, bệnh thổ tả, bệnh hủi, bệnh ung nhọt, bệnh ghẻ lở, bệnh ho lao, bệnh trúng gió, bệnh da, bệnh ngứa, bệnh da đóng vảy, bệnh hắc lào lang ben, bệnh ghẻ, bệnh huyết đảm (mật trong máu), bệnh đái đường, bệnh trĩ, bệnh mụt nhọt, bệnh ung nhọt ung loét, các bệnh khởi lên do mật, bệnh khởi lên từ đàm, niêm dịch, các bệnh khởi lên từ gió; bệnh do hòa hợp các thể dịch sinh ra; các bệnh do thời tiết sinh ra, các bệnh do làm việc quá độ sanh, các bệnh do sự trùng hợp các sự kiêng; các bệnh do nghiệp thuần thục, lạnh, nóng, đói, khát, đại tiện, tiểu tiện”. Như vậy, vị ấy sống, quán sự nguy hại trong thân này.`, ref: "Tăng Chi Bộ 10.60", url: "https://loicuaducphat.org/an/an10.60.html#content" },

{ text: `- Này các Tỷ-kheo, khởi điểm đầu tiên của vô minh không thể nêu rõ để có thể nói: “Trước điểm này, vô minh không có, rồi sau mới có.” Như vậy, này các Tỷ-kheo, lời này được nói đến. Tuy vậy, sự việc này được nêu rõ: “Do duyên này, vô minh (có mặt)”. Này các Tỷ-kheo, Ta nói rằng vô minh có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho vô minh? Năm triền cái, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng năm triền cái có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho năm triền cái? Ba ác hành, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng ba ác hành có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho ba ác hành? Các căn không chế ngự, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng, các căn không chế ngự có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho các căn không chế ngự? Không chánh niệm tỉnh giác, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng không chánh niệm tỉnh giác có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho không chánh niệm tỉnh giác? Phi như lý tác ý, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng phi như lý tác ý có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho phi như lý tác ý? Không có lòng tin, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng không có lòng tin có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho không có lòng tin? Không nghe diệu pháp, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng, không nghe diệu pháp có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho không nghe diệu pháp? Không giao thiệp với bậc Chân nhân, cần phải trả lời như vậy.`, ref: "Tăng Chi Bộ 10.61", url: "https://loicuaducphat.org/an/an10.61.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, không giao thiệp với các bậc Chân nhân được viên mãn, thời làm viên mãn không có nghe diệu pháp; không có nghe diệu pháp được viên mãn, thời làm viên mãn không có lòng tin; không có lòng tin được viên mãn, thời làm viên mãn phi như lý tác ý; phi như lý tác ý được viên mãn, thời làm viên mãn không chánh niệm tỉnh giác; không chánh niệm tỉnh giác được viên mãn, thời làm viên mãn các căn không chế ngự; các căn không chế ngự được viên mãn, thời làm viên mãn ba ác hành; ba ác hành được viên mãn, thời làm viên mãn năm triền cái, năm triền cái được viên mãn, thời viên mãn vô minh. Như vậy, đây là thức ăn của vô minh, và như vậy là sự viên mãn.`, ref: "Tăng Chi Bộ 10.61", url: "https://loicuaducphat.org/an/an10.61.html#content" },

{ text: `Và này các Tỷ-kheo, Ta nói minh giải thoát có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho minh giải thoát? Bảy giác chi, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng Bảy giác chi có thức ăn, không phải không có thức ăn. Và cái gì là thức ăn cho Bảy giác chi? Bốn niệm xứ, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng Bốn niệm xứ có thức ăn, không phải không có thức ăn. Cái gì là thức ăn cho Bốn niệm xứ ? Ba thiện hành, cần phải trả lời như vậy. Này các Tỷ kheo, Ta nói như rằng ba thiện hành có thức ăn, không phải không có thức ăn. Cái gì là thức ăn cho ba thiện hành? Các căn được chế ngự, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng các căn được chế ngự có thức ăn, không phải không có thức ăn. Cái gì là thức ăn cho các căn được chế ngự? Chánh niệm tỉnh giác, cần phải trả lời như vậy. Này các Tỷ-kheo, chánh niệm tỉnh giác có thức ăn, không phải không có thức ăn. Cái gì là thức ăn cho chánh niệm tỉnh giác? Như lý tác ý, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng, như lý tác ý có thức ăn, không phải không có thức ăn. Cái gì là thức ăn cho như ý tác ý? Lòng tin, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói lòng tin có thức ăn, không phải không có thức ăn. Cái gì là thức ăn cho lòng tin? Nghe diệu pháp, cần phải trả lời như vậy. Này các Tỷ-kheo, Ta nói rằng nghe diệu pháp có thức ăn, không phải không có thức ăn. Cái gì là thức ăn cho nghe diệu pháp? Giao thiệp với bậc Chân nhân, cần phải trả lời như vậy.`, ref: "Tăng Chi Bộ 10.61", url: "https://loicuaducphat.org/an/an10.61.html#content" },

{ text: `Cũng vậy, này các Tỷ-kheo, giao thiệp với bậc Chân nhân được viên mãn, thời làm viên mãn nghe diệu pháp; nghe diệu pháp được viên mãn, thời làm viên mãn lòng tin; lòng tin được viên mãn thời làm viên mãn như lý tác ý; như lý tác ý được viên mãn, thời làm viên mãn chánh niệm tỉnh giác; chánh niệm tỉnh giác được viên mãn, thời làm viên mãn các căn được chế ngự; các căn chế ngự được viên mãn, thời làm viên mãn ba thiện hành; ba thiện hành được viên mãn, thời làm viên mãn Bốn niệm xứ; Bốn niệm xứ được viên mãn, thời làm viên mãn Bảy giác chi; Bảy giác chi được viên mãn, thời làm viên mãn minh giải thoát. Như vậy là thức ăn của minh giải thoát, và như vậy là viên mãn.`, ref: "Tăng Chi Bộ 10.61", url: "https://loicuaducphat.org/an/an10.61.html#content" },

{ text: `- Thưa Hiền giả Sàriputta, thế nào là lạc, thế nào là khổ?\n- Này Hiền giả, tái sanh là khổ, không tái sanh là lạc. Khi có tái sanh, này Hiền giả, chờ đợi là khổ này: Lạnh, nóng, đói, khát, đại tiện, tiểu tiện, xúc chạm với lửa, xúc chạm với trượng, xúc chạm với kiếm. Cho đến bà con và bạn bè, khi gặp nhau, hội ngộ với nhau cũng não hại. Này Hiền giả, tái sanh là khổ, khi có tái sanh, chờ đợi là khổ này. Khi không có tái sanh, này Hiền giả, chờ đợi là lạc này: Không lạnh, không nóng, không đói, không khát, không đại tiện, không tiểu tiện, không có xúc chạm với lửa, không có xúc chạm với trượng, không có xúc chạm với kiếm. Cho đến bà con bạn bè, khi gặp nhau, khi hội ngộ với nhau không có não hại. Này Hiền giả, khi không có tái sanh, chờ đợi là lạc này.`, ref: "Tăng Chi Bộ 10.65", url: "https://loicuaducphat.org/an/an10.65.html#content" },

{ text: `- Thưa Hiền giả Sàriputta, trong Pháp và Luật này, thế nào là lạc, thế nào là khổ?\n- Không thích ý, này Hiền giả, trong Pháp và Luật này là khổ; thích ý là lạc. Khi nào không thích ý có mặt, này Hiền giả, chờ đợi là khổ này: Khi đi không được lạc thú, khi đứng... khi ngồi... khi nằm... khi đi đến làng.. khi đi đến rừng... khi đi đến gốc cây... khi đi đến ngôi nhà trống... khi đi đến chỗ lộ thiên... khi đi đến giữa các Tỷ-kheo, không được lạc thú. Khi nào không thích ý có mặt, này Hiền giả, chờ đợi là khổ này. Khi nào thích ý có mặt, này Hiền giả, chờ đợi là lạc này: Khi đi được lạc thú; khi đứng... khi ngồi... khi nằm... khi đi đến làng... khi đi đến rừng... khi đi đến gốc cây... khi đi đến ngôi nhà trống... khi đi đến chỗ lộ thiên... khi đi đến giữa các Tỷ-kheo, có được lạc thú. Khi nào thích ý có mặt, này Hiền giả, chờ đợi là khổ này.`, ref: "Tăng Chi Bộ 10.66", url: "https://loicuaducphat.org/an/an10.66.html#content" },

{ text: `- Này chư Hiền, với ai không có lòng tin trong các pháp thiện, không có xấu hổ... không có sợ hãi... không có tinh tấn... không có tuệ trong pháp thiện, với người ấy, bất luận đêm hay ngày, chờ đợi là tổn giảm trong các thiện pháp, không phải tăng trưởng.\nVí như, này chư Hiền, khi trăng đến độ trăng tối; bất luận đêm hay ngày, trăng tổn giảm về sắc, tổn giảm về hình tròn, tổn giảm về ánh sáng, tổn giảm về bề rộng quỹ đạo. Cũng vậy, này chư Hiền, với ai không lòng tin trong các thiện pháp, không có xấu hổ... không có sợ hãi... không có tinh tấn... không có trí tuệ trong các thiện pháp, với người ấy, bất luận là đêm hay ngày, chờ đợi là tổn giảm trong các thiện pháp, không phải tăng trưởng. Hạng người không có lòng tin, này chư Hiền, tức là tổn giảm. Hạng người không có sợ hãi, này chư Hiền, tức là tổn giảm. Hạng người phẫn nộ, này chư Hiền, tức là tổn giảm. Hạng người ác dục, này chư Hiền, tức là tổn giảm. Hạng người ác bằng hữu, này chư Hiền, tức là tổn giảm. Hạng người tà kiến, này chư Hiền, tức là tổn giảm.`, ref: "Tăng Chi Bộ 10.67", url: "https://loicuaducphat.org/an/an10.67.html#content" },

{ text: `- Này các Tỷ-kheo, thật không xứng đáng cho các Thầy, là những thiện nam tử, vì lòng tin xuất gia, từ bỏ gia đình, sống không gia đình, lại có thể sống chú tâm trong nhiều câu chuyện sai khác, như câu chuyện về vua... câu chuyện về hữu và phi hữu. Này các Tỷ-kheo, có mười đề tài để nói chuyện này. Thế nào là mười? Câu chuyện về ít dục, câu chuyện về biết đủ, câu chuyện về viễn ly, câu chuyện về không tụ hội, câu chuyện về tinh tấn, câu chuyện về giới, câu chuyện về định, câu chuyện về tuệ, câu chuyện về giải thoát, câu chuyện về giải thoát tri kiến. Này các Tỷ-kheo, có mười đề tài để nói chuyện này. Này các Tỷ-kheo, nếu các Thầy tiếp tục nói những câu chuyện liên hệ đến mười đề tài để nói chuyện này, thời các Thầy có thể với ánh sáng (của mình) đánh bạt ánh sáng của mặt trăng, mặt trời, những vật có đại thần lực, có uy lực, còn nói gì của các du sĩ ngoại đạo.`, ref: "Tăng Chi Bộ 10.69", url: "https://loicuaducphat.org/an/an10.69.html#content" },

{ text: `- Này các Tỷ-kheo, có mười sự việc được tán thán này. Thế nào là mười? Ở đây, này các Tỷ-kheo, Tỷ-kheo tự mình ít dục, và là người khiến cho đề tài ít dục được nói đến giữa các Tỷ-kheo. Tỷ-kheo ít dục và là người khiến cho đề tài ít dục được nói đến giữa các Tỷ-kheo, là sự việc đáng được tán thán và Tỷ-kheo tự mình biết đủ... tự mình sống viễn ly... tự mình không tụ hội... tự mình tinh tấn... tự mình đầy đủ giới... tự mình đầy đủ định... tự mình đầy đủ tuệ... tự mình đầy đủ giải thoát... tự mình đầy đủ giải thoát tri kiến, và là người khiến cho đề tài giải thoát tri kiến được nói đến giữa các Tỷ-kheo, là sự việc đáng được tán thán. Này các Tỷ-kheo, có mười sự việc được tán thán này.`, ref: "Tăng Chi Bộ 10.70", url: "https://loicuaducphat.org/an/an10.70.html#content" },

{ text: `Này các Tỷ-kheo, “Tiếng ồn là gai cho thiền”, đã được Ta nói như vậy. Này các Tỷ-kheo, có mười loại cây gai này. Thế nào là mười? Với người ưa thích viễn ly, ưa thích hội chúng là cây gai. Với người chuyên chú tu tập tướng bất tịnh, tu tập tịnh tướng là cây gai. Với người phòng hộ các căn, đi xem văn nghệ trình diễn là cây gai. Với người sống Phạm hạnh, thân cận với phụ nữ là cây gai. Với người chứng Thiền thứ nhất, tiếng ồn là cây gai. Với người chứng Thiền thứ hai, tầm tứ là cây gai. Với người chứng Thiền thứ ba, hỷ là cây gai. Với người chứng Thiền thứ tư, hơi thở là cây gai. Với người đã đạt được Diệt thọ tưởng định, tưởng và thọ là cây gai. Tham là cây gai. Sân là cây gai. Si là cây gai. Này các Tỷ-kheo, hãy sống không phải là cây gai. Này các Tỷ-kheo, hãy sống rời khỏi cây gai. Này các Tỷ-kheo, hãy sống không phải là cây gai và rời khỏi cây gai. Này các Tỷ-kheo, không có cây gai là bậc A-la-hán. Này các Tỷ-kheo, rời khỏi cây gai là bậc A-la-hán. Này các Tỷ-kheo, vị không có gai và rời khỏi cây gai là bậc A-la-hán`, ref: "Tăng Chi Bộ 10.72", url: "https://loicuaducphat.org/an/an10.72.html#content" },

{ text: `Này các Tỷ-kheo, đối với mười pháp khả lạc, khả hỷ, khả ý khó tìm được ở đời này, mười pháp là những chướng ngại. Thế nào là mười? Thụ động và không hăng hái là chướng ngại cho tài sản. Không trang sức, không tô điểm là chướng ngại cho dung sắc. Hành động không thích ứng là chướng ngại cho không bệnh. Ác bằng hữu là chướng ngại cho giới đức. Không chế ngự các căn là chướng ngại cho Phạm hạnh. Lừa dối là chướng ngại cho các bạn bè. Không học tập là chướng ngại cho nhiều trí. Không nghe, không hỏi là chướng ngại cho trí tuệ. Không có chú tâm, không có quán sát là chướng ngại cho các pháp. Tà hạnh là chướng ngại cho Thiên giới. Này các Tỷ-kheo, đối với mười khả lạc, khả hỷ, khả ý khó tìm được ở đời này, mười pháp này là những chướng ngại.`, ref: "Tăng Chi Bộ 10.73", url: "https://loicuaducphat.org/an/an10.73.html#content" },

{ text: `Này các Tỷ-kheo, đối với mười pháp khả lạc, khả hỷ, khả ý khó tìm được ở đời này, mười pháp là những thức ăn. Thế nào là mười? Không thụ động, hăng hái là món ăn cho các tài sản. Trang sức, tô điểm là món ăn cho dung sắc. Hành động thích ứng là món ăn cho không bệnh. Bạn bè với thiện bằng hữu là thức ăn cho các giới đức. Chế ngự các căn là thức ăn cho Phạm hạnh. Không có lừa dối là thức ăn cho bạn bè. Học tập là thức ăn cho trí tuệ. Chú tâm quán sát là thức ăn cho các pháp. Chánh hạnh là thức ăn cho Thiên giới. Này các Tỷ-kheo, đối với mười pháp khả lạc, khả hỷ, khả ý khó tìm được ở đời này, mười pháp này là những thức ăn.`, ref: "Tăng Chi Bộ 10.73", url: "https://loicuaducphat.org/an/an10.73.html#content" },

{ text: `Này các Tỷ-kheo, do không đoạn tận ba pháp, không có thể đoạn tận phi như lý tác ý, không có thể đoạn tận tu tập tà đạo, không có thể đoạn tận tánh thụ động. Thế nào là ba? Không đoạn tận vọng niệm, không đoạn tận không tỉnh giác, không đoạn tận tâm loạn động. Do không đoạn tận ba pháp này, này các Tỷ-kheo, không có thể đoạn tận phi như lý tác ý, không có thể đoạn tận tu tập tà đạo, không có thể đoạn tận tánh thụ động.`, ref: "Tăng Chi Bộ 10.76", url: "https://loicuaducphat.org/an/an10.76.html#content" },

{ text: `Này các Tỷ-kheo, do không đoạn tận ba pháp, không có thể đoạn tận vọng niệm, không có thể đoạn tận không tỉnh giác, không có thể đoạn tận tâm loạn động. Thế nào là ba? Không đoạn tận không muốn yết kiến các bậc Thánh, không đoạn tận không muốn nghe Thánh pháp, không đoạn tận bới lông tìm vết. Do không đoạn tận ba pháp này, này các Tỷ-kheo, không có thể đoạn tận vọng niệm, không có thể đoạn tận không tỉnh giác, không có thể đoạn tận tâm loạn động.`, ref: "Tăng Chi Bộ 10.76", url: "https://loicuaducphat.org/an/an10.76.html#content" },

{ text: `Này các Tỷ-kheo, do không đoạn tận ba pháp, không có thể đoạn tận trạo cử, không có thể đoạn tận không chế ngự, không có thể đoạn tận ác giới. Thế nào là ba? Không đoạn tận không có lòng tin, không đoạn tận xan tham, không đoạn tận biếng nhác, do không đoạn tận ba pháp này, này các Tỷ-kheo, không có thể đoạn tận trạo cử, không có thể đoạn tận không chế ngự, không có thể đoạn tận ác giới.`, ref: "Tăng Chi Bộ 10.76", url: "https://loicuaducphat.org/an/an10.76.html#content" },

{ text: `- Này các Tỷ-kheo, con quạ thành tựu với mười tà pháp. Thế nào là mười? Ngạo nghễ, hung hãn, cường dục, ăn lớn, độc ác, không từ bi, khiếp nhược, giọng chói tai, vọng niệm và cất chứa tài sản. Này các Tỷ-khao, con quạ thành tựu với mười tà pháp này. Cũng vậy, này các Tỷ-kheo, vị ác Tỷ-kheo thành tựu với mười tà pháp. Thế nào là mười? Ngạo nghễ, hung hãn, cường dục, ăn lớn, độc ác, không từ bi, khiếp nhược, giọng chói tai, vọng niệm và cất chứa tài sản. Này các Tỷ-kheo, vị ác Tỷ-kheo thành tựu với mười tà pháp này.`, ref: "Tăng Chi Bộ 10.77", url: "https://loicuaducphat.org/an/an10.77.html#content" },

{ text: `- Này các Tỷ-kheo, có mười trường hợp hiềm hận. Thế nào là mười? Hiềm hận được kết thành, khi nghĩ rằng: “Nó đã làm hại ta”. Hiềm hận được kết thành, khi nghĩ rằng: “Nó đang làm hại ta”. Hiềm hận được kết thành, khi nghĩ rằng: “Nó sẽ làm hại ta”. Hiềm hận được kết thành, khi nghĩ rằng: “Nó đã hại người ta yêu, người ta mến...” “Nó đang hại người ta yêu, hại người ta mến...” “Nó sẽ hại người ta yêu, người ta mến”. Hiềm hận được kết thành, khi nghĩ rằng: “Nó đã làm lợi cho người ta không yêu, người ta không mến”. Hiềm hận được kết thành, khi nghĩ rằng: “ Nó đang làm lợi cho người ta không yêu, người ta không mến”. Hiềm hận được kết thành, khi nghĩ rằng: “Nó sẽ làm lợi cho người ta không yêu, người ta không mến”. Làm cho vị ấy tức giận không có lý do. Này các Tỷ-kheo, có mười trường hợp hiềm hận này.`, ref: "Tăng Chi Bộ 10.79", url: "https://loicuaducphat.org/an/an10.79.html#content" },

{ text: `- Từ bao nhiêu pháp, Như Lai sống xuất ly, ly hệ, giải thoát với tâm không hạn cuộc.\n- Từ mười pháp, này Bàhuna, Như Lai sống xuất ly, ly hệ, giải thoát với tâm không hạn cuộc. Thế nào là mười? Từ sắc, này Bàhuna, Như Lai sống xuất ly, ly hệ, giải thoát với tâm không hạn cuộc. Từ thọ, này Bàhuna... Từ tưởng, này Bàhuna... Từ các hành, này Bàhuna... Từ thức, này Bàhuna... Từ sanh, này Bàhuna... Từ già, này Bàhuna...Từ chết, này Bàhuna...Từ các khổ này, Bàhuna.... Từ các phiền não, này Bàhuna, Như Lai sống xuất ly, ly hệ, giải thoát với tâm không hạn cuộc. Ví như, này Bàhuna, hoa sen xanh, hay hoa sen hồng, hay hoa sen trắng, sanh ra trong nước, lớn lên trong nước, vươn lên mặt nước và đứng, không có dính nước. Cũng vậy, này Bàhuna, từ mười pháp này, Như Lai sống xuất ly, ly hệ, giải thoát với tâm không hạn cuộc.`, ref: "Tăng Chi Bộ 10.81", url: "https://loicuaducphat.org/an/an10.81.html#content" },

{ text: `- Này Ananda, Tỷ-kheo nào không có lòng tin, sẽ được tăng trưởng, lớn mạnh, lớn rộng trong Pháp và Luật này, sự kiện này không xảy ra. Này Ananda, Tỷ-kheo nào ác giới... không nghe pháp... khó nói... làm bạn với ác... biếng nhác... thất niệm... không biết đủ... ác dục.. này Ananda, Tỷ-kheo nào có tà kiến sẽ được tăng trưởng lớn mạnh, lớn rộng trong Pháp và Luật này, sự kiện này không xảy ra.`, ref: "Tăng Chi Bộ 10.82", url: "https://loicuaducphat.org/an/an10.82.html#content" },

{ text: `Này Ananda, Tỷ-kheo nào có lòng tin, sẽ được tăng trưởng, lớn mạnh, lớn rộng trong Pháp và Luật này, sự kiện này có xảy ra. Này Ananda, Tỷ-kheo nào có giới... nghe pháp, thọ trì điều đã nghe... dễ nói... làm bạn với thiện... tinh cần, tinh tấn... trú niệm... biết đủ... ít dục... Này Ananda, Tỷ-kheo nào có chánh tri kiến, sẽ được tăng trưởng, lớn mạnh, lớn rộng trong Pháp và Luật này, sự kiện này có xảy ra. Này Anada, Tỷ-kheo nào thành tựu mười pháp này sẽ được tăng trưởng, lớn mạnh, lớn rộng trong Pháp và Luật này, sự kiện này có xảy ra.`, ref: "Tăng Chi Bộ 10.82", url: "https://loicuaducphat.org/an/an10.82.html#content" },

{ text: `- Này các Tỷ-kheo, nếu Tỷ-kheo nào mạ lỵ, khiển trách, nhiếc mắng các vị Thánh và những vị đồng Phạm hạnh, thật sự không thể không xảy ra được, không thể không có lúc để vị ấy khỏi phải gặp một trong mười tai nạn này. Thế nào là mười? Không chứng đắc điều chưa được chứng đắc, điều đã chứng đắc bị thối thất, không được sáng suốt đối với diệu pháp, tăng thượng mạn trong diệu pháp, sống Phạm hạnh không được hoan hỷ, vi phạm một uế tội, cảm xúc bệnh nặng, đạt đến điên cuồng loạn tâm, khi chết bị bất tỉnh (hôn mê), hay sau khi thân hoại mạng chung, sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Này các Tỷ-kheo, Tỷ-kheo nào mạ lỵ, khiển trách, nhiếc mắng các vị Thánh và những vị đồng Phạm hạnh, thật sự không thể không xảy ra được, không thể không có lúc để vị ấy phải gặp một trong mười tai nạn này.`, ref: "Tăng Chi Bộ 10.88", url: "https://loicuaducphat.org/an/an10.88.html#content" },

{ text: `Con người được sanh ra\nSanh với búa trong miệng,\nNgười ngu nói điều xấu,\nLà tự chém vào mình.\nAi khen người đáng chê,\nAi chê người đáng khen,\nÐều chất chứa bất hạnh,\nDo từ miệng tạo thành,\nVà chính do bất hạnh,\nNên không được an lạc\nNhỏ thay bất hạnh này,\nChính do cờ bạc sanh,\nKhiến do cờ bạc sanh,\nKhiến tài sản tiêu hao,\nBất hạnh này lớn hơn,\nKhông những mất tất cả,\nLại mất cả tự mình.\nLà người khởi ác ý,\nÐối với chư Thiện Thệ.\nAi chỉ trích bậc Thánh,\nVới lời, với ác ý,\nTrải qua trăm ngàn thời,\nVới ni-rab-bu-da,\nCòn thêm ba mươi sáu,\nVới năm a-bu-đa,\nPhải sanh vào địa ngục,\nChịu khổ đau tại đấy.`, ref: "Tăng Chi Bộ 10.89", url: "https://loicuaducphat.org/an/an10.89.html#content" },

{ text: `Này Gia chủ, phàm hành trì khổ hạnh nào, các pháp bất thiện tăng trưởng, các pháp thiện tổn giảm, khổ hạnh ấy, Ta nói, không nên hành trì. Nhưng này Gia chủ, phàm hành trì khổ hạnh nào, các pháp bất thiện tổn giảm, các pháp thiện tăng trưởng, khổ hạnh ấy, Ta nói nên hành trì. Này Gia chủ, phàm chấp trì nào, các pháp bất thiện tăng trưởng, các pháp thiện tổn giảm, chấp trì ấy, Ta nói, không nên chấp trì. Phàm chấp trì nào, các pháp bất thiện tổn giảm, các thiện pháp tăng trưởng, thời chấp trì ấy, Ta nói nên chấp trì. Này Gia chủ, phàm tinh cần nào được tinh cần, các pháp bất thiện tăng trưởng, các pháp thiện tổn giảm, thời tinh cần ấy, Ta nói rằng, không nên tinh cần. Phàm tinh cần nào được tinh cần, các pháp bất thiện tổn giảm, các pháp thiện tăng trưởng, thời tinh cần ấy, Ta nói nên tinh cần. Này Gia chủ, phàm từ bỏ sự từ bỏ nào, các pháp bất thiện tăng trưởng, các pháp thiện tổn giảm, thời từ bỏ ấy, Ta nói, không nên từ bỏ. Phàm từ bỏ sự từ bỏ nào, các pháp bất thiện tổn giảm, các pháp thiện tăng trưởng, thời từ bỏ ấy, Ta nói, nên từ bỏ. Này Gia chủ, phàm giải thoát sự giải thoát nào, các pháp bất thiện tăng trưởng, các thiện pháp tổn giảm, thời giải thoát ấy, Ta nói, không nên giải thoát. Phàm giải thoát sự giải thoát nào, các pháp bất thiện tổn giảm, các pháp thiện tăng trưởng, thời giải thoát ấy, Ta nói nên giải thoát.`, ref: "Tăng Chi Bộ 10.94", url: "https://loicuaducphat.org/an/an10.94.html#content" },

{ text: `Thành tựu mười pháp này, này các Tỷ-kheo, vị trưởng lão tại địa phương nào vị ấy trú, vị ấy trú an ổn. Thế nào là mười? Vị trưởng lão đã lâu ngày được biết đến, xuất gia đã lâu ngày có giới... chấp nhận và học hỏi trong các học pháp; là vị nghe nhiều.... khéo thể nhập với chánh kiến; cả hai giới bổn Pàtimokkha được khéo truyền đạt một cách rộng rãi, được khéo phân tích, khéo thông hiểu, khéo quyết định theo kinh, theo chi tiết, vị ấy thiện xảo trong sự sanh khởi và chấm dứt các tranh sự, ưa thích pháp; dùng lời ái ngữ, hết sức hân hoan trong thắng pháp, thắng luật; biết đủ với bất cứ vật dụng nào nhận được như y, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh; dễ mến, khéo chế ngự trong khi đi tới đi lui, khi ngồi trong nhà; chứng được không khó khăn, chứng được không mệt nhọc, chứng được không phí sức bốn Thiền thuộc tăng thượng tâm, hiện tại lạc trú; do đoạn diệt các lậu hoặc, vị ấy ngay trong hiện tại, với thắng trí chứng ngộ, chứng đạt và an trú vô lậu tâm giải thoát, tuệ giải thoát. Thành tựu mười pháp này, này các Tỷ-kheo, Tỷ-kheo trưởng lão trú tại địa phương nào, tại địa phương nào, sống được an ổn.`, ref: "Tăng Chi Bộ 10.98", url: "https://loicuaducphat.org/an/an10.98.html#content" },

{ text: `Vị ấy biết đủ, bằng lòng với tấm y để che thân, với đồ ăn khất thực để nuôi bụng, đi đến chỗ nào cũng mang theo y và bình bát. Cũng như con chim bay đến chỗ nào cũng mang theo hai cánh; cũng vậy, vị ấy bằng lòng với tấm y để che thân, với đồ ăn khất thực để nuôi bụng, đi đến chỗ nào cũng mang theo. Vị ấy thành tựu với thành tựu giới uẩn này, nội tâm cảm thọ sự an lạc không có phạm lỗi.`, ref: "Tăng Chi Bộ 10.99", url: "https://loicuaducphat.org/an/an10.99.html#content" },
{ text: `Ba Sa-môn tưởng này, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, làm cho đầy đủ bảy pháp. Thế nào là bảy? Luôn luôn là người làm liên tục, thực hiện liên tục trong các Giới Luật; không có tham ái; không có sân; không có quá mạn, ưa thích học tập; đối với các vật dụng cần yếu cho đời sống, vị ấy nghĩ: “Ðây là mục đích sống tinh cần tinh tấn”. Này các Tỷ-kheo, có ba Sa-môn tưởng này tu tập, được làm cho sung mãn, làm cho đầy đủ bảy pháp.`, ref: "Tăng Chi Bộ 10.101", url: "https://loicuaducphat.org/an/an10.101.html#content" },

{ text: `Với người có chánh kiến, này các Tỷ-kheo, tà kiến bị tẩy sạch, và những pháp ác bất thiện nào do duyên tà kiến khởi lên, các pháp ấy của người ấy được tẩy sạch. Và các pháp thiện do duyên chánh kiến, đi đến viên mãn trong tu tập. Với người chánh tư duy, này các Tỷ-kheo, tà tư duy bị tẩy sạch... Với người chánh ngữ, này các Tỷ-kheo, tà ngữ được tẩy sạch..Với người chánh nghiệp, này các Tỷ-kheo, tà nghiệp được tẩy sạch... Với người chánh mạng, này các Tỷ-kheo, tà mạng được tẩy sạch... Với người chánh tinh tấn, này các Tỷ-kheo, tà tinh tấn được tẩy sạch... Với người chánh niệm, này các Tỷ-kheo, tà niệm được tẩy sạch... Với người chánh định, này các Tỷ-kheo, tà định được tẩy sạch... Với người chánh trí, này các Tỷ-kheo, tà trí được tẩy sạch... Với người chánh giải thoát, này các Tỷ-kheo, tà giải thoát được tẩy sạch và những pháp ác bất thiện do duyên tà giải thoát khởi lên, các pháp ấy của người ấy được tẩy sạch. Và các pháp thiện do duyên chánh giải thoát, đi đến viên mãn trong tu tập. Này các Tỷ-kheo, đây là Thánh tẩy trần ấy, tẩy trần này đưa đến nhất hướng nhàm chán, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn. Do duyên tẩy trần này nên các chúng sanh bị sanh được giải thoát khỏi sanh; những chúng sanh bị già được giải thoát khỏi già, những chúng sanh bị chết được giải thoát khỏi chết; những chúng sanh bị sầu, bi, khổ, ưu, não được giải thoát khỏi sầu, bi, khổ, ưu, não.`, ref: "Tăng Chi Bộ 10.107", url: "https://loicuaducphat.org/an/an10.107.html#content" },

{ text: `Ít người giữa nhân loại,\nÐến được bờ bên kia,\nCòn số người còn lại,\nXuôi ngược chạy bờ này.\nNhững ai hành trì pháp,\nTheo Chánh pháp khéo dạy,\nSẽ đến bờ bên kia,\nVượt ma giới khó thoát.\nKẻ trí bỏ pháp đen,\nTu tập theo pháp trắng,\nBỏ nhà, sống không nhà,\nSống viễn ly khổ lạc.\nHãy cầu vui Niết-bàn,\nBỏ dục, không chướng ngại,\nKẻ trí tự rửa sạch,\nCấu uế từ nội tâm.\nNhững ai với chánh tâm,\nKhéo tu tập giác chi,\nTừ bỏ mọi ái nhiễm\nHoan hỷ không chấp thủ,\nKhông lậu hoặc, sáng chói,\nSống tịch tịnh ở đời.`, ref: "Tăng Chi Bộ 10.117", url: "https://loicuaducphat.org/an/an10.117.html#content" },

{ text: `Khi mặt trời mọc, này các Tỷ-kheo, cái này là đi trước, cái này là tướng báo trước, tức là rạng đông. Cũng vậy, này các Tỷ-kheo, đối với các thiện pháp, cái này là đi trước, cái này là tướng trước, tức là chánh tri kiến. Từ chánh tri kiến, này các Tỷ-kheo, có chánh tư duy. Từ chánh tư duy, có chánh ngữ. Từ chánh ngữ, có chánh nghiệp. Từ chánh nghiệp, có chánh mạng. Từ chánh mạng, có chánh tinh tấn. Từ chánh tinh tấn, có chánh niệm. Từ chánh niệm, có chánh định. Từ chánh định, có chánh trí. Từ chánh trí, có chánh giải thoát.`, ref: "Tăng Chi Bộ 10.121", url: "https://loicuaducphat.org/an/an10.121.html#content" },

{ text: `Mười pháp này, này các Tỷ-kheo, thanh tịnh, trong sáng, chỉ có trong Luật của bậc Thiện Thệ. Thế nào là mười? Chánh tri kiến, chánh tư duy, chánh ngữ, chánh nghiệp, chánh mạng, chánh tinh tấn, chánh niệm, chánh định, chánh trí, chánh giải thoát. Mười pháp này, này các Tỷ-kheo, thanh tịnh, trong sáng, chỉ có trong Luật của bậc Thiện Thệ.`, ref: "Tăng Chi Bộ 10.123", url: "https://loicuaducphat.org/an/an10.123.html#content" },

{ text: `Này các Tỷ-kheo, Ta nói sát sanh có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói lấy của không cho có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói tà hạnh trong các dục có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói, nói láo có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói, nói hai lưỡi có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói, nói lời độc ác có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói, nói lời phù phiếm có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói, tham dục có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói, sân có ba: do nhân tham, do nhân sân, do nhân si. Này các Tỷ-kheo, Ta nói, tà kiến có ba: do nhân tham, do nhân sân, do nhân si. Như vậy, này các Tỷ-kheo, tham là nhân duyên cho nghiệp sanh khởi, sân là nhân duyên cho nghiệp sanh khởi, si là nhân duyên cho nghiệp sanh khởi, do tham đoạn diệt, là nhân duyên cho nghiệp đoạn diệt, do si đoạn diệt, là nhân duyên cho nghiệp đoạn diệt, do si đoạn diệt, là nhân duyên cho nghiệp đoạn diệt.`, ref: "Tăng Chi Bộ 10.174", url: "https://loicuaducphat.org/an/an10.174.html#content" },

{ text: `Này các Tỷ-kheo, từ tâm giải thoát được thực hành, được tu tập, được làm cho sung mãn, được tác thành cỗ xe, được tác thành căn cứ địa, được tiếp tục an trú, được tích tập, được khéo khởi sự thời được chờ đợi là mười một lợi ích. Thế nào là mười một? Ngủ an lạc, thức an lạc, không ác mộng, được loài người ái mộ, được phi nhân ái mộ, chư Thiên bảo hộ, không bị lửa, thuốc độc, kiếm xúc chạm, tâm được định mau chóng, sắc mặt trong sáng, mệnh chung không hôn ám; nếu chưa thể nhập thượng pháp (A-la-hán quả); được sanh lên Phạm thiên giới. Này các Tỷ-kheo, từ tâm giải thoát được thực hành, được tu tập, được làm cho sung mãn, được tác thành cỗ xe, được tác thành căn cứ địa, được tiếp tục an trú, được tích tập, được khéo khởi sự thời được chờ đợi là mười một lợi ích.`, ref: "Tăng Chi Bộ 11.15", url: "https://loicuaducphat.org/an/an11.15.html#content" },
      
                { text: `1. "Ý dẫn đầu các pháp,\nÝ làm chủ, ý tạo;\nNếu với ý ô nhiễm,\nNói lên hay hành động,\nKhổ não bước theo sau,\nNhư xe, chân vật kéo ".\n\n2. "Ý dẫn đầu các pháp,\nÝ làm chủ, ý tạo,\nNếu với ý thanh tịnh,\nNói lên hay hành động,\nAn lạc bước theo sau,\nNhư bóng, không rời hình ".`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `3. "Nó mắng tôi, đánh tôi,\nNó thắng tôi, cướp tôi "\nAi ôm hiềm hận ấy,\nHận thù không thể nguôi.\n\n4. "Nó mắng tôi, đánh tôi,\nNó thắng tôi, cướp tôi, "\nKhông ôm hiềm hận ấy,\nHận thù được tự nguôi.\n\n5. "Với hận diệt hận thù,\nÐời này không có được.\nKhông hận diệt hận thù,\nLà định luật ngàn thu ".\n\n6. "Người khác không hiểu biết,\nChúng ta đây bị hại.\nChỗ ấy, ai biết được\nTranh luận được lắng êm."\n\n201. "Chiến thắng sinh thù oán,\nThất bại chịu khổ đau,\nSống tịch tịnh an lạc.\nBỏ sau mọi thắng bại."`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `7. "Ai sống nhìn tịnh tướng,\nkhông hộ trì các căn,\năn uống thiếu tiết độ,\nbiếng nhác, chẳng tinh cần.\nMa uy hiếp kẻ ấy,\nnhư cây yếu trước gió ".\n\n8. "Ai sống quán bất tịnh,\nKhéo hộ trì các căn,\năn uống có tiết độ,\ncó lòng tin, tinh cần,\nMa không uy hiếp được,\nNhư núi đá, trước gió"`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `9. "Ai mặc áo cà sa,\ntâm chưa rời uế trược,\nkhông tự chế, không thực,\nkhông xứng áo cà sa ".\n\n10. "Ai rời bỏ uế trược,\ngiới luật khéo nghiêm trì,\ntự chế, sống chơn thực,\nthật xứng áo cà sa."`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `11. "Không chân, tưởng chân thật,\nChân thật, thấy không chân\nHọ không đạt chân thật\nDo tà tư tà hạnh."\n\n12 "Chân thật, biết chân thật,\nKhông chân, biết không chân.\nChúng đạt được chân thật,\ndo chánh tư, chánh hạnh."`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `13 "Như ngôi nhà vụng lợp,\nMưa liền xâm nhập vào.\nCũng vậy tâm không tu,\nTham dục liền xâm nhập."\n\n14 "Như ngôi nhà khéo lợp,\nMưa không xâm nhập vào.\nCũng vậy tâm khéo tu,\nTham dục không xâm nhập."`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `15 "Nay sầu, đời sau sầu,\nKẻ ác, hai đời sầu;\nNó sầu, nó ưu não,\nThấy nghiệp uế mình làm."\n\n16 "Nay vui, đời sau vui,\nLàm phước, hai đời vui.\nNgười ấy vui, an vui,\nThấy nghiệp tịnh mình làm."\n\n17 "Nay than, đời sau than,\nKẻ ác, hai đời than,\nthan rằng: "Ta làm ác "\nÐọa cõi dữ, than hơn."\n\n18. "Nay sướng, đời sau sướng,\nLàm phước, hai đời sướng.\nMừng rằng: "Ta làm thiện ",\nSanh cõi lành, sướng hơn."`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `19. "Nếu người nói nhiều kinh,\nKhông hành trì, phóng dật;\nNhư kẻ chăn bò người,\nKhông phần Sa môn hạnh."\n\n20. "Dầu nói ít kinh điển,\nNhưng hành pháp, tùy pháp,\nTừ bỏ tham, sân, si,\nTỉnh giác, tâm giải thoát,\nKhông chấp thủ hai đời,\nDự phần Sa môn hạnh."`, ref: "Kinh Pháp Cú 1-20", url: "https://loicuaducphat.org/dhp/dhp1-20.html#content" },

{ text: `21. "Không phóng dật, đường sống,\nPhóng dật là đường chết.\nKhông phóng dật, không chết,\nPhóng dật như chết rồi."\n\n22. "Biết rõ sai biệt ấy,\nNgười trí không phóng dật,\nHoan hỷ, không phóng dật,\nAn vui hạnh bậc Thánh."\n\n23. "Người hằng tu thiền định,\nThường kiên trì tinh tấn.\nBậc trí hưởng Niết Bàn,\nÁch an tịnh vô thượng."\n\n24. "Nỗ lực, giữ chánh niệm,\nTịnh hạnh, hành thận trọng\nTự điều, sống theo pháp,\nAi sống không phóng dật,\nTiếng lành ngày tăng trưởng."\n\n25. "Nỗ lực, không phóng dật,\nTự điều, khéo chế ngự.\nBậc trí xây hòn đảo,\nNước lụt khó ngập tràn."`, ref: "Kinh Pháp Cú 21-32", url: "https://loicuaducphat.org/dhp/dhp21-32.html#content" },

{ text: `26. "Họ ngu si thiếu trí,\nChuyên sống đời phóng dật.\nNgười trí, không phóng dật,\nNhư giữ tài sản quý."\n\n27. "Chớ sống đời phóng dật,\nChớ mê say dục lạc.\nKhông phóng dật, thiền định,\nÐạt được an lạc lớn."\n\n28. "Người trí dẹp phóng dật,\nVới hạnh không phóng dật,\nLeo lầu cao trí tuệ,\nKhông sầu, nhìn khổ sầu,\nBậc trí đứng núi cao,\nNhìn kẻ ngu, đất bằng."\n\n29. "Tinh cần giữa phóng dật,\nTỉnh thức giữa quần mê.\nNgười trí như ngựa phi,\nBỏ sau con ngựa hèn."\n\n31. "Vui thích không phóng dật,\nTỷ kheo sợ phóng dật,\nBước tới như lửa hừng,\nThiêu kiết sử lớn nhỏ."\n\n32. "Vui thích không phóng dật,\nTỷ kheo sợ phóng dật,\nKhông thể bị thối đọa,\nNhất định gần Niết Bàn."`, ref: "Kinh Pháp Cú 21-32", url: "https://loicuaducphat.org/dhp/dhp21-32.html#content" },

{ text: `33. "Tâm hoảng hốt giao động,\nKhó hộ trì, khó nhiếp,\nNgười trí làm tâm thẳng,\nNhư thợ tên, làm tên."\n\n34. "Như cá quăng trên bờ,\nVất ra ngoài thủy giới;\nTâm này vũng vẫy mạnh,\nHãy đoạn thế lực Ma."\n\n35. "Khó nắm giữ, khinh động,\nTheo các dục quay cuồng.\nLành thay, điều phục tâm;\nTâm điều, an lạc đến."\n\n36. "Tâm khó thấy, tế nhị,\nTheo các dục quay cuồng.\nNgười trí phòng hộ tâm,\nTâm hộ, an lạc đến."`, ref: "Kinh Pháp Cú 33-43", url: "https://loicuaducphat.org/dhp/dhp33-43.html#content" },

{ text: `37. "Chạy xa, sống một mình,\nKhông thân, ẩn hang sâu\nAi điều phục được tâm,\nThoát khỏi Ma trói buộc"\n\n38. "Ai tâm không an trú,\nKhông biết chân diệu pháp,\nTịnh tín bị rúng động,\nTrí tuệ không viên thành."\n\n39. "Tâm không đầy tràn dục,\nTâm không (hận) công phá,\nÐoạn tuyệt mọi thiện ác,\nKẻ tỉnh không sợ hãi,"\n\n42. "Kẻ thù hại kẻ thù,\nOan gia hại oan gia,\nKhông bằng tâm hướng tà,\nGây ác cho tự thân."\n\n43. "Ðiều mẹ cha bà con,\nKhông có thể làm được\nTâm hướng chánh làm được\nLàm được tốt đẹp hơn."`, ref: "Kinh Pháp Cú 33-43", url: "https://loicuaducphat.org/dhp/dhp33-43.html#content" },

{ text: `40. "Biết thân như đồ gốm,\nTrú tâm như thành trì,\nChống ma với gươm trí;\nGiữ chiến thắng không tham"\n\n41 "Không bao lâu thân này,\nSẽ nằm dài trên đất,\nBị vất bỏ, vô thức,\nNhư khúc cây vô dụng."`, ref: "Kinh Pháp Cú 33-43", url: "https://loicuaducphat.org/dhp/dhp33-43.html#content" },

{ text: `46. "Biết thân như bọt nước,\nNgộ thân là như huyễn,\nBẻ tên hoa của ma,\nVượt tầm mắt thần chết."\n\n47. "Người nhặt các loại hoa,\nÝ đắm say, tham nhiễm,\nBị thần chết mang đi,\nNhư lụt trôi làng ngủ."\n\n48. "Người nhặt các loại hoa,\nÝ đắm say tham nhiễm,\nCác dục chưa thỏa mãn,\nÐã bị chết chinh phục."`, ref: "Kinh Pháp Cú 44-59", url: "https://loicuaducphat.org/dhp/dhp44-59.html#content" },

{ text: `54. "Hương các loại hoa thơm\nKhông ngược bay chiều gió\nNhưng hương người đức hạnh\nNgược gió khắp tung bay\nChỉ có bậc chân nhân\nTỏa khắp mọi phương trời."\n\n55. "Hoa chiên đàn, già la,\nHoa sen, hoa vũ quý,\nGiữa những hương hoa ấy,\nGiới hương là vô thượng."\n\n56. "Ít giá trị hương này,\nHương già la, chiên đàn;\nChỉ hương người đức hạnh,\nTối thượng tỏa Thiên giới."\n\n57. "Nhưng ai có giới hạnh,\nAn trú không phóng dật,\nChánh trí, chơn giải thoát,\nÁc ma không thấy đường."`, ref: "Kinh Pháp Cú 44-59", url: "https://loicuaducphat.org/dhp/dhp44-59.html#content" },

{ text: `58. "Như giữa đống rác nhớp,\nQuăng bỏ trên đường lớn,\nChỗ ấy hoa sen nở,\nThơm sạch, đẹp ý người."\n\n59. "Cũng vậy giữa quần sanh,\nUế nhiễm, mù, phàm tục,\nÐệ tử bậc Chánh Giác,\nSáng ngời với Tuệ Trí."`, ref: "Kinh Pháp Cú 44-59", url: "https://loicuaducphat.org/dhp/dhp44-59.html#content" },

{ text: `51. "Như bông hoa tươi đẹp,\nCó sắc nhưng không hương.\nCũng vậy, lời khéo nói,\nKhông làm, không kết quả."\n\n52. "Như bông hoa tươi đẹp,\nCó sắc lại thêm hương;\nCũng vậy, lời khéo nói,\nCó làm, có kết quả."\n\n53. "Như từ một đống hoa,\nNhiều tràng hoa được làm.\nCũng vậy, thân sanh tử,\nPhải làm nhiều việc lành."`, ref: "Kinh Pháp Cú 44-59", url: "https://loicuaducphat.org/dhp/dhp44-59.html#content" },

{ text: `60. "Ðêm dài cho kẻ thức,\nÐường dài cho kẻ mệt,\nLuân hồi dài, kẻ ngu,\nKhông biết chơn diệu pháp."\n\n61. "Tìm không được bạn đường,\nHơn mình hay bằng mình,\nThà quyết sống một mình,\nKhông bè bạn kẻ ngu."`, ref: "Kinh Pháp Cú 60-75", url: "https://loicuaducphat.org/dhp/dhp60-75.html#content" },

{ text: `62. "Con tôi, tài sản tôi,\nNgười ngu sanh ưu não,\nTự ta, ta không có,\nCon đâu, tài sản đâu."\n\n63. "Người ngu nghĩ mình ngu,\nNhờ vậy thành có trí.\nNgười ngu tưởng có trí,\nThật xứng gọi chí ngu."\n\n64. "Người ngu, dầu trọn đời,\nThân cận người có trí,\nKhông biết được Chánh pháp,\nNhư muỗng với vị canh."\n\n65. "Người trí, dầu một khắc,\nThân cận người có trí,\nBiết ngay chân diệu pháp,\nNhư lưỡi với vị canh."`, ref: "Kinh Pháp Cú 60-75", url: "https://loicuaducphat.org/dhp/dhp60-75.html#content" },

{ text: `66. "Người ngu si thiếu trí,\nTự ngã thành kẻ thù.\nLàm các nghiệp không thiện,\nPhải chịu quả đắng cay."\n\n67. "Nghiệp làm không chánh thiện,\nLàm rồi sanh ăn năn,\nMặt nhuốm lệ, khóc than,\nLãnh chịu quả dị thục."\n\n68. "Và nghiệp làm chánh thiện,\nLàm rồi không ăn năn,\nHoan hỷ, ý đẹp lòng,\nHưởng thọ quả dị thục."\n\n69. "Người ngu nghĩ là ngọt,\nKhi ác chưa chín muồi;\nÁc nghiệp chín muồi rồi,\nNgười ngu chịu khổ đau."\n\n71. "Nghiệp ác đã được làm,\nNhư sữa, không đông ngay,\nCháy ngầm theo kẻ ngu,\nNhư lửa tro che đậy."`, ref: "Kinh Pháp Cú 60-75", url: "https://loicuaducphat.org/dhp/dhp60-75.html#content" },

{ text: `72. "Tự nó chịu bất hạnh,\nKhi danh đến kẻ ngu.\nVận may bị tổn hại,\nÐầu nó bị nát tan."\n\n73. "Ưa danh không tương xứng,\nMuốn ngồi trước tỷ kheo,\nƯa quyền tại tịnh xá,\nMuốn mọi người lễ kính."\n\n74. "Mong cả hai tăng, tục,\nNghĩ rằng (chính ta làm).\nTrong mọi việc lớn nhỏ,\nPhải theo mệnh lệnh ta "\nNgười ngu nghĩ như vậy\nDục và mạn tăng trưởng.\n\n75. "Khác thay duyên thế lợi,\nKhác thay đường Niết Bàn.\nTỷ kheo, đệ tử Phật,\nHãy như vậy thắng tri.\nChớ ưa thích cung kính,\nHãy tu hạnh viễn ly."`, ref: "Kinh Pháp Cú 60-75", url: "https://loicuaducphat.org/dhp/dhp60-75.html#content" },

{ text: `76. "Nếu thấy bậc hiền trí,\nChỉ lỗi và khiển trách,\nNhư chỉ chỗ chôn vàng\nHãy thân cận người trí!\nThân cận người như vậy,\nChỉ tốt hơn, không xấu."\n\n77. "Những người hay khuyên dạy,\nNgăn người khác làm ác,\nÐược người hiền kính yêu,\nBị người ác không thích."\n\n78. "Chớ thân với bạn ác,\nChớ thân kẻ tiểu nhân.\nHãy thân người bạn lành,\nHãy thân bậc thượng nhân."\n\n79. "Pháp hỷ đem an lạc,\nVới tâm tư thuần tịnh;\nNgười trí thường hoan hỷ,\nVới pháp bậc Thánh thuyết."`, ref: "Kinh Pháp Cú 76-89", url: "https://loicuaducphat.org/dhp/dhp76-89.html#content" },

{ text: `80. "Người trị thủy dẫn nước,\nKẻ làm tên nắn tên,\nNgười thợ mộc uốn gỗ,\nBậc trí nhiếp tự thân."\n\n81. "Như đá tảng kiên cố,\nKhông gió nào giao động,\nCũng vậy, giữa khen chê,\nNgười trí không giao động."\n\n82. "Như hồ nước sâu thẳm,\nTrong sáng, không khuấy đục,\nCũng vậy, nghe chánh pháp,\nNgười trí hưởng tịnh lạc."\n\n83. "Người hiền bỏ tất cả,\nNgười lành không bàn dục,\nDầu cảm thọ lạc khổ,\nBậc trí không vui buồn."`, ref: "Kinh Pháp Cú 76-89", url: "https://loicuaducphat.org/dhp/dhp76-89.html#content" },

{ text: `84. "Không vì mình, vì người.\nKhông cầu được con cái,\nKhông tài sản quốc độ,\nKhông cầu mình thành tựu,\nVới việc làm phi pháp.\nVị ấy thật trì giới,\nCó trí tuệ, đúng pháp."\n\n85. "Ít người giữa nhân loại,\nÐến được bờ bên kia\nCòn số người còn lại,\nXuôi ngược chạy bờ này."\n\n86. "Những ai hành trì pháp,\nTheo chánh pháp khéo dạy,\nSẽ đến bờ bên kia,\nVượt ma lực khó thoát."`, ref: "Kinh Pháp Cú 76-89", url: "https://loicuaducphat.org/dhp/dhp76-89.html#content" },

{ text: `87. "Kẻ trí bỏ pháp đen,\nTu tập theo pháp trắng.\nBỏ nhà, sống không nhà,\nSống viễn ly khổ lạc."\n\n88. "Hãy cầu vui Niết Bàn,\nBỏ dục, không sở hữu,\nKẻ trí tự rửa sạch,\nCấu uế từ nội tâm."\n\n89. "Những ai với chánh tâm,\nKhéo tu tập giác chi,\nTừ bỏ mọi ái nhiễm,\nHoan hỷ không chấp thủ.\nKhông lậu hoặc, sáng chói,\nSống tịch tịnh ở đời."`, ref: "Kinh Pháp Cú 76-89", url: "https://loicuaducphat.org/dhp/dhp76-89.html#content" },

{ text: `90. "Ðích đã đến, không sầu,\nGiải thoát ngoài tất cả,\nÐoạn trừ mọi buộc ràng,\nVị ấy không nhiệt não."\n\n91. "Tự sách tấn, chánh niệm,\nKhông thích cư xá nào,\nNhư ngỗng trời rời ao,\nBỏ sau mọi trú ẩn."\n\n92. "Tài sản không chất chứa,\nĂn uống biết liễu tri,\nTự tại trong hành xứ,\n"Không vô tướng, giải thoát, "\nNhư chim giữa hư không,\nHướng chúng đi khó tìm."\n\n93. "Ai lậu hoặc đoạn sạch,\nĂn uống không tham đắm,\nTự tại trong hành xứ,\n"Không, vô tướng giải thoát. "\nNhư chim giữa hư không,\nDấu chân thật khó tìm. "`, ref: "Kinh Pháp Cú 90-99", url: "https://loicuaducphat.org/dhp/dhp90-99.html#content" },

{ text: `94. "Ai nhiếp phục các căn,\nNhư đánh xe điều ngự,\nMạn trừ, lậu hoặc dứt,\nNgười vậy, Chư Thiên mến."\n\n95. "Như đất, không hiềm hận,\nNhư cột trụ, kiên trì,\nNhư hồ, không bùn nhơ,\nKhông luân hồi, vị ấy."\n\n96. "Người tâm ý an tịnh,\nLời an, nghiệp cũng an,\nChánh trí, chơn giải thoát,\nTịnh lạc là vị ấy."\n\n98. "Làng mạc hay rừng núi\nThung lũng hay đồi cao,\nLa Hán trú chỗ nào,\nÐất ấy thật khả ái ".\n\n99. "Khả ái thay núi rừng,\nChỗ người phàm không ưa,\nVị ly tham ưa thích,\nVì không tìm dục lạc."`, ref: "Kinh Pháp Cú 90-99", url: "https://loicuaducphat.org/dhp/dhp90-99.html#content" },

{ text: `100. "Dầu nói ngàn ngàn lời,\nNhưng không gì lợi ích,\nTốt hơn một câu nghĩa,\nNghe xong, được tịnh lạc."\n\n101. "Dầu nói ngàn câu kệ\nNhưng không gì lợi ích,\nTốt hơn nói một câu,\nNghe xong, được tịnh lạc."\n\n102 "Dầu nói trăm câu kệ\nNhưng không gì lợi ích,\nTốt hơn một câu pháp,\nNghe xong, được tịnh lạc."`, ref: "Kinh Pháp Cú 100-115", url: "https://loicuaducphat.org/dhp/dhp100-115.html#content" },

{ text: `103. "Dầu tại bãi chiến trường\nThắng ngàn ngàn quân địch,\nTự thắng mình tốt hơn,\nThật chiến thắng tối thượng."\n\n104. "Tự thắng, tốt đẹp hơn,\nHơn chiến thắng người khác.\nNgười khéo điều phục mình,\nThường sống tự chế ngự."\n\n105. "Dầu Thiên Thần, Thát Bà,\nDầu Ma vương, Phạm Thiên\nKhông ai chiến thắng nổi,\nNgười tự thắng như vậy."`, ref: "Kinh Pháp Cú 100-115", url: "https://loicuaducphat.org/dhp/dhp100-115.html#content" },

{ text: `106. "Tháng tháng bỏ ngàn vàng,\nTế tự cả trăm năm,\nChẳng bằng trong giây lát,\nCúng dường bậc tự tu.\nCùng dường vậy tốt hơn,\nHơn trăm năm tế tự."\n\n107. "Dầu trải một trăm năm,\nThờ lửa tại rừng sâu,\nChẳng bằng trong giây lát,\nCúng dường bậc tự tu.\nCúng dường vậy tốt hơn,\nHơn trăm năm tế tự."\n\n108. "Suốt năm cúng tế vật,\nÐể cầu phước ở đời.\nKhông bằng một phần tư\nKính lễ bậc chánh trực."\n\n109. "Thường tôn trọng, kính lễ\nBậc kỳ lão trưởng thượng,\nBốn pháp được tăng trưởng:\nThọ, sắc, lạc, sức mạnh."`, ref: "Kinh Pháp Cú 100-115", url: "https://loicuaducphat.org/dhp/dhp100-115.html#content" },

{ text: `110. "Dầu sống một trăm năm\nÁc giới, không thiền định,\nTốt hơn sống một ngày,\nTrì giới, tu thiền định."\n\n111. "Ai sống một trăm năm,\nÁc tuệ, không thiền định.\nTốt hơn sống một ngày,\nCó tuệ, tu thiền định."\n\n112 "Ai sống một trăm năm,\nLười nhác không tinh tấn,\nTốt hơn sống một ngày\nTinh tấn tận sức mình."\n\n113. "Ai sống một trăm năm,\nKhông thấy pháp sinh diệt,\nTốt hơn sống một ngày,\nThấy được pháp sinh diệt."\n\n114. "Ai sống một trăm năm,\nKhông thấy câu bất tử,\nTốt hơn sống một ngày,\nThấy được câu bất tử."\n\n115. "Ai sống một trăm năm,\nKhông thấy pháp tối thượng,\nTốt hơn sống một ngày,\nThấy được pháp tối thượng."`, ref: "Kinh Pháp Cú 100-115", url: "https://loicuaducphat.org/dhp/dhp100-115.html#content" },

{ text: `116. "Hãy gấp làm điều lành,\nNgăn tâm làm điều ác.\nAi chậm làm việc lành,\nÝ ưa thích việc ác."\n\n117. "Nếu người làm điều ác,\nChớ tiếp tục làm thêm.\nChớ ước muốn điều ác,\nChứa ác, tất chịu khổ."\n\n118. "Nếu người làm điều thiện,\nNên tiếp tục làm thêm.\nHãy ước muốn điều thiện,\nChứa thiện, được an lạc."`, ref: "Kinh Pháp Cú 116-128", url: "https://loicuaducphat.org/dhp/dhp116-128.html#content" },

{ text: `119. "Người ác thấy là hiền.\nKhi ác chưa chín muồi,\nKhi ác nghiệp chín muồi,\nNgười ác mới thấy ác."\n\n121. "Chớ chê khinh điều ác,\nCho rằng "chưa đến mình ",\nNhư nước nhỏ từng giọt,\nRồi bình cũng đầy tràn.\nNgười ngu chứa đầy ác\nDo chất chứa dần dần."\n\n122. "Chớ chê khinh điều thiện\nCho rằng "Chưa đến mình, "\nNhư nước nhỏ từng giọt,\nRồi bình cũng đầy tràn.\nNgười trí chứa đầy thiện,\nDo chất chứa dần dần."`, ref: "Kinh Pháp Cú 116-128", url: "https://loicuaducphat.org/dhp/dhp116-128.html#content" },

{ text: `123. "Ít bạn đường, nhiều tiền,\nNgười buôn tránh đường hiểm.\nMuốn sống, tránh thuốc độc,\nHãy tránh ác như vậy."\n\n124. "Bàn tay không thương tích,\nCó thể cầm thuốc độc.\nKhông thương tích, tránh độc,\nKhông làm, không có ác."`, ref: "Kinh Pháp Cú 116-128", url: "https://loicuaducphat.org/dhp/dhp116-128.html#content" },

{ text: `125. "Hại người không ác tâm,\nNgười thanh tịnh, không uế,\nTội ác đến kẻ ngu,\nNhư ngược gió tung bụi."\n\n126. "Một số sinh bào thai,\nKẻ ác sinh địa ngục,\nNgười thiện lên cõi trời,\nVô lậu chứng Niết Bàn."\n\n127. "Không trên trời, giữa biển,\nKhông lánh vào động núi,\nKhông chỗ nào trên đời,\nTrốn được quả ác nghiệp."\n\n128. "Không trên trời, giữa biển,\nKhông lánh vào động núi,\nKhông chỗ nào trên đời,\nTrốn khỏi tay thần chết."`, ref: "Kinh Pháp Cú 116-128", url: "https://loicuaducphat.org/dhp/dhp116-128.html#content" },

{ text: `129. "Mọi người sợ hình phạt,\nMọi người sợ tử vong.\nLấy mình làm ví dụ\nKhông giết, không bảo giết."\n\n130. "Mọi người sợ hình phạt,\nMọi người thích sống còn;\nLấy mình làm ví dụ,\nKhông giết, không bảo giết."\n\n131. "Chúng sanh cầu an lạc,\nAi dùng trượng hại người,\nÐể tìm lạc cho mình,\nÐời sau không được lạc."\n\n132. "Chúng sanh cầu an lạc,\nKhông dùng trượng hại người,\nÐể tìm lạc cho mình,\nÐời sau được hưởng lạc."`, ref: "Kinh Pháp Cú 129-145", url: "https://loicuaducphat.org/dhp/dhp129-145.html#content" },

{ text: `133. "Chớ nói lời ác độc,\nNói ác, bị nói lại,\nKhổ thay lời phẫn nộ,\nÐao trượng phản chạm mình."\n\n134. "Nếu tự mình yên lặng,\nNhư chiếc chuông bị bể.\nNgươi đã chứng Niết Bàn\nNgươi không còn phẫn nộ."\n\n135. "Với gậy người chăn bò,\nLùa bò ra bãi cỏ;\nCũng vậy, già và chết,\nLùa người đến mạng chung."\n\n136. "Người ngu làm điều ác,\nKhông ý thức việc làm.\nDo tự nghiệp, người ngu\nBị nung nấu, như lửa."`, ref: "Kinh Pháp Cú 129-145", url: "https://loicuaducphat.org/dhp/dhp129-145.html#content" },

{ text: `141. "Không phải sống lõa thể\nBện tóc, tro trét mình,\nTuyệt thực, lăn trên đất,\nSống nhớp, siêng ngồi xổm,\nLàm con người được sạch,\nNếu không trừ nghi hoặc."\n\n142 "Ai sống tự trang sức,\nNhưng an tịnh, nhiếp phục,\nSống kiên trì, phạm hạnh,\nKhông hại mọi sinh linh,\nVị ấy là phạm chí,\nHay sa môn, khất sĩ."`, ref: "Kinh Pháp Cú 129-145", url: "https://loicuaducphat.org/dhp/dhp129-145.html#content" },

{ text: `143. "Thật khó tìm ở đời,\nNgười biết thẹn, tự chế,\nBiết tránh né chỉ trích\nNhư ngựa hiền tránh roi."\n\n144. "Như ngựa hiền chạm roi,\nHãy nhiệt tâm, hăng hái,\nVới tín, giới, tinh tấn,\nThiền định cùng trạch pháp.\nMinh hạnh đủ, chánh niệm,\nÐoạn khổ này vô lượng."\n\n145. "Người trị thủy dẫn nước,\nKẻ làm tên nắn tên,\nNgười thợ mộc uốn ván,\nBậc tự điều, điều thân."`, ref: "Kinh Pháp Cú 129-145", url: "https://loicuaducphat.org/dhp/dhp129-145.html#content" },

{ text: `146. "Cười gì, hân hoan gì,\nKhi đời mãi bị thiêu?\nBị tối tăm bao trùm,\nSao không tìm ngọn đèn?"\n\n147. "Hãy xem bong bóng đẹp,\nChỗ chất chứa vết thương,\nBệnh hoạn nhiều suy tư,\nThật không gì trường cửu."\n\n148. "Sắc này bị suy già,\nỔ tật bệnh, mỏng manh,\nNhóm bất tịnh, đỗ vỡ,\nChết chấm dứt mạng sống."\n\n149. "Như trái bầu mùa thu,\nBị vất bỏ quăng đi,\nNhóm xương trắng bồ câu,\nThấy chúng còn vui gì?"`, ref: "Kinh Pháp Cú 146-156", url: "https://loicuaducphat.org/dhp/dhp146-156.html#content" },

{ text: `150. "Thành này làm bằng xương,\nQuét tô bằng thịt máu,\nỞ đây già và chết,\nMạn, lừa đảo chất chứa."\n\n151. "Xe vua đẹp cũng già.\nThân này rồi sẽ già,\nPháp bậc thiện, không già.\nNhư vậy bậc chí thiện\nNói lên cho bậc thiện."\n\n152. "Người ít nghe kém học,\nLớn già như trâu đực.\nThịt nó tuy lớn lên,\nNhưng tuệ không tăng trưởng."`, ref: "Kinh Pháp Cú 146-156", url: "https://loicuaducphat.org/dhp/dhp146-156.html#content" },

{ text: `153. "Lang thang bao kiếp sống\nTa tìm nhưng chẳng gặp,\nNgười xây dựng nhà này,\nKhổ thay, phải tái sanh."\n\n154. "Ôi! Người làm nhà kia\nNay ta đã thấy ngươi!\nNgươi không làm nhà nữa.\nÐòn tay ngươi bị gẫy,\nKèo cột ngươi bị tan\nTâm ta đạt tịch diệt,\nTham ái thảy tiêu vong."`, ref: "Kinh Pháp Cú 146-156", url: "https://loicuaducphat.org/dhp/dhp146-156.html#content" },

{ text: `155. "Lúc trẻ, không phạm hạnh,\nKhông tìm kiếm bạc tiền.\nNhư cò già bên ao,\nỦ rũ, không tôm cá."\n\n156. "Lúc trẻ không phạm hạnh,\nKhông tìm kiếm bạc tiền;\nNhư cây cung bị gẫy,\nThở than những ngày qua."`, ref: "Kinh Pháp Cú 146-156", url: "https://loicuaducphat.org/dhp/dhp146-156.html#content" },

{ text: `157. "Nếu biết yêu tự ngã,\nPhải khéo bảo vệ mình,\nNgười trí trong ba canh,\nPhải luôn luôn tỉnh thức."\n\n158. "Trước hết tự đặt mình,\nVào những gì thích đáng.\nSau mới giáo hóa người,\nNgười trí khỏi bị nhiễm."\n\n159. "Hãy tự làm cho mình,\nNhư điều mình dạy người.\nKhéo tự điều, điều người,\nKhó thay, tự điều phục!"\n\n160. "Tự mình y chỉ mình,\nNào có y chỉ khác.\nNhờ khéo điều phục mình,\nÐược y chỉ khó được."`, ref: "Kinh Pháp Cú 157-166", url: "https://loicuaducphat.org/dhp/dhp157-166.html#content" },

{ text: `161. "Ðiều ác tự mình làm,\nTự mình sanh, mình tạo.\nNghiền nát kẻ ngu si,\nNhư kim cương, ngọc báu."\n\n162. "Phá giới quá trầm trọng,\nNhư dây leo bám cây\nGieo hại cho tự thân,\nNhư kẻ thù mong ước."\n\n163. "Dễ làm các điều ác,\nDễ làm tự hại mình.\nCòn việc lành, việc tốt,\nThật tối thượng khó làm."`, ref: "Kinh Pháp Cú 157-166", url: "https://loicuaducphat.org/dhp/dhp157-166.html#content" },

{ text: `165. "Tự mình, làm điều ác,\nTự mình làm nhiễm ô,\nTự mình không làm ác,\nTự mình làm thanh tịnh.\nTịnh, không tịnh tự mình,\nKhông ai thanh tịnh ai!"\n\n166. "Chớ theo pháp hạ liệt.\nChớ sống mặc, buông lung;\nChớ tin theo tà kiến,\nChớ tăng trưởng tục trần."`, ref: "Kinh Pháp Cú 157-166", url: "https://loicuaducphat.org/dhp/dhp157-166.html#content" },

{ text: `168. "Nỗ lực, chớ phóng dật!\nHãy sống theo chánh hạnh;\nNgười chánh hạnh hưởng lạc,\nCả đời này, đời sau."\n\n169. "Hãy khéo sống chánh hạnh,\nChớ sống theo tà hạnh!\nNgười chánh hạnh hưởng lạc,\nCả đời này, đời sau."\n\n170. "Hãy nhìn như bọt nước,\nHãy nhìn như cảnh huyễn!\nQuán nhìn đời như vậy,\nThần chết không bắt gặp."\n\n171. "Hãy đến nhìn đời này,\nNhư xe vua lộng lẫy,\nNgười ngu mới tham đắm,\nKẻ trí nào đắm say."`, ref: "Kinh Pháp Cú 167-178", url: "https://loicuaducphat.org/dhp/dhp167-178.html#content" },

{ text: `172. "Ai sống trước buông lung,\nSau sống không phóng dật,\nChói sáng rực đời này.\nNhư trăng thoát mây che."\n\n173. "Ai dùng các hạnh lành,\nLàm xóa mờ nghiệp ác,\nChói sáng rực đời này,\nNhư trăng thoát mây che."\n\n174. "Ðời này thật mù quáng,\nÍt kẻ thấy rõ ràng.\nNhư chim thoát khỏi lưới,\nRất ít đi thiên giới."\n\n175. "Như chim thiên nga bay,\nThần thông liệng giữa trời;\nChiến thắng ma, ma quân,\nKẻ trí thoát đời này."`, ref: "Kinh Pháp Cú 167-178", url: "https://loicuaducphat.org/dhp/dhp167-178.html#content" },

{ text: `176. "Ai vi phạm một pháp,\nAi nói lời vọng ngữ,\nAi bác bỏ đời sau,\nKhông ác nào không làm."\n\n177. "Keo kiết không sanh thiên,\nKẻ ngu ghét bố thí,\nNgười trí thích bố thí,\nÐời sau, được hưởng lạc."\n\n178. "Hơn thống lãnh cõi đất,\nHơn được sanh cõi trời,\nHơn chủ trì vũ trụ,\nQuả Dự Lưu tối thắng."`, ref: "Kinh Pháp Cú 167-178", url: "https://loicuaducphat.org/dhp/dhp167-178.html#content" },

{ text: `179. "Vị chiến thắng không bại,\nVị bước đi trên đời,\nKhông dấu tích chiến thắng,\nPhật giới rộng mênh mông,\nAi dùng chân theo dõi\nBậc không để dấu tích?"\n\n180. "Ai giải tỏa lưới tham,\nÁi phược hết dắt dẫn,\nPhật giới rộng mênh mông,\nAi dùng chân theo dõi,\nBậc không để dấu tích?"\n\n181. "Người trí chuyên thiền định,\nThích an tịnh viễn ly,\nChư thiên đều ái kính,\nBậc chánh giác, chánh niệm."`, ref: "Kinh Pháp Cú 179-196", url: "https://loicuaducphat.org/dhp/dhp179-196.html#content" },

{ text: `182. "Khó thay, được làm người,\nKhó thay, được sống còn,\nKhó thay, nghe diệu pháp,\nKhó thay, Phật ra đời!"\n\n183. "Không làm mọi điều ác.\nThành tựu các hạnh lành,\nTâm ý giữ trong sạch,\nChính lời chư Phật dạy."\n\n184. "Chư Phật thường giảng dạy;\nNhẫn, khổ hạnh tối thượng,\nNiết bàn, quả tối thượng;\nXuất gia không phá người;\nSa môn không hại người."\n\n185. "Không phỉ báng, phá hoại,\nHộ trì giới căn bản,\nĂn uống có tiết độ,\nSàng tọa chỗ nhàn tịnh\nChuyên chú tăng thượng tâm,\nChính lời chư Phật dạy."`, ref: "Kinh Pháp Cú 179-196", url: "https://loicuaducphat.org/dhp/dhp179-196.html#content" },

{ text: `186. "Dầu mưa bằng tiền vàng,\nCác dục khó thỏa mãn.\nDục đắng nhiều ngọt ít,\nBiết vậy là bậc trí."\n\n187. "Ðệ tử bậc chánh giác,\nKhông tìm cầu dục lạc,\nDầu là dục chư thiên,\nChỉ ưa thích ái diệt."`, ref: "Kinh Pháp Cú 179-196", url: "https://loicuaducphat.org/dhp/dhp179-196.html#content" },

{ text: `188. "Loài người sợ hoảng hốt,\nTìm nhiều chỗ quy y,\nHoặc rừng rậm, núi non,\nHoặc vườn cây, đền tháp."\n\n189. "Quy y ấy không ổn,\nKhông quy y tối thượng.\nQuy y các chỗ ấy,\nKhông thoát mọi khổ đau?"\n\n190. "Ai quy y Ðức Phật,\nChánh pháp và chư tăng,\nAi dùng chánh tri kiến,\nThấy được bốn Thánh đế."\n\n191. "Thấy khổ và khổ tập,\nThấy sự khổ vượt qua,\nThấy đường Thánh tám ngành,\nÐưa đến khổ não tận."\n\n192. "Thật quy y an ổn,\nThật quy y tối thượng,\nCó quy y như vậy,\nMới thoát mọi khổ đau."`, ref: "Kinh Pháp Cú 179-196", url: "https://loicuaducphat.org/dhp/dhp179-196.html#content" },

{ text: `193. "Khó gặp bậc thánh nhơn,\nKhông phải đâu cũng có.\nChỗ nào bậc trí sanh,\nGia đình tất an lạc."\n\n194. "Vui thay, Phật ra đời!\nVui thay, Pháp được giảng!\nVui thay, Tăng hòa hợp!\nHòa hợp tu, vui thay!"\n\n195. "Cúng dường bậc đáng cúng,\nChư Phật hoặc đệ tử,\nCác bậc vượt hý luận,\nÐoạn diệt mọi sầu bi."\n\n196. "Cúng dường bậc như vậy,\nTịch tịnh, không sợ hãi,\nCác công đức như vậy,\nKhông ai ước lường được."`, ref: "Kinh Pháp Cú 179-196", url: "https://loicuaducphat.org/dhp/dhp179-196.html#content" },

{ text: `197. "Vui thay, chúng ta sống,\nKhông hận, giữa hận thù!\nGiữa những người thù hận,\nTa sống, không hận thù!"\n\n198. "Vui thay, chúng ta sống,\nKhông bệnh, giữa ốm đau!\nGiữa những người bệnh hoạn,\nTa sống, không ốm đau."\n\n199. "Vui thay, chúng ta sống,\nKhông rộn giữa rộn ràng;\nGiữa những người rộn ràng,\nTa sống, không rộn ràng."\n\n200. "Vui thay chúng ta sống,\nKhông gì, gọi của ta.\nTa sẽ hưởng hỷ lạc,\nNhư chư thiên Quang Âm."`, ref: "Kinh Pháp Cú 197-208", url: "https://loicuaducphat.org/dhp/dhp197-208.html#content" },

{ text: `202. "Lửa nào sánh lửa tham?\nÁc nào bằng sân hận?\nKhổ nào sánh khổ uẩn,\nLạc nào bằng tịnh lạc."\n\n203. "Ðói ăn, bệnh tối thượng,\nCác hành, khổ tối thượng,\nHiểu như thực là vậy,\nNiết Bàn, lạc tối thượng."\n\n204 "Không bệnh, lợi tối thượng,\nBiết đủ, tiền tối thượng,\nThành tín đối với nhau,\nLà bà con tối thượng.\nNiết Bàn, lạc tối thượng."\n\n205. "Ðã nếm vị độc cư,\nÐược hưởng vị nhàn tịnh,\nKhông sợ hãi, không ác,\nNếm được vị pháp hỷ."`, ref: "Kinh Pháp Cú 197-208", url: "https://loicuaducphat.org/dhp/dhp197-208.html#content" },

{ text: `206. "Lành thay, thấy thánh nhân,\nSống chung thường hưởng lạc.\nKhông thấy những người ngu,\nThường thường được an lạc."\n\n207. "Sống chung với người ngu,\nLâu dài bị lo buồn.\nKhổ thay gần người ngu,\nNhư thường sống kẻ thù.\nVui thay, gần người trí,\nNhư chung sống bà con."\n\n208. "Bậc hiền sĩ, trí tuệ\nBậc nghe nhiều, trì giới,\nBậc tự chế, Thánh nhân;\nHãy gần gũi, thân cận\nThiện nhân, trí giả ấy,\nNhư trăng theo đường sao."`, ref: "Kinh Pháp Cú 197-208", url: "https://loicuaducphat.org/dhp/dhp197-208.html#content" },

{ text: `209. "Tự chuyên, không đáng chuyên\nKhông chuyên, việc đáng chuyên.\nBỏ đích, theo hỷ ái,\nGanh tị bậc tự chuyên."\n\n210. "Chớ gần gũi người yêu,\nTrọn đời xa kẻ ghét.\nYêu không gặp là khổ,\nOán phải gặp cũng đau."\n\n211. "Do vậy chớ yêu ai,\nÁi biệt ly là ác;\nNhững ai không yêu ghét,\nKhông thể có buộc ràng."\n\n212. "Do ái sinh sầu ưu,\nDo ái sinh sợ hãi,\nAi thoát khỏi tham ái,\nKhông sầu, đâu sợ hãi?"`, ref: "Kinh Pháp Cú 209-220", url: "https://loicuaducphat.org/dhp/dhp209-220.html#content" },

{ text: `213. "Ái luyến sinh sầu ưu,\nÁi luyến sinh sợ hải.\nAi giải thoát ái luyến\nKhông sầu, đâu sợ hãi?"\n\n214. "Hỷ ái sinh sầu ưu,\nHỷ ái sinh sợ hãi.\nAi giải thoát hỷ ái,\nKhông sầu, đâu sợ hãi?\n\n215. "Dục ái sinh sầu ưu,\nDục ái sinh sợ hãi,\nAi thoát khỏi dục ái,\nKhông sầu, đâu sợ hãi?"\n\n216. "Tham ái sinh sầu ưu,\nTham ái sinh sợ hãi.\nAi thoát khỏi tham ái,\nKhông sầu, đâu sợ hãi."`, ref: "Kinh Pháp Cú 209-220", url: "https://loicuaducphat.org/dhp/dhp209-220.html#content" },

{ text: `222. "Ai chận được phẫn nộ,\nNhư dừng xe đang lăn,\nTa gọi người đánh xe,\nKẻ khác, cầm cương hờ."\n\n223. "Lấy không giận thắng giận,\nLấy thiện thắng không thiện,\nLấy thí thắng xan tham,\nLấy chơn thắng hư ngụy."\n\n224. "Nói thật, không phẫn nộ,\nCủa ít, thí người xin,\nNhờ ba việc lành này,\nNgười đến gần thiên giới."\n\n225. "Bậc hiền không hại ai,\nThân thường được chế ngự,\nÐạt được cảnh bất tử,\nÐến đây, không ưu sầu."`, ref: "Kinh Pháp Cú 221-234", url: "https://loicuaducphat.org/dhp/dhp221-234.html#content" },

{ text: `226. "Những người thường giác tỉnh,\nNgày đêm siêng tu học,\nChuyên tâm hướng Niết Bàn,\nMọi lậu hoặc được tiêu."\n\n229. "Sáng sáng, thẩm xét kỹ.\nBậc có trí tán thán.\nBậc trí không tỳ vết,\nÐầy đủ giới định tuệ."\n\n230. "Hạnh sáng như vàng ròng,\nAi dám chê vị ấy?\nChư thiên phải khen thưởng,\nPhạm Thiên cũng tán dương ".`, ref: "Kinh Pháp Cú 221-234", url: "https://loicuaducphat.org/dhp/dhp221-234.html#content" },

{ text: `231. "Giữ thân đừng phẫn nộ,\nPhòng thân khéo bảo vệ,\nTừ bỏ thân làm ác,\nVới thân làm hạnh lành."\n\n232 "Giữ lời đừng phẫn nộ,\nPhòng lời, khéo bảo vệ,\nTừ bỏ lời thô ác,\nVới lời, nói điều lành."\n\n233. "Giữ ý đừng phẫn nộ,\nPhòng ý, khéo bảo vệ,\nTừ bỏ ý nghĩ ác,\nVới ý, nghĩ hạnh lành.’\n\n234. "Bậc trí bảo vệ thân,\nBảo vệ luôn lời nói\nBảo vệ cả tâm tư,\nBa nghiệp khéo bảo vệ."`, ref: "Kinh Pháp Cú 221-234", url: "https://loicuaducphat.org/dhp/dhp221-234.html#content" },

{ text: `236. "Hãy tự làm hòn đảo,\nTinh cần gấp, sáng suốt.\nTrừ cấu uế, thanh tịnh,\nÐến Thánh địa chư Thiên."\n\n238. "Hãy tự làm hòn đảo,\nTinh cần gấp sáng suốt.\nTrừ cấu uế, thanh tịnh,\nChẳng trở lại sanh già."\n\n239. "Bậc trí theo tuần tự.\nTừng sát na trừ dần.\nNhư thợ vàng lọc bụi\nTrừ cấu uế nơi mình."`, ref: "Kinh Pháp Cú 235-255", url: "https://loicuaducphat.org/dhp/dhp235-255.html#content" },

{ text: `240. "Như sét từ sắt sanh,\nSắt sanh lại ăn sắt,\nCũng vậy, quá lợi dưỡng\nTự nghiệp dẫn cõi ác."\n\n243. "Trong hàng cấu uế ấy,\nVô minh, nhơ tối thượng,\nÐoạn nhơ ấy, tỷ kheo,\nThành bậc không uế nhiễm."\n\n244. "Dễ thay, sống không hổ\nSống lỗ mãng như quạ,\nSống công kích huênh hoang,\nSống liều lĩnh, nhiễm ô."\n\n245. "Khó thay, sống xấu hổ,\nThường thường cầu thanh tịnh.\nSống vô tư, khiêm tốn,\nTrong sạch và sáng suốt."`, ref: "Kinh Pháp Cú 235-255", url: "https://loicuaducphat.org/dhp/dhp235-255.html#content" },

{ text: `251. "Lửa nào bằng lửa tham!\nChấp nào bằng sân hận!\nLưới nào bằng lưới si!\nSông nào bằng sông ái! "\n\n254. "Hư không, không dấu chân,\nNgoài đây, không sa môn,\nChúng sanh thích hý luận,\nNhư lai, hý luận trừ."\n\n255. "Hư không, không dấu chân,\nNgoài đây, không sa môn.\nCác hành không thường trú,\nChư Phật không giao động."`, ref: "Kinh Pháp Cú 235-255", url: "https://loicuaducphat.org/dhp/dhp235-255.html#content" },

{ text: `50. "Không nên nhìn lỗi người,\nNgười làm hay không làm.\nNên nhìn tự chính mình.\nCó làm hay không làm."\n\n252. "Dễ thay thấy lỗi người,\nLỗi mình thấy mới khó.\nLỗi người ta phanh tìm,\nNhư sàng trấu trong gạo,\nCòn lỗi mình, che đậy,\nNhư kẻ gian dấu bài."\n\n253. "Ai thấy lỗi của người,\nThường sanh lòng chỉ trích,\nNgười ấy lậu hoặc tăng,\nRất xa lậu hoặc diệt."`, ref: "Kinh Pháp Cú 235-255", url: "https://loicuaducphat.org/dhp/dhp235-255.html#content" },

{ text: `256. "Ngươi đâu phải pháp trụ,\nXử sự quá chuyên chế,\nBậc trí cần phân biệt\nCả hai chánh và tà!"\n\n257. "Không chuyên chế, đúng pháp,\nCông bằng, dắt dẫn người,\nBậc trí sống đúng pháp,\nThật xứng danh pháp trụ."\n\n258. "Không phải vì nói nhiều,\nMới xứng danh bậc trí.\nAn ổn, không oán sợ.\nThật đáng gọi bậc trí."\n\n259. "Không phải vì nói nhiều,\nMới xứng danh trì pháp,\nNhững ai tuy nghe ít,\nNhưng thân hành đúng pháp,\nKhông phóng túng chánh pháp,\nMới xứng danh trì pháp."`, ref: "Kinh Pháp Cú 256-272", url: "https://loicuaducphat.org/dhp/dhp256-272.html#content" },

{ text: `260. Không phải là trưởng lão,\nDầu cho có bạc đầu.\nNgười chỉ tuổi tác cao,\nÐược gọi là: "Lão ngu."\n\n261. "Ai chân thật, đúng pháp,\nKhông hại, biết chế phục,\nBậc trí không cấu uế,\nMới xứng danh Trưởng Lão."\n\n262. "Không phải nói lưu loát,\nKhông phải sắc mặt đẹp,\nThành được người lương thiện,\nNếu ganh, tham, dối trá."\n\n263. "Ai cắt được, phá được\nTận gốc nhổ tâm ấy\nNgười trí ấy diệt sân,\nÐược gọi người hiền thiện."`, ref: "Kinh Pháp Cú 256-272", url: "https://loicuaducphat.org/dhp/dhp256-272.html#content" },

{ text: `264. "Ðầu trọc, không sa môn\nNếu phóng túng, nói láo.\nAi còn đầy dục tham,\nSao được gọi sa môn?"\n\n265. "Ai lắng dịu hoàn toàn,\nCác điều ác lớn nhỏ,\nVì lắng dịu ác pháp,\nÐược gọi là Sa môn."\n\n266. " Chỉ khất thực nhờ người,\nÐâu phải là tỷ kheo!\nPhải theo pháp toàn diện,\nKhất sĩ không, không đủ."\n\n267. " Ai vượt qua thiện ác,\nChuyên sống đời Phạm Hạnh,\nSống thẩm sát ở đời,\nMới xứng danh tỷ kheo."`, ref: "Kinh Pháp Cú 256-272", url: "https://loicuaducphat.org/dhp/dhp256-272.html#content" },

{ text: `268. "Im lặng nhưng ngu si,\nÐâu được gọi ẩn sĩ?\nNhư người cầm cán cân,\nBậc trí chọn điều lành."\n\n269. " Từ bỏ các ác pháp,\nMới thật là ẩn sĩ.\nAi thật hiểu hai đời\nMới được gọi ẩn sĩ."\n\n270. " Còn sát hại sinh linh,\nÐâu được gọi Hiền thánh.\nKhông hại mọi hữu tình,\nMới được gọi Hiền Thánh."`, ref: "Kinh Pháp Cú 256-272", url: "https://loicuaducphat.org/dhp/dhp256-272.html#content" },

{ text: `271. "Chẳng phải chỉ giới cấm\nCũng không phải học nhiều,\nChẳng phải chứng thiền định,\nSống thanh vắng một mình."\n\n272. "Ta hưởng an ổn lạc,\nPhàm phu chưa hưởng được.\nTỷ kheo, chớ tự tin\nKhi lậu hoặc chưa diệt."`, ref: "Kinh Pháp Cú 256-272", url: "https://loicuaducphat.org/dhp/dhp256-272.html#content" },

{ text: `273. "Tám chánh, đường thù thắng,\nBốn câu, lý thù thắng.\nLy tham, pháp thù thắng,\nGiữa các loài hai chân,\nPháp nhãn, người thù thắng."\n\n274. "Ðường này, không đường khác\nÐưa đến kiến thanh tịnh.\nNếu ngươi theo đường này,\nMa quân sẽ mê loạn."\n\n275. "Nếu người theo đường này,\nÐau khổ được đoạn tận.\nTa dạy người con đường.\nVới trí, gai chướng diệt."\n\n276. "Người hãy nhiệt tình làm,\nNhư Lai chỉ thuyết dạy.\nNgười hành trì thiền định\nThoát trói buộc Ác ma."`, ref: "Kinh Pháp Cú 273-289", url: "https://loicuaducphat.org/dhp/dhp273-289.html#content" },

{ text: `277. "Tất cả hành vô thường "\nVới Tuệ, quán thấy vậy\nÐau khổ được nhàm chán;\nChính con đường thanh tịnh."\n\n278. "Tất cả hành khổ đau\nVới Tuệ quán thấy vậy,\nÐau khổ được nhàm chán;\nChính con đường thanh tịnh."\n\n279. "Tất cả pháp vô ngã,\nVới Tuệ quán thấy vậy,\nÐau khổ được nhàm chán\nChính con đường thanh tịnh."`, ref: "Kinh Pháp Cú 273-289", url: "https://loicuaducphat.org/dhp/dhp273-289.html#content" },

{ text: `280. "Khi cần, không nỗ lực,\nTuy trẻ mạnh, nhưng lười\nChí nhu nhược, biếng nhác.\nVới trí tuệ thụ động,\nSao tìm được chánh đạo?"\n\n281. "Lời nói được thận trọng,\nTâm tư khéo hộ phòng,\nThân chớ làm điều ác,\nHãy giữ ba nghiệp tịnh,\nChứng đạo thánh nhân dạy."\n\n282. "Tu thiền, trí tuệ sanh,\nBỏ Thiền, trí tuệ diệt.\nBiết con đường hai ngả\nÐưa đến hữu, phi hữu,\nHãy tự mình nỗ lực,\nKhiến trí tuệ tăng trưởng."`, ref: "Kinh Pháp Cú 273-289", url: "https://loicuaducphat.org/dhp/dhp273-289.html#content" },

{ text: `283. "Ðốn rừng không đốn cây\nTừ rừng, sinh sợ hãi;\nÐốn rừng và ái dục,\nTỷ kheo, hãy tịch tịnh."\n\n284. "Khi nào chưa cắt tiệt,\nÁi dục giữa gái trai,\nTâm ý vẫn buộc ràng,\nNhư bò con vú mẹ."\n\n285. "Tự cắt giây ái dục,\nNhư tay bẻ sen thu,\nHãy tu đạo tịch tịnh,\nNiết-Bàn, Thiện Thệ dạy."`, ref: "Kinh Pháp Cú 273-289", url: "https://loicuaducphat.org/dhp/dhp273-289.html#content" },

{ text: `286. "Mùa mưa ta ở đây\nÐông, hạ cũng ở đây,\nNgười ngu tâm tưởng vậy,\nKhông tự giác hiểm nguy."\n\n287. "Người tâm ý đắm say\nCon cái và súc vật,\nTử thần bắt người ấy,\nNhư lụt trôi làng ngủ. "\n\n288. "Một khi tử thần đến,\nKhông có con che chở,\nKhông cha, không bà con,\nKhông thân thích che chở."\n\n289. "Biết rõ ý nghĩa này,\nBậc trí lo trì giới,\nMau lẹ làm thanh tịnh,\nCon đường đến Niết-Bàn."`, ref: "Kinh Pháp Cú 273-289", url: "https://loicuaducphat.org/dhp/dhp273-289.html#content" },

{ text: `290. "Nhờ từ bỏ lạc nhỏ,\nThấy được lạc lớn hơn,\nBậc trí bỏ lạc nhỏ,\nThấy được lạc lớn hơn."\n\n291. "Gieo khổ đau cho người,\nMong cầu lạc cho mình,\nBị hận thù buộc ràng\nKhông sao thoát hận thù."\n\n292. "Việc đáng làm, không làm,\nKhông đáng làm, lại làm,\nNgười ngạo mạn, phóng dật,\nLậu hoặc ắt tăng trưởng."\n\n293. "Người siêng năng cần mẫn,\nThường thường quán thân niệm,\nKhông làm việc không đáng,\nGắng làm việc đáng làm,\nNgười tư niệm giác tỉnh,\nLậu hoặc được tiêu trừ."`, ref: "Kinh Pháp Cú 290-305", url: "https://loicuaducphat.org/dhp/dhp290-305.html#content" },

{ text: `296. "Ðệ tử Gotama,\nLuôn luôn tự tỉnh giác\nVô luận ngày hay đêm,\nTưởng Phật Ðà thường niệm."\n\n297. "Ðệ tử Gotama,\nLuôn luôn tự tỉnh giác,\nVô luận ngày hay đêm,\nTưởng Chánh Pháp thường niệm"\n\n298. "Ðệ tử Gotama,\nLuôn luôn tự tỉnh giác,\nVô luận ngày hay đêm,\nTưởng Tăng Già thường niệm."`, ref: "Kinh Pháp Cú 290-305", url: "https://loicuaducphat.org/dhp/dhp290-305.html#content" },

{ text: `299. "Ðệ tử Gotama,\nLuôn luôn tự tỉnh giác,\nVô luận ngày hay đêm,\nTưởng sắc thân thường niệm."\n\n300. "Ðệ tử Gotama,\nLuôn luôn tự tỉnh giác,\nVô luận ngày hay đêm,\nÝ vui niềm bất hại."\n\n301. "Ðệ tử Gotama,\nLuôn luôn tự tỉnh giác,\nVô luận ngày hay đêm,\nÝ vui tu thiền quán."`, ref: "Kinh Pháp Cú 290-305", url: "https://loicuaducphat.org/dhp/dhp290-305.html#content" },

{ text: `303. "Tín tâm, sống giới hạnh\nÐủ danh xưng tài sản,\nChỗ nào người ấy đến,\nChỗ ấy được cung kính."\n\n304. "Người lành dầu ở xa\nSáng tỏ như núi tuyết,\nNgười ác dầu ở gần\nNhư tên bắn đêm đen."\n\n305. "Ai ngồi nằm một mình.\nÐộc hành không buồn chán,\nTự điều phục một mình\nSống thoải mái rừng sâu."`, ref: "Kinh Pháp Cú 290-305", url: "https://loicuaducphat.org/dhp/dhp290-305.html#content" },

{ text: `306. "Nói láo đọa địa ngục\nCó làm nói không làm,\nCả hai chết đồng đẳng,\nLàm người, nghiệp hạ liệt."\n\n307. "Nhiều người khoác cà sa,\nÁc hạnh không nhiếp phục.\nNgười ác, do ác hạnh,\nPhải sanh cõi Ðịa ngục."\n\n308. "Tốt hơn nuốt hòn sắt\nCháy đỏ như lửa hừng,\nHơn ác giới, buông lung\nĂn đồ ăn quốc độ."`, ref: "Kinh Pháp Cú 306-319", url: "https://loicuaducphat.org/dhp/dhp306-319.html#content" },

{ text: `311. "Như cỏ sa vụng nắm,\nTất bị họa đứt tay\nHạnh Sa môn tà vạy,\nTất bị đọa địa ngục."\n\n312. "Sống phóng đãng buông lung,\nTheo giới cấm ô nhiễm,\nSống Phạm hạnh đáng nghi\nSao chứng được quả lớn?\n\n313. "Cần phải làm, nên làm\nLàm cùng tận khả năng\nXuất gia sống phóng đãng,\nChỉ tăng loạn bụi đời."`, ref: "Kinh Pháp Cú 306-319", url: "https://loicuaducphat.org/dhp/dhp306-319.html#content" },

{ text: `314. "Ác hạnh không nên làm,\nLàm xong, chịu khổ lụy,\nThiện hạnh, ắt nên làm,\nLàm xong, không ăn năn."\n\n315. "Như thành ở biên thùy,\nTrong ngoài đều phòng hộ\nCũng vậy, phòng hộ mình,\nSát na chớ buông lung.\nGiây phút qua, sầu muộn.\nKhi rơi vào địa ngục."`, ref: "Kinh Pháp Cú 306-319", url: "https://loicuaducphat.org/dhp/dhp306-319.html#content" },

{ text: `316. "Không đáng hổ, lại hổ.\nViệc đáng hổ, lại không.\nDo chấp nhận tà kiến,\nChúng sanh đi ác thú."\n\n317. "Không đáng sợ, lại sợ,\nÐáng sợ, lại thấy không,\nDo chấp nhận tà kiến.\nChúng sanh đi ác thú."\n\n318. "Không lỗi, lại thấy lỗi,\nCó lỗi, lại thấy không,\nDo chấp nhận tà kiến,\nChúng sanh đi ác thú."\n\n319. "Có lỗi, biết có lỗi,\nKhông lỗi, biết là không,\nDo chấp nhận chánh kiến,\nChúng sanh đi cõi lành."`, ref: "Kinh Pháp Cú 306-319", url: "https://loicuaducphat.org/dhp/dhp306-319.html#content" },

{ text: `320. "Ta như voi giữa trận,\nHứng chịu cung tên rơi,\nChịu đựng mọi phỉ báng.\nÁc giới rất nhiều người."\n\n321. "Voi luyện, đưa dự hội,\nNgựa luyện, được vua cưỡi,\nNgười luyện, bậc tối thượng\nChịu đựng mọi phỉ báng."\n\n322. "Tốt thay, con la thuần,\nThuần chủng loài ngựa Sin.\nÐại tượng, voi có ngà.\nTự điều mới tối thượng."`, ref: "Kinh Pháp Cú 320-333", url: "https://loicuaducphat.org/dhp/dhp320-333.html#content" },

{ text: `325. "Người ưa ngủ, ăn lớn\nNằm lăn lóc qua lại,\nChẳng khác heo no bụng,\nKẻ ngu nhập thai mãi."\n\n326. "Trước tâm này buông lung,\nChạy theo ái, dục, lạc.\nNay Ta chánh chế ngự,\nNhư cầm móc điều voi."\n\n327. "Hãy vui không phóng dật,\nKhéo phòng hộ tâm ý.\nKéo mình khỏi ác đạo,\nNhư voi bị sa lầy."`, ref: "Kinh Pháp Cú 320-333", url: "https://loicuaducphat.org/dhp/dhp320-333.html#content" },

{ text: `328. "Nếu được bạn hiền trí\nÐáng sống chung, hạnh lành,\nNhiếp phục mọi hiểm nguy\nHoan hỷ sống chánh niệm."\n\n329. "Không gặp bạn hiền trí.\nÐáng sống chung, hạnh lành\nNhư vua bỏ nước bại,\nHãy sống riêng cô độc,\nNhư voi sống rừng voi."\n\n330. "Tốt Hơn sống một mình,\nKhông kết bạn người ngu.\nÐộc thân, không ác hạnh\nSống vô tư vô lự,\nNhư voi sống rừng voi."`, ref: "Kinh Pháp Cú 320-333", url: "https://loicuaducphat.org/dhp/dhp320-333.html#content" },

{ text: `331. "Vui thay, bạn lúc cần!\nVui thay, sống biết đủ,\nVui thay, chết có đức!\nVui thay, mọi khổ đoạn."\n\n332. "Vui thay, hiếu kính mẹ,\nVui thay, hiếu kính cha,\nVui thay, kính Sa môn,\nVui thay, kính Hiền Thánh."\n\n333. "Vui thay, già có giới!\nVui thay, tín an trú!\nVui thay, được trí tuệ,\nVui thay, ác không làm."`, ref: "Kinh Pháp Cú 320-333", url: "https://loicuaducphat.org/dhp/dhp320-333.html#content" },

{ text: `334. "Người sống đời phóng dật,\nÁi tăng như giây leo.\nNhảy đời này đời khác,\nNhư vượn tham quả rừng."\n\n335. "Ai sống trong đời này,\nBị ái dục buộc ràng\nSầu khổ sẽ tăng trưởng,\nNhư cỏ Bi gặp mưa."\n\n336. "Ai sống trong đời này\nÁi dục được hàng phục\nSầu rơi khỏi người ấy\nNhư giọt nước lá sen."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `337. "Ðây điều lành Ta dạy,\nCác người tụ họp đây.\nHãy nhổ tận gốc ái\nNhư nhổ gốc cỏ Bi.\nChớ để ma phá hoại,\nNhư giòng nước cỏ lau."\n\n338. "Như cây bị chặt đốn,\nGốc chưa hại vẫn bền\nÁi tùy miên chưa nhổ,\nKhổ này vẫn sanh hoài."\n\n339. "Ba mươi sáu dòng Ái,\nTrôi người đốn khả ái.\nCác tư tưởng tham ái.\nCuốn trôi người tà kiến."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `340. "Dòng ái dục chảy khắp,\nNhư giây leo mọc tràn,\nThấy giây leo vừa sanh,\nVới tuệ, hãy đoạn gốc."\n\n341. "Người đời nhớ ái dục,\nƯa thích các hỷ lạc.\nTuy mong cầu an lạc,\nHọ vẫn phải sanh già."\n\n342. "Người bị ái buộc ràng,\nVùng vẫy và hoảng sợ,\nNhư thỏ bị sa lưới.\nHọ sanh ái trói buộc,\nChịu khổ đau dài dài."\n\n343. "Người bị ái buộc ràng,\nVùng vẫy và hoảng sợ,\nNhư thỏ bị sa lưới.\nDo vậy vị tỷ kheo,\nMong cầu mình ly tham\nNên nhiếp phục ái dục."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `344. "Lìa rừng lại hướng rừng\nThoát rừng chạy theo rừng.\nNên xem người như vậy,\nÐược thoát khỏi buộc ràng.\nLại chạy theo ràng buộc."\n\n345. "Sắt, cây, gai trói buộc\nNgười trí xem chưa bền.\nTham châu báu, trang sức\nTham vọng vợ và con."\n\n346. "Người có trí nói rằng:\n"Trói buộc này thật bền.\nRì kéo xuống, lún xuống,\nNhưng thật sự khó thoát.\nNgười trí cắt trừ nó,\nBỏ dục lạc, không màng."\n\n347. "Người đắm say ái dục\nTự lao mình xuống dòng\nNhư nhện sa lưới dệt.\nNgười trí cắt trừ nó,\nBỏ mọi khổ, không màng."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `348. "Bỏ quá, hiện, vị lai,\nÐến bờ kia cuộc đời,\nÝ giải thoát tất cả,\nChớ vướng lại sanh già."\n\n349. "Người tà ý nhiếp phục,\nTham sắc bén nhìn tịnh,\nNgười ấy ái tăng trưởng,\nLàm giây trói mình chặt."\n\n350. "Ai vui, an tịnh ý,\nQuán bất tịnh, thường niệm,\nNgười ấy sẽ diệt ái,\nCắt đứt Ma trói buộc."\n\n351. "Ai tới đích, không sợ,\nLy ái, không nhiễm ô\nNhổ mũi tên sanh tử,\nThân này thân cuối cùng."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `352. "Ái lìa, không chấp thủ.\nCú pháp khéo biện tài\nThấu suốt từ vô ngại,\nHiểu thứ lớp trước sau.\nThân này thân cuối cùng\nVị như vậy được gọi,\nBậc Ðại trí, đại nhân."\n\n353. "Ta hàng phục tất cả,\nTa rõ biết tất cả,\nKhông bị nhiễm pháp nào.\nTa từ bỏ tất cả\nÁi diệt, tự giải thoát.\nÐã tự mình thắng trí,\nTa gọi ai thầy ta?"\n\n354. "Pháp thí, thắng mọi thí!\nPháp vị, thắng mọi vị!\nPháp hỷ, thắng mọi hỷ!\nÁi diệt, dứt mọi khổ!"\n\n355. "Tài sản hại người ngu.\nKhông người tìm bờ kia\nKẻ ngu vì tham giàu,\nHại mình và hại người."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `356. "Cỏ làm hại ruộng vườn,\nTham làm hại người đời.\nBố thí người ly tham,\nDo vậy được quả lớn."\n\n357. "Cỏ làm hại ruộng vườn,\nSân làm hại người đời.\nBố thí người ly sân,\nDo vậy được quả lớn."\n\n358. "Cỏ làm hại ruộng vườn,\nSi làm hại người đời,\nBố thí người ly si,\nDo vậy được quả lớn."\n\n359. "Cỏ làm hại ruộng vườn,\nDục làm hại người đời.\nBố thí người ly dục,\nDo vậy được quả lớn."`, ref: "Kinh Pháp Cú 334-359", url: "https://loicuaducphat.org/dhp/dhp334-359.html#content" },

{ text: `360. "Lành thay, phòng hộ mắt!\nLành thay, phòng hộ tai.\nLành thay, phòng hộ mũi,\nLành thay, phòng hộ lưỡi."\n\n361. "Lành thay,phòng hộ thân!\nLành thay, phòng hộ lời,\nLành thay, phòng hộ ý.\nLành thay, phòng tất cả.\nTỷ kheo phòng tất cả.\nThoát được mọi khổ đau."\n\n362. "Người chế ngự tay chân,\nChế ngự lời và đầu,\nVui thích nội thiền định.\nÐộc thân, biết vừa đủ,\nThật xứng gọi tỷ kheo."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `363. "Tỷ kheo chế ngự miệng,\nVừa lời, không cống cao,\nKhi trình bày pháp nghĩa,\nLời lẽ dịu ngọt ngào."\n\n364. "Vị tỷ kheo thích pháp,\nMến pháp, suy tư Pháp.\nTâm tư niệm chánh Pháp,\nKhông rời bỏ chánh Pháp."\n\n365. "Không khinh điều mình được,\nKhông ganh người khác được\nTỷ kheo ganh tị người,\nKhông sao chứng Thiền Ðịnh."\n\n366. "Tỷ kheo dầu được ít,\nKhông khinh điều mình được,\nSống thanh tịnh không nhác,\nChư thiên khen vị này."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `367. "Hoàn toàn, đối danh sắc,\nKhông chấp Ta, của Ta.\nKhông chấp, không sầu não.\nThật xứng danh Tỷ kheo."\n\n368. "Tỷ kheo trú từ bi,\nTín thành giáo Pháp Phật,\nChứng cảnh giới tịch tỉnh.\nCác hạnh an tịnh lạc."\n\n369. "Tỷ kheo, tát thuyền này,\nThuyền không, nhẹ đi mau.\nTrừ tham, diệt sân hận,\nTất chứng đạt Niết-Bàn."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `371. "Tỷ kheo, hãy tu thiền,\nChớ buông lung phóng dật,\nTâm chớ đắm say dục,\nPhóng dật, nuốt sắt nóng\nBị đốt, chớ than khổ!"\n\n372. "Không trí tuệ, không thiền,\nKhông thiền, không trí tuệ.\nNgười có thiền có tuệ,\nNhất định gần Niết-Bàn."\n\n373. "Bước vào ngôi nhà trống,\nTỷ kheo tâm an tịnh,\nThọ hưởng vui siêu nhân\nTịnh quán theo chánh pháp."\n\n374. "Người luôn luôn chánh niệm,\nSự sanh diệt các uẩn,\nÐược hoan hỷ, hân hoan,\nChỉ bậc bất tử biết."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `375. "Ðây Tỷ kheo có trí,\nTụ tập pháp căn bản\nHộ căn, biết vừa đủ,\nGiữ gìn căn bản giới,\nThường gần gũi bạn lành,\nSống thanh tịnh tinh cần."\n\n376. "Giao thiệp khéo thân thiện,\nCử chỉ mực đoan trang.\nDo vậy hưởng vui nhiều,\nSẽ dứt mọi khổ đau."\n\n377. "Như hoa Vassikà,\nQuăng bỏ cánh úa tàn,\nCũng vậy vị Tỷ kheo,\nHãy giải thoát tham sân."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `378. "Thân tịnh, lời an tịnh,\nAn tịnh, khéo thiền tịnh.\nTỷ kheo bỏ thế vật,\nXứng danh "bậc tịch tịnh ".\n\n379. "Tự mình chỉ trích mình,\nTự mình dò xét mình,\nTỷ kheo tự phòng hộ\nChánh niệm, trú an lạc."\n\n380. "Tự mình y chỉ mình,\nTự mình đi đến mình,\nVậy hãy tự điều phục,\nNhư khách buôn ngựa hiền."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `381. "Tỷ kheo nhiều hân hoan,\nTịnh tín giáo pháp Phật,\nChứng cảnh giới tịch tịnh,\nCác hạnh an tịnh lạc."\n\n382. "Tỷ kheo tuy tuổi nhỏ\nSiêng tu giáo pháp Phật,\nSoi sáng thế gian này,\nNhư trăng thoát khỏi mây."`, ref: "Kinh Pháp Cú 360-382", url: "https://loicuaducphat.org/dhp/dhp360-382.html#content" },

{ text: `383. "Hỡi này Bà là môn,\nHãy tinh tấn đoạn dòng,\nTừ bỏ các dục lạc,\nBiết được hành đoạn diệt,\nNgười là bậc vô vi."\n\n384. "Nhờ thường trú hai pháp\nÐến được bờ bên kia.\nBà-la-môn có trí,\nMọi kiết sử dứt sạch."\n\n385. "Không bờ này, bờ kia\nCả hai bờ không có,\nLìa khổ, không trói buộc\nTa gọi Bà-la-môn."\n\n386. "Tu thiền, trú ly trần\nPhận sự xong, vô lậu,\nÐạt được đích tối thượng,\nTa gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `387. "Mặt trời sáng ban ngày,\nMặt trăng sáng ban đêm.\nKhí giới sáng Sát lỵ,\nThiền định sáng Phạm chí.\nCòn hào quang đức Phật,\nChói sáng cả ngày đêm."\n\n388. "Dứt ác gọi Phạm chí,\nTịnh hạnh gọi Sa môn,\nTự mình xuất cấu uế,\nNên gọi bậc xuất gia."\n\n390. "Ðối vị Bà-la-môn,\nÐây không lợi ích nhỏ.\nKhi ý không ái luyến,\nTâm hại được chận đứng,\nChỉ khi ấy khổ diệt,"`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `391. "Với người thân miệng ý,\nKhông làm các ác hạnh\nBa nghiệp được phòng hộ,\nTa gọi Bà-la-môn."\n\n392. "Từ ai, biết chánh pháp\nBậc Chánh Giác thuyết giảng,\nHãy kính lễ vị ấy,\nNhư phạm chí chờ lửa."\n\n393. "Ðược gọi Bà-la-môn,\nKhông vì đầu bện tóc,\nKhông chủng tộc, thọ sanh,\nAi thật chân, chánh, tịnh,\nMới gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `E\n\n394. "Kẻ ngu, có ích gì\nBện tóc với da dê,\nNội tâm toàn phiền não,\nNgoài mặt đánh bóng suông."\n\n395. "Người mặc áo đống rác,\nGầy ốm, lộ mạch gân,\nÐộc thân thiền trong rừng.\nTa gọi Bà-la-môn."\n\n396 "Ta không gọi Phạm Chí,\nVì chỗ sanh, mẹ sanh.\nChỉ được gọi tên suông\nNếu tâm còn phiền não.\nKhông phiền não, chấp trước\nTa gọi Bà-la-môn."\n\n397. "Ðoạn hết các kiết sử,\nKhông còn gì lo sợ\nKhông đắm trước buộc ràng\nTa gọi Bà-la-môn`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `399. "Không ác ý, nhẫn chịu,\nPhỉ báng, đánh, phạt hình,\nLấy nhẫn làm quân lực,\nTa gọi Bà-la-môn."\n\n400. "Không hận, hết bổn phận,\nTrì giới, không tham ái,\nNhiếp phục, thân cuối cùng,\nTa gọi Bà-la-môn."\n\n401. "Như nước trên lá sen,\nNhư hột cải đầu kim,\nNgười không nhiễm ái dục,\nTa gọi Bà-la-môn."\n\n402. "Ai tự trên đời này,\nGiác khổ, diệt trừ khổ,\nBỏ gánh nặng, giải thoát,\nTa gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `403. "Người trí tuệ sâu xa,\nKhéo biết đạo, phi đạo\nChứng đạt đích vô thượng,\nTa gọi Bà-la-môn."\n\n404. "Không liên hệ cả hai,\nXuất gia và thế tục,\nSống độc thân, ít dục,\nTa gọi Bà-la-môn."\n\n405. "Bỏ trượng, đối chúng sanh,\nYếu kém hay kiên cường,\nKhông giết, không bảo giết,\nTa gọi Bà-la-môn."\n\n406. "Thân thiện giữa thù địch\nÔn hòa giữa hung hăng.\nKhông nhiễm, giữa nhiễm trước,\nTa gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `407. "Người bỏ rơi tham sân,\nKhông mạn không ganh tị,\nNhư hột cải đầu kim,\nTa gọi Bà-la-môn."\n\n408. "Nói lên lời ôn hòa,\nLợi ích và chân thật,\nKhông mất lòng một ai,\nTa gọi Bà-la-môn."\n\n409. "Ở đời, vật dài, ngắn,\nNhỏ, lớn, đẹp hay xấu\nPhàm không cho không lấy,\nTa gọi Bà-la-môn."\n\n410. "Người không có hy cầu,\nÐời này và đời sau,\nKhông hy cầu, giải thoát,\nTa gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `411. "Người không còn tham ái,\nCó trí, không nghi hoặc,\nThể nhập vào bất tử,\nTa gọi Bà-la-môn."\n\n412. "Người sống ở đời này\nKhông nhiễm cả thiện ác,\nKhông sầu, sạch không bụi\nTa gọi Bà-la-môn."\n\n413 "Như trăng, sạch không uế\nSáng trong và tịnh lặng,\nHữu ái, được đoạn tận,\nTa gọi Bà là môn."\n\n414. "Vượt đường nguy hiểm này,\nNhiếp phục luân hồi, si,\nÐến bờ kia thiền định\nKhông dục ái, không nghi,\nKhông chấp trước, tịch tịnh,\nTa gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `415. "Ai ở đời, đoạn dục,\nBỏ nhà, sống xuất gia,\nDục hữu được đoạn tận,\nTa gọi Bà-la-môn."\n\n416. "Ai ở đời đoạn ái\nBỏ nhà, sống xuất gia,\nÁi hữu được đoạn tận,\nTa gọi Bà-la-môn."\n\n417. "Bỏ trói buộc loài người,\nVượt trói buộc cõi trời.\nGiải thoát mọi buộc ràng,\nTa gọi Bà-la-môn."\n\n418. "Bỏ điều ưa, điều ghét,\nMát lạnh, diệt sanh y\nBậc anh hùng chiến thắng,\nNhiếp phục mọi thế giới,\nTa gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },

{ text: `419. "Ai hiểu rõ hoàn toàn\nSanh tử các chúng sanh,\nKhông nhiễm, khéo vượt qua,\nSáng suốt chân giác ngộ,\nTa gọi Bà-la-môn."\n\n421 "Ai quá, hiện, vị lai\nKhông một sở hữu gì,\nKhông sở hữu không nắm,\nTa gọi Bà-la-môn."\n\n422. "Bậc trâu chúa, thù thắng\nBậc anh hùng, đại sĩ,\nBậc chiến thắng, không nhiễm,\nBậc tẩy sạch, giác ngộ,\nTa gọi Bà-la-môn."\n\n423. "Ai biết được đời trước,\nThấy thiên giới, đọa xứ,\nÐạt được sanh diệt tận\nThắng trí, tự viên thành\nBậc mâu ni đạo sĩ.\nViên mãn mọi thành tựu\nTa gọi Bà-la-môn."`, ref: "Kinh Pháp Cú 383-423", url: "https://loicuaducphat.org/dhp/dhp383-423.html#content" },
         
                { text: `Ðứng một bên, vị Thiên tử ấy bạch Thế Tôn với bài kệ:\n\n1. Nhiều Thiên tử và người,\nSuy nghĩ đến điềm lành,\nMong ước và đợi chờ,\nMột nếp sống an toàn,\nXin Ngài hãy nói lên,\nVề điềm lành tối thượng.\n\n2. Không thân cận kẻ ngu,\nNhưng gần gũi bậc Trí,\nÐảnh lễ người đáng lễ,\nLà điềm lành tối thượng.\n\n3. Ở trú xứ thích hợp,\nCông đức trước đã làm,\nChân chánh hướng tự tâm,\nLà điềm lành tối thượng.\n\n4. Học nhiều, nghề nghiệp giỏi,\nKhéo huấn luyện học tập,\nNói những lời khéo nói,\nLà điềm lành tối thượng.\n\n5. Hiếu dưỡng mẹ và cha,\nNuôi nấng vợ và con.\nLàm nghề không rắc rối,\nLà điềm lành tối thượng.\n\n6. Bố thí, hành, đúng pháp,\nSăn sóc các bà con,\nLàm nghiệp không lỗi lầm,\nLà điềm lành tối thượng.`, ref: "Kinh Tiểu Tụng 5", url: "https://loicuaducphat.org/kp/kp5.html#content" },

{ text: `7. Chấm dứt, từ bỏ ác,\nChế ngự đam mê rượu,\nTrong Pháp, không phóng dật,\nLà điềm lành tối thượng.\n\n8. Kính lễ và hạ mình,\nBiết đủ và biết ơn,\nÐúng thời, nghe Chánh Pháp,\nLà điềm lành tối thượng.\n\n9. Nhẫn nhục, lời hòa nhã,\nYết kiến các Sa-môn,\nÐúng thời, đàm luận Pháp,\nLà điềm lành tối thượng.\n\n10. Khắc khổ và Phạm hạnh,\nThấy được lý Thánh đế.\nGiác ngộ quả: "Niết Bàn"\nLà điềm lành tối thượng.\n\n11. Khi xúc chạm việc đời\nTâm không động, không sầu,\nKhông uế nhiễm, an ổn,\nLà điềm lành tối thượng.\n\n12. Làm sự việc như vầy,\nKhông chỗ nào thất bại,\nKhắp nơi được an toàn,\nLà điềm lành tối thượng.`, ref: "Kinh Tiểu Tụng 5", url: "https://loicuaducphat.org/kp/kp5.html#content" },

{ text: `1. Phàm ở tại đời này,\nCó sanh linh tụ hội,\nHoặc trên cõi đất này,\nHoặc chính giữa hư không,\nMong rằng mọi sanh linh,\nÐược đẹp ý vui lòng,\nVậy, hãy nên cẩn thận,\nLắng nghe lời dạy này.\n\n2. Do vậy các sanh linh,\nTất cả hãy chú tâm,\nKhởi lên lòng từ mẫn,\nÐối với thảy mọi loài,\nBan ngày và ban đêm,\nHọ đem vật cúng dường,\nDo vậy không phóng dật,\nHãy giúp hộ trì họ.\n\n3. Phàm có tài sản gì,\nÐời này hay đời sau,\nHay ở tại thiên giới,\nCó châu báu thù thắng,\nKhông gì sánh bằng được,\nVới Như Lai Thiện Thệ,\nNhư vậy, nơi Ðức Phật,\nLà châu báu thù diệu,\nMong với sự thật này,\nÐược sống chơn hạnh phúc.\n\n4. Ðoạn diệt và ly tham,\nBất tử và thù diệu.\nPhật Thích-ca Mâu-ni,\nChứng Pháp ấy trong thiền,\nKhông gì sánh bằng được,\nVới Pháp thù diệu ấy.\nNhư vậy, nơi Chánh Pháp,\nLà châu báu thù diệu,\nMong với sự thật này,\nÐược sống chơn hạnh phúc.`, ref: "Kinh Tiểu Tụng 6", url: "https://loicuaducphat.org/kp/kp6.html#content" },

{ text: `5. Phật, Thế Tôn thù thắng,\nNói lên lời tán thán,\nPháp thù diệu trong sạch,\nLiên tục không gián đoạn,\nKhông gì sánh bằng được,\nPháp thiền vi diệu ấy.\nNhư vậy, nơi Chánh Pháp,\nLà châu báu thù diệu,\nMong với sự thật này,\nÐược sống chơn hạnh phúc.\n\n6. Tám vị bốn đôi này,\nÐược bậc thiện tán thán.\nChúng đệ tử Thiện Thệ,\nXứng đáng được cúng dường.\nBố thí các vị ấy,\nÐược kết quả to lớn.\nNhư vậy, nơi tăng chúng,\nLà châu báu thù diệu\nMong với sự thật này,\nÐược sống chơn hạnh phúc.\n\n7. Các vị lòng ít dục,\nVới ý thật kiên trì,\nKhéo liên hệ mật thiết,\nLời dạy Gô-ta-ma!\nHọ đạt được quả vị,\nHọ thể nhập bất tử,\nHọ chứng đắc dễ dàng,\nHưởng thọ sự tịch tịnh,\nNhư vậy, nơi Tăng chúng,\nLà châu báu thù diệu,\nMong với sự thật này,\nÐược sống chơn hạnh phúc.\n\n8. Như cây trụ cột đá,\nKhéo y tựa lòng đất.\nDầu có gió bốn phương,\nCũng không thể dao động.\nTa nói bậc Chơn nhân,\nGiống như thí dụ này,\nVị thể nhập với tuệ,\nThấy được những Thánh đế,\nNhư vậy, nơi Tăng chúng,\nLà châu báu thù diệu,\nMong với sự thật này,\nÐược sống chơn hạnh phúc.`, ref: "Kinh Tiểu Tụng 6", url: "https://loicuaducphat.org/kp/kp6.html#content" },

{ text: `9. Những vị khéo giải thích,\nNhững sự thật Thánh đế,\nNhững vị khéo thuyết giảng,\nVới trí tuệ thâm sâu.\nDầu họ có hết sức,\nPhóng dật không chế ngự,\nHọ cũng không đến nỗi,\nSanh hữu lần thứ tám,\nNhư vậy, nơi Tăng chúng,\nLà châu báu thù diệu,\nMong với sự thật này,\nÐược sống chơn hạnh phúc.\n\n10. Vị ấy nhờ đầy đủ,\nVới chánh kiến sáng suốt,\nDo vậy có ba pháp,\nÐược hoàn toàn từ bỏ,\nThân kiến và nghi hoặc,\nGiới cấm thủ cũng không.\n\n11. Ðối với bốn đọa xứ,\nHoàn toàn được giải thoát.\nVị ấy không thể làm,\nSáu điều ác căn bản,\nNhư vậy, nơi Tăng chúng,\nLà châu báu thù diệu.\nMong với sự thật này,\nÐược sống chơn hạnh phúc.\n\n12. Dầu vị ấy có làm,\nÐiều gì ác đi nữa,\nVới thân hay với lời,\nKể cả với tâm ý,\nVị ấy không có thể,\nChe đậy việc làm ấy,\nViệc ấy được nói rằng,\nKhông thể thấy ác đạo.\nNhư vậy, nơi Tăng chúng,\nLà châu báu thù diệu.\nMong với sự thật này,\nÐược sống chơn hạnh phúc.`, ref: "Kinh Tiểu Tụng 6", url: "https://loicuaducphat.org/kp/kp6.html#content" },

{ text: `13. Ðẹp là những cây rừng,\nCó bông hoa đầu ngọn,\nTrong tháng hạ nóng bức,\nNhững ngày hạ đầu tiên,\nPháp thù thắng thuyết giảng,\nÐược ví dụ như vậy.\nPháp đưa đến Niết Bàn,\nPháp hạnh phúc tối thượng,\nNhư vậy, nơi Ðức Phật,\nLà châu báu thù diệu,\nMong với sự thật này,\nÐược sống chơn hạnh phúc.\n\n14. Cao thượng biết cao thượng,\nCho đem lại cao thượng,\nBậc Vô thượng thuyết giảng,\nPháp cao thượng thù thắng,\nNhư vậy nơi đức Phật,\nLà châu báu thù diệu,\nMong với sự thật này,\nÐược sống chơn hạnh phúc.\n\n15. Nghiệp cũ đã đoạn tận,\nNghiệp mới không tạo nên,\nVới tâm tư từ bỏ,\nTrong sanh hữu tương lai,\nCác hột giống đoạn tận,\nƯớc muốn không tăng trưởng\nBậc trí chứng Niết Bàn,\nVí như ngọn đèn này,\nNhư vậy, nơi Tăng chúng,\nLà châu báu thù diệu.\nMong với sự thật này,\nÐược sống chơn hạnh phúc.`, ref: "Kinh Tiểu Tụng 6", url: "https://loicuaducphat.org/kp/kp6.html#content" },

{ text: `16. Phàm ở tại đời này,\nCó sanh linh tụ hội,\nHoặc trên cõi đất này,\nHoặc chính giữa hư không,\nHãy đảnh lễ Ðức Phật,\nÐã như thực đến đây,\nÐược loài Trời, loài Người,\nÐảnh lễ và cúng dường,\nMong rằng, với hạnh này,\nMọi loài được hạnh phúc.\n\n17. Phàm ở tại nơi này,\nCó sanh linh tụ hội,\nHoặc trên cõi đất này,\nHoặc chính giữa hư không,\nHãy đảnh lễ Chánh pháp,\nÐã như thực đến đây,\nÐược loài Trời, loài Người;\nÐảnh lễ và cúng dường,\nMong rằng với hạnh này,\nMọi loài được hạnh phúc.\n\n18. Phàm ở tại đời này,\nCó sanh linh tụ hội\nHoặc trên cõi đất này,\nHoặc chính giữa hư không,\nHãy đảnh lễ chúng Tăng,\nÐảnh lễ và cúng dường,\nMong rằng với hạnh này,\nMọi loài được hạnh phúc.`, ref: "Kinh Tiểu Tụng 6", url: "https://loicuaducphat.org/kp/kp6.html#content" },

{ text: `1. Vị thiện xảo mục đích,\nCần phải làm như sau:\nSau khi hiểu thông suốt,\nCon đường an tịnh ấy,\nCó khả năng trực tánh,\nThật sự, khéo chân trực,\nDễ nói và nhu hòa,\nKhông có gì cao mạn.\n\n2. Sống cảm thấy vừa đủ,\nNuôi sống thật dễ dàng,\nÍt có sự rộn ràng,\nSống đạm bạc, giản dị.\nCác căn được tịnh lạc,\nKhôn ngoan và thận trọng,\nKhông xông xáo gia đình,\nKhông tham ái, tham vọng.\n\n3. Các hành sở của mình,\nKhông nhỏ nhen, vụn vặt,\nKhiến người khác có trí,\nCó thể sanh chỉ trích,\nMong mọi loài chúng sanh,\nÐược an lạc, an ổn,\nMong chúng chứng đạt được,\nHạnh phúc và an lạc.\n\n4. Mong tất cả những ai,\nHữu tình có mạng sống,\nKẻ yếu hay kẻ mạnh,\nKhông bỏ sót một ai,\nKẻ dài hay kẻ lớn,\nTrung thấp, loài lớn, nhỏ.\n\n5. Loài được thấy, không thấy,\nLoài sống xa, không xa,\nCác loài hiện đang sống,\nCác loài sẽ được sanh,\nMong mọi loài chúng sanh,\nSống hạnh phúc an lạc.`, ref: "Kinh Tiểu Tụng 9", url: "https://loicuaducphat.org/kp/kp9.html#content" },

{ text: `6. Mong rằng không có ai,\nLường gạt, lừa dối ai,\nKhông có ai khinh mạn,\nTại bất cứ chỗ nào,\nKhông vì giận hờn nhau,,\nKhông vì tưởng chống đối.\nLại có người mong muốn,\nLàm đau khổ cho nhau.\n\n7. Như tấm lòng người mẹ,\nÐối với con của mình,\nTrọn đời lo che chở,\nCon độc nhất mình sanh.\nCũng vậy, đối tất cả\nCác hữu tình chúng sanh,\nHãy tu tập tâm ý,\nKhông hạn lượng, rộng lớn.\n\n8. Hãy tu tập từ tâm,\nTrong tất cả thế giới,\nHãy tu tập tâm ý,\nKhông hạn lượng, rộng lớn,\nPhía trên và phía dưới,\nCũng vậy cả bề ngang,\nKhông hạn chế, trói buộc,\nKhông hận, không thù địch.\n\n9. Khi đứng hay khi ngồi,\nKhi ngồi hay khi nằm,\nLâu cho đến khi nào,\nKhi đang còn tỉnh thức,\nHãy an trú niệm này,\nNếp sống này như vậy.\nÐược đời đề cập đến,\nLà nếp sống tối thượng.\n\n10. Ai từ bỏ tà kiến,\nGiữ giới, đủ chánh kiến,\nNhiếp phục được tham ái,\nÐối với các dục vọng,\nKhông còn phải tái sanh,\nÐi đến thai tạng nữa.`, ref: "Kinh Tiểu Tụng 9", url: "https://loicuaducphat.org/kp/kp9.html#content" },

{ text: `Thế nào là một? - Mọi loài hữu tình đều tồn tại nhờ thức ăn. Thế nào là hai? - Danh và sắc. Thế nào là ba? - Ba loại cảm thọ. Thế nào là bốn? - Bốn Thánh đế. Thế nào là năm? - Năm thủ uẩn. Thế nào là sáu? - Sáu nội xứ. Thế nào là bảy? - Bảy giác chi. Thế nào là tám? - Thánh đạo tám ngành. Thế nào là chín? - Chín nơi cư trú của các loài hữu tình. Thế nào là mười? - Vị nào có đủ mười đức tánh được gọi là vị A-la-hán.`, ref: "Kinh Tiểu Tụng 4", url: "https://loicuaducphat.org/kp/kp4.html#content" },
       
               { text: `"Do cái này có mặt, cái kia hiện hữu. Do cái này sanh, cái kia sanh. Tức là duyên vô minh, có các hành; duyên các hành, có thức; duyên thức, có danh sắc; duyên danh sắc, có sáu xứ; duyên sáu xứ, có xúc; duyên xúc, có thọ; duyên thọ, có ái; duyên ái, có thủ; duyên thủ, có hữu; duyên hữu, có sanh; duyên sanh, có già, chết, sầu bi khổ ưu não. Như vậy là sự tập khởi của khổ uẩn này".\n\n1. Thật sự, khi các pháp,\nCó mặt, hiện khởi lên,\nÐối vị Bà-la-môn,\nNhiệt tâm hành thiền định,\n\nKhi ấy, với vị ấy,\nCác nghi hoặc tiêu trừ,\nVì biết rõ hoàn toàn,\nPháp cùng với các nhân.`, ref: "Udana 1.1", url: "https://loicuaducphat.org/ud/ud1.1.html#content" },

{ text: `"Do cái này không có mặt, cái kia không hiện hữu. Do cái này diệt, cái kia diệt. Tức là, do vô minh diệt nên hành diệt; do hành diệt, nên thức diệt; do thức diệt, nên danh sắc diệt; do danh sắc diệt nên sáu xứ diệt; do sáu xứ diệt nên xúc diệt, do xúc diệt nên thọ diệt, do thọ diệt, nên ái diệt; do ái diệt, nên thủ diệt; do thủ diệt, nên hữu diệt; do hữu diệt, nên sanh diệt; do sanh diệt, nên già, chết, sầu, bi, khổ, ưu não diệt. Như vậy là đoạn diệt của khổ uẩn này".\n\n2. Thật sự khi các pháp,\nCó mặt, hiện khởi lên,\nÐối với vị Bà-la-môn,\nNhiệt tâm, hành thiền định,\n\nKhi ấy, với vị ấy,\nCác nghi hoặc tiêu trừ,\nVì đã biết hoàn toàn,\nSự chấm dứt các duyên.`, ref: "Udana 1.2", url: "https://loicuaducphat.org/ud/ud1.2.html#content" },

{ text: `3. Thật sự khi các pháp\nCó mặt, hiện khởi lên,\nÐối với vị Bà-la-môn,\nNhiệt tâm hành thiền định,\n\nQuét sạch các ma quân,\nVị ấy đứng, an trú,\nNhư ánh sáng mặt trời,\nChói sáng khắp hư không.`, ref: "Udana 1.3", url: "https://loicuaducphat.org/ud/ud1.3.html#content" },

{ text: `- Tôn giả Gotama, cho đến như thế nào là Bà-la-môn, và những pháp nào tác thành Bà-la-môn? Thế Tôn sau khi biết được ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n4. Vị Bà-la-môn nào,\nLoại trừ các ác pháp,\nKhông kiêu, không uế nhiễm,\nTự ngã khéo chế ngự,\nVệ-đà được thông đạt,\nPhạm hạnh được viên thành,\n\nVị Bà-la-môn ấy,\nCó thể nói lên được,\nLời Phạm ngữ đúng pháp,\nVị ấy ở đời này,\nKhông hề có mạn tâm\nBất cứ ở nơi nào.`, ref: "Udana 1.4", url: "https://loicuaducphat.org/ud/ud1.4.html#content" },

{ text: `- Cho đến như thế nào, bạch Thế Tôn, là Bà-la-môn, và có bao nhiêu pháp, tác thành Bà-la-môn?\n\n5. Sau khi loại ác pháp,\nAi thường hành chánh niệm,\nKiết sử đoạn, giác ngộ,\nNhững vị ấy ở đời,\nThật là Bà-la-môn.`, ref: "Udana 1.5", url: "https://loicuaducphat.org/ud/ud1.5.html#content" },

{ text: `6. Ai sống không nhờ người,\nKhông được người biết đến,\nSống tự mình chế ngự,\nAn trú trên lõi cây,\n\nCác lậu hoặc đã đoạn,\nSân hận được trừ diệt,\nVị ấy được Ta gọi,\nLà vị Bà-la-môn.`, ref: "Udana 1.6", url: "https://loicuaducphat.org/ud/ud1.6.html#content" },

{ text: `Thế Tôn thấy nhiều kẻ bện tóc ấy, trong những đêm gió lạnh mùa đông, giữa những ngày mồng tám, trong thời tuyết rơi, đang lặng xuống và nổi lên trong nước, làm việc lặn xuống nổi lên, tưới nước và tế lửa, nghĩ rằng: "Với hành động này, được thanh tịnh." Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n9. Thanh tịnh không phải nước,\nỞ đây nhiều người tắm,\nTrong ai có chân thật,\nLại thêm có Chánh pháp,\nNgười ấy là Thanh tịnh,\nNgười ấy là Phạm chí.`, ref: "Udana 1.9", url: "https://loicuaducphat.org/ud/ud1.9.html#content" },

{ text: `- Vậy này Bàhiya, Ông cần phải học tập như sau: "Trong cái thấy, sẽ chỉ là cái thấy. Trong cái nghe, sẽ chỉ là cái nghe. Trong cái thọ tưởng, sẽ chỉ là cái thọ tưởng. Trong cái thức tri, sẽ chỉ là các thức tri ". Như vậy, này Bàhiya, Ông cần phải học tập. Vì rằng, này Bàhiya, nếu với Ông, trong cái thấy, sẽ chỉ là cái thấy; trong cái nghe, sẽ chỉ là cái nghe; trong cái thọ tưởng, sẽ chỉ là cái thọ tưởng; trong cái thức tri, sẽ chỉ là cái thức tri. Do vậy, này Bàhiva, ông không là chỗ ấy. Vì rằng, này Bàhiya, Ông không là đời này, không là đời sau, không là đời chặng giữa. Như vậy là đoạn tận khổ đau.`, ref: "Udana 1.10", url: "https://loicuaducphat.org/ud/ud1.10.html#content" },

{ text: `10. Chỗ nào nước và đất,\nLửa, gió không chấp trước,\nTại đây sao không chói,\nMặt trời không chiếu sáng,\nTại đây trăng không chiếu,\nTại đây u ám không.\n\nKhi ẩn sĩ Phạm chí,\nTự mình với trí tuệ,\nThể nhập vào Chánh pháp,\nVị ấy được giải thoát\nKhỏi sắc và vô sắc,\nKhỏi an lạc, đau khổ.`, ref: "Udana 1.10", url: "https://loicuaducphat.org/ud/ud1.10.html#content" },

{ text: `1. Viễn ly là an lạc,\nVới người biết tri túc,\nVới người có nghe pháp,\nVới người có chánh kiến\n\nKhông sân là an lạc,\nNhững ai ở trên đời,\nÐối hữu tình chúng sanh\nBiết tự chế, ngăn ngừa.\n\nLy tham là an lạc,\nVượt các dục ở đời,\nAi nhiếp phục ngã mạn,\nÐây an lạc tối thượng.`, ref: "Udana 2.1", url: "https://loicuaducphat.org/ud/ud2.1.html#content" },

{ text: `- Này các Tỷ-kheo, thật không thích đáng cho các Thầy, những thiện nam tử vì lòng tin xuất gia, từ bỏ gia đình, sống không gia đình, lại nói câu chuyện như vậy. Này các Tỳ-kheo, khi các Thầy hội họp với nhau, có hai việc cần phải làm: Ðàm luận về Chánh pháp hay giữ sự im lặng của bậc Thánh.\n\n2. Dục lạc gì ở đời,\nKể cả thiên lạc này,\nKhông bằng phần mười sáu,\nLạc do ái đoạn diệt.`, ref: "Udana 2.2", url: "https://loicuaducphat.org/ud/ud2.2.html#content" },

{ text: `4. Giữa làng, tại núi rừng,\nCảm thọ khổ và lạc,\nChớ quy về tự mình,\nChớ quy về người khác,\n\nCác xúc được cảm thọ,\nLà do duyên sanh y,\nVới vị không sanh y,\nDo đâu, xúc cảm thọ.`, ref: "Udana 2.4", url: "https://loicuaducphat.org/ud/ud2.4.html#content" },

{ text: `- Ðã lâu rồi, này Nam cư sĩ, ông tạo nên cơ hội này, tức là đến đây! - Bạch Thế Tôn, đã lâu rồi, con muốn yết kiến Thế Tôn. Nhưng con bị bận bịu lợi bởi những công việc phải làm này nên con không thể đi đến yết kiến Thế Tôn được. Rồi Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n5. Ai lão luyện Chánh pháp,\nÐược nghe nhiều Chánh pháp,\nKhông xem bất cứ gì\nLà an lạc của mình.\n\nHãy xem, não hại thay,\nNhững ai có sở hữu,\nKhiến cho con người này,\nBị trói buộc người khác.`, ref: "Udana 2.5", url: "https://loicuaducphat.org/ud/ud2.5.html#content" },
{ text: `6. An lạc thay là người\nKhông có gì sở hữu,\nNgười chánh tri hiểu biết,\nKhông có gì sở hữu.\n\nHãy xem não hại thay,\nNhững ai có sở hữu,\nKhiến cho con người này,\nBị trói buộc người khác.`, ref: "Udana 2.6", url: "https://loicuaducphat.org/ud/ud2.6.html#content" },

{ text: `- Bạch Thế Tôn, người con trai độc nhất của con khả ái, khả ý đã mệnh chung. Do vậy chúng con với áo ướt đẫm, với tóc ướt đẫm đã đến đây trong lúc quá sớm!\n\nRồi Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy nói lên lời cảm hứng này:\n\n7. Bị khả ái, dễ thương\nTrói buộc và chi phối,\nRất nhiều chư Thiên chúng,\nVà nhiều hạng con người\nÐau khổ và héo mòn,\nBị thần chết nhiếp phục.\n\nNgày đêm không phóng dật,\nTừ bỏ dung sắc đẹp,\nVị ấy đào gốc khổ,\nMồi nhử của ác ma,\nThật khó vượt qua được.`, ref: "Udana 2.7", url: "https://loicuaducphat.org/ud/ud2.7.html#content" },

{ text: `8. Không vui, giả dạng vui,\nKhông ái, giả dạng ái,\nKhổ đau, giả dạng lạc,\nNhiếp phục kẻ phóng dật.`, ref: "Udana 2.8", url: "https://loicuaducphat.org/ud/ud2.8.html#content" },

{ text: `10. Với ai, trong nội tâm,\nKhông có lòng phẫn nộ,\nVượt qua hữu, phi hữu,\nVị ấy thoát sợ hãi,\nAn lạc, không sầu muộn,\nChư Thiên không thấy được.`, ref: "Udana 2.10", url: "https://loicuaducphat.org/ud/ud2.10.html#content" },

{ text: `Rồi Thế Tôn thấy vị Tỷ-kheo ấy ngồi kiết già, lưng thẳng, chịu đựng sự đau đớn, kết quả của nghiệp về trước, nhói đau, cực khổ, thống khổ, chánh niệm, tỉnh giác, không có sầu não. Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n1. Tỷ-kheo bỏ mọi nghiệp,\nTẩy sạch bụi làm trước,\nAn trú, không ngã sở,\nKhông cần nói với người.`, ref: "Udana 3.1", url: "https://loicuaducphat.org/ud/ud3.1.html#content" },

{ text: `2. Ai vượt khỏi bùn này,\nÐè bẹp gai của dục,\nÐạt được si đoạn diệt,\nVị Tỷ-kheo như vậy,\nKhông cảm thọ khổ lạc!`, ref: "Udana 3.2", url: "https://loicuaducphat.org/ud/ud3.2.html#content" },

{ text: `3. Ai đã thắng gai dục,\nNắng, gia hại, trói buộc,\nVị ấy đứng bất động,\nNhư núi vững an trú,\nVị Tỷ-kheo như vầy,\nLạc khổ không dao động.`, ref: "Udana 3.3", url: "https://loicuaducphat.org/ud/ud3.3.html#content" },

{ text: `Thế Tôn thấy Tôn giả Sàriputta ngồi không xa bao nhiêu, ngồi kiết già lưng thẳng, đặt niệm trước mặt. Rồi Thế Tôn sau khi biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng:\n\n4. Như ngọn núi bằng đá,\nKhông động, khéo an trú,\nCũng vậy vị Tỳ-kheo,\nÐoạn diệt được ngu si,\nNhư ngọn núi bằng đá,\nKhông có bị dao động.`, ref: "Udana 3.4", url: "https://loicuaducphat.org/ud/ud3.4.html#content" },

{ text: `Thế Tôn thấy Tôn giả Maha Moggallàna ngồi không xa bao nhiêu, ngồi kiết-già lưng thẳng nội tâm khéo an trú thân hành niệm. Rồi Thế Tôn, sau khi biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n5. Thân hành niệm an lập,\nSáu xúc xứ chế ngự,\nTỷ-kheo thường thiền định,\nTự chứng tri Niết Bàn.`, ref: "Udana 3.5", url: "https://loicuaducphat.org/ud/ud3.5.html#content" },

{ text: `6. Trong ai không man trá,\nKhông mạn, tham đoạn tận,\nKhông ngã sở, không dục,\nPhẫn nộ được trừ diệt,\nTự ngã thành mát lạnh\nVị ấy là Phạm chí,\nLà Sa môn Tỷ-kheo.`, ref: "Udana 3.6", url: "https://loicuaducphat.org/ud/ud3.6.html#content" },

{ text: `7. Vị Tỷ-kheo khất thực,\nTự sống không nhờ người,\nChư Thiên thương vị ấy,\nThường an tịnh chánh niệm.`, ref: "Udana 3.7", url: "https://loicuaducphat.org/ud/ud3.7.html#content" },

{ text: `8. Vị Tỷ-kheo khất thực,\nTự sống không nhờ người,\nChư Thiên thương vị ấy,\nNhưng nếu Tỷ-kheo ấy,\nY tựa vào danh vọng,\nChư Thiên không có thương.`, ref: "Udana 3.8", url: "https://loicuaducphat.org/ud/ud3.8.html#content" },

{ text: `"Khi các Thầy ngồi hội họp với nhau, này các Tỷ-kheo, có hai công việc cần phải làm: Nói pháp hay giữ im lặng của bậc Thánh." Rồi Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n9. Ai sống không nghề nghiệp,\nNhẹ nhàng, muốn lợi ích,\nCác căn được chế ngự,\nToàn diện được giải thoát,\n\nKhông nhà, không ngã sở,\nKhông dục, giết ác ma,\nVị Tỷ-kheo như vậy,\nSống cô độc một mình.`, ref: "Udana 3.9", url: "https://loicuaducphat.org/ud/ud3.9.html#content" },

{ text: `Rồi Thế Tôn, sau bảy ngày ấy, từ định ấy xuất khởi, nhìn đời với Phật nhãn, thấy các chúng sanh bị thiêu đốt với nhiều loại thiêu đốt, bị nhiệt não bởi nhiều loại nhiệt não, bởi tham, bởi sân, bởi si. Rồi Thế Tôn, sau khi biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n10. Ðời này bị thiêu đốt,\nChi phần bởi cảm xúc,\nTự mình nói rõ lên,\nChứng bệnh của chính mình,\n\nBởi vì nó nghĩ đến,\nDo đó bị đổi khác,\nBị đổi khác vì hữu,\nBị lệ thuộc vì hữu,\nÐời này hữu chi phối,\nLại hoan hỷ với hữu,\n\nKhi nào có hoan hỷ,\nỞ đấy có sợ hãi,\nVới ai có sợ hãi,\nÐấy tức là đau khổ,\nChính do đoạn diệt hữu,\nPhạm hạnh này được sống.`, ref: "Udana 3.10", url: "https://loicuaducphat.org/ud/ud3.10.html#content" },

{ text: `Do duyên sanh y, khổ này được sanh khởi. Chính do đoạn diệt tất cả sanh y, khổ không có hiện hữu.\n\nHãy xem đời rộng này,\nBị vô minh chi phối,\nCác sanh loại được sanh,\nƯa thích được sanh khởi,\nKhông thoát được sanh hữu.\n\nVới ai đốt sanh hữu,\nTất cả mọi thời, xứ,\nTất cả sanh hữu này,\nVô thường khổ biến hoại,\n\nNhư vậy, thấy như thật,\nVới chơn chánh trí tuệ,\nHữu ái được đoạn tận,\nPhi hữu ái hoan hỷ.\n\nÐoạn diệt ái hoàn toàn,\nLy tham, diệt, hoàn toàn,\nNhư vậy là Niết Bàn,\nTỷ-kheo ấy mát lạnh,\nKhông chấp thủ tái sanh,\nNhiếp phục được ma vương,\nTrận chiến đã chiến thắng,\nVị Tỷ-kheo như vậy,\nVượt qua mọi sanh hữu.`, ref: "Udana 3.10", url: "https://loicuaducphat.org/ud/ud3.10.html#content" },

{ text: `Ở đây thiện bạn hữu, thiện thân hữu là pháp thứ nhất, này Meghiya, khiến tâm giải thoát chưa thuần thục đi đến thuần thực. Lại nữa, này Meghiya, Tỷ-kheo giữ giới, sống chế ngự với sự chế ngự của giới bổn Pàtimokha, đầy đủ uy nghĩ chánh hạnh, thấy sợ hãi trong những lỗi nhỏ nhặt, chấp nhận và học tập trong các học pháp. Ðây là pháp thứ hai, này Meghiya, khiến tâm giải thoát chưa thuần thục, đi đến thuần thục. Lại nữa, này Meghiya, phàm có những câu chuyện nào nghiêm túc, thích ứng khai mở tâm, đưa đến nhất hướng nhàm chán, ly tham, đoạn diệt, an tịnh, thắng trí, giác ngộ, Niết-bàn, như câu chuyện về ít dục, câu chuyện về biết đủ, câu chuyện về viễn ly, câu chuyện về hòa hợp, câu chuyện về tinh cần, tinh tấn, câu chuyện về giới luật, câu chuyện về thiền định, câu chuyện về trí tuệ, câu chuyện về giải thoát, câu chuyện về giải thoát tri kiến. Những câu chuyện như vậy có thể được không có khó khăn, có thể được không có mệt nhọc, có thể được không có phí sức. Ðây là pháp thứ ba, này Meghiya, khiến cho tâm giải thoát chưa thuần thục đi đến thuần thục.`, ref: "Udana 4.1", url: "https://loicuaducphat.org/ud/ud4.1.html#content" },

{ text: `Lại nữa, này Meghiya, vị Tỷ-kheo sống tinh cần, tinh tấn, để đoạn tận các pháp không thiện, để làm sanh khởi các pháp thiện, kiên trì, cương quyết, không từ bỏ gánh nặng đối với pháp thiện. Ðây là pháp thứ tư, này Meghiya, khiến cho tâm giải thoát chưa thuần thục, đi đến thuần thục. Lại nữa, này Meghiya, vị Tỷ-kheo có trí tuệ, đầy đủ trí tuệ, đi đến thẩm sát sanh diệt, với Thánh thể nhập đưa đến đoạn tận khổ đau. Ðây là pháp thứ năm. Này Meghiya, khiến tâm thoát chưa thuần thục đi đến thuần thục.`, ref: "Udana 4.1", url: "https://loicuaducphat.org/ud/ud4.1.html#content" },

{ text: `Lại nữa, này Meghiya, với vị Tỷ-kheo khéo an trú trong năm pháp này, bốn pháp cần phải tu tập thêm: Bất tịnh cần phải tu tập để đoạn tận tham; Từ cần phải tu tập để đoạn tận sân; Niệm hơi thở vô hơi thở ra cần phải tu tập để trừ khử tầm tư; Vô thường tưởng cần phải tu tập để nhổ lên kiêu mạn, tôi là. Này Meghiya, với ai có tưởng vô thường, tưởng vô ngã được an trú. Với ai có tưởng vô ngã, vị ấy đạt được sự nhổ lên kiêu mạn: tôi là, Niết-bàn ngay trong hiện tại.`, ref: "Udana 4.1", url: "https://loicuaducphat.org/ud/ud4.1.html#content" },

{ text: `1. Các tầm nhỏ tế nhị,\nHiện hành ý hoan hỷ,\nDo không biết đến chúng,\nTâm động chạy nhiều đời,\n\nNếu biết chúng tầm tư,\nNhiệt tâm và chánh niệm,\nChế ngự được tư tưởng,\nKhi ý không hoan hỷ,\nBậc Chánh giác bỏ chúng,\nKhông còn chút dư tàn.`, ref: "Udana 4.1", url: "https://loicuaducphat.org/ud/ud4.1.html#content" },

{ text: `Thế Tôn thấy số đông các Tỷ-kheo ấy, đang sống trong những cốc ở trong rừng, tháo động, kiêu căng, dao động, lắm mồm, lắm miệng, lắm lời, thất niệm, không tỉnh giác, không định tĩnh, tâm tán loạn, các căn thả lỏng. Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n2. Với thân không hộ trì,\nVới tà kiến chi phối,\nBị hôn trầm thụy miên,\nNhiếp phục và chế ngự,\nKẻ ấy bị rơi vào\nUy lực của Ma vương.\n\nDo vậy hộ trì tâm,\nSở hành chánh tư duy,\nÐặt chánh kiến hàng đầu,\nRõ biết tánh sanh diệt,\n\nNhiếp phục và chế ngự,\nHôn trầm và thụy miên\nVị Tỷ-kheo như vậy,\nTừ bỏ mọi ác thú.`, ref: "Udana 4.2", url: "https://loicuaducphat.org/ud/ud4.2.html#content" },

{ text: `4. Tâm ai như tảng đá,\nAn trú không dao động,\nKhông tham vật khả ái,\nÐáng phẫn nộ, không sân,\nTâm ai tu như vậy,\nTừ đâu khổ đến được?`, ref: "Udana 4.4", url: "https://loicuaducphat.org/ud/ud4.4.html#content" },

{ text: `Thế Tôn thấy Tôn giả Pindolabhàradvàja ngồi không xa bao nhiêu, ngồi kiết-già lưng thẳng, sống ở rừng, đi khất thực, mặc y lượm từ đống rác, chỉ mang ba y, ít dục, biết đủ, viễn ly, không ưa thích hội họp, tinh cần tinh tấn, nói hạnh đầu đà, chú tâm vào tăng thượng tâm. Rồi Thế Tôn sau khi rõ biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n6. Không mắng, không gia hại,\nChế ngự trong giới bổn,\nTiết độ trong ăn uống,\nNằm ngồi chỉ một mình,\nChú tâm vào tăng thượng,\nChính lời chư Phật dạy.`, ref: "Udana 4.6", url: "https://loicuaducphat.org/ud/ud4.6.html#content" },

{ text: `Thế Tôn thấy Tôn giả Sàriputta ngồi không xa bao nhiêu, kiết già lưng thẳng, ít dục, biết đủ, viễn ly, không ưa hội họp, tinh cần tinh tấn, chú tâm vào tăng thượng tâm. Rồi Thế Tôn sau khi biết ý nghĩa này, ngay lúc ấy, nói lên lời cảm hứng này:\n\n7. Tâm tăng thượng ẩn sĩ,\nKhông phóng dật, tu tập,\nTrên con đường chánh trí,\nVị ấy không cầu muộn,\nLuôn luôn được an tịnh,\nThường nắm giữ chánh niệm.`, ref: "Udana 4.7", url: "https://loicuaducphat.org/ud/ud4.7.html#content" },

{ text: `9. Người không biết chế ngự,\nVới lời đâm người khác,\nGiống như voi bị đâm,\nKhi tham gia chiến trận.\n\nNghe những lời thô ác,\nTỷ-kheo hãy chịu đựng,\nGiữ gìn không nói lên,\nTâm không có hiềm hận.`, ref: "Udana 4.8", url: "https://loicuaducphat.org/ud/ud4.8.html#content" },

{ text: `10. Ai sống không nhiệt não\nKhi chết không sầu muộn,\nBậc trí nếu thấy đường\nGiữa sầu, không sầu muộn.\n\nTỷ-kheo đoạn hữu ái,\nTâm tư được an tịnh,\nLuân hồi sanh tử tận,\nVị ấy không tái sanh.`, ref: "Udana 4.9", url: "https://loicuaducphat.org/ud/ud4.9.html#content" },

{ text: `Thế Tôn thấy Tôn giả Sàriuptta, ngồi xa Thế Tôn không bao nhiêu, ngồi kiết-già, lưng thẳng, quán sát sự an tịnh của mình. Rồi Thế Tôn sau khi biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng:\n\n11. Tỷ-kheo tâm an tịnh,\nChặt đứt dây sanh tử,\nLuân hồi sanh tử tận,\nThoát khỏi ma trói buộc.`, ref: "Udana 4.10", url: "https://loicuaducphat.org/ud/ud4.10.html#content" },

{ text: `1. Tâm ta đi cùng khắp,\nTất cả mọi phương trời,\nCũng không tìm thấy được,\nAi thân hơn tự ngã,\n\nTự ngã đối mọi người,\nQuá thân ái như vậy,\nVậy ai yêu tự ngã,\nChớ hại tự ngã người.`, ref: "Udana 5.1", url: "https://loicuaducphat.org/ud/ud5.1.html#content" },

{ text: `2. Tất cả hữu tình nào,\nSẽ có mặt ở đời,\nTất cả chúng sẽ đi,\nSau khi bỏ sắc thân,\nHiểu tất cả là vậy,\nBậc thiện sanh nhiệt tâm,\nSống đời sống Phạm hạnh.`, ref: "Udana 5.2", url: "https://loicuaducphat.org/ud/ud5.2.html#content" },

{ text: `3. Như người có mắt nhìn,\nCố gắng tránh lồi lõm,\nCũng vậy kẻ trí tránh,\nÐiều ác giữa đời này.`, ref: "Udana 5.3", url: "https://loicuaducphat.org/ud/ud5.3.html#content" },

{ text: `Thế Tôn thấy nhiều thiếu niên giữa Sàvatthi và Jetavana đang hành hạ các con cá, thấy vậy đi đến các thiếu niên ấy, sau khi đến nói với chúng: - Này các Thiếu niên, các Em có sợ đau khổ không? Các Em không ưa thích khổ phải không?". - Thưa vâng, bạch Thế Tôn, chúng con sợ đau khổ. Chúng con không ưa thích khổ.\n\nRồi Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n4. Nếu con không ưa khổ,\nDầu bất cứ chỗ nào,\nChớ làm các nghiệp ác,\nTrước mặt hay sau lưng\n\nNếu Con làm, sẽ làm,\nCác nghiệp ác, bất thiện,\nCon không giải thoát khổ,\nDầu nhảy vọt và chạy.`, ref: "Udana 5.4", url: "https://loicuaducphat.org/ud/ud5.4.html#content" },

{ text: `Ví như, này các Tỷ-kheo, biển lớn tuần tự thuận xuôi, tuần tự thuận hướng, tuần tự sâu dần, không có thình lình như một vực thẳm. Cũng vậy này các Tỷ-kheo, trong Pháp và Luật này, các học pháp và tuần tự, các quả dị thục là tuần tự, các con đường là tuần tự, không có sự thể nhập chánh trí, thình lình. Này các Tỷ-kheo, vì rằng trong Pháp và Luật này, các học pháp là tuần tự, các quả dị thực là tuần tự, các con đường là tuần tự, không có sự thể nhập chánh trí thình lình. Này các Tỷ-kheo, trong Pháp và Luật này, đây là vi diệu chưa từng có thứ nhất. Do thấy vậy, thấy vậy, Tỷ-kheo thích thú trong Pháp và Luật này.`, ref: "Udana 5.5", url: "https://loicuaducphat.org/ud/ud5.5.html#content" },

{ text: `Ví như, này các Tỷ-kheo, biển lớn không có chứa chấp xác chết. Nếu có xác chết trong biển lớn, lập tức bị quăng trên bờ hay vất lên đất liền. Cũng vậy, này các Tỷ-kheo, người nào là ác giới, theo ác pháp, sở hành bất tịnh đáng nghi ngờ, có những hành vi che đậy, không phải là Sa-môn nhưng tự nhận là Sa-môn, không sống Phạm hạnh nhưng tự nhận là có Phạm hạnh, nội tâm hôi hám, ứ đầy tham dục, tánh tình bất định. Chúng Tăng không sống chung với người ấy, lập tức hội họp lại và đuổi người ấy ra khỏi. Dầu cho người ấy có ngồi giữa chúng Tỷ-kheo tăng, nhưng người ấy sống xa chúng Tăng và chúng Tăng sống xa người ấy. Này các Tỷ-kheo, trong Pháp và Luật này, đây là pháp vi diệu chưa từng có thứ ba. Do thấy vậy, thấy vậy, Tỷ-kheo thích thú trong Pháp và Luật này.`, ref: "Udana 5.5", url: "https://loicuaducphat.org/ud/ud5.5.html#content" },

{ text: `Ví như, này các Tỷ-kheo, phàm có các con sông lớn nào, ví như sông Hằng, sông Yamunà, sông Aciracati, sông Sarabhù, sông Mahi, các con sông ấy khi chảy đến biển, liền bỏ tên họ trước, trở thành biển lớn. Cũng vậy, này các Tỷ-kheo, có bốn giai cấp này: Sát-đế-lị, Bà-la-môn, Phệ-xá, Thủ-đà, sau khi từ bỏ gia đình, sống không gia đình, xuất gia trong Pháp và Luật được Như Lai tuyên bố sau này, chúng từ bỏ tên và họ của chúng từ trước, và chúng trở thành những Sa môn Thích tử. Này các Tỷ-kheo, trong Pháp và Luật này, đây là pháp vi diệu chưa từng có thứ tư. Do thấy vậy, thấy vậy, Tỷ-kheo thích thú trong Pháp và luật này.`, ref: "Udana 5.5", url: "https://loicuaducphat.org/ud/ud5.5.html#content" },

{ text: `Ví như, này các Tỷ kheo, phàm có những dòng nước gì ở đời chảy vào biển lớn, phàm có những nước mưa từ trời rơi xuống, nhưng không vì vậy mà biển lớn có giảm tăng. Cũng vậy này các Tỷ Kheo, nếu có những vị Tỷ kheo nhập vào Niết Bàn giới, không có dư y, Niết bàn giới cũng không vì vậy được thấy có giảm tăng. Này các Tỳ Kheo, nếu có nhiều vị Tỷ kheo nhập vào Niết Bàn giới không có dư y, Niết bàn giới cũng không vì vậy, được thấy có giảm tăng. Này các Tỷ-kheo, trong Pháp và Luật này, đây là vi diệu thứ năm. Do thấy vậy, thấy vậy, Tỷ-kheo thích thú trong Pháp và luật này.`, ref: "Udana 5.5", url: "https://loicuaducphat.org/ud/ud5.5.html#content" },

{ text: `Ví như, này các Tỷ-kheo, biển lớn chỉ có một vị là vị mặn. Cũng vậy, này các Tỷ-kheo, pháp này cũng chỉ có một vị là vị giải thoát. Vì rằng, này các Tỷ-kheo, pháp này cũng chỉ có một vị là vị giải thoát. Này các Tỷ-kheo, trong Pháp và Luật này, đây là vi diệu chưa từng có thứ sáu. Do thấy vậy, thấy vậy, Tỷ-kheo thích thú trong Pháp và Luật này.`, ref: "Udana 5.5", url: "https://loicuaducphat.org/ud/ud5.5.html#content" },

{ text: `Ví như, này các Tỷ-kheo, biển lớn có nhiều châu báu, ở đấy có những châu báu này, như trân châu, ma-ni châu, lưu-ly, xà-cừ, ngọc bích, san-hô, bạc, vàng, ngọc đỏ, mã-não. Cũng vậy này các Tỷ-kheo, Pháp và Luật này có nhiều châu báu, nhiều loại châu báu, ở đấy có những loại châu báu này, như Bốn niệm xứ, Bốn chánh cần, Bốn như ý túc, Năm căn, Năm lực, Bảy giác chi, Thánh đạo tám ngành. Này các Tỷ-kheo, trong Pháp và Luật này, đây là vi diệu chưa từng có thứ bảy. Do thấy vậy, thấy vậy, các Tỷ-kheo thích thú trong Pháp và Luật này.`, ref: "Udana 5.5", url: "https://loicuaducphat.org/ud/ud5.5.html#content" },

{ text: `- Bạch Thế Tôn, đã lâu con thấy sự nguy hại trong các dục, sự bó buộc của đời sống gia đình, nhiều phận sự, nhiều công việc phải làm.\n\nThế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng:\n\n6. Thấy nguy hại ở đời,\nBiết pháp không sanh y,\nBậc Thánh không ưa ác,\nBậc tịnh không ưa ác!`, ref: "Udana 5.6", url: "https://loicuaducphat.org/ud/ud5.6.html#content" },

{ text: `Thế Tôn thấy Tôn giả Kankharevata ngồi không xa bao nhiêu, ngồi kiết-già, lưng thẳng tự mình quán sát sự thanh tịnh do vượt qua được nghi ngờ. Rồi Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng:\n\n7. Phàm những nghi hoặc gì,\nÐời này hay đời sau,\nTự mình chưa cảm thọ,\nHay người khác cảm thọ,\nNgười hành thiền từ bỏ,\nHoàn toàn tất cả chúng,\nNhiệt tâm hành Phạm hạnh.`, ref: "Udana 5.7", url: "https://loicuaducphat.org/ud/ud5.7.html#content" },

{ text: `8. Dễ làm là việc lành,\nÐối với kẻ làm lành;\nKhó làm là việc ác,\nÐối với kẻ làm lành;\n\nDễ làm là việc ác,\nÐối với kẻ làm ác;\nKhó làm là việc ác,\nÐối với các bậc Thánh.`, ref: "Udana 5.8", url: "https://loicuaducphat.org/ud/ud5.8.html#content" },

{ text: `Thế Tôn thấy Tôn giả Cùlapanthaka ngồi không xa bao nhiêu, ngồi kiết già, lưng thẳng để niệm trước mặt. Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng:\n\n10. Với thân, tâm an trú,\nÐứng, ngồi hay nằm xuống,\nTỷ-kheo an trú niệm,\nTrước sau được thù thắng,\nTrước sau được thù thắng,\nVượt tầm mắt ác ma.`, ref: "Udana 5.10", url: "https://loicuaducphat.org/ud/ud5.10.html#content" },

{ text: `2. Phải siêng năng cố gắng,\nTại bất cứ chỗ nào,\nChớ trở thành là người\nThuộc vào con người khác,\n\nChớ có sống ỷ lại,\nNương tựa vào ngưòi khác,\nChớ sống nghề buôn bán,\nÐem pháp để kiếm lời.`, ref: "Udana 6.2", url: "https://loicuaducphat.org/ud/ud6.2.html#content" },

{ text: `Do họ không biết mục đích, do họ không biết không phải mục đích, do không biết pháp, do không biết phi pháp, họ sống cạnh tranh, luận tranh, đấu tranh, đả thương nhau bằng binh khí miệng lưỡi: "Như thế này là pháp. Như thế này là pháp. Như thế này không phải pháp. Như thế này không phải pháp". Rồi Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng:\n\n4. Có một số Sa-môn,\nCùng với Bà-la-môn,\nHọ chấp trước, giành giật,\nTrong các luận thuyết này,\nHọ tranh luận tranh chấp,\nHọ nhìn chỉ một phía.`, ref: "Udana 6.4", url: "https://loicuaducphat.org/ud/ud6.4.html#content" },

{ text: `6. Có người ở đời này,\nChấp người làm là ta,\nTrói buộc với tư tưởng,\nNgười làm là người khác,\nHọ không biết sự này,\nHọ thấy là mũi tên,\n\nAi nhìn mũi tên này,\nVới thận trọng cần thiết,\nNgười ấy không còn chấp,\n"Người làm chính là ta",\nNgười ấy cũng không chấp,\n"Người làm là người khác",\n\nLoài người ở đời này,\nBị kiêu mạn khiếp phục,\nBị cột bởi kiêu mạn,\nBị trói bởi kiêu mạn,\nTrong các loài chủ thuyết,\nHọ cạnh tranh, luận tranh,\nHọ không thể vượt qua,\nLuân chuyển trong sanh tử.`, ref: "Udana 6.6", url: "https://loicuaducphat.org/ud/ud6.6.html#content" },

{ text: `Thế Tôn thấy Tôn giả Subhùti ngồi không xa bao nhiêu, ngồi kiết-già lưng thẳng, nhập định không tầm. Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy nỗi lên lời cảm hứng:\n\n7. Với ai, tầm quét sạch,\nNội tâm khéo cắt đứt,\nKhông còn chút dư tàn\nVượt qua ái nhiễm ấy,\n\nÐạt được tưởng vô sắc,\nVượt khỏi bốn ách nạn,\nKhông đi đến thọ sanh.`, ref: "Udana 6.7", url: "https://loicuaducphat.org/ud/ud6.7.html#content" },

{ text: `10. Con đôm đốm chiếu sáng,\nKhi mặt trời chưa mọc,\nKhi mặt trời mọc lên,\nÁnh sáng đôm đốm diệt,\n\nCũng vậy là ánh sáng,\nCủa các nhà ngoại đạo,\nKhi bậc Chánh Ðẳng Giác\nChưa xuất hiện ở đời,\n\nCác nhà ưa biện luận.\nKhông có được ánh sáng,\nCũng vậy đệ tử chúng,\nCòn các nhà tà kiến,\nHọ không được giải thoát,\nKhỏi các sự đau khổ.`, ref: "Udana 6.10", url: "https://loicuaducphat.org/ud/ud6.10.html#content" },

{ text: `1. Trên dưới khắp tất cả,\nÐược giải thoát hoàn toàn,\nKhông còn có tùy quán\n"Cái này chính là tôi".\n\nGiải thoát vậy vượt dòng,\nTrước chưa từng vượt qua,\nKhông còn có rơi rớt\nVào sanh hữu thọ sanh.`, ref: "Udana 7.1", url: "https://loicuaducphat.org/ud/ud7.1.html#content" },

{ text: `2. Cắt đứt được luân chuyển,\nÐạt được sự không dục,\nHoàn toàn được khô cạn,\nNước sông không chảy nữa,\nVòng luân hồi cắt đứt,\nKhông còn quay tiếp nữa\nLà tận cùng khổ đau.`, ref: "Udana 7.2", url: "https://loicuaducphat.org/ud/ud7.2.html#content" },

{ text: `"Ở đây, bạch Thế Tôn, nhiều người ở Sàvatthi, phần lớn đắm say quá độ về các dục, sống say đắm, tham đắm, tham muốn, tham mê, bị trói buộc, bị mê say trong các dục." Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n3. Chúng sanh bị tham đắm,\nTrong các loại ái dục,\nHọ không thấy lỗi lầm,\nTrong phiền não kiết sử,\n\nChắc chắn các chúng sanh,\nTrói buộc trong kiết sử,\nHọ không vượt qua được,\nDòng lũ lớn rộng này.`, ref: "Udana 7.3", url: "https://loicuaducphat.org/ud/ud7.3.html#content" },

{ text: `Rồi Thế Tôn thấy các người ấy ở Sàvatthi, phần lớn đắm say quá độ về các dục, sống say đắm, tham đắm, tham muốn, tham mê, bị trói buộc, bị mê say trong các dục. Rồi Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n4. Bị mù bởi các dục,\nBị bao phủ bởi lưới,\nBị ái dục bao trùm,\nLại còn bị trói buộc,\nBởi trói buộc phóng dật,\nNhư cá mắc miệng lưới,\nHọ đi đến già chết,\nNhư con bê bú sữa.`, ref: "Udana 7.4", url: "https://loicuaducphat.org/ud/ud7.4.html#content" },

{ text: `Thế Tôn thấy Tôn giả Annatakondanna ngồi không xa bao nhiêu, ngồi kiết già lưng thẳng, suy tư đến sự giải thoát do ái được diệt. Thế Tôn sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n6. Rễ không có bén đất,\nKhông lá, đâu dây leo,\nBậc trí thoát trói buộc,\nAi xứng đáng được khen,\nChư Thiên khen người ấy,\nPhạm Thiên cũng ngợi khen.`, ref: "Udana 7.6", url: "https://loicuaducphat.org/ud/ud7.6.html#content" },

{ text: `Lúc bấy giờ, Thế Tôn đang ngồi quán sát sự từ bỏ, đoạn diệt các hý luận tưởng. Rồi Thế Tôn sau khi biết sự từ bỏ, đoạn diệt các tưởng hý luận của mình, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n7. Với ai các hý luận,\nKhông còn có an trú,\nThoát ly được liên hệ,\nThoát ly được ảo tưởng,\n\nChư Thiên và thế giới,\nKhông thể nào rõ biết,\nSở hành vị ẩn sĩ,\nÐã vượt khỏi tham ái.`, ref: "Udana 7.7", url: "https://loicuaducphat.org/ud/ud7.7.html#content" },

{ text: `Thế Tôn thấy Tôn giả Mahàkaccàna ngồi không xa bao nhiêu, ngồi kiết già, lưng thẳng, với thân hành niệm khéo an trú trước mặt trong nội tâm. Rồi Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng này:\n\n8. Với ai thường thường niệm,\nLiên tục trú thân hành,\n"Trước không thể có được,\nVới tôi, nay không có,\nSẽ không thể có được,\nVới tôi, nay sẽ không".\nTiếp tục trú như vậy,\nÐúng thời vượt dục ái.`, ref: "Udana 7.8", url: "https://loicuaducphat.org/ud/ud7.8.html#content" },

{ text: `10. Ðời bị si trói buộc,\nÐược thấy bị tái sanh,\nBị trói bởi sanh y,\nKẻ ngu bị mù vây,\nTự thấy mình thường còn,\nNhưng với ai thấy được,\nSẽ không có vật gì.`, ref: "Udana 7.10", url: "https://loicuaducphat.org/ud/ud7.10.html#content" },

{ text: `- Này các Tỷ-kheo, có xứ này, tại đây không có đất, không có nước, không có lửa, không có gió; không có Hư không vô biên, không có Thức vô biên xứ, không có Vô sở hữu xứ, không có Phi tưởng phi phi tưởng xứ; không có đời này, không có đời sau, không có cả hai mặt trăng mặt trời. Do vậy, này các Tỷ-kheo, Ta tuyên bố không có đến, không có đi, không có trú, không có diệt, không có sanh; không có an trú, không có chuyện vận, không có sở duyên, đây là sự đoạn tận khổ đau.`, ref: "Udana 8.1", url: "https://loicuaducphat.org/ud/ud8.1.html#content" },

{ text: `Lúc bấy giờ, Thế Tôn đang thuyết giảng pháp thoại liên tưởng đến Niết-bàn cho các Tỷ-kheo, khích lệ làm cho phấn khởi, làm cho hoan hỷ. Các Tỷ-kheo ấy chú tâm, tác ý, dồn tất cả tâm tư lắng nghe pháp. Rồi Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng:\n\n1. Khó thấy là vô ngã,\nKhông dễ thấy, sự thật,\nVới bậc có hiểu biết,\nKhéo xâm nhập được ái,\nVới vị ấy thấy rõ,\nÐâu còn có vật gì.`, ref: "Udana 8.2", url: "https://loicuaducphat.org/ud/ud8.2.html#content" },

{ text: `– Này các Tỷ-kheo, có sự không sanh, không hiện hữu, không bị làm, không hữu vi. Này các Tỷ-kheo, nếu không có cái không sanh, không hiện hữu, không bị làm, không hữu vi, thì ở đây không thể trình bày sự xuất ly khỏi sanh, hiện hữu, bị làm, hữu vi. Vì rằng, này các Tỷ-kheo, có cái không sanh, không hiện hữu, không bị làm, không hữu vi, nên có trình bày sự xuất ly khỏi sanh, hiện hữu, bị làm, hữu vi.`, ref: "Udana 8.3", url: "https://loicuaducphat.org/ud/ud8.3.html#content" },

{ text: `- Cái gì có nương tựa, cái ấy có dao động. Cái gì không nương tựa, cái ấy không dao động. Không có dao động thì có khinh an. Có khinh an thì không có thiên về. Không có thiên về thì không có đến và đi; không có đến và đi thì không có diệt và sanh; không có diệt và sanh thì không có đời này, không có đời sau, không có đời ở giữa. Ðây là sự đoạn tận khổ đau.`, ref: "Udana 8.4", url: "https://loicuaducphat.org/ud/ud8.4.html#content" },

{ text: `4. Công đức người bố thí,\nLuôn luôn được tăng trưởng,\nTrừ được tâm hận thù,\nKhông chất chứa chế ngự,\n\nKẻ chí thiện từ bỏ,\nMọi ác hạnh bất thiện,\nDiệt trừ tham, sân, si.\nTâm giải thoát thanh tịnh.`, ref: "Udana 8.5", url: "https://loicuaducphat.org/ud/ud8.5.html#content" },

{ text: `Này các Gia chủ, có năm điều lợi ích này cho người giữ giới, cho người đầy đủ giới. Thế nào là năm? Ở đây, này các Gia chủ người giữ giới, người đầy đủ giới, do nhân duyên không phóng dật được tài sản lớn. Ðây là lợi ích thứ nhất cho người giữ giới, cho người đầy đủ giới. Lại nữa, này các Gia chủ, với người giữ giới, người đầy đủ giới, tiếng tốt lành được đồn xa. Ðây là lợi ích thứ hai cho người giữ giới, cho người đầy đủ giới. Lại nữa, này các Gia chủ, người giữ giới, người đầy đủ giới khi đi đến hội chúng nào, hoặc là Sát-đế-lỵ hoặc là Bà-la-môn, hoặc là gia-chủ, hoặc là Sa-môn, người ấy đi đến không có sợ hãi, không có ngỡ ngàng. Ðây là lợi ích thứ ba cho người giữ giới cho người có đầy đủ giới. Lại nữa, này các Gia chủ, người giữ giới, người đầy đủ giới, khi chết không có si ám. Ðây là lợi ích thứ tư cho người giữ giới, cho ngưòi có đầy đủ giới. Lại nữa, này các Gia chủ, người giữ giới, người đầy đủ giới khi thân hoại mạng chung được sanh thiện thú, Thiên giới, cõi đời này. Ðây là lợi ích thứ năm cho người giữ giới, cho người đầy đủ giới. Này các Gia chủ, có năm lợi ích này cho người giữ giới, cho ngưòi đầy đủ giới.`, ref: "Udana 8.6", url: "https://loicuaducphat.org/ud/ud8.6.html#content" },

{ text: `5. Tại chỗ nào bậc trí,\nLàm thành chỗ an trú,\nHãy cúng các món ăn,\nCho những người giữ giới,\nCho người biết chế ngự,\nSống đời sống Phạm hạnh,\nỞ đấy chư Thiên trú,\nHãy cúng dường chư Thiên.\n\nÐược cúng dường, chư Thiên,\nCúng dường lại vị ấy,\nÐược cung kính, chư Thiên,\nCung kính lại vị ấy,\nHọ từ mẫn vị ấy\nNhư mẹ thương con mình,\nNgười được chư Thiên thương,\nLuôn luôn thấy hiền thiện.`, ref: "Udana 8.6", url: "https://loicuaducphat.org/ud/ud8.6.html#content" },

{ text: `Và Thế Tôn đi đến sông Hằng, nước sông tràn đầy đến bờ, con quạ có thể uống được, một số người đi tìm thuyền, một số người đi tìm bè, một số người cột chiếc bè để đi qua sông. Rồi Thế Tôn, sau khi hiểu biết ý nghĩa này, ngay trong lúc ấy, nói lên lời cảm hứng:\n\n"Những ai làm cầu vượt biển trùng dương,\nbỏ lại đất sũng đầm ao,\ntrong khi người phàm phu đang cột bè.\nNhững người ấy thật là những vị trí tuệ được giải thoát."`, ref: "Udana 8.6", url: "https://loicuaducphat.org/ud/ud8.6.html#content" },

{ text: `- Này Visàkhà, những ai có một trăm người thân yêu, những người ấy có trăm sự đau khổ! Những ai có chín mươi người thân yêu, những người ấy có chín mươi sự đau khổ! Những ai có tám mươi người thân yêu, những người ấy có tám mươi sự đau khổ! Những ai có bảy mươi.. có sáu mươi... có năm mươi... có bốn mươi... có ba mươi.. có hai mươi... có mười.. có chín... có tám... có bảy..có sáu.. có năm... có bốn... có ba... có hai... có một người thân yêu, những người ấy có một sự đau khổ. Những ai không có người thân yêu, những người ấy không có sự đau khổ. Ta nói rằng họ là người không có sầu, không có tham đắm, không có ưu não.`, ref: "Udana 8.8", url: "https://loicuaducphat.org/ud/ud8.8.html#content" },

{ text: `8. Sầu, than và đau khổ,\nSai biệt có ở đời,\nDuyên thân ái, chúng có,\nKhông thân ái, chúng không,\nDo vậy, người an lạc,\n\nNgười không có sầu muộn,\nLà những ai ở đời,\nKhông có người thân ái,\nDo vậy ai tha thiết,\nÐược không sầu, không tham,\nChớ làm thân làm ái,\nVới một ai ở đời.`, ref: "Udana 8.8", url: "https://loicuaducphat.org/ud/ud8.8.html#content" },

{ text: `10. Như tia lửa cháy sáng,\nPhát từ búa sắt đập,\nDần dần được nguội lạnh,\nSanh thú không biết được,\n\nCũng vậy là những bậc\nÐã chân chánh giải thoát,\nÐã vượt qua thác nước,\nTrói buộc bởi các dục,\n\nHọ đạt được an lạc,\nKhông có bị dao động,\nHọ không có sanh thú,\nÐể có thể chỉ bày.`, ref: "Udana 8.10", url: "https://loicuaducphat.org/ud/ud8.10.html#content" },
       
                { text: `Này các Tỷ-kheo, hãy từ bỏ một pháp. Ta bảo đảm cho các Thầy không có tái sanh. Thế nào là một pháp? Tham, này các Tỷ-kheo, là một pháp, các Thầy hãy từ bỏ! Ta bảo đảm cho các Thầy không có tái sanh. Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này đã được nói đến.\n\nVới tham bị tham đắm,\nChúng sanh đi ác thú,\nBậc thiền quán, chánh trí,\nTừ bỏ tham ái ấy,\nTừ bỏ, không bao giờ\nTrở lại tại đời này.`, ref: "Itivuttaka 1", url: "https://loicuaducphat.org/iti/iti1.html#content" },
{ text: `Này các Tỷ-kheo, hãy từ bỏ một pháp. Ta bảo đảm cho các Thầy không có tái sanh. Thế nào là một pháp? Mạn, này các Tỷ kheo, là một pháp các Thầy hãy từ bỏ. Ta bảo đảm cho các Thầy không có tái sanh. Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này được nói đến.\n\nVới kiêu mạn kiêu căng,\nChúng sanh đi ác thú,\nBậc thiền quán, chánh trí\nTừ bỏ kiêu mạn ấy,\nTừ bỏ, không bao giờ\nTrở lại tại đời này.`, ref: "Itivuttaka 6", url: "https://loicuaducphat.org/iti/iti6.html#content" },

{ text: `Này các Tỷ-kheo, ai không thắng tri, không liễu tri tất cả, ở đây tâm không ly tham, từ bỏ, không thể diệt được khổ đau. Này các Tỷ-kheo, ai thắng tri, liễu tri tất cả, ở đây tâm ly tham, từ bỏ, có thể diệt được khổ đau. Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này được nói đến.\n\nAi hiểu, rõ biết được,\nTất cả là tất cả,\nÐối với tất cả chỗ,\nKhông có sự tham đắm,\nVị như vậy chắc chắn,\nLiễu tri được tất cả,\nVà có thể vượt qua,\nTất cả mọi đau khổ.`, ref: "Itivuttaka 7", url: "https://loicuaducphat.org/iti/iti7.html#content" },

{ text: `Này các Tỷ-kheo, ai không thắng tri không liễu tri Mạn, ở đây tâm không ly tham, không từ bỏ, thời không có thể diệt được khổ đau. Này các Tỷ-kheo, ai thắng tri liễu tri Mạn, ở đây tâm ly tham, từ bỏ, có thể diệt được khổ đau. Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này đã được nói đến.\n\nNgười bị mạn chi phối,\nDo bị mạn trói buộc,\nNên hoan hỷ sanh hữu,\nDo không liễu tri mạn,\nNên đi đến tái sanh.\n\nNhững ai đoạn diệt mạn,\nGiải thoát, mạn hoại diệt,\nHọ thắng mạn trói buộc,\nHọ vượt qua nhiếp phục,\nTất cả mọi đau khổ.`, ref: "Itivuttaka 8", url: "https://loicuaducphat.org/iti/iti8.html#content" },

{ text: `Này các Tỷ-kheo, Ta không thấy một triền cái nào khác, do bị bao trùm bởi triền cái ấy, chúng sanh trong một thời gian dài, lưu chuyển. Này các Tỷ-kheo, tức là Vô minh triền cái. Này các Tỷ-kheo, bị bao trùm bởi Vô minh triền cái, chúng sanh trong một thời gian dài chạy dài, lưu chuyển.\n\nKhông có một pháp khác,\nQuần sanh bị bao phủ,\nNgày đêm chạy lưu chuyển,\nNhư bao phủ bởi si.\n\nVà ai đoạn diệt si,\nÐâm thủng khối u ám,\nHọ không lưu chuyển nữa,\nTrong họ, nhân không còn.`, ref: "Itivuttaka 14", url: "https://loicuaducphat.org/iti/iti14.html#content" },

{ text: `Này các Tỷ-kheo, Ta không thấy một kiết sử nào khác, do bị cột bởi kiết sử ấy, chúng sanh trong một thời gian dài, chạy dài, lưu chuyển, này các Tỷ-kheo tức là Ái kiết sử. Này các Tỷ-kheo, bị cột với ái kiết sử, chúng sanh trong một thời gian dài, chạy dài lưu chuyển.\n\nNgười có ái làm bạn,\nThời gian dài, lưu chuyển,\nKhông vượt được lưu chuyển,\nSanh hữu vậy hay khác.\n\nAi biết nguy hiểm này,\nBiết ái tác thành khổ,\nBỏ ái, không chấp trước,\nTỷ-kheo giữ chánh niệm,\nBỏ gia đình xuất gia,\nSống nếp sống như vậy.`, ref: "Itivuttaka 15", url: "https://loicuaducphat.org/iti/iti15.html#content" },

{ text: `"Này các Tỷ-kheo, với vị Tỷ-kheo hữu học, tâm chưa thành tựu, đang sống cần cầu vô thượng an ổn khỏi các triền ách, sau khi làm thành nội chi phần, Ta không thấy một chi phần nào khác, được nhiều lợi ích như vậy, này các Tỷ-kheo, tức là Như lý tác ý. Này các Tỷ-kheo, vị Tỷ-kheo tác như lý tác ý, từ bỏ bất thiện, tu tập thiện." Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này đã được nói đến.\n\nVị Tỷ kheo hữu học,\nHành như lý tác ý,\nKhông một pháp nào khác,\nNhiều lợi ích như vậy.\nÐể đạt cho bằng được,\nLợi ích thật tối thượng.\nVị Tỷ kheo như lý,\nTinh tấn và tinh cần,\nCó thể thành đạt được,\nSư đoạn diệt khổ đau.`, ref: "Itivuttaka 16", url: "https://loicuaducphat.org/iti/iti16.html#content" },

{ text: `"Này các Tỷ-kheo, với vị Tỷ-kheo hữu học, tâm chưa thành tựu, đang sống cần cầu vô thượng an ổn khỏi các triền ách, sau khi làm thành ngoại chi phần, Ta không thấy một chi phần nào khác, được nhiều lợi ích như vậy, này các Tỷ-kheo, tức là làm bạn với thiện. Này các Tỷ-kheo, vị Tỷ-kheo làm bạn với thiện, từ bỏ bất thiện, tu tập thiện." Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này đã được nói đến.\n\nTỷ-kheo làm bạn thiện,\nTôn kính và kính trọng,\nLàm theo những lời nói,\nCủa bạn bè thân hữu,\nTỉnh giấc và chánh niệm,\nVị ấy sẽ tuần tự,\nÐạt được sự hoại diệt,\nTất cả mọi kiết sử.`, ref: "Itivuttaka 17", url: "https://loicuaducphat.org/iti/iti17.html#content" },

{ text: `"Thế nào là một pháp? Sự hòa hợp chúng Tăng. Này các Tỷ-kheo, khi chư Tăng được hòa hợp, không có những tranh luận với nhau, không có những mắng nhiếc lẫn nhau, không có những ngăn cách lẫn nhau, không có những từ bỏ lẫn nhau. Ở tại đây, những người không hòa hợp đi đến hòa hợp, và những người hòa hợp lại càng hòa hợp hơn nữa." Thế Tôn đã nói lên ý nghĩa này. Ở đây, điều này đã được nói đến.\n\nHạnh phúc là chúng Tăng,\nÐược sống trong hòa hợp,\nGiúp đỡ, ưa hòa hợp,\nThích hòa hợp, trú pháp\nKhông rơi rớt, vượt khỏi,\nAn ổn khỏi khổ ách,\nKẻ tạo được hòa hợp,\nGiữa Tăng chúng Tỷ-kheo,\nTrọn kiếp được an vui,\nTrong cảnh giới chư Thiên.`, ref: "Itivuttaka 19", url: "https://loicuaducphat.org/iti/iti19.html#content" },

{ text: `Này các Tỷ-kheo, chớ có sợ hãi các công đức. Này các Tỷ-kheo, công đức là đồng nghĩa với an lạc, cái gì khả lạc, khả hỷ, khả ái, khả ý, tức là công đức. Này các Tỷ-kheo, Ta thắng tri thọ hưởng quả dị thục, khả lạc, khả hỷ, khả ái, khả ý trong một thời gian dài của các công đức đã làm trong một thời gian dài. Sau khi tu tập từ tâm trong bảy năm, Ta đã không trở lui lại đời này trong bảy tăng kiếp và hoại kiếp. Này các Tỷ-kheo, Ta suy nghĩ như sau: "Quả này là do nghiệp nào Ta đã làm, là quả dị thục của nghiệp nào mà nay, Ta được đại thần lực như vậy, đại uy lực như vậy?". Rồi này các Tỷ-kheo, Ta suy nghĩ như sau: "Ðây là quả ba nghiệp Ta đã làm, là quả dị thục của ba nghiệp, do vậy Ta nay được đại thần lực như vậy, đại uy lực như vậy. Tức là bố thí, nhiếp phục, chế ngự".`, ref: "Itivuttaka 22", url: "https://loicuaducphat.org/iti/iti22.html#content" },

{ text: `Hãy để cho vị ấy,\nHọc tập về công đức,\nCông đức là lạc căn,\nTối thượng trong tương lai,\nHãy tu tập bố thí,\nSống nếp sống an tịnh,\nVà tu tập từ tâm.\n\nSau khi đã tu tập,\nCác pháp này như vậy,\nTức là cả ba pháp,\nKhiến an lạc sanh khởi,\nBậc Hiền trí được sanh\nTrong thế giới an lạc,\nThế giới không sân hận.`, ref: "Itivuttaka 22", url: "https://loicuaducphat.org/iti/iti22.html#content" },

{ text: `Có một pháp, này các Tỷ-kheo, được tu tập, được làm cho sung mãn, đem lại hai lợi ích, an trú ngay hiện tại và lợi ích cho tương lai. Thế nào là một pháp? Không phóng dật trong các thiện pháp. Này các Tỷ-kheo, đây là một pháp được tu tập, được làm cho sung mãn, đem lại được hai lợi ích, an trú ngay trong hiện tại và lợi ích cho tương lai.\n\nBậc Hiền trí tán thán,\nKhông phóng dật hành thiện,\nBậc Hiền không phóng dật,\nÐem lại hai lợi ích.\n\nLợi ích ngay đời này,\nVà lợi ích tương lai\nBậc trí do thắng trí,\nChứng đắc được lợi ích,\nNên được gọi bậc trí.`, ref: "Itivuttaka 23", url: "https://loicuaducphat.org/iti/iti23.html#content" },

{ text: `Các xương của một người, này các Tỷ-kheo, chạy dài, lưu chuyển có thể lớn như một đồi xương, một chồng xương, một đống xương, như núi Vepulla này, nếu có người thâu người lượm xương lại, gìn giữ chúng không làm chúng hủy hoại.\n\nChồng chất như xương người,\nChỉ sống có một kiếp,\nChất đống bằng hòn núi,\nBậc Ðại sĩ nói vậy.\n\nÐống xương ấy được nói,\nLớn như Vepulla,\nPhía Bắc núi Linh Thứu,\nThành núi Magadha.\n\nNgười thấy bốn sự thật,\nVới chân chánh trí tuệ\nKhổ và khổ tập khởi,\nSẽ vượt qua đau khổ,\nCon đường Thánh tám ngành,\nDẫn đến khổ tịnh chỉ.\n\nNgười ấy phải luân chuyển,\nTối đa là bảy lần,\nLà vị đoạn tận khổ,\nÐoạn diệt mọi kiết sử.`, ref: "Itivuttaka 24", url: "https://loicuaducphat.org/iti/iti24.html#content" },

{ text: `Phàm một người nào đã vi phạm một pháp, Ta nói rằng không có ác nghiệp nào vị ấy không làm được. Thế nào là một pháp? Này các Tỷ-kheo, tức là rõ biết mà nói láo.\n\nNgười nào đã nói láo,\nLà vi phạm một pháp,\nKhông kể đến đời sau,\nKhông ác gì không làm.`, ref: "Itivuttaka 25", url: "https://loicuaducphat.org/iti/iti25.html#content" },

{ text: `Này các Tỷ-kheo, nếu các chúng sanh có thể biết như Ta đã biết, quả dị thục của sự san sẻ bố thí họ sẽ không thụ hưởng nếu họ không bố thí và uế nhiễm xan tham không có ám ảnh tâm của họ và an trú. Dầu là miếng cuối cùng của họ, dầu là miếng ăn tối hậu, họ sẽ không thọ hưởng nếu họ không san sẻ, khi có người nhận của họ.\n\nNếu các hàng chúng sanh,\nCó thể biết như vậy,\nNhư bậc Ðại ẩn sĩ,\nÐã nói, tuyên bố lên,\nQuả dị thục lớn thay,\nCủa san sẻ bố thí!\n\nNhiếp phục uế xan tham,\nVới tâm thật thanh tịnh\nÐúng thời họ bố thí,\nÐối với các thánh nhân,\nTại đây bố thí vậy,\nCó quả thật to lớn.\n\nCho nhiều các thức ăn,\nKính lễ người đáng kính,\nTừ đấy xả, từ bỏ,\nÐịa vị làm con người,\nCác người làm bố thí\nÐược đi đến cõi Trời.\n\nHọ đi đến cõi trời,\nTại đấy chúng hoan hỷ,\nVới mọi điều sở thích,\nHọ thọ hưởng như ý,\nVị không có xan tham,\nÐược thọ hưởng đầy đủ,\nQuả dị thục của chúng,\nNhờ san sẻ bố thí.`, ref: "Itivuttaka 26", url: "https://loicuaducphat.org/iti/iti26.html#content" },

{ text: `Này các Tỷ-kheo, ví như ánh sáng của chùm sao, tất cả ánh sáng ấy không bằng một phần mười sáu ánh sáng của mặt trăng. Ánh sáng của mặt trăng vượt quả ánh sáng của chùm sao chói sáng, bừng sáng, và rực sáng. Cũng vậy, này các Tỷ-kheo, phàm có những nghiệp vụ đưa đến sanh y, tất cả những nghiệp vụ ấy không bằng một phần mười sáu từ tâm giải thoát. Chỉ có từ tâm giải thoát, vượt qua chúng, chói sáng, bừng sáng và rực sáng. Này các Tỷ-kheo, ví như vào tháng cuối mùa mưa, vào tiết mùa thu, trên bầu trời thanh tịnh, các mây được quét sạch, mặt trời mọc lên trên bầu trời, phá tan mọi tối tăm ở hư không, chói sáng, bừng sáng và rực sáng. Cũng vậy này các Tỷ-kheo, phàm có những nghiệp vụ đưa đến sanh y, tất cả những nghiệp vụ ấy không bằng một phần mười sáu từ tâm giải thoát. Chỉ có từ tâm giải thoát, vượt qua chúng, chói sáng, bừng sáng và rực sáng. Ví như này các Tỷ-kheo, khi đêm đã gần tàn, sao mai chói sáng, bừng sáng và rực sáng. Cũng vậy này các Tỷ-kheo, phàm có những nghiệp vụ nào đưa đến sanh y, tất cả những nghiệp vụ ấy không bằng một phần mười sáu từ tâm giải thoát. Chỉ có từ tâm giải thoát vượt qua chúng, chói sáng, bừng sáng và rực sáng.`, ref: "Itivuttaka 27", url: "https://loicuaducphat.org/iti/iti27.html#content" },

{ text: `Ai tu tập từ tâm,\nKhông phóng dật chánh niệm,\nCác kiết sử giảm thiểu,\nNhờ thấy sanh y diệt.\n\nNếu tâm không độc ác,\nÐối với một hữu tình,\nVới từ tâm như vậy,\nVị ấy là bậc Thiện,\nVới tâm tư từ mẫn,\nÐối tất cả hữu tình,\nBậc Thánh tự tác thành,\nCông đức thật vô lượng.\n\nAi chiến thắng quả đất,\nÐầy dẫy những hữu tình,\nBậc vua chúa chơn chánh,\nNhư các vị tiên nhân,\nTổ chức khắp mọi nơi,\nÐủ các loại tế đàn,\nLễ tế đàn với ngựa,\nLễ tế đàn với người,\nQuăng cọc, rượu chiến thắng,\nLễ chốt cửa dẹp lại,\n\nHọ không tác thành được\nMột phần thứ mười sáu,\nVới người khéo tu tập,\nTâm ý thật từ mẫn,\nNhư ánh sáng mặt trăng,\nThắng sáng mọi vì sao.\n\nAi không có giết hại,\nKhông khiến người giết hại,\nKhông có chinh phục người,\nKhông khiến người chinh phục,\nVới tâm tư từ mẫn,\nÐối với mọi chúng sanh,\nVị ấy không hận thù,\nÐối với bất cứ ai.`, ref: "Itivuttaka 27", url: "https://loicuaducphat.org/iti/iti27.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo đầy đủ hai pháp, ngay trong hiện tại, an trú đau khổ có hoạn nạn, có ưu não, có nhiệt não, sau khi thân hoại mạng chung, chờ đợi là ác thú. Thế nào là hai? Không hộ trì các căn và không tiết độ trong ăn uống. Này các Tỷ-kheo, Tỷ-kheo đầy đủ hai pháp này, ngay trong hiện tại an trú đau khổ, có hoạn nạn, có ưu não, có nhiệt não, sau khi thân hoại mạng chung, chờ đợi là ác thú.\n\nMắt, tai, mũi và lưỡi,\nKể cả thân và ý,\nNhững cửa này ở đây,\nTỷ-kheo không hộ trì.\n\nĂn uống không tiết độ,\nÐau khổ về thân thể,\nCác căn không hộ trì,\nÐau khổ về tâm tư\nVị ấy phải thọ lãnh\nNhững đau khổ như vậy.\n\nThân thể bị thiêu đốt,\nTâm tư bị thiêu đốt,\nDầu là đêm hay ngày,\nAn trú khổ như vậy.\n\n7`, ref: "Itivuttaka 28", url: "https://loicuaducphat.org/iti/iti28.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo đầy đủ hai pháp, ngay trong hiện tại, an trú an lạc, không có hoạn nạn, không có ưu não, không có nhiệt não, sau khi thân hoại mạng chung, được chờ đợi là thiện thú. Thế nào là hai? Hộ trì các căn và tiết độ trong ăn uống. Này các Tỷ-kheo, Tỷ-kheo đầy đủ hai pháp này, ngay trong hiện tại, an trú an lạc, không có hoạn nạn, không có ưu não, không có nhiệt não, sau khi thân hoại mạng chung, được chờ đợi là thiện thú.\n\nMắt, tai, mũi và lưỡi,\nKể cả thân và ý,\nNhững cửa này ở đây,\nTỷ-kheo khéo hộ trì.\n\nĂn uống có tiết độ,\nAn lạc về thân thể,\nCác căn có hộ trì,\nAn lạc về tâm tư,\nVị ấy được thọ lãnh\nNhững an lạc như vậy.\n\nThân không bị thiêu đốt,\nTâm không bị thiêu đốt,\nDầu là đêm hay ngày,\nAn trú lạc như vậy.`, ref: "Itivuttaka 29", url: "https://loicuaducphat.org/iti/iti29.html#content" },

{ text: `Từ bỏ thân làm ác,\nHay nói các lời ác,\nTừ bỏ ý ác hành,\nHay bất cứ gì khác\nCó liên hệ lỗi lầm.\n\nKhông làm các nghiệp ác,\nLàm nhiều điều thiện sự,\nKhi thân hoại mạng chung,\nNgười có thiện trí tuệ,\nÐược sanh lên cõi trời.`, ref: "Itivuttaka 31", url: "https://loicuaducphat.org/iti/iti31.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo không có nhiệt tình, không có sợ hãi, không có thể chứng được Chánh giác, không có thể chứng được Niết-bàn, không có thể chứng được vô thượng an ổn khỏi các khổ ách. Này các Tỷ-kheo, Tỷ-kheo có nhiệt tình, có sợ hãi, có thể chứng được giác ngộ, có thể chứng được Niết-bàn, có thể chứng được vô thượng an ổn khỏi các khổ ách.\n\nNgười không có nhiệt tình,\nKhông có biết sợ hãi,\nBiếng nhác, không tinh cần,\nNhiều hôn trầm thụy miên,\nKhông biết đến xấu hổ,\nKhông có lòng tôn kính,\nVị Tỷ-kheo như vậy,\nKhông có thể đạt tới,\nTối thượng Chánh-Ðẳng-Giác.\n\nAi giữ được chánh niệm,\nThông minh, tu thiền định,\nNhiệt tình, biết sợ hãi,\nVà không có phóng dật,\nSau khi chặt đứt được\nKiết sử sanh và già,\nỞ đây có thể đạt,\nChánh Ðẳng Giác vô thượng.`, ref: "Itivuttaka 34", url: "https://loicuaducphat.org/iti/iti34.html#content" },

{ text: `Này các Tỷ-kheo, Phạm hạnh được sống, không vì mục đích lừa dối quần chúng, không vì mục đích nịnh hót quần chúng, không vì mục đích được lợi ích, lợi dưỡng, cung kính, danh vọng, nghĩ rằng: "Mong rằng quần chúng biết đến ta". Này các Tỷ-kheo, Phạm hạnh được sống vì mục đích chế ngự và vì mục đích đoạn tận.\n\nVới mục đích chế ngự,\nVới mục đích đoạn tận,\nKhông kể người nói gì,\nThế Tôn đã thuyết giảng\nVề nếp sống Phạm hạnh,\nMột nếp sống đưa đến\nThể nhập vào Niết-bàn.\n\nÐường này là con đường\nÐược các bậc Ðại nhân,\nÐược các Ðại ẩn sĩ,\nNoi theo và thực hiện,\nVà những ai dấn bước,\nChính trên con đường ấy,\nNhư đức Phật đã dạy,\nSẽ làm khổ lắng dịu,\nVà thực hành làm đúng,\nNhư lời Ðạo sư dạy.`, ref: "Itivuttaka 35", url: "https://loicuaducphat.org/iti/iti35.html#content" },

{ text: `Ðầy đủ hai pháp, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại an trú với nhiều lạc hỷ, như lý nỗ lực để diệt tận các lậu hoặc. Thế nào là hai? Với sự hứng khởi đối với những trường hợp đáng phấn khởi, và như lý tinh cần đối với phấn khởi. Thành tựu hai pháp này, này các Tỷ-kheo, Tỷ-kheo ngay trong hiện tại sống với nhiều lạc hỷ, như lý nỗ lực để diệt tận các lậu hoặc.\n\nBậc có trí phấn khởi,\nTrường hợp đáng phấn khởi,\nVị Tỷ-kheo nhiệt tình,\nThông minh và cẩn trọng,\nQuán xuyến nhìn sự vật,\nVới trí tuệ Bát-nhã.\n\nNhiệt tình trú như vậy,\nSống đời sống an tịnh,\nKhông bồng bột hăng say,\nChú lực tâm tịnh chỉ,\nCó thể đạt chứng được,\nÐoạn diệt các khổ đau.`, ref: "Itivuttaka 37", url: "https://loicuaducphat.org/iti/iti37.html#content" },

{ text: `Này các Tỷ-kheo. Với Như Lai, bậc A-la-hán, Chánh Ðẳng Giác, hai tầm tứ được hành trì nhiều đó là an ổn và ẩn dật. Này các Tỷ-kheo, Như Lai ưa thích không làm hại, thích thú không làm hại. Với Như Lai ấy, này các Tỷ-kheo, ưa thích không làm hại này, thích thú không làm hại này, tầm tứ này được hành trì nhiều. "Với cử chỉ uy nghi này Ta không làm hại một ai, dầu là loài động vật hay không động vật".\n\nNày các Tỷ-kheo, Như Lai ưa thích ẩn dật, thích thú ẩn dật. Với Như Lai ấy, này các Tỷ-kheo, ưa thích ẩn dật này, thích thú ẩn dật. Với Như Lai ấy, này các Tỷ-kheo, ưa thích ẩn dật này, thích thú ẩn dật này, tầm tứ này được hành trì nhiều! Phàm có bất thiện gì, thì đều được đoạn tận.`, ref: "Itivuttaka 38", url: "https://loicuaducphat.org/iti/iti38.html#content" },

{ text: `Như Lai, bậc Giác ngộ,\nBậc có thể nhẫn nại,\nNhững gì mà người khác,\nKhông có thể nhẫn nại,\nHai tầm tứ, vị ấy\nHành trì và thực hiện,\nTrước hết được nói đến,\nLà an ổn tầm tứ,\nThứ đến là ẩn dật,\nThứ hai được trình bày,\n\nPhá tan màn hắc ám,\nÐã đến bờ bên kia,\nBậc Ðại sĩ đạt được,\nQuyền lực không lậu hoặc,\nÐạt thân mạng tối hậu\nTrong ái diệt, giải thoát.\nVị ẩn sĩ như vậy,\nChắc mang thân tối hậu,\nTa nói rằng vị ấy\nTừ bỏ được kiêu mạn,\nThoát khỏi được già lão,\nÐạt được bờ bên kia.\n\nNhư đứng trên tảng đá,\nTrên đỉnh núi đầu non,\nÐưa mắt nhìn xung quanh,\nQuần chúng dưới chân mình,\nCũng vậy bậc Thiện tuệ,\nLeo lên lầu Chánh pháp\nBiến nhãn không sầu muộn,\nNhìn xuống đám quần sanh,\nBị ưu tư sầu khổ,\nBị sanh già áp bức.`, ref: "Itivuttaka 38", url: "https://loicuaducphat.org/iti/iti38.html#content" },

{ text: `Có hai loại thuyết pháp của Như Lai, bậc A-la-hán, Chánh-Ðẳng Giác, cái này tiếp nối cái kia. Thế nào là hai? "Hãy thấy ác là ác", đây là thuyết pháp thứ nhất. Sau khi thấy ác là ác, ở đây, "Hãy nhàm chán, hãy từ bỏ, hãy thoát ly", đây là thuyết pháp thứ hai. Này các Tỷ-kheo, có hai loại thuyết pháp này của Như Lai, bậc A-la-hán, Chánh Ðẳng Giác, cái này tiếp nối cái kia.\n\nVới Như Lai, Phật Ðà,\nTừ mẫn mọi chúng sanh,\nHãy thấy lời thuyết giảng,\nTuần tự pháp theo pháp,\nHai pháp được trình bày,\n\nMột là hãy nhìn rõ,\nPháp ác là pháp ác\nVà chính tại ở đây,\nTừ bỏ, không tham đắm.\nTừ đây, không tham đắm,\nHãy làm cho an tịnh,\nMọi khổ đau phiền não.`, ref: "Itivuttaka 39", url: "https://loicuaducphat.org/iti/iti39.html#content" },

{ text: `Này các Tỷ-kheo, vô minh đi trước, làm cho đạt được các pháp bất thiện; tiếp theo là không xấu hổ, không sợ hãi. Này các Tỷ-kheo, minh đi trước, làm cho đạt được các pháp thiện; tiếp theo là xấu hổ và sợ hãi.\n\nPhàm có ác thú gì,\nÐời này và đời sau,\nTất cả do vô minh,\nLàm gốc, làm cội rễ,\nDục tham được cất chứa.\n\nVì rằng kẻ ác dục,\nKhông xấu hổ, không kính,\nTừ đó nó khởi ác,\nDo vậy đi đọa xứ.\n\nVậy hãy nên từ bỏ,\nDục tham và vô minh,\nMuốn minh được sanh khởi,\nTỷ-kheo cần từ bỏ\nTất cả mọi ác thú.`, ref: "Itivuttaka 40", url: "https://loicuaducphat.org/iti/iti40.html#content" },

{ text: `Này các Tỷ-kheo, những chúng sanh nào bị thối đọa khỏi Thánh trí tuệ, những chúng sanh ấy là khéo thối đọa, ngay trong hiện tại, họ an trú trong đau khổ, với tàn hại, với ưu não, với nhiệt não. Sau khi thân hoại mạng chung, chờ đợi là ác thú.\n\nNày các Tỷ-kheo, những chúng sanh nào không bị thối đọa khỏi Thánh trí tuệ, những chúng sanh ấy không có thối đọa. Ngay trong hiện tại, họ an trú trong an lạc, không có tàn hại, không có ưu não, không có nhiệt não. Sau khi thân hoại mạng chung, chờ đợi là thiện thú.\n\nThối đọa khỏi trí tuệ,\nHãy nhìn xem, thế giới\nVới hàng ngũ chư Thiên,\nAn trú trong danh sắc,\nNghĩ rằng: "Ðây sự thật"\n\nNhưng thù thắng ở đời,\nLại chính là trí tuệ,\nChính tuệ dắt dẫn đến\nThể nhập được Niết-bàn,\nVà chơn chánh quán tri,\nSự hoại diệt sanh hữu.\n\nChư Thiên và loài Người,\nHoan hỷ được chiêm ngưỡng,\nChư Phật Chánh Ðẳng Giác,\nNhững bậc giữ chánh niệm,\nÐầy đủ với trí tuệ,\nMang thân này cuối cùng.`, ref: "Itivuttaka 41", url: "https://loicuaducphat.org/iti/iti41.html#content" },

{ text: `Này các Tỷ-kheo, có hai pháp trắng này che chở cho đời. Thế nào là hai? Xấu hổ và sợ hãi. Này các Tỷ-kheo, nếu hai pháp này không che chở cho đời, thời ở đây không có sự phân biệt giữa mẹ, chị em của mẹ, vợ của anh em của mẹ hay giữa vợ của bậc giáo thọ sư, giữa những người vợ của những bậc đáng được kính trọng; thế giới sẽ rơi vào loạn luân như các loài dê cừu, gia cầm, heo, chó và các con chó rừng.\n\nVì rằng, này các Tỷ-kheo, có hai pháp trắng này che chở cho đời, cho nên ở đây có sự phân biệt giữa mẹ, chị em của mẹ, vợ của anh em của mẹ, hay vợ của bậc giáo thọ sư, giữa những người vợ của những bậc đáng được kính trọng.\n\nVới những ai không có,\nXấu hổ và sợ hãi,\nLiên tục và thường xuyên,\nHọ đi xuống bào thai,\nDựa trên gốc tinh dịch\nHọ đi đến sanh tử,\n\nVới những ai chánh trí,\nXấu hổ và sợ hãi,\nLiên tục và thường xuyên,\nVững trú trên Phạm hạnh,\nHọ được sự an tịnh,\nTái sanh được diệt tận.`, ref: "Itivuttaka 42", url: "https://loicuaducphat.org/iti/iti42.html#content" },

{ text: `Có cái sanh, hiện hữu,\nCái khởi lên làm ra,\nHữu vi không thường hằng,\nTác thành ra già chết,\nMột ổ của bệnh hoạn,\nMỏng manh, giòn, dễ vỡ,\n\nNhờ đồ ăn nuôi dưỡng,\nNên mới được hiện hữu,\nVật ấy thật không đủ\nÐể hoan hỷ ưa thích,\nThật có cái xuất ly,\nRa khỏi được cái ấy,\nThật có vượt lý luận,\n\nThường hằng, không sanh khởi,\nKhông có cái khởi lên,\nCon đường không cấu uế,\nKhông đưa đến sầu muộn,\nÐoạn diệt các pháp khổ,\nSự tịnh chỉ mọi hành,\nAn lạc thật tịnh lạc.`, ref: "Itivuttaka 43", url: "https://loicuaducphat.org/iti/iti43.html#content" },

{ text: `Này các Tỷ-kheo, hãy sống ưa muốn ẩn dật thiền tịnh, thích thú ẩn dật thiền tịnh, chuyên chú nội tâm tịnh chỉ, không gián đoạn thiền định, thành tựu quán tri, hành trì hạnh đi đến các ngôi nhà trống.\n\nNày các Tỷ-kheo sống ưa muốn ẩn dật thiền tịnh, thích thú ẩn dật thiền tịnh, chuyên chú vào nội tâm tịnh chỉ, không gián đoạn thiền định, thành tựu quán trí, hành tri hạnh đi đến các ngôi nhà trống, thời được chờ đợi là một trong hai quả này: ngay trong hiện tại được chánh trí, hay nếu có dư y, được quả Bất Lai.\n\nNhững ai tâm an tịnh,\nThông minh và thận trọng,\nChánh niệm tu thiền định,\nQuán nhìn pháp chơn chánh,\nKhông chờ đợi ham muốn,\nÐối với các loại dục.\n\nƯa muốn không phóng dật,\nSống an tịnh có mặt,\nThấy được sự sợ hãi,\nTrong nếp sống phóng dật,\nHọ không bị thối đọa,\nHọ đến gần Niết bàn.`, ref: "Itivuttaka 45", url: "https://loicuaducphat.org/iti/iti45.html#content" },

{ text: `Này các Tỷ-kheo, an trú cho lợi ích của học tập, cho trí tuệ tối thượng, cho lõi cây giải thoát, cho niệm được tăng thượng, thời được chờ đợi là một trong hai quả này: được chánh tri ngay trong hiện tại, hay nếu có dư y, chứng được Bất-lai.\n\nBậc hữu học viên mãn,\nKhông còn bị thối đọa,\nÐạt tối thượng trí tuệ,\nThấy sanh được diệt tận.\nTa nói chắc chắn rằng,\nẨn sĩ Mâu-ni ấy,\nMang sắc thân cuối cùng.\nÐã từ bỏ kiêu mạn,\nÐã vượt qua bờ kia,\nThoát khỏi sự già yếu.\n\nDo vậy hãy luôn luôn,\nVui trong thiền, thiền định,\nNhiệt tâm và nỗ lực,\nThấy sanh được diệt tận,\nHỡi này các Tỷ-kheo,\nHãy nhiếp phục ma quân,\nTu tập vượt qua được,\nThoát khỏi sự già chết.`, ref: "Itivuttaka 46", url: "https://loicuaducphat.org/iti/iti46.html#content" },

{ text: `Này các Tỷ-kheo, Tỷ-kheo phải sống cảnh giác, chánh niệm, tỉnh giác, thiền định, hoan hỷ, tín thành, và ở đây quán tri đúng thời trong các pháp thiện. Này các Tỷ-kheo, với Tỷ-kheo sống cảnh giác, chánh niệm, tỉnh giác, thiền định, hoan hỷ, tín thành, quán tri đúng thời trong các pháp thiện, thời được chờ đợi là một trong hai quả này: Ðược chánh tri ngay trong hiện tại, hay nếu có dư y, chứng được Bất lai.\n\nHỡi các bậc cảnh giác,\nHãy lắng nghe điều này,\nNhững ai còn nằm ngủ,\nHãy thức dậy tỉnh thức,\nThức tỉnh là tốt hơn,\nHơn kẻ đang nằm ngủ,\nÐối với người thức tỉnh,\nKhông có sự sợ hãi,\n\nNgười thức tỉnh, thức giấc,\nChánh niệm và tỉnh giấc,\nThiền định, tâm hoan hỷ,\nNhiệt tình đầy tín thành,\nChơn chánh biết thời giờ,\nThắng quán đến Chánh pháp,\nÐạt được sự nhất tâm,\nQuét sạch mọi tăm tối.\n\nDo vậy hãy tu tập,\nThức tỉnh và nhiệt tình,\nVị Tỷ-kheo thông minh,\nThận trọng, chứng cảnh thiền,\nChặt đứt các kiết sử,\nTrói buộc sanh với già,\nChính tại ở đời này,\nChứng chánh giác Vô thượng.`, ref: "Itivuttaka 47", url: "https://loicuaducphat.org/iti/iti47.html#content" },

{ text: `Này các Tỷ-kheo, có hai hạng người bị đọa lạc, bị đọa vào địa ngục nếu họ không đoạn tận lỗi lầm của họ. Thế nào là hai? Ai sống phi Phạm hạnh, lại tự cho sống Phạm hạnh. Ai đối với người sống Phạm hạnh viên mãn, thanh tịnh, lại buộc tội chỉ trích là phi Phạm hạnh không có căn cứ. Này các Tỷ-kheo, hai hạng người này bị đọa lạc, bị đọa vào địa ngục, nếu họ không đoạn tận lỗi lầm của họ.\n\nAi nói lời không chơn,\nRơi vào cõi địa ngục,\nAi sau khi đã làm,\nLại nói tôi không làm,\nCả hai sau khi chết,\nÐều đồng đẳng như nhau,\nHọ đều là những người,\nLàm các nghiệp hạ liệt,\nThuộc về cảnh đời sau,\n\nLại có rất nhiều người,\nTuy mang áo cà-sa,\nHọ không có chế ngự,\nÐối với các pháp ác,\nDo họ làm nghiệp ác,\nHọ phải sanh địa ngục,\n\nTốt hơn đối với họ,\nLà nuốt cục sắt tròn\nCháy đỏ như đống lửa,\nCòn hơn kẻ ác giới,\nKhông biết có chế ngự,\nNếu có ăn dùng gì,\nCác món ăn quốc độ.`, ref: "Itivuttaka 48", url: "https://loicuaducphat.org/iti/iti48.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là một số người chấp chặt? Này các Tỷ-kheo, có chư Thiên và loài Người ưa muốn sanh hữu, khi các pháp đoạn diệt sanh hữu được giảng cho họ, tâm họ không có phấn khởi, không có tín thành, không có an trú, không có bị lôi cuốn. Như vậy, này các Tỷ-kheo, đó là một số người chấp chặt.\n\nVà này các Tỷ-kheo, thế nào là một số người đi quá trớn? Nhưng có một số người lo âu, xấu hổ, nhàm chán với sanh hữu, hoan hỷ, phi sanh hữu. Họ nói: "Vì rằng khi thân hoại mạng chung, tự ngã này bị chặt đứt, bị hoại diệt, không có tồn tại sau khi chết. Quan điểm này là thiết thực, là thù thắng, là chân thật". Như vậy này các Tỷ-kheo, đó là một số người đi quá trớn.\n\nVà này các Tỳ Kheo, thế nào là một số có mắt được thấy? Ở đây, Tỷ-kheo thấy sự sanh hữu là sanh hữu, sau khi thấy sự sanh hữu, vị ấy hướng đến nhàm chán, ly tham, đoạn diệt. Như vậy này các Tỷ-kheo, đó là những người có mắt được thấy.\n\nNhững ai đã thấy được\nSanh hữu là sanh hữu,\nThấy được sự vượt qua\nCủa sự sanh hữu ấy.\nNhững vị ấy giải thoát,\nÐối như thật hiện hữu,\nVì nhờ đoạn diệt được\nTham ái đối sanh hữu.\n\nNếu vị ấy liễu tri,\nSanh hữu là sanh hữu,\nVị ấy ly tham ái\nÐối hữu và phi hữu,\nTỷ-kheo quyết phi hữu,\nÐối với chính sanh hữu,\nSẽ không còn đi đến\nSanh đi rồi sanh lại.`, ref: "Itivuttaka 49", url: "https://loicuaducphat.org/iti/iti49.html#content" },

{ text: `Này các Tỷ-kheo, có ba cảm thọ này. Thế nào là ba? Lạc thọ, khổ thọ, bất khổ bất lạc thọ. Này các Tỷ-kheo, có ba cảm thọ này.\n\nÐịnh tĩnh và tỉnh giác,\nChánh niệm đệ tử Phật,\nQuán tri các cảm thọ,\nVà hiện hữu các thọ.\n\nTại đấy, tâm được diệt,\nCon đường đưa đến diệt,\nTỷ-kheo nhờ diệt thọ,\nKhông ham muốn, tịch tịnh.`, ref: "Itivuttaka 52", url: "https://loicuaducphat.org/iti/iti52.html#content" },

{ text: `Này các Tỷ-kheo, có ba cảm thọ này. Thế nào là ba? Lạc thọ, khổ thọ, bất khổ bất lạc thọ.\n\nNày các Tỷ-kheo, lạc thọ cần phải được xem như là khổ. Khổ thọ cần phải được xem như là mũi tên. Bất khổ bất lạc thọ cần phải được xem như là vô thường. Vì rằng này các Tỷ-kheo, Tỷ-kheo đã xem lạc thọ như là khổ, đã xem khổ thọ như là mũi tên, đã xem bất khổ bất lạc thọ như là vô thường, này các Tỷ-kheo, Tỷ-kheo này gọi là bậc Thánh đã chơn chánh thấy, đã chặt đứt ái, đã giải toả kiết sử đã chơn chánh thắng tri mạn, đã đoạn tận khổ đau.\n\nAi thấy lạc là khổ,\nThấy khổ là mũi tên,\nThấy bất khổ bất lạc\nThọ ấy là vô thường,\n\nTỷ-kheo ấy thật sự\nÐã thấy thật chơn chánh,\nChính tại ở nơi đây,\nTừ đấy được giải thoát.\nThành tựu được thắng trí,\nBậc ẩn sĩ an tịnh\nChắc chắn đã vượt qua\nCác ách nạn trói buộc.`, ref: "Itivuttaka 53", url: "https://loicuaducphat.org/iti/iti53.html#content" },

{ text: `Này các Tỷ-kheo, có ba tầm cầu này. Thế nào là ba? Dục tầm cầu, hữu tầm cầu, Phạm hạnh tầm cầu. Này các Tỷ-kheo, có ba tầm cầu này.\n\nDục và hữu tầm cầu,\nCùng Phạm hạnh tầm cầu\nNếu chấp trước nắm giữ\nChính đây là sự thật,\nNhư vậy là chất chứa,\nÐủ mọi loại kiến xứ,\n\nVới ai không ham muốn\nÐối với các loại tham,\nVị ấy được giải thoát,\nNhờ diệt được khả ái,\nTầm cầu được từ bỏ,\n\nKiến xứ được nhổ lên,\nTỷ-kheo do diệt tận\nCác loại tầm cầu ấy,\nKhông còn có mong cầu,\nKhông còn có nghi hoặc.`, ref: "Itivuttaka 55", url: "https://loicuaducphat.org/iti/iti55.html#content" },

{ text: `Này các Tỷ-kheo, có ba loại lậu hoặc này. Thế nào là ba? Dục lậu, hữu lậu và vô minh lậu. Này các Tỷ-kheo, có ba lậu hoặc này.\n\nAi đoạn trừ dục lậu,\nLy tham thoát vô minh,\nHữu lậu được đoạn trừ,\nGiải thoát khỏi sanh y,\nMang cái thân cuối cùng,\nDẹp tan cỗ xe ma.`, ref: "Itivuttaka 57", url: "https://loicuaducphat.org/iti/iti57.html#content" },

{ text: `Này các Tỷ-kheo, có ba khát ái này. Thế nào là ba? Dục ái, hữu ái, phi hữu ái. Này các Tỷ-kheo, có ba khát ái này.\n\nTrói buộc bởi ái triền,\nTâm ưa hữu, phi hữu,\nBị ma triền trói buộc,\nChúng sanh ấy không được,\nAn ổn khỏi ách nạn.\nChúng sanh đi luân chuyển,\nÐến sanh rồi đến chết.\n\nNhững ai đoạn được ái,\nLy ái hữu, phi hữu,\nHọ đến bờ bên kia,\nTrong thế giới hiện tại,\nHọ đã chứng đạt được,\nCác lậu hoặc đoạn tận.`, ref: "Itivuttaka 58", url: "https://loicuaducphat.org/iti/iti58.html#content" },

{ text: `Thành tựu với ba pháp, này các Tỷ-kheo, vị Tỷ-kheo vượt qua được thế lực của Ác ma, và chói sáng như mặt trời. Thế nào là ba? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo thành tựu vô học giới uẩn, thành tựu vô học định uẩn, thành tựu vô học tuệ uẩn. Thành tựu với ba pháp này, này các Tỷ-kheo, vị Tỷ-kheo vượt qua được thế lực của Ác-ma, và chói sáng như mặt trời.\n\nGiới, định và trí tuệ,\nVới ai khéo tu tập,\nVị ấy vượt qua khỏi\nThế lực của Ác ma,\nVà chói sáng rực sáng,,\nNhư mặt trời chói sáng.`, ref: "Itivuttaka 59", url: "https://loicuaducphat.org/iti/iti59.html#content" },

{ text: `Này các Tỷ-kheo, có ba phước nghiệp sự này. Thế nào là ba? Phước nghiệp sự do bố thí tác thành, phước nghiệp sự do giới tác thành, và phước nghiệp do sự tu tập tác thành. Này các Tỷ-kheo, có ba phước nghiệp sự này.\n\nHãy để cho người ấy,\nHọc tập làm công đức,\nHướng dẫn đến tương lai\nÐem lại căn an lạc.\nHãy tu tập bố thí,\nTập sở hành an tịnh,\nVà tu tập từ tâm.\n\nTu xong ba pháp ấy,\nNhững pháp khởi lạc thọ.\nBậc Hiền trí được sanh,\nTại thế giới an lạc,\nKhông phiền não hận thù.`, ref: "Itivuttaka 60", url: "https://loicuaducphat.org/iti/iti60.html#content" },

{ text: `Này các Tỷ-kheo, có ba ác hành này. Thế nào là ba? Thân ác hành, ngữ ác hành, ý ác hành. Này các Tỷ-kheo, có ba ác hành này.\n\nLàm ác hạnh về thân,\nLàm ác hạnh về lời,\nLàm ác hạnh về ý,\nVà bất cứ hạnh gì,\nÐều được gọi hạnh ác,\n\nKhông làm nghiệp lành nào,\nLàm nhiều nghiệp không thiện,\nKhi thân hoại mạng chung,\nVới trí tuệ hạ liệt,\nVị ấy phải sanh vào\nTrong cảnh giới địa ngục.`, ref: "Itivuttaka 64", url: "https://loicuaducphat.org/iti/iti64.html#content" },

{ text: `Này các Tỷ-kheo, có ba thiện hành này. Thế nào là ba? Thân thiện hành, ngữ thiện hành, ý thiện hành. Này các Tỷ-kheo, có ba thiện hành này.\n\nTừ bỏ thân làm ác,\nTừ bỏ lời nói ác,\nTừ bỏ ý nghĩ ác,\nVà bất cứ hạnh gì,\nÐược gọi là hạnh ác,\n\nKhông làm các điều ác,\nLàm nhiều những hạnh lành,\nKhi thân hoại mạng chung,\nVới trí tuệ thù thắng,\nVị ấy được sanh lên,\nTrong cảnh giới chư Thiên.`, ref: "Itivuttaka 65", url: "https://loicuaducphat.org/iti/iti65.html#content" },

{ text: `Này các Tỷ-kheo, có ba thanh tịnh này. Thế nào là ba? Thân thanh tịnh, lời thanh tịnh, ý thanh tịnh. Này các Tỷ-kheo, có ba thanh tịnh này.\n\nThân và lời thanh tịnh\nVà ý cũng thanh tịnh,\nKhông có các lậu hoặc,\nÐầy đủ sự thanh tịnh,\nVị như vậy được gọi\nÐã từ bỏ tất cả.`, ref: "Itivuttaka 66", url: "https://loicuaducphat.org/iti/iti66.html#content" },

{ text: `Này các Tỷ-kheo, có ba trầm lặng này. Thế nào là ba? Thân trầm lặng, lời trầm lặng, ý trầm lặng. Này các Tỷ-kheo, có ba trầm lặng này.\n\nThân và lời trầm lặng\nVà ý cũng trầm lặng,\nKhông có các lậu hoặc,\nÐầy đủ với trầm lặng\nCủa các bậc chân ẩn sĩ,\nÐuợc tên gọi là vị\nÐã tắm sạch điều ác.`, ref: "Itivuttaka 67", url: "https://loicuaducphat.org/iti/iti67.html#content" },

{ text: `Này các Tỷ-kheo, với ai tham chưa đoạn tận, sân chưa đoạn tận, si chưa đoạn tận. Này các Tỷ-kheo, người ấy được gọi là người bị trói buộc với Ác ma, bị bẫy lưới của Ác ma bao trùm, bị làm theo ý Ác ma muốn.\n\nNày các Tỷ-kheo, với ai tham đã đoạn tận, sân đã đoạn tận, si đã đoạn tận, này các Tỷ-kheo, người ấy được gọi là người không trói buộc với Ác ma, được thoát khỏi bẫy lưới của Ác ma, không bị làm theo Ác ma muốn.\n\nVới ai đã từ bỏ\nTham, sân và vô minh,\nVị ấy được gọi là\nÐã tu tập tự ngã,\n\nÐã trở thành Phạm Thiên\nBậc Như Lai, Phật-đà,\nBậc đã vượt qua được,\nHận thù và sợ hãi,\nBậc đoạn tận tất cả,\nÐược gọi danh như vậy.`, ref: "Itivuttaka 68", url: "https://loicuaducphat.org/iti/iti68.html#content" },

{ text: `Với Tỷ-kheo hay Tỷ-kheo-ni nào, này các Tỷ-kheo, tham chưa đoạn tận, sân chưa đoạn tận, si chưa đoạn tận; này các Tỷ-kheo, vị ấy được gọi là vị chưa vượt qua đại dương, với sóng biển, với sóng ngầm, với nước xoáy, với cá mập, với các loài La-sát.\n\nNày các Tỷ-kheo, với Tỷ-kheo hay Tỷ-kheo ni nào, tham đã đoạn tận, sân đã đoạn tận, si đã đoạn tận; này các Tỷ-kheo, vị ấy được gọi là: "Ðã vượt qua đại dương, với sóng biển, với sóng ngầm, với nước xoáy, với cá mập, với các loài la-sát, đã vượt qua bờ kia, là vị Bà-la-môn đã đứng trên đất liền.\n\nVới ai đã từ bỏ\nTham, sanh và vô minh,\nVị ấy được gọi là\nÐã vượt qua biển này,\nVới cá mập, Dạ-xoa,\nVới sóng biển hãi hùng,\nRất khó được vượt qua,\nLà vị vượt ác triền.\n\nÐã từ bỏ thần chết,\nKhông còn có sanh y,\nÐã từ bỏ đau khổ,\nKhông còn có tái sanh,\nÐã đi đến mục đích,\nKhông thể ước lượng được,\nTa nói rằng vị ấy\nLàm ma vương si ám.`, ref: "Itivuttaka 69", url: "https://loicuaducphat.org/iti/iti69.html#content" },

{ text: `Dẫn ý vào đường tà\nNói những lời tà ngữ,\nVới thân làm nghiệp tà,\nNgười ở đời làm vậy.\n\nÍt nghe, ít học hỏi,\nKhông làm các công đức,\nỞ đây sống trong đời,\nVới sanh mạng ít oi,\nKhi thân hoại mạng chung,\nNgười ấy với liệt tuệ,\nBị sanh vào địa ngục.`, ref: "Itivuttaka 70", url: "https://loicuaducphat.org/iti/iti70.html#content" },

{ text: `Này các Tỷ-kheo, có ba xuất ly giới này. Thế nào là ba? Sự xuất ly này khỏi các dục, tức là viễn ly. Sự xuất ly này khỏi các sắc, tức là vô sắc. Sự đoạn diệt cái gì được hiện hữu, được làm ra, được duyên khởi, là sự xuất ly cái ấy. Này các Tỷ-kheo, có ba xuất ly giới này.\n\nBiết được xuất ly dục,\nVượt qua được các sắc,\nTịnh chỉ tất cả hành,\nLuôn luôn cảm nhiệt tình.\n\nTỷ-kheo ấy thấy chánh,\nTừ đấy, chính ở đây,\nVị ấy được giải thoát,\nThắng trí được viên thành,\nSống nếp sống an tịnh\nVị ấy sống như vậy,\nThật sự là ẩn sĩ,\nÐã vượt khỏi các ách.`, ref: "Itivuttaka 72", url: "https://loicuaducphat.org/iti/iti72.html#content" },

{ text: `Này các Tỷ-kheo, các pháp vô sắc an tịnh tốt hơn các sắc pháp; tịch diệt an tịnh tốt hơn các pháp vô sắc.\n\nNhững ai liễu tri sắc,\nKhông an trú vô sắc,\nChính trong sự tịch diệt,\nHọ đạt được giải thoát,\nCác hạng người như vậy,\nHọ bỏ rơi thần chết.\n\nVới thân cảm xúc được,\nBất tử không sanh y,\nSanh y được xả ly,\nChứng được, không lậu hoặc,\nVị Chánh đẳng Chánh giác,\nThuyết giảng về con đường\nCon đường không sầu muộn\nCon đường không cấu uế.`, ref: "Itivuttaka 73", url: "https://loicuaducphat.org/iti/iti73.html#content" },

{ text: `Ðời có những con này,\nTrở thành nam cư sĩ,\nSống đầy đủ tín giới,\nBiết nghe lời người khác,\nXa lìa sự xan tham.\nNhững người con như vậy,\nNhư trăng thoát đám mây,\nChói sáng giữa hội chúng.`, ref: "Itivuttaka 74", url: "https://loicuaducphat.org/iti/iti74.html#content" },

{ text: `Này các Tỷ-kheo, có ba hạng người này có mặt, hiện hữu ở đời. Thế nào là ba? Hạng người như hạn hán, hạng người như chỉ mưa trong địa phương và hạng người như mưa đổ xuống khắp tất cả. Và này các Tỷ-kheo, thế nào là hạng người như hạn hán? Ở đây, này các Tỷ-kheo, có người không bố thí cho ai cả, không cho đồ ăn, đồ uống, vải, xe cộ, vòng hoa, hương, dầu xoa, sàng tọa, đèn đuốc cho Sa-môn, Bà-la-môn, cho các người ăn xin nghèo khổ khốn cùng. Này các Tỷ-kheo, hạng người như vậy như hạn hán không mưa. Và này các Tỷ-kheo, thế nào là hạng người như chỉ mưa trong địa phương? Ở đây, này các Tỷ-kheo, có người có bố thí cho một số người, nhưng không bố thí cho một số người. Dầu số người đó là Sa-môn, Bà-la-môn hay các người ăn xin nghèo khổ, khốn cùng, họ không bố thí đồ ăn đồ uống, vải, xe cộ, vòng hoa, hương dầu xoa, sàng tọa, đèn đuốc. Này các Tỷ-kheo, hạng người như vậy là hạng người như mưa chỉ trong địa phương. Và này các Tỷ-kheo, thế nào là hạng người như mưa đổ xuống khắp tất cả? Ở đây, này các Tỷ-kheo, có hạng người cho tất cả mọi người, cho đồ ăn, đồ uống, vải mặc, xe cộ, vòng hoa, hương, dầu xoa, sàng tọa, đèn đuốc, cho các người Sa-môn, Bà-la-môn cho các người ăn xin nghèo đói khốn cùng. Này các Tỷ-kheo, có ba hạng người này, có mặt, hiện hữu ở đời.`, ref: "Itivuttaka 75", url: "https://loicuaducphat.org/iti/iti75.html#content" },

{ text: `Do hy vọng được ba lạc này, bậc Hiền trí hộ trì giới. Thế nào là ba? "Mong rằng lời tán thán sẽ đến với ta", bậc Hiền trí hộ trì giới. "Mong rằng, tài sản sẽ khởi lên cho ta", bậc Hiền trí hộ trì giới. "Mong rằng khi thân hoại mạng chung, ta sẽ sanh lên thiện thú, thiên giới, cõi đời này", bậc Hiền trí hộ trì giới.\n\nBậc trí hộ trì giới,\nHy vọng được ba lạc,\nÐược khen, được tài sản,\nÐời sau sống hoan hỷ,\nTrong cảnh giới chư Thiên.\n\nNếu không làm điều ác,\nNhưng theo kẻ làm ác,\nThì bị nghi làm ác,\nVà bị tăng tiếng xấu.\n\nGiống như người làm bạn,\nGiống như người làm theo,\nNgười này giống người ấy\nGiống như người cộng trú.\n\nNgười theo, người được theo,\nXúc chạm, được xúc chạm,\nNhư cây tên nhiễm độc\nNhiễm bó tên chưa nhiễm,\nBậc Trí vì sợ nhiễm,\nNên không bạn kẻ ác.\n\nVới ngọn cỏ kusa,\nDùng gói đồ cá thúi,\nKusa hay mùi thúi,\nCũng vậy, gần kẻ ngu.\n\nCòn người dùng ngọn lá,\nGói hương Ta-ga-ra,\nNgọn lá bay mùi thơm\nCũng vậy, gần bậc Trí.\n\nDo vậy, nhờ nghĩ đến\nCái giỏ bằng lá ấy,\nBiết được những cái gì\nSẽ rơi vào tự mình,\nBậc Hiền trí không theo,\nNhững hạng người bất thiện,\nChỉ biết làm bạn thân,\nNhững người lành hiền thiện.\n\nNhững kẻ ác, bất thiện,\nDắt dẫn đến địa ngục,\nCòn những kẻ tốt lành,\nÐạt đến cảnh thiện thú.`, ref: "Itivuttaka 76", url: "https://loicuaducphat.org/iti/iti76.html#content" },

{ text: `Này các Tỷ-kheo, thân này bị hủy hoại, thức bị lụn tàn, tất cả sanh y là vô thường, khổ, chịu sự biến hoại.\n\nBiết thân bị huỷ hoại,\nCòn thức bị lụn tàn,\nThấy sợ trong sanh y,\nHiểu được sanh và chết.\n\nSau khi chứng đạt được,\nSự an tịnh tối thượng,\nTự ngã được tu tập,\nChỉ còn đợi thời gian.`, ref: "Itivuttaka 77", url: "https://loicuaducphat.org/iti/iti77.html#content" },

{ text: `Rừng dục được sanh lên,\nChính do sự cộng trú,\nRừng dục được chặt đứt,\nChính nhờ không cộng trú,\nNhư leo tấm gỗ nhỏ,\nBị chìm dưới sông lớn,\n\nCũng vậy, nếu đi đến\nVới kẻ lười, biếng nhác,\nBậc sống đời tốt lành,\nRồi cũng bị chìm luôn.\nDo vậy hãy tránh xa,\nKẻ lười không tinh tấn.\n\nHãy chung sống cộng trú,\nVới bậc Thánh viễn ly,\nVới những bậc tinh cần\nSống trong cảnh thiền định,\nVới những vị thường xuyên,\nSiêng năng và cần mẫn.`, ref: "Itivuttaka 78", url: "https://loicuaducphat.org/iti/iti78.html#content" },

{ text: `Này các Tỷ-kheo, có ba pháp này đưa đến tổn giảm cho Tỷ-kheo hữu học.\n\nThế nào là ba? Ở đây, này các Tỷ-kheo, Tỷ-kheo hữu học ưa thích công việc, thích thú công việc, đam mê ưa thích công việc; ưa thích nói chuyện, thích thú nói chuyện, đam mê ưa thích nói chuyện; ưa thích nằm ngủ, thích thú nằm ngủ, đam mê ưa thích nằm ngủ.\n\nTỷ-kheo thích công việc,\nThích thú trong nói chuyện,\nVà ưa thích nằm ngủ,\nSống dao động trạo cử;\nVị Tỷ-kheo như vậy,\nKhông thể nào chứng ngộ,\nChứng Bồ-đề tối thượng,\n\nDo vậy, đối vị ấy,\nCần phải ít công việc,\nPhải ít sự nằm ngủ,\nKhông được có tháo động,\nVị Tỷ-kheo như vậy,\nMới có thể chứng được,\nChứng tối thượng Bồ-đề.`, ref: "Itivuttaka 79", url: "https://loicuaducphat.org/iti/iti79.html#content" },

{ text: `Này các Tỷ-kheo, có ba tầm tư bất thiện này. Thế nào là ba? Tầm tư liên hệ đến tự đề cao mình; tầm tư liên hệ đến lợi dưỡng, cung kính, danh vọng; tầm tư liên hệ đến lo lắng cho người khác. Này các Tỷ-kheo, có ba tầm tư bất thiện này.\n\nAi có sự liên hệ,\nTự đề cao chính mình,\nLiên hệ đến lợi dưỡng\nCung kính và tôn trọng,\nAi ưa thích, vui thích,\nLàm thân, làm bạn hữu,\nNhững vị ấy đứng xa\nDiệt tận các kiết sử.\n\nAi từ bỏ con cái,\nTừ bỏ các loài vật,\nTừ bỏ các lễ cưới\nBỏ cất chứa tài sản\nTỷ-kheo ấy có thể,\nChứng Bồ-đề vô thượng.`, ref: "Itivuttaka 80", url: "https://loicuaducphat.org/iti/iti80.html#content" },

{ text: `Này các Tỷ-kheo, Ta đã thấy các chúng sanh bị cung kính chinh phục, bị tâm cung kính xâm chiếm, sau khi thân hoại mạng chung, bị sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Này các Tỷ-kheo, Ta đã thấy các chúng sanh bị không cung kính chinh phục, tâm bị không cung kính xâm chiếm, sau khi thân hoại mạng chung, bị sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Này các Tỷ-kheo, Ta đã thấy các chúng sanh khi tâm bị chinh phục, bị xâm chiếm bởi cả hai cung kính và không cung kính, sau khi thân hoại mạng chung, bị sanh vào cõi dữ, ác thú, đọa xứ, địa ngục.\n\nAi khi được cung kính,\nKhi không được cung kính,\nTrong cả hai trường hợp,\nTâm định không lay chuyển.\nSống hạnh không phóng dật.\n\nTâm thường nhập thiền tư,\nVới tâm tưởng tế nhị,\nChánh quán các sở kiến,\nƯa thích chấp thủ diệt,\nÐược gọi bậc chân nhân.`, ref: "Itivuttaka 81", url: "https://loicuaducphat.org/iti/iti81.html#content" },

{ text: `Này các Tỷ-kheo, khi nào bậc Thánh đệ tử cạo bỏ râu tóc, đắp áo cà-sa, nghĩ đến xuất gia, từ bỏ gia đình, sống không gia đình; trong khi ấy, này các Tỷ-kheo, tiếng chư Thiên được vang lên: "Vị Thánh đệ tử này nghĩ đến chiến đấu với Ác ma". Này các Tỷ-kheo, đây là tiếng chư Thiên thứ nhất, thỉnh thoảng được vang lên giữa chư Thiên, tùy thời được khởi lên. Lại nữa, này các Tỷ-kheo, khi nào bậc Thánh đệ tử sống chuyên tâm tu tập về Bảy Bồ-đề phần; trong khi ấy, này các Tỷ-kheo, tiếng chư Thiên được vang lên: "Vị Thánh đệ tử này chiến đấu với Ác ma". Này các Tỷ-kheo, đây là tiếng chư Thiên thứ hai, thỉnh thoảng được vang lên giữa chư Thiên, tùy thời được khởi lên. Lại nữa, này các Tỷ-kheo, khi nào bậc Thánh đệ tử, với sự diệt tận các lậu hoặc, ngay trong hiện tại, tự mình với thắng trí chứng ngộ, chứng đạt và an trú vô lậu tâm giải thoát, tuệ giải thoát, trong khi ấy, này các Tỷ-kheo, tiếng chư Thiên vang lên: "Vị Thánh đệ tử này đã chiến thắng trong chiến trận. Ðứng đầu trong chiến trận, sau khi chiến thắng, vị ấy an trú". Này các Tỷ-kheo, đây là tiếng chư Thiên thứ ba, thỉnh thoảng được vang lên giữa chư Thiên, tùy thời được khởi lên. Này các Tỷ-kheo, giữa chư Thiên có các tiếng chư Thiên này, thỉnh thoảng được vang lên, tuỳ thời được khởi lên.`, ref: "Itivuttaka 82", url: "https://loicuaducphat.org/iti/iti82.html#content" },

{ text: `Này các Tỷ-kheo, hãy sống tuỳ quán bất tịnh trên thân, hãy khéo an trú niệm hơi thở vô hơi thở ra, đặt niệm trước mặt, hướng về nội tâm; hãy sống tùy quán vô thường trong tất cả các hành. Này các Tỷ-kheo, khi sống tùy quán bất tịnh trên thân tham tùy miên đối với tịnh giới được đoạn trừ; khi khéo an trú niệm hơi thở vô hơi thở ra, đặt niệm trước mặt, hướng về nội tâm, thời các tâm hướng ngoại, dự phần vào tổn hại không có; khi sống tùy quán vô thường trong tất cả hành, thời vô minh trừ diệt, minh được khởi lên.\n\nQuán bất tịnh trên thân,\nNiệm thở vô thở ra,\nTịnh chỉ tất cả hành,\nThường nhiệt tâm, chánh kiến,\n\nVị Tỷ-kheo như vậy,\nÐã thấy rất chơn chánh,\nTừ đấy ở nơi đây,\nVị ấy được giải thoát,\nThắng trí được thành tựu,\nLắng dịu thật an tịnh,\nVị ẩn sĩ như vậy,\nChắc vượt khỏi ách nạn.`, ref: "Itivuttaka 85", url: "https://loicuaducphat.org/iti/iti85.html#content" },

{ text: `Với vị Tỷ-kheo hành trì tùy pháp đúng pháp, khi vị ấy nói vị ấy nói đúng pháp không phải phi pháp; khi vị ấy suy tư, vị ấy suy tư với suy tư đúng pháp, không phải suy tư phi pháp. Do từ bỏ hai điều ấy, vị ấy trú xả, chánh niệm tỉnh giác.\n\nThích pháp, hân hoan pháp,\nSuy tư trên Chánh pháp,\nTỷ-kheo tùy niệm pháp,\nChánh pháp không tổn giảm.\n\nKhi đi hoặc khi đứng,\nKhi ngồi hoặc khi nằm,\nNội tâm được chế ngự\nVị ấy đạt an tịnh.`, ref: "Itivuttaka 86", url: "https://loicuaducphat.org/iti/iti86.html#content" },

{ text: `Này các Tỷ-kheo, dục tầm tác thành mù, tác thành không mắt, tác thành không trí, đưa đến tuệ đoạn diệt, dự phần vào tổn hại, không đưa đến Niết-bàn. Này các Tỷ-kheo, sân tầm tác thành mù, tác thành không mắt, tác thành không trí, đưa đến tuệ đoạn diệt, dự phần vào tổn hại, không đưa đến Niết-bàn. Này các Tỷ-kheo, hại tầm tác thành mù, tác thành không mắt, tác thành không trí, đưa đến tuệ đoạn diệt, dự phần vào tổn hại, không đưa đến Niết-bàn.\n\nHãy suy tư, suy tầm,\nBa tầm thuộc chánh thiện,\nÐối ba tư duy ác,\nHãy từ bỏ, lánh xa,\nVị ấy chắc chế ngự,\nHành tướng các tư duy,\n\nNhư cơn mưa dẹp sạch,\nCác bụi bặm chất chứa.\nVị ấy thật chắc chắn\nAn tịnh tầm với tâm.\nỞ đây vị ấy đạt,\nCon đường an tịnh đạo.`, ref: "Itivuttaka 87", url: "https://loicuaducphat.org/iti/iti87.html#content" },

{ text: `Tham sanh ra bất hạnh,\nTham làm tâm dao động,\nTham chính là sợ hãi,\nSanh ra từ bên trong,\nLoài Người không rõ biết\nLoại tham đặc biệt ấy.\n\nNgười tham không biết rõ\nÐâu chính là lợi ích,\nNgười tham không thấy được\nÐâu chính là Chánh pháp.\nMù lòa và tối tăm,\nSẽ xuất hiện, có mặt,\nỞ nơi một người nào,\nCó tham cùng chung sống.\n\nAi đoạn trừ được tham,\nKhông tham vật đáng tham,\nVới ai tham đoạn trừ\nNhư giọt nước lá sen.\n\nSân sanh ra bất hạnh,\nSân làm tâm dao động.\nSân chính là sợ hãi,\nSanh ra từ bên trong\nLoài Người không rõ biết,\nLòng sân đặc biệt ấy.\n\nNgười sân không biết rõ\nÐâu chính là lợi ích,\nNgười sân không thấy được\nÐâu chính là Chánh pháp,\nMù lòa và tối tăm,\nSẽ xuất hiện, có mặt,\nỞ nơi sân người nào,\nCó sân cùng chung sống.\n\nAi đoạn trừ được sân,\nKhông sân việc đáng sân,\nVới ai, sân đoạn trừ,\nNhư quả cây ta-la\nÐược chặt đứt khỏi cành.\n\nSi sanh ra bất hạnh,\nSi làm tâm dao động,\nSi chính là sợ hãi,\nSanh ra từ bên trong,\nLoài Người không rõ biết\nLòng si đặc biệt ấy.\n\nNgười si không rõ biết\nÐâu chính là lợi ích,\nNgười si không thấy được\nÐâu chính là Chánh pháp,\nMù lòa và tối tăm\nSẽ xuất hiện, có mặt,\nỞ nơi một người nào,\nCó si cùng chung sống.\n\nAi đoạn trừ được si,\nKhông si việc đáng si,\nVị ấy quét sạch được\nTất cả mọi si ám,\nNhư mặt trời mọc lên,\nQuét sạch mọi tăm tối.`, ref: "Itivuttaka 88", url: "https://loicuaducphat.org/iti/iti88.html#content" },

{ text: `Này các Tỷ-kheo, có ba nội uế, nội thù này, nội đối thủ, nội sát nhân, nội thù địch này. Thế nào là ba? Tham, này các Tỷ-kheo, là nội uế, nội thù, nội đối thủ, nội sát thủ, nội sát nhân, nội thù địch. Sân, này các Tỷ-kheo, là nội uế, nội thù, nội đối thủ, nội sát nhân, nội thù địch. Si, này các Tỷ-kheo, là nội uế, nội thù, nội đối thủ, nội sát nhân, nội thù địch. Này các Tỷ-kheo, có ba nội uế, nội thù, nội đối thủ, nội sát nhân, nội thù địch này.`, ref: "Itivuttaka 88", url: "https://loicuaducphat.org/iti/iti88.html#content" },

{ text: `Này các Tỷ-kheo, có ba tín thành tối thượng này. Thế nào là ba? Này các Tỷ-kheo, so sánh các chúng sanh, không chân, hai chân, bốn chân hay nhiều chân, có sắc hay không có sắc, có tưởng, không có tưởng, hay không có tưởng không không có tưởng. Như Lai được xem là tối thượng đối với chúng, tức là bậc A-la-hán, Chánh đẳng Chánh giác. Này các Tỷ-kheo, những ai có lòng tin thành với đức Phật, những vị ấy có lòng tín thành nơi tối thượng. Với những ai có lòng tín thành nơi tối thượng, quả dị thục là quả tối thượng. Này các Tỷ-kheo, so sánh các pháp hữu vi hay vô vi, ly tham được xem là tối thượng đối với họ, tức là kiêu mạn bị nhiếp phục, khát ái bị chế ngự, chấp nhận được nhổ lên, lưu chuyển bị cắt đứt, ái diệt, ly tham, đoạn diệt, Niết-bàn. Này các Tỷ-kheo, những ai có lòng tín thành nơi ly tham, những vị ấy có lòng tín thành nơi tối thượng; với những ai có lòng tin nơi tối thượng, quả dị thục là quả tối thượng. Này các Tỷ-kheo, so sánh Tăng chúng hay hội chúng, Tăng chúng đệ tử của Như Lai được xem là tối thượng, tức là bốn đôi, tám vị. Chúng đệ tử này của Thế Tôn là đáng cung kính, đáng tôn trọng, đáng cúng dường, đáng chắp tay, là ruộng phước vô thượng ở đời. Này các Tỷ-kheo, những ai có lòng tín thành nơi Tăng chúng, những vị ấy có lòng tín thành nơi tối thượng; với những ai có lòng tin nơi tối thượng, quả dị thục là quả tối thượng. Này các Tỷ-kheo, có ba tín thành tối thượng này.`, ref: "Itivuttaka 90", url: "https://loicuaducphat.org/iti/iti90.html#content" },

{ text: `Những ai có lòng tin,\nLòng tín nơi tối thượng,\nChính là sự rõ biết,\nBiết Chánh pháp tối thượng.\nNhững ai có lòng tin,\nNơi đức Phật tối thượng,\nBậc Vô thượng xứng đáng,\nXứng đáng được cúng dường.\n\nNhững ai có lòng tin,\nNơi Chánh pháp tối thượng,\nNhững pháp rời bỏ tham,\nAn tịnh, thật tịnh lạc.\nNhững ai có lòng tin,\nNơi Tăng chúng tối thượng.\nNhững ruộng phước công đức,\nVô thượng không gì hơn.\n\nNhững ai đã bố thí,\nVới đối tượng tối thượng,\nCông đức được tăng trưởng,\nTăng trưởng đến tối thượng.\nThọ mạng được tối thượng,\nDung sắc cũng tối thượng,\nDanh vọng, tiếng đồn tốt,\nAn lạc và sức mạnh.\n\nBậc trí có bố thí,\nBố thí vị tối thượng,\nVị định tĩnh, thiền định,\nTrong Chánh pháp tối thượng,\nChư Thiên hay loài Người,\nÐạt được sự tối thượng,\nHọ sung sướng hân hoan.`, ref: "Itivuttaka 90", url: "https://loicuaducphat.org/iti/iti90.html#content" },

{ text: `Tài sản ở gia đình,\nÐược đoạn tận từ bỏ,\nNhưng khó dự phần được,\nMục đích Sa-môn hạnh,\nTự đưa đến tổn hại,\nVà đưa đến tán loạn,\nGiống que lửa thiêu xác,\nÐi đến chỗ hoại vong.\n\nNhiều người khoác y vàng,\nÁc pháp, không tự chế,\nDo nghiệp ác, người ấy,\nChắc chắn sinh địa ngục.\n\nTốt hơn nuốt hòn sắt,\nChảy đỏ, một cục lửa,\nNếu kẻ hành ác giới,\nĂn đồ ăn quốc độ,\nKhông biết có chế ngự.`, ref: "Itivuttaka 91", url: "https://loicuaducphat.org/iti/iti91.html#content" },

{ text: `Này các Tỷ-kheo, nghĩa này là nghề tận cùng trong các nghề nuôi sống, tức là đi bát khất thực; Này các Tỷ-kheo, danh từ nhiếc mắng ở trong đời là nói rằng: "Ông là kẻ đi bát, với bát cầm tay, ông đi khắp mọi nơi". Tuy vậy chính nghề nuôi sống này được các thiện gia nam tử chấp nhận, những người sống vì lý tưởng, vì duyên sống với lý tưởng, không bị thúc đẩy làm nghề ấy vì sợ vua, vì sợ ăn trộm, vì mắc nợ, vì sợ hãi, không phải vì mất nghề nuôi sống; Nhưng vì nghĩ rằng: "Nay ta bị rơi vào sanh, già, chết, sầu, bi, khổ, ưu, não, bị khổ tràn đầy, bị khổ chinh phục. Rất có thể, một số phương pháp chấm dứt toàn bộ khổ uẩn này có thể trình bày". Này các Tỷ-kheo, thiện nam tử này xuất gia như vậy, tham ái trong các dục, với lòng tham sắc xảo, với tâm sân hận, ý tư duy nhiễm ác, thất niệm, không tỉnh giác, không định tĩnh, tâm tán loạn, với các căn hoang dại. Này các Tỷ-kheo, như một que lửa lấy từ chỗ thiêu xác, cả hai đầu đều cháy đỏ, ở giữa lại lắm phân, không hoàn thành được mục đích làm que củi ở trong làng hay ở trong rừng. Này các Tỷ-kheo, Ta nói người này như ví dụ như vậy, dầu cho bỏ tài sản gia đình nhưng không làm viên mãn mục đích Sa-môn hạnh.`, ref: "Itivuttaka 91", url: "https://loicuaducphat.org/iti/iti91.html#content" },

{ text: `Này các Tỷ-kheo, nếu một Tỷ-kheo nắm lấy viền áo Tăng-già lê đi theo sau lưng Ta, chân bước theo chân, nhưng vị ấy có tham ái trong các dục, với lòng sắc xảo, với tâm sân hận, ý tư duy nhiễm ác, thất niệm, không tỉnh giác, không định tĩnh, tâm tán loạn, với các căn hoang dại, vị ấy xa hẳn Ta và Ta xa vị ấy. Vì cớ sao? Này các Tỷ-kheo, Tỷ-kheo ấy không thấy Pháp. Do không thấy Pháp nên không thấy Ta.\n\nNày các Tỷ-kheo, nếu Tỷ-kheo sống xa đến một trăm do-tuần và vị ấy không có tham ái trong các dục, với lòng tham không sắc xảo, tâm không sân hận, ý tư duy không nhiễm ác, chánh niệm tỉnh giác, định tĩnh nhất tâm, các căn được chế ngự, vị ấy gần hẳn Ta và Ta gần vị ấy. Vì cớ sao? Này các Tỷ-kheo, Tỷ-kheo ấy thấy Pháp. Do thấy Pháp nên thấy Ta.\n\nNếu có thể bước theo,\nNhưng nhiều dục bực phiền.\nHãy xem người như vậy,\nThật là xa, rất xa,\nXa giữa người ái dục\nVà người không ái dục,\nXa giữa người lắng dịu\nVà người không lắng dịu,\nXa giữa người tham ái\nVà người đã trừ ái.\n\nSau khi thắng tri Pháp,\nBậc Hiền trí biết Pháp,\nNhư ao không gió thổi,\nKhông dao động, tịnh chỉ.\nHãy xem người như vậy,\nThật là gần, rất gần,\nGần giữa người không ái,\nVà người không có ái,\nGần giữa người lắng dịu,\nVà người được lắng dịu,\nGần giữa người không tham,\nVà người trừ tham ái.`, ref: "Itivuttaka 92", url: "https://loicuaducphat.org/iti/iti92.html#content" },

{ text: `Này các Tỷ-kheo, có ba loại lửa này. Thế nào là ba? Lửa tham, lửa sân, lửa si. Này các Tỷ-kheo, có ba loại lửa này.\n\nLửa tham đốt cháy người,\nSay mê trong các dục,\nCòn lửa sân đốt cháy,\nNhững người có sân hận,\nNhững người giết, sát hại,\nCác loại có sanh mạng.\n\nCòn lửa si đốt cháy,\nNhững kẻ bị mê muội,\nNhững kẻ không tinh luyện,\nTrong giáo pháp bậc Thánh,\nDo không được biết rõ\nCác loại lửa như vậy,\nNên loài Người ưa thích,\nVui thích với có thân.\n\nHọ làm cảnh dịa ngục,\nÐược lớn mạnh tăng trưởng,\nKể cả giới bàng sanh,\nChỗ sanh xứ súc vật,\nCùng với A-tu-la,\nVới cảnh giới quỷ đói,\nHọ không được thoát khỏi,\nTrói buộc của Ác ma.`, ref: "Itivuttaka 93", url: "https://loicuaducphat.org/iti/iti93.html#content" },

{ text: `Những ai ngày và đêm,\nChú tâm vào, chuyên học,\nHọc những lời giảng dạy,\nBậc Chánh đẳng Chánh giác.\nHọ làm cho lắng dịu\nNgọn lửa của lòng tham,\nLuôn luôn ý thức được,\nTánh bất tịnh sự vật.\n\nVới lòng thương, từ mẫn,\nNhững hạng người tối thượng,\nLàm lắng dịu, chỉ tịnh,\nNgọn lửa của sân hận.\nCòn ngọn lửa si mê,\nVới trí tuệ dập tắt,\nTrí tuệ này đưa đến\nThể nhập vào chân lý.\n\nBậc thận trọng sáng suốt,\nNgày đêm làm lắng dịu\nCác loại lửa như vậy,\nKhông có biết mệt mỏi,\nHọ làm cho lắng dịu,\nKhông một chút dư tàn.\n\nNhững bậc Thánh đã thấy,\nBậc trí tuệ hiểu biết,\nLà những bậc Hiền trí,\nThấy được nhờ chánh trí\nDo họ thắng tri được,\nSự diệt tận của sanh,\nNên họ không đi đến,\nSanh đi rồi sanh lại.`, ref: "Itivuttaka 93", url: "https://loicuaducphat.org/iti/iti93.html#content" },

{ text: `Này các Tỷ-kheo, có ba sanh khởi của dục. Thế nào là ba? Dục đối với sự vật hiện tại, sự thích thú đối với sự vật mình tạo ra, sự chấp nhận sự vật do người khác tạo ra. Này các Tỷ-kheo, có ba sanh khởi này của dục.\n\nChư Thiên hưởng dục lạc,\nChư Thiên uy lực lớn,\nHoá lạc thiên Chư Thiên,\nVà các chư Thiên khác\nThọ hưởng các dục lạc,\nDầu cõi này cõi khác,\nKhông ra khỏi luân hồi.\n\nBiết rõ hiểm nguy này,\nNgười trí đối các dục,\nTrong đời này đời khác,\nTừ bỏ tất cả dục,\nDầu thuộc về chư Thiên\nHay dục thuộc loài Người.\n\nNhững ai được chặt đứt\nDòng nước khó vượt qua,\nSự say đắm sự vật,\nThân ái và tốt đẹp,\nHọ làm cho lắng dịu,\nKhông có vật dư thừa,\nHọ vượt qua đau khổ,\nKhông còn chút dư tàn,\n\nNhững bậc Thánh đã thấy.\nBậc trí tuệ hiểu biết,\nLà những bậc Hiền trí,\nThấy được nhờ chánh trí.\nDo họ thắng tri được\nSự diệt tận của sanh,\nNên họ không đi đến,\nSanh đi rồi sanh lại.`, ref: "Itivuttaka 95", url: "https://loicuaducphat.org/iti/iti95.html#content" },

{ text: `Này các Tỷ-kheo, thế nào là Giới tốt lành? Ở đây này các Tỷ-kheo, vị Tỷ-kheo giữ giới, sống chế ngự với sự chế ngự của giới bổn Patimokkha, đầy đủ oai nghi chánh hạnh, thấy sợ hãi trong những lỗi nhỏ nhặt, chấp nhận và học tập trong các học pháp. Như vậy, này các Tỷ-kheo, là vị Tỷ-kheo có giới tốt lành.\n\nVà thế nào là có Pháp tốt lành? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo sống chuyên tâm chuyên chú tu tập Bảy pháp giác chi. Như vậy, này các Tỷ-kheo, là vị có pháp tốt lành. Như vậy là giới tốt lành và pháp tốt lành. Và thế nào là Tuệ tốt lành? Ở đây, này các Tỷ-kheo, vị Tỷ-kheo do diệt trừ các lậu hoặc, ngay trong hiện tại, tự mình với thắng trí chứng ngộ chứng đạt và an trú vô lậu tâm giải thoát, tuệ giải thoát. Như vậy, này các Tỷ-kheo, là vị Tỷ-kheo có tuệ tốt lành. Như vậy, một người có giới tốt lành, có pháp tốt lành, có tuệ tốt lành được gọi trong Pháp và Luật là vị toàn hảo.\n\nAi với thân, với lời,\nVới ý, không làm ác,\nVị ấy giới tốt lành,\nÐược gọi là Tỷ-kheo\nCó được lòng xấu hổ,\n\nAi, pháp khéo tu tập,\nNhững pháp giúp đạt đến,\nChứng được quả Bồ-đề,\nVị ấy pháp tốt lành,\nÐược gọi là Tỷ-kheo\nKhông có dục trào ra.\n\nAi quán tri đau khổ,\nỞ đây, diệt trừ khổ,\nVị ấy tuệ tốt lành,\nÐược gọi là Tỷ-kheo\nKhông có các lậu hoặc,.\n\nÐầy đủ những pháp ấy,\nThoát khỏi sự phiền muộn\nChặt đứt mọi nghi ngờ,\nKhông luyến ái tham đắm\nMọi sự vật ở đời,\nVị ấy được xưng gọi\nVị đoạn tận tất cả.`, ref: "Itivuttaka 97", url: "https://loicuaducphat.org/iti/iti97.html#content" },

{ text: `Này các Tỷ-kheo, có hai loại bố thí: Bố thí tài vật và bố thí Pháp. Này các Tỷ-kheo, đây là bố thí tối thượng trong hai loại bố thí này, tức là bố thí Pháp. Này các Tỷ-kheo, có hai sự phân phát này: Phân phát tài vật và phân phát Pháp. Ðây là phân phát tối thượng trong hai loại phân phát này, tức là phân phát Pháp. Này các Tỷ-kheo, có hai loại giúp đỡ này, giúp đỡ tài vật và giúp đỡ Pháp. Này các Tỷ-kheo, đây là giúp đỡ tối thượng trong hai loại giúp đỡ này, tức là giúp đỡ Pháp.`, ref: "Itivuttaka 98", url: "https://loicuaducphat.org/iti/iti98.html#content" },

{ text: `Này các Tỷ-kheo, có bốn pháp này ít oi, dễ được và không có phạm lỗi. Thế nào là bốn? Trong các loại y, này các Tỷ-kheo, y phấn tảo lượm từ đống rác là ít oi, dễ được và không phạm lỗi. Trong các loại, để ăn, này các Tỷ-kheo, đi khất thực từng miếng là ít oi, dễ được và không có phạm lỗi. Trong các sàng tọa, này các Tỷ-kheo, gốc cây là ít oi, dễ được và không có phạm lỗi. Trong các loại dược phẩm, này các Tỷ-kheo, nước tiểu hôi là ít oi, dễ được, không có phạm lỗi. Này các Tỷ-kheo, có bốn loại ít oi, dễ được, không có phạm lỗi nào. Này các Tỷ-kheo, nếu Tỷ-kheo biết đủ, với các loại ít oi, dễ được này, Ta tuyên bố rằng đây là một chi phần Sa-môn hạnh của vị ấy.\n\nBiết đủ với sự vật,\nÍt oi, dễ tìm được,\nLại không có phạm tội,\nTâm không bị phiền nhiễu,\nVề vấn đề sàng tọa,\nY áo và ăn uống;\nTâm không bị lo lắng,\nVề phương hướng phải đi,\n\nCác pháp được tuyên bố,\nThuận lợi Sa-môn hạnh,\nHọ được có đầy đủ,\nVới Tỷ-kheo biết đủ,\nVới vị không phóng dật.`, ref: "Itivuttaka 101", url: "https://loicuaducphat.org/iti/iti101.html#content" },

{ text: `Này các Tỷ-kheo, những Tỷ-kheo nào đầy đủ giới, đầy đủ định, đầy đủ tuệ, đầy đủ giải thoát, đầy đủ giải thoát tri kiến, những vị giáo giới, những vị giảng dạy, những vị tuyên bố, khích lệ, làm cho phấn khởi, làm cho hoan hỷ, những bậc xứng đáng thuyết minh diệu pháp, này các Tỷ-kheo, Ta tuyên bố rằng chỉ thấy các vị như vậy là lợi ích nhiều cho các Tỷ-kheo ấy; này các Tỷ-kheo, Ta tuyên bố rằng chỉ nghe các vị như vậy là lợi ích nhiều cho các Tỷ-kheo ấy; này các Tỷ-kheo, Ta tuyên bố rằng chỉ đi đến yết kiến các vị như vậy là lợi ích nhiều cho các Tỷ-kheo ấy; này các Tỷ-kheo, Ta tuyên bố rằng chỉ thân cận các vị như vậy là lợi ích nhiều cho các Tỷ-kheo ấy; này các Tỷ-kheo, Ta tuyên bố rằng chỉ nhớ nghĩ đến các vị như vậy là lợi ích nhiều cho các Tỷ-kheo ấy. Này các Tỷ-kheo, Ta tuyên bố rằng chỉ tùy theo các vị như vậy xuất gia là lợi ích nhiều cho các Tỷ-kheo ấy. Vì cớ sao? Này các Tỷ-kheo, khi phục vụ, chia sẻ, thân cận những Tỷ-kheo như vậy, thời giới uẩn chưa được đầy đủ đi đến được tu tập đầy đủ, định uẩn chưa được đầy đủ đi đến được tu tập đầy đủ, tuệ uẩn chưa được đầy đủ đi đến tu tập đầy đủ, giải thoát uẩn chưa được đầy đủ, đi đến được tu tập đầy đủ, giải thoát tri kiến uẩn chưa được đầy đủ đi đến được tu tập đầy đủ. Này các Tỷ-kheo, những Tỷ-kheo như vậy được gọi là những bậc Ðạo sư, được gọi là những người cầm đầu đoàn lữ hành, được gọi là những vị đã từ bỏ những nguyên nhân tác hại, được gọi là những vị quét sạch tối tăm, được gọi là những vị tác thành minh, được gọi là những vị tác thành quang; được gọi là những vị tác thành ánh sáng, được gọi là những vị cầm bó đuốc, được gọi là những vị phóng quang, được gọi là những bậc Thánh, được gọi là những người có mắt.`, ref: "Itivuttaka 104", url: "https://loicuaducphat.org/iti/iti104.html#content" },

{ text: `Do nhân y áo, này các Tỷ-kheo, ái sanh khởi cho Tỷ-kheo. Do nhân đồ ăn khất thực, này các Tỷ-kheo, ái khởi sanh cho Tỷ-kheo. Do nhân sàng tọa, này các Tỷ-kheo, ái khởi sanh cho Tỷ-kheo. Do nhân sanh hữu, không sanh hữu, này các Tỷ-kheo, ái sanh khởi cho Tỷ-kheo. Này các Tỷ-kheo, có bốn sự sanh khởi này của ái. Ở đây, ái sanh khởi lên cho Tỷ-kheo.\n\nNgười có ái làm bạn,\nBị luân hồi dài dài,\nNó không vượt luân hồi,\nÐời này qua đời khác.\n\nDo biết nguy hại vậy,\nÁi tác thành ra khổ,\nKhông còn có khát ái,\nKhông còn có chấp trước,\nVị Tỷ-kheo chánh niệm\nDu hành khắp đó đây.`, ref: "Itivuttaka 105", url: "https://loicuaducphat.org/iti/iti105.html#content" },

{ text: `Những gia đình nào, này các Tỷ-kheo, trong ấy các con cái kính lễ mẹ cha ở trong nhà, những gia đình ấy được chấp nhận ngang bằng với Phạm thiên. Những gia đình nào, này các Tỷ-kheo, trong ấy các con cái kính lễ mẹ cha ở trong nhà, những gia đình ấy được chấp nhận như các đạo sư thời xưa. Những gia đình nào, này các Tỷ-kheo, trong ấy con cái kính lễ mẹ cha ở trong nhà, những gia đình ấy được chấp nhận là đáng được cúng dường. Phạm thiên, này các Tỷ-kheo, là đồng nghĩa với mẹ cha. Các đạo sư thời xưa, này các Tỷ-kheo, là đồng nghĩa với mẹ cha. Ðáng được cúng dường, này các Tỷ-kheo, là đồng nghĩa với mẹ cha. Vì cớ sao? Giúp đỡ rất nhiều, này các Tỷ-kheo, là mẹ cha đối với con cái, nuôi chúng lớn, dưỡng dục chúng, giới thiệu chúng vào đời.`, ref: "Itivuttaka 106", url: "https://loicuaducphat.org/iti/iti106.html#content" },

{ text: `Mẹ cha gọi Phạm thiên,\nBậc Ðạo Sư thời trước,\nXứng đáng để con cháu,\nNuôi dưỡng và cúng dường.\n\nDo vậy, bậc hiền triết,\nÐảnh lễ và tôn trọng,\nDâng đồ ăn đồ uống,\nVải mặc và giường nằm,\nThoa bóp cả thân mình,\nTắm rửa cả chân tay.\n\nVới sở hành như vậy,\nÐối với mẹ và cha,\nÐời này người hiền khen,\nDời sau hưởng Thiên lạc.`, ref: "Itivuttaka 106", url: "https://loicuaducphat.org/iti/iti106.html#content" },

{ text: `Này các Tỷ-kheo, các Bà-la-môn gia chủ rất có lợi ích cho các Thầy, chính họ đã sắp đặt y áo, đồ ăn khất thực, sàng tọa, dược phẩm trị bệnh cho các Thầy. Này các Tỷ-kheo, các Thầy cũng rất có lợi ích cho các người Bà-la-môn gia chủ, vì các Thầy thuyết pháp cho họ, pháp ấy sơ thiện, trung thiện, hậu thiện, có nghĩa có văn, nói lên Phạm hạnh hoàn toàn viên mãn thanh tịnh. Như vậy, này các Tỷ-kheo, Phạm hạnh này được sống, do tương duyên với nhau, với mục đích vượt qua dòng nước mạnh, đoạn tận khổ đau.\n\nCó nhà và không nhà,\nCả hai nương tựa nhau,\nChứng đạt được diệu pháp,\nÁch an ổn, vô thượng.\n\nTừ các vị có nhà,\nVị không nhà nhận được\nY áo, các vật dụng,\nGiường nằm và chỗ ngồi,\nNhờ vậy tránh khỏi được,\nCác nguy hiểm nhọc nhằn.\n\nCác vị trú gia đình,\nƯớc mong mến gia đình,\nNương tựa bậc Thiện Thệ,\nLòng tin bậc Ứng Cúng,\nLòng tin Thánh trí tuệ,\nHọ tu tập thiền định.\n\nỞ đây, hành trì pháp,\nCon đường đến cõi lành,\nHân hoan trong thiên giới,\nHọ sống được hoan hỷ,\nNhư điều họ mong muốn.`, ref: "Itivuttaka 107", url: "https://loicuaducphat.org/iti/iti107.html#content" },

{ text: `Này các Tỷ-kheo, những Tỷ-kheo nào lừa đảo ngoan cố, lắm mồm, lắm miệng, buông thả hỗn hào vô lễ không định tỉnh, này các Tỷ-kheo, các Tỷ-kheo ấy không phải đệ tử của Ta; này các Tỷ-kheo, các Tỷ-kheo ấy rơi khỏi Pháp và Luật này; và này các Tỷ-kheo, các Tỷ-kheo ấy không đi đến tăng trưởng, tăng thịnh, tăng rộng trong Pháp và Luật này. Và này các Tỷ-kheo, các Tỷ-kheo nào không lừa đảo, không lắm mồm, lắm miệng, nghiêm trang, không ngoan cố, khéo định tĩnh; này các Tỷ-kheo, các Tỷ-kheo ấy là đệ tử của Ta; này các Tỷ-kheo, các Tỷ-kheo ấy không rơi khỏi Pháp và Luật này; và này các Tỷ-kheo, các Tỷ-kheo ấy đi đến tăng trưởng, tăng thịnh, tăng rộng trong Pháp và Luật này.\n\nLừa đảo và ngoan cố,\nLắm mồm và buông thả,\nHỗn hào không định tĩnh,\nNhững hạng người như vậy,\nKhông lớn mạnh trong Pháp,\nÐược bậc Chánh giác giảng.\n\nKhông lừa đảo lắm mồm,\nNghiêm trang và bình tĩnh\nKhông ngoan cố, khéo định,\nHọ lớn mạnh trong Pháp,\nÐược bậc Chánh giác giảng.`, ref: "Itivuttaka 108", url: "https://loicuaducphat.org/iti/iti108.html#content" },

{ text: `Này các Tỷ-kheo, ví như có người bị dòng sông cuốn trôi, dòng sông đẹp đẽ, dễ thương. Có người có mắt, đứng trên bờ thấy người ấy, nói rằng: "Này người kia, tuy người bị cuốn trôi bởi dòng sông đẹp đẽ dễ thương nhưng ở dưới kia có một cái hồ, đầy sóng và nước xoáy, đầy cá sấu và quỷ Dạ-xoa; nếu Ông đến chỗ ấy, Ông sẽ bị chết, hay đau khổ gần như chết. Rồi người ấy, sau khi nghe tiếng của người kia, liền với tay và với chân, bơi ngược dòng". Này các Tỷ-kheo, Ta ví dụ này là để giải thích ý nghĩa. Ở đây, ý nghĩa là như sau: "Dòng sông, này các Tỷ-kheo, là đồng nghĩa với ái. Sắc khả ái dễ thương, này các Tỷ-kheo, là đồng nghĩa với sáu nội xứ. Cái hồ ở dưới, này các Tỷ-kheo, là đồng nghĩa với năm hạ phần kiết sử. Sóng, này các Tỷ-kheo, là đồng nghĩa với phẫn nộ, ưu não. Nước xoáy, này các Tỷ-kheo, là đồng nghĩa với năm dục tăng trưởng. Cá sấu, với quỷ Dạ-xoa, này các Tỷ-kheo, là đồng nghĩa với đàn bà; Ngược dòng, này các Tỷ-kheo, là đồng nghĩa xuất ly. Tinh tấn với tay với chân là đồng nghĩa với tinh cần tinh tấn. Người có mắt đứng trên bờ, này các Tỷ-kheo, là Như Lai, bậc A-la-hán, Chánh Ðẳng Giác".`, ref: "Itivuttaka 109", url: "https://loicuaducphat.org/iti/iti109.html#content" },

{ text: `Cùng với sự đau khổ,\nHãy từ bỏ các dục,\nMong cầu trong tương lai,\nAn ổn khỏi khổ ách,\nChơn chánh hiểu biết rõ,\nTâm khéo được giải thoát.\n\nTại đấy, ở tại đấy,\nCảm xúc được giải thoát,\nVị ấy đạt hiểu biết,\nPhạm hạnh được thành tựu,\nÐến tận cùng thế giới,\nÐến được bờ bên kia.\nVị ấy được gọi vậy.`, ref: "Itivuttaka 109", url: "https://loicuaducphat.org/iti/iti109.html#content" },

{ text: `Khi đi hoặc khi đứng,\nKhi ngồi hay khi nằm,\nKhởi lên ác tâm tư,\nLiên hệ đến gia đình,\n\nThực hành theo ác đạo,\nMờ ám bởi si mê,\nVị Tỷ-kheo như vậy,\nKhông chứng Vô thượng giác.\n\nAi khi đi, khi đứng,\nKhi ngồi hay khi nằm,\nTập trung được tâm tư,\nƯa thích tầm chỉ tịnh,\nVị Tỷ-kheo như vậy,\nChứng được Vô thượng giác.`, ref: "Itivuttaka 110", url: "https://loicuaducphat.org/iti/iti110.html#content" },

{ text: `Ði đứng biết tự chế,\nNgồi nằm biết tự chế,\nTỷ-kheo biết tự chế,\nKhi co tay, duỗi tay.\n\nPhía trên, ngang, cùng khắp,\nXa cho đến cùng tột,\nBất cứ sanh thú nào,\nỞ tại thế giới này,\nKhéo quán sát sanh diệt,\nCủa tất cả pháp uẩn.\n\nSống như vậy nhiệt tâm,\nTâm chỉ tịnh, đúng pháp,\nTâm an tịnh, không động,\nThường xuyên chuyên học tập,\nLiên tục, thường siêng năng,\nTỷ-kheo được gọi vậy.`, ref: "Itivuttaka 111", url: "https://loicuaducphat.org/iti/iti111.html#content" },
     
                { text: `1. Ai nhiếp phục phẫn nộ\nÐang được dấy khởi lên,\nNhư dùng chất linh dược,\nNgăn độc rắn lan rộng\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n2. Ái cắt đứt tham dục,\nKhông còn chút dư tàn,\nNhư kẻ hái hoa sen\nSanh ra từ ao hồ.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },

{ text: `3. Ai cắt đứt tham ái,\nKhông còn chút dư tàn,\nLàm cho nước cạn khô,\nDòng nước chảy nhanh mạnh\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n4. Ai phá hoại kiêu mạn\nKhông còn chút dư tàn,\nNhư nước mạnh tàn phá\nCây cỏ lau yếu hèn,\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },

{ text: `5. Ai trong các sanh hữu,\nKhông tìm thấy lõi cây,\nNhư kẻ đi hái hoa,\nTrên cây sung không hoa.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n6. Với ai trong nội tâm,\nKhông còn có phẫn hận,\nÐã vượt thoát ra khỏi,\nCả hữu và phi hữu.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n7. Với ai những tầm tư,\nÐược làm cho tan biến\nNội tâm khéo sửa soạn,\nKhông còn chút dư tàn.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },

{ text: `8. Ai không đi quá trớn,\nCũng không quá chậm trễ,\nÐã nhiếp phục toàn diện,\nHý luận chướng ngại này.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n9. Ai không đi quá trớn,\nCũng không quá chậm trễ,\nBiết rõ được ở đời,\nSự này toàn hư vọng.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n10. Ai không đi quá trớn,\nCũng không quá chậm trễ,\nTừ bỏ, không có tham,\nSự này toàn hư vọng.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },

{ text: `11. Ai không đi quá trớn,\nCũng không quá chậm trễ,\nTừ bỏ, không tham dục,\nSự này toàn hư vọng.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n12. Ai không đi quá trớn,\nCũng không quá chậm trễ,\nTừ bỏ, ly sân hận,\nSự này toàn hư vọng.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n13. Ai không đi quá trớn,\nCũng không quá chậm trễ,\nTừ bỏ, ly si ám,\nSự này toàn hư vọng.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },

{ text: `14. Với ai, các tùy miên,\nHoàn toàn không hiện hữu,\nCác nguồn gốc bất thiện\nÐược nhổ lên trừ sạch.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n15. Với ai, không có gì,\nDo phiền não sanh khởi,\nLàm duyên trở lui lại,\nVề lại bờ bên này.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n16. Với ai, không có gì,\nDo rừng ái sanh khởi,\nTạo nhân khiến trói buộc\nCon người vào tái sanh.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.\n\n17. Ai đoạn năm triền cái,\nKhông sầu khổ bực phiền,\nVượt qua được nghi hoặc,\nThoát mũi tên phiền não.\nTỷ-kheo ấy từ bỏ,\nBờ này và bờ kia,\nNhư loài rắn thoát bỏ\nDa rắn cũ già xưa.`, ref: "Kinh Tập 1.1", url: "https://loicuaducphat.org/snp/snp1.1.html#content" },

{ text: `Dhàniya:\n18. Cơm ta, nấu đã chín,\nSữa uống, ta vắt xong,\nMục đồng Dhaniya,\nÐã nói lên như vậy.\nTrên bờ sông Mahì,\nTa chung sống đồng cư,\nChòi lá được khéo lợp,\nLửa đốt được cháy đỏ.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi.\n\nThế Tôn:\n19. Ta đoạn được phẫn nộ,\nTâm hoang vu không còn,\nBậc Thế Tôn, Chánh Giác\nÐã nói lên như vậy.\nTrên bờ sông Mahì,\nTa chỉ sống một đêm,\nChòi lá được rộng mở,\nLửa đốt được tịch tịnh.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi.`, ref: "Kinh Tập 1.2", url: "https://loicuaducphat.org/snp/snp1.2.html#content" },

{ text: `Dhàniya:\n20. Ruồi lằn và muỗi mòng,\nỞ đây không tìm thấy,\nMục đồng Dhaniya,\nÐã nói lên như vậy.\nTrên cánh đồng cỏ mọc,\nÐàn bò đi ăn cỏ,\nDầu cơn mưa có đến,\nChúng có thể chịu đựng.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi.\n\nThế Tôn:\n21. Các bè đã được cột,\nKhéo tác thành tốt đẹp,\nBậc Thế Tôn, Chánh Giác\nÐã nói lên như vậy.\nAi qua được bờ kia,\nNhiếp phục dòng nước mạnh,\nLợi ích của chiếc bè,\nÐâu còn thấy cần thiết.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi.`, ref: "Kinh Tập 1.2", url: "https://loicuaducphat.org/snp/snp1.2.html#content" },

{ text: `Thế Tôn:\n23. Tâm Ta khéo nhu thuận,\nÐược giải thoát, mở rộng,\nBậc Thế Tôn, Chánh Giác\nÐã nói lên như vậy.\nLâu ngày tu viên mãn,\nKhéo nhiếp phục chế ngự,\nTrong Ta các pháp ác,\nKhông còn được tìm thấy.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi.`, ref: "Kinh Tập 1.2", url: "https://loicuaducphat.org/snp/snp1.2.html#content" },

{ text: `Thế Tôn:\n25. Ta không có làm mướn,\nCho một ai ở đời,\nBậc Thế Tôn, Chánh Giác\nÐã nói lên như vậy\nVới điều được chứng đắc,\nTa du hành thế giới,\nVề tiền công cần thiết,\nKhông thể có nơi Ta.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi.`, ref: "Kinh Tập 1.2", url: "https://loicuaducphat.org/snp/snp1.2.html#content" },

{ text: `Dhàniya:\n26. Ðây có các bò cái,\nÐây có các bò con,\nMục đồng Dhaniya\nÐã nói lên như vậy.\nÐây có những bò mẹ,\nMang thai, nối giống dòng,\nÐây có những bò đực,\nNhững con chúa đầu đàn.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi.\n\nThế Tôn:\n27. Ðây không có bò cái,\nÐây không có bò con,\nBậc Thế Tôn, Chánh Giác\nÐã nói lên như vậy.\nÐây không có bò mẹ,\nMang thai, nối giống dòng,\nÐây không có bò đực,\nNhững con chúa đầu đàn.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi.`, ref: "Kinh Tập 1.2", url: "https://loicuaducphat.org/snp/snp1.2.html#content" },

{ text: `Thế Tôn:\n29. Giống như con bò đực,\nGiật đứt các trói buộc,\nBậc Thế Tôn, Chánh Giác\nÐã nói lên như vậy.\nNhư voi làm bựt đứt\nCác giây leo héo mục,\nTa không còn đi đến,\nChỗ thai tạng tái sanh.\nNếu là ý người muốn,\nThần mưa, hãy mưa đi."`, ref: "Kinh Tập 1.2", url: "https://loicuaducphat.org/snp/snp1.2.html#content" },

{ text: `Màra:\n33. Ai có các con trai,\nHoan hỷ với con trai,\nÐây là lời Ác ma,\nÐã nói lên như vậy\nNgười chủ các con bò,\nHoan hỷ với con bò.\nCòn người thì hoan hỷ,\nÐối với sự sanh y,\nAi không có sanh y,\nkhông thể có hoan hỷ.\n\nThế Tôn:\n34. Ai có các con trai,\nSầu muộn với con trai,\nBậc Thế Tôn, Chánh Giác,\nÐã nói lên như vậy.\nNgười chủ các con bò,\nSầu muộn với con bò;\nSầu muộn của con người,\nChính do sự sanh y,\nAi không có sanh y,\nKhông thể có sầu muộn.`, ref: "Kinh Tập 1.2", url: "https://loicuaducphat.org/snp/snp1.2.html#content" },

{ text: `35. Ðối với các hữu tình,\nTừ bỏ gậy và trượng,\nChớ làm hại một ai\nTrong chúng hữu tình ấy.\nCon trai không ước muốn,\nCòn nói gì bạn bè,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n36. Do thân cận giao thiệp,\nThân ái từ đấy sanh,\nTùy thuận theo thân ái,\nKhổ này có thể sanh.\nNhìn thấy những nguy hại,\nDo thân ái sanh khởi,\nHãy sống riêng một mình,\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `37. Do lòng từ thương mến,\nÐối bạn bè thân hữu,\nMục đích bị bỏ quên,\nTâm tư bị buộc ràng,\nDo thấy sợ hãi này,\nTrong giao du mật thiết,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n38. Ai nhớ nghĩ chờ mong,\nÐối với con và vợ,\nNgười ấy bị buộc ràng,\nNhư cành tre rậm rạp,\nCòn các ngọn tre cao,\nNào có gì buộc ràng,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `39. Như nai trong núi rừng,\nKhông gì bị trói buộc,\nTự đi chỗ nó muốn\nÐể tìm kiếm thức ăn.\nNhư các bậc Hiền trí,\nThấy tự do giải thoát,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n40. Giữa bạn bè thân hữu,\nBị gọi lên gọi xuống,\nTại chỗ ở trú xứ,\nHay trên đường bộ hành.\nThấy tự do giải thoát,\nKhông có gì tham luyến,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n49. Như vậy nếu ta cùng\nVới một người thứ hai,\nTranh luận cãi vã nhau,\nSân hận, gây hấn nhau,\nNhìn thấy trong tương lai,\nSợ hãi hiểm nguy này,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `41. Giữa bạn bè thân hữu,\nƯa thích, vui cười đùa,\nÐối với con, với cháu,\nÁi luyến thật lớn thay,\nNhàm chán sự hệ lụy,\nVới những người thân ái,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n42. Khắp cả bốn phương trời,\nKhông sân hận với ai,\nTự mình biết vừa đủ,\nVới vật này vật khác,\nVững chịu các hiểm nguy,\nKhông run sợ dao động,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `43. Có số người xuất gia,\nChung sống thật khó khăn,\nCũng như các gia chủ,\nỞ tại các cửa nhà,\nSống vô tư vô lự,\nGiữa con cháu người khác,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n44. Từ bỏ, để một bên,\nMọi biểu dương gia đình,\nNhư loại cây san hô,\nTước bỏ mọi lá cây,\nBậc anh hùng cắt đứt,\nMọi trói buộc gia đình.\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `45. Nếu tìm được bạn lành,\nThận trọng và sáng suốt,\nBạn đồng hành chung sống,\nBạn thiện trú Hiền trí.\nCùng nhau đồng nhiếp phục,\nTất cả mọi hiểm nạn,\nHãy sống với bạn ấy,\nHoan hỷ, giữ chánh niệm.\n\n46. Nếu không được bạn lành,\nThận trọng và sáng suốt,\nBạn đồng hành chung sống,\nBạn thiện trú Hiền trí.\nHãy như vua từ bỏ,\nÐất nước bị bại vong,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n47. Thật chúng ta tán thán,\nCác bằng hữu chu toàn,\nBậc hơn ta, bằng ta,\nNên sống gần thân cận.\nNếu không gặp bạn này.\nNhững bậc không lầm lỗi,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `50. Các dục thật mỹ miều,\nNgọt thơm và đẹp ý,\nDưới hình sắc, phi sắc,\nLàm mê loạn tâm tư,\nThấy sự nguy hiểm này,\nTrong các dục trưởng dưỡng,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n51. Ðây là một mụn nhọt,\nVà cũng là tai họa,\nMột tật bệnh, mũi tên,\nLà sợ hãi cho ta,\nThấy sự nguy hiểm này,\nTrong các dục trưởng dưỡng,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `52. Lạnh lẽo và nóng bức,\nÐói bụng và khát nước,\nGió thổi, ánh mặt trời.\nMuỗi lằn và rắn rết.\nTất cả xúc chạm này,\nÐều chịu đựng vượt qua,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n53. Như con voi to lớn,\nTừ bỏ cả bầy đàn,\nThân thể được sanh ra,\nTo lớn tợ hoa sen,\nTùy theo sự thích thú,\nSống tại chỗ rừng núi,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n54. Ai ưa thích hội chúng,\nSự kiện không xảy ra,\nNgười ấy có thể chứng,\nCảm thọ thời giải thoát.\nCân nhắc lời giảng dạy,\nÐấng bà con mặt trời,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `55. Ðược giải thoát vượt khỏi,\nCác tri kiến hý luận,\nÐạt được quyết định tánh,\nChứng đắc được con đường.\nNơi ta trí được sanh,\nKhông cần nhờ người khác,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n56. Không tham, không lừa đảo,\nKhông khát dục, gièm pha,\nMọi si mê ác trược,\nÐược gạn sạch quạt sạch.\nTrong tất cả thế giới,\nKhông tham ái ước vọng,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `57. Với bạn bè độc ác,\nHãy từ bỏ lánh xa,\nBạn không thấy mục đích,\nQuen nếp sống quanh co,\nChớ tự mình thân cận,\nKẻ đam mê phóng dật,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n58. Bậc nghe nhiều trì pháp,\nHãy gần gũi người ấy,\nBạn người tâm rộng lớn,\nNgười thông minh biện tài,\nBiết điều không nên làm,\nNhiếp phục được nghi hoặc,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `59. Mọi du hí vui đùa,\nVà dục lạc ở đời,\nKhông điểm trang bày biện,\nKhông ước vọng mong cầu,\nTừ bỏ mọi hào nhoáng,\nNói lên lời chân thật,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n60. Với con và với vợ,\nVới cha và với mẹ,\nTài sản cùng lúa gạo,\nNhững trói buộc bà con,\nHãy từ bỏ buộc ràng,\nCác dục vọng như vậy,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n61. Chúng đều là trói buộc,\nLạc thú thật nhỏ bé,\nVị ngọt thật ít oi,\nKhổ đau lại nhiều hơn,\nChúng đều là câu móc,\nBậc trí biết như vậy,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `62. Hãy chặt đứt, bẻ gãy,\nCác kiết sử trói buộc,\nNhư các loài thủy tộc,\nPhá hoại các mạng lưới.\nNhư lửa đã cháy xong,\nKhông còn trở lui lại,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n63. Với mắt cúi nhìn xuống,\nChân đi không lưu luyến,\nCác căn được hộ trì,\nTâm ý khéo chế ngự.\nKhông đầy ứ, rỉ chảy,\nKhông cháy đỏ bừng lên,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n64. Hãy trút bỏ, để lại,\nCác biểu tượng gia chủ,\nNhư loại cây san hô,\nLoại bỏ các nhành lá.\nÐã đắp áo cà sa,\nXuất gia bỏ thế tục,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `65. Không tham đắm các vị,\nKhông tác động, không tham,\nKhông nhờ ai nuôi dưỡng,\nChỉ khất thực từng nhà.\nÐối với mọi gia đình,\nTâm không bị trói buộc,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n66. Từ bỏ năm triền cái\nChe đậy trói buộc tâm,\nÐối với mọi kiết sử,\nHãy trừ khử, dứt sạch,\nKhông y cứ nương tựa,\nChặt đứt ái sân hận,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n67. Hãy xoay lưng trở lại\nÐối với lạc và khổ,\nCả đối với hỷ ưu,\nÐược cảm thọ từ trước,\nHãy chứng cho được xả,\nAn chỉ và thanh tịnh;\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `68. Tinh cần và tinh tấn,\nÐạt được lý chân đế,\nTâm không còn thụ động,\nKhông còn có biếng nhác,\nKiên trì trong cố gắng,\nDõng lực được sanh khởi,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n69. Không từ bỏ độc cư,\nHạnh viễn ly thiền định,\nThường thường sống hành trì,\nTùy pháp trong các pháp.\nChơn chánh nhận thức rõ,\nNguy hiểm trong sanh hữu,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n70. Mong cầu đoạn diệt ái,\nSống hạnh không phóng dật,\nKhông đần độn câm ngọng,\nNghe nhiều, giữ chánh niệm.\nCác pháp được giác sát,\nQuyết định, chánh tinh cần.\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `71. Như sư tử, không động,\nAn tịnh giữa các tiếng,\nNhư gió không vướng mắc,\nKhi thổi qua màn lưới.\nNhư hoa sen không dính,\nKhông bị nước thấm ướt,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n72. Giống như con sư tử,\nVới quai hàm hùng mạnh,\nBậc chúa của loài thú,\nSống chinh phục chế ngự.\nHãy sống các trú xứ,\nNhàn tịnh và xa vắng,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `73. Từ tâm, sống trú xả,\nBi tâm, hạnh giải thoát,\nSống hành trì thực hiện,\nHỷ tâm, cho đúng thời,\nKhông chống đối và chậm,\nVới một ai ở đời.\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n74. Ðoạn tận lòng tham ái,\nSân hận và si mê,\nChặt đứt và cắt đoạn,\nCác kiết sử lớn nhỏ\nKhông có gì sợ hãi,\nKhi mạng sống gần chung,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.\n\n75. Có những bạn vì lợi,\nThân cận và chung sống,\nNhững bạn không mưu lợi,\nNay khó tìm ở đời.\nNgười sáng suốt lợi mình,\nKhông phải người trong sạch,\nHãy sống riêng một mình\nNhư tê ngưu một sừng.`, ref: "Kinh Tập 1.3", url: "https://loicuaducphat.org/snp/snp1.3.html#content" },

{ text: `Bhàradvàja:\n76. Người tự nhận Người cày,\nTa không thấy Người cày,\nHãy trả lời chúng tôi,\nÐã hỏi về Người cày,\nChúng tôi muốn rõ biết,\nNgười cày như thế nào?\n\nThế Tôn:\n77. Lòng tin là hột giống,\nKhổ hạnh là cơn mưa,\nTrí tuệ đối với Ta\nLà ách và lưỡi cày,\nXấu hổ là cán cày,\nÝ là sợi dây buộc,\nVà niệm đối với Ta\nLà lưỡi cày, gậy thúc.\n\n78. Với thân khéo phòng hộ,\nVới lời khéo phòng hộ,\nVới món ăn trong bụng,\nBiết tiết độ, chế ngự,\nTa tác thành chơn thực,\nÐể cắt dọn cỏ rác,\nSự giải thoát của Ta\nThật hiền lành nhu thuận.\n\n79. Với tinh cần tinh tấn,\nTa gánh chịu trách nhiệm,\nTa tự mình đem lại\nAn ổn khỏi khổ ách.\nNhư vậy, Ta đi tới,\nKhông trở ngại thối lui,\nChỗ nào Ta đi tới,\nChỗ ấy không sầu muộn.\n\n80. Cày bừa là như vậy,\nÐược quả là bất tử,\nSau cày bừa như vậy,\nMọi khổ được giải thoát.`, ref: "Kinh Tập 1.4", url: "https://loicuaducphat.org/snp/snp1.4.html#content" },

{ text: `85. Người thợ rèn Cunda,\nLiền bạch với Thế Tôn:\nChư Phật nói thế nào,\nBậc chiến thắng con đường,\nBậc thiền định con đường,\nSao gọi không ước lường?\nCon hỏi xin trả lời,\nVị sống đúng con đường?\nXin trình bày cho con,\nKẻ làm đường ô uế.\n\nThế Tôn:\n86. Ai vượt khỏi nghi hoặc,\nVị thoát khỏi mũi tên,\nƯa thích cảnh Niết-bàn,\nKhông tham đắm vật gì,\nBậc lãnh đạo thế giới,\nChư Thiên và loài Người,\nChư Phật gọi vị ấy,\nBậc chiến thắng con đường.\n\n87. Ai ở đời biết được,\nPháp tối thượng, tối thượng,\nNói lên và phân tích,\nPháp ở đây là vậy.\nVị chặt đứt nghi hoặc,\nBậc ẩn sĩ, không dục,\nBậc Tỷ-kheo thứ hai\nÐược gọi thuyết con đường.\n\n88. Ai sống trên con đường,\nCon đường pháp khéo giảng,\nSống chế ngự chánh niệm,\nBước đường không lỗi lầm,\nTỷ-kheo thứ ba này\nÐược gọi sống trên đường.\n\n89. Ai sống ưa che đậy,\nDưới hình thức giới cấm,\nXông xáo, nhớp gia đình,\nBạt mạng và man trá,\nKhông chế ngự nhiếp phục,\nSống lắm mồm lắm miệng.\nNgười sở hành như vậy\nLà kẻ ô uế đạo.`, ref: "Kinh Tập 1.5", url: "https://loicuaducphat.org/snp/snp1.5.html#content" },

{ text: `91. Về bại vong con người,\nCon hỏi Gotama,\nCon đến hỏi Thế Tôn,\nCửa vào của bại vong?\n\n92. Thật dễ hiểu thành công,\nThật dễ hiểu bại vong,\nƯa mến pháp, thành công,\nThù ghét pháp bại vong.\n\n94. Ai mến kẻ bất thiện,\nKhông ái luyến bậc thiện,\nThích pháp kẻ bất thiện,\nChính cửa vào bại vong.\n\n96. Người tánh ưa thích ngủ,\nThích hội chúng, thụ động,\nBiếng nhác, thường phẫn nộ,\nChính cửa vào bại vong.`, ref: "Kinh Tập 1.6", url: "https://loicuaducphat.org/snp/snp1.6.html#content" },

{ text: `98. Ai với mẹ hay cha,\nGià yếu, tuổi trẻ hết,\nTuy giàu không giúp đỡ,\nChính cửa vào bại vong.\n\n100. Ai nói dối lường gạt,\nSa-môn, Bà-la-môn,\nHay các khất sĩ khác,\nChính cửa vào bại vong.\n\n102. Người giàu có tài sản,\nCó vàng bạc thực vật,\nHương vị ngọt một mình,\nChính cửa vào bại vong.\n\n104. Người tự hào về sanh,\nVề tài sản dòng họ,\nKhinh miệt các bà con,\nChính cửa vào bại vong.`, ref: "Kinh Tập 1.6", url: "https://loicuaducphat.org/snp/snp1.6.html#content" },

{ text: `106. Người đắm say nữ nhân,\nÐắm say rượu, cờ bạc,\nHoang phí mọi lợi đắc,\nChính cửa vào bại vong.\n\n112. Ðàn bà, hay đàn ông,\nRượu chè, tiêu hoang phí,\nÐược địa vị quyền thế,\nChính cửa vào bại vong.`, ref: "Kinh Tập 1.6", url: "https://loicuaducphat.org/snp/snp1.6.html#content" },

{ text: `145. Mong mọi loài chúng sanh,\nÐược an lạc, an ổn,\nMong họ chứng đạt được,\nHạnh phúc và an lạc.\n\n146. Mong tất cả những ai,\nHữu tình có mạng sống,\nKẻ yếu hay kẻ mạnh,\nKhông bỏ sót một ai,\nKẻ dài hay kẻ lớn,\nTrung, thấp, loài lớn, nhỏ.\n\n147. Loài được thấy, không thấy,\nLoài sống xa, không xa,\nCác loài hiện đang sống,\nCác loài sẽ được sanh,\nMong mọi loài chúng sanh\nSống hạnh phúc an lạc.\n\n148. Mong rằng không có ai,\nLường gạt lừa dối ai,\nKhông có ai khinh mạn,\nTại bất cứ chỗ nào.\nKhông vì giận hờn nhau,\nKhông vì tưởng chống đối.\nLại có người mong muốn,\nLàm đau khổ cho nhau.`, ref: "Kinh Tập 1.8", url: "https://loicuaducphat.org/snp/snp1.8.html#content" },

{ text: `149. Như tấm lòng người mẹ,\nÐối với con của mình,\nTrọn đời lo che chở,\nCon độc nhất mình sanh.\nCũng vậy, đối tất cả\nCác hữu tình chúng sanh,\nHãy tu tập tâm ý,\nKhông hạn lượng rộng lớn.\n\n150. Hãy tu tập từ tâm,\nTrong tất cả thế giới,\nHãy tu tập tâm ý,\nKhông hạn lượng rộng lớn.\nPhía trên và phía dưới,\nCũng vậy, cả bề ngang,\nKhông hạn chế, trói buộc,\nKhông hận, không thù địch.\n\n151. Khi đứng, hay khi đi,\nKhi ngồi, hay khi nằm,\nLâu cho đến khi nào,\nKhi đang còn tỉnh thức,\nHãy an trú niệm này,\nNếp sống này như vậy,\nÐược đời đề cập đến,\nLà nếp sống tối thượng.`, ref: "Kinh Tập 1.8", url: "https://loicuaducphat.org/snp/snp1.8.html#content" },

{ text: `152. Ai từ bỏ tà kiến,\nGiữ giới, đủ chánh kiến,\nNhiếp phục được tham ái,\nÐối với các dục vọng,\nKhông còn phải tái sanh,\nÐi đến thai tạng nữa.`, ref: "Kinh Tập 1.8", url: "https://loicuaducphat.org/snp/snp1.8.html#content" },

{ text: `Hemàvata:\n154. Có phải ý vị ấy,\nTâm nguyện thật khéo phát?\nCó phải đối sanh loại,\nCó tâm tư như vậy?\nCó phải các tư duy,\nÐược khéo léo điều phục\nÐối với các pháp khả ái,\nVà pháp không khả ái?\n\nSàtàgira:\n155. Ý vị ấy là vậy,\nTâm nguyện thật khéo phát,\nÐối với mọi sanh loại,\nCó tâm tư như vậy,\nNhư vậy là tư duy,\nÐược khéo léo điều phục.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `Hemàvata:\n156. Có phải là vị ấy\nKhông lấy vật không cho?\nCó phải với hữu tình,\nVị ấy khéo chế ngự?\nCó phải với phóng dật,\nVị ấy khéo viễn ly?\nCó phải đối thiền định,\nVị ấy không từ bỏ?\n\nSàtàgira:\n157. Vị ấy không có lấy\nNhững vật không được cho,\nVị ấy với hữu tình,\nRất khéo léo chế ngự,\nVị ấy với phóng dật,\nThật sự sống viễn ly,\nÐức Phật đối thiền định,\nKhông từ bỏ, sao lãng.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `Hemàvata:\n160. Có phải đối các dục,\nVị ấy không tham ái?\nCó phải tâm vị ấy\nKhông có bị dao động?\nCó phải tâm vị ấy\nVượt khỏi sự si ám?\nCó phải thật vị ấy,\nCó mắt đối các pháp?\n\nSàtàgira:\n161. Vị ấy không tham ái\nÐối với các dục vọng,\nTâm không có dao động,\nVượt khỏi mọi si ám,\nÐức Phật thật có mắt\nÐối với tất cả pháp.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `Hemàvata:\n162. Có phải là vị ấy\nÐầy đủ về các minh?\nCó phải là vị ấy\nSở hành thật thanh tịnh?\nCó phải là vị ấy\nCác lậu hoặc đoạn tận?\nCó phải là vị ấy\nKhông còn có tái sanh?\n\nSàtàgira:\n163. Sự thật là vị ấy,\nÐầy đủ với các minh,\nSở hành thật thanh tịnh,\nMọi lậu hoặc đoạn tận,\nThật sự đối vị ấy,\nKhông còn có tái sanh.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `Sàtàgira:\n164. Thật sự vị ẩn sĩ,\nVới tâm được viên mãn,\nMọi việc làm vị ấy\nÐược làm khéo hoàn mãn.\nChúng ta hãy yết kiến\nTôn giả Gotama,\nVị đầy đủ trí đức,\nÐầy đủ cả hạnh đức.\n\nHemàvata:\n165. Bắp chân giống như nai,\nThon vững chắc, bền bỉ,\nGiản dị ít nhu cầu,\nKhông tham đắm vật gì.\nHãy đi đến yết kiến\nẨn sĩ Gotama,\nVị hành trì thiền định,\nTrong rừng núi xa vắng.\n\n166. Sống cô độc một mình,\nNhư sư tử, như voi,\nNgài không có tham đắm,\nKhông cầu mong các dục.\nChúng ta hãy đi đến,\nVà hỏi thăm vị ấy\nVề con đường giải thoát\nKhỏi cạm bẫy Ác ma.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `Hemàvata:\n168. Do pháp nào có mặt,\nThế giới được sanh khởi,\nNói vậy là dạ-xoa,\nTên Hemavata.\nDo pháp nào có mặt,\nTác thành sự giao hợp?\nSự chấp thủ ở đời,\nLà chấp thủ cái gì?\nDo pháp nào có mặt,\nThế giới bị tàn hại?\n\nThế Tôn:\n169. Do sáu pháp có mặt,\nThế giới được sanh khởi,\nDo sáu pháp có mặt,\nTác thành sự giao hợp,\nSự chấp thủ ở đời,\nLà chấp thủ sáu pháp,\nDo sáu pháp có mặt,\nThế giới bị tàn hại.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `Hemàvata:\n170. Do chấp thủ cái gì,\nÐây thế giới bị hại?\nÐược hỏi, hãy nói lên,\nVề con đường thoát đời.\nLàm thế nào đau khổ,\nÐược giải thoát hoàn toàn?\n\nThế Tôn:\n171. Ðây, năm dục trưởng dưỡng,\nÝ được gọi thứ sáu,\nBỏ ước muốn ở đây,\nNhư vậy, thoát đau khổ.\n\n172. Ðây, con đường thoát đời.\nNhư thật nói Ông rõ,\nÐường này Ta nói Ông,\nNhư vậy, thoát đau khổ.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `Hemàvata:\n173. Ðây, ai vượt bộc lưu?\nÐây, ai vượt biển lớn?\nKhông chân đứng bám víu,\nAi không chìm vực sâu?\n\nThế Tôn:\n174. Ai luôn luôn đủ giới,\nCó tuệ, khéo thiền định,\nTâm hướng nội, chánh niệm,\nVượt bộc lưu khó vượt.\n\n175. Ai từ bỏ dục tưởng,\nVượt khỏi mọi kiết sử,\nAi, hỷ, hữu đoạn tận,\nKhông chìm vào vực sâu.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `Hemàvata:\n176. Vị trí tuệ thâm sâu,\nThấy được đích tế nhị,\nVị không có sở hữu,\nKhông tham đắm dục hữu.\nHãy yết kiến vị ấy,\nVị luôn luôn giải thoát,\nBậc đại sĩ tiến bước,\nTrên con đường Thiên đạo.\n\n177. Bậc danh xưng vô thượng,\nBậc thấy đích tế nhị,\nBậc ban bố trí tuệ,\nKhông tham đắm dục tạng.\nHãy yết kiến vị ấy,\nVị Toàn trí, Thiện tuệ,\nBậc Ðại sĩ tiến bước\nTrên con đường Thánh đạo.\n\n178. Hôm nay thật chúng con\nÐược thấy điềm tốt lành,\nÐược hào quang chói sáng,\nCủa bình minh tốt lành.\nVì chúng con được thấy,\nBậc Chánh Ðẳng Chánh Giác,\nBậc đã vượt bộc lưu,\nBậc đã đoạn lậu hoặc.\n\n180. Chúng con sẽ bộ hành\nLàng này qua làng khác,\nThành này qua thành khác,\nÐảnh lễ bậc Chánh giác,\nÐảnh lễ thiện pháp tánh,\nCủa Chánh pháp vi diệu.`, ref: "Kinh Tập 1.9", url: "https://loicuaducphat.org/snp/snp1.9.html#content" },

{ text: `181. Ở đời, tài sản gì,\nTối thắng cho con người?\nCái gì khéo thực hành\nÐem lại chơn an lạc.\nCái gì trong các vị,\nLà vị ngọt tối thượng?\nNếp sống như thế nào,\nGọi nếp sống tối thắng?\n\n182. Ở đời này, lòng tin,\nTối thắng cho con người,\nChánh pháp khéo thực hiện,\nÐem lại chơn an lạc,\nSự thật trong các vị,\nLà vị ngọt tối thượng,\nNếp sống với trí tuệ,\nLà nếp sống tối thắng.\n\n183. Thế nào vượt bộc lưu?\nThế nào vượt biển lớn?\nThế nào vượt qua khổ?\nThế nào thật thanh tịnh?\n\n184. Với tín, vượt bộc lưu,\nKhông phóng dật, vượt biển,\nTinh tấn, vượt đau khổ,\nVới tuệ, được thanh tịnh.`, ref: "Kinh Tập 1.10", url: "https://loicuaducphat.org/snp/snp1.10.html#content" },

{ text: `185. Thế nào được trí tuệ?\nThế nào được tài sản?\nThế nào đạt danh xưng?\nThế nào cột bạn hữu?\nÐời này qua đời sau,\nThế nào, chết không sầu?\n\n186. Tin tưởng bậc La-hán,\nTin pháp, đạt Niết-bàn,\nKhéo nghe, được trí tuệ,\nBậc trí, không phóng dật.\n\n187. Làm thích đáng trách nhiệm,\nPhấn đấu được tài sản,\nVới sự thật được danh,\nBố thí cột bạn bè.\n\n188. Ai là người gia chủ,\nTin tưởng bốn pháp này,\nSự thật và Chánh pháp,\nKiên trì và bố thí,\nVị ấy sau khi chết,\nNhất định không sầu muộn.\n\n189. Hãy hỏi các vị khác,\nSa-môn, Bà-la-môn,\nNếu có pháp nào khác\nỞ đời, lại thắng hơn,\nSự thật và nhiếp phục,\nBố thí và kham nhẫn?`, ref: "Kinh Tập 1.10", url: "https://loicuaducphat.org/snp/snp1.10.html#content" },

{ text: `194. Ràng buộc với xương gân,\nTrét thoa với da thịt,\nThân được da che đậy,\nNhư thật không thấy rõ.\n\n195. Trong một bụng chứa đầy,\nCục gan, và bọng đái,\nQuả tim và buồng phổi,\nCả thận, và tỳ tạng.\n\n196. Nước mũi, và nước miếng,\nMồ hôi, và nước mỡ,\nMáu, và nước khớp xương,\nMật, và bạch huyết cầu.\n\n197. Từ chín nguồn nước này,\nBất tịnh luôn luôn chảy,\nTừ mắt, đồ bẩn chảy,\nTừ tai, đồ bẩn chảy.`, ref: "Kinh Tập 1.11", url: "https://loicuaducphat.org/snp/snp1.11.html#content" },

{ text: `198. Nước mũi từ lỗ mũi,\nTừ miệng, có khi chảy,\nChảy mật, và niêm dịch,\nTừ thân, mồ hôi bẩn.\n\n199. Trong đầu thật trống rỗng,\nChứa đầy những óc, não.\nBị vô minh dắt dẫn,\nKẻ ngu nghĩ tịnh sạch.\n\n200. Khi bị chết nằm xuống,\nPhồng lên, và xanh bầm,\nQuăng bỏ trong nghĩa địa,\nBà con không đoái hoài.\n\n201. Chó, dã can đến ăn,\nChó sói, các côn trùng,\nQuạ, diều hâu đến ăn,\nCòn có hữu tình khác.`, ref: "Kinh Tập 1.11", url: "https://loicuaducphat.org/snp/snp1.11.html#content" },

{ text: `202. Ðược nghe lời Phật dạy,\nTỷ-kheo có trí tuệ,\nVị ấy liễu tri thân,\nThấy thân đúng như thật.\n\n203. Ðây thế nào, kia vậy,\nKia thế nào, đây vậy,\nÐối với thân trong ngoài,\nTừ bỏ mọi lòng dục.\n\n204. Từ bỏ lòng tham dục,\nÐây Tỷ-kheo có tuệ,\nChứng bất tử, tịch tịnh,\nNiết-bàn giới thường trú.\n\n205. Thân này với hai chân,\nBất tịnh và hôi thúi,\nÐầy xác chết, chảy nước,\nLại được giữ, nâng niu.\n\n206. Với thân thể như vậy,\nAi lại nghĩ đề cao,\nHay khinh miệt kẻ khác,\nTrừ kẻ không thấy gì.`, ref: "Kinh Tập 1.11", url: "https://loicuaducphat.org/snp/snp1.11.html#content" },
{ text: `207. Thân mật, sanh sợ hãi,\nTrú xứ, sanh bụi bặm,\nKhông trú xứ, không thân,\nHình ảnh bậc ẩn sĩ.\n\n208. Ai đã chặt sanh hữu,\nKhông còn gieo giống thêm,\nSanh hữu đã đoạn tận,\nKhông muốn nó tùy sanh,\nÐược gọi là ẩn sĩ,\nMột mình đi im lặng,\nBậc đại sĩ đã thấy,\nCon đường tịch tịnh ấy.\n\n209. Sau khi ước lượng đất,\nTìm hiểu được hột giống,\nKhông còn muốn tham ái,\nÐược tiếp tục tùy sanh,\nVị ấy chân ẩn sĩ,\nThấy sanh diệt chấm dứt,\nÐoạn tận mọi lý luận,\nKhông rơi vào tính toán.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `210. Ðã rõ mọi trú xứ,\nKhông ham trú xứ nào,\nVị ấy chân ẩn sĩ,\nKhông tham, không say đắm.\nKhông còn phải ra sức,\nÐã đạt bờ bên kia.\n\n211. Bậc chiến thắng toàn diện,\nBậc toàn tri, thiện tuệ,\nÐối với tất cả pháp,\nKhông còn bị ô nhiễm.\nBậc từ bỏ tất cả,\nÁi đoạn diệt, giải thoát.\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n212. Vị có trí tuệ lực,\nGiới cấm được đầy đủ,\nÐịnh tĩnh, thích thiền định,\nGìn giữ trì chánh niệm,\nGiải thoát các trói buộc,\nKhông hoang vu, lậu tận,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `213. Bộ hành, riêng một mình,\nẨn sĩ, không phóng dật,\nTrước chê bai, tán thán,\nKhông có bị dao động.\nNhư sư tử, không sợ,\nGiữa các tiếng vang động.\nNhư gió không vướng lưới,\nNhư son không dính nước,\nBậc lãnh đạo mọi người,\nNgười không ai lãnh đạo.\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n214. Vị nào biết xử sự,\nNhư cột trụ hồ tắm,\nKhi người khác nói lời,\nLời khen chê cực đoạn,\nVị không có tham ái,\nVới căn khéo định tĩnh,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `215. Ai thật tự mình đứng\nThẳng như cây thoi đưa,\nNhàm chán các nghiệp ác,\nQuán sát chánh, bất chánh,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n216. Ai biết tự chế ngự,\nKhông làm các điều ác,\nTrẻ và hạng trung niên,\nBậc ẩn sĩ chế ngự,\nVị không nên chọc giận,\nVì không làm ai giận,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n217. Ai sống nhờ người cho,\nNhận lãnh đồ khất thực,\nNhận từ trên, từ giữa,\nHay từ chỗ còn lại,\nKhông đủ để tán thán,\nKhông nói lời hạ mình,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `218. Sống thụ hạnh ẩn sĩ,\nTừ bỏ sự dâm dục,\nAi lúc còn tuổi trẻ,\nKhông bị trói buộc gì,\nTừ bỏ mạn, phóng dật,\nÐược hoàn toàn giải thoát,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n219. Rõ biết được thế giới,\nThấy được lý chân đế,\nVượt khỏi được bộc lưu,\nVượt biển lớn như vậy.\nVị chặt đứt trói buộc,\nKhông ỷ lại, vô lậu.\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `220. Hai nếp sống không giống.\nAn trú, thật xa nhau,\nGia chủ, có vợ con,\nKhông ngã sở, khéo nhiếp,\nGia chủ không chế ngự,\nNgăn chận hữu tình khác,\nBậc ẩn sĩ luôn luôn,\nChe chở loài hữu tình.\n\n221. Giống như loại chim công,\nLoại chim có cổ xanh,\nKhông bao giờ sánh bằng\nChim thiên nga nhanh nhẹn.\nCũng vậy, người gia chủ,\nKhông sánh bằng Tỷ-kheo,\nBậc ẩn sĩ viễn ly,\nSống thiền định trong rừng.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `242. Sát sanh và hành hình,\nÐả thương và bắt trói,\nTrộm cắp và nói láo,\nMan trá và lừa đảo,\nGiả bộ kẻ học thức,\nÐi lại với vợ người,\nÐây là đồ ăn thối,\nĂn thịt không phải thối.\n\n243. Ở đời, các hạng người,\nKhông chế ngự lòng dục,\nÐam mê các vị ngon,\nLiên hệ đến bất tịnh,\nTheo chủ nghĩa hư vô,\nBất chánh khó hướng dẫn,\nÐây là ăn đồ thối,\nĂn thịt không phải thối.`, ref: "Kinh Tập 2.2", url: "https://loicuaducphat.org/snp/snp2.2.html#content" },

{ text: `244. Ai thô bạo, dã man,\nSau lưng nói gièm pha,\nPhản bạn không từ bi,\nLại cống cao ngạo mạn,\nTánh không có bố thí,\nKhông cho ai vật gì,\nÐây là ăn đồ thối,\nĂn thịt không phải thối,\n\n245. Phẫn nộ và kiêu mạn,\nCứng đầu và chống đối\nMan trá và tật đố,\nNói vô ích, huênh hoang,\nKiêu mạn và quá mạn,\nThân mật với kẻ ác,\nÐây là ăn đồ thối,\nĂn thịt không phải thối,\n\n247. Ở đời đối hữu tình,\nNgười không biết kiềm chế,\nLấy cướp sở hữu người,\nChú tâm làm hại người,\nÁc giới và tàn nhẫn\nÁc ngữ, thiếu lễ độ,\nÐây là ăn đồ thối,\nĂn thịt không phải thối,`, ref: "Kinh Tập 2.2", url: "https://loicuaducphat.org/snp/snp2.2.html#content" },

{ text: `249. Không phải do cá thịt,\nCùng các loại nhịn ăn,\nKhông phải do lõa thể,\nÐầu trọc và bện tóc,\nKhông do tro trét mình,\nMặc da thú khô cứng,\nKhông phải do săn sóc,\nNuôi dưỡng lửa tế tự,\nKhông do nhiều khổ hạnh,\nÐể được chứng bất tử,\nKhông bùa chú tế tự,\nCác tế đàn thời tiết,\nLàm con người trong sạch,\nNếu nghi hoặc chưa đoạn.\n\n250. Do sống hộ trì căn,\nVới các căn nhiếp phục,\nVững trú trên Chánh pháp,\nThích chân trực, hiền hòa,\nVượt khỏi các tham ái,\nÐoạn tận mọi khổ đâu,\nBậc trí không nhiễm dính,\nÐiều được thấy, được nghe.`, ref: "Kinh Tập 2.2", url: "https://loicuaducphat.org/snp/snp2.2.html#content" },

{ text: `253. Ai mở miệng tuyên bố:\nTôi là bạn của anh,\nSở hành vượt xấu hổ,\nLại khinh chán bạn mình,\nKhông chịu khó gắng làm,\nCông việc có thể làm.\nCần biết người như vậy,\nKhông phải bạn của tôi.\n\n254. Ai đối với bạn hữu,\nChỉ làm với lời nói,\nLời nói đẹp, khả ái,\nNhưng chỉ lời nói suông,\nBậc trí biết người ấy,\nNgười chỉ nói, không làm.\n\n255. Người luôn luôn chú ý,\nNghi ngờ sự thiếu sót,\nTìm kiếm các nhược điểm,\nNgười ấy không phải bạn,\nVới ai có thể nắm,\nNhư con nằm trên ngực,\nNgười ấy mới thật bạn,\nKhông bị ai chia ly.\n\n256. Ai mong lợi ích quả,\nTu tập các sự kiện,\nÐem lại sự hân hoan,\nTu tập sự an lạc,\nÐem lại thưởng, tán thán,\nGánh trách nhiệm làm người.\n\n257. Uống xong vị viễn ly,\nUống xong vị an tịnh,\nKhông sợ hãi, không ác,\nHưởng vị ngọt, pháp hỷ.`, ref: "Kinh Tập 2.3", url: "https://loicuaducphat.org/snp/snp2.3.html#content" },

{ text: `259. Không thân cận kẻ ngu,\nNhưng gần gũi bậc trí,\nÐảnh lễ người đáng lễ\nLà điềm lành tối thượng.\n\n260. Ở trú xứ thích hợp,\nCông đức trước đã làm,\nChân chánh hướng tụ tâm,\nLà điều lành tối thượng.\n\n261. Học nhiều, nghề nghiệp giỏi,\nKhéo huấn luyện học tập,\nNói những lời khéo nói\nLà điềm lành tối thượng.\n\n262. Hiếu dưỡng mẹ và cha,\nNuôi dưỡng vợ và con,\nLàm nghề không rắc rối\nLà điềm lành tối thượng.`, ref: "Kinh Tập 2.4", url: "https://loicuaducphat.org/snp/snp2.4.html#content" },

{ text: `263. Bố thí, hành đúng pháp,\nSăn sóc các bà con,\nLàm nghiệp không lỗi lầm\nLà điềm lành tối thượng.\n\n264. Chấm dứt, từ bỏ ác,\nChế ngự đam mê rượu,\nTrong pháp, không phóng dật\nLà điềm lành tối thượng.\n\n265. Kính lễ và hạ mình,\nBiết đủ và biết ơn,\nÐúng thời, nghe Chánh pháp\nLà điềm lành tối thượng.\n\n266. Nhẫn nhục, lời hòa nhã,\nYết kiến các Sa-môn,\nÐúng thời, đàm luận pháp,\nLà điềm lành tối thượng.`, ref: "Kinh Tập 2.4", url: "https://loicuaducphat.org/snp/snp2.4.html#content" },

{ text: `267. Khắc khổ và Phạm hạnh,\nThấy được lý Thánh đế,\nGiác ngộ quả Niết bàn\nLà điềm lành tối thượng.\n\n268. Khi xúc chạm việc đời,\nTâm không động, không sầu,\nKhông uế nhiễm, an ổn\nLà điềm lành tối thượng.\n\n269. Làm sự việc như vậy,\nKhông chỗ nào thất bại,\nKhắp nơi được an toàn,\nLà điềm lành tối thượng.`, ref: "Kinh Tập 2.4", url: "https://loicuaducphat.org/snp/snp2.4.html#content" },

{ text: `Thế Tôn:\n\n271. Từ những nguyên nhân này,\nTham, sân được khởi lên,\nKhông ưa thích, ưa thích,\nSợ hãi từ đây sanh,\nTừ đây được sanh khởi,\nCác suy tầm của ý,\nNhư đứa trẻ độc ác,\nThả cho con quạ bay.\n\n272. Sự hiện hữu của ngã,\nChính do thân ái sanh,\nNhư các loại cây bàng,\nDo thân cây bàng sanh.\nSự triền phược các dục,\nThật rộng lớn vô cùng,\nNhư cây Màluvà,\nTỏa rộng lan khắp rừng.\n\n273. Hãy nghe! Này Dạ-xoa,\nNhững ai được rõ biết\nTừ đâu, khiến sanh khởi,\nHọ tẩy sạch nhân ấy.\nHọ vượt qua dòng nước,\nChảy mạnh khó vượt này,\nTrước chưa được vượt qua,\nKhông còn có tái sanh.`, ref: "Kinh Tập 2.5", url: "https://loicuaducphat.org/snp/snp2.5.html#content" },

{ text: `274. Pháp hạnh và Phạm hạnh,\nÐược gọi là tối thượng hạnh,\nNếu là người xuất gia,\nBỏ nhà, sống không nhà.\n\n275. Nếu bản tánh lắm mồm,\nƯa làm hại như thú,\nÐời sống ấy ác độc,\nLàm ngã tăng bụi trần.\n\n276. Tỷ-kheo ưa cãi nhau,\nBị vô minh che đậy,\nKhông biết pháp luật dạy,\nPháp do Phật tuyên thuyết.\n\n277. Bị vô minh lãnh đạo,\nHại bậc tu tập ngã,\nKhông biết đường ô nhiễm,\nÐưa đến cõi địa ngục.\n\n278. Vị Tỷ-kheo như vậy,\nRơi vào chỗ đọa xứ,\nÐi đầu thai chỗ này,\nÐến đầu thai chỗ khác,\nÐi từ tối tăm này,\nÐến chỗ tối tăm khác.\nVị ấy sau khi chết,\nRơi vào chỗ khổ đau.`, ref: "Kinh Tập 2.6", url: "https://loicuaducphat.org/snp/snp2.6.html#content" },

{ text: `279. Như hố phân đầy tràn,\nSau nhiều năm chất chứa,\nCũng vậy, kẻ uế nhiễm,\nThật khó lòng gột sạch.\n\n280. Hỡi này các Tỷ-kheo,\nHãy biết người như vậy,\nHệ lụy với gia đình,\nÁc dục, ác tư duy,\nÁc uy nghi cử chi,\nÁc sở hành, hành xứ.\n\n281. Tất cả đều đồng tình,\nTránh xa ngưòi như vậy,\nHãy thổi nó như bụi,\nHãy quăng nó như rác.\n\n282. Hãy đuổi kẻ nói nhiều,\nKẻ Sa-môn giả hiệu,\nSau khi đuổi ác dục,\nÁc uy nghi hành xứ.\n\n283. Hãy giữ mình trong sạch,\nChung sống kẻ trong sạch,\nSống thích đáng, chánh niệm,\nRồi hòa hợp, sáng suốt,\nHãy chấm dứt khổ đau.`, ref: "Kinh Tập 2.6", url: "https://loicuaducphat.org/snp/snp2.6.html#content" },

{ text: `284. Các ẩn sĩ thời xưa,\nChế ngự, sống khắc khổ,\nBỏ năm dục trưởng dưỡng,\nHành lý tưởng tự ngã.\n\n285. Phạm chí, không gia súc,\nKhông vàng bạc lúa gạo,\nHọc hỏi là tài sản,\nHọ che chở hộ trì,\nKho tàng tối thượng ấy.\n\n288. Không bị ai xâm phạm\nLà Phạm chí thời ấy,\nKhông bị ai chiến hại,\nHọ được pháp che chở,\nKhông ai ngăn chặn họ,\nTại ngưỡng cửa gia đình.\n\n289. Từ trẻ đến bốn tám,\nCác Phạm chí thời xưa,\nHọ sống hành Phạm hạnh,\nTầm cầu minh và hạnh.`, ref: "Kinh Tập 2.7", url: "https://loicuaducphat.org/snp/snp2.7.html#content" },

{ text: `292. Họ tán thán Phạm hạnh,\nGiới, học thức, nhu hòa,\nKhắc khổ và hòa nhã,\nBất hại và nhẫn nhục.\n\n293. Vị tối thắng trong họ,\nLà Phạm thiên, nỗ lực,\nVị ấy không giao hợp,\nCho đến trong cơn mộng.\n\n294. Ở đời, bậc có trí,\nHọc theo hạnh vị ấy,\nHọ tán thán Phạm hạnh,\nGiới đức và nhẫn nhục.`, ref: "Kinh Tập 2.7", url: "https://loicuaducphat.org/snp/snp2.7.html#content" },

{ text: `316. Từ vị nào một người,\nRõ biết được Chánh pháp,\nHãy đảnh lễ vị ấy,\nNhư chư Thiên, Inda,\nVị ấy được đảnh lễ,\nTâm tư sanh hoan hỷ,\nNghe nhiều, học hỏi nhiều,\nThuyết trình chơn diệu pháp.\n\n317. Vị sáng suốt chú tâm,\nSuy tư và quán sát\nThực hành pháp tuỳ pháp,\nTrở thành vị hiểu biết,\nThông minh và thận trọng,\nKhông phóng dật, vị ấy,\nTheo gương vị như vậy.`, ref: "Kinh Tập 2.8", url: "https://loicuaducphat.org/snp/snp2.8.html#content" },

{ text: `319. Như người nhảy xuống sông,\nDòng sông nước ngập tràn,\nNước sông, nhớp đục ngầu,\nDòng nước chảy nhanh mạnh\nNgười ấy bị lôi cuốn,\nTheo dòng nước trôi đi,\nLàm sao nó có thể,\nGiúp người khác vượt dòng.\n\n320. Cũng vậy, với người nào,\nPháp không được tu tập,\nKhông quán sát ý nghĩa,\nCủa những vị nghe nhiều,\nTự mình không rõ biết,\nNghi hoặc chưa vượt qua,\nLàm sao nó có thể,\nGiúp người khác thiền định.`, ref: "Kinh Tập 2.8", url: "https://loicuaducphat.org/snp/snp2.8.html#content" },

{ text: `321. Như người được leo lên,\nChiếc thuyền mạnh vững chắc,\nÐược trang bị đầy đủ,\nMái chèo và tay lái;\nNgười như vậy ở đây,\nGiúp nhiều người ngược dòng,\nRõ biết những phương tiện,\nThiện xảo và sáng suốt.\n\n322. Như vậy, bậc sáng suốt,\nLuôn luôn tự tu tập,\nBậc nghe nhiều hiểu nhiều,\nKhông còn bị dao động,\nVị ấy giúp đỡ được,\nCác người khác tu thiền,\nLàm khởi lên nguyên nhân,\nTha thiết muốn nghe pháp.\n\n323. Do vậy, hãy thân cận,\nBậc chân nhân hiền sĩ,\nBậc sáng suốt, có trí,\nBậc nghe nhiều học nhiều.\nSau khi biết mục đích,\nCố gắng khéo hành trì,\nRõ biết được Chánh pháp,\nVị ấy được an lạc.`, ref: "Kinh Tập 2.8", url: "https://loicuaducphat.org/snp/snp2.8.html#content" },
{ text: `324. Thế nào là giới đức?\nThế nào là chánh hạnh?\nCần phải làm tăng trưởng.\nThân khẩu ý nghiệp nào?\nÐể người chánh nhập cuộc,\nÐạt được đích tối thượng?\n\n325. Kính lễ bậc trưởng thượng,\nKhông ganh tị một ai,\nCần phải biết thời gian,\nÐể yết kiến Ðạo sư,\nBiết được đúng thời khắc,\nThuyết pháp bắt đầu giảng,\nHãy cẩn thận lắng nghe,\nLời giảng được khéo nói.\n\n326. Hãy đi đến đúng thời,\nTrước mặt vị Ðạo Sư,\nTừ bỏ tánh cứng đầu,\nVới thái độ khiêm tốn,\nHãy nhớ nghĩ ức niệm,\nHãy chơn chánh hành trì,\nMục đích và Chánh pháp,\nChế ngự và Phạm hạnh`, ref: "Kinh Tập 2.9", url: "https://loicuaducphat.org/snp/snp2.9.html#content" },

{ text: `327. Vui thích trong Chánh Pháp\nHoan hỷ trong Chánh Pháp,\nAn trú trên Chánh pháp,\nBiết phân tích Chánh pháp,\nSở hành không làm gì,\nCó lời uế nhiễm pháp,\nChịu hướng dẫn lãnh đạo,\nLời trung thực khéo nói.\n\n330. An vui thích Chánh pháp,\nDo bậc Thánh tuyên thuyết,\nHọ trở thành vô thượng,\nVề lời ý và nghiệp,\nHọ an tịnh nhu hòa,\nAn trú trên thiền định,\nChứng đạt được cốt lõi,\nPháp được nghe, trí tuệ.`, ref: "Kinh Tập 2.9", url: "https://loicuaducphat.org/snp/snp2.9.html#content" },

{ text: `328. Bỏ cười đùa, lắm miệng,\nKhóc than và sân hận,\nLàm những điều man trá,\nLừa đảo, tham, kiêu mạn,\nBồng bột và bạo ngôn,\nCứng rắn và đam mê,\nSống từ bỏ tất cả,\nLy say đắm, kiên trì.\n\n329. Thức tri được cốt lõi,\nNhững lời đươc khéo nói,\nÐươc nghe khéo thức tri,\nCốt lõi của thiền định,\nVới con người hấp tấp,\nLại phóng dật buông lung,\nTrí tuệ, đều được nghe,\nKhông có thể tăng trưởng.`, ref: "Kinh Tập 2.9", url: "https://loicuaducphat.org/snp/snp2.9.html#content" },

{ text: `331. Hãy đứng dậy, ngồi dậy,\nVới người mộng ích gì?\nKẻ bệnh ngủ làm gì?\nKhi mũi tên phiền lụy.\n\n332. Hãy đứng dậy, ngồi dậy,\nHãy kiên trì học tập,\nÐạt cho được an tịnh,\nÐừng để cho thần chết,\nBiết Ông là phóng dật,\nMê hoặc, chinh phục Ông.\n\n333. Chư Thiên và loài Người,\nSống y chỉ tầm cầu,\nHãy vượt ái dục này,\nChớ để thời khắc qua,\nKhi thời khắc đã qua,\nBị sầu khổ địa ngụ.\n\n334. Phóng dật là bụi nhơ,\nBụi do phóng dật khởi,\nVới minh, không phóng dật,\nTự mình rút mũi tên`, ref: "Kinh Tập 2.10", url: "https://loicuaducphat.org/snp/snp2.10.html#content" },

{ text: `Thế Tôn:\n337. Bỏ năm dục trưởng dưỡng,\nKhả ái và đẹp ý,\nVới lòng tin xuất gia,\nHãy trở thành con người,\nLàm chấm dứt khổ đau.\n\n338. Thân cận với bạn lành,\nSống trú xứ xa vắng,\nViễn ly không ồn ào,\nHãy tiết độ ăn uống\n\n339. Y áo, đồ khất thực,\nVật dụng và sàng tọa,\nChớ có tham ái chúng,\nChớ trở lui đời này.\n\n330. Chế ngự trong giới bổn,\nPhòng hộ trong năm căn,\nHãy tu tập niệm thân,\nSống với nhiều nhàm chán.\n\n341. Hãy từ bỏ tịnh tướng,\nHệ lụy với tham ái,\nTu tập tâm bất tịnh,\nNhất tâm, khéo định tĩnh.\n\n342. Hãy tu tập vô tướng,\nBỏ đi, mạn tùy miên,\nDo nhiếp phục kiêu mạn,\nNgươi sẽ sống an tịnh.`, ref: "Kinh Tập 2.11", url: "https://loicuaducphat.org/snp/snp2.11.html#content" },
{ text: `207. Thân mật, sanh sợ hãi,\nTrú xứ, sanh bụi bặm,\nKhông trú xứ, không thân,\nHình ảnh bậc ẩn sĩ.\n\n208. Ai đã chặt sanh hữu,\nKhông còn gieo giống thêm,\nSanh hữu đã đoạn tận,\nKhông muốn nó tùy sanh,\nÐược gọi là ẩn sĩ,\nMột mình đi im lặng,\nBậc đại sĩ đã thấy,\nCon đường tịch tịnh ấy.\n\n209. Sau khi ước lượng đất,\nTìm hiểu được hột giống,\nKhông còn muốn tham ái,\nÐược tiếp tục tùy sanh,\nVị ấy chân ẩn sĩ,\nThấy sanh diệt chấm dứt,\nÐoạn tận mọi lý luận,\nKhông rơi vào tính toán.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `210. Ðã rõ mọi trú xứ,\nKhông ham trú xứ nào,\nVị ấy chân ẩn sĩ,\nKhông tham, không say đắm.\nKhông còn phải ra sức,\nÐã đạt bờ bên kia.\n\n211. Bậc chiến thắng toàn diện,\nBậc toàn tri, thiện tuệ,\nÐối với tất cả pháp,\nKhông còn bị ô nhiễm.\nBậc từ bỏ tất cả,\nÁi đoạn diệt, giải thoát.\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n212. Vị có trí tuệ lực,\nGiới cấm được đầy đủ,\nÐịnh tĩnh, thích thiền định,\nGìn giữ trì chánh niệm,\nGiải thoát các trói buộc,\nKhông hoang vu, lậu tận,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `213. Bộ hành, riêng một mình,\nẨn sĩ, không phóng dật,\nTrước chê bai, tán thán,\nKhông có bị dao động.\nNhư sư tử, không sợ,\nGiữa các tiếng vang động.\nNhư gió không vướng lưới,\nNhư son không dính nước,\nBậc lãnh đạo mọi người,\nNgười không ai lãnh đạo.\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n214. Vị nào biết xử sự,\nNhư cột trụ hồ tắm,\nKhi người khác nói lời,\nLời khen chê cực đoạn,\nVị không có tham ái,\nVới căn khéo định tĩnh,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `215. Ai thật tự mình đứng\nThẳng như cây thoi đưa,\nNhàm chán các nghiệp ác,\nQuán sát chánh, bất chánh,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n216. Ai biết tự chế ngự,\nKhông làm các điều ác,\nTrẻ và hạng trung niên,\nBậc ẩn sĩ chế ngự,\nVị không nên chọc giận,\nVì không làm ai giận,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n217. Ai sống nhờ người cho,\nNhận lãnh đồ khất thực,\nNhận từ trên, từ giữa,\nHay từ chỗ còn lại,\nKhông đủ để tán thán,\nKhông nói lời hạ mình,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `218. Sống thụ hạnh ẩn sĩ,\nTừ bỏ sự dâm dục,\nAi lúc còn tuổi trẻ,\nKhông bị trói buộc gì,\nTừ bỏ mạn, phóng dật,\nÐược hoàn toàn giải thoát,\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.\n\n219. Rõ biết được thế giới,\nThấy được lý chân đế,\nVượt khỏi được bộc lưu,\nVượt biển lớn như vậy.\nVị chặt đứt trói buộc,\nKhông ỷ lại, vô lậu.\nCác bậc trí nhận thức,\nVị ấy thật ẩn sĩ.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `220. Hai nếp sống không giống.\nAn trú, thật xa nhau,\nGia chủ, có vợ con,\nKhông ngã sở, khéo nhiếp,\nGia chủ không chế ngự,\nNgăn chận hữu tình khác,\nBậc ẩn sĩ luôn luôn,\nChe chở loài hữu tình.\n\n221. Giống như loại chim công,\nLoại chim có cổ xanh,\nKhông bao giờ sánh bằng\nChim thiên nga nhanh nhẹn.\nCũng vậy, người gia chủ,\nKhông sánh bằng Tỷ-kheo,\nBậc ẩn sĩ viễn ly,\nSống thiền định trong rừng.`, ref: "Kinh Tập 1.12", url: "https://loicuaducphat.org/snp/snp1.12.html#content" },

{ text: `242. Sát sanh và hành hình,\nÐả thương và bắt trói,\nTrộm cắp và nói láo,\nMan trá và lừa đảo,\nGiả bộ kẻ học thức,\nÐi lại với vợ người,\nÐây là đồ ăn thối,\nĂn thịt không phải thối.\n\n243. Ở đời, các hạng người,\nKhông chế ngự lòng dục,\nÐam mê các vị ngon,\nLiên hệ đến bất tịnh,\nTheo chủ nghĩa hư vô,\nBất chánh khó hướng dẫn,\nÐây là ăn đồ thối,\nĂn thịt không phải thối.`, ref: "Kinh Tập 2.2", url: "https://loicuaducphat.org/snp/snp2.2.html#content" },

{ text: `244. Ai thô bạo, dã man,\nSau lưng nói gièm pha,\nPhản bạn không từ bi,\nLại cống cao ngạo mạn,\nTánh không có bố thí,\nKhông cho ai vật gì,\nÐây là ăn đồ thối,\nĂn thịt không phải thối,\n\n245. Phẫn nộ và kiêu mạn,\nCứng đầu và chống đối\nMan trá và tật đố,\nNói vô ích, huênh hoang,\nKiêu mạn và quá mạn,\nThân mật với kẻ ác,\nÐây là ăn đồ thối,\nĂn thịt không phải thối,\n\n247. Ở đời đối hữu tình,\nNgười không biết kiềm chế,\nLấy cướp sở hữu người,\nChú tâm làm hại người,\nÁc giới và tàn nhẫn\nÁc ngữ, thiếu lễ độ,\nÐây là ăn đồ thối,\nĂn thịt không phải thối,`, ref: "Kinh Tập 2.2", url: "https://loicuaducphat.org/snp/snp2.2.html#content" },

{ text: `249. Không phải do cá thịt,\nCùng các loại nhịn ăn,\nKhông phải do lõa thể,\nÐầu trọc và bện tóc,\nKhông do tro trét mình,\nMặc da thú khô cứng,\nKhông phải do săn sóc,\nNuôi dưỡng lửa tế tự,\nKhông do nhiều khổ hạnh,\nÐể được chứng bất tử,\nKhông bùa chú tế tự,\nCác tế đàn thời tiết,\nLàm con người trong sạch,\nNếu nghi hoặc chưa đoạn.\n\n250. Do sống hộ trì căn,\nVới các căn nhiếp phục,\nVững trú trên Chánh pháp,\nThích chân trực, hiền hòa,\nVượt khỏi các tham ái,\nÐoạn tận mọi khổ đâu,\nBậc trí không nhiễm dính,\nÐiều được thấy, được nghe.`, ref: "Kinh Tập 2.2", url: "https://loicuaducphat.org/snp/snp2.2.html#content" },

{ text: `253. Ai mở miệng tuyên bố:\nTôi là bạn của anh,\nSở hành vượt xấu hổ,\nLại khinh chán bạn mình,\nKhông chịu khó gắng làm,\nCông việc có thể làm.\nCần biết người như vậy,\nKhông phải bạn của tôi.\n\n254. Ai đối với bạn hữu,\nChỉ làm với lời nói,\nLời nói đẹp, khả ái,\nNhưng chỉ lời nói suông,\nBậc trí biết người ấy,\nNgười chỉ nói, không làm.\n\n255. Người luôn luôn chú ý,\nNghi ngờ sự thiếu sót,\nTìm kiếm các nhược điểm,\nNgười ấy không phải bạn,\nVới ai có thể nắm,\nNhư con nằm trên ngực,\nNgười ấy mới thật bạn,\nKhông bị ai chia ly.\n\n256. Ai mong lợi ích quả,\nTu tập các sự kiện,\nÐem lại sự hân hoan,\nTu tập sự an lạc,\nÐem lại thưởng, tán thán,\nGánh trách nhiệm làm người.\n\n257. Uống xong vị viễn ly,\nUống xong vị an tịnh,\nKhông sợ hãi, không ác,\nHưởng vị ngọt, pháp hỷ.`, ref: "Kinh Tập 2.3", url: "https://loicuaducphat.org/snp/snp2.3.html#content" },

{ text: `259. Không thân cận kẻ ngu,\nNhưng gần gũi bậc trí,\nÐảnh lễ người đáng lễ\nLà điềm lành tối thượng.\n\n260. Ở trú xứ thích hợp,\nCông đức trước đã làm,\nChân chánh hướng tụ tâm,\nLà điều lành tối thượng.\n\n261. Học nhiều, nghề nghiệp giỏi,\nKhéo huấn luyện học tập,\nNói những lời khéo nói\nLà điềm lành tối thượng.\n\n262. Hiếu dưỡng mẹ và cha,\nNuôi dưỡng vợ và con,\nLàm nghề không rắc rối\nLà điềm lành tối thượng.`, ref: "Kinh Tập 2.4", url: "https://loicuaducphat.org/snp/snp2.4.html#content" },

{ text: `263. Bố thí, hành đúng pháp,\nSăn sóc các bà con,\nLàm nghiệp không lỗi lầm\nLà điềm lành tối thượng.\n\n264. Chấm dứt, từ bỏ ác,\nChế ngự đam mê rượu,\nTrong pháp, không phóng dật\nLà điềm lành tối thượng.\n\n265. Kính lễ và hạ mình,\nBiết đủ và biết ơn,\nÐúng thời, nghe Chánh pháp\nLà điềm lành tối thượng.\n\n266. Nhẫn nhục, lời hòa nhã,\nYết kiến các Sa-môn,\nÐúng thời, đàm luận pháp,\nLà điềm lành tối thượng.`, ref: "Kinh Tập 2.4", url: "https://loicuaducphat.org/snp/snp2.4.html#content" },

{ text: `267. Khắc khổ và Phạm hạnh,\nThấy được lý Thánh đế,\nGiác ngộ quả Niết bàn\nLà điềm lành tối thượng.\n\n268. Khi xúc chạm việc đời,\nTâm không động, không sầu,\nKhông uế nhiễm, an ổn\nLà điềm lành tối thượng.\n\n269. Làm sự việc như vậy,\nKhông chỗ nào thất bại,\nKhắp nơi được an toàn,\nLà điềm lành tối thượng.`, ref: "Kinh Tập 2.4", url: "https://loicuaducphat.org/snp/snp2.4.html#content" },

{ text: `Thế Tôn:\n\n271. Từ những nguyên nhân này,\nTham, sân được khởi lên,\nKhông ưa thích, ưa thích,\nSợ hãi từ đây sanh,\nTừ đây được sanh khởi,\nCác suy tầm của ý,\nNhư đứa trẻ độc ác,\nThả cho con quạ bay.\n\n272. Sự hiện hữu của ngã,\nChính do thân ái sanh,\nNhư các loại cây bàng,\nDo thân cây bàng sanh.\nSự triền phược các dục,\nThật rộng lớn vô cùng,\nNhư cây Màluvà,\nTỏa rộng lan khắp rừng.\n\n273. Hãy nghe! Này Dạ-xoa,\nNhững ai được rõ biết\nTừ đâu, khiến sanh khởi,\nHọ tẩy sạch nhân ấy.\nHọ vượt qua dòng nước,\nChảy mạnh khó vượt này,\nTrước chưa được vượt qua,\nKhông còn có tái sanh.`, ref: "Kinh Tập 2.5", url: "https://loicuaducphat.org/snp/snp2.5.html#content" },

{ text: `274. Pháp hạnh và Phạm hạnh,\nÐược gọi là tối thượng hạnh,\nNếu là người xuất gia,\nBỏ nhà, sống không nhà.\n\n275. Nếu bản tánh lắm mồm,\nƯa làm hại như thú,\nÐời sống ấy ác độc,\nLàm ngã tăng bụi trần.\n\n276. Tỷ-kheo ưa cãi nhau,\nBị vô minh che đậy,\nKhông biết pháp luật dạy,\nPháp do Phật tuyên thuyết.\n\n277. Bị vô minh lãnh đạo,\nHại bậc tu tập ngã,\nKhông biết đường ô nhiễm,\nÐưa đến cõi địa ngục.\n\n278. Vị Tỷ-kheo như vậy,\nRơi vào chỗ đọa xứ,\nÐi đầu thai chỗ này,\nÐến đầu thai chỗ khác,\nÐi từ tối tăm này,\nÐến chỗ tối tăm khác.\nVị ấy sau khi chết,\nRơi vào chỗ khổ đau.`, ref: "Kinh Tập 2.6", url: "https://loicuaducphat.org/snp/snp2.6.html#content" },

{ text: `279. Như hố phân đầy tràn,\nSau nhiều năm chất chứa,\nCũng vậy, kẻ uế nhiễm,\nThật khó lòng gột sạch.\n\n280. Hỡi này các Tỷ-kheo,\nHãy biết người như vậy,\nHệ lụy với gia đình,\nÁc dục, ác tư duy,\nÁc uy nghi cử chi,\nÁc sở hành, hành xứ.\n\n281. Tất cả đều đồng tình,\nTránh xa ngưòi như vậy,\nHãy thổi nó như bụi,\nHãy quăng nó như rác.\n\n282. Hãy đuổi kẻ nói nhiều,\nKẻ Sa-môn giả hiệu,\nSau khi đuổi ác dục,\nÁc uy nghi hành xứ.\n\n283. Hãy giữ mình trong sạch,\nChung sống kẻ trong sạch,\nSống thích đáng, chánh niệm,\nRồi hòa hợp, sáng suốt,\nHãy chấm dứt khổ đau.`, ref: "Kinh Tập 2.6", url: "https://loicuaducphat.org/snp/snp2.6.html#content" },

{ text: `284. Các ẩn sĩ thời xưa,\nChế ngự, sống khắc khổ,\nBỏ năm dục trưởng dưỡng,\nHành lý tưởng tự ngã.\n\n285. Phạm chí, không gia súc,\nKhông vàng bạc lúa gạo,\nHọc hỏi là tài sản,\nHọ che chở hộ trì,\nKho tàng tối thượng ấy.\n\n288. Không bị ai xâm phạm\nLà Phạm chí thời ấy,\nKhông bị ai chiến hại,\nHọ được pháp che chở,\nKhông ai ngăn chặn họ,\nTại ngưỡng cửa gia đình.\n\n289. Từ trẻ đến bốn tám,\nCác Phạm chí thời xưa,\nHọ sống hành Phạm hạnh,\nTầm cầu minh và hạnh.`, ref: "Kinh Tập 2.7", url: "https://loicuaducphat.org/snp/snp2.7.html#content" },

{ text: `292. Họ tán thán Phạm hạnh,\nGiới, học thức, nhu hòa,\nKhắc khổ và hòa nhã,\nBất hại và nhẫn nhục.\n\n293. Vị tối thắng trong họ,\nLà Phạm thiên, nỗ lực,\nVị ấy không giao hợp,\nCho đến trong cơn mộng.\n\n294. Ở đời, bậc có trí,\nHọc theo hạnh vị ấy,\nHọ tán thán Phạm hạnh,\nGiới đức và nhẫn nhục.`, ref: "Kinh Tập 2.7", url: "https://loicuaducphat.org/snp/snp2.7.html#content" },

{ text: `316. Từ vị nào một người,\nRõ biết được Chánh pháp,\nHãy đảnh lễ vị ấy,\nNhư chư Thiên, Inda,\nVị ấy được đảnh lễ,\nTâm tư sanh hoan hỷ,\nNghe nhiều, học hỏi nhiều,\nThuyết trình chơn diệu pháp.\n\n317. Vị sáng suốt chú tâm,\nSuy tư và quán sát\nThực hành pháp tuỳ pháp,\nTrở thành vị hiểu biết,\nThông minh và thận trọng,\nKhông phóng dật, vị ấy,\nTheo gương vị như vậy.`, ref: "Kinh Tập 2.8", url: "https://loicuaducphat.org/snp/snp2.8.html#content" },

{ text: `319. Như người nhảy xuống sông,\nDòng sông nước ngập tràn,\nNước sông, nhớp đục ngầu,\nDòng nước chảy nhanh mạnh\nNgười ấy bị lôi cuốn,\nTheo dòng nước trôi đi,\nLàm sao nó có thể,\nGiúp người khác vượt dòng.\n\n320. Cũng vậy, với người nào,\nPháp không được tu tập,\nKhông quán sát ý nghĩa,\nCủa những vị nghe nhiều,\nTự mình không rõ biết,\nNghi hoặc chưa vượt qua,\nLàm sao nó có thể,\nGiúp người khác thiền định.`, ref: "Kinh Tập 2.8", url: "https://loicuaducphat.org/snp/snp2.8.html#content" },

{ text: `321. Như người được leo lên,\nChiếc thuyền mạnh vững chắc,\nÐược trang bị đầy đủ,\nMái chèo và tay lái;\nNgười như vậy ở đây,\nGiúp nhiều người ngược dòng,\nRõ biết những phương tiện,\nThiện xảo và sáng suốt.\n\n322. Như vậy, bậc sáng suốt,\nLuôn luôn tự tu tập,\nBậc nghe nhiều hiểu nhiều,\nKhông còn bị dao động,\nVị ấy giúp đỡ được,\nCác người khác tu thiền,\nLàm khởi lên nguyên nhân,\nTha thiết muốn nghe pháp.\n\n323. Do vậy, hãy thân cận,\nBậc chân nhân hiền sĩ,\nBậc sáng suốt, có trí,\nBậc nghe nhiều học nhiều.\nSau khi biết mục đích,\nCố gắng khéo hành trì,\nRõ biết được Chánh pháp,\nVị ấy được an lạc.`, ref: "Kinh Tập 2.8", url: "https://loicuaducphat.org/snp/snp2.8.html#content" },

{ text: `359. Tôi hỏi bậc ẩn sĩ,\nCó trí tuệ rộng lớn,\nÐã vượt qua bờ kia,\nTịch tịnh, tự an trú.\nLàm sao một Tỷ-kheo,\nBỏ nhà, bỏ các dục,\nLại có thể chơn chánh\nDu hành ở trên đời?\n\nThế Tôn:\n361. Tỷ-kheo nhiếp phục tham,\nÐối với các dục vọng,\nTại thiên giới, nhân giới,\nVượt hữu, chứng tri pháp;\nTỷ kheo ấy chơn chánh\nDu hành ở trên đời.\n\n362. Tỷ kheo bỏ hai lưỡi,\nBỏ phẩn nộ, xan tham,\nVới tùy thuộc chống đối,\nÐoạn tận thật hoàn toàn,\nTỷ kheo ấy chơn chánh\nDu hành ở trên đời.`, ref: "Kinh Tập 2.13", url: "https://loicuaducphat.org/snp/snp2.13.html#content" },

{ text: `363. Sau khi đã từ bỏ,\nCả ái và phi ái,\nKhông chấp thủ một ai,\nKhông y chỉ chỗ nào,\nGiải thoát được hoàn toàn\nCác kiết sử trói buộc,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.\n\n364. Ai không tìm lõi cây,\nÐối với các sanh y,\nCó thể nhiếp phục tham,\nÐối với các chấp thủ,\nVị ấy không y chỉ,\nKhông để ai dắt dẫn,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.\n\n365. Với lời và với ý,\nVà với cả nghiệp làm,\nKhông chống đối một ai,\nChơn chánh biết diệu pháp,\nThường cố gắng hướng đến,\nÐường Niết bàn tịch tịnh,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.`, ref: "Kinh Tập 2.13", url: "https://loicuaducphat.org/snp/snp2.13.html#content" },

{ text: `366. Tỷ-kheo không tự cao,\nKhi người đảnh lễ mình,\nDầu có bị nhiếc mắng,\nKhông khởi tâm tức tối,\nÐược đồ ăn của người,\nKhông có sự tham đắm,\nTỷ kheo ấy chơn chánh\nDu hành ở trên đời.\n\n367. Tỷ-kheo sau khi đoạn,\nTham dục và sanh hữu,\nTừ bỏ, không làm hại,\nKhông trói buộc một ai,\nVị ấy vượt nghi hoặc,\nÐã rút ra mũi tên,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.\n\n368. Tỷ-kheo sau khi biết,\nÐiều thích đáng cho mình,\nKhông làm hại một ai,\nCó mặt ở trên đời,\nSau khi đã biết pháp\nNhư thật, như thế nào,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.`, ref: "Kinh Tập 2.13", url: "https://loicuaducphat.org/snp/snp2.13.html#content" },

{ text: `369. Với ai, các tuỳ miên,\nKhông còn có tồn tại,\nVà cội gốc bất thiện,\nÐược nhổ lên tận trừ,\nVị ấy không tham dục,\nKhông có hy cầu gì.\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.\n\n370. Ai đoạn tận lậu hoặc,\nÐoạn trừ cả kiêu mạn,\nMọi con đường tham dục,\nÐược chế ngự nhiếp phục,\nÐược nhiếp phục tịch tịnh,\nTự ngã được an lập,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.\n\n371. Có lòng tin, nghe pháp,\nThấy được quyết định tánh,\nBậc hiền không phe phái,\nGiữa rất nhiều phe phái,\nCó thể nhiếp phục được,\nTham, sân và hận thù,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.`, ref: "Kinh Tập 2.13", url: "https://loicuaducphat.org/snp/snp2.13.html#content" },

{ text: `372. Thanh tịnh và chiến thắng,\nKéo lên màn che kín,\nTự tại trong các pháp,\nÐến bờ kia, bất động,\nÐoạn diệt các sở hành,\nThiện xảo trong chánh trí,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.\n\n373. Trong những thời quá khứ,\nTrong những thời vị lai,\nVượt qua các chủ thuyết,\nTrí tuệ thật thanh tịnh,\nVới tất cả mọi xứ,\nÐược hoàn toàn giải thoát.\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.\n\n374. Rõ biết được Pháp cú,\nChứng tri được Chánh pháp,\nThấy được sự mở rộng,\nÐoạn tận các lậu hoặc,\nÐối tất cả sanh y,\nÐược trừ diệt hoàn toàn,\nTỷ-kheo ấy chơn chánh\nDu hành ở trên đời.`, ref: "Kinh Tập 2.13", url: "https://loicuaducphat.org/snp/snp2.13.html#content" },

{ text: `386. Tỷ-kheo chớ ra ngoài,\nTrong thời gian phi thời,\nHãy vào làng khất thực,\nÐúng thời, thì hãy đi,\nAi đi đứng phi thời,\nBị bẫy sập trói buộc.\nDo vậy các đức Phật,\nKhông có đi phi thời.\n\n387. Các sắc và các tiếng,\nCác vị, hương và xúc,\nChính những loại pháp ấy\nLàm mê hoặc chúng sanh.\nHãy nhiếp phục, lòng dục,\nÐối với các pháp ấy,\nHãy vào cho đúng thời,\nÐể dùng buổi ăn sáng.\n\n388. Tỷ-kheo được đúng thời,\nCác đồ ăn khất thực,\nHãy đi về một mình,\nNgồi tại chỗ an tịnh,\nSuy tư hướng nội tâm,\nÝ không chạy ra ngoài,\nLàm cho thoát ra khỏi,\nMọi chấp thủ tự ngã.`, ref: "Kinh Tập 2.14", url: "https://loicuaducphat.org/snp/snp2.14.html#content" },

{ text: `389. Hãy nói cho vị ấy,\nSự thù diệu Chánh pháp,\nKhông có nói hai lưỡi,\nKhông bài xích một ai,\n\n390. Nhưng có những hạng người,\nDùng khẩu chiến bằng lời,\nNhững hạng người tuệ nhỏ,\nChúng ta không tán thán,\nTriền phược trói buộc họ,\nTừ chỗ này chỗ kia,\nỞ đây họ dẫn tâm,\nÐưa tâm đi quá xa.`, ref: "Kinh Tập 2.14", url: "https://loicuaducphat.org/snp/snp2.14.html#content" },

{ text: `391. Ðồ khất thực, tinh xá,\nCùng sàng tọa trú xứ,\nNước để trừ bụi nhớp,\nY áo Tăng-già-lê,\nSau khi nghe Chánh pháp,\nDo Thiện Thệ thuyết giảng,\nBậc đệ tử thắng tuệ,\nQuán sát, hãy dùng chúng.\n\n392. Do vậy đồ khất thực,\nSàng tọa và trú xứ,\nNước để trừ bụi nhớp,\nY áo Tăng-già-lê,\nÐối với những pháp ấy,\nÐừng để cho dính nhiễm.\nTỷ-kheo như giọt nước,\nKhông dính trên lá sen.`, ref: "Kinh Tập 2.14", url: "https://loicuaducphat.org/snp/snp2.14.html#content" },

{ text: `394. Chớ giết loài hữu tình,\nChớ bảo người giết hại,\nHay chấp nhận kẻ khác,\nGiết hại các người khác,\nÐối với mọi sanh loại,\nTừ bỏ các hình phạt,\nÐối với kẻ mạnh bạo,\nNhư đối kẻ run sợ.\n\n395. Rồi hãy quyết từ bỏ,\nLấy của không được cho,\nÐệ tử khéo sáng suốt,\nVật gì, vật của ai,\nChớ khiến người khác lấy,\nChớ chấp nhận lấy trộm.\nHãy từ bỏ, chấm dứt,\nMọi của cải không cho.\n\n396. Hãy từ bỏ, tránh xa\nÐời sống phi Phạm hạnh,\nNhư bậc trí tránh né,\nLửa cháy hố than hừng.\nNếu tự mình bất lực,\nKhông thể sống Phạm hạnh,\nThời chớ có xâm phạm\nVợ của các người khác.`, ref: "Kinh Tập 2.14", url: "https://loicuaducphat.org/snp/snp2.14.html#content" },

{ text: `397. Khi đi đến hội chúng,\nHay đi đến đoàn chúng,\nHay một mình một người,\nChớ nói lời nói láo,\nChớ khiến người nói láo,\nChớ chấp nhận nói láo,\nTất cả điều không thật,\nHãy tránh xa từ bỏ.\n\n398. Chớ sống theo nếp sống,\nUống rượu và say rượu,\nVới vị là cư sĩ,\nÐã chấp nhận pháp này,\nChớ khiến nguời uống rượu,\nChớ chấp thuận uống rượu\nSau khi biết uống rượu,\nCuối đường là điên cuồng.\n\n399. Chỉ kẻ ngu say rượu,\nMới làm các điều ác,\nVà khiến các người khác,\nSống buông lung phóng dật,\nHãy từ bỏ, tránh xa\nXứ phi công đức này,\nKhiến điên cuồng si mê,\nLàm kẻ ngu thỏa thích.`, ref: "Kinh Tập 2.14", url: "https://loicuaducphat.org/snp/snp2.14.html#content" },

{ text: `400. Chớ có giết hữu tình,\nChớ lấy của không cho,\nChớ nói láo không thật,\nChớ uống rượu say mê,\nTừ bỏ phi Phạm hạnh,\nKhông hành trì dâm dục\nKhông có ăn ban đêm,\nKhông ăn lúc phi thời.\n\n401. Chớ mang các vòng hoa,\nChớ dùng các nước thơm,\nHãy nằm trên mặt đất,\nTrên thảm chiếu trải dài,\nTám hạnh này được gọi\nLà hạnh ngày trai giới,\nDo đức Phật giảng dạy,\nÐể chấm dứt khổ đau.\n\n402. Từ nay ngày trai giới,\nChia nửa tháng hai phần,\nNgày mười bốn, mười lăm,\nHay ngày tám mỗi tháng,\nVới tâm ý hoan hỷ,\nThực hành thần thông pháp\nGồm có đủ tám phần,\nKhéo đầy đủ vẹn toàn.\n\n403. Do vậy, vào buổi sáng,\nThực hành ngày trai giới,\nBậc có trí sáng suốt,\nVới tâm tư tín thành,\nVới tâm ý tùy hỷ,\nCúng dường Tỷ-kheo Tăng,\nVới món ăn đồ uống,\nHợp với khả năng mình.\n\n404. Hãy nuôi dưỡng mẹ cha,\nHợp pháp và đúng pháp,\nVà cũng đúng với pháp,\nHãy làm nghề buôn bán,\nNgười gia chủ như vậy,\nSở hành không phóng dật,\nÐược sanh làm Thiên nhân,\nTên là: "Tự chói sáng".`, ref: "Kinh Tập 2.14", url: "https://loicuaducphat.org/snp/snp2.14.html#content" },

{ text: `Ànanda:\n405. Xuất gia, tôi tán thán,\nNhư Pháp nhãn xuất gia,\nSau khi Ngài quán sát,\nChấp thuận hạnh xuất gia.\n\n406. Trói buộc, sống gia đình,\nTụ hội mọi bụi đời,\nPhóng khoáng, đời xuất gia,\nThấy vậy nên xuất gia.\n\n407. Sau khi Ngài xuất gia,\nThân ác nghiệp Ngài tránh,\nTừ bỏ lời nói ác,\nMạng sống Ngài thanh tịnh.`, ref: "Kinh Tập 3.1", url: "https://loicuaducphat.org/snp/snp3.1.html#content" },

{ text: `408. Phật đi đến Vương Xá,\nÐến chỗ núi bao vây,\nTại nước Ma-kiệt-đà,\nNgài sống hạnh khất sĩ,\nMang theo thật đầy đủ,\nCác tướng tốt quang minh.\n\n411. Người đẹp, lớn, thanh tịnh,\nThành tựu với hạnh đức,\nChỉ nhìn vừa một tầm.\nMắt nhìn xuống, chánh niệm,\n\n413. Khất thực, từng nhà một,\nCăn hộ trì chế ngự,\nBình bát được mau đầy,\nTỉnh giác và chánh niệm.\nSau khi đi khất thực,\nẨn sĩ ra khỏi thành.`, ref: "Kinh Tập 3.1", url: "https://loicuaducphat.org/snp/snp3.1.html#content" },

{ text: `422. Trên sườn núi Tuyết sơn,\nSống dân tộc đoạn trực,\nTài sản nghị lực đủ,\nỞ xứ Kosala.\n\n423. Dòng họ thuộc mặt trời,\nSanh tộc là Thích-ca,\nTừ bỏ gia tộc ấy,\nThưa vua, Ta xuất gia,\nTa không có tha thiết,\nÐối với các loại dục.\n\n424. Thấy nguy hiểm trong dục,\nBỏ chúng, là an ổn,\nTa sẽ đi, tinh tấn,\nÝ Ta, được hoan hỷ.`, ref: "Kinh Tập 3.1", url: "https://loicuaducphat.org/snp/snp3.1.html#content" },

{ text: `425. Bên sông Ni-liên-thuyền,\nTa tinh cần tinh tấn,\nCố gắng, Ta thiền định,\nÐạt an ổn khổ ách.\n\n434. Dầu máu có khô cạn,\nMật, đàm Ta khô cạn,\nDầu thịt có hủy hoại,\nTâm Ta càng tịnh tín,\nTa lại càng vững trú,\nNiệm, tuệ và thiền định.\n\n435. Do Ta sống như vậy,\nÐạt được thọ tối thượng,\nTâm không cầu các dục,\nNhìn chúng sanh thanh tịnh.`, ref: "Kinh Tập 3.2", url: "https://loicuaducphat.org/snp/snp3.2.html#content" },

{ text: `436. Dục, đội quân thứ nhất.\nThứ hai, gọi bất lạc,\nThứ ba, đói và khát,\nThứ tư, gọi tham ái.\n\n437. Năm, hôn trầm thụy miên,\nThứ sáu, gọi sợ hãi,\nThứ bảy, gọi nghi ngờ,\nTám, dèm pha ngoan cố.\n\n438. Lợi, danh và cung kính,\nDanh vọng được tà vạy,\nAi tự đề cao mình,\nHủy báng các người khác.\n\n439. Ôi, này Na-mu-ci,\nÐây là quân đội Ngươi,\nÐây quân đội chiến trận,\nCủa dòng họ Kanhà,\nKẻ nhát, không thắng Ngươi,\nAi thắng Ngươi, được lạc.`, ref: "Kinh Tập 3.2", url: "https://loicuaducphat.org/snp/snp3.2.html#content" },

{ text: `444. Nhiếp phục được tâm tư,\nKhéo an trú chánh niệm,\nTa sẽ đi bộ hành,\nNước này qua nước khác,\nÐể huấn luyện rộng rãi,\nCho những người đệ tử.\n\n445. Không phóng dật, tinh cần,\nHọ hành lời Ta dạy,\nDầu Ngươi không muốn vậy,\nHọ vẫn sẽ đi tới,\nChỗ nào họ đi tới,\nChỗ ấy không sầu muộn.`, ref: "Kinh Tập 3.2", url: "https://loicuaducphat.org/snp/snp3.2.html#content" },

{ text: `451. Hãy nói lên lời nói,\nKhông thiêu đốt tự ngã,\nKhông làm hại người khác,\nLời nói ấy khéo nói.\n\n452. Hãy nói lời khả ái,\nNói lời khiến hoan hỷ,\nKhông mang theo ác hại,\nKhiến người khác ưa thích.\n\n453. Chân thật, lời bất tử,\nÐây thường pháp là vậy,\nHọ nói, bậc Thiện nhân,\nAn trú trên chân thật,\nTrên mục đích, trên pháp.\n\n454. Lời gì đức Phật nói,\nAn ổn, đạt Niết-bàn,\nÐoạn tận các khổ đau,\nÐấy lời nói tối thượng.`, ref: "Kinh Tập 3.3", url: "https://loicuaducphat.org/snp/snp3.3.html#content" },

{ text: `455. Ta không phải Phạm chí,\nCũng không phải con vua,\nCũng không phải buôn bán,\nKhông phải là ai hết,\nDo liễu tri giai cấp,\nCủa các hàng phàm phu,\nTa kẻ trí ở đời,\nBộ hành, không sở hữu.\n\n456. Mang áo Tăng-già-lê,\nTa sống, không gia đình,\nVới tóc được cạo sạch,\nTự ngã được an tịnh,\nỞ đời Ta không nhiễm.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `462. Chớ hỏi về thọ sanh,\nHãy hỏi về hạnh đức,\nThật vậy, từ củi gỗ,\nMột ngọn lửa được sanh,\nTừ gia đình thấp kém,\nBậc ẩn sĩ, có trí,\nÐược huấn luyện thuần thục,\nÐược xấu hổ chế ngự.\n\n463. Ðược chân thật huấn luyện,\nÐược nhiếp phục chế ngự,\nBậc đạt đến hiểu biết,\nPhạm hạnh được viên thành,\nHãy đúng thời cúng dường,\nÐồ cúng dường vị ấy.\nVậy vị Phạm chí nào\nMuốn nguyện cầu công đức,\nHãy tổ chức tế đàn,\nVới cúng dường như vậy.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `464. Những vị nào, bỏ dục,\nDu hành, không gia đình,\nKhéo chế ngự nhiếp phục,\nNhư con thoi trực chỉ.\nÐúng thời đối vị ấy,\nHãy cúng đồ tế tự,\nVị Phạm chỉ cầu phước,\nHãy bố thí như vậy,\nHãy tổ chức tế đàn,\nVới cúng dường như vậy.\n\n465. Những vị đã ly tham,\nCác căn khéo định tĩnh,\nNhư trăng được giải thoát,\nKhỏi nanh vuốt Ràhu,\nHãy đúng thời cúng dường,\nÐồ cúng dường vị ấy,\nVậy vị Phạm hạnh nào,\nMuốn nguyện cầu công đức,\nHãy tổ chức tế đàn,\nVới cúng dường như vậy.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `466. Không tham dính vật gì,\nHọ du hành ở đời,\nLuôn luôn giữ chánh niệm,\nTừ bỏ ngã sở kiến,\nHãy đúng thời cúng dường,\nÐồ cúng dường vị ấy.\nVậy vị Phạm chí nào,\nMuốn cầu nguyện công đức,\nHãy tổ chức tế đàn,\nVới cúng dường như vậy.\n\n467. Ai từ bỏ các dục,\nTự nhiếp phục, du hành.\nAi biết sự chấm dứt,\nCủa sanh và sự chết,\nTịch tịnh và mát lạnh.\nMát lạnh như nước hồ.\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.\n\n468. Bình đẳng kẻ bình đẳng,\nXa lánh không bình đẳng,\nNhư Lai chứng đạt được,\nTrí tuệ không giới hạn,\nKhông bị dính, uế nhiễm,\nÐời này hay đời sau.\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `469. Trong ai không man trá,\nKhông sống với kiêu mạn,\nAi không có tham dục,\nKhông của ta, không cầu,\nPhẫn nộ được đoạn trừ,\nTự ngã thật tịch tịnh,\nVị Bà-la-môn ấy,\nCấu uế, sầu muộn đoạn,\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.\n\n470. Ai đoạn diệt hoàn toàn\nMọi trú xứ của ý,\nKhông còn có nắm giữ,\nSự vật gì ở đời,\nKhông còn có chấp thủ,\nÐời này hay đời sau.\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `471. Tâm ai thật định tĩnh,\nVượt khỏi được bộc lưu,\nRõ biết được Chánh pháp,\nVới tri kiến tối thượng,\nLậu hoặc được đoạn trừ,\nMang thân này tối hậu.\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.\n\n472. Với ai, các hữu lậu,\nVà lời nói thô ác,\nÐược đoạn tận chấm dứt,\nKhông còn có tồn tại,\nVị ấy đạt hiểu biết,\nGiải thoát mọi khía cạnh.\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `473. Giữa những người nhiễm trước,\nVị ấy không nhiễm trước,\nGiữa chúng sanh kiêu mạn,\nVị ấy không kiêu mạn,\nLiễu tri được đau khổ,\nKể cả ruộng và đất.\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.\n\n474. Không dựa vào ước vọng,\nVị ấy thấy viễn ly,\nVượt qua sự hiểu biết,\nCùng tri kiến người khác,\nÐối với mọi sở duyên,\nVị ấy đều không có,\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.\n\n475. Vị ấy chứng tri được\nCác pháp gần hay xa,\nÐược đoạn trừ, chấm dứt,\nKhông còn có hiện hữu,\nAn tịnh, không chấp thủ,\nÐược hoàn toàn giải thoát\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `476. Thấy được sự đoạn tận,\nSanh diệt các kiết sử,\nTrừ được đường tham dục,\nKhông còn lại dư tàn.\nThanh tịnh, không lỗi lầm,\nKhông cấu uế, không nhiễm.\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.\n\n477. Ai không thấy tự ngã,\nVới tự ngã của mình,\nÐịnh tâm và chánh trực,\nKiên trì không dao động,\nVị ấy không có dục,\nKhông cứng cỏi, phân vân.\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.\n\n478. Với ai không còn nữa,\nNguyên nhân của si mê,\nBiết rõ và thấy rõ,\nÐối với hết thảy pháp,\nVà mang nặng thân này,\nThân này thân cuối cùng.\nChứng đạt Chánh Ðẳng Giác,\nVô thượng an ổn xứ,\nÐạt cho đến như vậy,\nNhư Lai thật xứng đáng,\nÐồ cúng dường tế tự.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `Thế Tôn:\n483. Với ai, không xông xáo,\nVới ai, tâm không động,\nGiải thoát khỏi các dục,\nVới ai bỏ hôn trầm,\n\n484. Lãnh đạo kẻ biên giới,\nThiện xảo trong sanh tử,\nẨn sĩ đầy đủ tuệ,\nÐã đến lễ tế đàn.\n\n485. Nhiếp phục kiêu ngạo xong,\nHãy chắp tay đảnh lễ,\nCúng dường đồ ăn uống,\nCúng dường vậy tăng trưởng.\n\nBà-la-môn:\n486. Ngài là bậc Giác Ngộ,\nXứng đáng được cúng dường,\nNgài là ruộng phước đức,\nVô thượng, không gì hơn,\nVị tiếp nhận cúng dường,\nXứng đáng toàn thế giới.\nBố thí cho Tôn giả,\nKết quả thật to lớn.`, ref: "Kinh Tập 3.4", url: "https://loicuaducphat.org/snp/snp3.4.html#content" },

{ text: `487. Thanh niên Màgha thưa:\nTôn giả Gotama,\nCon hỏi bậc Hiền hòa,\nMặc cà sa không nhà,\nAi ưa muốn được cầu,\nLà thí chủ, gia chủ\nMong muốn được phước đức,\nBố thí, mong cầu phước.\nỞ đây, thí người khác,\nÐồ ăn và đồ uống,\nTại đâu nên bố thí,\nÐể đồ cúng được tịnh.\n\n488. Thế Tôn bèn trả lời:\nNày thanh niên Màgha,\nAi ưa muốn được cầu,\nLà thí chủ, gia chủ,\nMong muốn được phước đức,\nBố thí, mong cầu phước,\nỞ đây, thí người khác\nÐồ ăn và đồ uống,\nNgười ấy cần phải thí,\nNgười xứng đáng cúng dường.\n\n490. Những ai sống ở đời,\nThật sự không nhiễm trước,\nHoàn toàn không sở hữu,\nTự ngã được nhiếp phục,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.`, ref: "Kinh Tập 3.5", url: "https://loicuaducphat.org/snp/snp3.5.html#content" },

{ text: `491. Những ai đã chặt đứt,\nMọi kiết sử trói buộc,\nNhiếp phục được giải thoát,\nKhông dao động, mong cầu.\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.\n\n493. Vị nào đã đoạn tận,\nTham, sân và cả si,\nCác lậu hoặc đã đoạn,\nPhạm hạnh đã thành tựu,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.`, ref: "Kinh Tập 3.5", url: "https://loicuaducphat.org/snp/snp3.5.html#content" },

{ text: `494. Ai sống không man trá,\nVà không có kiêu mạn,\nCác lậu hoặc đã đoạn,\nPhạm hạnh đã thành tựu,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.\n\nNhững vị sống không tham,\nKhông ngã sở, không cầu,\nCác lậu hoặc đã đoạn,\nPhạm hạnh đã thành tựu,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.`, ref: "Kinh Tập 3.5", url: "https://loicuaducphat.org/snp/snp3.5.html#content" },

{ text: `495. Những ai đối với ai,\nKhông rơi vào hệ lụy,\nVượt khỏi được bộc lưu,\nDu hành không ngã sở,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự,\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.\n\n496. Với ai không tham ái,\nMột vật gì ở đời,\nKhông ái hữu, phi hữu,\nÐời này hay đời sau,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.`, ref: "Kinh Tập 3.5", url: "https://loicuaducphat.org/snp/snp3.5.html#content" },

{ text: `497. Những ai từ bỏ dục,\nSống không có gia đình,\nKhéo léo biết chế ngự,\nNhư con thoi, chính trực,\nÐúng thời, đối vị ấy.\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.\n\n498. Những ai, ly tham ái,\nCác căn khéo định tĩnh,\nNhư mặt trăng thoát khỏi,\nNanh vuốt của Ràhu,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.`, ref: "Kinh Tập 3.5", url: "https://loicuaducphat.org/snp/snp3.5.html#content" },

{ text: `499. Những ai được an tịnh,\nLy tham, ly phẫn nộ,\nSau khi bỏ đời này,\nKhông còn có sanh thú,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.\n\n500. Ðoạn sanh tử đã xong,\nKhông còn chút dư tàn,\nNghi ngờ và phân vân,\nTất cả được nhiếp phục,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.`, ref: "Kinh Tập 3.5", url: "https://loicuaducphat.org/snp/snp3.5.html#content" },

{ text: `501. Những ai sống ở đời\nTự mình làm hòn đảo,\nKhông có vật sở hữu,\nGiải thoát được trọn vẹn,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự.\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.\n\n502. Những ai ngay đời này,\nNhư thật rõ biết được,\nÐây đời sống cuối cùng,\nKhông còn có tái sanh,\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.\n\n503. Ai đạt tuệ tối thượng,\nƯa thiền, giữ chánh niệm,\nÐạt được sự giác ngộ,\nChỗ quy ngưỡng nhiều người.\nÐúng thời, đối vị ấy,\nHãy cúng đồ tế tự,\nVị Phạm chí cầu phước,\nHãy bố thí như vậy.`, ref: "Kinh Tập 3.5", url: "https://loicuaducphat.org/snp/snp3.5.html#content" },

{ text: `505. Rồi thanh niên Màgha,\nLại thưa thêm như sau:\nAi ưa muốn được cầu,\nLà thí chủ, gia chủ,\nMong muốn được phước đức,\nBố thí, mong cầu phước,\nỞ đây, thí người khác,\nÐồ ăn và đồ uống,\nThế Tôn hãy nói con,\nPháp tế tự hoàn toàn.\n\n506. Thế Tôn nói Màgha,\nHãy tế đàn, tế tự,\nPhải làm cho trong sạch,\nHoàn toàn mọi tâm tư,\nÐối người lễ tế đàn,\nÐối tượng là đồ cúng,\nHãy an trú ở đây,\nTừ bỏ sự sân hận.\n\n507. Vị ấy đoạn tận tham,\nNhiếp phục cả sân hận,\nTu tập tâm từ bi,\nVô lượng khắp tất cả,\nVới hạnh không phóng dật,\nNgày đêm luôn tu tập,\nCùng khắp mọi phương hướng,\nBiến mãn vô lượng tâm.`, ref: "Kinh Tập 3.5", url: "https://loicuaducphat.org/snp/snp3.5.html#content" },

{ text: `513. Sabhiya hỏi rằng:\nTôn giả Gotama,\nDo đạt được những gì,\nÐược gọi là Tỷ-kheo?\nNhờ gì, gọi nhu hòa?\nThế nào gọi chế ngự?\nVà phải như thế nào,\nÐược gọi bậc Giác ngộ?\nÐược con hỏi như vậy,\nMong Thế Tôn trả lời.\n\n514. Thế Tôn bèn đáp lại:\nHỡi này Sabhiya,\nAi chính với con đường,\nDo tự mình tạo ra,\nÐi đến sự tịch mịch,\nVượt qua các nghi hoặc,\nTừ bỏ, đoạn tận hẳn\nCả hữu và phi hữu,\nPhạm hạnh đã thành tựu,\nTái sanh đã đoạn tận,\nVị ấy được xứng danh,\nGọi là vị Tỷ-kheo.\n\n515. Vị trú xả, chánh niệm,\nTại bất cứ chỗ nào,\nVị không làm hại ai,\nCùng khắp cả thế giới,\nVượt bộc lưu, tịnh ý,\nKhông có bị dao động,\nVị nào không đột khởi,\nVị ấy gọi nhu hòa.\n\n516. Vị nào có các căn,\nÐược huấn luyện tu tập,\nCả nội và cả ngoại,\nTrong tất cả thế giới,\nVị nào thông suốt được\nÐời này và đời sau,\nÐúng thời, nghi điều phục,\nVị ấy gọi chế ngự.\n\n517. Ai phân tích các kiếp,\nToàn diện và hoàn toàn,\nLuân chuyển cả hai mặt,\nChết đi và sanh lại,\nBụi bặm được dứt sạch,\nKhông uế nhiễm, thanh tịnh,\nÐạt được sanh đoạn diệt,\nVị ấy gọi Phật-đà.`, ref: "Kinh Tập 3.6", url: "https://loicuaducphat.org/snp/snp3.6.html#content" },

{ text: `518. Sabhiya hỏi rằng:\nTôn giả Gotama,\nDo đạt được những gì,\nÐược gọi là Bà-la-môn?\nNhờ gì, gọi Sa-môn?\nThế nào là tắm sạch?\nVà phải như thế nào?\nÐược gọi là voi chúa?\nÐược con hỏi như vậy,\nMong Thế Tôn trả lời.\n\n519. Thế Tôn liền đáp lại:\nHỡi này Sabhiya,\nAi loại khỏi ra ngoài,\nTất cả các ác pháp,\nKhông uế, khéo định tĩnh,\nKiên trì, vững an trú,\nVượt qua được luân hồi,\nHoàn toàn về mọi mặt,\nKhông y chỉ vị ấy,\nÐược gọi Bà-la-môn.\n\n520. Ðược an tịnh, tịch tịnh,\nÐoạn tận cả thiện ác,\nKhông cấu uế, rõ biết,\nÐời này và đời sau,\nChế ngự và nhiếp phục,\nCả vấn đề sanh tử,\nVị đức tánh như vậy,\nÐược gọi là Sa-môn.\n\n521. Ai gột sạch, tắm sạch\nTất cả các ác pháp,\nKể cả trong lẫn ngoài,\nKhắp tất cả thế giới,\nGiữa chư Thiên, loài Người,\nBị thời kiếp chi phối,\nKhông rơi vào thời kiếp,\nÐược gọi đã tắm sạch.\n\n522. Ai không làm điều ác,\nMọi điều ác ở đời,\nTất cả các kiết sử,\nKhông dính mắc, trói buộc,\nKhắp tất cả mọi nơi,\nKhông dính, không trói buộc,\nVị đức tánh như vậy,\nÐược gọi là voi chúa.`, ref: "Kinh Tập 3.6", url: "https://loicuaducphat.org/snp/snp3.6.html#content" },

{ text: `523. Sabhiya hỏi rằng:\nTôn giả Gotama,\nThế nào chư Phật gọi\nVị chiến thắng đất ruộng,\nDo gì, gọi là thiện?\nThế nào gọi bậc trí,\nVà phải như thế nào\nÐược gọi là ẩn sĩ?\nÐược con hỏi như vậy,\nMong Thế Tôn trả lời.\n\n524. Thế Tôn bèn đáp lại:\nHỡi này Sabhiya,\nAi quán sát nhiếp phục,\nRuộng đất thật toàn diện\nChư Thiên và loài Người,\nLà đất ruộng Phạm thiên,\nGiải thoát được trói buộc,\nCội gốc mọi đất ruộng,\nVị đức tánh như vậy,\nÐược gọi thắng đất ruộng.\n\n525. Ai quán sát nhiếp phục,\nKho tàng thật toàn diện,\nChư Thiên và loài Người,\nLà đất ruộng Phạm thiên,\nGiải thoát được trói buộc,\nCội gốc mọi kho tàng,\nVị đức tánh như vậy,\nÐược gọi vị thiện xảo.\n\n526. Ai quán sát nhiếp phục,\nCả hai tâm và ý,\nCả nội và cả ngoại,\nVề trí tuệ thanh tịnh,\nNhiếp phục chế ngự được,\nCác pháp đen và trắng,\nVị đức tánh như vậy,\nÐược gọi bậc Hiền trí,\n\n527. Sau khi đã biết được,\nPháp bất thiện, pháp thiện,\nCả nội và cả ngoại,\nTrong tất cả thế giới,\nVị ấy được cúng dường,\nChư Thiên và loài Người,\nVượt qua lưới trói buộc,\nVị ấy gọi ẩn sĩ.`, ref: "Kinh Tập 3.6", url: "https://loicuaducphat.org/snp/snp3.6.html#content" },

{ text: `528. Sabhiya hỏi rằng:\nTôn giả Gotama,\nDo đạt được những gì\nÐược gọi bậc có trí?\nNhờ gì, gọi tùy trí?\nThế nào xưng tinh tấn?\nThế nào được danh xưng,\nLà vị đã thuần thục?\nÐược con hỏi như vậy,\nMong Thế Tôn trả lời.\n\n529. Thế Tôn liền đáp lại:\nHỡi này Sabhiya,\nDo quán sát, quán triệt,\nCác hý luận, danh sắc,\nKể cả nội và ngoại,\nVề cội gốc bệnh hoạn,\nVị ấy thoát trói buộc,\nCội gốc các bệnh hoạn,\nVị đức tánh như vậy\nÐược gọi vị rõ biết\n\n531. Vị ở đời từ bỏ\nTất cả các pháp ác,\nVới tinh tấn vượt qua,\nMọi khổ đau địa ngục,\nVị ấy có tinh tấn,\nCó tinh cần, siêng năng,\nVị đức tánh như vậy,\nÐược gọi vị có trí.\n\n532. Với ai các trói buộc,\nBị bựt đứt, huỷ hoại,\nNguồn gốc các tham ái,\nVị ấy được giải thoát,\nKhỏi tất cả gốc tham,\nVị đức tánh như vậy,\nÐược gọi vị thuần thục.`, ref: "Kinh Tập 3.6", url: "https://loicuaducphat.org/snp/snp3.6.html#content" },

{ text: `533. Sabhiya hỏi rằng:\nTôn giả Gotama,\nDo đạt được những gì,\nÐược gọi vị được nghe?\nNhờ gì, gọi bậc Thánh?\nSở hành như thế nào,\nNhư thế nào được tên,\nLà một người du sĩ?\nÐược con hỏi như vậy,\nMong Thế Tôn trả lời.\n\n534. Thế Tôn bèn đáp lại:\nHỡi này Sabhiya!\nDo ở đời được nghe,\nThắng tri tất cả pháp,\nPháp có lỗi, không lỗi,\nPhàm mọi pháp ở đời,\nLà vị đã chiến thắng,\nÐoạn nghi, được giải thoát,\nTrọn vẹn không dao động,\nÐược gọi, vị có nghe.\n\n535. Sau khi đoạn, chặt đứt,\nMọi lậu hoăc chấp trước,\nVị ấy sau khi biết\nKhông đi đến thai tạng,\nÐoạn trừ và từ bỏ,\nBa loại tưởng bùn nhơ,\nKhông đi vào thời kiếp,\nÐược gọi là bậc Thánh.\n\n536. Vị nào ở nơi đây,\nThành tựu các giới hạnh,\nThiện xảo mọi lãnh vực,\nRõ biết được Chánh Pháp,\nCùng khắp cả mọi nơi,\nKhông chấp trước, giải thoát,\nKhông sân hận một ai,\nÐược gọi là có hạnh.\n\n537. Ai không làm các nghiệp\nÐưa đến quả đau khổ\nPhía trên và phía dưới,\nBề ngang và chặng giữa,\nSống với sự liễu tri,\nTừ bỏ, không chấp nhận,\nMan trá và kiêu mạn,\nTham ái và phẫn nộ,\nLàm cho đến cùng tận,\nCả danh và cả sắc,\nVị này đã đạt được,\nTên gọi là du sĩ.`, ref: "Kinh Tập 3.6", url: "https://loicuaducphat.org/snp/snp3.6.html#content" },

{ text: `574. Sinh mạng của loài Người,\nỞ đời không ai biết,\nKhông tướng, nhiều phiền toái,\nNhỏ nhoi, liên hệ khổ.\n\n575. Không có sự gắng nào,\nKhiến sống thoát khỏi chết,\nSau khi già là chết,\nPháp hữu tình là vậy.\n\n576. Như các trái chín muồi,\nCó sợ bị rơi sớm,\nCũng vậy, người được sanh,\nThường có sợ bị chết.\n\n577. Như người thợ làm ghè\nLàm chén bát đất sét,\nCuối cùng, bể tất cả,\nMạng sống người là vậy.`, ref: "Kinh Tập 3.8", url: "https://loicuaducphat.org/snp/snp3.8.html#content" },

{ text: `578. Trẻ tuổi và lớn tuổi,\nNgười ngu và kẻ trí,\nTất cả đi đến chết,\nCuối cùng rồi cũng chết.\n\n579. Những ai chết chi phối,\nÐi qua đến đời sau,\nCha không cứu được con,\nHay bà con cứu nhau.\n\n580. Hãy xem, các bà con\nÐứng nhìn và than khóc,\nTừng người, đi đến chết,\nNhư bò mang đi giết,\n\n581. Như vậy, thế giới này\nBị già chết chi phối,\nDo vậy, bậc nhiều trí,\nBiết đời, nên không sầu`, ref: "Kinh Tập 3.8", url: "https://loicuaducphat.org/snp/snp3.8.html#content" },

{ text: `582. Ai không biết con đường,\nÐường đến và đường đi,\nDo không thấy hai ngã,\nThan khóc, không lợi ích.\n\n583. Nếu thật sự than khóc,\nÐem lại lợi ích gì,\nKẻ ngu tự hại mình,\nNgười có mắt sẽ làm.\n\n584. Không với sầu, nước mắt,\nKhiến nội tâm an tịnh,\nKhổ càng tăng trưởng thêm,\nThân càng bị gia hại.\n\n585. Ốm yếu, sắc da tái,\nTự mình hại chính mình,\nKẻ chết không được hộ,\nThan khóc thật vô ích.\n\n586. Chúng sanh không bỏ sầu,\nCàng gặp nhiều đau khổ,\nCàng rên khóc kẻ chết,\nCàng bị sau chi phối.`, ref: "Kinh Tập 3.8", url: "https://loicuaducphat.org/snp/snp3.8.html#content" },

{ text: `587. Hãy xem các người khác\nÐi theo hạnh nghiệp mình,\nRơi vào giới thần chết,\nHữu tình đầy hoảng sợ.\n\n588. Loài Người còn mong ước,\nThế này hay thế khác,\nNhưng sự việc xảy ra,\nHoàn toàn thật sai khác,\nNhư vậy tánh không có,\nXem định tánh của đời.\n\n589. Nếu loài Người sống được,\nSống hơn một trăm năm,\nRồi không có bà con,\nỞ đây, bỏ mạng sống.\n\n590. Do vậy, sau khi nghe\nBậc La-hán thuyết giảng,\nHãy nhiếp phục than van,\nKhi thấy kẻ bị chết,\nHãy suy nghĩ như sau,\nTa không còn vị ấy.`, ref: "Kinh Tập 3.8", url: "https://loicuaducphat.org/snp/snp3.8.html#content" },

{ text: `591. Như nhà lửa bị cháy,\nNhờ nước, lửa dập tắt,\nCũng vậy, bậc Hiền trí,\nCó tuệ trí, thiện xảo,\nmau chóng nhiếp phục sầu,\nNhư bông gió thổi bay.\n\n592. Ai tự tìm hạnh phúc,\nHãy tự mình rút tên,\nMũi tên là than khóc,\nTham cầu tư ưu sầu.\n\n593. Ai đã rút mũi tên,\nKhông nương tựa nhờ cậy,\nTâm vị ấy đạt được,\nSự an lành an tịnh,\nVượt khỏi mọi ưu sầu,\nTâm không sầu, tịch tịnh.`, ref: "Kinh Tập 3.8", url: "https://loicuaducphat.org/snp/snp3.8.html#content" },

{ text: `Và Ta không có gọi,\nKẻ ấy Bà-la-môn.\nChỉ vì do thọ sanh,\nDầu vị ấy cao sang,\nDầu vị ấy giàu có,\nNhưng còn ham thế lợi.\nKhông tham lam thế lợi,\nKhông chấp thủ sở hữu,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nVị đoạn tận kiết sử,\nKhông ai không sợ hãi,\nSiêu việt mọi chấp trước,\nThoát ly các hệ phược,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.`, ref: "Kinh Tập 3.9", url: "https://loicuaducphat.org/snp/snp3.9.html#content" },

{ text: `Cắt dây thừng, dây ách,\nDây cương, cùng dây trói,\nQuăng đi cây chắn ngang,\nKẻ ấy Ta mới gọi,\nBậc sáng suốt, giác ngộ,\nChánh danh Bà-la-môn.\n\nAi không lỗi, chịu đựng,\nNhiếc mắng cùng đánh trói,\nTrang bị với nhẫn lực,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nKhông phẫn nộ, giữ luật,\nCó giới hạnh không kiêu,\nNhiếp phục thân tối hậu,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nNhư nước trên lá sen,\nHột cải trên đỉnh nhọn,\nKhông tham luyến dục vọng,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.`, ref: "Kinh Tập 3.9", url: "https://loicuaducphat.org/snp/snp3.9.html#content" },

{ text: `Ai biết ngay đời này\nKhổ vì ngã đoạn tận,\nGánh nặng được đặt xuống,\nXa lìa các hệ phược,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nTuệ thâm sâu, có trí\nThiện xảo đạo phi đạo,\nÐích tối thượng đạt được,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nAi không còn liên hệ,\nCả tại gia, xuất gia,\nKhông nhà trú, thiểu dục,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.`, ref: "Kinh Tập 3.9", url: "https://loicuaducphat.org/snp/snp3.9.html#content" },

{ text: `Bỏ gậy đối chúng sanh,\nKẻ yếu cùng kẻ mạnh,\nKhông giết, không hại ai,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nGiữa kẻ thù, không thù,\nGiữa hung bạo, an tịnh,\nGiữa chấp thủ, không chấp,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nDối, tham, sân, mạn, phú,\nAi bỏ rơi được chúng,\nNhư hột cải rơi khỏi.\nÐầu nhọn của mũi kim,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.`, ref: "Kinh Tập 3.9", url: "https://loicuaducphat.org/snp/snp3.9.html#content" },

{ text: `Ai dạy thật nhỏ nhẹ,\nNói lên lời chơn thực,\nKhông xúc phạm một ai,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nDài ngắn hay lớn nhỏ,\nThanh tịnh hay bất tịnh,\nỞ đời vật dài ngắn,\nLớn, nhỏ, tịnh, bất tịnh,\nKhông lấy vật không cho,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nVới ai không tham cầu,\nÐời này và đời sau,\nTừ bỏ mọi tham cầu,\nÐoạn rời mọi hệ phược,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nAi không có chấp tàng,\nVới trí đoạn nghi hoặc,\nÐạt nhập đáy bất tử.\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.`, ref: "Kinh Tập 3.9", url: "https://loicuaducphat.org/snp/snp3.9.html#content" },

{ text: `Ở đời ai vượt khỏi,\nMọi buộc ràng thiện ác,\nKhông sầu, không bụi uế,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nAi không uế, thanh tịnh,\nKhông gợn, sáng như trăng,\nHỷ, hữu được đoạn trừ,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nAi vượt qua hiểm lộ,\nÁc lộ, luân hồi, si,\nVượt khỏi, đến bờ kia,\nThiền tư, không dao động,\nÐoạn trừ mọi nghi hoặc,\nAn tịnh, không chấp trước,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nỞ đời, bỏ dục vọng,\nKhông nhà, sống xuất gia,\nÐoạn trừ dục và hữu,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.`, ref: "Kinh Tập 3.9", url: "https://loicuaducphat.org/snp/snp3.9.html#content" },

{ text: `Ở đời, bỏ tham ác,\nKhông nhà, sống xuất gia,\nÐoạn trừ ác và hữu,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nAi từ bỏ nhân ách,\nVượt qua cả thiên ách,\nÐoạn trừ mọi ách nạn,\nThoát ly mọi hệ phược,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nTừ bỏ lạc, bất lạc,\nThanh lương, không y trú,\nChiến thắng mọi thế giới,\nBậc anh hùng dũng mãnh,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nAi không có chấp trước,\nÐời trước, sau, đời này,\nKhông chấp, không sở hữu,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.\n\nAi biết được đời trước,\nThấy được thiện, ác thú,\nÐạt được sanh diệt đoạn,\nKẻ ấy Ta mới gọi,\nChánh danh Bà-la-môn.`, ref: "Kinh Tập 3.9", url: "https://loicuaducphat.org/snp/snp3.9.html#content" },

{ text: `Ðiều thế giới cho gọi,\nLà “tên” và “gia tộc”,\nChỉ tục danh, thông danh\nDanh từ khởi nhiều chỗ.\n\nÐã lâu đời chấp trước,\nTà kiến của kẻ ngu,\nKẻ ngu tự tuyên bố,\nBà-la-môn do sanh.\n\nKhông phải do sanh đẻ,\nÐược gọi Bà-la-môn,\nKhông phải do sanh đẻ,\nGọi phi Bà-la-môn;\nChính do sự hành động\nÐược gọi Bà-la-môn,\nChính do sự hành động\nGọi phi Bà-la-môn.\n\nHành động làm nông phu,\nHành động làm công thợ,\nHành động làm lái buôn,\nHành động làm nô bộc.\n\nHành động làm ăn trộm,\nHành động làm nhà binh.\nHành động làm tế quan,\nHành động làm vua chúa.\n\nKẻ trí thấy hành động,\nNhư thật là như vậy.\nThấy rõ lý duyên khởi,\nBiết rõ nghiệp dị thục.\n\nDo nghiệp, đời luân chuyển\nDo nghiệp, người luân hồi;\nNghiệp trói buộc chúng sanh,\nNhư trục xe quay bánh.\n\nDo khổ hạnh, Phạm hạnh,\nTiết chế và chế ngự,\nTác thành Bà-la-môn.\nBà-la-môn như vậy,\nMới thật là tối thượng,`, ref: "Kinh Tập 3.9", url: "https://loicuaducphat.org/snp/snp3.9.html#content" },

{ text: `657. Phàm con người đã sanh,\nSanh với búa trong miệng,\nKẻ ngu khi nói bậy,\nTự chặt đứt lấy mình.\n\n658. Ai khen kẻ đáng chê,\nAi chê người đáng khen,\nTự chất chứa bất hạnh,\nDo lỗ miệng của mình,\nChính do bất hạnh ấy,\nNên không được an lạc.\n\n661. Kẻ nói không chân thật,\nÐi đến cõi địa ngục,\nAi tự mình có làm,\nLại nói: "Tôi không làm",\nCả hai sau khi chết,\nÐều được xem đồng đẳng,\nHành động họ hạ liệt,\nÐời sau, đồng làm người.\n\n662. Ai khởi lên ác tâm,\nÐối người không ác ý,\nÐối người sống thanh tịnh,\nKhông có gì uế nhiễm,\nÁc ấy trở lui lại,\nÐến với kẻ ngu ấy,\nNhư bụi bặm nhỏ nhiệm\nQuăng ngược chiều gió thổi.`, ref: "Kinh Tập 3.10", url: "https://loicuaducphat.org/snp/snp3.10.html#content" },

{ text: `700. Không nhà, con đi đến\nTìm hạnh người khất sĩ,\nCon hỏi bậc ẩn sĩ\nHãy nói lên cho con,\nCon đường đạo tối thượng,\nÐưa đến đạo Mâu-ni,\n\nThế Tôn đáp như sau:\n701. Khó hành, khó thực hiện,\nLà đạo hạnh Mâu ni,\nTa sẽ cho Ông biết,\nHãy đến lắng tai nghe,\nTa sẽ nói cho Ông,\nHãy vững trí, an thần,\nHãy kiên trì bền chí.\n\n702. Hãy tu hạnh Sa-môn,\nKhông để bị dao động,\nGiữa khen chê trong làng,\nHãy chế ngự tâm sân,\nSống hạnh thật an tịnh,\nKhông cống cao kiêu mạn.\n\n703. Tiếng cao thấp phát ra,\nNhư ngọn lửa trong vườn,\nNữ nhân hay cám dỗ,\nChớ cám dỗ ẩn sĩ.\n\n704. Hãy từ bỏ dâm dục,\nXả mọi dục cao thấp.\nÐối hữu tình yếu mạnh,\nKhông đối nghịch, tham đắm.\n\n705. Ta thế nào, họ vậy,\nHọ thế nào, Ta vậy,\nLấy ngã làm ví dụ,\nChớ giết, chớ bảo giết.`, ref: "Kinh Tập 3.11", url: "https://loicuaducphat.org/snp/snp3.11.html#content" },

{ text: `706. Hãy bỏ dục, bỏ tham,\nÐây phàm phu bị nắm,\nBậc có mắt hành đạo,\nVượt địa ngục, loài Người.\n\n707. Bụng đói, ăn chừng mực,\nÍt dục, không tham lam.\nVị ấy không ham dục,\nKhông dục, thật tịch tịnh.\n\n708. Sau khi đi khất thực,\nẨn sĩ vào rừng sâu,\nÐi đến dưới gốc cây,\nSửa soạn ngồi an tịnh.\n\n709. Bậc Hiền trí hành thiền,\nHoan hỷ trong rừng sâu,\nHành thiền dưới gốc cây,\nThỏa mãn sở thích mình.`, ref: "Kinh Tập 3.11", url: "https://loicuaducphat.org/snp/snp3.11.html#content" },

{ text: `710. Khi đêm hết, sáng đến,\nCần phải đi đến làng,\nChớ hân hoan khất thực,\nÐồ mang từ làng đi.\n\n711. Ẩn sĩ không đi gấp,\nÐến làng, giữa gia đình,\nTìm ăn, cắt nói chuyện,\nKhông nói chuyện liên hệ.\n\n712. Nếu được, thật là tốt,\nKhông được, cũng là tốt,\nNghĩ vậy, cả hai mặt,\nVị ấy trở về cây.\n\n713. Ði với bát cầm tay,\nKhông câm, dáng như câm,\nChớ khinh, đồ cho ít,\nKhông chê người đem cho.\n\n714. Bậc Sa-môn thuyết giảng,\nCon đường cao và thấp,\nNhưng đến bờ bên kia,\nKhông có hai con đường,\nTuy vậy chớ nghĩ rằng,\nÐường này chỉ là một.`, ref: "Kinh Tập 3.11", url: "https://loicuaducphat.org/snp/snp3.11.html#content" },

{ text: `715. Với ai, không có tham,\nTỷ-kheo cắt dòng nước,\nÐoạn tận hành thiện ác,\nVị ấy không sầu não.\n\n716. Thế Tôn lại nói thêm:\nTa dạy cho các Ông\nThức tri hạnh ẩn sĩ,\nHãy tu như lưỡi dao,\nVới lưỡi ấn nóc họng,\nHãy hạn chế bao tử.\n\n717. Tâm chớ có thụ động,\nNhưng chớ nghĩ quá nhiều.\nKhông hôi hám, độc lập,\nSống cứu cánh Phạm hạnh\n\n718. Hãy tập ngồi một mình,\nSống đúng hạnh Sa-môn.\nSống một mình được gọi\nLà hạnh bậc ẩn sĩ,\nNếu tự mình tìm được\nThoải mái trong cô độc.\n\n719. Hãy chói sáng mười phương,\nSau khi nghe tiếng nói,\nCủa các bậc hiền sĩ,\nHãy hành thiền, bỏ dục,\nMong đệ tử của Ta,\nTăng trưởng tâm và tín.`, ref: "Kinh Tập 3.11", url: "https://loicuaducphat.org/snp/snp3.11.html#content" },

{ text: `720. Hãy học các dòng nước,\nTừ khe núi vực sâu.\nNước khe núi chảy ồn,\nBiển lớn động im lặng.\n\n721. Cái gì trống kêu to,\nCái gì đầy yên lặng,\nNgu như ghè vơi nước,\nBậc trí như ao đầy.\n\n722. Khi Sa-môn nói nhiều,\nNói liên hệ đến đích,\nTự biết nên thuyết pháp,\nTự biết nên nói nhiều.\n\n723. Ai biết, biết tự chế,\nAi biết, không nói nhiều,\nVị ấy là ẩn sĩ,\nXứng đáng hạnh ẩn sĩ,\nVị ấy là ẩn sĩ,\nÐạt được hạnh ẩn sĩ.`, ref: "Kinh Tập 3.11", url: "https://loicuaducphat.org/snp/snp3.11.html#content" },

{ text: `724. Ai không tuệ tri khổ,\nVà hiện hữu của khổ,\nVà chỗ khổ hoàn toàn\nÐược đoạn tận không dư,\nVị ấy không biết đường,\nÐưa đến khổ an tịnh.\n\n725. Không có tâm giải thoát,\nKhông có tuệ giải thoát,\nVị ấy không có thể\nÐoạn tận sanh và già.\n\n726. Những ai tuệ tri khổ\nVà hiện hữu của khổ\nVà chỗ khổ hoàn toàn\nÐược đoạn tận không dư,\nVị ấy biết con đường,\nÐưa đến khổ an tịnh.\n\n727. Ðầy đủ tâm giải thoát,\nVới trí tuệ giải thoát,\nNhững vị ấy có thể\nVới trí tuệ giải thoát,\nÐoạn tận sanh và già.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `728. Chính do duyên sanh y,\nCác khổ được sanh khởi,\nTất cả các khổ đau,\nSai biệt ở trên đời,\nAi chính do vô minh\nTạo lên sự sanh y,\nKẻ ngu ấy gặp khổ\nNối tiếp nhau sanh trưởng,\nDo vậy vị hiểu biết,\nKhông tạo lên sanh y,\nTuỳ quán được hiện hữu\nCủa sanh và của khổ.\n\n729. Những ai tiếp tục rơi,\nDòng luân chuyển sanh tử,\nÐến hữu này hữu khác,\nSanh thú do vô minh.\n\n730. Vô minh này, đại si,\nÐưa đến luân chuyển dài,\nChúng sanh, minh đạt được,\nKhông còn phải tái sanh.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `731. Phàm khổ gì hiện hữu,\nTất cả duyên các hành,\nDo đoạn diệt các hành,\nKhổ không có hiện hữu.\n\n732. Do biết nguy hiểm này,\nKhổ do duyên các hành,\nTịnh chỉ tất cả hành,\nDo phá hoại các tưởng,\nNhư vậy, khổ được diệt,\nBiết như thực là vậy.\n\n733. Bậc Hiền trí chánh kiến,\nHiểu biết, với chánh trí,\nNhiếp phục Ma kiết sử,\nKhông đi đến tái sanh.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `734. Phàm khổ gì hiện hữu,\nTất cả do duyên thức,\nVới thức được đoạn diệt,\nKhổ không có hiện hữu.\n\n735. Do biết nguy hiểm hày,\nKhổ do duyên các thức,\nTỷ-kheo tịnh chỉ thức,\nKhông dục ái, tịch tịnh.\n\n736. Những ai, xúc chi phối,\nChạy theo dòng sanh hữu,\nNhững người hành tà đạo,\nXa vời diệt kiết sử.\n\n737. Những ai liễu tri xúc,\nNhờ trí, thích an tịnh,\nDo họ thắng tri xúc,\nKhông dục ái, tịch tịnh.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `738. Với lạc thọ, khổ thọ,\nHay bất khổ, bất lạc;\nNội thọ và ngoại thọ,\nPhàm có cảm thọ gì.\n\n739. Biết được đây là khổ,\nGiả dối bị hủy hoại.\nThấy các xúc hoại diệt,\nNhư vậy, đây ly tham,\nTỷ-kheo diệt các thọ,\nKhông dục ái, tịch tịnh.\n\n740. Người có ái bạn đường,\nBị luân chuyển dài dài,\nÐến hữu này, hữu khác,\nLuân chuyển không dừng nghỉ.\n\n741. Do biết nguy hiểm nầy,\nChính ái tác thành khổ,\nLy ái, không chấp thủ,\nChánh niệm, Tỷ-kheo hành.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `747. Phàm khổ gì hiện hữu,\nTất cả duyên thức ăn,\nDo đoạn diệt thức ăn,\nKhổ không có hiện hữu.\n\n748. Do biết nguy hiểm này,\nKhổ do duyên thức ăn,\nLiễu tri mọi thức ăn,\nKhông y mọi thức ăn.\n\n749. Nhờ chánh trí không bệnh,\nÐoạn diệt các lậu hoặc,\nThọ dụng các thức ăn,\nGiác sát, trú Chánh pháp,\nVị đạt được trí tuệ,\nKhông rơi vào ước lượng.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `750. Phàm khổ gì hiện hữu,\nTất cả duyên dao động,\nDo đoạn diệt dao động,\nKhổ không có hiện hữu.\n\n751. Do biết nguy hiểm này,\nKhổ do duyên dao động,\nDo vậy, bỏ dao động,\nChận dừng lại các hành,\nKhông có gì chướng ngại\nKhông chấp thủ, chánh niệm,\nVị Tỷ-kheo bộ hành,\nKhắp tất cả chân trời.\n\n752. Không nương tựa, không động,\nNương tựa có chấp thủ,\nChấp hữu này, hữu khác,\nKhông chinh phục luân chuyển.\n\n753. Sau khi rõ biết được,\nNguy hiểm tai hại nầy,\nTrong các sự nương tựa,\nCó sợ hãi lớn lao,\nKhông nương tựa y chỉ,\nKhông chấp thủ, chánh niệm,\nVị Tỷ-kheo bộ hành,\nKhắp tất cả chân trời.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `756. Hãy xem thế giới nầy,\nVới thế giới chư Thiên,\nHoan hỷ với phi ngã,\nAn trú trên danh sắc,\nNghĩ rằng danh sắc này\nLà chân thật không ngụy.\n\n757. Dầu họ nghĩ thế nào,\nKhi danh sắc đổi khác,\nDanh sắc là hư vọng,\nGiả dối sống tạm bợ,\n\n758. Niết-bàn không hư ngụy,\nBậc Thánh chân thật biết,\nHọ thắng tri chân thật,\nKhông ái dục, tịch tịnh.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `759. Sắc, tiếng, hương, vị, xúc,\nTất cả những pháp này,\nKhả lạc, hỷ, khả ý,\nKhi nào chúng hiện hữu.\n\n760. Thế giới với chư Thiên\nXem chúng là khả lạc,\nKhi chúng bị hoại diệt,\nMới thấy chúng là khổ.\n\n761. Bậc Thánh thấy là lạc,\nKhi có thân đoạn diệt,\nÐây hoàn toàn trái ngược,\nÐiều mọi giới được thấy.\n\n762. Ðiều người khác gọi lạc,\nBậc Thánh gọi là khổ,\nÐiều người khác gọi khổ,\nBậc Thánh biết là lạc,\n\n765. Bậc thiện, được rộng mở,\nBậc thấy, được ánh sáng,\nAi ngoài các bậc Thánh,\nXứng đáng đạo chánh giác.\nDo chánh trí đạo ấy\nChứng vô lậu Niết-bàn.`, ref: "Kinh Tập 3.12", url: "https://loicuaducphat.org/snp/snp3.12.html#content" },

{ text: `766. Ai ao ước được dục,\nNếu dục được thành tựu,\nChắc tâm ý hoan hỷ,\nÐược điều con người muốn.\n\n767. Nếu người có dục ấy,\nƯớc muốn được sanh khởi,\nCác dục ấy bị diệt,\nBị khổ như tên đâm.\n\n768. Ai tránh né các dục\nNhư chân tránh đầu rắn,\nChánh niệm vượt thoát được,\nÁi triền này ở đời.\n\n769. Người nào tham đắm dục,\nRuộng đất, vàng, bò, ngựa,\nNgười nô tỳ, phục vụ,\nNữ nhân và bà con.\n\n770. Như người không sức lực,\nBị các dục chinh phục,\nTai họa dẫm đạp nó,\nKhổ đau bước theo nó,\nNhư nước ùa tràn vào,\nChiếc thuyền bị vỡ nát.\n\n771. Do vậy người thường niệm,\nTừ bỏ các loài dục,\nBỏ dục, vượt bộc lưu,\nTát thuyền đến bờ kia.`, ref: "Kinh Tập 4.1", url: "https://loicuaducphat.org/snp/snp4.1.html#content" },

{ text: `772. Chúng sanh vào trong hang,\nChấp chặt bị bao trùm,\nNgười có thái độ vậy,\nChìm sâu trong si mê.\nHạnh viễn ly với nó,\nNhư vậy thật xa vời,\nCác dục ở trong đời,\nKhông dễ gì đoạn tận.\n\n773. Dục cầu làm nhân duyên,\nBị lạc hữu trói buộc,\nHọ rất khó giải thoát,\nKhông thể có người khác,\nÐến giải thoát cho mình,\nHọ cầu việc đã qua,\nHọ mong việc chưa lại;\nHọ tham đắm các dục,\nNhững dục này hiện tại,\nVà những dục quá khứ.`, ref: "Kinh Tập 4.2", url: "https://loicuaducphat.org/snp/snp4.2.html#content" },

{ text: `774. Ai tham đắm các dục,\nBị trí buộc si mê,\nHọ xan tham keo kiết.\nAn trú trên bất chánh,\nKhi rơi vào đau khổ,\nHọ sầu muộn than khóc,\nỞ đây sau khi chết,\nTương lai sẽ thế nào?\n\n775. Do vậy ở tại đây,\nCon người cần học tập,\nNhững gì mình biết được,\nLà bất chánh ở đời.\nDo nhân duyên như vậy,\nMà sống không bất chánh,\nVì rằng bậc Thánh nói:\nNgắn thay, sanh mạng này.`, ref: "Kinh Tập 4.2", url: "https://loicuaducphat.org/snp/snp4.2.html#content" },

{ text: `776. Ta thấy ở trên đời,\nLoài Người run, sợ hãi,\nÐi đến khát ái này,\nTrong những loại sanh hữu.\nPhàm những người thấp kém,\nThan van trước miệng chết,\nChưa viễn ly khát ái,\nÐối với hữu, phi hữu.\n\n777. Hãy nhìn những người ấy,\nRun sợ trong tự ngã,\nNhư cá chỗ ít nước,\nTrong dòng sông khô cạn,\nThấy được sự kiện này,\nHãy sống không của ta,\nKhông làm sự việc gì,\nKhiến tham đắm các hữu.`, ref: "Kinh Tập 4.2", url: "https://loicuaducphat.org/snp/snp4.2.html#content" },

{ text: `778. Hãy nhiếp phục ước muốn,\nÐối với hai cực đoan,\nNhờ liễu tri các xúc,\nKhông còn có tham đắm,\nCái gì tự ngã trách,\nCái ấy không có làm,\nBậc trí không bị nhớp,\nBởi những gì thấy nghe.\n\n779. Do liễu tri các tưởng,\nVượt qua khỏi bộc lưu,\nBậc Mâu-ni không nhiễm,\nÐối với mọi chấp thủ,\nVới mũi tên rút ra,\nSở hành không phóng dật,\nKhông cầu mong đời này,\nKhông mong ước đời sau.`, ref: "Kinh Tập 4.2", url: "https://loicuaducphat.org/snp/snp4.2.html#content" },

{ text: `780. Thật có một số người\nNói lên với ác ý,\nVà thật cũng có người,\nNói lên ý chân thật.\nDầu có lời nói gì,\nẨn sĩ không liên hệ,\nDo vậy bậc Mâu-ni,\nKhông chỗ nào hoang vu.\n\n782. Người không có ai hỏi,\nLại nói cho người khác,\nBiết đến những giới cấm,\nCủa tự cá nhân mình.\nBậc thiện xảo nói rằng,\nNhư vậy không Thánh pháp,\nNếu ai tự nói lên\nLời tán thán tự ngã.\n\n783. Vị Tỷ-kheo an tịnh,\nSống hết sức tịch tịnh,\nKhi tán thán giới đức,\nKhông nói "Tôi là vậy".\nBậc thiện xảo nói rằng\nNhư vậy là Thánh pháp\nVới vị ấy đề cao,\nỞ đời, không khởi lên.\n\n786. Vị tẩy sạch loại bỏ,\nKhông tìm được ở đời,\nCác kiến được sửa soạn,\nÐối với hữu, phi hữu.\nBỏ man trá, kiêu mạn,\nVị tẩy sạch loại bỏ,\nVị ấy đi với gì,\nVị ấy không chấp thủ.\n\n787. Với ai có chấp thủ,\nBị chỉ trích trong Pháp,\nVới ai không chấp thủ,\nLấy gì có thể nói?\nChính đối với vị ấy,\nNgã, phi ngã đều không,\nVị ấy đã tẩy sạch,\nMọi tà kiến ở đời.`, ref: "Kinh Tập 4.3", url: "https://loicuaducphat.org/snp/snp4.3.html#content" },

{ text: `791. Từ bỏ tri kiến cũ,\nY chỉ tri kiến mới,\nÐi đến sự tham đắm,\nKhông vượt qua ái dục;\nHọ nắm giữ chấp trước,\nHọ từ bỏ xa lánh,\nNhư khỉ thả cành này,\nRồi lại nắm cành khác,\n\n792. Người tự mình chấp nhận,\nCác chủng loại giới cấm,\nÐi chỗ cao chỗ thấp,\nSống bị tưởng chi phối;\nNgười có trí rộng lớn,\nNhờ trí tuệ, quán pháp,\nCó trí, không đi đến\nCác pháp cao và thấp.\n\n793. Vị ấy đạt thù thắng,\nTrong tất cả các pháp,\nPhàm có điều thấy, nghe,\nHay cảm thọ, tưởng đến;\nVới vị tri kiến vậy,\nSống đời sống rộng mở,\nKhông bị ai ở đời,\nCó thể chi phối được.\n\n794. Họ không tác thành gì,\nHọ không đề cao gì,\nHọ không có nói lên,\nÐây tối thắng thanh tịnh,\nKhông dính líu tham đắm,\nMọi chấp trước triền phược,\nHọ không tạo tham vọng,\nBất cứ đâu ở đời.\n\n795. Với vị Bà-la-môn\nÐã vượt khỏi biên giới,\nSau khi biết và thấy,\nKhông có kiến chấp trước.\nTham ái không chi phối,\nCũng không tham, ly tham,\nVị ấy ở đời này,\nKhông chấp thủ gì khác.`, ref: "Kinh Tập 4.4", url: "https://loicuaducphat.org/snp/snp4.4.html#content" },

{ text: `796. Ai thiên trú trong kiến,\nXem kiến ấy tối thắng,\nỞ đời đặt kiến ấy,\nVào địa vị tối thượng.\nNgười ấy nói tất cả,\nNgười khác là hạ liệt,\nDo vậy không vượt khỏi,\nSự tranh luận ở đời.\n\n797. Khi nó thấy lợi ích,\nÐến với tự ngã nó,\nÐối với vật thấy nghe,\nGiới đức hay thọ tưởng;\nVị ấy ở tại đấy,\nLiền chấp trước nắm giữ,\nNó thấy mọi người khác,\nLà hạ liệt thấp kém.\n\n798. Người y chỉ kiến ấy,\nThấy người khác hạ liệt,\nBậc thiện nói như vậy,\nÐấy là sự trói buộc;\nDo vậy đối thấy nghe,\nThọ, tưởng hay giới cấm,\nBậc Tỷ-kheo không có\nY chỉ, nương tựa vào.\n\n799. Chớ có tác thành ra\nTri kiến ở trên đời,\nTừ ở nơi chánh trí,\nHay từ nơi giới đức,\nKhông bận tâm so sánh,\nTự ngã bằng người khác,\nKhông có suy nghĩ đến,\nÐây "liệt " hay đây "thắng".\n\n800. Ðoạn tận, từ bỏ ngã,\nKhông chấp thủ sự gì,\nKhông tác thành, dựng nên,\nNương tựa ở nơi trí,\nChân thật giữa tranh chấp\nKhông theo phe phái nào,\nVị ấy không đi theo\nMột loại tri kiến nào.`, ref: "Kinh Tập 4.5", url: "https://loicuaducphat.org/snp/snp4.5.html#content" },

{ text: `801. Với ai, hay cực đoan,\nKhông có hướng nguyện gì,\nVới hữu và phi hữu,\nHay đời này đời sau,\nVị ấy không an trú,\nTại một trú xứ nào,\nTừ bỏ mọi chấp thủ,\nÐối với tất cả pháp.\n\n802. Ðối vị ấy ở đây,\nNhững gì được thấy nghe,\nÐược cảm thọ tưởng đến,\nChút suy tưởng cũng không;\nVị Bà-la-môn ấy\nKhông chấp thủ tri kiến,\nKhông ai ở đời này\nCó thể chi phối được.\n\n803. Họ không tác thành gì,\nHọ không đề cao gì,\nCác pháp không được họ,\nChấp trước nắm giữ gì\nKhông một Phạm chí nào,\nBị giới cấm dắt dẫn,\nÐi đến bờ bên kia,\nVị ấy không trở lui.`, ref: "Kinh Tập 4.5", url: "https://loicuaducphat.org/snp/snp4.5.html#content" },

{ text: `804. Sinh mạng này ngắn thay,\nTrong trăm năm, rồi chết,\nNếu ai sống hơn nữa,\nRồi cũng chết vì già.\n\n805. Loài Người sầu vì ngã,\nMọi chấp thủ vô thường,\nTrống không là đời này,\nThấy vậy sống không nhà.\n\n806. Vì loài Người nghĩ rằng\nCái này là của tôi,\nCái ấy bị sự chết,\nLàm hoại diệt hư tàn.\nBiết vậy, bậc Hiền trí,\nKhông gọi, không hướng đến,\nCái này ngã của ta,\nCái này là của ta.\n\n807. Như những gì hiện lên,\nTrong giấc ngủ mộng mị,\nCon người khi tỉnh dậy,\nKhông còn thấy được gì.\nCũng vậy ở đời này,\nNgười được ưa, ái luyến,\nRồi sẽ chết mất đi,\nKhông ai còn thấy được.\n\n808. Các loại hạng người ấy\nÐược thấy và được nghe,\nNên họ được gọi tên,\nTên này hay tên khác.\nVới người đã chết đi,\nChỉ được gọi tên không,\nVì chỉ có tên suông,\nSẽ được còn tồn tại.\n\n809. Tham đắm cái của ta,\nHọ không có từ bỏ,\nSầu khổ và than van,\nCùng xan tham keo kiết.\nDo vậy bậc ẩn sĩ,\nSau khi bỏ chấp thủ,\nÐã sống một đời sống,\nThấy được sự an ổn.`, ref: "Kinh Tập 4.6", url: "https://loicuaducphat.org/snp/snp4.6.html#content" },

{ text: `810. Ðối với vị Tỷ-kheo\nSống thanh vắng một mình,\nSống tu tập tâm ý,\nHướng đến hạnh viễn ly,\nNếp sống vậy được nói,\nHòa hợp với vị ấy,\nVà không nêu tự ngã,\nTrong hiện hữu của mình.\n\n811. Vị ẩn sĩ không tựa,\nKhông y chỉ một ai,\nKhông làm thành thương yêu,\nKhông tác thành ghét bỏ.\nDo vậy trong sầu than,\nTrong xan tham keo kiết,\nNhư nước trên lá cây,\nKhông dính ướt làm nhơ.\n\n812. Giống như một giọt nước,\nKhông dính ướt hoa sen,\nNhư nước trên bông sen,\nKhôn dính ướt làm nhơ.\nÐối với vật thấy nghe,\nÐược cảm thọ tưởng đến,\nCũng vậy bậc ẩn sĩ\nKhông dính ướt tham đắm.\n\n813. Do vậy bậc tẩy sạch,\nKhông có suy tư đến,\nÐiều được thấy được nghe,\nÐược cảm thọ tưởng đến.\nVị ấy muốn thanh tịnh,\nKhông có dựa gì khác,\nVị ấy không tham đắm,\nCũng không có ly tham.`, ref: "Kinh Tập 4.6", url: "https://loicuaducphat.org/snp/snp4.6.html#content" },

{ text: `815. Ai đắm say dâm dục,\nQuên mất lời giảng dạy,\nRơi vào đường tà vạy,\nNếp sống ấy không thánh.\n\n816. Ai trước sống một mình,\nNay rơi vào dâm dục,\nNhư xe bị nghiêng ngã,\nNgười ấy ở trong đời,\nÐược gọi là phàm phu,\nÐược gọi là hạ liệt.\n\n817. Tiếng tốt có từ trước,\nNgười ấy bị tổn giảm,\nThấy vậy hãy học tập,\nTừ bỏ sự dâm dục.\n\n818. Chi phối bởi suy tư,\nTrầm ngâm như kẻ nghèo,\nNghe tiếng trách người khác,\nNhư kẻ bị thất vọng.\n\n819. Bị người khác buộc tội,\nNó làm các đao kiếm,\nTrở thành người tham lớn,\nChấp thủ điều vọng ngôn.\n\n820. Ðược danh là Hiền trí,\nAn trú sống một mình,\nNếu rơi vào dâm dục,\nSầu não như kẻ ngu.\n\n821. Thấy nguy hại như vậy,\nBậc ẩn sĩ trước sau,\nKiên trì sống cô độc,\nKhông thực hành dâm dục.\n\n822. Hãy học tập viễn ly,\nÐây hạnh thánh tối thượng,\nKhông nghĩ mình tối thắng,\nDầu gần được Niết-bàn.\n\n823. Sở hành bậc ẩn sĩ,\nTrống không, không mong dục,\nBậc vượt khỏi bộc lưu,\nÐược các người ở đời,\nBị tham dục trói buộc,\nGanh tị và thèm muốn.`, ref: "Kinh Tập 4.7", url: "https://loicuaducphat.org/snp/snp4.7.html#content" },

{ text: `825. Những ai muốn tranh luận,\nSau khi vào hội chúng,\nHọ công kích lẫn nhau,\nHọ gọi nhau là ngu,\nHọ đi đến người khác,\nVà khởi lên tranh luận,\nHọ muốn được tán thán,\nHọ gọi chúng thiện xảo.\n\n826. Ham mê thích tranh luận,\nỞ giữa các hội chúng,\nƯớc muốn được tán thán,\nHọ sợ hãi thất bại,\nKhi bị đánh thất bại,\nHọ trở thành rủn chí,\nBị chê, họ nổi giận,\nKẻ tìm lỗi người khác.\n\n828. Giữa các vị Sa-môn,\nCác tranh luận khởi lên,\nTrong các tranh luận này,\nCó chiến thắng chiến bại.\nDo thấy rõ như vậy,\nKhông vui thích tranh luận\nDầu có được tán thán,\nCũng không lợi ích gì.\n\n829. Hay trong tranh luận này,\nNó được lời tán thán,\nSau khi đã nói lên,\nChính giữa các hội chúng.\nDo vậy nó vui cười,\nNó tự hào kiêu hãnh,\nÐạt được mục đích ấy,\nNhư tâm ý nói lên.\n\n830. Cái làm nó cống cao,\nCũng là đất hại nó,\nTuy vậy nó vẫn nói,\nLời cống cao kiêu mạn,\nKhi thấy được như vậy,\nHãy đừng có tranh luận,\nBậc thiện xảo nói rằng,\nThanh tịnh không do vậy.\n\n832. Những ai chấp tri kiến,\nTranh luận về kiến ấy,\nTuyên bố thuyết giảng rằng:\nChỉ đây là sự thật,\nÔng hãy nói với họ,\nỞ đây không tranh luận,\nÔng hãy nói thêm rằng\nỞ đây không địch thủ.\n\n834. Vậy Ông hãy đi đến,\nSuy tư ngẫm nghĩ kỹ,\nVới tâm ý suy tư,\nTrên những loại tri kiến,\nHãy hoà đồng chung hợp,\nVới bậc đã tẩy sạch,\nÔng không có thể không\nCùng vị ấy tiến bước.`, ref: "Kinh Tập 4.8", url: "https://loicuaducphat.org/snp/snp4.8.html#content" },

{ text: `Thế Tôn:\n835. Sau khi thấy khát ái,\nBất lạc và tham đắm,\nKhông thể có ưa muốn,\nÐối với sự dâm dục.\nSao, với bao đầy tràn,\nNước tiểu, phân uế này,\nTa không có ước muốn,\nVới chân động chạm nó.`, ref: "Kinh Tập 4.9", url: "https://loicuaducphat.org/snp/snp4.9.html#content" },

{ text: `839. Không phải từ tri kiến,\nTừ truyền thống, từ trí,\nKhông phải từ giới cấm,\nThanh tịnh được đem đến.\nNgười ta nói như vậy,\nNhưng cũng không phải là\nKhông kiến, không truyền thống,\nKhông trí, không giới cấm,\nTừ bỏ tất cả chúng,\nKhông chấp thủ sự gì,\nBậc thiện không y chỉ,\nKhông ước muốn sanh hữu.\n\n842. Bằng ta thắng hơn ta,\nHay thấp kém hơn ta,\nAi suy nghĩ như vậy,\nDo vậy đấu tranh khởi,\nAi không bị dao động\nBởi ba vấn đề ấy,\nNhư vậy, đối vị ấy,\nKhông bằng, không thù thắng.`, ref: "Kinh Tập 4.9", url: "https://loicuaducphat.org/snp/snp4.9.html#content" },

{ text: `844. Ðoạn tận mọi nhà cửa,\nSống là kẻ không nhà,\nẨn sĩ không thân thiết,\nVới một ai ở làng,\nTrống không các dục vọng,\nKhông xem trọng sự gì,\nKhông nói chuyện tranh luận,\nVới một ai ở đời.\n\n845. Vị ấy sống viễn ly,\nMọi sự việc ở đời,\nBậc Long tượng không chấp,\nVà không nói đến họ.\nNhư hoa sen có gai,\nSanh ra ở trong nước,\nKhông bị nước và bùn,\nMắc dính và thấm ướt.\nNhư vậy bậc ẩn sĩ,\nNói an tịnh, không tham,\nKhông bị dục và đời,\nMắc dính và thấm ướt.`, ref: "Kinh Tập 4.9", url: "https://loicuaducphat.org/snp/snp4.9.html#content" },

{ text: `846. Bậc trí, không do kiến,\nCũng không do thọ tưởng,\nÐi đến sự kiêu mạn,\nKhông có tham dự vào,\nKhông để cho hành động,\nCho truyền thống dắt dẫn,\nKhông để bị chi phối,\nTrong trú xứ của ý.\n\n847. Người không ưa thích tưởng,\nKhông có bị trói buộc,\nVị được tuệ giải thoát,\nKhông có sự si mê,\nVà những ai chấp thủ,\nTư tưởng và tri kiến,\nNgười ấy sống xung đột,\nVới mọi người ở đời.`, ref: "Kinh Tập 4.9", url: "https://loicuaducphat.org/snp/snp4.9.html#content" },

{ text: `848. Người sống đời an tịnh,\nKiến và giới thế nào?\nCon hỏi Gotama,\nLà bậc người tối thượng.\n\nThế Tôn:\n850. Không phẫn nộ, không sợ,\nKhông khoa đại, không hối,\nNói hòa nhã, không động,\nBậc ẩn sĩ thận ngôn.\n\n851. Không ước vọng tương lai,\nKhông sầu muộn quá khứ,\nThấy viễn ly giữa xúc,\nKhông để kiến dắt dẫn.\n\n852. Sống riêng, không man trá,\nKhông thích, không xan tham,\nKhông xông xáo nhàm chán,\nKhông đi đến hai lưỡi.\n\n853. Không mê vật khả ái,\nCũng không có quá mạn,\nNhu hòa, nhưng ứng biện,\nKhông vọng tín, không tham.\n\n854. Không tu tập vì lợi,\nKhông được lợi, không sân,\nKhông bị ái kích thích,\nKhông đam mê các vị.\n\n855. Thường trú xả, chánh niệm,\nỞ đời, không nghĩ mình,\nBằng hơn hay thua người,\nVị ấy, không bồng bột.\n\n856. Không y chỉ một ai,\nBiết pháp, không y chỉ,\nVị ấy không có ái,\nÐối với hữu, phi hữu.`, ref: "Kinh Tập 4.10", url: "https://loicuaducphat.org/snp/snp4.10.html#content" },

{ text: `857. Ta gọi vị an tịnh,\nKhông mong cầu các dục,\nVị ấy không triền phược,\nVượt khỏi các tham trước.\n\n858. Vị ấy không con cái,\nThú vật, ruộng, đất đai,\nKhông có gì nắm lấy,\nLà ta, là không ta.\n\n859. Phàm phu có buộc tội,\nHoặc Sa-môn, Phạm chí,\nVị ấy không quan tâm,\nTrong lời nói không động,\n\n860. Không tham, không xan lẫn,\nẨn sĩ không nói cao,\nKhông nói bằng, nói thấp,\nKhông đi đến thời kiếp,\nVì vị ấy vượt khỏi,\nSự chi phối thời kiếp.\n\n861. Ai không có vật gì,\nKhông có, không sầu muộn,\nKhông đi đến các pháp,\nVị ấy gọi an tịnh.`, ref: "Kinh Tập 4.10", url: "https://loicuaducphat.org/snp/snp4.10.html#content" },

{ text: `Người hỏi:\n862. Từ đâu được khởi lên,\nCác tranh luận, đấu tranh,\nThan van và sầu muộn,\nCùng với tánh xan tham,\nMạn và tăng thượng mạn,\nKể cả với hai lưỡi,\nTừ đâu chúng sanh nhiều,\nMong Ngài hãy nói lên.\n\nThế Tôn:\n863. Từ ái sanh khởi nhiều,\nCác tranh luận, đấu tranh\nThan van và sầu muộn,\nCùng với tánh xan tham,\nMạn và tăng thượng mạn,\nKể cả với hai lưỡi,\nCác tranh luận, đấu tranh,\nÐều liên hệ xan tham,\nNhững lời nói hai lưỡi,\nKhởi lên từ tranh luận.`, ref: "Kinh Tập 4.11", url: "https://loicuaducphat.org/snp/snp4.11.html#content" },

{ text: `Người hỏi:\n864. Do những nhân duyên nào,\nKhả ái sanh ở đời?\nHay những tham lam nào,\nÐược lưu hành ở đời?\nƯớc vọng và thành đạt,\nLà do nhơn duyên nào?\nKhiến loài Người được sanh,\nTrong thời gian tương lai?\n\nThế Tôn:\n865. Do ước muốn là nhân,\nKhả ái sanh ở đời,\nHay với những tham lam,\nÐược lưu hành ở đời,\nƯớc vọng và thành đạt,\nDo ước muốn làm nhân,\nKhiến loài Người được sanh,\nTrong thời gian tương lai.\n\nNgười hỏi:\n866. Ước muốn sanh ở đời\nLà do nhân duyên nào?\nHay cả những quyết định,\nDo nhân nào được sanh?\nPhẫn nộ và vọng ngữ,\nCùng với cả nghi hoặc,\nHoặc là những pháp nào,\nÐược Sa-môn nói đến?\n\nThế Tôn:\n867. Khả ý, bất khả ý,\nÐược gọi vậy ở đời,\nDo y chỉ nơi chúng,\nƯớc muốn được sanh khởi.\nSau khi thấy trong sắc,\nCả hữu và phi hữu,\nChúng sanh mới làm được,\nNhững quyết định ở đời.\n\n868. Phẫn nộ và vọng ngữ,\nCùng với cả nghi hoặc,\nNhững pháp này lưu hành,\nKhi pháp đôi có mặt,\nKẻ nghi hãy học tập,\nTrên con đường chánh trí,\nSau khi biết các pháp,\nDo Sa-môn thuyết giảng.`, ref: "Kinh Tập 4.11", url: "https://loicuaducphat.org/snp/snp4.11.html#content" },

{ text: `Người hỏi:\n869. Khả ý, bất khả ý,\nLà do nhân duyên nào,\nDo cái gì không có,\nHọ không có hiện hữu.\nCòn về ý nghĩa này,\nVề phi hữu và hữu,\nHãy nói cho chúng con,\nNguyên nhân gì chúng sanh?\n\nThế Tôn:\n870. Do nhân duyên cảm xúc,\nKhả ý, bất khả ý,\nNếu không có cảm xúc,\nHọ cũng không hiện hữu,\nCòn về ý nghĩa này,\nVề phi hữu và hữu,\nTa nói cho Ông rõ,\nNguyên nhân này, chúng sanh.\n\nNgười hỏi:\n871. Còn cảm xúc ở đời,\nDo nhân gì sanh khởi,\nHay các loại chấp thủ,\nDo từ đâu sanh nhiều,\nDo cái gì không có,\nNgã sở hữu không có,\nCái gì không hiện hữu,\nKhiến không có cảm xúc?\n\nThế Tôn:\n872. Do duyên danh và sắc,\nNên có các cảm xúc,\nDo nhân các ước muốn,\nNên có những chấp thủ,\nNếu ước muốn không có,\nNgã sở hữu cũng không,\nDo sắc không hiện hữu,\nKhiến không có cảm xúc.`, ref: "Kinh Tập 4.11", url: "https://loicuaducphat.org/snp/snp4.11.html#content" },

{ text: `Người hỏi:\n873. Sở hành như thế nào,\nSắc pháp không hiện hữu,\nAn lạc và khổ đau,\nThế nào không có mặt,\nHãy nói lên cho con,\nKhông có như thế nào,\nChúng con muốn được biết,\nTâm ý con nói vậy.\n\nThế Tôn:\n874. Không có tưởng các tưởng,\nKhông có tưởng vô tưởng,\nPhi tưởng cũng không có,\nVô hữu tưởng cũng không.\nDo sở hành như vậy,\nSắc pháp không hiện hữu,\nDo nhân duyên các tưởng,\nHý luận được hình thành.\n\n877. Biết được những pháp ấy,\nÐều nương tựa y chỉ,\nBiết vậy bậc ẩn sĩ,\nSuy tư trên y chỉ,\nBiết được, nên giải thoát,\nKhông đi đến tranh luận,\nBậc Hiền không tìm đến,\nCả hữu và phi hữu.`, ref: "Kinh Tập 4.11", url: "https://loicuaducphat.org/snp/snp4.11.html#content" },

{ text: `Người hỏi:\n878. Mỗi người tự thiên chấp,\nVề tri kiến của mình,\nDo chấp thủ sai biệt,\nBậc thiện xảo nói lên,\nAi biết như thế này,\nVị ấy biết được pháp,\nAi chỉ trích điểm này,\nVị ấy không hoàn toàn.\n\n879. Do chấp thủ như vậy,\nHọ tranh luận với nhau,\nHọ nói kẻ khác ngu.\nKhông có khéo thiện xảo.\nTrong những lời nói này,\nLời nói ai chân thật,\nHay tất cả vị này,\nLà những bậc khéo nói?\n\nThế Tôn:\n880. Nếu không có chấp thuận,\nPháp của các người khác,\nNói kẻ khác là ngu,\nTuệ như vậy thấp kém.\nTất cả là ngu si,\nCó tuệ thật thấp kém.\nTất cả tri kiến này.\nÐều chỉ là thiên chấp.\n\n881. Nếu các cuộc tranh luận,\nÐược tri kiến gạn lọc,\nTrí tuệ được thanh tịnh,\nThiện xảo trí sáng suốt,\nHọ không có một ai,\nLà trí tuệ hạ liệt,\nVà tri kiến của họ,\nÐược hoàn toàn viên mãn.\n\n882. Ta không có nói rằng:\n"Ðây chính là sự thật".\nCác người ngu với nhau,\nCùng nhau nói như vậy,\nVới tri kiến tự mình,\nHọ nói là chân thật,\nDo vậy các người khác,\nÐược họ xem là ngu.`, ref: "Kinh Tập 4.12", url: "https://loicuaducphat.org/snp/snp4.12.html#content" },

{ text: `Người hỏi:\n883. Một số người nói rằng:\n"Ðây mới là sự thật"\nHọ nói các người khác,\nLà trống không, giả dối,\nDo chấp thủ như vậy,\nHọ tranh luận đấu tranh,\nVì sao bậc Sa-môn,\nKhông cùng nói một lời?\n\nThế Tôn:\n884. Sự thật chỉ có một,\nKhông sự thật thứ hai,\nNgười hiểu biết tranh luận,\nVới người có hiểu biết,\nNhưng chân thật họ khen,\nChỉ sự thật của họ,\nDo vậy bậc Sa-môn,\nKhông cùng nói một lời.`, ref: "Kinh Tập 4.12", url: "https://loicuaducphat.org/snp/snp4.12.html#content" },

{ text: `Người hỏi:\n885. Vì sao họ nói lên,\nNhững chân thật sai khác,\nVì sao bậc thiện xảo,\nLại nói lời tranh luận,\nNếu các sự thật ấy,\nLà nhiều và sai biệt,\nHay họ chỉ nhớ đến,\nNhững suy luận của họ.\n\nThế Tôn:\n886. Thật sự các sự thật,\nKhông có nhiều sai biệt,\nTừ các luồng tư tưởng,\nVề thường còn ở đời,\nDo họ suy nghĩ đến,\nTư tưởng các tri kiến,\nHọ nói có hai pháp,\nSự thật và giả dối.\n\n887. Các pháp được thấy nghe,\nÐược giữ giới, thọ tưởng,\nHọ y cứ pháp này,\nHọ suy tư, nhìn thấy,\nAn trú các quyết định,\nHọ chê cười người khác,\nHọ nói các người khác,\nLà ngu si bất thiện.\n\n888. Vì rằng đối người khác,\nNó xem là ngu si,\nTự mình gọi chính mình,\nLà thiện xảo tốt đẹp,\nDo chính mình khen mình,\nVị ấy gọi thiện xảo,\nKhinh thường các người khác,\nLời người ấy là vậy.\n\n889. Vị ấy quá say mê,\nVới tri kiến của mình,\nNên trở thành kiêu mạn,\nViên mãn tự ý mình,\nTự mình với tâm ý,\nLàm lễ quán đảnh mình,\nDo vậy, bị say mê,\nTrong tri kiến của mình.\n\n894. An trú trên quyết định,\nTự mình lượng sức người\nVị ấy ở trên đời,\nChỉ tăng thêm tranh luận,\nAi từ bỏ tất cả,\nMọi quyết định, chủ trương,\nKhông bị người ở đời,\nChê là kẻ liệt tuệ.`, ref: "Kinh Tập 4.12", url: "https://loicuaducphat.org/snp/snp4.12.html#content" },

{ text: `Người hỏi:\n915. Con hỏi bậc Ðại tiên,\nBậc bà con mặt trời,\nCon đường đến viễn ly,\nCon đường đến an tịnh,\nTỷ-kheo sau khi thấy,\nLàm thế nào mát lạnh,\nKhông có sự chấp thủ,\nMột vật gì ở đời?\n\nThế Tôn:\n916. Thế Tôn đáp như sau:\nHãy chặt đứt hoàn toàn,\nGốc rễ các hý luận,\nMọi tư tưởng "tôi là ",\nTất cả phải chấm dứt,\nPhàm có nội ái nào,\nSau khi nhiếp phục chúng,\nThường chánh niệm học tập.\n\n917. Phàm có loại pháp gì,\nÐược thắng tri hoàn toàn,\nHoặc thuộc về nội pháp,\nHay thuộc về ngoại pháp,\nChớ có làm kiên trì,\nBất cứ một pháp nào,\nTrạng thái ấy không gọi,\nSự mát lạnh của tịnh.\n\n918. Chớ có nghĩ như sau:\nCái kia là tốt hơn,\nÐây là hạ liệt hơn,\nHay đây là ngang bằng,\nDo phải bị xúc chạm,\nVới các sắc sai biệt,\nHãy chớ để tự mình,\nAn trú trên vọng tưởng.\n\n919. Hãy giữ được an tịnh,\nVề phía tự nội tâm,\nTỷ-kheo không cầu tìm,\nAn tịnh từ chỗ khác,\nVới người được an tịnh,\nTừ phía tự nội tâm,\nÐã không có tự ngã,\nTừ đâu có vô ngã.\n\n920. Như chính giữa trung ương,\nCủa biển cả đại dương,\nSóng biển không có sanh,\nBiển hoàn toàn đứng lặng,\nCũng vậy, này Tỷ-kheo\nHãy đứng lặng không động,\nKhông tạo nên bồng bột,\nÐối sự gì ở đời.`, ref: "Kinh Tập 4.14", url: "https://loicuaducphat.org/snp/snp4.14.html#content" },

{ text: `Người hỏi:\n921. Vị có mắt rộng mở\nÐã tuyên bố rõ ràng,\nPháp có thể chế ngự,\nMọi nguy hiểm khó khăn,\nBậc Hiền thiện mong Ngài,\nTuyên bố rõ con đường,\nHay về biệt giải thoát,\nHoặc về pháp thiền định?\n\nThế Tôn:\n922. Chớ có những con mắt,\nÐầy dẫy những tham đắm!\nHãy chận đứng lỗ tai,\nNghe câu chuyện của làng.\nLại chớ nên đắm say,\nCác mùi vị ngon lành,\nChớ xem là của ta,\nMọi sự vật ở đời!\n\n923. Trong khi được cảm giác,\nVới các loại cảm xúc,\nTỷ-kheo không than van,\nBất cứ một điều gì.\nVị ấy không cầu mong,\nDầu lại sanh hữu nào,\nVà không có run sợ,\nRơi vào các kinh hoàng.\n\n924. Các đồ ăn thâu được,\nCùng với các đồ uống,\nCác món ăn nhai được,\nCác đồ vải mặc được,\nChớ có cất chứa chúng,\nNhững đồ vật nhận được,\nChớ có quá lo âu,\nNếu không thâu được chúng.\n\n925. Hãy tu tập thiền định\nChớ làm kẻ lang thang,\nChớ ưa thích trạo cử,\nÐừng rơi vào phóng dật,\nÐối với các chỗ ngồi,\nCùng với các chỗ nằm,\nTỷ-kheo hãy an trú,\nNhững chỗ không tiếng động.\n\n926. Ngủ nghỉ có chừng mực,\nChớ có ngủ quá nhiều,\nHãy luôn luôn tỉnh thức,\nNỗ lực và nhiệt tâm,\nHãy từ bỏ biếng nhác,\nMan trá, cười, chơi đùa,\nHãy từ bỏ dâm dục,\nBỏ ưa thích trang điểm.`, ref: "Kinh Tập 4.14", url: "https://loicuaducphat.org/snp/snp4.14.html#content" },

{ text: `928. Tỷ-kheo không run sợ,\nKhi bị người chỉ trích,\nCũng không có cống cao,\nKhi được khen tán thán,\nHãy từ bỏ tham ái,\nCùng với tánh xan tham,\nKể luôn cả phẫn nộ,\nCùng với nói hai lưỡi.\n\n929. Tỷ-kheo không an trú,\nTrong nghề nghiệp bán buôn,\nLại không có chỉ trích,\nBất cứ tại chỗ nào,\nKhi ở tại thôn làng,\nKhông tức giận một ai,\nChớ có vì lợi dưỡng,\nNói chuyện với quần chúng.\n\n930. Tỷ-kheo không nên nói,\nKhoa trương quá mức độ,\nVà cũng không nói lời\nCó dụng ý lợi dưỡng.\nChớ có học tập theo,\nLối sỗ sàng trâng tráo,\nChớ có thốt ra lời\nKhiêu khích xung đột ai!\n\n931. Chớ có bị dắt dẫn,\nRơi vào lời nói láo,\nKhông cố ý làm nên,\nÐiều man trá giả dối,\nChớ có khinh người khác,\nVề vấn đề sinh mạng,\nVề vấn đề trí tuệ,\nVà vấn đề giới hạnh.\n\n932. Sau khi phẫn uất nghe\nNhiều ngôn từ lời lẽ\nCủa các vị Sa-môn,\nHay những kẻ phàm phu,\nChớ có phản ứng họ,\nVới những lời thô ác,\nBậc hiền lành an tịnh,\nKhông phản pháo một ai.\n\n933. Sau khi rõ biết được\nPháp này là như vậy,\nTỷ-kheo hãy học tập,\nSáng suốt và chánh niệm,\nRõ biết sự mát lạnh,\nÐược gọi bậc "an tịnh ",\nChớ có sống phóng dật,\nTrong lời dạy Cù-đàm.\n\n934. Bậc đã được chiến thắng,\nKhông ai chiến thắng nổi\nTự mình thấy được pháp,\nKhông nghe theo tin đồn,\nDo vậy hãy học tập\nLuôn luôn không phóng dật,\nVới tâm tư cung kính,\nLời dạy đức Thế Tôn,\nThế Tôn nói như vậy.`, ref: "Kinh Tập 4.14", url: "https://loicuaducphat.org/snp/snp4.14.html#content" },

{ text: `940. Ở đây sự học tập,\nÐã được nói rõ lên,\nPhàm triền phược ở đời,\nChớ liên hệ với chúng,\nÐâm thủng dục hoàn toàn,\nTự học tập Niết-bàn.\n\n941. Chân thật không xông xáo,\nKhông man trá, hai lưỡi,\nKhông phẫn nộ, ẩn sĩ,\nVượt tham ác, xan tham.\n\n942. Người nghĩ đến Niết-bàn,\nBỏ ngủ, nhác, thụy miên,\nKhông sống với phóng dật,\nKhông an trú, quá mạn.\n\n943. Không rơi vào nói láo,\nKhông tham ái các sắc,\nCần liễu tri quá mạn,\nSống từ bỏ bạo ác.\n\n944. Không hoan hỷ việc cũ,\nKhông nhẫn chịu sự mới,\nTrong tổn giảm không sầu,\nKhông liên hệ tham ái,\n\n945. Ái, Ta gọi bộc lưu,\nMong cầu gọi bọt nước,\nSở duyên gọi biến kể,\nBùn dục khó vượt qua.\n\n946. Ẩn sĩ không rời chân,\nPhạm chí trú đất liền,\nVị từ bỏ tất cả,\nThật được gọi an tịnh.\n\n947. Biết vậy, gọi người biết,\nBiết rồi không y pháp,\nChơn chánh sống ở đời,\nKhông tham ái một ai.`, ref: "Kinh Tập 4.15", url: "https://loicuaducphat.org/snp/snp4.15.html#content" },

{ text: `948. Ai ở đây vượt dục,\nÁi khó vượt ở đời,\nKhông sầu, không tham muốn,\nCắt dòng không trói buộc.\n\n949. Trước Ông làm khô cạn\nSau Ông không vật gì,\nỞ giữa không nắm giữ,\nÔng sẽ sống an tịnh.\n\n950. Toàn diện đối danh sắc,\nKhông gì nghĩ "của ta"\nKhông có gì không sầu,\nKhông có già ở đời.\n\n951. Không nghĩ "đây của tôi ",\nKhông nghĩ "đây của người ",\nNgười không có tự ngã,\nKhông sầu vì không ngã.\n\n952. Không tàn bạo, không tham,\nKhông dục, thường đồng đẳng,\nÐược hỏi Ta nói lên,\nLợi ích bậc bất động.\n\n953. Bậc ly dục rõ biết,\nVị ấy không sở hành,\nThoát ly, không tinh cần,\nThấy an ổn khắp nơi.\n\n954. Bậc ẩn sĩ, không nói,\nBằng nhau, thua, hơn nhau,\nAn tịnh, ly xan tham,\nKhông nhận, không bác bỏ.\nThế Tôn giảng như vậy.`, ref: "Kinh Tập 4.15", url: "https://loicuaducphat.org/snp/snp4.15.html#content" },

{ text: `957. Bậc Giác ngộ, độc lập,\nNhư thật, không man trá,\nNgài đến ở đời này,\nLãnh đạo các đồ chúng,\nTừ nhiều người trói buộc,\nCon đến với câu hỏi.\n\n958. Vị Tỷ kheo nhàm chán,\nSống an tọa, trống không,\nTại gốc cây, nghĩa địa,\nHay núi rừng hang sâu.\n\n959. Tại chỗ cao thấp ấy,\nCó bao nhiêu sợ hãi,\nKhiến Tỷ kheo không run,\nTại trú xứ vắng lặng?\n\n960. Bao nguy hiểm ở đời,\nTỷ Kheo cần chinh phục,\nTrong hướng đi bất tử,\nTại trú xứ xa vắng?\n\n961. Ngôn ngữ và hành xứ\nCủa vị ấy là gì?\nCó bao nhiêu giới cấm,\nTỷ Kheo cần tinh tấn?\n\n962. Chấp nhận học tập gì,\nVị Tỷ Kheo nhất tâm,\nThông minh, giữ chánh niệm,\nTẩy sạch các cấu uế,\nTrên tự ngã của mình,\nNhư thợ lọc vàng bạc?`, ref: "Kinh Tập 4.16", url: "https://loicuaducphat.org/snp/snp4.16.html#content" },

{ text: `963. Này Sàriputta,\nThế Tôn bèn trả lời:\nVới người biết nhàm chán,\nCó gì là khoan khoái!\nKhi sử dụng sàng tọa,\nTại chỗ tịnh trống không,\nVới ai muốn giác ngộ,\nSống đúng với tùy pháp,\nTa sẽ nói người ấy,\nNhư Ta đã quán tri.\n\n964. Vị Tỷ kheo có trí,\nChánh niệm sống biên địa,\nKhông có sợ năm điều,\nÐáng sợ hãi ở đời.\nCác loại ruồi, mối bay\nCùng các loài bò sát,\nXúc chạm của loài người,\nCùng các loại bốn chân.\n\n965. Vị ấy không nên sợ,\nTri kiến của người khác,\nKhi đã được thấy biết,\nNhiều sợ hãi của chúng,\nBậc tìm đến chí thiện,\nThấy được các nguy hiểm\nCần phải lo khắc phục\nTất cả nguy hiểm khác.`, ref: "Kinh Tập 4.16", url: "https://loicuaducphat.org/snp/snp4.16.html#content" },

{ text: `966. Khi thọ lãnh bệnh hoạn,\nKhi cảm xúc đói khổ,\nVới lạnh và cực nóng,\nCần phải nhiếp phục chúng,\nBị chúng cảm xúc nhiều,\nKẻ không bỏ nhà cửa\nCần tinh tấn cần mẫn,\nLòng hết sức kiên trì.\n\n967. Chớ ăn trộm, ăn cắp,\nChớ nói lời nói láo,\nHãy cảm xúc từ tâm,\nÐối kẻ yếu, kẻ mạnh,\nKhi rõ biết tâm tư,\nTrong tình trạng dao động,\nHãy gột sạch, tẩy sạch,\nPhần hắc ám đen tối.\n\n968. Chớ để bị chi phối,\nBởi phẫn nộ, quá mạn,\nHãy đào chúng tận gốc,\nVà an trú như vậy,\nÐối những gì khả ái,\nHay đối không khả ái,\nHãy hoàn toàn nhiếp phục,\nChớ để bị chi phối.\n\n969. Thiên trọng về trí tuệ,\nHoan hỷ trong chí thiện,\nHãy chận đứng loại bỏ,\nNguy hiểm ách nạn ấy,\nHãy khắc phục bất lạc,\nÐối trú xứ vắng lặng,\nHãy khắc phục bốn pháp,\nKhiến sầu muộn khóc than.`, ref: "Kinh Tập 4.16", url: "https://loicuaducphat.org/snp/snp4.16.html#content" },

{ text: `970. Ta sẽ ăn những gì,\nVà được ăn tại đâu.\nThật khó khăn ta ngủ,\nNay ta ngủ tại đâu?\nVới những tư tưởng ấy,\nVị ấy có thể than,\nBậc hữu học, không nhà,\nHãy nhiếp phục trừ chúng.\n\n971. Với đồ ăn, vải mặc,\nÐúng thời, thâu hoạch được,\nCần ước lượng vừa đủ,\nVới mục đích thỏa mãn,\nChế ngự đối với chúng,\nSống nhiếp phục trong lòng,\nDầu phẫn uất, không nói,\nNhững lời độc thô ác.\n\n972. Với mắt cúi nhìn xuống,\nChân không đi lang thang,\nChú tâm vào thiền định,\nVới rất nhiều tỉnh giác,\nCố gắng tu tập xả,\nTự ngã khéo định tĩnh,\nHãy cắt đứt trừ khử,\nCác nghi ngờ hối tiếc.\n\n973. Bị buộc tội bằng lời,\nChánh niệm, tâm hoan hỉ,\nPhá hoại sự cứng rắn,\nGiữa các đồng Phạm hạnh,\nNói lên những lời nói,\nHiền thiện và đúng thời,\nKhông để tâm suy tư,\nCác chủ thuyết người khác.`, ref: "Kinh Tập 4.16", url: "https://loicuaducphat.org/snp/snp4.16.html#content" },

{ text: `974. Lại nữa, năm loại vua,\nHiện có ở trên đời,\nHãy học nhiếp phục chúng.\nLuôn luôn giữ chánh niệm.\nÐối với sắc và tiếng,\nÐối với vị và hương,\nCùng đối các cảm xúc,\nHãy chế ngự tham ái.\n\n975. Hãy chế ngự ước muốn,\nÐối với những pháp ấy,\nVị Tỷ kheo chánh niệm,\nTâm tư khéo giải thoát,\nRồi đúng thời vị ấy,\nChơn chánh suy tư pháp,\nVới chuyên tâm nhất trí,\nHãy đoạn tận hắc ám.\nThế Tôn nói như vậy.`, ref: "Kinh Tập 4.16", url: "https://loicuaducphat.org/snp/snp4.16.html#content" },

{ text: `Tôn Giả Ajita:\n1032. Do gì, đời bị che,\nDo gì, không chói sáng,\nHãy nói lên cái gì,\nLàm uế nhiễm cuộc đời,\nCái gì sợ hãi lớn?\n\nThế Tôn đáp Ajita:\n1033. Ðời bị vô minh che,\nDo xan tham, phóng dật,\nÐời không được chói sáng,\nTa nói do mong cầu,\nNên đời bị uế nhiễm,\nChính là sự đau khổ,\nNên có sợ hãi lớn.`, ref: "Kinh Tập 5.2", url: "https://loicuaducphat.org/snp/snp5.2.html#content" },

{ text: `Tôn Giả Ajita:\n1034. Mọi nơi dòng nước chảy,\nCái gì ngăn dòng nước?\nHãy nói lên cái gì?\nChế ngự được dòng nước?\nCái gì đóng dòng nước?\n\nThế Tôn:\n1035. Các dòng nước ở đời,\nChánh niệm ngăn chận lại,\nChánh niệm được Ta gọi,\nChế ngự các dòng nước,\nVà chính do trí tuệ,\nÐóng lại các dòng nước.`, ref: "Kinh Tập 5.2", url: "https://loicuaducphat.org/snp/snp5.2.html#content" },

{ text: `Tôn Giả Ajita:\n1036. Trí tuệ và chánh niệm,\nCùng với danh và sắc,\nKính thưa bậc Tôn giả,\nHãy nói điều con hỏi,\nTừ đâu chúng bị diệt?\n\nThế Tôn:\n1037. Câu hỏi gì Ông hỏi,\nHỡi này A-ji-ta,\nTa sẽ đáp cho Ông,\nChỗ nào danh và sắc,\nÐược đoạn diệt hoàn toàn,\nKhông còn lại dư tàn,\nChính do đoạn diệt thức,\nDanh sắc được đoạn diệt.`, ref: "Kinh Tập 5.2", url: "https://loicuaducphat.org/snp/snp5.2.html#content" },

{ text: `Tôn Giả Ajita:\n1038. Những ai biết tư sát,\nCác pháp thuộc hữu vi,\nCùng với bậc hữu học,\nVà phàm phu ở đời,\nÐược hỏi, Ngài hãy nói,\nVề nếp sống của họ?\nBậc thận trọng sáng suốt,\nHãy nói lên, thưa Ngài!\n\nThế Tôn:\n1039. Chớ tham đắm các dục,\nGiữ tâm tư an tịnh,\nThiện xảo trong các pháp,\nTỷ-kheo giữ chánh niệm,\nSống đời sống xuất gia.`, ref: "Kinh Tập 5.2", url: "https://loicuaducphat.org/snp/snp5.2.html#content" },

{ text: `Tôn Giả Tissametteyya:\n1040. Ai thỏa mãn ở đời,\nVới ai không dao động,\nAi thắng tri hai biên,\nỞ giữa, không dính líu,\nAi Ngài gọi đại nhân,\nỞ đời, ai vượt khỏi,\nThêu dệt các ái nhiễm?\n\nThế Tôn đáp Tissametteyya:\n1041. Giữa dục, sống Phạm hạnh,\nKhông ái, luôn chánh niệm,\nTỷ-kheo lặng tính toán,\nAn tịnh, không dao động.\n\n1042. Ai thắng tri hai biên,\nChặng giữa, nhờ suy tư,\nKhông dính líu bị nhiễm,\nTa gọi là đại nhân,\nVị ấy, ở đời này,\nVượt khỏi sự thêu dệt,\nCác ái nhiễm tham muốn.`, ref: "Kinh Tập 5.3", url: "https://loicuaducphat.org/snp/snp5.3.html#content" },

{ text: `Tôn Giả Mettagu:\n1049. Con xin hỏi Thế Tôn,\nMong Thế Tôn trả lời,\nVấn đề con đã hỏi,\nCon nghĩ Ngài hiền trí,\nTự ngã đã tu tập,\nTừ đâu, ở trong đời,\nÐau khổ này khởi lên,\nVới nhiều loại như vậy?\n\nThế Tôn đáp Mettagu:\n1050. Ông hỏi ta vấn đề,\nSanh khởi của khổ đau,\nTa sẽ nói cho Ông,\nNhư Ta đã được biết,\nChính do duyên sanh y,\nNên khổ được khởi lên,\nVới nhiều loại như vậy,\nKhác biệt ở trong đời.\n\n1051. Những ai vì vô minh,\nTác thành các sanh y,\nKẻ ngu tạo đau khổ,\nTiếp tục được sanh khởi,\nDo vậy kẻ hiểu biết,\nKhông nên tạo sanh y,\nVì thấy sự sanh khởi,\nCủa sanh và đau khổ.`, ref: "Kinh Tập 5.5", url: "https://loicuaducphat.org/snp/snp5.5.html#content" },

{ text: `Tôn Giả Mettagu:\n\n1052. Ðiều chúng con đã hỏi,\nNgài đã đáp chúng rồi,\nNay xin hỏi câu khác,\nMong Ngài giải đáp cho,\nThế nào bậc Hiền trí,\nVượt khỏi dòng nước mạnh,\nVượt khỏi sanh và già,\nCùng sầu muộn than khóc,\nMong rằng bậc ẩn sĩ,\nHãy khéo trả lời con,\nÐúng như Ngài đã biết,\nPháp nhĩ là như vậy?\n\nThế Tôn:\n\n1053. Ta sẽ nói cho Ông,\nPháp thiết thực hiện tại,\nKhông do trao truyền lại,\nSau khi biết pháp ấy,\nVị ấy sống chánh niệm,\nVượt tham ái ở đời.\n\n1055. Phàm Ông rõ biết gì,\nTrên dưới, ngang ở giữa,\nHãy từ bỏ hoan hỷ,\nHãy từ bỏ trú xứ,\nChớ để cho ý thức,\nAn trú trên sanh hữu.\n\n1056. An trú vậy, chánh niệm,\nTỷ-kheo không phóng dật,\nSau khi bỏ sở hành,\nÐưa đến ngã, sở hữu.\nÐối với sanh và già,\nSầu muộn và than khóc,\nỞ đây, biết được vậy,\nHãy từ bỏ đau khổ.\n\n1059. Vị Bà-la-môn nào,\nÐược thắng tri, có trí,\nKhông có sở hữu gì,\nKhông ái luyến dục hữu,\nChắc chắn vị như vậy,\nVượt qua bộc lưu này,\nÐã đến được bờ kia,\nKhông cứng cỏi không nghỉ.\n\n1060. Người ấy sau khi biết,\nThông suốt được Thánh điển,\nKhông dính ái triền này,\nVề hữu và phi hữu,\nVị ấy ly tham ái,\nKhông phiền lụy không cầu,\nTa nói rằng vị ấy,\nÐã vượt khỏi sanh già.`, ref: "Kinh Tập 5.5", url: "https://loicuaducphat.org/snp/snp5.5.html#content" },

{ text: `Thế Tôn đáp Upasiva:\n1070. Biết gìn giữ chánh niệm,\nKhông mong đợi vật gì,\nÔng sẽ vượt bộc lưu,\nNương tựa: "không có gì ",\nNgày đêm ngươi nhận thấy,\nÐoạn dục, ly nghi ngờ,\nÁi diệt là Niết-bàn.\n\n1072. Ai hoàn toàn ly tham,\nÐối với tất cả dục,\nY chỉ không có gì,\nTừ bỏ mọi gì khác,\nÐược giải thoát hoàn toàn,\nTương giải thoát tối thượng,\nTại đấy, vị ấy trú,\nKhông tiếp tục đi tới.\n\n1074. Cũng giống như ngọn lửa,\nBị sức gió mạnh thổi,\nÐi đến chỗ tận cùng,\nKhông có thể ước lượng,\nCũng vậy, vị ẩn sĩ,\nÐược giải thoát danh thân,\nÐi đến chỗ tận cùng,\nKhông có thể ước lượng.\n\n1076. Người đi đến tận cùng,\nKhông thể còn ước lượng,\nVới gì, nói đến nó,\nKhông còn có cái ấy,\nKhi tất cả các pháp,\nÐã được nhổ hẳn lên,\nMọi con đường nói phô,\nÐược nhổ lên sạch hết.`, ref: "Kinh Tập 5.7", url: "https://loicuaducphat.org/snp/snp5.7.html#content" },

{ text: `Tôn Giả Nanda:\n1077. Quần chúng có nói rằng:\nCó ẩn sĩ ở đời,\nNgài nghĩ như thế nào?\nChúng gọi là ẩn sĩ\nVị có đầy đủ trí?\nHay vị đầy đủ mạng?\n\n1078. Các bậc thiện nói rằng:\nỞ đời này Nan-da,\nKhông phải vì tri kiến,\nVì truyền thống, vì trí\nÐược gọi là ẩn sĩ,\nTa chỉ gọi ẩn sĩ,\nNhững ai diệt quân lực,\nKhông phiền não, không cầu.`, ref: "Kinh Tập 5.8", url: "https://loicuaducphat.org/snp/snp5.8.html#content" },

{ text: `Thế Tôn đáp Hemaka:\n1086. He-ma-ka ở đây,\nÐối các Pháp khả ái,\nÐược nghe và được thấy,\nÐược cảm tưởng, nhận thức,\nTẩy sạch ước muốn tham,\nLà Niết-bàn, bất tử.\n\n1087. Biết vậy, giữ chánh niệm,\nHiện tại, đạt mát lạnh,\nVị ấy thường an tịnh,\nVượt chấp trước ở đời.`, ref: "Kinh Tập 5.9", url: "https://loicuaducphat.org/snp/snp5.9.html#content" },

{ text: `Tôn Giả Todeyya:\n1088. Ai sống không dục vọng,\nAi sống không có ái,\nAi vượt khỏi nghi hoặc,\nGiải thoát của vị ấy,\nGiải thoát như thế nào?\n\nThế Tôn đáp Todeyya:\n1089. Ai sống không dục vọng,\nAi sống không có ái,\nAi vượt khỏi nghi hoặc\nGiải thoát của vị ấy\nKhông có gì là khác.\n\nTôn Giả Todeyya:\n1090. Vị sống không ước vọng\nHay sống có ước vọng,\nVị ấy có trí tuệ,\nHay tác thành trí tuệ,\nÔi kính bậc Biến nhãn,\nHãy trả lời con rõ,\nÐể con có thể biết,\nThế nào là ẩn sĩ,\nÔi kính bậc Thích tử.\n\nThế Tôn:\n1091. Vị sống không ước vọng,\nKhông có ước vọng nào,\nVị ấy có trí tuệ,\nKhông tác thành trí tuệ,\nNhư vậy, Tô-đê-ya,\nHãy biết bậc ẩn sĩ,\nKhông có sở hữu gì,\nKhông tham dính dục hữu.`, ref: "Kinh Tập 5.10", url: "https://loicuaducphat.org/snp/snp5.10.html#content" },

{ text: `Tôn Giả Kappa:\n\n1092. Những ai đứng giữa nước,\nTrong dòng nước mạnh chảy,\nGiữa sợ hãi lớn lao,\nThưa Ngài hãy nói lên,\nHòn đảo cho những kẻ,\nBị già chết chinh phục,\nNgài nói con hòn đảo,\nÐể không có khổ khác,\nGiống như đau khổ này.\n\nThế Tôn đáp Kappa:\n\n1093. Những ai đứng giữa nước,\nTrong dòng nước mạnh chảy,\nGiữa sợ hãi lớn lao,\nTa nói Ông hòn đảo,\nCho những ai đang bị,\nGià và chết chinh phục.\n\n1094. Hòn đảo vô song này,\nKhông sở hữu, chấp trước,\nTa nói Ông Niết-bàn,\nGià chết được đoạn diệt,\n\n1095. Biết vậy, giữ chánh niệm,\nHiện tại đạt mát lạnh,\nKhông rơi vào ma lực,\nKhông tùy tùng theo ma.`, ref: "Kinh Tập 5.11", url: "https://loicuaducphat.org/snp/snp5.11.html#content" },

{ text: `Tôn Giả Jatukanni:\n1096. Ðược nghe bậc anh hùng,\nKhông tham đắm dục vọng,\nNên con đã đến đây,\nÐể hỏi bậc vô dục,\nÐã thoát khỏi bộc lưu,\nBậc sanh với con mắt,\nHãy nói đường an tịnh,\nThế Tôn hãy như thật,\nNói cho con được biết.\n\n1097. Chinh phục dục vọng xong,\nThế Tôn sống ở đời,\nNhư mặt trời chiếu sáng,\nCõi đất với hào quang,\nBậc trí tuệ rộng lớn,\nHãy nói pháp cho con,\nKẻ trí tuệ bé nhỏ,\nDo rõ biết pháp này,\nỞ đây, con đoạn được,\nKể cả sanh và già.\n\nThế Tôn đáp Jatukanni:\n1098. Hãy nhiếp phục lòng tham,\nÐối với các dục vọng;\nHãy nhìn hạnh xuất ly,\nÐưa đến sự an ổn;\nChớ chấp chờ, từ bỏ,\nSự vật gì ở đời.\n\n1099. Những gì có trước Ông,\nHãy làm nó khô cạn,\nÐừng có sự vật gì,\nỞ phía đàng sau Ông,\nỞ giữa, Ông không chấp,\nÔng sẽ sống an tịnh.\n\n1100. Hỡi này Bà-la-môn!\nÐối với danh và sắc,\nHoàn toàn không tham đắm,\nKhông có các lậu hoặc,\nChính do lậu hoặc này,\nBị thần chết chi phối.`, ref: "Kinh Tập 5.12", url: "https://loicuaducphat.org/snp/snp5.12.html#content" },

{ text: `Thế Tôn đáp Bhadràvudha:\n1103. Hãy nhiếp phục tất cả,\nMọi tham ái chấp thủ,\nTrên, dưới cả bề ngang,\nVà kể luôn chặng giữa,\nNhững ai có chấp thủ,\nSự gì ở trong đời,\nChính do sự việc ấy,\nÁc ma theo người ấy.\n\n1104. Do vậy, bậc hiểu biết,\nKhông có chấp thủ gì,\nTỷ-kheo giữ chánh niệm,\nTrong tất cả thế giới,\nPhàm có sở hữu gì,\nVị ấy không mong ước,\nNhìn xem quần chúng này,\nLà chúng sanh chấp thủ,\nTrong lãnh vực của Ma,\nBị tham dính chấp trước.`, ref: "Kinh Tập 5.13", url: "https://loicuaducphat.org/snp/snp5.13.html#content" },

{ text: `Tôn Giả Udaya:\n1105. Con đến với câu hỏi,\nVề tất cả mọi pháp,\nÐể hỏi bậc tu thiền,\nBậc an tọa không bụi;\nTrách nhiệm đã làm xong,\nBậc không có lậu hoặc,\nÐã đạt bờ bên kia,\nHãy nói trí giải thoát\nÐể phá hoại vô minh.\n\nThế Tôn đáp Udaya:\n1106. Ðoạn ước muốn, dục vọng,\nVà cả hai loại ưu,\nVà trừ bỏ hôn trầm,\nNgăn chận mọi hối hận.\n\n1107. Ta nói trí giải thoát,\nÐể phá hoại vô minh,\nThanh tịnh nhờ xả niệm,\nSuy tư pháp đi trước.\n\nTôn Giả Udaya:\n1108. Ðời cái gì trói buộc,\nCái gì, đời vận hành?\nDo đoạn được cái gì,\nÐược gọi là Niết-bàn?\n\nThế Tôn:\n1109. Ðời bị hỷ trói buộc,\nSuy tầm là sở hành,\nDo đoạn được khát ái,\nÐược gọi là Niết-bàn.`, ref: "Kinh Tập 5.14", url: "https://loicuaducphat.org/snp/snp5.14.html#content" },

{ text: `Tôn Giả Posàla:\n1112. Vị nói về quá khứ,\nBất động nghi hoặc đoạn,\nÐã đến bờ bên kia,\nCon đến với câu hỏi\nHỏi về hết thảy pháp.\n\n1113. Với ai, sắc tưởng diệt,\nÐoạn tận hết thảy thân,\nNhìn thấy nội và ngoại,\nThật sự không có gì,\nCon hỏi bậc Thích-ca,\nThế nào người như vậy,\nCó thể bị dắt dẫn?\n\nThế Tôn đáp Posàla:\n1114. Như Lai được thắng trí,\nTất cả nhờ thức trú,\nRõ biết vị an trú,\nGiải thoát, đạt cứu cánh.\n\n1115. Biết được sự tác thành,\nThuộc về vô sở hữu,\nBiết hỷ là kiết sử,\nDo thắng tri như vậy,\nTại đấy, thấy như vậy,\nÐây là trí như thật,\nCủa vị Bà-la-môn,\nÐã thành tựu Phạm hạnh.`, ref: "Kinh Tập 5.15", url: "https://loicuaducphat.org/snp/snp5.15.html#content" },

{ text: `Tôn Giả Mogharàja:\n1118. Vị thầy được thù diệu,\nCon đến với câu hỏi,\nCần nhìn đời thế nào,\nÐể thần chết không thấy.\n\nThế Tôn đáp Mogharàja:\n1119. Hãy nhìn đời trống không,\nLuôn luôn giữ chánh niệm,\nNhô lên ngã tùy kiến,\nNhư vậy vượt tử vong,\nHãy nhìn đời như vậy,\nThần chết không thấy được.`, ref: "Kinh Tập 5.16", url: "https://loicuaducphat.org/snp/snp5.16.html#content" },

{ text: `Thế Tôn đáp Pingiya:\n1121. Thấy được sự tác hại,\nTrong các loại sắc pháp,\nChúng sanh sống phóng dật,\nBị phiền lụy trong sắc,\nDo vậy, Pin-gi-ya,\nÔng chớ có phóng dật,\nHãy từ bỏ sắc pháp\nChớ đi đến tái sanh.\n\n1123. Thấy chúng sanh loài Người,\nRơi vào trong khát ái,\nBị già nua đốt cháy,\nBị già nua chinh phục\nDo vậy, Pin-gi-ya,\nÔng chớ có phóng dật\nHãy từ bỏ khát ái,\nKhông còn bị tái sanh.`, ref: "Kinh Tập 5.17", url: "https://loicuaducphat.org/snp/snp5.17.html#content" },

       
                { text: `Trưởng Lão Subhuti\n\n1. Am thất ta khéo lợp,\nAn lạc, ngăn chận gió,\nThần mưa, hãy mưa đi,\nMưa như ý Ngươi muốn!\nTâm ta khéo định tĩnh,\nGiải thoát, sống tinh cần,\nThần mưa, hãy mưa đi!`, ref: "Trưởng Lão Tăng Kệ 1.1", url: "https://loicuaducphat.org/thag/thag1.1.html#content" },

{ text: `Trưởng Lão Mahakotthita\n\n2. Tịch tịnh và chỉ tức,\nTụng đọc lời trí tuệ,\nTâm tư không tháo động,\nÁc pháp được vứt bỏ,\nGiống như những lá cây,\nBị gió thổi phiêu bạt.`, ref: "Trưởng Lão Tăng Kệ 1.2", url: "https://loicuaducphat.org/thag/thag1.2.html#content" },

{ text: `Trưởng Lão Kankha-Revata\n\n3. Hãy thấy trí tuệ này\nCủa những bậc Như Lai,\nNhư lửa cháy nửa đêm,\nCho ánh sáng, cho mắt,\nHọ nhiếp phục nghi ngờ\nCho những ai đi đến.`, ref: "Trưởng Lão Tăng Kệ 1.3", url: "https://loicuaducphat.org/thag/thag1.3.html#content" },

{ text: `Trưởng Lão Punna Mantaniputta\n\n4. Hãy thân cận người hiền,\nBậc hiền minh thấy nghĩa,\nNghĩa lớn và thâm sâu,\nKhó thấy, tế, tế nhị,\nBậc trí chứng đạt được,\nKhông phóng dật, chú tâm.`, ref: "Trưởng Lão Tăng Kệ 1.4", url: "https://loicuaducphat.org/thag/thag1.4.html#content" },

{ text: `Trưởng Lão Dabba\n\n5. Ai thật khó nhiếp phục,\nNay đã được nhiếp phục,\nDabba tự biết đủ,\nNghi ngờ được vượt qua,\nThắng trận, không sợ hãi,\nDabba trú tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 1.5", url: "https://loicuaducphat.org/thag/thag1.5.html#content" },

{ text: `Trưởng Lão Sila-Vaniya\n\n6. Có Tỷ-kheo đi đến\nRừng Sitavana,\nSống một mình, độc cư,\nBiết đủ, tâm nhập định,\nThắng trận, không kinh hoàng,\nKiên trì hộ thân niệm.`, ref: "Trưởng Lão Tăng Kệ 1.6", url: "https://loicuaducphat.org/thag/thag1.6.html#content" },

{ text: `Trưởng Lão Bhalliya\n\n7. Ai đuổi đi thần chết,\nVới đạo binh của nó,\nNhững dòng nước lớn mạnh,\nTrói cây lau yếu ớt,\nThắng trận, không sợ hãi,\nNhiếp phục, trú tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 1.7", url: "https://loicuaducphat.org/thag/thag1.7.html#content" },

{ text: `Trưởng Lão Vira\n\n8. Ai thật khó nhiếp phục\nNay đã được nhiếp phục,\nVìra tự thỏa mãn,\nNghi ngờ được vượt qua,\nThắng trận, không kinh hoàng,\nVìra trú tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 1.8", url: "https://loicuaducphat.org/thag/thag1.8.html#content" },

{ text: `Trưởng Lão Punnamasa\n\n10. Ta sống không mong chờ,\nÐời này hay đời sau,\nVị đã đạt trí tuệ,\nAn tịnh, tự chế ngự,\nKhông dính nhiễm các pháp,\nBiết sanh diệt của đời.`, ref: "Trưởng Lão Tăng Kệ 1.10", url: "https://loicuaducphat.org/thag/thag1.10.html#content" },

{ text: `Trưởng Lão Culagavaccha\n\n11. Tỷ-kheo nhiều hân hoan,\nTrong pháp Phật tuyên bố,\nÐạt được đạo tịch tịnh,\nCác hành an tịnh lạc.`, ref: "Trưởng Lão Tăng Kệ 1.11", url: "https://loicuaducphat.org/thag/thag1.11.html#content" },

{ text: `Trưởng Lão Mahagavaccha\n\n12. Trí tuệ lực, giới hạnh,\nÐịnh, thiền lạc, chánh niệm,\nChỉ ăn những món ăn\nÐem lại quả tốt đẹp,\nỞ đây, tham viễn ly,\nChờ đợi giờ mạng chung.`, ref: "Trưởng Lão Tăng Kệ 1.12", url: "https://loicuaducphat.org/thag/thag1.12.html#content" },

{ text: `Trưởng Lão Vanavaccha\n\n3. Ðẹp sắc, mây xanh biếc,\nNước mát lạnh, chảy trong,\nKẻ chăn bò Inda,\nChe kín cả ngôi rừng,\nNhững ngôi núi đá ấy,\nLàm hân hoan tâm ta.`, ref: "Trưởng Lão Tăng Kệ 1.13", url: "https://loicuaducphat.org/thag/thag1.13.html#content" },

{ text: `Sa-di Trưởng Lão Sivaka.\n\n14. Thầy ta nói với ta,\n'Hãy đi, Sìvaka!'\nThân ta sống ở làng,\nNhưng tâm hướng về rừng,\nDầu còn nằm ta đi,\nNgười biết, không trói buộc.`, ref: "Trưởng Lão Tăng Kệ 1.14", url: "https://loicuaducphat.org/thag/thag1.14.html#content" },

{ text: `Trưởng Lão Belatthasisa\n\n16. Như vật hiền giống tốt\nVới sừng, kéo cái cày,\nÐi đứng không mệt nhọc,\nCũng vậy, ta ngày đêm,\nÐi đứng không mệt nhọc,\nÐược lạc không thế vật.`, ref: "Trưởng Lão Tăng Kệ 1.16", url: "https://loicuaducphat.org/thag/thag1.16.html#content" },

{ text: `Trưởng Lão Dasaka\n\n17. Ai hôn trầm, ăn nhiều,\nNằm ngủ, lăn qua lại,\nNhư heo lớn, ăn no,\nKẻ ngu tiếp thai sanh.`, ref: "Trưởng Lão Tăng Kệ 1.17", url: "https://loicuaducphat.org/thag/thag1.17.html#content" },

{ text: `Trưởng Lão Singala-Pitar\n\n18. Hãy nhìn trong khu rừng,\nRừng Bhesakala!\nMột Tỷ-kheo đang sống,\nThừa tự lời Phật dạy,\nNgang thân địa đại này,\nTỏa khắp tưởng bộ xương.\nTa nghĩ Tỷ-kheo ấy,\nMau đoạn tận dục tham.`, ref: "Trưởng Lão Tăng Kệ 1.18", url: "https://loicuaducphat.org/thag/thag1.18.html#content" },

{ text: `Trưởng Lão Kula\n\n19. Người trị thủy dẫn nước,\nKẻ làm nên nắn tên,\nNgười thợ mộc uốn gỗ,\nBậc tự điều, điều thân.`, ref: "Trưởng Lão Tăng Kệ 1.19", url: "https://loicuaducphat.org/thag/thag1.19.html#content" },

{ text: `Trưởng Lão Ajita\n\n20. Ta không có sợ chết,\nKhông ưa thích sanh mạng,\nTa sẽ bỏ thân này,\nTỉnh giác và chánh niệm.`, ref: "Trưởng Lão Tăng Kệ 1.20", url: "https://loicuaducphat.org/thag/thag1.20.html#content" },

{ text: `Trưởng Lão Nigrodha\n\n21. Ðối với ta, sợ hãi\nKhông làm ta sợ hãi,\nThâm hiểu đạo bất tử,\nBậc Ðạo Sư chúng ta\nKhông tìm được chân đứng,\nỞ đâu, sự sợ hãi,\nChỗ ấy vị Tỷ-kheo\nDẫn bước trên đường ấy.`, ref: "Trưởng Lão Tăng Kệ 1.21", url: "https://loicuaducphat.org/thag/thag1.21.html#content" },

{ text: `Trưởng Lão Cittaka\n\n22. Chim công, màu xanh biếc,\nCổ đẹp, có màu tươi,\nÐang gọi nhau trong rừng,\nRừng Kà-ram-vi-yà,\nVới gió mát tiếng trong,\nChúng gọi và thức dậy,\nVị hành thiền đang ngủ.`, ref: "Trưởng Lão Tăng Kệ 1.22", url: "https://loicuaducphat.org/thag/thag1.22.html#content" },

{ text: `Trưởng Lão Gosala\n\n23. Ta chấp nhận toàn diện,\nLời dạy bậc đáng kính,\nTánh sanh diệt các uẩn,\nTa sẽ lên ngọn núi,\nTăng trưởng hạnh viễn ly.`, ref: "Trưởng Lão Tăng Kệ 1.23", url: "https://loicuaducphat.org/thag/thag1.23.html#content" },

{ text: `Trưởng Lão Abhaya\n\n26. Nghe được lời khéo giảng,\nBậc bà con mặt trời,\nTa đâm thủng tinh vi,\nNhư tên chẻ ngọn tóc.`, ref: "Trưởng Lão Tăng Kệ 1.26", url: "https://loicuaducphat.org/thag/thag1.26.html#content" },

{ text: `Trưởng Lão Lomasakangiya\n\n27. Cỏ dabba, kusa,\nCác loài cỏ đâm ngực,\nLoài cỏ tên munja,\nCỏ tên pabbaja.\nTừ nơi ngực của ta,\nTa sẽ đẩy chúng lui,\nTa sẽ làm tăng trưởng,\nHạnh cô độc viễn ly.`, ref: "Trưởng Lão Tăng Kệ 1.27", url: "https://loicuaducphat.org/thag/thag1.27.html#content" },

{ text: `Trưởng Lão Con Trai Của Jambugamika\n\n28. Con có được thỏa mãn,\nVới y phục mang mặc?\nCon có được hoan hỷ,\nVới trang sức điểm tô?\nVà mùi hương thơm này,\nDo giới con tỏa ra,\nChớ không do người khác\nTạo mùi thơm như vậy!`, ref: "Trưởng Lão Tăng Kệ 1.28", url: "https://loicuaducphat.org/thag/thag1.28.html#content" },

{ text: `Trưởng Lão Harita\n\n29. Thầy hay làm tự ngã,\nÐược thấm nhuần hướng thượng,\nNhư người thợ cung tên\nLàm cây tên ngay thẳng,\nHãy làm tâm ngay thẳng,\nHỡi này Ha-ri-ta!\nHãy chặt đứt vô minh.`, ref: "Trưởng Lão Tăng Kệ 1.29", url: "https://loicuaducphat.org/thag/thag1.29.html#content" },

{ text: `Trưởng Lão Uttiya\n\n30. Trong khi ta lâm bệnh,\nNiệm khởi lên nơi ta,\nTrong khi ta lâm bệnh,\nKhông phải thời phóng dật.`, ref: "Trưởng Lão Tăng Kệ 1.30", url: "https://loicuaducphat.org/thag/thag1.30.html#content" },

{ text: `Trưởng Lão Gahvaratiriya\n\n31. Trong núi rừng rộng lớn,\nBị muỗi lằng đốt cắn,\nNhư voi đầu chiến trận,\nTại đấy sống chánh niệm.`, ref: "Trưởng Lão Tăng Kệ 1.31", url: "https://loicuaducphat.org/thag/thag1.31.html#content" },

{ text: `Trưởng Lão Suppiya\n\n32. Bị già, được không già,\nBị nung nấu, được tịnh,\nMong rằng ta sẽ được\nTịch tịnh thật tối thượng,\nAn ổn thật vô thượng,\nThoát khỏi các khổ ách.`, ref: "Trưởng Lão Tăng Kệ 1.32", url: "https://loicuaducphat.org/thag/thag1.32.html#content" },

{ text: `Trưởng Lão Sopaka\n\n33. Như người mẹ tốt lành\nThương người con độc nhất,\nCũng vậy đối chúng sanh,\nÐủ mọi loài, mọi chỗ,\nHãy có lòng tốt đẹp,\nThương mến và từ ái.`, ref: "Trưởng Lão Tăng Kệ 1.33", url: "https://loicuaducphat.org/thag/thag1.33.html#content" },

{ text: `Trưởng Lão Posiya\n\n34. Không gần là tốt đẹp,\nKẻ trí thường biết vậy,\nTừ làng đi đến rừng,\nTừ rừng, ta vào nhà,\nTừ đấy, đứng dậy đi,\nKhông đoái hoài Bô-syà.`, ref: "Trưởng Lão Tăng Kệ 1.34", url: "https://loicuaducphat.org/thag/thag1.34.html#content" },

{ text: `Trưởng Lão Samannakani\n\n35. Kẻ tìm lạc, được lạc,\nNếu sở hành đúng đắn,\nLại thêm được kính trọng,\nDanh vọng được tăng trưởng.\nAi tu tập chánh trực,\nCon đường Thánh tám ngành,\nÐây là đường lộ trình,\nÐạt đến cảnh bất tử.`, ref: "Trưởng Lão Tăng Kệ 1.35", url: "https://loicuaducphat.org/thag/thag1.35.html#content" },

{ text: `Trưởng Lão Con Của Kuma\n\n36. Lành thay, điều được nghe!\nLành thay, hạnh phúc sống!\nLành thay, thường an trú!\nÐời sống kẻ không nhà.\nTìm hỏi nghĩa Chánh pháp,\nLàm các hạnh cung kính,\nÐấy là hạnh Sa-môn,\nCủa bậc Vô sở hữu.`, ref: "Trưởng Lão Tăng Kệ 1.36", url: "https://loicuaducphat.org/thag/thag1.36.html#content" },

{ text: `Trưởng Lão Bạn Của Con Kuma\n\n37. Bộ hành nhiều xứ sở,\nVới hạnh không suy tưởng,\nThiêu đốt phần thiền định,\nÐi khắp xứ làm gì?\nDo vậy, ngăn vọng động,\nKhông vọng hướng, hãy thiền.`, ref: "Trưởng Lão Tăng Kệ 1.37", url: "https://loicuaducphat.org/thag/thag1.37.html#content" },

{ text: `Trưởng Lão Tissa\n\n39. Như bị kiếm chém xuống,\nNhư bị lửa cháy đầu,\nVị Tỷ-kheo xuất gia,\nChánh niệm, đoạn tham dục.`, ref: "Trưởng Lão Tăng Kệ 1.39", url: "https://loicuaducphat.org/thag/thag1.39.html#content" },

{ text: `Trưởng Lão Sirivaddha\n\n41. Giữa đồi Vebhara,\nGiữa đồi Pandava,\nSét đánh vào cửa hang,\nÐứa con bậc Vô tỷ,\nNhư vậy, vẫn ngồi thiền.`, ref: "Trưởng Lão Tăng Kệ 1.41", url: "https://loicuaducphat.org/thag/thag1.41.html#content" },

{ text: `Trưởng Lão Sumangala\n\n43. Khéo thoát! Ôi khéo thoát!\nThật sự ta khéo thoát,\nThoát ba sự cong queo,\nTa thoát cong với liềm,\nTa thoát cột với cày,\nTa thoát cực với cuốc,\n\nNếu có đây, có đây,\nThật đủ chán, đủ chán,\nHỡi Sumangala!\nHỡi Sumangala!\nHãy thiền, hãy thiền định!\nHỡi Sumangala!\nHãy sống không phóng dật.`, ref: "Trưởng Lão Tăng Kệ 1.43", url: "https://loicuaducphat.org/thag/thag1.43.html#content" },

{ text: `Trưởng Lão Ramaṇīyavihāri\n\n45. Như con thú hiền thiện,\nGiống tốt, huấn luyện khéo,\nSau khi đã vấp ngã,\nLại đứng lên, an trú,\nTa đầy đủ chánh kiến,\nÐệ tử bậc Chánh giác.`, ref: "Trưởng Lão Tăng Kệ 1.45", url: "https://loicuaducphat.org/thag/thag1.45.html#content" },

{ text: `Trưởng Lão Samiddhi\n\n46. Ta với lòng tín ngưỡng,\nBỏ gia đình, xuất gia,\nNiệm tuệ ta tăng trưởng,\nTâm tư ta thiền định,\nDầu ngươi tạo sắc gì,\nKhông làm ta sợ hãi.`, ref: "Trưởng Lão Tăng Kệ 1.46", url: "https://loicuaducphat.org/thag/thag1.46.html#content" },

{ text: `Trưởng Lão Ujjaya\n\n47. Ðảnh lễ Phật, anh hùng,\nNgài giải thoát mọi chỗ,\nTrong nếp sống của ngài,\nGồm cả phần giáo điển,\nCon sống không lậu hoặc,\nKhông còn bị trói buộc.`, ref: "Trưởng Lão Tăng Kệ 1.47", url: "https://loicuaducphat.org/thag/thag1.47.html#content" },

{ text: `Trưởng Lão Sanjaya\n\n48. Từ khi ta xuất gia,\nBỏ nhà, sống không nhà,\nTa không có tư duy,\nNhững tư tưởng phàm phu,\nNhững tư niệm phi thành,\nLiên hệ đến sân hận.`, ref: "Trưởng Lão Tăng Kệ 1.48", url: "https://loicuaducphat.org/thag/thag1.48.html#content" },

{ text: `Trưởng Lão Ramaneyyaka\n\n49. Dầu tiếng người hò hét,\nTiếng náo động chim muông,\nTâm ta không dao động,\nTa ưa thích độc cư.`, ref: "Trưởng Lão Tăng Kệ 1.49", url: "https://loicuaducphat.org/thag/thag1.49.html#content" },

{ text: `Trưởng Lão Vimala\n\n50. Ðất, nước mưa ướt thấm,\nGió thổi mát không gian,\nTrên trời, chớp vạch đường,\nTư tưởng ta lắng dịu,\nTâm ta thật định tĩnh.`, ref: "Trưởng Lão Tăng Kệ 1.50", url: "https://loicuaducphat.org/thag/thag1.50.html#content" },

{ text: `Trưởng Lão Ghodhika\n\n51. Trời mưa, như hát hay,\nTa ở trong am thất,\nÐược che kín khỏi gió,\nTa sống thật an lạc,\nTâm ta khéo định tĩnh.\nHãy mưa, nếu trời muốn.`, ref: "Trưởng Lão Tăng Kệ 1.51", url: "https://loicuaducphat.org/thag/thag1.51.html#content" },

{ text: `Trưởng Lão Kutivihari\n\n56. Ai ở trong chòi lá?\nMột Tỷ-kheo ly tham,\nTâm được khéo định tĩnh,\nÐang ở trong chòi lá,\nHiền giả, hãy biết vậy!\nKhông phải là vô ích,\nChòi lá ông dựng lên.`, ref: "Trưởng Lão Tăng Kệ 1.56", url: "https://loicuaducphat.org/thag/thag1.56.html#content" },

{ text: `Trưởng Lão Kutivihari (2)\n\n57. Ðây ngôi chòi cũ kỹ,\nNgài muốn ngôi chòi mới,\nHãy bỏ muốn ngôi chòi,\nChòi mới đem khổ mới,\nNày Tỷ-kheo nên biết!`, ref: "Trưởng Lão Tăng Kệ 1.57", url: "https://loicuaducphat.org/thag/thag1.57.html#content" },

{ text: `Trưởng Lão Ramaniyakutika\n\n58. Ngôi chòi ta xinh đẹp,\nDo đàn tín cúng dường,\nVới tâm ý hoan hỷ,\nVới lòng tin dâng cúng.\nTa không cần thiếu nữ,\nNày các nữ nhân kia,\nHãy đi đến những ai,\nCó cần đến các cô.`, ref: "Trưởng Lão Tăng Kệ 1.58", url: "https://loicuaducphat.org/thag/thag1.58.html#content" },

{ text: `Trưởng Lão Kosalavihari\n\n59. Do lòng tin, xuất gia,\nTa sống không gia đình,\nTrong rừng, một chòi lá,\nÐược dựng lên cho ta,\nTa sống không phóng dật,\nNhiệt tâm, niệm tỉnh giác.`, ref: "Trưởng Lão Tăng Kệ 1.59", url: "https://loicuaducphat.org/thag/thag1.59.html#content" },

{ text: `Trưởng Lão Vappa\n\n61. Vị đã thấy, thấy được,\nNgười thấy, người không thấy,\nVị không thấy, không thấy,\nNgười không thấy, người thấy.`, ref: "Trưởng Lão Tăng Kệ 1.61", url: "https://loicuaducphat.org/thag/thag1.61.html#content" },

{ text: `Trưởng Lão Vajji-Putta\n\n62. Một mình chúng tôi sống,\nTrong rừng núi hoang vu,\nNhư khúc gỗ bị quăng,\nBỏ rơi trong rừng núi,\nNhưng nhiều người thương mến,\nÐời sống ấy của ta,\nNhư kẻ đọa địa ngục,\nƯa đón cảnh thiên giới.`, ref: "Trưởng Lão Tăng Kệ 1.62", url: "https://loicuaducphat.org/thag/thag1.62.html#content" },

{ text: `Trưởng Lão Pakkha\n\n63. Chúng rơi theo, sà xuống,\nCái đang bị rơi xuống,\nVới lòng tham thúc đẩy,\nChúng lại đến, đến nữa.\nBổn phận ta làm xong,\nTa vui thích sung sướng,\nVới an lạc, đón mừng,\nTa đón mừng an lạc.`, ref: "Trưởng Lão Tăng Kệ 1.63", url: "https://loicuaducphat.org/thag/thag1.63.html#content" },

{ text: `Trưởng Lão Ukkhepakata Vaccha\n\n65. Tài sản được chất chứa,\nTrải nhiều tháng nhiều năm,\nDo Vaccha tác thành,\nNay Vaccha quăng bỏ,\nNgài thuyết giảng như vậy,\nCho các hàng cư sĩ,\nKhéo ngồi chỗ trịnh trọng,\nTâm hân hoan rộng lớn.`, ref: "Trưởng Lão Tăng Kệ 1.65", url: "https://loicuaducphat.org/thag/thag1.65.html#content" },

{ text: `Trưởng Lão Meghiya\n\n66. Bậc Ðại hùng giảng dạy,\nVượt qua tất cả pháp,\nTa nghe pháp Ngài dạy,\nSống hoan hỷ cạnh Ngài,\nBa minh đã chứng đạt,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 1.66", url: "https://loicuaducphat.org/thag/thag1.66.html#content" },

{ text: `Trưởng Lão Ekadhamma Savaniya\n\n67. Phiền não ta đốt cháy,\nMọi hữu được nhổ lên,\nÐường luân hồi đoạn tận,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 1.67", url: "https://loicuaducphat.org/thag/thag1.67.html#content" },

{ text: `Trưởng Lão Ekudaniya\n\n68. Tâm tăng thượng ẩn sĩ,\nKhông phóng dật, tu tập,\nTrên con đường chánh trí,\nVị ấy không sầu muộn,\nLuôn luôn được an tịnh,\nThường nắm giữ chánh niệm.`, ref: "Trưởng Lão Tăng Kệ 1.68", url: "https://loicuaducphat.org/thag/thag1.68.html#content" },

{ text: `Trưởng Lão Channa\n\n69. Sau khi nghe Chánh pháp,\nVị ngọt lớn pháp lớn,\nDo nhất thiết thắng trí,\nThuyết giảng và trình bày,\nTa dấn thân trên đường,\nÐường đưa đến bất tử,\nNgài thật bậc thiện xảo,\nCon đường diệt khổ ách.`, ref: "Trưởng Lão Tăng Kệ 1.69", url: "https://loicuaducphat.org/thag/thag1.69.html#content" },

{ text: `Trưởng Lão Punna\n\n70. Ở đây chỉ có giới,\nLà pháp thật tối thượng,\nNhưng vị nào có tuệ,\nVị ấy là vô thượng,\nVị đủ giới và tuệ,\nChiến thắng giới Nhân, Thiên.`, ref: "Trưởng Lão Tăng Kệ 1.70", url: "https://loicuaducphat.org/thag/thag1.70.html#content" },

{ text: `Trưởng Lão Vacchapala\n\n71. Nếu thấy được sự thật,\nThật vi diệu, vi tế,\nVới trí tuệ thiện xảo,\nVới tâm tư khiêm tốn,\nSống rập theo giới luật,\nDo chính đức Phật dạy,\nVới người ấy Niết-bàn,\nChứng được không khó khăn.`, ref: "Trưởng Lão Tăng Kệ 1.71", url: "https://loicuaducphat.org/thag/thag1.71.html#content" },

{ text: `Trưởng Lão Manava\n\n73. Ta thấy một người già,\nMột người khổ bệnh hoạn,\nTa thấy một người chết,\nVới tuổi thọ kiệt quệ,\nDo vậy ta thoát ra,\nSống đời sống xuất gia,\nTừ bỏ mọi dục vọng,\nHấp dẫn và thích ý.`, ref: "Trưởng Lão Tăng Kệ 1.73", url: "https://loicuaducphat.org/thag/thag1.73.html#content" },

{ text: `Trưởng Lão Suyamana\n\n74. Với dục tham, sân hận,\nVới thụy miên hôn trầm,\nVới trạo hối, nghi ngờ,\nVị Tỷ-kheo hoàn toàn,\nKhông còn năm triền cái,\nNăm triền cái đoạn tận.`, ref: "Trưởng Lão Tăng Kệ 1.74", url: "https://loicuaducphat.org/thag/thag1.74.html#content" },

{ text: `Trưởng Lão Susarada\n\n75. Lành thay là tri kiến,\nCủa bậc có luyện tập,\nNghi hoặc được cắt đứt,\nTrí giác được tăng trưởng.\nCho đến kẻ ngu si,\nÐược đổi thành người trí,\nDo vậy thật tốt đẹp,\nSống giao thiệp người lành.`, ref: "Trưởng Lão Tăng Kệ 1.75", url: "https://loicuaducphat.org/thag/thag1.75.html#content" },

{ text: `Trưởng Lão Piyanjaha\n\n76. Khi loài Người kiêu hãnh,\nHãy hạ thấp ông xuống,\nKhi loài Người hạ thấp,\nHãy nâng cao tâm ông,\nHãy sống tại những chỗ,\nLoài Người không muốn sống,\nTại chỗ ngồi ưa thích,\nChớ có nên thích thú.`, ref: "Trưởng Lão Tăng Kệ 1.76", url: "https://loicuaducphat.org/thag/thag1.76.html#content" },

{ text: `Trưởng Lão Hattharoha-Putta\n\n77. Trước tâm này lang thang,\nChạy chỗ này chỗ khác,\nChạy chỗ nó ưa thích,\nChạy chỗ nó vui sướng,\nNay ta chế ngự tâm,\nVới như lý tư duy,\nNhư câu móc chế ngự,\nNhiếp phục con voi rừng.`, ref: "Trưởng Lão Tăng Kệ 1.77", url: "https://loicuaducphat.org/thag/thag1.77.html#content" },

{ text: `Trưởng Lão Rakkhita\n\n79. Mọi tham ta đã đoạn,\nMọi sân được nhổ lên,\nMọi si được từ bỏ,\nTa mát lạnh tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 1.79", url: "https://loicuaducphat.org/thag/thag1.79.html#content" },

{ text: `Trưởng Lão Ugga\n\n80. Mọi nghiệp ta đã làm,\nDầu ít hay là nhiều,\nTất cả được đoạn trừ,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 1.80", url: "https://loicuaducphat.org/thag/thag1.80.html#content" },

{ text: `Trưởng Lão Samitigutta\n\n81. Việc ác ta đã làm,\nTrong các đời sống trước,\nỞ đây chỉ cảm thọ,\nThọ lãnh từ nghiệp ấy,\nCăn bản các nghiệp khác,\nThật sự không còn nữa.`, ref: "Trưởng Lão Tăng Kệ 1.81", url: "https://loicuaducphat.org/thag/thag1.81.html#content" },

{ text: `Trưởng Lão Siha\n\n83. Hỡi Sìha, hãy sống,\nKhông buông lung, phóng dật,\nNgày đêm không biếng nhác,\nKiên trì trong tu tập,\nHãy thực hành thiện pháp,\nGấp bỏ thân tích tụ.`, ref: "Trưởng Lão Tăng Kệ 1.83", url: "https://loicuaducphat.org/thag/thag1.83.html#content" },

{ text: `Trưởng Lão Nita\n\n84. Trọn đêm Thầy nằm ngủ,\nBan ngày thích tụ hội,\nKẻ ngu sống như vậy,\nSẽ đoạn khổ được sao?`, ref: "Trưởng Lão Tăng Kệ 1.84", url: "https://loicuaducphat.org/thag/thag1.84.html#content" },

{ text: `Trưởng Lão Sunaga\n\n85. Thiện xảo tướng của tâm,\nBiết vị ngọt viễn ly,\nHành thiền, niệm, thận trọng,\nChứng lạc không thế tục.`, ref: "Trưởng Lão Tăng Kệ 1.85", url: "https://loicuaducphat.org/thag/thag1.85.html#content" },

{ text: `Trưởng Lão Nagita\n\n86. Ngoài đây có ngoại đạo,\nHọ dạy những con đường,\nKhông như con đường này,\nÐưa đến quả Niết-bàn,\nThật khác, đức Thế Tôn,\nGiáo giới hàng Tăng chúng,\nÐạo Sư chỉ Niết-bàn,\nNhư thấy trên bàn tay.`, ref: "Trưởng Lão Tăng Kệ 1.86", url: "https://loicuaducphat.org/thag/thag1.86.html#content" },

{ text: `Trưởng Lão Pavittha\n\n87. Thấy như thật các uẩn,\nMọi sanh hữu phá hủy,\nÐoạn sanh tử luân hồi,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 1.87", url: "https://loicuaducphat.org/thag/thag1.87.html#content" },

{ text: `Trưởng Lão Ajjuna\n\n88. Ta có thể tự mình,\nKéo nước từ đất liền,\nNhư nước lớn cuốn trôi,\nTa thể nhập sự thật.`, ref: "Trưởng Lão Tăng Kệ 1.88", url: "https://loicuaducphat.org/thag/thag1.88.html#content" },

{ text: `Trưởng Lão Devasabha\n\n89. Vượt khỏi các bùn nhơ,\nTừ vực thẳm trở về,\nThoát bộc lưu trói buộc,\nMọi kiêu mạn tiêu trừ.`, ref: "Trưởng Lão Tăng Kệ 1.89", url: "https://loicuaducphat.org/thag/thag1.89.html#content" },

{ text: `Trưởng Lão Samidatta\n\n90. Năm uẩn được rõ biết,\nTồn tại sẽ cắt đứt,\nVòng sanh tử đoạn tận,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 1.90", url: "https://loicuaducphat.org/thag/thag1.90.html#content" },

{ text: `Trưởng Lão Paripunnaka\n\n91. Dầu có hưởng món ăn,\nNhư cam lồ trăm vị,\nNhưng không thể sánh bằng,\nMón ta ăn hôm nay;\nÐây là Pháp vi diệu,\nÐược Phật Go-ta-ma,\nBậc tri kiến vô lượng,\nÐã thuyết giảng cho ta.`, ref: "Trưởng Lão Tăng Kệ 1.91", url: "https://loicuaducphat.org/thag/thag1.91.html#content" },

{ text: `Trưởng Lão Vijaya\n\n92. Với ai, lậu hoặc đoạn,\nKhông y tựa đồ ăn,\nHành xứ, không, vô tướng,\nGiải thoát cũng như vậy,\nNhư chim trên hư không,\nDấu chân thật khó tìm.`, ref: "Trưởng Lão Tăng Kệ 1.92", url: "https://loicuaducphat.org/thag/thag1.92.html#content" },

{ text: `Trưởng Lão Eraka\n\n93. Hỡi này Ê-ra-ka,\nKhổ thay là các dục!\nHỡi này Ê-ra-ka,\nKhông lạc là các dục!\nAi tham dục các dục,\nLà tham dục đau khổ,\nAi không tham các dục,\nLà không tham dục khổ.\nHỡi này Ê-ra-ka!\nHãy biết là như vậy.`, ref: "Trưởng Lão Tăng Kệ 1.93", url: "https://loicuaducphat.org/thag/thag1.93.html#content" },

{ text: `Trưởng Lão Cakkhupala\n\n95. Dầu ta có bị mù,\nDầu mắt ta hư hoại,\nDầu con đường ta đi,\nDầu gai góc khó khăn,\nTa sẽ tự mình đi,\nDấn thân trên đường ấy,\nNhưng ta không cùng đi,\nKẻ ác hạnh như vậy.`, ref: "Trưởng Lão Tăng Kệ 1.95", url: "https://loicuaducphat.org/thag/thag1.95.html#content" },

{ text: `Trưởng Lão Khandasumana\n\n96. Do một bông từ bỏ,\nÐược hưởng tám ức năm,\nSống trong cảnh cõi trời,\nCòn số năm còn lại,\nTa được sống tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 1.96", url: "https://loicuaducphat.org/thag/thag1.96.html#content" },

{ text: `Trưởng Lão Tissa\n\n97. Từ bỏ trăm bình bát,\nBằng đồng, vàng quý giá,\nTa cầm lấy bình bát,\nLàm bằng đất sét thường,\nÐây là lần thứ hai,\nTa làm lễ quán đảnh.`, ref: "Trưởng Lão Tăng Kệ 1.97", url: "https://loicuaducphat.org/thag/thag1.97.html#content" },

{ text: `Trưởng Lão Abhaya (2)\n\n98. Thấy sắc, mất chánh niệm,\nTác ý tưởng luyến ái,\nTâm cảm thọ say mê,\nÐắm trước tưởng an trú,\nCác lậu hoặc tăng trưởng,\nÐưa đến gốc sanh hữu.`, ref: "Trưởng Lão Tăng Kệ 1.98", url: "https://loicuaducphat.org/thag/thag1.98.html#content" },

{ text: `Trưởng Lão Uttiya\n\n99. Nghe tiếng, mất chánh niệm,\nTác ý tưởng luyến ái,\nTâm cảm thọ say mê,\nÐắm trước tưởng an trú,\nCác lậu hoặc tăng trưởng,\nÐưa đến nhiễm luân hồi.`, ref: "Trưởng Lão Tăng Kệ 1.99", url: "https://loicuaducphat.org/thag/thag1.99.html#content" },

{ text: `Trưởng Lão Devasabha (II)\n\n100. Thành tựu chánh tính tấn,\nSở hành trên niệm xứ,\nTràn đầy hoa giải thoát,\nSẽ nhập diệt, vô lậu.`, ref: "Trưởng Lão Tăng Kệ 1.100", url: "https://loicuaducphat.org/thag/thag1.100.html#content" },

{ text: `Trưởng Lão Belatthakani\n\n101. Từ bỏ đời cư sĩ,\nTrách nhiệm chưa làm xong,\nDùng miệng như cái cày,\nBụng ăn no, biếng nhác,\nNhư con heo to lớn,\nÐồ ăn thật đầy đủ,\nKẻ nhác lại liên tục,\nÐi đến chỗ thai tạng.`, ref: "Trưởng Lão Tăng Kệ 1.101", url: "https://loicuaducphat.org/thag/thag1.101.html#content" },

{ text: `Trưởng Lão Setuccha\n\n102. Bị kiêu mạn lừa đảo,\nTâm uế nhiễm trong hành,\nLợi bất lợi, dao động,\nHọ không chứng thiền định.`, ref: "Trưởng Lão Tăng Kệ 1.102", url: "https://loicuaducphat.org/thag/thag1.102.html#content" },

{ text: `Trưởng Lão Bandhura\n\n103. Ta không có cần thiết,\nViệc này hay vật này,\nTa sống trong hạnh phúc,\nThọ hưởng được pháp vị.\nSau khi uống vị ngọt,\nTối thượng và đệ nhất,\nTa sẽ không thân thiết,\nVới thuốc độc nọc độc.`, ref: "Trưởng Lão Tăng Kệ 1.103", url: "https://loicuaducphat.org/thag/thag1.103.html#content" },

{ text: `Trưởng Lão Khitaka\n\n104. Thân ta thật nhẹ nhàng,\nCảm xúc hỷ lạc lớn,\nNhư bông thổi trước gió,\nThân ta nhẹ trôi bay.`, ref: "Trưởng Lão Tăng Kệ 1.104", url: "https://loicuaducphat.org/thag/thag1.104.html#content" },

{ text: `Trưởng Lão Malitavambha\n\n105. Ta không muốn an trú,\nKhi ta không vừa ý,\nChỗ nào có lạc thú,\nTa liền rời bỏ đi,\nTại chỗ nào mục đích,\nKhông phải không liên hệ,\nChỗ ấy, người có mắt,\nCó thể an trú được.`, ref: "Trưởng Lão Tăng Kệ 1.105", url: "https://loicuaducphat.org/thag/thag1.105.html#content" },

{ text: `Trưởng Lão Suhemanta\n\n106. Tại chỗ nào mục đích,\nTrăm tánh, tướng ẩn chứa,\nKẻ ngu thấy một phần,\nKẻ trí thấy trăm phần.`, ref: "Trưởng Lão Tăng Kệ 1.106", url: "https://loicuaducphat.org/thag/thag1.106.html#content" },

{ text: `Trưởng Lão Dhammasava\n\n107. Cân nhắc, suy tư xong,\nTa xuất gia, không nhà,\nBa minh ta đạt được,\nLời Phật dạy, làm xong.`, ref: "Trưởng Lão Tăng Kệ 1.107", url: "https://loicuaducphat.org/thag/thag1.107.html#content" },

{ text: `Trưởng Lão Sangha-Rakkhita\n\n109. Dầu có sống cô độc,\nVới lòng thương từ mẫn,\nCủa bậc đã lo nghĩ,\nÐến hạnh phúc tối thượng,\nVị này vẫn không nghĩ,\nÐến lời dạy Bổn Sư.\nNhư vậy vị ấy sống,\nVới căn còn mộc mạc,\nChẳng khác con nai cái,\nNon yếu trong khu rừng.`, ref: "Trưởng Lão Tăng Kệ 1.109", url: "https://loicuaducphat.org/thag/thag1.109.html#content" },

{ text: `Trưởng Lão Usabha\n\n110. Những cây được vươn cao,\nNhờ mây cao tưới mát,\nVới mưa mới thấm nhuần,\nÐược xanh tươi lớn mạnh,\nÐối với U-xa-bha,\nƯa thích sống viễn ly,\nÝ thức được rừng núi,\nVị ấy khiến sanh khởi,\nRất nhiều điều tốt đẹp.`, ref: "Trưởng Lão Tăng Kệ 1.110", url: "https://loicuaducphat.org/thag/thag1.110.html#content" },

{ text: `Trưởng Lão Jenta\n\n111. Khó thay, đời xuất gia,\nKhó thay, đời cư sĩ,\nSâu kín thay, Chánh pháp,\nKhó kiếm thay, tài sản,\nLựa chọn thật khó khăn,\nNếp sống này, sống khác,\nKhi tâm trí, luôn luôn,\nNghĩ đến lẽ vô thường.`, ref: "Trưởng Lão Tăng Kệ 1.111", url: "https://loicuaducphat.org/thag/thag1.111.html#content" },

{ text: `Trưởng Lão Vacchagotta\n\n112. Ta chứng được Ba minh,\nÐạt được đại thiền định,\nTâm chỉ được thiện xảo,\nTa đạt được mục đích,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 1.112", url: "https://loicuaducphat.org/thag/thag1.112.html#content" },

{ text: `Trưởng Lão Vanavaccha\n\n113. Dưới tảng đá, băng đá\nCó nước suối, trong chảy,\nCó khỉ và có nai,\nLai vãng sống gần bên,\nCỏ cây bao trùm nước,\nNúi rừng ấy, ta ưa.`, ref: "Trưởng Lão Tăng Kệ 1.113", url: "https://loicuaducphat.org/thag/thag1.113.html#content" },

{ text: `Trưởng Lão Adhimutta\n\n114. Trong nếp sống tâm tư,\nHướng về hạnh từ bỏ,\nVới thân thể thô lỗ,\nNặng nề như thế này,\nNếu ham muốn thân thể,\nÐược thọ hưởng các lạc,\nTừ đâu thành tựu được,\nHạnh của bậc Sa-môn?`, ref: "Trưởng Lão Tăng Kệ 1.114", url: "https://loicuaducphat.org/thag/thag1.114.html#content" },

{ text: `Trưởng Lão Mahanama\n\n115. Hãy xem, sao đời nay,\nLại chấm dứt ở đây,\nVới hòn núi nhiều ngọn,\nVà nhiều cây cối này?\nNúi Nesàdaka,\nMột ngọn núi có danh,\nRập rạp với cỏ cây,\nChe kín trùm tất cả.`, ref: "Trưởng Lão Tăng Kệ 1.115", url: "https://loicuaducphat.org/thag/thag1.115.html#content" },

{ text: `Trưởng Lão Parapariya\n\n116. Từ bỏ sáu xúc xứ,\nCăn môn khéo chế ngự,\nGốc tà ác, nhổ sạch,\nTa đạt lậu hoặc tận.`, ref: "Trưởng Lão Tăng Kệ 1.116", url: "https://loicuaducphat.org/thag/thag1.116.html#content" },

{ text: `Trưởng Lão Vajji-Putta\n\n119. Hãy đi đến khu rừng,\nRậm rạp những rễ cây,\nHãy để cho Niết-bàn,\nChìm sâu vào tâm người,\nHỡi này Go-ta-ma!\nHãy tu tập thiền định,\nViệc làm lăng xăng này,\nCó nghĩa gì cho ông.`, ref: "Trưởng Lão Tăng Kệ 1.119", url: "https://loicuaducphat.org/thag/thag1.119.html#content" },

{ text: `Trưởng Lão Isidatta\n\n120. Năm uẩn được rõ biết,\nÐứng với rễ chặt đứt,\nKhổ diệt đã đạt được,\nLậu hoặc diệt, ta chứng.`, ref: "Trưởng Lão Tăng Kệ 1.120", url: "https://loicuaducphat.org/thag/thag1.120.html#content" },

{ text: `Trưởng Lão Uttara\n\n121. Không có gì có mặt,\nLại thường còn mãi mãi,\nKhông có các hành gì,\nLại thường hằng thường trú.\nCác uẩn được khởi lên,\nÐến đời khác diệt vong.\n\n122. Biết được nguy hiểm này,\nTa không muốn sanh hữu,\nTừ bỏ tất cả dục,\nTa chứng lậu hoặc tận.`, ref: "Trưởng Lão Tăng Kệ 2.1", url: "https://loicuaducphat.org/thag/thag2.1.html#content" },

{ text: `Trưởng Lão Pindola-Bharadvaja\n\n123. Nói về đời sống này,\nKhông phải không có luật,\nNhưng các món đồ ăn,\nKhông có gì gần tâm\nDo có các món ăn,,\nThân thể được tồn tại,\nThấy vậy, ta bộ hành,\nTìm kiếm các món ăn.\n\n124. Bậc trí kinh nghiệm rằng:\nThật sự là đám bùn,\nÐảnh lễ và cúng dường,\nXuất phát tự gia đình,\nNhư mũi tên tế nhị,\nRất khó nhổ được ra,\nCũng vậy với kẻ ngu,\nCung kính khó từ bỏ.`, ref: "Trưởng Lão Tăng Kệ 2.2", url: "https://loicuaducphat.org/thag/thag2.2.html#content" },

{ text: `Trưởng Lão Valliya\n\n125. Trong chòi nhỏ, năm cửa,\nCó con khỉ đi vào,\nLoanh quanh từng cửa một,\nNó va chạm từng giây!\n\n126. Này khỉ, hãy dừng lại!\nChớ có chạy như vậy,\nNgươi không còn như trước,\nTrí tuệ cầm giữ ngươi,\nNgươi đâu còn có thể,\nÐi xa như trước được.`, ref: "Trưởng Lão Tăng Kệ 2.3", url: "https://loicuaducphat.org/thag/thag2.3.html#content" },

{ text: `Trưởng Lão Gangatiriya\n\n127. Trên bờ sông Hằng Hà,\nDùng ba lá thốt nốt,\nTa dựng lên cho ta\nMột chòi lá nho nhỏ,\nBát ta là cái ghè,\nDùng cúng sữa người chết,\nCòn y áo của ta\nLượm chắp từ đống rác.\n\n128. Suốt hai năm sống vậy.\nTa chỉ nói một chữ,\nTrong khoảng năm thứ ba,\nKhối si ám tan tành.`, ref: "Trưởng Lão Tăng Kệ 2.4", url: "https://loicuaducphat.org/thag/thag2.4.html#content" },

{ text: `Trưởng Lão Ajina\n\n129. Nếu chứng được Ba minh,\nÐoạn tử, không lậu hoặc,\nVị ấy vẫn có thể,\nKhông được người biết đến,\nVà kẻ ngu không biết,\nCó thể sanh khinh thường.\n\n130. Khi người ấy nhận được\nÐồ ăn uống cúng dường,\nDẫu cho có ác pháp,\nVẫn được họ kính trọng.`, ref: "Trưởng Lão Tăng Kệ 2.5", url: "https://loicuaducphat.org/thag/thag2.5.html#content" },

{ text: `Trưởng Lão Melajina\n\n131. Khi ta nghe Chánh pháp,\nBậc Ðạo Sư thuyết giảng,\nTa thắng tri nghi hoặc,\nBậc toàn trí, toàn thắng.\n\n132. Ðối vị trưởng lữ đoàn,\nVới vị đại anh hùng,\nTrong các bậc đánh xe\nBậc tối thắng vô thượng,\nÐối con đường, lộ trình\nTa không có nghi hoặc.`, ref: "Trưởng Lão Tăng Kệ 2.6", url: "https://loicuaducphat.org/thag/thag2.6.html#content" },

{ text: `Trưởng Lão Radha\n\n133. Như mái nhà vụng lợp,\nMưa dễ thấm ướt vào,\nCũng vậy, tâm vụng tu\nTham ái được xâm nhập.\n\n134. Như mái nhà khéo lợp\nMưa không thể thấm vào,\nCũng vậy, tâm khéo tu\nTham ái không xâm nhập.`, ref: "Trưởng Lão Tăng Kệ 2.7", url: "https://loicuaducphat.org/thag/thag2.7.html#content" },

{ text: `Trưởng Lão Suradha\n\n135. Sanh của ta đã tận,\nChiến thắng dạy, làm xong,\nLưới danh được đoạn diệt,\nGốc sanh hữu nhổ lên.\n\n136. Mục đích hạnh xuất gia,\nBỏ nhà, sống không nhà,\nÐích ấy đã đạt được,\nMọi kiết sử, diệt xong.`, ref: "Trưởng Lão Tăng Kệ 2.8", url: "https://loicuaducphat.org/thag/thag2.8.html#content" },

{ text: `Trưởng Lão Gotama\n\n137. Bậc ẩn sĩ nằm ngủ,\nSống an lạc hạnh phúc,\nHọ không bị nữ nhân,\nTrói buộc và chi phối.\nNữ nhân, phải luôn luôn\nPhòng hộ và chế ngự.\nSự thật về nữ nhân,\nThật khó được chấp nhận.\n\n138. Hỡi này các dục vọng,\nTa quyết giết các ngươi,\nNay chúng ta đối ngươi,\nKhông còn gì nợ nần,\nChúng ta nay đi đến\nCảnh giới gọi Niết bàn,\nÐi đến tại chỗ ấy\nKhông còn có sầu muộn.`, ref: "Trưởng Lão Tăng Kệ 2.9", url: "https://loicuaducphat.org/thag/thag2.9.html#content" },

{ text: `Trưởng Lão Vasabha\n\n140. Không phải Bà-la-môn,\nVới dung sắc bên ngoài,\nBà-la-môn chính thống,\nPhải dung sắc bên trong,\nVới ai, làm ác nghiệp,\nNgười ấy là hắc nhân,\nLà chồng của Sujà.`, ref: "Trưởng Lão Tăng Kệ 2.10", url: "https://loicuaducphat.org/thag/thag2.10.html#content" },

{ text: `Trưởng Lão Mahacunda\n\n141. Khéo nghe, nghe tăng trưởng,\nNghe tăng trưởng, phát tuệ,\nNhờ tuệ biết ý nghĩa,\nNghĩa được biết, lạc đến.\n\n142. Hãy trú chỗ xa vắng,\nHãy sống, thoát kiết sử,\nTại đấy, hỷ chưa đạt,\nHãy sống giữa chúng Tăng,\nTự ngã được chế ngự,\nAn trú trong chánh niệm.`, ref: "Trưởng Lão Tăng Kệ 2.11", url: "https://loicuaducphat.org/thag/thag2.11.html#content" },

{ text: `Trưởng Lão Jotidasa\n\n143. Những ai dùng dây thừng,\nHành cướp giật nhiều cách,\nNhững dân họ hung bạo,\nLàm não hại người khác,\nNhư vậy, họ gieo hại,\nVì nghiệp không tiêu mất.\n\n144. Người nào làm nghiệp gì,\nNghiệp thiện hay nghiệp ác,\nHọ thừa tự nghiệp ấy,\nLoại nghiệp họ đang làm.`, ref: "Trưởng Lão Tăng Kệ 2.12", url: "https://loicuaducphat.org/thag/thag2.12.html#content" },

{ text: `Trưởng Lão Herannakani\n\n145. Ðêm ngày chạy, trôi qua,\nMạng sống bị tổn giảm\nTuổi thọ người hủy diệt,\nNhư nước dòng suối con.\n\n146. Kẻ ngu làm ác hạnh,\nKhông hiểu việc mình làm,\nVề sau bị khổ đau,\nKhi ác nghiệp chín muồi.`, ref: "Trưởng Lão Tăng Kệ 2.13", url: "https://loicuaducphat.org/thag/thag2.13.html#content" },

{ text: `Trưởng Lão Somamitta\n\n147. Như leo trên ván nhỏ,\nGiữa biển lớn bị chìm,\nCũng vậy đến kẻ khác,\nNgười hạnh tốt cũng chìm.\nDo vậy hãy bỏ nó,\nKẻ làm biếng làm nhác.\n\n148. Hãy sống gần bậc Thánh,\nBậc viễn ly, tinh cần,\nThiền định, thường tinh tấn,\nBậc Hiền trí sáng suốt.`, ref: "Trưởng Lão Tăng Kệ 2.14", url: "https://loicuaducphat.org/thag/thag2.14.html#content" },

{ text: `Trưởng Lão Mahakala\n\n152. Ai không rõ biết vậy,\nLại tác thành sanh y,\nKẻ ngu bước đi đến,\nChịu khổ đau liên tục,\nDo vậy ai hiểu biết,\nKhông tạo nên sanh y,\nTa sẽ không nằm xuống,\nVới đầu bị bẻ nát.`, ref: "Trưởng Lão Tăng Kệ 2.16", url: "https://loicuaducphat.org/thag/thag2.16.html#content" },

{ text: `Trưởng Lão Tissa\n\n153. Vị trọc đầu, đắp y,\nÐược nhiều kẻ thù oán\nKhi nhận đồ ăn uống,\nVải mặc và chỗ nằm.\n\n154. Biết nguy hiểm như vậy,\nBiết có sợ hãi lớn,\nTrong cung kính cúng dường;\nVị Tỷ-kheo xuất gia,\nNhận ít, không tham đắm,\nLuôn luôn giữ chánh niệm.`, ref: "Trưởng Lão Tăng Kệ 2.17", url: "https://loicuaducphat.org/thag/thag2.17.html#content" },

{ text: `Trưởng Lão Kimbila\n\n155. Trong vườn trúc phía Ðông,\nCác Thích tử thân hữu,\nTừ bỏ những tài sản,\nKhông phải là ít oi,\nVui thích với những gì,\nNhận được từ bình bát.\n\n156. Siêng, tinh cần, tinh tấn,\nThường kiên trì hăng hái,\nƯa thích lạc pháp vị,\nTừ bỏ lạc thế gian.`, ref: "Trưởng Lão Tăng Kệ 2.18", url: "https://loicuaducphat.org/thag/thag2.18.html#content" },

{ text: `Trưởng Lão Nanda\n\n157. Không như lý tác ý,\nTa chuyên trang sức ngoài,\nTa thô tháo dao động,\nSay đắm trong tham dục.\n\n158. Với phương tiện thiện xảo,\nTa, bà con mặt trời,\nÐược hướng về chánh lý,\nLàm ta thoát sanh hữu.`, ref: "Trưởng Lão Tăng Kệ 2.19", url: "https://loicuaducphat.org/thag/thag2.19.html#content" },

{ text: `Trưởng Lão Sirima\n\n159. Người khác tán thán nó,\nKẻ tự ngã chưa định,\nNgười khác khen sai lầm,\nKẻ tự ngã chưa định.\n\n160. Người khác chỉ trích nó,\nKẻ tự ngã đã định,\nNgười khác chê sai lầm,\nKẻ tự ngã khéo định.`, ref: "Trưởng Lão Tăng Kệ 2.20", url: "https://loicuaducphat.org/thag/thag2.20.html#content" },

{ text: `Trưởng Lão Uttara\n\n161. Ta liễu tri các uẩn,\nTa khéo nhổ tham ái,\nTa tu tập giác chi,\nTa đạt lậu hoặc diệt.\n\n162. Do liễu tri các uẩn,\nThoát ly kẻ gài lưới,\nTu tập giác chi xong,\nTa sẽ nhập Niết-bàn,\nCác lậu hoặc tận diệt.`, ref: "Trưởng Lão Tăng Kệ 2.21", url: "https://loicuaducphat.org/thag/thag2.21.html#content" },

{ text: `Trưởng Lão Sobhita\n\n165. Tỷ-kheo giữ chánh niệm,\nVới trí tuệ tinh cần,\nMột đêm, ta nhớ đến,\nCó đến năm trăm kiếp.\n\n166. Ta tu Bốn niệm xứ,\nBảy giác chi, Tám thánh (đạo),\nMột đêm, ta nhớ đến,\nCó đến năm trăm kiếp.`, ref: "Trưởng Lão Tăng Kệ 2.23", url: "https://loicuaducphat.org/thag/thag2.23.html#content" },

{ text: `Trưởng Lão Valliya\n\n167. Những bổn phận cần làm,\nVới tinh cần tinh tấn,\nNhững bổn phận cần làm\nVới người muốn giác ngộ.\nCon sẽ làm tất cả,\nCon không có thối thất,\nHãy xem sự tinh tấn,\nSự nỗ lực của con.\n\n168. Ngài hãy nói cho con,\nCon đường nhập bất tử,\nVới yên lặng thiền tư,\nCon đạt Thánh yên lặng,\nNhư dòng sông Hằng Hà,\nNhập sâu vào biển cả.`, ref: "Trưởng Lão Tăng Kệ 2.24", url: "https://loicuaducphat.org/thag/thag2.24.html#content" },

{ text: `Trưởng Lão Vitasoka\n\n169. Hãy cạo tóc cho ta\nNgười cạo tóc đã đến,\nTa cầm lấy cái gương,\nQuan sát thân thể ta.\n\n170. Thân được thấy trống rỗng,\nChìm tối trong đêm đen,\nMọi vải quấn chặt đứt,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 2.25", url: "https://loicuaducphat.org/thag/thag2.25.html#content" },

{ text: `Trưởng Lão Punnamasa\n\n171. Từ bỏ năm triền cái,\nÐạt an ổn khỏi ách,\nNắm giữ gương Chánh pháp,\nBiết và thấy tự ngã.\n\n172. Ta quán sát thân này,\nTừ trong cho đến ngoài,\nThân được thấy trống không,\nTrong thân cả ngoài thân.`, ref: "Trưởng Lão Tăng Kệ 2.26", url: "https://loicuaducphat.org/thag/thag2.26.html#content" },

{ text: `Trưởng Lão Nandaka\n\n173. Như con vật hiền thiện,\nThuộc giống tốt, khéo luyện,\nSau khi ngã quỵ xuống,\nLại gượng lên đứng dậy,\nLấy được thêm sức mạnh,\nKhông bỏ kéo gánh nặng.\n\n174. Cũng vậy, hãy nhận con,\nÐệ tử bậc Chánh giác,\nCon đầy đủ chánh kiến,\nKhéo tu luyện thuần thục,\nCon thật con chánh thống.\nCủa đức Phật Chánh giác.`, ref: "Trưởng Lão Tăng Kệ 2.27", url: "https://loicuaducphat.org/thag/thag2.27.html#content" },

{ text: `Trưởng Lão Bharata\n\n175. Hãy đến Nandaka,\nChúng ta hãy cùng đi,\nÐi đến bậc Giáo thọ,\nChúng ta hãy rống lên,\nTiếng rống con sư tử,\nTrước mặt Phật tối thượng.\n\n176. Ẩn sĩ thương chúng ta,\nKhích lệ ta xuất gia,\nMục đích chúng ta đạt,\nMọi kiết sử đoạn tận.`, ref: "Trưởng Lão Tăng Kệ 2.28", url: "https://loicuaducphat.org/thag/thag2.28.html#content" },

{ text: `177. Như những con sư tử\nTrong hang động núi non,\nRống tiếng rống sư tử,\nCũng vậy với trí tuệ,\nBậc anh hùng thắng trận,\nThắng ma và ma quân.\n\n178. Ta hầu bậc Ðạo Sư\nÐảnh lễ Pháp và Tăng,\nTa hân hoan vui vẻ,\nThấy con chứng vô lậu.`, ref: "Trưởng Lão Tăng Kệ 2.29", url: "https://loicuaducphat.org/thag/thag2.29.html#content" },

{ text: `179. Hầu hạ bậc chân nhân,\nLuôn luôn nghe Chánh pháp,\nNghe xong, ta sẽ bước,\nTrên con đường bất tử.\n\n180. Trong ta, tham hữu đoạn,\nTham hữu không có mặt,\nQuá khứ, và vị lai,\nKhông có ở trong ta,\nHiện tại cũng không có,\nTồn tại ở trong ta.`, ref: "Trưởng Lão Tăng Kệ 2.30", url: "https://loicuaducphat.org/thag/thag2.30.html#content" },

{ text: `181. Từ khi ta xuất gia,\nTrong pháp bậc Chánh giác,\nGiải thoát, ta tiến lên,\nTa vượt qua dục giới.\n\n182. Nhờ Phạm-chí quán sát,\nTâm ta được giải thoát,\nTa giải thoát bất động,\nMọi kiết sử đoạn diệt.`, ref: "Trưởng Lão Tăng Kệ 2.31", url: "https://loicuaducphat.org/thag/thag2.31.html#content" },

{ text: `Trưởng Lão Sivaka\n\n183. Vô thường, những ngôi nhà,\nÐây đó lại dựng lên,\nTìm kiếm người làm nhà,\nTái sanh là đau khổ.\n\n184. Hỡi kẻ làm nhà kia!\nNgươi đã bị thấy rồi,\nTừ nay, ngươi không thể,\nLại dựng nhà lên nữa,\nMọi tường vách đổ vỡ,\nNóc nhà bị tan hoang,\nTâm bị đẩy khỏi dòng,\nỞ đây, bị thổi nát.`, ref: "Trưởng Lão Tăng Kệ 2.32", url: "https://loicuaducphat.org/thag/thag2.32.html#content" },

{ text: `Trưởng Lão Isidinna\n\n187. Ta thấy người cư sĩ,\nTrì pháp với lời nói,\nCác dục là vô thường,\nHọ ưa thích ái luyến,\nChâu báu và vòng nhẫn,\nHọ đón chờ vợ con.\n\n188. Thật sự họ không biết,\nPháp như thật là gì?\nDầu họ có tuyên bố:\n'Các dục là vô thường!'\nHọ không có sức mạnh,\nÐể cắt đứt tham ái,\nDo vậy, họ luyến tiếc,\nVợ con và tài sản.`, ref: "Trưởng Lão Tăng Kệ 2.34", url: "https://loicuaducphat.org/thag/thag2.34.html#content" },

{ text: `Trưởng Lão Sambulakaccana\n\n189. Mưa ào ào đổ xuống,\nMưa ầm ầm vang động,\nTa sống chỉ một mình,\nTrong hang động kinh hoàng,\nDầu ta sống một mình,\nTrong hang động kinh hoàng,\nTa không hoảng, sợ hãi,\nKhông lông tóc dựng ngược\n\n190. Pháp nhĩ ta là vậy,\nNên dầu sống một mình,\nTrong hang động kinh hoàng,\nTa không hoảng, sợ hãi,\nKhông lông tóc dựng ngược.`, ref: "Trưởng Lão Tăng Kệ 2.35", url: "https://loicuaducphat.org/thag/thag2.35.html#content" },

{ text: `Trưởng Lão Nitaka\n\n191. Tâm ái như tảng đá\nÐứng vững, không dao động,\nHỡi những vật khả ái,\nTâm không có tham ái,\nÐối vật làm dao động,\nTâm không có dao động,\nTâm ai tu tập vậy,\nTừ đâu, khổ sẽ đến.\n\n192. Tâm ta như tảng đá\nÐứng vững, không dao động,\nÐối những vật khả ái,\nTâm không có tham ái,\nÐối vật làm dao động,\nTâm không có dao động,\nTâm ta tu tập vậy,\nTừ đâu, khổ đến ta.`, ref: "Trưởng Lão Tăng Kệ 2.36", url: "https://loicuaducphat.org/thag/thag2.36.html#content" },

{ text: `Trưởng Lão Sonapotiriyaputta\n\n193. Thầy chớ có ngủ nữa,\nVới đêm, sao vòng hoa,\nÐêm này, người có trí,\nThức dậy, không có ngủ.\n\n194. Khi con voi tấn công,\nRơi từ lưng voi xuống,\nTrên chiến trường ta chết,\nTốt hơn sống bại trận.`, ref: "Trưởng Lão Tăng Kệ 2.37", url: "https://loicuaducphat.org/thag/thag2.37.html#content" },

{ text: `Trưởng Lão Nisabha\n\n195. Sau khi đã từ bỏ\nNăm loại dục trưởng dưỡng,\nNhững vật thật khả ái,\nKhiến tâm ý thích thú,\nVới lòng tin, xuất gia,\nChấm dứt sự khổ đau.\n\n196. Ta không hoan hỷ chết,\nTa không hoan hỷ sống,\nTa chờ đợi thời đến,\nTỉnh giác và chánh niệm.`, ref: "Trưởng Lão Tăng Kệ 2.38", url: "https://loicuaducphat.org/thag/thag2.38.html#content" },

{ text: `Trưởng Lão Kappatakura\n\n199. Ðây là đồ rách rưới,\nCủa Kappata-kura,\nY áo đang phủ đắp,\nThật là quá nặng nề,\nTrong bình bát bất tử,\nÐược đựng đầy Chánh pháp,\nNhưng nó không thực hành,\nCon đường hành thiền định.\n\n200. Hỡi này Kappata,\nChớ lắc qua lắc lại,\nChớ khiến ta phải đánh,\nCác tiếng vào tai ông,\nHỡi này Kappata,\nChớ làm kẻ si mê,\nNgồi lắc qua lắc lại,\nGiữa Tăng chúng hội họp.`, ref: "Trưởng Lão Tăng Kệ 2.40", url: "https://loicuaducphat.org/thag/thag2.40.html#content" },

{ text: `Trưởng Lão Kumara-Kassapa\n\n201. Ôi Phật đà, ôi Pháp!\nÔi Ðạo Sư thành tựu!\nỞ đây, vị đệ tử,\nChứng đạt Chánh pháp này.\n\n202. Trải qua vô lượng kiếp,\nTa tác thành có thân,\nThân này thân cuối cùng,\nThân này hành trì xong,\nTrên con đường sống chết,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 2.41", url: "https://loicuaducphat.org/thag/thag2.41.html#content" },

{ text: `Trưởng Lão Dhammapala\n\n203. Ai Tỷ-kheo trẻ tuổi\nChú tâm hành lời Phật,\nTỉnh thức giữa người ngủ,\nVị ấy, đời không uổng.\n\n204. Do vậy, bậc Hiền trí,\nNhớ đến lời Phật dạy,\nChuyên tu tín và giới,\nHoan hỷ thấy Chánh pháp.`, ref: "Trưởng Lão Tăng Kệ 2.42", url: "https://loicuaducphat.org/thag/thag2.42.html#content" },

{ text: `Trưởng Lão Brahmali\n\n205. Với những ai, các căn,\nÐã đi đến tịnh chỉ,\nNhư được khéo điều phục,\nBởi đánh xe điều ngự,\nKiêu mạn được đoạn tận,\nKhông còn có lậu hoặc,\nChư Thiên rất ái mộ\nNhững vị có hạnh ấy.`, ref: "Trưởng Lão Tăng Kệ 2.43", url: "https://loicuaducphat.org/thag/thag2.43.html#content" },

{ text: `Trưởng Lão Mogharaja\n\n207. Hỡi Mogharàja!\nSống với da thô độc,\nSống với tâm hiền thiện,\nLuôn luôn hành thiền định,\nTrong những đêm đông giá\nThầy là một Tỷ-kheo,\nVậy Thầy sống thế nào\nThầy sẽ làm những gì?\n\n208. Con có được nghe rằng:\nỞ nước Magadha,\nÐất nước giàu thịnh vượng,\nToàn dân sống đầy đủ,\nNhững am lợp bằng rơm,\nCòn tốt đẹp hơn nhiều,\nHơn đời sống an lạc,\nCủa mọi người dân khác.`, ref: "Trưởng Lão Tăng Kệ 2.44", url: "https://loicuaducphat.org/thag/thag2.44.html#content" },

{ text: `Trưởng Lão Visakha, Con Của Pancali\n\n209. Chớ có tự kiêu mạn,\nChớ có khinh khi người,\nKhông khinh, không hại người,\nÐã đến bờ bên kia,\nVà chớ có khen mình,\nTrước mặt các hội chúng,\nKhông dao động, khiêm tốn,\nKhéo nói, khéo chế ngự.\n\n210. Với người, thấy ý nghĩa,\nTế nhị và kín đáo,\nThiện xảo về trí tuệ\nNếp sống khéo hộ trì,\nThực hiện giới chư Phật,\nNiết-bàn đối vị ấy,\nKhông gì khó chứng đạt.`, ref: "Trưởng Lão Tăng Kệ 2.45", url: "https://loicuaducphat.org/thag/thag2.45.html#content" },

{ text: `Trưởng Lão Culaka\n\n211. Những chim công kêu hót,\nMào đẹp, lông đuôi xinh,\nVới cổ, màu xanh tươi,\nMỏ đẹp, tiếng hót hay,\nÐất này, khéo lát cỏ,\nNước mắt khéo thấm nhuần,\nVới khoảng trời khéo che,\nMây mưa khéo bao phủ.\n\n212. Thân người khéo khỏe mạnh,\nTâm ý tốt, thiền tu,\nLành thay, khéo khởi tâm,\nTrong lời khéo Phật dạy.\nHãy cảm xúc con đường\nÐưa đến cõi bất tử,\nÐường ấy đường vô thượng,\nÐường trong trắng lành mạnh,\nÐường tế nhị nhỏ nhiệm,\nCon đường thật khéo thấy.`, ref: "Trưởng Lão Tăng Kệ 2.46", url: "https://loicuaducphat.org/thag/thag2.46.html#content" },

{ text: `Trưởng Lão Anupama\n\n213. Tâm đi đến hỷ mạn\nNhư bị đâm giáo nhọn,\nNếu người sống tâm ấy,\nNhư sống với giáo, gậy.\n\n214. Này tâm, ta gọi ngươi,\nKẻ bẻ gãy hạnh phúc,\nNày tâm, ta gọi ngươi,\nKẻ phá hoại đời ta!\nBậc Ðạo Sư của ngươi,\nKhó được nay đã được,\nChớ có dắt dẫn ta,\nÐến chỗ có hại ta!`, ref: "Trưởng Lão Tăng Kệ 2.47", url: "https://loicuaducphat.org/thag/thag2.47.html#content" },

{ text: `Trưởng Lão Vajjita\n\n215. Trong thời luân hồi dài,\nTa trôi lăn nhiều cõi,\nTa không thấy Thánh đế,\nTa phàm phu mù lòa.\n\n216. Với hạnh không phóng dật,\nTa phá vỡ luân hồi,\nMọi sanh thú chặt đứt,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 2.48", url: "https://loicuaducphat.org/thag/thag2.48.html#content" },

{ text: `Trưởng Lão Sandhita\n\n217. Dưới gốc cây Bồ-đề,\nVới ánh sáng lá xanh,\nKhi cây đang vươn lên,\nTrong sức sống lớn mạnh,\nMột tưởng về Phật hành,\nChánh niệm ta đạt được.\n\n218. Ðã qua ba mốt kiếp,\nTưởng ấy ta không chứng,\nNay chính nhờ tưởng ấy,\nTa đạt lậu hoặc diệt.`, ref: "Trưởng Lão Tăng Kệ 2.49", url: "https://loicuaducphat.org/thag/thag2.49.html#content" },

{ text: `Trưởng Lão Anganika Bharadvaja\n\n219. Trong rừng ta thờ lửa,\nTruyền thống không chơn chánh,\nKhông biết đường thanh tịnh,\nTheo khổ hạnh bất tử.\n\n220. Với lạc, ta được lạc,\nHãy xem pháp, tùy pháp,\nBa minh chứng đạt được,\nLời Phật dạy, làm xong.\n\n221. Trước bà con Phạm chí,\nNay ta chính Phạm chí,\nBa minh, ta quán đảnh,\nAn ổn ta đạt được,\nThông hiểu đúng Chánh pháp,\nThuần thục lời Phật dạy.`, ref: "Trưởng Lão Tăng Kệ 3.1", url: "https://loicuaducphat.org/thag/thag3.1.html#content" },

{ text: `Trưởng Lão Paccaya\n\n222. Năm ngày ta xuất gia,\nHữu học, ý chưa đạt,\nTa trú hạnh viễn ly,\nTâm phát nguyện như sau:\n\n223. Ta sẽ không ăn uống,\nKhông ra ngoài tinh xá,\nTa sẽ không nằm xuống,\nKhông nằm một bên hông,\nNếu mũi tên tham ái,\nChưa rút nhổ lên được.\n\n224. Hạnh ta sống như vậy,\nHãy nhìn ta tinh cần,\nBa minh ta đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 3.2", url: "https://loicuaducphat.org/thag/thag3.2.html#content" },

{ text: `Trưởng Lão Bakula\n\n225. Với ai những công việc\nCần phải làm từ trước,\nVề sau, vị ấy mới\nCó ý định muốn làm.\nVị ấy tự phá hoại\nCăn cứ địa an lạc,\nVề sau, chịu khổ đau\nTrong nung nấu hối tiếc.\n\n226. Hãy nói điều có làm,\nKhông nói điều không làm,\nBậc Hiền trí rõ biết,\nNgười chỉ nói, không làm.\n\n227. Niết-bàn nhiệm màu lạc,\nBậc Chánh Giác thuyết giảng,\nKhông sầu muộn ly tham,\nThật sự là an ổn,\nTại đấy, sự đau khổ,\nÐược đoạn diệt hoàn toàn.`, ref: "Trưởng Lão Tăng Kệ 3.3", url: "https://loicuaducphat.org/thag/thag3.3.html#content" },

{ text: `Trưởng Lão Dhaniya\n\n228. Nếu muốn mong đợi lạc\nTrong đời sống Sa-môn,\nChớ khinh y chúng Tăng,\nChớ khinh Tăng ẩm thực.\n\n229. Nếu muốn mong đợi lạc\nTrong đời sống Sa-môn,\nHãy sử dụng trú xứ,\nNhư rắn và như chuột.\n\n230. Nếu muốn mong đợi lạc\nTrong đời sống Sa-môn,\nHãy biết tự bằng lòng\nVới bất cứ việc gì,\nVà hãy cương quyết tu,\nTu tập hạnh nhất pháp.`, ref: "Trưởng Lão Tăng Kệ 3.4", url: "https://loicuaducphat.org/thag/thag3.4.html#content" },

{ text: `Trưởng Lão Matangaputta\n\n231. Ôi quá lạnh, quá nóng!\nÔi, đã quá trễ rồi!\nÐây là lời kêu than,\nNhư vậy bỏ việc làm,\nThời sát-na quý báu\nLặng lẽ vượt trôi qua.\n\n232. Ai nghĩ đến lạnh nóng,\nKhông hơn loài cỏ rác,\nLàm bổn phận con người,\nKhông hại đến an lạc.\n\n233. Cỏ dabba, ku-sa,\nLoại cỏ gai đâm ngực,\nTa dùng ngực đẩy chúng,\nSống tăng trưởng viễn ly.`, ref: "Trưởng Lão Tăng Kệ 3.5", url: "https://loicuaducphat.org/thag/thag3.5.html#content" },

{ text: `Trưởng Lão Khujja Sobhita\n\n234. Giữa các vị Sa-môn,\nSống Pàtaliputta,\nNhững vị luận thuyết giỏi,\nNhững vị có nghe nhiều,\nCó một vị tuổi lớn\nÐứng ở tại cửa vào,\nTên là Sobhita,\nCó tật, bị còm lưng.\n\n235. Giữa các vị Sa-môn,\nSống Pataliputta,\nNhững vị luận thuyết giỏi,\nNhững vị có nghe nhiều,\nCó một vị tuổi lớn,\nÐứng ở tại cửa vào,\nVị ấy đã đến đây,\nTheo ngọn gió đưa đến.\n\n236. Vị ấy khéo chiến đấu,\nVị ấy khéo tế tự,\nTrên chiến trường chiến đấu,\nVị ấy đã chiến thắng,\nVới Phạm hạnh tích lũy,\nVị ấy đạt an lạc.`, ref: "Trưởng Lão Tăng Kệ 3.6", url: "https://loicuaducphat.org/thag/thag3.6.html#content" },

{ text: `Trưởng Lão Varana\n\n237. Ai ở đời, giữa người,\nLàm hại chúng sanh khác,\nVị ấy tự hại mình\nÐời này và đời sau.\n\n238. Ai với tâm từ bi,\nThương tưởng mọi hữu tình,\nMột người làm như vậy,\nGặt phước đức thật nhiều.\n\n239. Hãy học tập khéo nói,\nHãy hầu hạ Sa-môn,\nSống một mình kín đáo,\nVới tâm tư tịnh chỉ.`, ref: "Trưởng Lão Tăng Kệ 3.7", url: "https://loicuaducphat.org/thag/thag3.7.html#content" },

{ text: `Trưởng Lão Vassika\n\n240. Dầu chỉ một mình ta,\nCó lòng tin, sáng suốt,\nGiữa các bà con ta,\nNhững người không lòng tin,\nThông hiểu được Chánh pháp,\nÐầy đủ những giới đức,\nVì lợi ích hạnh phúc,\nCho các bà con ta.\n\n241. Những bà con bị ta,\nVì thương họ trách móc,\nDo bà con ái mộ,\nLàm tốt đối Tỷ-kheo.\n\n242. Khi họ bị mệnh chung,\nHọ được lạc chư Thiên,\nCác anh và mẹ ta,\nHoan hỷ điều họ muốn.`, ref: "Trưởng Lão Tăng Kệ 3.8", url: "https://loicuaducphat.org/thag/thag3.8.html#content" },

{ text: `Trưởng Lão Yasoja\n\n243. Một người đen, gầy mòn,\nYếu ốm đầy đường gân,\nTiết độ trong ăn uống,\nTâm tư không ưu não.\n\n244. Trong rừng núi rộng lớn,\nBị muỗi ruồi đốt cắn,\nNhư con voi lâm trận,\nTa chánh niệm chịu đựng.\n\n245. Sống một, như Phạm thiên,\nSống hai, như chư Thiên,\nSống ba, như làng mạc,\nNhiều hơn, như ở chợ.`, ref: "Trưởng Lão Tăng Kệ 3.9", url: "https://loicuaducphat.org/thag/thag3.9.html#content" },

{ text: `Trưởng Lão Satimattiya\n\n246. Lòng tin trước ông có,\nNay không còn nơi ông,\nCủa ông vẫn của ông,\nTa không có ác hạnh.\n\n247. Vô thường và dao động,\nLà lòng tin của ông,\nSự thấy là như vậy,\nLà sự thấy của ta,\nCó khi ông thương mến,\nRồi ông lại không ưa,\nVì sao bậc ẩn sĩ,\nChịu héo mòn ở đây?\n\n248. Cơm nấu cho ẩn sĩ,\nÍt ít từng gia đình,\nTa sẽ đi khất thực,\nỐng chân ta còn mạnh.`, ref: "Trưởng Lão Tăng Kệ 3.10", url: "https://loicuaducphat.org/thag/thag3.10.html#content" },

{ text: `Trưởng Lão Upali\n\n249. Vì lòng tin ra đi,\nMới xuất gia, tân học,\nHãy sống với bạn lành,\nMạng thanh tịnh, không nhác.\n\n250. Vì lòng tin, ra đi,\nMới xuất gia, tân học,\nTỷ-kheo trú giữa chúng,\nSáng suốt, học Luật tạng.\n\n251. Vì lòng tin, ra đi,\nMới xuất gia, tân học,\nKhéo biết việc nên làm,\nVà việc không nên làm,\nHãy để vị ấy sống,\nKhông để cao tôn xưng.`, ref: "Trưởng Lão Tăng Kệ 3.11", url: "https://loicuaducphat.org/thag/thag3.11.html#content" },

{ text: `Trưởng Lão Uttarapala\n\n252. Ta thật là hiền thiện,\nSuy tư mục đích tốt,\nBỏ năm dục trưởng dưỡng,\nLà thế giới si mê.\n\n253. Sanh trong giới vức ma,\nBị tên mạnh xung kích,\nNhưng ta giải thoát được,\nCạm bẫy của Ma vương.\n\n254. Mọi dục, ta đoạn tận,\nMọi sanh hữu, hủy hoại,\nÐường sanh tử chấm dứt,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 3.12", url: "https://loicuaducphat.org/thag/thag3.12.html#content" },

{ text: `Trưởng Lão Abhibhuta\n\n255. Hãy nghe mọi bà con,\nNhững ai đã đến đây,\nTa thuyết pháp cho ông,\nTái sanh là đau khổ.\n\n256. Hãy tinh cần, ra đi,\nChú tâm lời Phật dạy,\nÐánh bại quân lực ma,\nNhư voi, nhà cỏ lau.\n\n257. Ai trong Pháp Luật này,\nSẽ sống không phóng dật,\nTừ bỏ dòng tái sanh,\nSẽ chấm dứt khổ đau.`, ref: "Trưởng Lão Tăng Kệ 3.13", url: "https://loicuaducphat.org/thag/thag3.13.html#content" },

{ text: `Trưởng Lão Gotama\n\n258. Ta tái sanh địa ngục,\nLiên tục đến ngạ quỷ,\nTa sống trải nhiều ngày,\nTrong đau khổ bàng sanh.\n\n259. Và sống vui làm Người,\nThỉnh thoảng sanh cõi Trời,\nTrú Giới sắc, Vô sắc,\nPhi tưởng, Phi phi tưởng.\n\n260. Ta khéo biết sanh hữu,\nKhông cốt tủy, duyên thành,\nDao động thường biến chuyển,\nTác thành tự ngã ta,\nTa đạt được tịnh tịch,\nChánh niệm tâm an trú.`, ref: "Trưởng Lão Tăng Kệ 3.14", url: "https://loicuaducphat.org/thag/thag3.14.html#content" },

{ text: `Trưởng Lão Harita\n\n261. Với ai, những công việc,\nCần phải làm từ trước,\nVề sau, vị ấy mới\nCó ý định muốn làm.\nVị ấy, tự phá hoại,\nCăn cứ địa an lạc,\nVề sau chịu khổ đau\nTrong nung nấu hối tiếc.\n\n262. Hãy nói điều có làm,\nKhông nói điều không làm,\nBậc Hiền trí rõ biết,\nNgười chỉ nói, không làm.\n\n263. Niết-bàn khéo an lạc,\nBậc Chánh giác thuyết giảng,\nKhông sầu muộn, ly tham,\nThật sự, là an ổn,\nTại đấy, nỗi đau khổ,\nÐược đoạn diệt hoàn toàn.`, ref: "Trưởng Lão Tăng Kệ 3.15", url: "https://loicuaducphat.org/thag/thag3.15.html#content" },

{ text: `Trưởng Lão Vimala\n\n264. Hãy tránh xa bạn ác,\nGiao thiệp bậc thượng nhân,\nVâng theo lời khuyến giáo,\nHướng đến lạc bất động.\n\n265. Như leo trên ván nhỏ,\nGiữa biển lớn bị chìm,\nCũng vậy đến kẻ khác,\nNgười hạnh tốt cũng chìm.\nDo vậy hãy bỏ nó,\nKẻ làm biếng, làm nhác.\n\n266. Hãy sống gần bậc Thánh,\nBậc viễn ly tinh cần,\nThiền định, thường tinh tấn,\nBậc Hiền trí sáng suốt.`, ref: "Trưởng Lão Tăng Kệ 3.16", url: "https://loicuaducphat.org/thag/thag3.16.html#content" },

{ text: `267. Trang điểm, mặc áo đẹp,\nÐeo vòng hoa, thơm nức,\nMùi thơm gỗ chiên đàn,\nGiữa đám đông, đường lớn,\nMột vũ nữ đang múa,\nMúa lượn theo nhạc khí.\n\n268. Ta vào thành, khất thực,\nÐi ngang, ta thấy nàng\nTrang điểm, mặc áo đẹp,\nGieo bẫy mồi thần chết.\n\n269. Rồi ta tự tác ý,\nNhư lý khởi tư duy,\nCác hiểm nguy hiển lộ,\nNhàm chán, ta an trú.\n\n270. Và tâm ta giải thoát,\nThấy pháp nhĩ là vậy,\nBa minh chứng đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 4.1", url: "https://loicuaducphat.org/thag/thag4.1.html#content" },

{ text: `Trưởng Lão Bhagu\n\n271. Bị buồn ngủ chi phối,\nTa ra khỏi tinh xá,\nLại lên đường kinh hành,\nTại đấy té xuống đất.\n\n272. Xoa bóp cả chân tay,\nLại lên đường kinh hành,\nQua lại đường kinh hành,\nNội tâm ta định tĩnh.\n\n273. Rồi ta tự tác ý,\nNhư lý khởi tư duy,\nCác hiểm nguy hiển lộ,\nNhàm chán ta an trú.\n\n274. Và tâm ta giải thoát\nThấy pháp nhĩ là vậy,\nBa minh chứng đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 4.2", url: "https://loicuaducphat.org/thag/thag4.2.html#content" },

{ text: `Trưởng Lão Sabhiya\n\n275. Người khác không rõ biết,\nTa ở đây một thời,\nTại đây, bậc có trí,\nBiết vậy sống tịnh chỉ.\n\n276. Khi họ không rõ biết,\nHọ làm như bất tử;\nKhi họ rõ biết pháp,\nGiữa bệnh, họ không bệnh.\n\n277. Ai sở hành phóng đãng,\nCấm giới bị uế nhiễm,\nPhạm hạnh đáng nghi ngờ,\nVị ấy chứng quả lớn,\n\n278. Sống giữa đồng Phạm hạnh,\nKhông được trọng, tôn kính,\nVị ấy xa Diệu pháp,\nNhư trời xa đất liền.`, ref: "Trưởng Lão Tăng Kệ 4.3", url: "https://loicuaducphat.org/thag/thag4.3.html#content" },

{ text: `Trưởng Lão Nandaka\n\n279. Gớm thay, vật hôi thối!\nÐầy sắc mùi hôi tanh,\nVật sở hữu của ma,\nỨ chảy nhiều dòng nước,\nThân này có chín dòng,\nLuôn luôn được tuôn chảy.\n\n280. Chớ khinh miệt cổ nhân!\nChớ xúc phạm Như Lai,\nHọ không tham thiên giới,\nCòn nói gì cõi người.\n\n281. Kẻ ngu, thiếu trí tuệ,\nTà ý, si bao phủ,\nKẻ ấy đầy tham đắm,\nBị ma quăng dây trói.\n\n282. Những ai đã thoát ly,\nTham, sân và vô minh,\nÐây họ không tham đắm,\nDây cắt, không trói buộc.`, ref: "Trưởng Lão Tăng Kệ 4.4", url: "https://loicuaducphat.org/thag/thag4.4.html#content" },

{ text: `Trưởng Lão Jambuka\n\n283. Trải năm mươi lăm năm,\nThân đầy những bụi bặm,\nĂn cơm tháng một lần,\nTóc râu ta nhổ sạch.\n\n284. Ta đứng chỉ một chân,\nTa không dùng giường nằm,\nTa ăn phân phơi khô,\nTa không nhận lời mời.\n\n285. Sở hành ta nhiều vậy,\nDẫn ta đến ác thú,\nBị nước lớn cuốn trôi,\nCho đến khi quy Phật.\n\n286. Hãy nhìn Phật ta quy,\nHãy nhìn Pháp, pháp nhĩ,\nBa minh ta đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 4.5", url: "https://loicuaducphat.org/thag/thag4.5.html#content" },

{ text: `287. Thật tốt lành cho ta,\nKhi ở thành Gayà,\nTrong tháng lễ mùa xuân,\nTháng tên Phagguna,\nTa thấy bậc Chánh Giác,\nThuyết Chánh pháp tối thượng.\n\n288. Bậc có hào quang lớn,\nLà Ðạo Sư hội chúng,\nÐạt được vị tối thắng,\nBậc lãnh đạo nhiếp chúng,\nChiến thắng giới Trời, Người,\nBậc thấy khó cân lường.\n\n289. Ðại long tượng, đại hùng,\nÐại quang minh, vô lậu,\nMọi lậu hoặc đoạn tận,\nÐạo Sư, không sợ hãi.\n\n290. Lâu nay ta uế nhiễm,\nBị tà kiến trói buộc,\nNay chính Thế Tôn ấy,\nGiải thoát Senaka,\nThoát khỏi mọi buộc ràng,\nÐược tự tại, giải thoát.`, ref: "Trưởng Lão Tăng Kệ 4.6", url: "https://loicuaducphat.org/thag/thag4.6.html#content" },

{ text: `291. Ai khi phải từ từ\nLại lội qua gấp gấp,\nAi khi phải lội gấp,\nLại từ từ lội qua,\nKẻ ngu thiếu chánh lý,\nÐi đến cảnh khổ đau.\n\n292. Lợi ích bị tổn giảm,\nNhư trăng vào thời đen,\nGặp phải sự ô nhục,\nChống đối các bạn bè.\n\n293. Ai khi phải từ từ,\nLội qua rất từ từ,\nAi khi phải lội gấp,\nLội qua thật gấp gáp,\nKẻ trí có chánh lý,\nÐi đến cảnh an lạc.\n\n294. Lợi ích được viên mãn,\nNhư trăng vào thời sáng,\nÐược danh tiếng vinh dự,\nKhông chống đối bạn bè.`, ref: "Trưởng Lão Tăng Kệ 4.7", url: "https://loicuaducphat.org/thag/thag4.7.html#content" },

{ text: `296. Các lậu hoặc ta đoạn,\nKhông còn có tái sanh,\nTa là bậc La-hán,\nÐáng được sự cúng dường.\nBa minh ta đạt được,\nThấy đuợc giới bất tử.\n\n297. Bị dục làm mù quáng,\nBị lưới tà bao trùm,\nKhát ái làm màn che,\nBao trùm che phủ kín.\nDo phóng dật trói buộc,\nNhư cá mắc mắt lưới.\n\n298. Ta vượt qua dục ấy,\nCắt đứt ma trói buộc,\nNhổ lên gốc khát ái,\nTa mát lạnh tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 4.8", url: "https://loicuaducphat.org/thag/thag4.8.html#content" },

{ text: `Trưởng Lão Candana\n\n299. Với vàng che phủ kín,\nChúng nữ tỳ vây quanh,\nMang theo đứa con thơ,\nNgười vợ đến với ta.\n\n300. Thấy mẹ của con ta,\nTừ xa đang đi đến,\nKhéo trang điểm đẹp đẽ,\nNhư ma gieo bẫy mồi.\n\n301. Rồi ta tự tác ý,\nNhư lý khởi tư duy,\nCác hiểm nguy hiển lộ,\nNhàm chán, ta an trú.\n\n302. Và tâm ta giải thoát,\nThấy pháp nhĩ là vậy,\nBa minh chứng đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 4.9", url: "https://loicuaducphat.org/thag/thag4.9.html#content" },

{ text: `Trưởng Lão Dhammika\n\n303. Pháp che chở hộ trì,\nNgười hành trì Chánh pháp,\nPháp đem lại an lạc,\nCho người khéo hành pháp,\nÐây là những lợi ích,\nKhi pháp khéo hành trì,\nNgười hành trì Chánh pháp,\nKhông đi xuống ác thú.\n\n304. Cả hai pháp, phi pháp,\nKết quả không giống nhau;\nPhi pháp, dẫn địa ngục,\nPháp đưa đến cõi lành.\n\n305. Do vậy, đối Chánh pháp,\nKhởi ý muốn hành trì,\nTâm tư sanh hoan hỷ,\nKhéo thiện lai như vậy.\nVững trú trên Chánh pháp,\nÐệ tử bậc Thiện Thệ,\nSáng suốt tiến bước lên,\nQuy y bậc tối thượng.\n\n306. Phá vỡ cội ung nhọt,\nNhổ lên lưới ái triền,\nLuân hồi được đoạn tận,\nKhông còn có sanh y,\nNhư trăng vào ngày rằm,\nTrong đêm thanh trong sáng.`, ref: "Trưởng Lão Tăng Kệ 4.10", url: "https://loicuaducphat.org/thag/thag4.10.html#content" },

{ text: `Trưởng Lão Sabbaka\n\n307. Khi ta thấy con cò,\nTrương đôi cánh trắng tinh,\nSợ hãi đám mây đen,\nTìm chỗ kín ẩn nấp;\nKhi ấy chính con sông,\nAjakaranì,\nÐem hoan hỷ cho ta.\n\n308. Khi ta thấy con cò,\nTrương đôi cánh trắng sạch,\nSợ hãi đám mây đen,\nTìm hang để ẩn nấp,\nNhưng tìm không có thấy.\nKhi ấy chính con sông,\nAjakaranì,\nÐem hoan hỷ cho ta.\n\n309. Ai lại không thích thú,\nKhi thấy ở tại đây,\nTrên cả hai dãy bờ,\nCó hàng cây Jambu,\nLàm chói sáng bờ sông,\nSau lưng cái hang lớn.\n\n310. Hãy nghe những con nhái,\nKhéo thoát những đàn rắn,\nKêu lên niềm hoan hỷ,\nVới tiếng kêu nhẹ nhàng:\nNay không phải là thời,\nBuông thả với suối rừng,\nThật an ổn con sông\nAjakaranì,\nThoải mái và yên lành,\nThật an vui thích thú!`, ref: "Trưởng Lão Tăng Kệ 4.11", url: "https://loicuaducphat.org/thag/thag4.11.html#content" },

{ text: `Trưởng Lão Mudita\n\n311. Ðể cứu mạng sống ta,\nTa xuất gia tu hành,\nTa được thọ đại giới,\nNhờ vậy được lòng tin,\nTa kiên trì tinh tấn,\nHăng hái ta tiến bước.\n\n312. Dầu thân này hủy hoại,\nTừng miếng thịt tiêu mòn,\nÐầu khớp xương hai gối,\nỐng chân làm ta ngã.\n\n313. Ta sẽ không ăn uống,\nKhông ra ngoài tinh xá,\nTa sẽ không nằm xuống,\nKhông nằm một bên hông,\nNếu mũi tên tham ái,\nChưa được rút nhổ lên.\n\n314. Hạnh ta sống như vậy,;\nHãy nhìn ta tinh cần,\nBa minh ta đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 4.12", url: "https://loicuaducphat.org/thag/thag4.12.html#content" },

{ text: `Trưởng Lão Rajadatta\n\n315. Một Tỷ-kheo đi đến\nTại một bãi tha ma,\nThấy thân một đàn bà,\nBị quăng tại chỗ ấy,\nVất bỏ trong nghĩa địa,\nLàm mồi cho sâu ăn.\n\n316. Có kẻ sinh nhàm chán,\nThấy thân chết khốn nạn,\nTrong ta, dục tham hiện,\nNhư mù, ta bị trói.\n\n317. Mau hơn cơm sôi trào,\nChỗ ấy, ta đi thoát,\nChánh niệm, ta tỉnh giác,\nTa đến, ngồi một bên.\n\n318. Rồi ta tự tác ý,\nNhư lý khởi tư duy,\nCác hiểm nguy hiển lộ,\nNhàm chán ta an trú.\n\n319. Và tâm ta giải thoát,\nThấy Pháp nhĩ là vậy,\nBa minh chứng đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 5.1", url: "https://loicuaducphat.org/thag/thag5.1.html#content" },

{ text: `Trưởng Lão Subhuta\n\n320. Ðặt mình vào tại chỗ,\nKhông được cho thích đáng,\nMột người muốn làm việc,\nNhưng không được thành tựu\nNhư vậy công việc ấy,\nÐược xem bị thất bại.\n\n321. Nếu từ bỏ phần thắng,\nGốc khổ được rút lên,\nNó giống kẻ đánh bạc,\nVận rủi quăng con bài,\nNếu nó quăng tất cả,\nNó chẳng khác người mù,\nKhông nhìn thấy con đường,\nBằng phẳng, không bằng phẳng.\n\n322. Hãy nói điều có làm,\nKhông nói điều không làm,\nBậc Hiền trí rõ biết,\nNgười chỉ nói không làm.\n\n323. Như bông hoa tươi đẹp,\nCó sắc nhưng không hương,\nCũng vậy lời khéo nói,\nCó làm, có kết quả.\n\n324. Như bông hoa tươi đẹp,\nCó sắc lại không hương,\nCũng vậy lời khéo nói\nKhông làm không kết quả.`, ref: "Trưởng Lão Tăng Kệ 5.2", url: "https://loicuaducphat.org/thag/thag5.2.html#content" },

{ text: `Trưởng Lão Girimananda\n\n325. Trời mưa như bài ca,\nKhéo hát với nhạc điệu,\nTa ngồi trong am thất,\nAn lạc, được che chở,\nTại đấy ta an trú,\nThoải mái và an tịnh,\nThần mưa, nếu ngươi muốn,\nHãy mưa, hãy mưa đi.\n\n326. Trời mưa như bài ca\nKhéo hát với nhạc điệu,\nTa ngồi trong am thất,\nAn lạc, được che chở.\nTại đấy ta an trú,\nTâm tư thật tịnh chỉ,\nThần mưa, nếu ngươi muốn,\nHãy mưa, hãy mưa đi.\n\n327. Trời mưa như bài ca,\nKhéo hát với nhạc điệu,\nTa ngồi trong am thất,\nAn lạc, đuợc che chở.\nTại đấy ta an trú,\nTâm tư, ly tham ái,\nThần mưa nếu ngươi muốn,\nHãy mưa, hãy mưa đi.\n\n328. Trời mưa như bài ca,\nKhéo hát với nhạc điệu,\nTa ngồi trong am thất,\nAn lạc được che chở.\nTại đấy ta an trú,\nTâm tư ly sân hận,\nThần mưa nếu ngươi muốn,\nHãy mưa, hãy mưa đi.\n\n329. Trời mưa như bài ca,\nKhéo hát với nhạc điệu,\nTa ngồi trong am thất,\nAn lạc, được che chở.\nTại đấy ta an trú,\nTâm tư ly si mê,\nThần mưa nếu ngươi muốn,\nHãy mưa, hãy mưa đi.`, ref: "Trưởng Lão Tăng Kệ 5.3", url: "https://loicuaducphat.org/thag/thag5.3.html#content" },

{ text: `Trưởng Lão Sumana\n\n330. Ðiều giáo thọ sư muốn,\nTôi biết trong chánh pháp,\nVới tôi mong bất tử,\nÐiều phải làm, làm xong.\n\n331. Pháp tôi đạt, tự chứng,\nKhông phải chỉ nghe suông,\nTrí tôi được thanh tịnh,\nKhông còn có nghi ngờ,\nMong tôi đứng gần ngài,\nNói lên điều xác chứng.\n\n332. Tôi biết các đời trước,\nThiên nhãn tôi thanh tịnh,\nMục đích tôi đạt được,\nLời Phật dạy làm xong.\n\n333. Học tập, không phóng dật,\nKhéo nghe lời ngài dạy,\nMọi lậu hoặc, tôi đoạn,\nNay không còn tái sanh.\n\n334. Ngài giảng tôi thánh giới,\nTừ mẫn ngài hộ trì.\nNgài dạy, không vô ích,\nTôi đệ tử học ngài.`, ref: "Trưởng Lão Tăng Kệ 5.4", url: "https://loicuaducphat.org/thag/thag5.4.html#content" },

{ text: `Trưởng Lão Vaddha\n\n335. Lành thay, bà mẹ ta,\nKích thích, khích lệ ta,\nNghe lời dạy của bà,\nÐược dạy bởi bà mẹ,\nTa tinh cần, tinh tấn,\nChứng Bồ-đề vô thượng.\n\n336. Ta xứng được cúng dường,\nBa minh, thấy bất tử.\nTa chứng quả La-hán,\nXứng đáng được cúng dường,\nBa minh đã chứng đạt,\nThấy được quả bất tử,\nChiến thắng quân Ma vương,\nTa sống, không lậu hoặc.\n\n337. Các lậu hoặc, nội, ngoại,\nTrước đã có trong ta,\nTất cả bị nhổ sạch,\nKhông còn khởi tên nữa.\n\n339. Khổ đã được chấm dứt,\nThân này thân cuối cùng,\nÐường sanh tử đứt đoạn,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 5.5", url: "https://loicuaducphat.org/thag/thag5.5.html#content" },

{ text: `Trưởng Lão Nadikassapa\n\n340. Thật lợi ích cho ta\nÐức Phật đến tại đây,\nÐến con sông tên gọi\nSông Nê-răn-ja-ra,\nTa nghe pháp ngài giảng\nÐoạn tận các tà kiến\n\n341. Ta hành lễ tế tự,\nÐọc cao lời tế lễ,\nTa đốt lên lửa thiêng,\nÐổ cúng dường vào lửa,\nNghĩ rằng ta thanh tịnh,\nTa thật mù, phàm phu.\n\n342. Lang thang rừng tà kiến,\nBị giới cấm, mờ mắt,\nKhông tịnh, nghĩ thanh tịnh,\nMù lòa, ta không thấy\n\n343. Ta đoạn tận tà kiến,\nMọi sanh hữu phá tan,\nTa đốt lên ngọn lửa,\nXứng đáng được cúng dường,\nTa cúi mình đảnh lễ,\nBậc Như Lai Ðiều Ngự.\n\n344. Mọi si mê, ta đoạn,\nHữu ái được phá hủy,\nÐường sanh tử đoạn tận,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 5.6", url: "https://loicuaducphat.org/thag/thag5.6.html#content" },

{ text: `Trưởng Lão Gaya-Kassapa\n\n345. Buổi sáng, trưa, buổi chiều,\nBa lần trong một ngày,\nTa xuống dòng Gà-yà,\nSông Ga-ya-phay-gu.\n\n346. Các điều ác, ta làm\nTrong các đời sống trước,\nNay đây ta rửa sạch,\nXưa ta tin là vậy.\n\n347. Nghe lời nói khéo giảng,\nCon đường đủ pháp nghĩa,\nVới ý nghĩa chân thật,\nTa như lý quán sát.\n\n348. Ta tắm sạch mọi ác,\nTa không uế, trong sạch.\nTa trong sạch thuần tịnh,\nThừa tự bậc trong sạch,\nTa chính là con trai,\nCon chính tông đức Phật.\n\n349. Lặn vào dòng Tám chánh,\nTa gột sạch mọi ác,\nBa minh ta đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 5.7", url: "https://loicuaducphat.org/thag/thag5.7.html#content" },

{ text: `Trưởng Lão Vakkali\n\n350. Bị bệnh gió chi phối,\nThầy sống trong rừng sâu,\nChỗ khất thực hạn chế,\nThân gầy mòn ốm yếu,\nTỷ-kheo sẽ làm gì?\nVới thân thể như vậy?\n\n351. Thân con được tràn ngập,\nVới hỷ lạc tỏa rộng,\nDầu có bị gầy ốm,\nCon sẽ sống trong rừng.\n\n352. Tu tập Bốn niệm xứ,\nNăm căn và Năm lực,\nTu tập các Giác chi,\nCon sẽ sống trong rừng.\n\n353. Con thấy bạn đồng tu,\nSống hòa hiệp, dõng mãnh,\nLuôn kiên trì tinh tấn,\nCon sẽ sống trong rừng.\n\n354. Tùy niệm Phật thiền định,\nBậc Tối thượng Ðiều Ngự,\nNgày đêm không biếng nhác,\nCon sẽ sống trong rừng.`, ref: "Trưởng Lão Tăng Kệ 5.8", url: "https://loicuaducphat.org/thag/thag5.8.html#content" },

{ text: `Trưởng Lão Vijitasena\n\n355. Ta sẽ chế ngự ngươi,\nNhư cửa khóa ngăn voi,\nTa sẽ không thúc ngươi,\nNày tâm trong điều ác,\nNgươi chính là lưới dục,\nNgươi do thân sanh ra.\n\n356. Chế ngự ngươi không đi,\nNhư voi, không cửa mở,\nNày tâm, kẻ phù thủy,\nDầu ngươi cố gắng mãi,\nNgươi không còn lang thang,\nƯa thích làm điều ác.\n\n357. Như người cầm câu móc,\nNgăn mãi voi chưa thuần,\nNhư người dùng sức mạnh,\nCải hóa kẻ không muốn,\nCũng vậy đối với ngươi,\nTa sẽ cải hóa ngươi.\n\n358. Như bánh xe tuyệt hảo,\nKhéo huấn luyện ngựa hay,\nCũng vậy ta điều ngươi,\nDựa lên trên Năm lực.\n\n359. Ta sẽ cột chặt ngươi,\nVới chánh niệm vững chắc,\nTự mình đã chế ngự,\nTa sẽ chế ngự ngươi,\nNhờ sức nặng tinh tấn,\nNgươi được ta áp lực,\nDo vậy, hỡi này tâm,\nNgươi sẽ không xa ta.`, ref: "Trưởng Lão Tăng Kệ 5.9", url: "https://loicuaducphat.org/thag/thag5.9.html#content" },

{ text: `Trưởng Lão Yasadatta\n\n360. Với tâm, muốn chỉ trích,\nKẻ ngu nghe lời dạy\nCủa bậc đã thắng trận,\nNgười ấy, thái độ vậy,\nRất xa vời Chánh pháp,\nNhư đất xa bầu trời.\n\n361. Với tâm muốn chỉ trích,\nKẻ ngu nghe lời dạy\nCủa bậc đã chiến thắng,\nNgười ấy thái độ vậy,\nTổn giảm xa Chánh pháp,\nNhư trăng nửa tháng đen.\n\n362. Với tâm muốn chỉ trích,\nKẻ ngu nghe lời dạy\nCủa bậc đã chiến thắng,\nNgười ấy thái độ vậy,\nKhô cạn trong diệu pháp,\nNhư cá mắc nước cạn.\n\n363. Với tâm muốn chỉ trích,\nKẻ ngu nghe lời dạy\nCủa bậc đã chiến thắng,\nNgười ấy thái độ vậy,\nKhông lớn trong diệu pháp,\nNhư giống thối trong ruộng.\n\n364. Ai tâm tư thỏa mãn,\nNghe bậc Thánh giảng dạy,\nTừ bỏ mọi lậu hoặc,\nChứng ngộ không dao động,\nÐạt tịch tịnh tối thượng,\nChứng Niết-bàn vô lậu.`, ref: "Trưởng Lão Tăng Kệ 5.10", url: "https://loicuaducphat.org/thag/thag5.10.html#content" },

{ text: `Trưởng Lão Sonakutikanna\n\n365. Ta thọ được đại giới,\nTa giải thoát vô lậu,\nThế Tôn, ta được thấy,\nTa sống chung tinh xá.\n\n366. Thế Tôn, trải nhiều ngày\nSống ngay ở ngoài trời,\nÐạo Sư khéo an trú,\nRồi mới vào tịnh xá.\n\n367. Trải y Tăng-già-lê\nGotama nằm xuống,\nNhư sư tử hang đá,\nÐoạn tận mọi sợ hãi.\n\n368. Khéo lựa lời tốt lành,\nÐệ tử bậc Chánh Giác,\nTrước đức Phật tuyệt hảo,\nSona thuyết diệu pháp.\n\n369. Liễu Tri Năm thủ uẩn,\nTu tập con đường Thánh\nÐạt an tịnh tối thượng,\nChứng Niết-bàn vô lậu.`, ref: "Trưởng Lão Tăng Kệ 5.11", url: "https://loicuaducphat.org/thag/thag5.11.html#content" },

{ text: `Trưởng Lão Kosiya\n\n370. Ai hiểu những lời dạy\nCủa các bậc Ðạo Sư,\nBậc trí sống an trú,\nPhát sanh lòng ái niệm,\nBậc trí có lòng tin,\nBiết thù thắng trong Pháp.\n\n371. Vị khi nạn lớn khởi,\nSuy tư không tê liệt,\nBậc trí có kiên trì,\nBiết thù thắng trong Pháp.\n\n372. Ai vững trú như biển,\nKhông dục, trí tuệ sâu,\nThấy rõ chân nghĩa lý,\nTế nhị và vi diệu,\nBậc trí trú bất động,\nBiết thù thắng trong Pháp.\n\n373. Bậc nghe nhiều, trì Pháp,\nHành pháp và Tùy pháp,\nBậc trí gọi như thị,\nBiết thù thắng trong Pháp.\n\n374. Ai hiểu nghĩa lời nói,\nBiết nghĩa, hành như thật,\nBậc trí gọi nội nghĩa,\nBiết thù thắng trong Pháp.`, ref: "Trưởng Lão Tăng Kệ 5.12", url: "https://loicuaducphat.org/thag/thag5.12.html#content" },

{ text: `Trưởng Lão Uruvela Kassapa\n\n375. Thấy được các thần thông\nGotama danh tiếng,\nNhưng ta chưa thần phục,\nBị ganh, mạn lừa dối.\n\n376. Bậc Ðiều Ngự loài Người,\nBiết được tâm tư ta,\nChất vấn ta hốt hoảng,\nKỳ diệu lông dựng ngược.\n\n377. Xưa ta thuộc bện tóc,\nThần thông ta nhỏ mọn,\nTa xem chúng vô dụng,\nTa xuất gia đầu Phật,\n\n378. Xưa bằng lòng tế tự,\nXem dục giới hàng đầu,\nSau ta nhổ tận sạch\nCả tham, sân và si.\n\n379. Ta biết các đời truóc,\nThiên nhãn ta trong sạch,\nThần thông biết tâm nguòi,\nThiên nhĩ, ta đạt được.\n\n380. Do đích gì xuất gia,\nBỏ nhà, sống không nhà,\nÐích ấy ta đạt được,\nMọi kiết sử tận diệt.`, ref: "Trưởng Lão Tăng Kệ 6.1", url: "https://loicuaducphat.org/thag/thag6.1.html#content" },

{ text: `Trưởng Lão Tekicchakari\n\n381. Lúa đã gặt thâu xong\nGạo đã được đập, giã,\nNhưng một miếng, không có,\nTa sẽ làm gì đây?\n\n382. Hãy niệm Phật vô lượng!\nTâm hân hoan thoải mái,\nThân thấm nhuần hỷ thọ,\nLuôn luôn cảm phấn chấn.\n\n383. Hãy niệm Pháp vô lượng!\nTâm hân hoan thoải mái,\nThân thấm nhuần hỷ thọ,\nLuôn luôn cảm phấn chấn.\n\n384. Hãy niệm Tăng vô lượng!\nTâm hân hoan thoải mái,\nThân thấm nhuần hỷ thọ,\nLuôn luôn cảm phấn chấn.\n\n385. Ngài sống giữa ngoài trời,\nNhững đêm này giá lạnh\nChớ để lạnh hại ngài!\nHãy vào trong tịnh xá,\nCó cửa đóng then gài.\n\n386. Ta sẽ cảm thọ được,\nVới bốn tâm vô lượng,\nTa sẽ sống an lạc\nVới những tâm tư ấy,\nGiá lạnh không hại ta,\nTa sống không dao động.`, ref: "Trưởng Lão Tăng Kệ 6.2", url: "https://loicuaducphat.org/thag/thag6.2.html#content" },

{ text: `Trưởng Lão Maha-Naga\n\n387. Ai đối đồng Phạm hạnh,\nKhông có sự cung kính,\nChúng thối giảm diệu pháp\nNhư cá mắc nước cạn.\n\n388. Ai đối đồng Phạm hạnh,\nKhông có sự cung kính,\nKhông lớn trong diệu pháp,\nNhư giống thối trong ruộng.\n\n389. Ai đối đồng Phạm hạnh,\nKhông có sự cung kính,\nChúng xa rời Niết-bàn,\nTrong lời dạy Pháp vương.\n\n390. Ai đối đồng Phạm hạnh,\nThật có sự cung kính,\nKhông thối giảm diệu pháp,\nNhư cá được nước nhiều.\n\n391. Ai đối đồng Phạm hạnh,\nThật có sự cung kính,\nLớn mạnh trong diệu pháp,\nNhư giống tốt trong ruộng.\n\n392. Ai đối đồng Phạm hạnh,\nThật có sự cung kính,\nHọ đến gần Niết-bàn,\nTrong lời dạy Pháp vương.`, ref: "Trưởng Lão Tăng Kệ 6.3", url: "https://loicuaducphat.org/thag/thag6.3.html#content" },

{ text: `Trưởng Lão Kulla\n\n393. Kulla đến nghĩa địa,\nThấy bỏ một đàn bà,\nVất ném trong nghĩa địa,\nLàm mồi cho sâu ăn.\n\n394. Kulla, hãy nhìn thân,\nBệnh hoạn nhớp hôi thối,\nNước ứ chảy, rỉ chảy,\nÐược kẻ ngu thích thú.\n\n395. Sau khi nắm gương pháp,\nÐạt được chánh tri kiến,\nTa quán sát thân này,\nTrống rỗng cả trong ngoài.\n\n396. Ðây thế nào, kia vậy,\nKia thế nào, đây vậy,\nDưới thế nào, trên vậy,\nTrên thế nào, dưới vậy.\n\n397. Ngày thế nào, đêm vậy,\nÐêm thế nào, ngày vậy,\nTrước thế nào, sau vậy,\nSau thế nào, trước vậy.\n\n398. Người vậy không ưa thích,\nCả năm loại nhạc khí,\nKhi đã được nhất tâm,\nChơn chánh thiền quán pháp.`, ref: "Trưởng Lão Tăng Kệ 6.4", url: "https://loicuaducphat.org/thag/thag6.4.html#content" },

{ text: `Trưởng Lão Malunkyaputta\n\n399. Có người sống phóng dật,\nÁi lớn như cây leo,\nSống trôi nổi luân chuyển,\nÐời này qua đời khác,\nNhư con khỉ trong rừng,\nThèm muốn các trái cây.\n\n400. Khát ái khốn nạn này\nThấm độc cả thế giới,\nKhi đã chinh phục ai,\nKhiến sầu muộn tăng trưởng,\nChẳng khác giống cỏ rừng,\nLan tràn và lớn mạnh.\n\n401. Ai nhiếp phục được ái,\nKhốn nạn, khó chinh phục,\nSầu rơi khỏi vị ấy,\nNhư giọt nước trên sen.\n\n402. Các ông đã đến đây,\nTa thuyết điều lành ấy,\nHãy đào rễ khát ái,\nNhư tìm rễ ngon ngọt,\nLoại cỏ u-sì-ra,\nChớ để Ma, dòng nước,\nTàn phá ông cây lau.\nLiên tục vậy mãi mãi.\n\n403. Hãy hành lời Phật dạy,\nChớ để Sát-na qua,\nSát-na qua, sầu khổ,\nThọ quả trong địa ngục,\n\n404. Phóng dật như bụi bặm,\nBụi nhơ, do phóng dật,\nKhông phóng dật, minh trí,\nNhổ mũi tên khỏi ta.`, ref: "Trưởng Lão Tăng Kệ 6.5", url: "https://loicuaducphat.org/thag/thag6.5.html#content" },

{ text: `Trưởng Lão Sappadasa\n\n405. Ðã được hăm lăm năm,\nTừ khi ta xuất gia,\nNhưng đến một búng tay,\nTa không đạt tâm tịnh.\n\n406. Nhứt tâm không đạt được,\nBị dục tham chi phối,\nKhoa tay, ta than khóc,\nBỏ tịnh xá, ta đi.\n\n407. Ta sẽ đem dao lại,\nSự sống ta, nghĩa gì?\nHọc tập bị tước bỏ,\nNhư ta, chết tốt hơn.\n\n408. Rồi ta cầm con dao\nTa vào chỗ giường nằm,\nCon dao được rút ra,\nÐể cắt cổ của ta.\n\n409. Rồi ta tự tác ý,\nNhư lý, khởi tư duy,\nCác hiểm nguy hiển lộ\nNhàm chán, ta an trú\n\n410. Và tâm ta giải thoát,\nThấy Pháp nhĩ là vậy,\nBa minh chứng đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 6.6", url: "https://loicuaducphat.org/thag/thag6.6.html#content" },

{ text: `Trưởng Lão Katiyana\n\n411. Này Ka-ti-ya-na,\nHãy thức dậy, ngồi lên,\nChớ có ngủ quá nhiều,\nHãy tự mình thức tỉnh,\nNày bà con phóng dật,\nKẻ thụ động biếng nhác\nChớ để cho thần chết,\nLường gạt, chiến thắng ông.\n\n412. Như sóng tràn biển lớn,\nCũng vậy sanh và già,\nTràn ngập chôn lấp ông,\nHãy tự làm cho ông,\nMột hòn đảo an toàn,\nVì rằng không ai khác,\nPhục vụ giúp đỡ ông,\nNhư là chỗ nương tựa.\n\n413. Ðạo Sư lập con đường,\nÐường vượt qua trói buộc,\nVượt qua sự sợ hãi,\nCủa sanh và của già,\nTrước đêm và sau đêm,\nHãy sống không phóng dật,\nChú tâm cố kiên trì,\nTrong nỗ lực chuyên tâm.\n\n414. Từ bỏ triền phược trước,\nMặc áo Tăng-già-lê,\nÐầu cạo trọc trơn láng,\nĂn đồ ăn khất thực,\nChớ có ưa chơi giỡn,\nChớ đam mê ngủ nghỉ,\nHãy nỗ lực thiền định,\nHỡi Ka-ti-ya-na!\n\n415. Hãy thiền tu, chiến thắng,\nHỡi Ka-ti-ya-na!\nHãy thiện xảo con đường,\nAn ổn các khổ ách;\nHãy đạt cho kỳ được,\nSự thanh tịnh tối thượng.\nÔng sẽ chứng Niết-bàn,\nNhư nước làm tắt lửa.\n\n416. Ánh sáng được tạo ra,\nHào quang còn yếu ớt,\nChẳng khác như cây lau,\nGió thổi nằm rạp xuống,\nHỡi bà con Tu-đa,\nNhư vậy, chớ chấp thủ,\nHãy tẩn xuất Ác-ma,\nLy tham mọi cảm thọ,\nChờ đợi thời của ông!\nTại đây ông mát lạnh.`, ref: "Trưởng Lão Tăng Kệ 6.7", url: "https://loicuaducphat.org/thag/thag6.7.html#content" },

{ text: `Trưởng Lão Migajala\n\n417. Khéo giảng bậc có mắt,\nHào quang còn yếu ớt,\nMọi kiết sử vượt qua,\nMọi luân chuyển hoạt diệt.\n\n418. Pháp hướng dẫn, hướng thượng,\nLàm khô héo ác căn,\nChặt đứt gốc nọc độc,\nDiệt ác, đạt tịch tịnh.\n\n419. Phá vỡ gốc vô trí,\nChấm dứt nghiệp sanh hữu,\nTrí kim cang đánh nát,\nMọi chấp trì của thức.\n\n420. Cảm thọ được phơi bày,\nChấp thủ được giải thoát,\nHữu như hố than hừng,\nÐược tùy quán bởi trí.\n\n421. Vị lớn, khéo thâm sâu,\nChận đứng già và chết,\nCon đường Thánh tám ngành,\nTịnh chỉ khổ, vận tốt.\n\n422. Biết được nghiệp là nghiệp,\nBiết nghiệp quả là quả,\nNhư thực soi, quán chiếu,\nCác pháp do duyên sanh,\nÐưa đến đại an ổn,\nTịch tịnh, cứu cánh thiện.`, ref: "Trưởng Lão Tăng Kệ 6.8", url: "https://loicuaducphat.org/thag/thag6.8.html#content" },

{ text: `Trưởng Lão Jenta Purohitaputta\n\n423. Ta say đắm tự kiêu,\nVới sanh chủng, tài sản,\nKể cả với quyền lực,\nÐịa vị và dung sắc,\nTa sống kiêu mạn vậy.\nTham dắm và mê say.\n\n424. Ta quá sức kiêu hãnh.\nXem không ai bằng ta,\nSi mê, quá tự hào,\nKiêu căng và cống cao.\n\n425. Mẹ cha và người khác,\nÐược cung kính tôn trọng,\nTa không lễ một ai,\nKiêu hãnh, không lễ phép.\n\n426. Thấy lãnh đạo đệ nhất,\nTối ưu Ðiều Ngự Sư,\nNhư mặt trời sáng chói,\nCầm đầu chúng Tỷ-kheo.\n\n427. Gạt bỏ mạn, kiêu hãnh,\nVới tâm thật an lành,\nVới đầu ta đảnh lễ,\nBậc tối thượng chúng sanh.\n\n428. Quá mạn, ty liệt mạn,\nTừ bỏ, nhổ tận gốc,\nNgã mạn được chặt đứt,\nMọi loại mạn tận diệt.`, ref: "Trưởng Lão Tăng Kệ 6.9", url: "https://loicuaducphat.org/thag/thag6.9.html#content" },

{ text: `Trưởng Lão Sumana\n\n430. Từ hồ nước to lớn,\nTên A-no-tat-ta\nTa đem nước hồ về,\nCho bậc giáo thọ sư,\nThấy vậy bậc Ðạo Sư,\nNói về ta như sau:\n\n431. Này Sà-ri-put-ta!\nXem đứa trẻ này đến,\nTự bưng cầm ghè nước,\nNội tâm khéo định tĩnh.\nVới nhiệm vụ khả ái,\nCử chỉ rất thuần thiện.\n\n432. Người đệ tử Sa-di,\nCủa Anuruddha,\nCó thần thông uy lực,\nThuần thục và điêu luyện.\n\n433. Thuần lương nhờ giáo dục,\nDo vị đại thuần lương,\nThiện hạnh nhờ giáo dục,\nBởi bậc khéo thiện hạnh.\nNhờ Anuruddha,\nKhéo huấn luyện điều phục,\nÐược học tập giảng dạy,\nLàm xong việc phải làm.\n\n434. Ðạt được tịnh tối thắng,\nChứng đắc, không dao động,\nSa-di Sumana,\nMuốn: 'Không ai biết ta'.`, ref: "Trưởng Lão Tăng Kệ 6.10", url: "https://loicuaducphat.org/thag/thag6.10.html#content" },

{ text: `Trưởng Lão Nhātakamuni\n\n435. Bị bệnh gió chi phối,\nÔng sống trong rừng sâu,\nChỗ khất thực hạn chế,\nThân gầy mòn ốm yếu.\nTỷ-kheo sẽ làm gì,\nVới thân thể như vậy.\n\n436. Thân con được tràn ngập,\nVới hỷ lạc tỏa rộng,\nDầu có bị gầy ốm,\nCon sẽ sống trong rừng.\n\n437. Tu tập Bảy giác chi,\nNăm căn và Năm lực,\nÐầy đủ thiền tế nhị,\nCon sống, không lậu hoặc.\n\n438. Thoát khỏi các kết sử,\nTâm tịnh, không uế nhiễm,\nThường hằng, khéo quán sát,\nCon sống không lậu hoặc.\n\n439. Mọi lậu hoặc nội ngoại,\nTrước có mặt trong con,\nTất cả bị chặt đứt,\nThông dư, không khởi nữa.\n\n440. Năm uẩn được liễu tri,\nChúng đứng, rễ chặt đứt,\nKhổ diệt đã đạt được,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 6.11", url: "https://loicuaducphat.org/thag/thag6.11.html#content" },

{ text: `Trưởng Lão Brahmadatta\n\n441. Từ đâu phẫn nộ khởi,\nVới người không phẫn nộ,\nVới người được nhiếp phục,\nSống nếp sống thăng bằng.\nVới vị trí giải thoát,\nPhải an tịnh như vậy.\n\n442. Với ai bị chửi mắng,\nLên tiếng chửi mắng lại,\nNgười ấy tệ ác hơn,\nNgười đã chửi mắng trước.\nVới ai bị chửi mắng,\nNhưng không chửi mắng lại,\nNgười ấy được chiến thắng,\nTrên cả hai mặt trận.\n\n443. Sở hành của người ấy,\nVừa lợi mình lợi người,\nBiết người khác phẫn nộ,\nChánh niệm, tự lắng dịu.\n\n444. Là thầy thuốc cả hai,\nCho mình và cho người,\nQuần chúng nghĩ là ngu,\nKhông khéo hiểu Chánh Pháp.\n\n445. Nếu phẫn nộ nổi lên,\nHãy nghĩ dụ cái cưa,\nNếu tham vị khởi lên,\nHãy nghĩ dụ thịt con.\n\n446. Nếu tâm ngươi chạy theo,\nTheo dục, theo sanh hữu,\nHãy gấp nắm với niệm,\nNhư nắm con vật ác,\nÐi vào trong ruộng lúa.`, ref: "Trưởng Lão Tăng Kệ 6.12", url: "https://loicuaducphat.org/thag/thag6.12.html#content" },

{ text: `Trưởng Lão Sirimanda\n\n447. Mưa rất là nặng hạt,\nTrên tội được che giấu.\nMưa không có nặng nề,\nTrên tội được phát lộ,\nÐâu có phát lộ tội,\nNhư vậy, mưa không nặng.\n\n448. Ðời bị chết áp đảo,\nBị giải tỏa, bao vây,\nBị mũi tên ái đâm,\nThường bị dục huân tập.\n\n449. Ðời bị chết ấp đảo,\nVà bị già bao vây,\nThường bị hại, không yên,\nNhư cướp với gậy dao.\n\n450. Chúng đến như đống lửa,\nCả ba, chết bệnh già,\nKhông sức nào địch nổi,\nKhông nhanh nào chạy thoát.\n\n451. Chớ để ngày trống rỗng,\nHãy làm ít hoặc nhiều,\nÐêm càng bị bỏ phí,\nMạng sống càng rút ngắn.\n\n452. Vậy hoặc đi hay đứng,\nHoặc ngồi hay nằm xuống,\nÐêm cuối đi đến gần,\nNgươi không thời phóng dật.`, ref: "Trưởng Lão Tăng Kệ 6.13", url: "https://loicuaducphat.org/thag/thag6.13.html#content" },

{ text: `Trưởng Lão Sabbhakama\n\n453. Con vật hai chân này,\nBất tịnh và hôi thối,\nÐầy các loại tử thi,\nTừ đấy, nước rỉ chảy.\n\n454. Nai trốn, dùng bẫy sập,\nVới cá dùng câu móc,\nVới khỉ, dùng hầm hố,\nPhàm phu bị bắt vậy.\n\n455. Sắc, tiếng, vị, hương, xúc,\nKhả ái và thích ý,\nNăm dục trưởng dưỡng này,\nÐược tiếng trong nữ sắc.\n\n456. Phàm phu tâm say đắm,\nChạy theo hưởng nữ sắc,\nTăng nghĩa địa hãi hùng,\nChất chứa sự tái sanh.\n\n457. Ai tránh né nữ sắc,\nNhư chân tránh đầu rắn,\nChánh niệm, vượt qua được,\nKẻ đầu độc thế giới.\n\n458. Thấy nguy hiểm trong dục,\nAn ổn trong viễn ly,\nThoát khỏi tất cả dục,\nTa đạt lậu hoặc tận.`, ref: "Trưởng Lão Tăng Kệ 6.14", url: "https://loicuaducphat.org/thag/thag6.14.html#content" },

{ text: `Trưởng Lão Sundara-Samudda\n\n459. Trang sức mặc áo đẹp,\nÐeo vòng hoa trang điểm,\nChân bôi sơn màu đỏ,\nMột kỹ nữ đi dép.\n\n460. Chân rút ra khỏi dép,\nChấp tay, hướng phía trước,\nNàng với giọng nhẹ dịu,\nMở đầu nói với ta;\n\n461. Chàng trẻ tuổi xuất gia,\nHãy dừng, lãnh vực em,\nThọ hưởng năm dục vọng,\nEm cho chàng phương tiện,\nEm hứa chàng sự thật,\nEm đem chàng lửa thề.\n\n462. Khi chàng em đều già,\nCả hai đều chống gậy,\nCả hai cùng xuất gia,\nHai phần được vận may.\n\n463. Thấy người kỹ nữ ấy,\nChấp tay lời van xin,\nTrang sức, mặc áo đẹp,\nNhư thần chết gieo mồi.\n\n464. Rồi ta tự tác ý,\nNhư lý khởi tư duy,\nCác hiểm nguy hiển lộ,\nNhàm chán ta an trú.\n\n465. Và tâm ta giải thoát,\nThấy Pháp nhĩ là vậy,\nBa minh chứng đạt được,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Tăng Kệ 7.1", url: "https://loicuaducphat.org/thag/thag7.1.html#content" },

{ text: `Trưởng Lão Lakuntaka-Bhaddiya\n\n466. Ra ngoài các khu vườn,\nTên Ambàtaka,\nTrong rừng với lùm cây,\nÁi, ái căn từ bỏ,\nBhaddiya ngồi thiền,\nBậc may mắn hạnh phúc.\n\n467. Một số người ưa thích,\nTrống, sáo và trống nhỏ,\nCòn ta, dưới gốc cây,\nTa thích lời Phật dạy.\n\n468. Nếu Phật ban ân huệ,\nTa được ân huệ ấy,\nTa trì thân hành niệm,\nThường hằng ở mọi giới.\n\n469. Cười chê ta vì thân,\nAi theo ta vì tiếng,\nChúng không biết được ta,\nVì dục tham chi phối.\n\n470. Không biết được phần trong,\nKhông thấy được phía ngoài,\nChận bốn phía, người ngu,\nBị tiếng nói lôi cuốn.\n\n471. Không biết được phần trong,\nQuán thấy được phía ngoài,\nChỉ thấy quả phía ngoài,\nCũng bị tiếng lôi cuốn.\n\n472. Quán trí được phần trong,\nQuán thấy được phía ngoài,\nThấy không bị chướng ngại,\nKhông bị tiếng lôi cuốn.`, ref: "Trưởng Lão Tăng Kệ 7.2", url: "https://loicuaducphat.org/thag/thag7.2.html#content" },

{ text: `Trưởng Lão Bhadda\n\n473. Ta là con độc nhất\nÐược cha thương mẹ thương,\nDo nhiều hạnh giới cấm,\nVan vái mới được ta.\n\n474. Vì lòng thương xót ta,\nMuốn ta được hạnh phúc,\nCả cha và mẹ ta,\nDẫn ta đến đức Phật\n\n475. Ðược đứa con trai này,\nThật trải nhiều khó khăn,\nNuôi dưỡng rất tế nhị,\nÐược nuông chiều săn sóc,\nChúng con kính dâng Ngài,\nKính thưa bậc cứu độ,\nÐể làm người thị giả,\nHầu hạ bậc chiến thắng.\n\n476. Bậc Ðạo Sư nhận ta,\nNói A-nan như sau:\nHãy cho nó xuất gia,\nNó sẽ thành thuần lương.\n\n477. Sau khi bậc Ðạo Sư,\nBảo xuất gia cho ta,\nXong rồi bậc chiến thắng,\nBước vào trong tinh xá,\nKhi mặt trời chưa mọc,\nTâm ta được giải thoát.\n\n478. Rồi bậc Ðạo Sư ta,\nÐể chấm dứt công việc,\nTừ yên lặng thiền tịnh,\nNgài đứng dậy gọi ta:\nNày Bhadda hãy đến,\nTa thọ Ðại giới vậy.\n\n479. Từ sanh, đến bảy năm,\nTa được thọ Ðại giới,\nBa minh ta đạt được,\nÔi pháp, thiện pháp tánh!`, ref: "Trưởng Lão Tăng Kệ 7.3", url: "https://loicuaducphat.org/thag/thag7.3.html#content" },

{ text: `Trưởng Lão Sarabhanga\n\n487. Tay bẻ những cây lau,\nTa làm am ta ở,\nDo vậy, được tên tục:\n'Người bẻ gãy cây lau'.\n\n488. Nay không còn thích hợp,\nTự tay bẻ cây lau,\nTheo học giới giảng dạy,\nGotama danh xưng.\n\n489. Chính Sara-bhanga,\nTừ trước chưa từng thấy,\nThấy chứng bệnh toàn diện,\nMột cách thật đầy đủ.\nBệnh ấy nay được thấy,\nDo lời bậc siêu thiên.\n\n491. Ly ái, không chấp thủ,\nBảy Phật chứng Niết-bàn,\nPháp này được thuyết giảng,\nBởi các vị chứng Pháp.\n\n492. Vì từ mẫn chúng sanh,\nBốn sự thật được giảng,\nKhổ, khổ tập, con đường,\nDiệt, chấm dứt khổ đau.\n\n493. Trong đời sống liên tục,\nKhổ luân chuyển không dứt,\nKhi thân này bị hoại,\nKhi mạng sống cáo chung,\nTái sanh khác không còn,;\nTa thật, khéo giải thoát,\nGiải thoát mọi sanh y.`, ref: "Trưởng Lão Tăng Kệ 7.5", url: "https://loicuaducphat.org/thag/thag7.5.html#content" },

{ text: `Trưởng Lão Maha-Kaccayana\n\n494. Chớ làm quá nhiều việc,\nTránh quần chúng đua tranh,\nNgười siêng tham đắm vị,\nBỏ đích đem an lạc.\n\n495. Ta cảm là 'đống bùn',\nCung kính các gia đình,\nLà mũi tên nhỏ nhiệm,\nThật khó được rút ra,\nTôn trọng khó từ bỏ,\nÐối với kẻ không tốt.\n\n496. Hành động của con người,\nKhông phải là độc ác,\nTùy thuộc vào người khác,\nNgười khác nói hay làm,\nTự mình chớ có làm,\nVì người, bà con nghiệp.\n\n497. Không vì người khác nói,\nCon người thành ăn trộm,\nKhông vì người khác nói,\nCon người thành bậc Thánh.\nNhư mình tự biết mình,\nChư Thiên biết mình vậy.\n\n498. Người khác không biết được,\nÐây ta sống một thời,\nNhững ai biết được vậy,\nBậc trí sống lắng dịu.\n\n499. Chỉ bậc trí sống mạnh,\nDầu tài sản đoạn tận,\nNếu không được trí tuệ,\nCó tiền như không sống,\n\n500. Với tai nghe tất cả,\nVới mắt thấy tất cả,\nKẻ trí bỏ tất cả,\nNhư không thấy không nghe,\n\n501. Có mắt, như kẻ mù,\nCó tai như kẻ điếc,\nCó trí, như kẻ ngu,\nCó sức, như kẻ yếu,\nÐể việc lành khởi lên,\nNằm như kẻ chết nằm.`, ref: "Trưởng Lão Tăng Kệ 8.1", url: "https://loicuaducphat.org/thag/thag8.1.html#content" },

{ text: `Trưởng Lão Sirimitta\n\n502. Không phẫn nộ, không hận,\nKhông gian, không hai lưỡi,\nVị Tỷ-kheo như vậy,\nÐời sau, không ưu sầu.\n\n503. Không phẫn nộ, không hận,\nKhông gian, không hai lưỡi,\nTỷ-kheo thường hộ căn,\nÐời sau không ưu sầu.\n\n504. Không phẫn nộ, không hận,\nKhông gian, không hai lưỡi,\nTỷ-kheo giữ thiện giới,\nÐời sau, không ưu sầu.\n\n505. Không phẫn nộ, không hận,\nKhông gian, không hai lưỡi,\nTỷ-kheo thiện bằng hữu,\nÐời sau không ưu sầu\n\n506. Không phẫn nộ, không hận,\nKhông gian, không hai lưỡi,\nTỷ-kheo thiện trí tuệ,\nÐời sau, không ưu sầu.\n\n507. Với ai tin Như Lai,\nKhông dao động, thiện trú,\nVới ai, nếp giới hạnh,\nÐược thiện nhân tán thán,\nÐược bậc Thánh tùy hỷ.\n\n508. Với ai, có tín thành,\nÐối với chúng Tăng già,\nCó tri kiến chánh trực,\nHọ nói về người ấy:\nVị ấy không nghèo đói,\nÐời sống không trống rỗng.\n\n509. Vậy nên bậc Hiền trí,\nHãy chú tâm tín, giới,\nTịnh, tín, thấy đúng pháp;\nVào cốt tủy lời Phật.`, ref: "Trưởng Lão Tăng Kệ 8.2", url: "https://loicuaducphat.org/thag/thag8.2.html#content" },

{ text: `Trưởng Lão Maha-Panthaka\n\n510. Khi đầu tiên ta thấy,\nBậc Ðạo Sư vô úy,\nXúc động khởi nơi ta,\nThấy được người Tối thượng.\n\n511. Ai cả tay cả chân,\nCầu khẩn thần may đến,\nVới cử chỉ như vậy,\nKhiến Ðạo Sư hoan hỷ,\nVị ấy không thể đạt,\nNhư sở nguyện của mình.\n\n512. Còn ta đã từ bỏ,\nVợ con, tiền, lúa, gạo,\nSau khi cạo râu tóc,\nTa xuất gia không nhà.\n\n513. Học, sinh hoạt đầy đủ,\nCác căn khéo chế ngự,\nÐảnh lễ bậc Chánh giác,\nTa trú, không khuất phục.\n\n514. Rồi ta khởi ước nguyện,\nTâm an trú tha thiết,\nTa quyết không ngồi nữa,\nDầu chỉ là một phút,\nCho đến khi rút được,\nRút mũi tên tham ác.\n\n515. Ta an trú như vậy,\nHãy xem nhờ nỗ lực,\nBa minh ta đạt được,\nLời Phật dạy làm xong.\n\n516. Ta biết được đời trước,\nThiên nhãn được thanh tịnh,\nTa xứng được cúng dường,\nGiải thoát khỏi sanh y.\n\n517. Như đêm trở thành sáng,\nKhi mặt trời mới mọc,\nMọi khát ái khô kiệt,\nTa vào, ngồi kiết-già.`, ref: "Trưởng Lão Tăng Kệ 8.3", url: "https://loicuaducphat.org/thag/thag8.3.html#content" },

{ text: `Trưởng Lão Bhuta\n\n518. Khi bậc trí thấy được,\nGià chết là đau khổ,\nTại đấy, kẻ phàm phu,\nKhông thấy, chấp thủ khổ.\nSau khi liễu tri khổ,\nChánh niệm, tu thiền định,\nKhông tìm thấy lạc nào,\nƯu việt hơn lạc này.\n\n519. Khi đoạn tận được ái,\nÁi đem khổ, độc hại,\nTạo hý luận trói buộc,\nÐẩy mạnh đến đau khổ,\nSau khi đoạn tận ái,\nChánh niệm, tu thiền định,\nKhông tìm thấy lạc nào,\nƯu việt hơn lạc này.\n\n520. Khi với tuệ, thấy được,\nCon đường lành vô thượng,\nGồm hai lần bốn phần,\nTịnh trừ mọi phiền não,\nSau khi thấy với tuệ;\nChánh niệm tu thiền định,\nKhông tìm thấy lạc nào,\nƯu việt hơn lạc này.\n\n521. Khi tu tập con đường,\nKhông sầu, không cấu uế,\nVô vi, an tịnh đạo,\nTịnh trừ mọi phiền não,\nChặt trói buộc kiết sử,\nChánh niệm, tu thiền định,\nKhông tìm thấy lạc nào,\nƯu việt hơn lạc này.\n\n522. Khi trên trời vang rền,\nTiếng trống mây giông tố,\nKhắp con đường chim bay,\nDòng mưa dày đặc đổ,\nTỷ-kheo đi đến hang,\nTu tập, ngồi thiền định,\nKhông tìm thấy lạc nào,\nƯ u việt hơn lạc này.\n\n523. Khi trên những bờ sông,\nNhững vòng hoa rừng núi,\nNở lên và chói sáng,\nVới nhiều màu nhiều sắc,\nVới tâm tư thoải mái,\nNgồi thiền trên bờ sông,\nKhông tìm thấy lạc nào,\nƯu việt hơn lạc này.\n\n524. Khi nửa đêm, rừng vắng,\nTrời đổ trận mưa rào,\nLoài có ngà có nanh,\nÐang sống đang gầm thét,\nTỷ-kheo đến triền núi,\nNgồi yên lặng tọa thiền,\nKhông tìm thấy lạc nào,\nƯu việt hơn lạc này.\n\n525. Khi tầm tứ chế ngự\nGiữa núi, trong hang động\nThoải mái tự ngồi thiền,\nKhông sợ không chướng ngại\nKhông tìm thấy lạc nào,\nƯu việt hơn lạc này.\n\n526. Khi ngồi được hỷ lạc,\nKhông uế chướng, không sầu,\nKhông tù túng, thoát ái,\nKhông bị mũi tên đâm,\nMọi lậu hoặc chấm dứt,\nVị ấy ngồi tọa thiền,\nKhông tìm thấy lạc nào,\nƯu việt hơn lạc này.`, ref: "Trưởng Lão Tăng Kệ 9.1", url: "https://loicuaducphat.org/thag/thag9.1.html#content" },

{ text: `Trưởng Lão Kaludayi\n\n527. Thế Tôn, nay là thời,\nCác cây nở hoa đỏ,\nTừ bỏ chòm lá cũ,\nTìm đến thời sai quả.\nChúng như ngọn lửa hừng,\nChói sáng và rực sáng,\nBạch đấng Ðại anh hùng,\nNay là thời hưởng vị.\n\n528. Những cây nở hoa đẹp,\nKhắp phương tỏa hương thơm,\nBỏ lá, vọng sanh quả,\nNay là thời lên đường,\nTừ bỏ địa phương này,\nKính thưa bậc Anh hùng.\n\n529. Không quá lạnh, quá nóng,\nThế Tôn thời tiết đẹp,\nHãy để hai dân tộc,\nThích-Ca, Ko-li-ya,\nNhìn Ngài mặt hướng Tây,\nVượt sông Ro-hi-ni.\n\n530. Trong hy vọng, ruộng cày,\nTrong hy vọng, giống gieo,\nTrong hy vọng, thương gia,\nVượt biển đem tiền về.\nHy vọng con kiên trì,\nMong con, hy vọng thành.\n\n531. Người tiếp tục gieo giống,\nTrời lại tiếp tục mưa,\nNgười nông tiếp tục cày,\nThóc gạo tiếp tục đến,\nÐến nhiều cho quốc gia.\n\n532. Ăn xin tiếp tục xin,\nThí chủ tiếp tục cho,\nThí chủ tiếp tục cho\nTiếp tục lên Thiên giới.\n\n533. Bậc anh hùng tiếp tục,\nCho đến bảy thế hệ\nGia đình ấy được sanh,\nBậc trí tuệ rộng lớn,\nCon nghĩ Ngài có thể,\nLà Thiên chủ chư Thiên,\nTrong Ngài đã được sanh,\nBậc ẩn sĩ chân danh.\n\n534. Phụ vương đại ẩn sĩ,\nTên gọi Tịnh Phạn vương,\nCòn mẹ bậc Chánh giác,\nDanh xưng là Ma-da,\nBà mang thai Bồ-tát,\nThân hoại, hưởng thiên giới.\n\n535. Gô-ta-mi, mạng chung,\nTừ đấy, sau khi chết,\nÐược hưởng thọ đầy đủ,\nCác dục lạc cõi trời,\nVui hưởng năm món dục,\nÐược Thiên nữ đoanh vây.\n\n536. Ta là con đức Phật,\nNgài thắng bậc bất thắng,\nBậc An-gi-ra-sa,\nBậc không ai sánh được,\nVua dòng họ Thích-ca,\nPhụ thân của cha tôi,\nVua dòng Go-ta-ma\nLà bậc Tổ phụ tôi,\nÐúng pháp là như vậy.`, ref: "Trưởng Lão Tăng Kệ 10.1", url: "https://loicuaducphat.org/thag/thag10.1.html#content" },

{ text: `Trưởng Lão Ekavihariya\n\n537. Khi trước mặt sau lưng,\nKhông có một người nào,\nNhư vậy an lạc lớn,\nSống một mình trong rừng.\n\n538. Ta sẽ đi một mình,\nÐến ngôi rừng Phật khen,\nHưởng an lạc đã được,\nVị Tỷ-kheo thọ hưởng,\nNhờ sống đời tinh tấn,\nSống riêng chỉ một mình.\n\n539. Ta sẽ gấp vào rừng,\nMột mình, sống lý tưởng,\nNgôi rừng được loài voi,\nCuồng loạn sống tự do,\nTrú xứ đem hoan hỷ,\nCho ẩn sĩ thiền định.\n\n540. Trong ngôi rừng Sì-ta,\nVới núi hang nước mát,\nSau khi rửa tay chân,\nTa kinh hành một mình.\n\n541. Sống một, không sống hai,\nTrong rừng lớn đẹp đẽ,\nTa sẽ sống tại đấy,\nViệc xong, không lậu hoặc.\n\n542. Như vậy, ta muốn làm,\nMong ước nguyện thành tựu,\nTa sẽ có lòng tin,\nKhông ai làm ai được.\n\n543. Ta cột áo giáp lại,\nSẽ vào trong rừng sâu,\nTa không ra khỏi rừng,\nNếu chưa đạt lậu tận.\n\n544. Trong khi gió nhẹ thổi,\nMát lạnh, thơm mùi hương,\nTa ngồi trên chỏm núi,\nTa sẽ phá vô minh.\n\n545. Trên tấm thảm hang động,\nTrải đầy những hoa rừng,\nTa hưởng lạc giải thoát,\nTại vòng đai núi rừng.\n\n546. Chí nguyện ta viên mãn,\nGiống như mặt trăng rằm.\nMọi lậu hoặc tận trừ,\nNay không còn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 10.2", url: "https://loicuaducphat.org/thag/thag10.2.html#content" },

{ text: `Trưởng Lão Maha Kappina\n\n547. Ai thấy sớm sự việc,\nTrước khi sự việc đến,\nVà biết được cả hai,\nCó lợi hay có hại,\nThù hay bạn người ấy,\nKhông thấy được sơ hở,\nDầu quan sát kỹ càng.\n\n548. Với ai khéo tu tập,\nNiệm thở vào thở ra,\nTiếp tục hành viên mãn,\nNhư lời Phật thuyết giảng,\nSẽ chói sáng đời này,\nNhư trăng thoát vùng mây.\n\n549. Tâm ta thật trắng bạch,\nVô lượng, khéo tu tập,\nThấu triệt, chế ngự vững,\nChói sáng khắp mọi phương.\n\n550. Bậc có tuệ vẫn sống,\nDầu tài sản kiệt tận,\nKhông có được trí tuệ,\nCó tiền, như không sống.\n\n551. Tuệ phê phán điều nghe,\nTuệ tăng trưởng danh xưng,\nỞ đời người có tuệ,\nÐược vui trong đau khổ.\n\n552. Pháp này thuộc hiện tại,\nKhông vi diệu hy hữu,\nÐâu có sanh, thì chết,\nÐây không gì hy hữu.\n\n553. Sanh đã không gián đoạn,\nSống có chết thường hằng,\nSanh sanh, chết tại đấy,\nPháp hữu tình là vậy.\n\n554. Ðiều lợi cho kẻ sống,\nKhông lợi cho kẻ chết,\nThan khóc cho kẻ chết,\nKhông danh, không thanh tịnh,\nKhông được hàng Sa-môn,\nBà-la-môn tán thán.\n\n555. Than khóc hại thân, mắt,\nDung sắc, lực và trí,\nNếu tâm tư, hoan hỷ,\nCác phương cũng hân hoan,\nDầu hạnh phúc đi tìm,\nKhông có gì an lạc.\n\n556. Do vậy các cư sĩ,\nMuốn nhận trong gia đình,\nChỉ những người có trí,\nVà những người nghe nhiều,\nVới sức mạnh trí tuệ,\nHọ làm tròn nhiệm vụ,\nNhư chiếc thuyền vượt qua,\nCon sông nước tràn đầy.`, ref: "Trưởng Lão Tăng Kệ 10.3", url: "https://loicuaducphat.org/thag/thag10.3.html#content" },

{ text: `Trưởng Lão Cula-Panthaka\n\n557. Ta chậm chạp, tiến chậm,\nTrước ta bị khinh miệt,\nAnh ta đuổi ta đi:\nNay, ngươi hãy về nhà.\n\n558. Ta bị đuổi như vậy,\nTại cửa chính Tăng xá,\nSầu khổ, đứng tại đấy,\nVọng luyến lời Phật dạy.\n\n559. Tại đấy, Thế Tôn đến,\nNgài rờ trên đầu ta,\nVới cánh tay, nắm ta,\nDắt ta vào Tăng xá.\n\n560. Ðạo Sư thương xót ta,\nCho ta khăn lau chân;\nHãy an trú tâm tư,\nVào vật thanh tịnh này.\nVà ngồi xuống một bên,\nTâm tư khéo an trú.\n\n561. Ta nghe lời Ngài dạy,\nSống hân hoan Chánh pháp,\nTa thực hành thiền định,\nÐể đạt đích tối thượng.\n\n562. Ta biết được đời trước,\nThiên nhãn ta thanh tịnh,\nBa minh đã đạt được,\nLời Phật dạy làm xong.\n\n563. Pan-tha-ka hóa hiện,\nDưới hàng ngàn hình thức,\nNgồi vườn xoài xinh đẹp,\nChờ đợi thời phát hiện.\n\n564. Rồi Ðạo Sư giữ ta,\nMột sứ giả báo thời,\nÐúng thời được báo hiệu,\nTa đến, ngang hư không.\n\n565. Ðảnh lễ chân Ðạo Sư,\nMột bên ta ngồi xuống.\nBiết ta đã ngồi xuống,\nBậc Ðạo Sư chấp nhận.\n\n566. Bậc nhận đồ tế vật,\nCả toàn thể thế giới,\nLà phước điền loài Người,\nNgài chấp nhận cúng dường.`, ref: "Trưởng Lão Tăng Kệ 10.4", url: "https://loicuaducphat.org/thag/thag10.4.html#content" },

{ text: `Trưởng Lão Kappa\n\n567. Ðầy nhiều loại uế vật,\nChỗ chưa còn phần uế,\nNhư vũng nước đọng lâu,\nUng nhọt vết thương lớn.\n\n563. Ðầy những máu và mủ,\nChìm đắm, trong hố phân,\nThân ứ nước rỉ chảy,\nLuôn chảy nước bất tịnh.\n\n569. Trói bởi sáu mươi gân,\nTrét dùng thịt làm hồ,\nMặc áo giáp bằng da,\nThân hôi thúi vô dụng.\n\n570. Nối thành dây xúc xương,\nCột lại với dây gân,\nDo chúng nhiều hợp sức,\nTác thành những uy nghi.\n\n571. Thường tiến đến sự chết,\nÐến gần cảnh tử thần,\nỞ đấy, bị quăng bỏ,\nCon người đi theo dục.\n\n572. Thân bị vô minh che,\nTrói bởi bốn trói buộc,\nThân chìm trong bộc lưu,\nMắc vào lưới tùy miên,\n\n573. Hệ lụy năm triền cái,\nÁm ảnh bởi tâm tư,\nÐi theo gốc khát ái,\nChe trùm bởi màn si.\n\n574. Thân này luân chuyển vậy,\nDẫn đi bởi xe nghiệp,\nKhi thành công, khi bại,\nChịu đựng nhiều ái sanh.\n\n575. Ai nghĩ 'thân của tôi',\nLà phàm phu ngu muội,\nTăng mộ phần đáng sợ,\nChấp chặt sự tái sanh.\n\n576. Ai tránh né thân này,\nNhư tránh rắn dính phân,\nHọ bỏ gốc sanh hữu,\nChứng Niết-bàn, vô lậu.`, ref: "Trưởng Lão Tăng Kệ 10.5", url: "https://loicuaducphat.org/thag/thag10.5.html#content" },

{ text: `Trưởng Lão Upasena, Con Của Vanganta\n\n577. Xứ viễn ly, không ồn,\nChỗ thú rừng thường trú,\nTỷ-kheo dọn sàng tọa,\nTu học hạnh tịnh cư.\n\n578. Từ những đống rác rưới,\nTừ một phần, xa lộ,\nLàm Y Tăng-già-lê,\nMang áo cũ sờn mòn.\n\n579. Với tâm tư hạ mình,\nTiếp tục đi từng nhà,\nTỷ-kheo sống khất thực,\nCăn hộ, khéo chế ngự.\n\n580. Bằng lòng món ăn thô,\nKhông tìm nhiều vị khác;\nNếu tham đắm các vị,\nÝ không vui tu thiền.\n\n581. Ít dục và biết đủ,\nẨn sĩ sống viễn ly,\nKhông thân cận cả hai,\nTại gia và xuất gia.\n\n582. Như kẻ ngu, người câm,\nHãy tỏ mình như vậy,\nBậc trí giữa chúng Tăng,\nChớ có giảng quá dài.\n\n383. Chớ có chỉ trích ai,\nHãy tránh làm hại ai,\nChế ngự trong giới bổn,\nTiết độ trong ăn uống.\n\n584. Khéo nắm giữ các tướng,\nThiện xảo tâm diễn khởi,\nChú tâm vào tịnh chỉ,\nÐúng thời tu thiền quán.\n\n585. Ðủ tinh tấn nhẫn nại,\nLuôn chuyên chú bổn phận,\nChưa đạt được khổ diệt,\nKẻ trí tin tưởng tiến.\n\n586. Tỷ-kheo muốn thanh tịnh,\nSống nếp sống như vậy,\nMọi lậu hoặc đoạn tận,\nChứng được tối tịch tịnh.`, ref: "Trưởng Lão Tăng Kệ 10.6", url: "https://loicuaducphat.org/thag/thag10.6.html#content" },

{ text: `Trưởng Lão Gotama\n\n587. Hãy biết hạnh phúc mình,\nQuan sát lời nghe giảng,\nÐây cái gì thích hợp,\nSa-môn hạnh mình theo.\n\n588. Bạn kẻ thiện trong đạo,\nHành học pháp rộng lớn,\nKhéo nghe bậc Ðạo Sư,\nÐây hợp Sa-môn hạnh.\n\n589. Với tâm kính chư Phật,\nTrọng Chánh pháp như thật,\nVà mến quý chư Tăng,\nÐây hợp Sa-môn đạo.\n\n590. Giữ uy nghi, đi lại,\nMạng sống tịnh, không chê,\nTư tưởng khéo ổn định,\nÐây hợp Sa-môn đạo.\n\n591. Ðiều làm hay không làm,\nUy nghi được ái kính,\nAn trú tăng thượng tâm,\nÐây hợp Sa-môn đạo.\n\n592. Sàng tọa tại rừng núi,\nXa vắng ít ồn ào,\nThân cận bậc Mâu-ni,\nÐây hợp Sa-môn đạo\n\n593. Giới hạnh và học nhiều,\nNhư thật nghiên cứu pháp,\nThiền quán những sự thật,\nÐây hợp Sa-môn đạo.\n\n594. Tu quán trên vô thường,\nTưởng vô ngã, bất tịnh,\nKhông ưa thích tục sự,\nÐây hợp Sa-môn đạo.\n\n595. Tu tập các Giác chi,\nThần túc, căn là lực,\nThu Chánh đạo Tám ngành,\nÐây hợp Sa-môn đạo.\n\n596. Mâu-ni bỏ khát ái,\nÐập tan gốc lậu hoặc,\nHãy an trú giải thoát,\nÐây hợp Sa-môn đạo.`, ref: "Trưởng Lão Tăng Kệ 10.7", url: "https://loicuaducphat.org/thag/thag10.7.html#content" },

{ text: `Trưởng Lão Sankicca\n\n597. Lợi ích ngài là gì,\nỞ rừng sâu, mùa mưa,\nNhư U-ju-hà-na,\nHỡi này ngài thân mến!\nHang gió đẹp cho ngài,\nSống một mình, tu thiền.\n\n598. Như gió mùa thổi mây,\nTrong thời tiết mùa mưa,\nTưởng ta bay tràn khắp,\nTưởng dung hòa viễn ly.\n\n599. Quạ đen, từ trứng sinh,\nLấy nghĩa địa làm nhà,\nKhiến ta khởi lên niệm,\nViễn ly đối với thân.\n\n600. Người kẻ khác không hộ,\nNgười không hộ kẻ khác,\nTỷ-kheo, sống an lạc,\nKhông kỳ vọng các dục.\n\n601. Tảng đá có nước trong,\nChỗ hội họp quy tụ,\nCác loài vượn mặt đen,\nCác loài nai nhút nhát,\nDưới màn hoa nước chảy,\nTảng đá ấy ta thích.\n\n602. Ta sống trong rừng núi,\nTrong hang động khe đá,\nTại trú xứ xa vắng,\nChỗ thú rừng qua lại.\n\n603. Hãy hại chúng, giết chúng!.\nHãy làm khổ hữu tình,\nTa không biết niệm ấy,\nPhi Thánh liên hệ sân,\n\n604. Ðạo Sư, ta hầu hạ,\nLời Phật dạy làm xong,\nGánh nặng đặt xuống thấp,\nGốc sanh hữu, nhổ sạch.\n\n605. Vì đích gì, xuất gia,\nBỏ nhà sống không nhà,\nMục đích ấy, ta đạt,\nMọi kiết sử tận diệt.\n\n606. Ta không thích thú chết,\nTa không thích thú sống,\nTa chờ thời gian đến,\nNhư thợ làm việc xong.\n\n607. Ta không thích thú chết,\nTa không thích thú sống,\nTa chờ thời gian đến,\nTỉnh giác, giữa chánh niệm.`, ref: "Trưởng Lão Tăng Kệ 11.1", url: "https://loicuaducphat.org/thag/thag11.1.html#content" },

{ text: `Trưởng Lão Silava\n\n608. Ở đây hãy học giới,\nKhéo học tập ở đời,\nGiới thành đạt toàn diện,\nÐưa đến mọi thành công.\n\n609. Bậc trí hãy hộ giới,\nNếu kỳ vọng ba lạc,\nÐược danh xưng tài sản,\nSau chết, hưởng thiên lạc.\n\n610. Người trì giới, tự chế,\nÐược nhiều người bạn tốt,\nKẻ ác giới, hành ác,\nMất mát các bạn bè.\n\n611. Người ác giới chỉ được,\nÁc danh, không tài sản,\nBậc trì giới luôn được\nKhen danh xưng, tán thán.\n\n612. Khởi đầu, an trú giới,\nGiới là mẹ thiện pháp,\nGiới đứng đầu mọi pháp,\nVậy hãy trong sạch giới.\n\n613. Giới hạn chế, phòng ngự,\nLàm sáng chói tâm tư,\nLà đầu bến chư Phật,\nVậy hãy trong sạch giới\n\n614. Giới sức mạnh vô song,\nGiới, binh khí tối thượng,\nGiới, trang sức đệ nhất,\nGiới áo giáp hy hữu.\n\n615. Giới, đầu cầu cường dại,\nGiới, hương thơm vô thượng,\nGiới, hương thoa đệ nhất,\nNhờ giới, bay bốn phương.\n\n616. Giới, tư lương cao nhất,\nGiới, hành trang tối thượng,\nGiới vận tải, đệ nhất,\nNhờ giới, đi bốn phương.\n\n617. Ðây, kẻ xấu bị trách,\nSau chết sanh đọa xứ,\nKẻ ngu không định giới,\nƯu tư khắp các chỗ.\n\n618. Ðây bậc tốt được khen,\nSau chết sanh thoát giải,\nKẻ trí khéo định giới,\nHân hoan, khắp các chỗ.\n\n619. Ở đây, giới tối cao,\nNhưng trí tuệ, tối thượng,\nGiữa loài Người, loài Trời,\nBậc giới tuệ thắng lợi.`, ref: "Trưởng Lão Tăng Kệ 12.1", url: "https://loicuaducphat.org/thag/thag12.1.html#content" },

{ text: `Trưởng Lão Sunita\n\n620. Ta sanh nhà hạ tiện,\nNghèo khổ không đủ ăn,\nNghề ta rất hèn hạ,\nTa kẻ quét hoa rơi.\n\n621. Ta bị người nhàm chán,\nMiệt thị và khinh bỉ,\nHạ mình xuống thật thấp,\nTa kính lễ quần chúng.\n\n622. Rồi ta thấy đức Phật,\nThượng thủ chúng Tỷ-kheo,\nBậc Ðại Hùng vào thành,\nMagadha tối thượng.\n\n623. Ta quăng bỏ đòn gánh,\nÐến gần để đảnh lễ,\nVới lòng thương xót ta,\nBậc Thượng nhân đứng lại.\n\n624. Lễ chân Ðạo Sư xong,\nTa đứng liền một bên,\nTa xin được xuất gia,\nBậc tối thượng mọi loài.\n\n625. Bậc Ðạo Sư từ bi,\nTừ mẫn khắp thế giới,\nNói: 'Hãy đến Tỷ-kheo',\nÐại giới, ta thọ vậy.\n\n626. Rồi ta sống trong rừng,\nMột mình không biếng nhác,\nTa theo lời Ðạo Sư,\nNhư bậc chiến thắng dạy.\n\n627. Trong đêm canh thứ nhất,\nTa nhớ các đời trước,\nTrong đêm canh chặng giữa,\nThiên nhãn ta thanh tịnh,\nTrong đêm canh cuối cùng,\nTa phá khối si ám.\n\n628. Khi đêm vừa mở rộng,\nRạng đông, trời ló rạng,\nÐế Thích, Phạm Thiên đến,\nChấp tay đảnh lễ ta,\n\n629. Ðảnh lễ bậc Thượng sanh!\nÐảnh lễ bậc Thượng nhân!\nNgài đoạn tận lậu hoặc,\nNgài xứng đáng cúng dường.\n\n630. Bậc Ðạo Sư thấy ta,\nÐứng đầu chúng chư Thiên,\nNở ra một nụ cười,\nNói với ta nghĩa này.\n\n631. Nhờ khổ hạnh, Phạm hạnh,\nNhờ tự chế, điều phục,\nNhờ vậy, là Phạm chí,\nÐây, Phạm chí tối thượng.`, ref: "Trưởng Lão Tăng Kệ 12.2", url: "https://loicuaducphat.org/thag/thag12.2.html#content" },

{ text: `Trưởng Lão Sona-Kolivisa\n\n632. Người xưa, cao trong nước,\nPhục vụ vua Ăng-ga,\nNay lại cao trong pháp,\nSo-na vượt đau khổ.\n\n633. Năm được cắt, năm bỏ,\nNăm thượng pháp tu tập,\nTỷ-kheo vượt năm gút,\nÐược gọi vượt bộc lưu.\n\n634. Tỷ-kheo tánh kiêu ngoa,\nPhóng dật, ưa vị ngoài,\nGiới, thiền định, trí tuệ,\nKhông đi đến viên mãn.\n\n635. Việc phải làm, quăng bỏ,\nKhông phải việc, lại làm,\nKẻ kiêu ngoa phóng dật,\nLậu hoặc được tăng trưởng.\n\n636. Những ai khéo tinh cần,\nThường tu tập niệm thân,\nKhông phải việc, không làm,\nKiên trì việc nên làm.\nBậc chánh niệm tỉnh giác,\nLậu hoăc đi đến diệt.\n\n637. Trên đường thẳng được thuyết,\nHãy bước, chớ quanh co,\nHãy tự mình trách mình,\nHãy đem Niết-bàn lại,\n\n638. Khi tinh cần nỗ lực,\nCăng thẳng, vượt mức độ,\nThế gian, Vô Thượng Sư,\nDùng ví dụ chiếc đàn,\nBậc pháp nhãn, có mắt,\nNgài thuyết pháp cho ta.\n\n639. Ta nghe lời Ngài giảng,\nLạc trú lời giảng dạy,\nBình tĩnh, ta thực hành,\nÐể đạt đích tối thượng,\nBa minh ta đạt được,\nLời Phật dạy làm xong.\n\n640. Ai chuyên nhất xuất ly,\nTâm tư hướng viễn ly,\nAi chuyên nhất vô sân,\nDiệt trừ các chấp thủ.\n\n641. Ai chuyên nhất ái diệt,\nTâm tư không si mê,\nThấy sanh khởi các xứ,\nTâm được khéo giải thoát.\n\n642. Vị Tỷ-kheo tâm tịnh,\nÐược giải thoát chơn chánh,\nKhông chất chứa việc làm,\nÐiều phải làm không có.\n\n643. Như một hòn đá tảng,\nKhông bị gió lay động,\nCũng vậy toàn bộ phận,\nSắc, vị, thanh, hương, xúc.\n\n644. Pháp ái bất khả ái,\nKhông động, người như vậy,\nTâm trú, không hệ lụy,\nTùy quán, sự hoại diệt.`, ref: "Trưởng Lão Tăng Kệ 13.1", url: "https://loicuaducphat.org/thag/thag13.1.html#content" },

{ text: `Trưởng Lão Khadiravaniya Revata\n\n645. Từ khi xa xuất gia,\nBỏ nhà, sống không nhà,\nTa không biết tư duy,\nPhi thánh, liên hệ sân.\n\n646. Hay làm hại, sát hại,\nHay làm khổ hữu tình,\nTa không biết tư duy,\nTrong thời gian dài này.\n\n647. Và ta biết lòng từ,\nVô lượng khéo tu tập,\nTa thứ lớp tích lũy,\nNhư lời đức Phật dạy.\n\n648. Là bạn thân tất cả,\nTừ mẫn mọi hữu tình,\nTa tu tập tâm từ,\nLuôn vui, không sân hận.\n\n649. Ta thích thú với tâm,\nKhông động, không dao động,\nTa tu tập Phạm trú,\nÐược bậc thiện hành trì.\n\n650. Ta đạt được vô tầm,\nÐệ tử bậc Chánh giác,\nVới im lặng bậc Thánh,\nTa trực diện đạt được.\n\n651. Như núi đá không động,\nÐứng vững khéo an trú,\nCũng vậy là Tỷ-kheo,\nÐạt được si mê diệt,\nVị ấy như ngọn núi,\nKhông gì làm dao động.\n\n652. Con người không uế nhiễm,\nLuôn tìm sự trong sạch,\nTội nhẹ như đầu tóc,\nXem nặng như mây khói.\n\n653. Như thành trì biên địa,\nPhòng hộ cả trong ngoài,\nHãy phòng hộ tự ngã,\nSát-na không bỏ qua.\n\n654. Ta không thích thú chết,\nTa không thích thú sống,\nTa chờ thời gian đến,\nNhư thợ làm việc xong.\n\n655. Ta không thích thú chết,\nTa không thích thú sống,\nTa chờ thời gian đến,\nTỉnh giác, giữ chánh niệm.\n\n656. Ðạo Sư, ta hầu hạ,\nLời Phật dạy làm xong,\nGánh nặng, đặt xuống thấp,\nGốc sanh hữu, nhổ sạch.\n\n657. Vì đích gì xuất gia,\nBỏ nhà, sống không nhà,\nMục đích ấy, ta đạt,\nMọi kiết sử diệt tận.\n\n658. Nỗ lực, chớ phóng dật,\nÐấy lời ta giáo giới,\nTa sẽ nhập Niết-bàn,\nTa thoát mọi sanh y.`, ref: "Trưởng Lão Tăng Kệ 14.1", url: "https://loicuaducphat.org/thag/thag14.1.html#content" },

{ text: `Trưởng Lão Godatta\n\n659. Như con bò giống tốt,\nÐược huấn luyện tốt đẹp,\nBị cột vào gánh nặng,\nMang gánh nặng kéo đi,\nBị áp đè quá nặng,\nKhông lật đổ gánh nặng.\n\n660. Cũng vậy, ai nhiều tuệ,\nNhư nước ở trong biển,\nKhông khinh miệt người khác,\nThánh pháp là như vậy,\nÐối với các hữu tình.\n\n661. Sống trong vòng thời gian,\nBị thời gian hàng phục,\nHữu, phi hữu chi phối,\nLoài Người chịu đau khổ,\nCon cháu họ sầu ưu,\nChính ngay trong đời này.\n\n662. Hân hoan, khi được lạc,\nGặp khổ lại chán chường,\nKẻ ngu bị não hại,\nChi phối cả hai đường,\nKhông thấy được như thật.\n\n663. Những ai giữa khổ lạc,\nNgười dệt không chi phối,\nÐứng vững như cột cửa,\nKhông hân hoan chán chường\n\n664. Ðối với được hay mất,\nVới danh với không danh,\nÐối với chê hay khen,\nVới khổ hay với lạc.\n\n665. Chúng tôi dính chỗ nào,\nNhư giọt nước trên sen,\nBậc anh hùng mọi chỗ,\nÐược lạc, không bị bại.\n\n666. Người đúng pháp không được,\nNgười được, không đúng pháp,\nÐúng pháp nhưng không được,\nHơn được không đúng pháp.\n\n667. Người có danh, ít trí\nNgười có trí, không danh,\nKhông danh nhưng có trí,\nHơn ít trí, có danh.\n\n668. Ðược khen bởi kẻ ngu,\nBị chê bởi kẻ trí,\nÐược kẻ trí chê bai,\nHơn được người ngu khen.\n\n669. Lạc do dục đem lại,\nKhổ do viễn ly sanh,\nKhổ do viễn ly sanh\nHơn lạc do dục sanh.\n\n670. Làm phi pháp để sống,\nLàm đúng pháp, có chết,\nLàm đúng pháp, có chết,\nHơn sống, làm phi pháp.\n\n671. Ai đoạn dục phẫn nộ,\nTâm tịnh hữu, phi hữu\nSống ở đời, không ái,\nKhông thương yêu ghét bỏ.\n\n672. Sau khi tu Giác chi,\nCác căn và các lực,\nÐạt tịch tịnh tối thắng,\nChứng Niết-bàn vô lậu.`, ref: "Trưởng Lão Tăng Kệ 14.2", url: "https://loicuaducphat.org/thag/thag14.2.html#content" },

{ text: `Trưởng Lão Anna-Kondanna\n\n673. Ta bội phần hân hoan,\nÐược nghe pháp vị lớn,\nPháp được giảng ly tham,\nHoàn toàn không chấp thủ.\n\n674. Trên thế giới đất tròn,\nNhiều màu sắc hình tướng,\nLàm say đắm tâm tư,\nTa nghĩ là như vậy,\nTướng tịnh rất hấp dẫn,\nLiên hệ đến tham dục.\n\n675. Như gió thổi tung bụi,\nÐược mây trấn áp xuống,\nCác tư duy lắng dịu,\nKhi thấy, với trí tuệ.\n\n676. Mọi hành là vô thường\nKhi thấy với trí tuệ,\nVị ấy nhàm chán khổ,\nÐây con đường đến tịnh.\n\n677. Mọi hành là đau khổ,\nKhi thấy với trí tuệ,\nVị ấy nhàm chán khổ,\nÐây con đường đến tịnh.\n\n678. Mọi pháp là vô ngã,\nKhi thấy với trí tuệ,\nVị ấy nhàm chán khổ,\nÐây con đường đến tịnh.`, ref: "Trưởng Lão Tăng Kệ 15.1", url: "https://loicuaducphat.org/thag/thag15.1.html#content" },

{ text: `679. Trưởng lão Kondanna,\nGiác ngộ bởi giác ngộ,\nÐã sắc bén thoát ly,\nÐoạn tận sanh và chết,\nVà đời sống Phạm hạnh,\nÐược hoàn toàn viên mãn.\n\n680. Hoặc bộc lưu, bẫy mồi,\nHoặc cột trụ vững chắc,\nNgọn núi khó phá hoại,\nSau khi chặt phá xong,\nCột trụ và bẫy mồi,\nChặt tảng đá khó phá,\nHành thiền, vượt bờ kia,\nThoát khỏi Ma trói buộc.\n\n681. Tỷ-kheo hoảng hốt động,\nÐi đến các bạn ác,\nChìm trong bộc lưu lớn,\nBị sóng lớn ngập tràn.\n\n682. Bậc trí không hoảng hốt,\nKhông dao động, thận trọng,\nCác căn khéo chế ngự,\nLàm bạn với kẻ thiện,\nBậc trí tuệ như vậy,\nCó thể đoạn đau khổ.\n\n683. Một người đen, gầy mòn,\nYếu ốm, đầy đường gân,\nTiết độ trong ăn uống,\nTâm tư không ưa não.\n\n684. Trong rừng núi rộng lớn,\nBị muỗi ruồi đốt cắn,\nNhư con voi lâm trận,\nTa chánh niệm, chịu đựng.\n\n685. Ta không thích thú chết,\nTa không thích thú sống,\nTa chờ thời gian đến,\nNhư thợ làm việc xong.\n\n686. Ta không thích thú chết,\nTa không thích thú sống,\nTa chờ thời gian đến,\nTỉnh giác, giữ chánh niệm.\n\n687. Ðạo Sư, ta hầu hạ,\nLời Phật dạy, làm xong,\nGánh nặng, đặt xuống thấp,\nGốc sanh hữu, nhổ sạch.\n\n688. Vì mục đích xuất gia,\nBỏ nhà, sống không nhà,\nMục đích ấy, ta đạt,\nTa cần gì ở rừng.`, ref: "Trưởng Lão Tăng Kệ 15.1", url: "https://loicuaducphat.org/thag/thag15.1.html#content" },

{ text: `Trưởng Lão Udayi\n\n689. Ðức Phật, sanh làm người,\nTự điều phục thiền định,\nUy nghi Phạm thiên đạo,\nHoan hỷ trong tâm tịnh.\n\n690. Loài người đảnh lễ Ngài,\nBậc đạt được bờ kia,\nÐối với hết thảy pháp,\nChư Thiên đảnh lễ Ngài,\nNhư vậy ta được nghe,\nTa là A-la-hán.\n\n691. Vượt qua mọi kiết sử,\nTừ rừng đến Niết-bàn,\nVui thoát ly các dục,\nNhư vàng thoát khoáng sản.\n\n692. Vị ấy thật như voi,\nTuyệt luân đẹp rực rỡ\nÐứng trên đỉnh núi cao\nDãy trường sơn Hi-mã,\nTrong mọi danh Nàga,\nNgài chân danh Vô thượng.\n\n693. Rồi ta sẽ tán thán,\nNàga này cho người,\nNàga không làm ác,\nNên được gọi Nàga,\nTừ tốn, không làm hại,\nLà hai chân Nàga.\n\n694. Chánh niệm và tỉnh giác,\nHai chân khác Nàga,\nVoi Nàga là tín,\nNgà màu trắng là xả\n\n695. Chánh niệm là cổ họng,\nTrí tuệ chỉ cho đầu,\nSuy tầm với cái vòi,\nChỉ cho tư duy pháp.\nHòa trú là bụng pháp,\nViễn ly ví đuôi voi.\n\n696. Tu thiền, thở vô lạc,\nNội tâm, khéo định tỉnh,\nNàga đi, định tỉnh,\nNàga đứng, định tỉnh.\n\n697. Nàga nằm, định tỉnh,\nNàga ngồi, định tỉnh,\nTrong tất cả tình huống,\nNàga sống chế ngự\nÐây thành tích Nàga.`, ref: "Trưởng Lão Tăng Kệ 15.2", url: "https://loicuaducphat.org/thag/thag15.2.html#content" },

{ text: `Trưởng Lão Udayi\n\n698. Ăn đồ ăn không tội,\nÐồ có tội không ăn;\nÐược đồ ăn, y phục,\nTừ bỏ, không tích trữ.\n\n699. Kiết sử tế hay thô,\nChặt đứt mọi trói buộc,\nChỗ nào vị ấy đi,\nBước đi, không kỳ vọng.\n\n700. Như sen sanh trong nước,\nLớn lên được tăng trưởng,\nKhông có dính nước ướt,\nThơm ngát, rất khả ái.\n\n701. Cũng vậy bậc Chánh Giác,\nSanh và trú ở đời,\nKhông có dính sự đời,\nNhư sen không dính nước.\n\n702. Như đống lửa cháy đỏ,\nKhông củi tự tắt dần,\nTrong than tro lắng dịu,\nÐược gọi lửa diệt tận.\n\n703. Ví dụ, bậc trí thuyết,\nÐể nêu rõ ý nghĩa,\nÐại Nàga sẽ hiểu,\nNhững gì về Nàga,\nDo Nàga ấy giảng.\n\n704. Vô tham và vô sân,\nVô si, không lậu hoặc,\nNàga từ bỏ thân,\nSẽ diệt độ Niết-bàn,\nKhông còn có lậu hoặc.`, ref: "Trưởng Lão Tăng Kệ 15.2", url: "https://loicuaducphat.org/thag/thag15.2.html#content" },

{ text: `Trưởng Lão Parapariya\n\n726. Khi Tỷ-kheo tên là,\nPàràpariya,\nNgồi độc cư một mình,\nViễn ly, tu thiền định,\nNhững tâm tư như sau,\nÐược khởi lên nơi ngài:\n\n727. Có gì là thứ lớp,\nLà giới cấm, động tác?\nCon người làm phận mình,\nKhông làm hại một ai?\n\n728. Các căn của loài Người,\nLàm lợi ích, làm hại,\nKhông hộ trì, làm hại,\nCó hộ trì, làm lợi.\n\n729. Người chế ngự các căn,\nNguời phòng hộ các căn,\nNgười làm bổn phận mình,\nKhông làm hại một ai.\n\n730. Con mắt đi đến sắc,\nKhông chế ngự ngăn chận,\nKhông thấy các nguy hiểm,\nVị ấy không thoát khổ.\n\n731. Lỗ tai đi đến tiếng,\nKhông chế ngự ngăn chặn,\nKhông thấy sự nguy hiểm,\nVị ấy không thoát khổ.\n\n732. Không thấy sự xuất ly,\nThọ hưởng các mùi hương,\nVị ấy không thoát khổ,\nVì tham đắm các hương.\n\n733. Nhớ chua ngọt tối thượng,\nNhớ vị đắng tối thượng,\nBị ái vị nô lệ,\nTâm không thể giác tỉnh.\n\n734. Tưởng nhớ các cảm xúc,\nÐẹp đẽ và khoái cảm,\nÐam mê, duyên tham ái,\nGặp nhiều loại đau khổ.\n\n735. Ý đối các pháp này\nTất cả là năm pháp,\nKhông có thể phòng hộ,\nKhổ đi theo vị ấy.`, ref: "Trưởng Lão Tăng Kệ 16.2", url: "https://loicuaducphat.org/thag/thag16.2.html#content" },

{ text: `Trưởng Lão Parapariya\n\n736. Phần lớn các thân xác,\nÐầy tràn mủ và máu,\nDo người thù thắng làm,\nThành hộp đẹp tô màu.\n\n737. Cay đắng như vị ngọt,\nKhổ do khả ái buộc,\nNhư dao bén dính mật,\nKẻ tham đâu có biết.\n\n738. Ai tham đắm nữ sắc,\nNữ vị, nữ xúc chạm,\nAi mê say nữ hương,\nGặp nhiều loại đau khổ.\n\n739. Mọi dòng từ nữ nhân,\nNăm loại tràn năm xứ,\nNgười có tinh tấn lực,\nCó thể ngăn chận chúng.\n\n740. Người có đích, trú pháp,\nNgười thiện xảo, sáng suốt,\nHoan hỷ làm nghĩa vụ,\nLiên hệ đến pháp, nghĩa.\n\n741. Chìm trong việc lợi tạm,\nHãy bỏ việc không lợi,\nNếu nó nghĩ việc ấy,\nKhông phải việc nên làm,\nVị ấy không phóng dật,\nSáng suốt thấy rõ vậy.\n\n742. Nếu là việc làm tốt,\nHân hoan hành đúng pháp,\nHãy nắm việc làm ngay,\nÐấy thật lạc tối thượng.\n\n743. Với phương tiện cao thấp,\nLừa dối các người khác,\nÐánh giết, làm sầu khổ,\nHung bạo, áp đảo người.\n\n743. Như người mạnh đẽo gỗ,\nDùng nêm đánh bật nêm,\nCũng vậy là kẻ thiện,\nDùng căn đánh bật căn.\n\n745. Tu tập tín, tấn, định,\nHuấn luyện niệm, trí tuệ,\nDùng năm đánh đổ năm,\nKhông tỳ vết bước tới.\n\n746. Là vị Bà-la-môn,\nNgười có đích, trú pháp,\nLàm theo giáo huấn Phật,\nLàm toàn diện, toàn lực,\nNgười ấy hưởng an lạc.`, ref: "Trưởng Lão Tăng Kệ 16.2", url: "https://loicuaducphat.org/thag/thag16.2.html#content" },

{ text: `Trưởng Lão Telakani\n\n747. Lâu ngày, đầy nhiệt tình,\nTa suy tư Chánh pháp,\nHỏi Sa-môn, Phạm chí,\nNhưng tâm không an tịnh.\n\n748. Ở đời, ai đã đến,\nÐến được bờ bên kia,\nAi đã chứng đạt được,\nLặn sâu vào bất tử,\nPháp ai ta chấp nhận,\nPháp thông đệ nhất nghĩa.\n\n749. Mắc lưỡi câu bên trong,\nNhư cá ăn mồi tục,\nTa bị bắt, bị trói,\nChẳng khác A-tu-la,\nTên Vê-pa-xi-li,\nBị lưới Ðế Thích trói.\n\n750. Ta kéo lê xiềng xích,\nKhông sao thoát sầu bi,\nAi cởi trói cho ta,\nGiúp ta chứng Chánh giác.\n\n751. Sa-môn, Phạm chí nào,\nNói cách hủy hoại chúng,\nPháp ai ta chấp nhận,\nGiúp từ bỏ già chết,\n\n752. Bị nghi hoặc trói buộc,\nBị hăng say chi phối,\nKhiến tánh tình phẫn nộ,\nKhiến tâm tư cứng rắn,\nBị xâu xé cắt đứt,\nBởi lòng tham mạnh mẽ.\n\n753. Bị cung ái bắn trúng,\nBa mươi kiến trói buộc,\nXem sức mạnh ngực ta,\nBị áp đè, vẫn vững,\n\n754. Các tùy kiến không đoạn,\nCác tư niệm dao động,\nBị chúng đâm, ta run,\nNhư lá bị gió thổi,\n\n755. Khởi lên từ nội tâm,\nÐốt cháy nhanh ngã sở,\nThân với sáu xúc xứ,\nNgã hữu từ đấy sanh.\n\n756. Ta không thấy lương y,\nRút mũi tên cho ta,\nDùng cách khác dò tìm,\nKhông dùng dao thăm dò.\n\n757. Có vị lương y nào,\nKhông dao, không vết thương,\nKhông hại đến tay chân,\nRút mũi tên cho ta,\nMũi tên đã đâm vào,\nTrong nội tâm của ta,\n\n758. Bậc Pháp chủ tối tôn,\nLoại trừ thuốc độc hại,\nKhi ta rơi vực sâu,\nÐưa tay giúp đỡ ta,\nTới đất liền an toàn.`, ref: "Trưởng Lão Tăng Kệ 16.3", url: "https://loicuaducphat.org/thag/thag16.3.html#content" },

{ text: `Trưởng Lão Telakani\n\n759. Ta lặn sâu trong hồ,\nÐầy bụi bùn không thoát,\nÐầy man trá, tật đố,\nCăng thẳng và hôn ám.\n\n760. Sấm trạo cử nổ vang,\nMây kiết sử bao phủ,\nThác nước tà tư duy,\nLiên hệ đến tham dục,\nChúng lôi cuốn trôi ta,\nVào đại dương tà kiến.\n\n761. Khắp nơi, dòng suối chảy,\nCây leo đứng, đâm chồi,\nAi chận đứng dòng ấy?\nAi chặt đứt cây leo?\n\n762. Tôn giả hãy làm đê,\nNgăn chận những dòng suối,\nChớ có để dòng nước,\nDo ý sanh cuốn ngài,\nNhư dòng nước cuốn gấp,\nTrôi cây chảy theo dòng.\n\n763. Cũng vậy ta sợ hãi,\nBờ này tìm bờ kia,\nKhi ấy bậc Ðạo Sư,\nCó Thánh chúng hầu hạ,\nVới binh khí trí tuệ,\nChờ y chỉ cho người.\n\n764. Ðưa ta, đang chìm đắm,\nChiếc cầu thang, khéo làm,\nPhật thanh tịnh, vững chắc,\nLàm bằng lõi Chánh pháp,\nRồi ngài nói với ta,\nChớ có sợ hãi gì!.\n\n765. Leo lên lầu niệm xứ,\nTừ đấy ta quán sát,\nLoài Người ưa thân kiến,\nTrước đây, ta tự hào.\n\n766. Khi ta thấy con đường,\nCon thuyền cần leo lên,\nTa không trú tự ngã,\nVì thấy bến tối thượng.\n\n767. Mũi tên khởi tự ngã,\nSanh do nhân sanh hữu\nNgài dạy đường tối thượng,\nChấm dứt các pháp ấy.\n\n768. Cột gút đã lâu ngày,\nẨn nằm, trú trong da,\nÐức Phật cởi, quăng đi,\nLoại bỏ mọi độc hại.`, ref: "Trưởng Lão Tăng Kệ 16.3", url: "https://loicuaducphat.org/thag/thag16.3.html#content" },

{ text: `Trưởng Lão Ratthapala\n\n769. Hãy xem bóng trang sức,\nNhóm vết thương tích tụ,\nBệnh hoạn, nhiều tham tưởng,\nNhưng không gì trường cửu.\n\n770. Hãy nhìn sắc trang sức,\nVới châu báu, vòng tai,\nBộ xương, da bảo phủ,\nSáng chói nhờ y phục.\n\n771. Chân sơn với son, sáp,\nMặt thoa với phấn bột,\nChỉ mê hoặc kẻ ngu,\nKhông mê bậc cầu giác.\n\n772. Tóc được uốn tám vòng,\nMắt xoa với thuốc son,\nChỉ mê hoặc kẻ ngu,\nKhông mê bậc cầu giác.\n\n773. Như hộp thuốc mới sơn,\nUế thân được trang điểm,\nChỉ mê hoặc kẻ ngu,\nKhông mê bậc cầu giác.\n\n774. Thợ săn bày lưới sập,\nNai khôn không chạm lưới,\nĂn mồi xong, ta đi,\nMặc kẻ bắt nai khóc.\n\n775. Bẫy thợ săn bị cắt,\nNai khôn không chạm lưới,\nĂn mồi xong, ta đi,\nMặc kẻ săn nai sầu.`, ref: "Trưởng Lão Tăng Kệ 16.4", url: "https://loicuaducphat.org/thag/thag16.4.html#content" },

{ text: `Trưởng Lão Ratthapala\n\n776. Ta thấy người đời giàu,\nÐược tiền, si không cho,\nVì tham, cất chứa tiền,\nChạy theo dục càng nhiều.\n\n777. Vua dùng lực chiếm đất,\nChiếm ở đến bờ biên,\nBiên bên này chưa thỏa,\nCòn muốn biên bờ kia.\n\n778. Vua và rất nhiều người,\nÁi chưa chết, đã chết,\nTái sanh, bị thiếu thốn,\nChúng từ bỏ thân này,\nNhưng ở đời lòng dục,\nKhông bao giờ thỏa mãn.\n\n779. Bà con than khóc nó,\nTóc xõa, rối tơ vò,\nChúng nói: Ôi chúng ta,\nKhông có được bất tử,\nThân trùm vải, chúng mang,\nDựng giàn hỏa, chúng thiêu.\n\n780. Bị cây đâm, cây thọc,\nNó bị thiêu bị cháy,\nChỉ với một tấm vải,\nTừ bỏ mọi tài sản,\nKẻ chết không nương tựa,\nBà con, bạn láng giềng.\n\n781. Kẻ thừa tự mang đi,\nTài sản gia nghiệp nó.\nRiêng con người phải đi,\nTheo chỗ, nghiệp nó tạo,\nTài sản không có đi,\nÐi theo người đã chết,\nKhông con trai, không vợ,\nKhông tài sản, quốc độ.\n\n782. Tài sản không làm sao,\nMua được tuổi trường thọ;\nPhú quý nào có thể,\nTránh khỏi được già suy.\nBậc có trí nói rằng:\nMạng sống này ít ỏi,\nThật sự là vô thường,\nLuôn luôn bị biến hoại.\n\n783. Giàu, nghèo đều cảm xúc,\nNgu, trí đồng cảm thọ,\nKẻ ngu bị ngu đánh,\nNgã quỵ, nằm dài xuống.\nCòn bậc trí không sợ,\nÐối với mọi cảm xúc.\n\n784. Do vậy tuệ thắng tài,\nNhờ tuệ đạt viên mãn,\nChưa đạt được cứu cánh,\nÐối với hữu, phi hữu,\nKẻ ngu làm các nghiệp,\nÁc độc và bất thiện.\n\n785. Nhập thai, sanh đời khác,\nLuân hồi, tiếp tục sanh,\nKẻ ít trí, tin tưởng,\nNhập thai, sanh đời khác.\n\n786. Như kẻ trộm bị bắt,\nQuả tang, khi ăn trộm,\nDo nghiệp tự chính nó,\nBị hại theo ác tội,\nCũng vậy sau khi chết,\nQuần chúng trong đời sau,\nDo nghiệp tự chính nó,\nBị hại theo ác tội.\n\n787. Các dục thật đẹp đẽ,\nVị ngọt và khả ái,\nChúng làm tâm đắm say,\nVới sắc và phi sắc,\nDo thấy sự nguy hiểm,\nTrong các dục công đức,\nDo vậy tôi xuất gia,\nNhư vậy thưa Ðại vương,\n\n788. Như trái cây rụng xuống,\nCũng vậy tuổi thanh niên,\nLớn lên và già yếu,\nRồi thân hoại mạng chung,\nThấy vậy tôi xuất gia,\nNhư vậy thưa Ðại vương,\nÐời sống Sa-môn hạnh,\nChơn thật, tốt đẹp hơn.\n\n789. Tín tâm tôi xuất gia,\nVào giáo hội bậc thánh,\nTôi xuất gia không tội,\nKhông nợ, tôi thọ thực.\n\n790. Thấy dục như lửa hừng,\nThấy vàng như dao đâm,\nXem nhập thai là khổ,\nHọa lớn trong địa ngục.\n\n791. Thấy nguy hiểm như vậy,\nTa cảm thấy hoảng sợ,\nKhi bị đâm, bị thương,\nTa đạt được tịch tịnh,\nVà ta tận diệt được,\nCả ba loại lậu hoặc.\n\n792. Ðạo Sư, ta hầu hạ,\nLời Phật dạy, làm xong,\nGánh nặng, đặt xuống thấp,\nGốc sanh hữu, nhổ sạch.\n\n793. Vì đích gì xuất gia,\nBỏ nhà, sống không nhà,\nMục đích ấy ta đạt,\nMọi kiết sử tận diệt.`, ref: "Trưởng Lão Tăng Kệ 16.4", url: "https://loicuaducphat.org/thag/thag16.4.html#content" },

{ text: `Trưởng Lão Malunkyaputta\n\n794. Thấy sắc, niệm say mê,\nNếu tác ý ái tưởng,\nTâm tham đắm cảm thọ,\nTâm nhập và an trú.\n\n795. Thọ người ấy tăng trưởng,\nNhiều loại, do sắc sanh,\nTham, hại tâm lớn mạnh,\nChúng gia hại tâm nó,\nKhổ chất chứa như vậy,\nRất xa vời Niết-bàn.\n\n796. Nghe tiếng, niệm say mê,\nNếu tác ý ái tưởng,\nTâm tham đắm cảm thọ,\nXâm nhập và an trú.\n\n797. Thọ người ấy tăng trưởng,\nNhiều loại, do tiếng sanh,\nTham, hại tâm lớn mạnh,\nChúng gia hại tâm nó,\nKhổ chất chứa như vậy,\nRất xa vời Niết-bàn.\n\n798. Ngửi hương, niệm say mê,\nNếu tác ý ái tưởng,\nTâm tham đắm cảm thọ,\nXâm nhập và an trú.\n\n799. Thọ người ấy tăng trưởng,\nNhiều loại do hương sanh,\nTham, hại tâm lớn mạnh,\nChúng gia hại tâm nó.\nKhổ chất chứa như vậy,\nRất xa vời Niết-bàn.\n\n800. Nếm vị, niệm say mê,\nNếu tác ý ái tưởng,\nTâm tham đắm cảm thọ,\nXâm nhập và an trú.\n\n801. Thọ người ấy tăng trưởng,\nNhiều loại do vị sanh,\nTham, hại tâm lớn mạnh,\nChúng gia hại tâm nó,\nKhổ chất chứa như vậy,\nRất xa vời Niết-bàn.\n\n802. Cảm xúc, niệm say mê,\nNếu tác ý ái tưởng,\nTâm tham đắm cảm thọ,\nXâm nhập và an trú.\n\n803. Thọ người ấy tăng trưởng,\nNhiều loại, do xúc sanh,\nTham, hại tâm lớn mạnh,\nChúng gia hại tâm nó,\nKhổ chất chứa như vậy,\nRất xa vời Niết-bàn.\n\n804. Biết pháp, niệm say mê,\nNếu tác ý ái tưởng,\nTâm tham đắm cảm thọ,\nXâm nhập và an trú.\n\n805. Thọ người ấy tăng trưởng,\nNhiều loại do ý sanh,\nTham, hại tâm lớn mạnh,\nChúng gia hại tâm nó,\nKhổ chất chứa như vậy,\nRất xa vời Niết-bàn.`, ref: "Trưởng Lão Tăng Kệ 16.5", url: "https://loicuaducphat.org/thag/thag16.5.html#content" },

{ text: `Trưởng Lão Malunkyaputta\n\n806. Không tham nhiễm các sắc,\nThấy sắc, giữ chánh niệm,\nTâm không tham cảm thọ,\nKhông xâm nhập, an trú.\n\n807. Thấy sắc như thế nào,\nNhư vậy có cảm thọ,\nTừ bỏ không tích lũy,\nChánh niệm, hành trì vậy.\n\n808. Như vậy, không chứa khổ,\nÐược gọi gần Niết-bàn,\nKhông tham nhiễm các tiếng,\nNghe tiếng, giữ chánh niệm,\nTâm không tham cảm thọ,\nKhông xâm nhập an trú.\n\n809. Nghe tiếng như thế nào,\nNhư vậy có cảm thọ,\nTừ bỏ không tích lũy,\nChánh niệm, hành trì vậy.\nNhư vậy không chứa khổ,\nÐược gọi gần Niết-bàn.\n\n810. Không tham nhiễm các hương,\nNgửi hương, giữ chánh niệm,\nTâm không tham cảm thọ,\nKhông xâm nhập an trú.\n\n811. Ngửi hương như thế nào,\nNhư vậy, có cảm thọ,\nTừ bỏ, không tích lũy,\nChánh niệm, hành trì vậy,\nNhư vậy, không chứa khổ,\nÐược gọi, gần Niết-bàn.\n\n812. Không tham nhiễm các vị,\nNếm vị, giữ chánh niệm,\nTâm không tham cảm thọ,\nKhông xâm nhập, an trú.\n\n813. Nếm vị như thế nào,\nNhư vậy, có cảm thọ,\nTừ bỏ, không tích lũy,\nChánh niệm, hành trì vậy.\nNhư vậy không chứa khổ,\nÐược gọi, gần Niết-bàn.\n\n814. Không tham nhiễm các xúc,\nCảm xúc giữ chánh niệm,\nTâm không tham cảm thọ,\nKhông xâm nhập, an trú.\n\n815. Cảm xúc như thế nào,\nNhư vậy, có cảm thọ,\nTừ bỏ, không tích lũy,\nChánh niệm, hành trì vậy.\nNhư vậy không chứa khổ,\nÐược gọi, gần Niết-bàn.\n\n816. Không tham nhiễm các pháp,\nBiết pháp, giữ chánh niệm,\nTâm không tham cảm thọ,\nKhông xâm nhập, an trú.\n\n817. Cảm xúc như thế nào,\nNhư vậy, có cảm thọ,\nTừ bỏ, không tích lũy,\nChánh niệm, hành trì vậy.\nNhư vậy, không chứa khổ,\nÐược gọi, gần Niết-bàn.`, ref: "Trưởng Lão Tăng Kệ 16.5", url: "https://loicuaducphat.org/thag/thag16.5.html#content" },

{ text: `Trưởng Lão Bhaddiya Kaligodhayaputta\n\n842. Khi ta ngồi cổ voi,\nMang đồ mặc tế nhị,\nĂn gạo thật ngon thơm,\nVới món thịt khéo nấu.\n\n843. Nay hiền thiện, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n844. Áo lượm rác, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n845. Thường khất thực, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n846. Mặc ba y, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n847. Ði từng nhà, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n848. Ăn một bữa kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n849. Ăn trong bát, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n850. Không ăn thêm, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n851. Sống trong rừng, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n852. Ngồi gốc cây, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n853. Sống ngoài trời, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n854. Trú nghĩa địa, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n855. Tùy xứ trú, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n856. Sống thường ngồi, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.`, ref: "Trưởng Lão Tăng Kệ 16.7", url: "https://loicuaducphat.org/thag/thag16.7.html#content" },

{ text: `Trưởng Lão Bhaddiya Kaligodhayaputta\n\n857. Ham muốn ít, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n858. Sống biết đủ, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n859. Hạnh viễn ly, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n860. Không giao du, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n861. Sống tinh cần, kiên trì,\nVui đồ ăn đặt bát,\nThiền tư, không chấp trước,\nLà con của Gô-dha.\n\n862. Từ bỏ bát quý giá,\nBằng vàng, bằng nhựa quý,\nTa lấy bát bằng đất,\nÐây quán đảnh thứ hai.\n\n863. Vòng thành cao bảo vệ,\nVọng lâu, cửa kiên cố,\nVới lính tay cầm gươm,\nTa đã sống sợ hãi.\n\n864. Nay hiền thiện, không sợ,\nBỏ run sợ kinh hãi,\nThiền tư, vào rừng sâu,\nLà con của Gô-dha.\n\n865. An trú trên giới uẩn,\nChánh niệm, tu tuệ quán,\nThứ lớp ta đạt được,\nMọi kiết sử đoạn diệt.`, ref: "Trưởng Lão Tăng Kệ 16.7", url: "https://loicuaducphat.org/thag/thag16.7.html#content" },

{ text: `Trưởng Lão Angulimala\n\n866. Này Sa-môn, Ngài đi,\nLại nói: 'Ta đứng rồi'.\nTa đứng, Ngài lại nói:\n'Sao nhà ngươi chưa đứng?'\nSa-môn, ta hỏi Ngài,\nVề ý nghĩa việc này,\nSao Ngài đã đứng lại,\nCòn ta lại còn đi.\n\n867. Angulimàlà,\nTa luôn luôn đã đứng,\nVới tất cả chúng sanh,\nTa từ bỏ gậy trượng,\nCòn ông đối hữu tình,\nChưa có tự chế ngự,\nDo vậy Ta đã đứng,\nCòn Ông thời chưa đứng.\n\n868. Ðã lâu con tôn kính,\nBậc vĩ đại Tiên nhân,\nNay bậc Sa-môn này,\nÐã bước vào Ðại lâm,\nCon nay sẽ sẵn sàng,\nTừ bỏ ngàn điều ác,\nSau khi nghe kệ Ngài,\nLiên hệ đến Chánh pháp.\n\n869. Nói xong, tên tướng cướp,\nLiền quăng bỏ cây kiếm,\nQuăng bỏ cả khí giới,\nXuống vực núi thâm sâu.\nTên tướng cướp đảnh lễ,\nDưới chân bậc Thiện Thệ,\nChính ngay tại chỗ ấy,\nXin đức Phật xuất gia.\n\n870. Ðức Phật đại từ bi,\nLà bậc đại Tiên nhân,\nÐạo Sư cả nhân giới,\nCùng với cả thiên giới,\nNói lên những lời này:\nHãy đến, thiện Tỷ-kheo,\nNhư vậy, đối vị ấy,\nThành tựu Tỷ-kheo tánh.\n\n871. Ai trước sống phóng dật,\nSau sống không phóng dật,\nChói sáng thế giới này,\nNhư trăng thoát mây che.\n\n872. Ai trước làm nghiệp ác,\nNay lấy thiện chận lại,\nChói sáng thế giới này,\nNhư trăng thoát mây che.\n\n873. Ai Tỷ-kheo còn trẻ,\nChuyên tâm hành Phật dạy,\nChói sáng thế giới này,\nNhư trăng thoát mây che.\n\n874. Mong rằng kẻ thù ta\nÐược nghe lời Chánh pháp,\nMong rằng kẻ thù ta\nChuyên tâm lời Phật dạy,\nMong rằng kẻ thù ta\nThân cận với những người\nÐã đạt được an tịnh,\nSống thọ trì Chánh pháp.\n\n875. Mong rằng kẻ thù ta,\nThời thời được nghe pháp,\nThuyết giảng về nhẫn nhục,\nTán thán về nhu hòa,\nVà sở hành của họ,\nPhù hợp với Chánh pháp.\n\n876. Vị chúng sanh như vậy,\nKhông có ám hại ta,\nHay cũng không ám hại,\nMột người khác nào hết.\nNgười ấy sẽ đạt được,\nSự an tịnh tối thượng,\nSẽ bảo vệ hộ trì,\nNgười mạnh và kẻ yếu.`, ref: "Trưởng Lão Tăng Kệ 16.8", url: "https://loicuaducphat.org/thag/thag16.8.html#content" },

{ text: `Trưởng Lão Angulimala\n\n877. Người trị thủy dẫn nước,\nKẻ làm tên nắn tên,\nNgười thợ mộc uốn gỗ,\nBậc trí nhiếp tự thân.\n\n878. Có kẻ được điều phục,\nBởi gậy, móc và roi,\nVị ấy điều phục ta,\nKhông dùng gậy, dùng kiếm.\n\n879. Ta được tên Vô Hại,\nTrước có tên Làm Hại,\nNay ta tên Chân Thật,\nTa không hại một ai.\n\n880. Trước ta là tên cướp,\nLừng danh 'vòng ngón tay',\nChìm đắm dòng nước lớn,\nCho đến khi quy Phật.\n\n881. Trước tay ta lấm máu,\nLừng danh, 'vòng ngón tay',\nHãy xem, ta quy y,\nNhổ lên gốc tái sanh.\n\n882. Làm xong nhiều nghiệp vậy,\nDẫn đến sanh ác thú,\nCảm thọ nghiệp dị thục,\nThoát nợ, ta thọ thực.\n\n883. Những kẻ ngu vô trí\nÐam mê sống phóng dật,\nKẻ trí không phóng dật,\nNhư bảo vệ vật báu.\n\n884. Chớ đam mê phóng dật,\nChớ say đắm dục lạc,\nKhông phóng dật, thiền tư,\nÐạt được lạc tối thượng.\n\n885. Ðến ta điều tốt đẹp,\nKhông tốt đẹp, không đến,\nLời khuyên bảo cho ta,\nKhông có gì không tốt,\nTrong các pháp phân biệt,\nCó mặt ở trên đời,\nPháp gì tối thượng nhất,\nTa chọn, ta chứng đạt.\n\n886. Ðến ta, điều tốt đẹp,\nKhông tốt đẹp, không đến,\nLời khuyên bảo cho ta,\nKhông có gì không tốt,\nBa minh ta đạt được,\nLời Phật dạy, làm xong.\n\n887. Trong rừng, dưới gốc cây,\nHay trên núi trong hang,\nTại chỗ ấy, ta trú,\nTâm tư thật hứng khởi.\n\n888. Thật an lạc, ta nằm,\nThật an lạc, ta dậy,\nTâm tư thuần an lạc,\nLà nếp sống của ta,\nThoát khỏi cạm bẫy Ma,\nÔi, Ðạo Sư từ mẫn!\n\n889. Trước ta sanh Phạm chí,\nHai hệ, dòng họ cao,\nNay ta con Thiện Thệ,\nÐạo Sư, bậc Pháp vương.\n\n890. Ái ly, không chấp thủ,\nCăn hộ trì, chế ngự,\nÐoạn bỏ gốc tà ác,\nTa đạt lậu hoặc diệt.\n\n891. Ta hầu hạ Ðạo Sư,\nLời Phật dạy làm xong,\nGánh nặng đã đặt xuống,\nGốc sanh hữu nhổ sạch.`, ref: "Trưởng Lão Tăng Kệ 16.8", url: "https://loicuaducphat.org/thag/thag16.8.html#content" },

{ text: `Trưởng Lão Anuruddha\n\n892. Bỏ cha mẹ, bà con,\nBỏ anh em, chị em,\nBỏ năm dục trưởng dưỡng,\nA-na-luật tu thiền.\n\n893. Sống hệ lụy múa, ca,\nDạy với tiếng xập xỏa,\nSống vậy không đạt được,\nCảnh giới đạo thanh tịnh,\nVì rằng ta ưa thích,\nTrong giới vực của Ma.\n\n894. Và ta vượt tất cả,\nVui thích lời Phật dạy,\nVượt mọi loại bộc lưu,\nA-na-luật tu thiền.\n\n895. Sắc, thanh, vị, hương, xúc,\nHấp dẫn, rất thích ý,\nVượt qua tất cả chúng,\nA-na-luật tu thiền.\n\n896. Ði khất thực trở về,\nÐơn độc, vị ẩn sĩ,\nTìm vải từ đống rác,\nA-na-luật đạt được,\nKhông còn các lậu hoặc.\n\n897. Ẩn sĩ thâu, lượm lấy,\nGiặt, nhuộm, và đắp mặc,\nCác vải từ đống rác,\nSáng suốt, A-na-luật,\nKhông còn các lậu hoặc.\n\n898. Nhiều dục, không biết đủ,\nƯa giao du, tháo động,\nNhững pháp này có mặt,\nThuộc tà ác, uế nhiễm,\n\n899. Chánh niệm và ít dục,\nBiết đủ, không não loạn,\nThích viễn ly, hân hoan,\nThường tinh cần tinh tấn.\n\n900. Những pháp này có mặt,\nThuần thiện Bồ đề phần,\nVị ấy không lậu hoặc,\nBậc Ðại tiên nói vậy.\n\n901. Biết tâm tư ta vậy,\nThế gian Vô Thượng Sư,\nVới thân do ý tạo,\nThần thông đến với ta.\n\n902. Tùy theo ta nghĩ gì,\nNgài thuyết rõ tất cả,\nPhật không ưa hý luận,\nNgài thuyết không hý luận.\n\n903. Ngộ pháp ta hoan hỷ,\nTrú trong giáo pháp Ngài,\nBa minh chứng đạt được,\nLời Phật dạy làm xong.\n\n912. Ta thấy bậc Chánh giác,\nBậc Ðạo Sư vô úy,\nTín tâm khởi nơi Ngài,\nTa xuất gia không nhà.\n\n916. Trong thiền định năm chi,\nTâm an tịnh nhất tâm,\nTâm ta được khinh an,\nThiên nhãn ta thanh tịnh.\n\n917. Ta biết sanh và chết,\nChỗ đến đi hữu tình,\nÐời này và đời khác,\nTa trú thiền năm chi.\n\n918. Ta hầu hạ Ðạo Sư,\nLời Phật dạy làm xong,\nGánh nặng đã đặt xuống,\nGốc sanh hữu nhổ sạch.\n\n919. Tại làng Vê-lu-va,\nGiữa dân tộc Vajji,\nTa đi đến đoạn diệt,\nChấm dứt dòng sanh tử,\nDưới bóng của khóm trúc,\nTa sẽ nhập Niết-bàn,\nKhông còn có lậu hoặc.`, ref: "Trưởng Lão Tăng Kệ 16.9", url: "https://loicuaducphat.org/thag/thag16.9.html#content" },

{ text: `Trưởng Lão Parapariya\n\n920. Ðây là những tư tưởng\nCủa một vị Sa-môn,\nTại rừng gọi Ðại lâm,\nKhi rừng đang trổ hoa,\nNgài ngồi chỉ một mình,\nViễn ly, tâm thiền định.\n\n921. Khác thay, những uy nghi,\nCủa những vị Tỷ-kheo,\nKhi bậc Tối thượng nhân,\nBậc Thế Tôn còn sống,\nCòn nay điều được thấy,\nThật sai khác đi nhiều.\n\n922. Y để ngăn gió lạnh,\nÐể che điều xấu hổ,\nHọ thọ dụng tiết độ.\nBiết đủ, từ đâu đến.\n\n923. Vị ngon hay vị dở\nÐược ít hay được nhiều,\nHọ thọ dụng món ăn,\nChỉ cần nuôi mạng sống,\nTâm không có tham lam,\nCũng không có say đắm.\n\n924. Các đồ vật để sống,\nHay các loại dược phẩm,\nHọ không quá tha thiết\nNhư đối lậu hoặc diệt.\n\n925. Dưới gốc cây trong rừng,\nHay trong hang trong động,\nChuyên tâm tu viễn ly,\nSống lấy vậy cứu cánh.\n\n926. Sống khiêm tốn giản dị,\nNhu hòa, ý kham nhậm,\nVới cử chỉ tao nhã,\nKhông nói năng quàng xiên,\nTâm tư hướng lợi ích\nCho mình và cho người.\n\n927. Do vậy sở hành họ,\nThật dễ thương tốt lành,\nKhi họ đi, họ ăn,\nKhi họ thọ dụng gì,\nCử chỉ uy nghi họ,\nNhư dòng dầu trơn mướt.\n\n928. Mọi lậu hoặc đoạn tận,\nÐại thiền, đại thiện lợi,\nNay những Trưởng lão ấy,\nÐã hoàn toàn Niết-bàn,\nNgày nay thật ít vị,\nGiống như các vị ấy.`, ref: "Trưởng Lão Tăng Kệ 16.10", url: "https://loicuaducphat.org/thag/thag16.10.html#content" },

{ text: `930. Các pháp thuộc tà ác,\nThời đại bị uế nhiễm,\nÐối với họ những vị,\nAn trú trong viễn ly,\nHy vọng được chứng ngộ.\nCác diệu pháp còn lại.\n\n931. Uế nhiễm họ tăng trưởng,\nảnh hưởng xấu nhiều người,\nHọ hình như chơi giỡn,\nVới những kẻ ngu si,\nNhư bọn quỷ La-sát,\nÐùa giỡn với kẻ điên.\n\n932. Bị uế nhiễm chinh phục,\nChạy theo nhiễm này nọ,\nÐối với vật uế nhiễm,\nHọ như người la to,\nNhững đồ vật lấy được.\n\n933. Từ bỏ chân diệu pháp,\nHọ cãi lộn với nhau,\nHọ chạy theo tà kiến,\nHọ nghĩ: 'Ðây tốt hơn'.\n\n934. Từ bỏ, xoay lưng lại,\nTài sản, con và vợ,\nDo nhân muổng đồ xin,\nHọ làm việc không xứng.\n\n935. Họ ăn đến đầy bụng,\nHọ nằm phơi ra ngủ,\nSau khi thức, họ nói,\nÐiều bậc Ðạo Sư trách.\n\n936. Mọi mỹ nghệ thủ công,\nHọ tôn trọng học tập,\nNội tâm không an tịnh,\nBỏ mặc hạnh Sa-môn.\n\n937. Ðất, dầu, các loại bột,\nNước, chỗ ngồi, cơm ăn,\nHọ tặng cho cư sĩ,\nHy vọng được nhiều hơn.\n\n938. Cây tăm để xỉa răng,\nLoại trái Ka-pit-tha\nLá hoa để nhai ăn,\nÐồ khất thực đầy đủ,\nCùng các loại trái xoài,\nVà trái A-ma-lặc.\n\n939. Với các loại dược phẩm,\nHọ giống như thầy thuốc,\nHọ làm các công việc,\nChẳng khác người thế tục,\nHọ trang sức y phục,\nGiống như các kỹ nữ.\nHọ tự tỏ quyền uy,\nChẳng khác người hoàng tộc.\n\n940. Giả dối và lừa đảo,\nNgụy chứng và man trá,\nVới rất nhiều thủ đoạn,\nÐể thọ hưởng tài vật.\n\n941. Sử dụng cách lường gạt,\nChạy theo những mưu chước,\nDùng phương tiện sinh sống,\nKéo về nhiều tài sản.\n\n942. Họ quy tụ hội chúng,\nVì nghề, không vì pháp,\nHọ thuyết pháp quần chúng,\nVì lợi , không vì nghĩa.\n\n943. Những người ngoài Tăng đoàn,\nLại tranh luận cãi nhau,\nVề quyền lợi Tăng đoàn,\nKhông tàm quý liêm sỉ,\nHọ tự mình nuôi sống,\nVới quyền lợi kẻ khác.\n\n944. Một số thiếu tín thành,\nDầu đầu trọc đắp y,\nMong muốn được kính trọng,\nHam quyền lợi danh vọng.\n\n945. Như vậy, như hiện nay,\nNhiều việc đã đọa lạc,\nThật không còn dễ dàng,\nNhư thời lúc trước nữa,\nHoặc cảm xúc chứng đắc,\nÐiều chưa được xúc chứng,\nHoặc gìn giữ duy trì,\nÐiều đã được xúc chứng.\n\n946. Như người không mang giày,\nÐi trên chỗ có gai,\nLuôn luôn giữ chánh niệm,\nCũng vậy vị ẩn sĩ,\nKhi đi vào trong làng,\nCần gìn giữ chánh niệm.\n\n947. Nhớ vị tu đời trước,\nNhớ nếp sống của họ,\nDầu nay thời hậu lai,\nVẫn có thể xúc chứng,\nCon đường đạo bất tử.\n\n948. Như vậy vị Sa-môn,\nTrong rừng cây Sàla,\nCác căn có tu tập,\nNói lên lời như vậy,\nPhạm chí nhập Niết-bàn,\nẨn sĩ đoạn tái sanh.`, ref: "Trưởng Lão Tăng Kệ 16.10", url: "https://loicuaducphat.org/thag/thag16.10.html#content" },

{ text: `Trưởng Lão Phussa\n\n949. Ẩn sĩ Pan-đa-ra,\nThấy nhiều vị thành tín,\nTự ngã có tu tập,\nKhéo hộ trì chế ngự\nNgài mới đặt câu hỏi,\nVới vị tên Phussa.\n\n950. Trong thời gian tương lai,\nSẽ có ước muốn gì?\nSẽ có chí nguyện gì?\nSẽ có cử chỉ gì?\nMong ngài hãy trả lời,\nCâu hỏi của chúng tôi.\n\n951. Ẩn sĩ Pan-đa-ra,\nHãy nghe lời ta nói,\nHãy thọ trì cẩn thận,\nTa sẽ nói tương lai.\n\n952. Phẫn nộ và hiềm hận,\nChe đậy và cứng đầu,\nNhiều lừa đảo ganh tị,\nTương lai nhiều loại vậy,\n\n953. Họ tự cho có trí,\nPháp sâu, chỉ đến bờ,\nHọ khinh nhờn Chánh pháp,\nHọ không kính trọng nhau.\n\n954. Nhiều nguy hiểm ở đời,\nSẽ xảy ra tương lai,\nPháp được khéo giảng này,\nKẻ ngu làm uế nhiễm.\n\n955. Trong Tăng chúng, những vị,\nCó đức hạnh hạ liệt,\nHọ thường hay tuyên bố,\nCó tự tín, không sợ,\nKẻ không học, lắm lời,\nSẽ đứng vào thế mạnh.\n\n956. Trong Tăng chúng, những vị,\nCó giới hạnh tốt đẹp,\nKhi họ có tuyên bố,\nTuyên bố đúng sự thật,\nHọ thường ở thể yếu,\nHổ thẹn thiếu nhiệt thành.\n\n957. Bạc, vàng và đồng ruộng,,\nÐất đai, dê và cừu,\nNô tỳ nữ và trai,\nKẻ ngu si vô trí,\nSẽ thâu nhận tất cả,\nTrong tương lai là vậy.\n\n958. Kẻ ngu dễ nóng giận,\nKhông định tĩnh trong giới,\nKiêu ngạo, đi đó đây,\nNhư thú ưa đánh nhau.\n\n959. Họ trở thành tháo động,\nThường đắp y màu xanh,\nLừa đảo và ngoan cố,\nLắm mồm, ăn nói giả,\nHọ bắt chước giả bộ,\nNhư bậc Thánh thời xưa.\n\n960. Với tóc bôi dầu láng,\nDao động, mắt vẽ xanh,\nÐắp y màu trắng ngà,\nHọ qua lại trên đường.\n\n961. Y vàng được khéo nhuộm,\nLá cờ bậc La-hán,\nÐược các bậc giải thoát,\nÐắp mang không nhàm chán,\nCòn họ chán y vàng,\nÁi luyến đắp màu trắng.\n\n962. Họ trở thành tham lợi,\nBiếng nhác, ít tinh cần,\nKhó sống rừng hoang vu,\nThích sống gần xóm làng.\n\n963. Những ai sợ được lợi,\nLuôn luôn ưa tà mạng,\nHọ học đòi người ấy,\nThân cận, không tự chế.\n\n964. Những ai không được lợi,\nHọ không trọng không kính,\nBậc khả kính, Hiền trí,\nHọ không có thân cận.\n\n965. Khinh cờ hiệu của mình,\nƯa thích màu ngoại sắc,\nCó kẻ mang y trắng,\nLá cờ hiệu ngoại đạo.\n\n966. Không kính y màu vàng,\nThời ấy họ là vậy,\nChờ đợi màu y vàng,\nKhông phải của Tỷ-kheo.\n\n967. Bị đau khổ chinh phục,\nBị quặn đau tên đâm,\nChờ đợi đại khủng bố.\nVoi ta không nghĩ nghì.\n\n968. Khi bậc sáu ngà thấy,\nCờ La-hán khéo nhuộm,\nVoi nói lên những kệ,\nLiên hệ đến mục đích.\n\n969. Ai sẽ mặc cà-sa,\nTâm chưa rời uế trược,\nKhông tự chế, không thực,\nKhông xứng áo cà-sa.\n\n970. Ai rời bỏ uế trược,\nKhéo định trong giới luật,\nTự nhiếp phục chơn thực,\nThật xứng áo cà-sa.\n\n971. Phá giới, trí hạ liệt,\nKhông tự chế, tham dục,\nTâm loạn, thiếu phấn chấn,\nKhông xứng áo cà-sa.\n\n972. Ai đầy đủ giới hạnh,\nLy tham, có định tĩnh,\nTâm tư thật trinh bạch,\nVị ấy xứng áo cà-sa.\n\n973. Ai kiêu ngạo phóng đãng,\nNgu si, không giới hạnh,\nXứng đáng mặc áo trắng,\nLàm gì có cà-sa.\n\n974. Tỷ-kheo, Tỷ-kheo ni,\nTâm uế, không tin kính,\nTương lai sẽ ức hiếp,\nÐối vị có tâm từ.\n\n975. Kẻ ngu mang y áo,\nDầu được Trưởng lão dạy,\nLiệt trí sẽ không nghe,\nKhông tự chế, tham dục.\n\n976. Kẻ ngu dầu dạy vậy,\nKhông có kính trọng nhau,\nSẽ không có vâng lời,\nLời dạy giáo thọ sư,\nGiống như ngựa bất kham,\nÐối với người đánh xe.\n\n977. Như vậy, thời tương lai,\nHành tung sẽ là vậy.\nTỷ-kheo, Tỷ-kheo ni,\nKhi thời tối hậu đến,\nHãy ôn hòa thân ái,\nHãy cung kính lẫn nhau.\n\n978. Ðại nạn ấy chưa đến,\nTrước khi đại nạn đến,\nHãy ôn hòa thân ái,\nHãy cung kính lẫn nhau.\n\n979. Hãy có tâm từ bi,\nKhéo chế ngự trong giới,\nChuyên tinh tấn nỗ lực,\nThường kiên trì phấn chấn.\n\n980. Thấy nguy hiểm phóng dật,\nKhông phóng dật an ổn,\nHãy tu Tám Thánh đạo,\nGiác chứng đạo bất tử.`, ref: "Trưởng Lão Tăng Kệ 17.1", url: "https://loicuaducphat.org/thag/thag17.1.html#content" },

{ text: `Trưởng Lão Sariputta\n\n981. Ai tùy theo năng lực,\nCó giới, tịnh, chánh niệm\nKhông phóng dật hành trì,\nSở hành đúng tư duy,\nThích hướng nội, khéo định,\nÐơn độc, biết tri túc,\nVới sở hành như vậy,\nVị ấy gọi Tỷ-kheo.\n\n982. Ăn đồ ướt hay khô,\nKhông ăn quá thỏa mãn,\nBụng trống, ăn tiết độ,\nTỷ-kheo trú chánh niệm.\n\n983. Ăn bốn, năm miếng xong,\nRồi hãy uống nước uống,\nThật đủ trú thoải mái,\nVới Tỷ-kheo tinh cần.\n\n984. Nhận lấy đồ hợp pháp,\nY áo đáp nhu cầu,\nThật đủ trú thoải mái,\nVới Tỷ-kheo tinh cần.\n\n985. Khi ngồi thế kiết-già,\nÐầu gối phải mưa ướt,\nThật đủ trú thoải mái,\nVới Tỷ-kheo tinh cần.`, ref: "Trưởng Lão Tăng Kệ 17.2", url: "https://loicuaducphat.org/thag/thag17.2.html#content" },

{ text: `Trưởng Lão Sariputta\n\n986. Ai xem lạc là khổ,\nAi xem khổ như tên,\nÐứng chặng giữa cả hai,\nDo đâu, đời nắm được?\n\n987. Không cho ta ác dục,\nBiếng nhác tinh cần kém,\nÍt nghe, không tín kính,\nDo đâu, đời nắm được?\n\n988. Nghe nhiều, có hiền trí,\nKhéo định tĩnh trong giới,\nChuyên chú an chỉ tâm,\nHãy đứng lên trên đầu.\n\n989. Ai chuyên tâm hý luận,\nNhư thú ưa hý luận,\nRơi khỏi, trật Niết-bàn,\nVô thượng, thoát khổ ách.\n\n990. Ai từ bỏ hý luận,\nThích đạo phi hý luận,\nÐi đến được Niết-bàn,\nVô thượng, thoát khổ ách.`, ref: "Trưởng Lão Tăng Kệ 17.2", url: "https://loicuaducphat.org/thag/thag17.2.html#content" },

{ text: `Trưởng Lão Sariputta\n\n991. Tại làng hay trong rừng,\nThung lũng hay đồi cao,\nChỗ nào La-hán trú,\nÐất ấy thật khả ái.\n\n992. Khả ái thay núi rừng,\nChỗ người phàm không ưa,\nVị ly tham sẽ thích,\nVì không tìm dục lạc.`, ref: "Trưởng Lão Tăng Kệ 17.2", url: "https://loicuaducphat.org/thag/thag17.2.html#content" },

{ text: `Trưởng Lão Sariputta\n\n993. Như người chỉ của chôn,\nCũng vậy, người thấy lỗi,\nNói điều người trí trách,\nHãy gần người trí vậy.\nThân cận người như vậy,\nChỉ tốt hơn, không xấu.\n\n994. Cần phải khuyên, phải dạy,\nPhải ngăn chặn bất thiện,\nLàm vậy, người thiện thương,\nNgười bất thiện không ưa.\n\n995. Thế Tôn, bậc có mắt,\nThuyết pháp cho người khác,\nKhi pháp được thuyết giảng,\nTa lắng tai nhiệt tình.\nTa nghe, không uổng phí,\nGiải thoát không lậu hoặc,\n\n996. Không cần biết đời trước,\nKhông cần được thiên nhãn.\nTa không có phát nguyện,\nChứng được tha tâm thông,\nBiết chúng sanh sống chết,\nHay nhĩ giới thanh tịnh.`, ref: "Trưởng Lão Tăng Kệ 17.2", url: "https://loicuaducphat.org/thag/thag17.2.html#content" },

{ text: `Trưởng Lão Sariputta\n\n997. Ngồi dưới một gốc cây,\nÐầu trọc, đắp đại y,\nTrưởng lão tuệ đệ nhất,\nU-pa-ti-sa tu thiền.\n\n998. Ðầy đủ thiền vô tầm\nÐệ tử bậc Chánh giác,\nVới im lặng bậc Thánh,\nNgay lúc ấy, đạt được\n\n999. Giống như ngọn núi đá,\nKhông động, khéo vững trú,\nCũng vậy, vị Tỷ-kheo,\nÐã đoạn diệt si ám,\nVị ấy như ngọn núi,\nKhông có bị dao động.\n\n1000. Người không có uế nhiễm,\nLuôn tầm cầu thanh tịnh,\nÁc nhẹ như đầu lông,\nXem nặng như mây trời.\n\n1001. Ta không hoan hỷ chết,\nTa không hoan hỷ sống,\nTa sẽ bỏ thân này,\nTỉnh giác và chánh niệm.\n\n1002. Ta không hoan hỷ chết,\nTa không hoan hỷ sống,\nTa sẽ bỏ thân này,\nNhư thợ làm việc xong.`, ref: "Trưởng Lão Tăng Kệ 17.2", url: "https://loicuaducphat.org/thag/thag17.2.html#content" },

{ text: `Trưởng Lão Sariputta\n\n1003. Cả hai chết, không chết,\nSau đời hay trước đời,\nHãy dấn thân tiến bước,\nChớ để hư, uổng phí,\nDầu một khắc, sát-na,\nChớ để uổng phí qua.\n\n1004. Như ngôi thành biên địa,\nÐược bảo vệ trong ngoài,\nNhư vậy, hộ tự ngã,\nChớ để phí sát-na,\nSát-na qua, sầu muộn,\nChịu khổ trong địa ngục.`, ref: "Trưởng Lão Tăng Kệ 17.2", url: "https://loicuaducphat.org/thag/thag17.2.html#content" },

{ text: `Trưởng Lão Sariputta\n\n1005. Ðạt tịch tịnh, chỉ tức,\nÐọc chú, không cống cao,\nQuét sạch các ác pháp,\nNhư gió quét lá cây.\n\n1006. Ðạt tịch tịnh, chỉ tức,\nÐọc chú, không cống cao,\nGạt ngoài các ác pháp,\nNhư gió quét lá cây.\n\n1007. Ðạt tịch tịnh an lặng,\nÝ trong sáng không nhiễm,\nBậc trì giới trọn lành,\nCó thể dứt đau khổ.\n\n1008. Có người không ai tin,\nTại gia hay xuất gia,\nNhững ai trước là tốt,\nVề sau trở thành xấu,\nHoặc trước là người xấu.\nSau trở thành người tốt.\n\n1009. Hạng Tỷ-kheo tham dục,\nSống hôn trầm thụy miên,\nTrạo cử và nghi ngờ,\nTâm đủ năm phiền não.\n\n1010. Với ai, đối cả hai,\nÐược trọng, không được trọng,\nThiền định, không dao động,\nAn trú không phóng dật.\n\n1011. Thiền tư luôn kiên trì,\nTuệ quán, kiến tế nhị,\nƯa thích chấp thủ diệt,\nVị ấy gọi chân nhân.\n\n1012. Biển lớn và đất lớn,\nNúi và các phương trời,\nKhông ví dụ sánh được,\nPhật, giải thoát thù thắng.\n\n1013. Trưởng lão chuyển pháp luân,\nBậc đại trí, thiền định,\nNhư đất, nước và lửa,\nKhông tham không ghét bỏ.\n\n1014. Ðạt được tuệ tối thắng,\nÐại giác, đại Mâu-ni,\nKhông chậm, tỏ chậm chạp\nThường sống thật thanh lương.\n\n1015. Ta hầu hạ Bổn Sư,\nLời Phật dạy làm xong,\nGánh nặng đã đặt xuống,\nGốc sanh hữu nhổ sạch.\n\n1016. Tinh cần, chớ phóng dật,\nÐây lời giáo huấn ta!\nTa sẽ nhập Niết-bàn,\nTa thoát mọi sanh y.`, ref: "Trưởng Lão Tăng Kệ 17.2", url: "https://loicuaducphat.org/thag/thag17.2.html#content" },

{ text: `Trưởng Lão Ananda\n\n1017. Hai lưỡi và phẫn nộ,\nXan tham, thích phá hoại,\nBậc trí không giao du,\nKẻ ác bạn kẻ xấu.\n\n1018. Với bậc tin, dễ thương,\nVới bậc trí, nghe nhiều,\nBậc Hiền trí, giao du,\nKẻ thiện bạn chân nhân.`, ref: "Trưởng Lão Tăng Kệ 17.3", url: "https://loicuaducphat.org/thag/thag17.3.html#content" },

{ text: `Trưởng Lão Ananda\n\n1030. Hãy kính người nghe nhiều,\nChớ hại điều sở học,\nÐấy cội gốc Phạm hạnh,\nDo vậy, hãy trì pháp.\n\n1031. Biết câu trước câu sau,\nBiết nghĩa, giỏi từ cú,\nNắm giữ điều khéo nắm,\nSuy tìm trên nghĩa lý.\n\n1032. Chính nhờ đức kham nhẫn,\nSở nguyện được tác thành,\nSau khi đã tinh tấn,\nVị ấy lại cân nhắc,\nÐúng thời, ra nỗ lực,\nNội tâm khéo định tĩnh.\n\n1033. Nghe nhiều, thọ trì pháp\nCó tuệ, đệ tử Phật,\nChờ đợi thức tri pháp,\nNên thân cận vị ấy.\n\n1034. Nghe nhiều thọ trì pháp,\nHộ tạng Ðại ẩn sĩ,\nCặp mắt, toàn thế giới,\nHãy lễ vị nghe nhiều.\n\n1035. Ưa pháp, vui thích pháp,\nLuôn suy tư Chánh pháp,\nTỷ-kheo nhớ niệm pháp,\nDiệu pháp không tổn giảm.`, ref: "Trưởng Lão Tăng Kệ 17.3", url: "https://loicuaducphat.org/thag/thag17.3.html#content" },

{ text: `1036. Thân ích kỷ nặng chăng,\nKhông có ưa hoạt động,\nThời gian mòn mỏi qua,\nKhông thể đứng dậy sao?\nTham đắm theo thân lạc,\nTừ đâu, Sa-môn lạc?\n\n1037. Mọi phương đều mờ mịt,\nPháp không khỏi nơi ta,\nNgười bạn tốt đã đi,\nTối tăm lan tràn khắp.\n\n1038. Người bạn đã đi qua,\nÐạo Sư đã đi qua,\nBạn như vậy không còn,\nNhư quán thân hành niệm.\n\n1039. Các vị xưa đã qua,\nVị mới ta không hạp,\nNay một mình ta thiền,\nNhư chim, khi mưa đến.`, ref: "Trưởng Lão Tăng Kệ 17.3", url: "https://loicuaducphat.org/thag/thag17.3.html#content" },

{ text: `Trưởng Lão Maha-Kassapa\n\n1054. Chớ du hành đi đầu,\nDo quần chúng tôn xưng,\nTâm ý bị loạn động\nThiền định khó tu chứng,\nQuần chúng tụ là khổ,\nThấy vậy, tránh quần chúng.\n\n1055. Bậc ẩn sĩ không đi,\nÐi đến các gia đình,\nTâm ý bị loạn động,\nThiền định khó tu chứng,\nAi hăng say tham vị,\nBỏ đích đem an lạc.\n\n1056. Ðảnh lễ cúng dường này,\nXuất phát từ gia đình\nNên biết họ thực sự,\nLà đám bùn sa lầy.\nNhư mũi tên tế nhị\nRất khó rút ra khỏi,\nKẻ xấu rất khó lòng.\nTừ bỏ sự cung kính.`, ref: "Trưởng Lão Tăng Kệ 18.1", url: "https://loicuaducphat.org/thag/thag18.1.html#content" },

{ text: `Trưởng Lão Maha-Kassapa\n\n1062. Ði khất thực trở về\nCa-diếp leo tảng đá,\nNgồi thiền, không chấp thủ,\nÐoạn sợ hãi kinh hoàng.\n\n1063. Ði khất thực trở về,\nCa-diếp leo tảng đá,\nNgồi thiền, không chấp thủ,\nÐã đốt cháy, thanh lương.\n\n1064. Ði khất thực trở về\nCa-diếp leo tảng đá\nNgồi thiền, không chấp thủ,\nXong việc, không lậu hoặc.\n\n1069. Vừa đủ ta chánh niệm,\nHăng hái muốn tu thiền,\nVừa đủ ta Tỷ-kheo\nHăng hái muốn phước lợi.\n\n1070. Vừa đủ ta Tỷ-kheo,\nHăng hái muốn an lạc,\nVừa đủ ta Tỷ-kheo,\nHăng hái tu Du-già.`, ref: "Trưởng Lão Tăng Kệ 18.1", url: "https://loicuaducphat.org/thag/thag18.1.html#content" },

{ text: `Trưởng Lão Maha-Kassapa\n\n1065. Khu đất thật khả ái,\nVới những vòng tràng hoa,\nHoa tên Ka-rê-ri,\nTrải rộng ra cùng khắp,\nVới voi rú khả ý,\nÐồi núi ấy ta thích\n\n1066. Những hồ nước trong mát,\nTuyệt đẹp, màu mây xanh,\nChe kín bởi loài bọ,\nTên 'kẻ chăn In-đa'\nNhững ngọn núi đá ấy,\nLàm tâm ta thích thú.\n\n1067. Giống đồi mây xanh biếc,\nVí tháp đẹp lâu đài,\nVới vượn hú khả ý,\nÐồi núi ấy, ta thích.\n\n1068. Ðất bằng thật khả ái,\nÐược mưa ướt thấm nhuần,\nÐồi núi được ẩn sĩ,\nLàm thành nơi trú xứ.\nVang lên tiếng chim công,\nÐồi núi ấy ta thích.\n\n1071. Tràn đầy hoa cây gai,\nNhư trời phủ làn mây,\nÐầy mọi loài chim chóc,\nÐồi núi ấy ta thích.\n\n1072. Không đông chúng gia chủ\nChỗ trú xứ đoàn thú,\nÐầy mọi loài chim chóc,\nÐồi núi ấy ta thích.\n\n1073. Dưới tảng đá, băng đá,\nCó nước suối trong chảy,\nCó khỉ và có nai,\nLai vãng sống gần bên,\nCỏ cây bao trùm nước,\nÐồi núi ấy ta thích.\n\n1074. Người vậy không ưa thích,\nCả năm loại nhạc khí,\nKhi đã được nhất tâm,\nChơn chánh thiền quán pháp.`, ref: "Trưởng Lão Tăng Kệ 18.1", url: "https://loicuaducphat.org/thag/thag18.1.html#content" },

{ text: `1075. Chớ làm quá nhiều việc,\nTránh quần chúng đua tranh,\nNgười siêng tham đắm vị,\nBỏ đích đem an lạc.\n\n1076. Chớ làm nhiều công việc,\nTránh việc không lợi này,\nThân cực nhọc mệt mỏi,\nNgười khổ không an chỉ.\n\n1077. Chỉ lắp bắp cái môi,\nKhông thấy được tự ngã,\nCổ cứng đờ nó đi,\nNó nghĩ: ta tốt hơn.\n\n1078. Không hơn nghĩ tốt hơn,\nKẻ ngu nghĩ tự ngã,\nBậc trí không tán thán,\nNgười có trí cứng đờ.\n\n1079. Ta tốt hơn, hay là\nTa không được tốt hơn,\nHay ta là dở hơn,\nTa cũng tốt như vậy,\nAi không có dao động\nTrong các loại mạn này.\n\n1080. Có tuệ, nói như thật,\nKhéo định tĩnh trong giới,\nÐạt được tâm an chỉ,\nNgười ấy kẻ trí khen.\n\n1081. Ai giữa đồng Phạm hạnh\nKhông được có kính trọng,\nVị ấy xa diệu pháp,\nNhư đất xa bầu trời.\n\n1082. Những ai có tàm quý,\nThường chơn chánh an trú,\nPhạm hạnh được tăng trưởng,\nHọ đoạn được tái sanh.\n\n1083. Tỷ-kheo cống cao động\nDầu đắp y đống rác,\nNhư con khỉ đội lốt,\nVới da con sư tử,\nNgười vậy không có thể,\nChói sáng nhờ y ấy.\n\n1084. Không cống cao, không động,\nThận trọng, căn chế ngự,\nChói sáng với tấm y\nÐược lượm từ đống rác,\nChẳng khác con sư tử,\nTrong hang động núi rừng.\n\n1092. Không nhiễm dính y phục\nChỗ nằm và đồ ăn,\nKhông thể trắc lường được\nLà con bậc Gotama!\nNhư hoa sen trong sạch,\nKhông thể dính nước vào,\nÝ thiên về xuất ly,\nThoát ly cả ba giới.\n\n1093. Với bậc Ðại ẩn sĩ,\nCổ dựng trên niệm xứ,\nTay dựa trên đức tin,\nVới đầu là Trí tuệ\nBậc Ðại trí luôn luôn,\nHành trì thật thanh lương.`, ref: "Trưởng Lão Tăng Kệ 18.1", url: "https://loicuaducphat.org/thag/thag18.1.html#content" },

{ text: `Trưởng Lão Talaputta\n\n1094. Khi nào ta sẽ đến,\nMột mình, không có hai,\nỞ trong những hang động,\nCủa các loại núi rừng,\nTa quán mọi sanh hữu,\nTất cả là vô thường,\nNay ta là như vậy,\nKhi nào ta sẽ vậy?\n\n1095. Khi nào ta sẽ là,\nẩn sĩ mang y vá,\nMang y vải màu vàng,\nKhông của ta, không ái,\nÐoạn trừ, diệt tham tâm,\nÐoạn luôn cả sân, si,\nTa đi đến khu rừng,\nSẽ trú trong an lạc.\n\n1096. Khi nào ta thấy được\nThận này là vô thường,\nBị chết già áp bức,\nỔ giết chóc, bệnh tật\nTa sẽ trú trong rừng,\nMột mình, quán vô úy\nKhi nào sẽ là vậy?\n\n1097. Khi nào ta sẽ lấy\nGươm sắc bén trí tuệ,\nChặt dây leo khát ái,\nVới nhiều dây chằng chịt,\nSanh khởi lên sợ hãi,\nMang đến sự khổ đau.\nKhi nào sẽ là vậy?\n\n1098. Khi nào ta sẽ là,\nCó sức mạnh rút gươm,\nGươm do tuệ tạo thành,\nLà lửa sáng ẩn sĩ;\nVới sức mạnh đập tan\nÁc ma với Ma quân\nTrên chỗ ngồi sư tử,\nKhi nào sẽ là vậy?\n\n1099. Khi nào ta sẽ được\nHội tụ với bậc thiện,\nÐược thấy giữa các vị,\nÐảm nhận các trọng pháp,\nTinh cần với các vị,\nThấy sự vật như thật,\nChiến thắng được các căn\nKhi nào sẽ là vậy?`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `1100. Khi nào nhác đói khát\nGió, nóng, trùng bò sát,\nSẽ không não hại ta,\nỞ Gi-ri-bhaje,\nÐang lo đến tự ngã,\nKhi nào sẽ là vậy?\n\n1101. Khi nào ta có thể\nChánh niệm, đã định tĩnh\nHiểu được với trí tuệ,\nBốn sự thật khéo giảng,\nBởi bậc Ðại ẩn sĩ,\nKhi nào sẽ là vậy?\n\n1102. Khi nào ta sẽ chuyên\nChú tâm vào an chỉ,\nThấy được với trí tuệ,\nSắc, thanh, hương, vị, xúc,\nCác pháp vô thường này,\nNhư lửa cháy hừng đỏ,\nKhi nào ta sẽ vậy?\n\n1103. Khi nào ta bị nói,\nVới lời nói thô ác,\nKhông vì lý do ấy,\nTâm trí bị thất vọng.\nKhi được lời tán thán,\nKhông vì lý do ấy,\nTâm tư được thỏa mãn.\nKhi nào ta sẽ vậy?\n\n1104. Khi nào nhiều như củi,\nCỏ, cây leo, thân cây,\nTa cân nhắc bình đẳng,\nNhững pháp vô lượng này,\nNội pháp và ngoại pháp,\nKhi nào ta sẽ vậy?`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `1105. Khi nào mây đem mưa,\nVới nước mới trong rừng,\nLàm ướt y áo ta,\nTa đi trên đường ướt,\nCon đường ẩn sĩ đi.\nKhi nào sẽ là vậy?\n\n1106. Khi nào nghe trong rừng,\nTiếng kêu của loài chim,\nChim công, có mào đầu.\nTrong hang động núi rừng,\nTa an trú suy tư,\nÐể đạt quả bất tử,\nKhi nào ta sẽ vậy?\n\n1107. Khi nào với thần thông,\nTa có thể vượt qua,\nKhông chìm, không sợ hãi,\nSông Hằng, Yamunà,\nSông Sarasvati,\nVới cửa sông hãi hùng,\nVới nước ào vực sâu,\nKhi nào sẽ là vậy?\n\n1108. Khi nào, như con voi,\nTrên chiến trường tấn công,\nTa sẽ phá tan tành,\nLòng dục đối dục cảnh,\nChuyên chú trong thiền định,\nTừ bỏ mọi tịnh tướng,\nKhi nào sẽ là vậy?\n\n1109. Khi nào như người nghèo\nMắc nợ chưa trả được,\nBị kẻ giàu thúc bách,\nTìm ra được của chôn,\nTa sẽ được thoải mái,\nHọ được lời giảng dạy,\nCủa vị Ðại ẩn sĩ,\nKhi nào sẽ được vậy?`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `1110. Nhiều năm ta được ngươi,\nYêu cầu làm như sau:\nNhư vậy là vừa rồi,\nNgươi sống đời gia đình,\nNay ta đã xuất gia,\nDo vậy, hỡi này tâm,\nDo vì lý do gì,\nNgươi không có chuyên tâm?\n\n1111. Này tâm, phải chăng ngươi,\nYêu cầu ta như sau:\nTại Giribbaje\nLoài chim có lông sáng,\nÐón chào với tiếng kêu,\nSấm của Ðại In-da.\nHãy làm vị ấy vui,\nÐang tu thiền trong rừng.\n\n1112. Trong gia đình, bạn bè,\nNgười yêu và bà con,\nCác du hí ở đời,\nCác đối tượng của dục,\nTất cả đều từ bỏ,\nTa chấp nhận thế này.\nHỡi này tâm, ngươi không\nBằng lòng với ta chăng?\n\n1113. Việc này chỉ vì ta,\nÐây không vì người khác,\nKhi đến thời vũ trang,\nSao lại còn than khóc?\nThế giới này toàn động,\nChờ đợi là như vậy.\nNên ta đã ra đi,\nTìm cầu đạo bất tử.\n\n1114. Vị nói điều khó nói,\nTối thượng loài hai chân,\nBậc Y vương vĩ đại,\nÐánh xe điều ngự người,\nVới tâm không tham dục,\nNgài khéo chế ngự được,\nNgười khó lòng chế ngự,\nChế ngự được tâm người,\nVọng động như con vượn.\n\n1115. Trong khu rừng vang lên,\nTiếng chim công, chim cò,\nChỗ trú xứ ưu tiên,\nCủa loài beo, loài cọp,\nNgươi sống tại chỗ ấy,\nChớ chờ đợi về thân,\nChớ có quá đam mê,\nNày tâm, hãy khích lệ,\nHãy khuyên ta như trước,\n\n1116. Các dục có nhiều vẻ.\nDịu ngọt, rất khả ý,\nỞ đây, hàng phàm phu,\nVô trí, bị trói buộc.\nHọ muốn chịu đau khổ,\nKhi họ tìm tái sanh,\nDắt dẫn bởi tâm họ,\nHọ chết trong địa ngục.`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `1117. Hãy tu thiền, căn, lực\nHãy tu định giác chi,\nHãy giác chứng ba minh,\nTrong lời dạy đức Phật,\nNày tâm, hãy khích lệ,\nHãy khuyên ta như trước.\n\n1118. Hãy tu tập con đường\nÐể đạt được bất tử,\nÐường đưa đến thể nhập,\nChỗ đoạn diệt mọi khổ.\nCon đường có tám ngành,\nRửa sạch mọi uế nhiễm.\nNày tâm, hãy khích lệ,\nHãy khuyên ta như trước.\n\n1119. Hãy như lý quán sát,\nCác uẩn là đau khổ,\nHãy từ bỏ xa ngươi,\nNhững nguyên nhân đau khổ.\nNgay trong thời hiện tại,\nHãy chấm dứt đau khổ,\nNày tâm, hãy khích lệ,\nHãy khuyên ta như trước.\n\n1120. Hãy như lý tuệ quán,\nLà vô thường, là khổ,\nLà không, là vô ngã,\nLà tà ác, sát hại,\nHãy chế ngự tâm ngươi,\nChớ để nó chạy loạn.\nNày tâm, hãy khích lệ,\nHãy khuyên ta như trước.\n\n1121. Trọc đầu và xấu sắc,\nÐi đến bị nguyền rủa,\nKhi khất thực gia đình,\nTay cầm hình đầu lâu,\nNay ngươi có chú tâm,\nVào lời dạy Bổn Sư,\nVào lời Ðại ẩn sĩ,\nNày tâm, hãy khích lệ\nHãy khuyên ta như trước.\n\n1122. Hãy đi trên con đường,\nTự ngã khéo chế ngự,\nGiữa các nhà, tâm ý\nKhông ái luyến các dục,\nNhư trăng vào tháng tròn,\nKhông có bợn mây mù.\nNày tâm, hãy khích lệ,\nHãy khuyên ta như trước.\n\n1123. Hãy sống trong rừng núi,\nĂn đồ ăn khất thực,\nSống tại chỗ nghĩa địa,\nMặc y lượm đống rác.\nChỉ có ngồi không nằm\nLuôn vui hạnh Ðầu-đà,\nNày tâm, hãy khích lệ,\nHãy khuyên ta như trước.`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `1124. Như người đã trồng cây,\nLiền tìm cho được trái,\nNay ngươi ước muốn trái,\nHá chặt rễ cây sao?\nNày tâm, thật giống như,\nVí dụ ngươi đã làm,\nKhi ngươi khích lệ ta,\nTrong vô thường dao động.\n\n1125. Ngươi, vô sắc, cô độc,\nKẻ lữ hành từ xa,\nNay ta sẽ không làm,\nTheo lời nói của ngươi.\nCác dục là khổ đau,\nCay đắng, sợ hãi lớn,\nTâm hướng vọng Niết-bàn,\nTa sẽ bước, đi tới.\n\n1126. Ta đi tới xuất gia,\nKhông phải vì bất hạnh,\nKhông đùa vô liêm sỉ,\nKhông vì duyên tâm hứng,\nKhông bị đày đi xa,\nKhông vì nhân mạng sống,\nKhi ta đã bằng lòng,\nNày tâm, đối với ngươi.\n\n1127. Ít dục được tán dương,\nBởi những bậc chân nhân,\nKể cả đoạn giả dối,\nVà an tịnh đau khổ.\nNhư vậy, hỡi này tâm,\nKhi ngươi khích lệ ta,\nCòn nay ngươi đi ngược,\nÐiều ngươi trước quen làm.\n\n1128. Khát ái và vô minh,\nÐáng thương và đáng ghét,\nSắc đẹp và lạc thọ,\nDục trưởng dưỡng hấp dẫn,\nTất cả đã quăng bỏ,\nTa không có cố gắng,\nÐi đến một lần nữa,\nNhững đồ đã quăng bỏ.`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `1129. Này tâm, khắp mọi nơi,\nTa làm theo lời ngươi,\nTrải qua nhiều đời sống,\nNgươi không tức giận ta,\nVà thân nội sanh này,\nLà lòng ngươi biết ơn!\nTrên đường luân hồi dài,\nKhổ do chính ngươi tạo.\n\n1130. Này tâm, chính ngươi làm\nTác thành con người ta,\nChính ngươi làm, ta thành,\nThành một Bà-la-môn,\nThành vua chúa hoàng tộc,\nMột ngày là người buôn,\nNgày kia thành nô tỳ,\nHoặc thành loại chư Thiên.\nTất cả đều do ngươi,\nChính do ngươi tác thành.\n\n1131. Chính do nhân nhà ngươi,\nChúng ta thành Tu-la,\nChính do ngươi tác thành,\nTa rơi đáy địa ngục;\nMột thời thành súc sanh,\nMột thời thành ngạ quỷ,\nTất cả đều do ngươi,\nChính do ngươi tác thành.\n\n1132. Ngươi sẽ không lừa ta,\nNhiều lần, nhiều thời nữa,\nNhư những người phù thủy,\nBày các trò ảo thuật,\nNgươi chơi lừa phỉnh ta,\nNhư chơi với người điên,\nNày tâm, hãy nói ta,\nChỗ nào ta lỗi lầm.\n\n1133. Trước tâm này lang thang,\nChạy chỗ này chỗ khác,\nChạy chỗ nó ưa thích,\nChạy chỗ nó vui sướng,\nNay ta chế ngự tâm,\nVới như lý tư duy,\nNhư câu móc chế ngự,\nNhiếp phục con voi rừng.\n\n1134. Với ta, bậc Ðạo Sư,\nXác định đời vô thường,\nÐời không có trường cửu,\nÐời không có kiên thực.\nNày tâm, hãy đẩy ta,\nNhảy vào lời Phật dạy,\nKhiến ta vượt bộc lưu,\nRất khó được vượt qua.\n\n1135. Ta nay đã xuất gia,\nTrong pháp Ðại ẩn sĩ\nNhững người giống như ta,\nKhông chấp nhận tổn thất.\n\n1136. Rừng, biển, sông, đất liền,\nBốn phương, phụ trên dưới,\nTất cả là vô thường,\nBa hữu là hoạn nạn,\nNày tâm, hãy đi đâu?\nNgươi sẽ hưởng an lạc.`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `1137. Kìa, kìa, hỡi này tâm,\nÐích ta thật vững chắc,\nNgười sẽ làm được gì,\nKhiến ta phải quay lại,\nNày tâm, ta đâu còn,\nTùy thuộc thế lực ngươi,\nKhông ai chịu xúc chạm,\nCái bị có hai miệng,\nGớm ghiếc thay cái vật,\nÐầy chín dòng chảy nước.\n\n1138. Ôi, ngươi sẽ ưa sống,\nTrên đảnh sườn núi cao,\nChỗ ở đàn heo nai,\nHay cảnh đẹp thiên nhiên,\nHay trong núi rừng sâu,\nThấm mát mưa nước mới,\nTại đấy ngươi sẽ thích,\nNgươi lấy hang làm nhà.\n\n1139. Loài chim lông cổ đẹp,\nVới mào đẹp, cánh đẹp,\nVới lông nhiều màu sắc,\nÐón chào tiếng sấm vang,\nVới tiếng kêu dịu ngọt,\nChúng sẽ làm ngươi thích,\nNgươi tu tập thiền định,\nTrong núi rừng thâm sâu.\n\n1140. Khi trời đổ mưa xuống,\nTrên đám cỏ bón phân,\nVà trong rừng nở hoa.\nVới đầu hoa như mây,\nGiữa rừng, ta sẽ nằm,\nChẳng khác gì khúc cây,\nÐối ta, rất mềm dịu,\nThật giống như giường bông.\n\n1141. Như vậy, ta sẽ làm,\nGiống như người chủ nhà,\nNhững gì ta nhận được,\nTa xem là vừa đủ,\nNhư thợ da không nhác,\nKhéo làm cho nhuần nhuyễn,\nCái bị bằng da mèo.\n\n1142. Như vậy ta sẽ làm,\nGiống như người chủ nhà,\nNhững gì ta nhận được,\nTa xem là vừa đủ,\nTinh tấn ta dẫn ngươi,\nRơi vào thế lực ta.\nNhư voi say bị nài,\nKhéo dùng móc chế ngự.\n\n1143. Với ngươi khéo nhiếp phục,\nKhéo an trú vững vàng,\nNhư người huấn luyện ngựa,\nVới con ngựa thuần thục,\nTa có thể dấn bước\nTrên con đường an lành,\nCon đường được những vị\nHộ trì tâm thường dùng.\n\n1144. Ta sẽ trói chặt ngươi,\nVào đối tượng cần thiết,\nNhư con voi bị dây\nTrói chặt vào cây cột.\nTa khéo hộ trì ngươi,\nKhéo luyện với chánh niệm.\nNhờ vậy, ngươi sẽ thành,\nKhông dựa mọi sanh hữu.\n\n1145. Với tuệ, chặt tà đạo,\nVới lực, chận, hướng chánh\nThấy tập khởi, diệt sanh,\nNgươi sẽ là thừa tự\nBậc phát ngôn tối thượng.\n\n1146. Này tâm, ngươi dẫn ta,\nÐến ngôi làng thô lỗ,\nKhiến trú vào thế lực\nCủa bốn tưởng điên đảo,\nHãy đến, theo vị ấy\nVị chặt đứt kiết sử,\nBậc có tâm đại bi,\nBậc Mâu-ni vĩ đại.\n\n1147. Như loài thú tự do,\nTrong ngôi rừng đẹp đẽ.\nNgươi vào núi xinh đẹp\nCó mây làm vòng hoa,\nTại đấy, không có người,\nTrong rừng ngươi sẽ thích,\nNay tâm, chắc chắn vậy\nNgươi sẽ đến bờ kia.\n\n1148. Những ai còn rơi vào,\nThế lực ý muốn ngươi,\nNam nhân và nữ nhân,\nHưởng an lạc ngươi cho\nKhông trí, bị rơi vào\nTrong thế lực Ác-ma,\nAi ưa thích sanh hữu,\nSẽ là thuộc hạ ngươi,\nHỡi này tâm của ta.`, ref: "Trưởng Lão Tăng Kệ 19.1", url: "https://loicuaducphat.org/thag/thag19.1.html#content" },

{ text: `Trưởng Lão Maha-Moggallana\n\n1149. Chúng ta người ở rừng,\nSống đồ ăn khất thực,\nBằng lòng với miếng ăn\nÐược bỏ rơi trong bát,\nPhá nát ma, ma quân,\nNếu nội tâm khéo định.\n\n1150. Chúng ta người ở rừng,\nSống đồ ăn khất thực,\nBằng lòng với miếng ăn,\nÐược bỏ rơi trong bát,\nDẹp sạch ma, ma quân,\nNhư voi, nhà bằng lau.\n\n1151. Chúng ta ở gốc cây,\nNhẫn nại, tâm kiên trì,\nBằng lòng với miếng ăn,\nÐược bỏ rơi trong bát,\nPhá nát ma, ma quân,\nNếu nội tâm khéo định\n\n1152. Chúng ta ở gốc cây,\nNhẫn nại, tâm kiên trì,\nBằng lòng với miếng ăn,\nÐược bỏ rơi trong bát,\nDẹp sạch ma, ma quân,\nNhư voi, nhà bằng lau.`, ref: "Trưởng Lão Tăng Kệ 20.1", url: "https://loicuaducphat.org/thag/thag20.1.html#content" },

{ text: `Trưởng Lão Maha-Moggallana\n\n1153. Với am, sườn bằng xương,\nMay dính với gân thịt,\nGớm thay, đầy hơi thối!\nMang tay chân người khác,\nLàm thân thể của mình!\n\n1154. Cái bị đựng đầy phân,\nÐược da bao bọc lại,\nÔi con Quỷ cái kia!\nVới vú bị ung nhọt,\nThân Ngươi, chín dòng nước\nLuôn luôn được tuôn chảy.\n\n1155. Thân Ngươi chín dòng nước\nHôi thối, tạo trói buộc,\nTỷ-kheo tránh thân ấy,\nNhư kẻ sạch tránh phân.\n\n1156. Nếu người khác biết Ngươi\nNhư ta biết được Ngươi,\nNgười ấy tránh xa Ngươi,\nNhư khi mưa tránh phân.\n\n1157. Thật là vậy, Ðại hùng,\nNhư Sa-môn, ngài nói:\nỞ đây, có kẻ đắm,\nNhư bò già trong bùn.\n\n1158. Ai nghĩ có thể nhuộm,\nBầu trời với màu nghệ,\nHoặc với màu sắc khác\nKẻ ấy chỉ thất bại.\n\n1159. Tâm ta giống trời ấy,\nNội tâm khéo định tĩnh,\nChớ đem ác tâm đến\nNhư chim rơi đống lửa.`, ref: "Trưởng Lão Tăng Kệ 20.1", url: "https://loicuaducphat.org/thag/thag20.1.html#content" },

{ text: `1168. Các hành là vô thường\nCó sanh phải có diệt,\nSau khi sanh, chúng diệt,\nNhiếp chúng là an lạc.\n\n1169. Những ai thấy năm uẩn,\nLà khác, không phải ngã,\nQuán thấu vật tế nhị,\nNhư tên đâm mũi tóc.\n\n1170. Những ai thấy các hành,\nLà khác, không phải ngã,\nChúng thấu triệt tế nhị,\nNhư têm đâm mũi tóc.\n\n1171. Như bị kiếm chém xuống,\nNhư bị lửa cháy đầu,\nVị Tỷ-kheo xuất gia,\nChánh niệm, đoạn tham dục.\n\n1172. Như bị kiếm chém xuống,\nNhư bị lửa cháy đầu,\nVị Tỷ-kheo xuất gia,\nChánh niệm, đoạn tham hữu.\n\n1174. Không với nhu nhược này,\nKhông với ít lực này\nCó thể chứng Niết-bàn,\nGiải thoát mọi buộc ràng.\n\n1175. Vị Tỷ-kheo trẻ này,\nCon người tối thượng này,\nChiến thắng ma, ma quân,\nMang thân này tối hậu.`, ref: "Trưởng Lão Tăng Kệ 20.1", url: "https://loicuaducphat.org/thag/thag20.1.html#content" },

{ text: `1176. Giữa đồi Vebhàra,\nGiữa đồi Pandava,\nSét đánh vào hang động,\nCon bậc Vô tỷ ấy,\nÐã đi vào hang núi,\nÐang ngồi nhập thiền định.\n\n1177. An tịnh và thoải mái,\nẨn sĩ trú vùng xa,\nThừa tự Phật tối thắng,\nÐược Phạm thiên tán thán.\n\n1178. Hỡi này Bà-la-môn,\nHãy đảnh lễ Ca-diếp,\nNgài là con thừa tự,\nBậc Giác Ngộ tối thắng,\nẨn sĩ trú vùng xa\nAn tịnh và thoải mái.\n\n1181. Vị ấy trước bữa ăn,\nThấy được tám giải thoát.\nThuận hướng và nghịch hướng.\nRồi mới đi khất thực.\n\n1182. Một Tỷ-kheo như vậy,\nHỡi này Bà-la-môn,\nHãy khởi ý tín nhiệm\nVị La hán như vậy,\nChấp tay đảnh lễ gấp,\nChớ để đầu ông hỏng.`, ref: "Trưởng Lão Tăng Kệ 20.1", url: "https://loicuaducphat.org/thag/thag20.1.html#content" },

{ text: `Trưởng Lão Vangisa\n\n1218. Với ta đã xuất gia,\nBỏ nhà, sống không nhà,\nTư tưởng này chạy loạn,\nKhởi lên từ hắc ám.\n\n1219. Nhà bắn cung thiện xảo,\nThượng sanh giỏi cung pháp,\nNgàn người bắn khắp phía,\nKhông nao núng chút nào.\n\n1220. Nếu phụ nữ có đến,\nDầu nhiều hay đông hơn,\nSẽ không dao động ta,\nVì ta trú Chánh pháp.\n\n1221. Chính ta từng được nghe,\nPhật dòng họ Mặt Trời,\nGiảng đạo hướng Niết-bàn,\nỞ đây ý ta thích.\n\n1222. Như vậy ta an trú,\nÁc ma, ngươi có đến,\nTa sẽ làm như vậy,\nNgươi không thấy đường ta.\n\n1223. Ta bỏ lạc bất lạc,\nMọi tâm tư gia sự,\nKhông tạo một chỗ nào,\nThành cơ sở tham dục,\nAi thoát rừng, ly tham,\nMới ứng danh Tỷ-kheo.\n\n1224. Phàm địa giới, không giới,\nCả sắc giới trong đời,\nÐều biến hoại vô thường,\nHiểu vậy, sống liễu tri.\n\n1225. Chúng sanh thường chấp trước,\nÐối với các sanh y,\nÐối vật họ thấy nghe,\nHọ xúc chạm suy tư,\nỞ đây ai đoạn dục,\nTâm tư không nhiễm ô.\nKhông mắc dính chỗ này,\nVị ấy danh Mâu-ni.\n\n1226. Ðối sáu mươi tám kiến,\nThuộc phàm phu phi pháp,\nKhông học phái tà chấp,\nVị ấy chân Tỷ-kheo.\n\n1228. Vẹn toàn, tâm thường định,\nKhông dối trá thận trọng,\nLy ái, vị Mâu-ni,\nChứng đạt đường an tịnh,\nTùy duyên nhập Niết Bàn,\nVị ấy chờ thời đến.`, ref: "Trưởng Lão Tăng Kệ 21.1", url: "https://loicuaducphat.org/thag/thag21.1.html#content" },

{ text: `Trưởng Lão Vangisa\n\n1228. Ðệ tử Gotama,\nHãy từ bỏ kiêu mạn,\nTrên con đường kiêu mạn,\nHãy tránh né hoàn toàn,\nHam mê đường kiêu mạn,\nSẽ hối trách dài dài.\n\n1229. Bị lừa bởi lừa dối,\nBị hại bởi kiêu mạn,\nLoài Người rơi địa ngục,\nChúng sầu khổ lâu dài,\nBị hại về kiêu mạn,\nHọ phải sanh địa ngục.\n\n1230. Không bao giờ sầu muộn,\nTỷ-kheo chiến thắng đạo,\nChơn chánh dấn thân bước,\nHưởng danh dự an lạc,\nNhư thật được tên gọi,\nLà bậc đã thấy pháp.\n\n1231. Do vậy ở đời này,\nKhông thô lậu, không kiêu,\nÐoạn triền cái, thanh tịnh,\nÐoạn kiêu mạn, không dư,\nVới minh, tâm an tịnh,\nBậc đoạn tận khổ đau.`, ref: "Trưởng Lão Tăng Kệ 21.1", url: "https://loicuaducphat.org/thag/thag21.1.html#content" },

{ text: `1232. Dục ái đốt cháy tôi!\nTâm tôi bị thiêu cháy,\nLành thay Gotama,\nVì lòng từ nói lên,\nPháp tiêu diệt lửa hừng.\n\n1233. Chính vì điên đảo tưởng,\nTâm ông bị thiêu đốt,\nHãy từ bỏ tịnh tướng,\nHệ lụy đến tham dục.\n\n1234. Nhìn các hành vô thường,\nKhổ đau, không phải ngã,\nDập tắt đại tham dục,\nChớ để bị cháy dài,\nHãy tu tâm bất tịnh,\nNhứt tâm, khéo định tĩnh,\nTu tập thân hành niệm,\nHành hạnh nhiều yếm ly.\n\n1235. Hãy tập hạnh vô tướng,\nÐoạn diệt mạn tùy miên,\nNhờ quán sân kiêu mạn,\nHạnh ông sẽ an tịnh.`, ref: "Trưởng Lão Tăng Kệ 21.1", url: "https://loicuaducphat.org/thag/thag21.1.html#content" },

{ text: `1236. Ai nói lên lời gì,\nLời ấy không khổ mình,\nLời không làm hại người,\nLời ấy là thiện thuyết.\n\n1237. Ai nói lời ái ngữ,\nLời nói khiến hoan hỷ,\nLời nói không ác độc,\nLời nói là ái ngữ.\n\n1238. Lời chân, lời bất tử,\nThường pháp xưa là vậy,\nThiện nhân trú trên chân,\nTrên nghĩa và trên pháp.\n\n1239. Lời đức Phật nói lên,\nÐạt an ổn Niết-bàn,\nChấm dứt mọi khổ đau,\nThật nói lời tối thượng.`, ref: "Trưởng Lão Tăng Kệ 21.1", url: "https://loicuaducphat.org/thag/thag21.1.html#content" },
        
                { text: `Trưởng Lão Ni Muttà\n\n2. Hỡi này, giải thoát Ni\nHãy giải thoát các ách,\nNhư mặt trăng thoát khỏi,\nMiệng hàm của Ràhu,\nVới tâm tư giải thoát,\nKhỏi nợ nần trói buộc,\nHãy thọ hưởng món ăn,\nDo khất thực đem lại.`, ref: "Trưởng Lão Ni Kệ 1.2", url: "https://loicuaducphat.org/thig/thig1.2.html#content" },

{ text: `Trưởng Lão Ni Punnà\n\n3. Hỡi này, thành Mãn ni,\nHãy tràn đầy Chánh pháp,\nNhư mặt trăng tròn đầy,\nTrong ngày rằm trăng tròn,\nHãy tràn đầy trí tuệ,\nPhá tan khối si ám.`, ref: "Trưởng Lão Ni Kệ 1.3", url: "https://loicuaducphat.org/thig/thig1.3.html#content" },

{ text: `Trưởng Lão Ni Tissà\n\n4. Tissà hãy học tập,\nHọc trong những học pháp,\nChớ để cho các ách,\nVượt khỏi chi phối nàng.\nHãy sống không liên hệ,\nMọi ách không trói buộc,\nSống giữa thế giới này,\nKhông có các lậu hoặc.`, ref: "Trưởng Lão Ni Kệ 1.4", url: "https://loicuaducphat.org/thig/thig1.4.html#content" },

{ text: `Một Trưởng Lão Ni Tissà Khác\n\n5. Tissà, hãy cột tâm\nTập trung trên các pháp,\nChớ để từng sát-na\nUổng phí vượt khỏi nàng!\nNhững sát-na đã qua\nHọ sầu muộn, đau khổ,\nKhi họ bị rơi vào\nTrong cảnh giới địa ngục.`, ref: "Trưởng Lão Ni Kệ 1.5", url: "https://loicuaducphat.org/thig/thig1.5.html#content" },

{ text: `Trưởng Lão Ni Dhìra\n\n6. Dhìra, hãy cảm xúc,\nNhững cảm chứng đoạn diệt,\nTịnh chỉ các vọng tưởng,\nLà chân chánh an lạc,\nHãy thuận hướng Niết-bàn,\nÁch an ổn, vô thường.`, ref: "Trưởng Lão Ni Kệ 1.6", url: "https://loicuaducphat.org/thig/thig1.6.html#content" },

{ text: `Một Trưởng Lão Ni Dhìra Khác\n\n7. Dhìra, hãy kiên trì,\nNắm giữ các thiện pháp,\nHỡi này Tỷ-kheo-ni,\nCác căn được tu tập,\nHãy mang cái thân này,\nLà cái thân cuối cùng,\nSau khi đã chiến thắng,\nÁc ma nữ quân lực,\nSau khi đã chiến thắng,\nÁc ma với quân lực.`, ref: "Trưởng Lão Ni Kệ 1.7", url: "https://loicuaducphat.org/thig/thig1.7.html#content" },

{ text: `Trưởng Lão Ni Mittà\n\n8. Hỡi này Mittà bạn!\nVới lòng tin xuất gia,\nHãy tu tập rèn luyện,\nHân hoan trong bạn lành,\nHãy tu tập rèn luyện,\nTrong các pháp hiếu thiện,\nCố gắng đạt cho được,\nAn ổn khỏi ách nạn.`, ref: "Trưởng Lão Ni Kệ 1.8", url: "https://loicuaducphat.org/thig/thig1.8.html#content" },

{ text: `Trưởng Lão Ni Bhadhà\n\n9. Hỡi Bhàdha hiền thiện,\nVới lòng tin xuất gia,\nHãy sống vui hoan hỷ,\nTrong các pháp hiền thiện,\nHãy tu tập rèn luyện,\nTrong các pháp chí thiện,\nCố gắng đạt cho được,\nAn ổn khỏi ách nạn.`, ref: "Trưởng Lão Ni Kệ 1.9", url: "https://loicuaducphat.org/thig/thig1.9.html#content" },

{ text: `Trưởng Lão Ni Upasanà\n\n10. Hỡi Upasanà\nHãy vượt dòng nước mạnh,\nDòng nước khó vượt qua,\nBị thần chết chi phối,\nHãy mang cái thân này,\nLà cái thân cuối cùng,\nSau khi đã chiến thắng,\nÁc ma với quân lực.`, ref: "Trưởng Lão Ni Kệ 1.10", url: "https://loicuaducphat.org/thig/thig1.10.html#content" },

{ text: `Trưởng Lão Ni Muttà\n\n11. Lành thay giải thoát Ni,\nTa thật khéo giải thoát,\nGiải thoát ra khỏi được,\nBa vật còm và cong,\nThoát cối xay, cái chày,\nThoát ông chồng lưng còm,\nHỡi này giải thoát Ni!\nTa thoát được sống chết,\nNhững gì dẫn tái sanh,\nÐược nhổ lên tận gốc.`, ref: "Trưởng Lão Ni Kệ 1.11", url: "https://loicuaducphat.org/thig/thig1.11.html#content" },

{ text: `Trưởng Lão Ni Dhammadinnà\n\n12. Trong ai, lòng ước muốn,\nÐạt được quả vô sanh,\nÐược sanh khởi tỏa rộng,\nÐầy tràn cả tâm ý,\nTâm không bị trói buộc,\nTrong các dục chi phối,\nVị ấy được tên gọi\nLà bậc vào dòng trên.`, ref: "Trưởng Lão Ni Kệ 1.12", url: "https://loicuaducphat.org/thig/thig1.12.html#content" },

{ text: `Trưởng Lão Ni Visàkhà\n\n13. Hãy làm, hãy thực hành\nÐúng theo lời Phật dạy.\nVà sau khi làm xong,\nKhông có lòng ăn năn,\nHãy gấp rửa chân sạch,\nVà ngồi xuống một bên.`, ref: "Trưởng Lão Ni Kệ 1.13", url: "https://loicuaducphat.org/thig/thig1.13.html#content" },

{ text: `Trưởng Lão Ni Sumànà\n\n14. Sau khi thấy các giới,\nVới cái nhìn đau khổ,\nChớ có đi trở lại,\nVào con đường tái sanh,\nHãy từ bỏ, xả ly\nLòng dục trong sanh hữu,\nSống đời sống hành trì,\nTa mát lạnh tịch tịnh.`, ref: "Trưởng Lão Ni Kệ 1.14", url: "https://loicuaducphat.org/thig/thig1.14.html#content" },

{ text: `Trưởng Lão Ni Uttarà\n\n15. Ta đã chế ngự được,\nThân miệng và tâm tư,\nTa chinh phục khát ái,\nCho đến tận gốc rễ,\nTa sống được mát lạnh,\nTrong tịch tịnh, an lặng.`, ref: "Trưởng Lão Ni Kệ 1.15", url: "https://loicuaducphat.org/thig/thig1.15.html#content" },

{ text: `Trưởng Lão Ni Sumànà\n\n16. Hỡi này, lão Ni kia,\nHãy an lạc nằm nghỉ,\nÐắp phủ trong tấm y,\nChính tự mình làm lấy,\nLòng tham người an tịnh,\nNgười mát lạnh tịch tịnh.`, ref: "Trưởng Lão Ni Kệ 1.16", url: "https://loicuaducphat.org/thig/thig1.16.html#content" },

{ text: `Trưởng Lão Ni Dhammà\n\n17. Sau khi khất thực xong,\nYếu sức, chống trên gậy,\nVới chân tay run rẩy,\nTa ngã trên mặt đất,\nThấy nguy hiểm của thân,\nTâm ta được giải thoát.`, ref: "Trưởng Lão Ni Kệ 1.17", url: "https://loicuaducphat.org/thig/thig1.17.html#content" },

{ text: `Trưởng Lão Ni Sanjhà\n\n18. Bỏ gia đình, xuất gia,\nTa từ bỏ con cái,\nTừ bỏ gia súc quý,\nTừ bỏ tham và sân,\nCòn đối với vô minh,\nTa sống hạnh viễn ly,\nSau khi chinh phục được,\nTận gốc cả tham ái,\nTa được sống mát lạnh,\nTịch tịnh và an lặng.`, ref: "Trưởng Lão Ni Kệ 1.18", url: "https://loicuaducphat.org/thig/thig1.18.html#content" },

{ text: `Trưởng Lão Ni Abhirùpa Nandà\n\n19. Này Nandà, hãy nhìn,\nTấm thân chỗ quy tụ,\nNhiều bệnh hoạn, bất tịnh,\nÐầy hôi hám thối nát,\nTâm nàng hãy tu tập,\nQuán tri tánh bất tịnh,\nÐạt cho được nhất tâm,\nTâm tư khéo thiền định.\n\n20. Hãy tu tập vô tướng,\nHãy bỏ mạn tùy miên,\nDo thắng tri được mạn,\nNàng sẽ sống an tịnh.`, ref: "Trưởng Lão Ni Kệ 2.1", url: "https://loicuaducphat.org/thig/thig2.1.html#content" },

{ text: `Trưởng Lão Ni Jentì\n\n21. Chính Bảy giác chi này\nLà đường đạt Niết-bàn,\nTất cả, ta tu tập,\nNhư lời đức Phật dạy.\n\n22. Ta thấy được Thế Tôn,\nÐây thân tụ cuối cùng\nVòng sanh tử đoạn tận,\nNay không còn tái sanh.`, ref: "Trưởng Lão Ni Kệ 2.2", url: "https://loicuaducphat.org/thig/thig2.2.html#content" },

{ text: `Trưởng Lão Ni Mẹ Của Sumangala\n\n23. Hỡi thiện giải thoát Ni,\nLành thay khéo giải thoát,\nTa được khéo giải thoát,\nKhỏi cái chày giã gạo,\nTa không còn xấu hổ,\nVới ông chồng đan dù,\nVới soong chảo nấu ăn,\nVới nghèo đói tồi tàn.\n\n24. Chặt đứt được tham sân,\nTa sống không tham sân,\nTa đi đến gốc cây,\nÔi, an lạc ta thiền.`, ref: "Trưởng Lão Ni Kệ 2.3", url: "https://loicuaducphat.org/thig/thig2.3.html#content" },

{ text: `Trưởng Lão Ni Addhakasi\n\n25. Tiền lạc thú của ta,\nKhông thua thuế Kàsi,\nSau khi so sánh giá,\nThôn trưởng định giá vậy.\n\n26. Nay ta lại nhàm chán,\nChính sắc đẹp của ta,\nTa chán ngấy sắc ấy,\nTa không còn luyến tiếc.\nTa chớ có liên tục,\nChạy theo vòng luân hồi,\nBa minh ta chứng được,\nThành tựu lời Phật dạy.`, ref: "Trưởng Lão Ni Kệ 2.4", url: "https://loicuaducphat.org/thig/thig2.4.html#content" },

{ text: `Trưởng Lão Ni Città\n\n27. Dầu ta có mỏi mệt,\nBệnh hoạn quá yếu đuối,\nDựa trên gậy ta đi,\nTa leo lên đỉnh núi.\n\n28. Với đại y vắt ngang,\nVới bình bát lộn ngược,\nTa dựa mình tảng đá,\nPhá tan khối si ám.`, ref: "Trưởng Lão Ni Kệ 2.5", url: "https://loicuaducphat.org/thig/thig2.5.html#content" },

{ text: `Trưởng Lão Ni Mettikà\n\n29. Dầu ta có đau đớn,\nSức yếu, tuổi trẻ qua,\nDựa trên gậy, ta đi,\nTa leo lên đỉnh núi.\n\n30. Với đại y vắt ngang,\nVới bình bát lộn ngược,\nTa ngồi trên tảng đá,\nTâm ta được giải thoát.\nBa minh chứng đạt được,\nThành tựu lời Phật dạy.`, ref: "Trưởng Lão Ni Kệ 2.6", url: "https://loicuaducphat.org/thig/thig2.6.html#content" },

{ text: `Trưởng Lão Ni Mittà\n\n31. Ngày mười bốn, ngày rằm,\nNgày mồng tám giữa tháng,\nNgày thần túc nguyệt phần,\nTa thọ trì tám giới.\n\n32. Ta gìn giữ trai giới,\nKhiến chư Thiên hoan hỷ,\nMỗi ngày ăn một bữa,\nCạo đầu đắp đại y,\nTa đâu muốn thiên giới,\nTa nhiếp phục tâm khổ.`, ref: "Trưởng Lão Ni Kệ 2.7", url: "https://loicuaducphat.org/thig/thig2.7.html#content" },

{ text: `Trưởng Lão Ni Mẹ Của Abhayà\n\n33. Từ bàn chân trở lên,\nTừ đầu tóc trở xuống,\nHãy quán sát thân này,\nThân này thật bất tịnh,\nThật hôi hám thối tha.\n\n34. Ta an trú như vậy,\nMọi tham dục nhổ sạch,\nNhiệt não được đoạn trừ,\nTa mát lạnh, tịch tịnh.`, ref: "Trưởng Lão Ni Kệ 2.8", url: "https://loicuaducphat.org/thig/thig2.8.html#content" },

{ text: `Trưởng Lão Ni Abhaya\n\n35. Hỡi này vô úy Ni!\nThân này thật mỏng manh,\nChính ở đây phàm phu,\nƯa thích, thường tham đắm.\nTa sẽ bỏ thân này,\nTỉnh giác và chánh niệm\n\n36. Chú tâm không phóng dật,\nTa gắng thoát pháp khổ,\nÁi diệt, ta chứng đạt,\nThành tựu lời Phật dạy.`, ref: "Trưởng Lão Ni Kệ 2.9", url: "https://loicuaducphat.org/thig/thig2.9.html#content" },

{ text: `37. Bốn lần và năm lần,\nTa ra khỏi tinh xá,\nNhưng tâm không an tịnh,\nKhông nhiếp phục được tâm,\nNhưng đến đêm mồng tám,\nÁi được ta nhổ sạch.\n\n38. Chú tâm không phóng dật,\nTa gắng thoát pháp khổ,\nÁi diệt, ta chứng đạt,\nThành tựu lời Phật dạy.`, ref: "Trưởng Lão Ni Kệ 2.10", url: "https://loicuaducphat.org/thig/thig2.10.html#content" },

{ text: `Trưởng Lão Ni Sàmà Khác\n\n39. Ðã được hăm lăm năm,\nTừ khi ta xuất gia.\nTa không thắng tri tâm,\nKhông được tâm thăng bằng,\n\n40.Tâm không được an tịnh,\nKhông nhiếp phục được tâm\nDo vậy ta dao động,\nNhớ đến lời Phật dạy.\n\n41. Chú tâm không phóng dật\nTa gắng thoát pháp khổ,\nÁi diệt, ta chứng đạt,\nThành tựu lời Phật dạy\nHôm nay đêm mồng bảy,\nKhái ái được khô cạn.`, ref: "Trưởng Lão Ni Kệ 3.1", url: "https://loicuaducphat.org/thig/thig3.1.html#content" },

{ text: `Trưởng Lão Ni Uttama\n\n42. Bốn lần và năm lần,\nTa ra khỏi tinh xá.\nNhưng tâm không an tịnh,\nKhông nhiếp phục được tâm.\n\n43. Ta đến Tỷ-kheo -ni,\nVới ta đồng tín nữ,\nNàng thuyết pháp cho ta,\nVới uẩn, xứ và giới.\n\n44. Nghe xong pháp nàng thuyết,\nNhư nàng đã dạy ta,\nBảy ngày ngồi kiết-già,\nTa thọ hưởng hỷ lạc,\nMồng tám ta duỗi chân,\nPhá tan khối si ám.`, ref: "Trưởng Lão Ni Kệ 3.2", url: "https://loicuaducphat.org/thig/thig3.2.html#content" },

{ text: `Trưởng Lão Ni Uttarà Khác\n\n45. Bảy pháp giác chi này,\nCon đường đạt Niết-bàn,\nTất cả ta tu tập,\nNhư lời đức Phật dạy.\n\n46. Do quán không vô tướng\nTa đạt quả mong muốn,\nTa thành con gái Phật,\nSanh ra từ miệng Ngài,\nLuôn luôn ta hoan hỷ,\nTrong an lạc Niết-bàn.\n\n47. Mọi dục được đoạn diệt,\nDục trời và dục người,\nVòng sanh hữu đoạn tận,\nNay không còn tái sanh.`, ref: "Trưởng Lão Ni Kệ 3.3", url: "https://loicuaducphat.org/thig/thig3.3.html#content" },

{ text: `Trưởng Lão Ni Dantikà\n\n48. Ra khỏi ngôi tinh xá,\nÐể nghỉ trưa ban ngày,\nTrên đỉnh núi Linh Thứu,\nTa thấy một con voi,\nDầm nước xong đi lên,\nTrên bờ một con sông.\n\n49. Một người cầm cái móc,\nYêu cầu đưa chân lên,\nCon voi duỗi chân ra,\nVà người leo lên voi.\n\n50. Thấy kẻ chưa nhiếp phục,\nÐi đến được nhiếp phục,\nTa thấy nó vâng chịu,\nTheo quyền lực của người.\nNhư vậy, ta định tâm,\nÐi vào trong rừng ấy.`, ref: "Trưởng Lão Ni Kệ 3.4", url: "https://loicuaducphat.org/thig/thig3.4.html#content" },

{ text: `Trưởng Lão Ni Ubirì\n\n51. Hỡi nàng Ubirì,\nNàng khóc trong rừng sâu,\nKhóc than ôi Jivà,\nCon gái thân của tôi,\nHãy tự mình hồi tỉnh,\nHỡi này Ubirì!\nTrong bãi đốt thân này\nTất cả tám vạn tư,\nNgười đồng tên Jivà\nNàng khóc Jivà nào?\n\n52. Mũi tên khó nhìn thấy,\nÐâm dính nơi tâm ta,\nChắc chắn đã được Ngài,\nNhổ lên khỏi tâm ta,\nSầu muộn vì con gái,\nÐã được chấm dứt hẳn.\n\n53. Nay mũi tên được nhổ,\nMọi ham muốn lắng dịu,\nTa đi đến quy y\nBậc Mâu-ni ẩn sĩ,\nQuy y Ba ngôi báu\nPhật, Pháp và chúng Tăng.`, ref: "Trưởng Lão Ni Kệ 3.5", url: "https://loicuaducphat.org/thig/thig3.5.html#content" },

{ text: `Trưởng Lão Ni Sukkà\n\n54. Hỡi này người Vương Xá,\nCác người đã làm gì?\nGiống như người nằm mê,\nBị say vì uống mật!\nCác người không hầu hạ,\nSukkà thuyết lời Phật.\n\n55. Chúng tôi nghĩ bậc trí,\nUống được nước cam lồ,\nDòng nước thật thuần tinh,\nKhông gì chướng ngại nổi\nChẳng khác kẻ đi đường,\nÐón nhận nước trời mưa.\n\n56. Hỡi này nàng Sukkà!\nNgười con của ánh sáng!\nÐược ly tham định tĩnh,\nNhờ ánh sáng Chánh pháp,\nHãy mang thân cuối cùng,\nSau khi thấy ma quân.`, ref: "Trưởng Lão Ni Kệ 3.6", url: "https://loicuaducphat.org/thig/thig3.6.html#content" },

{ text: `Trưởng Lão Ni Selà\n\n57. Nàng sẽ không thoát khỏi,\nThoát ly khỏi đời này,\nNhư vậy hạnh viễn ly,\nNàng dùng để làm gì?\nHãy thọ hưởng dục lạc,\nChớ bứt rứt về sau.\n\n58. Các dục giống gươm giáo,\nChém nát các uẩn ta,\nNhững dục mà ngươi gọi,\nLà lạc thú cuộc đời.\n\n59. Ngày nay dục lạc ấy,\nVới ta không hấp dẫn,\nỞ tất cả mọi nơi,\nHỷ lạc được đoạn tận,\nKhối tối tăm mù ám,\nÐã bị làm tan nát,\nHỡi này kẻ Ác ma,\nNgươi hãy biết như vậy,\nNgươi chính là Ác ma\nNgươi đã bị bại trận.`, ref: "Trưởng Lão Ni Kệ 3.7", url: "https://loicuaducphat.org/thig/thig3.7.html#content" },

{ text: `Trưởng Lão Ni Somà\n\n60. Ðịa vị khó chứng đạt,\nChỉ thánh nhân chứng đạt,\nTrí nữ nhân hai ngón,\nSao hy vọng chứng đạt.\n\n61. Nữ tánh chướng ngại gì,\nKhi tâm khéo thiền định,\nKhi trí tuệ triển khai,\nChánh quán pháp vi diệu.\n\n62. Ở tất cả mọi nơi,\nHỷ lạc được đoạn tận,\nKhối tối tăm mù mịt,\nÐã bị làm tan nát.\nHỡi này kẻ Ác ma,\nNgươi hãy biết như vậy,\nNgươi chính là Ác ma,\nNgươi đã bị bại trận.`, ref: "Trưởng Lão Ni Kệ 3.8", url: "https://loicuaducphat.org/thig/thig3.8.html#content" },

{ text: `Trưởng Lão Ni Bhaddà\n\n63. Con được thừa tự Phật,\nCa-diếp khéo thiền định.\nBiết được đời quá khứ,\nThấy cõi trời đọa xứ.\n\n64. Ẩn sĩ đoạt diệt sanh,\nThắng trí được thành tựu\nCùng với Ba minh này,\nLà Phạm chí Ba minh.\n\n65. Cũng vậy nàng Bhaddà\nNgười xứ Kapila,\nNàng là bậc Ba minh,\nÐã đoạn được sự chết,\nMang thân này cuối cùng,\nSau khi thắng ma quân.\n\n66. Thấy nguy hại ở đời,\nHai chúng tôi xuất gia.\nChúng tôi được chế ngự,\nÐoạn tận các lậu hoặc,\nCảm xúc thành mát lạnh,\nÐược tịch tịnh giải thoát.`, ref: "Trưởng Lão Ni Kệ 4.1", url: "https://loicuaducphat.org/thig/thig4.1.html#content" },

{ text: `Trưởng Lão Ni Vô Danh\n\n67. Ðã được hai lăm năm,\nTừ khi ta xuất gia,\nCho đến búng ngón tay,\nTâm ta không lắng dịu.\n\n68. Tâm không được an tịnh,\nVì đầy ứ dục tham,\nTa giơ tay khóc than,\nTa đi vào tinh xá.\n\n69. Ta đến vị Ni ấy,\nÐồng tín nữ với ta,\nNàng thuyết pháp cho ta,\nVề uẩn, xứ và giới.\n\n70. Nghe pháp nàng giảng dạy,\nTa ngồi vào một bên,\nTa hết đời quá khứ,\nThiên nhãn được thanh tịnh,\n\n71. Với trí biết tâm người,\nLỗ tai được thanh tịnh.\nTa chứng thần túc thông,\nTa đạt được lậu tận,\nSáu thắng trí ta chứng,\nLời Phật dạy đã làm.`, ref: "Trưởng Lão Ni Kệ 5.1", url: "https://loicuaducphat.org/thig/thig5.1.html#content" },

{ text: `Trưởng Lão Ni Vimala, Xưa Là Một Kỹ Nữ\n\n72. Say mê với giai cấp,\nVới dung sắc tuổi xuân,\nVới danh xưng, danh vọng,\nTa ỷ lại tuổi trẻ,\nÐối với những người khác,\nTa khinh bỉ khinh thường.\n\n73. Thân này ta trang điểm,\nTa khêu gợi kẻ ngu,\nTa đứng trong khung cửa,\nTại cửa hàng buôn sắc,\nNhư thợ săn, ác độc,\nÐang gieo đặt bẫy mồi.\n\n74. Ta khoa trương trang sức,\nPhô bày nhiều chỗ kín,\nÐể châm biếm nhiều người,\nTa làm nhiều ảo thuật.\n\n75. Hôm nay ta khất thực,\nÐầu trọc, đắc đại y,\nTa ngồi dưới gốc cây,\nTa chứng định không tầm.\n\n76. Mọi khổ ách đoạn tận,\nCả cõi trời, cõi người,\nQuăng bỏ mọi lậu hoặc,\nTa mát lạnh tịch tịnh.`, ref: "Trưởng Lão Ni Kệ 5.2", url: "https://loicuaducphat.org/thig/thig5.2.html#content" },

{ text: `Trưởng Lão Ni Sìha\n\n77. Không như lý tác ý,\nBị dục tham ám ảnh,\nTa trước bị dao động\nKhông chế ngự được tâm.\n\n78. Bị phiền não chi phối,\nLạc tưởng ngự trị ta\nTâm ta không thăng bằng,\nBị tham tâm chi phối.\n\n79. Bảy năm sống ốm yếu,\nVàng da, dung sắc xấu\nÐêm ngày không an lạc\nTa sống chịu khổ đau.\n\n80. Do vậy ta lấy dây,\nÐi vào giữa khu rừng,\nTốt hơn ta treo cổ,\nCòn hơn sống hạ liệt.\n\n81. Làm chắc dây thòng lọng,\nTa cột ở cành cây,\nQuàng thòng lọng quanh cổ,\nTâm ta liền giải thoát.`, ref: "Trưởng Lão Ni Kệ 5.3", url: "https://loicuaducphat.org/thig/thig5.3.html#content" },

{ text: `Trưởng Lão Ni Sundarì Nandà\n\n82. Nandà, hãy nhìn thân,\nBệnh bất tịnh, hôi thúi,\nHãy tu tâm bất tịnh,\nNhất tâm khéo định tĩnh.\n\n83. Như thân này thân ấy,\nNhư thân ấy thân này,\nHôi thối và rữa nát,\nChỉ kẻ ngu thích thú.\n\n84. Như vậy quán thân này,\nNgày đêm không mệt mỏi,\nVới trí tuệ của con,\nDo vậy hãy thoát ly,\nVới trí tuệ của con,\nThoát khỏi kiêu sắc đẹp,\nVà người si nhìn thấy,\nVới cái nhìn như thật.\n\n85. Thành này làm bằng xương,\nQuét tô bằng máu thịt,\nỞ đây già và chết,\nMạn, lừa đảo chất chứa.\n\n86. Với tâm không phóng dật,\nNhư lý, quán thân ấy,\nTánh như thật thân này,\nÐược thấy trong và ngoài.\nTa nhàm chán thân thể,\nNội tâm được ly tham,\nKhông phóng dật ly hệ,\nTa an bình tịch tịnh.`, ref: "Trưởng Lão Ni Kệ 5.4", url: "https://loicuaducphat.org/thig/thig5.4.html#content" },

{ text: `Trưởng Lão Ni Manduttara\n\n87. Trước ta đảnh lễ lửa,\nTrăng, mặt trời chư thiên\nTa đi đến bến sông,\nTa xuống nước, lê tắm.\n\n88. Chấp nhận nhiều giới cấm\nTa chỉ cạo nửa đầu\nTa nằm ngủ dưới đất,\nCơm tối ta không ăn.\n\n89. Thích trang điểm trang sức,\nƯa tắm rửa, xoa bóp,\nThân này ta cung dưỡng,\nThỏa mãn các dục tham,\n\n90. Từ khi được lòng tin\nKhông nhà ta xuất gia,\nTa thấy thân như Phật,\nNhờ sạch các dục tham.\n\n91. Mọi sanh hữu chặt đứt,\nCả ham muốn hy cầu,\nMọi ách nạn giải tỏa,\nTa đạt tâm an tịnh.`, ref: "Trưởng Lão Ni Kệ 5.5", url: "https://loicuaducphat.org/thig/thig5.5.html#content" },

{ text: `Trưởng Lão Ni Mittakali\n\n92. Vì lòng tin, xuất gia,\nBỏ nhà, sống không nhà,\nTa sống tâm hướng mạnh,\nTheo lợi dưỡng cung kính.\n\n93. Từ bỏ đích tối thượng,\nPhục vụ đích hạ liệt,\nBị phiền não ngự trị,\nBỏ đích Sa-môn hạnh.\n\n94. Ngồi trong phòng tinh xá,\nTa cảm bị dao động\nTa đi vào tà đạo,\nKhát ái ngự trị ta.\n\n95. Ngắn ngủi sinh mạng ta,\nGià, bệnh đang đè nặng,\nTrước khi thân hủy diệt,\nGiờ phóng dật không còn.\n\n96. Như thật ta quán sát,\nSinh diệt của các uẩn,\nTâm giải thoát, ta chứng,\nLời Phật dạy làm xong.`, ref: "Trưởng Lão Ni Kệ 5.6", url: "https://loicuaducphat.org/thig/thig5.6.html#content" },

{ text: `Trưởng Lão Ni Sakulà\n\n97. Khi sống ở gia đình,\nNghe Tỷ kheo thuyết pháp,\nTa thấy pháp vô uế,\nÐạo Niết-bàn bất tử.\n\n98. Từ bỏ con trai, gái,\nCả tài sản lúa gạo,\nCạo tóc ta xuất gia\nSống đời sống không nhà.\n\n99. Ta làm người học nữ,\nTu tập con đường chánh,\nÐoạn tận tham và sân,\nÐoạn từng lậu hoặc một.\n\n100. Thọ giới Tỷ-kheo-ni,\nTa nhớ đời quá khứ,\nThiên nhãn ta thanh tịnh,\nKhông uế, khéo tu tập.\n\n101. Thấy các hàng ngoại diện,\nDo nhân sanh biến hoại,\nTa đoạn mọi lậu hoặc,\nMát lạnh ta tịch tịnh.`, ref: "Trưởng Lão Ni Kệ 5.7", url: "https://loicuaducphat.org/thig/thig5.7.html#content" },

{ text: `Trưởng Lão Ni Sonà\n\n102. Ta sanh được mười con,\nTrong thân chất chứa này,\nDo vậy ta già yếu,\nTa đến Tỷ-kheo-ni.\n\n103. Nàng thuyết pháp cho ta,\nVề uẩn xứ và giới,\nNghe pháp nàng thuyết giảng.\nCắt tóc ta xuất gia.\n\n104. Ta học lời nàng dạy,\nThiên nhãn ta thanh tịnh,\nTa biết các đời trước,\nChỗ ta sống đời trước.\n\n105. Ta tu pháp vô tướng,\nNhất tâm khéo thiền tịnh,\nTức thời ta giải thoát,\nKhông chấp thủ tịch tịnh.\n\n106. Năm uẩn được liễu tri,\nÐứng lại, gốc bị cắt,\nTham dục, ta không có,\nCăn cứ địa kiên trì?\nTừ nay ta không còn\nVấn đề phải tái sanh.`, ref: "Trưởng Lão Ni Kệ 5.8", url: "https://loicuaducphat.org/thig/thig5.8.html#content" },

{ text: `Trưởng Lão Ni Patàcàrà\n\n112. Với cây, cày ruộng đất,\nGieo hột giống trên đất,\nLoài Người được tài sản,\nNuôi dưỡng vợ và con.\n\n113. Sao ta, giới đầy đủ\nLàm theo Ðạo Sư dạy,\nLại không chứng Niết-bàn,\nKhông nhác, không dao động.\n\n114. Khi ta đang rửa chân,\nLàm cho dòng nước chảy,\nThấy được nước rửa chân\nTừ cao chảy xuống thấp,\n\n115. Nhờ vậy, tâm được định,\nNhư ngựa hiền khéo luyện.\nRồi ta cầm cây đèn,\nBước vào ngôi tinh xá,\nNằm trên chiếc giường nhỏ,\nTa nhìn quán ngọn đèn.\n\n116. Rồi lấy cây kim nhỏ,\nDìm tim đèn xuống dần,\nThấy cây đèn Niết-bàn,\nTâm ta được giải thoát.`, ref: "Trưởng Lão Ni Kệ 5.10", url: "https://loicuaducphat.org/thig/thig5.10.html#content" },

{ text: `30 Trưởng Lão Ni\n\n117. Loài Người trong tuổi trẻ,\nCầm chày giã lúa gạo,\nLoài Người được tài sản,\nNuôi dưỡng vợ và con.\n\n118. Hãy hành lời Phật dạy,\nKhông làm gì nhiệt não,\nRửa chân thật mau lẹ,\nHãy ngồi xuống một bên,\nChú tâm tu tâm chỉ,\nLàm theo lời Phật dạy.\n\n119. Sau khi nghe lời dạy,\nLời Patàcàrà,\nSau khi rửa chân xong,\nHọ vào ngồi một bên,\nChú tâm tu tâm chỉ,\nLàm theo lời Phật dạy.\n\n120. Trong đêm canh thứ nhất,\nHọ nhớ đời quá khứ\nTrong đêm canh chặng giữa,\nThiên nhãn được thanh tịnh,\nTrong đêm canh cuối cùng,\nKhối si ám phá tan.\n\n121. Ðứng dậy họ lễ chân,\nVị giáo giới cho họ,\nNhư Chư Thiên ba mươi\nÐảnh lễ vị Sakka,\nVị không bị đánh bại,\nỞ lại chỗ chiến trường,\nÐặt Patàcàrà,\nVào hàng bậc lãnh đạo,\nChúng tôi sẽ được sống,\nBa minh, không lậu hoặc.`, ref: "Trưởng Lão Ni Kệ 5.11", url: "https://loicuaducphat.org/thig/thig5.11.html#content" },

{ text: `Trưởng Lão Ni Candà\n\n122. Trước ta sống bất hạnh,\nKhông chồng và không con,\nKhông bè bạn, bà con,\nKhông có cơm, có áo.\n\n123. Ta cầm gậy bình bát\nÐi ăn xin từng nhà,\nBị lạnh nóng đày đọa,\nBảy năm ta sống vậy.\n\n124. Thấy được Tỷ-kheo-ni,\nTa nhận đồ ăn uống,\nSau khi đến, ta xin,\nÐược xuất gia không nhà.\n\n125. Nàng Patàcàrà,\nThương ta, cho xuất gia,\nRồi giảng dạy cho ta,\nHướng dẫn đến chân đế.\n\n126. Nghe xong lời nàng giảng.\nTa làm theo lời dạy,\nLời giảng bậc tôn Ni,\nKhông phải lời trống không,\nTa chứng được Ba minh,\nTa không còn lậu hoặc.`, ref: "Trưởng Lão Ni Kệ 5.12", url: "https://loicuaducphat.org/thig/thig5.12.html#content" },

{ text: `Trưởng Lão Ni Patàcàrà\n\n137. Ông không biết con đường\nNó đến hay nó đi,\nTừ đâu con trai đến,\nÔng lại khóc: 'Con tôi'.\n\n138. Ông đâu biết con đường,\nNó đến hay nó đi,\nÔng khóc nó làm gì?\nPháp hữu tình là vậy.\n\n129. Không có ai yêu cầu,\nTừ chỗ kia, nó đến,\nKhông có ai cho phép,\nTừ chỗ này, nó đi,\nTừ đâu, nó đến đây!\nÐược sống bấy nhiêu ngày.\n\n130. Mệnh chung, hình sắc người,\nLuân hồi, nó sẽ đi!\nÐến vậy, đi như kia,\nỞ đây, khóc than gì?\n\n131. Cây tên, khó thấy được,\nTừ tim ta, nhổ lên:\nNàng diệt sầu vì con,\nSầu ấy ám ảnh ta.\n\n132. Nay cây tên được nhổ\nKhông dục cầu, tịch tịnh\nTa quy y ẩn sĩ,\nPhật, Pháp và chúng Tăng.`, ref: "Trưởng Lão Ni Kệ 6.1", url: "https://loicuaducphat.org/thig/thig6.1.html#content" },

{ text: `Trưởng Lão Ni Vàsetthi\n\n133. Ta sầu muộn vì con\nKhổ, tâm cuồng tưởng loạn,\nLõa thể, tóc rối ren,\nÐời sống vậy, ta sống.\n\n134. Lang thang đường, đống rác,\nNghĩa địa, đường xe đi,\nBa năm ta đã sống,\nKham khổ, chịu đói khát.\n\n135. Rồi ta thấy Thiện Thệ,\nÐến thành Mi-thi-la,\nÐiều ngự kẻ chưa điều,\nBậc Giác Ngộ, vô úy.\n\n136. Lấy lui tâm bình tĩnh,\nTa đảnh lễ đến gần.\nThương ta, Gotama,\nNgài thuyết pháp cho ta.\n\n137. Nghe Ngài thuyết pháp xong,\nTa xuất gia, không nhà,\nTùy hành lời Ðạo Sư,\nTa chứng đạo an ổn.\n\n138. Mọi sầu muộn chặt đứt,\nÐoạn tận, được chấm dứt,\nTa liễu tri nền gốc,\nTừ đấy sầu muộn sanh.`, ref: "Trưởng Lão Ni Kệ 6.2", url: "https://loicuaducphat.org/thig/thig6.2.html#content" },

{ text: `Trưởng Lão Ni Khemà\n\n139. Nàng vừa trẻ vừa đẹp,\nTa vừa trẻ vừa xuân,\nVới cung đàn năm điệu,\nHãy vui hưởng, Khemà.\n\n140. Với thân hôi thối này,\nBệnh hoạn và mong manh,\nTa nhàm chán ghét bỏ,\nDục ái đã nhổ lên.\n\n141. Dục ví như gươm giáo,\nCác uẩn đoạn đầu đài,\nÐiều người nói dục lạc,\nNay ta đã xa lìa.\n\n142. Mọi nơi, hỷ duyệt đoạn,\nKhối si ám tan tành,\nHãy biết vậy, Ác ma!\nNgươi bị hại, Ma vương.\n\n143. Ngươi đánh lễ vầng sao!\nNgươi thờ lửa rừng sâu,\nNgươi không biết như thật,\nKẻ ngu nghĩ rằng tịnh.\n\n144. Còn ta, ta đảnh lễ,\nBậc Giác ngộ, Thượng nhân,\nGiải thoát mọi khổ đau,\nHành lời Ðạo Sư dạy.`, ref: "Trưởng Lão Ni Kệ 6.3", url: "https://loicuaducphat.org/thig/thig6.3.html#content" },

{ text: `Trưởng Lão Ni Sujàtà\n\n145. Trang sức, mặc áo đẹp\nVòng hoa, xức chiên đàn,\nÐeo mọi loại nữ trang\nCầm đầu chúng nữ tỳ.\n\n146. Mang theo đồ ăn uống,\nNhiều món ăn cứng mềm,\nTừ nhà ta đi ra,\nÐi đến vườn thưởng ngoạn.\n\n147. Tại đây ta vui chơi,\nRồi ta đi về nhà,\nTa thấy ngôi tinh xá,\nKhi ta bước vào rừng,\nRừng tên Anjanà,\nTại xứ Sàketa.\n\n148. Thấy hào quang thế giới,\nÐảnh lễ, ta tới gần,\nThương ta, bậc Pháp nhãn,\nNgài thuyết pháp cho ta.\n\n149. Nghe xong bậc Ðại tiên,\nTa thể nhập chân lý,\nTại đấy ta chứng pháp,\nLy trần tạo bất tử.\n\n150. Do liễu tri diệu pháp,\nTa xuất gia, không nhà,\nBa minh ta đạt được,\nKhông trống rỗng lời Phật.`, ref: "Trưởng Lão Ni Kệ 6.4", url: "https://loicuaducphat.org/thig/thig6.4.html#content" },

{ text: `Trưởng Lão Ni Anopamà\n\n151. Sanh gia đình cao quý,\nNhiều châu báu, tài sản,\nÐầy đủ dung sắc đẹp,\nCon gái cưng Majjha.\n\n152. Ðược con vua cầu hôn,\nCon phú gia xin cưới,\nSứ giả đến cha ta,\n"Hãy cho tôi Anopama."\n\n153. Công chúa con gái ngài,\nCân nặng như thế nào\nTôi sẽ tặng tám lần\nBằng vàng ròng châu báu.\n\n154. Ta thấy đấng Giác ngộ,\nBậc Thế Tôn vô thượng,\nTa đảnh lễ chân Ngài,\nÐến gần, ngồi một bên.\n\n155. Thương ta, Gotama,\nNgài thuyết pháp cho ta.\nNgay tại chỗ ngồi ấy,\nTa chứng quả thứ ba.\n\n156. Rồi ta cạo bỏ tóc,\nXuất gia, sống không nhà,\nHôm nay, đêm thứ bảy,\nKhát ái được gột sạch.`, ref: "Trưởng Lão Ni Kệ 6.5", url: "https://loicuaducphat.org/thig/thig6.5.html#content" },

{ text: `Trưởng Lão Ni Mahàpajàpatì Gotamì\n\n157. Bậc Giác ngộ anh hùng!\nCon xin đảnh lễ Ngài,\nNgài là bậc Tối thượng,\nGiữa mọi loài chúng sanh,\nNgài giải khổ cho con,\nCùng rất nhiều người khác.\n\n158. Liễu tri mọi đau khổ,\nGột sạch nhân khát ái,\nCon đường Thánh tám ngành,\nÐoạn diệt, ta chứng ngộ.\n\n159. Trước ta sống là mẹ,\nLà con, là cha, anh,\nLà ông nội, ông ngoại,\nÐời sống trước là vậy,\nKhông rõ biết như thật,\nLuân hồi, tìm không gặp.\n\n160. Nay ta thấy Thế Tôn,\nThân này thân tối hậu,\nSanh tử được đoạn tận,\nNay không còn tái sanh.\n\n161. Siêng, tinh cần nỗ lực,\nThường, kiên trì tinh tấn,\nHãy thắng đệ tử Phật,\nHòa hợp, đảnh lễ Ngài.\n\n162. Vì hạnh phúc nhiều người,\nMa-yà sanh Cù-đàm,\nGiải tỏa nhóm khổ đau\nCho người bị bệnh chết.`, ref: "Trưởng Lão Ni Kệ 6.6", url: "https://loicuaducphat.org/thig/thig6.6.html#content" },

{ text: `Trưởng Lão Ni Guttà\n\n163. Vì mục đích tối thượng,\nGuttà, người xuất gia,\nTừ bỏ cả con cái,\nCho đến bản thân mình,\nHãy nhiệt tâm hành trì,\nChớ để tâm chi phối.\n\n164. Tâm lừa đảo chúng sanh,\nƯa ác ma lãnh vực,\nLuân hồi nhiều đời sống,\nChúng dong ruổi, si mê.\n\n165. Dục vọng và sân hận,\nKể cả với thân kiến,\nCộng thêm giới cấm thủ\nVới nghi hoặc thứ năm.\n\n166. Hỡi này, Tỷ-kheo-ni,\nTừ bỏ kiết sử này,\nLà hạ phần kiết sử,\nNgươi hết lại đời này.\n\n167. Hãy tránh xa tham mạn,\nVô minh và trạo cử,\nChặt đứt kiến sử xong,\nNgươi sẽ dứt đau khổ.\n\n168. Quảng bỏ vòng sanh tử,\nLiễu tri sự tái sanh,\nHiện tại không ước vọng,\nNgươi sẽ sống an tịnh.`, ref: "Trưởng Lão Ni Kệ 6.7", url: "https://loicuaducphat.org/thig/thig6.7.html#content" },

{ text: `Trưởng Lão Ni Vijjayà\n\n169. Bốn lần và năm lần\nTa ra khỏi tinh xá,\nTâm không được an tịnh,\nKhông chế ngự được tâm.\n\n170. Ta đến Tỷ-kheo-ni,\nTa hỏi, đàm luận pháp,\nNàng thuyết pháp cho ta,\nVề giới và về xứ.\n\n171. Bốn sự thật bậc Thánh\nVề các căn, các lực,\nGiác chi, tám đường chánh,\nÐạt đạo tối thượng nghĩa.\n\n172. Nghe lời vị ấy dạy,\nTa làm theo giáo huấn,\nTrong đêm canh thứ nhất,\nTa nhớ đến đời trước.\n\n173. Trong đêm canh chặng giữa\nThiên nhãn được thanh tịnh,\nTrong đêm canh cuối cùng,\nKhối si ám tan tành.\n\n174. Từ đấy ta được sống,\nBiến mãn thân hỷ lạc,\nÐêm thứ bảy, duỗi chân,\nKhối si ám tan tành.`, ref: "Trưởng Lão Ni Kệ 6.8", url: "https://loicuaducphat.org/thig/thig6.8.html#content" },

{ text: `Trưởng Lão Ni Uttarà\n\n175. Loài Người trong tuổi trẻ,\nCầm chày giã lúa gạo,\nTuổi trẻ được tài sản,\nNuôi dưỡng vợ và con.\n\n176. Hãy hành lời Phật dạy,\nKhông làm gì nhiệt não,\nRửa chân thật mau lẹ,\nHãy ngồi xuống một bên.\n\n177. Sau khi an trú tâm,\nNhứt tâm, khéo định tĩnh,\nHãy quán sát các hành,\nThuộc ngoại, không thuộc ngã.\n\n178. Ta nghe lời giáo huấn,\nLời Patàcàrà;\nSau khi ta rửa chân,\nBước vào, ngồi một bên.\n\n179. Trong đêm canh thứ nhất,\nTa nhớ đời quá khứ,\nTrong đêm canh chặng giữa\nThiên nhãn được thanh tịnh.\n\n180. Trong đêm canh cuối cùng,\nKhỏi si ám tan tành,\nTừ ba minh, đứng dậy\nGiáo huấn Ngài, làm xong.\n\n181. Như Thiên chủ Sakka,\nỞ cõi trời Ba mươi,\nKhông bao giờ bại trận,\nỞ tại các chiến trường,\nTa sống, tôn xưng Ngài,\nLà bậc Thầy lãnh đạo,\nTa chứng được ba minh,\nTa không còn lậu hoặc.`, ref: "Trưởng Lão Ni Kệ 7.1", url: "https://loicuaducphat.org/thig/thig7.1.html#content" },

{ text: `Trưởng Lão Ni Calà\n\n182. Sau khi an trú niệm,\nTỷ-kheo-ni luyện căn,\nThể nhập đạo an tịnh,\nAn lạc tịnh các hành.\n\n183. Vì ai, ngươi đầu trọc,\nHiện tướng, Sa-môn ni?\nKhông theo hệ phái nào,\nSao sống si mê vậy?\n\n184. Các hệ phái ngoại đạo\nNương tựa trên tà kiến,\nHọ không hiểu Chánh pháp\nHọ không thuần thục pháp.\n\n185. Sanh gia tộc Thích-ca,\nÐức Phật, bậc vô tỷ\nNgài thuyết pháp cho ta,\nVượt qua các tà kiến.\n\n186. Ngài thuyết Tám thánh đạo,\nVề khổ, nguyên nhân khổ,\nVề vượt qua đau khổ\nVà con đường khổ diệt.\n\n187. Ta nghe lời Phật dạy,\nSống vui thích giáo pháp,\nBa minh đã đạt được,\nLời Phật dạy làm xong.\n\n188. Mọi nơi, hỷ duyệt đoạn,\nKhỏi si ám tan tành!\nHãy biết vậy, Ác ma!\nNgười bị hại, Ma vương.`, ref: "Trưởng Lão Ni Kệ 7.2", url: "https://loicuaducphat.org/thig/thig7.2.html#content" },

{ text: `Trưởng Lão Ni Upacàlà\n\n189. Trú niệm có pháp nhãn\nTỷ-kheo-ni luyện căn,\nThể nhập đạo an tịnh,\nBậc thượng nhân hành trì.\n\n190. Sao ngươi không thích sanh,\nCó sanh mới hưởng dục,\nHãy hưởng thọ dục lạc,\nChớ hối tiếc về sau.\n\n191. Ðã sanh, thời bị chết,\nTay chân bị đứt đoạn,\nBị giết, trói, phiền não.\nSau đưa đến khổ đau.\n\n192. Sanh gia bậc Thích-ca\nÐức Phật không chiến bại.\nNgài thuyết pháp cho ta,\nVượt qua khỏi sự sanh.\n\n193. Ngài thuyết Tám thánh đạo,\nVề khổ, nguyên nhân khổ,\nVề vượt qua đau khổ,\nVà con đường khổ diệt.\n\n194. Ta nghe lời Ngài dạy,\nSống vui thích giáo pháp,\nBa minh đã đạt được,\nLời Phật dạy làm xong.\n\n195. Mọi nơi, hỷ duyệt đoạn,\nKhỏi si ám tan tành,\nHãy biết vậy, Ác ma!\nNgươi bị hại, Ma vương.`, ref: "Trưởng Lão Ni Kệ 7.3", url: "https://loicuaducphat.org/thig/thig7.3.html#content" },

{ text: `Trưởng Lão Ni Sìsupacàlà\n\n196. Tỷ-kheo-ni giữ giới,\nKhéo hộ trì các căn,\nÐạt được đạo an tịnh,\nNước cam lồ thuần tịnh.\n\n199. Thời này đến thời khác,\nHữu này đến hữu khác,\nChúng đều bị thân kiến,\nLãnh đạo và chi phối,\nChúng không vượt thân kiến,\nLuân chuyển vòng sanh tử,\n\n200. Toàn thế giới bốc cháy\nToàn thế giới đồng cháy,\nToàn thế giới bừng cháy,\nToàn thế giới rung động.\n\n201. Phật thuyết pháp cho ta,\nPháp bất động vô tỷ,\nÐược bậc không phàm phu,\nPhục vụ và nhiệt hành,\nChỗ ấy, tâm ý ta,\nHân hoan và ưa thích.\n\n202. Ta nghe lời vị ấy,\nSống vui trong giáo pháp,\nBa minh đã đạt được,\nLời Phật dạy làm xong.\n\n203. Mọi chỗ, hỷ diệt đoạn,\nKhỏi si ám tan tành,\nHãy biết vậy, Ác ma!\nNgười bị bại, Ma Vương.`, ref: "Trưởng Lão Ni Kệ 8.1", url: "https://loicuaducphat.org/thig/thig8.1.html#content" },

{ text: `Trưởng Lão Ni Mẹ Của Vaddha\n\n204. Vaddha, chớ bao giờ,\nRơi vào cõi tham dục,\nNày con, chớ chia phần,\nTrong đau khổ liên tục.\n\n205. Hạnh phúc là ẩn sĩ,\nKhông tham, nghi đoạn tận,\nSống mát lạnh, chế ngự,\nKhông còn các lậu hoặc.\n\n206. Ẩn sĩ ấy hành trì,\nCon đường đạt chánh kiến,\nChấm dứt sự khổ đau,\nVaddha! Hãy tiến tu.\n\n207. Với tự tín mẹ nói,\nMục đích này cho con,\nMẹ thân! Con nghĩ rằng,\nMẹ không còn tham dục.\n\n208. Vaddha! Phàm hành gì,\nThấp, cao hay bậc trung,\nMột tí nhỏ tham dục,\nKhông có ở nơi ta.\n\n209. Ta đoạn mọi lậu hoặc,\nKhông phóng dật, thiền tu,\nBa minh đã đạt được,\nLàm xong lời dạy.\n\n210. Vi diệu thay, mẹ ta,\nKhích lệ, thúc đẩy ta,\nNhững kệ thuộc chân đế,\nVới lòng từ thương tưởng.\n\n211. Ta nghe lời mẹ dạy,\nLời giáo giới mẹ hiền,\nTa hành pháp cảm kích,\nÐạt an ổn khổ ách.\n\n212. Ta tinh tấn tinh cần,\nNgày đêm không biếng nhác,\nÐược mẹ khéo khích lệ,\nTa chứng tịnh tối tượng.`, ref: "Trưởng Lão Ni Kệ 9.1", url: "https://loicuaducphat.org/thig/thig9.1.html#content" },

{ text: `Trưởng Lão Ni Kisà Gotamì\n\n213. Bạn lành được ẩn sĩ,\nKhắp thế giới, ngợi khen,\nThân cận với bạn lành,\nKẻ ngu thành người trí.\n\n214. Hãy thân bậc chân nhân,\nThân vậy, trí tăng trưởng,\nThân cận bậc chân nhân,\nMọi khổ đau được thoát.\n\n215. Hãy biết, Bốn thánh đế,\nKhổ và khổ tập khởi,\nBiết về đau khổ diệt,\nVà đoạn Thánh tám ngành.\n\n216. Khổ thay phận nữ nhân,\nChính Ngài đã nói lên,\nBậc đánh xe điều ngự,\nNhững ai đáng điều ngự,\nKhổ thay phận chồng chung,\nNhiều người một lần sanh.\n\n217. Trong đau khổ đâm họng,\nMẹ yếu uống thuốc độc,\nTrường hợp gặp bào thai,\nBị chết khi đang sanh,\nCả hai mẹ và con,\nÐều cùng gặp tai nạn.\n\n218. Khi mang thai đi về,\nTa thấy chồng chết đường,\nVà khi ta sanh đẻ,\nTa không về đến nhà.\n\n219. Hai con đều bị chết,\nChồng nữ nhân khốn khổ,\nLại bị chết giữa đường;\nMẹ, cha và cả anh,\nÐều cùng bị thiêu đốt,\nDồn chung trên đống lửa.\n\n220. Ôi, nữ nhân khốn khổ,\nSanh gia cảnh khốn cùng,\nNgười phải chịu khổ đau,\nVô lượng, không kể xiết.\nNước mắt người đã khóc,\nTrải nhiều ngàn lần sanh.\n\n221. Ta thấy giữa nghĩa trang,\nThịt con ta bị ăn,\nGia đình bị tàn hại,\nBị mọi người khinh bỉ,\nTuy vậy, người chết chồng.\nÐạt được sự bất tử.\n\n222. Ta tu tập Thánh đạo,\nÐường tám ngành, bất tử,\nTa chứng được Niết-bàn,\nThấy được gương Chánh pháp.\n\n223. Trên ta, mũi tên đâm,\nÐã được rút ra khỏi,\nGánh nặng đã đặt xuống,\nViệc nên làm đã làm,\nTa là Trưởng lão Ni,\nKisà-Gotamì,\nVới tâm khéo giải thoát,\nTa nói lên đời này.`, ref: "Trưởng Lão Ni Kệ 10.1", url: "https://loicuaducphat.org/thig/thig10.1.html#content" },

{ text: `Trưởng Lão Ni Uppalavanna\n\n224. Hai, mẹ và con gái,\nChúng tôi sống một chồng,\nLời nàng đã nói lên\nLàm ta xúc động mạnh,\nCảnh ngộ thật hy hữu,\nLàm tóc lông dựng ngược.\n\n225. Ðáng ngán thay các dục,\nBất tịnh, hôi, nhiều gai,\nỞ đây, mẹ, con gái,\nChúng tôi lấy một chồng.\n\n226. Thấy nguy hiểm trong dục,\nViễn ly an ổn vững\nNàng xuất gia Vương Xá,\nBỏ nhà, sống không nhà.\n\n227. Ta biết các đời trước,\nThiên nhãn được thanh tịnh,\nTrí biết được tâm người,\nNhĩ giới được trong sạch.\n\n228. Ta chứng được thần thông,\nLậu tận ta đạt được,\nTa chứng sáu thắng trí,\nLời Phật dạy, làm xong.\n\n233. Với tâm khéo nhiếp phục,\nThần túc khéo tu trì,\nSáu thắng trí, ta chứng,\nLời Phật dạy, làm xong.\n\n234. Các dục giống gươm giáo,\nChém nát các uẩn ta,\nNhững dục mà ngươi gọi,\nLà lạc thú cuộc đời.\nNgày nay, dục lạc ấy.\nVới ta, không hấp dẫn.\n\n235. Ở tất cả mọi nơi,\nHỷ lạc được đoạn tận,\nKhối tối tăm mù ám,\nÐã bị làm tan nát,\nHỡi này kẻ Ác ma,\nNgươi hãy biết như vậy,\nNgươi chính là Ác ma,\nNgươi đã bị bại trận.`, ref: "Trưởng Lão Ni Kệ 11.1", url: "https://loicuaducphat.org/thig/thig11.1.html#content" },

{ text: `236. Mùa đông ta mang nước,\nLuôn luôn xuống dòng nước,\nTa sợ các hình phạt,\nLời trách móc các bà.\n\n237. Hỡi này Bà-la-môn,\nNgươi sợ hãi vì ai?\nLuôn luôn xuống dòng nước,\nTay chân run cầm cập.\nNgươi phải chịu cảm thọ,\nRét lạnh quá độ vậy?\n\n238. Và nàng có biết chăng\nHỡi này Punnikà?\nSao nàng lại đến hỏi\nVị làm các nghiệp lành,\nVị đã chận đứng lại,\nCác nghiệp ác bất thiện.\n\n239. Vị ấy già hay trẻ,\nLàm các nghiệp ác độc,\nNgười ấy nhờ rảy nước,\nÐược giải thoát ác nghiệp.\n\n240. Ai nói với ngươi vậy,\nKẻ ngu với kẻ ngu,\nNgười tin nhờ rảy nước,\nÐược giải thoát ác nghiệp.\n\n241. Tất cả những ếch, rùa,\nSẽ được lên cõi trời,\nCùng các rắn cá sấu,\nVà các thủy vậy khác.\n\n242. Kẻ giết bò giết heo,\nKẻ đánh cá sanh thú,\nCác kẻ cướp giết người,\nCác người làm ác khác,\nHọ nhờ có rảy nước,\nCó thể thoát ác nghiệp.\n\n243. Nếu những con sông này,\nCó thể làm trôi mất,\nÁc nghiệp xưa ngươi làm,\nChúng cũng làm trôi luôn,\nCác thiện nghiệp ngươi làm,\nKhiến ngươi thành rỗng không.\n\n244. Phạm chí vì cái gì,\nNgươi sợ phải xuống nước,\nCái ấy chớ có làm,\nChớ để lạnh hại da.\n\n245. Ta đi theo tà đạo,\nNàng hướng ta Thánh đạo,\nThưa nàng ta cho nàng,\nCái áo thấm nước này.\n\n246. Ngươi giữ cái áo lại,\nTa không muốn cái áo!\nNếu ngươi sợ đau khổ,\nNếu ngươi không thích khổ.\n\n247. Chớ làm các điều ác,\nCông khai hay kín đáo,\nNếu ngươi làm sẽ làm,\nLàm các điều ác nghiệp.\n\n248. Ngươi không thoát đau khổ,\nDầu thấy đến, ngươi chạy,\nNếu ngươi sợ đau khổ,\nKhông ưa thích đau khổ.\n\n249. Hãy đến quy y Phật,\nQuy y Pháp và Tăng,\nHãy chấp nhận Giới luật,\nNgươi sẽ được lợi ích.\n\n250. Ta đến quy y Phật,\nQuy y Pháp và Tăng,\nTa chấp nhận Giới luật,\nTa sẽ được lợi ích,\n\n251. Trước ta là bà con,\nVới tộc họ Phạm thiên,\nNay ta là Phạm chí,\nChân thật là như vậy,\nTa chứng ngộ Ba minh,\nÐầy đủ trí Vệ-đà,\nAn ổn đến với ta,\nTâm tư được gột sạch.`, ref: "Trưởng Lão Ni Kệ 12.1", url: "https://loicuaducphat.org/thig/thig12.1.html#content" },

{ text: `Trưởng Lão Ni Rohinì\n\n271. Nàng chỉ cho ta thấy,\nÐây là một Sa-môn,\nNàng thức ta tỉnh dậy,\nÐây là một Sa-môn,\nNàng khen tặng Sa-môn,\nMuốn thành nữ Sa-môn.\n\n272. Nàng tìm cho Sa-môn\nRất nhiều đồ ăn uống,\nNày hỡi, Rô-hi-ni,\nSao nàng quý Sa-môn?\n\n273. Họ nhác không thích làm,\nSống với đồ người cho,\nHọ ham lợi thích ngọt,\nSao nàng quý Sa-môn?\n\n274. (Rohini): "Cha thân đã lâu rồi,\nCha hỏi về Sa-môn,\nCon sẽ tán thán họ\nTuệ giới hạnh tinh cần.\n\n275. Họ thích làm không nhác,\nHọ làm việc tối thắng,\nHọ trừ bỏ tham sân,\nVì vậy con quý họ.\n\n276. Ba cội gốc điều ác,\nHọ quét sạch thanh tịnh,\nMọi điều ác đoạn tận,\nVì vậy con quý họ.\n\n277. Thân nghiệp họ trong sạch,\nKhẩu nghiệp họ cũng vậy,\nÝ nghiệp họ trong sạch,\nDo vậy con quý họ.\n\n278. Không cấu uế giải thoát,\nNhư vỏ ốc trong sạch,\nTrong sạch cả bên trong,\nTrong sạch cả bên ngoài,\nCông đức họ trắng tinh,\nDo vậy con quý họ.\n\n279. Nghe nhiều thọ trì pháp,\nMạng sống đúng Chánh pháp,\nHọ thuyết nghĩa thuyết pháp,\nDo vậy con quý họ.\n\n280. Nghe nhiều thọ trì pháp,\nMạng sống đúng Chánh pháp,\nNhất tâm giữ chánh niệm,\nDo vậy con quý họ.\n\n281. Đi xa, giữ chánh niệm\nLời sáng suốt khiêm nhường,\nHọ chấm dứt đau khổ,\nDo vậy con quý họ.\n\n282. Từ làng họ ra đi,\nKhông nhìn ngó vật gì,\nHọ đi không mong chờ,\nDo vậy con quý họ.\n\n283. Không tìm cầu kho tàng,\nKhông kho chứa, kho cất,\nHọ tầm cầu cứu cánh,\nDo vậy con quý họ.\n\n284. Họ không nắm giữ tiền,\nKhông nắm vàng, nắm bạc,\nHọ sống với hiện tại,\nDo vậy con quý họ.\n\n285. Từ gia đình quốc độ,\nHọ xuất gia khác nhau,\nNhưng họ thương kính nhau,\nDo vậy con quý họ."\n\n286. Hỡi này Rô-hi-ni,\nNàng sanh trong gia đình,\nNàng đem lại hạnh phúc,\nCho gia đình chúng ta,\nNàng tin Phật, Pháp, Tăng,\nLòng tín kính sắc bén.\n\n287. Nàng biết rõ cái này,\nLà ruộng phước vô thượng,\nChúng tôi cùng tín kính,\nCác vị Sa-môn này,\n\n288. Tế đàn thiết lập đây,\nÐối với ta rất lớn.\n(Rohini): "Nếu cha sợ đau khổ,\nNếu cha không thích khổ,\n\n289. Hãy quy y Phật-đà,\nQuy y Pháp và Tăng,\nHãy chấp nhận giới đức,\nCha sẽ được hạnh phúc.\n\n290. (Cha Rohini): "Ta quy y Phật-đà,\nQuy y Pháp và Tăng,\nTa chấp nhận giới luật,\nTa sẽ được hạnh phúc.\n\n291. Lúc trước ta chỉ là,\nBà con của Phạm thiên,\nNay ta thật chính là,\nMột vị Bà-la-môn,\nTa chứng đạt Ba minh,\nÐược an toàn yên ổn,\nBa Vệ-đà chứng ngộ,\nTa tắm rửa thật sạch.`, ref: "Trưởng Lão Ni Kệ 13.2", url: "https://loicuaducphat.org/thig/thig13.2.html#content" },

{ text: `339. Ta trước mặc áo trắng,\nÐược nghe giảng Chánh pháp,\nDo ta không phóng dật,\nChứng tri được chân lý.\n\n340. Nhờ vậy đối mọi dục,\nKhông còn tham muốn lớn,\nThấy sợ hãi thân kiến,\nTa mong muốn viễn ly.\n\n342. Từ bỏ, ta xuất gia,\nGia sản đâu có ít.\nNhờ diệu pháp khéo thuyết,\nRa đi, với lòng tin.\n\n343. Ta không thể hy cầu\nVật gì thuận gia sản\nVàng bạc ta đã bỏ,\nSao lại đi đến chúng?\n\n344. Vàng bạc không giác ngộ,\nKhông làm người an tịnh,\nKhông hợp hạnh Sa-môn,\nKhông phải tài sản thánh.\n\n345. Chính vàng hay bạc này\nLàm tham ái, đắm say,\nLàm con người ngu si,\nLàm tăng trưởng bụi trần,\nNguy hiểm nhiều ưu não,\nÐây, không gì trường cửu.\n\n346. Ðây, loài Người tham đắm,\nPhóng dật, tâm uế nhiễm,\nChống đối thù địch nhau\nRộng đường đấu tranh nhau.\n\n347. Giết hại, trói, tra tấn,\nHao tài sầu, ưu tư\nNhững ai chìm trong dục,\nGặp phải nhiều tai họa.\n\n348. Vì sao bà con ta\nGiống như kẻ thù ta,\nLại trói buộc ta vào,\nTrong vòng các dục lạc,\nHãy biết ta xuất gia,\nVì thấy dục đáng sợ.\n\n349. Bạc, vàng không có thể\nÐoạn được các lậu hoặc,\nCác dục là thù địch,\nSát nhân, chuyên giết hại,\nChúng là kẻ oán thù,\nLà mũi tên, dây trói.\n\n350. Vì sao bà con ta\nGiống như kẻ thù ta,\nLại trói buộc ta vào\nTrong vòng các dục lạc,\nHãy biết ta xuất gia,\nCạo tóc đắp đại y.\n\n351. Nuôi sống bằng đồ ăn,\nTích lũy nhờ khất thực,\nY áo được tác thành\nVới miếng vải lượm lặt\nSống vậy, thích hợp ta,\nCơ bản, sống không nhà.\n\n352. Dục đại sĩ từ bỏ\nDục loài Trời, loài Người,\nTrú an ổn, giải thoát\nKhông dao động an lạc.\n\n353. Chớ để ta đến dục,\nTrong dục, không an toàn,\nDục, thù địch sát nhân\nGây khổ, dụ đống lửa.\n\n354. Ðường hiểm, đầy sợ hãi,\nÐầy khổ hoạn, gai góc,\nTham ái đường gập ghềnh,\nHoang si mê rộng lớn.\n\n355. Tai họa đầy hãi hùng,\nCác dục dụ đầu rắn,\nKẻ ngu thích thú dục,\nKẻ mù lòa phàm phu.\n\n356. Chúng sanh chìm bùn đục,\nNhững kẻ không thấy đời,\nHọ không có rõ biết,\nSự chấm dứt sanh tử.\n\n357. Loài Người vì nhân dục,\nCon đường đến ác thú,\nPhần nhiều đi đường ấy,\nKhiến tự ngã bệnh hoạn.\n\n358. Như vậy dục sanh thù,\nNung nấu, làm uế nhiễm,\nDục thuộc về thể vật,\nTrói người vào tử vong.\n\n359. Dục làm cho diên cuồng,\nLoạn ngôn tâm thác loạn,\nLàm uế nhiễm chúng sanh,\nSắp rơi bẫy Ác ma.\n\n360. Dục nguy hiểm không cùng,\nNhiều khổ, thuốc độc lớn,\nNgọt ít, tạo đấu tranh,\nHéo tàn ngày tươi sáng.\n\n361. Ta quyết định như vậy,\nKhông trở lui dục nhân,\nTác thành điều bất hạnh,\nLuôn vui hưởng Niết-bàn.\n\n362. Quyết đấu tranh với dục,\nChờ đợi, mát, lắng dịu,\nSẽ sống không phóng dật,\nÐoạn diệt kiết sử dục.\n\n363. Ta đi theo đường ấy\nÐường đại sĩ đi qua,\nKhông sầu, không cấu uế,\nAn ổn, thẳng, Tám ngành.\n\n364. Hãy xem Subhà này,\nAn trú trên Chánh pháp,\nCon gái một thợ vàng,\nÐạt được không tham dục,\nNgồi hành trì thiền định,\nỞ dưới một gốc cây.`, ref: "Trưởng Lão Ni Kệ 13.5", url: "https://loicuaducphat.org/thig/thig13.5.html#content" },

{ text: `Trưởng Lão Ni Sumedhà\n\n450. Con gái vua Konca,\nVới hoàng hậu chánh ngôi,\nTại Matavatì,\nÐược sanh Sumedha,\nHân hoan gắng thực hành,\nLời dạy bậc Ðạo Sư.\n\n451. Giới hạnh thuyết giảng khéo,\nNghe nhiều khéo huấn luyện,\nTheo lời đức Phật dạy,\nNàng đến cha mẹ nàng,\nNói rằng: 'Thưa mẹ cha,\nCả hai, hãy nghe con!'.\n\n452. Con hân hoan Niết-bàn,\nDầu sanh hữu Chư Thiên,\nSanh hữu ấy vô thường,\nGiá trị gì các dục,\nTrống không, vị ngọt ít,\nCòn tàn hại thời nhiều.\n\n453. Các dục thật cay đắng,\nVí như nọc rắn độc,\nKẻ ngu mới tham đắm,\nTrong các loại dục ấy.\nNhững ai thọ hưởng dục,\nTrong một thời gian dài,\nBị khổ đau địa ngục,\nHành hạ và tàn hại.\n\n454. Những kẻ làm nghiệp ác,\nNhững kẻ tâm trí ác,\nBị đau đớn sầu khổ,\nTrong cảnh giới đọa xứ.\nKẻ ngu thường không nhiếp,\nChế ngự thân, khẩu, ý.\n\n455. Kẻ ngu có liệt tuệ,\nKhông tư duy quyết định,\nKhông ngăn chặn khổ tập,\nKhi có thời thuyết pháp,\nKhông biết lo học hỏi,\nKhông giác tri Thánh đế.\n\n456. Những sự thật, thưa mẹ,\nPhật thù thắng thuyết giảng,\nPhần lớn chúng quần sanh,\nKhông hiểu sự thật ấy;\nHọ hoan hỷ tái sanh,\nƯớc muốn sanh thiên giới.\n\n457. Sanh thiên không thường trú,\nSanh hữu là vô thường,\nKẻ ngu không sợ hãi,\nLuôn luôn phải tái sanh.\n\n458. Bị sanh bốn đọa xứ,\nÐược sanh Thiên, Nhân giới\nÐược chúng khó khăn thay,\nNhững ai rơi đọa xứ,\nTrong cảnh giới địa ngục,\nKhông có sự xuất gia.\n\n459. Mong cả hai cha mẹ,\nCho con được xuất gia,\nTrong giáo pháp thuyết giảng,\nCủa bậc chứng Mười lực,\nSống thong dong nhàn hạ,\nNỗ lực đoạn sanh tử.\n\n460. Sao con ưa tái sanh,\nVới thân tội lỗi này,\nThân trống rỗng, không lõi,\nVì mục đích đoạn diệt,\nTham ái được tái sanh,\nXin cho con xuất gia.\n\n461. Nay thời, Phật ra đời,\nPhi thời đã từ bỏ,\nThời cơ nay đã đến,\nCho đến trọn đời con,\nCon không làm tổn thương,\nGiới luật và Phạm hạnh.`, ref: "Trưởng Lão Ni Kệ 16.1", url: "https://loicuaducphat.org/thig/thig16.1.html#content" },

{ text: `Trưởng Lão Ni Sumedhà\n\n468. Sá gì thân hôi nhớp,\nPhát mùi, gây sợ hãi,\nBao da đựng xác chết,\nRỉ chảy đồ bất tịnh.\n\n469. Sá gì thân ta biết,\nGhê tởm, lấm máu thịt,\nChỗ chứa đựng loài sâu,\nMồi ăn cho chim chóc,\nThân xác này là vậy,\nNay đem đến cho ai?\n\n470. Thân thể bỏ nghĩa địa,\nKhông lâu, mất thức tri,\nNhư khúc gỗ quăng bỏ,\nBà con đều ghê tởm.\n\n471. Thân ấy quăng nghĩa địa,\nLàm mồi ăn kẻ khác,\nTrước chúng tắm rửa sạch,\nNay chúng sinh ghê tởm,\nCha mẹ còn như vậy,\nNói gì chung quần chúng.\n\n472. Họ mê thân không lõi,\nRàng buộc bởi gân xương,\nÐầy nước miếng, nước mắt,\nÐầy phân tiểu hôi hám.\n\n473. Nếu thân được mổ xẻ,\nLội nội phần ra ngoài,\nChính mẹ phải ghê tởm,\nKhông chịu nổi mùi hôi.\n\n474. Chính do uẩn, xứ, giới,\nTác thành các thân này,\nGốc tái sanh, đau khổ;\nHọ như lý nói lên,\nHoàn toàn không vui thích.\nVậy ai, tôi muốn cưới?\n\n475. Từng ngày trăm ngọn giáo,\nLuôn luôn mới đâm thân,\nDầu bị hại trăm năm,\nNhư vậy còn tốt hơn,\nVì khổ ấy cuối cùng,\nRồi cũng được tiêu diệt.\n\n476. Kẻ trí quyết bằng lòng\nSự giết hại như trên,\nBậc Ðạo Sư dạy rằng:\nHọ luân hồi dài dà,\nVới tâm tư giết hại,\nLiên tục nối tiếp nhau.\n\n477. Trong cảnh giới Trời, Người,\nBàng sanh, a-tu-la,\nNgạ quỷ và Ðịa ngục,\nChịu giết hại vô lượng.\n\n478. Trong địa ngục, rất nhiều,\nKẻ tâm uế, đọa lạc,\nChỗ trú ẩn Thiên giới,\nKhông có lạc Niết-bàn.\n\n479. Những ai đạt Niết-bàn,\nHọ liên hệ mật thiết,\nVới những lời thuyết dạy,\nCủa bậc đủ Mười lực,\nThong dong không rộn ràng,\nNỗ lực đoạn sanh tử.\n\n480. Thưa cha ngày hôm nay\nCon quyết tâm ra đi,\nNhững tài sản rỗng không,\nKhông có giá trị gì,\nCon ghê tởm các dục,\nCon chán ngấy các dục,\nHọ đã được tách thành,\nNhư thân cây Ta-la.`, ref: "Trưởng Lão Ni Kệ 16.1", url: "https://loicuaducphat.org/thig/thig16.1.html#content" },

{ text: `Trưởng Lão Ni Sumedhà\n\n489. Dầu có mười bảy báu,\nKhắp mười phương đầy tràn,\nKhông có dục thỏa mãn,\nNgười chết, chưa thỏa mãn.\n\n490. Các dục ví gươm giáo,\nCác dục ví đầu rắn,\nVí như bó đuốc cháy\nGiống xương gậm trơn tru.\n\n491. Các dục không thường còn,\nCũng không có thường hằng,\nKhổ nhiều, thuốc độc lớn,\nNhư hòn đạn cháy đỏ,\nNguồn gốc của bất hạnh,\nKết quả là đau khổ.\n\n492. Dục như trái của cây,\nNhư miếng thịt, khổ lụy,\nGiống như mộng như huyễn,\nDục như của vay mượn.\n\n493. Dục như gươm, như cọc,\nBệnh tật và cục bướu,\nBất hạnh và dao động,\nVí như hố than hừng,\nNguồn gốc của bất hạnh,\nSợ hãi và tàn sát.\n\n497. Kẻ ngu, đã lâu rồi,\nKhóc luân hồi nói tiếp,\nTừ vô thỉ đến nay,\nKhóc phải bị mệnh chung,\nKhóc anh em bị giết,\nKhóc tự mình bị giết.\n\n498. Hãy nhớ từ vô thỉ,\nNước mắt, sữa và máu,\nTuôn chảy theo luân hồi,\nKhông bao giờ dừng nghỉ,\nHãy nhớ các chúng sanh,\nLuân hồi xương chất đống.\n\n499. Hãy nhớ tràn bốn biển,\nÐầy nước mắt, sữa, máu,\nHãy nhớ xương một kiếp,\nCao bằng Vi-pu-la.\n\n500. Hãy nhớ từ vô thỉ,\nKhông đủ để làm thành,\nCả đất nước Diêm Phù,\nNhững nấm mồ hột táo,\nCủa mẹ cha luân hồi.\n\n501. Hãy nhớ từ vô thỉ,\nNhững cỏ cây cành lá,\nKhông đủ để chứa đựng,\nNhững ghè bốn ngón tay,\nChứa người cha, luân hồi.\n\n502. Hãy nhớ tới hình ảnh,\nCon rùa mù biển đông,\nCho đầu nó lọt vào,\nLỗ hổng khúc cây trôi,\nÐể nói lên ví dụ,\nÐược làm người khó vậy.`, ref: "Trưởng Lão Ni Kệ 16.1", url: "https://loicuaducphat.org/thig/thig16.1.html#content" },

{ text: `Trưởng Lão Ni Sumedhà\n\n503. Hãy nhớ thân sắc người,\nÐược ví bong bóng nước,\nÐầy cả những bất hạnh,\nTrống không không có lõi,\nHãy thấy uẩn vô thường!\nNhớ địa ngục nhiều họa.\n\n504. Hãy nhớ nghĩa địa lớn,\nNhờ tái sanh tiếp tục,\nNhờ sợ hãi thuồng luồng,\nHãy nhớ Bốn sự thật.\n\n505. Nước bất tử có đây,\nSao người uống trăm đắng,\nTất cả các dục lạc,\nThật trăm cay ngàn đắng.\n\n506. Nước bất tử có đây!\nSao người ưa dục não!\nMọi dục lạc đốt cháy\nSôi sùng sục nung nấu.\n\n507. Ðây không có kẻ thù!\nSao thích dục thù địch?\nVua lửa, trộm, nước, oán,\nThù chung thật là nhiều.\n\n508. Ở đây có giải thoát!\nSao để dục giết trói,\nTrong dục có giết trói!\nMê dục nhiều khổ đau.\n\n509. Ðuốc cỏ đang cháy rực,\nNắm, không thả, bị đốt,\nDục ví như bó đuốc,\nÐốt cháy ai không thoát.\n\n510. Chớ nhận dục lạc nhỏ,\nBỏ lạc lớn rộng rãi,\nChớ như cá nuốt câu,\nSau phải chịu hoạn nạn.\n\n511. Hãy nhiếp dục trong dục,\nNhư chó bị dây cột,\nChớ để dục ăn ngươi,\nNhư dân đói ăn chó.\n\n512. Khổ thật là vô lượng,\nKhiến tâm nhiều ưu tư,\nNgươi hệ lụy với dục,\nHãy bỏ dục vô thường.\n\n513. Ở đây, không có già!\nSao theo dục bị già?\nMọi sanh ở khắp nơi,\nBị bệnh chết chi phối,\n\n514. Ðây không già, không chết.\nÐây con đường không già,\nKhông chết, không sầu não,\nKhông thù địch trói buộc,\nKhông vấp ngã sợ hãi,\nKhông nung nấu đọa đầy.\n\n515. Ðích này, nhiều người đạt,\nÐích này là bất tử,\nNay cần phải chứng được,\nAi như lý chú tâm,\nNếu không có nỗ lực,\nKhông sao chứng đạt được.\n\n523. Ðây là nhân, là nguồn\nÐây chính là căn gốc,\nKham nhẫn lời Ðạo Sư!\nÐây dây chuyền thứ nhất\nÐấy chính là Niết-bàn,\nNếu chúng ta mến pháp.\n\n524. Như vậy với lòng tin,\nHọ thuyết rõ nên lời\nLời nói đầy trí tuệ,\nThù thắng và tối thượng\nHọ chán ghét tái sanh,\nDo chán ghét, tham diệt.`, ref: "Trưởng Lão Ni Kệ 16.1", url: "https://loicuaducphat.org/thig/thig16.1.html#content" },

         
        ];

       module.exports = { SuttaQuotesData };